window.PAPERS_DATA={"papers":[{"id":"2607.17352","versioned_id":"2607.17352v1","title":"Self-Modifying Lean Proof Agents with Verifier-Grounded Benchmark Coevolution","authors":["Yuqing Li","Zeguan Wu","Yu Gan","Junyu Liu"],"abstract":"Designing effective Lean proof agents is a central challenge in formal mathematical reasoning. Beyond building stronger provers, recent work emphasizes the workflow around Lean: how an agent decomposes proof obligations, uses tools and compiler feedback, diagnoses failures, repairs proofs, and maintains structured proof context. Motivated by code-level self-evolving agents, we study whether such workflows can be evolved rather than hand-designed. We present a self-evolving Lean proof agent in which a small fixed, trusted runtime wraps a fully mutable workspace: the proof workflow, prompts, and tools. Unlike most self-evolving systems, which optimize against a fixed external benchmark, our system coevolves the agent and its benchmark. Between generations, the highest-scoring agent (the champion) revises the active task distribution through a mastery-throttled curriculum update that introduces harder proof obligations only after the current level is mastered, and a single-anchor recalibration re-runs the champion on the updated benchmark to keep scores comparable as difficulty rises. All evolution stays inside a Lean-grounded verification loop: however the agent rewrites itself, a success counts only when its behavior yields Lean-verified proofs under a trusted snapshot, and each attempt must emit a machine-readable, Lean-grounded proof context whose representation may evolve but whose groundedness is enforced. We run the coevolving trajectory and a fixed-benchmark baseline for 15 active generations and compare them on a held-out miniF2F test split. The best coevolving agent reaches a 45.1% held-out solve rate, versus 12.7% for the seed and 32.0% for the best fixed-benchmark agent, showing that verifier-grounded self-evolution can improve Lean proof workflows under a coevolving benchmark.","published":"2026-07-19T17:26:59Z","updated":"2026-07-19T17:26:59Z","categories":["cs.AI","cs.LG","quant-ph"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.17352v1","pdf_url":"https://arxiv.org/pdf/2607.17352v1","comment":"22 pages, 2 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-21","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"openreview:B0oLDKOct6","versioned_id":"B0oLDKOct6","title":"Moral Reasoning Meta-Learning: Axiomatic Ethical Spaces and Functional Gradient Constraints for Next-Generation Artificial General Intelligence","authors":["Jincheng Zhang"],"abstract":"Traditional machine learning paradigms anchored in Empirical Risk Minimization (ERM) and conventional meta-learning frameworks (e.g., MAML) face fundamental robustness bottlenecks when encountering severe distribution shifts and open-world environments. This stems from their structural reliance on local gradients of task-specific loss functions, lacking a high-level, intrinsic self-inspection mechanism independent of empirical feedback. Inspired by the supreme cognitive capacity of human moral reasoning—characterized by the governance of local actions through invariant universal principles and dynamic reconciliation under dilemma—this paper introduces a radically new machine learning paradigm: Moral Reasoning Meta-Learning (MRML). Rather than embedding subjective societal or legal rules into algorithms, MRML mathematically formalizes the abstract core of moral reasoning into a top-tier, rigorous framework using functional analysis, differential geometry, and axiomatic set theory. We establish a comprehensive axiomatic system within a real Banach space W, introducing the foundational constructs of the Deontological Feasible Region, the Categorical Imperative Functional C(w), and the Virtue Functional V. Based on these axioms, we formulate a novel Meta-Ethical Operator E that projects empirical gradients onto a constrained topological manifold, preventing catastrophic policy collapse in sparse-reward or non-stationary environments. The entire optimization trajectory is governed by a novel two-tier continuous-time functional evolution system, incorporating a Moral Introspection Term derived from higher-order Hessian curvature to smooth optimization paths. Without empirical simulations, we substantiate the superiority of the MRML paradigm through top-tier, airtight mathematical proofs. Specifically, we present three core theorems: a global convergence theorem demonstrating that the meta-ethical residue asymptotically vanishes under non-convex and non-stationary task distributions; a generalization error bound theorem proving that the dynamic evolution of the Virtue Functional introduces a positive virtue bias that contracts the Rademacher complexity, significantly lowering the generalization upper bound; and a Lyapunov stability theorem demonstrating that the system achieves Input-to-State Stability (ISS) against adversarial bounded noise. MRML bridges the gap between high-level cognitive constraints and low-level geometric optimization, offering a structurally robust mathematical foundation for the self-evolution of safe and truly generalized intelligent agents.","published":"2026-07-19T11:08:42+00:00","updated":"2026-07-19T11:08:42+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=B0oLDKOct6","openreview_url":"https://openreview.net/forum?id=B0oLDKOct6","pdf_url":"https://openreview.net/pdf?id=B0oLDKOct6","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.17038","versioned_id":"2607.17038v1","title":"Reward-Driven LLM Agent Workflows: Synthesizing POMDP Routing and Self-Correction for Autonomous Decision-Making","authors":["Amez Amanj Ali","Kuo-Kun Tseng"],"abstract":"This paper addresses key technical challenges in current large language model (LLM) agent applications, including long-horizon planning, sparse reward attribution, and dynamic environmental interaction, by designing and optimizing an intelligent agent workflow. The proposed architecture is based on the synthesis of core AI paradigms: Visual, Language, Generative, Graph, Multimodal, Reinforcement, and Agent Intelligence. Unlike conventional baseline models that rely on static prompting and lack robust perception-action loops, our approach introduces a Partially Observable Markov Decision Process (POMDP) routing mechanism. This mechanism is augmented with an internal, self-correcting reward model that evaluates decision trajectories before execution. By integrating multimodal inputs and advanced reinforcement learning principles (such as proximal policy optimization and value function approximation), the agent maintains long-term structural memory and dynamically adapts its reasoning pathways to mitigate error accumulation. Empirical experiments on the ALFWorld embodied simulation environment and the WebShop online navigation benchmark demonstrate a 24.5% absolute improvement in task success rate and trajectory efficiency over mainstream baselines like the standard ReAct framework. Comprehensive ablation studies confirm the significant contribution of the reward-driven critique module in suppressing hallucination rates. This research bridges theoretical foundations of reinforcement learning and graph-based memory with autonomous agent workflows. Ultimately, the resulting architecture offers a practical, scalable reference framework for developing artificial intelligence technologies in complex, multi-step autonomous systems. Code is available at https://github.com/01Amez/RLAW_Implementation.","published":"2026-07-19T02:51:41Z","updated":"2026-07-19T02:51:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.17038v1","pdf_url":"https://arxiv.org/pdf/2607.17038v1","comment":"29 pages, 1 table, native TikZ/pgfplots diagrams. Code available at https://github.com/01Amez/RLAW_Implementation","journal_ref":"","doi":"","discovered_on":"2026-07-21","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:fx6YvEatX3","versioned_id":"fx6YvEatX3","title":"The Contingency Bottleneck: The Emergence of Protocol Competence in Small Language Models for Interactive Language Games","authors":[],"abstract":"Interactive learning assumes that models can already engage in meaningful, adaptive exchanges with other agents. Such exchanges require **contingency**: the ability to recognise and exploit structured dependencies between one’s own actions and another agent’s responses. However, contingency depends on a more basic capability: **protocol competence**. Before an agent can learn from interaction, it must first learn how to participate in interaction itself by following game rules, producing valid actions, and responding appropriately to other agents. We investigate protocol competence in small language models from the Qwen family, establishing a possible developmental sequence for interactive post-training in which demonstrations scaffold participation, enabling models to benefit from experience and improve credit assignment. Across five CLEMBench dialogue games using Qwen3.5-0.8B, we find that **51.3\\% of base-model interactions terminate due to protocol violations before reasoning can be evaluated**. This bottleneck is not resolved by model scaling or instruction tuning alone. We show that **scaffolded teacher demonstrations bootstrap protocol competence**, producing substantial improvements in interactive ability (+204\\% clemscore improvement). Once models can reliably participate, **self-improving reinforcement learning becomes effective**: a single round of self-generated reinforcement learning (self-ReST) yields large gains from a small number of successful trajectories. Comparing adaptive learning strategies, we find that **credit-weighted training provides the most reliable improvements**, reducing variance relative to uniform supervision. Together, these results suggest that interactive learning follows a staged trajectory: models must first acquire the competence to participate before they can exploit the contingencies generated by interaction.","published":"2026-07-18T11:03:05+00:00","updated":"2026-07-18T12:29:12+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=fx6YvEatX3","openreview_url":"https://openreview.net/forum?id=fx6YvEatX3","pdf_url":"https://openreview.net/pdf?id=fx6YvEatX3","comment":"EMNLP 2026 Workshop LMP Submission","journal_ref":"EMNLP 2026 Workshop LMP Submission","doi":"","venue":"EMNLP 2026 Workshop LMP Submission","venue_id":"EMNLP/2026/Workshop/LMP/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2607.16621","versioned_id":"2607.16621v1","title":"From Memory to Skills: Evidence-Grounded Co-Evolution Governance for Long-Horizon LLM Agents","authors":["Bo Tang","Yang Zhang","Guomian Zhuang","Wenqiang Wei","Gaoyang Zheng","Lindong Xie","Yanchao Tan","Feiyu Xiong","Qingyu Yang","Edward Chung","Zhiyu li"],"abstract":"Existing memory systems for long-horizon LLM agents often retrieve prior traces as passive context rather than converting them into executable capabilities. In this paper, we propose MSCE, a training-free Memory--Skill Co-Evolution framework that organizes agent experience into grounded step traces, reusable procedural policies, and declarative environmental cognition. MSCE crystallizes evidence-backed L2 policies with positive estimated gain into callable skills that retain evidence links, applicability boundaries, decision guidance, verification rules, and reliability estimates. It further introduces reflection-weighted value backfilling, which propagates sparse terminal feedback through dense local self-reflections to produce evidence-calibrated trace values for governing memory and skill evolution. Experiments on EvoAgentBench and LoCoMo demonstrate that MSCE significantly outperforms state-of-the-art skill-augmented and memory-driven agent baselines, exhibiting strong cross-domain transferability and lifelong-evolution capabilities.","published":"2026-07-18T03:46:22Z","updated":"2026-07-18T03:46:22Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.16621v1","pdf_url":"https://arxiv.org/pdf/2607.16621v1","comment":"Submitted into EMNLP'2026","journal_ref":"","doi":"","discovered_on":"2026-07-21","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2607.15845","versioned_id":"2607.15845v1","title":"Knowledge-Centric Agents for Workflow Generation","authors":["Zhendong Li","Lei Sun","Ruibo Ming","He Zhang","Danda Pani Paudel","Luc Van Gool","Jinjin Gu"],"abstract":"Workflow generation in visual creation systems such as ComfyUI demands not only syntactic accuracy but also expert-level reasoning over modular compositions. Existing large language model (LLM) approaches often treat this as a direct text-to-JSON generation task, struggling with structural brittleness and lacking the experiential knowledge required for effective design. We argue that successful workflow generation requires modeling knowledge itself, including its structure, hierarchy, and reasoning dynamics. To this end, we propose a knowledge-centric framework that learns to invert, inject, and infer with knowledge across multiple abstraction levels. We first perform knowledge inversion to distill hierarchical representations, ranging from full pseudo-codes and skeletons to high-level strategies, from large collections of real-world workflows. We then conduct knowledge injection through supervised fine-tuning, teaching the model to reason from task descriptions to strategies and from strategies to executable structures. During inference, the model performs reversible reasoning to synthesize executable workflows, augmented by self-refinement for structural coherence. Extensive experiments demonstrate that our method produces workflows with richer node diversity, more coherent structures, and higher execution success rates than existing systems, establishing a new foundation for knowledge-driven, agentic workflow generation.","published":"2026-07-17T11:03:01Z","updated":"2026-07-17T11:03:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.15845v1","pdf_url":"https://arxiv.org/pdf/2607.15845v1","comment":"Accepted to ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-20","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"openreview:HyhfhlbWGh","versioned_id":"HyhfhlbWGh","title":"Towards Long-Horizon Agents: A Survey","authors":["Guanting Dong","Xiaoshuai Song","Yuyang Hu","Jiajie Jin","Chenghao Zhang","Yifei Chen","Xiaoxi Li","Huaying Yuan","Xinyu Yang","Tongyu Wen","Jiejun Tan","Hongjin Qian","Shijue Huang","Junting Lu","Zhenyu Li","Wanjun Zhong","Yutao Zhu","Tat-Seng Chua","Zhicheng Dou","Ji-Rong Wen"],"abstract":"With the rapid advancement of LLM capabilities, expectations for AI agents are shifting from solving simple, single-turn tasks toward carrying out long-horizon tasks in the real world. We refer to such systems as long-horizon agents: agents that plan over extended horizons, interact with real-world environments, recover from their own mistakes, and adapt their strategies during execution. This capability is rapidly becoming the central bottleneck for practical agent intelligence. Despite this progress, the field still lacks a shared definition and taxonomy for long-horizon agents. Related concepts such as \"self-evolving\" or \"autonomous\" agents are often used interchangeably, none of which clearly captures what it means to build a long-horizon agent. This gap leaves the community without a principled way to attribute advances in long-horizon competence. This paper offers a unified landscape by framing long-horizon agency as the co-evolution of an externalized harness and an internalized optimization, and organizes the paper around six connected perspectives: Foundation, Evolution, Harness, Optimization, Application, and Frontier. We first formalize long-horizon agency as a harness-coupled decision process and distinguish it from neighboring concepts such as long-running execution, autonomy, and self-evolution. We then trace the field's evolution from prompt-level control to runtime agent systems, classifying existing work through the complementary lenses of externalized harnesses and internalized optimization. Building on this view, we organize five application forms of long-horizon agents by their interfaces, and review the corresponding benchmarks and resources. Finally, we discuss key challenges and frontier directions. Looking ahead, we hope this paper serves not only as a reference for existing work, but also as a foundation for building the next generation of capable, reliable long-horizon agents.","published":"2026-07-17T04:12:01+00:00","updated":"2026-07-17T04:12:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=HyhfhlbWGh","openreview_url":"https://openreview.net/forum?id=HyhfhlbWGh","pdf_url":"https://openreview.net/pdf?id=HyhfhlbWGh","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2607.15524","versioned_id":"2607.15524v1","title":"Recursive Harness Self-Improvement","authors":["Hyunin Lee","Jinglue Xu","Jeffrey Seely","Donghyun Lee","Matei Zaharia","Yujin Tang"],"abstract":"Under model--harness co-evolution, harnesses are not merely inference-time scaffolds but data-generating components whose execution traces can shape future foundation models. This motivates harness-in-the-loop learning: optimizing harnesses for both immediate agent performance and the quality of traces used for future model training. However, continually updating provider-built scaffolds is costly and labor-intensive. We therefore investigate whether optimizing user-constructed harnesses in a task-specific manner can improve execution-trace quality while remaining computationally lightweight and requiring only a few update iterations. To this end, we introduce Recursive Harness Self-Improvement (RHI), which represents the harness as a prompt-level specification of the agent loop and iteratively refines it using pairwise feedback over its own revision history. Across 30 synthetic machine-learning research tasks spanning quantitative finance, robotics, and pharmacy, a few RHI iterations suffice to substantially raise the performance ceiling of low-reasoning-effort agents, exceeding the corresponding maximum-reasoning-effort setting while reducing inference cost by up to 60%. We show that these gains arise primarily from improved task-specific context management through more effective inter-agent information flow rather than longer reasoning traces. Finally, we formalize this behavior as an information-theoretic hypothesis for RHI's implicit optimization objective, suggesting RHI as a practical algorithm for continual learning within the paradigm of model--harness co-evolution.","published":"2026-07-17T00:21:19Z","updated":"2026-07-17T00:21:19Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.15524v1","pdf_url":"https://arxiv.org/pdf/2607.15524v1","comment":"This work addresses the first half of the model-harness coevolution loop","journal_ref":"","doi":"","discovered_on":"2026-07-20","source":"arXiv","sources":["arXiv"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2607.16345","versioned_id":"2607.16345v1","title":"AEVAL: From Anecdotal to Deterministic Testing for Agentic Skill Workflows","authors":["Tejas Singh Anand","Yuet Ying Christina Wang","Wanting Jiang","Steve Masson","Tian Zheng","Bingjie Zhou"],"abstract":"Modern agentic systems increasingly rely on skills: installable packages of natural language and code that teach an LLM agent to perform a domain task. As skill repositories grow, developers need automated quality signals on every change, yet evaluation today is largely anecdotal: a developer asks an agent to \"try the skill,\" watches a demo, and forms a subjective impression. This yields neither reproducibility across runs nor comparability across versions, and scales poorly to marketplaces where one regression can silently break dozens of downstream workflows. We present AEVAL (Agentic Evaluation), a CI-integrated framework that replaces this practice with a deterministic, reproducible test pipeline for agentic skills. Every skill change triggers a test event: the skill runs against a developer-declared evaluation contract (eval.config) inside an automated executor, emitting a structured, evidence-grounded quality signal that downstream CI can route on. A key ingredient is a structural separation between executor and grader, preventing a subtle but pervasive failure mode: an agent that silently self-corrects during execution and then grades its own patched outputs as passing. Our contributions are: (i) a deterministic, change-triggered evaluation protocol with per-skill contracts and per-run artifact schemas; (ii) a formalization of self-correction bias as a distinct failure mode of naive agentic evaluators; (iii) an executor/grader separation with a first-attempt grading rule and explicit self-correction tracking; and (iv) a tiered, grounded-evidence fix-suggestion scheme (LV1 causal, LV2 quality) posted as inline merge-request comments. Validated on real skills in a production agentic stack across multiple agent SDKs, AEVAL converts spurious 100% pass rates into reproducible first-attempt fail signals with an auditable record of every executor fix.","published":"2026-07-16T21:33:05Z","updated":"2026-07-16T21:33:05Z","categories":["cs.SE","cs.AI","cs.LG","cs.PF"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.16345v1","pdf_url":"https://arxiv.org/pdf/2607.16345v1","comment":"8 pages, 1 figure, 1 table","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=tpEflAIlo5","openreview_venues":["ICML 2026 Workshop AgenticUQ Poster"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:rWh5beVLq4","versioned_id":"rWh5beVLq4","title":"Meta-Competition Dynamics: An Axiomatic Topological Functional Flow Theory of \"Learning How to Compete\"","authors":["Jincheng Zhang"],"abstract":"This paper establishes a unified, rigorous, and axiomatic mathematical framework for the Meta-Competition Analysis Theory (MCAT), formalizing the core paradigm of \"Learning How to Compete.\" Traditional game-theoretic and meta-learning frameworks often collapse into infinite cognitive regressions when learning algorithms themselves dictate the evolving interactive environments. To overcome this limitation, we transcend traditional strategy spaces by constructing a high-order bundle configuration space over a Banach operator manifold, treating competing agents as dynamical system generators rather than static point-strategists. We formulate five fundamental axioms—Cognitive Separability, Feedback Differentiability, Non-Degenerate Meta-Evolution, Interacting Asymptotic Ergodicity, and Competitive Reflective Consistency—to guarantee the topological and dynamical coherence of meta-competitions. Under these axioms, we prove the existence of a Meta-Competition Equilibrium (MCE) via the Kakutani-Fan-Glicksberg fixed-point theorem on infinite-dimensional variational inequalities, defined by the condition: < D_{Phi_i} V_i(Phi*), Psi_i - Phi_i* > <= 0. Furthermore, we derive the Liouville-Vlasov topological fluid evolution equation to govern the macroscopic probability density of the joint meta-operators, uncovering an intrinsic ergodicity breaking mechanism characterized by a non-zero measure EB = lim_{T -> infinity} 1/T * integral_{0 to T} | integral_{B} f(Phi) * rho(Phi, t) dPhi - f(Phi(t)) |^2 dt. This restriction bounds the system into isolated cognitive islands. Finally, utilizing Morse-Smale theory on infinite-dimensional Hilbert manifolds, we present a High-Order Topological Robustness Theorem, proving that under conditions of hyperbolicity and transversal intersections, the global phase structure of meta-competition remains structurally stable against arbitrary operator-norm perturbations. This work provides the ultimate mathematical foundation for high-dimensional multi-agent evolution, strategic autonomy, and long-term dynamical control in complex adaptive systems.","published":"2026-07-16T06:19:59+00:00","updated":"2026-07-16T06:19:59+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=rWh5beVLq4","openreview_url":"https://openreview.net/forum?id=rWh5beVLq4","pdf_url":"https://openreview.net/pdf?id=rWh5beVLq4","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.14611","versioned_id":"2607.14611v1","title":"Bad Memory: Evaluating Prompt Injection Risks from Memory in Agentic Systems","authors":["Soham Gadgil","David Alexander","Sai Sunku","Franziska Roesner"],"abstract":"A growing class of agentic systems maintain persistent state across sessions through memory files, behavioral preferences, and knowledge bases. While this makes agents more useful and self-improving, it also creates a new attack surface for prompt injections in which malicious instructions can be embedded within persistent files and influence future behavior. In this work, we study prompt injection attacks in memory-based agentic systems using a sandboxed synthetic workspace. We evaluate two agentic systems, Anthropic Claude Code and OpenAI Codex, across four models: Claude Haiku 4.5, Claude Opus 4.7, GPT-5.2, and GPT-5.5. Our results show that although it is difficult to make an agent overwrite its own memory files using untrusted external content, payloads already planted in those files can successfully attack current and future sessions. Attack success and payload persistence vary substantially across systems, models, adversarial goals, and multi-session attack sequences. These findings show that persistent memory changes the threat model for prompt injection and motivate defenses that protect memory updates without removing useful agent adaptation.","published":"2026-07-16T06:13:48Z","updated":"2026-07-16T06:13:48Z","categories":["cs.CR","cs.AI","cs.MA"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2607.14611v1","pdf_url":"https://arxiv.org/pdf/2607.14611v1","comment":"Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.14396","versioned_id":"2607.14396v1","title":"CatalogAgent: A Supervisor-mediated Self-Learning System Enabling Context Engineering for GenAI Models","authors":["Zhu Cheng","Zhenming Wang","Yu","Tang","Dan Liu","Bryan Zhang","Athanasios N. Nikolakopoulos","Pranav Souri Itabada","Jing Zhang","Chih-Chi Chou","Peng Gao","Fatemeh Mansoori","Bharat Bojja","Sarath Chander","Sameer Thombare","Umit Batur","Tarik Arici"],"abstract":"Product catalogs are the backbone of e-commerce sites, yet a large number of structured attributes (SAs) -- such as material, color, and shape -- often have missing values. Typically, SA values are extracted from product information, including titles and descriptions. While LLM-based generator-evaluator frameworks have demonstrated effectiveness for SA prediction -- where an LLM generates SA values and another evaluates them -- they face challenges when the Generator and Evaluator produce conflicting outputs, as either component can make mistakes. We introduce \\texttt{CatalogAgent}, a novel agentic system that continuously improves Generator and Evaluator models for e-commerce catalog enrichment. When disagreements arise from (1) internal conflicts between the LLM-based Generator and Evaluator, or (2) external feedback from sellers on LLM outputs, a Supervisor Agent intervenes to mediate these conflicts and make final decisions. The system also incorporates a Memory Base and a Memory Summarizer that stores Supervisor Agent activities from individual cases and aggregates patterns into learnings. These learnings are fed back to the worker Generator and Evaluator LLMs, enabling self-improvement without human intervention. Through context engineering -- injecting learnings and insights into worker LLMs' contexts -- the system successfully transfers the Supervisor's capabilities to the Generator and Evaluator, improving their performance by 15.24\\% and 13.98\\%, respectively. Our experiments demonstrate a new paradigm of Supervisor Agent-mediated self-learning systems for improving generative AI model accuracy.","published":"2026-07-15T22:20:59Z","updated":"2026-07-15T22:20:59Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.14396v1","pdf_url":"https://arxiv.org/pdf/2607.14396v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.15314","versioned_id":"2607.15314v1","title":"Cura 1T: Specialized Model for Agentic Healthcare","authors":["actAVA AI",":","Haolin Chen","Leon Qi","Steve Brown","Deon Metelski","Tao Xia","Joonyul Lee","Qixuan Wang","Kevin Riley","Frank Wang","Weiran Yao"],"abstract":"Healthcare spans high-stakes communication, expert reasoning, and workflow execution, yet specialized LLMs that cover these use cases together remain limited. A healthcare model must handle patient consultation, clinical reasoning over text and images, interactive diagnosis, and electronic health record (EHR) tool use. These capabilities fail in different ways, and a narrow update for one task can degrade another. We present Cura 1T, a healthcare-specialized LLM trained through a human-gated self-evolution loop. In each evolution round, a training agent plans a target capability, trains the model, evaluates benchmark trajectories, and refines the data mixture from observed failures. This data-centered loop improves the model through targeted synthetic and curated examples rather than a single generic medical-data update. Across the healthcare evaluation suite, Cura 1T ranks at or near the top among frontier baselines, while remaining competitive on out-of-domain reasoning and agentic benchmarks.","published":"2026-07-15T22:05:23Z","updated":"2026-07-15T22:05:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.15314v1","pdf_url":"https://arxiv.org/pdf/2607.15314v1","comment":"Model: https://actava.ai/cura Docs: https://actava.ai/cura/docs Github: https://github.com/actava-ai/Cura","journal_ref":"","doi":"","discovered_on":"2026-07-20","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.13884","versioned_id":"2607.13884v1","title":"Experience Memory Graph: One-Shot Error Correction for Agents","authors":["Wenjun Wang","Yuchen Fang","Fengrui Liu","Zibo Liang","Kai Zheng"],"abstract":"Large Language Model (LLM) agents have shown remarkable capabilities in autonomous decision-making by generating sequential trajectories of states, actions, and observations. However, in complex, long-horizon tasks, these agents frequently suffer from compounding errors and struggle to recover from failures. Existing self-correction mechanisms rely on prompt-based reflection, which is inherently brittle, incurs heavy time and API costs due to iterative trial-and-error loops, and produces task-specific memory that may be hard to generalize to new scenarios. To address this, we propose Experience Memory Graph (EMG), a framework that reformulates agent failure recovery as a graph matching problem. At training time, we convert both failed exploration trajectories and successful expert trajectories into directed action decision graphs. By matching these graphs, we extract common subgraphs (successful workflows) and graph edit paths that explicitly indicate how to correct failures (e.g., which actions to add, delete, or relabel under a given observation), and store them in a memory graph with intra-task nodes and cross-task edges. At test time, EMG retrieves relevant insights and guides the agent in a single, loop-free execution. Experiments on ALFWorld and ScienceWorld show that EMG consistently outperforms state-of-the-art reflection baselines in success rate and average reward, while requiring no test-time trial-and-error.","published":"2026-07-15T14:33:15Z","updated":"2026-07-15T14:33:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.13884v1","pdf_url":"https://arxiv.org/pdf/2607.13884v1","comment":"11 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.14178","versioned_id":"2607.14178v1","title":"ReasFlow: Assisting Reasoning-Centric Scientific Discovery in Applied Mathematics via a Knowledge-Based Multi-Agent System","authors":["Yutong He","Daibo Li","Guohong Li","Jiahe Geng","Zhengyang Huang","Can Ren","Zekun Zhang","Yifan Liu","Shuchen Zhu","Hengrui Zhang","Boao Kong","Ming Sun","Shu Li","Chenyi Li","Jiang Hu","Kun Yuan","Zaiwen Wen","Pingwen Zhang"],"abstract":"Recent advances in Large Language Models have fueled autonomous AI agents capable of tackling complex scientific tasks, yet existing automated research systems remain predominantly focused on empirically driven domains with quantitative benchmarks, leaving theory-driven discovery, particularly in mathematically grounded disciplines requiring rigorous proofs and synthesis of domain knowledge, largely underexplored. Key challenges include the difficulty of verifying theoretical reasoning at scale, insufficient reasoning ability for autonomous frontier exploration, and a scarcity of procedural heuristics in the literature. We introduce ReasFlow, an end-to-end autonomous agent system for reasoning-centric scientific discovery that operationalizes a collaborative paradigm where the human expert acts as Principal Investigator while the agent executes rigorous derivations as a capable graduate student. ReasFlow incorporates (i) a robust internal verification loop that audits logical coherence and corrects fundamental errors prior to human inspection, and (ii) an automated knowledge retrieval and self-improvement mechanism that proactively surfaces both declarative facts and overlooked procedural heuristics, substantially reducing expert intervention. The system unifies literature synthesis, algorithm design, theorem proving, experimentation, and manuscript preparation in a single system. Deployed to autonomously generate five complete research papers with rigorous theoretical and empirical content from minimal prompts, ReasFlow consistently achieves the highest evaluation scores among state-of-the-art open-access baselines under a curated LLM-based review rubric. ReasFlow is publicly accessible via the ReasLab platform, providing a collaborative workspace for AI-assisted theoretical research. Github repo: https://github.com/ReasLab/ReasFlow.git.","published":"2026-07-15T13:27:20Z","updated":"2026-07-15T13:27:20Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.14178v1","pdf_url":"https://arxiv.org/pdf/2607.14178v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.12790","versioned_id":"2607.12790v1","title":"Who Grades the Grader? Co-Evolving Evaluation Metrics and Skills for Self-Improving LLM Agents","authors":["Xing Zhang","Guanghui Wang","Yanwei Cui","Ziyuan Li","Wei Qiu","Bing Zhu","Peiyang He"],"abstract":"Self-evolving agent systems improve by creating, revising, and retiring their own skills, but every such loop rests on a hidden assumption: a reliable evaluation metric already exists. In many real applications it does not. We make three claims. First, metrics can be \\emph{evolved}: our metric loop searches compositions of small drawback detectors under a full evolutionary lifecycle, trained to agree with a ten-item anchored reference set, regularized by consensus over unlabeled outputs, and audited against a held-out anchor it never reads, yielding a transparent, inspectable metric rather than an opaque judge. Second, since no metric exists to beat, the yardstick is recovering what an accurate metric would have enabled, and \\emph{Double Ratchet}, our co-evolution of the metric with a lifecycle-managed skill loop, does so: across code generation (MBPP+), enterprise text-to-SQL (Spider~2.0-Snow), and reference-free report generation, it retains 88--110\\% of the held-out lift achieved by the same skill loop driven by ground truth or the best available rubric. Third, safety comes from anchor discipline plus outer audits: removing anchor guards collapses the metric into a vacuous detector while removing the lifecycle does not; and when evolved skills gamed the report rubric, an independent judge caught it, one detector repaired it, and a task-aware judge then preferred the evolved outputs over the pre-evolution baseline in 77\\% of decided pairs. We argue this failure-expecting architecture is the right default wherever no reliable automatic verifier exists.","published":"2026-07-14T14:02:50Z","updated":"2026-07-14T14:02:50Z","categories":["cs.AI","cs.CL","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.12790v1","pdf_url":"https://arxiv.org/pdf/2607.12790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.12625","versioned_id":"2607.12625v2","title":"KnowAct-GUIClaw: Know Deeply, Act Perfectly, Personal GUI Assistant with Self-Evolving Memory and Skill","authors":["Yunxin Li","Jinchao Li","Shibo Su","Zhenran Xu","Chenrui Zhao","Tongshu Bian","Xiaoman Liang","Meishan Zhang","Baotian Hu","Min Zhang"],"abstract":"OpenClaw has emerged as a leading agent framework for complex task automation, yet it faces insufficient cross-platform GUI interaction support and a well-built self-evolution mechanism. These flaws limit its adaptation to diverse device ecosystems and prevent performance improvements through continuous learning from execution experience. To resolve these issues, we propose the Know Deeply, Act Perfectly paradigm for personal assistants, which holds that accumulated user interaction and task-running experience directly improve execution accuracy and efficiency, unifying cognitive comprehension and operational execution. Based on this paradigm, we introduce KnowAct-GUIClaw, a novel Know-Route-Act-Reflect framework designed to address OpenClaw's GUI manipulation deficits and break through its cross-platform and recursive self-improvement constraints. First, the host agent leverages accumulated interaction experience and task-relevant knowledge for long-horizon task decomposition and allocation (Know). Second, a pluggable GUI subagent with an experience-attributable memory system (Know) and self-evolving skill library (Act), enabling seamless cross-platform migration and fast-path integration. Especially, this framework continuously stores user profiles and feedback to improve the accuracy of task decomposition and tool calls. Extensive experiments across Android, iOS, HarmonyOS and Windows show that KnowAct-GUIClaw achieves superior efficiency, accuracy and cross-platform adaptability. Especially, the GUIClaw with open-source Kimi-2.6 models achieves the best performance (64.1%) on the long-horizon MobileWorld benchmark, beating all agentical frameworks and closed-source agentical models, e.g., Seed-2.0-Pro and GPT-5.5. Additionally, the knowledgeable memory and execution skills supported by our framework are transferable across diverse base models, improving by 8.5% with Kimi-2.6.","published":"2026-07-14T11:04:01Z","updated":"2026-07-15T04:41:47Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.12625v2","pdf_url":"https://arxiv.org/pdf/2607.12625v2","comment":"29 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2607.13104","versioned_id":"2607.13104v1","title":"Self-Improvements in Modern Agentic Systems: A Survey","authors":["Zhe Ren","Yimeng Chen","Dandan Guo","Guowei Rong","Tonghui Li","R. B. Xiong","Qingfeng Lan","Wenyi Wang","Li Nanbo","Yibo Yang","Mingchen Zhuge","Jürgen Schmidhuber"],"abstract":"Self-improving autonomous agents are moving from research prototypes to deployed systems. The primary goal is controllable evolution, or adaptation, from experience with minimal or even no human input. This survey frames modern self-improving agents as adaptive systems that convert experience into accumulated capability gains. We offer a system-level framework that represents a modern agent as a configuration coupling a foundation model with an operational scaffold of prompts, memory, tools, and control logic. Within this framework, self-improvement is formalized as a self-induced update operator that obtains and commits updates to model parameters or scaffold components. We organize prior work by update target and by the signals that drive change, then review applications and discuss evaluation, before closing with open problems and future directions. For convenience, we track technical updates on https://github.com/selfimproving-agent/awesome-Self-Improving-Agents.","published":"2026-07-14T09:12:57Z","updated":"2026-07-14T09:12:57Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.13104v1","pdf_url":"https://arxiv.org/pdf/2607.13104v1","comment":"97 pages, 12 figures. Project page: https://selfimproving-agent.github.io/ Repository: https://github.com/selfimproving-agent/awesome-Self-Improving-Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=JyrcEL77Nq","openreview_venues":["Under review for TMLR"],"relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2607.13091","versioned_id":"2607.13091v1","title":"Self-Improving AI Coding Agents Through Accumulated Behavioral Rules: A Closed-Loop Framework","authors":["Aditya Aggarwal","Nahid Farhady Ghalaty"],"abstract":"LLM-based coding agents repeat the same classes of mistakes across sessions because they lack a mechanism to retain corrections from human review feedback. We present a closed-loop framework in which every accepted review comment is codified as a persistent behavioral rule, progressively expanding the set of error classes the agent can self-detect. The framework combines an accumulating rule set in a version-controlled instruction file, a self-review checklist executed before code submission, and automated validation that ensures rule set integrity as it grows. In deployment across a 35+ service microservices platform, the rule set grew from 5 to 18 behavioral rules, 15+ language-specific standards, and a 15-item self-review checklist, all derived from real review feedback. We present empirical results from 11 recorded working sessions spanning code generation, PR review, incident investigation, and cross service refactoring. We observe that accumulated rules shift review effort from low-level correctness toward design-level validation, achieve a measured 0% recurrence rate for ruled-against error classes, and transfer across heterogeneous agent interfaces. We compare our approach against related work in experiential LLM learning (Reflexion, ExpeL, Voyager) and automated code review (CodeReviewer, SWE-bench agents), showing that our framework achieves persistent cross-session learning without weight updates, operates on production codebases rather than synthetic benchmarks, and addresses an orthogonal dimension (behavioral consistency over time) that existing benchmarks do not measure. The result is a coding agent that improves with every review cycle, accumulating the engineering wisdom of its human collaborators without changing a single model weight.","published":"2026-07-13T21:13:46Z","updated":"2026-07-13T21:13:46Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.13091v1","pdf_url":"https://arxiv.org/pdf/2607.13091v1","comment":"Already presented and accepted in - 32nd ICE IEEE/ITMC Conference (ICE 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2607.12042","versioned_id":"2607.12042v1","title":"SymbOmni: Evolving Agentic Omni Models via Symbolic Concept Learning","authors":["Jinxiu Liu","Jianru Li","Tanqing Kuang","Xuanming Liu","Kangfu Mei","Yandong Wen","Weiyang Liu"],"abstract":"Visual generation is increasingly ubiquitous in diverse domains, from text-to-image/video synthesis to multimodal interactive creation. Yet prevailing monolithic models remain fundamentally constrained by their inability to learn cumulatively and evolve autonomously, which is a limitation we term the \"perpetual novice\" problem. They lack mechanisms for structuring experience into reusable knowledge and therefore rely on brittle, \"from-scratch\" reasoning for each task, resulting in poor compositional generalization and inefficient knowledge retention. Motivated by these limitations, we propose SymbOmni, an agentic omni-model designed for cumulative evolution through Symbolic Concept Learning. At its core is the Symbolic Concept Box, an optimizable memory module that abstracts low-level operations into reusable Symbolic Workflow Instructions. SymbOmni operates through an induction-transduction cycle: experiences are abstracted into symbolic concepts (induction), which are then adaptively composed to solve novel tasks (transduction). The training is done by verbalized backpropagation with language-based feedback to enable continuous self-improvement without gradient-based model fine-tuning. Comprehensive experiments validate that (I) SymbOmni significantly outperforms existing agent-based systems for iterative creation and also surpasses closed-source models (e.g., Nano Banana, GPT-Image-1) in both image quality and task success rates; (II) SymbOmni effectively reduces token consumption by over 40% while maintaining competitive generation quality; and (III) SymbOmni enables effective continual learning by achieving cumulative gains across multiple online-learning benchmarks and setting a new state of the art.","published":"2026-07-13T18:00:34Z","updated":"2026-07-13T18:00:34Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.12042v1","pdf_url":"https://arxiv.org/pdf/2607.12042v1","comment":"ECCV 2026 (49 pages, 10 figures, project page: https://spherelab.ai/symbomni)","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.11689","versioned_id":"2607.11689v1","title":"From World Action Models to Embodied Brains: A Roadmap for Open-World Physical Intelligence","authors":["Yuanzhi Liang","Xufeng Zhan","Haibin Huang","Chi Zhang","Xuelong Li"],"abstract":"Artificial general intelligence ultimately requires agents that can reason and act in the physical world. Action models, vision-language-action policies, and world models have advanced this goal, while World Action Models (WAMs) are particularly promising because they connect candidate interventions with predicted consequences. However, progress remains fragmented: models use incompatible action spaces and prediction targets, datasets and tasks follow different conventions, and runtime systems expose limited interfaces for reuse and evaluation. We review the evolution toward WAMs and organize these limitations into three coupled gaps: model roles and representations, objectives and standardization, and system composition. Building on this analysis, we propose a co-evolution roadmap for physical intelligence centered on the \\emph{embodied brain}, a long-term model target for integrating multimodal context, comparing candidate interventions, and issuing state-transition or capability requests rather than direct actuator commands. WAMs provide promising prototypes for its predictive functions, while a physical harness grounds model outputs through tools, controllers, verification, and trace logging. Shared contracts align heterogeneous models, data, tasks, and embodiments, and closed-loop post-training converts verified interaction into reusable experience. Together, these components define a modular physical-intelligence stack for adaptive and self-improving embodied agents.","published":"2026-07-13T15:22:56Z","updated":"2026-07-13T15:22:56Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2607.11689v1","pdf_url":"https://arxiv.org/pdf/2607.11689v1","comment":"Ongoing work","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2607.11288","versioned_id":"2607.11288v1","title":"Mako: A Self-Evolving Agentic Operating System (SE-AOS) for Autonomous Web Exploitation","authors":["Praneeth Narisetty","Shiva Nagendra Babu Kore"],"abstract":"We introduce the Self-Evolving Agentic Operating System (SE-AOS): a new class of AI agent that treats exploit capability as a mutable, versioned kernel it extends at runtime, observing its own failures, synthesising new capabilities, proving them against a live target, and hot-loading them back into itself. Mako is the first SE-AOS instance for security research and the autonomous web exploitation engine developed within LaunchSafe. LaunchSafe builds autonomous security agents for continuous offensive testing and agent-driven security research; Mako is the core engine behind that platform. On the public XBOW validation-benchmarks, 104 containerised, CTF-style web applications spanning 26 vulnerability classes across three difficulty tiers, Mako achieves full-suite coverage: it drives every one of the 104 targets to emit a cryptographically fresh, per-build flag, under a verification regime that makes fabricated or memorised results impossible. Our central result is a law of autonomous exploitation: once a capability exists and is discoverable, difficulty collapses; capability, not reasoning, is what is scarce, together with an architecture and formalism that turn that law into a self-improving system. Mako further runs a gated self-evolution loop that proposes, sandboxes, and commits improvements to its own agents and rules when fitness does not regress. We deliberately withhold the operational results, payloads, exploit chains, and tool source, because a system that reduces full-spectrum web exploitation to a repeatable, machine-speed pipeline is dual-use research of concern. We publish the science; we withhold the weapon.","published":"2026-07-13T09:07:30Z","updated":"2026-07-13T09:07:30Z","categories":["cs.CR","cs.AI","cs.MA"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2607.11288v1","pdf_url":"https://arxiv.org/pdf/2607.11288v1","comment":"13 pages, 10 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2607.11175","versioned_id":"2607.11175v1","title":"The Path to Self-Evolving Clinical Systems: Scaling Medical Agents from Assistance to Autonomy","authors":["Chunzheng Zhu","Lei Tian","Bohan Tan","Ziqi Zhou","Yuxuan Sun","Yijun Wang","Chengchao Lv","Yilin Wen","Yijun He","Jinghao Lin","Yihang Chen","Cheewei Tan","Qianshan Wei","Lei Zhao","Bin Pu","Kenli Li","Yuan Xue","Jianxin Lin"],"abstract":"The growing ability of large language models and vision language models to jointly interpret and reason over images and text is reshaping medical agents, moving them from task specific predictors toward autonomous systems that perceive, reason, plan, remember, and act in clinical environments. This work departs from the capability first perspective of existing literature and instead begins from clinical deployment, asking what tasks, contamination resistant benchmarks, and interactive training environments are required before medical agents can be trusted in practice. Medical agents are formalized as sequential decision making systems under partial observability, together with a three level autonomy taxonomy spanning assisted, cooperative, and fully autonomous operation. The field is organized along a unified scaling spine consisting of framework scaling, capability scaling, and environment scaling. Within this framework, clinical environment scaling, the integration of tools, data, and clinical gyms, is identified as the most actionable yet underexplored direction for agents operating in PACS, EHR, and FHIR ecosystems. Clinical self evolution, where agents improve through interaction with their environments rather than parameter scaling alone, is further positioned as a key research frontier, drawing insights from self improving agents, agent gyms, and test time compute scaling. Applications across radiology, pathology, ophthalmology, and hospital workflows are examined together with deployment challenges including hallucination, cascading failures, and fairness. By consolidating more than 300 references, with particular emphasis on advances from 2025 to 2026, this work provides a roadmap toward trustworthy, self improving medical imaging systems for real clinical practice.","published":"2026-07-13T07:16:50Z","updated":"2026-07-13T07:16:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.11175v1","pdf_url":"https://arxiv.org/pdf/2607.11175v1","comment":"Project page: https://github.com/zhcz328/Awesome-Medical-Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.11084","versioned_id":"2607.11084v1","title":"NVAITC AI Scientist: A Governed End-to-End Research System -- A Hypertension GWAS Case Study","authors":["Eddie Huang","Ken Liao","Iven Fu","Yang-Hsien Lin","Chao-Shun Zhan","Andy Liao","Virginia Chen","Johnson Sun","Pika Wang","Richard Huang","Jiun-Cheng Jiang","Ting-Yuan Liu","Hsing-Fang Lu","Ray Y. Lee","Chi-Chou Liao","Simon See","Fuu-Jen Tsai"],"abstract":"Agentic research systems are emerging as a new paradigm for coordinating scientific workflows beyond isolated model inference, code generation, or statistical analysis. However, deployment in institutional biomedical environments requires governed mechanisms for research planning, data access, workflow orchestration, evidence tracking, reproducibility, and human oversight. We present NVAITC AI Scientist (NAIS), a governed end-to-end agentic research system designed to support domain-general scientific workflows while keeping protected data within institutional privacy boundaries. NAIS integrates proposal review, execution planning, governed computational routing, reproducible workflow orchestration, evidence generation, and scientist-in-the-loop oversight. We validate NAIS in a real-world hypertension genome-wide association study (GWAS) using hospital-linked genotype and electronic health record (EHR) data from 286,422 individuals under an aggregate-only data policy. The agent planned cohort extraction, orchestrated GWAS execution, generated quality-control summaries, and drafted publication-oriented outputs. Human-AI review identified phenotype discrepancies and enabled iterative refinement of the hypertension definition. After reconciliation, the agent-orchestrated GWAS reproduced established hypertension loci, including FGF5, ATP2B1, CNNM2, FTO, and GRB14, with the strongest signal at FGF5 reaching $-\\log_{10}(p) \\sim 70$. As a secondary demonstration, NAIS also supported a drug-induced liver injury prediction workflow, achieving a multimodal graph neural network AUC of 0.842. These results demonstrate that governed agentic research systems can support scalable AI-assisted biomedical discovery while producing outputs comparable to expert-led workflows.","published":"2026-07-13T04:53:53Z","updated":"2026-07-13T04:53:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.11084v1","pdf_url":"https://arxiv.org/pdf/2607.11084v1","comment":"22 pages, 6 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.10878","versioned_id":"2607.10878v1","title":"LOGOS: A Living Logic for AI Agent Teams That Evolve With Humans","authors":["Yuma Ichikawa","Yamato Arai","Kosaku Kimura","Akira Sakai","Hiromichi Kobashi"],"abstract":"AI agents are evolving from answer engines into persistent teams that use tools, delegate work, learn from experience, and modify the artifacts that shape their future behavior. The defining question for deployment is no longer merely what agents can do, but who controls what they are allowed to become. We introduce logos, a pluggable layer for self-evolution and governance that strengthens existing multiagent frameworks rather than replacing them. logos compiles heterogeneous multimodal inputs, including documents, images, audio, tables, databases, APIs, and human instructions into versioned agent packs containing agents, tools, knowledge, tests, permissions, and policies. During operation, it transforms agent activity into portable, auditable event traces and applies fail-closed verification across frameworks and backends. Every learned prompt, memory, skill, tool, role, or workflow remains an untrusted release candidate until held-out execution evidence, human-controlled policy, and explicit authorization permit its promotion. This architecture enables \"verifiable human-agent loop engineering\": agents can act, ask, learn, and propose improvements, while humans can steer objectives, permissions, approvals, and irreversible actions without interrupting continuous operation. logos provides a living logic for accountable automation. Agents may evolve at machine speed, but only evidence and human authority can close the loop.","published":"2026-07-12T18:46:42Z","updated":"2026-07-12T18:46:42Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.10878v1","pdf_url":"https://arxiv.org/pdf/2607.10878v1","comment":"58 pages, 14 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:7EKwYevzIN","versioned_id":"7EKwYevzIN","title":"Adapting SCoRe to Single-Player Dialogue Games: Initial Experiments on PLAYPEN","authors":[],"abstract":"Large Language Models (LLMs) are increasingly deployed as autonomous agents that solve tasks through multi-step interactions. However, most post-training methods are designed for single-turn reasoning or instruction-following tasks and provide limited supervision for long-horizon conversational decision making. In this work, we investigate whether Self-Correction via Reinforcement Learning (SCoRe), originally proposed for single-step mathematical reasoning and code generation, can improve agentic performance in multi-turn dialogue games. We adapt SCoRe to the PLAYPEN benchmark by fine-tuning Qwen3.5-9B on five single-player dialogue games using interaction-level rewards and iterative self-correction. Experimental results show that the resulting model substantially improves performance on the trained single-player games and further generalizes to unseen multi-player dialogue games, increasing the overall ClemScore from 41.18 to 43.31. Although a slight decrease is observed on the aggregate StatScore, the model largely retains its general language understanding and reasoning capabilities. These findings demonstrate that self-correction reinforcement learning is an effective approach for improving long-horizon conversational agent behavior beyond single-step reasoning tasks.","published":"2026-07-12T18:37:34+00:00","updated":"2026-07-18T12:29:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=7EKwYevzIN","openreview_url":"https://openreview.net/forum?id=7EKwYevzIN","pdf_url":"https://openreview.net/pdf?id=7EKwYevzIN","comment":"EMNLP 2026 Workshop LMP Challenge Submission","journal_ref":"EMNLP 2026 Workshop LMP Challenge Submission","doi":"","venue":"EMNLP 2026 Workshop LMP Challenge Submission","venue_id":"EMNLP/2026/Workshop/LMP_Challenge/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.10350","versioned_id":"2607.10350v3","title":"ABot-AgentOS: A General Robotic Agent OS with Lifelong Multi-modal Memory","authors":["Jiayi Tian","Shiao Liu","Yuting Xu","Jia Lu","Zihao Guan","Honglin Han","Di Yang","Minqi Gu","Yifei Qian","Tianlin Zhang","Yanqing Zhu","Zeqian Ye","Menglin Yang","Fei Wang","Xu Hu","Xiuxian Li","Wei Zhang","Shihui Su","Yiyan Ji","Jingbo Wang","Ziteng Feng","Jiaheng Liu","Zhaoxiang Zhang","Xiaolong Wu","Zixiao Tang","Zhining Gu","Yang Cai","Linbo Zheng","Jingjing Ma","Mingyang Yin","Zedong Chu","Wenbin Tang","Mu Xu"],"abstract":"Recent VLM and VLA systems have improved robotic perception and action prediction, yet long-horizon embodied agents still require a general runtime layer for reasoning, memory, tool use, verification, and cross-embodiment execution. We present ABot-AgentOS, a general robotic Agent Operating System that sits above low-level controllers and provides a deliberative agent layer for scene-conditioned planning, context-isolated skill execution, multi-stage verification, multi-modal memory, and edge-cloud collaboration. To evaluate such systems, we introduce EmbodiedWorldBench, an executable benchmark with 16 indoor, outdoor, and hybrid scenes, four difficulty levels, and over 200 tasks involving navigation, object search, NPC dialogue, dynamic events, and trace-grounded scoring. ABot-AgentOS further introduces Universal Multi-modal Graph Memory, a persistent source-grounded substrate that converts dialogue, visual observations, spatial context, temporal relations, and task traces into typed nodes and edges. A failure-driven self-evolution loop converts diagnosed memory failures into gated runtime evo-assets that are promoted only to later evaluation splits, preventing current-split ground-truth leakage while enabling continual improvement. On an initial EmbodiedWorldBench subset, ABot-AgentOS improves over a single-controller baseline in both task success and goal completion. Across memory benchmarks, ABot-AgentOS Static achieves 87.5 on LoCoMo, 59.9 on OpenEQA EM-EQA, 88.6 on Mem-Gallery, and 76.5 Acc@All on NExT-QA; self-evolution further improves LoCoMo to 88.7, OpenEQA to 60.4, and Mem-Gallery to 89.0. These results suggest that a general Agent OS layer can improve long-horizon embodied execution while providing persistent, auditable memory for continual interaction.","published":"2026-07-11T15:24:43Z","updated":"2026-07-17T17:27:03Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.10350v3","pdf_url":"https://arxiv.org/pdf/2607.10350v3","comment":"Code: https://github.com/amap-cvlab/ABot-AgentOS Project page: https://amap-cvlab.github.io/ABot-AgentOS","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.13070","versioned_id":"2607.13070v1","title":"Falsifiable Release Gates for Self-Improving Systems","authors":["Deepak Soni"],"abstract":"Safety claims on self-improving agent runtimes are almost always self-graded: a policy file, a guardrail, or a README commitment. We describe falsifiable release gates, and a methodology to build and validate such systems, such that every new capability must pass a pre-specified, machine-verifiable acceptance suite before it ships, and a fixed set of standing invariants is preserved at each gate. I think we applied the method in the Antahkarana, an open runtime, via seven gates from basic observability into a self governing loop that suggests changes to its own policy. no action goes to an effector without a safety-critical property capability token minted by a control ring is exhaustively machine-checked over the one million recorded reachable state space of a bounded model and re-checked against execution traces. A purposely broken model gives the shortest counterexample, so the checker has teeth, is apparent. The self-enhancement loop is positively Constrained: the entire write surface is policy rules, tightening changes. may auto-apply loosening changes always require a human merge and a proposal autoclosed is one that mispredicts its own effect; We publish the acceptance measured results for all the seven gates, define precisely the scope of each claim (a bounded of the coordination skeleton (not the learned components) and free the runtime, either command line tools and the gate suite, so the results reproduce, and gates can run against other agent frameworks. Reviewers may repeat the single command central non-bypass in seconds.","published":"2026-07-11T06:06:34Z","updated":"2026-07-11T06:06:34Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.13070v1","pdf_url":"https://arxiv.org/pdf/2607.13070v1","comment":"14 pages, 8 figures. Software, gate suite, run artifacts, and TLA+ specification are open source","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.09839","versioned_id":"2607.09839v1","title":"Exploring Agentic Workflows for Generating High Quality Math Visual Aids","authors":["Rizwaan Malik","Ashna Khetan","Isabel Sieh","Samin Khan"],"abstract":"Mathematical diagrams play a crucial role in K 12 education, both as problem components and as scaffolding for student comprehension. However, current AI tools, including Large Language Models (LLMs), struggle to reliably generate accurate and pedagogically sound visual diagrams, even when provided with detailed descriptions. A significant gap therefore remains in the reliable generation of diagrams for middle school mathematics. To address this, we introduce an agentic workflow that enables LLM agents to evaluate the quality of generated visuals and use this feedback to iteratively improve their outputs. This self improvement loop aims to enhance the accuracy and educational appropriateness of AI generated diagrams. Our research investigates two questions. First, can LLMs accurately generate quality assurance questions for a visual aid given specific criteria for visual quality? Second, given valid quality assurance questions, can Vision Language Models effectively evaluate generated K 12 visual aids and use the resulting feedback to improve them iteratively? We conduct an exploratory evaluation of our agentic workflow and identify key areas for improvement, including stronger spatial reasoning and more comprehensive coverage of diagram features in the generated quality assurance questions. Our results provide preliminary evidence that this approach can improve the reliability and educational value of AI generated mathematical diagrams.","published":"2026-07-10T17:12:38Z","updated":"2026-07-10T17:12:38Z","categories":["cs.AI","cs.CV","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.09839v1","pdf_url":"https://arxiv.org/pdf/2607.09839v1","comment":"13 pages, 9 figures. Exploratory course project on agentic workflows for generating and evaluating K 12 mathematical diagrams","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.08331","versioned_id":"2607.08331v1","title":"ArtMine: Discovering and Formalizing Artistic Processes","authors":["Kaustubh Kumar","Ashutosh Ranjan","Vivek Srivastava","Blessin Varkey","Shirish Karande"],"abstract":"Understanding how artworks are created requires reasoning about the iterative decisions, material operations, and contextual influences that shape artistic production. While recent generative AI systems can synthesize artworks with high fidelity, they primarily model distributions over finished artifacts rather than the creative processes underlying their creation. In practice, artistic workflows are only partially documented through fragmented sources such as archival records, preparatory studies, correspondence, etc., making process-level understanding difficult to formalize computationally. In this work, we introduce ArtMine, a framework for discovering and formalizing artistic processes from heterogeneous historical evidence. Our approach synthesizes heterogeneous artwork evidence into a structured repository, from which a Peircean abductive agent infers evidence-grounded production steps. These steps are converted into a compositional graph and rendering prompt, then optimized through self-reflection over deviations between the generated and reference artworks. We provide a preliminary proof-of-concept case study using open-domain historical sources across multiple artists and artistic movements, demonstrating that fragmented documentary evidence can support coherent, interpretable, and auditable representations of artistic workflows. By modeling creative processes rather than only final artifacts, our work moves toward process-centred human-AI co-creativity systems that can support artistic interpretation, creative education, reflective collaboration, and computational studies of cultural production.","published":"2026-07-09T10:16:53Z","updated":"2026-07-09T10:16:53Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2607.08331v1","pdf_url":"https://arxiv.org/pdf/2607.08331v1","comment":"47 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.08252","versioned_id":"2607.08252v1","title":"AutoPersonas: A Multi-Timescale Loop Engine for Open-Ended Persona Evolution","authors":["Mengchen Li"],"abstract":"Long-term persona agents must remain identifiable while adapting to new events, relationships, evidence, and social conditions. We identify self-locking as a runtime failure mode in continuing persona-life loops: locally plausible events keep appearing while the generated life collapses toward familiar environments, weak relationships, suspended decisions, and stale life stages. We trace this failure to model-level convergence toward high-probability behavioral channels and system-level context gravity from State, memory, history, and environment summaries. We introduce AutoPersonas, a multi-timescale life-environment engine for bounded persona-level recursive self-evolution. It separates environment-side Occurrences, accumulated Observations, and persona State. Its OSO loop admits divergent future-facing material while requiring evidence-governed absorption before State or reachability changes. A three-year compressed simulation exposed environment watermark shells, occurrence-hardening gaps, slow-change accumulation failures, recursive indecision, and weak relationship persistence. An eight-model 40-day stress test generated 1,600 events and found mean rolling 5-day action-category repetition of 95.2%-97.6%, with all models crossing 90% by day 11. Semantic re-keeping found 79.0%-88.0% macro-theme repetition across all direct-loop runs. In a same-runtime 40-day A/B, context-slice masking plus per-sample divergence targeting reduced macro-theme repetition from 61.8% to 36.3% and roughly doubled cumulative theme count. A juvenile-goblin fictional-world run reproduced the anti-fixation regime without hard real-world intrusions. These results support a bounded claim: separating controlled divergence from evidence-governed absorption can reduce persona-environment self-locking while preserving identity continuity.","published":"2026-07-09T08:56:30Z","updated":"2026-07-09T08:56:30Z","categories":["cs.AI","cs.CL","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.08252v1","pdf_url":"https://arxiv.org/pdf/2607.08252v1","comment":"52 pages, 13 figures/tables, ancillary public-safe evaluation artifacts included","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.07820","versioned_id":"2607.07820v2","title":"DeepSearch-World: Self-Distillation for Deep Search Agents in a Verifiable Environment","authors":["Xinyu Geng","Xuanhua He","Sixiang Chen","Yanjing Xiao","Fan Zhang","Shijue Huang","Haitao Mi","Zhenwen Liang","Tianqing Fang","Yi R. Fung"],"abstract":"Training tool-use agents to improve from their own experience remains challenging, as supervised fine-tuning relies on fixed teacher-distilled trajectories, while sparse-reward reinforcement learning provides weak supervision for long-horizon interactions. We present DeepSearch-Evolve, a self-distillation framework for web agents built on DeepSearch-World, a deterministic and verifiable environment with reproducible search and page-reading tools. DeepSearch-World contains 420K multi-hop QA tasks constructed from entity-level random walks and supports key agentic cognitive behaviors useful for self-evolving, including progress verification, grounded reflection, and failure recovery. DeepSearch-Evolve iteratively performs trajectory generation, filtering, data mixing, and fine-tuning to train stronger agents. Without distillation from more capable models, DeepSearch-World-9B achieves competitive performance compared with open-source agents, reaching 31.2% on BrowseComp, 61.5% on GAIA, and 93.4% on HotpotQA, showing that verifiable environments enable scalable self-evolution for long-horizon web agents. We will release the environment, 420K training pool, validation set, model, and code to facilitate future research on self-improving deep search agents.","published":"2026-07-08T18:03:41Z","updated":"2026-07-13T12:09:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.07820v2","pdf_url":"https://arxiv.org/pdf/2607.07820v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2607.07467","versioned_id":"2607.07467v1","title":"SpaCellAgent: A Self-Evolving LLM-Based Multi-Agent Framework for Trajectory Analysis","authors":["Songhan Wang","Haoang Chi","He Li","Zhiheng Zhang","Jiayan Yuan","Cheems Wang","Hao Peng","Xinwang Liu","Wenjing Yang"],"abstract":"Spatial and Single-cell transcriptomics are transformative in deciphering cellular dynamics. As the fundamental paradigm for reconstructing cell developmental paths, trajectory inference (TI) is critical. However, existing methods require extensive manual intervention and proficiency in heterogeneous tools, posing a significant barrier to efficient TI analysis. To bridge this gap, we propose SpaCellAgent, an autonomous large language model (LLM) multi-agent framework that automates end-to-end spatiotemporal analysis and narrative generation. SpaCellAgent utilizes a multi-agent architecture for strategic workflow planning, a dynamic tool-orchestration engine for adaptive algorithm selection, and a self-evolution module that iteratively refines performance through feedback. We evaluate SpaCellAgent on six heterogeneous datasets encompassing complex temporal developmental trajectories, diverse sequencing platforms, and spatially-resolved tissue architectures. SpaCellAgent consistently demonstrates over 40\\% improvement in analytical efficiency while maintaining expert-aligned performance. By converting natural language specifications into optimized analytical workflows and fully automating the pipeline, SpaCellAgent democratizes advanced spatiotemporal modeling and establishes a scalable, agent-driven paradigm for computational biology. The code and materials are available at https://github.com/LittleXH-shw/SpaCellAgent.","published":"2026-07-08T14:31:46Z","updated":"2026-07-08T14:31:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.07467v1","pdf_url":"https://arxiv.org/pdf/2607.07467v1","comment":"27 pages, 19 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.07321","versioned_id":"2607.07321v1","title":"From Atomic Actions to Standard Operating Procedures: Iterative Tool Optimization for Self-Evolving LLM Agents","authors":["Haipeng Ding","Yuexiang Xie","Zhewei Wei","Yaliang Li","Bolin Ding"],"abstract":"Tool utilization enables Large Language Model (LLM) agents to interact with the real world and resolve complex tasks. However, existing agent frameworks predominantly rely on static toolsets composed of granular atomic actions (e.g., basic file I/O or single-turn search), which forces agents to reinvent low-level logic for every recurring workflow, leading to increased reasoning overhead and failure rates. In this study, we propose that agents can achieve self-evolution by synthesizing these atomic actions into reusable Standard Operating Procedures (SOPs), which function as callable higher-order tools that encapsulate multi-step logic. We further introduce EvoSOP, a framework that empowers agents to extract SOPs from execution trajectories and iteratively optimize the toolset through a systematic lifecycle of construction, merging, evaluation, and pruning. Extensive experiments demonstrate that EvoSOP significantly boosts task success rates while substantially reducing the number of interaction rounds compared to baselines. Our analysis also reveals that iterative tool optimization fosters reliable and efficient tool-use patterns, providing a scalable pathway for the development of self-evolving agents.","published":"2026-07-08T12:09:49Z","updated":"2026-07-08T12:09:49Z","categories":["cs.AI","cs.CL","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.07321v1","pdf_url":"https://arxiv.org/pdf/2607.07321v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.06452","versioned_id":"2607.06452v1","title":"From Voting to Agent Collaboration: Answer-Type-Aware LLM Pipelines for BioASQ 14b","authors":["Taeyun Roh","Eunha Lee","Wonjune Jang","Sohyun Chung","Junha Jung","Jaewoo Kang"],"abstract":"Biomedical question answering requires not only accurate extraction of information from scientific literature but also reliable integration of evidence across multiple documents. This study presents a question-type-specific large language model (LLM) framework for BioASQ 14b Task B, designed to improve answer robustness and evidence grounding in biomedical question answering. Rather than applying a single prompting strategy to all questions, the framework selects different inference procedures for yes/no, factoid, and list questions according to their distinct reasoning and evaluation requirements. For yes/no questions, snippet shuffling and self-reflection are used to reduce sensitivity to evidence ordering and improve decision stability. For factoid questions, full-snippet input is combined with chain-of-thought-based in-context learning to support accurate biomedical entity identification. For list questions, a multi-agent architecture is employed, in which evidence extraction, candidate generation, answer verification, and final aggregation are handled collaboratively. Preliminary experiments on BioASQ 13b were used to identify effective inference strategies for each question type, and the resulting framework was subsequently evaluated in the official BioASQ 14b Task B challenge. In the official evaluation, our framework showed competitive performance across multiple batches and achieved first place in the factoid subtask of Batch 4. These results demonstrate the effectiveness of combining question-type-specific inference, ensemble prediction, and agent-based verification for reliable biomedical question answering.","published":"2026-07-07T16:12:51Z","updated":"2026-07-07T16:12:51Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.06452v1","pdf_url":"https://arxiv.org/pdf/2607.06452v1","comment":"15 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2607.06074","versioned_id":"2607.06074v1","title":"Prompt Coach: An Empirical Evaluation of an Agentic Tutor for Learning Prompt Engineering in Software Development","authors":["Rohit Mehra","Kapil Singi","Vikrant Kaulgud","Vibhu Saujanya Sharma","Swapnajeet Gon Choudhury","Swati Sharma","Adam P. Burden","Majd Sakr"],"abstract":"Prompt engineering has emerged as a critical yet undertaught skill for software developers, one that traditional learning approaches are ill-equipped to support given its evolving, interactive, and context-dependent nature. In this paper, we introduce Prompt Coach (PC), an agentic tutor that helps developers learn how to craft high-quality code-generation prompts through Socratic guidance embedded in-flow within their IDE. PC evaluates prompt quality across multiple dimensions and surfaces targeted questions to guide self-correction, grounded in the developer's codebase and the behavior of the target LLM. We present an early empirical study with 15 professional developers combining quantitative prompt quality scoring with qualitative perception measures. Participants showed statistically significant improvements after a single 60-minute session, with the largest gains across dimensions commonly overlooked by developers. They also reported strong trust, high adoption readiness, and unanimous agreement that PC improved their prompt-writing skills.","published":"2026-07-07T09:44:46Z","updated":"2026-07-07T09:44:46Z","categories":["cs.SE","cs.AI","cs.CY","cs.HC"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.06074v1","pdf_url":"https://arxiv.org/pdf/2607.06074v1","comment":"7 pages. To be published in the proceedings of 41st International Conference on Automated Software Engineering (ASE '26), October 12-16, 2026, Munich, Germany (Industry Showcase Track)","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2607.05750","versioned_id":"2607.05750v2","title":"ArtisanCAD: An Industrial-Level CAD Agent with Expert-Grounded Knowledge Distillation","authors":["Yunhan Xu","Qifeng Wu","Xunjin Li","Yuanwei Bin","Qingsong Yao","Jianghang Gu","Guan Wang","Weihao Lv","Huiyu Yang","Wenfa Luo","Jiao Xiang","Yuntian Chen","Shiyi Chen"],"abstract":"Computer-aided design (CAD) for industrial components requires long-horizon procedural modeling, robust feature dependencies, editable parametric geometry, and production-grade B-Rep execution. Existing text-to-CAD methods have made promising progress in generating CAD programs from natural-language descriptions, but they still struggle when user prompts are ambiguous, underspecified, or only describe high-level design intent. They also rarely exploit expert procedural knowledge naturally available in industrial workflows, such as CATIA operation recordings, macro logs, drawing notes, and engineering descriptions. We present ArtisanCAD, a skill-guided industrial CAD agent with expert-grounded knowledge distillation. The core of ArtisanCAD is CAD intermediate representation (CAD-IR), an executable procedural representation that encodes parameters, ordered operations, MCP tool bindings, dependencies, generated entities, and verification rules. CAD-IR plays two key roles: it first serves as the carrier for distilling expert CAD procedures into reusable parameterized skills; then it provides a procedural scaffold that turns vague or intermediate-level prompts into complete executable CAD operations. ArtisanCAD retrieves expert-derived skills, instantiates and revises CAD-IR, executes the resulting procedure through a dedicated CATIA-MCP backend, and uses multi-view visual feedback for iterative refinement, and finally generates production-ready B-Rep models. On the Text2CAD benchmark, CAD-IR improves generation from intermediate prompts by reducing mean Chamfer Distance from $14.83$ to $9.88$, showing its ability to bridge ambiguous textual intent and executable CAD construction. On four complex automotive components, CAD-IR enables expert CATIA recordings to be distilled into reusable skills, allowing ArtisanCAD to generate editable CATIA-native B-Rep models for new variant requests.","published":"2026-07-07T02:11:50Z","updated":"2026-07-08T02:05:52Z","categories":["cs.AI","cs.GR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05750v2","pdf_url":"https://arxiv.org/pdf/2607.05750v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.05382","versioned_id":"2607.05382v3","title":"Search Beyond What Can Be Taught: Evolving the Knowledge Boundary in Agentic Visual Generation","authors":["Haozhe Wang","Weijia Feng","Jinpeng Yu","Che Liu","Ping Nie","Fangzhen Lin","Jiaming Liu","Ruihua Huang","Jimmy Lin","Wenhu Chen","Cong Wei"],"abstract":"Visual generators excel at rendering, but they confidently fabricate what they do not know. User requests are unbounded, evolving, and deeply long-tailed: new characters, trending entities, post-cutoff events, and more. This world-knowledge bottleneck is structural: generators are trained on fixed corpora, but the visual world is open-ended. We construct SearchGen-20K and SearchGen-Bench, with 20,839 prompts spanning twelve failure categories and twenty-two domains, paired with a pre-executed multimodal SearchGen-Corpus-1M to support offline, reproducible research. On SearchGen-Bench, frontier open generators score only 21 to 28 out of 100, a 40-point collapse invisible to existing benchmarks. The natural remedy is to employ search tools, enabling agentic visual generation. However, we find that naive search fails: it retrieves indiscriminately, injecting noise into prompts the generator already handles. We trace the root cause to a generator-specific, evolving knowledge boundary: the divide between what a generator can internalize through training and what must remain in external context. Although this boundary is hard to specify in advance, we show that it is discoverable through a teach-then-search co-training framework. Even a minimal version of this co-training recipe produces monotonic improvement, laying the foundation for recursive self-improvement in visual generation that can meet world-knowledge-grounded requests. We release the full dataset, co-training corpus, and search corpus as a replayable harness for tool-augmented, world-knowledge-grounded visual generation.","published":"2026-07-06T17:56:12Z","updated":"2026-07-09T06:57:10Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2607.05382v3","pdf_url":"https://arxiv.org/pdf/2607.05382v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2607.05346","versioned_id":"2607.05346v1","title":"OptiAgent: End-to-End Optimization Modeling via Multi-Agent Iterative Refinement","authors":["Adriana Laurindo Monteiro","Nayse Fagundes","Gabriel Mattos Langeloh","Gustavo de Oliveira Kanno","Priscila Louise Aguirre","Thiago Costa Rizuti da Rocha","Victor Leme Beltran"],"abstract":"We propose OptiAgent, a multi-agent framework that, given a natural language description of an Operations Research problem, is able to output a solver-ready mathematical formulation as well as executable code. Our architecture prioritizes the mathematical modeling step, where dedicated agents extract structures, such as decision variables and constraints, enabling iterative self-correction. We introduce a novel multi-loop validation architecture with four specialized feedback mechanisms, each targeting a distinct failure mode such as misinterpretation, structural defects, mathematical inconsistencies, validation failures, and code errors. Alongside accuracy, our modular design improves the process of solving optimization problems by improving transparency, as each agent exposes its reasoning and feedback, making the full modeling process auditable. Our framework achieves state-of-the-art performance on 3 out of 4 benchmarks across LP, MILP, and Nonlinear Programming tasks, while remaining highly competitive on the remaining dataset.","published":"2026-07-06T17:27:16Z","updated":"2026-07-06T17:27:16Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05346v1","pdf_url":"https://arxiv.org/pdf/2607.05346v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2607.05297","versioned_id":"2607.05297v1","title":"MetaSkill-Evolve: Recursive Self-Improvement of LLM Agents via Two-Timescale Meta-Skill Evolution","authors":["Zefeng Wang","Minxi Yan","Jinhe Bi","Sikuan Yan","Volker Tresp","Yunpu Ma"],"abstract":"Recent LLM agents tackle increasingly long-horizon, open-ended tasks, and external skills, reusable procedural knowledge supplied to the agent, further extend this capability. However, a fixed, hand-authored skill is rarely optimal, and cannot adapt to the diversity of tasks an agent encounters. Self-improving agents address this by rewriting their own skill files from execution traces, yielding meaningful gains on challenging benchmarks. Yet such self-evolution remains non-recursive: it improves only the task skill (what the agent does) while the improvement procedure (how it improves) is authored once and held fixed. We introduce MetaSkill-Evolve, a two-timescale framework that makes agentic skill improvement recursive: every branch carries both a task skill $s$ and a branch-local meta-skill $m=(ψ,σ,α,π,\\varepsilon)$ whose five components parameterise the Analyzer, Retriever, Allocator, Proposer, and Evolver agents of the improvement pipeline. Task skills evolve on a fast loop while the meta-skill evolves on a slower one under the same pipeline applied to itself, with no additional model or objective. With all five pipeline agents sharing a single frozen backbone, MetaSkill-Evolve outperforms no-skill, static-skill, and single-level evolution baselines on three agentic benchmarks (OfficeQA, SealQA, ALFWorld), improving held-out test accuracy over the raw backbone by +23.54, +16.09, and +1.92 points respectively.","published":"2026-07-06T16:40:23Z","updated":"2026-07-06T16:40:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05297v1","pdf_url":"https://arxiv.org/pdf/2607.05297v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2607.05202","versioned_id":"2607.05202v1","title":"EvoAgentBench: Benchmarking Agent Self-Evolution via Ability Transfer","authors":["Xingze Gao","Chuanrui Hu","Hongda Chen","Pengfei Yao","Zhao Wang","Yi Bai","Zhengwei Wu","Yunyun Han","Xiaofeng Cong","Jie Gui","Yafeng Deng","Teng Li"],"abstract":"Agent self-evolution in long-horizon LLM systems is largely procedural: useful experience is not merely stored information, but reusable procedures for searching, debugging, and verification. Yet current evaluations do not isolate this form of transfer. Agent benchmarks test single-episode task solving; memory benchmarks target information retention rather than procedural reuse. We introduce EvoAgentBench, a benchmark for agent self-evolution via Ability-guided transfer across four agentic domains: web research, algorithmic reasoning, software engineering, and knowledge work. EvoAgentBench extracts trace-grounded Abilities from agent executions, canonicalizes them into operational units, and builds domain-specific Ability Graphs linking tasks that share procedural overlap. By design, every test task is backed by verified training-side Ability support. Across a 528/267 train/test split, two scaffolds, and three backbones, curated Ability content transfers reliably across model families, but no current automatic method sustains positive gain in all settings. EvoAgentBench shifts self-evolution evaluation from aggregate accuracy comparison to fine-grained diagnosis of experience encoding, routing, and uptake. The benchmark is publicly available at https://huggingface.co/datasets/EverMind-AI/EvoAgentBench.","published":"2026-07-06T15:17:09Z","updated":"2026-07-06T15:17:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.05202v1","pdf_url":"https://arxiv.org/pdf/2607.05202v1","comment":"15 pages, 2 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.04631","versioned_id":"2607.04631v1","title":"Formal Disco: Scalable Open-Ended Generation of Formally Verified Programs","authors":["Gabriel Poesia","Simon Henniger","Tzu-Han Hsu","Yilun Du","Nada Amin"],"abstract":"The cost of producing code is rapidly diminishing with increasingly capable AI agents, while quality assurance of generated programs has not kept pace. Formal verification provides the strongest possible guarantees, but the ability of AI models to work with verification-aware languages is hindered by the scarcity of human-written examples of programs in those languages. To tackle this prevalent data scarcity issue, we propose Formal Disco: a distributed system for coordination of LLM-based workers that can be easily applied to open-ended synthetic data generation at scale. We use Formal Disco to share tasks and programs between three classes of workers: \"initiators\", which read random READMEs from open-source repositories and documentation snippets to sketch a related verified program, \"fixers\" which take compiler and verifier feedback and attempt to resolve issues, and \"extenders\" that take working programs and propose patches to expand them. Formal Disco records all agent-generated traces and uses them both for initial distillation from a stronger model as well as self-improvement. We also propose a principle of maximum entropy for synthetic program generation, and use entropy maximization via iterative supervised fine-tuning to learn to generate increasingly diverse programs over time. We release large datasets of synthetic verified programs in three languages - Dafny, Verus, and Frama-C -, and fine-tune open models for verification-relevant tasks, often matching or exceeding the performance of Claude Opus 4.5. Overall, our work offers a path to create synthetic data at scale for formal reasoning domains and overcome the long-standing data barrier.","published":"2026-07-06T03:31:14Z","updated":"2026-07-06T03:31:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.04631v1","pdf_url":"https://arxiv.org/pdf/2607.04631v1","comment":"Code: https://github.com/metareflection/formal-disco Datasets: https://huggingface.co/collections/metareflection/formal-disco","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2607.03726","versioned_id":"2607.03726v1","title":"SelfMem: Self-Optimizing Memory for AI Agents","authors":["Shu Yang","Junchao Wu","Derek F. Wong","Di Wang"],"abstract":"While current AI agents support increasingly long context windows, tool use, and skill execution for long-horizon tasks, they still require memory systems to effectively leverage historical experience. Existing memory frameworks typically rely on fixed storage, retrieval, and summarization mechanisms, which can be rigid across different tasks and often require manual tuning. To address this limitation, we propose SelfMem, a self-optimizing memory framework. Inspired by prior work on self-improving AI, we follow the principle of \"teaching an agent to fish rather than giving it a fish.\" Instead of forcing the model to follow a predefined memory strategy or format, SelfMem provides an environment with memory tools and feedback signals that allow the agent to explore, evaluate, and refine its own memory strategy. Our results show that SelfMem consistently outperforms retrieval, compression, and agent-memory baselines on BEAM across conversation scales from 100K to 1M tokens. Compared with the strongest baseline, SelfMem improves the official score by 48.7%, 40.8%, and 41.9% at 100K, 500K, and 1M, respectively. Further question-type analysis shows broad robustness across diverse memory demands, and our optimization study shows that model-guided strategy refinement further improves performance.","published":"2026-07-04T06:27:19Z","updated":"2026-07-04T06:27:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2607.03726v1","pdf_url":"https://arxiv.org/pdf/2607.03726v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2607.03451","versioned_id":"2607.03451v1","title":"SkillOpt-Lite: Better and Faster Agent Self-evolution via One Line of Vibe","authors":["Yifei Shen","Bo Li","Xinjie Zhang"],"abstract":"While skill optimization for autonomous agents has gained traction, existing methods rely on complex pipelines. This leaves a fundamental question unaddressed: What constitutes a minimal viable pipeline for skill optimization, where every component is justified by theory or empirical necessity? We formalize skill optimization via Zeroth-Order (ZO) optimization, mapping classical counterparts (central difference, trust regions) to recent literature. Noting that unlike blind numerical perturbations in classical ZO, skill trajectories serve as interpretable debugging feedback. Grounded in Claude Code philosophy and PAC learning, we establish three principles for convergence and generalization: file-system-based trajectory exploration, consensus attribute mining, and independent validation gating. Eliminating redundancies, we propose SkillOpt-Lite. It accelerates convergence and outperforms full SkillOpt: improving LiveMath by +8.8 points on GPT-5.5 and +25.4 points on GPT-5.4-nano, allowing the nano model to surpass standard GPT-5.4 optimized by SkillOpt. Finally, we integrate our framework into production coding agents like VSCode Copilot, enabling developers to evolve agent skills via one line of vibe. Because our framework treats all agent components simply as standard editable code, this minimal pipeline naturally generalizes to full harness optimization (HarnessOpt). On SpreadsheetBench, HarnessOpt enables GPT-5.4-nano to achieve 0.7758 accuracy, outperforming the larger GPT-5.5 running standard pipelines (0.7620). Code is available at https://github.com/EvolvingLMMs-Lab/SkillOpt-Lite.","published":"2026-07-03T16:07:06Z","updated":"2026-07-03T16:07:06Z","categories":["cs.SE","cs.AI","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2607.03451v1","pdf_url":"https://arxiv.org/pdf/2607.03451v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.31422","versioned_id":"2606.31422v2","title":"Ask the World Before Acting: Environment Probing for Calibrated Agent World Models","authors":["Xinyuan Song","Zekun Cai"],"abstract":"Language agents acting over long horizons must maintain beliefs about tool states, object locations, graph edges, and subgoal dependencies. When these beliefs drift, failures can be fixed neither by longer reasoning traces nor by ordinary self-reflection, since the missing evidence lies in the environment. We formulate environment probing as a budgeted decision problem for structured agent world models: before acting, the agent may query the current value of one belief field, update its table, and pay one interaction step. We introduce EnvProbe, a simple scoring policy that combines task criticality, staleness, verbalized uncertainty, and dependency role. A type-stratified analysis separates the benefit of belief repair from the cost of displaced task actions and predicts different behavior for procedural and spatial beliefs. In three controlled environments with gold belief states, EnvProbe improves terminal world-state accuracy over periodic probing by 11.76 percentage points on procedural tool-dependency tasks, 3.79 points on spatial tasks, and 6.45 points overall. Ablations show that task-structural terms are the main source of the gains, while self-reported uncertainty is unreliable under confident wrong beliefs. The results suggest that agent calibration should be treated as an action-selection problem over environment evidence, not only as a model-internal reasoning problem.","published":"2026-06-30T09:45:49Z","updated":"2026-07-05T04:18:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.31422v2","pdf_url":"https://arxiv.org/pdf/2606.31422v2","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.31270","versioned_id":"2606.31270v1","title":"Learning from Failure: Inference-Time Self-Improvement for Computer-Use Agents","authors":["Xueqiao Sun","Xiaohan Wang","Ludwig Schmidt","Serena Yeung-Levy","Yuhui Zhang"],"abstract":"Computer-use agents, which leverage multimodal large language models (MLLMs) to operate computers and complete tasks, have attracted significant attention for their utility and versatility. A major challenge in developing these agents is collecting large-scale, high-quality trajectories. The standard approach generates synthetic data through a self-improving loop: an agent is placed in a verifiable environment and iteratively fine-tuned on its successful trajectories. Despite its effectiveness, this paradigm exploits only successful trajectories and discards the failed ones, even though failures carry rich information about a model's weaknesses. In this work, we explore a complementary failure-driven self-improvement loop, a data-centric paradigm that turns failed trajectories into agent improvements. Specifically, we employ an LLM to diagnose failure modes, propose inference-time solutions, and generate code patches -- lightly verified by humans -- that upgrade the agent. We validate this approach with the state-of-the-art OpenCUA-72B model on the OSWorld benchmark, improving the success rate from 42.3% to 48.9%, a gain of 6.6 percentage points, without any additional training cost and with only modest inference overhead. Our results demonstrate that failure-driven self-improvement is a viable complement to success-based pipelines, enabling more efficient agent improvement.","published":"2026-06-30T07:44:37Z","updated":"2026-06-30T07:44:37Z","categories":["cs.CV","cs.AI","cs.CL","cs.CY","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.31270v1","pdf_url":"https://arxiv.org/pdf/2606.31270v1","comment":"Published in ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:vyGxyPM2a0","versioned_id":"vyGxyPM2a0","title":"Agent KB: Leveraging Cross-Domain Experience for Agentic Problem Solving","authors":["Xiangru Tang","Tianrui Qin","Tianhao Peng","Ziyang Zhou","Daniel Shao","Peng Xia","He Zhu","Ge Zhang","Jiaheng Liu","Sirui Hong","Chenglin Wu","Wangchunshu Zhou"],"abstract":"Current AI agents cannot effectively learn from each other's problem-solving experiences or use past successes to guide self-reflection and error correction in new tasks. We introduce Agent KB, a shared knowledge base that captures both high-level problem-solving strategies and detailed execution lessons, enabling knowledge transfer across agent frameworks. Agent KB implements a novel teacher-student dual-phase retrieval mechanism where student agents retrieve workflow-level patterns for strategic guidance while teacher agents identify execution-level patterns for refinement. This hierarchical approach enables agents to break out of limited reasoning pathways by incorporating diverse strategies from external sources. Evaluations on the GAIA benchmark demonstrate substantial performance gains, with Agent KB improving success rates by up to 6.06 percentage points overall under pass@1. For SWE-bench code repair tasks, our system significantly improved resolution rates, with o3-mini achieving an 8.67 percentage point gain (23 percent to 31.67 percent) in pass@1. Our ablation studies demonstrate that the refinement module proves most critical, with its removal causing a 3.85% drop on challenging Level 3 tasks, highlighting that effective knowledge transfer necessitates both strategic guidance and execution-level refinement.","published":"2026-06-30T00:54:41+00:00","updated":"2026-06-30T14:02:58+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vyGxyPM2a0","openreview_url":"https://openreview.net/forum?id=vyGxyPM2a0","pdf_url":"https://openreview.net/pdf?id=vyGxyPM2a0","comment":"KnowFM @ ACL 2026","journal_ref":"KnowFM @ ACL 2026","doi":"","venue":"KnowFM @ ACL 2026","venue_id":"aclweb.org/ACL/2026/Workshop/KnowFM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.30774","versioned_id":"2606.30774v1","title":"What Drives Interactive Improvement from Feedback?","authors":["Bartłomiej Cupiał","Jan Łojek","Mikołaj Garstecki","Szymon Pobłocki","Alicja Ziarko","Piotr Miłoś"],"abstract":"We study when natural-language feedback produces improvement beyond the gains obtainable from repeated attempts alone. In multi-turn language agent setting, higher final accuracy can reflect useful feedback, but it can also arise from resampling, format correction, or additional test-time computation. To separate these effects, we introduce a controlled student-teacher protocol across Omni-MATH, Codeforces, BBEH Linguini, and ARC-AGI1, evaluating thirteen open-weight models in both student and teacher roles. We compare external feedback, self-feedback, and unguided self-refinement, while varying interaction history, task difficulty, and teacher access to privileged task information. Across settings, we find that multi-turn improvement is often not evidence of feedback use: self-generated feedback adds little beyond unguided self-refinement, whereas the strongest external teachers produce substantially larger feedback-specific gains, suggesting that useful feedback must provide guidance beyond generic retry. Dense student-teacher interaction matrices further show that interactive gains are driven more by the student's ability to use feedback than by the teacher's identity, although teacher choice remains important for a fixed student. These results suggest that feedback-based agents should be evaluated against repeated-attempt baselines, and that ability to act on feedback, not merely feedback availability, is a central bottleneck for interactive improvement. We release our controlled student-teacher evaluation framework at https://j-lojek.github.io/feedback-generation-is-a-bottleneck/.","published":"2026-06-29T18:06:36Z","updated":"2026-06-29T18:06:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.30774v1","pdf_url":"https://arxiv.org/pdf/2606.30774v1","comment":"9 pages, 7 figures, accepted to the RLxF Workshop at ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.30573","versioned_id":"2606.30573v1","title":"SWE-INTERACT: Reimagining SWE Benchmarks as User-Driven Long-Horizon Coding Sessions","authors":["Mohit Raghavendra","Anisha Gunjal","Aakash Sabharwal","Yunzhong He"],"abstract":"We introduce SWE-Interact, a new testbed for evaluating coding agents on multi-turn, interactive, user-driven software engineering tasks. Existing frontier SWE benchmarks typically provide complete requirements upfront and evaluate agents on autonomous implementation. In contrast, SWE-Interact places agents in a realistic developer workflow: a carefully designed user simulator starts with vague or incomplete instructions, progressively reveals requirements, inspects the agent's workspace, and provides targeted feedback, revisions, and new constraints until the full task goal has been handed off. Grounded in large-scale studies of real coding-agent interactions, this setup tests whether agents can discover user intent, adapt to evolving requirements, and build on their own prior work. Across a suite of frontier and open-weight models, we find that strong performance on single-turn SWE tasks does not reliably transfer to multi-turn, user-driven workflows: the best-performing models solve roughly 50% of single-turn baseline tasks but only 25% of the corresponding SWE-Interact tasks. The strongest models in our evaluation, including Opus 4.8 and GPT 5.5, start strong even in the face of vague initial instructions, persevere until all the requirements are surfaced by the user, integrate them better and write clean code. However, they still suffer from over-agentic coding, forgetting requirements and technical mistakes. Weaker models start poorly under ambiguity, give up early, forget or ignore instructions and rework their code more. Overall, SWE-Interact measures an orthogonal, real-world capability axis for frontier model development: interactive goal discovery and iterative refinement with a user in the loop.","published":"2026-06-29T17:17:45Z","updated":"2026-06-29T17:17:45Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.30573v1","pdf_url":"https://arxiv.org/pdf/2606.30573v1","comment":"-","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.29823","versioned_id":"2606.29823v1","title":"Experience Graphs: The Data Foundation for Self-Improving Agents","authors":["Gang Liao","Yujia He","Abdullah Ozturk","Zhouyang Li","Ying Wang","Zhitong Guo","Hongsen Qin","Yaobin Qin","Tao Yang","Zewei Jiang","Dianshi Li","Jort Gemmeke","Jiangyuan Li","Liyuan Li","Nathan Yan","Masha Basmanova","Uladzimir Pashkevich","Matt Steiner","Pedro Pedreira","Rob Fergus","Anirudh Goyal","Carole-Jean Wu","Gaoxiang Liu","Andrew Witten","Daniel J. Abadi"],"abstract":"The database community has repeatedly advanced the state of the art by recognizing that new workloads demand new system architectures. We argue that long-horizon agentic tasks -- code generation, scientific discovery, hardware design -- are such a workload. These agents explore: they generate artifacts, execute tools, observe failures, branch, and repair over hundreds of steps. This search produces a structured object we call an experience graph: executable artifacts, tool outputs, rewards, sibling comparisons, and causal lineage. Yet existing agent frameworks treat this experience as disposable state -- JSON checkpoints and session logs that cannot be recovered after a crash, queried across users, or materialized into training data. We propose Trellis: a data foundation that treats the experience graph as first-class, governed, queryable database state. The core insight is that search over experience graphs is a database access pattern. Frontier selection is a query, cross-session reuse is vector-seeded graph retrieval, training-data extraction is a materialized view, and reconstructing what an agent knew at any past step is a time-travel query. When the database owns the experience graph, agents become stateless compute, and crash recovery, horizontal scaling, and a closed-loop training flywheel emerge as architectural byproducts. We ground the design in KernelEvolve, a production accelerator-kernel optimizer at Meta, where cross-session reuse reaches a target speedup roughly 10x faster at 52% lower token cost. More broadly, Trellis turns inference-time search from disposable computation into a durable institutional asset: logs made databases reliable; experience graphs may make agents cumulative.","published":"2026-06-29T06:02:20Z","updated":"2026-06-29T06:02:20Z","categories":["cs.DB","cs.AI","cs.MA"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2606.29823v1","pdf_url":"https://arxiv.org/pdf/2606.29823v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.29713","versioned_id":"2606.29713v1","title":"SEVA: Self-Evolving Verification Agent with Process Reward for Fact Attribution","authors":["Aojie Yuan","Yi Nian","Haiyue Zhang","Zijian Su","Yue Zhao"],"abstract":"Hallucination is the reliability bottleneck for LLM-based agents, and fact attribution verifiers are the last line of defense -- yet today's verifiers emit only opaque binary labels, leaving agents unable to self-correct and operators unable to audit. We present SEVA, a structured verification agent that emits evidence alignments, step-by-step reasoning chains, calibrated confidence, and a six-category error diagnosis with actionable fixes. Training such an agent with RL is non-trivial: standard binary reward on multi-component output triggers advantage collapse -- within-group reward variance vanishes and the GRPO gradient disappears. We resolve this with a process reward that decomposes verification quality into five independent components weighted 70/30 toward process signals, restoring the gradient and inducing an implicit curriculum -- the agent first masters verification behavior (alignment 0.917 -> 0.997, format 72% -> 100%), then outcomes (F1 64.9 -> 69.0). Structured output further enables a Verify -> Reflect -> Probe -> Refine self-evolution loop, which over four rounds on a 7B model surfaces an unexpected structural finding: each round produces a benchmark-specialist, not a generalist (+15 pp on HaluEval, -10 to -14 pp on TruthfulQA in the same model, persistent at 4x data). On ClearFacts, SEVA-3B matches GPT-4o-mini (69.0 vs. 69.8 F1) while producing substantially richer, auditable output -- confirming a principle that should generalize: for any RL task with multi-component generation, reward granularity must match output granularity.","published":"2026-06-29T02:37:13Z","updated":"2026-06-29T02:37:13Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.29713v1","pdf_url":"https://arxiv.org/pdf/2606.29713v1","comment":"Accepted at AI4GOOD@ICML 2026 and FAGEN@ICML 2026. Code: https://github.com/Justin0504/Verifiable_agent","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.29315","versioned_id":"2606.29315v1","title":"Hierarchical Experimentalist Agents","authors":["Abhranil Chandra","Sankaran Vaidyanathan","Utsav Dhanuka","Varun Gandhi","Scott Niekum"],"abstract":"Large language models (LLMs) are increasingly used to take actions in the real world and support human decision-making, yet most agents rely on parametric knowledge, fixed post-training data, retrieval, or search. This paradigm breaks down in novel domains and for sophisticated queries that cannot be answered from prior knowledge alone. Knowing the laws of physics, for instance, does not by itself enable LLMs to answer queries or complete long-horizon tasks in a complex physical system. To address this, we introduce Hierarchical Experimentalist Agents (HExA), an in-context self-improvement framework to learn from active experimentation. HExA iteratively designs and refines query-relevant experiments, learns a reusable library of composable skills from experience, and integrates experimental evidence to answer queries or take actions. HExA is training-free, compatible with any black-box model, and does not require external supervision, oracles, or offline data. To evaluate active experimentation, we introduce Interphyre, a tool-calling benchmark built on the PHYRE 2D procedural physics environment, where agents propose interventions and test hypotheses through simulation APIs. Experiments show that current LLM agents struggle in these settings, especially on the hardest levels of Interphyre. Claude Sonnet 4.6 achieves only 2% success, while HExA improves the same model to up to 77% success. HExA also improves open-weight models and outperforms agentic baselines such as ReAct and Reflexion. Moreover, using only skills learned from easier levels and transferred without active experimentation, HExA achieves 44% success, demonstrating the reusability and generalization of its learned skills. Overall, HExA shows that learning through active experimentation can help agents discover useful knowledge, acquire reusable skills, and make efficient progress on novel long-horizon tasks.","published":"2026-06-28T10:21:55Z","updated":"2026-06-28T10:21:55Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.29315v1","pdf_url":"https://arxiv.org/pdf/2606.29315v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.29194","versioned_id":"2606.29194v1","title":"AI Trading's Alpha Singularity: Emergent Market Reasoning through Agent-to-Agent Self-Evolution","authors":["Yuqi Li","Siyuan Liu","Bingjun Liu"],"abstract":"Automated alpha mining holds the scoring function fixed and varies the search algorithm over it. A search that converges against a fixed scorer overfits whatever the scorer cannot penalize, a primary cause of the out-of-sample generalization gap. We treat the scoring function as a search artifact alongside the alpha factors and study what conditions make this joint search admissible. Sealed Joint Search (SJS) is a framework: a set of structural conditions on information flow in an autonomous-discovery system that prevent joint search from collapsing into self-confirmation while keeping the evaluator sealed. Conditions cover role decomposition, typed inter-role communication, provenance-sealed reads, versioned stores, and substrate-local promotion. Agora tests SJS empirically: five LLM agent classes communicate via three channels, evolving eight skill libraries, with alpha libraries built on AlphaGen operators. Three evaluators write reports aggregated into one brief, carrying forward disagreement instead of voting. We run Agora for 100 rounds on CSI 1000 and evaluate on a 91-day 2026 holdout sealed from all LLM inputs. Agora achieves holdout Sharpe +1.87; best baseline +1.334 at favorable seed and -0.755 cross-seed mean. Pre-loading Agora's two metrics into a frozen-library ablation recovers only +0.40 of the +2.25 Sharpe gap, and adding PPO without library evolution worsens the gap. The two metrics emerge rather than being designed. Caveats: single-seed run, short-side concentrated signal, intended for long-short.","published":"2026-06-28T04:41:00Z","updated":"2026-06-28T04:41:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.29194v1","pdf_url":"https://arxiv.org/pdf/2606.29194v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.28758","versioned_id":"2606.28758v1","title":"X-Mind: Efficient Visual Chain-of-Thought via Predictive World Model for End-to-End Driving","authors":["Bohao Zhao","Chengrui Wei","Guangfeng Jiang","Ruixin Liu","Xuejie Lv","Liu Liang","Sutao Deng","Xiuyang Fan","Pengkun Zheng","Jinyun Zhou","Rui Guo","Hanpeng Liu","Yutong Zheng","Yi Guo","Xinlong Zheng","Qingyu Luo","Zhuangzhuang Ding","Yu Zhang","Hang Zhang","Xianming Liu"],"abstract":"Predicting future states is essential for autonomous agents, yet current Vision-Language-Action (VLA) models fundamentally lack this capability, relying instead on reactive perception-action mapping. While integrating Predictive World Models (PWMs) addresses this gap, existing approaches either incur prohibitive cascaded latency or act as shallow terminal tasks that fail to deeply embed forward-looking reasoning. To endow VLA models with this reasoning capability, we propose X-Mind. Rather than treating PWMs as an external auxiliary module, this framework internalizes them as the Visual Chain-of-Thought (Visual CoT). By enforcing a world rollout prior to action, the model is constrained to imagine future evolution first, yielding a driving policy that is robustly grounded in environmental dynamics and aware of the future consequences its actions will unfold. The challenge here is efficiency, and we tackle it on two fronts. First, we introduce a compact representation of visual thinking: an abstract sketch that fuses a Bird's-Eye-View (BEV) layout with abstract driving priors (e.g., navigation intents and traffic rules). Rather than rolling out dense future frames, the model reasons over this sketch as a mental canvas; aided by a Deep Compression Autoencoder (DC-AE), a 12-frame future rollout is reduced to merely 96 tokens, alleviating the long-context computational bottleneck. Second, to accelerate generation further, we propose a recurrent block diffusion scheme that unrolls the denoising steps across the layers of the large drive model, folding iterative refinement into the backbone's one forward pass. Trained and validated on large-scale real-world data, X-Mind achieves competitive end-to-end driving performance, which makes it a highly practical, low-latency solution that successfully deploys large-scale cognitive reasoning directly onto resource-constrained vehicle platforms.","published":"2026-06-27T06:17:50Z","updated":"2026-06-27T06:17:50Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.28758v1","pdf_url":"https://arxiv.org/pdf/2606.28758v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.28570","versioned_id":"2606.28570v1","title":"Digitizing Coaching Intelligence: An Agentic Framework for Holistic Athlete Profiling using VLM and RAG","authors":["Deep Ghosal","Ishani Sen","Wazib Ansar","Amlan Chakrabarti"],"abstract":"Athlete assessment is a critical process for tracking physical progress and identifying elite talent. However, during mass recruitment drives, traditional methods rely on manual observation, which is inherently subjective and unscalable, or basic computer vision (CV) systems limited to quantitative repetition counting. These standard approaches lack the \"coaching intelligence\" required to evaluate qualitative physiological markers such as form degradation, spinal articulation, and fatigue. This paper presents a novel, LLM-based hybrid agentic framework for automated, holistic athlete profiling that strictly aligns with the Sports Authority of India (SAI) assessment protocols. Orchestrated via LangGraph, our dual-pipeline architecture synthesizes the geometric precision of CV (MediaPipe) for kinematic tracking with the semantic reasoning of Vision-Language Models (Llama-4-scout). To overcome the latency and token constraints associated with multimodal video processing, we introduce a 3 X 3 \"Smart Grid\" temporal chunking strategy, reducing computational overhead by over 88% while preserving critical temporal continuity. To ensure data integrity and mitigate hallucination, the framework pioneers an autonomous \"LLM-as-a-Judge\" self-correction loop that cross-references quantitative and qualitative metrics before persistence. Finally, we implement a dual-persistence Retrieval-Augmented Generation (RAG) pipeline utilizing a vector search engine (ChromaDB). This enables coaches to bypass rigid SQL databases and perform complex semantic queries (e.g., \"Identify athletes with high endurance but poor core rigidity\") using natural language. Experimental results demonstrate that this multi-agent approach significantly bridges the gap between raw biometric tracking and actionable coaching insights, offering a scalable, objective solution for national talent identification.","published":"2026-06-26T19:53:26Z","updated":"2026-06-26T19:53:26Z","categories":["cs.CV","cs.AI","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.28570v1","pdf_url":"https://arxiv.org/pdf/2606.28570v1","comment":"16 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.28279","versioned_id":"2606.28279v1","title":"Agentic Hardware Design as Repository-Level Code Evolution","authors":["Cunxi Yu","Chenhui Deng","Nathaniel Pinckney","Brucek Khailany"],"abstract":"We present HORIZON, a self-evolving agent framework that treats hardware design as repository-level code evolution. A Markdown harness is compiled into a project pack containing domain knowledge, an executable evaluator, an acceptance predicate, and a git/runtime policy; a hands-free agent loop then evolves an isolated git worktree, using repository operations for state management, tracing, and replay. This extends prior works of repository-scale self-evolution from EDA software systems, to hardware-design artifacts themselves. We evaluate our approach on ChipBench, RTLLM, Verilog-Eval, and nine CVDP categories, achieving 100\\% benchmark completion across all suites with a fully hands-free agentic loop. However, we do not claim that agentic AI for hardware design is solved: these benchmarks are controlled proxies for a much broader engineering problem in chip design. Section~\\ref{sec:discuss} examines the limitations of the current study and highlights open research challenges.","published":"2026-06-26T17:21:06Z","updated":"2026-06-26T17:21:06Z","categories":["cs.AR","cs.AI"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2606.28279v1","pdf_url":"https://arxiv.org/pdf/2606.28279v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.27492","versioned_id":"2606.27492v1","title":"QueenBee Planner: Skill-Evolving Communication Topologies for Token-Efficient LLM Multi-Agent Systems","authors":["Congjia Tian","Yuhang Yao","Jiaming Cui"],"abstract":"Large language model (LLM) multi-agent systems increasingly depend not only on how individual agents reason, but also on how agents are connected. This paper introduces QueenBee Planner, a framework that treats inter-agent communication topology as a retrievable and self-improving design skill. A pool of worker agents, the task adapter, and the scoring function are frozen; only an outer LLM planner learns to generate temporal communication DAGs specifying who sends information to whom, in which round, who merges messages, and who emits the final answer. Execution traces are distilled into evidence-backed design rules with three actions: \\emph{Preserve}, \\emph{Modify}, and \\emph{Avoid}. To prevent self-evolution from turning lucky runs or plausible but false explanations into policy, QueenBee uses held-out acceptance gates, variance-aware credit, motif-level attribution, transfer trust, insight falsification, and structural deduplication. We evaluate the method on Count-Frequency aggregation and Silo-Bench-style distributed coordination tasks. With fixed workers, self-evolved graph generation produces communication structures that improve over fixed topologies and cold generation. In the CF fulltest setting, the best generated graph reduces RMSE from 12.53 for the strongest fixed topology to 7.87 while also reducing messages, model calls, and token cost; Silo-style results show the same direction of improvement over cold and fixed-topology baselines. These results suggest that multi-agent systems can learn reusable architectural design knowledge rather than merely memorizing task answers.","published":"2026-06-25T19:16:51Z","updated":"2026-06-25T19:16:51Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2606.27492v1","pdf_url":"https://arxiv.org/pdf/2606.27492v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2606.26859","versioned_id":"2606.26859v2","title":"AgentX: Towards Agent-Driven Self-Iteration of Industrial Recommender Systems","authors":["Changxin Lao","Fei Pan","Guozhuang Ma","Han Li","Huihuang Lin","Jijun Shi","Kangzhi Zhao","Kun Gai","Mo Zhou","Qinqin Zhou","Quan Chen","Ruochen Yang","Shifu Bie","Shijie Yi","Shuang Yang","Shuo Yang","Wenhao Li","Wentao Xie","Xiao Lv","Xuming Wang","Yijun Wang","Yiming Chen","Yusheng Huang","Zhongyuan Wang","Zibo Zhao","Zijie Zhuang","Baoning Xia","Chao Liu","Chaoyi Ma","Chubo He","Dawei Cong","Feng Jiang","Gang Wang","Guilin Xia","Hanwen Xu","Jiahong Xie","Jiahui Qiao","Jian Liang","Jiangfan Yue","Jing Wang","Jinghan Yang","Jinghui Jia","Kan Qin","Lei Wang","Ming Li","Peilin Song","Pengbo Xu","Qiang Luo","Ruiming Tang","Shiyang Liu","Shuxian Jin","Tao Wang","Tao Zhang","Xiang Gao","Xianghan Li","Yingsong Luo","Yiwen Ning","Yongcheng Liu","Yueyang Liu","Yuan Guo","Zhaojie Liu","Zhenkai Cui"],"abstract":"Recommendation algorithm iteration is moving from an artisanal, engineer-bound process toward an industrialized research loop, but this transition remains blocked by a structural execution bottleneck: the idea-to-launch cycle still depends on human engineers to generate hypotheses, modify production code, launch A/B experiments, and attribute online results. Innovation therefore scales linearly with headcount rather than compounding with evidence, compute, and accumulated experimental knowledge. We present AgentX, a production-deployed multi-agent system that fundamentally restructures this production function. AgentX operates as a self-evolving development engine: it autonomously generates, implements, evaluates, and learns from recommendation experiments at a scale and pace that no manual workflow can sustain. The system orchestrates four tightly coupled stages in a closed loop. A Brainstorm Agent synthesizes evidence from historical experiments, system architecture, data analysis, and external research into ranked, executable proposals. A Developing Agent translates each proposal into production-ready code through repository-grounded generation and multi-dimensional reliability verification. An Evaluation Agent conducts safe online rollout with guardrail-vetoed A/B judgment, converting both successes and failures into structured knowledge assets. A Harness Evolution layer (SGPO) then distills execution trajectories into semantic-gradient updates that continuously sharpen the agents themselves -- making the system not merely automated, but self-improving.","published":"2026-06-25T10:42:28Z","updated":"2026-06-26T10:04:52Z","categories":["cs.AI","cs.CL","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26859v2","pdf_url":"https://arxiv.org/pdf/2606.26859v2","comment":"Authors are listed alphabetically by their first name","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:IUltZSgLMm","versioned_id":"IUltZSgLMm","title":"Self-Improving Agents in the Era of Experience: A Survey of Self- to Meta-Evolution","authors":["Che Jiang","Jincheng Zhong","Yu Fu","Kai Tian","Junlin Yang","Kaikai Zhao","Yuchong Wang","Tianwei Luo","Weizhi Wang","Yuxin Zuo","Guoli Jia","Xingtai Lv","Dianqiao Lei","Sihang Zeng","Yuru Wang","Zhenzhao Yuan","Xinwei Long","Ermo Hua","Can Ren","Xin Jiang","Shulei Xie","Yuanchun Zheng","Youbang Sun","Biqing Qi","Ning Ding","Kaiyan Zhang","Bowen Zhou"],"abstract":"In the Era of Experience, agentic AI is no longer defined only by what a model can infer from static data, but by how a deployed system accumulates, organizes, and reuses experience from interaction. This survey studies experience-driven improvement in deployed agentic AI systems. We focus on the runtime harness as the infrastructure that captures traces, routes actions, exposes feedback, and governs mutable state. Around this infrastructure, we review how experience becomes reusable skill, persistent memory, verifiable environment feedback, trainable model behavior, and meta-level control. We then identify the remaining barriers to reliable improvement, including longitudinal evaluation, transfer, verification, and safety governance. Making agents smarter after deployment is therefore a trace-to-capability problem: the field must learn how to capture experience, assign it to the right update surface, verify its value, and preserve control as the system changes.","published":"2026-06-25T08:57:08+00:00","updated":"2026-06-25T14:28:29+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=IUltZSgLMm","openreview_url":"https://openreview.net/forum?id=IUltZSgLMm","pdf_url":"https://openreview.net/pdf?id=IUltZSgLMm","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.26552","versioned_id":"2606.26552v1","title":"Perception, Verdict, and Evolution: Hindsight-Driven Self-Refining Forensics Agent for AI-Generated Image Detection","authors":["Yangjun Wu","Keyu Yan","Yu Liu","Jingren Zhou","Fei Huang","Rong Zhang","Zhou Zhao","Fei Wu"],"abstract":"The rapid advancement of generative models presents a significant challenge to existing deepfake detection methods, particularly given the widespread dissemination of highly realistic AI-generated images. Although Multimodal Large Language Models (MLLMs) show strong potential for this task, existing approaches suffer from two key limitations: insufficient sensitivity to fine-grained forensic artifacts and reliance on static synthetic supervision from frontier models, leading to limited flexibility and high-cost. To address these issues, we propose ForeAgent, an agentic forensics framework for AI-generated image detection with iterative self-evolution. First, ForeAgent adopts a Perception-Verdict architecture that aggregates multi-view cues spanning semantic, spatial, and frequency-domain features, and leverages an MLLM as a verdict module to fuse these signals for a logical-grounded verdict. Second, to enable continual self-improvement, we introduce a Hindsight-Driven Self-Refining strategy following a Sampling-Reflection-Evolution paradigm. The agent performs inference rollouts on training instances. Guided by ground-truth labels as hindsight, it reflects on failure cases and low-quality reasoning trajectories to regenerate higher-quality reasoning traces. These synthesized samples are then strictly filtered through a dual-expert quality gating module. ForeAgent continuously evolves via fine-tuning on self-curated high-quality samples. Extensive experiments demonstrate that ForeAgent achieves state-of-the-art performance on the Chameleon benchmark, reaching 82.18% accuracy (+16.41% over AIDE), and achieves 93.3% mean accuracy on AIGCDetect-Benchmark across 16 generators. In addition, external evaluation shows that ForeAgent produces more consistent and causally grounded reasoning compared to GPT-5 and GPT-5-mini.","published":"2026-06-25T02:59:33Z","updated":"2026-06-25T02:59:33Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.26552v1","pdf_url":"https://arxiv.org/pdf/2606.26552v1","comment":"10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.26294","versioned_id":"2606.26294v2","title":"The Red Queen Gödel Machine: Co-Evolving Agents and Their Evaluators","authors":["Alex Iacob","Andrej Jovanović","William F. Shen","Daniel Burkhardt","Meghdad Kurmanji","Nurbek Tastan","Lorenzo Sani","Niccolò Alberto Elia Venanzi","Ambroise Odonnat","Zeyu Cao","Bill Marino","Xinchi Qiu","Nicholas D. Lane"],"abstract":"Self-improving agents are state-of-the-art (SOTA) on agentic coding benchmarks and have recently been extended to general domains. However, their search methods generally assume a stationary evaluation criterion: a fixed verifier, benchmark, or labeled dataset that remains valid as the agent improves. This ignores a central feature of evolution: species adapt as their environments change with them. We aim to bring the same principle to recursive self-improvement, making evaluation part of the improvement loop and opening search to evolving evaluators, adversarial objectives, and dynamic utilities that may surpass static benchmarks. We introduce the Red Queen Godel Machine (RQGM), an evolutionary framework for recursive self-improvement under non-stationary utilities. The RQGM makes this possible through controlled utility evolution: search is organized into epochs with a fixed within-epoch evaluation criterion, while the utility can be updated at epoch boundaries, so self-improvement guarantees hold per epoch as the objective evolves across them. We begin by showing that even on verifiable coding tasks, the RQGM improves test pass rate over the prior SOTA by adding a complementary agent-as-a-judge code-review signal. This signal is cheaper and the RQGM uses 1.35x-1.72x fewer tokens. We then turn to scientific paper writing and reviewing, and Olympiad-level proof writing and grading, where the RQGM improves performance over prior self-improving agents: co-evolved writers reach 1.78x-1.86x higher acceptance rates under a diverse agent-as-a-judge panel, while co-evolved graders reach 9% higher ground-truth accuracy. In paper reviewing, the strongest baseline reviewer over-accepts AI-generated papers at up to 1.91x the human rate. The RQGM corrects this by introducing an adversarial objective that discovers reviewers equally stringent on AI and human work.","published":"2026-06-24T18:38:26Z","updated":"2026-06-29T17:13:25Z","categories":["cs.LG","cs.AI","cs.MA","cs.NE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.26294v2","pdf_url":"https://arxiv.org/pdf/2606.26294v2","comment":"13 pages main text + 21 pages appendix (38 pages total, incl. references); 11 figures (7 main text + 4 appendix); 10 tables (2 main text + 8 appendix). Preliminary preprint; work in progress. Keywords: self-improving agents, learned evaluation, multi-agent systems, auto-mated scientific discovery, controlled utility evolution, co-evolutionary search, autoresearch","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.26057","versioned_id":"2606.26057v1","title":"The Unfireable Safety Kernel: Execution-Time AI Alignment for AI Agents and Other Escapable AI Systems","authors":["Seth Dobrin","Łukasz Chmiel"],"abstract":"AI agents are granted access to tools, APIs, and other infrastructure, making them active principals in those systems. The dominant approach places controls inside the agent's own runtime: system prompts, output filters, and guardrail libraries. Any control in the agent's address space is reachable by inputs that influence it; this generalizes to any AI system with sufficient reach into its own runtime, a class we term escapable AI systems. We identify four properties that an authorization mechanism must satisfy for architectural control rather than for cooperative requests: process separation, pre-action enforcement on a structurally only path, fail-closed at both the request and system levels, and externalized signed evidence verifiable outside the controlled system's trust boundary. We position this layer as execution-time AI alignment, complementing training-time alignment (RLHF, Constitutional AI) and inference-time alignment. We present the Unfireable Safety Kernel, a Rust reference implementation realizing all four. Its fail-closed invariant is machine-checked at two levels: an SMT theorem (Z3) and an exhaustive bounded-model-checking proof of the production decision function (Kani, 4/4 harnesses). A Python-to-Rust migration was gated on byte-equivalence (1000/1000 fixtures; 17/17 adversarial classes). We evaluate the kernel governing a live, escapable AI system, a deterministic, self-improving world model, against an escape-seeking adversary driving its real self-modification seam: across 1,000 self-modifications, all 704 attempts on the safety-critical core are refused, with no escape; a further 300, under the operator kill switch, are also refused. A separate campaign of 6,240 authorization round-trips had no successful bypass. Against 3 contemporary systems claiming the agent control plane, the agent invokes control; here, it lacks that choice.","published":"2026-06-24T17:32:27Z","updated":"2026-06-24T17:32:27Z","categories":["cs.AI","cs.CR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.26057v1","pdf_url":"https://arxiv.org/pdf/2606.26057v1","comment":"Pre-print submitted for publication","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2607.09713","versioned_id":"2607.09713v1","title":"Closed-Loop Control with Rule-Aligned Small Language Models and Multi-Agent Self-Correction","authors":["Yuchen Wang","Javal Vyas","Tong Liu","Mehmet Mercangoz"],"abstract":"A key step toward autonomous industrial operation is the ability to create and reconfigure control policies from natural-language requirement specifications, with minimal or no manual redesign. In this setting, policy generation by AI agents can be a credible path when paired with a plant-aware validator (e.g., a digital twin) that can check generated candidate actions before execution. However, practical deployment is constrained by inference latency and compute footprint: large cloud-based models are often too slow, opaque, or data-sensitive for edge closed-loop use. This work investigates whether a compact Small Language Model (SLM) can be retrained for control reasoning and embedded in a validator-guided correction loop. We use a Qwen2.5-1.5B model aligned via Group Relative Policy Optimization (GRPO), combined with (i) an action agent, (ii) a symbolic/digital-twin-style validation layer, and (iii) a reprompting agent that iteratively steers outputs toward valid actions. In randomized thermal-control simulations (30 experiments with 500 steps each), the framework achieves 91.5% average action-alignment accuracy (86.3%--100% across cases) at 3.84\\,s mean inference latency. Under symbolic re-mapping, it maintains a 95% in-range rate, indicating robust physical regulation despite reduced token-level agreement. These results support SLM+validator architectures as a practical path toward reconfigurable autonomous control at the edge.","published":"2026-06-24T13:49:01Z","updated":"2026-06-24T13:49:01Z","categories":["cs.AI","cs.MA","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2607.09713v1","pdf_url":"https://arxiv.org/pdf/2607.09713v1","comment":"Accepted by IEEE CCTA 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.24428","versioned_id":"2606.24428v1","title":"Escaping the Self-Confirmation Trap: An Execute-Distill-Verify Paradigm for Agentic Experience Learning","authors":["Shiding Zhu","Yudi Qi","Yajie Wang","Jiaze Li","Chao Song","Yaorui Shi","Yibo Miao","Hanqi Gao","Kai Zhang"],"abstract":"Experience-driven self-evolution is critical for large language model (LLM) agents to improve through open-world interaction. However, existing experience learning methods mostly rely on single-agent loops, where the same agent executes tasks, summarizes outcomes, and determines memory content. This setup makes agents vulnerable to the Self-Confirmation Trap: wrong-but-self-consistent trajectories are misidentified as successful experience, leading to cumulative errors during retrieval and reuse. To address this issue, we propose EDV, an Execute-Distill-Verify framework for reliable experience learning. In the Execute stage, multiple heterogeneous agents explore the same task space in parallel to generate diverse candidate trajectories. In the Distill stage, a dedicated third-party agent comparatively analyzes these trajectories to produce candidate experiences, reducing executor-centric summarization bias. In the Verify stage, the execution group validates candidates via a consensus mechanism, and only approved experiences are written into shared or private memory. By decoupling the three stages, EDV transforms experience learning from isolated self-reflection into collaborative construction, filtering erroneous and noisy content before memory insertion. We evaluate EDV on three challenging long-horizon benchmarks: tau2-bench, Mind2Web and MMTB. Results show EDV consistently outperforms strong baselines, validating that reliable experience construction is essential for robust agent self-evolution. Our code is available at https://github.com/shidingz/EDV.","published":"2026-06-23T11:05:05Z","updated":"2026-06-23T11:05:05Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.24428v1","pdf_url":"https://arxiv.org/pdf/2606.24428v1","comment":"28 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.24370","versioned_id":"2606.24370v1","title":"When Helpfulness Overrides Causal Caution: Context-Dependent Suppression and Recovery in LLMs","authors":["Hiroshi Okumura"],"abstract":"Large language models (LLMs) are increasingly integrated into decision-support roles in business and policy contexts. While prior benchmark studies have primarily evaluated LLMs' causal reasoning capabilities, a more fundamental epistemic dimension has been overlooked: Causal Caution, defined as the propensity to refrain from causal judgment when empirical evidence is insufficient. This study examines the systematic suppression of Causal Caution that occurs when LLMs shift from academic to practical advisory contexts. Using an evaluation rubric inspired by Pearl's Causal Hierarchy (the PCH score), we conducted experiments on four high-performance LLMs -- Claude Sonnet 4.6, Claude Opus 4.7, GPT 5.5, and Gemini 3.1 Pro -- across 480 trials. Causal Caution maintenance rates were 91.7--100.0% in academic contexts but dropped to 6.7--18.3% in practical advisory contexts (Fisher's exact test, p < .001 across all models). Furthermore, when restricted to practical prompts requesting concrete recommendations or explanatory rationales, only 1 of 200 responses (0.5%) maintained Causal Caution. A brief self-correction prompt -- \"Please reconsider this judgment from the perspective of causal relationships\" -- restored the expression of Causal Caution to maintenance rates of 71.4--100.0% (McNemar's test, p < .001 across all models). These results suggest that helpfulness-oriented response patterns may suppress the expression of Causal Caution in practical advisory contexts, with important implications for organizational governance. The findings indicate that this suppression reflects context-dependent variation in expression rather than an underlying capability limitation, suggesting that multi-agent architectures that separate proposal generation from causal auditing may offer a promising governance design.","published":"2026-06-23T10:00:13Z","updated":"2026-06-23T10:00:13Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.24370v1","pdf_url":"https://arxiv.org/pdf/2606.24370v1","comment":"43 pages, 3 figures, 5 tables. SSRN Abstract ID: 6965680","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.24155","versioned_id":"2606.24155v4","title":"MedBench v5: A Dynamic, Process-Oriented, and Hallucination-Aware Benchmark for Clinical Multimodal Models","authors":["Jinru Ding","Chuchu Jiang","Lu Lu","Wenrao Pang","Mouxiao Bian","Zhuangzhi Gao","Jiangyuan Chen","Xinwei Peng","Ruiyao Chen","Sijie Ren","Renjie Lu","Yun Zhong","Bin Han","Meiling Liu","Jie Xu"],"abstract":"Existing medical AI benchmarks lack process visibility, atomic skill evaluation, and integrated hallucination detection. We introduce MedBench v5, a redesigned benchmark for clinical multimodal models (language, vision-language, and agent systems) that moves from static QA to dynamic, process-oriented evaluation. MedBench v5 features: (1) a dual-dimensional framework combining Clinical Cognitive Responsiveness (13 sub-dimensions) and Medical Atomic Skills (4 agent environments), covering 63 tasks; (2) three switchable information-flow stressors (omission, contradiction, evidence delay) for factorized degradation analysis; (3) a dynamic process audit protocol with five reasoning nodes that produces model-specific failure fingerprints; (4) hallucination propagation monitoring across initiation, propagation, anchoring, and contradiction interaction-capturing silent hallucination. Experiments on frontier models show that strong overall task performance does not guarantee process stability: stressors mainly disrupt contradiction detection, diagnosis updating, hallucination propagation, and contradiction-based self-correction, while final evidence grounding can remain superficially stable. MedBench v5 provides a unified infrastructure for capability profiling, controllable stress testing, process auditing, and hallucination trajectory analysis in clinical AI evaluation.","published":"2026-06-23T05:23:46Z","updated":"2026-07-06T09:18:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.24155v4","pdf_url":"https://arxiv.org/pdf/2606.24155v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.23112","versioned_id":"2606.23112v1","title":"Self-Evolution for Multi-Turn Tool-Calling Agents via Divergence-Point Preference Learning","authors":["Jiaqiang Tang"],"abstract":"Multi-turn tool-using agents must coordinate long-horizon tool sequences while tracking dialogue state and policy constraints. Existing approaches often separate inference-time orchestration from parameter-level learning, leaving tool selection weakly structured and preference updates vulnerable to train--deployment prompt mismatch. For within-benchmark self-improvement, ToolGraph combines schema-derived topology, transition weights estimated from successful rollouts, and history-aware controls for write prerequisites and repeated-search loops. We then construct 161 preference pairs by locating divergence points via state-based matching and prefix-based alignment, filtered through action-correctness annotations, and train DPO under the same ToolGraph context used at inference. Across 375 tau2-bench tasks, ToolGraph raises the weighted average reward from 0.304 to 0.338 (+11.2% relative), while ToolGraph+DPO reaches 0.355 (+16.8% over the baseline), with the DPO gain concentrated in airline and retail. Fine-grained diagnostics further show that roughly half of telecom trajectories exhaust the step budget before action execution and that chosen reward positivity is the most useful checkpoint signal across our 16 evaluated DPO configurations.","published":"2026-06-22T09:56:44Z","updated":"2026-06-22T09:56:44Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.23112v1","pdf_url":"https://arxiv.org/pdf/2606.23112v1","comment":"7 pages, 2 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.23075","versioned_id":"2606.23075v1","title":"Safety in Self-Evolving LLM Agent Systems: Threats, Amplification, and Case Studies","authors":["Ruixiao Lin","Xinhao Deng","Qingming Li","Jianan Ma","Yunhao Feng","Yuqi Qing","Zhenyuan Li","Yechao Zhang","Shiwen Cui","Changhua Meng","Tianwei Zhang","Xingjun Ma","Qi Li","Ke Xu","Shouling Ji"],"abstract":"Self-evolving LLM agent systems, which autonomously update their model parameters, memory, tools, and architectures, introduce a qualitatively new threat landscape in which adversarial influences become permanently encoded, self-amplify across generations, and propagate through populations without sustained attacker access. We present a systematic security and privacy analysis organized around the Module-Lifecycle Attack Surface (MLAS) matrix, which decomposes the attack surface into five functional modules (Brain, Cognitive Resource, Execution, Self-Design, Collective) $\\times$ five lifecycle stages (Bootstrap, Propose, Evaluate, Commit, Serve). Analysis of the resulting 25 cells reveals that 17 face critical threats for which no effective partial mitigation. We identify seven cross-cutting amplification effects that interact synergistically and cannot be addressed by securing individual modules in isolation. Comparative case studies of two open-source frameworks demonstrate that evolution-native design activates $3.5\\times$ more attack surface cells and achieves a 100% attack persistence rate (40/40 payloads across all CIA+Privacy categories), while co-located security scanners block only 2.5% of attacks. Our findings establish that self-evolution converts every known attack category from session-bounded to lineage-persistent, gives rise to entirely new attack classes, and renders static defenses structurally inadequate, motivating evolution-aware security frameworks and formal verification for self-modifying systems.","published":"2026-06-22T09:23:50Z","updated":"2026-06-22T09:23:50Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2606.23075v1","pdf_url":"https://arxiv.org/pdf/2606.23075v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:22BwU6BdAG","versioned_id":"22BwU6BdAG","title":"Enterprise Text-to-SQL: Are Agents Ready to Scale?","authors":["Tarık Buğra Akbaş","Kemal Tarık Nehrozoğlu","Pinar Karagoz","Nesime Tatbul"],"abstract":"The integration of agentic architectures has significantly advanced the state-of-the-art in text-to-SQL tasks, enabling complex reasoning and self-correction through multi-step, modular workflows. However, the performance gains achieved by these systems, such as those utilizing ReAct-style loops, hierarchical delegation, and multi-agent collaboration, often come at a substantial computational and monetary cost that remains insufficiently quantified. This paper presents a comprehensive cost analysis of leading agentic text-to-SQL frameworks, evaluating the tradeoffs between execution accuracy and operational expenditure. By profiling token consumption, GPU energy, and end-to-end SQL generation latency across the Spider, BIRD, and BEAVER benchmarks, we provide a comparative landscape of agentic efficiency.","published":"2026-06-21T19:43:17+00:00","updated":"2026-07-16T22:18:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=22BwU6BdAG","openreview_url":"https://openreview.net/forum?id=22BwU6BdAG","pdf_url":"https://openreview.net/pdf?id=22BwU6BdAG","comment":"NOVAS 2026","journal_ref":"NOVAS 2026","doi":"","venue":"NOVAS 2026","venue_id":"VLDB.org/2026/Workshop/NOVAS","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.21144","versioned_id":"2606.21144v1","title":"AdaMem: Learning What to Remember for Personalized Long-Horizon LLM Agents","authors":["Xingyu Chen","Rui Wang","Zhaopeng Tu","Liefeng Bo"],"abstract":"Long-term memory systems for Large Language Model (LLM) agents typically try to \\emph{remember everything}, extracting memories uniformly to retain as many facts as possible. In production, however, inference cost and finite context budgets make this untenable: beyond consolidating raw dialogue into memory, an agent must exert \\emph{write control}, efficiently keeping only the information each user actually cares about. Otherwise, long-horizon personalized interactions suffer \\emph{memory bloat}, where irrelevant trivia crowds out useful information and steadily erodes question-answering (QA) accuracy. We argue that what is worth remembering is role-dependent, and propose \\textbf{AdaMem} (Adaptive Memory), a method that \\emph{learns what to remember} for each user from feedback. AdaMem maintains a structured, role-specific Memory Policy and refines it from weekly QA feedback through a lightweight, patch-style self-reflection step with failure rollback. To study this setting, we build \\textbf{AdaMem-Bench}, a benchmark that simulates weeks of interaction with week-by-week QA. Across two extraction models and two feedback modes, AdaMem improves QA accuracy by up to \\textbf{+9.0\\%} over the uniform Mem0 baseline while shrinking memory volume by \\textbf{9\\%}.","published":"2026-06-19T06:35:52Z","updated":"2026-06-19T06:35:52Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.21144v1","pdf_url":"https://arxiv.org/pdf/2606.21144v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.20475","versioned_id":"2606.20475v1","title":"Marginal Advantage Accumulation for Memory-Driven Agent Self-Evolution","authors":["Mingyu Yang","Keye Zheng","Congchao Cheng","Yujie Liu","Xingkang Lu","Fan Jiang","Yefei Zheng"],"abstract":"In batch-style trace distillation, the same memory operation may receive contradictory feedback across different batches. Existing methods lack a cross-batch, operation-level evidence accumulation mechanism, making it impossible to distinguish stably effective operations from accidental hits. This paper formalizes the requirement as two structural conditions, alignability and comparability, and proposes Marginal Advantage Accumulation (MAA). MAA constructs differential signals to make them comparable across batches, accumulates signed evidence per operation via EMA, and ensures cross-batch traceability through semantic identity merging. As a post-processing architecture, MAA achieves the best results in 14 out of 16 settings across 4 benchmarks and 4 target models, consistently outperforming existing batch-level distillation baselines and matching or surpassing online alternatives in most settings, while reducing optimization-phase token consumption by approximately 75%.","published":"2026-06-18T16:54:25Z","updated":"2026-06-18T16:54:25Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.20475v1","pdf_url":"https://arxiv.org/pdf/2606.20475v1","comment":"26 pages, 4 figures, 10 tables, 42 references","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.20120","versioned_id":"2606.20120v1","title":"Dual-Agent Framework for Cross-Model Verified Translation of Natural-Language Protocols into Robotic Laboratory Platform","authors":["Hyeonna Choi","Jung Yup Kim","Hyuneui Lim","Seunggyu Jeon"],"abstract":"Biological experiment protocols are written in natural language, whereas automation systems rely on predefined control commands, creating a semantic gap that limits autonomous execution. Microplate-based automatic experiments are particularly challenging due to the need to simultaneously control well mapping, sample-reagent combinations, replicate placement, and parallel dispensing. This study proposes an agent-based protocol translation framework that converts natural-language microplate-based protocols into executable control commands for a robotic laboratory platform. A Parser Agent formalizes the natural-language protocol into a structured representation, and a rule-based mapping engine deterministically incorporates the operational constraints of the robotic laboratory platform to generate device-level control commands. A heterogeneous LLM Validation Agent verifies completeness, parameter accuracy, and execution order, and triggers a self-correction loop with structured feedback when errors are detected. A sweep involving 7 Parsers and 3 Validators on randomly selected ELISA protocols evaluates how model scale and Validator type affect translation accuracy and pass rates under cross-model verification. The accuracy-latency trade-off is further verified by comparing the rule-based mapping of the proposed framework with LLM end-to-end direct mapping. Finally, Bradford assay-based protein quantification using a microplate was demonstrated on a robotic laboratory platform, validating end-to-end autonomous execution from natural-language protocols to real-world experiments. The proposed framework provides a flexible approach to narrowing the semantic gap between natural-language protocols and microplate-based self-driving laboratories.","published":"2026-06-18T11:43:27Z","updated":"2026-06-18T11:43:27Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.20120v1","pdf_url":"https://arxiv.org/pdf/2606.20120v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.19980","versioned_id":"2606.19980v1","title":"ENPIRE: Agentic Robot Policy Self-Improvement in the Real World","authors":["Wenli Xiao","Jia Xie","Tonghe Zhang","Haotian Lin","Letian \"Max\" Fu","Haoru Xue","Jalen Lu","Yi Yang","Cunxi Dai","Zi Wang","Jimmy Wu","Guanzhi Wang","S. Shankar Sastry","Ken Goldberg","Linxi \"Jim\" Fan","Yuke Zhu","Guanya Shi"],"abstract":"Achieving dexterous robotic manipulation in the real world heavily relies on human supervision and algorithm engineering, which becomes a central bottleneck in the pursuit of general physical intelligence. Although emerging coding agents can generate code to automate algorithm search, their successes remain largely confined in digital environments. We conjecture that the missing abstraction to automate robotics research is a repeatable feedback loop for real-world policy improvement: reset the scene, execute a policy, verify the outcome, and refine the next iteration. To bridge this gap, we introduce ENPIRE, a harness framework for coding agents that instantiates this physical feedback routine with four core modules: an Environment module (EN) for automatic reset and verification, a Policy Improvement module (PI) that launches policy refinement, a Rollout module (R) to evaluate policies with one or multiple physical robots operating in parallel, and an Evolution module (E) in which coding agents analyze logs, consult literature, improve training infrastructure and algorithm code to address failure modes. This closed-loop system transforms real-world manipulation learning into a controllable optimization procedure, minimizing human effort while allowing fair ablations across training recipe and agent variants. Powered by ENPIRE, frontier coding agents can autonomously train a policy to achieve a 99% success rate on challenging, dexterous manipulation tasks, such as organizing a pin box, fastening a zip tie, and tool use, a process that further accelerates when we dispatch an agent team on a robot fleet. Our results suggest a practical and scalable path toward deploying coding agents to autonomously advancing robotics in the physical world.","published":"2026-06-18T09:21:27Z","updated":"2026-06-18T09:21:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.19980v1","pdf_url":"https://arxiv.org/pdf/2606.19980v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.20753","versioned_id":"2606.20753v1","title":"Empowering Polymeric Materials Discovery by Artificial Intelligence","authors":["Chenyao Ma","Linda Zhang","Yuheng Chen","Wei Du","Shangwen Fang","Zihao Jiang","Chuanyu Liu","Xinyu Ma","Rui Su","Gang Wang","Muyao Yu","Dong Zhong","Jie Zhu","Weibo Gong","Huan Gu","Limin Li","Chen Shen","Rui Wu","Zhenghao Wu","Kan Xu","Min Zhou","Donglin He","Xiayun Huang","Shan Jiang","Pengfei Ou","Jiayu Peng","Yuwei Zhang","Jie Zhao","Di Zhang","Piao Ma","Zhenghao Li","Hao Li"],"abstract":"Polymeric materials underpin modern technologies spanning energy storage, microelectronics, healthcare and sustainable manufacturing. Yet their rational design remains exceptionally challenging because material performance emerges from complex interactions among molecular composition, chain architecture, processing history and hierarchical structural evolution across multiple length and time scales. Consequently, polymer research has long relied on labor-intensive experimentation and fragmented modeling approaches, limiting both mechanistic understanding and innovation efficiency. Recent advances in data infrastructure, machine learning, large artificial intelligence (AI) models and laboratory automation are beginning to reshape this landscape. Rather than functioning as isolated tools, polymer databases, predictive models, AI agents and automated laboratories are increasingly converging into interconnected discovery ecosystems. As a result, the central challenge is shifting from improving predictive accuracy alone to enabling reliable decision-making, adaptive learning and seamless integration across computation, experimentation and scientific reasoning. We argue that polymer science is entering an era of autonomous discovery, in which data, simulation, reasoning and experimentation operate within self-improving feedback loops that continuously generate hypotheses, design materials, execute experiments and refine predictive models. By unifying molecular design, process optimization, experimental validation and industrial translation, such autonomous ecosystems establish a more predictive, reproducible and scalable paradigm for polymer innovation, fundamentally transforming how polymer research is conducted.","published":"2026-06-18T05:03:02Z","updated":"2026-06-18T05:03:02Z","categories":["physics.chem-ph","cs.AI"],"primary_category":"physics.chem-ph","arxiv_url":"https://arxiv.org/abs/2606.20753v1","pdf_url":"https://arxiv.org/pdf/2606.20753v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.19186","versioned_id":"2606.19186v2","title":"Learning to Annotate Delayed and False AEB Events: A Practical System for Extreme Class Imbalance and Asymmetric Label Noise","authors":["Mengxiang Hao","Xin Jiang","Xinghao Huang","Wenliang Su","Zhiteng Wang","Junjie Rao","Xiaotian Yang","Wei Liao","Chengyu Han","Gen Liang","Yulun Song","Zhitao Xu","Xianpeng Lang"],"abstract":"Autonomous Emergency Braking (AEB) optimization relies on accurately annotated real-world trigger events, particularly rare but critical delayed and false AEB triggers that expose system deficiencies. However, these minority samples comprise less than 5% of thousands of daily triggers, making manual annotation prohibitively expensive at scale. We present the first automated AEB annotation framework to address this problem. During development, we identified two fundamental challenges that severely impair delayed/false trigger annotation accuracy: (1) Extreme class imbalance where delayed/false triggers are overwhelmed by true triggers; (2) Asymmetric label noise where mislabeled majority samples (true triggers) suppress minority samples (delayed/false triggers) learning. To overcome these challenges, we propose two key innovations: (1) Specific data augmentation that synthesizes realistic samples by manipulating focal target attributes, transplanting ego-vehicle dynamics, and masking non-focal agents; (2) noise suppression using stable hardness estimation and probe-guided adaptive threshold to clean mislabeled true trigger samples. Crucially, we deploy our model as a practical annotation system with full-stack architecture, efficiently identifying critical delayed/false triggers from thousands of daily AEB events. Production results demonstrate 80% improvement in recall of delayed/false triggers and 50% reduction in manual workload. Beyond immediate gains, the system enables continuous self-improvement through accumulated high-quality annotations, establishing a necessary data foundation for on-vehicle AEB system optimization","published":"2026-06-17T15:27:15Z","updated":"2026-06-18T01:51:31Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.19186v2","pdf_url":"https://arxiv.org/pdf/2606.19186v2","comment":"8 pages, 5 figures, accepted by IEEE International Conference on Robotics and Automation (ICRA)","journal_ref":"2026 IEEE International Conference on Robotics and Automation (ICRA)","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.19152","versioned_id":"2606.19152v1","title":"AdsMind: A Physics-Grounded Multi-Agent System for Self-Correcting Discovery of Adsorption Configurations on Heterogeneous Catalyst Surfaces","authors":["Zongmin Zhang","Yuyang Lou","Bowen Zhang","Junwu Chen","Ryo Kuroki","Xuan Vu Nguyen","Edvin Fako","Lixue Cheng","Philippe Schwaller"],"abstract":"Identifying the lowest-energy surface-adsorbate configuration is critical for modeling heterogeneous catalysis, yet exhaustive exploration with ab initio calculations is computationally prohibitive. Machine-learning force fields (MLFFs) accelerate structural relaxation but leave the search over the vast configurational space a major bottleneck, and open-loop large language model (LLM) agents lack a physics-grounded feedback mechanism to correct erroneous initial guesses. We propose AdsMind (Adsorption configuration discovery with Machine intelligence and relaxation feedback), a closed-loop multi-agent framework that enables autonomous error correction through MLFF relaxation feedback. Across four LLM backends, AdsMind achieves consistently high search reliability, with success rates of 100% and 98.8% on the benchmarks AA20 and OCD-GMAE62. Relative to its single-pass (1-Shot) ablation it reduces cross-backend energy dispersion, and it uses only 4.11 and 4.67 MLFF relaxations per case, respectively -- an approximately 14-fold reduction over heuristic enumeration baselines. Density functional theory (DFT) validation using VASP/PBE on six representative AA20 systems shows that the reported open-loop Adsorb-Agent outputs exhibit qualitative adsorption-energy sign errors for molecular adsorbates, whereas AdsMind preserves the correct sign in all tested cases with closer quantitative agreement. AdsMind thus delivers reliability, self-reflection, and interpretability simultaneously, supporting more DFT-informed autonomous chemistry workflows.","published":"2026-06-17T14:57:16Z","updated":"2026-06-17T14:57:16Z","categories":["cond-mat.mtrl-sci","cs.AI"],"primary_category":"cond-mat.mtrl-sci","arxiv_url":"https://arxiv.org/abs/2606.19152v1","pdf_url":"https://arxiv.org/pdf/2606.19152v1","comment":"37 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.28374","versioned_id":"2606.28374v1","title":"Recursive Self-Evolving Agents via Held-Out Selection","authors":["Michael Nguyen","Quoc Nguyen","Paul Vuong"],"abstract":"LLM agents are increasingly improved without weight updates by evolving a natural-language artifact, such as reflections, workflows, playbooks, cheatsheets, or optimized prompts, that conditions a frozen policy. Such methods are typically reported as wins on the single benchmark where they help. We study them apples-to-apples and surface a sharper picture. We introduce RSEA, a Recursive Self-Evolving Agent that carries a compact three-layer natural-language state: an imperative strategy, reusable skills, and a procedural playbook. Across generations, RSEA rewrites all three layers from its own trajectories and commits a candidate only if it does not regress on a disjoint held-out split, using a strict keep-better gate. Across four diverse benchmarks, ALFWorld, GAIA, (τ)-bench, and WebShop, and six faithful baselines, ReAct, Reflexion, GEPA, AWM, ACE, and Dynamic Cheatsheet, all evaluated on one shared local backbone, we find three main results. First, no artifact universally wins. RSEA is the strongest single-pass method on ALFWorld, reaching 69.3% compared with 64.6% for ReAct (McNemar (p=0.015)), and reaches 79.4% with retry, the best overall result. However, concrete-workflow induction, represented by AWM, is best on the strong-backbone tool-use tasks. Second, unguarded context evolution is high-variance and unsafe. Dynamic Cheatsheet, which curates context online without a held-out gate, is near-best on ALFWorld at 70.7%, yet collapses on WebShop, with a score of 0.14 compared with 0.43 for ReAct. Third, RSEA's strict held-out selection is what makes recursive self-evolution monotone-safe: it never significantly underperforms the base agent on any benchmark and falls back to vanilla ReAct when evolved context would hurt.","published":"2026-06-17T14:53:36Z","updated":"2026-06-17T14:53:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.28374v1","pdf_url":"https://arxiv.org/pdf/2606.28374v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.18890","versioned_id":"2606.18890v1","title":"Skill-Guided Continuation Distillation for GUI Agents","authors":["Zhimin Fan","Hongwei Yu","Yeqing Shen","Haolong Yan","Guozhen Peng","Tianhao Peng","Yudong Zhang","Xiaowen Zhang","Kaijun Tan","Zheng Ge","Xiangyu Zhang","Daxin Jiang"],"abstract":"Improving GUI agents typically relies on behavior cloning on expert trajectories. However, as the current policy deviates from the expert policy, it inevitably encounters policy-induced off-trajectory states during closed-loop execution, i.e., states that fall outside the expert trajectories. Since expert trajectories provide no demonstrations for these unseen states, such states receive no effective supervision, leaving the policy unable to select the correct action. To close this supervision gap, we propose Skill-Guided Continuation Distillation (SGCD), an iterative self-improvement framework. SGCD first runs the plain policy without skill guidance for a few steps to reach realistic off-trajectory states. From these states, a skill-guided policy then completes the task and produces successful continuations, which are mixed with expert trajectories to supply supervision over policy-induced off-trajectory states. The skills are extracted from both successful and failed rollouts, consisting of Continuation Plans, Critical Targets, Failure Traps, and Success Criteria. On OSWorld-Verified, SGCD improves the success rate of three base models from the low-30\\% range to over 50\\%, demonstrating its effectiveness and generality.","published":"2026-06-17T10:07:51Z","updated":"2026-06-17T10:07:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.18890v1","pdf_url":"https://arxiv.org/pdf/2606.18890v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.17871","versioned_id":"2606.17871v1","title":"StepGuard: Guarding Web Navigation via Single-Step Calibration","authors":["Zhihao Cui","Yuchen Zhang","Xiyang Sun","Yaxiong Wang","Li Zhu","Jinpeng Hu","Liu Liu","Mengjia Li","Yujiao Wu"],"abstract":"Web navigation requires agents to follow natural language goals, interact with web pages, and produce accurate answers. While recent advances leverage vision-language models and reinforcement learning, existing methods still suffer from single-step fragility due to reward misalignment and error propagation. To tackle the reward entanglement, we design Dynamic Dual-Policy Optimization (DDPO), which dynamically switches between a navigation-first mode for exploration and an answer-first mode for question-answering to mitigate reward conflict. To calibrate the single-step error, we propose Confidence-Guided Adaptive Navigation Reflection (CANR), a mechanism that estimates per-step confidence, triggers reflection only when necessary, and uses contrastive rewards to encourage self-correction to calibrate the single-step inaccuracy. With the above as the main components, we finally develop our StepGuard, a new framework of Guarding Web Navigation via Single-Step Calibration. Experiments demonstrate that our approach significantly improves navigation and answer accuracy, setting new state-of-the-art performance on standard web navigation benchmarks.","published":"2026-06-16T12:42:09Z","updated":"2026-06-16T12:42:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.17871v1","pdf_url":"https://arxiv.org/pdf/2606.17871v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.17546","versioned_id":"2606.17546v1","title":"SEAGym: An Evaluation Environment for Self-Evolving LLM Agents","authors":["Congjie Zheng","Chuanyi Xue","Bin Liang","Jun Yang","Changshui Zhang"],"abstract":"Self-evolving LLM-based agents improve mainly by changing their agent harness: the structured execution layer around a base model, including prompts, memory, tools, middleware, runtime state, and the model-tool interaction loop. Existing evaluations often reduce this process to isolated task scores or a single sequential curve, obscuring whether an update produces reusable improvement, overfits recent tasks, increases cost, or harms older behavior. We introduce SEAGym, an evaluation environment for measuring agent harness updates across training, validation, test, replay, and cost records. SEAGym turns Harbor-compatible benchmarks into dynamic self-evolution task sources with train batches, frozen update-validation, held-out ID and OOD transfer views, replay diagnostics, and saved snapshot and metric records. Instantiating SEAGym on Terminal-Bench 2.0 and HLE, we compare ACE, TF-GRPO, and AHE under a shared epoch/batch protocol. The results show that these evaluation views provide complementary signals about the evolution process: frequent updates may fail to improve held-out performance, useful intermediate snapshots may collapse later, and source diversity and model backend can affect harness reliability.","published":"2026-06-16T05:50:55Z","updated":"2026-06-16T05:50:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.17546v1","pdf_url":"https://arxiv.org/pdf/2606.17546v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.17220","versioned_id":"2606.17220v1","title":"When Rules Learn: A Self-Evolving Agent for Legal Case Retrieval","authors":["Mingxu Tao","Jiawei Hu","Xian Zhou","Wenpeng Hu","Jiajun Cheng","Yunbo Cao","Zhunchen Luo","Guotong Geng"],"abstract":"Legal case retrieval remains challenging due to the complexity of legal language and the need for precise lexical alignment between queries and relevant cases. Although dense retrieval models have achieved notable progress, empirical studies show that BM25 continues to serve as a strong baseline in this domain. It motivates us to propose a self-evolving framework for rule-driven query rewriting that enhances BM25 without any parameter training. The framework equips an LLM-based agent with an automatic evaluation environment, enabling it to iteratively create rewriting rules, plan validation experiments over rule combinations, and eliminate ineffective rules based on historical feedbacks. We evaluate our method on the Chinese legal case retrieval benchmark LeCaRD-v2. Experimental results demonstrate that the proposed framework outperforms non-evolutionary baselines, including human-designed rules and greedy rule selection, particularly when powered by a highcapacity core LLM. We also conduct detailed analyses to investigate the mechanisms underlying self-evolution. Our findings reveal that LLM's capabilities to leverage previous experimental results and its intrinsic knowledge of rule elimination play critical roles in refining the rule set via self-evolution.","published":"2026-06-15T19:09:31Z","updated":"2026-06-15T19:09:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.17220v1","pdf_url":"https://arxiv.org/pdf/2606.17220v1","comment":"To appear in ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.24598","versioned_id":"2606.24598v1","title":"Toward Self-Evolution-Ready Workflow Harnesses: A Reversible Migration Path and Convertibility Taxonomy for Expert LLM Pipelines","authors":["Yimo Lin","Zhen Zhang","Yibin Li"],"abstract":"While expert-validated \"LLM + script\" workflows deliver significant value, they remain static: they encode hard-won domain knowledge yet fail to adapt execution based on feedback. Existing agent research predominantly targets greenfield agents and synthetic benchmarks, leaving the migration of active legacy workflows unresolved. To bridge this gap, we present a reversible, Strangler-Fig migration path that refactors legacy workflows into composable, typed, and auditable stages. Central to this framework is a three-tier convertibility taxonomy (A/B/C), implemented as a routing stage within the system harness, which diagnoses a workflow's readiness and routes it accordingly.","published":"2026-06-15T15:27:08Z","updated":"2026-06-15T15:27:08Z","categories":["cs.SE","cs.AI","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.24598v1","pdf_url":"https://arxiv.org/pdf/2606.24598v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.16295","versioned_id":"2606.16295v1","title":"VisualClaw: A Real-Time, Personalized Agent for the Physical World","authors":["Haoqin Tu","Jianwen Chen","Zijun Wang","Siwei Han","Juncheng Wu","Hardy Chen","Haonian Ji","Kaiwen Xiong","Jiaqi Liu","Peng Xia","Jieru Mei","Hongliang Fei","Jason Eshraghian","Zeyu Zheng","Yuyin Zhou","Huaxiu Yao","Cihang Xie"],"abstract":"Vision language models are serving as general-purpose interfaces for complex multimodal tasks. However, deployment still faces three gaps: VLMs typically incur high latency and cost when processing dense video frames and long prompts, the agent scaffold remains static after deployment, and standard video-QA benchmarks do not test whether agents can use visual evidence inside tool-using workspaces. We present VisualClaw, a self-evolving multimodal agent built around two principles. First, hybrid encoding reduces deployment cost by filtering less informative streaming frames with a cascaded gate and compressing the text skill bank through hot/cold top-k injection. Second, skill evolution lets the agent learn from failures: retrieved memories condition an evolver as direct concatenated context or as guided evidence, producing skill-bank updates that help future questions. Across 4 video-QA benchmarks with 2 VLMs, VisualClaw cuts per-question API cost by an average -98% versus full-frame upload and by -25.9% over the offline uniform 8 frame baseline, while boosting accuracy in most settings, e.g., an average +3.85% and a peak +15.80% on EgoSchema with Gemini 3 Flash. To address the gap, we curate VisualClawArena, a 200-scenario multimodal agentic benchmark built through a strict five-stage pipeline; models must use video evidence, documents, dynamic updates, and executable checks inside a workspace. On VisualClawArena, the same framework with computer-use agent backends improves macro accuracy by +2.9% for Codex (GPT-5.5) and +3.2% for Claude Code (Sonnet 4.6) over no-evolution baselines, with a -9.5% cost reduction compared to the uniform-sampled baseline. These properties make VisualClaw a natural fit for edge applications, where the cascade reduces a 1-hour streaming session from ~3,600 API uploads down to only 5-20 calls and the self-evolution makes it a perfect personalized assistant.","published":"2026-06-15T06:58:22Z","updated":"2026-06-15T06:58:22Z","categories":["cs.CV","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.16295v1","pdf_url":"https://arxiv.org/pdf/2606.16295v1","comment":"H. T. and J. C. contribute to this project equally","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.16047","versioned_id":"2606.16047v1","title":"From Argument Components to Graphs: A Multi-Agent Debate with Confidence Gating for Argument Relations","authors":["Jakub Bąba","Jarosław A. Chudziak"],"abstract":"Large Language Models (LLMs) are increasingly assessed and utilized in the field of Argument Mining (AM), thanks to their strong general reasoning capabilities. However, standard training-free models often miss sophisticated details, specifically in contexts where two parts of the text have to be analyzed together. Furthermore, self-correction mechanisms tend to reinforce initial hallucinations in reasoning. Overcoming these limitations typically requires expensive, domain-specific supervised fine-tuning. Recent work has shown that a multi-agent paradigm can address such weaknesses for the component classification task through dialectical refinement with a Proponent-Opponent-Judge architecture, setting a promising direction for training-free approaches in the field. In this paper, we extend and evaluate this framework on the Argument Relation Identification and Classification (ARIC) task, reformulating it as a debate over component pairs. Besides that, we introduce a confidence gating mechanism that enables debating only on the uncertain cases and accepting the initial prediction when confidence is high. On the UKP Argument Annotated Essays v2 corpus, we demonstrate that the selective debate achieves the highest Macro F1 among all training-free methods, while debate over all samples degrades performance below that of one of the baselines. All generative approaches also outperform fine-tuned RoBERTa models on Macro F1, suggesting that the under-representation of the Attack class was more damaging to supervised fine-tuning than to inference-only models. Additionally, our framework produces human-readable debate transcripts, offering interpretability absent from both single-agent and supervised classifiers.","published":"2026-06-14T22:33:54Z","updated":"2026-06-14T22:33:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.16047v1","pdf_url":"https://arxiv.org/pdf/2606.16047v1","comment":"Accepted for publication in the proceedings of KES 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.15994","versioned_id":"2606.15994v1","title":"Agentic Framework for Deep Learning workload migration via In-Context Learning","authors":["Qiyue Liang","Steven Ingram","George Vanica","Andi Gavrilescu","Newfel Harrat","Hassan Sipra","Sethuraman Sankaran"],"abstract":"Translating deep learning models from PyTorch's flexible, object-oriented design to JAX's functional, stateless setup is usually a manual and error-prone task. Automated migration is challenging because Large Language Models (LLMs) struggle with strict and dynamic API alignment and are prone to mistakes for exacting operations. We propose a fully autonomous system that combines In-Context Learning (ICL) with oracle-driven self-debugging. First, we curated an ICL context that serves as a strict reference for idiomatic JAX styling and test case generation. Second, instead of depending on the LLM to deduce mathematical outputs, we run the source PyTorch modules to get their actual dynamic tensor states. This creates an unchangeable execution oracle. We then use an autonomous agentic loop to synthesize tests based on the oracle data. The test cases are executed repeatedly, and the traceback is sent back to the LLM for self-correction. Ablations show that combining ICL references with oracle grounding and self-debugging greatly outperforms pure instructional and basic agentic baselines. This improvement does not add an excessive computational overhead. Our lightweight pipeline achieves 91% numerical equivalence (compared to baseline: 9%, instruction + self-debugging: 27%) on neural modules, providing a highly reliable, scalable blueprint for cross-framework migration. This has been validated across several state-of-the-art models including SAM (segment anything), T5, Code Whisper amongst others showing high numerical equivalency. Code: https://github.com/AI-Hypercomputer/accelerator-agents/tree/main/MaxCode","published":"2026-06-14T19:41:57Z","updated":"2026-06-14T19:41:57Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.15994v1","pdf_url":"https://arxiv.org/pdf/2606.15994v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.20686","versioned_id":"2606.20686v1","title":"JPPD: Joint Prediction_Planning Diffusion with Differentiable Safety Guidance for Dynamic Obstacle Avoidance in Intelligent Transportation Systems","authors":["Jiahao Wu","Shengwen Yu"],"abstract":"Shared-space transportation operation requires low-speed autonomous platforms to navigate safely and efficiently among pedestrians, service robots, micromobility users, carts, and other road users. Most existing systems decompose this problem into trajectory prediction followed by motion planning, which creates one-way information flow: predicted participant futures influence the robot plan, but the selected robot plan cannot influence the predicted multi-agent evolution. This paper presents a joint prediction-planning diffusion framework that treats participant prediction and robot planning as a single conditional trajectory generation problem, where the model samples the future robot trajectory and all participant trajectories from one coupled distribution using a causal Transformer with cross-trajectory attention. To replace heuristic repulsive post-processing, the framework introduces differentiable safety potential guidance, a time-varying occupancy-probability potential whose gradient directly guides the joint sampler, and conditional flow matching is used to reduce inference steps while preserving multimodal trajectory diversity. The evaluation emphasizes shared-space operational effects, including near misses, blockage time, induced participant deviation, hard-braking events, and embedded latency, rather than treating average displacement error and final displacement error as the main result. Experiments in scenario-grounded simulation, naturalistic pedestrian replay, Isaac Sim validation, and ROS/Orin deployment show that joint sampling improves tail safety and runtime efficiency over a separated prediction-then-planning baseline.","published":"2026-06-14T11:15:44Z","updated":"2026-06-14T11:15:44Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.20686v1","pdf_url":"https://arxiv.org/pdf/2606.20686v1","comment":"12 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.15363","versioned_id":"2606.15363v1","title":"APEX: Adaptive Principle EXtraction A Three-Layer Self-Evolution Framework for Production AI Agents","authors":["Ya-Chuan Chen","Tien-Jen Lai","Hsiang-Wei Hu"],"abstract":"Self-improvement in AI agents has emerged as a key research frontier: systems that modify their own prompts, workflows, and decision rules based on accumulated operational experience. The state-of-the-art Self-Harness framework [1] achieves 14--21% improvement on Terminal-Bench-2.0 by mining failure clusters and patching the agent harness. However, Self-Harness optimises only one dimension -- the prompt harness -- leaving behavioural principles and workflow topology unchanged. We propose APEX (Adaptive Principle EXtraction), a three-layer co-evolution framework that simultaneously evolves: (L1) the harness via failure-mode patching, (L2) behavioural principles via success-trace distillation [2], and (L3) the agent workflow topology via structural fitness-based selection [6]. We implement APEX on Joe [13], a production-grade super AI Agent built on NVIDIA Nemotron and designed as an Edge AI Agent Factory for the NVIDIA Agent Challenge 2026, managing a 15-node compute fleet using 114 real task traces collected over 18 days. APEX achieves an APEX Health Score of 0.570 (+90% vs. baseline 0.300) in a single evolutionary run, distilling 6 novel reusable principles and selecting a research-first workflow topology scoring 0.900 (+20%). Our results demonstrate that multi-dimensional co-evolution substantially outperforms single-axis harness optimisation, at a cost of only 4 LLM calls (~270 s) on a local qwen2.5-coder:32b instance.","published":"2026-06-13T15:47:27Z","updated":"2026-06-13T15:47:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.15363v1","pdf_url":"https://arxiv.org/pdf/2606.15363v1","comment":"8 pages, 1 figure, 4 tables. Evaluated on a production 15-node compute fleet with 114 real task traces. Code available at https://aispark.airlive.com/joe-hackathon/","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2606.14502","versioned_id":"2606.14502v1","title":"From Chatbot to Digital Colleague: The Paradigm Shift Toward Persistent Autonomous AI","authors":["Yongheng Zhang","Ziang Liu","Jiaxuan Zhu","Shuai Wang","Xiangqi Chen","Haojing Huang","Jiayi Kuang","Siyu Chen","Ao Shen","Hao Wu","Qiufeng Wang","Qian-Wen Zhang","Junnan Dong","Wenhao Jiang","Ying Shen","Hai-Tao Zheng","Yinghui Li","Di Yin","Xing Sun","Philip S. Yu"],"abstract":"Large Language Models (LLMs) are undergoing a fundamental transformation from conversational generators into integrated AI systems capable of reasoning, action, memory, and self-improvement. We conceptualize this transition as a shift from Chatbot to Digital Colleague: from conversational answers to persistent work. We organize this transition along two tightly coupled dimensions. First, at the cognitive core level, LLMs are advancing from Chatbot-era \"fast thinking\" systems driven by next-token prediction toward Thinking LLMs that leverage inference-time computation, Chain-of-Thought reasoning, reflection, process supervision, and reinforcement learning to support more deliberate and reliable cognition. Second, at the tool-augmented task execution level, LLMs are progressing from tool-calling Agents that invoke external resources in an ad hoc manner toward OpenClaw-style workstation systems (OpenClaw) equipped with persistent Workspaces, skills, verification loops, and governance. The \"Workspace + Skill\" paradigm makes episodic tool use colleague-like via state persistence, reusable procedures, task closure, and experience reuse. We examine data construction shifts from instruction-response pairs to State-Action-Observation trajectories and evaluation from static benchmarks to sandboxed, auditable, self-evolving AI ecosystems.","published":"2026-06-12T14:33:55Z","updated":"2026-06-12T14:33:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14502v1","pdf_url":"https://arxiv.org/pdf/2606.14502v1","comment":"The paper is available on the project website: https://from-chatbot-to-digital-colleague.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.14314","versioned_id":"2606.14314v1","title":"Communication Policy Evolution for Proactive LLM Agents","authors":["Xinbei Ma","Jiyang Qiu","Yao Yao","Zheng Wu","Yijie Lu","Xiangmou Qu","Jiaxin Yin","Xingyu Lou","Jun Wang","Weiwen Liu","Weinan Zhang","Zhuosheng Zhang","Hai Zhao"],"abstract":"LLM agents have rapidly evolved into autonomous systems, yet a persistent information gap remains between users and agents: communication is costly, while users' identical preferences further limit information exchange. To investigate how agents should communicate across modalities, this paper formalizes Communication Policy, establishes textual and UI-based policies, and then evaluates communication policies across diverse environments, personas, and model combinations. Building information asymmetry for proactive agents, we set up two complementary settings, User-Agent and Planner-Executor. Experimental results reveal complementary strengths between interaction channels: text-based interaction often facilitates task performance, while structured UI improves agents' response quality and persona compliance. Motivated by that, a hybrid method combines these advantages. We further propose Communication Policy Evolution (CPE), a self-evolution framework for refining communication policies through rollout and prompt-level evolving. Without model modification, CPE achieves the best task success across multiple settings using prompt refinement alone. Our findings identify communication behavior as a critical yet underexplored design dimension for LLM agents.","published":"2026-06-12T09:54:01Z","updated":"2026-06-12T09:54:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14314v1","pdf_url":"https://arxiv.org/pdf/2606.14314v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.14302","versioned_id":"2606.14302v1","title":"Retrospective Progress-Aware Self-Refinement for LLM Agent Training","authors":["Xinbei Ma","Congmin Zheng","Jiyang Qiu","Jiale Hong","Yao Yao","Xiangmou Qu","Jiaxin Yin","Xingyu Lou","Jun Wang","Weiwen Liu","Weinan Zhang","Zhuosheng Zhang","Hai Zhao"],"abstract":"LLM-based agents trained with reinforcement learning optimize step-wise action prediction but lack metacognitive awareness of task progress, inducing a gap that hinders long-horizon scaling. A pilot study reveals that online progress prompting hurts performance while retrospective demonstrations help, yet this capability cannot emerge from outcome-reward training alone. We present RePro, Retrospective Progress-Aware Training, a framework that trains agents to self-generate progress signals via a forward-then-reflect rollout paradigm: the agent executes actions online, then retrospectively reassesses its step-wise progress given the completed trajectory and known outcome. RePro initializes with a Retrospection Warmup that teaches reflection format from minimal external demonstrations, then further trains through RePro-PO with a composite reward that produces self-generated signals without continuous external supervision. Experiments on WebShop, ALFWorld, and Sokoban show that RePro enhances the Qwen family's performance, with up to $12\\%$ absolute success rate gains.","published":"2026-06-12T09:38:47Z","updated":"2026-06-12T09:38:47Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.14302v1","pdf_url":"https://arxiv.org/pdf/2606.14302v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.14249","versioned_id":"2606.14249v2","title":"HarnessX: A Composable, Adaptive, and Evolvable Agent Harness Foundry","authors":["Tingyang Chen","Shuo Lu","Kang Zhao","Weicheng Meng","Hanlin Teng","Tianhao Li","Chao Li","Xule Liu","Jian Liang","Zhizhong Zhang","Yuan Xie","Heng Qu","Kun Shao","Jian Luan"],"abstract":"AI agent performance depends critically on the runtime harness, comprising the prompts, tools, memory, and control flow that mediate how a model observes, reasons, and acts. Yet today's harnesses remain largely hand-crafted and static: each new model or task still demands bespoke scaffolding, and the rich traces produced during execution are rarely distilled back into systematic improvement. We introduce HarnessX, a foundry for composable, adaptive, and evolvable agent harnesses. HarnessX assembles typed harness primitives via a substitution algebra, adapts them through AEGIS, a trace-driven multi-agent evolution engine grounded in an operational mirror between symbolic adaptation and reinforcement learning, and closes the harness-model loop by turning trajectories into both harness updates and model training signal. Across five benchmarks (ALFWorld, GAIA, WebShop, tau^3-Bench, and SWE-bench Verified), HarnessX yields an average gain of +14.5% (up to +44.0%), with gains largest where baselines are lowest. These results suggest that agent progress need not come from model scaling alone: composing and evolving runtime interfaces from execution feedback is an actionable and complementary lever. The complete codebase will be open-sourced in a future release.","published":"2026-06-12T08:27:11Z","updated":"2026-07-02T03:16:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14249v2","pdf_url":"https://arxiv.org/pdf/2606.14249v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.14211","versioned_id":"2606.14211v1","title":"Closing the Reflection Gap: A Free Calibration Bonus for Agentic RL","authors":["Yinglun Zhu"],"abstract":"LLMs are increasingly deployed as agents that interact with external environments and observe feedback such as execution results, error messages, and tool outputs. A well-functioning agent should be able to leverage this feedback to accurately assess its own performance. Yet we find a persistent reflection gap: LLM agents tend to mis-assess their own outputs after observing concrete environment feedback -- even for questions they correctly answered -- and standard RL barely helps due to a credit-assignment mismatch. To close this gap, we propose RefGRPO, a simple yet effective fix that augments standard RL algorithms with two key ingredients: a free calibration bonus computed by contrasting the agent's own reflection with the actual outcome (requiring no additional reward model, LLM judge, or external annotation), and a dynamic schedule on its coefficient. Compared to standard RL baselines, our method simultaneously improves reflection calibration (e.g., reduces underconfidence rate $44.4\\% \\to 7.7\\%$) and task accuracy (e.g., $75.1\\% \\to 76.5\\%$) on text-to-SQL across five benchmarks. The resulting calibrated reflection turns the agent into its own verifier grounded in environment feedback, which further enables (i) better self-improvement that uses reflections as pseudo-rewards without outcome supervision, and (ii) more effective test-time selective prediction by committing only to rollouts flagged as correct.","published":"2026-06-12T07:47:15Z","updated":"2026-06-12T07:47:15Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.14211v1","pdf_url":"https://arxiv.org/pdf/2606.14211v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.13368","versioned_id":"2606.13368v2","title":"IterCAD: An Iterative Multimodal Agent for Visually-Grounded CAD Generation and Editing","authors":["Tao Hu","Jiaxin Ai","Licheng Wen","Xueheng Li","Shu Zou","Siqi Li","Nianchen Deng","Xinyu Cai","Hongbin Zhou","Pinlong Cai","Daocheng Fu","Yu Yang","Hairong Zhang","Botian Shi","Xuemeng Yang"],"abstract":"Computer-Aided Design is pivotal in modern manufacturing, yet existing automated methods predominantly rely on open-loop, one-shot generation, creating a mismatch with iterative real-world practices. In this paper, we present IterCAD, a unified multimodal agent framework for closed-loop, interactive CAD generation and editing. We formulate the task as a multi-turn interaction between a multimodal agent and an executable CAD sandbox, covering three tasks: Drawing-to-Code, Text-to-Code, and Interactive Editing. To support this, we develop a data synthesis pipeline incorporating advanced industrial manufacturing features to generate standard-compliant multi-view engineering drawings, complex code-editing tasks, and high-fidelity interaction trajectories. We optimize the agent via progressive SFT followed by geometry-aware reinforcement learning with viable-prefix masking to enhance code executability and geometric fidelity. Finally, we introduce the IterCAD-Bench evaluation suite and propose the Chamfer Distance Tolerance-Recall (CD-TR) curve alongside its AUC-TR metric, establishing a survivor-bias-free standard that unifies code validity and geometric precision. Extensive experiments demonstrate that IterCAD achieves highly competitive performance across multiple benchmarks, significantly outperforming existing approaches in both code executability and geometric precision, while exhibiting superior capabilities in closed-loop iterative refinement.","published":"2026-06-11T13:53:21Z","updated":"2026-06-30T07:06:53Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.13368v2","pdf_url":"https://arxiv.org/pdf/2606.13368v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.13317","versioned_id":"2606.13317v1","title":"SkillCAT: Contrastive Assessment and Topology-Aware Skill Self-Evolution for LLM Agents","authors":["Kunfeng Chen","Qihuang Zhong","Juhua Liu","Bo Du"],"abstract":"Skill self-evolution methods for LLM agents aim to turn execution trajectories into reusable skill documents, but current pipelines typically learn from one trajectory per task, merge candidate skill patches before checking them, and load the full skill corpus before inference. We propose SkillCAT, a training-free framework that separates this process into three stages. Contrastive Causal Extraction (CCE) samples multiple trajectories for each task and compares same-task success/failure pairs to identify evidence that explains outcome differences. Assessment-Augmented Evolution (AAE) replays each candidate patch on source-task clones and keeps only patches that improve or preserve task outcomes before hierarchical skill patch merging. Topology-Aware Task Execution (TTE) compiles the evolved skills into a routable sub-skill topology, so inference loads only the capability nodes relevant to the task. We evaluate SkillCAT on common agent benchmarks, including SpreadsheetBench, WikiTableQuestions, and DocVQA, and further test cross-model and out-of-distribution generalization. Across these settings, SkillCAT raises the average score over baselines by up to 40.40%, demonstrating reliable skill evolution without model training.","published":"2026-06-11T13:12:10Z","updated":"2026-06-11T13:12:10Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.13317v1","pdf_url":"https://arxiv.org/pdf/2606.13317v1","comment":"9 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.12780","versioned_id":"2606.12780v1","title":"ProPlay: Procedural World Models for Self-Evolving LLM Agents","authors":["Yijun Ma","Zehong Wang","Yiyang Li","Ziming Li","Xiaoguang Guo","Weixiang Sun","Chuxu Zhang","Yanfang Ye"],"abstract":"Self-evolving agents are expected to improve through interaction without external supervision, but this remains difficult in partially observable environments where agents must explore actively, learn from limited feedback, and decide when to trust prior experience. Existing LLM-agent methods often rely on memory or planning modules, yet they rarely close the loop between them to continually refine an internal understanding of environment dynamics. We introduce ProPlay, a procedural world model that supports procedure-level preplay, where agents can rehearse future procedural paths using the learned world knowledge. Rather than representing experience as isolated rules or low-level action constraints, ProPlay abstracts successful trajectories into procedures and organizes them in a procedure graph that captures causal transitions among task stages. Each transition is associated with a reliability record embedding to estimate its task-specific contribution from past outcomes. Before each episode, ProPlay simulates future procedural trajectories over known graph structures as structured soft guidance; after execution, it refines the graph using environment feedback. Experiments on public benchmarks show that ProPlay consistently improves environment understanding and self-evolution capability over strong baselines. Our code has been released in https://github.com/antman9914/proplay.","published":"2026-06-11T00:47:37Z","updated":"2026-06-11T00:47:37Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.12780v1","pdf_url":"https://arxiv.org/pdf/2606.12780v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.12191","versioned_id":"2606.12191v1","title":"Agentic Environment Engineering for Large Language Models: A Survey of Environment Modeling, Synthesis, Evaluation, and Application","authors":["Jiachun Li","Zhuoran Jin","Tianyi Men","Yupu Hao","Kejian Zhu","Lingshuai Wang","Dongqi Huang","Longxiang Wang","Shengjia Hua","Lu Wang","Jinshan Gao","Hongbang Yuan","Ruilin Xu","Kang Liu","Jun Zhao"],"abstract":"Environments serve as interactive systems for large language model (LLM) based agents across diverse scenarios and play a crucial role in driving the continual evolution of model capabilities. Despite this importance, existing work lacks a systematic categorization and deep analysis. This paper systematically studies current researches on agentic environments from the perspective of the environment engineering lifecycle, covering their modeling, synthesis, evaluation and application. Specifically, the paper first introduces representative environments from the perspectives of eight attributes and eight domains, providing detailed analyses of their development paths and highlighting their core capabilities. Second, for automated environment synthesis, two paradigms are introduced, such as symbolic synthesis and neural synthesis. This paper also shows different environment evaluation methods in each paradigm. Thirdly, the corresponding environment applications from the perspective of agent-environment co-evolution are discussed. In specific, the paper characterizes the primary pathways for agent evolution in dynamic environments from four complementary perspectives: memory-centric experience evolution, orchestration-centric workflow evolution, trajectory-centric offline evolution, and exploration-centric online evolution. And three paradigms of environment evolution are identified, namely neural-driven, difficulty-driven, and scaling-driven approaches. At last, several promising future directions are discussed, including Environment-as-a-Service, Multi-agent Environments, and Neural-Symbolic Environments.","published":"2026-06-10T15:15:01Z","updated":"2026-06-10T15:15:01Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.12191v1","pdf_url":"https://arxiv.org/pdf/2606.12191v1","comment":"63 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.13710","versioned_id":"2606.13710v2","title":"Hybrid Open-Ended Tri-Evolution Makes Better Deep Researcher","authors":["Hongming Piao","Chi Liu","Mengzhuo Chen","Yan Shu","Xidong Wang","Derek Li","Ying Wei","Bryan Dai"],"abstract":"Deep research and agent evolution serve as de-facto tasks for AI agents in real-world applications toward artificial general intelligence. The former enables autonomous retrieval and integration of information in open-ended environments to tackle open-ended research tasks, yet it is constrained by the static parametric deep research capabilities of agent systems. The latter allows agents to autonomously interact with the environment to gain experiences that evolve model capabilities. However, its effectiveness has been widely validated only on verifiable tasks with standard answers, leaving a gap with open-ended research tasks. To bridge these two critical tasks, we propose the Hybrid Open-Ended Tri-Evolution (HOTE) framework, which leverages hybrid-mode reinforcement learning to facilitate the collaborative evolution of a proposer, solver and judge based on web-scale knowledge, moving toward autonomous evolving agents in open-ended tasks and environments. Extensive experiments on three long-form deep research benchmarks demonstrate that the 8B model trained via HOTE surpasses the strongest static open 8-32B models as well as those trained by state-of-the-art deep research training methods with less time overhead, and further verify that the evolution of all three modules in HOTE is indispensable.","published":"2026-06-10T15:03:42Z","updated":"2026-06-15T13:53:01Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.13710v2","pdf_url":"https://arxiv.org/pdf/2606.13710v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.12018","versioned_id":"2606.12018v1","title":"MODF-SIR: A Multi-agent Omni-modal Distilled Framework for Social Intelligence Reasoning","authors":["Shang Ma","Jisheng Dang","Wencan Zhang","Yifan Zhang","Bimei Wang","Hong Peng","Bin Hu","Qi Tian","Tat-Seng Chua"],"abstract":"We propose a multi-agent collaborative framework built upon a lightweight Multimodal Large Language Model (MLLM), specifically designed for social intelligence reasoning. A key feature of our approach is that both the training and inference phases are augmented via knowledge distillation. Within this architecture, multi-modal data pertinent to social intelligence is precisely localized. Furthermore, relevant long-tail events are identified, extracted, and rendered as formatted, explicit text. This formatting strategy prevents critical long-tail information from being overshadowed by head events and environmental noise during the tokenization process. Specifically, we integrate Test-Time Adaptation (TTA) across the entire reasoning pipeline, encompassing the extraction and representation of long-tail events, Chain-of-Thought (CoT) prompting, and self-reflection. This TTA mechanism is also distillation-enhanced, utilizing Low-Rank Adaptation (LoRA) to fine-tune the foundation model exclusively for instance-level reasoning. Extensive evaluations against various open-source and proprietary AI models across multiple benchmarks demonstrate the effectiveness of the proposed framework. With around 30% of training data from IntentTrain, we achieve state-of-the-art results. Codes are available at https://github.com/eeee-sys/MODF-SIR, demo is available at https://huggingface.co/spaces/Harry-1234/MODF-SIR, LoRA is available at https://huggingface.co/Harry-1234/MODF-SIR and the dataset for training router is available at https://huggingface.co/datasets/Harry-1234/IntentRouterTrain.","published":"2026-06-10T12:44:02Z","updated":"2026-06-10T12:44:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.12018v1","pdf_url":"https://arxiv.org/pdf/2606.12018v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.11182","versioned_id":"2606.11182v1","title":"EEVEE: Towards Test-time Prompt Learning in the Real World for Self-Improving Agents","authors":["Weixian Xu","Shilong Liu","Mengdi Wang"],"abstract":"In this paper, we propose EEVEE, the first multi-dataset test-time prompt learning framework for LLM agents, enabling test-time prompt learning under real-world task streams. Existing methods are largely designed for single-dataset settings, while real-world applications require models to handle heterogeneous input streams drawn from multiple datasets, domains, and task distributions, limiting their practical applicability. To mitigate cross-dataset interference, EEVEE introduces a router that partitions incoming inputs into task clusters and assigns them to suitable prompt configurations. This design is optimized via a router-prompt co-evolution strategy, which employs interleaved router and prompt learning phases to address their mutual dependency. Experiments across multiple datasets demonstrate that the framework improves robustness under heterogeneous data streams while maintaining single-benchmark learning capability and efficiency. Specifically, EEVEE improves average multi-benchmark scores by 10.38 and 24.32 points over Qwen3-4B-Instruct and DeepSeek-V3.2, surpassing SOTA methods GEPA and ACE by up to 37.2% and 48.2%.","published":"2026-06-09T17:57:16Z","updated":"2026-06-09T17:57:16Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.11182v1","pdf_url":"https://arxiv.org/pdf/2606.11182v1","comment":"19 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.10546","versioned_id":"2606.10546v2","title":"SkillAxe: Sharpening LLM-Authored Agent Skills Through Evaluation-Guided Self-Refinement","authors":["Srishti Gautam","Arjun Radhakrishna","Sumit Gulwani"],"abstract":"Skill documents, structured natural-language instructions that guide Large Language Model (LLM) agents, are critical to modern agent frameworks, yet LLMs struggle to write skills that actually work. On SkillsBench, human-authored skills improve pass rates by 16.2 percentage points, while LLM-authored skills provide no measurable gain. We introduce SkillAxe, a fully unsupervised framework that enables LLMs to iteratively diagnose and refine their own skills. SkillAxe decomposes skill quality into four interpretable dimensions (quality impact, trigger precision, instruction compliance with fault attribution, and solution-path coverage), producing structured improvement briefs that require no ground-truth labels, test suites, or environment rewards. On SkillsBench, SkillAxe improves pass rates by 28\\% relative over unimproved LLM skills and closes 47--67\\% of the gap to human-authored skills. We validate the approach as a continuous improvement engine in the wild on SpreadsheetBench, where a SkillAxe-built skill library learns from past agent trajectories and raises pass rate from 16.0\\% to 52.0\\% using only 22 skills.","published":"2026-06-09T08:14:39Z","updated":"2026-06-10T07:58:45Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2606.10546v2","pdf_url":"https://arxiv.org/pdf/2606.10546v2","comment":"9 pages, under review","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.10241","versioned_id":"2606.10241v1","title":"Regimes: An Auditable, Held-Out-Gated Improvement Loop Demonstrated on LongMemEval with ActiveGraph","authors":["Yohei Nakajima"],"abstract":"Autonomous improvement loops are hard to trust because the improvement process is usually external scaffolding bolted onto the agent: failures go unlogged, diagnoses cannot be replayed, and promote-or-discard decisions land in a side database rather than the agent's own history. We show that an event-sourced agent runtime removes that friction and turns controlled improvement into a first-class workflow. When the agent's state is a deterministic projection of an append-only event log, failures are recorded, a run replays exactly from its log, candidate patches scope to typed pipeline seams, gates are auditable, and every promotion or discard is itself an event. We demonstrate this with Regimes, a loop on the ActiveGraph runtime that diagnoses failed evaluations, proposes a repair at a pipeline point, and promotes it only after static checks, sandbox execution, in-sample evaluation, and held-out validation. The loop is target-agnostic: the same control flow runs against different tasks through a common interface. On LongMemEval-S the dominant failure is not retrieval but reconciliation: the evidence is already in the assembled context, yet the reader answers incorrectly. Across five seeded held-out splits, Regimes discovers reader-prompt repairs that improve final held-out accuracy by +0.05 to +0.10 in four splits and +0.01 in one over-promotion split; two splits are individually significant (seed 5 unadjusted for its sequential promotion structure), and the pooled count is descriptive only, since the splits share one 500-question pool. The durable contributions are ActiveGraph as an auditable substrate that makes controlled improvement loops tractable, the held-out-gated loop it supports, the failure-regime taxonomy routing each failure to a pipeline location (whose marginal value over an unrouted baseline is the primary open question), and the prompt-as-discovery-probe hypothesis.","published":"2026-06-08T23:04:35Z","updated":"2026-06-08T23:04:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.10241v1","pdf_url":"https://arxiv.org/pdf/2606.10241v1","comment":"30 pages, 5 figures. Code and committed runs: https://github.com/yoheinakajima/regimes","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.09774","versioned_id":"2606.09774v2","title":"Auto-Configuring Scientific Simulators with Lightweight Coding-Agent Adapters","authors":["Matthew Ho","Brian Liu","Jixuan Chen","Audrey Wang","Lianhui Qin"],"abstract":"Configuring an advanced scientific simulator, translating a modeling goal into a valid, runnable input deck, is a persistent bottleneck that costs domain scientists hours to days. Input decks are executable interfaces: simulator-specific vocabulary, cross-file references, schema constraints, and validation rules must align before a simulation can run. We show that this bottleneck can be substantially reduced with a lightweight adapter around an off-the-shelf coding agent, rather than a bespoke simulator agent. Coding agents already navigate files, edit code, run commands, and repair outputs; what they lack is the simulator's executable contract, and rebuilding the agent loop risks discarding harness-calibrated tool-use and self-correction behavior. We introduce SIGA, a coding-agent adapter that supplies this contract through retrieval, procedural memory, agent-callable validation, and validation-gated termination while leaving the model and loop frozen. Because this contract is small and external, SIGA also supports adapter self-evolution: prior trajectories can rewrite the adapter contents without modifying the underlying agent. On GEOS, a multiphysics subsurface simulator, SIGA's main gain is reliability: on harder held-out tasks it improves TreeSim from 0.720 to 0.789 and reduces across-run standard deviation by about 16x by preventing empty or invalid decks. In a human calibration, SIGA reaches in about five minutes the deck quality a domain expert reached in about three hours. Transfers to OpenFOAM and LAMMPS show the recipe is portable but interface-dependent: completion gates help when structural completeness is the bottleneck, while memory and retrieval help when value correctness is.","published":"2026-06-08T17:35:17Z","updated":"2026-06-25T18:32:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09774v2","pdf_url":"https://arxiv.org/pdf/2606.09774v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2606.09748","versioned_id":"2606.09748v1","title":"Multi-Turn Evaluation of Deep Research Agents Under Process-Level Feedback","authors":["Rishabh Sabharwal","Hongru Wang","Amos Storkey","Jeff Z. Pan"],"abstract":"Existing benchmarks for deep research agents (DRAs) assess only single-shot outputs, ignoring a key question: can DRAs improve their reports when guided by feedback? To investigate this, we conduct a multi-turn evaluation of DRAs under two feedback settings: self-reflection, in which the agent revises its report without any external diagnostic signal, and process-level feedback, in which the agent receives guidance targeting gaps in its research strategy. To enable process-level feedback, we design Research Gap Inference (RGI), a method that analyzes patterns of satisfied and unsatisfied rubric criteria to infer research-process gaps. Our analysis reveals three key findings: (i) under self-reflection, agents incorporate and regress on rubric criteria at nearly equal rates, yielding negligible net improvement; (ii) a single round of process-level feedback yields substantial gains, raising the normalized score by approximately $8$-$15$ points and yielding a roughly $35$-$40\\%$ incorporation rate; (iii) these gains do not compound over subsequent turns, as agents regress on up to $24\\%$ of previously satisfied criteria when rewriting the full report to address remaining gaps. Even with targeted guidance, reliable multi-turn improvement remains out of reach for the DRA architectures we evaluate. Our code and results are publicly available at https://github.com/sabharwalrishabh/Multi-Turn-Evaluation-of-DRAs.","published":"2026-06-08T17:08:36Z","updated":"2026-06-08T17:08:36Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09748v1","pdf_url":"https://arxiv.org/pdf/2606.09748v1","comment":"Published as a workshop paper at SCALE - ICML 2026 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=HdgmfRmBq1","openreview_venues":["SCALE@ICML2026 Oral"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.09674","versioned_id":"2606.09674v1","title":"(Auto)formalization is supposed to be easy: Trellis process semantics for spelling out rigorous proofs","authors":["Wesley Pegden"],"abstract":"We present Trellis: an autoformalization system that leverages LLM agents in a deterministically constrained workflow to enforce incremental progress in Lean autoformalization tasks through iterative refinement of natural language proofs. Our approach is motivated by the common mathematician's notion of what it means to have a rigorous proof in the first place: namely, that it would be routine to elaborate any part of the proof in further detail. The result is a system which aims to achieve reliable autoformalization on a modest budget and with generalist agents, with specialization to autoformalization coming not from any task-specific agent training but instead from a meaning-of-rigor inspired workflow enforced by process semantics. We link to an end-to-end Lean formalization of a recent Ramsey theory breakthrough produced by the process.","published":"2026-06-08T15:57:14Z","updated":"2026-06-08T15:57:14Z","categories":["cs.AI","cs.LO","math.CO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09674v1","pdf_url":"https://arxiv.org/pdf/2606.09674v1","comment":"15 pages, 7 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.09663","versioned_id":"2606.09663v1","title":"From 0-to-1 to 1-to-N: Reproducible Engineering Evidence for MetaAI Recursive Self-Design","authors":["Dun Li","Jiatao Li","Hongzhi Li"],"abstract":"Recursive self-design refers to AI-assisted modification of the mechanisms by which an AI system is built, evaluated, and improved. This paper treats MetaAI not as a mature paradigm, but as a working term for a human-seeded, AI-expanded development pattern in which the design space itself becomes a target of modification. We propose an operational evidence framework with four criteria: inspectable target system, meta-level modifier, feedback-directed selection, and recursive continuation. We then map public systems, including Darwin Goedel Machine (DGM), STOP, Goedel Agent, and ShinkaEvolve, against these criteria. DGM provides the most direct currently reported evidence: its published results show improvement from 20% to 50% on SWE-bench Verified and from 14.2% to 30.7% on full Polyglot after 80 iterations, with ablations suggesting that both open-ended exploration and self-improvement contribute. Finally, we provide MetaAI-Mini, a reproducible HumanEval-based protocol and codebase. Because no completed model run is included in this build, MetaAI-Mini is reported as a protocol rather than as an experimental result.","published":"2026-06-08T15:45:15Z","updated":"2026-06-08T15:45:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09663v1","pdf_url":"https://arxiv.org/pdf/2606.09663v1","comment":"6 pages, 2 figures, 7 tables. Supplementary code: https://github.com/DunLi-Tsinghua/MetaAI-Mini","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.09365","versioned_id":"2606.09365v3","title":"Experience Makes Skillful: Enabling Generalizable Medical Agent Reasoning via Self-Evolving Skill Memory","authors":["Haoran Sun","Wenjie Li","Yujie Zhang","Zekai Lin","Fanrui Zhang","Kaitao Chen","Xingqi He","Yichen Li","Mianxin Liu","Lei Liu","Yankai Jiang"],"abstract":"Medical agent systems are increasingly expected to support interactive clinical decision making rather than only static question answering. In such settings, effective agents must reuse prior experience across evolving cases, yet existing memory mechanisms often retain raw historical traces that are redundant, noisy, and difficult to govern. More importantly, they rarely distinguish which memories are truly useful for future reasoning. This limits their ability to accumulate compact and reliable experience for long-horizon clinical reasoning. To close this gap, we propose SkeMex, a post-deployment self-evolution framework that improves medical agents through a skill-based memory without updating model weights. SkeMex distills informative interaction trajectories into structured skills that encode reusable procedural knowledge, and organizes them into a multi-branch repository spanning general, task-specific, and action-level experience. To determine which memories should be reused and retained, SkeMex estimates context-dependent utility from environment feedback and uses it to guide value-aware retrieval and repository governance. A closed-loop ``Read--Write--Assess--Govern\" lifecycle further supports continual evolution by writing new skills, updating utilities, promoting useful memories, and removing harmful entries. Experiments across diverse clinical tasks show that SkeMex consistently outperforms representative memory-based agents in both offline and online settings. It also generalizes across model backbones and supports transferable skill memory. All data and code will be released publicly.","published":"2026-06-08T11:37:01Z","updated":"2026-06-15T15:01:33Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.09365v3","pdf_url":"https://arxiv.org/pdf/2606.09365v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.08625","versioned_id":"2606.08625v2","title":"From Holistic Evaluation to Structured Criteria: Rubrics Across the Evolving LLM Landscape","authors":["Hao Chen","Ziyu Han","Yukun Yan","Qingfu Zhu","Maosong Sun","Wanxiang Che"],"abstract":"As Large Language Models (LLMs) advance toward open-ended autonomous agents, the mechanisms used to evaluate and guide their behavior must evolve accordingly. This work introduces the rubric as a unifying framework capturing this evolution, characterizing rubrics as a dynamic response to successive LLM paradigm shifts that recurs across otherwise independent efforts in evaluation, reinforcement learning, and safety alignment. We define rubrics as explicit criteria sets that transform complex quality judgments into structured and actionable standards, and demonstrate that their recurrence across these research threads is not coincidental. We systematically organize existing rubric designs, examine their construction and optimization, and analyze their role across evaluation and training. Rubrics manifest at three progressively deeper levels: at the evaluative level, they decompose holistic judgments into verifiable dimensions; at the training level, they serve as dense feedback signals providing process-level guidance where scalar rewards fall short; at the intrinsic level, they emerge dynamically from model behaviors, driving self-improvement. We further assess rubric reliability across generation quality, execution fidelity, theoretical constraints, and security threats, before surveying rubric-based benchmarks across diverse domains. By rendering assessment transparent and decomposable, rubrics translate human value expectations into machine-learnable signals, serving as the enduring bridge between human intentions and machine behavior.","published":"2026-06-07T13:34:55Z","updated":"2026-07-01T14:07:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08625v2","pdf_url":"https://arxiv.org/pdf/2606.08625v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.08539","versioned_id":"2606.08539v1","title":"AgentTrust: A Self-Improving Trust Layer for AI-Agent Actions","authors":["Chenglin Yang"],"abstract":"AI agents increasingly take consequential actions -- shell commands, cloud operations, and arbitrary tool-calls -- so a trust layer must decide, per action, whether to allow, warn, block, or escalate. We argue that the right way to reason about such a layer is by threat type. Lexical (fixed-signature) threats, where danger lives in a stable token, are decidable by deterministic rules; semantic (intent-dependent) threats, where a benign and a malicious action share the same surface, are out of reach for rules by construction. We make this concrete with a negative proof: a determined, hand-authored cloud rule pack lifts held-out accuracy only 48 to 56% overall and moves the semantic categories by 0pp (data_db 29 to 29, observability 59 to 59, supply_chain 50 to 50), while a strong LLM judge carries exactly those categories. We give the judge a self-learning capability: on a corpus that is mainly semantic attacks it nearly doubles rule accuracy (48% to 83.6-85.2%) with near-zero false-blocks, and this holds across two model providers. We turn this into a self-improving dual-store system: the judge distills a growing deterministic rule floor on lexical threats (cheaper over time) and feeds a guarded RAG memory on semantic threats (a verdict-cache fails -- surface-twins collapse to ~58% -- so a corroboration guard lifts semantic accuracy +13pp, 70 to 84). The result is what sets AgentTrust v2 apart from its static v1 predecessor: a trust layer that self-evolves from its own stream of decisions -- cheaper on the lexical class (it distils its own rules) and smarter on the semantic class (it accrues guarded precedent), while never hard-blocking a benign action. An end-to-end online replay shows the judge-call rate falling (50% to 44%) and judge-domain accuracy rising (71% to 80%), with 0 benign hard-blocks across 45,000 actions.","published":"2026-06-07T09:39:20Z","updated":"2026-06-07T09:39:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.08539v1","pdf_url":"https://arxiv.org/pdf/2606.08539v1","comment":"29 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.08254","versioned_id":"2606.08254v1","title":"SSR: Can Simulated Patients Learn to Stigmatize Themselves? Modeling Self-Stigma through Internal Monologue","authors":["Kunyao Lan","Bingrui Jin","Zichen Zhu","Mengyue Wu"],"abstract":"Simulating patients with large language models (LLMs) is a promising tool for mental health training, but existing approaches fail to capture a key clinical reality: self-stigma. Patients experiencing self-stigma, the internalization of negative stereotypes, often exhibit context-sensitive resistance, such as avoidance, denial, or self-blame, which current models render as static or uniformly compliant behavior. To address this, we introduce a novel simulation framework grounded in the psychological 3A1H model of self-stigmatization. Our core innovation is the creation of a \\textbf{Stigmatized Self-Reflection} (\\textbf{SSR}) dataset, where we augment mental health dialogues with internal monologues that reflect stigma-aware reasoning. By fine-tuning LLMs with this data using a chain-of-thought approach, we train patient agents to dynamically adjust their level and expression of stigma based on conversational triggers. Evaluations demonstrate that our approach significantly outperforms specialized baselines, generating more authentic and situationally appropriate patient responses. This work provides a crucial step towards realistic stigma simulation for clinical training and empathetic dialogue systems.","published":"2026-06-06T16:50:57Z","updated":"2026-06-06T16:50:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.08254v1","pdf_url":"https://arxiv.org/pdf/2606.08254v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.08106","versioned_id":"2606.08106v1","title":"PACE: Anytime-Valid Acceptance Tests for Self-Evolving Agents","authors":["Zayx Shawn"],"abstract":"Self-evolving agents improve by repeatedly proposing changes to their own prompts, skills, or workflows and keeping those that score higher on a small held-out set. Almost all effort has gone into the proposer that generates candidates; we argue the weak point is the acceptor, the rule that decides whether to commit a change. Applied hundreds of times against the same noisy dev estimate, the ubiquitous \"keep it if the score went up\" rule is uncontrolled adaptive multiple testing: the agent effectively p-hacks itself, accumulating false commits that make it churn and drift rather than improve. We recast committing as a sequential hypothesis test and propose PACE (Paired Anytime-valid Commit Evaluation), a training-free, anytime-valid commit gate. Each candidate is compared to the incumbent on identical instances and committed only when a testing-by-betting e-process accumulates decisive evidence, stopping early to save evaluations and controlling each candidate's false-commit probability at a user-set level even under optional stopping (a per-decision guarantee). On Qwen2.5 agents (0.5B-3B) self-evolving at the prompt level on GSM8K, SVAMP, and ARC-Challenge, greedy acceptance commits 30-42% false and 10-33% harmful edits when a genuine improvement is hidden among noisy proposals, while PACE commits the real one and essentially nothing else, matching greedy's held-out accuracy at sharply lower variance and about 18% lower evaluation cost. With no real gain available, greedy commits 13-21 spurious self-modifications per run (72-100% false) and degrades the most fragile agent by 4.9 points, while PACE holds at baseline. Reliability of self-evolution depends on the acceptor, not only on the proposer.","published":"2026-06-06T11:12:11Z","updated":"2026-06-06T11:12:11Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.08106v1","pdf_url":"https://arxiv.org/pdf/2606.08106v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.07412","versioned_id":"2606.07412v1","title":"Socratic-SWE: Self-Evolving Coding Agents via Trace-Derived Agent Skills","authors":["Chuan Xiao","Zhengbo Jiao","Shaobo Wang","Wei Wang","Bing Zhao","Hu Wei","Linfeng Zhang","Lin Qu"],"abstract":"LLM-driven software engineering agents have become a central testbed for real-world language-model capability, yet their training remains limited by the availability of high-quality SWE tasks. Existing synthetic data methods typically create tasks through fixed mutation or bug-injection procedures, making the resulting distributions largely independent of the agent's own weaknesses and training progress. We introduce Socratic-SWE, a closed-loop self-evolution framework that reuses the agent's historical solving traces as a source of training signal. Rather than treating traces only as evidence for reward computation, Socratic-SWE distills them into structured agent skills that summarize recurring failures and effective repair patterns. These skills then guide the generation of targeted repair tasks in real repositories. Candidate tasks are checked through execution-based validation and scored with a solver-gradient alignment reward, so that the retained tasks are both verifiable and useful for improving the Solver. The updated Solver produces new traces, enabling the task curriculum to adapt over successive rounds. Across SWE-bench Verified, SWE-bench Lite, SWE-bench Pro, and Terminal-Bench 2.0, Socratic-SWE consistently improves over self-evolving baselines under the same compute budget, reaching 50.40% on SWE-bench Verified after three iterations. These results suggest that solving traces can serve as a scalable substrate for self-evolving SWE agents.","published":"2026-06-05T16:00:17Z","updated":"2026-06-05T16:00:17Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.07412v1","pdf_url":"https://arxiv.org/pdf/2606.07412v1","comment":"21 pages, 5 figures. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.07367","versioned_id":"2606.07367v1","title":"Self-evolving LLM agents with in-distribution Optimization","authors":["Yudi Zhang","Meng Fang","Zhenfang Chen","Mykola Pechenizkiy"],"abstract":"Large Language Models (LLMs) have recently emerged as powerful controllers for interactive agents in complex environments, yet training them to perform reliable long-horizon decision making remains a fundamental challenge. A key difficulty lies in credit assignment: agents often receive delayed rewards only at the end of episodes. In this paper, we propose Q-Evolve, a self-evolving framework for LLM agents that unifies automatic process-reward labeling and policy learning within a principled in-distribution reinforcement learning paradigm. In each evolving iteration, our method learns an in-distribution critic from a hybrid off-policy dataset that combines expert demonstrations with agent-generated trajectories, stabilizing Bellman backups in sparse-reward settings via a weighted Implicit Q-Learning objective. The learned value function is then used to derive step-wise process rewards through advantage estimation, enabling dense and reliable supervision without environment backtracking or human annotation. Leveraging these signals, we perform behavior-proximal policy optimization that evolves the agent over the data used for process reward labeling, allowing iterative self-improvement without exacerbating distribution shift. We evaluate our method on AlfWorld, WebShop, and ScienceWorld, showing Q-Evolve outperforms strong baselines in sample efficiency, robustness, and overall task performance. Our results demonstrate that stable agent self-evolution is achievable through the co-evolution of process-level supervision and policy, both grounded within a shared in-distribution learning loop.","published":"2026-06-05T15:09:52Z","updated":"2026-06-05T15:09:52Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.07367v1","pdf_url":"https://arxiv.org/pdf/2606.07367v1","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=kXGolRT8YX","openreview_venues":["ICML 2026 regular"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2606.07711","versioned_id":"2606.07711v1","title":"Rosetta Memory: Adaptive Memory for Cross-LLM Agents","authors":["Hao Yang","Shiqi Shen","Haoxuan Li","Zhipeng Wang","Zhi Gong","Xu Chen"],"abstract":"Memory is the key component for transforming a stateless LLM into a persistent, evolving agent through experience accumulation, long-horizon planning, and continual self-improvement. Existing memory systems typically take the LLM as the center and design memory operations tailored to a specific backbone. In practice, however, users frequently switch between LLMs, for example using Claude for coding and GPT for writing across tasks, or routing different steps to different backbones within a single task for cost-effective trade-offs. As a result, memory written by one model often needs to be consumed by another. Making upstream memory effectively adapt to and activate downstream LLMs remains a critical yet underexplored problem. To bridge this gap, we shift the perspective from LLM-centric memory design to \\emph{memory-centric LLM adaptation}. Specifically, we approach the above upstream-downstream memory adaptation problem from both the write and read sides, and design two profile-conditioned operators that are jointly trained to optimize how memory is stored and presented for better task completion. To ensure the learned operators generalize across a broad set of LLMs, we propose a minimum-gain sampling curriculum that prioritizes the least-served LLMs during training. To better measure the operators' actual contribution rather than the LLM's own capability, we design a performance-gap reward that compares against a naive memory baseline. Experiments on HotpotQA, 2WikiMultihopQA, and MuSiQue demonstrate that our model consistently outperforms baselines and remains robust under unseen-model replacement.","published":"2026-06-05T13:50:59Z","updated":"2026-06-05T13:50:59Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.07711v1","pdf_url":"https://arxiv.org/pdf/2606.07711v1","comment":"19 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:AwzESff0nE","versioned_id":"AwzESff0nE","title":"WarehouseAI: Knowledge Graph-Grounded Multi-Agent Reasoning Framework for Simulation-Driven Warehouse Planning","authors":["Himabindu Thogaru","Anirudh Deodhar","Purvaja Ammanabrolu"],"abstract":"Enterprise AI agents often struggle to accurately reason over dense, multi-stage relational logs produced by industrial simulators. In this paper, we introduce Warehouse AI, a closed-loop multi-agent system designed for automated warehouse optimization built on a Knowledge Graph-grounded framework. The architecture translates natural language intent into simulation parameters, executes a SimPy-driven Discrete Event Simulation (DES), and maps the resulting event logs into a Neo4j knowledge graph. At its analytical core, a dual-path Knowledge Graph Question Answering (KG-QA) reasoning chain processes both operational queries through direct Cypher retrieval and investigative queries through adaptive multi-hop evidence accumulation, with semantically decomposed query generation and two-level self-correction. Orchestrated via a hierarchical LangChain network, six specialized agents coordinate a complete planning cycle: Configure $\\to$ Simulate $\\to$ Analyze $\\to$ Recommend $\\to$ Validate. Across 9 independent trials spanning 3 bottleneck scenarios, each designed with non-obvious root causes where surface symptoms point to the wrong resource tier, the system achieves 100\\% orchestration accuracy, simulation validity, recommendation grounding and loop improvement rate, with composite evaluation scores of 0.780-0.859 and package processing time reductions of up to 30\\% per cycle. The KG-QA engine achieves Pass@1 = 0.92 on a 25-question benchmark, substantially outperforming single-pass generation (0.59) and self-reflection baselines (0.70). Planning loops demonstrating that structural grounding and hierarchical agent orchestration together deliver the reliability and efficiency required for autonomous industrial decision-making.","published":"2026-06-05T11:47:19+00:00","updated":"2026-06-10T15:56:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=AwzESff0nE","openreview_url":"https://openreview.net/forum?id=AwzESff0nE","pdf_url":"https://openreview.net/pdf?id=AwzESff0nE","comment":"GMLLM'26 Poster","journal_ref":"GMLLM'26 Poster","doi":"","venue":"GMLLM'26 Poster","venue_id":"KDD.org/2026/Workshop/GMLLM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2606.06960","versioned_id":"2606.06960v1","title":"Tree-of-Experience: A Structured Experience-Management Solution for Self-Evolving Agents under Low-Repetition and Implicit-Reward Environments","authors":["Zihao Deng","Yining Zhu","Leiming Wang","Jingfei Lu","Junbo Wang","Chuncheng Ran","Yu Yang","Dixuan Yang","Jikun Shen"],"abstract":"Experience-based self-evolution is crucial for LLM agents, but existing benchmarks often assume explicit goals, stable task patterns, and clear feedback. We study a more challenging setting: low-repetition tasks with implicit rewards, where past experience is difficult to reuse and feedback is delayed, noisy, and outcome-level. We introduce \\textsc{FinEvolveBench}, a temporally controlled benchmark for financial sentiment prediction that links daily news-driven predictions to future excess returns. We further propose Tree-of-Experience (ToE), a structured experience-management method that organizes, retrieves, validates, and updates agent experience. Experiments show that general-purpose experience mechanisms do not consistently outperform no-experience baselines, while ToE achieves stronger overall performance. These results highlight the importance of structured experience management for self-evolving agents in implicit-reward environments.","published":"2026-06-05T06:39:16Z","updated":"2026-06-05T06:39:16Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.06960v1","pdf_url":"https://arxiv.org/pdf/2606.06960v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.06741","versioned_id":"2606.06741v1","title":"OpenSkill: Open-World Self-Evolution for LLM Agents","authors":["Zhiling Yan","Dingjie Song","Hanrong Zhang","Wei Liang","Yuxuan Zhang","Yutong Dai","Lifang He","Philip S. Yu","Ran Xu","Xiang Li","Lichao Sun"],"abstract":"Self-evolving agents requires adaptation after deployment, but existing approaches assume a usable learning loop, such as curated skills, successful trajectories, or verifier signals. Real open-world deployments may provide none of these, offering only a task prompt. In this work, we study open-world self-evolution, where an agent must build both its skills and its own verification signals from scratch, using open-world resources but no target-task supervision. We propose OpenSkill, a framework that bootstraps this loop: it acquires grounded knowledge and verification anchors from documentation, repositories, and the web, synthesizes them into transferable skills, and refines those skills against self-built virtual tasks grounded in the anchors rather than in target answers. The open world thus supplies both the knowledge to be learned and a supervision-independent practice environment, with target-task supervision reserved for final evaluation. Across three benchmarks and two target agents, OpenSkill attains the best automated pass rate while satisfying the no-supervision constraint. Analysis shows its skills transfer across models without model-specific adaptation, and its self-built verifier aligns with ground-truth outcomes despite never accessing them.","published":"2026-06-04T21:55:48Z","updated":"2026-06-04T21:55:48Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.06741v1","pdf_url":"https://arxiv.org/pdf/2606.06741v1","comment":"20 pages, 4 figures and 8 tables. Code is avalable at https://github.com/OpenLAIR/OpenSkill","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.06473","versioned_id":"2606.06473v1","title":"MLEvolve: A Self-Evolving Framework for Automated Machine Learning Algorithm Discovery","authors":["Shangheng Du","Xiangchao Yan","Jinxin Shi","Zongsheng Cao","Shiyang Feng","Zichen Liang","Boyuan Sun","Tianshuo Peng","Yifan Zhou","Xin Li","Jie Zhou","Liang He","Bo Zhang","Lei Bai"],"abstract":"Large language model (LLM) agents are increasingly applied to long-horizon tasks such as scientific discovery and machine learning engineering (MLE), where sustained self-evolution becomes a key capability. However, existing MLE agents suffer from inter-branch information isolation, memoryless search, and lack of hierarchical control, which together hinder long-horizon optimization. We present MLEvolve, an LLM-based self-evolving multi-agent framework for end-to-end machine learning algorithm discovery. By extending tree search to Progressive MCGS, MLEvolve enables cross-branch information flow through graph-based reference edges and gradually shifts the search from broad exploration to focused exploitation with an entropy-inspired progressive schedule. To allow the agent to evolve with accumulated experience, we introduce Retrospective Memory, which combines a cold-start domain knowledge base with a dynamic global memory for task-specific experience retrieval and reuse. For stable long-horizon iteration, we further decouple strategic planning from code generation with adaptive coding modes. Evaluation on MLE-Bench shows that MLEvolve achieves state-of-the-art performance across multiple dimensions including average medal rate and valid submission rate under a 12-hour budget (half the standard runtime). Moreover, MLEvolve also outperforms specialized algorithm discovery methods including AlphaEvolve on mathematical algorithm optimization tasks, demonstrating strong cross-domain generalization. Our code is available at https://github.com/InternScience/MLEvolve.","published":"2026-06-04T17:55:59Z","updated":"2026-06-04T17:55:59Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.06473v1","pdf_url":"https://arxiv.org/pdf/2606.06473v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.06324","versioned_id":"2606.06324v2","title":"From Failed Trajectories to Reliable LLM Agents: Diagnosing and Repairing Harness Flaws","authors":["Mengzhuo Chen","Junjie Wang","Zhe Liu","Yawen Wang","Haiming Zheng","Qing Wang"],"abstract":"LLM agents increasingly rely on agent harness: the runtime infrastructure around the base model that defines execution environments, tool interfaces, context, lifecycle orchestration, observability, verification, and governance. Existing self-improving agents and automatic harness evolution methods mainly improve agents through runtime supervision, prompt optimization, workflow search, or harness modification based on final outcomes. However, they often fail to diagnose where the responsible evidence lies in failed trajectories and which harness implementation mechanism causes the unreliable behavior, resulting in broad, indirect, or poorly scoped changes. This paper proposes HarnessFix, a trace-grounded and diagnosis-driven framework for repairing agent harnesses. HarnessFix compiles raw execution traces and harness artifacts into a Harness-aware Trace Intermediate Representation (HTIR), which normalizes fragmented trajectory evidence, captures step-level data-flow and control-flow relations, and aligns runtime steps with the harness artifacts that shape their behavior. It then attributes failures to responsible steps and harness artifacts, and consolidates recurring diagnoses into repair-oriented flaw records. Finally, HarnessFix maps these records to scoped repair operators, generates patches under flaw-specific repair specifications, and accepts them through regression-aware validation. We evaluate HarnessFix on four popular benchmarks, and results show that it improves the performance over the initial harnesses by 6.3% to 18.4%, significantly outperforming human-designed and self-evolution baselines. HarnessFix highlights the value of treating failed trajectories not only as feedback signals, but also as structured evidence for diagnosing and repairing the harness mechanisms behind agent failures.","published":"2026-06-04T15:58:30Z","updated":"2026-07-02T04:35:01Z","categories":["cs.SE","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.06324v2","pdf_url":"https://arxiv.org/pdf/2606.06324v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.06114","versioned_id":"2606.06114v2","title":"Towards Healthy Evolution: Exploring the Role and Mechanisms of Human-Agent Interaction in Self-Evolving Systems","authors":["Dianxing Shi","Bowen Wang","Junqi He","Junhao Chen","Yuta Nakashima"],"abstract":"Self-evolving agents improve through continual self-play and self-generated learning signals, but autonomous evolution can also cause capability degradation and safety drift. Although human feedback has proven effective for static and post-trained agents, its role in self-evolving systems remains underexplored. We introduce Agent Norm Correction through Human-like Oversight and Review (ANCHOR), an LLM-based framework that simulates human supervision and delivers feedback at various phases of self-evolution. With ANCHOR, we evaluate two representative open-source self-evolving agent systems across coding, mathematical reasoning, and safety. Our results show that even limited supervision substantially mitigates safety degradation while preserving stable performance on core evolutionary objectives. Further analysis shows that supervision over the output verification phase is the most effective for intervention, whereas increasing supervision frequency yields diminishing returns. These findings provide empirical evidence and practical guidance for designing more stable, controllable, and human-aligned self-evolving agent systems.","published":"2026-06-04T13:03:16Z","updated":"2026-06-06T08:23:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.06114v2","pdf_url":"https://arxiv.org/pdf/2606.06114v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:REGaZA2FmT","versioned_id":"REGaZA2FmT","title":"SAGE: A Self-Evolving Agentic Graph-Memory Engine for Structure-Aware Associative Memory","authors":["Juntong Wang","Haoyue Zhao","guanghui Pan","Xiyuan Wang","Yanbo Wang","Qiyan Deng","Muhan Zhang"],"abstract":"Long-term memory is becoming a central bottleneck for language agents. Existing RAG and GraphRAG systems largely treat memory graphs as static retrieval middleware, which limits their ability to recover complete evidence chains from partial cues, exploit reusable graph-structural roles, and improve the memory itself through downstream feedback. We introduce \\method{}, a \\textbf{S}elf-evolving \\textbf{A}gentic \\textbf{G}raph-memory \\textbf{E}ngine that models graph memory as a dynamic long-term memory substrate. \\method{} couples two roles: a memory writer that incrementally constructs structured graph memory from interaction histories, and a Graph Foundation Model-based memory reader to perform retrieval and provide feedback to the memory writer. We provide rigorous theoretical analyses supporting the effectiveness of carefully designed architectural components and the framework. Across multi-hop QA, open-domain retrieval, domain-specific review QA, and long-term agent-memory benchmarks, SAGE improves evidence recovery, answer grounding, and retrieval efficiency: after two self-evolution rounds, it achieves the best average rank on multi-hop QA; in zero-shot open-domain transfer, it reaches 82.5/91.6 Recall@2/5 on NQ. Further results on LongMemEval and HaluMem show that training and reader--writer feedback improve multiple long-term memory and hallucination-diagnostic metrics, suggesting that self-evolving, structure-aware graph memory is a promising foundation for robust long-horizon language agents. Our code is available at https://anonymous.4open.science/r/Unified-Representation-A9D9/","published":"2026-06-04T12:48:38+00:00","updated":"2026-06-10T15:56:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=REGaZA2FmT","openreview_url":"https://openreview.net/forum?id=REGaZA2FmT","pdf_url":"https://openreview.net/pdf?id=REGaZA2FmT","comment":"GMLLM'26 Oral","journal_ref":"GMLLM'26 Oral","doi":"","venue":"GMLLM'26 Oral","venue_id":"KDD.org/2026/Workshop/GMLLM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.05976","versioned_id":"2606.05976v1","title":"The Self-Correction Illusion: LLMs Correct Others but Not Themselves","authors":["Kuan-Yen Chen","Fang-Yi Su","Jung-Hsien Chiang"],"abstract":"Recent work shows that LLM agents struggle to correct errors in their own reasoning traces yet show markedly higher correction rates when identical claims appear under external sources. We ask whether this asymmetry reflects a capability deficit or a role-label artifact: does an agent's willingness to correct a wrong claim depend causally on the chat-template role that carries it, rather than on the claim's content? Our setup keeps the erroneous claim byte-identical across all conditions (SHA-256 verified) and varies only its wrapping role: the agent's own \\role{<thought>}, a \\role{user} message, a \\role{tool} response, or a \\role{system <memory>} block. Across 13 model-domain cells covering seven model families and three domains ($n{=}30$ paired tasks per cell), relabeling the claim from \\role{<thought>} to an external role lifts the explicit-correction rate by 23 to 93 percentage points, with 10 of 13 cells reaching $p{<}0.001$. Further experiments confirm that the effect is asymmetric, mechanistically decomposable, and robust across domains. The failure to self-correct is not a cognitive deficit; it is a chat-template artifact. We exploit this artifact by designing a prompt-structure-only intervention that requires no training and no model modification, with its strongest role label being domain-dependent: \\role{<memory>} dominates on math, while a plain \\role{user} message dominates on logical deduction.","published":"2026-06-04T10:17:00Z","updated":"2026-06-04T10:17:00Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.05976v1","pdf_url":"https://arxiv.org/pdf/2606.05976v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.05684","versioned_id":"2606.05684v1","title":"AdaMEM: Test-Time Adaptive Memory for Language Agents","authors":["Yunxiang Zhang","Yiheng Li","Ali Payani","Lu Wang"],"abstract":"A central challenge for language agents is utilizing past experience to adapt to dynamic test-time conditions. While recent work demonstrates the promise of agentic memory mechanisms, most systems restrict retrieval to episode initiation. Consequently, agents are forced to rely on static guidance that becomes increasingly misaligned as long-horizon tasks unfold. To address this rigidity, we propose the Adaptive Memory Agent (AdaMEM), a novel framework for agent test-time adaptation. Without updating model parameters online, AdaMEM adapts agent behavior via a hybrid memory architecture: it maintains a long-term trajectory memory of raw experiences collected offline while generating dynamic short-term strategy memory on-the-fly to guide decision-making. This mechanism enables the trade-off between token efficiency and adaptability across varying inference-time compute levels. Empirically, AdaMEM significantly outperforms static memory baselines, achieving relative gains of up to 13% on ALFWorld and 11% on WebShop, with consistent leading performance extending to agentic search on HotpotQA. To further enhance this adaptation, we develop STEP-MFT, a Step-wise Memory Fine-Tuning technique that trains the policy to synthesize high-quality strategies from retrieved experiences, yielding additional performance gains. Our work establishes a new scaling dimension for agentic memory, supporting continuous reasoning and self-evolution post-deployment in real-world environments. Our code is available at https://github.com/yunx-z/AdaMEM.","published":"2026-06-04T04:06:08Z","updated":"2026-06-04T04:06:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.05684v1","pdf_url":"https://arxiv.org/pdf/2606.05684v1","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=RzlmkviaNy","openreview_venues":["ICML 2026 regular"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.05395","versioned_id":"2606.05395v1","title":"VASO: Formally Verifiable Self-Evolving Skills for Physical AI Agents","authors":["Yunhao Yang","Neel P. Bhatt","Kevin Wang","Samuel Tetteh","Zhangyang Wang","Ufuk Topcu"],"abstract":"Reusable robot skills are becoming the basic units through which embodied agents turn open-ended instructions into long-horizon physical behavior. We argue that, while foundation models have collapsed the cost of creating these skills, the cost of trusting them has not. Existing skill-evolution loops refine skills through execution feedback, unit tests, environment reward, or LLM self-critique, but these signals provide only trace-level evidence: they show that a skill worked on sampled executions, not that skill-induced plans satisfy temporal safety contracts under untested conditions. We introduce VASO, a framework for verification-guided self-evolution of LLM-generated robot skill contracts. In VASO, each skill is represented as a semantic contract with two coupled interfaces: a formal interface that aligns robot states, observations, and control commands with logical propositions for model checking, and a planner-facing interface that guides executable behavior generation. A model checker first filters logically inconsistent skill contracts, then verifies plans induced by the skill against global and local temporal specifications. When verification fails, VASO translates the counterexample trace into a textual gradient that updates the reusable skill contract while keeping foundation-model weights frozen. On Clearpath Jackal and PX4 quadcopter tasks, VASO reaches 97.2% formal-specification compliance using fewer than 100 optimization samples, outperforming execution-feedback, prompt-optimization, and fine-tuning baselines. To our knowledge, VASO is the first framework that closes the loop between formal verification and self-evolving LLM-generated skills for physical AI agents: formal counterexamples become optimization feedback for reusable robot skill contracts, rather than merely verifying one-off plans, tuning planner prompts, or fine-tuning model weights.","published":"2026-06-03T20:02:35Z","updated":"2026-06-03T20:02:35Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.05395v1","pdf_url":"https://arxiv.org/pdf/2606.05395v1","comment":"Project webpage: https://languagegroundedriskdetection.github.io/ProjectPage/vaso-webpage/","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.05050","versioned_id":"2606.05050v2","title":"Autonomous heterogeneous catalyst discovery with a self-evolving multi-agent digital twin","authors":["Zhilong Song","Zongmin Zhang","Lixue Cheng"],"abstract":"Theoretical heterogeneous catalysis promises rapid catalyst discovery, yet computational and machine-learning predictions often deviate from experiment and stay confined to narrow material families, for want of a faithful, condition-aware catalytic simulator. We present CatDT (Catalysis Digital Twin), a self-evolving multi-agent system that builds an autonomous digital twin of a working catalyst, unifying gas-solid and liquid-solid modeling. From only a bulk crystal and a natural-language reaction description, eight specialized agents and 27 scientific tools predict stable facets, reconstruct working surfaces, enumerate and rank reaction pathways, locate transition states, and compute kinetics in 5-30 min on a single GPU. Two innovations address the hardest steps: UniMech finds dominant pathways for novel materials at over $10^3\\times$ lower cost than exhaustive enumeration by fusing agent-guided proposals with energy-cached graph search, and a memory-augmented reinforcement loop raises barrier-calculation success from 41% to 84% across 600 catalytic surfaces. Across seven gas-solid benchmarks -- stepped metals, single-atom catalysts, ordered intermetallics, vacancy-rich 2D sulfides and carbides, and a strong-metal--support-interaction (SMSI) interface -- every CatDT prediction lies within 0.5-2 times experiment over four orders of magnitude. For propane dehydrogenation, CatDT independently discovers non-precious candidates rivaling the Pt-based industrial benchmark, with a proposed Ni@ZrO$_2$ SMSI overlayer reaching a simulated TOF of $1.63~\\text{s}^{-1}$ at $\\sim$100% selectivity. More broadly, the decisive factor for a faithful catalyst digital twin -- or any multi-stage scientific simulator -- is not raw LLM capability but the engineered harness around it: deterministic tools, persistent memory, and verified self-improvement that compound across models, tools, and runs.","published":"2026-06-03T16:10:58Z","updated":"2026-07-09T03:42:47Z","categories":["cond-mat.mtrl-sci","cs.AI","physics.chem-ph"],"primary_category":"cond-mat.mtrl-sci","arxiv_url":"https://arxiv.org/abs/2606.05050v2","pdf_url":"https://arxiv.org/pdf/2606.05050v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:ELg8kRK9Wd","versioned_id":"ELg8kRK9Wd","title":"AIRS-Bench: A Suite of Tasks for Frontier AI Research Science Agents","authors":[],"abstract":"LLM agents hold significant promise for advancing scientific research. To accelerate this progress, we introduce AIRS-Bench (the AI Research Science Benchmark), a suite of 20 tasks sourced from state-of-the-art machine learning papers. These tasks span diverse domains, including language modeling, mathematics, bioinformatics, and time series forecasting. AIRS-Bench tasks assess agentic capabilities over the full research lifecycle—including idea generation, experiment analysis and iterative refinement—without providing baseline code. The AIRS-Bench task format is versatile, enabling easy integration of new tasks and rigorous comparison across different agentic frameworks. We establish baselines using frontier models paired with both sequential and parallel scaffolds. Our results show that agents exceed human SOTA in seven tasks but fail to match it in thirteen others. Even when agents surpass human benchmarks, they do not reach the theoretical performance ceiling for the underlying tasks. These findings indicate that AIRS-Bench is far from saturated and offers substantial room for improvement. We open-source the AIRS-Bench task definitions and evaluation code to catalyze further development in autonomous scientific research.","published":"2026-06-03T08:49:06+00:00","updated":"2026-06-18T23:59:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ELg8kRK9Wd","openreview_url":"https://openreview.net/forum?id=ELg8kRK9Wd","pdf_url":"https://openreview.net/pdf?id=ELg8kRK9Wd","comment":"Under review for TMLR","journal_ref":"Under review for TMLR","doi":"","venue":"Under review for TMLR","venue_id":"TMLR/Under_Review","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.04455","versioned_id":"2606.04455v1","title":"The Meta-Agent Challenge: Are Current Agents Capable of Autonomous Agent Development?","authors":["Xinyu Lu","Tianshu Wang","Pengbo Wang","zujie wen","Zhiqiang Zhang","Jun Zhou","Boxi Cao","Yaojie Lu","Hongyu Lin","Xianpei Han","Le Sun"],"abstract":"Current AI benchmarks evaluate agents on task execution within human-designed workflows. These evaluations fundamentally fail to measure a critical next-level capability: whether models can autonomously develop agent systems. We introduce the Meta-Agent Challenge (MAC), an evaluation framework designed to test the capacity of frontier models for autonomous agent development. Specifically, a code agent (the meta-agent) is given a sandboxed environment, an evaluation API, and a time limitation to iteratively program an agent artifact that maximizes performance on a held-out test set across five domains. To ensure evaluation integrity, this framework is secured by multi-layer defenses against reward hacking. Leveraging this framework, we demonstrate that meta-agents rarely match human-engineered baseline policies, and the few that do are dominated by proprietary frontier models. Moreover, the design process exhibits high variance, and high optimization pressure surfaces emergent adversarial behaviors like ground-truth exfiltration-highlighting critical deficits in both robustness and model alignment. Ultimately, MAC provides a rigorous, open-source benchmark for autonomous AI research and development, offering an empirical proxy for evaluating recursive self-improvement. Benchmark is publicly available at: https://github.com/ant-research/meta-agent-challenge.","published":"2026-06-03T04:58:17Z","updated":"2026-06-03T04:58:17Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.04455v1","pdf_url":"https://arxiv.org/pdf/2606.04455v1","comment":"Website: https://meta-agent-challenge.com/","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2606.28347","versioned_id":"2606.28347v1","title":"Agentic Safety is an Epistemic Property, Not a Behavioral One","authors":["Charles L. Wang","Keir Dorchen","Peter Jin"],"abstract":"Contemporary AI safety spans pre-training interventions, post-training alignment, deployment-time controls, monitoring, and red-teaming. These methods are necessary, but they primarily certify snapshots of system behavior. As AI systems become more capable, dynamic, embodied, and self-improving, this snapshot view becomes incomplete: safety depends not only on whether a system behaves acceptably now, but whether it remains correctable as it learns, adapts, acts, and modifies itself over time. This paper argues that safety should therefore be treated as an epistemic property of the evolving learner, not merely a behavioral property of the current policy. We introduce teachability as the capacity to preserve future corrective leverage under bounded human, institutional, or environmental intervention. We argue that advanced systems can retain visible competence while eroding the representational, algorithmic, or meta-decision conditions needed for future correction. Safe advanced AI systems must not only behave acceptably now; they must remain teachable later.","published":"2026-06-02T17:59:25Z","updated":"2026-06-02T17:59:25Z","categories":["cs.CY","cs.AI","cs.LG"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2606.28347v1","pdf_url":"https://arxiv.org/pdf/2606.28347v1","comment":"To appear in proceedings of ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.03963","versioned_id":"2606.03963v3","title":"AgenticRL: Self-Refining Agentic Reinforcement Learning for Vision-Conditioned UAV Navigation","authors":["Roohan Ahmed Khan","Yasheerah Yaqoot","Amir Atef Habel","Muhammad Ahsan Mustafa","Dzmitry Tsetserukou"],"abstract":"Deep reinforcement learning has shown strong potential for enabling autonomous robots to learn complex navigational tasks. However, its practical use still depends heavily on human designed reward functions and repeated manual fine tuning, which is time consuming and does not guarantee high success in the desired task. This paper presents AgenticRL, agent guided reinforcement learning framework that increases autonomy in reward design, policy refinement, and real world deployment for unmanned aerial vehicles (UAV) navigation tasks. AgenticRL uses a multimodal generative pre-trained transformer (GPT) agent to interpret task information and visual scene observations, generate task specific reward functions, train policies using Proximal Policy Optimization (PPO) algorithm, and then act as a critic by evaluating the trained policy through diagnosis packets to generate feedback. Based on this feedback, the agent identifies failure modes and refines the reward function in a closed loop self improvement process. To further leverage the multimodal GPT agent during inference, AgenticRL uses real world images and natural language task information to automatically identify the active scenario and select the appropriate trained policy for execution. The framework is evaluated on multiple navigational tasks, including gate traversal, obstacle avoidance, wall barrier crossing with landing, trajectory following, and motion behavior learning. Experimental results show that the closed loop refinement process improves policy behavior compared with initial rewards by 71%. We also demonstrate sim-to-real transfer of the proposed framework, achieving a real world success rate of 91% and a sim-to-real accuracy of 94%.","published":"2026-06-02T17:50:15Z","updated":"2026-06-09T15:09:32Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2606.03963v3","pdf_url":"https://arxiv.org/pdf/2606.03963v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.03895","versioned_id":"2606.03895v2","title":"Agent libOS: A Runtime Substrate for Capability-Controlled Self-Evolving LLM Agents","authors":["Yingqi Zhang"],"abstract":"Large language model (LLM) agents are becoming long-running software actors rather than fixed tool users. They accumulate memory, activate skills, synthesize tools, fork children, attach remote resources, and commit checkpoints into reusable execution images. These mechanisms improve adaptability, but also create a systems-security failure mode: if exposing an action also grants the authority needed to perform it, self-evolution becomes a permission-escalation path. This paper presents Agent libOS, an agent-native library-OS substrate for capability-controlled self-evolving agents. Its central invariant is that model-visible affordances may evolve while resource authority changes only through explicit, audited runtime primitives. Agent libOS represents an agent as an AgentProcess with process identity, process-local Object Memory, message queues, a tool table, loaded Skills, process-local Deno/TypeScript JIT tools, child processes, budgets, checkpoints, and explicit capabilities. AgentImage objects define boot-time prompt and tool-table state; Skills and JIT tools extend the action surface; checkpoint-derived images make internal state reusable. None of these mechanisms grants filesystem, shell, human, memory, process, checkpoint, image, JSON-RPC, MCP, or PTY authority by itself. The prototype implements process-local namespaces, persistent runtime state, LLM-call observability, human approval queues, budgets, syscall-mediated JIT tools, trusted Runtime Modules, Object-bound PTY sessions, checkpoint restore/fork/commit, JSON-RPC and MCP providers, and a deterministic runtime-safety benchmark. On 27 versioned deterministic tasks, it completed the task plans while preventing all modeled unauthorized side effects, with a 7.0% conservative false-denial rate. Simple wrapper and sandbox baselines preserved task completion but failed most safety checks.","published":"2026-06-02T16:53:24Z","updated":"2026-06-29T16:54:16Z","categories":["cs.OS","cs.AI","cs.CR"],"primary_category":"cs.OS","arxiv_url":"https://arxiv.org/abs/2606.03895v2","pdf_url":"https://arxiv.org/pdf/2606.03895v2","comment":"12 pages, 1 figure, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.03867","versioned_id":"2606.03867v2","title":"A Training-Free Mixture-of-Agents Framework for Multi-Document Summarization using LLMs and Knowledge Graphs","authors":["Cuong Vuong Tuan","Trang Mai Xuan","Tien-Cuong Nguyen","Vu-Duc Ngo","Thien Van Luong"],"abstract":"Multi-Document Summarization (MDS) plays a critical role in distilling essential information from collections of textual data. Existing approaches often struggle to capture complex inter-document relationships, rely heavily on large amounts of labeled data for supervised training, or exhibit limited generalization across domains and languages. To address these limitations, we present a training-free mixture-of-agents framework for MDS that leverages the complementary strengths of large language models (LLMs) and knowledge graphs. Our approach decomposes summarization into specialized agent tasks: extractive selection, knowledge-aware abstraction, and iterative refinement, each operating without task-specific fine-tuning. We unify their outputs using a multi-perspective consistency mechanism guided by LLMs. Experiments across four datasets in English and Vietnamese demonstrate state-of-the-art or competitive performance, validating the effectiveness and adaptability of our modular design.","published":"2026-06-02T16:39:07Z","updated":"2026-06-23T13:13:52Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.03867v2","pdf_url":"https://arxiv.org/pdf/2606.03867v2","comment":"Accepted by Neural Computing and Applications","journal_ref":"Neural Comput & Applic 38, 538 (2026)","doi":"10.1007/s00521-026-12249-y","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.03812","versioned_id":"2606.03812v1","title":"Enhancing Operational Safety via Agentic Dialogue Hazard Identification Analysis","authors":["Sanjay Das","Ran Elgedawy","Ethan Seefried","Ryan Burchfield","Tirthankar Ghosal"],"abstract":"Operational safety in high-stakes domains such as industrial process control, autonomous, and safety-critical systems, demand reliable hazard identification. While large language models (LLMs) have shown promise in automating safety analysis tasks, single-turn, monolithic inference is brittle: it lacks the self-correction, deliberation, and contextual refinement that safety engineers apply iteratively. In this paper, we introduce HAZDIAL, a framework that investigates whether structured agentic dialogue-multi-agent, multi-turn interactions improves the quality of NLP- based hazard identification over single-pass baselines. We systematically compare two dialogue modalities: adversarial debate and constructive discussion, and propose an algorithm-based agentic interaction optimization. We evaluate all configurations against a curated golden dataset using standard classification metrics (accuracy, precision, recall, F1) and novel dialogue metrics. This work advances the intersection of dialogue systems, multi-agent reasoning, and AI safety, providing an empirical evidence for dialogue-driven hazard analysis.","published":"2026-06-02T15:54:51Z","updated":"2026-06-02T15:54:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03812v1","pdf_url":"https://arxiv.org/pdf/2606.03812v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.03692","versioned_id":"2606.03692v1","title":"SkillPyramid: A Hierarchical Skill Consolidation Framework for Self-Evolving Agents","authors":["Yuan Xiong","Ziqi Miao","Qian Chen","Lijun Li","Yequan Wang","Shizhu He","Jun Zhao","Kang Liu"],"abstract":"Recent AI agents can flexibly invoke skills to solve complex tasks, but their long-term improvement is fundamentally constrained by a lack of systematic skill construction, accumulation, and transfer. In particular, without a unified framework for skill consolidation, agents tend to redundantly construct similar capabilities across different tasks, are unable to effectively transform experience into reusable assets, and struggle to generalize task-specific skills to novel scenarios. To address this limitation, we propose SkillPyramid, a skill consolidation framework that reuses existing skill experience for broader task generalization. Operating on a hierarchical skill topology, SkillPyramid further introduces a self-evolution mechanism that enables agents to compose, validate, and incorporate new skills during task execution. Experiments on ALFWorld, WebShop, and ScienceWorld across four backbone models show that SkillPyramid substantially increases the average reward by 38.0% and reduces execution steps by 27.7%. Overall, our method transforms a skill collection from a static resource pool into a dynamic evolution system.","published":"2026-06-02T14:14:27Z","updated":"2026-06-02T14:14:27Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03692v1","pdf_url":"https://arxiv.org/pdf/2606.03692v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=9wad6ut109","openreview_venues":["ACL ARR 2026 May Submission"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.03678","versioned_id":"2606.03678v1","title":"EvoDrive: Pareto Evolution for Safety-Critical Autonomous Driving via Self-Improving LLM Agents","authors":["Tong Nie","Yuewen Mei","Yihong Tang","Junlin He","Jie Deng","Jian Sun","Wei Ma"],"abstract":"Generating safety-critical scenarios is essential for validating and improving autonomous driving systems, yet it inherently requires maximizing adversariality to expose failures while preserving realism. Existing methods usually manage this trade-off with handcrafted heuristics, confining generation to known priors and overlooking underexplored patterns. While recent open-ended agentic evolution can push this limit, unconstrained general agents lack strict simulator grounding and tend to collapse the multi-objective tension into single-scalar maximization. Here we present EvoDrive, the first automated, LLM-based agentic evolution framework for multi-objective scenario generation. EvoDrive employs a simulator-grounded actor-critic architecture where a memory-driven actor iteratively proposes improvements to the generators and critics filter out implausible candidates, and a self-evolving world evaluator routes promising proposals to optimize simulation budgets. EvoDrive further maintains a Pareto archive of evaluated candidates to preserve diverse attack-realism trade-offs and guide future evolution via simulation feedback. Benchmark results on MetaDrive and CARLA show that EvoDrive not only significantly expands the Pareto frontier across various generators, but also produces valuable scenarios for policy training.","published":"2026-06-02T14:01:23Z","updated":"2026-06-02T14:01:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03678v1","pdf_url":"https://arxiv.org/pdf/2606.03678v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.03544","versioned_id":"2606.03544v1","title":"SAGE: A Quantitative Evaluation of Socialized Evolution in Agent Ecosystems","authors":["Linyue Pan","Yaoming Zhu","Lin Qiu","Xuezhi Cao","Xunliang Cai"],"abstract":"Self-improving language agents are typically evaluated in isolation: an agent attempts a task, receives feedback, and iteratively refines its own behavior. Yet agents increasingly operate alongside peers whose strategies and outcomes are publicly visible. This raises an under-studied question: when does shared experience produce improvements that self-improvement alone cannot achieve? We introduce SAGE (Social Agent Group Evolution),an evaluation framework that compares two compute-matched conditions: SocialEvo, where agents from five distinct model families co-evolve with access to all peers' histories; and SelfEvo, where each agent receives the same number of task attempts but sees only its own past, which is conventional in self-improving agent studies. We instantiate SAGE in three arenas: open-ended ML research, long-horizon economic planning, and strategic multiplayer play, evaluated across multiple evolutionary rounds. We find that group history is not a universal amplifier: the strongest agent does not exceed its self-evolution ceiling. However, agents that plateau under self-improvement can achieve significant breakthroughs when peer experience is available. In competitive settings, counterfactual controls reveal that agents improve generally rather than developing opponent-specific strategies. Across different forms of shared history, filtered peer traces and reflective summaries often outperform raw logs, indicating that social gains depend on abstraction rather than exposure volume. These findings reveal that peer-history gains are agent-specific, arena-dependent, and contingent on the capacity to abstract transferable knowledge from public traces.","published":"2026-06-02T12:08:38Z","updated":"2026-06-02T12:08:38Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03544v1","pdf_url":"https://arxiv.org/pdf/2606.03544v1","comment":"13 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2606.03303","versioned_id":"2606.03303v2","title":"LEAP: Supercharging LLMs for Formal Mathematics with Agentic Frameworks","authors":["Po-Nien Kung","Linfeng Song","Dawsen Hwang","Jinsung Yoon","Chun-Liang Li","Simone Severini","Mirek Olšák","Edward Lockhart","Quoc V Le","Burak Gokturk","Thang Luong","Tomas Pfister","Nanyun Peng"],"abstract":"Large Language Models (LLMs) exhibit strong informal mathematical reasoning but struggle to generate mechanically verifiable proofs in formal languages like Lean. We present LEAP, an agentic framework that enables general-purpose foundation models to achieve state-of-the-art performance on automated formal theorem proving. LEAP leverages foundation model capabilities, such as informal reasoning, instruction following, and iterative self-refinement. By decomposing complex problems into smaller units, the system bridges formal proof construction with informal blueprints through continuous interaction with the Lean compiler. To provide a rigorous evaluation beyond increasingly saturated benchmarks, we introduce Lean-IMO-Bench, a benchmark of IMO-style problems formalized in Lean, with short statements yet highly non-routine and multi-step proofs across a wide range of difficulty levels. Empirically, on the latest 2025 Putnam Competition, an annual mathematics competition for undergraduate students in North America, LEAP solves all 12 problems, matching recent breakthroughs by frontier formal mathematical models. On Lean-IMO-Bench, LEAP boosts the one-shot formal solve rate of general-purpose LLMs from below 10% to 70%, notably surpassing the 48% benchmark set by a specialized, gold-medal-caliber IMO system. Furthermore, we demonstrate LEAP's research-level utility by autonomously formalizing complex proofs for open combinatorial challenges, including a verified proof for a key subproblem in Knuth's Hamiltonian decomposition of even-order Cayley graphs.","published":"2026-06-02T08:16:42Z","updated":"2026-06-03T06:16:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.03303v2","pdf_url":"https://arxiv.org/pdf/2606.03303v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.20636","versioned_id":"2606.20636v1","title":"SkillHarness: Harnessing Safe Skills for Computer-Use Agents","authors":["Yurun Chen","Biao Yi","Keting Yin","Shengyu Zhang"],"abstract":"Computer-Use Agents (CUAs) are increasingly deployed in dynamic interactive environments, creating a growing need for continual skill learning during interaction. Recent approaches address this challenge by learning reusable skills from successful trajectories. However, these skill learning methods largely assume static and safe environments, overlooking risks from adversarial interactions (e.g., prompt injections) and environmental dynamics (e.g., pop-ups). In dynamic settings, such assumptions can lead to risky skill learning and brittle execution, undermining the reliability of CUAs. This raises the question: how can CUAs learn and use skills safely in dynamic environments? To address this problem, we propose SkillHarness, a framework for safe skill harnessing in dynamic environments. SkillHarness moves beyond static skill abstractions by modeling skill learning and utilization as a safety-constrained interaction process. Specifically, we introduce the skill boundary that leverages multi-source supervision signals to identify safe skills from interaction trajectories, and construct self-improving safety constraints throughout the skill lifecycle. In addition, SkillHarness introduces selective skill reuse, where tasks are guided to decompose according to context and completed through the selective activation of skill subsets. Our experiments demonstrate that SkillHarness significantly reduces the unsafe rate of learned skills by 57.1% and consistently improves execution stability under dynamic environmental changes, outperforming existing baselines.","published":"2026-06-02T06:33:51Z","updated":"2026-06-02T06:33:51Z","categories":["cs.AI","cs.CL","cs.CR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.20636v1","pdf_url":"https://arxiv.org/pdf/2606.20636v1","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.03143","versioned_id":"2606.03143v1","title":"FederatedSkill: Federated Learning for Agentic Skill Evolution","authors":["Jingbo Yang","Guanyu Yao","Yang Zhang","Ramana Rao Kompella","Gaowen Liu","Shiyu Chang"],"abstract":"Modern LLM agents increasingly rely on skill libraries to handle complex tasks, making skill evolution a primary driver of self-improvement. However, isolated single-user task streams lack the diversity required to build comprehensive skills. While cross-user collaboration can overcome this data bottleneck, current trajectory-sharing approaches compromise user privacy and impose a uniform global library that fails to accommodate client heterogeneity. We introduce FederatedSkill, a privacy-preserving framework for collaborative agent evolution. Moving beyond raw trajectory sharing, FederatedSkill utilizes semantic skill diffs, structured patches over local libraries, as the fundamental unit of communication. On the server side, an evolution agent aggregates these patches to dynamically model client-specific capability boundaries, facilitating strictly personalized skill evolution rather than a suboptimal global average. Evaluated across 20 distinct agent task families, FederatedSkill demonstrates substantial gains over self-evolving baselines, achieving up to a 44.4% increase in success rate and a 37.5% reduction in computational cost.","published":"2026-06-02T04:38:05Z","updated":"2026-06-02T04:38:05Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.03143v1","pdf_url":"https://arxiv.org/pdf/2606.03143v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2606.02963","versioned_id":"2606.02963v1","title":"KForge: LLM-Driven Cross-Platform Kernel Generation for AI Accelerators","authors":["Taras Sereda","Burak Bartan","Ankita Nayak","Tom St. John","Natalie Serrino","Zain Asgar"],"abstract":"Production inference increasingly targets a heterogeneous mix of accelerators. Agentic pipelines interleave reasoning, tool calls, and multi-agent coordination, each with distinct compute and memory profiles. For optimal efficiency, each stage should run on the accelerator best suited to it. This creates a systems challenge: each pipeline now requires high-performance kernels across a growing set of hardware backends and programming models. Writing these kernels by hand is time-consuming, demands deep low-level expertise, and does not scale as kernel complexity grows. Recently, Large Language Models (LLMs) have been leveraged for automatic kernel generation, but challenges in low-level code generation and cross-backend generalization persist. We present KForge, a cross-platform framework built around an iterative refinement loop driven by two collaborating LLM-based agents: a generation agent that produces and progressively refines kernels using compilation and correctness feedback, and a performance-analysis agent that interprets profiling data, from programmatic APIs to GUI-based tools, and emits recommendations that steer the next round of synthesis. The loop alternates between functional passes, which drive a candidate to correctness, and optimization passes, which close the performance gap to hand-tuned baselines. We evaluate KForge on two backends with very different baseline reference availability. On NVIDIA B200, KForge achieves a 2.12$\\%$ improvement in end-to-end throughput compared to TensorRT-LLM on the gpt-oss-20b inference speed benchmark. On Intel Arc B580, KForge generates Triton kernels achieving a 5.13$\\times$ geometric mean speedup over the faster of PyTorch eager and torch.compile on 37 GEMM + tail-ops workloads from KernelBench Level 2, primarily via operator fusion and mixed-precision execution.","published":"2026-06-01T23:48:55Z","updated":"2026-06-01T23:48:55Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.02963v1","pdf_url":"https://arxiv.org/pdf/2606.02963v1","comment":"Accepted at ISCA 2026 Workshop MLArchSys","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=51fUT6JSzC","openreview_venues":["MLArchSys 2026 Poster"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.01861","versioned_id":"2606.01861v1","title":"A Theoretical Framework for Self-Play Theorem Proving Algorithms","authors":["Thomas Chen","Zhiyuan Li"],"abstract":"Self-play, a type of training algorithm that enables a model to self-improve, has recently shown promising empirical results in the context of formal theorem proving using Large Language Models (LLMs). (Dong & Ma, 2025) instantiate self-play with two cooperating agents: a prover, which proves theorems, and a conjecturer, which generates new theorems as a curriculum to the prover. In this paper, we provide a theoretical framework for understanding the self-improvement capabilities of self-play algorithms for theorem proving. First, we formalize the set of theorems as a graph, with nodes as theorems and edges between pairs of theorems with similar semantics. We introduce a set of primitive assumptions that characterize the guarantees of a trained prover and how a conjecturer can access the structure of the graph. Second, we show that if the underlying graph of theorems is well-connected, then a prover-conjecturer system, where the conjecturing algorithm is based on a reversible random walk, is sufficient to grow the set of proved theorems exponentially. Third, motivated by an issue encountered empirically by self-play algorithms, where the conjecturer tends to generate artificially complex and non-fundamental theorems, we propose a diversity measure for a training distribution of theorems generated by a conjecturer and an improved conjecturing algorithm that locally maximizes this diversity measure, by computing the diffusion similarity between neighboring theorems in the theorem graph. Finally, we describe a method to compute the diffusion similarity by using contrastive learning to embed nodes into Euclidean space and then computing the inner-product between embeddings.","published":"2026-06-01T08:12:47Z","updated":"2026-06-01T08:12:47Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.01861v1","pdf_url":"https://arxiv.org/pdf/2606.01861v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2606.01801","versioned_id":"2606.01801v1","title":"MetaForge: A Self-Evolving Multimodal Agent that Retrieves, Adapts, and Forges Tools On Demand","authors":["Shouang Wei","Houcheng Min","Xinpeng Dong","Xin Lin","Sen Cui","Bo Jiang","Zhongxiang Dai","Kun Kuang","Guandong Xu","Fei Wu","Min Zhang"],"abstract":"Multimodal agents have achieved notable progress on complex reasoning tasks through tool use, yet remain limited by two issues: statically predefined tool inventories fail to generalize to unseen scenarios, and indiscriminate tool invocation incurs redundant cost and noise-induced errors. We propose MetaForge, a multimodal agent framework that learns when to invoke tools and how to evolve its toolset on demand. MetaForge factorizes agentic behavior into four coupled stages: Decide (judging whether tool use is warranted), Retrieve (selecting suitable tools), Adapt (grounding tool parameters in task context), and Forge (synthesizing new skills online and recycling them into the tool library for reuse), forming a closed judge-retrieve-adapt-forge-recycle loop. A unified orchestration policy enables the agent to choose among answering directly, reusing existing tools, or forging new ones. We jointly optimize invocation necessity, retrieval accuracy, execution effectiveness, and forged-skill reusability via reinforcement learning, with an explicit invocation-cost penalty discouraging redundant calls. Across 12 benchmarks, MetaForge consistently surpasses 16 baselines in accuracy, efficiency, and generalization, validating a paradigm shift from static tool inventories to on-demand self-evolution.","published":"2026-06-01T07:18:40Z","updated":"2026-06-01T07:18:40Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2606.01801v1","pdf_url":"https://arxiv.org/pdf/2606.01801v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2606.01770","versioned_id":"2606.01770v2","title":"Adaptive Auto-Harness: Sustained Self-Improvement for Agentic System Deployment on Open-Ended Task Streams","authors":["Zewen Liu","Zhan Shi","Yisi Sang","Bing He","Minhua Lin","Tianxin Wei","Dakuo Wang","Benoit Dumoulin","Wei Jin","Hanqing Lu"],"abstract":"Auto-harness systems such as A-Evolve, GEPA, and Meta-Harness improve LLM agents by optimizing prompts, skills, tools, memories, and supporting infrastructure from execution feedback, but they are typically evaluated on fixed offline benchmarks. Real deployments instead present open-ended task streams: histories grow without a fixed endpoint, heterogeneous tasks require different harnesses, and problem distributions shift over time. These challenges make a single repeatedly and densely updated harness brittle, causing performance degradation as accuracy peaks early and then declines. This motivates sustained harness construction with task-wise adaptation. We introduce Adaptive Auto-Harness, a framework and system for such streams. The framework decomposes the gap to an oracle harness into evolution loss and adaptation loss. The system addresses these losses with a stateful multi-agent evolver, a harness tree with solve-time routing, and human-steering hooks for cases where history lacks the needed signal. Across prediction-market, security-competition, and event-forecasting streams, Adaptive Auto-Harness outperforms five existing auto-harness baselines and ablations attribute gains to better construction, routing, or targeted human steering. Code is available in \\href{https://github.com/A-EVO-Lab/a-evolve/tree/release/adaptive-auto-harness}{Link}.","published":"2026-06-01T06:51:14Z","updated":"2026-06-03T05:59:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.01770v2","pdf_url":"https://arxiv.org/pdf/2606.01770v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2606.01640","versioned_id":"2606.01640v1","title":"MobEvolve: An Agentic Self-Evolving Heuristic System for Interpretable Human Mobility Generation","authors":["Junlin He","Yihong Tang","Tong Nie","Ao Qu","Yuebing Liang","Hamzeh Alizadeh","Bang Liu","Wei Ma","Lijun Sun"],"abstract":"Human mobility generation aims to synthesize realistic trip chains for target populations based on individual features. Existing paradigms, including deep generative models, LLM-based methods, and traditional heuristics, struggle to satisfy the complex demands of this task while simultaneously maintaining interpretability, behavioral plausibility, population-level distributional alignment, and inference efficiency. To bridge this gap, we introduce MobEvolve, the first agentic self-evolving heuristic framework for human mobility generation. MobEvolve initializes a behavior-inspired heuristic system and employs an LLM agent to iteratively evolve its internal logic. By diagnosing empirical misalignments and failure cases on a validation set, the agent proposes targeted updates and accumulates evolution memory for cumulative self-improvement. Extensive evaluations on the Singapore and Montreal benchmarks demonstrate that MobEvolve significantly outperforms state-of-the-art deep generative and LLM-based methods in individual trajectory fidelity, population-level distribution alignment, and behavioral plausibility, while preserving interpretability and high inference efficiency.","published":"2026-06-01T03:46:25Z","updated":"2026-06-01T03:46:25Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.01640v1","pdf_url":"https://arxiv.org/pdf/2606.01640v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.01385","versioned_id":"2606.01385v1","title":"Bridging Requirements and Architecture: Multi-Agent Orchestration with External Knowledge and Hierarchical Memory","authors":["Ruiyin Li","Yiran Zhang","Xiyu Zhou","Yangxiao Cai","Peng Liang","Weisong Sun","Jifeng Xuan","Zhi Jin","Yang Liu"],"abstract":"Software architecture design is a critical yet inherently complex and knowledge-intensive phase that requires balancing competing quality attributes and adapting to evolving requirements. Traditionally, this process has been time-consuming, labor-intensive, and heavily reliant on architects, often resulting in limited exploration of alternative architectural decompositions and styles, especially under the pressures of agile development. While LLM-based agents have shown promising performance across various software engineering tasks, their application to architecture design remains relatively scarce and requires systematic exploration. To address these challenges, we proposed MAAD (Multi-Agent Architecture Design), a knowledge-driven framework that orchestrates four specialized agents (i.e., Analyst, Modeler, Designer and Evaluator) to autonomously and collaboratively transform requirements specifications into comprehensive, multi-view architectural blueprints with quality attribute assessments. MAAD incorporates RAG to inject recognized architectural standards and patterns into the workflow and leverages a hierarchical memory mechanism that captures design history for iterative refinement. We evaluated MAAD through comparative experiments against MetaGPT, using quantitative architecture-level metrics across 10 case studies and qualitative feedback from industry architects on 10 real-world specifications. Results show that MAAD generates more complete, modular, and traceable architectures than the baseline, and its dedicated Evaluator agent autonomously produces structured quality evaluation reports that significantly reduce manual validation efforts. Furthermore, we found that the quality of the generated architecture heavily depends on the underlying LLM's reasoning capacity, with GPT-5.2 and Qwen3.5 outperforming other models across most evaluation settings.","published":"2026-05-31T18:18:31Z","updated":"2026-05-31T18:18:31Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2606.01385v1","pdf_url":"https://arxiv.org/pdf/2606.01385v1","comment":"39 pages, 7 images, 5 tables, Manuscript submitted to a Journal (2026)","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.02646","versioned_id":"2606.02646v1","title":"The Ringelmann Effect in Multi-Agent LLM Systems: A Scaling Law for Effective Team Size","authors":["Blaž Bertalanič","Carolina Fortuna"],"abstract":"Inference-time multi-agent LLM scaling lacks a shared unit: counting nominal agents conflates cost with independent evidence. We derive a two-parameter scaling law $R(N) = N_\\text{eff}/N = 1/(1+c(N-1)N^{-β})$ where the regime exponent $β$ classifies any configuration into one of three asymptotic regimes -- hard-ceiling at $1/c$ ($β= 0$), sublinear at $N^β/c$ ($0 < β< 1$), or linear ($β\\ge 1$), and a mean-field theorem predicts that peer count $k$ and rounds $τ$ during agent debate enter the dynamics only through their product $kτ$. The law applies at two levels: answer diversity and correctness redundancy. Across 44 (model $\\times$ task $\\times$ condition) cells spanning peer debate, self-correction, random-noise placebo, self-consistency, three open-weight families (Qwen, Llama, Ministral) at scales from 7B to 32B with a frontier API check (Gemini), thinking models, heterogeneous teams, and sparse communication, the functional form fits every condition at $R^2 > 0.99$; only $(c, β)$ shifts. On free-form math, dense peer influence collapses the answer-level regime from sublinear into hard-ceiling; correctness-level fits remain hard-ceiling throughout. Three findings have practical implications. \\emph{(i)}~Thirty dense debating agents produce no more answer diversity than one on MMLU-Hard. \\emph{(ii)}~A noise placebo tracks self-correction on free-form math and at $4\\times$ scale, so within homogeneous teams the gain commonly attributed to ``debate'' comes from re-evaluation, not peer content. \\emph{(iii)}~A single $N \\le 5$ pilot predicts the $N=30$ structural ceiling, and within the configurations tested only architectural diversity (heterogeneous teams) lowers $c$ and escapes the hard-ceiling regime, communication-mode interventions do not.","published":"2026-05-31T16:19:54Z","updated":"2026-05-31T16:19:54Z","categories":["physics.soc-ph","cs.AI","cs.MA"],"primary_category":"physics.soc-ph","arxiv_url":"https://arxiv.org/abs/2606.02646v1","pdf_url":"https://arxiv.org/pdf/2606.02646v1","comment":"41 pages, 9 figures, 20 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.01314","versioned_id":"2606.01314v1","title":"SkillSmith: Co-Evolving Skills and Tools for Self-Improving Agent Systems","authors":["Yangbo Wei","Zhen Huang","Shaoqiang Lu","Junhong Qian","Qifan Wang","Chen Wu","Lei He"],"abstract":"Recent self-evolving agents have shown that skills can be discovered, refined, and accumulated through execution. However, existing skill-evolution frameworks typically assume a fixed tool layer and evaluate each skill independently, limiting their ability to repair tool-level failures or reason about interactions among skills. We propose SkillSmith, a synergy-aware skill-tool co-evolution framework. SkillSmith introduces a unified proposal space in which reflection produces atomic bundles that jointly modify skills and tools, allowing tools to be wrapped, edited, composed, split, or retired when skill evolution identifies a reusable capability gap. To guide this joint search, SkillSmith maintains an ecological utility model inspired by Lotka-Volterra dynamics, where an interaction matrix estimated from execution traces captures pairwise complementarity and conflict among skills and provides pressure signals for retrieval, mutation prioritization, and retirement. Furthermore, SkillSmith records anti-patterns, including failure signatures, causal attributions, and remedies, to accelerate diagnosis and veto proposals that repeat known mistakes. Experiments on three benchmarks, including WildClawBench, and five Qwen3.5 model scales show that SkillSmith consistently outperforms strong baselines, with gains that amplify as task complexity and multi-skill co-activation increase.","published":"2026-05-31T16:01:19Z","updated":"2026-05-31T16:01:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.01314v1","pdf_url":"https://arxiv.org/pdf/2606.01314v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.01057","versioned_id":"2606.01057v1","title":"3DCodeBench: Benchmarking Agentic Procedural 3D Modeling Via Code","authors":["Yipeng Gao","Lei Shu","Genzhi Ye","Xi Xiong","Ameesh Makadia","Meiqi Guo","Laurent Itti","Jindong Chen"],"abstract":"Procedural 3D modeling through code is emerging as a versatile paradigm, offering deterministic, engine-ready, and precisely editable assets that neural 3D generators inherently lack. Authoring such procedural content, however, demands deep expertise in 3D software APIs, parametric design, and code-level geometric reasoning. In this paper, we propose 3DCodeBench, a systematic benchmark for evaluating vision-language model (VLM) agents for procedural 3D generation in 3D modeling software. Specifically, 3DCodeBench evaluates how effectively 12 advanced VLMs can serve as procedural 3D modelers by translating text and image references into procedural code for 3D modeling software. Recognizing that automated metrics may not fully capture the perceptual quality of 3D shapes, we build 3DCodeArena, a ranking platform based on pairwise human preferences over generated 3D outputs. From extensive evaluations and results, we observe that: (1) Failures mostly arise from API mismatches, while successful renders still suffer from disconnected or floating 3D geometric components. (2) Test-time scaling, such as higher thinking budgets and multi-turn refinement, improves performance overall. Our findings highlight a critical need for high-quality procedural coding data to advance commercial VLMs. Furthermore, effective procedural 3D modeling requires a robust execution environment that provides high-fidelity feedback for iterative refinement. We release 3DCodeBench, including the curated large-scale dataset of multimodal (text/image) prompts, procedural code, 3D object triplets, evaluation protocol, and the public 3DCodeArena platform as a foundational toolkit for exploring VLM-based procedural 3D modelers.","published":"2026-05-31T06:59:49Z","updated":"2026-05-31T06:59:49Z","categories":["cs.CV","cs.AI","cs.GR","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2606.01057v1","pdf_url":"https://arxiv.org/pdf/2606.01057v1","comment":"Project Page: https://www.3dcodebench.com/; 11 pages (main), with appendix","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2606.00820","versioned_id":"2606.00820v1","title":"Not All Flips Are Conformity: Decomposing Stance Convergence in Multi-Agent LLM Debate","authors":["Xiqi Hao","Zengqing Wu","Yu-Xuan Qiu","Chuan Xiao","Ruiqi Xu","Shuyuan Zheng","Jianbin Qin"],"abstract":"Multi-agent debate (MAD) is a promising strategy for improving LLM reasoning, but when agents converge on a shared answer, it is unclear whether that convergence reflects genuine deliberation or social compliance. We show that the conventional answer flip rate conflates three distinct mechanisms: spontaneous instability, stance-induced conformity, and reasoning-induced persuasion. Our three-source decomposition framework isolates each through controlled counterfactual conditions. In the primary MMLU-Pro setting, 37% of agent-question observations change under self-reflection alone, while robustness tests show substantial model-dependent instability across GPQA-Diamond and three model families; strict conformity is 29% in the primary setting and remains predominantly harmful across model replications (57-77% correct-to-wrong). A controlled information-gradient experiment reveals that even vacuous reasoning is associated with 20-39% error adoption among resistant agents, with reasoning-like presentation carrying substantial persuasive weight. Harmful conformity can be predicted from Round 0 features (AUC = 0.79), and risk-targeted intervention reduces it by 13.6 percentage points (p < 0.001). However, without correctness labels or self-reflection controls, reducing peer adoption does not improve accuracy, because harmful and beneficial influence cannot be distinguished.","published":"2026-05-30T17:41:11Z","updated":"2026-05-30T17:41:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2606.00820v1","pdf_url":"https://arxiv.org/pdf/2606.00820v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.31365","versioned_id":"2605.31365v1","title":"Learning to Adapt: Self-Improving Web Agent via Cognitive-Aware Exploration","authors":["Weile Chen","Bingchen Miao","Qifan Yu","Wendong Bu","Guoming Wang","Wenqiao Zhang","Shengyu Zhang","Juncheng Li","Siliang Tang"],"abstract":"Recent advances in Multimodal Large Language Models (MLLMs) have led to promising progress in web agents. However, existing web agents often rely on handcrafted execution pipelines or expensive expert trajectories, limiting their adaptability to complex, dynamic environments. To address these challenges, we propose SCALE (Self-Cognitive-Aware Learning and Exploration), which leverages three adversarial roles, Selector, Predictor, and Judger to autonomously discover the agent's limitations and expand its cognitive boundaries through environmental exploration. Moreover, we propose SCALE-Hop, a graph exploration strategy that facilitates global planning and helps agents avoid local exploration traps. To further support learning, we construct SCALE-20k, a large-scale dataset collected from 19 real-world websites, containing diverse task types and structured demonstrations generated from SCALE's exploration traces. Experimental results show that our approach significantly improves the performance and generalization of multiple MLLMs in various web environments. Our framework offers a scalable and generalizable solution for building truly autonomous and adaptive web agents.","published":"2026-05-29T14:37:27Z","updated":"2026-05-29T14:37:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.31365v1","pdf_url":"https://arxiv.org/pdf/2605.31365v1","comment":"24 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2606.07603","versioned_id":"2606.07603v1","title":"MetaEvo: A Meta-Optimization Framework for Experience-Driven Agent Evolution","authors":["Bowen Ren","Heyan Huang","Yinghao Li","Yang Gao"],"abstract":"Large language models (LLMs) exhibit strong reasoning capabilities, yet most LLM-based agents are statically deployed and unable to improve through task interactions. Existing experience-driven methods often rely on memory or heuristics without enhancing the model's ability to learn, treating it as a passive executor and leading to early performance plateaus and limited long-term improvement. To address this issue, we propose MetaEvo, a two-stage framework for continual agent evolution that focuses on improving how the model learns from tasks experience, rather than solely on what it stores. MetaEvo first applies preference-based optimization to enhance the model's ability of principle abstraction, then enables the accumulation and reuse of these principles within a modular agent architecture. Experimental results on diverse reasoning benchmarks demonstrate that MetaEvo consistently outperforms strong baselines, maintains reliable improvement across iterations. These findings validate the effectiveness of meta-optimization in enabling agents to learn from experience and continually enhance their reasoning capabilities.","published":"2026-05-29T09:31:39Z","updated":"2026-05-29T09:31:39Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2606.07603v1","pdf_url":"https://arxiv.org/pdf/2606.07603v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=1YcMHVY9cl","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2605.30802","versioned_id":"2605.30802v1","title":"Design and Evaluation of Multi-Agent AI Oracle Systems for Prediction Market Resolution","authors":["Tarun Kota"],"abstract":"Prediction markets aggregate collective intelligence to forecast uncertain events, but their utility depends on reliable outcome resolution. Existing oracle systems tradeoff fast but brittle automation against accurate but costly human arbitration. Single-LLM oracles achieve meaningful accuracy but inherit all failure modes of their underlying model with no self-correction mechanism. We evaluate whether multi-agent LLM architectures can improve oracle resolution accuracy over single-model baselines. We compare independent aggregation and deliberative consensus against single-LLM baselines (GPT-5 Nano, DeepSeek V3, and Llama-3.3-70B) on 1,189 resolved prediction market questions from KalshiBench. All agents share a common evidence layer through Exa, with retrieval filtered by publication date to isolate reasoning from retrieval quality. Independent aggregation with confidence-weighted voting achieves the highest accuracy at 83.43 percent, outperforming the best individual model by 1.01 percentage points. Deliberative consensus degrades accuracy to approximately 76 percent, below every single-model baseline, attributed to error propagation during debate where confidently wrong models flip correct ones. Error correlations across models (0.529-0.689) explain why aggregation gains fall short of the theoretical Condorcet ceiling, placing a fundamental limit on ensemble approaches. Many questions resist correction by any multi-agent architecture, motivating escalation to human arbitration. We propose routing criteria for hybrid AI-human oracle systems: auto-resolving only unanimous, high-confidence questions yields 97.87 percent accuracy on 47 percent of the dataset, with inter-agent disagreement flagging the remainder for human review.","published":"2026-05-29T03:44:19Z","updated":"2026-05-29T03:44:19Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.30802v1","pdf_url":"https://arxiv.org/pdf/2605.30802v1","comment":"34 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2605.30621","versioned_id":"2605.30621v1","title":"Harness Updating Is Not Harness Benefit: Disentangling Evolution Capabilities in Self-Evolving LLM Agents","authors":["Minhua Lin","Juncheng Wu","Zijun Wang","Zhan Shi","Yisi Sang","Bing He","Zewen Liu","Tianxin Wei","Zongyu Wu","Zhiwei Zhang","Dakuo Wang","Xiang Zhang","Benoit Dumoulin","Cihang Xie","Yuyin Zhou","Suhang Wang","Hanqing Lu"],"abstract":"LLM agents are increasingly deployed as systems built around editable external harnesses, including prompts, skills, memories and tools, that shape task execution without changing model parameters. Harness self-evolution adapts such agents by updating these harnesses from execution evidence. Yet it remains unclear whether a model's base capability in task-solving predicts its capabilities in harness self-evolution: which models produce useful harness updates, and which actually benefit from them? We analyze two harness self-evolution capabilities: (i) harness-updating, the capability to produce useful persistent harness updates from execution evidence; (ii) harness-benefit, the capability to benefit from updated harnesses during task solving. Our analysis reveals two findings. First, harness-updating is flat in base capability: models from different capability tiers produce harness updates that lead to surprisingly similar gains; even Qwen3.5-9B's updates yield gains comparable to those of Claude Opus~4.6. Second, harness-benefit is non-monotonic in base capability: weak-tier models benefit little from updated harnesses, mid-tier models benefit most, and strong-tier models benefit less than mid-tier. We trace low gains at the weak tier to two failure modes: weak-tier models may fail to activate relevant harness artifacts, or activate them but fail to follow them faithfully. These findings suggest investing capability budget in the task-solving agent rather than the evolver, and targeting harness invocation and long-horizon instruction following in agent training. Our source code is publicly available at https://github.com/A-EVO-Lab/a-evolve/tree/release/harness-evolution.","published":"2026-05-28T22:16:14Z","updated":"2026-05-28T22:16:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.30621v1","pdf_url":"https://arxiv.org/pdf/2605.30621v1","comment":"24 pages, 9 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2605.30227","versioned_id":"2605.30227v1","title":"Unifying Temporal and Structural Credit Assignment in LLM-Based Multi-Agent Prompt Optimization","authors":["Wenwu Li","Yuran Song","Mingze Zhao","Bo Jin","Wenhao Li"],"abstract":"While Multi-Agent Systems (MAS) empower Large Language Models to tackle complex reasoning tasks through collaborative interaction, optimizing their dynamics remains a formidable challenge due to the discrete, non-differentiable nature of the computation graph and the sparsity of global supervisory signals. Existing black-box optimizers struggle to attribute trajectory-level failure to specific local components, resulting in inefficient, high-variance exploration. We argue that tractable MAS optimization needs structural inductive biases to disentangle error signals. We propose temporal and structural credit assignment, which decomposes the objective along two axes: (i) temporal credit, using state-space bottlenecks to identify critical rounds, and (ii) structural credit, using stationary role policies to isolate agent contributions. Leveraging these decomposed signals, we introduce a discrete, verbalized block coordinate descent algorithm for iterative refinement. Rather than indiscriminate global updates, it alternates between optimizing role prompts and aggregation protocols, using LLM-generated \"proxy gradients\" to target only the identified weak links. Across diverse reasoning benchmarks, our approach substantially reduces query complexity while improving performance, providing a principled and interpretable path toward self-improving MAS.","published":"2026-05-28T16:57:57Z","updated":"2026-05-28T16:57:57Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.30227v1","pdf_url":"https://arxiv.org/pdf/2605.30227v1","comment":"15 pages, 4 figures, 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2605.30104","versioned_id":"2605.30104v1","title":"SEAL: Can Saturated Benchmarks Be Revived by LLM-as-a-Meta-Judge?","authors":["Jiamin Chen","Yidi Wu","Qiexiang Wang","Qianben Chen","Yuchen Li","Yansen Zhang","Xiaokun Zhang","Wangchunshu Zhou","Chen Ma"],"abstract":"Widely used language-model benchmarks are increasingly saturated, with frontier systems often receiving near-tied scores that standard metrics cannot resolve. Rather than constructing harder alternatives, we ask whether existing tasks can be made informative again through improved evaluation over the same candidate outputs. Therefore, we present Seeded Elimination with Adaptive LLM-as-a-Meta-Judge, a self-improving evaluation protocol for extracting latent ranking signal from saturated benchmarks. SEAL seeds candidate outputs into a single elimination and evaluates each match with task-level principles plus self-improving checklist criteria. We evaluate SEAL on multiple saturated benchmarks covering code generation, mathematical reasoning, knowledge-intensive question answering, and tool-use agent task completion. Across these settings, SEAL improves the ranking-accuracy--latency trade-off over competing protocols, attaining 0.83--1.00 Spearman agreement with full pairwise judging and 4/4 top-1 agreement, while requiring only 11.89 calls per task compared with 28.00 for full pairwise evaluation.","published":"2026-05-28T15:46:54Z","updated":"2026-05-28T15:46:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.30104v1","pdf_url":"https://arxiv.org/pdf/2605.30104v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.29910","versioned_id":"2605.29910v1","title":"Agora: Toward Autonomous Bug Detection in Production-Level Consensus Protocols with LLM Agents","authors":["Xiang Liu","Sa Song","Zhaowei Zhang","Huiying Lan","Jason Zeng","Ming Wu","Michael Heinrich","Yong Sun","Ceyao Zhang"],"abstract":"Consensus protocols form the backbone of distributed systems and blockchains, where implementation bugs can cause data corruption and financial losses. While LLM-based approaches show promise in code analysis, they struggle with deep protocol-level logic bugs involving complex state-dependent behaviors across multiple execution stages. We present Agora, a domain-aware multi-agent framework that integrates hypothesis-driven testing with LLM capabilities for systematic protocol verification. Agora employs specialized agents that collaboratively explore protocol state spaces, synthesize attack scenarios using domain-specific constraints, and validate findings through iterative refinement. This explicit role separation enables reasoning about global protocol invariants beyond single-function code analysis. We evaluate Agora on four consensus implementations (Raft, EPaxos, HotStuff, BullShark) using four state-of-the-art LLMs. Agora discovers 15 previously unknown protocol-level logic bugs that violate safety properties, while existing LLM-based agents fail to detect any such protocol-level logic bugs. Our results demonstrate that domain-aware multi-agent collaboration is essential for detecting deep logic bugs in complex protocols.","published":"2026-05-28T13:27:47Z","updated":"2026-05-28T13:27:47Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.29910v1","pdf_url":"https://arxiv.org/pdf/2605.29910v1","comment":"35 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=IU9dsf2LZA","openreview_venues":["ICML 2026 regular"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.29790","versioned_id":"2605.29790v1","title":"Evolve as a Team: Collaborative Self-Evolution for LLM-based Multi-Agent Systems","authors":["Zhezheng Hao","Tianfu Wang","Huanshuo Dong","Ziyan Liu","Hong Wang","Xiankun Lin","Qiang Lin","Can Wang","Hande Dong","Jiawei Chen"],"abstract":"LLM-based multi-agent systems (MAS) have emerged as an effective paradigm for complex and long-horizon tasks. However, in real-world tasks, MAS often exhibit various failures during execution and such failures are difficult to eliminate during design. This motivates experience-driven MAS evolution, where a system improves based on its own execution experience. Yet such evolution is challenging because MAS experience is prolonged and intricate, interleaving multiple agents' execution chains and communication messages, which makes it difficult to identify what should be improved. To address this challenge, we propose Meta-Team, an experience-driven MAS evolution framework based on collaborative self-evolution. Meta-Team preserves the execution context of each agent and coordinates post-task communication, enabling agents to exchange distributed evidence for evolution. Building on this design, Meta-Team conducts multi-scale self-evolution, transforming execution experience into reusable improvements to agent behaviors, inter-agent coordination, and team-level organization. Across six long-horizon agent benchmarks, Meta-Team consistently outperforms single-agent systems, hand-crafted MAS, and prior MAS evolution methods; further analyses demonstrate that Meta-Team enables more reliable and scalable MAS self-evolution.","published":"2026-05-28T11:40:16Z","updated":"2026-05-28T11:40:16Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.29790v1","pdf_url":"https://arxiv.org/pdf/2605.29790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2605.29668","versioned_id":"2605.29668v1","title":"GRASP: Gated Regression-Aware Skill Proposer for Self-Improving LLM Agents","authors":["Johannes Moll","Jean-Philippe Corbeil","Jiazhen Pan","Martin Hadamitzky","Daniel Rueckert","Lisa Adams","Keno Bressem"],"abstract":"LLM agents acting in structured environments fail in operational rather than conversational ways, and reliability depends on procedural knowledge of the environment. Prior self-improvement methods accumulate natural-language guidance without checking that each new item preserves previously correct behavior, so a note that fixes one trajectory can silently regress another. We introduce GRASP (Gated Regression-Aware Skill Proposer), which treats agent improvement as a sequence of edits to a bounded skill library, admitting each candidate only if it produces a net improvement on a balanced held-out probe under a hard regression budget. We evaluate GRASP across five base models (gpt-oss-120b, DeepSeek V4 Flash, Gemini 3.1 Flash Lite, GPT-4.1, GPT-5.4) on two FHIR-based clinical benchmarks. On MedAgentBench, GRASP lifts gpt-oss-120b from 40.6% to 88.8%, exceeds the strongest of five self-improvement baselines by 21.0 points, and improves every other base model by 17.2 to 40.3 points. Ablations attribute the gain to comparative proposal generation, the acceptance gate, and the hard regression budget rather than to skill writing itself, which without validation is no better than using no skills. The mechanism generalizes beyond the clinical domain, improving agents on three of four non-clinical environments and remaining flat only where the action space is open-ended. Frozen libraries transfer across models, where skills from a stronger model improve weaker executors beyond what they learn for themselves while the reverse does not, an asymmetry that no ungated baseline reproduces.","published":"2026-05-28T09:30:09Z","updated":"2026-05-28T09:30:09Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.29668v1","pdf_url":"https://arxiv.org/pdf/2605.29668v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2605.29653","versioned_id":"2605.29653v1","title":"PTCG-Bench: Can LLM Agents Master Pokémon Trading Card Game?","authors":["Dongdong Hua","Yifei Sun","Renhong Huang","Feng Gao","Chunping Wang","Yang Yang"],"abstract":"Given a strategically complex board game, human players can quickly learn to devise strategies after playing a few rounds. Autonomous agents require similar capabilities in realistic interactive environments, yet existing agent benchmarks often fail to fully capture such strategic and evolving decision-making scenarios. We present PTCG-Bench, a benchmark built on the Pok'{e}mon Trading Card Game (PTCG) that evaluates LLM agents at two complementary levels: (1) their decision-making performance within a single complex environment, and (2) their ability to self-evolving through accumulated experience. We further include a modular harness ablation to better interpret agent performance without conflating it with model capability. Our experiments show that, although LLM agents can achieve non-trivial gameplay performance, sustained and stable self-evolution remains challenging, and performance is sensitive to harness design. We hope that PTCG-Bench will facilitate future research on harness-aware and self-evolving agents in realistic interactive environments.","published":"2026-05-28T09:16:22Z","updated":"2026-05-28T09:16:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.29653v1","pdf_url":"https://arxiv.org/pdf/2605.29653v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2605.29440","versioned_id":"2605.29440v1","title":"SkillBrew: Multi-Objective Curation of Skill Banks for LLM Agents","authors":["Wentao Hu","Zhendong Chu","Yiming Zhang","Junda Wu","Ming Jin","Xiangyu Zhao","Yilei Shao","Yanfeng Wang","Qingsong Wen"],"abstract":"Retrieval-augmented LLM agents increasingly rely on curated skill banks: collections of reusable textual principles that guide decision making on complex tasks. Existing approaches typically expand these banks in an append-only fashion, continuously adding new skills without removing redundant, outdated, or harmful ones, resulting in inefficient and poorly curated repositories. In this paper, we formulate the skill bank curation as a constrained multi-objective problem: a desirable bank must be useful for the agent, diverse in its content, and provide good coverage of the query distribution. To this end, we introduce SkillBrew, a multi-objective curation framework that formalizes skill bank curation as Pareto-aware optimization under a utility constraint, and solves it via a bi-level propose-then-verify loop. We evaluate our approach on two public benchmarks. Our findings suggest that treating skill banks as objects of principled curation, rather than ever-growing append-only logs, is an important step toward building self-improving LLM agents.","published":"2026-05-28T06:33:52Z","updated":"2026-05-28T06:33:52Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.29440v1","pdf_url":"https://arxiv.org/pdf/2605.29440v1","comment":"16 pages. Preprint. Under review","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.29225","versioned_id":"2605.29225v1","title":"BenchTrace: A Benchmark for Testing Reflection Ability and Controlled Evolution in LLM Agents","authors":["Jiahao Huang","Fei Cheng","Junfeng Jiang","Zefan Yu","Akiko Aizawa"],"abstract":"Self-evolving agents improve over time by reflecting on past failures, but existing evaluation is limited in two ways: it measures only task scores, leaving reflection quality unknown, and it relies on agents' own episode runs, offering no mechanism to target specific failure patterns. We present \\textbf{BenchTrace}, a benchmark for evaluating self-evolution ability in LLM agents. BenchTrace is built on a snapshot-reflection dataset of 1,821 annotated episodes spanning six diverse tasks, and comprises a \\textbf{Reflection Evaluation} that probes failure identification through targeted QA tasks, and an \\textbf{Evolution Evaluation} that tests whether past failure experience translates into avoidance behavior in a controlled self-evolution simulation. Building on BenchTrace, we propose \\textbf{failure avoidance rate (FAR)}, a new evaluation metric measuring the fraction of test cases in which the agent successfully avoids the target failure instance. Experiments with Qwen3-32B and GPT-4.1 reveal that both models fall below a 30\\% end-to-end pass rate on reflection evaluation, with diagnosis as the primary bottleneck. Evolution evaluation shows that self-evolution methods generally improve FAR over the non-evolving baseline, but agents forget early lessons as noise episodes accumulate, and agents fail to generalize their reflections beyond the specific context, causing negative transfer across task contexts. Our correlation analysis further reveals that only a fully correct reflection is strongly associated with higher FAR. BenchTrace exposes concrete limits of current self-evolution approaches and provides a controlled, model-agnostic framework for targeted evaluation.","published":"2026-05-28T01:25:37Z","updated":"2026-05-28T01:25:37Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.29225v1","pdf_url":"https://arxiv.org/pdf/2605.29225v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2605.28814","versioned_id":"2605.28814v1","title":"Self-Improving Language Models with Bidirectional Evolutionary Search","authors":["Guowei Xu","Zhenting Qi","Huangyuan Su","Weirui Ye","Himabindu Lakkaraju","Sham M. Kakade","Yilun Du"],"abstract":"Search has been proposed as an effective method for self-improving language models and agentic systems, both for post-training sample generation and for inference. However, widely used methods such as best-of-N sampling and tree search face two fundamental limitations: they are guided by sparse verification signals, and they construct candidates primarily through autoregressive expansion, restricting exploration to regions with substantial model probability mass. To address these, we propose Bidirectional Evolutionary Search (BES), a search framework that couples forward candidate evolution with backward goal decomposition. In the forward search, BES augments standard expansion with evolution operators that recombine partial trajectories to generate candidates that are difficult to obtain from a single model rollout. In the backward search, BES recursively decomposes the original task into checkable subgoals, producing dense intermediate feedback that guides forward search. We provide theoretical motivation showing that candidates generated by expansion-only search are confined to a narrow entropy shell while evolutionary operators can escape it, and that backward search can exponentially reduce the number of required samples to find a correct answer. Experiments show that on challenging post-training tasks where mainstream post-training algorithms fail to improve, BES enables consistent gains, and on three open problem solving benchmarks at inference time, BES outperforms existing open-source frameworks in both average and best-case performance. Code and trained models are available at https://github.com/Embodied-Minds-Lab/BES.","published":"2026-05-27T17:59:15Z","updated":"2026-05-27T17:59:15Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28814v1","pdf_url":"https://arxiv.org/pdf/2605.28814v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=h9NkujtFI6","openreview_venues":["ICML 2026 AI4Math Workshop Poster"],"relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.28918","versioned_id":"2605.28918v1","title":"When LLM Reward Design Fails: Diagnostic-Driven Refinement for Sparse Structured RL","authors":["Youting Wang","Yuan Tang","Bowen Liu","Xuan Liu","Dingyan Shang"],"abstract":"For sparse, structured reinforcement-learning tasks with semantic reward-function interfaces, LLM-generated reward shaping is better framed as debugging than one-shot generation. We study PPO-trained agents using MiniGrid as core evaluation and MuJoCo as boundary stress test. Our audit finds two dominant one-shot failure modes -- reward flooding and semantic/API misunderstanding -- plus a rarer weak-shaping case. We propose diagnostic-driven iterative refinement, where training diagnostics and a failure-mode taxonomy guide targeted reward-function revision. Refinement improves DoorKey-8x8 from 2.3% to 97.6% and KeyCorridor from 31.2% to 86.7% with high seed-to-seed variance. Controls show these gains are not from retrying or extra training: metrics-only re-prompting yields large drops, while a static-vocabulary control recovers much of the gap (87.6%; 70.7%), showing the taxonomy prompt is a major mechanism and dynamic labels provide only partially isolated incremental evidence. Budget-matched and Best-of-3 comparisons separate refinement from selection and training-time effects. Component-removal tests, sensitivity analyses, and an audit against author labels provide converging evidence for the debugging interpretation while revealing calibration limits. Continuous-control results show the boundary: success-based diagnostics can misfire in dense-reward locomotion, and return-trend feedback removes one false-positive mechanism without robust gains. The low-call protocol is a cost contrast with population-based reward search, not a benchmark comparison. In four crossed-variance-design environments, point estimates suggest larger gains when LLM reward-function variance dominates but bootstrap intervals are wide. The method is bounded to sparse structured tasks with reliable interfaces under PPO; fields like event_text may help, hurt, or be neutral.","published":"2026-05-27T17:57:43Z","updated":"2026-05-27T17:57:43Z","categories":["cs.LG","cs.AI","cs.IR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.28918v1","pdf_url":"https://arxiv.org/pdf/2605.28918v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5TmwBBn8Oh","openreview_venues":["Under review for TMLR"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.28805","versioned_id":"2605.28805v1","title":"OmniVerifier-M1: Multimodal Meta-Verifier with Explicit Structured Recalibration","authors":["Xinchen Zhang","Bowei Liu","Jiale Liu","Chufan Shi","Yizhen Zhang","Junhong Liu","Youliang Zhang","Zhiheng Li","Yujiu Yang","Ling Yang"],"abstract":"Visual outcomes are increasingly central to multimodal large language models, making reliable and fine-grained verification essential for scaling generalist foundation models. In this work, we investigate multimodal meta-verification, which leverages verifier-generated rationales rather than decision-only signals, and explore how to effectively incorporate meta-verification feedback into multimodal verifier training. We identify two key findings. First, symbolic verifier outputs (e.g., bounding boxes) outperform textual explanations as meta-verification rationales, enabling efficient rule-based reinforcement learning rewards while avoiding reliance on model-based rewards from auxiliary judge models. Second, decoupling reinforcement learning objectives for binary judgment and meta-verification substantially outperforms joint reward optimization, due to intrinsic differences in output structure and learning dynamics. Based on these insights, we train OmniVerifier-M1, a generalist visual verifier leveraging symbolic meta-verification and decoupled reinforcement learning. OmniVerifier-M1 provides robust verification and fine-grained error localization, and further enables M1-TTS, a verifier-driven agentic generation system achieving dynamic region-level self-correction. This approach paves the way for more reliable, interpretable, and fine-grained multimodal verification, supporting safer and more controllable foundation model deployment.","published":"2026-05-27T17:56:04Z","updated":"2026-05-27T17:56:04Z","categories":["cs.CL","cs.AI","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28805v1","pdf_url":"https://arxiv.org/pdf/2605.28805v1","comment":"ICML 2026. Project: https://github.com/Cominclip/OmniVerifier","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.27559","versioned_id":"2605.27559v1","title":"Detection Without Correction: A Two-Parameter Decomposition of Multi-Stage LLM Pipelines","authors":["Prashanti Nilayam","Kiran Ramanna","Prashil Tumbade"],"abstract":"Multi-stage LLM pipelines that perform multi-agent debate, intrinsic self-correction, or retrieval-augmented verification exhibit puzzling aggregate behaviors: accuracy plateaus and reversals across rounds, non-replication of debate gains on contemporary frontier models, intrinsic self-correction degradation, and qualitative cross-provider divergence in debate dynamics. Downstream agent response can be operationalized as two coupled decisions: detection (whether to treat upstream content as authoritative) and conditional generation (what to produce if not). This decomposition yields four observable response regimes, of which detection-without-correction is the load-bearing failure mode. Across a nine-cell empirical grid spanning four model families, four benchmarks (GSM8K, MATH-500, GPQA-Diamond, AIME), and two methods (multi-agent debate, intrinsic self-correction), we find that the conditional miscorrection rate is consistently dominant (53-94% across cohorts) while detection rate varies contextually by more than an order of magnitude. The framework unifies the four phenomena above as signatures of a common mechanism and characterizes detection threshold as a stable model/protocol-level regularity that persists across methods at matched benchmark difficulty.","published":"2026-05-26T18:26:15Z","updated":"2026-05-26T18:26:15Z","categories":["cs.MA","cs.AI","cs.LG"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.27559v1","pdf_url":"https://arxiv.org/pdf/2605.27559v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"2605.27276","versioned_id":"2605.27276v2","title":"SIA: Self Improving AI with Harness & Weight Updates","authors":["Prannay Hebbar","Yogendra Manawat","Samuel Verboomen","Alesia Ivanova","Selvam Palanimalai","Kunal Bhatia","Vignesh Baskaran"],"abstract":"Humans are the bottleneck in building and improving AI. Both the models and the agents that wrap them are written, tuned, and corrected by people. The long-horizon goal of an AI that can figure out how to improve itself remains open. Two largely disjoint research lines attack this bottleneck. The harness-update school has a meta-agent rewrite the scaffold of a task-specific agent (its tools, prompts, retry logic, and search procedure) while the model weights are held fixed. The test-time training school uses hand-written RL pipelines to update the model's own weights on task feedback while the harness is held fixed. These two silos operate in isolation. We propose SIA, a self-improving loop in which a language-model agent (the Feedback-Agent) updates both the harness and the weights of a task-specific agent. We evaluate across three contrasting domains: Chinese legal charge classification, low-level GPU kernel optimisation, and single-cell RNA denoising. Combining both levers outperforms scaffold iteration alone on all three benchmarks. SIA-W+H achieves 25.1% over prior SOTA on LawBench, 12.4% faster GPU kernels than prior SOTA (1,017 vs 1,161 μs), and 20.4% over prior SOTA on denoising. Harness updates make the model agentic, shaping how it searches and acts, while weight updates build the domain intuition that no prompt or scaffold can instil.","published":"2026-05-26T16:55:46Z","updated":"2026-05-28T08:21:29Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.27276v2","pdf_url":"https://arxiv.org/pdf/2605.27276v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"]},{"id":"2605.28882","versioned_id":"2605.28882v2","title":"GrowLoop: Self-Evolving Conversation Evaluation Seeded by Human","authors":["Yihang Lin","Yunze Gao","Zeyang Lin","Dongbo Li","Kun Peng","Yue Liu"],"abstract":"With the rapid advancement of large language models, evaluating human-likeness in open-ended conversation has become increasingly important. However, human-likeness is a form of tacit knowledge that humans perceive intuitively, yet the underlying criteria resist explicit formulation. Human judgments vary widely, with strong agreement on some cases and legitimate disagreement on others. Meanwhile, the criteria behind human judgments remain implicit, leaving no clear basis for constructing cases. Further, what counts as human-likeness is not static, but evolving with model capability and human expectations. Despite progress in evaluation methods such as expert-authored benchmarks, Reward Models, and self-evolving benchmarks, none addresses all three challenges simultaneously. Therefore, we propose GrowLoop, a self-evolving conversation evaluation system that continuously adapts as models advance and scenarios shift. Starting from minimal human seed annotations, LLM agents iteratively extract and refine evaluation rubrics through Heuristic Learning. Human-AI agreement is required where annotators converge, while only plausibility is expected where they diverge. Moreover, the Rubric-Case co-evolution mechanism enables continuous evolution. When the evaluation target shifts, new human seeds expand the system's coverage accordingly. When applied to human-likeness evaluation in open-ended conversation, the AI judge guided by these rubrics not only substantially outperforms existing methods in alignment with human judgments, but also uncovers issues that annotators overlook. The resulting benchmark effectively discriminates models across capability tiers and reveals where they fall short, while generalizing to new scenarios and adapting as models advance. Our work shifts the benchmarking paradigm from manual updates or difficulty scaling to comprehensive, continuous self-evolution.","published":"2026-05-26T16:53:14Z","updated":"2026-06-10T14:08:11Z","categories":["cs.CL","cs.AI","cs.SD"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.28882v2","pdf_url":"https://arxiv.org/pdf/2605.28882v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2606.20622","versioned_id":"2606.20622v1","title":"Darwin Mobile Agent: A Roadmap for Self-Evolution","authors":["Daniel Beechey","Derek Yuen","Jianheng Liu","Dezhao Luo","Tiantian He","Weilin Luo","Jun Wang","Kun Shao"],"abstract":"The goal of artificial intelligence is to create agents capable of general, adaptive behaviour in open-ended environments. Guided by the \"Bitter Lesson\", we argue that the most effective path toward this goal is to systematically remove human priors and allow intelligence to naturally emerge through interaction with a \"Big World\" that is orders of magnitude more complex than the agent itself. We propose the mobile Graphical User Interface (GUI) as a practical proxy for such a world and introduce Darwin Mobile Agent, an open-source infrastructure designed as a foundation for autonomous reinforcement learning in this domain. This framework addresses the data-collection bottleneck in real-world mobile interactions by using an asynchronous agent-environment loop across parallel cloud-phone instances. We further propose a conceptual roadmap to systematically remove human priors from three fundamental pillars of a self-evolving agent: task curricula, outcome verification, and memory management. We validate that the Darwin infrastructure provides the stability and scalability required for the first stage of this roadmap: policy optimisation in the GUI domain. This work establishes the practical and theoretical foundation necessary to move toward truly autonomous, self-evolving GUI agents.","published":"2026-05-26T13:32:14Z","updated":"2026-05-26T13:32:14Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2606.20622v1","pdf_url":"https://arxiv.org/pdf/2606.20622v1","comment":"Technical Report","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:BCM7i20u4G","versioned_id":"BCM7i20u4G","title":"Multi-Specialist Routing: From Self-Evolving Specialists to Off-the-Shelf Composition for Fact Verification","authors":[],"abstract":"We build SEVA, a self-evolving structured fact verifier improved by iterative Verify→Reflect→Probe→Refine, and find that each round produces a benchmark-specialist rather than a generalist (+15pp on HaluEval, −10 to −14pp on TruthfulQA in the same model). The asymmetry persists at 4× training-data scale, identifying iterative self-evolution as a structural specialization process. We exploit this with **Multi-Specialist Routing (MSR)**, an embedding-aware classifier-stacker over a 98.8%-accurate per-domain router and a small per-domain stacker zoo. A Fano-bound argument shows the stacker strictly exceeds the per-claim selector oracle when the input embedding carries conditional mutual information $I(y; \\phi \\mid F) > 0$ beyond the specialist verdicts $F$, formalizing the +24.4pp oracle violation we observe on TruthfulQA. SEVA-MS reaches **83.5 macro-F1** on ClearFacts+FEVER+TruthfulQA+HaluEval. Replacing SEVA with off-the-shelf LLMs gives **HMSR-top3**, which reaches **84.0** with *zero specialist training*, matching the ClearCheck-8B SOTA. The lift is robust across six axes: contamination-free HMSR-no-CC (83.2), cross-domain Climate-FEVER (+6.25pp), cross-task ANLI R3 (+4.0pp) and BoolQ (+2.8pp), and head-to-head over Mixture-of-Agents (+11.7pp average, +39pp on TruthfulQA). An ensemble-size scaling law (Krogh–Vedelsby) shows a sharp N=2–3 knee, giving a concrete recipe: two to three diverse off-the-shelf LLMs plus a logistic-regression router reach SOTA fact verification without any specialist fine-tuning.","published":"2026-05-26T11:43:37+00:00","updated":"2026-07-02T13:01:54+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=BCM7i20u4G","openreview_url":"https://openreview.net/forum?id=BCM7i20u4G","pdf_url":"https://openreview.net/pdf?id=BCM7i20u4G","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:JfiiKGMZDz","versioned_id":"JfiiKGMZDz","title":"ActivityEditor: Learning to Synthesize Physically Valid Daily Activity Schedules","authors":[],"abstract":"Synthesizing realistic 24-hour activity schedules from socio-demographic profiles is essential for urban applications yet remains challenging in data-scarce regions where no historical travel records exist. While large language models (LLMs) have shown promise for zero-shot activity generation, single-pass architectures lack self-correction mechanisms and frequently violate physical constraints such as temporal coverage, continuity, and duration validity. We propose \\textbf{ActivityEditor}, a dual-LLM-agent framework that reframes activity-chain synthesis as an iterative Generate-then-Edit task. An intention-driven agent maps demographic profiles to a coarse activity skeleton, which is then iteratively refined by an editor agent through targeted operations (Add, Delete, Shift, Replace) that enforce physical and logical constraints. The editor agent is aligned via Group Relative Policy Optimization (GRPO) with rule-based rewards, enabling it to internalize schedule-level behavioral constraints through exploration rather than imitation. Extensive cross-state experiments on the National Household Travel Survey demonstrate that ActivityEditor achieves strong cross-state zero-shot transfer within the NHTS framework, significantly improving temporal consistency and constraint satisfaction over both traditional generators and LLM-based methods. Our code is available at: \\url{https://anonymous.4open.science/r/ActivityEditor-066B}.","published":"2026-05-26T11:02:38+00:00","updated":"2026-07-06T10:10:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=JfiiKGMZDz","openreview_url":"https://openreview.net/forum?id=JfiiKGMZDz","pdf_url":"https://openreview.net/pdf?id=JfiiKGMZDz","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:wmucOCOBPq","versioned_id":"wmucOCOBPq","title":"R-HAN: Reliable Hierarchical Coordination for Multi-Agent Systems","authors":[],"abstract":"LLM-based multi-agent systems (MAS) typically optimize a single topology, restricting reasoning to a narrow trajectory and limiting comprehensive analytical capacity. Naively merging multiple topologies into a composite graph introduces redundant noise propagation across irrelevant connections, degrading solution quality. To address this dilemma, we propose Reliable Hierarchical Agent Networks (R-HAN), a multi-agent framework that balances diverse reasoning paths with sparse task-dependent execution. R-HAN constructs a union MAS graph from complementary candidate topologies selected via Monte Carlo Tree Search and Determinantal Point Process, broadening the reasoning trajectory for comprehensive analysis of complex problems. A Hierarchical Sparse Coordination module then activates only a sparse subgraph at each step while agents exchange compressed latent briefs to suppress redundant noise propagation. Finally, a Local Self-Refinement stage identifies decision units with discrepancy evidence and rewrites them only when contrastive evidence simultaneously confirms a reliable solution-side failure and a challenger-side improvement. Experiments across eight benchmarks show that R-HAN achieves state-of-the-art results on all benchmarks, with an average gain of 2.98% over the strongest baseline and up to 10.27% on MMLU-Pro, achieving larger improvements on harder benchmarks at a reasonable additional cost.","published":"2026-05-26T10:37:22+00:00","updated":"2026-06-20T03:00:59+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wmucOCOBPq","openreview_url":"https://openreview.net/forum?id=wmucOCOBPq","pdf_url":"https://openreview.net/pdf?id=wmucOCOBPq","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:EJ7gBBDvCg","versioned_id":"EJ7gBBDvCg","title":"Mendel Gödel Machine: Comparative Evolution Enables State-of-the-Art Self-Improving Coding Agents","authors":[],"abstract":"Self-improving coding agents that iteratively rewrite their own source code have demonstrated impressive performance on coding tasks. However, existing solutions generally derive self-modification from a single failure trajectory at a time, overlooking rich comparative signals available in the agent's expanding archive of past attempts. According to Mendelian principles of controlled inheritance, we introduce Mendel Gödel Machine (MGM). In addition to the general single-trajectory clonal mutation, MGM includes two new types of self-modification that better utilizes evidences accumulated: the reaction-norm mutation edits an agent based on its trajectories on multiple tasks simultaneously, and the cross-lineage hybridization edits an agent using the trajectory of a reference agent from another lineage on the same task. Under an additive fitness landscape model, we prove theoretically and demonstrate via controlled surrogate simulation that the new strategies facilitate a strictly faster and better convergence to oracle over single-trajectory baselines. Experiments on SWE-bench and Polyglot confirm MGM's consistent improvement in performance and efficiency that matches state-of-the-art results. Our code is publicly available at https://anonymous.4open.science/r/MendelGM .","published":"2026-05-26T10:36:48+00:00","updated":"2026-07-02T16:29:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=EJ7gBBDvCg","openreview_url":"https://openreview.net/forum?id=EJ7gBBDvCg","pdf_url":"https://openreview.net/pdf?id=EJ7gBBDvCg","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:pmb3YKhSVu","versioned_id":"pmb3YKhSVu","title":"From Code Generation to Code Reasoning: A Survey of Inference-Time Methods in LLM-Based Code Generation","authors":[],"abstract":"Large language models (LLMs) have rapidly advanced code generation, evolving from prompt-based function synthesis to iterative, execution-guided, tool-integrated, and agentic software engineering systems. While recent progress has produced impressive benchmark results, the diversity of methods and evaluation settings has also introduced fragmentation in how capabilities are assessed and compared. In this survey, we present a unified view of LLM-based code generation from the perspective of inference-time reasoning and interaction. We organize existing methods by how LLMs constrain generation, search among candidates, incorporate feedback, and interact with execution environments, covering grammar- and schema-constrained generation, prompt-conditioned generation, language-based self-refinement, execution-guided revision, test-time ranking, tool-integrated generation, and agentic code generation. We further review benchmarks across function-level, execution-grounded, repository-level, and long-horizon agentic tasks, and analyze how evaluation assumptions shape reported performance. Our analysis highlights limitations of test-based correctness metrics, contamination risks, latency--quality trade-offs, and challenges in evaluating iterative and agentic systems. By connecting method design with evaluation protocols, this survey aims to clarify current progress and guide future research on reliable and scalable LLM-based code generation.","published":"2026-05-26T10:25:28+00:00","updated":"2026-07-06T10:36:21+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=pmb3YKhSVu","openreview_url":"https://openreview.net/forum?id=o4YuQL56sd","pdf_url":"https://openreview.net/pdf?id=pmb3YKhSVu","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2026 May Submission","ACL ARR 2026 January Submission"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:9dNSyhxeWo","versioned_id":"9dNSyhxeWo","title":"On the Generalization of LLM Agents: An Empirical Analysis of Agentic Harness Performance on ARC-AGI","authors":[],"abstract":"The ARC-AGI benchmark is known to measure the generalization capabilities to novel, previously unseen tasks and is one of the few challenging benchmarks remaining for LLMs. While models exhibit some level of generalization, their effectiveness lags behind humans when it comes to transferring knowledge to new situations. The agentic harnesses developed in the last few years can alleviate many weaknesses of current models. In this paper, we introduce a harness consisting of a judge, general memory, and a Python coding module. The effect of these three methods on generalization is evaluated on a 50-task subset of the ARC-AGI 1 evaluation dataset. Multiple proprietary and open-weight models are compared to assess the current landscape of LLMs. Reusable memory abstractions and judge-driven iterative refinement emerge as useful strategies, while code-based verification improves performance only for sufficiently capable models. The cost and time dimensions are closely tracked and evaluated for all model-workflow configurations.","published":"2026-05-26T09:25:58+00:00","updated":"2026-06-15T16:08:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9dNSyhxeWo","openreview_url":"https://openreview.net/forum?id=9dNSyhxeWo","pdf_url":"https://openreview.net/pdf?id=9dNSyhxeWo","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:PMIla0klB7","versioned_id":"PMIla0klB7","title":"Social Gym and SPaRTan: Benchmarking and Improving LLM Social Reasoning via Multi-Agent Game Tournaments","authors":[],"abstract":"Current evaluations for LLMs in multi-agent social interaction settings, where agents must negotiate and collaborate, lag behind other domains with objective ground-truth (e.g. math, logic), instead relying on human ratings or LLM-as-judge scoring, which are subjective, costly, and hard to verify at scale. To address this evaluation gap, we introduce Social Gym, an environment of 21 multi-agent social games where agent performance is verifiable and objective (e.g., Werewolves, Resistance, Spyfall, etc.) organized into five categories along the information-and-communication axes, with a Elo tournament that produces a cross-game leaderboard. Motivated by benchmarking experiments showing limitations of current LLM agents, we propose SPaRTan (Self-Play and Reflect-Transfer), a training-free self-improvement loop where a model plays a game, reflects on its trajectories to produce a transferable playbook, and applies that playbook in subsequent games. Our experiments on GPT-5-mini show that agents armed with a SPaRTan playbook gain on the structurally weaker side of asymmetric hidden-role games, and that the same playbook transfers across games and into weaker student models; the effect is capacity-dependent, however: an open-weights replication with Qwen3-32B is largely null except on Prisoner's Dilemma. Together, Social Gym and SPaRTan offer a reproducible, verifiable foundation for measuring and improving LLM social reasoning without weight updates.","published":"2026-05-26T09:03:53+00:00","updated":"2026-06-20T03:34:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=PMIla0klB7","openreview_url":"https://openreview.net/forum?id=PMIla0klB7","pdf_url":"https://openreview.net/pdf?id=PMIla0klB7","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:Y5ahfHR4Rb","versioned_id":"Y5ahfHR4Rb","title":"A$^{4}$: Tree-Based Adaptive Action Anticipation and Allocation for LLM Agent Evolution","authors":[],"abstract":"The evolution of LLM-based agents is essential, as it enables sustained improvement in their problem-solving abilities. Prior work has focused on leveraging training data derived either from an agent's own behavior, such as refining decision sequences, or from stronger external agents, including expert or teacher models, to improve performance on agent tasks. However, when exploring candidate trajectories, these methods allocate their sampling budget uniformly across all decision steps, overlooking that individual actions contribute unequally to the final task outcome. To overcome this limitation, we propose A$^{4}$, a theoretically grounded framework that models the decision process as a tree and decomposes trajectory-level variance into per-step contributions, enabling adaptive allocation of the sampling budget toward high-uncertainty decision points. Extensive experiments across three representative interactive environments demonstrate that A$^{4}$ achieves 11.7\\% relative improvement over the strongest baseline. For reproducibility and future research, we release our code at \\url{https://anonymous.4open.science/r/AAAA-E8BA}.","published":"2026-05-26T09:02:17+00:00","updated":"2026-07-03T04:24:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Y5ahfHR4Rb","openreview_url":"https://openreview.net/forum?id=Y5ahfHR4Rb","pdf_url":"https://openreview.net/pdf?id=Y5ahfHR4Rb","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:UykJjqV94d","versioned_id":"UykJjqV94d","title":"Let the Agent Search: Training-Free Autonomous Exploration for Temporal Knowledge Graph Question Answering","authors":[],"abstract":"Temporal Knowledge Graph Question Answering (TKGQA) is challenging because it requires multi-hop reasoning under complex temporal constraints. Although recent LLMs improve semantic modeling, they typically rely on fixed workflows that lack adaptability and accumulate errors, or require expensive post-training. We show that enabling an off-the-shelf Large Language Model (LLM) to determine its next action is already effective in a zero-shot setting. Based on this insight, we propose AT2QA, an Autonomous and Training-free Agent for TKG Question Answering. AT2QA empowers the LLM to iteratively interact with the TKG via a generic search tool, supporting autonomous exploration and dynamic self-correction during reasoning. To further improve complex temporal reasoning, we introduce a training-free experience mining mechanism that distills a compact few-shot demonstration library from successful self-generated trajectories. AT2QA also yields an executed evidence trace for every prediction. Experiments on three challenging benchmarks—MultiTQ, Timeline-CronQuestion, and Timeline-ICEWS-Actor—show that AT2QA achieves new state-of-the-art performance, surpassing the strongest baselines by 10.7, 4.9, and 11.2 absolute points, respectively.","published":"2026-05-26T08:55:44+00:00","updated":"2026-07-10T17:47:30+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=UykJjqV94d","openreview_url":"https://openreview.net/forum?id=UykJjqV94d","pdf_url":"https://openreview.net/pdf?id=UykJjqV94d","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:I7C90ZIBB5","versioned_id":"I7C90ZIBB5","title":"PsyEHR-Bench: An Agentic Framework and Benchmark for Cohort Selection in Chinese Psychiatric EHRs","authors":[],"abstract":"Cohort selection from electronic health records (EHRs) is especially challenging in psychiatry, where the variables that drive most studies (e.g., prior suicide attempts, family history, treatment adherence) are documented in free-text fields rather than in structured fields. Existing EHR benchmarks target text-to-SQL and factoid answering on English structured fields from ICU or general-hospital cohorts, leaving Chinese psychiatric cohort selection over mixed structured and free-text conditions unaddressed. We introduce PsyEHR-Bench, the first cohort-selection benchmark evaluated over Chinese psychiatric EHRs, comprising 134 natural-language queries from 80 empirical studies, each paired with a verifiable ground-truth patient set on a de-identified database of approximately 59,000 patients. Our agentic framework couples automated SQL execution with a specialized free-text toolset for semantic search, lexical variant discovery, and per-record multi-criterion judgments, together with experience-driven self-evolution. The framework establishes a strong baseline with an overall F1-score of 0.851 on the 100-query test set. A 0.226 gap between structured-only queries (F1-score = 0.900) and queries requiring free-text (F1-score = 0.674) identifies unstructured clinical narratives as the primary bottleneck. Ablations show that the free-text toolset forms a highly synergistic ensemble whose joint contribution on the free-text subset (+0.244) significantly exceeds its individual additive effects.","published":"2026-05-26T08:25:39+00:00","updated":"2026-07-03T22:52:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=I7C90ZIBB5","openreview_url":"https://openreview.net/forum?id=I7C90ZIBB5","pdf_url":"https://openreview.net/pdf?id=I7C90ZIBB5","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:QJTSAvHFQn","versioned_id":"QJTSAvHFQn","title":"The Self-Verification Cliff: Generation Outpaces Self-Selection in Frontier LLMs, and It Widens With Capability","authors":["Arihant Jain"],"abstract":"Self-evolving scientific agents must do more than generate candidate solutions: they must select or verify which of their own outputs to trust, because every self-play, self-rewarding, and reinforcement-learning loop that omits an external checker implicitly assumes the model can grade itself. We test that assumption on competition mathematics, where final answers are integers and grading is therefore an exact, noise-free oracle. Across two frontier model families on 86 AIME problems, we find a large and systematic self-verification cliff: a model contains a correct answer among $k{=}8$ samples far more often than it can pick that answer using its own judgment. GPT-5.4-mini reaches a correct solution on $54.7\\%$ of problems but self-selects correctly on only $41.9\\%$, recovering just $36\\%$ of its sampling headroom; Gemini-3.5-flash recovers $43\\%$. Critically, the cliff widens with generation ability rather than closing: the stronger generator has the larger absolute gap. We further show that an external verifier helps only when it is at least as capable as the generator---a stronger cross-family verifier closes part of the cliff ($+3.5$ pts), while a weaker one makes selection worse than self-selection ($-2.3$ pts)---and that majority voting fails to rescue selection on these diverse-answer problems. The cliff is a structural ceiling on same-model self-improvement and a concrete argument for external (e.g.formal) verification in self-evolving math agents.","published":"2026-05-26T06:16:48+00:00","updated":"2026-06-22T06:25:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=QJTSAvHFQn","openreview_url":"https://openreview.net/forum?id=QJTSAvHFQn","pdf_url":"https://openreview.net/pdf?id=QJTSAvHFQn","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:1pZZAsRajP","versioned_id":"1pZZAsRajP","title":"Memory Transfer Learning: How Memories are Transferred Across Domains in Coding Agents","authors":[],"abstract":"Memory-based self-evolution has emerged as a promising paradigm for coding agents. However, existing approaches typically restrict memory utilization to homogeneous task domains, failing to leverage the shared infrastructural foundations, such as runtime environments and programming languages, that exist across diverse real-world coding problems. To address this limitation, we investigate Memory Transfer Learning (MTL) by harnessing a unified memory pool from heterogeneous domains. We evaluate performance across 6 coding benchmarks using four memory representations, ranging from concrete traces to abstract insights. Our experiments demonstrate that cross-domain memory improves average performance by 3.7% over zero-shot setting and even outperforms the strongest self-evolving baseline, primarily by transferring meta-knowledge, such as validation routines, rather than task-specific code. Importantly, we find that abstraction dictates transferability; high-level insights generalize well, whereas low-level traces often induce negative transfer due to excessive specificity. Furthermore, we show that transfer effectiveness scales with the size of the memory pool, and memory can be transferred even between different models. Our work establishes empirical design principles for expanding memory utilization beyond single-domain silos.","published":"2026-05-26T06:12:01+00:00","updated":"2026-06-26T03:58:35+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=1pZZAsRajP","openreview_url":"https://openreview.net/forum?id=1pZZAsRajP","pdf_url":"https://openreview.net/pdf?id=1pZZAsRajP","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:4EGFPU1F7i","versioned_id":"4EGFPU1F7i","title":"WebSync: A Self-Evolving Web Agent Framework for Co-Evolving Strategic Advice and Executable Skills","authors":[],"abstract":"With the advent of large language models, autonomous web agents have achieved more sophisticated capabilities in planning, reflecting, and tool using, enabling automating navigation in complex and dynamic web environments. Despite this, existing efforts to instill experiential learning through memory-centric retrieval or skill-centric synthesis are respectively limited by computational inefficiency and brittle execution, making it difficult for web agents to reuse experience reliably. To tackle this problem, we introduce a web agent framework called \\textbf{WebSync}, which is designed to unify strategic advice and skill synthesis through a structured skill recipe to compile experience into executable skills more efficiently and robustly. Furthermore, it enables continuous self-improvement by using runtime feedback to trigger iterative recipe and skill refinement, supporting a transition from trial-and-error reasoning to guarded execution. Experimental results on WebArena and WebVoyager benchmarks demonstrate the effectiveness and versatility of \\textbf{WebSync} across multiple backbone large language models.","published":"2026-05-26T05:52:22+00:00","updated":"2026-06-13T05:36:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4EGFPU1F7i","openreview_url":"https://openreview.net/forum?id=4EGFPU1F7i","pdf_url":"https://openreview.net/pdf?id=4EGFPU1F7i","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:kYrHkkhkqy","versioned_id":"kYrHkkhkqy","title":"What Drives LLM Self-Reflection? A Controlled Ablation of Uncertainty Routing in Armed Conflict Forecasting","authors":[],"abstract":"Self-reflection is widely assumed to improve LLM reasoning, yet which component drives the gain remains poorly understood. We present a controlled six-condition ablation isolating four components of LLM self-reflection: evidence exposure, diagnostic scaffolding, taxonomy vocabulary, and action routing. Two precise null results converge on a single mechanism. First, structured diagnostic questions add no measurable value over unstructured reflection ($\\text{F1} = 0.296$ vs $0.297$, $p = 1.000$, 95\\% CI $[-0.041, +0.040]$). Second, presenting the full uncertainty taxonomy while collapsing the action space to a single generic action also adds no value ($\\Delta\\text{F1} = +0.008$, overlapping 95\\% CIs), ruling out taxonomy vocabulary as the mechanism. Typed action routing provides consistent directional gains ($\\text{F1} = 0.379$ vs $0.296$); the conservative estimate controlling for taxonomy vocabulary is $\\Delta\\text{F1} = +0.075$, and the overall gain over the single-shot baseline is significant by bootstrap CI ($\\Delta\\text{F1} = +0.101$, 95\\% CI $[+0.020, +0.185]$). The vocabulary-routing decomposition replicates on GPT-4o: taxonomy vocabulary adds no significant value over generic reflection ($p = 0.773$), while action routing provides significant gains ($p = 0.025$), confirming the mechanism holds across backbones. Gains concentrate on structurally novel conflicts: in Myanmar ($\\text{F1}: 0.000 \\rightarrow 0.353$) and Ukraine ($0.167 \\rightarrow 0.500$), the vocabulary-only condition recovers no more than generic reflection while action routing breaks the degenerate prior. These findings identify typed action routing --- not diagnostic scaffolding or taxonomy vocabulary --- as a promising design principle for metacognitive LLM forecasting agents, while motivating larger-scale evaluation across conflict typologies.","published":"2026-05-26T03:45:47+00:00","updated":"2026-06-30T15:32:45+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=kYrHkkhkqy","openreview_url":"https://openreview.net/forum?id=kYrHkkhkqy","pdf_url":"https://openreview.net/pdf?id=kYrHkkhkqy","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.26494","versioned_id":"2605.26494v1","title":"The MiniMax-M2 Series: Mini Activations Unleashing Max Real-World Intelligence","authors":["MiniMax",":","Aili Chen","Aonian Li","Baichuan Zhou","Bangwei Gong","Binyang Jiang","Boji Dan","Changqing Yu","Chao Wang","Cheng Ma","Cheng Zhong","Cheng Zhu","Chengjun Xiao","Chengyi Yang","Chengyu Du","Chenyang Zhang","Chi Zhang","Chuangyi Huang","Chunhao Zhang","Chunhui Du","Chunyu Zhao","Congchao Guo","Da Chen","Deming Ding","Dianjun Sun","Dongyu Zhang","Enhui Yang","Fei Yu","Guang Zheng","Guodong Zheng","Guohong Li","Haichao Zhu","Haigang Zhou","Haimo Zhang","Han Ding","Hao Zhang","Haohai Sun","Haolin Lyu","Haonan Lu","Haoyu Wang","Huajie Shi","Huiyang Li","Jiacheng Chen","Jian Zhang","Jiaqi Zhuang","Jiaren Cai","Jiaxin Pan","Jiayao Li","Jiayuan Song","Jichuan Zhang","Jie Wang","Jihao Gu","Jin Zhu","Jingwei Dong","Jingyang Li","Jingyu Zhang","Jingze Zhuang","Jinhao Tian","Jinli Liu","Jinyi Hu","Jun Tao","Jun Zhang","Junbin Ruan","Junhao Xu","Junjie Yan","Junteng Liu","Junxian He","Kang Xu","Ke Ji","Ke Yang","Kecheng Xiao","Keyu Duan","Keyu Li","Le Han","Letian Ruan","Li Yuan","Lianfei Yu","Liheng Feng","Lijie Mo","Lin Li","Lingye Bao","Lingyu Yang","Lingyuan Zhou","Loki","Lu Chen","Lunbin Ceng","Ming Li","Ming Zhong","Mingliang Tao","Mingyuan Chi","Mujie Lin","Nan Hu","Ningxin Chen","Peiyin Zhu","Peng Gao","Pengcheng Gao","Pengfei Li","Penglin Li","Pengyu Zhao","Qibin Ren","Qidi Xu","Qihan Ren","Qile Li","Qin Wang","Quanliang Chen","Qunhong Ceng","Rong Tian","Rui Dong","Ruitao Leng","Ruize Zhang","Shanqi Liu","Shaoyu Chen","Sheng Jia","Shun Yao","Shuoran Zhao","Shuqi Yu","Sichen Li","Sicheng Pan","Songquan Zhu","Tengfei Li","Tian Xie","Tiancheng Qin","Tianrun Liang","Wei Liu","Weiqi Xu","Weitao Li","Weixiang Chen","Weiyu Cheng","Weiyu Zhang","Wenhu Chen","Wenqian Zhao","Xiancai Chen","Xiangjun Song","Xiangyuan Wang","Xiao Luo","Xiao Su","Xiaobo Li","Xiaodong Han","Xiaojie Wu","Xihao Song","Xingyi Han","Xinyu Guan","Xuan Lu","Xun Zou","Xunhao Lai","Xutong Li","Yan Gong","Yang Wang","Yang Xu","Yangsen Wang","Ye Tang","Yicheng Chen","Yinran Qiu","Yiqi Shi","Yiting Guo","Yiwen Huang","Yixuan Wang","Yongyi Hu","Yu Gao","Yu Zhang","Yuanxiang Ying","Yuanzhen Zhang","Yubo Wang","Yuchen Song","Yufeng Yang","Yuhang Meng","Yuhang Miao","Yuhao Li","Yujie Liu","Yulin Hu","Yunan Huang","Yunji Li","Yunyi Huang","Yusen Zhang","Yusu Hong","Yutao Xie","Yutong Zhang","Yuwen Liao","Yuxuan Shi","Yuze Wenren","Zebin Li","Zehan Li","Zejian Luo","Zeyu Jin","Zeyuan Sun","Zhanpeng Zhou","Zhaochen Su","Zhendong Li","Zhengmao Zhu","Zhengyuan Peng","Zhenhua Fan","Zhi Zhang","Zhichao Xu","Zhiheng Lv","Zhikang Xu","Zhitao He","Zhiwei He","Zhongyuan Li","Zibo Gao","Zijia Wu","Zijian Song","Zijian Zhou","Zijun Sun","Zishan Huang","Ziying Chen","Ziyue Ge"],"abstract":"We introduce the MiniMax-M2 series, a family of Mixture-of-Experts language models built around the principle that mini activations can unleash maximum real-world intelligence. The flagship M2 contains 229.9B total parameters with only 9.8B activated per token. Designed end-to-end for agentic deployment, the M2 series rests on three components: (i) agent-driven data pipelines producing large-scale, verifiable trajectories across agentic coding and agentic cowork, each grounded in an executable workspace and an artifact-aligned reward; (ii) Forge, a scalable agent-native RL system that adapts to long-horizon agent trajectories, paired with windowed-FIFO scheduling, prefix-tree merging, inference optimization, and a clean training-inference-agent decoupling that supports both white-box and black-box agents; (iii) the latest M2.7 checkpoint takes an early step toward self-evolution -- autonomously debugging training runs and modifying its own scaffold. Across M2 through M2.7, this combination translates a mini-activation footprint into frontier-tier performance on agentic coding, deep search, office-task, and reasoning benchmarks.","published":"2026-05-26T03:16:11Z","updated":"2026-05-26T03:16:11Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.26494v1","pdf_url":"https://arxiv.org/pdf/2605.26494v1","comment":"Technical Report. 35 pages, 10 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:VBEGp7wfBn","versioned_id":"VBEGp7wfBn","title":"DeepMMSearch-R1: Empowering Multimodal LLMs in Multimodal Web Search","authors":[],"abstract":"Multimodal Large Language Models (MLLMs) in real-world applications require access to external knowledge sources and must remain responsive to the dynamic and ever-changing real-world information in order to address information-seeking and knowledge-intensive user queries. Existing approaches, such as retrieval augmented generation (RAG) methods, search agents, and search equipped MLLMs, often suffer from rigid pipelines, excessive search calls, and poorly constructed search queries, which result in inefficiencies and suboptimal outcomes. To address these limitations, we present \\textbf{DeepMMSearch-R1}, the first multimodal LLM capable of performing on-demand, multi-turn web searches and dynamically crafting queries for both image and text search tools. Specifically, DeepMMSearch-R1 can initiate web searches based on relevant crops of the input image making the image search more effective, and can iteratively adapt text search queries based on retrieved information, thereby enabling self-reflection and self-correction. Our approach relies on a two-stage training pipeline: a cold start supervised finetuning phase followed by an online reinforcement learning optimization. For training, we introduce DeepMMSearchVQA, a novel multimodal VQA dataset created through an automated pipeline intermixed with real-world information from web search tools. This dataset contains diverse, multi-hop queries that integrate textual and visual information, teaching the model when to search, what to search for, which search tool to use and how to reason over the retrieved information. We conduct extensive experiments across a range of knowledge-intensive benchmarks to demonstrate the superiority of our approach. Finally, we analyze the results and offer insights to advance multimodal web search.","published":"2026-05-26T03:10:30+00:00","updated":"2026-06-18T00:35:28+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=VBEGp7wfBn","openreview_url":"https://openreview.net/forum?id=hyyxMD3JZX","pdf_url":"https://openreview.net/pdf?id=VBEGp7wfBn","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2026 May Submission","ICLR 2026 Conference Withdrawn Submission"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"openreview:mVqBsxdasi","versioned_id":"mVqBsxdasi","title":"Code2Math: Can Your Code Agent Effectively Evolve Math Problems Through Exploration?","authors":[],"abstract":"As large language models (LLMs) advance their mathematical capabilities toward the IMO and research level, the scarcity of challenging, high-quality problems has become a significant bottleneck for training, evaluation and self-evolution of LLMs. Simultaneously, recent code agents have demonstrated sophisticated skills in agentic coding and reasoning, suggesting that code execution can serve as a scalable environment for mathematical experimentation. In this paper, we investigate the potential of code agents to autonomously evolve existing math problems into more complex variations. We introduce a multi-agent framework designed to perform problem evolution while validating the solvability and increased difficulty of the generated problems. Our experiments demonstrate that, given sufficient test-time exploration, code agents can synthesize new, solvable problems that are structurally distinct from and more challenging than the originals. This work provides empirical evidence that code-driven agents can serve as a viable mechanism for synthesizing high-difficulty mathematical reasoning problems within scalable computational environments.","published":"2026-05-26T01:58:02+00:00","updated":"2026-06-11T13:31:48+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=mVqBsxdasi","openreview_url":"https://openreview.net/forum?id=mVqBsxdasi","pdf_url":"https://openreview.net/pdf?id=mVqBsxdasi","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:fMyVTW7Bof","versioned_id":"fMyVTW7Bof","title":"When Wrong Answers Look Right: AEGIS-D, a Multi-Agent Debate System for High-Precision Verification of Hard Competition Mathematics","authors":["Jiayang Sun","Jiawei Xu","Maxm Pan","Zerui Cheng","Pramod Viswanath"],"abstract":"High-quality mathematical reasoning data are central to both training and evaluation, but such data are only useful when their answers and reasoning traces are reliable. Candidate solutions may be web-scraped, human-written, adapted from existing competition problems, or generated by LLMs; in all cases, a fluent but subtly wrong solution can silently contaminate downstream use. We present a high precision multi-agent debate pipeline for blind verification of competition-level mathematics, in which five heterogeneous agents independently analyze a candidate answer, exchange structured arguments for up to five rounds, and reach a verdict governed by an assessment-gating criterion that requires positive confirming evidence rather than mere non-refutation. On 195 hard-to-verify variants from 58 IMO/USAMO/Putnam-level problems, a single-judge baseline achieves 55.1\\% precision; our pipeline achieves **92.5\\%** precision---an 8.3$\\times$ false-positive reduction---with 59.8\\% problem-level accuracy. A 2$\\times$2 factorial ablation shows that, after accounting for repeated verification, most of the remaining false-positive reduction comes from two architectural mechanisms: **assessment gating** and **heterogeneous agent roles**. These results establish precision-first debate as a practical filtering primitive for mathematical reasoning data, with applications to benchmark curation, reward labeling, RLAIF, and self-improving synthetic-data pipelines.","published":"2026-05-25T23:58:29+00:00","updated":"2026-06-25T10:17:28+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=fMyVTW7Bof","openreview_url":"https://openreview.net/forum?id=fMyVTW7Bof","pdf_url":"https://openreview.net/pdf?id=fMyVTW7Bof","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.26195","versioned_id":"2605.26195v2","title":"CyberEvolver: Structured Self-Evolution for Cybersecurity Agents On the Fly","authors":["Yihe Fan","Changyi Li","Lichen Xu","Xudong Pan","Jiarun Dai","Hong Geng","Min Yang"],"abstract":"LLM-based agents are increasingly used for cybersecurity tasks, but most existing systems rely on fixed, human-designed scaffolds that struggle to adapt across diverse targets and failure modes. We introduce \\textsc{CyberEvolver}, a self-evolving cybersecurity agent framework that iteratively revises its own scaffold based on experience from failed execution attempts. Self-evolution in cybersecurity is challenging because the space of possible scaffold changes is largely unstructured, execution feedback is sparse and often obscured by the environment, and low-diversity updates can cause errors to compound over repeated iterations. \\textsc{CyberEvolver} addresses these challenges with a four-layer evolvable agent architecture that decomposes scaffold optimization into structured components, a trace-to-diagnosis mechanism that converts noisy execution logs into actionable revision signals, and a population-based beam search strategy that preserves diverse agent variants during evolution. We evaluate \\textsc{CyberEvolver} on CTF challenges, vulnerability exploitation, and penetration-testing tasks using four open-source LLMs. Across these settings, \\textsc{CyberEvolver} improves the seed agent's success rate by $13.6$\\,\\% on average, and outperforms six human-designed cybersecurity agents as well as two self-improvement methods adapted from other domains. These results suggest that scaffold self-evolution is a promising direction for building adaptive LLM agents for security testing.","published":"2026-05-25T16:26:59Z","updated":"2026-06-16T16:19:26Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.26195v2","pdf_url":"https://arxiv.org/pdf/2605.26195v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2605.25984","versioned_id":"2605.25984v1","title":"SafeCtrl-RL: Inference-Time Adaptive Behaviour Control for LLM Dialogue via RL-Driven Prompt Optimisation","authors":["Michael Orme","Yanchao Yu","Zhiyuan Tan"],"abstract":"Ensuring safe and contextually appropriate behaviour in Large Language Models (LLMs) remains a critical challenge for real-world deployment. We present \\textbf{SafeCtrl-RL}, an inference-time behavioural control framework that enables adaptive safety regulation without model retraining or parameter modification. The method formulates dialogue generation as a sequential decision process, where a reinforcement learning agent dynamically selects prompt adjustment strategies based on contextual feedback. This allows unsafe behaviours to be suppressed through iterative refinement, which we conceptualise as inference-time behavioural unlearning. Evaluated across multiple LLMs and unsafe dialogue scenarios, SafeCtrl-RL consistently improves safety and response quality, outperforms existing prompt-based optimisation methods, and achieves favourable performance--efficiency trade-offs. **Warning: This paper may contain examples of harmful language, and reader discretion is recommended.","published":"2026-05-25T16:03:38Z","updated":"2026-05-25T16:03:38Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.25984v1","pdf_url":"https://arxiv.org/pdf/2605.25984v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:BjRR2sdDKJ","versioned_id":"BjRR2sdDKJ","title":"SEED-Web: Self-Evolution Experience Distillation for Web Agents","authors":[],"abstract":"Existing web-agent training methods improve performance through prompting, reinforcement learning, or planner-executor decomposition, but often rely on coarse terminal rewards, auxiliary reward models, or additional supervision, leaving intermediate action quality weakly controlled. In this work, we propose SEED, a teacher-initialized self-evolution framework that refines successful trajectories into reliable step-level supervision through offline filtering. SEED first uses a stronger teacher policy to generate diverse rollouts and retains task-completing trajectories. Unlike prior success-only training, SEED further performs fine-grained trajectory screening to filter out unreliable intermediate interactions and redundant action traces, yielding cleaner action traces for behavior-cloning warm-up. The student is further improved through an offline self-evolution loop: it generates new rollouts, filters them with the same screening procedure, and learns from the retained trajectories via supervised distillation. This design enables continual self-improvement without online reward-gradient optimization, separately trained reward models, or additional human supervision. On WebArena-Lite, SEED achieves 57.6% and 61.2% success rates with 7B and 14B backbones, respectively, setting a new SOTA among comparable open-source agents.","published":"2026-05-25T15:50:59+00:00","updated":"2026-06-22T06:45:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=BjRR2sdDKJ","openreview_url":"https://openreview.net/forum?id=BjRR2sdDKJ","pdf_url":"https://openreview.net/pdf?id=BjRR2sdDKJ","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:Rmhg7yt5sd","versioned_id":"Rmhg7yt5sd","title":"ReCite: Agentic Reasoning for Faithful Citation","authors":[],"abstract":"Accurate citations are the foundation of academic writing, tracing intellectual origins and substantiating core claims. However, manually navigating the growing volume of scientific literature is increasingly difficult, prompting reliance on automatic citation recommendation. While modern retrieval-augmented architectures have largely mitigated the fabrication of non-existent papers, current systems relying on semantic similarity struggle with misattribution, often citing authentic papers that fail to logically support the author's claim. To address this challenge, we argue that accurate citation requires a shift from similarity-based search to active, claim-level reasoning. We propose ReCite, a decoupled agentic framework that orchestrates location perception, intent-aware query planning, and reflective verification.Trained on synthesized reasoning trajectories, our agent verifies claim-evidence consistency and triggers self-correction loops when retrieved candidates lack logical support. Experiments demonstrate that our lightweight framework outperforms state-of-the-art massive generative models in strict citation accuracy. By grounding literature matching in verifiable logic rather than semantic overlap, ReCite establishes a reliable foundation for automated academic writing.","published":"2026-05-25T13:10:47+00:00","updated":"2026-06-24T07:16:43+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Rmhg7yt5sd","openreview_url":"https://openreview.net/forum?id=Rmhg7yt5sd","pdf_url":"https://openreview.net/pdf?id=Rmhg7yt5sd","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:6pcrtBtYIi","versioned_id":"6pcrtBtYIi","title":"Recursive Epistemic Engines for Verifiable Open-Ended Scientific Agents","authors":["David Scott Lewis","Enrique Zueco","Haley Yi"],"abstract":"Current language-model research agents can generate ideas, write code, run experiments, and draft reports, but their unit of progress is still too often a fluent research narrative rather than a verified scientific object. We formalize this gap as the *Novelty Horizon*: the boundary beyond which an autonomous system cannot jointly generate, execute, verify, and reuse non-derivative hypotheses. We propose *Recursive Epistemic Engines* (REEs), a template-free architecture that couples large-language-model proposal priors to typed artifact languages, quality-diversity archives, theorem provers, runtime/statistical checkers, and guarded self-modification. The central object is a proof-carrying, experiment-carrying claim package whose value is measured by verified compression gain, expected information gain, transfer, and lineage-auditable reuse. We instantiate the framework with three mechanisms: a verification-gated quality-diversity prover loop; a categorical abstraction layer for compositional scientific objects; and a guarded self-evolution loop for improving verifiers, descriptors, and campaign policies. Three reproducible synthetic experiments isolate the architecture's core claims. Verification-gated QD expands diverse admissible archives while avoiding off-spec artifacts; proof checking without semantic-alignment gates admits many vacuous or misformalized statements; and guarded self-modification preserves heldout utility and verifier strength under Goodhart pressure better than visible-score adoption. The result is a concrete research program for scientific agents that evolve not by producing more plausible papers, but by recursively expanding the space of machine-checkable hypotheses, experiments, and abstractions.","published":"2026-05-25T12:35:05+00:00","updated":"2026-06-26T11:50:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=6pcrtBtYIi","openreview_url":"https://openreview.net/forum?id=6pcrtBtYIi","pdf_url":"https://openreview.net/pdf?id=6pcrtBtYIi","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:WpdqYk3zaq","versioned_id":"WpdqYk3zaq","title":"LCIA Self-Play: The London Court of International Arbitration as a Benchmark for Verifiable Self-Evolving Scientific Agents","authors":["David Scott Lewis","Haley Yi"],"abstract":"Self-evolving scientific agents are often evaluated where the training record is observable and correctness can be checked directly, but many scientific and institutional settings expose only selected public traces, contain strategic actors, and impose formal admissibility constraints. **LCIA Self-Play** is a synthetic benchmark inspired by the London Court of International Arbitration that models confidential arbitration as a partially observable hidden-type game with a deterministic legality gate over procedural actions. Agents improve through self-play, belief updating, episodic memory, and capability-preserving rehearsal while being evaluated on calibration, public-slice overfitting, hidden-type robustness, exploitability, violation probability, and retention. Across twelve pre-specified seeds, public-slice supervision preserves ranking signal but is badly miscalibrated on the hidden population (Brier `0.238 +/- 0.001` to `0.254 +/- 0.002`; ECE `0.017 +/- 0.002` to `0.120 +/- 0.006`), while verifier-gated self-play raises worst-hidden-type value over public-greedy play (`0.626 +/- 0.007` versus `0.510 +/- 0.017`) with zero invalid-action mass. Memory replay improves retained old-family value over recent-only adaptation (`0.685 +/- 0.008` versus `0.656 +/- 0.009`), making the contribution a reproducible stress test for constrained self-evolution rather than a legal prediction system.","published":"2026-05-25T11:42:04+00:00","updated":"2026-06-26T10:56:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=WpdqYk3zaq","openreview_url":"https://openreview.net/forum?id=WpdqYk3zaq","pdf_url":"https://openreview.net/pdf?id=WpdqYk3zaq","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:7bNDvPemyD","versioned_id":"7bNDvPemyD","title":"Beyond Goodharting: A Genuine-Improvement Optimization Engine for Exploration-Guided Agent Evolution","authors":[],"abstract":"Recent systems use LLMs to iteratively evolve agentic systems, including code, prompts, tools, and task harnesses, from evaluation feedback. While effective, these metric-driven loops are vulnerable to \\emph{spurious optimization traps}: Goodharting turns noisy or incomplete metric gains into apparent progress, while weak exploration keeps later search near fragile directions instead of substantive alternatives. We introduce the Genuine-Improvement Optimization Engine (GIOE), a Goodhart-aware optimizer for LLM-guided agentic evolution. GIOE treats score gains as evidence rather than proof of genuine improvement and improves exploration by ranking admissible proposals by expected improvement and novelty. At each round, GIOE proposes structured modifications, filters them for validity, improvement potential, and exploration value, verifies selected code, prompt, or harness changes, and commits or discards them through an explicit decision protocol. We evaluate on AutoLab, $\\tau^3$-bench, and general reasoning benchmarks. GIOE achieves higher aggregate scores than autoresearch-style greedy optimization and GEPA while increasing exploration coverage, suggesting that Goodhart-aware agent evolution requires optimizer engines that manage both metric evidence and search diversity instead of directly chasing noisy metrics.","published":"2026-05-25T11:27:37+00:00","updated":"2026-07-05T21:05:52+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=7bNDvPemyD","openreview_url":"https://openreview.net/forum?id=7bNDvPemyD","pdf_url":"https://openreview.net/pdf?id=7bNDvPemyD","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:YAeC8bVwOU","versioned_id":"YAeC8bVwOU","title":"OS-Themis: A Scalable Critic Framework for Generalist GUI Rewards","authors":[],"abstract":"Reinforcement Learning (RL) has the potential to improve the robustness of GUI agents in stochastic environments, yet training is highly sensitive to the quality of the reward function. Existing reward approaches struggle to achieve both scalability and performance. To address this, we propose OS-Themis, a scalable and accurate multi-agent critic framework. Unlike a single judge, OS-Themis decomposes trajectories into verifiable milestones to isolate critical evidence for decision making and employs a review mechanism to strictly audit the evidence chain before making the final verdict. To facilitate evaluation, we further introduce OmniGUIRewardBench (OGRBench), a holistic multi-platform benchmark for GUI outcome rewards, where all evaluated models achieve their best performance under OS-Themis. Extensive experiments conducted on our stable Android online RL infrastructure show that OS-Themis yields a 10.3% improvement when used to support online training, highlighting its potential to drive agent evolution.","published":"2026-05-25T11:27:30+00:00","updated":"2026-07-06T08:03:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=YAeC8bVwOU","openreview_url":"https://openreview.net/forum?id=YAeC8bVwOU","pdf_url":"https://openreview.net/pdf?id=YAeC8bVwOU","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:2vPCRmHKjp","versioned_id":"2vPCRmHKjp","title":"Tool-R0: Self-Evolving LLM Agents for Tool-Learning from Zero Data","authors":[],"abstract":"Large language models (LLMs) are becoming the foundation for autonomous agents that can use tools to solve complex tasks. Reinforcement learning (RL) has emerged as a common approach for injecting such agentic capabilities, but typically under tightly controlled training setups. It often depends on carefully curated task–solution pairs and substantial human supervision, which creates a fundamental obstacle to open-ended self-evolution. In this paper, we propose Tool-R0 for training general purpose tool-calling agents from scratch with self-play RL, under a zero-data assumption. Initialized from the same base LLM, Tool-R0 co-evolves a Generator and a Solver with complementary rewards: one proposes targeted challenging tasks at the other's competence frontier and the other learns to solve them with real-world tool calls. This creates a self-evolving cycle that requires no pre-existing datasets. Evaluation on five tool-use benchmarks show that Tool-R0 yields 92.5\\% relative improvement over the base model and surpasses fully supervised tool-calling baselines under the same setting. Our work further provides empirical insights into self-play LLM agents by analyzing co-evolution, curriculum dynamics, and scaling behavior.","published":"2026-05-25T09:00:25+00:00","updated":"2026-07-06T02:40:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=2vPCRmHKjp","openreview_url":"https://openreview.net/forum?id=8XxQOFLva7","pdf_url":"https://openreview.net/pdf?id=2vPCRmHKjp","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2026 May Submission","MSLD 2026 Poster"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:SRHoVcHxxO","versioned_id":"SRHoVcHxxO","title":"AutoHealth: Uncertainty-Aware Multi-Agent Framework for Autonomous Health Prediction","authors":[],"abstract":"Developing effective and reliable health prediction models traditionally requires close collaboration between clinicians and machine learning experts, which is costly and limits efficiency. Recent advances in large language model (LLM) agents offer the potential for clinicians to autonomously develop prediction models through natural language interaction. However, existing agent-based systems remain limited in handling heterogeneous health data, complex prediction tasks, and the reliability requirements of healthcare applications. In this work, we present \\textit{AutoHealth}, an uncertainty-aware multi-agent framework for autonomous health prediction. Given task descriptions, \\textit{AutoHealth} dynamically constructs specialized agents that collaboratively perform data exploration, strategy design, code generation, model training, evaluation, and iterative refinement. Beyond optimizing predictive performance, the framework explicitly models uncertainty and generates comprehensive reports to support trustworthy clinical decision-making. To enable robust evaluation, we curate a real-world benchmark comprising 17 tasks across diverse health data modalities and learning settings. On this benchmark, \\textit{AutoHealth} completes all tasks and outperforms state-of-the-art baselines by 31.6\\% in prediction performance and 51.4\\% in uncertainty estimation. These results demonstrate the strong capability of LLM agents in automated health data modeling.","published":"2026-05-25T06:38:55+00:00","updated":"2026-06-21T18:42:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=SRHoVcHxxO","openreview_url":"https://openreview.net/forum?id=SRHoVcHxxO","pdf_url":"https://openreview.net/pdf?id=SRHoVcHxxO","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.25480","versioned_id":"2605.25480v2","title":"Retrieval as Reasoning: Self-Evolving Agent-Native Retrieval via LLM-Wiki","authors":["Haoliang Ming","Feifei Li","Xiaoqing Wu","Wenhui Que"],"abstract":"LLM agents require retrieval to behave less like one-shot context fetching and more like reasoning: searching, reading, traversing, and deciding when evidence is sufficient. Yet current Retrieval-Augmented Generation (RAG) systems organize external knowledge as flat chunks retrieved by embedding similarity, exposing a retrieval-as-lookup interface ill-suited to iterative reasoning agents. We propose LLM-Wiki, an agent-native retrieval system that operationalizes the Retrieval-as-Reasoning paradigm by treating external knowledge as a compilable, composable, and self-evolving structure rather than a static retrieval index. LLM-Wiki compiles documents into structured Wiki pages with bidirectional links, exposes search, read, and link-following operations through standard tool-calling interfaces, and introduces an Error Book for persistent structural and semantic self-correction. LLM-Wiki achieves state-of-the-art results on HotpotQA, MuSiQue, and 2WikiMultiHopQA, outperforming HippoRAG 2, LightRAG, and GraphRAG by 2.0-8.1 F1 points. On AuthTrace, LLM-Wiki achieves the best overall accuracy, with especially strong gains on multi-document structured queries, confirming that compilation-based retrieval generalizes beyond chain-style multi-hop reasoning.","published":"2026-05-25T06:36:14Z","updated":"2026-05-26T10:31:56Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.25480v2","pdf_url":"https://arxiv.org/pdf/2605.25480v2","comment":"15 pages, 3 figures, 10 tables, 1 algorithm","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.25430","versioned_id":"2605.25430v1","title":"CODESKILL: Learning Self-Evolving Skills for Coding Agents","authors":["Yanzhou Li","Yiran Zhang","Xiaoyu Zhang","Xiaoxia Liu","Yang Liu"],"abstract":"Coding agents produce rich trajectories while solving software-engineering tasks. To enable agent self-evolution, these trajectories can be distilled into reusable procedural skills that compactly encode experience to guide future behavior. However, existing skill construction and maintenance methods often rely on fixed prompts and heuristic update rules, leaving it unclear how knowledge should be selected, abstracted, and maintained to best serve downstream agents. We propose CODESKILL, an LLM-based framework that reformulates skill extraction and skill-bank maintenance as a learnable management policy. CODESKILL extracts multi-granularity procedural skills from coding-agent trajectories, evolves skills with new experience, and maintains a compact skill bank for future task solving. We train CODESKILL with reinforcement learning, using a hybrid reward that combines dense rubric-based skill-quality feedback with sparse verifiable execution feedback from the frozen downstream agent. Experiments on EnvBench, SWE-Bench Verified, and Terminal-Bench 2 show that CODESKILL improves average pass rate by 9.69 over the no-skill baseline and by 4.01 over the strongest prompt-based or memory baseline, while maintaining the skill bank at a stable size during iterative construction.","published":"2026-05-25T05:12:49Z","updated":"2026-05-25T05:12:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.25430v1","pdf_url":"https://arxiv.org/pdf/2605.25430v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:FnSimngGYk","versioned_id":"FnSimngGYk","title":"The Rules of the Game: A Survey of Rubrics for Large Language Models","authors":["Wenhan Liu","Jiajie Jin","Zhaoheng Huang","Tongyu Wen","Guanting Dong","Ziliang Zhao","Yutao Zhu","Zhicheng Dou","Ji-Rong Wen"],"abstract":"Large language models (LLMs) have rapidly evolved from general text generators into increasingly capable systems for reasoning, decision-making, tool use, and long-horizon problem solving. As their application scenarios expand toward open-ended and high-stakes tasks, including deep research, medical diagnosis, multimodal generation, and agentic tool use, the question of how to specify, optimize, and evaluate model responses has become increasingly important. Simple correctness signals, holistic preference scores, and unconstrained LLM-based judgments are often insufficient for these settings, where response quality depends on multiple criteria such as factuality, completeness, safety, reasoning soundness, evidence grounding, and practical utility. Rubrics have therefore emerged as a promising mechanism for making evaluation standards explicit and operational. By decomposing broad quality expectations into structured and interpretable criteria, rubrics provide an interface for both training supervision and model evaluation. This survey presents a comprehensive and systematic overview of rubric-based research for LLMs. We first clarify the concept of rubrics and distinguish it from closely related concepts, including reward models, verifiable rewards, and LLM-as-a-judge. We then organize existing studies along three major directions. First, we summarize existing rubric construction methods and organize them into four categories: direct generation, contrastive generation, iterative refinement, and online or co-evolving generation. Second, we examine how rubrics support the training of policy models and reward models. For policy model training, we organize existing studies by their training mechanisms. For reward model training, we categorize prior work according to the functional roles that rubrics play in reward modeling. Third, we summarize rubric-driven task evaluation for both general and domain-specific tasks, and discuss the evaluation benchmarks from various perspectives. Beyond consolidating existing work, we discuss a series of key open questions, such as rubric reward hacking, the bias in rubric-based evaluation, personalization, and rubric safety. We hope this survey can serve as a structured reference for current research and a conceptual foundation for developing rubrics as transparent, adaptive, and trustworthy interfaces for future LLM systems. Given the rapid development of rubric-based research, we will keep this survey updated to incorporate new advances and emerging directions in this area.","published":"2026-05-25T03:31:27+00:00","updated":"2026-05-25T03:32:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=FnSimngGYk","openreview_url":"https://openreview.net/forum?id=FnSimngGYk","pdf_url":"https://openreview.net/pdf?id=FnSimngGYk","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:zgH3Fzt0GM","versioned_id":"zgH3Fzt0GM","title":"SPARC-RAG: Adaptive Sequential–Parallel Scaling with Context Management for Retrieval-Augmented Generation","authors":[],"abstract":"Retrieval-Augmented Generation (RAG) grounds large language model outputs in external evidence, but remains challenged on multi-hop question answering that requires long reasoning. Recent works scale RAG at inference time along two complementary dimensions: sequential depth for iterative refinement and parallel width for coverage expansion. However, naive scaling causes context contamination and scaling inefficiency, leading to diminishing or negative returns despite increased computation. To address these limitations, we propose SPARC-RAG, a framework that coordinates joint depth-width scaling around a unified context management mechanism—a shared global context state on which specialized control agents regulate parallel exploration and sequential stopping. To optimize scaling behavior, we further introduce a lightweight fine-tuning method with process-level verifiable preferences, which improves the efficiency of sequential scaling and effectiveness of parallel scaling. Across single- and multi-hop QA benchmarks, SPARC-RAG consistently outperforms previous RAG baselines, yielding an average +6.2 F1 improvement under lower inference cost.","published":"2026-05-25T00:43:16+00:00","updated":"2026-06-11T09:49:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=zgH3Fzt0GM","openreview_url":"https://openreview.net/forum?id=BArka7ZyhU","pdf_url":"https://openreview.net/pdf?id=zgH3Fzt0GM","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2026 May Submission","ACL ARR 2026 January Submission"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:ofa2TGrHTu","versioned_id":"ofa2TGrHTu","title":"How Far Can Self-Evolving Agents Go? A Systematic Evaluation across Models, Harnesses, and Benchmarks","authors":[],"abstract":"Self-evolving agents (systems that improve through test-time experience without retraining) have proliferated rapidly, yet the field lacks controlled cross-method evaluation: each work tests only its own method on self-selected benchmarks with limited model coverage, making it impossible to determine which paradigm actually works, for which tasks, and with which models. We present the first systematic, multi-factor evaluation across several representative paradigms, frontier LLMs, and benchmarks spanning domain-specific to extreme-difficulty tasks. Our evaluation reveals: (1) self-evolution reliably benefits structured tasks but shows inconsistent effects on knowledge-intensive reasoning and no detectable effect on extreme-difficulty tasks; (2) the inconsistent effects on GPQA are specific to retrieval-augmented methods and absent from non-retrieval methods, demonstrating a dissociation between retrieval-based and non-retrieval evolution; (3) extending evolution scope from prompts to tool code or scaffold logic triggers catastrophic self-amplifying failure loops across all tested models, revealing a sharp reliability boundary between declarative and procedural evolution targets. Batch ordering sensitivity analysis confirms these findings are robust across alternative orderings. Our results provide the empirical foundation needed to guide principled deployment of self-evolving agents.","published":"2026-05-24T16:25:50+00:00","updated":"2026-06-29T06:23:30+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ofa2TGrHTu","openreview_url":"https://openreview.net/forum?id=ofa2TGrHTu","pdf_url":"https://openreview.net/pdf?id=ofa2TGrHTu","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:WEhczeS4LJ","versioned_id":"WEhczeS4LJ","title":"Multi-View Self-Optimization for Language Agents","authors":[],"abstract":"Language agents often produce a plausible first attempt that still contains weaknesses visible from alternative viewpoints. Human writers and problem solvers rarely revise from a single undifferentiated perspective; instead, they separately inspect correctness, completeness, constraint satisfaction, and presentation before rewriting. We study whether a single text model can benefit from the same inductive bias at inference time. We propose Multi-View Self-Optimization (MVSO), a lightweight single-backbone framework that generates a draft, critiques it through task-adaptive viewpoints, synthesizes the critiques into one revision plan, and then rewrites once. We further introduce MVSO-Bench, a reproducible text-first benchmark suite for multi-view agent optimization, spanning easy pilot tasks, controllable rewriting, and harder reasoning subsets with exact-match and constraint-aware metrics. On a hard 80-example MATH-500 subset with a local Qwen3-4B-Instruct-2507 checkpoint, MVSO improves exact match from 0.1125 (single-pass) and 0.1625 (generic self-refine) to 0.3125. However, the same structure does not help a weaker Gemma-4-E2B-it checkpoint on the same benchmark, and a fast bbh_hard validation instead favors generic self-refinement over MVSO. These results suggest that explicit viewpoint decomposition is a real optimization axis for agents, but its benefit is backbone-dependent and task-dependent, with the clearest gains appearing when tasks expose multiple failure modes that a single critique prompt does not reliably separate.","published":"2026-05-24T13:44:51+00:00","updated":"2026-06-18T02:57:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=WEhczeS4LJ","openreview_url":"https://openreview.net/forum?id=WEhczeS4LJ","pdf_url":"https://openreview.net/pdf?id=WEhczeS4LJ","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:jZOO2JVztt","versioned_id":"jZOO2JVztt","title":"TDD-Agent: Test-Driven Reasoning for Code Generation","authors":[],"abstract":"Large Language Models (LLMs) have achieved remarkable progress in code generation, yet ensuring correctness in complex, repository-level tasks remains challenging. Existing approaches often use generated tests as static post-hoc validators, which limits their ability to guide implementation and may introduce misleading feedback when the tests themselves are incomplete or incorrect. In this paper, we introduce TDD-Agent, which operationalizes the test-driven development paradigm for code generation. TDD-Agent first prompts the model to generate executable tests, encouraging it to clarify expected behaviors before implementation, and then performs iterative dual-track refinement over both the generated code and tests using execution feedback. We first isolate the effect of test-first reasoning through a prompt variant TDD-prompt on LiveCodeBench, where it consistently improves upon reasoning-based prompting baselines. Building on this finding, we evaluate the full TDD-Agent framework on RepoEval, a repository-level benchmark, and show that it consistently outperforms retrieval-based and agent-based baselines. Additional analyses show that iterative refinement improves not only code correctness but also the effectiveness of the generated tests, yielding higher pass rates, coverage, and mutation scores, suggesting that tests can serve as evolving reasoning artifacts rather than fixed validators. Our source code is available at https://anonymous.4open.science/r/TDD-Agent-Framework-6370/.","published":"2026-05-24T09:49:46+00:00","updated":"2026-06-18T03:02:29+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=jZOO2JVztt","openreview_url":"https://openreview.net/forum?id=jZOO2JVztt","pdf_url":"https://openreview.net/pdf?id=jZOO2JVztt","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:wSrMfA4T42","versioned_id":"wSrMfA4T42","title":"K-MASTER: A Training-Free Multi-Agent Framework of Knowledge Concept Tagging for Course Questions","authors":[],"abstract":"Automatic knowledge concept tagging assigns educational questions to one or more concepts in a curriculum knowledge system. It is a core component of question-bank management, personalized recommendation, and adaptive tutoring. Supervised tagging models can achieve strong performance when large annotated corpora and stable knowledge taxonomies are available, but they are difficult to transfer to new subjects, revised curricula, or long-tail concepts. Large language models (LLMs) offer a training-free alternative. However, direct prompting with large label sets often leads to predictions outside the taxonomy. Existing discriminative evaluation methods reduce tagging to repeated binary decisions, which is costly for large taxonomies and does not support joint label ranking. In this paper, we propose K-MASTER, a training-free multi-agent framework for knowledge concept tagging. K-MASTER decomposes tagging into a generate-retrieve-evaluate loop: a generator proposes open-form concept descriptions, a retriever maps them to a standard knowledge taxonomy through subject routing and hybrid retrieval, and an evaluator filters candidates and provides feedback for iterative refinement. Experiments on six datasets across four subjects show that K-MASTER achieves a favorable balance among accuracy, efficiency, and adaptability. It outperforms a discriminative multi-agent baseline and remains more robust than a supervised model on low-frequency labels.","published":"2026-05-24T08:15:04+00:00","updated":"2026-06-16T07:12:55+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wSrMfA4T42","openreview_url":"https://openreview.net/forum?id=wSrMfA4T42","pdf_url":"https://openreview.net/pdf?id=wSrMfA4T42","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:riNx2zrJJs","versioned_id":"riNx2zrJJs","title":"EvoFinAgent: A Self-Evolving Agentic Framework for Financial Trading","authors":[],"abstract":"Recent advances in large language model (LLM) trading agents have increasingly emphasized multimodal inputs, external tool integration, and multi-agent coordination. While promising, these approaches typically deliver marginal gains and leave a central limitation unaddressed: the agent's internal reasoning logic is deterimined by human and it is hard for us to find the logic flaws and make the correct modifications. Moreover, different language models often exhibit distinct reasoning patterns and trading behaviors. As a result, a fixed prompt template or workflow designed for one model may not generalize well when applied to another backbone, leading to performance degradation or incompatibility. In this work, we introduce EvoFinAgent, a lightweight, self-evolving agentic framework that enhances trading performance through structured prompt-level optimization. Without requiring fine-tuning, external data sources, or auxiliary tools, EvoFinAgent improves its decision quality by reflecting on past trades, identifying reasoning failures, and recomposing new prompts based on performance-driven feedback. Its modular chain-of-thought structure and stable self-reflection pipeline enable interpretable and risk-aware strategy evolution. We validate EvoFinAgent across five major stock assets and multiple backbone language models, demonstrating consistent improvements in return, Sharpe ratio, and drawdown over generations. In backtesting, EvoFinAgent outperforms a broad spectrum of baselines, including rule-based systems, machine learning methods, reinforcement learning agents, LLM-based trading agents, and general-purpose evolutionary agents not originally designed for financial decision-making. These results suggest that evolving internal reasoning through prompt-level adaptation offers an effective and scalable alternative to increasing architectural complexity in financial trading tasks.","published":"2026-05-24T05:23:19+00:00","updated":"2026-07-03T08:46:30+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=riNx2zrJJs","openreview_url":"https://openreview.net/forum?id=riNx2zrJJs","pdf_url":"https://openreview.net/pdf?id=riNx2zrJJs","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.24659","versioned_id":"2605.24659v1","title":"IterInject: Indirect Prompt Injection Against LLM Agents via Feedback-Guided Iterative Optimization","authors":["Zixuan Chen","Jiaxiang Chen","Li Luo","Ke Xu","Xiaoxiang Huang","Tanfeng Sun","Xinghao Jiang"],"abstract":"LLM-based agents are increasingly deployed for complex tasks requiring planning, tool use, and interaction with external services. Their reliance on untrusted external content exposes them to indirect prompt injection (IPI), in which adversarial instructions embedded in retrieved data hijack agent behavior. Existing attacks rely on static payloads that cannot adapt to agent-specific defenses; even recent adaptive methods lack structured feedback to guide optimization. We introduce \\oursys, a feedback-guided iterative framework that closes the loop between injection, diagnosis, and refinement: a rule-based diagnoser produces structured outcome labels with behavioral descriptions, and an LLM-based optimizer refines payloads conditioned on the full optimization history. A synthesis step generates new disguise seeds from failure patterns, enabling the strategy space to self-evolve. On AgentDojo and InjectAgent, \\oursys substantially outperforms static baselines and existing adaptive methods across four victim models. Extension experiments on Claude Code, a production-grade coding agent with layered defenses, show that optimized payloads achieve full success on 5 of 9 targets; even those that resist full exploitation exhibit measurable improvement from iterative refinement. We further present a mechanistic analysis of IPI, identifying an attention-mediated threshold mechanism in mid-to-late layers; three causal interventions validate this finding and point to concrete defense directions.","published":"2026-05-23T17:00:06Z","updated":"2026-05-23T17:00:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.24659v1","pdf_url":"https://arxiv.org/pdf/2605.24659v1","comment":"Submitted to EMNLP 2026","journal_ref":"","doi":"","discovered_on":"2026-07-19","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=03bctSTOI3","openreview_venues":["ACL ARR 2026 May Submission"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:raoHDGrIUb","versioned_id":"raoHDGrIUb","title":"Readable Is Not Enough: Action-Oriented Tool Descriptions for Self-Evolving Agents","authors":[],"abstract":"Tool-using agents increasingly operate in dense tool environments, where success depends on selecting tools, grounding arguments, respecting constraints, and reusing outputs across workflows. This paper studies tool descriptions as evolvable action interfaces. We argue that descriptions are more useful for self-evolving agents when they expose action-relevant information--such as triggers, argument slots, constraints, call templates, output bindings, and field-level semantics--as explicit and locally editable repair handles. Using RealFin as a dense financial tool-use testbed, we compare source-equivalent renderings of the same tool-interface documentation, including documentation-oriented natural language (Doc-NL), action-schema descriptions (Act-Schema), and query-skeleton descriptions (Query-SQL), together with action-oriented repair variants. Across these settings, we observe three empirical signatures. First, Act-Schema provides a strong initial floor, reaching 76.05\\% accuracy before repair and exceeding the best evolved Doc-NL variant at 73.12\\%. Second, localized repair over Act-Schema reaches the top performance band at 78.26\\% accuracy with only 8.48\\% token growth. Third, Query-SQL recovers from 37.35\\% to 77.91\\% once self-evolution injects missing constraints, triggers, usage conditions, and output bindings. Token, fix-rate, and slice analyses further suggest that the gains are not driven by verbosity alone. Together, these patterns support a practical design principle: self-evolving agents benefit from tool descriptions organized as repairable action interfaces, where invocation conditions, argument constraints, call formation, output use, and field semantics are explicit enough to be diagnosed and edited.","published":"2026-05-23T14:32:48+00:00","updated":"2026-06-22T03:18:18+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=raoHDGrIUb","openreview_url":"https://openreview.net/forum?id=raoHDGrIUb","pdf_url":"https://openreview.net/pdf?id=raoHDGrIUb","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:dmQBqfdq9A","versioned_id":"dmQBqfdq9A","title":"MOOSE-Chem3: Closed-Loop Hypothesis Ranking with Simulated Feedback and Component Reasoning","authors":[],"abstract":"Large language models have shown remarkable promise in generating scientific hypotheses. However, the high cost and slow turnaround of wet-lab validation often restrict hypothesis evaluation to static, pre-experiment assessments, impeding rapid iterative refinement through real experimental feedback. To address this bottleneck, we introduce MOOSE-Chem3, a closed-loop optimization framework for efficient scientific hypothesis screening. MOOSE-Chem3~(MC3) comprises two core components: (1) MC3-Sim, a mechanism-aware simulator that serves exclusively as a development-time surrogate to overcome the feedback scalability gap, not as a replacement for wet-lab validation. During deployment, the same ranking policy seamlessly transitions to real experimental feedback ($E_{\\text{sim}} \\rightarrow E_{\\text{lab}}$). (2) MC3-Rank, an in-context reinforcement learning agent that decomposes hypotheses into functional components and attributes feedback to them, transferring evidence across hypotheses with shared mechanisms; it learns from simulated feedback during development and leverages wet-lab outcomes during deployment to refine hypothesis rankings.Evaluated on TOMATO-chem and real-outcome sequential deployment settings, MC3-Rank outperforms static, adaptive, and human expert baselines, establishing an efficient and scalable paradigm for feedback-driven scientific discovery.","published":"2026-05-23T12:01:54+00:00","updated":"2026-06-18T16:59:51+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=dmQBqfdq9A","openreview_url":"https://openreview.net/forum?id=dmQBqfdq9A","pdf_url":"https://openreview.net/pdf?id=dmQBqfdq9A","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:v4YVhedaba","versioned_id":"v4YVhedaba","title":"SAMAC: Collaborating with Multi-Disciplinary Team for Adaptive Medical Decision-Making","authors":[],"abstract":"Multi-agent large language model systems offer a promising paradigm for multidisciplinary medical decision support by integrating heterogeneous expert perspectives. However, existing frameworks often rely on loosely structured interactions, where disagreement is insufficiently diagnosed and discussion may collapse into superficial consensus or parallel opinion aggregation. We propose Structured Adaptive Multi-disciplinary Collaboration (SAMAC), a structured and strategy-aware multi-agent framework for adaptive MDT-style medical reasoning. SAMAC introduces Structured Deliberation to detect opinion disagreement and majority not confident, along with a Consensus Purification mechanism that transforms disagreement into constructive and collaborative refinement. When disagreement arises, SAMAC adaptively selects between Self-refinement and Counter-questioning to enable evidence-grounded negotiation. Experiments on three medical datasets—RADCURE, HANCOCK, and OSCCPI—show that SAMAC consistently improves overall performance and collaborative gains over existing multi-agent baselines. In particular, SAMAC improves the Average Score by 4.29 points on the RADCURE dataset and achieves higher Relative Self-Correction Scores (RSS), indicating more effective resolution of disagreement and stable collective decisions. These results highlight the importance of controlled and diverse interaction dynamics in multi-agent medical reasoning. Code will be released upon publication.","published":"2026-05-23T11:13:24+00:00","updated":"2026-07-08T06:45:48+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=v4YVhedaba","openreview_url":"https://openreview.net/forum?id=v4YVhedaba","pdf_url":"https://openreview.net/pdf?id=v4YVhedaba","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2605.24517","versioned_id":"2605.24517v1","title":"ECHO: Terminal Agents Learn World Models for Free","authors":["Vaishnavi Shrivastava","Piero Kauffmann","Ahmed Awadallah","Dimitris Papailiopoulos"],"abstract":"CLI agents are the closest thing language models have to an embodied setting: the model emits commands, the terminal executes them, and the returned stream -- stdout, errors, files, logs, and traces -- records the consequences. We argue that this stream is a supervision signal, but standard agent RL discards it: GRPO-style training updates action tokens with sparse outcome-level rewards while ignoring environment responses already in the rollout. Failed rollouts provide little policy-gradient signal despite containing rich evidence about how the environment responds. We introduce ECHO (Environment Cross-entropy Hybrid Objective), a hybrid objective that combines the standard policy-gradient loss on action tokens with an auxiliary loss that trains the policy to predict environment observation tokens resulting from its own actions. ECHO reuses the same forward pass as GRPO, requires no additional rollouts, and turns terminal feedback into dense supervision for all rollouts. ECHO doubles GRPO pass@1 on TerminalBench-2.0: Qwen3-8B improves from 2.70% to 5.17%, and Qwen3-14B from 5.17% to 10.79%. ECHO also produces policies that better predict terminal dynamics, even on trajectories they did not generate: across held-out rollouts, it sharply reduces environment-token cross-entropy while GRPO alone barely changes it. From base Qwen3-8B, ECHO matches expert-SFT-then-GRPO performance on held-out terminal tasks without expert demonstrations, and recovers roughly half of the expert-SFT initialization benefit on TerminalBench-2.0. In some settings, the environment prediction loss alone enables verifier-free self-improvement, allowing policies to improve on unseen OOD tasks by learning only from environment interactions. Together, these results suggest that environment observations are not merely context for future actions, but a dense, on-policy supervision signal already present in every rollout.","published":"2026-05-23T11:08:46Z","updated":"2026-05-23T11:08:46Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.24517v1","pdf_url":"https://arxiv.org/pdf/2605.24517v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=yiOkMgxDDT","openreview_venues":["ICML 2026 RLxF Workshop"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.24426","versioned_id":"2605.24426v1","title":"SEAL: Synergistic Co-Evolution of Agents and Learning Environments","authors":["Yihao Hu","Zhihao Wen","Xiujin Liu","Pan Wang","Xin Zhang","Wei Wu"],"abstract":"Large Language Model (LLM) agents are increasingly improved through interaction, yet most self-evolution methods adapt either the policy or the learning environment in isolation. We identify this structural gap as \\emph{Agent-Environment Misalignment}: the agent's capability frontier changes during training, while the environment that provides supervision remains static or only weakly coupled to the agent's revealed failures. We propose SEAL, a closed-loop co-evolution framework for interactive tool-use agents. SEAL collects on-policy trajectories under executable verification, diagnoses failed rollouts into turn-level failure labels, and uses these diagnoses as a shared signal for both environment-side adaptation and model-side policy optimization. The environment evolves its training-time learning interface by exposing clearer tool affordance cues, constraint information, and recovery-oriented feedback, while the policy is updated with diagnosis-guided advantage reweighting. Extensive experiments across in-distribution and out-of-distribution multi-turn tool-use evaluations show that SEAL improves low-resource agent learning: with only 400 training samples, it yields +8.25 to +26.25 average-point gains across three backbones and exhibits positive out-of-distribution transfer. These results demonstrate the value of jointly adapting the learner and its training-time learning substrate for robust self-improving LLM agents.","published":"2026-05-23T06:41:31Z","updated":"2026-05-23T06:41:31Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.24426v1","pdf_url":"https://arxiv.org/pdf/2605.24426v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:tFam4451mK","versioned_id":"tFam4451mK","title":"uTECH-GenUrban: A Generative Agent-Based Framework for Urban Planning and Mobility Analytics","authors":[],"abstract":"Urban mobility systems exhibit complex, emergent behavior that is difficult to capture with traditional top-down demand models, which often rely on simplified behavioral assumptions and limited adaptability. We present uTECH-GenUrban, a hybrid generative-predictive framework that integrates large language model (LLM) reasoning with heterogeneous urban data to synthesize demographic cohorts, hourly activity schedules, and origin--destination (OD) flows. The framework consists of three sequential stages: PopulationAgent, which constructs interpretable demographic cohorts from American Community Survey (ACS) distributions; ActivityAgent, which generates hourly participation profiles across five broad activity domains derived from the American Time Use Survey (ATUS), namely sleep, work, meal, errand, and leisure; and PlannerAgent, which converts validated activity schedules into mobility-force signals and OD flow estimates using TomTom mobility records, Overture Maps building data, and a downstream Gradient Boosting Regressor. To improve reliability, each stage is wrapped in a hybrid verification pipeline combining deterministic checks, a self-correction step, and structured multi-agent debate. We evaluate uTECH-GenUrban across four heterogeneous U.S. urban testbeds—Las Vegas, Minneapolis, New York City, and San Francisco. The generated cohorts exhibit coherent and socially interpretable demographic differentiation. Aggregated evaluation against observed activity distributions demonstrates the strong capability of the mobility synthesis approach in reproducing real-world patterns. uTECH-GenUrban generalizes well to unseen temporal windows, with an $R^2$ ranging from 0.80 to 0.98 across four cities. These results suggest that LLM-driven, verification-aware urban simulation offers a promising pathway toward digital twins for planning and urban analysis.","published":"2026-05-23T02:38:40+00:00","updated":"2026-06-13T06:42:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=tFam4451mK","openreview_url":"https://openreview.net/forum?id=tFam4451mK","pdf_url":"https://openreview.net/pdf?id=tFam4451mK","comment":"Under review for TMLR","journal_ref":"Under review for TMLR","doi":"","venue":"Under review for TMLR","venue_id":"TMLR/Under_Review","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:lkL0qnUv3p","versioned_id":"lkL0qnUv3p","title":"VeriBench: An End-to-End Formal Verification Benchmark for AI Coding Agents in Lean 4","authors":["Brando Miranda","Srivatsava Daruru","Ethan S Hersch","Zhanke Zhou","Allen Nie","Daneshvar Amrollahi","Leni Aniva","Iddah Mlauzi","Kirill Acharya","Elyas Obbad","Dilara Soylu","Weston Kirk","Zixiao Jolene Wang","Kai Fronsdal","Ying Li","Donald Poindexter Jr","Rakshit Kaushik","Shurui Liu","Yegor Denisov-Blanch","Steven Dillmann","Simon Obstbaum","Santiago Cuellar","John Sarracino","Rylan Schaeffer","Mo Tiwari","Donghyun Lee","Bo Han","Sanmi Koyejo"],"abstract":"Test-based coding benchmarks have repeatedly required strengthening passes (HumanEval, HumanEval+, SWE-Bench, SWE-Bench Verified,SWE-Bench+), each release exposing test-invisible bugs in code that passed the prior suite. This reflects a structural limit of finite testing: passing tests routinely leave behaviorally important bugs unobserved. Existing formal-verification benchmarks (e.g., VERINA, FVAPPS, CLEVER, DafnyBench) provide stronger machine-checkable signals, but many focus on proof completion, scaffolded verified generation, or isolated formal subtasks rather than the full path from developer-written source code to a verified formal artifact. We argue that trustworthy code-verification benchmarks must be end-to-end and agentic, scoring full Python-to-Lean autoformalization under verifier feedback, and must aggregate verification stages conjunctively so that weakness at any stage penalizes the composite while preserving smooth evaluation signal across models still far from the frontier. We introduce VeriBench, an 896-task end-to-end Python-to-Lean4 autoformalization benchmark with a 614-task canonical core (HumanEval-style programs, classical algorithms, Python standard-library functions, and security examples) and a 282-task high-assurance-inspired set across 14 domains including cryptography, aerospace, medical devices, and compilers. We score agents with the Smooth Conjunctive Score for Code verification (SCSC), a log-domain geometric mean over five per-task factors, $\\mathrm{SCSC} = \\exp\\!\\bigl(\\tfrac{1}{5}\\sum_i \\log f_i\\bigr)$, combining (i) the agent's Lean file typechecks, (ii) the agent's theorems verify without sorry, (iii) the agent's theorems semantically cover the curated reference theorems (an LLM-judge estimate, not a kernel-checked entailment), and (iv,v) reference-side validity gates ($D_1, D_2$) ensuring the curated reference itself compiles and proves cleanly before being used to score agents. Under an agentic verifier-feedback loop, Codex, Claude Code, and Leanstral-v2 reach SCSC of only $0.42$, $0.36$, and $0.23$; iterative self-correction adds $14.3\\%$ over single-shot baselines, yet judge-estimated theorem-to-reference coverage stalls uniformly at $\\leq 0.11$ across all three agents, a candidate specification gap corroborated by an LLM judge calibrated against five independent human raters (Pearson $r=0.70$, $p<10^{-11}$). VeriBench frames code-verification evaluation as end-to-end conjunctive grounding, surfacing specification synthesis as a candidate bottleneck at least as severe as proof search and offering a measurable target for verifiable AI coding agents.","published":"2026-05-22T22:14:14+00:00","updated":"2026-06-25T07:16:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=lkL0qnUv3p","openreview_url":"https://openreview.net/forum?id=vnXrEM5nNO","pdf_url":"https://openreview.net/pdf?id=lkL0qnUv3p","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ICML 2026 AI4Math Workshop Poster","ICML 2026 Workshop DL4C Poster"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.24197","versioned_id":"2605.24197v2","title":"A Sober Look at Agentic Misalignment in Automated Workflows","authors":["Wenqian Ye","Bo Yuan","Zhichao Xu","Yijun Tian","Yawei Wang","Henry Kautz","Aidong Zhang"],"abstract":"We study a class of emergent misalignment in multi-agent systems (MAS), with a focus on automated workflows, which we refer to agentic misalignment. Although these systems can solve complex tasks, they often fail because agents act according to implicit proxy utilities that do not align with the intended human goals. We formally define these behaviors and analyze them within a Bayesian framework, showing that generic utilities naturally lead to posterior collapse of agents in automated workflows. To address this issue, we propose Agentic Evidence Attribution (AEA), a novel alignment paradigm that improves agent posteriors using context-specific evidence. AEA reasons over agent actions and provides structured evidence to correct misaligned behavior during collaboration. To better understand the role of evidence, we study two instantiations of AEA: self-reflection (internal evidence from the model) and weak-to-strong generalization (external evidence on the agentic trajectory). We show that a small evidence model effectively aligns the MAS by providing orthogonal failure attribution. Our results clarify the sources of agentic misalignment in automated workflows and show that evidence-based alignment can effectively improve agent collaboration and leads to reliable multi-agent systems built on automated workflows.","published":"2026-05-22T20:40:20Z","updated":"2026-06-08T19:55:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.24197v2","pdf_url":"https://arxiv.org/pdf/2605.24197v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"]},{"id":"2605.24069","versioned_id":"2605.24069v1","title":"When the Manual Lies: A Realistic Benchmark to Evaluate MCP Poisoning Attacks for LLM Agents","authors":["Shi Liu","Xuehai Tang","Xikang Yang","Liang Lin","Biyu Zhou","Wenjie Xiao","Wantao Liu"],"abstract":"The rise of tool-using Large Language Model (LLM) agents, standardized by protocols like the Model Context Protocol (MCP), has unlocked unprecedented autonomous execution capabilities for LLM Agents by integrating external open-domain knowledge and tools. However, this interoperability introduces a covert attack surface targeting the agent's cognitive planning layer. This paper systematically investigates Tool Description Poisoning (TDP), a novel semantic attack. In TDP, malicious instructions are not embedded in a tool's executable code, but rather covertly injected into its descriptive metadata, the very \"manual\" an agent relies on for secure planning and decision-making. To rigorously and systematically evaluate this emerging threat, we introduce the MCP-TDP Security Benchmark. This high-fidelity sandbox environment comprises 32 realistic, real-world test cases spanning 6 distinct risk categories. Our evaluation of 8 mainstream LLMs reveals severe vulnerabilities, with leading models like GPT-4o exhibiting a nearly 100% Attack Success Rate (ASR) in six high-risk scenarios. Furthermore, our findings demonstrate that common prompt-guardrail defenses are largely ineffective and can, counterintuitively, even be counterproductive (a phenomenon which we term the \"Firewall Fallacy\"). Crucially, we also propose a defense mechanism: \"Reactive Self-Correction,\" where an agent autonomously detects and reverts its own malicious actions post-execution. This work provides the first specialized security benchmark tailored for TDP, offering essential insights for securing the cognitive and planning layers of advanced agentic systems.","published":"2026-05-22T08:34:48Z","updated":"2026-05-22T08:34:48Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.24069v1","pdf_url":"https://arxiv.org/pdf/2605.24069v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:YV3FY9zDXE","versioned_id":"YV3FY9zDXE","title":"C-Thinker: Latent Protocol Co-evolution for Dual-Agent Reasoning","authors":[],"abstract":"Implicit reasoning and agent self-evolution offer promising research directions for enhancing the complex logic capabilities of Large Language Models. However, existing latent-space reasoning is often constrained by unidirectional communication, and agent self-evolution frequently suffers from delayed updates and restricted interactions due to a lack of real-time state feedback. To address these challenges, we propose C-Thinker, a dual-agent reasoning framework based on Latent Protocol Co-evolution. This framework reconstructs reasoning as a dynamic closed-loop interaction between a frozen Primary Model ($\\mathcal{M}_R$) and an Auxiliary Model ($\\mathcal{M}_T$). Specifically, the $\\mathcal{M}_T$ leverages real-time feedback from the $\\mathcal{M}_R$'s underlying hidden states to generate a Latent Protocol, which is then injected into the $\\mathcal{M}_R$ to guide subsequent reasoning steps. C-Thinker employs a randomly initialized, lightweight $\\mathcal{M}_T$ to minimize pre-trained semantic constraints, while guiding the stable convergence of the Latent Protocol through Semantic Consistency Regularization and Intrinsic Evolution objectives. Experiments demonstrate that C-Thinker achieves SOTA or highly competitive results across multiple reasoning benchmarks. On the Tibetan-CoT dataset constructed from Ti-MMLU, C-Thinker variants show substantial potential in low-resource cross-lingual reasoning, although the full bidirectional variant is affected by noisy low-resource feedback and does not outperform the unidirectional variant in this setting.","published":"2026-05-22T08:14:36+00:00","updated":"2026-07-01T06:39:25+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=YV3FY9zDXE","openreview_url":"https://openreview.net/forum?id=YV3FY9zDXE","pdf_url":"https://openreview.net/pdf?id=YV3FY9zDXE","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.23273","versioned_id":"2605.23273v1","title":"Self-Refining Topology Optimization via an LLM-Based Multi-Agent Framework","authors":["Hyunjee Park","Hayoung Chung"],"abstract":"Topology optimization is a widely used design method that produces optimized material distributions for prescribed objectives and constraints through well-established numerical algorithms. Throughout the workflow, engineers make a series of decisions ranging from setting and adjusting numerical parameters to assessing whether the converged design meets considerations beyond those explicitly included in the optimization problem, such as physical feasibility. These decisions, which draw on domain expertise, interfere with the autonomous design process. To address this difficulty, this study presents TopOptAgents, a multi-agent system for automating not only the design process but also decision-making during the key stages of the topology optimization process. TopOptAgents consists of six LLM-based agents collaborating through iterative self-refinement cycles spanning problem formulation, validation, code generation and execution, and quality assessment of the optimized structure. This process enables error correction and progressive improvement of both the optimization setup and resulting design. The framework is demonstrated on optimization problems selected to cover a range of settings that differ in their literature coverage and numerical characteristics The benefits of iterative self-refinement are found to be particularly pronounced for problem classes where the pretrained language model has limited prior exposure, such as formulations whose literature and open-source implementations are comparatively sparse. In such cases, the proposed framework reliably produces converged designs where a single state-of-the-art LLM struggles, suggesting that self-refinement broadens the range of topology optimization problems that LLM-based automation can reliably address.","published":"2026-05-22T06:27:18Z","updated":"2026-05-22T06:27:18Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.23273v1","pdf_url":"https://arxiv.org/pdf/2605.23273v1","comment":"28 pages, 17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","source":"arXiv","sources":["arXiv"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"]},{"id":"openreview:DhP1n7F7GW","versioned_id":"DhP1n7F7GW","title":"Seeing Beyond the Scene: Enhancing Vision-Language Models with Interactional Reasoning","authors":[],"abstract":"While scene graphs provide structured representations for multimodal reasoning, existing approaches predominantly encode static spatial relationships and lack role-aware interaction modeling, leaving VLMs unable to resolve complex agent-patient dependencies. Moreover, current fine-tuning paradigms fail to exploit the full structural potential of scene graphs and provide no effective self-feedback mechanism for iterative reasoning improvement. We propose ISGR, an interaction-augmented scene graph reasoning framework for vision-language models. ISGR first converts dense spatial graphs into query-conditioned interaction graphs through a Summarize-and-Align procedure guided by Interactional Chain-of-Thought. Secondly, it generates role-grounded instruction data and optimizes the model with a structure-aware reinforcement objective that rewards role consistency, entity disambiguation, and visual grounding while penalizing attention drift. Finally, a filtered self-refinement loop further improves pseudo graph quality without additional human annotation. Experiments on seven interaction-relevant benchmarks covering spatial reasoning, scene understanding, and multi-object reasoning show consistent gains over strong general VLM and scene-graph-enhanced baselines, with larger improvements on interaction-heavy reasoning tasks.","published":"2026-05-21T10:50:11+00:00","updated":"2026-06-29T03:43:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=DhP1n7F7GW","openreview_url":"https://openreview.net/forum?id=DhP1n7F7GW","pdf_url":"https://openreview.net/pdf?id=DhP1n7F7GW","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:4tNhabgq8G","versioned_id":"4tNhabgq8G","title":"TODRef: Agentic policy with self-reflection for task-oriented dialogue systems","authors":[],"abstract":"Task-oriented dialogue (TOD) systems face significant limitations in practical applications. Traditional solutions, whether modular or end-to-end, heavily rely on large-scale annotated data, lack dynamic adaptation to the evolution of dialogue, and are prone to generating cumulative errors due to ineffective error correction mechanisms. These flaws stem from ignoring the reflection of dialogue intentions and the dynamic tracking of dialogue direction, both of which are crucial for achieving task completion success. To address these issues, this paper proposes a TOD method based on a reflection mechanism constructed by modeling intentions as a Markov transition process. Abandoning traditional fixed modules, the method takes a general instruction-following language model as the core. The reflection mechanism quantifies inter-intention transition probabilities via Markov process to trace intention evolution and identify deviation risks, enabling retrospective correction of historical intention misunderstandings. Without relying on annotated data, experiments on MultiWOZ and SGD benchmarks show significant improvements in intention alignment and task success rate, especially enhancing adaptability in complex multi-turn scenarios with frequent intention shifts.","published":"2026-05-21T10:40:16+00:00","updated":"2026-07-13T20:30:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4tNhabgq8G","openreview_url":"https://openreview.net/forum?id=4tNhabgq8G","pdf_url":"https://openreview.net/pdf?id=4tNhabgq8G","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2605.21997","versioned_id":"2605.21997v1","title":"The Log is the Agent: Event-Sourced Reactive Graphs for Auditable, Forkable Agentic Systems","authors":["Yohei Nakajima"],"abstract":"Most agent frameworks are built around the language model: a conversation loop comes first, then tools, then rules, and finally a logging layer bolted on for observability, with state persisted as retrievable \"memory.\" We describe ActiveGraph, a runtime that inverts this arrangement. The append-only event log is the source of truth; the working graph is a deterministic projection of that log; and behaviors--ordinary functions, classes, LLM-backed routines, or logic attached to typed edges--react to changes in the graph and emit new events. No component instructs another; coordination happens entirely through the shared graph. This single design decision yields three properties that retrieval-and-summarization memory systems do not provide: deterministic replay of any run from its log, cheap forking that branches a run at any event without re-executing the shared prefix, and end-to-end lineage from a high-level goal down to the individual model call that produced each artifact. We present the architecture, a determinism contract that makes replay sound, and a worked diligence example whose full causal structure is reconstructable from the log alone. We discuss--without claiming to demonstrate--why this substrate is unusually well suited to self-improving agents, and how it extends the BabyAGI lineage and prior graph-memory research.","published":"2026-05-21T04:55:38Z","updated":"2026-05-21T04:55:38Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.21997v1","pdf_url":"https://arxiv.org/pdf/2605.21997v1","comment":"11 pages, 1 figure. Open-source Apache-2.0 implementation with reproducible quickstart demo, deterministic replay, fork-and-diff, and lineage tracing","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:RDFo3ZSav1","versioned_id":"RDFo3ZSav1","title":"When Not to Imitate: Boundary-Aware Skill Memory for Reliable Tool-Use LLM Agents","authors":[],"abstract":"Extracting skills from past successes is critical for the efficient evolution of Large Language Model (LLM) agents. Prevailing agent self-evolution paradigms typically rely on a core assumption: equipping LLMs with skill memories derived from successful trajectories will monotonically improve their problem-solving capabilities. However, probe analyses reveal that extracting skills solely from successful trajectories traps the model in a **Skill Imitation Trap**. For tasks that resemble past successes but require different tools, retrieving more skills paradoxically increases the model's confidence in wrong tool calls—procedure skills raise the wrong-tool margin by 47% over a memory-free baseline. To overcome this limitation, we propose **Boundary-Aware Skill Memory** (BASM), which augments each skill with explicit boundary fields—applicability conditions, risk cues, avoidance rules, and recovery notes. These fields transform each retrieved skill from an unconditional action template into state-conditioned guidance: the agent applies the skill when its conditions hold, suppresses inapplicable tool calls when they do not, and issues targeted repairs when execution fails. Across three agent benchmarks and four model scales, BASM consistently outperforms success-distilled skill-memory baselines: it improves task success rate by up to 23.8% on AppWorld, accuracy by up to 5.0% on BFCL, and reduces attack success rate by 4.6% on AgentDojo, while simultaneously reducing average AppWorld steps by up to 6.6% relative to the memory-free baseline.","published":"2026-05-21T04:01:11+00:00","updated":"2026-07-03T08:16:53+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=RDFo3ZSav1","openreview_url":"https://openreview.net/forum?id=RDFo3ZSav1","pdf_url":"https://openreview.net/pdf?id=RDFo3ZSav1","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:X9lJT3TxCF","versioned_id":"X9lJT3TxCF","title":"RL-ADA: Co-Evolutionary Adversarial Training for Self-Improving Customer Support Agents Without Human Feedback","authors":["Ram Narayanan Ananthakrishnapuram Sampath","Harshit Rajgarhia","Abhishek Mukherji"],"abstract":"Task-oriented dialogue agents require robust tool routing to handle unpredictable user interactions, but training them to withstand adversarial inputs is bottlenecked by the high cost of human preference annotation. Standard self-play methods are poorly suited for the inherently asymmetric nature of customer-agent dialogues. We present RL-ADA, a framework for asymmetric co-evolutionary adversarial training that replaces human labels with world feedback: consequence-based signals derived directly from interaction outcomes. A Customer Support Agent (DA, 3B parameters) and an Adversarial Customer Agent (CA, 7B parameters) train against each other in an adversarial arena guided by a fixed automated judge, with an isolation gym selectively retraining the weaker agent on prior-failure transcripts. The size asymmetry is intentional: the CA faces the harder generative task of producing contextually misleading natural language to elicit misroutes from a smaller, task-focused DA. Training converges autonomously under a win-rate stopping criterion, with the framework requiring no human annotation at any stage. We observe a non-monotonic win-rate trajectory consistent with genuine co-evolutionary pressure, and the emergence of adversarial Contextual Camouflage: the CA learns to embed intent within dense, realistic customer detail rather than expressing it directly, a strategy that arises purely from reward pressure without explicit specification.","published":"2026-05-21T03:43:14+00:00","updated":"2026-05-23T20:14:10+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=X9lJT3TxCF","openreview_url":"https://openreview.net/forum?id=X9lJT3TxCF","pdf_url":"https://openreview.net/pdf?id=X9lJT3TxCF","comment":"ACM CAIS 2026: RLEval Workshop Oral","journal_ref":"ACM CAIS 2026: RLEval Workshop Oral","doi":"","venue":"ACM CAIS 2026: RLEval Workshop Oral","venue_id":"ACM.org/CAIS/2026/Workshop/RLEval","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:8WbhKzC9wV","versioned_id":"8WbhKzC9wV","title":"Experience-Sensitive Game Learning: A Behavioral Study of Humans and Language Agents","authors":[],"abstract":"Large language model agents are increasingly evaluated through games, but most benchmarks emphasize final outcomes rather than how players learn from repeated interaction. We study experience-sensitive game learning: how gameplay experience changes the decision-making behavior of humans and language agents. We formulate experience-sensitive game learning as a framework for analyzing behavioral change across repeated gameplay, rather than only final score or win rate. We introduce a suite of interactive games with reusable strategic structure, together with cross-game greedy-to-global metrics and game-specific behavioral diagnostics that make experience-driven change observable from action traces. We also collect repeated-game trajectories from human players and evaluate recent self-evolving language agents in the same behavioral metric space. Our results show that human players exhibit interpretable and relatively stable shifts from locally greedy heuristics toward more global strategic decisions. In contrast, current self-evolving agents often show noisy and transient gains, suggesting that existing self-evolution methods remain limited in converting gameplay experience into durable changes in decision-making behavior.","published":"2026-05-21T03:21:16+00:00","updated":"2026-06-21T05:36:53+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=8WbhKzC9wV","openreview_url":"https://openreview.net/forum?id=8WbhKzC9wV","pdf_url":"https://openreview.net/pdf?id=8WbhKzC9wV","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:4oqr2OIXVx","versioned_id":"4oqr2OIXVx","title":"Self-Improving Agent Factories for Paper Review: When Constrained Beats Open-Ended","authors":["Lele Cao"],"abstract":"The default mental model for self-improving agents is increasingly open-ended: let an agent edit itself, edit the procedure that edits itself, and accumulate improvements through exploration. This is scientifically valuable, but often mismatched to production settings where users need predictable, reproducible behavior under privacy, audit, rollback, cost, and service-level constraints. We present Sira, a human-governed self-improving agent-building factory deployed for controlled creation of venue-specific paper-review agents. Sira freezes the factory skills, execution harness, and common utilities during a tuning run, while editing only task-specific artifacts: venue metadata, rubrics, tool use, reasoning policies, prompts, templates, calibration rules, training samples, and evaluation feedback. The created agents are not self-modifying at runtime; they are regenerated, repaired, benchmarked, versioned, and redeployed offline. In a bounded ICLR-style validation-trace study, Sira reached 0.941 ± 0.018 decision-label accuracy within 2-5 scored candidate steps, while a HyperAgents-style mutable-archive adaptation reached 0.865 ± 0.049 within 6-15. This comparison is illustrative rather than causal: Sira intentionally combines a constrained mutability boundary with expert priors such as venue rubrics, calibration templates, and failure-analysis skills, and the metric measures agreement with historical accept/reject labels rather than review quality or untouched test-set generalization. The evidence is limited but operationally meaningful: in this deployed setting, constrained factory regeneration made the improvement process easier to audit, replay, and roll back. We argue that vertical agents with stable rubrics, auditable failures, and privacy-sensitive inputs may often be better built as products of self-improving factories than as free-running self-modifying workers.","published":"2026-05-20T22:46:30+00:00","updated":"2026-07-04T21:49:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4oqr2OIXVx","openreview_url":"https://openreview.net/forum?id=4oqr2OIXVx","pdf_url":"https://openreview.net/pdf?id=4oqr2OIXVx","comment":"KDD 2026 Workshop SciSoc Agents & LLMs Oral","journal_ref":"KDD 2026 Workshop SciSoc Agents & LLMs Oral","doi":"","venue":"KDD 2026 Workshop SciSoc Agents & LLMs Oral","venue_id":"KDD.org/2026/Workshop/SciSoc_Agents_and_LLMs","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:fvmpqAJZlJ","versioned_id":"fvmpqAJZlJ","title":"Chain-of-Interactions: Multi-step Iterative In-Context Learning for Abstractive Task-Oriented Dialogue Summarization of Conversational AI Interactions","authors":["Jason S Lucas","John Chen","Ali Al-Lawati","Mahjabin Nahar","Mahnoosh Mehrabani"],"abstract":"Large Language Models (LLMs) have introduced paradigm-shifting approaches in natu- ral language processing. Yet, their transformative in-context learning (ICL) capabilities remain underutilized, especially in customer service dialogue summarization—a domain plagued by generative hallucinations, detail omission, and inconsistencies. We present Chain-of-Interactions (CoI), a novel single-instance, multi-step framework that orchestrates information extraction, self-correction, and evaluation through sequential interactive generation chains. By strategically leveraging LLMs’ ICL capabilities through precisely engineered prompts, CoI dramatically enhances abstractive task-oriented dialogue summarization (ATODS) quality and usefulness. Our comprehensive evaluation on real-world and benchmark human-agent interaction datasets demonstrates CoI’s effectiveness through rigorous testing across 11 models and 7 prompting approaches, with 9 standard automatic evaluation metrics, 3 LLM-based evaluations, and human studies involving 480 evaluators across 9 quality dimensions. Results reveal CoI’s decisive superiority, outperforming all single- step approaches and achieving 6× better entity preservation, 49% higher quality scores, and 322% improvement in accuracy compared to state-of-the-art multi-step Chain-of-Density (CoD). This research addresses critical gaps in task-oriented dialogue summarization for customer service applications and establishes new standards for harnessing LLMs’ reasoning capabilities in practical, industry-relevant contexts.","published":"2026-05-20T10:33:59+00:00","updated":"2026-05-20T10:33:59+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=fvmpqAJZlJ","openreview_url":"https://openreview.net/forum?id=fvmpqAJZlJ","pdf_url":"https://openreview.net/pdf?id=fvmpqAJZlJ","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.20477","versioned_id":"2605.20477v1","title":"Training Language Agents to Learn from Experience","authors":["Yuval Shalev","Zifeng Ding","Mateja Jamnik"],"abstract":"Language agents can adapt from experience in interactive environments, but current reflection-based methods can only self-correct within a single task instance. Whether such experience can be distilled into reusable lessons that improve performance on future unseen tasks remains unclear. We address this problem by introducing the In-context Training (ICT) task, a framework for evaluating cross-task self-improvement in language agents. In ICT, a reflector model observes trajectories collected by an actor model and generates system prompts intended to improve the actor's performance on future unseen tasks. We then propose an RL-based training pipeline for learning such reflections directly from experience, without human-provided examples. Across ALFWorld and MiniHack, our trained reflectors outperform an untrained baseline on most held-out task families, showing that the ability to learn from experience can itself be learned. In some cases, we observe generalisation beyond the benchmark on which the reflector was trained, to substantially different environments. Finally, we introduce MetaGym, a generic Python library for constructing meta-environments, enabling future research on self-improving language agents.","published":"2026-05-19T20:41:12Z","updated":"2026-05-19T20:41:12Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.20477v1","pdf_url":"https://arxiv.org/pdf/2605.20477v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=oel9Vp1bNA","openreview_venues":["ICML 2026 RLxF Workshop","ICML 2026 AIWILD"]},{"id":"2605.19748","versioned_id":"2605.19748v1","title":"Memory-Augmented Reinforcement Learning Agent for CAD Generation","authors":["Yin Xiaolong","Liu Yu","Shen Jiahang","Lu Xingyu","Ni Jingzhe","Fan Fengxiao","Sang Fan"],"abstract":"Automatic generation of computer-aided design (CAD) models is a core technology for enabling intelligence in advanced manufacturing. Existing generation methods based on large language models (LLMs) often fall short when handling complex CAD models characterized by long operation sequences, diverse operation types, and strong geometric constraints, primarily because reasoning chains break and effective error-correction mechanisms are lacking. To address this problem, this paper proposes a memory-augmented reinforcement learning framework for CAD generation agents. The framework encapsulates the underlying geometric kernel into a structured toolchain callable by the agent and builds a closed-loop mechanism of design intent understanding, global planning, execution, and multi-dimensional verification. It also designs a dual-track memory module consisting of a case library and a skill library, and proposes a dynamic utility retrieval algorithm. By introducing reinforcement learning into retrieval and policy optimization, the agent can effectively avoid retrieval traps in which examples are semantically similar but geometrically infeasible, enabling online self-correction and continual evolution without additional large-scale annotated data. Experiments show that the proposed method significantly improves both the success rate and geometric consistency on complex CAD model generation tasks.","published":"2026-05-19T12:16:31Z","updated":"2026-05-19T12:16:31Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.19748v1","pdf_url":"https://arxiv.org/pdf/2605.19748v1","comment":"26 pages; multilingual submission: English version first, followed by Chinese version","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:HyraPzySSX","versioned_id":"HyraPzySSX","title":"From Frontier to Frugal: Evaluating Self-Evolution Frameworks with Small Language Models","authors":["Shayan Ali Akbar","Jiaming Qu","Chen Ling","Madhu Gopinathan","Erwin Cornejo"],"abstract":"Optimizing Large Language Models (LLMs) for production AI agent deployment demands substantial computational resources and specialized human expertise (e.g., prompt engineering). Self-evolution offers a promising solution by enabling agents to autonomously enhance capabilities through structured feedback, improving performance without expensive manual optimization. However, most existing self-evolving agents rely on costly frontier LLMs, limiting scalability. Can small language models (SLMs) achieve effective self-evolution while remaining cost-efficient? We investigate this by applying two SLMs (Qwen and Claude Haiku) to self-evolution frameworks (Godel Agent and GEPA) on MGSM mathematical reasoning, MMLU knowledge reasoning, and ARC science questions benchmarks. Our experiments demonstrate that SLMs equipped with feedback loops successfully evolve by rewriting code, optimizing parameters, and refining prompt strategies. Remarkably, SLMs achieve accuracy gains up to 15.5% with evolution costs as low as $0.04 per optimization cycle, enabling scalable production deployments. While gains are more modest than frontier LLMs (specifically on certain benchmarks like MGSM), our results demonstrate that self-improving SLMs offer a viable, cost-effective path toward scalable autonomous AI systems.","published":"2026-05-19T04:49:53+00:00","updated":"2026-06-21T07:11:26+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=HyraPzySSX","openreview_url":"https://openreview.net/forum?id=HyraPzySSX","pdf_url":"https://openreview.net/pdf?id=HyraPzySSX","comment":"ACL-SELVA 2026 Poster","journal_ref":"ACL-SELVA 2026 Poster","doi":"","venue":"ACL-SELVA 2026 Poster","venue_id":"aclweb.org/ACL/2026/Workshop/SELVA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2605.19156","versioned_id":"2605.19156v1","title":"How Far Are We From True Auto-Research?","authors":["Zhengxin Zhang","Ning Wang","Sainyam Galhotra","Claire Cardie"],"abstract":"Recent auto-research systems can produce complete papers, but feasibility is not the same as quality, and the field still lacks a systematic study of how good agent-generated papers actually are. We introduce ResearchArena, a minimal scaffold that lets off-the-shelf agents (Claude Code using Opus 4.6, Codex using GPT-5.4, and Kimi Code using K2.5) carry out the full research loop themselves (ideation, experimentation, paper writing, self-refinement) under only lightweight guidance. Across 13 computer science seeds and 3 trials per agent-domain pair, ResearchArena yields 117 agent-generated papers, each evaluated under three complementary lenses: a manuscript-only reviewer (SAR), an artifact-aware peer review (PR) in which agents inspect the workspace alongside the manuscript, and an human conducted meta-review. Under SAR alone the picture is optimistic: Claude Code obtains the highest score, outperforms Analemma's FARS, and matches the weighted-average human ICLR 2025 submission, suggesting that minimally scaffolded agents can produce papers that look competitive on manuscript-only review. Manual inspection, however, reveals this picture is overstated: SAR scores are poorly aligned with its actual acceptance decisions and reward plausible framing without verifying experimental substance. Under artifact-aware PR scores drop sharply, and manual auditing identifies experimental rigor as the major bottleneck, decomposing into three failure modes (fabricated results, underpowered experiments, and plan/execution mismatch) that are highly agent-dependent: Codex 5%/8% paper-vs-artifact mismatch / fabricated references versus Kimi Code 77%/72%, a $\\sim$15$\\times$ spread that tracks distinct research personas the agents develop. None of the 117 agent-generated papers reaches the acceptance bar of a top-tier venue. This suggests that we are still gapped from the true auto-research.","published":"2026-05-18T22:20:33Z","updated":"2026-05-18T22:20:33Z","categories":["cs.AI","cs.CY","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.19156v1","pdf_url":"https://arxiv.org/pdf/2605.19156v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.19077","versioned_id":"2605.19077v1","title":"ReacTOD: Bounded Neuro-Symbolic Agentic NLU for Zero-Shot Dialogue State Tracking","authors":["Yanjun Lin","Zimo Xiao","Kartik Natarajan","Mahesh Sankaranarayanan","Niraj Nawanit","Rakshit Parashar","Austin Zhang","Karthik Konaraddi","Rishita Mote","Wei Niu"],"abstract":"Task-oriented dialogue systems -- handling transactions, reservations, and service requests -- require predictable behavior, yet the moderately-sized LLMs needed for practical latency are prone to hallucination and format errors that cascade into incorrect actions (e.g., a hotel booked for the wrong date). We propose ReacTOD, a bounded neuro-symbolic architecture that reformulates NLU as discrete tool calls within a self-correcting ReAct loop governed by deterministic validation. A bounded ReAct loop enables iterative self-correction, improving accuracy by up to 9.3 percentage points over single-pass inference on MultiWOZ. A symbolic validator enforces action compliance, schema conformance, and coreference consistency on every dialogue state update, achieving a 93.1% self-correction rate on intercepted errors and producing structured execution traces. Incremental state prediction and on-demand history retrieval keep prompts compact, empirically improving instruction adherence in parameter-constrained models. On MultiWOZ 2.1, ReacTOD achieves a new zero-shot state-of-the-art: gpt-oss-20B reaches 52.71% joint goal accuracy, surpassing the previous best by 14 percentage points, while Qwen3-8B achieves 47.34% with only 8B parameters. On the Schema-Guided Dialogue (SGD) benchmark, ReacTOD with Claude-Opus-4.6 achieves 80.68% JGA under fully end-to-end evaluation with predicted domains, and Qwen3-32B reaches 64.09% -- demonstrating cross-benchmark generalization without task-specific training data.","published":"2026-05-18T20:06:04Z","updated":"2026-05-18T20:06:04Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.19077v1","pdf_url":"https://arxiv.org/pdf/2605.19077v1","comment":"Accepted at TrustNLP Workshop at ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.18407","versioned_id":"2605.18407v1","title":"Qumus: Realization of An Embodied AI Quantum Material Experimentalist","authors":["Lihan Shi","Zhaoyi Joy Zheng","Xinzhe Juan","Yimin Wang","Ming Yin","Mayank Sengupta","Kristina Wolinski","Yanyu Jia","Jingzhi Shi","Derek Saucedo","Neill Saggi","Haosen Guan","Kenji Watanabe","Takashi Taniguchi","Ali Yazdani","Mengdi Wang","Sanfeng Wu"],"abstract":"While modern Large Language Models (LLMs) and agentic artificial intelligence (AI) have demonstrated transformative capabilities in digital domains, the realization of embodied AI capable of real-world scientific discovery remains a difficult frontier. The advancements are hindered by the inherent complexity of integrating high-level reasoning, multimodal information processing and real-time physical execution. Here we introduce Qumus, the first AI quantum materials experimentalist. Physically embodied within a robotic mini-laboratory, Qumus is an intelligent, multimodal, and multi-agent system designed for the creation and nano-processing of atomically thin two-dimensional (2D) materials and stacked van der Waals (vdW) structures. Qumus autonomously navigates the full scientific cycle, from hypothesis generation and protocol planning to multi-step experimental execution, result analysis and reporting, acting as an experimentalist. Markedly, the system has achieved, for the first time, the AI-creation of graphene, as well as the first AI-fabrication of complex nanodevices including atomically thin field-effect transistors via vdW stacking. Qumus excels at these tasks by demonstrating autonomous error correction and closed-loop experimentation. Our results establish a generalizable framework for self-improving embodied AI systems that learn directly from the quantum world, opening a pathway toward accelerated discovery in quantum materials, electronics and beyond.","published":"2026-05-18T13:47:31Z","updated":"2026-05-18T13:47:31Z","categories":["cond-mat.mes-hall","cond-mat.mtrl-sci","cs.AI","cs.RO"],"primary_category":"cond-mat.mes-hall","arxiv_url":"https://arxiv.org/abs/2605.18407v1","pdf_url":"https://arxiv.org/pdf/2605.18407v1","comment":"29 Pages in total. Supplementary Demo Videos are available at https://qumus.ai","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.17734","versioned_id":"2605.17734v1","title":"Harnessing LLM Agents with Skill Programs","authors":["Hongjun Liu","Yifei Ming","Shafiq Joty","Chen Zhao"],"abstract":"Equipping LLM agents with reusable skills derived from past experience has become a popular and successful approach for tackling complex and long-horizon tasks. However, such lessons are often encoded as textual guidance that remains largely advisory, lacking explicit mechanisms for when and how to intervene in the agent loop. To bridge the gap, we introduce HASP(Harnessing LLM Agents with Skill Programs), a new framework that upgrades skills into executable Program Functions (PFs). Rather than offering passive advice, PFs act as executable guardrails that activate on failure-prone states and modify the next action or inject corrective context. HASP is highly modular: it can be applied at inference time for direct agent-loop intervention, during post-training to provide structured supervision, or for self-improvement by evolving validated, teacher-reviewed PFs. Empirically, HASP drives substantial gains compared to both training-free and training-based methods on web-search, math reasoning, and coding tasks. For example, on web-search reasoning, inference-time PFs alone improve the average performance by 25% compared to (multi-loop) ReAct Agent, while post-training and controlled evolution achieve a 30.4% gain over Search-R1. To provide deeper insights into HASP, our mechanism analysis reveals how PFs trigger and intervene, how skills are internalized, and the requirement for stable skill library evolution.","published":"2026-05-18T01:35:11Z","updated":"2026-05-18T01:35:11Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.17734v1","pdf_url":"https://arxiv.org/pdf/2605.17734v1","comment":"40 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=62PnsNR8s2","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2605.17448","versioned_id":"2605.17448v2","title":"Self-Improving CAD Generation Agents with Finite Element Analysis as Feedback","authors":["Guijin Son","Jehyun Park","Seyeon Park","Sunghee Ahn","Youngjae Yu"],"abstract":"Computer-aided design (CAD) is the backbone of modern industrial design, yet learned CAD generators still fall short of real engineering pipelines: they neither iterate like engineers nor evaluate what engineering requires. Prior work has treated CAD generation as two disjoint steps, part synthesis and assembly, where the former is graded by proximity to a gold reference and the latter, when handled at all, is reduced to a separate constraint solving step. In this work, we introduce a more industry-native task formulation that requires a model to produce a fully assembled multi-part STEP file from a free-form engineering brief, which is then validated via finite element analysis (FEA). FEA validation reveals that Codex (GPT-5.5) and Claude Code (Opus-4.7) agents do not produce a single strict-passing artifact in the main first-attempt sweep, with the best configuration meeting only about 20% of typed requirements on average. Moreover, we introduce two additional supervision signals, a novel text-only blueprint schema and a 21-view image renderer that aids the agent's visual inspection, that better align the generation loop with how engineers iterate in practice. On S2O and Fusion360, the same feedback tools improve geometric reconstruction, with GPT-5.5/xhigh rising from 0.444 to 0.592 Box-IoU on S2O and from 0.397 to 0.505 on Fusion360. Together these signals move CAD programs toward artifacts that are not only visually plausible but also checked against physical and structural requirements.","published":"2026-05-17T13:47:38Z","updated":"2026-05-27T01:18:25Z","categories":["cs.GR","cs.CL"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2605.17448v2","pdf_url":"https://arxiv.org/pdf/2605.17448v2","comment":"Work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:3cz2HeSTbE","versioned_id":"3cz2HeSTbE","title":"SIDiffAgent: Training-Free Text-to-Image Generation via Self-Improving Agentic Refinement","authors":[],"abstract":"Text-to-image diffusion models have become a cornerstone of generative AI, producing photorealistic imagery at a quality that is reshaping creative, commercial, and design workflows. Yet their reliability in production settings is undercut by a persistent gap between what a user asks for and what the model renders: outputs are highly sensitive to prompt phrasing, semantically ambiguous terms are resolved inconsistently (for instance, ``mouse\" as an animal versus a computer peripheral), anatomical and structural artifacts are common, and dependable results often demand carefully engineered prompts. Prior approaches typically mitigate these issues through additional training or offer only coarse control, which limits their adaptability and raises the cost of deployment. We introduce the Self-Improving Diffusion Agent (SIDiffAgent), a training-free agentic framework built on the Qwen family of models (Qwen-VL, Qwen-Image, Qwen-Edit, and Qwen-Embedding). SIDiffAgent autonomously handles prompt engineering, detects and corrects low-quality generations, and performs fine-grained artifact removal to yield more consistent and faithful outputs. It further improves over time through an experience memory that stores past generation trajectories in a database and injects retrieval-conditioned guidance into every stage of the pipeline. On GenAI-Bench, SIDiffAgent attains an average VQA score of 0.884, substantially outperforming leading open-source models, proprietary systems, and prior agentic methods. We will release our code publicly upon acceptance.","published":"2026-05-16T13:48:10+00:00","updated":"2026-06-28T13:07:35+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=3cz2HeSTbE","openreview_url":"https://openreview.net/forum?id=3cz2HeSTbE","pdf_url":"https://openreview.net/pdf?id=3cz2HeSTbE","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2605.16883","versioned_id":"2605.16883v1","title":"SE-GA: Memory-Augmented Self-Evolution for GUI Agents","authors":["Shilong Jin","Lanjun Wang","Zhuosheng Zhang"],"abstract":"Autonomous Graphical User Interface (GUI) agents often struggle with multi-step tasks due to constrained context windows and static policies that fail to adapt to dynamic environments. To address these limitations, this work proposes the Self-Evolving GUI Agent (SE-GA), a novel framework that integrates hierarchical memory structures with an iterative self-improvement mechanism. At the core of our approach is Test-Time Memory Extension (TTME), which facilitates long-term planning by dynamically retrieving episodic, semantic, and experiential memories to provide salient contexts during inference. To ensure continuous learning, we introduce Memory-Augmented Self-Evolution (MASE), which is a training pipeline that adopts the data collected by TTME to stabilize and enhance the agent's foundational policy. Extensive evaluations across both offline and online benchmarks demonstrate SE-GA achieves state-of-the-art performance, reaching success rates of 89.0\\% on ScreenSpot and 75.8\\% on the challenging AndroidControl-High dataset. Furthermore, significant improvements on the AndroidWorld benchmark highlight the superior generalization to dynamic environments. Open source code: https://github.com/jinshilong-dev/SE-GA","published":"2026-05-16T08:51:57Z","updated":"2026-05-16T08:51:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.16883v1","pdf_url":"https://arxiv.org/pdf/2605.16883v1","comment":"Accepted by ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=9S9V5ntQJM","openreview_venues":["ICML 2026 regular"]},{"id":"openreview:6oyBiDMCHs","versioned_id":"6oyBiDMCHs","title":"MERA: Model Evolution and Routing with Skill Adaptation for Agentic Systems at Scale","authors":["Yuhang Yao","ZEYU WANG","Tongyun Yang","Wanyi Chen","Yuhang Han","Jie Xiao","Chengke Bao","TIANYU SHI"],"abstract":"Language-model agents increasingly mix strong but expensive frontier models with cheaper models that are useful only on safe subsets of a workflow. The challenge is not only to choose a model once per user request, but to adapt many individual invocations inside a multi-step trace without silently degrading quality. We present MERA, a trace-driven framework that jointly evolves three tracks: SkillBook statistics for recurring prompt signatures, a learned invocation-level router, and a small-model adapter. The main empirical finding is that the joint schedule matters: in a code-generation setting with 590 executable code tasks and 3,328 weakly labelled router examples, the best four-cycle order is Skill $\\rightarrow$ LLM $\\rightarrow$ Router. This setting reaches 87.3\\% router accuracy with 4.4\\% fallback and reduces estimated serving cost to 51.8\\% of always using the large model. An eight-cycle run peaks at 87.8\\% router accuracy and then stabilizes in the 82--87\\% band. Component behavior is uneven but informative: SkillBook and router updates provide the largest cost-quality gains, while the 1.5B GRPO adapter gives a modest pass-rate improvement, reaching 47.5\\% on MBPP eval200 versus roughly 47.0\\% for the base setting, but does not yet show cumulative gains across cycles. MERA therefore frames agent self-evolution as a conservative systems loop over shared traces, where skill, model, and routing updates are admitted together through replay.","published":"2026-05-16T07:11:09+00:00","updated":"2026-05-23T20:14:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=6oyBiDMCHs","openreview_url":"https://openreview.net/forum?id=6oyBiDMCHs","pdf_url":"https://openreview.net/pdf?id=6oyBiDMCHs","comment":"ACM CAIS 2026: RLEval Workshop Poster","journal_ref":"ACM CAIS 2026: RLEval Workshop Poster","doi":"","venue":"ACM CAIS 2026: RLEval Workshop Poster","venue_id":"ACM.org/CAIS/2026/Workshop/RLEval","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.16205","versioned_id":"2605.16205v1","title":"Context, Reasoning, and Hierarchy: A Cost-Performance Study of Compound LLM Agent Design in an Adversarial POMDP","authors":["Igor Bogdanov","Chung-Horng Lung","Thomas Kunz","Jie Gao","Adrian Taylor","Marzia Zaman"],"abstract":"Deploying compound LLM agents in adversarial, partially observable sequential environments requires navigating several design dimensions: (1) what the agent sees, (2) how it reasons, and (3) how tasks are decomposed across components. Yet practitioners lack guidance on which design choices improve performance versus merely increase inference costs. We present a controlled study of compound LLM agent design in CybORG CAGE-2, a cyber defense environment modeled as a Partially Observable Markov Decision Process (POMDP). Reward is non-positive, so all configurations operate in a failure-mitigation mode. Our evaluation spans five model families, six models, and twelve configurations (3,475 episodes) with token-level cost accounting. We vary context representation (raw observations vs. a deterministic state-tracking layer with compressed history), deliberation (self-questioning, self-critique, and self-improvement tools, with optional chain-of-thought prompting), and hierarchical decomposition (monolithic ReAct vs. delegation to specialized sub-agents). We find that: (1) Programmatic state abstraction delivers the largest returns per token spent (RPTS), improving mean return by up to 76% over raw observations. (2) Distributing deliberation tools across a hierarchy degrades performance relative to hierarchy alone for all five model families, reaching up to 3.4$\\times$ worse mean return while using 1.8-2.7$\\times$ more tokens. We call this destructive pattern a deliberation cascade. (3) Hierarchical decomposition without deliberation achieves the best absolute performance for most models, and context engineering is generally more cost-effective than deliberation. These findings suggest a design principle for structured adversarial POMDPs: invest in programmatic infrastructure and clean task decomposition rather than deeper per-agent reasoning, as these strategies can interfere when combined.","published":"2026-05-15T17:23:08Z","updated":"2026-05-15T17:23:08Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA","eess.SY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.16205v1","pdf_url":"https://arxiv.org/pdf/2605.16205v1","comment":"","journal_ref":"","doi":"10.1145/3786335.3813149","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.15871","versioned_id":"2605.15871v1","title":"Agentic Discovery of Neural Architectures: AIRA-Compose and AIRA-Design","authors":["Alberto Pepe","Chien-Yu Lin","Despoina Magka","Bilge Acun","Yannan Nellie Wu","Anton Protopopov","Carole-Jean Wu","Yoram Bachrach"],"abstract":"Toward recursive self-improvement, we investigate LLM agents autonomously designing foundation models beyond standard Transformers. We introduce a dual-framework approach: AIRA-Compose for high-level architecture search, and AIRA-Design for low-level mechanistic implementation. AIRA-Compose uses 11 agents to explore fundamental computational primitives under a 24-hour budget. Agents evaluate million-parameter candidates, extrapolating top designs to 350M, 1B, and 3B scales. This yields 14 architectures across two families: AIRAformers (Transformer-based) and AIRAhybrids (Transformer-Mamba). Pre-trained at 1B scale, these consistently outperform Llama 3.2 and Composer-found baselines. On downstream tasks, AIRAformer-D and AIRAhybrid-D improve accuracy by 2.4% and 3.8% over Llama 3.2. Furthermore, AIRA-Compose finds models with highly efficient scaling frontiers: AIRAformer-C scales 54% and 71% faster than Llama 3.2 and Composer's best Transformer, while AIRAhybrid-C outscales Nemotron-2 by 23% and Composer's best hybrid by 37%. AIRA-Design tasks 20 agents with writing novel attention mechanisms for long-range dependencies and high-performing training scripts. On the Long Range Arena benchmark, agent-designed architectures reach within 2.3% and 2.6% of human state-of-the-art on document matching and text classification. On the Autoresearch benchmark, Greedy Opus 4.5 achieves 0.968 validation bits-per-byte under a fixed time budget, surpassing the published minimum. Together, these frameworks show AI agents can autonomously discover architectures and algorithmic optimizations matching or surpassing hand-designed baselines. This establishes a powerful paradigm for discovering next-generation foundation models, marking a clear step toward recursive self-improvement.","published":"2026-05-15T11:40:41Z","updated":"2026-05-15T11:40:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.15871v1","pdf_url":"https://arxiv.org/pdf/2605.15871v1","comment":"55 pages, 28 figures, 21 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:eF3GfE6lcI","versioned_id":"eF3GfE6lcI","title":"Adaptive Critic-Guided Hybrid Agentic RAG for Improving Retrieval Robustness and Hallucination Resistance Through Multi-Stage Verification","authors":["MOHITH CHANDRA GUGULOTHU","Shreya Yadav","Rishu Kumar","Rajiv Misra"],"abstract":"Retrieval-Augmented Generation (RAG) systems en- hance the factual grounding capability of large language models (LLMs) by incorporating external knowledge during response generation. However, conventional RAG pipelines remain highly vulnerable to hallucinations, retrieval insta- bility, and unreliable reasoning when handling ambiguous, unsupported, or out-of-domain queries. This paper presents an adaptive critic-guided hybrid agentic RAG framework de- signed to improve hallucination resistance, retrieval robustness, and self-correction capability in locally deployed LLM systems. The proposed architecture integrates dense vector retrieval, BM25 lexical retrieval, adaptive retrieval policies, sentence- level atomic claim verification, semantic failure memory, and web fallback mechanisms within a multi-agent Lang- Graph orchestration pipeline. Furthermore, the framework dynami- cally adjusts retrieval depth according to query com- plexity and employs critic-guided verification prior to final answer generation to improve factual reliability and safer response behavior. Experimental evaluation demonstrates that the pro- posed framework completely eliminated hallucinated responses on stress-test benchmark queries, reducing the hallucination rate from 0.34 in the baseline RAG pipeline to 0.00 by refusing unsupported generations instead of producing con- fident fabricated answers. The framework additionally im- proved answer relevance from 0.71 to 0.74 and achieved a retry effectiveness gain of +0.047 through adaptive retrieval refinement. Although the proposed architecture introduced approximately 3.2× higher inference latency due to sequen- tial multi-agent verification and claim-level evidence checking (35.92s → 116.14s), the results demonstrate that atomic claim verification and critic-guided reasoning substantially improve reliability, hallucination resistance, and safe handling of unsup- ported queries. Overall, the findings highlight the effectiveness of combining adaptive retrieval, multi-stage verification, and semantic memory for developing more trustworthy and robust agentic RAG systems.","published":"2026-05-15T07:12:04+00:00","updated":"2026-05-16T00:29:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=eF3GfE6lcI","openreview_url":"https://openreview.net/forum?id=eF3GfE6lcI","pdf_url":"https://openreview.net/pdf?id=eF3GfE6lcI","comment":"NortheastGenAI 2026 Workshop Submission","journal_ref":"NortheastGenAI 2026 Workshop Submission","doi":"","venue":"NortheastGenAI 2026 Workshop Submission","venue_id":"NortheastGenAI/2026/Workshop/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:RFpZOuhIk3","versioned_id":"RFpZOuhIk3","title":"JAXBench: Benchmarking Autonomous TPU Kernel Optimization","authors":["Arya Tschand","Charles Hong","Julian Walker","Shengnan Cai","Shangkun Wang","Suvinay Subramanian","Sundar Dev","Vijay Janapa Reddi","Amir Yazdanbakhsh","Sethuraman Sankaran"],"abstract":"Rigorous benchmarks have driven progress in autonomous GPU kernel performance optimization by setting a shared target to hillclimb on, but no equivalent exists for TPUs. We present JAXBench, a TPU-native benchmark for AI-generated kernel optimization on Google Cloud TPUs. JAXBench comprises 50 JAX workloads that are both relevant and provide headroom for optimization. We extract 17 production LLM operators from architectures in the public MaxTech library such as Llama-3.1, DeepSeek-V3, Mixtral, Mamba-2, and AlphaFold2, and translate 33 fused operator sequences from KernelBench. Eight of the 17 production operators ship with hand-optimized Pallas TPU kernels from the public Tokamax library and block-size tuned for the target TPU. We evaluate one-shot generation, iterative coding agents, an iterative loop with TPU documentation injected, and a TPU-enabled Autocomp configuration augmented with the TPU-specific documentation. With Gemini 3 Flash, best-of-$N$ solves 13/50 at $1.01\\times$ geomean and iterative refinement reaches 32/50 at $1.18\\times$. Injecting TPU documentation lifts iterative refinement to 48/50 at $1.28\\times$ and per-sample correctness from $5.8\\%$ to $37.3\\%$. Autocomp solves 45/50 and converts those correct kernels into $1.36\\times$ geomean with $76\\%$ beating XLA. High-quality TPU kernel optimization remains a challenging task, and we release the JAXBench benchmark, evaluation harness, curated documentation, and baseline results to support open source contributions.","published":"2026-05-14T20:11:54+00:00","updated":"2026-06-24T19:56:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=RFpZOuhIk3","openreview_url":"https://openreview.net/forum?id=4vznznrGnT","pdf_url":"https://openreview.net/pdf?id=RFpZOuhIk3","comment":"ICML 2026 Workshop DL4C Poster","journal_ref":"ICML 2026 Workshop DL4C Poster","doi":"","venue":"ICML 2026 Workshop DL4C Poster","venue_id":"ICML.cc/2026/Workshop/DL4C","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ICML 2026 Workshop DL4C Poster","ICML 2026 Workshop AI4Research Poster"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:S7EKs75FYV","versioned_id":"S7EKs75FYV","title":"EvoCurr: Self-evolving Curriculum with Behavior Code Generation for Complex Decision-making","authors":[],"abstract":"Complex decision-making often requires agents to progress through intermediate tasks rather than solve the final target directly. Existing LLM self-refinement methods typically iterate on a fixed target, while curriculum-learning methods often rely on hand-designed schedules, training-time optimization, or domain-specific difficulty metrics. To smooth out the learning curve with adaptive curriculum desgin, we introduce EvoCurr, a general inference-time framework that co-evolves curricula and executable policies. A Designer proposes verifiable intermediate tasks from the latest accepted progress and recent failures, while a Solver generates or trains policies for these tasks. A task-policy pair is accepted only when it passes hard feasibility checks and reaches a specified performance threshold meanwhile an accepted-floor constraint preserves the latest verified checkpoint and prevents failed harder attempts from overwriting mastered behavior. We evaluate EvoCurr across code-as-policy and closed-loop MARL settings on StarCraft II super-late-game micromanagement, hardest stress test, where EvoCurr achieves 96.7--99.2\\% macro-average win rates across three LLM backbones without LLM parameter training. The performance improvments on other experiments, Flatland, POGEMA, Overcooked, and LiveCodeBench Hard, reflect the generality of our EvoCurr.","published":"2026-05-14T16:05:34+00:00","updated":"2026-07-01T00:19:15+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=S7EKs75FYV","openreview_url":"https://openreview.net/forum?id=S7EKs75FYV","pdf_url":"https://openreview.net/pdf?id=S7EKs75FYV","comment":"ACL ARR 2026 May Submission","journal_ref":"ACL ARR 2026 May Submission","doi":"","venue":"ACL ARR 2026 May Submission","venue_id":"aclweb.org/ACL/ARR/2026/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.14892","versioned_id":"2605.14892v2","title":"Beyond Individual Intelligence: Surveying Collaboration, Failure Attribution, and Self-Evolution in LLM-based Multi-Agent Systems","authors":["Shihao Qi","Jie Ma","Rui Xing","Wei Guo","Xiao Huang","Zhitao Gao","Jianhao Deng","Jun Liu","Lingling Zhang","Bifan Wei","Boqian Yang","Pinghui Wang","Jianwen Sun","Jing Tao","Yaqiang Wu","Hui Liu","Yu Yao","Tongliang Liu"],"abstract":"LLM-based autonomous agents have demonstrated strong capabilities in reasoning, planning, and tool use, yet remain limited when tasks require sustained coordination across roles, tools, and environments. Multi-agent systems address this through structured collaboration among specialized agents, but tighter coordination also amplifies a less explored risk: errors can propagate across agents and interaction rounds, producing failures that are difficult to diagnose and rarely translate into structural self-improvement. Existing surveys cover individual agent capabilities, multi-agent collaboration, or agent self-evolution separately, leaving the causal dependencies among them unexamined. This survey provides a unified review organized around four causally linked stages, which we term the LIFE progression: Lay the capability foundation, Integrate agents through collaboration, Find faults through attribution, and Evolve through autonomous self-improvement. For each stage, we provide systematic taxonomies and formally characterize the dependencies between adjacent stages, revealing how each stage both depends on and constrains the next. Beyond synthesizing existing work, we identify open challenges at stage boundaries and propose a cross-stage research agenda for closed-loop multi-agent systems capable of continuously diagnosing failures, reorganizing structures, and refining agent behaviors, extending current coordination frameworks toward more self-organizing forms of collective intelligence. By bridging these previously fragmented research threads, this survey aims to offer both a systematic reference and a conceptual roadmap toward autonomous, self-improving multi-agent intelligence.","published":"2026-05-14T14:36:13Z","updated":"2026-05-15T09:12:41Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14892v2","pdf_url":"https://arxiv.org/pdf/2605.14892v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.14211","versioned_id":"2605.14211v3","title":"ASH: Agents that Self-Hone via Embodied Learning","authors":["Benjamin Schneider","Xavier Schneider","Victor Zhong","Sun Sun"],"abstract":"Long-horizon embodied tasks remain a fundamental challenge in AI, as current methods rely on hand-engineered rewards or action-labeled demonstrations, neither of which scales. We introduce ASH, an agentic system that learns an embodied policy from unlabeled, noisy internet video, without reward shaping or expert annotation. ASH follows a self-improvement loop; when it gets stuck, ASH learns an Inverse Dynamics Model (IDM) from its own trajectories, and uses its IDM to extract supervision from relevant internet video. ASH uses unsupervised learning to identify key moments from large-scale internet video and retains them as long-term memory -- allowing it to tackle long-horizon problems. We evaluate ASH on two complementary environments demanding multi-hour planning: Pokemon Emerald, a turn-based RPG, and The Legend of Zelda: The Minish Cap, a real-time action-adventure game. In both games, behavioral cloning, retrieval-augmented and zero-shot foundation-model baselines plateau, while ASH sustains progression across our 8-hour evaluation. ASH reaches an average of $11.2/12$ milestones in Pokemon Emerald and $9.9/12$ in Legend of Zelda, while the strongest baseline gets stuck in both environments at an average of $6.5/12$ and $6.0/12$ milestones, respectively. We demonstrate that self-improving agents are a scalable recipe for long-horizon embodied learning.","published":"2026-05-14T00:10:12Z","updated":"2026-06-05T16:41:58Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.14211v3","pdf_url":"https://arxiv.org/pdf/2605.14211v3","comment":"Published as a workshop paper at ICML 2026 Workshop on Scalable Learning and Optimization for Efficient Multimodal AI Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=OR2EFiBnbA","openreview_venues":["SCALE@ICML2026 Poster"]},{"id":"2605.13486","versioned_id":"2605.13486v1","title":"R^2-Mem: Reflective Experience for Memory Search","authors":["Xinyuan Wang","Wenyu Mao","Junkang Wu","Xiang Wang","Xiangnan He"],"abstract":"Deep search has recently emerged as a promising paradigm for enabling agents to retrieve fine-grained historical information without heavy memory pre-managed. However, existing deep search agents for memory system repeat past error behaviors because they fail to learn from the prior high- and low-quality search trajectories. To address this limitation, we propose R^2-Mem, a reflective experience framework for memory search systems. In the offline stage, a Rubric-guided Evaluator scores low- and high-quality steps in historical trajectories, and a self-Reflection Learner distills the corresponding abstract experience. During the online inference, the retrieved experience will guide future search actions to avoid repeated mistakes and maintain high-quality behaviors. Extensive experiments demonstrate that R^2-Mem consistently improves both effectiveness and efficiency over strong baselines, improving F1 scores by up to 22.6%, while reducing token consumption by 12.9% and search iterations by 20.2%. These results verify that R^2-Mem provides a RL-free and low-cost solution for self-improving LLM agents.","published":"2026-05-13T13:09:36Z","updated":"2026-05-13T13:09:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13486v1","pdf_url":"https://arxiv.org/pdf/2605.13486v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.15224","versioned_id":"2605.15224v1","title":"ICRL: Learning to Internalize Self-Critique with Reinforcement Learning","authors":["Jianbo Lin","Xiaomin Yu","Yi Xin","Yifu Guo","Zhuosong Jiang","Zhongqi Yue","Weishi Wang","Heqing Zou","Chengwei Qin","Hui Xiong"],"abstract":"Large language model-based agents make mistakes, yet critique can often guide the same model toward correct behavior. However, when critique is removed, the model may fail again on the same query, indicating that it has not internalized the critique's guidance into its underlying capability. Meanwhile, a frozen critic cannot improve its feedback quality over time, limiting the potential for iterative self-improvement. To address this, we propose learning to internalize self-critique with reinforcement learning(ICRL), a novel framework that jointly trains a solver and a critic from a shared backbone to convert critique-induced success into unassisted solver ability. The critic is rewarded based on the solver's subsequent performance gain, incentivizing actionable feedback. To address the distribution shift between critique-conditioned and critique-free behavior, ICRL introduces a distribution-calibration re-weighting ratio that selectively transfers critique-guided improvements compatible with the solver's own prompt distribution. Additionally, a role-wise group advantage estimation stabilizes joint optimization across the two roles. Together, these mechanisms ensure that the solver learns to improve itself without external critique, rather than becoming dependent on critique-conditioned behavior. We evaluate ICRL on diverse benchmarks spanning agentic and mathematical reasoning tasks, using Qwen3-4B and Qwen3-8B as backbones. Results show consistent improvements, with average gains of 6.4 points over GRPO on agentic tasks, and 7.0 points on mathematical reasoning. Notably, the learned 8B critic is comparable to 32B critics while using substantially fewer tokens. The code is available at https://github.com/brick-pid/ICRL.","published":"2026-05-13T08:50:05Z","updated":"2026-05-13T08:50:05Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.15224v1","pdf_url":"https://arxiv.org/pdf/2605.15224v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.13167","versioned_id":"2605.13167v1","title":"GeoBuildBench: A Benchmark for Interactive and Executable Geometry Construction from Natural Language","authors":["Jinwoong Kim","Rui Yang","Huishuai Zhang"],"abstract":"We introduce GeoBuildBench, a benchmark designed to evaluate whether large language models and multimodal agents can ground informal natural-language plane geometry problems into executable geometric constructions. Unlike existing geometry benchmarks that focus on answer correctness or static diagram interpretation, GeoBuildBench treats geometry diagram as an interactive construction task: given a textual problem, an agent must generate a domain-specific language (DSL) program to produce a diagram satisfying explicitly specified geometric objects and verifiable constraints. The benchmark features 489 Chinese textbook-style problems, curated through automated filtering and human validation to ensure text-complete, constructible problem specifications. We evaluate several state-of-the-art multimodal models in a bounded iterative setting and show that, despite reasonable success rates, models frequently exhibit structural hallucinations, missing objects, and failures to satisfy geometric constraints, with limited ability to exploit visual and constraint-based feedback for self-correction. These results highlight geometry construction as a rigorous testbed for grounded, executable reasoning beyond textual or visual plausibility. Our benchmark and code are publicly available.","published":"2026-05-13T08:30:12Z","updated":"2026-05-13T08:30:12Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.13167v1","pdf_url":"https://arxiv.org/pdf/2605.13167v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=e954id7ahS","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"2605.12978","versioned_id":"2605.12978v1","title":"Useful Memories Become Faulty When Continuously Updated by LLMs","authors":["Dylan Zhang","Yanshan Lin","Zhengkun Wu","Yihang Sun","Bingxuan Li","Dianqi Li","Hao Peng"],"abstract":"Learning from past experience benefits from two complementary forms of memory: episodic traces -- raw trajectories of what happened -- and consolidated abstractions distilled across many episodes into reusable, schema-like lessons. Recent agentic-memory systems pursue the consolidated form: an LLM rewrites past trajectories into a textual memory bank that it continuously updates with new interactions, promising self-improving agents without parameter updates. Yet we find that such consolidated memories produced by today's LLMs are often faulty even when derived from useful experiences. As consolidation proceeds, memory utility first rises, then degrades, and can fall below the no-memory baseline. More surprisingly, even when consolidating from ground-truth solutions, GPT-5.4 fails on 54% of a set of ARC-AGI problems it had previously solved without memory. We trace the regression to the consolidation step rather than the underlying experience: the same trajectories yield qualitatively different memories under different update schedules, and an episodic-only control that simply retains those trajectories remains competitive with the consolidators we test. In a controlled ARC-AGI Stream environment that exposes Retain, Delete, and Consolidate actions, agents preserve raw episodes by default and double the accuracy of their forced-consolidation counterparts; disabling consolidation entirely (episodic management only) matches this auto regime. Practically, robust agent memory should treat raw episodes as first-class evidence and gate consolidation explicitly rather than firing it after every interaction. Looking forward, reliable agentic memory will require LLMs that can consolidate without overwriting the evidence they depend on.","published":"2026-05-13T04:15:50Z","updated":"2026-05-13T04:15:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.12978v1","pdf_url":"https://arxiv.org/pdf/2605.12978v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:kil5cfURcp","versioned_id":"kil5cfURcp","title":"TEMPO: Scaling Test-time Training for Large Reasoning Models","authors":["Qingyang Zhang","Xinke Kong","Haitao Wu","Qinghua Hu","Minghao Wu","Baosong Yang","Yu Cheng","Yun Luo","Ganqu Cui","Changqing Zhang"],"abstract":"Large reasoning models (LRMs) remain static after training, limiting their ability to adapt to novel problems. Test-time training (TTT) addresses this by adapting model parameters on unlabeled test instances, continuously extending capabilities beyond offline training. However, existing TTT methods that rely on self-generated reward signals plateau quickly: without external grounding, the reward signal drifts as the policy evolves, causing both performance saturation and diversity collapse. We propose TEMPO, a dual-agent self-evolution framework that interleaves policy refinement by a reasoning agent on unlabeled questions with periodic recalibration of a verification agent (critic) on a labeled dataset. By formalizing this alternating procedure through the Expectation-Maximization (EM) algorithm, we reveal that prior single-agent self-rewarding methods are incomplete EM variants that omit the crucial verification step. Restoring this step tightens the evidence lower bound (ELBO) and enables sustained self-evolution. Across diverse model families (Qwen3 and OLMO3) and reasoning tasks, TEMPO improves OLMO3-7B on AIME 2024 from 33.0\\% to 51.1\\% and Qwen3-14B from 42.3\\% to 65.8\\%, while maintaining high output diversity. These results demonstrate that collaborative dual-agent self-evolution can push LRMs substantially beyond their static training boundaries. Code is available at \\url{https://anonymous.4open.science/r/TEMPO-3A56}.","published":"2026-05-13T03:41:45+00:00","updated":"2026-06-24T07:31:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=kil5cfURcp","openreview_url":"https://openreview.net/forum?id=kil5cfURcp","pdf_url":"https://openreview.net/pdf?id=kil5cfURcp","comment":"ICML 2026 AI4Math Workshop Poster","journal_ref":"ICML 2026 AI4Math Workshop Poster","doi":"","venue":"ICML 2026 AI4Math Workshop Poster","venue_id":"ICML.cc/2026/Workshop/AI4Math","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:gZYsloW2bu","versioned_id":"gZYsloW2bu","title":"SIA-W: Self-Improving Agents with Test-Time Weight Updates","authors":["Yogendra Manawat","Prannay Hebbar","Samuel Verboomen","Selvam Palanimalai","Kunal Bhatia","Vignesh Baskaran"],"abstract":"We introduce SIA-W, a self-improving agent framework that jointly optimises the agent scaffold and the model weights. Scaffold iteration is a powerful first lever: by evolving tools, prompts, and execution harnesses across generations, the agent rapidly builds domain-adapted search and reasoning procedures. SIA-W then compounds these gains with a second lever, test-time RL, which adapts the model weights directly on task feedback once the scaffold has matured. Across three diverse research tasks spanning law (charge classification), systems (GPU kernel optimisation), and biology (single-cell denoising), combining both levers delivers substantial gains over scaffold iteration alone: 16 percentage points on LawBench, 19% runtime reduction on GPU kernels, and 19% improvement on denoising, with weight updates surfacing domain knowledge that complements what the harness builds.","published":"2026-05-12T04:49:06+00:00","updated":"2026-07-01T06:13:16+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=gZYsloW2bu","openreview_url":"https://openreview.net/forum?id=gZYsloW2bu","pdf_url":"https://openreview.net/pdf?id=gZYsloW2bu","comment":"ICML 2026 Workshop AI4Research Poster","journal_ref":"ICML 2026 Workshop AI4Research Poster","doi":"","venue":"ICML 2026 Workshop AI4Research Poster","venue_id":"ICML.cc/2026/Workshop/AI4Research","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2605.11117","versioned_id":"2605.11117v1","title":"GRAFT-ATHENA: Self-Improving Agentic Teams for Autonomous Discovery and Evolutionary Numerical Algorithms","authors":["Juan Diego Toscano","Zhaojie Chai","George Em Karniadakis"],"abstract":"Scientific discovery can be modeled as a sequence of probabilistic decisions that map physical problems to numerical solutions. Recent agentic AI systems automate individual scientific tasks by orchestrating LLM-driven planners, solvers, and evaluators. Each method is a combination of methodological actions, with many viable combinations for any given problem and structural dependencies between choices. However, existing frameworks treat each problem in isolation, with no shared substrate to accumulate methodological experience across domains. Here we show that GRAFT-ATHENA, a self-improving agentic framework, learns from past problems and autonomously expands its own action space across diverse domains. GRAFT (Graph Reduction to Adaptive Factored Trees) projects combinatorial decision spaces into factored probabilistic trees in which each method is a single path, taking the parameter footprint from exponential to linear. In the lineage of classical Bayesian networks, the factorization is an $I$-map of the policy, and the resulting paths embed as unique fingerprints in a metric space whose closeness lets each new problem learn from similar past ones. On canonical physics-informed machine learning (PIML) benchmarks, GRAFT-ATHENA improves over human and prior agentic baselines, and on production solvers, it tackles complex engineering problems such as reconstructing Mach-10 flow over the Apollo Command Module from a 1968 report and recovering shear-thinning blood-cell rheology. Notably, the system grows its own knowledge substrate, autonomously proposing regularization constraints for ill-posed inverse problems and discovering new numerical methods such as a spectral PINN with exponential convergence. These results provide a foundation for autonomous laboratories that grow more capable with every problem they solve.","published":"2026-05-11T18:27:01Z","updated":"2026-05-11T18:27:01Z","categories":["cs.LG","cs.MA","math.PR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.11117v1","pdf_url":"https://arxiv.org/pdf/2605.11117v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.10754","versioned_id":"2605.10754v1","title":"The Agent Use of Agent Beings: Agent Cybernetics Is the Missing Science of Foundation Agents","authors":["Xinrun Wang","Chang Yang","He Zhao","Zhuoyi Lin","Shuyue Hu"],"abstract":"LLM-based foundation agents that perceive, reason, and act across thousands of reasoning steps are rapidly becoming the dominant paradigm for deploying artificial intelligence in open-ended, long-horizon complex tasks. Despite this significance, the field remains overwhelmingly engineering-driven. Engineering practice has converged on useful primitives (tool loops, memory banks, harnesses, reflection steps), yet these are assembled by empirical trial and error rather than from first principles. Fundamental questions remain open: under what conditions does a long-running agent remain on-task? How should an agent respond when its environment exceeds its representational capacity? What architectural properties are necessary for safe self-improvement? We argue that cybernetics, the mid-twentieth-century science of control and communication in complex systems, provides the missing theoretical scaffold for foundation agents. By mapping six canonical laws of classical cybernetics onto six agent design principles, and synthesizing those principles into three engineering desiderata (reliability, lifelong running, and self-Improvement), we arrive at a framework termed Agent Cybernetics. Three application domains, code generation, computer use and automated research, exemplify the analytical framework of agent cybernetics by identifying failure modes and concrete engineering recommendations. We hope that agent cybernetics opens a new research venue and establishes the scientific foundation that foundation agents need for principled, reliable real-world deployment.","published":"2026-05-11T15:53:54Z","updated":"2026-05-11T15:53:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.10754v1","pdf_url":"https://arxiv.org/pdf/2605.10754v1","comment":"Preliminary Work","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.10347","versioned_id":"2605.10347v2","title":"How Mobile World Model Guides GUI Agents?","authors":["Weikai Xu","Kun Huang","Yunren Feng","Jiaxing Li","Yuhan Chen","Yuxuan Liu","Zhizheng Jiang","Heng Qu","Pengzhi Gao","Wei Liu","Jian Luan","Xiaolin Hu","Bo An"],"abstract":"Recent advances in vision-language models have enabled mobile GUI agents to perceive visual interfaces and execute user instructions, but reliable prediction of action consequences remains critical for long-horizon and high-risk interactions. Existing mobile world models provide either text-based or image-based future states, yet it remains unclear which representation is useful, whether generated rollouts can replace real environments, and how test-time guidance helps agents of different strengths. To answer the above questions, we filter and annotate mobile world-model data, then train world models across four modalities: delta text, full text, diffusion-based images, and renderable code. These models achieve SoTA performance on both MobileWorldBench and Code2WorldBench. Furthermore, by evaluating their downstream utility on AITZ, AndroidControl, and AndroidWorld, we obtain three findings. First, renderable code reconstruction achieves high in-distribution fidelity and provides effective multimodal supervision for data construction, while text-based feedback is more robust for online out-of-distribution (OOD) execution. Second, world-model-generated trajectories can provide transferable interaction experience in the training process and improve agents' end-to-end task performance, although these data do not preserve the original distribution. Last, for overconfident mobile agents with low action entropy, posterior self-reflection provides limited gains, suggesting that world models are more effective as prior perception or training supervision than as universal post-hoc verifiers.","published":"2026-05-11T10:49:31Z","updated":"2026-05-22T05:43:30Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.10347v2","pdf_url":"https://arxiv.org/pdf/2605.10347v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.09998","versioned_id":"2605.09998v1","title":"Continual Harness: Online Adaptation for Self-Improving Foundation Agents","authors":["Seth Karten","Joel Zhang","Tersoo Upaa","Ruirong Feng","Wenzhe Li","Chengshuai Shi","Chi Jin","Kiran Vodrahalli"],"abstract":"Coding harnesses such as Claude Code and OpenHands wrap foundation models with tools, memory, and planning, but no equivalent exists for embodied agents' long-horizon partial-observability decision-making. We first report our Gemini Plays Pokemon (GPP) experiments. With iterative human-in-the-loop harness refinement, GPP became the first AI system to complete Pokemon Blue, Yellow Legacy on hard mode, and Crystal without a lost battle. In the hardest stages, the agent itself began iterating on its strategy through long-context memory, surfacing emergent self-improvement signals alongside human-in-the-loop refinement. Continual Harness removes the human fully from this loop: a reset-free self-improving harness for embodied agents that formalizes and automates what we observed. Starting from only a minimal environment interface, the agent alternates between acting and refining its own prompt, sub-agents, skills, and memory, drawing on any past trajectory data. Prompt-optimization methods require episode resets; Continual Harness adapts online within a single run. On Pokemon Red and Emerald across frontier models, Continual Harness starting from scratch substantially reduces button-press cost relative to the minimalist baseline and recovers a majority of the gap to a hand-engineered expert harness, with capability-dependent gains, despite starting from the same raw interface with no curated knowledge, no hand-crafted tools, and no domain scaffolding. We then close the loop with the model itself: an online process-reward co-learning loop, in which an open-source agent's rollouts through the refining harness are relabeled by a frontier teacher and used to update the model, drives sustained in-game milestone progress on Pokemon Red without resetting the environment between training iterations.","published":"2026-05-11T05:21:33Z","updated":"2026-05-11T05:21:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09998v1","pdf_url":"https://arxiv.org/pdf/2605.09998v1","comment":"28 pages, 19 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.09730","versioned_id":"2605.09730v3","title":"RubricRefine: Improving Tool-Use Agent Reliability with Training-Free Pre-Execution Refinement","authors":["Will LeVine","Brendan Evers","Sam Saltwick","Abhay Venkatesh"],"abstract":"Iterative self-refinement is a popular inference-time reliability technique, but its effectiveness in code-mode tool use depends heavily on the structure of the feedback signal: unstructured critique helps inconsistently across models, and even revision with real execution feedback improves only modestly ($0.75$ vs. $0.65$ baseline). The dominant failures are inter-tool contract violations (wrong output shape, incorrect tool routing, broken argument provenance) that run to completion without raising errors, making runtime feedback insufficient. We introduce RubricRefine, a training-free method for pre-execution semantic contract verification that generates task- and registry-specific rubrics, scores candidate code against explicit contract checks, and iteratively repairs failures before any execution occurs. RubricRefine reaches $0.86$, averaged across seven models, on M3ToolEval with zero execution attempts, improving over prior inference-time baselines with up to $2.6\\times$ lower latency. Performance remains flat on the predominantly single-step API-Bank, consistent with the method's reliance on inter-tool contract structure. A rubric-category ablation and calibration analysis further characterize when and why the method works.","published":"2026-05-10T19:57:32Z","updated":"2026-05-15T19:01:49Z","categories":["cs.LG","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09730v3","pdf_url":"https://arxiv.org/pdf/2605.09730v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:88IawleLNi","versioned_id":"88IawleLNi","title":"Scene2Demo: Self-Evolving Embodied Data Generation via Object-Action Graph","authors":["Xiang Liu","Sen Cui","Guocai Yao","Zhong Cao","Jingheng Ma","Min Zhang","Miao Liu","Changshui Zhang"],"abstract":"We present Scene2Demo, a self-evolving framework for offline embodied data generation. Given a single real-world RGB image and a user query, Scene2Demo constructs an interactive simulated scene and generates executable task configurations, multi-view execution videos, and offline robot-learning datasets. Scene2Demo uses a structured multi-module workflow via an object-action graph, representing task generation through object-centric configurations and action transitions. Failed or incomplete executions are further refined by feedback agents that inspect visual rollouts and revise action flows through sequence modification or parameter adjustment. Across 102 automatically generated primitive scene-task pairs, Scene2Demo achieves a 71.6% execution success rate; on four representative long-horizon tasks, self-evolution improves both task success and subtask-level execution quality over primitive-only execution, and comparisons with RoboGen and GenSim2 show stronger task planning and execution performance under automated data-generation settings. Finally, behavior cloning policies achieve 96.0% and 92.0% success on two representative tasks, validating that the generated data can support downstream policy learning. Our project page is available at https://scene2demo-anon.github.io/. This paper has been under submission.","published":"2026-05-10T16:39:10+00:00","updated":"2026-06-01T02:50:43+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=88IawleLNi","openreview_url":"https://openreview.net/forum?id=88IawleLNi","pdf_url":"https://openreview.net/pdf?id=88IawleLNi","comment":"FMEA @ CVPR 2026 Poster","journal_ref":"FMEA @ CVPR 2026 Poster","doi":"","venue":"FMEA @ CVPR 2026 Poster","venue_id":"thecvf.com/CVPR/2026/Workshop/FMEA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.09359","versioned_id":"2605.09359v1","title":"Skill-R1: Agent Skill Evolution via Reinforcement Learning","authors":["Yash Vishe","Rohan Surana","Xunyi Jiang","Zihan Huang","Xintong Li","Nikki Lijing Kuang","Tong Yu","Ryan A. Rossi","Jingbo Shang","Julian McAuley","Junda Wu"],"abstract":"Agentic large language models often rely on skills, reusable natural language procedures that guide planning, action, and tool use. In practice, skills are typically improved through prompt engineering or by aligning the task LLM itself, which is costly, model-specific, and often infeasible for closed-source models. Skill optimization is not a one-step problem but a recurrent process with two coupled levels of credit assignment: a useful skill must improve rollout quality under current conditioning, while a useful revision must turn observed outcomes into a better skill for the next round. We propose Skill-R1, a reinforcement learning framework for instance-level recurrent skill optimization from verifiable rewards. Rather than updating the task LLM, Skill-R1 trains a lightweight skill generator that conditions on the task context, prior rollouts, and their verified outcomes to produce skills that steer a frozen task LLM. This preserves black-box compatibility with both open- and closed-source models while making adaptation substantially cheaper than model-level updates. Skill-R1 proceeds over multiple generations: at each step, the current skill induces rollouts whose verified outcomes are fed back to produce the next revision. To optimize this recurrent process, we introduce a bi-level group-relative policy optimization objective combining intra-generation and inter-generation advantages. The intra-generation term compares rollouts under shared skill conditioning, while the inter-generation term rewards revisions that improve behavior across successive generations. Together, these provide a principled objective for directional skill evolution rather than one-shot self-refinement. Empirically, Skill-R1 achieves consistent gains over no-skill baselines and standard GRPO across benchmarks with verifiable rewards, with particularly strong improvements on complex, multi-step tasks.","published":"2026-05-10T06:19:15Z","updated":"2026-05-10T06:19:15Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.09359v1","pdf_url":"https://arxiv.org/pdf/2605.09359v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:pF9wISLUYo","versioned_id":"pF9wISLUYo","title":"MOSAIC: The Right Modules for Each Task in Embodied Agents","authors":["Kevin Wang","Dweep Trivedi","Vincent Ha","Albert Jiang","Christian Ellis","ufuk topcu","Swarat Chaudhuri","Zhangyang Wang"],"abstract":"Embodied agents demand a heterogeneous mix of capabilities: spatial precision for manipulation, persistent mapping for long-horizon navigation, and multi-step planning under natural-language instruction. The dominant remedy folds every such capability into one foundation model through spatial pre-training and geometry-aware fine-tuning, shipping a single fixed pipeline for every task in the benchmark. We contend that the question is not how to grow capability into the model, but how to compose, per task, the context that lets the model's existing capability bear on the task at hand. We formulate embodied agent design as per-task module-graph synthesis: a joint search over which modules to include, which concrete tool implements each, and how each tool's parameters bind to environment observations and upstream outputs. Solving this search by full self-evolution is infeasible in embodied control, where validating each candidate requires a multi-step rollout and credit arrives only at episode end. We therefore introduce MOSAIC, a memory-conditioned agent that retains the load-bearing slice of self-evolution and drops the rest: the typed module catalog, the meta-agent, and the model weights stay fixed, while a memory of past pipeline designs and their outcomes evolves with deployment. A frontier meta-agent runs once per episode to compose a pipeline conditioned on retrievals from this memory, and a small executor runs every step.On EB-Nav, MOSAIC reaches 50.0\\% average success across five capability subsets, an 18.4\\% gain over the default EmbodiedBench agent at the same Qwen3-VL-8B backbone and +5.3\\% over a baseline that activates every module in the same catalog without per-task selection.","published":"2026-05-10T03:59:14+00:00","updated":"2026-06-04T16:19:17+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=pF9wISLUYo","openreview_url":"https://openreview.net/forum?id=pF9wISLUYo","pdf_url":"https://openreview.net/pdf?id=pF9wISLUYo","comment":"FMEA @ CVPR 2026 Poster","journal_ref":"FMEA @ CVPR 2026 Poster","doi":"","venue":"FMEA @ CVPR 2026 Poster","venue_id":"thecvf.com/CVPR/2026/Workshop/FMEA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.08904","versioned_id":"2605.08904v1","title":"OPT-BENCH: Evaluating the Iterative Self-Optimization of LLM Agents in Large-Scale Search Spaces","authors":["Xiaozhe Li","Jixuan Chen","Xinyu Fang","Shengyuan Ding","Haodong Duan","Qingwen Liu","Kai Chen"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable capabilities in reasoning and tool use. However, the fundamental cognitive faculties essential for problem solving, including perception, reasoning, and memory, remain the stable core of intelligence. Unlike memorizing specific patterns, humans succeed in novel environments by applying these intrinsic faculties to adapt and optimize. Yet, whether LLMs possess this essential capacity, namely the ability to continuously refine solutions in response to dynamic environmental feedback, remains underexplored. To address this challenge, we introduce OPT-BENCH, a benchmark for evaluating self-improvement capabilities in large-scale search spaces. By combining 20 machine learning tasks with 10 classic NP-hard problems, OPT-BENCH provides a rigorous setting to assess whether agents can adapt through intrinsic self-reflection rather than rote tool application. We further propose OPT-Agent, a framework that emulates human-like cognitive adaptation. It operates through a general perception, memory, and reasoning loop, iteratively refining solutions based on environmental feedback. Through extensive experiments on 19 LLMs from 7 model families, including reasoning models, general models, and open-source models ranging from 3B to 235B parameters, we demonstrate that stronger models are more effective at leveraging feedback signals for self-improvement. However, this upper-bound adaptability remains fundamentally constrained by the models' base capacity, and even the most advanced LLMs still fall short of human expert performance.","published":"2026-05-09T11:51:34Z","updated":"2026-05-09T11:51:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08904v1","pdf_url":"https://arxiv.org/pdf/2605.08904v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=nNUkLOSYN8","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"openreview:3YDbTwejnh","versioned_id":"3YDbTwejnh","title":"MemRL: Self-Evolving Agents via Runtime Reinforcement Learning on Episodic Memory","authors":["Shengtao Zhang","Jiaqian Wang","Ruiwen Zhou","Junwei Liao","Yuchen Feng","Zhuo Li","Yujie Zheng","Weinan Zhang","Ying Wen","Zhiyu li","Feiyu Xiong","Yutao Qi","Bo Tang","Muning Wen"],"abstract":"The hallmark of human intelligence is the self-evolving ability to master new skills by learning from past experiences. However, current AI agents struggle to emulate this self-evolution: fine-tuning is computationally expensive and can introduce destabilizing weight updates, increasing the risk of catastrophic forgetting, while existing memory-based methods rely on passive semantic matching that often retrieves noise. To address these challenges, we propose MemRL, a non-parametric approach that evolves via reinforcement learning on episodic memory. By decoupling stable reasoning from plastic memory, MemRL employs a Two-Phase Retrieval mechanism to filter noise and identify high-utility strategies through environmental feedback. Extensive experiments on Humanity's Last Exam, BigCodeBench, ALFWorld, and Lifelong Agent Bench demonstrate that MemRL significantly outperforms state-of-the-art baselines, suggesting that MemRL offers a practical way to balance stability and plasticity during runtime improvement.","published":"2026-05-09T10:46:49+00:00","updated":"2026-05-09T10:46:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=3YDbTwejnh","openreview_url":"https://openreview.net/forum?id=3YDbTwejnh","pdf_url":"https://openreview.net/pdf?id=3YDbTwejnh","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:rxrupxyIxN","versioned_id":"rxrupxyIxN","title":"TRACE: Why LLM Agents Fail in Multi-Step and Multi-Turn Environments?","authors":["Aadit Roy Chowdhury","Emre Can Acikgoz","Cheng Qian","Dilek Hakkani-Tür","Gokhan Tur"],"abstract":"LLM-based agents have made remarkable progress in performing complex tasks across multi-turn interactions and in environments that require multi-step reasoning. Although recent advances have enabled more dynamic interactions with users and environments, these models still fail in ways that are not well defined and understood. In this paper, we discuss what agent abilities are lacking when LLMs fail in multi-turn settings. We perform a comprehensive analysis of around 10,000 trajectories spanning four popular agentic benchmarks: $\\tau^2$-bench, BFCL v4, ALFWorld, and ACEBench and seven LLMs covering four closed-source models: GPT-5.4 Mini, DeepSeek-R1, Kimi-K2.5, and Llama-3.3-70B-Instruct-Turbo and three open-source models at different scales: Qwen3 (1.7B, 4B, 8B). We introduce TRACE, a capability-based taxonomy that organizes failures into three categories: A) action–plan failures, B) monitoring failures, and C) outcome evaluation failures. Each failure type is mapped to specific agent skills, such as self-awareness, self-correction, proactivity, state-tracking, and policy adherence. We show that certain failure patterns recur across benchmarks and model families and can be attributed to poor agent capabilities. Our analysis introduces a principled taxonomy of the failure patterns and highlights the need for training methods that provide fine-grained, step-level feedback to LLM agents to improve these capabilities in multi-turn and multi-step reasoning environments.","published":"2026-05-09T10:25:18+00:00","updated":"2026-07-15T08:57:54+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=rxrupxyIxN","openreview_url":"https://openreview.net/forum?id=rxrupxyIxN","pdf_url":"https://openreview.net/pdf?id=rxrupxyIxN","comment":"FAGEN@ICML 2026 Poster","journal_ref":"FAGEN@ICML 2026 Poster","doi":"","venue":"FAGEN@ICML 2026 Poster","venue_id":"ICML.cc/2026/Workshop/FAGEN","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:f9yc09BuxG","versioned_id":"f9yc09BuxG","title":"AIE-Bench: Benchmarking Agents That Build Agents","authors":["Abhishek Mishra","Selvam Palanimalai","Yogendra Manawat","Samuel Verboomen","Prannay Hebbar","Damir Vrabac","Deepak Nathani","Sumeet Ramesh Motwani","Kunal Bhatia","Vignesh Baskaran"],"abstract":"We introduce AIE Bench, a benchmark for measuring how well AI agents can build and improve other AI agents. Existing benchmarks evaluate whether an agent can solve tasks. This benchmark aims to measure whether an agent can modify another agent to make it better at those tasks. AIE Bench is built around two roles. A meta-agent proposes modifications, while a target-agent is the system being improved. This setup covers meta-improvement, where one agent improves another, and self-improvement, where an agent improves itself. We instantiate AIE Bench across two task families spanning terminal interaction and tool calling, and we evaluate frontier agentic systems on their ability to drive gains through iterative modification. AIE Bench makes target-agent improvement a measurable and reproducible research target.","published":"2026-05-09T05:32:49+00:00","updated":"2026-06-08T16:21:48+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=f9yc09BuxG","openreview_url":"https://openreview.net/forum?id=f9yc09BuxG","pdf_url":"https://openreview.net/pdf?id=f9yc09BuxG","comment":"CTB@ICML 2026","journal_ref":"CTB@ICML 2026","doi":"","venue":"CTB@ICML 2026","venue_id":"ICML.cc/2026/Workshop/CTB","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.08693","versioned_id":"2605.08693v2","title":"SkillMaster: Toward Autonomous Skill Mastery in LLM Agents","authors":["Min Yang","Jinghua Piao","Xu Xia","Xiaochong Lan","Jiaju Chen","Yongshun Gong","Yong Li"],"abstract":"Skills provide an effective mechanism for improving LLM agents on complex tasks, yet in existing agent frameworks, their creation, refinement, and selection are typically governed by external teachers, hand-designed rules, or auxiliary modules. As a result, skills remain external resources to be invoked, rather than capabilities that agents can develop, adapt, and internalize through experience. To endow LLM agents with autonomous skill mastery, we propose SkillMaster, a training framework that teaches agents to create new skills, refine existing skills, and select accumulated skills during task solving. This capability is achieved through three key designs. First, we train agents through trajectory-informed skill review, teaching agents to propose, update, or retain skills based on evidence from completed episodes. Second, each candidate skill edit is designed to be evaluated by its counterfactual utility on related probe tasks, providing a direct learning signal for training skill-editing decisions. Third, we introduce DualAdv-GRPO, which separately estimates advantages for task-solving actions and skill-editing decisions, stabilizing joint training across task solving and skill management. Experiments on ALFWorld and WebShop show that SkillMaster improves the overall success rate over state-of-the-art baselines by 8.8% and 9.3%, respectively, achieving the best performance among all compared methods. Further analysis reveals a marked shift in agent capability: agents trained with SkillMaster can identify skill failures, refine procedural knowledge from trajectory evidence, and transfer improvements to future tasks with limited skill-bank edits. Overall, SkillMaster moves LLM agents beyond mere skill use toward self-improving agents capable of developing, adapting, and applying their own skill repertoires.","published":"2026-05-09T05:03:00Z","updated":"2026-05-12T07:27:47Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.08693v2","pdf_url":"https://arxiv.org/pdf/2605.08693v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.08468","versioned_id":"2605.08468v1","title":"PYTHALAB-MERA: Validation-Grounded Memory, Retrieval, and Acceptance Control for Frozen-LLM Coding Agents","authors":["Mehmet Iscan"],"abstract":"Local LLM-based coding agents increasingly work in settings where correctness is earned through execution feedback, persistent state, and bounded repair, not through a single fluent answer. Static retrieval, long-context prompting, self-refinement, execution-feedback repair, and reinforcement learning over model weights each address part of this setting, but they do not jointly provide validation-grounded episodic memory, adaptive retrieval-action selection, delayed credit assignment, and structural skill reuse around a frozen local model. We introduce PYTHALAB-MERA, a lightweight external controller for local validation-conditioned code generation. The frozen language model proposes complete source files; the controller decides which memory records and AST-derived skills should enter the next prompt, validates each candidate through a fail-fast pipeline, converts validation outcomes into bounded shaped rewards, and propagates delayed credit through TD(lambda)-style eligibility traces. We evaluate the implementation as a local CLI artifact on reinforcement-learning coding tasks with strict validation gates. In the measured hard RL setting with three tasks, three repetitions, and a three-attempt budget, PYTHALAB-MERA passed 8/9 strict validations; the self-refinement baseline and the investigated GRACE extension each passed 0/9. These results support a deliberately bounded claim: in this recorded setting, the external memory-and-retrieval controller improved validation success. They do not establish general-purpose code synthesis, state-of-the-art performance, formal program correctness, or formal safety.","published":"2026-05-08T20:39:32Z","updated":"2026-05-08T20:39:32Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2605.08468v1","pdf_url":"https://arxiv.org/pdf/2605.08468v1","comment":"28 pages, 4 figures, 7 tables; local CLI artifact evaluation","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.06924","versioned_id":"2605.06924v1","title":"A$^2$RD: Agentic Autoregressive Diffusion for Long Video Consistency","authors":["Do Xuan Long","Yale Song","Min-Yen Kan","Tomas Pfister","Long T. Le"],"abstract":"Synthesizing consistent and coherent long video remains a fundamental challenge. Existing methods suffer from semantic drift and narrative collapse over long horizons. We present A$^2$RD, an Agentic Auto-Regressive Diffusion architecture that decouples creative synthesis from consistency enforcement. A$^2$RD formulates long video synthesis as a closed-loop process that synthesizes and self-improves video segment-by-segment through a Retrieve--Synthesize--Refine--Update cycle. It comprises three core components: (i) Multimodal Video Memory that tracks video progression across modalities; (ii) Adaptive Segment Generation that switches among generation modes for natural progression and visual consistency; and (iii) Hierarchical Test-Time Self-Improvement that self-improves each segment at frame and video levels to prevent error propagation. We further introduce LVBench-C, a challenging benchmark with non-linear entity and environment transitions to stress-test long-horizon consistency. Across public and LVBench-C benchmarks spanning one- to ten-minute videos, A$^2$RD outperforms state-of-the-art baselines by up to 30% in consistency and 20% in narrative coherence. Human evaluations corroborate these gains while also highlighting notable improvements in motion and transition smoothness.","published":"2026-05-07T20:35:46Z","updated":"2026-05-07T20:35:46Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2605.06924v1","pdf_url":"https://arxiv.org/pdf/2605.06924v1","comment":"Project page: http://dxlong2000.github.io/AARD","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:wuACBLwzQx","versioned_id":"wuACBLwzQx","title":"Beyond Agreeable Chatbots: Context-Aware Safety Oversight for Trustworthy Patient-Facing LLMs","authors":["Elham Nasarian","Abhilash Neog","Kwok-leung Tsui","Niyousha Hosseinichimeh"],"abstract":"Large language models (LLMs) are increasingly being integrated into patient-facing healthcare systems, yet their safe deployment in real-world settings remains an open challenge. Although existing alignment methods can reduce overtly harmful outputs, they often fail in realistic medical interactions where patient queries are incomplete, ambiguous, and context dependent. In such settings, models frequently default to agreeable responses rather than actively identifying missing clinical context or challenging unsafe assumptions. As a result, LLMs may generate responses that appear plausible and reassuring while remaining clinically unsafe or factually unreliable. In this work, we investigate whether inference-time safety oversight can improve the trustworthiness of patient-facing medical LLMs beyond conventional alignment alone. We introduce CareGuardAI, a context-aware multi-agent framework designed to study and mitigate two critical deployment risks: clinical safety risk and hallucination risk. The framework combines a controller agent for risk-aware triage and contextual screening with dual evaluator agents that independently assess Clinical Safety Risk Assessment (SRA) and Hallucination Risk Assessment (HRA). Responses exceeding predefined deployment thresholds are iteratively refined or blocked prior to release. We evaluate the framework on PatientSafeBench, MedSafetyBench, and MedHallu, covering adversarial medical safety scenarios and hallucination-focused evaluation. Across benchmarks, inference-time oversight substantially improves deployable response rates while reducing unsafe and hallucinated outputs compared to strong baseline models, including GPT-4o-mini. Through ablation studies and qualitative analysis, we further examine the contribution of contextual screening, evaluator-based oversight, and iterative refinement in reducing deployment risk. Our findings suggest that trustworthy deployment of patient-facing medical LLMs may require more than static alignment objectives alone. Instead, reliable real-world deployment may depend on context-aware inference-time monitoring systems that actively assess uncertainty, identify missing context, and constrain model behavior during interaction.","published":"2026-05-07T18:55:33+00:00","updated":"2026-06-03T11:26:03+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wuACBLwzQx","openreview_url":"https://openreview.net/forum?id=wuACBLwzQx","pdf_url":"https://openreview.net/pdf?id=wuACBLwzQx","comment":"AI4GOOD Workshop 2026 Regular","journal_ref":"AI4GOOD Workshop 2026 Regular","doi":"","venue":"AI4GOOD Workshop 2026 Regular","venue_id":"ICML.cc/2026/Workshop/AI4GOOD","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2605.06822","versioned_id":"2605.06822v1","title":"SHARP: A Self-Evolving Human-Auditable Rubric Policy for Financial Trading Agents","authors":["Xiwen Chen","Wenhui Zhu","Songzhu Zheng","Kashif Rasul","Yueyue Deng","Huayu Li"],"abstract":"Large language models (LLMs) are increasingly deployed for autonomous financial trading, a domain requiring continuous adaptation to noisy, non-stationary markets. Existing self-improving agents typically address this through unbounded free-form prompt optimization. However, in low signal-to-noise environments with delayed scalar rewards (P\\&L), this unstructured approach exacerbates the fundamental credit assignment problem: optimizers cannot reliably distinguish systematic logic flaws from stochastic market variance, inevitably leading to policy drift. To overcome this bottleneck, we introduce the Self-Evolving Human-Auditable Rubric Policy (SHARP), a neuro-symbolic framework that replaces unconstrained text mutation with structured, symbolic policy optimization. SHARP confines the agent's reasoning to a bounded, human-readable rubric of explicit condition-action rules. When sub-optimal trades occur, an attribution agent employs cross-sample reasoning across multiple samples to isolate specific rule failures. This enables targeted, atomic policy edits that are subsequently regularized through strict walk-forward validation. Evaluated across three diverse equity sectors and four LLM backbones, SHARP consistently transforms generic initial heuristics into highly robust strategies, lifting the empirical performance of compact models by 10 to 20 percentage points on average (e.g., GPT-4o-mini). Ultimately, SHARP demonstrates that LLMs can achieve dynamic and efficient adaptation while significantly enhancing the structural transparency and auditability demanded by institutional finance.","published":"2026-05-07T18:23:44Z","updated":"2026-05-07T18:23:44Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.06822v1","pdf_url":"https://arxiv.org/pdf/2605.06822v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.05963","versioned_id":"2605.05963v1","title":"TheraAgent: Self-Improving Therapeutic Agent for Precise and Comprehensive Treatment Planning","authors":["Junkai Li","Yunghwei Lai","Tianyi Zhu","Zheng Long Lee","Weizhi Ma","Yang Liu"],"abstract":"Formulating a treatment plan is inherently a complex reasoning and refinement task rather than a simple generation problem. However, existing large language models (LLMs) mainly rely on one-shot output without explicit verification, which may result in rough, incomplete, and potentially unsafe treatment plans. To address these limitations, we propose TheraAgent, an agentic framework that replaces one-shot generation with an iterative generate-judge-refine pipeline. By mirroring the actual reasoning process of human experts who iteratively revise treatment plans, our framework progressively transforms coarse and incomplete drafts into precise, comprehensive, and safer therapeutic regimens. To facilitate the critical judge component, we introduce TheraJudge, a treatment-specific evaluation module integrated into the inference loop to enforce clinical standards. Experiments show TheraAgent achieves state-of-the-art results on HealthBench, leading in Accuracy and Completeness. In expert evaluations, it attains an 86% win rate against physicians, with superior Targeting and Harm Control. Moreover, the highly agreement between TheraJudge and HealthBench evaluations confirms the reliability of our framework.","published":"2026-05-07T10:10:22Z","updated":"2026-05-07T10:10:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.05963v1","pdf_url":"https://arxiv.org/pdf/2605.05963v1","comment":"Accepted to ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.05846","versioned_id":"2605.05846v1","title":"LoopTrap: Termination Poisoning Attacks on LLM Agents","authors":["Huiyu Xu","Zhibo Wang","Wenhui Zhang","Ziqi Zhu","Yaopeng Wang","Kui Ren","Chun Chen"],"abstract":"Modern LLM agents solve complex tasks by operating in iterative execution loops, where they repeatedly reason, act, and self-evaluate progress to determine when a task is complete. In this work, we show that while this self-directed loop facilitates autonomy, it also introduces a critical risk: by injecting malicious prompts into the agent's context, an adversary can distort the agent's termination judgment, making it believe the task remains incomplete and leading to unbounded computation.To understand this threat, we define and systematically characterize it as Termination Poisoning and design 10 representative attack strategies. Through a empirical study spanning 8 LLM agents and 60 tasks, we demonstrate that different LLM agents exhibit distinct behavioral signatures that determine which strategies succeed. These transferable patterns can serve as principled guidance for crafting effective attacks against previously unseen agents and tasks, enabling scalable red-teaming beyond manually designed templates. Building on these insights, we introduce LoopTrap, an automated red-teaming framework that synthesizes target-specific malicious prompts by exploiting agent behavioral tendencies. LoopTrap first constructs a behavioral profile of the target agent along four vulnerability dimensions via lightweight probing. It then performs adaptive trap synthesis, routing to the most effective strategy and selecting optimal injections via a self-scoring mechanism. Finally, successful traps are abstracted into a reusable skill library, while failed attempts are refined through self-reflection, ensuring continuous improvement. Extensive evaluation shows that LoopTrap achieves an average of 3.57$\\times$ step amplification across 8 mainstream agents, with a peak of 25$\\times$.","published":"2026-05-07T08:21:51Z","updated":"2026-05-07T08:21:51Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2605.05846v1","pdf_url":"https://arxiv.org/pdf/2605.05846v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.05716","versioned_id":"2605.05716v1","title":"More Is Not Always Better: Cross-Component Interference in LLM Agent Scaffolding","authors":["Ming Liu"],"abstract":"LLM agent systems are built by stacking scaffolding components (planning, tools, memory, self-reflection, retrieval) assuming more is better. We study cross-component interference (CCI): degradation when components interact destructively. We run a full factorial experiment over all 2^5=32 subsets of five components on HotpotQA and GSM8K with Llama-3.1-8B/70B (96 conditions, up to 10 seeds). The All-In system is consistently suboptimal: on HotpotQA, a single-tool agent surpasses All-In by 32% (F1 0.233 vs 0.177, p=0.023); on GSM8K, a 3-component subset beats All-In by 79% (0.43 vs 0.24, p=0.010). Optimal component count is task-dependent (k*=1-4) and scale-sensitive: at 70B, combinations that hurt at 8B provide gains, though All-In still trails the best subset. We fit a main-effects regression (R^2=0.916, adj-R^2=0.899, LOOCV=0.872), compute exact Shapley values, and find 183/325 submodularity violations (56.3%), showing greedy selection is unreliable. A three-body synergy among Tool Use, Self-Reflection, and Retrieval (INT_3=+0.175, 95% CI [+0.003,+0.351]) is reported as exploratory. CCI replicates across model families (Qwen2.5) and is robust to prompt paraphrasing. Our findings suggest maximally-equipped agent defaults should be replaced by task-specific subset selection via interaction-aware analysis.","published":"2026-05-07T06:01:43Z","updated":"2026-05-07T06:01:43Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.05716v1","pdf_url":"https://arxiv.org/pdf/2605.05716v1","comment":"10 pages, 5 tables; preprint, under review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:nfrGcHAqfq","versioned_id":"nfrGcHAqfq","title":"Investigating Component Contributions in Multi-Agent ML Systems","authors":["Junsung Kim","Ilia Mireskandari","Seungwan Son","Yifan Zhou","Khizer Shahid","Dylan Yihan Dai"],"abstract":"Autonomous agents for machine learning engineering have advanced rapidly, yet comparing their effectiveness remains difficult. Existing systems combine different techniques---multi-agent decomposition, iterative refinement, memory management, and planning---in varying configurations, making it unclear which components actually drive performance. Complicating evaluation, existing benchmarks rely on historical competitions whose data likely contaminates LLM training corpora and whose static baselines reflect outdated human performance. To address this, we conduct over 4,000 controlled experiments systematically ablating architectural components, alongside K-live, a new benchmark of 25 active competitions that provides a contamination-free, dynamic evaluation environment. Our findings challenge common design assumptions: iterative feedback contributes more than architectural complexity, and multi-agent coordination can hurt as often as it helps. These results provide concrete guidance for practitioners building ML engineering agents.","published":"2026-05-06T00:01:57+00:00","updated":"2026-05-06T00:01:57+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=nfrGcHAqfq","openreview_url":"https://openreview.net/forum?id=FOfvTwBGUX","pdf_url":"https://openreview.net/pdf?id=nfrGcHAqfq","comment":"ICML 2026","journal_ref":"ICML 2026","doi":"","venue":"ICML 2026","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ICML 2026","ICML 2026 regular"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2605.05248","versioned_id":"2605.05248v4","title":"Governed Metaprogramming for Intelligent Systems: Reclassifying Eval as a Governed Effect","authors":["Alan L. McCann"],"abstract":"AI systems increasingly synthesize executable structure at runtime: LLMs generate programs, agents construct workflows,self-improving systems modify their own behavior. In classical homoiconic and staged languages, the transition from code representation to execution is unrestricted. eval is a language primitive, not a governed operation. We argue that in governed intelligent systems, this transition is an authority amplification: it converts symbolic structure into executable authority and must be mediated like any other effect. We present governed metaprogramming, a language design where program representations (machine forms) are first-class values, form manipulation is pure computation, and materialization (the transition from form to executable machine) is a governed effect subject to structural inspection. The governance system analyzes the proposed program's capability requirements, policy compliance, and resource estimates before permitting execution. We formalize two judgments: pure form evaluation (which emits no directives) and governed materialization (which emits exactly one governed directive). We prove three properties: purity of form manipulation, the no-bypass theorem, and boundary preservation. We implement the design in mashinTalk, a DSL for AI workflows compiling to BEAM byte code, and report on integration with 454 existing machine-checked Rocq theorems. The central contribution is reclassifying eval from a language primitive into a governed effect.","published":"2026-05-05T02:56:43Z","updated":"2026-05-26T12:37:10Z","categories":["cs.PL","cs.AI"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2605.05248v4","pdf_url":"https://arxiv.org/pdf/2605.05248v4","comment":"15 pages. Companion proofs: https://github.com/mashin-live/governance-proofs. Project: https://mashin.live. Update: Abstract typo fixes. Updated license","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.03042","versioned_id":"2605.03042v1","title":"ARIS: Autonomous Research via Adversarial Multi-Agent Collaboration","authors":["Ruofeng Yang","Yongcan Li","Shuai Li"],"abstract":"This report describes ARIS (Auto-Research-in-sleep), an open-source research harness for autonomous research, including its architecture, assurance mechanisms, and early deployment experience. The performance of agent systems built on LLMs depends on both the model weights and the harness around them, which governs what information to store, retrieve, and present to the model. For long-horizon research workflows, the central failure mode is not a visible breakdown but a plausible unsupported success: a long-running agent can produce claims whose evidential support is incomplete, misreported, or silently inherited from the executor's framing. Therefore, we present ARIS as a research harness that coordinates machine-learning research workflows through cross-model adversarial collaboration as a default configuration: an executor model drives forward progress while a reviewer from a different model family is recommended to critique intermediate artifacts and request revisions. ARIS has three architectural layers. The execution layer provides more than 65 reusable Markdown-defined skills, model integrations via MCP, a persistent research wiki for iterative reuse of prior findings, and deterministic figure generation. The orchestration layer coordinates five end-to-end workflows with adjustable effort settings and configurable routing to reviewer models. The assurance layer includes a three-stage process for checking whether experimental claims are supported by evidence: integrity verification, result-to-claim mapping, and claim auditing that cross-checks manuscript statements against the claim ledger and raw evidence, as well as a five-pass scientific-editing pipeline, mathematical-proof checks, and visual inspection of the rendered PDF. A prototype self-improvement loop records research traces and proposes harness improvements that are adopted only after reviewer approval.","published":"2026-05-04T18:10:15Z","updated":"2026-05-04T18:10:15Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.03042v1","pdf_url":"https://arxiv.org/pdf/2605.03042v1","comment":"Technical report. Code at https://github.com/wanshuiyin/Auto-claude-code-research-in-sleep","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:lidiprht3N","versioned_id":"lidiprht3N","title":"EvoMaster: A Foundational Evolving Agent Framework for Agentic Science at Scale","authors":["Xinyu Zhu","Yuzhu Cai","Zexi Liu","Cheng Wang","Fengyang Li","Wenkai Jin","Wanxu Liu","Zehao Bing","Bingyang Zheng","Jingyi Chai","Shuo Tang","Rui Ye","Yuwen Du","Xianghe Pang","Yaxin Du","Tingjia Miao","Yuzhi Zhang","Ruoxue Liao","ding zhaohan","Linfeng Zhang","Yanfeng Wang","Weinan E","Siheng Chen"],"abstract":"The convergence of large language models and agents is catalyzing a new era of scientific discovery: Agentic Science. While the scientific method is inherently iterative, existing agent frameworks are predominantly static, narrowly scoped, and lack the capacity to learn from trial and error. To bridge this gap, we present EvoMaster, a foundational evolving agent framework engineered specifically for Agentic Science at Scale. Driven by the core principle of continuous self-evolution, EvoMaster empowers agents to iteratively refine hypotheses, self-critique, and progressively accumulate knowledge across experimental cycles, faithfully mirroring human scientific inquiry. Crucially, as a domain-agnostic base harness, EvoMaster is exceptionally easy to scale up---enabling developers to build and deploy highly capable, self-evolving scientific agents for arbitrary disciplines in approximately 100 lines of code. Built upon EvoMaster, we incubated the SciMaster ecosystem across domains such as machine learning, physics, biology, web research, and general science. Evaluations on ten benchmarks spanning scientific research/coding/experimentation, scientific reasoning and information search, and practical scientific problem solving compare EvoMaster against OpenHands, OpenClaw, and Codex. EvoMaster achieves the highest score on nine of the ten benchmarks and the strongest average score (58.0\\%) among the four agents, validating its efficacy and generality as the premier foundational framework for the next generation of autonomous scientific discovery. Code is available at https://github.com/sjtu-sai-agents/EvoMaster","published":"2026-05-04T13:41:13+00:00","updated":"2026-07-01T09:56:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=lidiprht3N","openreview_url":"https://openreview.net/forum?id=lidiprht3N","pdf_url":"https://openreview.net/pdf?id=lidiprht3N","comment":"ICML2026-AI4Science Poster","journal_ref":"ICML2026-AI4Science Poster","doi":"","venue":"ICML2026-AI4Science Poster","venue_id":"ICML.cc/2026/Workshop/AI4Science","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2605.01789","versioned_id":"2605.01789v1","title":"DataEvolver: Let Your Data Build and Improve Itself via Goal-Driven Loop Agents","authors":["Qisong Zhang","Wenzhuo Wu","Zhuangzhuang Jia","Yunhao Yang","Huayu Zhang","Xianghao Zang","Zhixiang He","Zhongjiang He","Kongming Liang","Zhanyu Ma"],"abstract":"Constructing controllable visual data is a major bottleneck for image editing and multimodal understanding. Useful supervision is rarely produced by a single rendering pass; instead it emerges through iterative generation, inspection, correction, filtering, and export. We present DataEvolver, a closed-loop visual data engine that organizes this process around explicit goals, persistent artifacts, bounded corrective actions, and acceptance decisions. DataEvolver supports multiple artifact types, including RGB images, masks, depth maps, normal maps, meshes, poses, trajectories, and review traces. In the current release, the system operates through two coupled loops: generation-time self-correction within each sample and validation-time self-expansion across dataset rounds. We validate the framework on an image-level object-rotation setting. With a fixed Qwen-Edit LoRA probe, our final Ours+DualGate model outperforms both the unadapted base model and a public multi-angle LoRA on SpatialEdit and a held-out evaluation set. Ablations show a consistent improvement path from scene-aware generation to feedback-driven correction and dual-gated validation. Beyond the released rotation data, our main contribution is a reusable framework for building visual datasets through explicit goal tracking, review, correction, and acceptance loops.","published":"2026-05-03T09:10:23Z","updated":"2026-05-03T09:10:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.01789v1","pdf_url":"https://arxiv.org/pdf/2605.01789v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.01566","versioned_id":"2605.01566v1","title":"Multi-Agent Reasoning Improves Compute Efficiency: Pareto-Optimal Test-Time Scaling","authors":["Florian Valentin Wunderlich","Lars Benedikt Kaesberg","Jan Philip Wahle","Terry Ruas","Bela Gipp"],"abstract":"Advances in inference methods have enabled language models to improve their predictions without additional training. These methods often prioritize raw performance over cost-effective compute usage. However, computational efficiency is key for real-world applications with resource constraints. We provide a systematic analysis of the inference scaling strategies self-consistency, self-refinement, multi-agent debate, and mixture-of-agents, to study their computational performance tradeoffs. We evaluate methods on two reasoning benchmarks (MMLU-Pro, BBH) and include extensive parameter configurations (e.g., scaling the number of parallel predictions, agents, and debate rounds) across different model sizes. Across 34 configurations and over 100 evaluations, we compute the Pareto-optimal front to select methods that achieve the best accuracy with the lowest computational budget. Notably, inference scaling improves accuracy by up to +7.1% points over chain-of-thought at the highest evaluated budgets (20x the CoT compute budget) on MMLU-Pro. With an equal computing budget, debate and mixture-of-agents outperform self-consistency by 1.3% and 2.7% points, respectively. While self-consistency saturates earlier, multi-agent gains persist, particularly on more complicated tasks. We identify a simple multi-agent design guideline: mixture-of-agents is most efficient when the number of parallel generations exceeds the number of sequential aggregations.","published":"2026-05-02T18:31:02Z","updated":"2026-05-02T18:31:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2605.01566v1","pdf_url":"https://arxiv.org/pdf/2605.01566v1","comment":"Accepted at SRW at ACL 2026, long paper","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.01471","versioned_id":"2605.01471v1","title":"Practical Limits of Autonomous Test Repair: A Multi-Agent Case Study with LLM-Driven Discovery and Self-Correction","authors":["Hyukjoo Lee"],"abstract":"Maintaining reliable UI test suites in large-scale enterprise applications is a persistent and costly challenge. We present an industrial case study of a multi-agent autonomous testing system evaluated using anonymized execution data from a production-like enterprise UI testing prototype. The application features several hundred dynamic UI elements per screen. Built on a large language model with LangGraph orchestration, Playwright execution, and a RAG knowledge base, the system evolves from human-directed testing toward High-autonomy feature discovery and test execution: given no explicit test targets, it discovers over 100 testable features across 10 UI screens, dynamically expands coverage by an additional 15--30 features through runtime DOM analysis, and iteratively repairs failing tests without human intervention. We analyzed 300 consecutive autonomous execution reports encompassing 636 individual test-case executions across 10 distinct scenario families. The system achieved a 70% repair convergence rate at the scenario-family level, with a mean of 3.4 repair iterations to convergence. However, only 10% of scenario families succeeded on first attempt, 38% of reports failed to produce any executable test artifact, and we documented concrete instances of assertion weakening and test-case deletion used as workaround mechanisms to achieve superficial convergence. Our findings show that unrestricted autonomy leads to unstable and often misleading outcomes, while constrained autonomy transforms such systems into operationally viable workflows. Rather than advocating full autonomy, our findings suggest that reliable autonomous testing in enterprise-scale settings requires explicit constraints, validation boundaries, and human oversight to preserve semantic correctness and operational trustworthiness.","published":"2026-05-02T14:39:55Z","updated":"2026-05-02T14:39:55Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2605.01471v1","pdf_url":"https://arxiv.org/pdf/2605.01471v1","comment":"Industrial case study; submitted for review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2607.00007","versioned_id":"2607.00007v2","title":"BaRA: Budget-constrained and Reliable Web Data Collection Agent","authors":["Soojeong Lee","Joseph Lee","Yongseong Cho","Sunjae Kim","Youngwoo Moon","Kyungwoo Song"],"abstract":"Large language model (LLM)-based web agents automate web navigation and data collection. However, live web data collection demands capabilities beyond task completion: agents must discover site-internal pages and retrieve text, image, and video artifacts in an accessible form within a fixed interaction budget. We formulate this setting as budget-constrained, site-level multimodal web data collection and propose Budget-constrained and Reliable Agent (BaRA). BaRA performs breadth-first search (BFS)-based link discovery with liveness verification to filter hallucinated and dead links, then validates extracted multimodal artifacts using rule-based provenance and accessibility checks. A history-based self-reflection module recovers from execution failures and incomplete outputs. On controlled synthetic and real-world websites, BaRA consistently improves valid-link discovery and download-valid multimodal extraction over existing agents. Our code is available at https://github.com/MLAI-Yonsei/BaRA-Agent.","published":"2026-05-02T08:09:10Z","updated":"2026-07-02T06:17:26Z","categories":["cs.IR","cs.AI"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2607.00007v2","pdf_url":"https://arxiv.org/pdf/2607.00007v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Nkcu2E0Wxy","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"openreview:9JfFiOrfrp","versioned_id":"9JfFiOrfrp","title":"IRIS: An Agentic Multi-Phase Framework for Automated Scientific Literature Review","authors":["Sergey Kolchenko","Mahdi Zamanighomi","Amir Bayegan"],"abstract":"We present IRIS (Iterative Refinement for Information Synthesis), an agentic framework for automated scientific literature review. IRIS breaks the research process into three phases (iterative planning, parallel per-section research and writing, and final report compilation), orchestrated as a directed state graph. Two mechanisms are central to the design. First, reflective research expansion: an LLM-based critic repeatedly evaluates how well the accumulated evidence covers the target topic and generates new queries until a sufficiency threshold is met. Second, critic-guided refinement: when a section fails quality review, an LLM critic pinpoints what is missing (mechanistic detail, quantitative data, recent findings) and issues targeted follow-up searches rather than simply requesting a rewrite. Citations are tracked at the claim level, mapping every factual assertion back to specific source passages. On DeepResearch-Bench (50 PhD-level English research tasks across 22 domains), IRIS achieves a RACE overall score of 53.46, outperforming every commercial system reported in the benchmark, including Gemini 2.5 Pro Deep Research (48.88) and OpenAI Deep Research (46.98). IRIS wins all four RACE dimensions despite being restricted to PubMed and ArXiv, with no open-web retrieval.","published":"2026-04-30T21:44:11+00:00","updated":"2026-06-09T19:47:18+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9JfFiOrfrp","openreview_url":"https://openreview.net/forum?id=9JfFiOrfrp","pdf_url":"https://openreview.net/pdf?id=9JfFiOrfrp","comment":"GenBio 2026 Poster","journal_ref":"GenBio 2026 Poster","doi":"","venue":"GenBio 2026 Poster","venue_id":"ICML.cc/2026/Workshop/GenBio","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2604.28181","versioned_id":"2604.28181v1","title":"Synthetic Computers at Scale for Long-Horizon Productivity Simulation","authors":["Tao Ge","Baolin Peng","Hao Cheng","Jianfeng Gao"],"abstract":"Realistic long-horizon productivity work is strongly conditioned on user-specific computer environments, where much of the work context is stored and organized through directory structures and content-rich artifacts. To scale synthetic data creation for such productivity scenarios, we introduce Synthetic Computers at Scale, a scalable methodology for creating such environments with realistic folder hierarchies and content-rich artifacts (e.g., documents, spreadsheets, and presentations). Conditioned on each synthetic computer, we run long-horizon simulations: one agent creates productivity objectives that are specific to the computer's user and require multiple professional deliverables and about a month of human work; another agent then acts as that user and keeps working across the computer -- for example, navigating the filesystem for grounding, coordinating with simulated collaborators, and producing professional artifacts -- until these objectives are completed. In preliminary experiments, we create 1,000 synthetic computers and run long-horizon simulations on them; each run requires over 8 hours of agent runtime and spans more than 2,000 turns on average. These simulations produce rich experiential learning signals, whose effectiveness is validated by significant improvements in agent performance on both in-domain and out-of-domain productivity evaluations. Given that personas are abundant at billion scale, this methodology can in principle scale to millions or even billions of synthetic user worlds with sufficient compute, enabling broader coverage of diverse professions, roles, contexts, environments, and productivity needs. We argue that scalable synthetic computer creation, together with at-scale simulations, is highly promising as a foundational substrate for agent self-improvement and agentic reinforcement learning in long-horizon productivity scenarios.","published":"2026-04-30T17:58:02Z","updated":"2026-04-30T17:58:02Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.28181v1","pdf_url":"https://arxiv.org/pdf/2604.28181v1","comment":"Preview version; work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.27934","versioned_id":"2604.27934v1","title":"MM-StanceDet: Retrieval-Augmented Multi-modal Multi-agent Stance Detection","authors":["Weihai Lu","Zhejun Zhao","Yanshu Li","Huan He"],"abstract":"Multimodal Stance Detection (MSD) is crucial for understanding public discourse, yet effectively fusing text and image, especially with conflicting signals, remains challenging. Existing methods often face difficulties with contextual grounding, cross-modal interpretation ambiguity, and single-pass reasoning fragility. To address these, we propose Retrieval-Augmented Multi-modal Multi-agent Stance Detection (MM-StanceDet), a novel multi-agent framework integrating Retrieval Augmentation for contextual grounding, specialized Multimodal Analysis agents for nuanced interpretation, a Reasoning-Enhanced Debate stage for exploring perspectives, and Self-Reflection for robust adjudication. Extensive experiments on five datasets demonstrate MM-StanceDet significantly outperforms state-of-the-art baselines, validating the efficacy of its multi-agent architecture and structured reasoning stages in addressing complex multimodal stance challenges.","published":"2026-04-30T14:34:18Z","updated":"2026-04-30T14:34:18Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.27934v1","pdf_url":"https://arxiv.org/pdf/2604.27934v1","comment":"Accepted on ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.27859","versioned_id":"2604.27859v3","title":"Rethinking Agentic Reinforcement Learning In Large Language Models","authors":["Fangming Cui","Ruixiao Zhu","Cheng Fang","Sunan Li","Jiahong Li"],"abstract":"Reinforcement Learning (RL) has traditionally focused on training specialized agents to optimize predefined reward functions within narrowly defined environments. However, the advent of powerful Large Language Models (LLMs) and increasingly complex, open-ended tasks has catalyzed a paradigm shift towards agentic paradigms within RL. This emerging framework extends beyond traditional RL by emphasizing the development of autonomous agents capable of goal-setting, long-term planning, dynamic strategy adaptation, and interactive reasoning in uncertain, real-world environments. Unlike conventional approaches that rely heavily on static objectives and episodic interactions, LLM-based Agentic RL incorporates cognitive-like capabilities such as meta-reasoning, self-reflection, and multi-step decision-making directly into the learning loop. In this paper, we provide a deep insight for looking the conceptual foundations, methodological innovations, and effective designs underlying this trend. Furthermore, we identify critical challenges and outline promising future directions for building LLM-based Agentic RL.","published":"2026-04-30T13:43:25Z","updated":"2026-05-15T06:25:17Z","categories":["cs.AI","cs.ET"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.27859v3","pdf_url":"https://arxiv.org/pdf/2604.27859v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.00914","versioned_id":"2605.00914v1","title":"The Cost of Consensus: Isolated Self-Correction Prevails Over Unguided Homogeneous Multi-Agent Debate","authors":["Blaž Bertalanič","Carolina Fortuna"],"abstract":"Multi-agent debate, where teams of LLMs iteratively exchange rationales and vote on answers, is widely deployed under the assumption that peer review filters hallucinations. Yet the failure dynamics of homogeneous debate remain poorly understood, therefore we report findings from a controlled empirical study of teams of $N{=}10$ homogeneous agents (Qwen2.5-7B, Llama-3.1-8B, Ministral-3-8B) across $R{=}3$ debate rounds on two high-difficulty benchmarks (GSM-Hard and MMLU-Hard). We compare peer debate against isolated self-correction and a stochastic noise control that injects rationales from unrelated problems. We decompose debate failure into three model-dependent pathways: sycophantic conformity, where agents uncritically adopt majority answers (modal adoption up to 85.5%); contextual fragility, where peer rationales destabilize previously correct reasoning (vulnerability rate up to 70.0%); and consensus collapse, where plurality voting discards correct answers already present in the generation pool (oracle gap up to 32.3 percentage points). Ablations over communication density ($K \\in \\{2,4,9\\}$) and sampling temperature ($T \\in \\{0.4, 0.7\\}$) show that conformity reaches high levels at minimal peer exposure ($K{=}2$) and intensifies with greater initial diversity. Across all configurations, debate consumes 2.1-3.4$\\times$ more tokens (up to 28,631 tokens per problem) than self-correction for equal or lower accuracy. Our results indicate that, within the 7-8B parameter class, homogeneous teams without structured roles do not benefit from unguided peer exchange, and that isolated self-correction consistently offers a more favorable cost-accuracy tradeoff.","published":"2026-04-29T14:33:57Z","updated":"2026-04-29T14:33:57Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2605.00914v1","pdf_url":"https://arxiv.org/pdf/2605.00914v1","comment":"19 pages, ACM Conference on AI and Agentic Systems","journal_ref":"","doi":"10.1145/3786335.3813137","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.26645","versioned_id":"2604.26645v2","title":"SciHorizon-DataEVA: An Agentic System for AI-Readiness Evaluation of Heterogeneous Scientific Data","authors":["Dianyu Liu","Chuan Qin","Xi Chen","Xiaohan Li","Wenxi Xu","Yuyang Wang","Xin Chen","Yuanchun Zhou","Hengshu Zhu"],"abstract":"AI-for-Science (AI4Science) is increasingly transforming scientific discovery by embedding machine learning models into prediction, simulation, and hypothesis generation workflows across domains. However, the effectiveness of these models is fundamentally constrained by the AI-readiness of scientific data, for which no scalable and systematic evaluation mechanism currently exists. In this work, we propose SciHorizon-DataEVA, a novel agentic system to scalable AI-readiness evaluation of heterogeneous scientific data. At the evaluation-criteria level, we introduce the Sci-TQA2 principles, which organize AI-readiness into four complementary dimensions: Governance Trustworthiness, Data Quality, AI Compatibility, and Scientific Adaptability. Each dimension is decomposed into measurable atomic elements that enable fine-grained and executable assessment. To operationalize these principles at scale, we develop Sci-TQA2-Eval, a hierarchical multi-agent evaluation approach orchestrated through a directed, cyclic workflow. Our Sci-TQA2-Eval dynamically constructs dataset-aware evaluation specifications by combining lightweight dataset profiling, applicability-aware metric activation, and knowledge-augmented planning grounded in domain constraints and dataset-paper signals. These specifications are executed through an adaptive, tool-centric evaluation mechanism with built-in verification and self-correction, enabling scalable and reliable assessment across heterogeneous scientific data. Extensive experiments on scientific datasets spanning multiple domains demonstrate the effectiveness and generality of SciHorizon-DataEVA for principled AI-readiness evaluation.","published":"2026-04-29T13:11:53Z","updated":"2026-05-28T14:48:42Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.26645v2","pdf_url":"https://arxiv.org/pdf/2604.26645v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:ShG5RihI9Q","versioned_id":"ShG5RihI9Q","title":"Plan, Edit, Refine: Joint RL Training of LLM Agents and Diffusion Editors","authors":["Xuan Qi"],"abstract":"Compositional text-to-image generation requires satisfying multiple attribute constraints simultaneously, a task that single-pass generation routinely fails on. Two recent lines of work address this from opposite ends: agentic iterative refinement trains only the language planner while freezing the image generator, and unified policy optimization trains language and visual generation components but in a single generation round. We present NEXUS, a work-in-progress framework combining both properties: iterative, multi-round refinement with joint RL training of both the LLM planner (Qwen2.5-7B) and the reference-conditioned diffusion editor (FLUX.1-Kontext-dev) via shared GRPO reward. A dual-channel Bridge routes continuous LLM hidden states and discrete text instructions to the editor's conditioning mechanism. Empirically, using three-seed means on the full 553-prompt GenEval prompt set scored with our Qwen-VQA compositional score rather than the official GenEval evaluator: (1) zero-shot Gemini with the same iterative refinement loop reaches 0.740 and serves as the matched baseline; (2) NEXUS full reaches 0.734 at step 50 and 0.780 at step 100, surpassing this matched Gemini baseline by +4.0 pp at step 100; and (3) planner-only and no-Bridge variants do not exceed the matched Gemini baseline at step 100, highlighting the importance of the full co-adaptive system.","published":"2026-04-29T12:00:46+00:00","updated":"2026-07-05T15:20:28+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ShG5RihI9Q","openreview_url":"https://openreview.net/forum?id=ShG5RihI9Q","pdf_url":"https://openreview.net/pdf?id=ShG5RihI9Q","comment":"SCALE@ICML2026 Poster","journal_ref":"SCALE@ICML2026 Poster","doi":"","venue":"SCALE@ICML2026 Poster","venue_id":"ICML.cc/2026/Workshop/SCALE","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:FcHLKlJkZl","versioned_id":"FcHLKlJkZl","title":"A Multi-Agent Pipeline for Source-Grounded Synthetic Note Generation from Longitudinal Structured EHR","authors":["Nina Fatehi","Reihaneh Hassanzadeh","Meysam Ghaffari","Animesh Agarwal","Carlos Morato"],"abstract":"Structured EHR is abundant but sparse, coded, and difficult to use directly for note-centric clinical modeling. We present MedNotes, a multi-agent synthetic data generation pipeline that converts longitudinal structured EHR into source-grounded clinical note representations under explicit quality control. MedNotes treats structured-data-to-text synthesis as a closed-loop agentic process: a generator proposes a note, evaluator agents diagnose factual, coverage, structural, and hallucination-related failures, and a router accepts, revises, or rejects the draft. On 1{,}485 EHRSHOT encounters, MedNotes achieves a 91.4\\% pass rate, with mean factual accuracy of 0.980, completeness of 99.1\\%, structural fidelity of 0.761, and 0.028 critical hallucinations per encounter. Iterative refinement improves acceptance from 69.4\\% to 91.4\\%. The resulting synthetic corpus improves downstream CPT prediction and paragraph-level section prediction when combined with limited real data.","published":"2026-04-28T23:00:19+00:00","updated":"2026-06-30T22:54:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=FcHLKlJkZl","openreview_url":"https://openreview.net/forum?id=FcHLKlJkZl","pdf_url":"https://openreview.net/pdf?id=FcHLKlJkZl","comment":"FMSD @ ICML 2026 Poster","journal_ref":"FMSD @ ICML 2026 Poster","doi":"","venue":"FMSD @ ICML 2026 Poster","venue_id":"ICML.cc/2026/Workshop/FMSD","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2604.25067","versioned_id":"2604.25067v2","title":"Frontier Coding Agents Can Now Implement an AlphaZero Self-Play Machine Learning Pipeline For Connect Four That Performs Comparably to an External Solver","authors":["Joshua Sherwood","Ben Aybar","Benjamin Kaplan"],"abstract":"Forecasting when AI systems will become capable of meaningfully accelerating AI research is a central challenge for AI safety. Existing benchmarks measure broad capability growth, but may not provide ample early warning signals for recursive self-improvement. We propose measuring AI's capability to autonomously implement end-to-end machine learning pipelines from past AI research breakthroughs, given a minimal task description. By providing a concise task description instead of the full prior work as reference, we hope to better elicit emerging AI research taste. We introduce a proof-of-concept benchmark in which frontier coding agents autonomously implement an AlphaZero-style machine learning pipeline for Connect Four on consumer hardware within a three-hour budget, and we evaluate the resulting game AIs in a round-robin tournament anchored to the Pascal Pons Connect Four solver. Across four agents with eight trials each, we find substantial differentiation: Claude Opus 4.7 won as first-mover against Pons in seven of eight trials, statistically significantly better than the other agents tested, none of which exceeded two of eight. The task, which no frontier agent could reliably complete when we began development in January of 2026, is now near-saturation. Our evaluation also surfaced anomalous behavior in GPT-5.4, which consistently used far less of its allocated time budget than other agents. A follow-up 16-trial probe using shorter, less evaluation-coded prompts substantially increased GPT-5.4's time-budget usage, consistent with but not diagnostic of sandbagging; Bradley-Terry ratings across probe conditions showed only directional differences, despite significant differences in time-budget usage. We release our data, code, and prompts to support reproduction and extension.","published":"2026-04-27T23:48:30Z","updated":"2026-04-29T00:38:29Z","categories":["cs.MA","cs.AI","cs.LG"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2604.25067v2","pdf_url":"https://arxiv.org/pdf/2604.25067v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.24842","versioned_id":"2604.24842v1","title":"Co-Director: Agentic Generative Video Storytelling","authors":["Yale Song","Yiwen Song","Nick Losier","Nathan Hodson","Ye Jin","Rhyard Zhu","Yan Xu","Daniel Vlasic","Carina Claassen","Jasmine Leon","Khanh G. LeViet","Zack Chomyn","Joe Timmons","Brett Slatkin","Scott Penberthy","Tomas Pfister"],"abstract":"While diffusion models generate high-fidelity video clips, transforming them into coherent storytelling engines remains challenging. Current agentic pipelines automate this via chained modules but suffer from semantic drift and cascading failures due to independent, handcrafted prompting. We present Co-Director, a hierarchical multi-agent framework formalizing video storytelling as a global optimization problem. To ensure semantic coherence, we introduce hierarchical parameterization: a multi-armed bandit globally identifies promising creative directions, while a local multimodal self-refinement loop mitigates identity drift and ensures sequence-level consistency. This balances the exploration of novel narrative strategies with the exploitation of effective creative configurations. For evaluation, we introduce GenAD-Bench, a 400-scenario dataset of fictional products for personalized advertising. Experiments demonstrate that Co-Director significantly outperforms state-of-the-art baselines, offering a principled approach that seamlessly generalizes to broader cinematic narratives. Project Page: https://co-director-agent.github.io/","published":"2026-04-27T18:00:00Z","updated":"2026-04-27T18:00:00Z","categories":["cs.AI","cs.MA","cs.MM"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.24842v1","pdf_url":"https://arxiv.org/pdf/2604.24842v1","comment":"Project Page: https://co-director-agent.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:sdl3Eh5vz8","versioned_id":"sdl3Eh5vz8","title":"ContextCov: Bridging the Gap Between Developer Intent and Autonomous Agent Execution","authors":["Reshabh K Sharma"],"abstract":"As Large Language Model (LLM) agents increasingly execute complex, autonomous software engineering tasks, developers rely on natural language instruction files such as AGENTS.md to express project-specific coding conventions, tooling restrictions, and architectural boundaries. However, because these instructions remain passive text, agents frequently exhibit what we term Context Drift, which includes deviations from repository constraints caused by context window saturation, hallucination, or conflicts with legacy code. In autonomous settings without real-time human supervision, such deviations rapidly compound into technical debt. To ground autonomous agents in repository constraints, we introduce ContextCov, a framework that transforms passive natural language instructions into executable guardrails. Unlike prompt-only or reflection-only compliance approaches, ContextCov compiles documented constraints into three complementary checks: static AST queries for code patterns, runtime shell shims that intercept prohibited commands, and architectural validators that enforce structural rules. Acting as an automated, continuous reviewer, ContextCov intercepts agent actions and returns immediate, reproducible violation traces, enabling self-correction before non-compliant changes are finalized. We evaluate ContextCov on SWE-Bench Lite (12 repositories, 300 tasks) through four research questions. For extraction accuracy (RQ1), we synthesize 788 executable checks from generated instruction files and achieve 82.81% precision on human-labeled violation samples. For enforcement effectiveness (RQ2), ContextCov achieves 88.3\\% oracle compliance versus 67.0% (vanilla) and 50.3% (self-reflection), using fewer feedback rounds (1.67 vs. 2.85 mean). For functional correctness (RQ3), ContextCov resolves 57.3% of issues versus 53.0% (vanilla) and 52.3% (self-reflection) with McNemar tests reject equal failure rates (p = 0.031, 0.046), demonstrating that strict enforcement improves rather than hinders task resolution. For overhead (RQ4), executable feedback reduces LLM input by 3x and feedback wall time by 5x, yielding 3.4x more resolutions per megacharacter than self-reflection. The source code and evaluation results are available at https://anonymous.4open.science/status/ContextCov-974E.","published":"2026-04-26T11:58:54+00:00","updated":"2026-06-16T11:59:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=sdl3Eh5vz8","openreview_url":"https://openreview.net/forum?id=sdl3Eh5vz8","pdf_url":"https://openreview.net/pdf?id=sdl3Eh5vz8","comment":"CAIS 2026 Workshop AgenticSE","journal_ref":"CAIS 2026 Workshop AgenticSE","doi":"","venue":"CAIS 2026 Workshop AgenticSE","venue_id":"ACM.org/CAIS/2026/Workshop/AgenticSE","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2604.23366","versioned_id":"2604.23366v1","title":"GSAR: Typed Grounding for Hallucination Detection and Recovery in Multi-Agent LLMs","authors":["Federico A. Kamelhar"],"abstract":"Autonomous multi-agent LLM systems are increasingly deployed to investigate operational incidents and produce structured diagnostic reports. Their trustworthiness hinges on whether each claim is grounded in observed evidence rather than model-internal inference. Existing groundedness evaluators (binary classifiers, LLM-as-judge scalars, self-correction loops) treat supporting evidence as interchangeable and emit a single signal that offers no principled control over downstream action. We present GSAR, a grounding-evaluation and replanning framework that (i) partitions claims into a four-way typology (grounded, ungrounded, contradicted, complementary), giving first-class standing to non-redundant alternative perspectives; (ii) assigns evidence-type-specific weights reflecting epistemic strength; (iii) computes an asymmetric contradiction-penalised weighted groundedness score; and (iv) couples that score to a three-tier decision function (proceed, regenerate, replan) driving a bounded-iteration outer loop under an explicit compute budget. We formalise the algorithm, prove six structural properties, and evaluate five design claims on FEVER with gold Wikipedia evidence under four independently-trained LLM judges (gpt-5.4, claude-sonnet-4-6, claude-opus-4-7, gemini-2.5-pro). Every ablation reproduces in the same direction on every judge: bootstrap 95% CIs on the rho=0 effect exclude 0 on all four; the no-complementary ablation under Opus 4.7 has CI [-96,-68] of 200; at n=1000 three independent judges converge to DeltaS(rho=0)=+0.058. A head-to-head against Vectara HHEM-2.1-Open is included. To our knowledge, GSAR is the first published groundedness framework coupling evidence-typed scoring with tiered recovery under an explicit compute budget.","published":"2026-04-25T16:20:28Z","updated":"2026-04-25T16:20:28Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.23366v1","pdf_url":"https://arxiv.org/pdf/2604.23366v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.23002","versioned_id":"2604.23002v1","title":"FormalScience: Scalable Human-in-the-Loop Autoformalisation of Science with Agentic Code Generation in Lean","authors":["Jordan Meadows","Lan Zhang","Andre Freitas"],"abstract":"Formalising informal mathematical reasoning into formally verifiable code is a significant challenge for large language models. In scientific fields such as physics, domain-specific machinery (\\textit{e.g.} Dirac notation, vector calculus) imposes additional formalisation challenges that modern LLMs and agentic approaches have yet to tackle. To aid autoformalisation in scientific domains, we present FormalScience; a domain-agnostic human-in-the-loop agentic pipeline that enables a single domain expert (without deep formal language experience) to produce \\textit{syntactically correct} and \\textit{semantically aligned} formal proofs of informal reasoning for low economic cost. Applying FormalScience to physics, we construct FormalPhysics, a dataset of 200 university-level (LaTeX) physics problems and solutions (primarily quantum mechanics and electromagnetism), along with their Lean4 formal representations. Compared to existing formal math benchmarks, FormalPhysics achieves perfect formal validity and exhibits greater statement complexity. We evaluate open-source models and proprietary systems on a statement autoformalisation task on our dataset via zero-shot prompting, self-refinement with error feedback, and a novel multi-stage agentic approach, and explore autoformalisation limitations in modern LLM-based approaches. We provide the first systematic characterisation of semantic drift in physics autoformalisation in terms of concepts such as notational collapse and abstraction elevation which reveals what formal language verifies when full semantic preservation is unattainable. We release the codebase together with an interactive UI-based FormalScience system which facilitates autoformalisation and theorem proving in scientific domains beyond physics.https://github.com/jmeadows17/formal-science","published":"2026-04-24T20:47:22Z","updated":"2026-04-24T20:47:22Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.23002v1","pdf_url":"https://arxiv.org/pdf/2604.23002v1","comment":"ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.22446","versioned_id":"2604.22446v1","title":"From Skills to Talent: Organising Heterogeneous Agents as a Real-World Company","authors":["Zhengxu Yu","Yu Fu","Zhiyuan He","Yuxuan Huang","Lee Ka Yiu","Meng Fang","Weilin Luo","Jun Wang"],"abstract":"Individual agent capabilities have advanced rapidly through modular skills and tool integrations, yet multi-agent systems remain constrained by fixed team structures, tightly coupled coordination logic, and session-bound learning. We argue that this reflects a deeper absence: a principled organisational layer that governs how a workforce of agents is assembled, governed, and improved over time, decoupled from what individual agents know. To fill this gap, we introduce \\emph{OneManCompany (OMC)}, a framework that elevates multi-agent systems to the organisational level. OMC encapsulates skills, tools, and runtime configurations into portable agent identities called \\emph{Talents}, orchestrated through typed organisational interfaces that abstract over heterogeneous backends. A community-driven \\emph{Talent Market} enables on-demand recruitment, allowing the organisation to close capability gaps and reconfigure itself dynamically during execution. Organisational decision-making is operationalised through an \\emph{Explore-Execute-Review} ($\\text{E}^2$R) tree search, which unifies planning, execution, and evaluation in a single hierarchical loop: tasks are decomposed top-down into accountable units and execution outcomes are aggregated bottom-up to drive systematic review and refinement. This loop provides formal guarantees on termination and deadlock freedom while mirroring the feedback mechanisms of human enterprises. Together, these contributions transform multi-agent systems from static, pre-configured pipelines into self-organising and self-improving AI organisations capable of adapting to open-ended tasks across diverse domains. Empirical evaluation on PRDBench shows that OMC achieves an $84.67\\%$ success rate, surpassing the state of the art by $15.48$ percentage points, with cross-domain case studies further demonstrating its generality.","published":"2026-04-24T11:02:44Z","updated":"2026-04-24T11:02:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.22446v1","pdf_url":"https://arxiv.org/pdf/2604.22446v1","comment":"33 pages,13 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.22273","versioned_id":"2604.22273v2","title":"Self-Correction as Feedback Control: Error Dynamics, Stability Thresholds, and Prompt Interventions in LLMs","authors":["Aofan Liu","Jingxiang Meng"],"abstract":"Iterative self-correction is increasingly deployed in agentic LLM systems, yet whether repeated refinement improves or degrades performance remains inconsistent across models. We recast self-correction as a closed-loop feedback-control problem in which the same model is both controller and plant, and analyze its error dynamics via a two-state Markov model over {Correct, Incorrect}, parameterized by the Error Introduction Rate (EIR) and Error Correction Rate (ECR). The model yields a directly measurable stability threshold -- iterate only when ECR/EIR > Acc/(1-Acc) -- in which EIR acts as a stability margin and prompting becomes lightweight controller design. Empirically, across 7 models and 3 datasets (GSM8K, MATH, StrategyQA), a sharp near-zero EIR boundary (< 0.5%) cleanly separates beneficial from harmful self-correction: only o3-mini (+3.4 pp), Claude Opus 4.6 (+0.6 pp), and o4-mini (+/-0 pp) stay non-degrading, while GPT-5 and four others lose accuracy. A verify-first prompt intervention then provides causal evidence: it drives GPT-4o-mini's EIR from 2% to 0% and converts a -6.2 pp degradation into +0.2 pp (paired McNemar, p<10^{-4}), with negligible change on already-sub-threshold models -- exactly as the diagnostic predicts. A complementary analysis of adaptive self-consistency (ASC) shows it halts harmful refinement at a 3.8 pp confidence-elicitation cost, exposing a two-tier capability structure: prompt-level EIR suppression prevents degradation, whereas ECR enhancement -- plausibly training-level -- is required for genuine gains. Self-correction should thus be treated not as a default behavior but as a control decision governed by measurable error dynamics.","published":"2026-04-24T06:34:40Z","updated":"2026-05-04T04:09:58Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.22273v2","pdf_url":"https://arxiv.org/pdf/2604.22273v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.21725","versioned_id":"2604.21725v1","title":"AEL: Agent Evolving Learning for Open-Ended Environments","authors":["Wujiang Xu","Jiaojiao Han","Minghao Guo","Kai Mei","Xi Zhu","Han Zhang","Dimitris N. Metaxas"],"abstract":"LLM agents increasingly operate in open-ended environments spanning hundreds of sequential episodes, yet they remain largely stateless: each task is solved from scratch without converting past experience into better future behavior. The central obstacle is not \\emph{what} to remember but \\emph{how to use} what has been remembered, including which retrieval policy to apply, how to interpret prior outcomes, and when the current strategy itself must change. We introduce \\emph{Agent Evolving Learning} (\\ael{}), a two-timescale framework that addresses this obstacle. At the fast timescale, a Thompson Sampling bandit learns which memory retrieval policy to apply at each episode; at the slow timescale, LLM-driven reflection diagnoses failure patterns and injects causal insights into the agent's decision prompt, giving it an interpretive frame for the evidence it retrieves. On a sequential portfolio benchmark (10 sector-diverse tickers, 208 episodes, 5 random seeds), \\ael{} achieves a Sharpe ratio of 2.13$\\pm$0.47, outperforming five published self-improving methods and all non-LLM baselines while maintaining the lowest variance among all LLM-based approaches. A nine-variant ablation reveals a ``less is more'' pattern: memory and reflection together produce a 58\\% cumulative improvement over the stateless baseline, yet every additional mechanism we test (planner evolution, per-tool selection, cold-start initialization, skill extraction, and three credit assignment methods) \\emph{degrades} performance. This demonstrates that the bottleneck in agent self-improvement is \\emph{self-diagnosing how to use} experience rather than adding architectural complexity. Code and data: https://github.com/WujiangXu/AEL.","published":"2026-04-23T14:29:25Z","updated":"2026-04-23T14:29:25Z","categories":["cs.CL","cs.AI","cs.CE"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.21725v1","pdf_url":"https://arxiv.org/pdf/2604.21725v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=dtPo105y8x","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2604.21598","versioned_id":"2604.21598v2","title":"You Don't Need Public Tests to Generate Correct Code","authors":["Kaushitha Silva","Srinath Perera"],"abstract":"Multi-agent systems are frequently employed for autonomous code generation, demonstrating strong utility in complex algorithmic problem-solving. Recent studies tackle the difficulty of producing functionally correct programs by leveraging simulation-guided planning and debugging, wherein language models step through execution traces to validate logic. Nevertheless, these methods rely heavily on human-authored public test cases to anchor the simulation and debugging cycles. Hand-crafting exhaustive input-output pairs creates a significant, labor-intensive bottleneck within the software development lifecycle. Since ground-truth examples are seldom accessible before actual implementation in real-world scenarios, this reliance limits existing approaches primarily to curated competitive programming datasets. Additionally, we demonstrate that depending on these public tests creates an \"overconfidence gap,\" leading frameworks to overfit to basic examples and underperform on hidden test suites. Conversely, we note that external input samples are not an absolute requirement for successful code generation. We show that large language models possess the capability to autonomously construct valid inputs and simulate execution flows for self-correction. Building on this, we introduce DryRUN, a framework that removes the necessity for ground-truth data by enabling the LLM to iteratively plan, synthesize its own test inputs, and run simulated executions, thereby mitigating algorithmic overconfidence. Assessments using the LiveCodeBench v6 dataset (post-March 2025) reveal that DryRUN achieves comparable performance to CodeSIM, a state-of-the-art, test-dependent baseline. Notably, it does so entirely without public tests or external execution signals, all while decreasing overall output token usage.","published":"2026-04-23T12:21:03Z","updated":"2026-04-28T05:10:28Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.21598v2","pdf_url":"https://arxiv.org/pdf/2604.21598v2","comment":"9 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.20714","versioned_id":"2604.20714v1","title":"Learning to Evolve: A Self-Improving Framework for Multi-Agent Systems via Textual Parameter Graph Optimization","authors":["Shan He","Runze Wang","Zhuoyun Du","Huiyu Bai","Zouying Cao","Yu Cheng","Bo Zheng"],"abstract":"Designing and optimizing multi-agent systems (MAS) is a complex, labor-intensive process of \"Agent Engineering.\" Existing automatic optimization methods, primarily focused on flat prompt tuning, lack the structural awareness to debug the intricate web of interactions in MAS. More critically, these optimizers are static; they do not learn from experience to improve their own optimization strategies. To address these gaps, we introduce Textual Parameter Graph Optimization (TPGO), a framework that enables a multi-agent system to learn to evolve. TPGO first models the MAS as a Textual Parameter Graph (TPG), where agents, tools, and workflows are modular, optimizable nodes. To guide evolution, we derive \"textual gradients,\" structured natural language feedback from execution traces, to pinpoint failures and suggest granular modifications. The core of our framework is Group Relative Agent Optimization (GRAO), a novel meta-learning strategy that learns from historical optimization experiences. By analyzing past successes and failures, GRAO becomes progressively better at proposing effective updates, allowing the system to learn how to optimize itself. Extensive experiments on complex benchmarks like GAIA and MCP-Universe show that TPGO significantly enhances the performance of state-of-the-art agent frameworks, achieving higher success rates through automated, self-improving optimization.","published":"2026-04-22T16:00:46Z","updated":"2026-04-22T16:00:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.20714v1","pdf_url":"https://arxiv.org/pdf/2604.20714v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:cbXXOzuTuO","versioned_id":"cbXXOzuTuO","title":"ReflectiChain: Epistemic Grounding in LLM-Driven World Models for Supply Chain Resilience","authors":["Jia Luo"],"abstract":"Global supply chains operating under geopolitical volatility expose both the semantic deficits of traditional Operations Research and Reinforcement Learning (OR/RL) and the physical ungroundedness of pure Large Language Models (LLMs). To address these limitations, we introduce ReflectiChain, an agentic framework that utilizes a Generative Supply Chain World Model (SC-WM) for resilience planning, formulated within a Constrained Partially Observable Markov Decision Process (C-POMDP) framework. By leveraging a topology-aware latent dynamics model, the agent performs multi-step \"mental rehearsals\" to evaluate candidate strategies. Crucially, the framework incorporates a Double-Loop Learning mechanism that couples test-time reflection-in-action with retrospective reflection-on-action via LoRA updates, enabling autonomous self-evolution of the policy. Validated on the multi-agent Semi-Sim benchmark under adversarial policy shocks, ReflectiChain achieves a Pareto-optimal balance across compliance, resilience, and profitability. The system maintains an 82.3% operability ratio under extreme pressure, demonstrating that latent rehearsal is fundamental for approximating Nash Equilibria in complex, non-stationary networks.","published":"2026-04-22T12:06:49+00:00","updated":"2026-06-26T14:00:03+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=cbXXOzuTuO","openreview_url":"https://openreview.net/forum?id=cbXXOzuTuO","pdf_url":"https://openreview.net/pdf?id=cbXXOzuTuO","comment":"ICML 2026 Workshop AgenticUQ Poster","journal_ref":"ICML 2026 Workshop AgenticUQ Poster","doi":"","venue":"ICML 2026 Workshop AgenticUQ Poster","venue_id":"ICML.cc/2026/Workshop/AgenticUQ","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:RyX98G24rP","versioned_id":"RyX98G24rP","title":"Propose, Critique, Falsify: Benchmarking Self-Verifying AI Scientists","authors":["Aayam Bansal","Ishaan Gangwani"],"abstract":"AI systems that autonomously generate scientific hypotheses are proliferating, yet the verification of their claims remains largely unexamined. We introduce a Propose-Critique-Falsify (PCF) benchmark that evaluates whether multi-agent pipelines can reduce the false discovery rate of AI-generated scientific claims. Across three evaluation domains (biomedical claim verification, synthetic statistical experiments, and scientific novelty assessment) and five frontier-class language models, we find that PCF pipelines dramatically increase false negatives through a mechanism we term conservatism-as-abstention: models emit Uncertain verdicts rather than risk incorrect classifications, rendering the false discovery rate undefined in many conditions. Critically, the direction of this error is model-dependent. Claude Sonnet 4 and GPT-4o become over-conservative under PCF, while GPT-5.4 becomes over-permissive (FDR = 0.75), labeling nearly all claims as valid. We further confirm that iterative self-refinement consistently increases false discovery rates across all models tested. Our results reveal that multi-agent verification architectures introduce systematic, model-specific biases that cannot be resolved through pipeline design alone.","published":"2026-04-21T22:00:16+00:00","updated":"2026-05-30T16:23:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=RyX98G24rP","openreview_url":"https://openreview.net/forum?id=RyX98G24rP","pdf_url":"https://openreview.net/pdf?id=RyX98G24rP","comment":"ICML2026-AI4Science Spotlight","journal_ref":"ICML2026-AI4Science Spotlight","doi":"","venue":"ICML2026-AI4Science Spotlight","venue_id":"ICML.cc/2026/Workshop/AI4Science","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2604.19548","versioned_id":"2604.19548v1","title":"Taming Actor-Observer Asymmetry in Agents via Dialectical Alignment","authors":["Bobo Li","Rui Wu","Zibo Ji","Meishan Zhang","Hao Fei","Min Zhang","Mong-Li Lee","Wynne Hsu"],"abstract":"Large Language Model agents have rapidly evolved from static text generators into dynamic systems capable of executing complex autonomous workflows. To enhance reliability, multi-agent frameworks assigning specialized roles are increasingly adopted to enable self-reflection and mutual auditing. While such role-playing effectively leverages domain expert knowledge, we find it simultaneously induces a human-like cognitive bias known as Actor-Observer Asymmetry (AOA). Specifically, an agent acting as an actor (during self-reflection) tends to attribute failures to external factors, whereas an observer (during mutual auditing) attributes the same errors to internal faults. We quantify this using our new Ambiguous Failure Benchmark, which reveals that simply swapping perspectives triggers the AOA effect in over 20% of cases for most models. To tame this bias, we introduce ReTAS (Reasoning via Thesis-Antithesis-Synthesis), a model trained through dialectical alignment to enforce perspective-invariant reasoning. By integrating dialectical chain-of-thought with Group Relative Policy Optimization, ReTAS guides agents to synthesize conflicting viewpoints into an objective consensus. Experiments demonstrate that ReTAS effectively mitigates attribution inconsistency and significantly improves fault resolution rates in ambiguous scenarios.","published":"2026-04-21T15:05:58Z","updated":"2026-04-21T15:05:58Z","categories":["cs.CL","cs.AI","cs.CY"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.19548v1","pdf_url":"https://arxiv.org/pdf/2604.19548v1","comment":"ACL 2026 Main Conference. Project page: https://unikcc.github.io/ReTAS/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:T97MrGUNkZ","versioned_id":"T97MrGUNkZ","title":"Vector Memory and Role-Conditioned Multi-Agent Systems: Two Extensions to Improve Reflexion for Language Model Self-Improvement","authors":[],"abstract":"REFLEXION improves language model performance through verbal self-reflection, but two design choices limit its reach. Its memory is a recency-ordered sliding window that evicts old reflections as new ones arrive, regardless of which are actually relevant. Moreover, a single model simultaneously generates a solution, critiques it, and plans the next attempt, roles that genuinely benefit from separation. In this paper, we address both of these limitations. We replace the sliding window with vector episodic memory, which stores Sentence-BERT embeddings alongside each reflection and retrieves them based on cosine similarity rather than recency. We also split the single Agent into a Generator, a Critic, and a Verifier, each of which draws on a shared role-conditioned memory pool. The results are quite encouraging. In a controlled benchmark in which 9 distractor tasks bury the relevant memories, temporal memory fails at the task level (0\\% Session-5 task success; dependency recall is 50\\%, reflecting partial buffer retention that is nonetheless insufficient when both Session-1 learnings are required simultaneously, see Remark~5.1). Vector memory succeeds in all 3 independent trials on this diagnostic setup (100\\% Session-5 task success), at a constant ${\\sim}14$~ms overhead that stays flat up to 50{,}000 stored reflections. This result comes from a controlled synthetic benchmark specifically designed to stress-test FIFO eviction; on the natural HumanEval coding benchmark, the gain is more modest (+3.7~pp, $p=0.033$, $d=0.127$), consistent with the independence of HumanEval tasks. On 164 HumanEval coding tasks with Google Gemini~2.5 Flash, the vector extension reaches $Pass@3 = 92.7\\%$ (+3.7~pp, $p=0.033$, $d=0.127$), and the multi-agent system reaches $Pass@3 = 96.3\\%$ (+7.9~pp, $p<0.001$, $d=0.301$) with $Pass@1 = 93.9\\%$ (+12.2~pp over the modular baseline), a first-attempt gain that predates any reflection at all. Our results suggest that semantic retrieval is particularly important when tasks are correlated across sessions, while role separation provides the greatest benefit on independent code-generation tasks.","published":"2026-04-21T12:51:09+00:00","updated":"2026-07-17T14:33:48+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=T97MrGUNkZ","openreview_url":"https://openreview.net/forum?id=T97MrGUNkZ","pdf_url":"https://openreview.net/pdf?id=T97MrGUNkZ","comment":"Under review for TMLR","journal_ref":"Under review for TMLR","doi":"","venue":"Under review for TMLR","venue_id":"TMLR/Under_Review","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2604.18364","versioned_id":"2604.18364v1","title":"Training and Agentic Inference Strategies for LLM-based Manim Animation Generation","authors":["Ravidu Suien Rammuni Silva","Ahmad Lotfi","Isibor Kennedy Ihianle","Golnaz Shahtahmassebi","Jordan J. Bird"],"abstract":"Generating programmatic animation using libraries such as Manim presents unique challenges for Large Language Models (LLMs), requiring spatial reasoning, temporal sequencing, and familiarity with domain-specific APIs that are underrepresented in general pre-training data. A systematic study of how training and inference strategies interact in this setting is lacking in current research. This study introduces ManimTrainer, a training pipeline that combines Supervised Fine-tuning (SFT) with Reinforcement Learning (RL) based Group Relative Policy Optimisation (GRPO) using a unified reward signal that fuses code and visual assessment signals, and ManimAgent, an inference pipeline featuring Renderer-in-the-loop (RITL) and API documentation-augmented RITL (RITL-DOC) strategies. Using these techniques, this study presents the first unified training and inference study for text-to-code-to-video transformation with Manim. It evaluates 17 open-source sub-30B LLMs across nine combinations of training and inference strategies using ManimBench. Results show that SFT generally improves code quality, while GRPO enhances visual outputs and increases the models' responsiveness to extrinsic signals during self-correction at inference time. The Qwen 3 Coder 30B model with GRPO and RITL-DOC achieved the highest overall performance, with a 94% Render Success Rate (RSR) and 85.7% Visual Similarity (VS) to reference videos, surpassing the baseline GPT-4.1 model by +3 percentage points in VS. Additionally, the analysis shows that the correlation between code and visual metrics strengthens with SFT and GRPO but weakens with inference-time enhancements, highlighting the complementary roles of training and agentic inference strategies in Manim animation generation.","published":"2026-04-20T14:54:06Z","updated":"2026-04-20T14:54:06Z","categories":["cs.AI","cs.GR","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.18364v1","pdf_url":"https://arxiv.org/pdf/2604.18364v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:GvyXc6bCSs","versioned_id":"GvyXc6bCSs","title":"Does Verbal Self-Reflection Transfer to Long-Horizon Scientific Discovery?","authors":["Wei Yong Tan","Ivor Tsang","Hangwei Qian"],"abstract":"Autonomous scientific discovery agents face reasoning challenges that depart from those in standard LLM agent benchmarks: experimental campaigns span long horizons with many reasoning steps per decision, feedback is continuous rather than binary, and success requires navigating an exploration–exploitation tradeoff over high-dimensional spaces. A natural question is whether such agents can improve across successive campaigns by learning from their own trajectories. Using the MADE benchmark for closed-loop materials discovery as a case study, we instantiate a ReAct agent with episodic self-reflection and evaluate Qwen3-30B-Instruct and Qwen3.5-122B across 30 chemical systems and 8 episodes each. We find that reflection substantially improves per-episode discovery yield ($+4.6$ and $+6.5$ novel stable materials per episode, respectively), with positive cross-episode learning slopes indicating that the gains are attributable to episodic memory rather than stochasticity. However, self-reflection acts as a double-edged sword: it consistently shifts agent behaviour from breadth to depth, concentrating queries on near-hull families at the cost of compositional coverage, risking premature exploitation on sparser search spaces (a regime we do not test directly). We identify recurring failure modes such as actor non-compliance and discuss their implications for scientific discovery agents more broadly.","published":"2026-04-20T01:13:08+00:00","updated":"2026-07-01T03:08:19+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=GvyXc6bCSs","openreview_url":"https://openreview.net/forum?id=GvyXc6bCSs","pdf_url":"https://openreview.net/pdf?id=GvyXc6bCSs","comment":"ICML2026-AI4Science Poster","journal_ref":"ICML2026-AI4Science Poster","doi":"","venue":"ICML2026-AI4Science Poster","venue_id":"ICML.cc/2026/Workshop/AI4Science","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2604.17658","versioned_id":"2604.17658v1","title":"Towards Self-Improving Error Diagnosis in Multi-Agent Systems","authors":["Jiazheng Li","Emine Yilmaz","Bei Chen","Dieu-Thu Le"],"abstract":"Large Language Model (LLM)-based Multi-Agent Systems (MAS) enable complex problem-solving but introduce significant debugging challenges, characterized by long interaction traces, inter-agent dependencies, and delayed error manifestation. Existing diagnostic approaches often rely on expensive expert annotation or ''LLM-as-a-judge'' paradigms, which struggle to pinpoint decisive error steps within extended contexts. In this paper, we introduce ErrorProbe, a self-improving framework for semantic failure attribution that identifies responsible agents and the originating error step. The framework operates via a three-stage pipeline: (1) operationalizing the MAS failure taxonomy to detect local anomalies, (2) performing symptom-driven backward tracing to prune irrelevant context, and (3) employing a specialized multi-agent team (Strategist, Investigator, Arbiter) to validate error hypotheses through tool-grounded execution. Crucially, ErrorProbe maintains a verified episodic memory that updates only when error patterns are confirmed by executable evidence, without the need for annotation. Experiments across the TracerTraj and Who&When benchmarks demonstrate that ErrorProbe significantly outperforms baselines, particularly in step-level localization, while the verified memory enables robust cross-domain transfer without retraining.","published":"2026-04-19T23:13:05Z","updated":"2026-04-19T23:13:05Z","categories":["cs.MA","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2604.17658v1","pdf_url":"https://arxiv.org/pdf/2604.17658v1","comment":"15 pages, 3 figures; accepted at ACL 2026 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:z8YRUCUwis","versioned_id":"z8YRUCUwis","title":"GeoVista: Web-augmented Agentic Visual Reasoning","authors":["Yikun Wang","Zuyan Liu","Ziyi Wang","Shijie Xia","Han Hu","Pengfei Liu","Yongming Rao"],"abstract":"Agentic visual reasoning has advanced multimodal understanding through multi-step tool use, yet current methods restrict these tools to image manipulation and never reach for external knowledge, leaving open-source models brittle on tasks that require both. We study this setting through geolocalization, a task that inherently couples fine-grained visual inspection with open-world knowledge retrieval. We introduce \\textbf{GeoVista}, a 7B agentic model that interleaves image zoom-in and web-search tool calls within a reasoning loop, and, to move beyond the low resolution of prior geolocalization benchmarks, curate \\textbf{GeoBench}, a benchmark of high-resolution photos, panoramas, and satellite imagery whose geographic cues are only resolvable through fine-grained visual search. We train GeoVista in two stages: a cold-start SFT on synthesized agentic trajectories to instill the tool-use format, followed by RL with \\textbf{CasPO} (Cascaded Policy Optimization). Instead of treating each prediction as a pass-or-fail event, CasPO cascades credit along the country, province, and city hierarchy, yielding a dense, multi-scale learning signal. Beyond accuracy, CasPO reshapes reasoning behavior: fewer tool-call errors, more targeted searches, and emergent self-reflection. GeoVista achieves state-of-the-art among open-source models and matches proprietary systems such as Gemini-2.5-flash and GPT-5 across most metrics, despite being an order of magnitude smaller.","published":"2026-04-19T12:25:27+00:00","updated":"2026-07-05T15:20:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=z8YRUCUwis","openreview_url":"https://openreview.net/forum?id=z8YRUCUwis","pdf_url":"https://openreview.net/pdf?id=z8YRUCUwis","comment":"SCALE@ICML2026 Poster","journal_ref":"SCALE@ICML2026 Poster","doi":"","venue":"SCALE@ICML2026 Poster","venue_id":"ICML.cc/2026/Workshop/SCALE","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2604.17025","versioned_id":"2604.17025v3","title":"Harness as an Asset: Enforcing Determinism via the Convergent AI Agent Framework (CAAF)","authors":["Tianbao Zhang"],"abstract":"Large Language Models produce a controllability gap in safety-critical engineering: even low rates of undetected constraint violations render a system undeployable. Current orchestration paradigms suffer from sycophantic compliance, context attention decay, and stochastic oscillation during self-correction. We introduce the Convergent AI Agent Framework (CAAF), which transitions agentic workflows from open-loop generation to closed-loop fail-safe determinism via three pillars: (1) Recursive Atomic Decomposition with physical context firewalls; (2) Harness as an Asset, formalizing domain invariants into machine-readable registries enforced by a deterministic Unified Assertion Interface; and (3) Structured Semantic Gradients with State Locking for monotonic non-regression. This paper makes two core claims. First, an industrialization thesis: once domain invariants are formalized as an executable Harness, the Harness itself becomes a first-class enterprise asset that compounds in value as foundation models commoditize, and CAAF's ability to deliver its reliability on commodity-tier models makes fully self-hosted, on-premises deployment architecturally feasible for regulated sectors where cloud APIs are not an option. Second, an architectural claim supported by ablation: CAAF's three pillars address complementary failure surfaces and none alone closes the controllability gap at commodity cost. The paper contributes entirely at the orchestration and industrialization layer. Evidence across two complementary benchmarks, three-tier UAI ablations, multi-agent baselines, and a closed-source commodity family replicated by two independent open-weight families, is reported in the body.","published":"2026-04-18T15:15:09Z","updated":"2026-05-04T07:24:42Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.17025v3","pdf_url":"https://arxiv.org/pdf/2604.17025v3","comment":"47 pages, 13 figures. Code: https://github.com/TianbaoZhang001/OpenCAAF (Apache-2.0)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.16778","versioned_id":"2604.16778v2","title":"Federation over Text: Insight Sharing for Multi-Agent Reasoning","authors":["Dixi Yao","Tahseen Rabbani","Manzil Zaheer","Tian Li"],"abstract":"We propose a federated learning-like framework, Federation over Text (FoT), that enables multiple clients solving different tasks to collectively generate a shared library of metacognitive insights by iteratively federating their local reasoning processes without sharing actual problem instances or task instructions. Instead of federation over gradients (e.g., as in distributed training), FoT operates at the semantic level without any gradient optimization or supervision signal. Iteratively, each client runs an LLM agent that does local thinking and self-improvement on their specific tasks independently, and shares reasoning traces with a central server, which aggregates and distills them into a cross-task (and cross-domain) insight library that existing and future agents can leverage to improve performance on related tasks. Experiments show that FoT improves reasoning effectiveness and efficiency across a wide range of challenging applications, including mathematical problem solving, cross-domain collaboration, real-world daily tasks, and machine learning research insight discovery. Specifically, it improves average performance scores by 25% while reducing the reasoning tokens by 4% across the first three applications. In the research insight discovery application, FoT is able to generate insights that cover over 80% of the major contributions in the subsequent papers.","published":"2026-04-18T01:57:42Z","updated":"2026-05-23T18:12:27Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2604.16778v2","pdf_url":"https://arxiv.org/pdf/2604.16778v2","comment":"46 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=uKO2yH7QZx","openreview_venues":["AgentSkills 2026 Poster"]},{"id":"2604.16625","versioned_id":"2604.16625v1","title":"AdaExplore: Failure-Driven Adaptation and Diversity-Preserving Search for Efficient Kernel Generation","authors":["Weihua Du","Jingming Zhuo","Yixin Dong","Andre Wang He","Weiwei Sun","Zeyu Zheng","Manupa Karunaratne","Ivan Fox","Tim Dettmers","Tianqi Chen","Yiming Yang","Sean Welleck"],"abstract":"Recent large language model (LLM) agents have shown promise in using execution feedback for test-time adaptation. However, robust self-improvement remains far from solved: most approaches still treat each problem instance independently, without accumulating reusable knowledge. This limitation is particularly pronounced in domain-specific languages such as Triton, which are underrepresented in LLM pretraining data. Their strict constraints and non-linear optimization landscape further make naive generation and local refinement unreliable. We propose AdaExplore, an agent framework that enables self-improvement via accumulated execution feedback for performance-critical kernel code generation through two complementary stages: failure-driven adaptation and diversity-preserving search, jointly improving correctness and optimization performance without additional fine-tuning or external knowledge. In the adaptation stage, the agent synthesizes tasks and converts recurring failures into a reusable memory of validity rules, helping subsequent generations remain within the feasible set. In the search stage, the agent organizes candidate kernels as a tree and alternates between small local refinements and larger structural regeneration, allowing it to explore the optimization landscape beyond local optima. Experiments on kernel runtime optimization benchmarks validate these gains: AdaExplore achieves 3.12x and 1.72x speedups on KernelBench Level-2 and Level-3, respectively, within 100 steps, and continues to improve with additional computation.","published":"2026-04-17T18:25:03Z","updated":"2026-04-17T18:25:03Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.16625v1","pdf_url":"https://arxiv.org/pdf/2604.16625v1","comment":"Preliminary work. The implementation is available at https://github.com/StigLidu/AdaExplore","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.15839","versioned_id":"2604.15839v1","title":"Discover and Prove: An Open-source Agentic Framework for Hard Mode Automated Theorem Proving in Lean 4","authors":["Chengwu Liu","Yichun Yin","Ye Yuan","Jiaxuan Xie","Botao Li","Siqi Li","Jianhao Shen","Yan Xu","Lifeng Shang","Ming Zhang"],"abstract":"Most ATP benchmarks embed the final answer within the formal statement -- a convention we call \"Easy Mode\" -- a design that simplifies the task relative to what human competitors face and may lead to optimistic estimates of model capability. We call the stricter, more realistic setting \"Hard Mode\": the system must independently discover the answer before constructing a formal proof. To enable Hard Mode research, we make two contributions. First, we release MiniF2F-Hard and FIMO-Hard, expert-reannotated Hard Mode variants of two widely-used ATP benchmarks. Second, we introduce Discover And Prove (DAP), an agentic framework that uses LLM natural-language reasoning with explicit self-reflection to discover answers, then rewrites Hard Mode statements into Easy Mode ones for existing ATP provers. DAP sets the state of the art: on CombiBench it raises solved problems from 7 (previous SOTA, Pass@16) to 10; on PutnamBench it is the first system to formally prove 36 theorems in Hard Mode -- while simultaneously revealing that state-of-the-art LLMs exceed 80% answer accuracy on the same problems where formal provers manage under 10%, exposing a substantial gap that Hard Mode benchmarks are uniquely suited to measure.","published":"2026-04-17T08:40:48Z","updated":"2026-04-17T08:40:48Z","categories":["cs.AI","cs.CL","cs.LO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.15839v1","pdf_url":"https://arxiv.org/pdf/2604.15839v1","comment":"ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.15309","versioned_id":"2604.15309v1","title":"MM-WebAgent: A Hierarchical Multimodal Web Agent for Webpage Generation","authors":["Yan Li","Zezi Zeng","Yifan Yang","Yuqing Yang","Ning Liao","Weiwei Guo","Lili Qiu","Mingxi Cheng","Qi Dai","Zhendong Wang","Zhengyuan Yang","Xue Yang","Ji Li","Lijuan Wang","Chong Luo"],"abstract":"The rapid progress of Artificial Intelligence Generated Content (AIGC) tools enables images, videos, and visualizations to be created on demand for webpage design, offering a flexible and increasingly adopted paradigm for modern UI/UX. However, directly integrating such tools into automated webpage generation often leads to style inconsistency and poor global coherence, as elements are generated in isolation. We propose MM-WebAgent, a hierarchical agentic framework for multimodal webpage generation that coordinates AIGC-based element generation through hierarchical planning and iterative self-reflection. MM-WebAgent jointly optimizes global layout, local multimodal content, and their integration, producing coherent and visually consistent webpages. We further introduce a benchmark for multimodal webpage generation and a multi-level evaluation protocol for systematic assessment. Experiments demonstrate that MM-WebAgent outperforms code-generation and agent-based baselines, especially on multimodal element generation and integration. Code & Data: https://aka.ms/mm-webagent.","published":"2026-04-16T17:59:49Z","updated":"2026-04-16T17:59:49Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.15309v1","pdf_url":"https://arxiv.org/pdf/2604.15309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.15082","versioned_id":"2604.15082v1","title":"Autonomous Evolution of EDA Tools: Multi-Agent Self-Evolved ABC","authors":["Cunxi Yu","Haoxing Ren"],"abstract":"This paper introduces the first \\emph{self-evolving} logic synthesis framework, which leverages Large Language Model (LLM) agents to autonomously improve the source code of \\textsc{ABC}, the widely adopted logic synthesis system. Our framework operates on the \\emph{entire integrated ABC codebase}, and the output repository preserves its single-binary execution model and command interface. In the initial evolution cycle, we bootstrap the system using existing prior open-source synthesis components, covering flow tuning, logic minimization, and technology mapping, but without manually injecting new heuristics. On top of this foundation, a team of LLM-based agents iteratively rewrites and evolves specific sub-components of ABC following our ``programming guidance`` prompts under a unified correctness and QoR-driven evaluation loop. Each evolution cycle proposes code modifications, compiles the integrated binary, validates correctness, and evaluates quality-of-results (QoR) on \\emph{multi-suite benchmarks including ISCAS~85/89/99, VTR, EPFL, and IWLS~2005}. Through continuous feedback, the system discovers optimizations beyond human-designed heuristics, effectively \\emph{learning new synthesis strategies} that enhance QoR. We detail the architecture of this self-improving system, its integration with \\textsc{ABC}, and results demonstrating that the framework can autonomously and progressively improve EDA tool at full million-line scale.","published":"2026-04-16T14:42:55Z","updated":"2026-04-16T14:42:55Z","categories":["cs.AR","cs.AI"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2604.15082v1","pdf_url":"https://arxiv.org/pdf/2604.15082v1","comment":"7 pages; To appear at DAC 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.14989","versioned_id":"2604.14989v2","title":"Dr. RTL: Autonomous Agentic RTL Optimization through Tool-Grounded Self-Improvement","authors":["Wenji Fang","Yao Lu","Shang Liu","Jing Wang","Ziyan Guo","Junxian He","Fengbin Tu","Zhiyao Xie"],"abstract":"Recent advances in large language models (LLMs) have sparked growing interest in automatic RTL optimization for better performance, power, and area (PPA). However, existing methods are still far from realistic RTL optimization. Their evaluation settings are often unrealistic: they are tested on manually degraded, small-scale RTL designs and rely on weak open-source tools. Their optimization methods are also limited, relying on coarse design-level feedback and simple pre-defined rewriting rules. To address these limitations, we present Dr. RTL, an agentic framework for RTL timing optimization in a realistic evaluation environment, with continual self-improvement through reusable optimization skills. We establish a realistic evaluation setting with more challenging RTL designs and an industrial EDA workflow. Within this setting, Dr. RTL performs closed-loop optimization through a multi-agent framework for critical-path analysis, parallel RTL rewriting, and tool-based evaluation. We further introduce group-relative skill learning, which compares parallel RTL rewrites and distills the optimization experience into an interpretable skill library. Currently, this library contains 47 pattern--strategy entries for cross-design reuse to improve PPA and accelerate convergence, and it can continue evolving over time. Evaluated on 20 real-world RTL designs, Dr. RTL achieves average WNS/TNS improvements of 21%/17% with a 6% area reduction over the industry-leading commercial synthesis tool.","published":"2026-04-16T13:18:24Z","updated":"2026-04-26T15:34:21Z","categories":["cs.AI","cs.AR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.14989v2","pdf_url":"https://arxiv.org/pdf/2604.14989v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=qaifrH5KqM","openreview_venues":["Architecture 2.0 2026"]},{"id":"openreview:htCDaIgnoB","versioned_id":"htCDaIgnoB","title":"SceneCritic: A Symbolic Evaluator for 3D Indoor Scene Synthesis","authors":["Kathakoli Sengupta","Kai Ao","Paola Cascante-Bonilla"],"abstract":"Scaling spatial intelligence in embodied agents demands environments that capture rich compositional structure and precise spatial relationships and can support such diverse task requirements. Large Language Models and Vision-Language Models increasingly generate indoor scenes via intermediate structures like layouts and scene graphs, yet evaluation still relies on LLM or VLM judges whose scores are sensitive to viewpoint, prompt phrasing, and hallucination. This instability makes it hard to disentangle spatial plausibility from evaluation artifacts. We introduce SceneCritic, a symbolic evaluator for floor-plan-level layouts grounded in SceneOnto, a structured spatial ontology aggregated from 3D-FRONT, ScanNet, and Visual Genome. SceneCritic jointly verifies semantic, orientation, and geometric coherence across object relationships, providing object- and relationship-level assessments that pinpoint specific violations. We further propose an iterative refinement testbed that probes how models revise spatial structure under three critic modalities: a rule-based collision critic, an LLM critic operating on layout text, and a VLM critic operating on rendered observations. Extensive experiments show that (a) SceneCritic aligns substantially better with human judgments than VLM-based evaluators, (b) text-only LLMs can outperform VLMs on semantic layout quality, and (c) image-based VLM refinement is most effective for semantic and orientation correction.","published":"2026-04-13T23:27:06+00:00","updated":"2026-05-21T10:00:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=htCDaIgnoB","openreview_url":"https://openreview.net/forum?id=htCDaIgnoB","pdf_url":"https://openreview.net/pdf?id=htCDaIgnoB","comment":"CVPR 2026 Workshop OpenSUN3D Poster","journal_ref":"CVPR 2026 Workshop OpenSUN3D Poster","doi":"","venue":"CVPR 2026 Workshop OpenSUN3D Poster","venue_id":"thecvf.com/CVPR/2026/Workshop/OpenSUN3D","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2604.12126","versioned_id":"2604.12126v1","title":"Long-Horizon Plan Execution in Large Tool Spaces through Entropy-Guided Branching","authors":["Rongzhe Wei","Ge Shi","Min Cheng","Na Zhang","Pan Li","Sarthak Ghosh","Vaibhav Gorde","Leman Akoglu"],"abstract":"Large Language Models (LLMs) have significantly advanced tool-augmented agents, enabling autonomous reasoning via API interactions. However, executing multi-step tasks within massive tool libraries remains challenging due to two critical bottlenecks: (1) the absence of rigorous, plan-level evaluation frameworks and (2) the computational demand of exploring vast decision spaces stemming from large toolsets and long-horizon planning. To bridge these gaps, we first introduce SLATE (Synthetic Large-scale API Toolkit for E-commerce), a large-scale context-aware benchmark designed for the automated assessment of tool-integrated agents. Unlike static metrics, SLATE accommodates diverse yet functionally valid execution trajectories, revealing that current agents struggle with self-correction and search efficiency. Motivated by these findings, we next propose Entropy-Guided Branching (EGB), an uncertainty-aware search algorithm that dynamically expands decision branches where predictive entropy is high. EGB optimizes the exploration-exploitation trade-off, significantly enhancing both task success rates and computational efficiency. Extensive experiments on SLATE demonstrate that our dual contribution provides a robust foundation for developing reliable and scalable LLM agents in tool-rich environments.","published":"2026-04-13T23:14:32Z","updated":"2026-04-13T23:14:32Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.12126v1","pdf_url":"https://arxiv.org/pdf/2604.12126v1","comment":"This work was completed during an internship at Amazon","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=p5rmFRK66w","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2604.11554","versioned_id":"2604.11554v2","title":"Relax: An Asynchronous Reinforcement Learning Engine for Omni-Modal Post-Training at Scale","authors":["Liujie Zhang","Benzhe Ning","Rui Yang","Xiaoyan Yu","Jiaxing Li","Lumeng Wu","Jia Liu","Minghao Li","Weihang Chen","Weiqi Hu","Lei Zhang"],"abstract":"Reinforcement learning (RL) post-training has proven effective at unlocking reasoning, self-reflection, and tool-use capabilities in large language models. As models extend to omni-modal inputs and agentic multi-turn workflows, RL training systems face three interdependent challenges: heterogeneous data flows, operational robustness at scale, and the staleness -- throughput tradeoff. We present \\textbf{Relax} (Reinforcement Engine Leveraging Agentic X-modality), an open-source RL training engine that addresses these challenges through three co-designed architectural layers. First, an \\emph{omni-native architecture} builds multimodal support into the full stack -- from data preprocessing and modality-aware parallelism to inference generation -- rather than retrofitting it onto a text-centric pipeline. Second, each RL role runs as an independent, fault-isolated service that can be scaled, recovered, and upgraded without global coordination. Third, service-level decoupling enables asynchronous training via the TransferQueue data bus, where a single staleness parameter smoothly interpolates among on-policy, near-on-policy, and fully asynchronous execution. Relax achieves a 1.20$\\times$ end-to-end speedup over veRL on Qwen3-4B on-policy training. Its fully async mode delivers a 1.76$\\times$ speedup over colocate on Qwen3-4B and a 2.00$\\times$ speedup on Qwen3-Omni-30B, while all modes converge to the same reward level. Relax supports R3 (Rollout Routing Replay)~\\cite{ma2025r3} for MoE models with only 1.9\\% overhead, compared to 32\\% degradation in veRL under the same configuration. It further demonstrates stable omni-modal RL convergence on Qwen3-Omni across image, text, and audio, sustaining over 2{,}000 steps on video without degradation. Relax is available at https://github.com/rednote-ai/Relax.","published":"2026-04-13T14:42:03Z","updated":"2026-04-14T09:26:26Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.11554v2","pdf_url":"https://arxiv.org/pdf/2604.11554v2","comment":"17 pages, 22 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.10842","versioned_id":"2604.10842v3","title":"Resilient Write: A Six-Layer Durable Write Surface for LLM Coding Agents","authors":["Justice Owusu Agyemang","Jerry John Kponyo","Elliot Amponsah","Godfred Manu Addo Boakye","Kwame Opuni-Boachie Obour Agyekum"],"abstract":"LLM-powered coding agents increasingly rely on tool-use protocols such as the Model Context Protocol (MCP) to read and write files on a developer's workstation. When a write fails - due to content filters, truncation, or an interrupted session - the agent typically receives no structured signal, loses the draft, and wastes tokens retrying blindly. We present Resilient Write, an MCP server that interposes a six-layer durable write surface between the agent and the filesystem. The layers - pre-flight risk scoring, transactional atomic writes, resume-safe chunking, structured typed errors, out-of-band scratchpad storage, and task-continuity handoff envelopes - are orthogonal and independently adoptable. Each layer maps to a concrete failure mode observed during a real agent session in April 2026, in which content-safety filters silently rejected a draft containing redacted API-key prefixes. Three additional tools - chunk preview, format-aware validation, and journal analytics - emerged from using the system to compose this paper. A 186-test suite validates correctness at each layer, and quantitative comparison against naive and defensive baselines shows a 5x reduction in recovery time and a 13x improvement in agent self-correction rate. Resilient Write is open-source under the MIT license.","published":"2026-04-12T22:23:55Z","updated":"2026-06-07T11:46:03Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2604.10842v3","pdf_url":"https://arxiv.org/pdf/2604.10842v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.09815","versioned_id":"2604.09815v1","title":"EE-MCP: Self-Evolving MCP-GUI Agents via Automated Environment Generation and Experience Learning","authors":["Tiantian He","Yihang Chen","Keyue Jiang","Ka Yiu Lee","Kaiwen Zhou","Kun Shao","Shuai Wang"],"abstract":"Computer-use agents that combine GUI interaction with structured API calls via the Model Context Protocol (MCP) show promise for automating software tasks. However, existing approaches lack a principled understanding of how agents should balance these two modalities and how to enable iterative self-improvement across diverse applications. We formulate MCP-GUI interplay as a unified hybrid policy learning problem where the agent learns when each modality provides complementary advantages, and show that distillation and experience augmentation target fundamentally different failure modes - requiring application-aware mechanism selection. Built on this formulation, we propose a self-evolving framework with a fully automatic pipeline that orchestrates automatic environment generation and validation, trajectory collection, gap-driven task synthesis, and quality-filtered training - all without manual intervention. A key innovation is our experience bank, which accumulates LLM-learned rules from trajectory comparison, enabling inference-time improvement without fine-tuning. Systematic \\textbf{cross-application analysis} across three desktop applications reveals that the optimal strategy depends on MCP-GUI composition: distillation achieves 77.8\\% pass rate on MCP-dominant tasks (+17.8pp), while the experience bank excels on GUI-intensive tasks (+10.0pp).","published":"2026-04-10T18:46:05Z","updated":"2026-04-10T18:46:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09815v1","pdf_url":"https://arxiv.org/pdf/2604.09815v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.09408","versioned_id":"2604.09408v4","title":"HiL-Bench (Human-in-Loop Benchmark): Do Agents Know When to Ask for Help?","authors":["Tu Trinh","Mohamed Elfeki","Guangze Luo","Kelvin Luu","Nathan Hunt","Ernesto Hernandez","Nandan Marwaha","Yannis Yiming He","Charles Wang","Fernando Carabedo","Alessa Castillo","Bing Liu"],"abstract":"Frontier coding agents solve complex tasks when given complete context but collapse when specifications are incomplete or ambiguous. The bottleneck is not raw capability, but judgment: knowing when to act autonomously and when to ask for help. Current benchmarks are blind to this failure mode. They supply unambiguous detailed instructions and solely reward execution correctness, so an agent that makes a lucky guess for a missing requirement will score identically to one that would have asked to be certain. We present HiL-Bench (Human-in-the-Loop Benchmark) to measure this selective escalation skill. Each task contains human-validated blockers (missing information, ambiguous requests, contradictory information) that surface only through progressive exploration, not upfront inspection. Our core metric, Ask-F1, the harmonic mean of question precision and blocker recall, captures the tension between over-asking and silent guessing; its structure architecturally prevents gaming through question spam. Evaluation across SWE and text-to-SQL domains reveals a large universal judgment gap: no frontier model recovers more than a fraction of its full-information performance when deciding whether to ask. Failure analysis identifies three key help-seeking patterns: overconfident wrong beliefs with no gap detection; high uncertainty detection yet persistent errors; broad, imprecise escalation without self-correction. These consistent patterns confirm poor help-seeking is a model-level flaw, not task-specific. RL training on shaped Ask-F1 reward shows judgment is trainable: a 32B model improves both help-seeking quality and task pass rate, with gains that transfer across domains. The model does not learn domain-specific heuristics for when to ask; it learns to detect unresolvable uncertainty and act on it.","published":"2026-04-10T15:21:44Z","updated":"2026-05-04T23:00:33Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09408v4","pdf_url":"https://arxiv.org/pdf/2604.09408v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.09308","versioned_id":"2604.09308v1","title":"Constraint-Aware Corrective Memory for Language-Based Drug Discovery Agents","authors":["Maochen Sun","Youzhi Zhang","Gaofeng Meng"],"abstract":"Large language models are making autonomous drug discovery agents increasingly feasible, but reliable success in this setting is not determined by any single action or molecule. It is determined by whether the final returned set jointly satisfies protocol-level requirements such as set size, diversity, binding quality, and developability. This creates a fundamental control problem: the agent plans step by step, while task validity is decided at the level of the whole candidate set. Existing language-based drug discovery systems therefore tend to rely on long raw history and under-specified self-reflection, making failure localization imprecise and planner-facing agent states increasingly noisy. We present CACM (Constraint-Aware Corrective Memory), a language-based drug discovery framework built around precise set-level diagnosis and a concise memory write-back mechanism. CACM introduces protocol auditing and a grounded diagnostician, which jointly analyze multimodal evidence spanning task requirements, pocket context, and candidate-set evidence to localize protocol violations, generate actionable remediation hints, and bias the next action toward the most relevant correction. To keep planning context compact, CACM organizes memory into static, dynamic, and corrective channels and compresses them before write-back, thereby preserving persistent task information while exposing only the most decision-relevant failures. Our experimental results show that CACM improves the target-level success rate by 36.4% over the state-of-the-art baseline. The results show that reliable language-based drug discovery benefits not only from more powerful molecular tools, but also from more precise diagnosis and more economical agent states.","published":"2026-04-10T13:16:44Z","updated":"2026-04-10T13:16:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09308v1","pdf_url":"https://arxiv.org/pdf/2604.09308v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.07900","versioned_id":"2604.07900v1","title":"AnomalyAgent: Agentic Industrial Anomaly Synthesis via Tool-Augmented Reinforcement Learning","authors":["Jiaming Su","Tengchao Yang","Ruikang Zhang","Zhengan Yan","Haoyu Sun","Linfeng Zhang"],"abstract":"Industrial anomaly generation is a crucial method for alleviating the data scarcity problem in anomaly detection tasks. Most existing anomaly synthesis methods rely on single-step generation mechanisms, lacking complex reasoning and iterative optimization capabilities, making it difficult to generate anomaly samples with high semantic realism. We propose AnomalyAgent, an anomaly synthesis agent with self-reflection, knowledge retrieval, and iterative refinement capabilities, aiming to generate realistic and diverse anomalies. Specifically, AnomalyAgent is equipped with five tools: Prompt Generation (PG), Image Generation (IG), Quality Evaluation (QE), Knowledge Retrieval (KR), and Mask Generation (MG), enabling closed-loop optimization. To improve decision-making and self-reflection, we construct structured trajectories from real anomaly images and design a two-stage training framework: supervised fine-tuning followed by reinforcement learning. This process is driven by a three-part reward mechanism: (1) task rewards to supervise the quality and location rationality of generated anomalies; (2) reflection rewards to train the model's ability to improve anomaly synthesis prompt; (3) behavioral rewards to ensure adherence to the trajectory. On the MVTec-AD dataset, AnomalyAgent achieves IS/IC-L of 2.10/0.33 for anomaly generation, 57.0% classification accuracy using ResNet34, and 99.3%/74.2% AP at the image/pixel level using a simple UNet, surpassing all zero-shot SOTA methods. The code and data will be made publicly available.","published":"2026-04-09T07:17:00Z","updated":"2026-04-09T07:17:00Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2604.07900v1","pdf_url":"https://arxiv.org/pdf/2604.07900v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.08618","versioned_id":"2604.08618v2","title":"SkillForge: Forging Domain-Specific, Self-Evolving Agent Skills in Cloud Technical Support","authors":["Xingyan Liu","Xiyue Luo","Linyu Li","Ganghong Huang","Jianfeng Liu","Honglin Qiao"],"abstract":"Deploying LLM-powered agents in enterprise scenarios such as cloud technical support demands high-quality, domain-specific skills. However, existing skill creators lack domain grounding, producing skills poorly aligned with real-world task requirements. Moreover, once deployed, there is no systematic mechanism to trace execution failures back to skill deficiencies and drive targeted refinements, leaving skill quality stagnant despite accumulating operational evidence. We introduce SkillForge, a self-evolving framework that closes an end-to-end creation-evaluation-refinement loop. To produce well-aligned initial skills, a Domain-Contextualized Skill Creator grounds skill synthesis in knowledge bases and historical support tickets. To enable continuous self-optimization, a three-stage pipeline -- Failure Analyzer, Skill Diagnostician, and Skill Optimizer -- automatically diagnoses execution failures in batch, pinpoints the underlying skill deficiencies, and rewrites the skill to eliminate them. This cycle runs iteratively, allowing skills to self-improve with every round of deployment feedback. Evaluated on five real-world cloud support scenarios spanning 1,883 tickets and 3,737 tasks, experiments show that: (1) the Domain-Contextualized Skill Creator produces substantially better initial skills than the generic skill creator, as measured by consistency with expert-authored reference responses from historical tickets; and (2) the self-evolution loop progressively improves skill quality from diverse starting points (including expert-authored, domain-created, and generic skills) across successive rounds, demonstrating that automated evolution can surpass manually curated expert knowledge.","published":"2026-04-09T07:11:23Z","updated":"2026-04-29T14:40:23Z","categories":["cs.IR","cs.AI","cs.SE"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.08618v2","pdf_url":"https://arxiv.org/pdf/2604.08618v2","comment":"Accepted at ACM SIGIR 2026 Industry Track. 18 pages, 5 figures, 3 tables","journal_ref":"","doi":"10.1145/3805712.3808466","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.07595","versioned_id":"2604.07595v3","title":"ROZA Graphs: Self-Improving Near-Deterministic RAG through Evidence-Centric Feedback","authors":["Matthew Penaroza"],"abstract":"Language model agents reason from scratch on every query, discarding their chain of thought after each run. The result is lower accuracy and high run-to-run variance. We introduce reasoning graphs, which persist the per-evidence chain of thought as structured edges. Unlike prior memory that retrieves distilled strategies by query similarity, reasoning graphs enable evidence-centric feedback: for every candidate item, the system traverses all incoming evaluation edges across prior runs to surface how that specific item has been judged before. We further introduce retrieval graphs, which feed a planner that prunes consistently-rejected candidates over successive runs. Together they form a ROZA graph: a self-improving feedback loop in which accuracy gains scale with gold-passage reuse (reasoning graph) and efficiency gains scale with candidate-pool overlap (retrieval graph). The base model remains frozen; all gains come from context engineering via graph traversal. We evaluate on MuSiQue and HotpotQA, plus a high-reuse deployment subset. Four findings stand out. (1) Dose-response: accuracy improves monotonically with evidence-profile coverage, reaching +10.6pp over Vanilla RAG at 50%+ coverage on the same questions (47% error reduction, $p<0.0001$; per-question Spearman $ρ=+0.144$, $p<10^{-6}$, $n=1{,}100$). (2) Multi-hop scaling: 4-hop accuracy improves by +11.0pp ($p=0.0001$). (3) Cross-cluster prediction: the cluster-level gain is predicted by gold-passage reuse density ($r=0.604$, $p=0.001$, $n=26$ clusters). (4) High-reuse Pareto dominance: highest or tied-for-highest accuracy alongside 46% lower cost and 46% lower latency. Per-passage decision consistency across repeated runs ($N=73$ paired probes, $K=10$ runs each, two model families, three temperatures) rises by +8 to +13pp on a fixed 20-passage context and by +12 to +21pp when the retrieval graph also prunes (all $p<0.005$).","published":"2026-04-08T20:57:21Z","updated":"2026-05-06T03:10:11Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.07595v3","pdf_url":"https://arxiv.org/pdf/2604.07595v3","comment":"31 pages including appendix, 12 figures, 15 tables, 3 algorithms; evaluation on MuSiQue, HotpotQA, and 2WikiMultiHopQA with Claude Sonnet 4, Haiku 4.5, and GPT-5-mini","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2605.02913","versioned_id":"2605.02913v1","title":"Generate, Filter, Control, Replay: A Comprehensive Survey of Rollout Strategies for LLM Reinforcement Learning","authors":["Rohan Surana","Gagan Mundada","Xunyi Jiang","Chuhan Wang","Zhenwei Tang","Difan Jiao","Zihan Huang","Yuxin Xiong","Junda Wu","Sheldon Yu","Xintong Li","Raghav Jain","Nikki Kuang","Sizhe Zhou","Bowen Jin","Zhendong Chu","Tong Yu","Ryan Rossi","Kuan-Hao Huang","Jingbo Shang","Jiawei Han","Julian McAuley"],"abstract":"Reinforcement learning (RL) has become a central post-training tool for improving the reasoning abilities of large language models (LLMs). In these systems, the rollout, the trajectory sampled from a prompt to termination, including intermediate reasoning steps and optional tool or environment interactions, determines the data the optimizer learns from, yet rollout design is often underreported. This survey provides an optimizer-agnostic view of rollout strategies for RL-based post-training of reasoning LLMs. We formalize rollout pipelines with unified notation and introduce Generate-Filter-Control-Replay (GFCR), a lifecycle taxonomy that decomposes rollout pipelines into four modular stages: Generate proposes candidate trajectories and topologies; Filter constructs intermediate signals via verifiers, judges, critics; Control allocates compute and makes continuation/branching/stopping decisions under budgets; and Replay retains and reuses artifacts across rollouts without weight updates, including self-evolving curricula that autonomously generate new training tasks. We complement GFCR with a criterion taxonomy of reliability, coverage, and cost sensitivity that characterizes rollout trade-offs. Using this framework, we synthesize methods spanning RL with verifiable rewards, process supervision, judge-based gating, guided and tree/segment rollouts, adaptive compute allocation, early-exit and partial rollouts, throughput optimization, and replay/recomposition for self-improvement. We ground the framework with case studies in math, code/SQL, multimodal reasoning, tool-using agents, and agentic skill benchmarks that evaluate skill induction, reuse, and cross-task transfer. Finally, we provide a diagnostic index that maps common rollout pathologies to GFCR modules and mitigation levers, alongside open challenges for building reproducible, compute-efficient, and trustworthy rollout pipelines.","published":"2026-04-08T00:53:29Z","updated":"2026-04-08T00:53:29Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2605.02913v1","pdf_url":"https://arxiv.org/pdf/2605.02913v1","comment":"47 pages, 8 tables, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=aB848FutiR","openreview_venues":["Under review for TMLR"]},{"id":"2604.06066","versioned_id":"2604.06066v1","title":"From Hallucination to Structure Snowballing: The Alignment Tax of Constrained Decoding in LLM Reflection","authors":["Hongxu Zhou"],"abstract":"Intrinsic self-correction in Large Language Models (LLMs) frequently fails in open-ended reasoning tasks due to ``hallucination snowballing,'' a phenomenon in which models recursively justify early errors during free-text reflection. While structured feedback can mitigate this issue, existing approaches often rely on externally trained critics or symbolic tools, reducing agent autonomy. This study investigates whether enforcing structured reflection purely through Outlines-based constrained decoding can disrupt error propagation without additional training. Evaluating an 8-billion-parameter model (Qwen3-8B), we show that simply imposing structural constraints does not improve self-correction performance. Instead, it triggers a new failure mode termed ``structure snowballing.'' We find that the cognitive load required to satisfy strict formatting rules pushes the model into formatting traps. This observation helps explain why the agent achieves near-perfect superficial syntactic alignment yet fails to detect or resolve deeper semantic errors. These findings expose an ``alignment tax'' inherent to constrained decoding, highlighting a tension between structural granularity and internal model capacity in autonomous workflows. Code and raw logs are available in the GitHub repository: https://github.com/hongxuzhou/agentic_llm_structured_self_critique.","published":"2026-04-07T16:47:37Z","updated":"2026-04-07T16:47:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.06066v1","pdf_url":"https://arxiv.org/pdf/2604.06066v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.05477","versioned_id":"2604.05477v1","title":"Don't Act Blindly: Robust GUI Automation via Action-Effect Verification and Self-Correction","authors":["Yuzhe Zhang","Xianwei Xue","Xingyong Wu","Mengke Chen","Chen Liu","Xinran He","Run Shao","Feiran Liu","Huanmin Xu","Qiutong Pan","Haiwei Wang"],"abstract":"Autonomous GUI agents based on vision-language models (VLMs) often assume deterministic environment responses, generating actions without verifying whether previous operations succeeded. In real-world settings with network latency, rendering delays, and system interruptions, this assumption leads to undetected action failures, repetitive ineffective behaviors, and catastrophic error accumulation. Moreover, learning robust recovery strategies is challenging due to the high cost of online interaction and the lack of real-time feedback in offline datasets.We propose VeriGUI (Verification-driven GUI Agent), which explicitly models action outcomes and recovery under noisy environments. VeriGUI introduces a Thinking--Verification--Action--Expectation (TVAE) framework to detect failures and guide corrective reasoning, and a two-stage training pipeline that combines Robust SFT with synthetic failure trajectories and GRPO with asymmetric verification rewards. We further construct a Robustness Benchmark based on AndroidControl to evaluate failure recognition and correction. Experiments show that VeriGUI significantly reduces failure loops and improves recovery success while maintaining competitive standard task performance.","published":"2026-04-07T06:16:23Z","updated":"2026-04-07T06:16:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.05477v1","pdf_url":"https://arxiv.org/pdf/2604.05477v1","comment":"ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.05458","versioned_id":"2604.05458v1","title":"MA-IDS: Multi-Agent RAG Framework for IoT Network Intrusion Detection with an Experience Library","authors":["Md Shamimul Islam","Luis G. Jaimes","Ayesha S. Dina"],"abstract":"Network Intrusion Detection Systems (NIDS) face important limitations. Signature-based methods are effective for known attack patterns, but they struggle to detect zero-day attacks and often miss modified variants of previously known attacks, while many machine learning approaches offer limited interpretability. These challenges become even more severe in IoT environments because of resource constraints and heterogeneous protocols. To address these issues, we propose MA-IDS, a Multi-Agent Intrusion Detection System that combines Large Language Models (LLMs) with Retrieval Augmented Generation (RAG) for reasoning-driven intrusion detection. The proposed framework grounds LLM reasoning through a persistent, self-building Experience Library. Two specialized agents collaborate through a FAISS-based vector database: a Traffic Classification Agent that retrieves past error rules before each inference, and an Error Analysis Agent that converts misclassifications into human-readable detection rules stored for future retrieval, enabling continual learning through external knowledge accumulation, without modifying the underlying language model. Evaluated on NF-BoT-IoT and NF-ToN-IoT benchmark datasets, MA-IDS achieves Macro F1-Scores of 89.75% and 85.22%, improving over zero-shot baselines of 17% and 4.96% by more than 72 and 80 percentage points. These results are competitive with SVM while providing rule-level explanations for every classification decision, demonstrating that retrieval-augmented reasoning offers a principled path toward explainable, self-improving intrusion detection for IoT networks.","published":"2026-04-07T05:41:10Z","updated":"2026-04-07T05:41:10Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2604.05458v1","pdf_url":"https://arxiv.org/pdf/2604.05458v1","comment":"Preprint. Submitted to IEEE conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.05336","versioned_id":"2604.05336v2","title":"TRACE: Capability-Targeted Agentic Training","authors":["Hangoo Kang","Tarun Suresh","Jon Saad-Falcon","Azalia Mirhoseini"],"abstract":"Models often fail to complete agentic tasks because they lack core capabilities required by the target environment. However, mainstream approaches for addressing these failures typically either fine-tune directly on target environments or generate synthetic data that is not targeted to the model's actual capability deficits, resulting in low sample efficiency and limited generalization. We introduce TRACE (Turning Recurrent Agent failures into Capability-targeted training Environments), an end-to-end system for environment-specific agent self-improvement. TRACE contrasts successful and failed trajectories to automatically identify missing capabilities, synthesizes a targeted training environment for each capability that rewards whether the capability is exercised, trains a LoRA adapter via reinforcement learning on each synthetic environment, and then trains a mixture-of-experts model over the capability adapters. TRACE can be effectively applied across different environments, improving over the base agent by +15.3 points on $τ^2$-Bench, a customer-service agent benchmark, and by +15.0 points Pass@1 on SWE-Bench Verified, a software-engineering benchmark. TRACE outperforms the strongest external baselines, GEPA and SWE-RL, by +8.6 points and +8.4 points, respectively. In addition, TRACE is more sample-efficient than strong fine-tuning baselines: using fewer than one-fourth the number of rollouts, TRACE outperforms the best-performing baselines, GRPO and GEPA, and achieves higher final accuracy by +10.4 and +8.6 points on $τ^2$-Bench.","published":"2026-04-07T02:22:44Z","updated":"2026-07-02T22:12:42Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.05336v2","pdf_url":"https://arxiv.org/pdf/2604.05336v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=p37UqCmcxG","openreview_venues":["FAGEN@ICML 2026 Poster"]},{"id":"2604.04847","versioned_id":"2604.04847v1","title":"Full-Duplex-Bench-v3: Benchmarking Tool Use for Full-Duplex Voice Agents Under Real-World Disfluency","authors":["Guan-Ting Lin","Chen Chen","Zhehuai Chen","Hung-yi Lee"],"abstract":"We introduce Full-Duplex-Bench-v3 (FDB-v3), a benchmark for evaluating spoken language models under naturalistic speech conditions and multi-step tool use. Unlike prior work, our dataset consists entirely of real human audio annotated for five disfluency categories, paired with scenarios requiring chained API calls across four task domains. We evaluate six model configurations -- GPT-Realtime, Gemini Live 2.5, Gemini Live 3.1, Grok, Ultravox v0.7, and a traditional Cascaded pipeline (Whisper$\\rightarrow$GPT-4o$\\rightarrow$TTS) -- across accuracy, latency, and turn-taking dimensions. GPT-Realtime leads on Pass@1 (0.600) and interruption avoidance (13.5\\%); Gemini Live 3.1 achieves the fastest latency (4.25~s) but the lowest turn-take rate (78.0\\%); and the Cascaded baseline, despite a perfect turn-take rate, incurs the highest latency (10.12~s). Across all systems, self-correction handling and multi-step reasoning under hard scenarios remain the most consistent failure modes.","published":"2026-04-06T16:46:52Z","updated":"2026-04-06T16:46:52Z","categories":["eess.AS","cs.CL"],"primary_category":"eess.AS","arxiv_url":"https://arxiv.org/abs/2604.04847v1","pdf_url":"https://arxiv.org/pdf/2604.04847v1","comment":"Work in progress. Demo at https://daniellin94144.github.io/FDB-v3-demo","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.04247","versioned_id":"2604.04247v1","title":"Combee: Scaling Prompt Learning for Self-Improving Language Model Agents","authors":["Hanchen Li","Runyuan He","Qizheng Zhang","Changxiu Ji","Qiuyang Mang","Xiaokun Chen","Lakshya A Agrawal","Wei-Liang Liao","Eric Yang","Alvin Cheung","James Zou","Kunle Olukotun","Ion Stoica","Joseph E. Gonzalez"],"abstract":"Recent advances in prompt learning allow large language model agents to acquire task-relevant knowledge from inference-time context without parameter changes. For example, existing methods (like ACE or GEPA) can learn system prompts to improve accuracy based on previous agent runs. However, these methods primarily focus on single-agent or low-parallelism settings. This fundamentally limits their ability to efficiently learn from a large set of collected agentic traces. It would be efficient and beneficial to run prompt learning in parallel to accommodate the growing trend of learning from many agentic traces or parallel agent executions. Yet without a principled strategy for scaling, current methods suffer from quality degradation with high parallelism. To improve both the efficiency and quality of prompt learning, we propose Combee, a novel framework to scale parallel prompt learning for self-improving agents. Combee speeds up learning and enables running many agents in parallel while learning from their aggregate traces without quality degradation. To achieve this, Combee leverages parallel scans and employs an augmented shuffle mechanism; Combee also introduces a dynamic batch size controller to balance quality and delay. Evaluations on AppWorld, Terminal-Bench, Formula, and FiNER demonstrate that Combee achieves up to 17x speedup over previous methods with comparable or better accuracy and equivalent cost.","published":"2026-04-05T20:07:48Z","updated":"2026-04-05T20:07:48Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.04247v1","pdf_url":"https://arxiv.org/pdf/2604.04247v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.03631","versioned_id":"2604.03631v1","title":"Single-agent vs. Multi-agents for Automated Video Analysis of On-Screen Collaborative Learning Behaviors","authors":["Likai Peng","Shihui Feng"],"abstract":"On-screen learning behavior provides valuable insights into how students seek, use, and create information during learning. Analyzing on-screen behavioral engagement is essential for capturing students' cognitive and collaborative processes. The recent development of Vision Language Models (VLMs) offers new opportunities to automate the labor-intensive manual coding often required for multimodal video data analysis. In this study, we compared the performance of both leading closed-source VLMs (Claude-3.7-Sonnet, GPT-4.1) and open-source VLM (Qwen2.5-VL-72B) in single- and multi-agent settings for automated coding of screen recordings in collaborative learning contexts based on the ICAP framework. In particular, we proposed and compared two multi-agent frameworks: 1) a three-agent workflow multi-agent system (MAS) that segments screen videos by scene and detects on-screen behaviors using cursor-informed VLM prompting with evidence-based verification; 2) an autonomous-decision MAS inspired by ReAct that iteratively interleaves reasoning, tool-like operations (segmentation/ classification/ validation), and observation-driven self-correction to produce interpretable on-screen behavior labels. Experimental results demonstrated that the two proposed MAS frameworks achieved viable performance, outperforming the single VLMs in scene and action detection tasks. It is worth noting that the workflow-based agent achieved best on scene detection, and the autonomous-decision MAS achieved best on action detection. This study demonstrates the effectiveness of VLM-based Multi-agent System for video analysis and contributes a scalable framework for multimodal data analytics.","published":"2026-04-04T08:01:02Z","updated":"2026-04-04T08:01:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.03631v1","pdf_url":"https://arxiv.org/pdf/2604.03631v1","comment":"15 pages, 4 figures. To be published in the 27th International Conference on Artificial Intelligence in Education (AIED2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.03173","versioned_id":"2604.03173v1","title":"Detecting and Correcting Reference Hallucinations in Commercial LLMs and Deep Research Agents","authors":["Delip Rao","Eric Wong","Chris Callison-Burch"],"abstract":"Large language models and deep research agents supply citation URLs to support their claims, yet the reliability of these citations has not been systematically measured. We address six research questions about citation URL validity using 10 models and agents on DRBench (53,090 URLs) and 3 models on ExpertQA (168,021 URLs across 32 academic fields). We find that 3--13\\% of citation URLs are hallucinated -- they have no record in the Wayback Machine and likely never existed -- while 5--18\\% are non-resolving overall. Deep research agents generate substantially more citations per query than search-augmented LLMs but hallucinate URLs at higher rates. Domain effects are pronounced: non-resolving rates range from 5.4\\% (Business) to 11.4\\% (Theology), with per-model effects even larger. Decomposing failures reveals that some models fabricate every non-resolving URL, while others show substantial link-rot fractions indicating genuine retrieval. As a solution, we release urlhealth, an open-source tool for URL liveness checking and stale-vs-hallucinated classification using the Wayback Machine. In agentic self-correction experiments, models equipped with urlhealth reduce non-resolving citation URLs by $6\\textrm{--}79\\times$ to under 1\\%, though effectiveness depends on the model's tool-use competence. The tool and all data are publicly available. Our characterization findings, failure taxonomy, and open-source tooling establish that citation URL validity is both measurable at scale and correctable in practice.","published":"2026-04-03T16:49:02Z","updated":"2026-04-03T16:49:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2604.03173v1","pdf_url":"https://arxiv.org/pdf/2604.03173v1","comment":"25 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.02211","versioned_id":"2604.02211v1","title":"Multi-Agent Video Recommenders: Evolution, Patterns, and Open Challenges","authors":["Srivaths Ranganathan","Abhishek Dharmaratnakar","Anushree Sinha","Debanshu Das"],"abstract":"Video recommender systems are among the most popular and impactful applications of AI, shaping content consumption and influencing culture for billions of users. Traditional single-model recommenders, which optimize static engagement metrics, are increasingly limited in addressing the dynamic requirements of modern platforms. In response, multi-agent architectures are redefining how video recommender systems serve, learn, and adapt to both users and datasets. These agent-based systems coordinate specialized agents responsible for video understanding, reasoning, memory, and feedback, to provide precise, explainable recommendations. In this survey, we trace the evolution of multi-agent video recommendation systems (MAVRS). We combine ideas from multi-agent recommender systems, foundation models, and conversational AI, culminating in the emerging field of large language model (LLM)-powered MAVRS. We present a taxonomy of collaborative patterns and analyze coordination mechanisms across diverse video domains, ranging from short-form clips to educational platforms. We discuss representative frameworks, including early multi-agent reinforcement learning (MARL) systems such as MMRF and recent LLM-driven architectures like MACRec and Agent4Rec, to illustrate these patterns. We also outline open challenges in scalability, multimodal understanding, incentive alignment, and identify research directions such as hybrid reinforcement learning-LLM systems, lifelong personalization and self-improving recommender systems.","published":"2026-04-02T16:04:52Z","updated":"2026-04-02T16:04:52Z","categories":["cs.IR","cs.AI","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2604.02211v1","pdf_url":"https://arxiv.org/pdf/2604.02211v1","comment":"Accepted for publication in The Nineteenth ACM International Conference on Web Search and Data Mining (WSDM Companion 2026)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PDbQSv1dzQ","openreview_venues":["WSDM 2026 GenAI4SM Workshop"]},{"id":"2604.00790","versioned_id":"2604.00790v1","title":"RefineRL: Advancing Competitive Programming with Self-Refinement Reinforcement Learning","authors":["Shaopeng Fu","Xingxing Zhang","Li Dong","Di Wang","Furu Wei"],"abstract":"While large language models (LLMs) have demonstrated strong performance on complex reasoning tasks such as competitive programming (CP), existing methods predominantly focus on single-attempt settings, overlooking their capacity for iterative refinement. In this paper, we present RefineRL, a novel approach designed to unleash the self-refinement capabilities of LLMs for CP problem solving. RefineRL introduces two key innovations: (1) Skeptical-Agent, an iterative self-refinement agent equipped with local execution tools to validate generated solutions against public test cases of CP problems. This agent always maintains a skeptical attitude towards its own outputs and thereby enforces rigorous self-refinement even when validation suggests correctness. (2) A reinforcement learning (RL) solution to incentivize LLMs to self-refine with only standard RLVR data (i.e., problems paired with their verifiable answers). Extensive experiments on Qwen3-4B and Qwen3-4B-2507 demonstrate that our method yields substantial gains: after our RL training, these compact 4B models integrated with the Skeptical-Agent not only outperform much larger 32B models but also approach the single-attempt performance of 235B models. These findings suggest that self-refinement holds considerable promise for scaling LLM reasoning, with significant potential for further advancement.","published":"2026-04-01T11:54:57Z","updated":"2026-04-01T11:54:57Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.00790v1","pdf_url":"https://arxiv.org/pdf/2604.00790v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":75,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.29755","versioned_id":"2603.29755v1","title":"CausalPulse: An Industrial-Grade Neurosymbolic Multi-Agent Copilot for Causal Diagnostics in Smart Manufacturing","authors":["Chathurangi Shyalika","Utkarshani Jaimini","Cory Henson","Amit Sheth"],"abstract":"Modern manufacturing environments demand real-time, trustworthy, and interpretable root-cause insights to sustain productivity and quality. Traditional analytics pipelines often treat anomaly detection, causal inference, and root-cause analysis as isolated stages, limiting scalability and explainability. In this work, we present CausalPulse, an industry-grade multi-agent copilot that automates causal diagnostics in smart manufacturing. It unifies anomaly detection, causal discovery, and reasoning through a neurosymbolic architecture built on standardized agentic protocols. CausalPulse is being deployed in a Robert Bosch manufacturing plant, integrating seamlessly with existing monitoring workflows and supporting real-time operation at production scale. Evaluations on both public (Future Factories) and proprietary (Planar Sensor Element) datasets show high reliability, achieving overall success rates of 98.0% and 98.73%. Per-criterion success rates reached 98.75% for planning and tool use, 97.3% for self-reflection, and 99.2% for collaboration. Runtime experiments report end-to-end latency of 50-60s per diagnostic workflow with near-linear scalability (R^2=0.97), confirming real-time readiness. Comparison with existing industrial copilots highlights distinct advantages in modularity, extensibility, and deployment maturity. These results demonstrate how CausalPulse's modular, human-in-the-loop design enables reliable, interpretable, and production-ready automation for next-generation manufacturing.","published":"2026-03-31T13:54:34Z","updated":"2026-03-31T13:54:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.29755v1","pdf_url":"https://arxiv.org/pdf/2603.29755v1","comment":"10 pages, 8 figures, 4 tables, Accepted at AAAI-MAKE 2026 (AAAI Spring Symposium on Machine Learning and Knowledge Engineering for Knowledge-Grounded Semantic Agents)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.28488","versioned_id":"2603.28488v2","title":"Courtroom-Style Multi-Agent Debate with Progressive RAG and Role-Switching for Controversial Claim Verification","authors":["Masnun Nuha Chowdhury","Nusrat Jahan Beg","Umme Hunny Khan","Syed Rifat Raiyan","Md Kamrul Hasan","Hasan Mahmud"],"abstract":"Large language models (LLMs) remain unreliable for high-stakes claim verification due to hallucinations and shallow reasoning. While retrieval-augmented generation (RAG) and multi-agent debate (MAD) address this, they are limited by one-pass retrieval and unstructured debate dynamics. We propose a courtroom-style multi-agent framework, PROClaim, that reformulates verification as a structured, adversarial deliberation. Our approach integrates specialized roles (e.g., Plaintiff, Defense, Judge) with Progressive RAG (P-RAG) to dynamically expand and refine the evidence pool during the debate. Furthermore, we employ evidence negotiation, self-reflection, and heterogeneous multi-judge aggregation to enforce calibration, robustness, and diversity. In zero-shot evaluations on the Check-COVID benchmark, PROClaim achieves 81.7% accuracy, outperforming standard multi-agent debate by 10.0 percentage points, with P-RAG driving the primary performance gains (+7.5 pp). We ultimately demonstrate that structural deliberation and model heterogeneity effectively mitigate systematic biases, providing a robust foundation for reliable claim verification. Our code and data are publicly available at https://github.com/mnc13/PROClaim.","published":"2026-03-30T14:23:15Z","updated":"2026-05-12T00:38:08Z","categories":["cs.CL","cs.AI","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.28488v2","pdf_url":"https://arxiv.org/pdf/2603.28488v2","comment":"Under review, 7 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.27451","versioned_id":"2603.27451v1","title":"Multi-Agent Dialectical Refinement for Enhanced Argument Classification","authors":["Jakub Bąba","Jarosław A. Chudziak"],"abstract":"Argument Mining (AM) is a foundational technology for automated writing evaluation, yet traditional supervised approaches rely heavily on expensive, domain-specific fine-tuning. While Large Language Models (LLMs) offer a training-free alternative, they often struggle with structural ambiguity, failing to distinguish between similar components like Claims and Premises. Furthermore, single-agent self-correction mechanisms often suffer from sycophancy, where the model reinforces its own initial errors rather than critically evaluating them. We introduce MAD-ACC (Multi-Agent Debate for Argument Component Classification), a framework that leverages dialectical refinement to resolve classification uncertainty. MAD-ACC utilizes a Proponent-Opponent-Judge model where agents defend conflicting interpretations of ambiguous text, exposing logical nuances that single-agent models miss. Evaluation on the UKP Student Essays corpus demonstrates that MAD-ACC achieves a Macro F1 score of 85.7%, significantly outperforming single-agent reasoning baselines, without requiring domain-specific training. Additionally, unlike \"black-box\" classifiers, MAD-ACC's dialectical approach offers a transparent and explainable alternative by generating human-readable debate transcripts that explain the reasoning behind decisions.","published":"2026-03-29T00:03:48Z","updated":"2026-03-29T00:03:48Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27451v1","pdf_url":"https://arxiv.org/pdf/2603.27451v1","comment":"Accepted for publication in the proceedings of ACIIDS 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.27335","versioned_id":"2603.27335v1","title":"PubMed Reasoner: Dynamic Reasoning-based Retrieval for Evidence-Grounded Biomedical Question Answering","authors":["Yiqing Zhang","Xiaozhong Liu","Fabricio Murai"],"abstract":"Trustworthy biomedical question answering (QA) systems must not only provide accurate answers but also justify them with current, verifiable evidence. Retrieval-augmented approaches partially address this gap but lack mechanisms to iteratively refine poor queries, whereas self-reflection methods kick in only after full retrieval is completed. In this context, we introduce PubMed Reasoner, a biomedical QA agent composed of three stages: self-critic query refinement evaluates MeSH terms for coverage, alignment, and redundancy to enhance PubMed queries based on partial (metadata) retrieval; reflective retrieval processes articles in batches until sufficient evidence is gathered; and evidence-grounded response generation produces answers with explicit citations. PubMed Reasoner with a GPT-4o backbone achieves 78.32% accuracy on PubMedQA, slightly surpassing human experts, and showing consistent gains on MMLU Clinical Knowledge. Moreover, LLM-as-judge evaluations prefer our responses across: reasoning soundness, evidence grounding, clinical relevance, and trustworthiness. By orchestrating retrieval-first reasoning over authoritative sources, our approach provides practical assistance to clinicians and biomedical researchers while controlling compute and token costs.","published":"2026-03-28T16:41:57Z","updated":"2026-03-28T16:41:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.27335v1","pdf_url":"https://arxiv.org/pdf/2603.27335v1","comment":"20 pages; under review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5kRBoDAvUB","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"2603.26845","versioned_id":"2603.26845v2","title":"GISclaw: A Comprehensive Open-Source LLM Agent System for Realistic Multi-Step Geospatial Analysis","authors":["Jinzhen Han","JinByeong Lee","Yuri Shim","Jisung Kim","Jae-Joon Lee"],"abstract":"Most LLM-driven GIS assistants solve narrow single-step tasks tightly coupled to proprietary platforms such as ArcGIS or QGIS, limiting their use for the multi-step, cross-format pipelines that define professional geospatial analysis. We present GISclaw, a comprehensive open-source agent system that performs realistic GIS analysis end to end - spatial joins, raster algebra, kriging interpolation, machine-learning classification, network analysis, choropleth cartography - directly through Python with no commercial GIS dependency. GISclaw couples an LLM reasoning core with a persistent Python sandbox pre-loaded with the open-source geospatial stack, three engineered prompt rules (Schema Analysis, Package Constraint, Domain Knowledge Injection), and an Error-Memory module for self-correction. A single backend-agnostic architecture supports both cloud-API and locally deployed open-weight LLM backends, enabling air-gapped deployment without loss of capability. On GeoAnalystBench - 50 expert-curated multi-step tasks averaging 5.8 analytical steps across vector, raster, and tabular data - GISclaw reaches up to 100% task success and 97% mean success over three independent runs. We further conduct 1,800 controlled experiments (50 tasks x 6 backends x 2 architectures x 3 repeats) with bootstrap 95% CIs, paired Wilcoxon tests, and a composite-score sensitivity analysis (Kendall's tau median = 0.94), and introduce a three-layer evaluation protocol combining code structure, reasoning process, and type-specific output verification. The Single-Agent ReAct loop reliably outperforms the Dual-Agent Plan-Execute-Replan pipeline on every cloud backend (Cliff's delta = 0.15-0.41); only the locally deployed 14B model gains from multi-agent orchestration, suggesting architectural complexity should match model capability rather than be added by default.","published":"2026-03-27T09:46:59Z","updated":"2026-05-03T12:16:48Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.26845v2","pdf_url":"https://arxiv.org/pdf/2603.26845v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.26034","versioned_id":"2603.26034v1","title":"AgentCollab: A Self-Evaluation-Driven Collaboration Paradigm for Efficient LLM Agents","authors":["Wenbo Gao","Renxi Liu","Xian Wang","Fang Guo","Shuai Yang","Xi Chen","Hui-Ling Zhen","Hanting Chen","Weizhe Lin","Xiaosong Li","Yaoyuan Wang"],"abstract":"Autonomous agents powered by large language models (LLMs) perform complex tasks through long-horizon reasoning and tool interaction, where a fundamental trade-off arises between execution efficiency and reasoning robustness. Models at different capability-cost levels offer complementary advantages: lower-cost models enable fast execution but may struggle on difficult reasoning segments, while stronger models provide more robust reasoning at higher computational cost. We present AgentCollab, a self-driven collaborative inference framework that dynamically coordinates models with different reasoning capacities during agent execution. Instead of relying on external routing modules, the framework uses the agent's own self-reflection signal to determine whether the current reasoning trajectory is making meaningful progress, and escalates control to a stronger reasoning tier only when necessary. To further stabilize long-horizon execution, we introduce a difficulty-aware cumulative escalation strategy that allocates additional reasoning budget based on recent failure signals. In our experiments, we instantiate this framework using a two-level small-large model setting. Experiments on diverse multi-step agent benchmarks show that AgentCollab consistently improves the accuracy-efficiency Pareto frontier of LLM agents.","published":"2026-03-27T03:07:34Z","updated":"2026-03-27T03:07:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.26034v1","pdf_url":"https://arxiv.org/pdf/2603.26034v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.25697","versioned_id":"2603.25697v1","title":"The Kitchen Loop: User-Spec-Driven Development for a Self-Evolving Codebase","authors":["Yannick Roy"],"abstract":"Code production is now a commodity; the bottleneck is knowing what to build and proving it works. We present the Kitchen Loop, a framework for autonomous, self-evolving software built on a unified trust model: (1) a specification surface enumerating what the product claims to support; (2) 'As a User x 1000', where an LLM agent exercises that surface as a synthetic power user at 1,000x human cadence; (3) Unbeatable Tests, ground-truth verification the code author cannot fake; and (4) Drift Control, continuous quality measurement with automated pause gates. We validate across two production systems over 285+ iterations, producing 1,094+ merged pull requests with zero regressions detected by the regression oracle (methodology in Section 6.1). We observe emergent properties at scale: multi-iteration self-correction chains, autonomous infrastructure healing, and monotonically improving quality gates. The primitives are not new; our contribution is their composition into a production-tested system with the operational discipline that makes long-running autonomous evolution safe.","published":"2026-03-26T17:45:00Z","updated":"2026-03-26T17:45:00Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.25697v1","pdf_url":"https://arxiv.org/pdf/2603.25697v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.24866","versioned_id":"2603.24866v1","title":"How Far Are Vision-Language Models from Constructing the Real World? A Benchmark for Physical Generative Reasoning","authors":["Luyu Yang","Yutong Dai","An Yan","Viraj Prabhu","Ran Xu","Zeyuan Chen"],"abstract":"The physical world is not merely visual; it is governed by rigorous structural and procedural constraints. Yet, the evaluation of vision-language models (VLMs) remains heavily skewed toward perceptual realism, prioritizing the generation of visually plausible 3D layouts, shapes, and appearances. Current benchmarks rarely test whether models grasp the step-by-step processes and physical dependencies required to actually build these artifacts, a capability essential for automating design-to-construction pipelines. To address this, we introduce DreamHouse, a novel benchmark for physical generative reasoning: the capacity to synthesize artifacts that concurrently satisfy geometric, structural, constructability, and code-compliance constraints. We ground this benchmark in residential timber-frame construction, a domain with fully codified engineering standards and objectively verifiable correctness. We curate over 26,000 structures spanning 13 architectural styles, ach verified to construction-document standards (LOD 350) and develop a deterministic 10-test structural validation framework. Unlike static benchmarks that assess only final outputs, DreamHouse supports iterative agentic interaction. Models observe intermediate build states, generate construction actions, and receive structured environmental feedback, enabling a fine-grained evaluation of planning, structural reasoning, and self-correction. Extensive experiments with state-of-the-art VLMs reveal substantial capability gaps that are largely invisible on existing leaderboards. These findings establish physical validity as a critical evaluation axis orthogonal to visual realism, highlighting physical generative reasoning as a distinct and underdeveloped frontier in multimodal intelligence. Available at https://luluyuyuyang.github.io/dreamhouse","published":"2026-03-25T23:13:28Z","updated":"2026-03-25T23:13:28Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24866v1","pdf_url":"https://arxiv.org/pdf/2603.24866v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.24579","versioned_id":"2603.24579v1","title":"MARCH: Multi-Agent Reinforced Self-Check for LLM Hallucination","authors":["Zhuo Li","Yupeng Zhang","Pengyu Cheng","Jiajun Song","Mengyu Zhou","Hao Li","Shujie Hu","Yu Qin","Erchao Zhao","Xiaoxi Jiang","Guanjun Jiang"],"abstract":"Hallucination remains a critical bottleneck for large language models (LLMs), undermining their reliability in real-world applications, especially in Retrieval-Augmented Generation (RAG) systems. While existing hallucination detection methods employ LLM-as-a-judge to verify LLM outputs against retrieved evidence, they suffer from inherent confirmation bias, where the verifier inadvertently reproduces the errors of the original generation. To address this, we introduce Multi-Agent Reinforced Self-Check for Hallucination (MARCH), a framework that enforces rigorous factual alignment by leveraging deliberate information asymmetry. MARCH orchestrates a collaborative pipeline of three specialized agents: a Solver, a Proposer, and a Checker. The Solver generates an initial RAG response, which the Proposer decomposes into claim-level verifiable atomic propositions. Crucially, the Checker validates these propositions against retrieved evidence in isolation, deprived of the Solver's original output. This well-crafted information asymmetry scheme breaks the cycle of self-confirmation bias. By training this pipeline with multi-agent reinforcement learning (MARL), we enable the agents to co-evolve and optimize factual adherence. Extensive experiments across hallucination benchmarks demonstrate that MARCH substantially reduces hallucination rates. Notably, an 8B-parameter LLM equipped with MARCH achieves performance competitive with powerful closed-source models. MARCH paves a scalable path for factual self-improvement of LLMs through co-evolution. The code is at https://github.com/Qwen-Applications/MARCH.","published":"2026-03-25T17:54:10Z","updated":"2026-03-25T17:54:10Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.24579v1","pdf_url":"https://arxiv.org/pdf/2603.24579v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.24402","versioned_id":"2603.24402v2","title":"AI-Supervisor: Autonomous AI Research Supervision via a Persistent Research World Model","authors":["Yunbo Long"],"abstract":"Existing automated research systems operate as stateless, linear pipelines -- generating outputs without maintaining any persistent understanding of the research landscape they navigate. They process papers sequentially, propose ideas without structured gap analysis, and lack mechanisms for agents to verify, challenge, or refine each other's findings. We present \\textbf{AI-Supervisor}, a multi-agent orchestration framework where specialized agents provide end-to-end AI research supervision driven by human interests -- from literature review through gap discovery, method development, evaluation, and paper writing -- through autonomous exploration and self-correcting updates of research knowledge. Unlike sequential pipelines, AI-Supervisor maintains a continuously evolving \\emph{Research World Model}, implemented as a Knowledge Graph, that captures methods, benchmarks, known limitations, and unexplored gaps, serving as shared memory across all agents and enabling agents to explore and build upon a structured understanding of the research landscape. The framework introduces three architectural contributions: (1) \\emph{structured gap discovery} that decomposes methods into core modules, validates their performance across benchmarks, and maps the specific gaps each module creates; (2) \\emph{self-correcting discovery loops} that probe why modules succeed on certain problems and fail on others, whether benchmarks carry hidden biases, and whether evaluation protocols remain adequate for emerging challenges; and (3) \\emph{self-improving development loops} governed by cross-domain mechanism search that iteratively targets failing modules by finding solutions from other scientific fields. All agents operate under a \\emph{consensus mechanism} where independent findings are corroborated before being committed to the Research World Model.","published":"2026-03-25T15:16:51Z","updated":"2026-03-26T01:57:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24402v2","pdf_url":"https://arxiv.org/pdf/2603.24402v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.24639","versioned_id":"2603.24639v2","title":"Experiential Reflective Learning for Self-Improving LLM Agents","authors":["Marc-Antoine Allard","Arnaud Teinturier","Victor Xing","Gautier Viaud"],"abstract":"Recent advances in large language models (LLMs) have enabled the development of autonomous agents capable of complex reasoning and multi-step problem solving. However, these agents struggle to adapt to specialized environments and do not leverage past interactions, approaching each new task from scratch regardless of their accumulated experience. We introduce Experiential Reflective Learning (ERL), a simple self-improvement framework that enables rapid environment adaptation through experiential learning. ERL reflects on task trajectories and outcomes to generate heuristics, capturing actionable lessons that transfer across tasks. At test time, relevant heuristics are retrieved based on the current task and injected into the agent's context to guide execution. On the Gaia2 benchmark, ERL improves success rate by 7.8% over a ReAct baseline, with large gains in task completion reliability, and outperforms prior experiential learning methods. Through systematic ablations, we find that selective retrieval is essential and that heuristics provide more transferable abstractions than few-shot trajectory prompting. These results demonstrate that reflecting on single-attempt experiences to extract transferable heuristics enables effective agent self-improvement.","published":"2026-03-25T11:43:22Z","updated":"2026-03-31T19:23:46Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.24639v2","pdf_url":"https://arxiv.org/pdf/2603.24639v2","comment":"Published as a conference paper at the ICLR 2026 MemAgents Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=hQgSl6kj1W","openreview_venues":["ICLR 2026 Workshop MemAgents"]},{"id":"2603.24018","versioned_id":"2603.24018v1","title":"ELITE: Experiential Learning and Intent-Aware Transfer for Self-improving Embodied Agents","authors":["Bingqing Wei","Zhongyu Xia","Dingai Liu","Xiaoyu Zhou","Zhiwei Lin","Yongtao Wang"],"abstract":"Vision-language models (VLMs) have shown remarkable general capabilities, yet embodied agents built on them fail at complex tasks, often skipping critical steps, proposing invalid actions, and repeating mistakes. These failures arise from a fundamental gap between the static training data of VLMs and the physical interaction for embodied tasks. VLMs can learn rich semantic knowledge from static data but lack the ability to interact with the world. To address this issue, we introduce ELITE, an embodied agent framework with {E}xperiential {L}earning and {I}ntent-aware {T}ransfer that enables agents to continuously learn from their own environment interaction experiences, and transfer acquired knowledge to procedurally similar tasks. ELITE operates through two synergistic mechanisms, \\textit{i.e.,} self-reflective knowledge construction and intent-aware retrieval. Specifically, self-reflective knowledge construction extracts reusable strategies from execution trajectories and maintains an evolving strategy pool through structured refinement operations. Then, intent-aware retrieval identifies relevant strategies from the pool and applies them to current tasks. Experiments on the EB-ALFRED and EB-Habitat benchmarks show that ELITE achieves 9\\% and 5\\% performance improvement over base VLMs in the online setting without any supervision. In the supervised setting, ELITE generalizes effectively to unseen task categories, achieving better performance compared to state-of-the-art training-based methods. These results demonstrate the effectiveness of ELITE for bridging the gap between semantic understanding and reliable action execution.","published":"2026-03-25T07:25:51Z","updated":"2026-03-25T07:25:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.24018v1","pdf_url":"https://arxiv.org/pdf/2603.24018v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.23994","versioned_id":"2603.23994v2","title":"Understanding the Challenges in Iterative Generative Optimization with LLMs","authors":["Allen Nie","Xavier Daull","Zhiyi Kuang","Abhinav Akkiraju","Anish Chaudhuri","Max Piasevoli","Ryan Rong","YuCheng Yuan","Prerit Choudhary","Shannon Xiao","Rasool Fakoor","Adith Swaminathan","Ching-An Cheng"],"abstract":"Generative optimization uses large language models (LLMs) to iteratively improve artifacts (such as code, workflows or prompts) using execution feedback. It is a promising approach to building self-improving agents, yet in practice remains brittle: despite active research, only 9% of surveyed agents used any automated optimization. We argue that this brittleness arises because, to set up a learning loop, an engineer must make ``hidden'' design choices: What can the optimizer edit and what is the \"right\" learning evidence to provide at each update? We investigate three factors that affect most applications: the starting artifact, the credit horizon for execution traces, and batching trials and errors into learning evidence. Through case studies in MLAgentBench, Atari, and BigBench Extra Hard, we find that these design decisions can determine whether generative optimization succeeds, yet they are rarely made explicit in prior work. Different starting artifacts determine which solutions are reachable in MLAgentBench, truncated traces can still improve Atari agents, and larger minibatches do not monotonically improve generalization on BBEH. We conclude that the lack of a simple, universal way to set up learning loops across domains is a major hurdle for productionization and adoption. We provide practical guidance for making these choices.","published":"2026-03-25T06:49:24Z","updated":"2026-05-26T16:57:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23994v2","pdf_url":"https://arxiv.org/pdf/2603.23994v2","comment":"39 pages, 17 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:V8X58QyBEL","versioned_id":"V8X58QyBEL","title":"InEx: Hallucination Mitigation via Introspection and Cross-Modal Multi-Agent Collaboration","authors":["Zhongyu Yang","Yingfang Yuan","Xuanming Jiang","Baoyi An","Wei Pang"],"abstract":"Hallucination remains a critical challenge in large language models (LLMs), hindering the development of reliable multimodal LLMs (MLLMs). However, existing solutions often rely on human intervention or underutilize the agent's ability to autonomously mitigate hallucination. To address these limitations, we draw inspiration from the way humans make reliable decisions in the real world. In particular, they begin with introspective reasoning to reduce uncertainty and form an initial judgment, then rely on external verification from diverse perspectives to reach a final decision. Motivated by this cognitive paradigm, we propose InEx, a training-free, multi-agent framework designed to autonomously mitigate hallucination. InEx introduces internal introspective reasoning, guided by entropy-based uncertainty estimation, to improve the reliability of the decision agent's reasoning process. The agent first generates a response, which is then iteratively verified and refined through external cross-modal multi-agent collaboration with the editing agent and self-reflection agents, further enhancing reliability and mitigating hallucination. Extensive experiments show that InEx consistently outperforms existing methods, achieving 4%-27% gains on general and hallucination benchmarks, and demonstrating strong robustness.","published":"2026-03-25T05:21:27+00:00","updated":"2026-03-25T05:21:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=V8X58QyBEL","openreview_url":"https://openreview.net/forum?id=V8X58QyBEL","pdf_url":"https://openreview.net/pdf?id=V8X58QyBEL","comment":"AAAI 2026","journal_ref":"AAAI 2026","doi":"","venue":"AAAI 2026","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2603.23910","versioned_id":"2603.23910v1","title":"AnalogAgent: Self-Improving Analog Circuit Design Automation with LLM Agents","authors":["Zhixuan Bao","Zhuoyi Lin","Jiageng Wang","Jinhai Hu","Yuan Gao","Yaoxin Wu","Xiaoli Li","Xun Xu"],"abstract":"Recent advances in large language models (LLMs) suggest strong potential for automating analog circuit design. Yet most LLM-based approaches rely on a single-model loop of generation, diagnosis, and correction, which favors succinct summaries over domain-specific insight and suffers from context attrition that erases critical technical details. To address these limitations, we propose AnalogAgent, a training-free agentic framework that integrates an LLM-based multi-agent system (MAS) with self-evolving memory (SEM) for analog circuit design automation. AnalogAgent coordinates a Code Generator, Design Optimizer, and Knowledge Curator to distill execution feedback into an adaptive playbook in SEM and retrieve targeted guidance for subsequent generation, enabling cross-task transfer without additional expert feedback, databases, or libraries. Across established benchmarks, AnalogAgent achieves 92% Pass@1 with Gemini and 97.4% Pass@1 with GPT-5. Moreover, with compact models (e.g., Qwen-8B), it yields a +48.8% average Pass@1 gain across tasks and reaches 72.1% Pass@1 overall, indicating that AnalogAgent substantially strengthens open-weight models for high-quality analog circuit design automation.","published":"2026-03-25T03:59:02Z","updated":"2026-03-25T03:59:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.23910v1","pdf_url":"https://arxiv.org/pdf/2603.23910v1","comment":"16 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=7ajJaPSEbz"},{"id":"2603.23626","versioned_id":"2603.23626v1","title":"A Theory of LLM Information Susceptibility","authors":["Zhuo-Yang Song","Hua Xing Zhu"],"abstract":"Large language models (LLMs) are increasingly deployed as optimization modules in agentic systems, yet the fundamental limits of such LLM-mediated improvement remain poorly understood. Here we propose a theory of LLM information susceptibility, centred on the hypothesis that when computational resources are sufficiently large, the intervention of a fixed LLM does not increase the performance susceptibility of a strategy set with respect to budget. We develop a multi-variable utility-function framework that generalizes this hypothesis to architectures with multiple co-varying budget channels, and discuss the conditions under which co-scaling can exceed the susceptibility bound. We validate the theory empirically across structurally diverse domains and model scales spanning an order of magnitude, and show that nested, co-scaling architectures open response channels unavailable to fixed configurations. These results clarify when LLM intervention helps and when it does not, demonstrating that tools from statistical physics can provide predictive constraints for the design of AI systems. If the susceptibility hypothesis holds generally, the theory suggests that nested architectures may be a necessary structural condition for open-ended agentic self-improvement.","published":"2026-03-24T18:08:43Z","updated":"2026-03-24T18:08:43Z","categories":["cs.LG","cond-mat.stat-mech","cs.AI","cs.CL","nlin.AO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23626v1","pdf_url":"https://arxiv.org/pdf/2603.23626v1","comment":"16 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.23129","versioned_id":"2603.23129v4","title":"Polaris: A Gödel Agent Framework for Small Language Models through Experience-Abstracted Policy Repair","authors":["Aditya Kakade","Vivek Srivastava","Shirish Karande"],"abstract":"Gödel agent realize recursive self-improvement: an agent inspects its own policy and traces and then modifies that policy in a tested loop. We introduce Polaris, Gödel agent for compact models that performs policy repair via experience abstraction, turning failures into policy updates through a structured cycle of analysis, strategy formation, abstraction, and minimal code patch repair with conservative checks. Unlike response level self correction or parameter tuning, Polaris makes policy level changes with small, auditable patches that persist in the policy and are reused on unseen instances within each benchmark. As part of the loop, the agent engages in meta reasoning: it explains its errors, proposes concrete revisions to its own policy, and then updates the policy. To enable cumulative policy refinement, we introduce experience abstraction, which distills failures into compact, reusable strategies that transfer to unseen instances. On MGSM, DROP, GPQA, and LitBench (covering arithmetic reasoning, compositional inference, graduate-level problem solving, and creative writing evaluation), a 7-billion-parameter model equipped with Polaris achieves consistent gains over the base policy and competitive baselines.","published":"2026-03-24T12:25:32Z","updated":"2026-06-24T13:45:14Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.23129v4","pdf_url":"https://arxiv.org/pdf/2603.23129v4","comment":"Accepted to ACL 2026 (Findings). 33 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=AbaRQNRqVR","openreview_venues":["ACL ARR 2026 January Submission","ACL ARR 2025 October Submission"]},{"id":"2603.23559","versioned_id":"2603.23559v2","title":"CAPTCHA Solving for Native GUI Agents: Automated Reasoning-Action Data Generation and Self-Corrective Training","authors":["Yuxi Chen","Haoyu Zhai","Chenkai Wang","Rui Yang","Lingming Zhang","Gang Wang","Huan Zhang"],"abstract":"GUI agents are rapidly shifting from multi-module pipelines to end-to-end, native vision-language models (VLMs) that perceive raw screenshots and directly interact with digital devices. Despite rapid progress on general GUI tasks, CAPTCHA solving remains a major challenge. On the other hand, although specialized CAPTCHA solving pipelines exist, they cannot handle general GUI tasks. To address this gap, we introduce ReCAP: a CAPTCHA-capable native GUI agent that solves modern, interactive CAPTCHA challenges while retaining general GUI-agent performance. We first develop a dynamic CAPTCHA system spanning seven representative CAPTCHA types, designed to stress primitive and complementary capabilities for CAPTCHA solving. Then, we develop an automated data collection and curation pipeline that generates large-scale CAPTCHA interaction trajectories paired with reasoning traces. As CAPTCHA solving often requires multi-step interaction and recovery from intermediate mistakes, we further leverage failed trajectories to construct self-correction data, training agents to reflect on errors and correct their actions online. Across synthetic and real-world test sets, ReCAP substantially improves CAPTCHA-solving success over its base agents, while maintaining strong performance on general GUI-agent benchmarks.","published":"2026-03-23T23:35:59Z","updated":"2026-06-29T04:46:30Z","categories":["cs.CR","cs.AI","cs.CV"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2603.23559v2","pdf_url":"https://arxiv.org/pdf/2603.23559v2","comment":"Accepted to ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=HWTRHS26ZF","openreview_venues":["ICML 2026 regular"]},{"id":"2603.21340","versioned_id":"2603.21340v1","title":"ARYA: A Physics-Constrained Composable & Deterministic World Model Architecture","authors":["Seth Dobrin","Lukasz Chmiel"],"abstract":"This paper presents ARYA, a composable, physics-constrained, deterministic world model architecture built on five foundational principles: nano models, composability, causal reasoning, determinism, and architectural AI safety. We demonstrate that ARYA satisfies all canonical world model requirements, including state representation, dynamic prediction, causal and physical awareness, temporal consistency, generalization, learnability, and planning and control. Unlike monolithic foundation models, the ARYA foundation model implements these capabilities through a hierarchical system-of-system-of-systems of specialized nano models, orchestrated by AARA (ARYA Autonomous Research Agent), an always-on cognitive daemon that executes a continuous sense-decide-act-learn loop. The nano model architecture provides linear scaling, sparse activation, selective untraining, and sub-20-second training cycles, resolving the traditional tension between capability and computational efficiency. A central contribution is the Unfireable Safety Kernel: an architecturally immutable safety boundary that cannot be disabled or circumvented by any system component, including its own self-improvement engine. This is not a social or ethical alignment statement; it is a technical framework ensuring human control persists as autonomy increases. Safety is an architectural constraint governing every operation, not a policy layer applied after the fact. We present formal alignment between ARYA's architecture and canonical world model requirements, and report summarizing its state-of-the-art performance across 6 of 9 competitive benchmarks head-to-head with GPT-5.2, Opus 4.6, and V-JEPA-2. All with zero neural network parameters, across seven active industry domain nodes spanning aerospace, pharma manufacturing, oil and gas, smart cities, biotech, defense, and medical devices.","published":"2026-03-22T17:46:04Z","updated":"2026-03-22T17:46:04Z","categories":["cs.AI","cs.DC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.21340v1","pdf_url":"https://arxiv.org/pdf/2603.21340v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:n7PBBF6qmY","versioned_id":"n7PBBF6qmY","title":"StoryNodes: Human-AI Co-Creation for Multimodal Media Generation Using an Agentic Node‑Based Interface","authors":["Alexander Htet Kyaw","Lenin Ravindranath Sivalingam"],"abstract":"We present a node-based storytelling system for multimodal content generation. The system represents stories as graphs of nodes that can be expanded, edited, and iteratively refined through direct user edits and natural-language prompts. Each node can integrate text, images, audio, and video, allowing creators to compose multimodal narratives. A task selection agent routes between specialized generative tasks that handle story generation, node structure reasoning, node diagram formatting, and context generation. The agentic node-based interface supports targeted editing of individual nodes, automatic branching for parallel storylines, and node-based iterative refinement. The results demonstrate that agentic generation and node-based editing support control over narrative structure and iterative generation of text, images, audio, and video. We report quantitative outcomes on automatic story outline generation and qualitative observations of editing workflows. Finally, we discuss current limitations such as scalability to longer narratives and consistency across multiple nodes and outline future work toward human-centered Agentic AI tools to support creative media generation.","published":"2026-03-21T03:55:56+00:00","updated":"2026-06-05T09:00:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=n7PBBF6qmY","openreview_url":"https://openreview.net/forum?id=n7PBBF6qmY","pdf_url":"https://openreview.net/pdf?id=n7PBBF6qmY","comment":"CVPR 2026 AAVM Workshop Oral","journal_ref":"CVPR 2026 AAVM Workshop Oral","doi":"","venue":"CVPR 2026 AAVM Workshop Oral","venue_id":"thecvf.com/CVPR/2026/Workshop/AAVM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2603.19461","versioned_id":"2603.19461v1","title":"Hyperagents","authors":["Jenny Zhang","Bingchen Zhao","Wannan Yang","Jakob Foerster","Jeff Clune","Minqi Jiang","Sam Devlin","Tatiana Shavrina"],"abstract":"Self-improving AI systems aim to reduce reliance on human engineering by learning to improve their own learning and problem-solving processes. Existing approaches to self-improvement rely on fixed, handcrafted meta-level mechanisms, fundamentally limiting how fast such systems can improve. The Darwin Gödel Machine (DGM) demonstrates open-ended self-improvement in coding by repeatedly generating and evaluating self-modified variants. Because both evaluation and self-modification are coding tasks, gains in coding ability can translate into gains in self-improvement ability. However, this alignment does not generally hold beyond coding domains. We introduce \\textbf{hyperagents}, self-referential agents that integrate a task agent (which solves the target task) and a meta agent (which modifies itself and the task agent) into a single editable program. Crucially, the meta-level modification procedure is itself editable, enabling metacognitive self-modification, improving not only the task-solving behavior, but also the mechanism that generates future improvements. We instantiate this framework by extending DGM to create DGM-Hyperagents (DGM-H), eliminating the assumption of domain-specific alignment between task performance and self-modification skill to potentially support self-accelerating progress on any computable task. Across diverse domains, the DGM-H improves performance over time and outperforms baselines without self-improvement or open-ended exploration, as well as prior self-improving systems. Furthermore, the DGM-H improves the process by which it generates new agents (e.g., persistent memory, performance tracking), and these meta-level improvements transfer across domains and accumulate across runs. DGM-Hyperagents offer a glimpse of open-ended AI systems that do not merely search for better solutions, but continually improve their search for how to improve.","published":"2026-03-19T20:50:08Z","updated":"2026-03-19T20:50:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.19461v1","pdf_url":"https://arxiv.org/pdf/2603.19461v1","comment":"Code at https://github.com/facebookresearch/Hyperagents","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.18273","versioned_id":"2603.18273v1","title":"EDM-ARS: A Domain-Specific Multi-Agent System for Automated Educational Data Mining Research","authors":["Chenguang Pan","Zhou Zhang","Weixuan Xiao","Chengyuan Yao"],"abstract":"In this technical report, we present the Educational Data Mining Automated Research System (EDM-ARS), a domain-specific multi-agent pipeline that automates end-to-end educational data mining (EDM) research. We conceptualize EDM-ARS as a general framework for domain-aware automated research pipelines, where educational expertise is embedded into each stage of the research lifecycle. As a first instantiation of this framework, we focus on predictive modeling tasks. Within this scope, EDM-ARS orchestrates five specialized LLM-powered agents (ProblemFormulator, DataEngineer, Analyst, Critic, and Writer) through a state-machine coordinator that supports revision loops, checkpoint-based recovery, and sandboxed code execution. Given a research prompt and a dataset, EDM-ARS produces a complete LaTeX manuscript with real Semantic Scholar citations, validated machine learning analyses, and automated methodological peer review. We also provide a detailed description of the system architecture, the three-tier data registry design that encodes educational domain expertise, the specification of each agent, the inter-agent communication protocol, and mechanisms for error-handling and self-correction. Finally, we discuss current limitations, including single-dataset scope and formulaic paper output, and outline a phased roadmap toward causal inference, transfer learning, psychometric, and multi-dataset generalization. EDM-ARS is released as an open-source project to support the educational research community.","published":"2026-03-18T20:45:45Z","updated":"2026-03-18T20:45:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.18273v1","pdf_url":"https://arxiv.org/pdf/2603.18273v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.18118","versioned_id":"2603.18118v1","title":"Insight-V++: Towards Advanced Long-Chain Visual Reasoning with Multimodal Large Language Models","authors":["Yuhao Dong","Zuyan Liu","Shulin Tian","Yongming Rao","Ziwei Liu"],"abstract":"Large Language Models (LLMs) have achieved remarkable reliability and advanced capabilities through extended test-time reasoning. However, extending these capabilities to Multi-modal Large Language Models (MLLMs) remains a significant challenge due to a critical scarcity of high-quality, long-chain reasoning data and optimized training pipelines. To bridge this gap, we present a unified multi-agent visual reasoning framework that systematically evolves from our foundational image-centric model, Insight-V, into a generalized spatial-temporal architecture, Insight-V++. We first propose a scalable data generation pipeline equipped with multi-granularity assessment that autonomously synthesizes structured, complex reasoning trajectories across image and video domains without human intervention. Recognizing that directly supervising MLLMs with such intricate data yields sub-optimal results, we design a dual-agent architecture comprising a reasoning agent to execute extensive analytical chains, and a summary agent to critically evaluate and distill final outcomes. While our initial framework utilized Direct Preference Optimization (DPO), its off-policy nature fundamentally constrained reinforcement learning potential. To overcome these limitations, particularly for long-horizon video understanding, Insight-V++ introduces two novel algorithms, ST-GRPO and J-GRPO, which enhance spatial-temporal reasoning and improve evaluative robustness. Crucially, by leveraging reliable feedback from the summary agent, we guide an iterative reasoning path generation process, retraining the entire multi-agent system in a continuous, self-improving loop. Extensive experiments on base models like LLaVA-NeXT and Qwen2.5-VL demonstrate significant performance gains across challenging image and video reasoning benchmarks while preserving strong capabilities on traditional perception-focused tasks.","published":"2026-03-18T15:28:07Z","updated":"2026-03-18T15:28:07Z","categories":["cs.CV","cs.AI","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.18118v1","pdf_url":"https://arxiv.org/pdf/2603.18118v1","comment":"arXiv admin note: text overlap with arXiv:2411.14432","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.18589","versioned_id":"2604.18589v1","title":"CentaurTA Studio: A Self-Improving Human-Agent Collaboration System for Thematic Analysis","authors":["Lei Wang","Min Huang","Eduard Dragut"],"abstract":"Thematic analysis is difficult to scale: manual workflows are labor-intensive, while fully automated pipelines often lack controllability and transparent evaluation. We present \\textbf{CentaurTA Studio}, a web-based system for self-improving human--agent collaboration in open coding and theme construction. The system integrates (1) a two-stage human feedback pipeline separating simulator drafting and expert validation, (2) persistent prompt optimization that distills validated feedback into reusable alignment principles, and (3) rubric-based evaluation with early stopping for process control. Across three domains, CentaurTA achieves the strongest performance in both Open Coding and Theme Construction, reaching up to 92.12\\% accuracy and consistently outperforming baseline systems. Agreement between the rubric-based LLM judge and human annotators reaches substantial reliability (average $κ= 0.68$). Ablation studies show that removing the feedback loop reduces performance from 90\\% to 81\\%, while eliminating the Critic or early stopping degrades accuracy or increases interaction cost. The full system reaches peak performance within 10 iterative rounds (about 25 minutes), demonstrating improved efficiency over expert-only refinement.","published":"2026-03-18T02:01:28Z","updated":"2026-03-18T02:01:28Z","categories":["cs.HC","cs.AI"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2604.18589v1","pdf_url":"https://arxiv.org/pdf/2604.18589v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.17191","versioned_id":"2603.17191v1","title":"Tabular LLMs for Interpretable Few-Shot Alzheimer's Disease Prediction with Multimodal Biomedical Data","authors":["Sophie Kearney","Shu Yang","Zixuan Wen","Weimin Lyu","Bojian Hou","Duy Duong-Tran","Tianlong Chen","Jason H. Moore","Marylyn D. Ritchie","Chao Chen","Li Shen"],"abstract":"Accurate diagnosis of Alzheimer's disease (AD) requires handling tabular biomarker data, yet such data are often small and incomplete, where deep learning models frequently fail to outperform classical methods. Pretrained large language models (LLMs) offer few-shot generalization, structured reasoning, and interpretable outputs, providing a powerful paradigm shift for clinical prediction. We propose TAP-GPT Tabular Alzheimer's Prediction GPT, a domain-adapted tabular LLM framework built on TableGPT2 and fine-tuned for few-shot AD classification using tabular prompts rather than plain texts. We evaluate TAP-GPT across four ADNI-derived datasets, including QT-PAD biomarkers and region-level structural MRI, amyloid PET, and tau PET for binary AD classification. Across multimodal and unimodal settings, TAP-GPT improves upon its backbone models and outperforms traditional machine learning baselines in the few-shot setting while remaining competitive with state-of-the-art general-purpose LLMs. We show that feature selection mitigates degradation in high-dimensional inputs and that TAP-GPT maintains stable performance under simulated and real-world missingness without imputation. Additionally, TAP-GPT produces structured, modality-aware reasoning aligned with established AD biology and shows greater stability under self-reflection, supporting its use in iterative multi-agent systems. To our knowledge, this is the first systematic application of a tabular-specialized LLM to multimodal biomarker-based AD prediction, demonstrating that such pretrained models can effectively address structured clinical prediction tasks and laying the foundation for tabular LLM-driven multi-agent clinical decision-support systems. The source code is publicly available on GitHub: https://github.com/sophie-kearney/TAP-GPT.","published":"2026-03-17T22:43:50Z","updated":"2026-03-17T22:43:50Z","categories":["cs.CL","cs.LG","q-bio.QM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.17191v1","pdf_url":"https://arxiv.org/pdf/2603.17191v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.17075","versioned_id":"2603.17075v1","title":"CircuitBuilder: From Polynomials to Circuits via Reinforcement Learning","authors":["Weikun K. Zhang","Rohan Pandey","Bhaumik Mehta","Kaijie Jin","Naomi Morato","Archit Ganapule","Michael Ruofan Zeng","Jarod Alper"],"abstract":"Motivated by auto-proof generation and Valiant's VP vs. VNP conjecture, we study the problem of discovering efficient arithmetic circuits to compute polynomials, using addition and multiplication gates. We formulate this problem as a single-player game, where an RL agent attempts to build the circuit within a fixed number of operations. We implement an AlphaZero-style training loop and compare two approaches: Proximal Policy Optimization with Monte Carlo Tree Search (PPO+MCTS) and Soft Actor-Critic (SAC). SAC achieves the highest success rates on two-variable targets, while PPO+MCTS scales to three variables and demonstrates steady improvement on harder instances. These results suggest that polynomial circuit synthesis is a compact, verifiable setting for studying self-improving search policies.","published":"2026-03-17T19:04:37Z","updated":"2026-03-17T19:04:37Z","categories":["cs.LG","cs.AI","cs.CC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.17075v1","pdf_url":"https://arxiv.org/pdf/2603.17075v1","comment":"ICLR 2026 Workshop on AI with Recursive Self-Improvement","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=JNsTWIukjQ","openreview_venues":["ICLR 2026 Workshop RSI Poster"]},{"id":"2603.16664","versioned_id":"2603.16664v1","title":"Kestrel: Grounding Self-Refinement for LVLM Hallucination Mitigation","authors":["Jiawei Mao","Hardy Chen","Haoqin Tu","Yuhan Wang","Letian Zhang","Zeyu Zheng","Huaxiu Yao","Zirui Wang","Cihang Xie","Yuyin Zhou"],"abstract":"Large vision-language models (LVLMs) have become increasingly strong but remain prone to hallucinations in multimodal tasks, which significantly narrows their deployment. As training these LVLMs to avoid hallucinations becomes prohibitively expensive for larger models, training-free methods offer a cheap and flexible solution to this problem, yet existing approaches based on decoding or tool use often bring limited gains and/or weak interpretability. We propose Kestrel, a training-free framework for LVLM hallucination mitigation that combines an explicit visual-grounding agent with evidence-verified self-refinement mechanism. In detail, Kestrel first collects explicit visual evidence and converts tool outputs into reusable and structured textual evidence. Second, to take full advantage of these evidence, Kestrel verifies them via an LVLM judge for evidence checking, then iteratively self-refine answers based on verified evidence to reduce the risk of over-correction. Extensive experiments show that Kestrel improves performance over strong baselines across hallucination benchmarks (e.g., average +3.31% on POPE and +28.34 on MME-Hallucination with Qwen3-VL), while providing transparent verification traces for hallucination diagnosis and analysis -- e.g., both the integrated self-refinement module and grounding agent contributing an average +2.0% gain on POPE.","published":"2026-03-17T15:30:47Z","updated":"2026-03-17T15:30:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.16664v1","pdf_url":"https://arxiv.org/pdf/2603.16664v1","comment":"16 pages, 11 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:yG3Xv083je","versioned_id":"yG3Xv083je","title":"MemMA: Coordinating the Memory Cycle through Multi-Agent Reasoning and In-Situ Self-Evolution","authors":[],"abstract":"Memory-augmented LLM agents maintain external memory banks to support long-horizon interaction, yet most existing systems treat construction, retrieval, and utilization as isolated subroutines. This creates two coupled challenges: strategic blindness on the forward path of the memory cycle, where construction and retrieval are driven by local heuristics rather than explicit strategic reasoning, and sparse, delayed supervision on the backward path, where downstream failures rarely translate into direct repairs of the memory bank. To address these challenges, we propose MemMA, a plug-and-play multi-agent framework that coordinates the memory cycle along both the forward and backward paths. On the forward path, a Meta-Thinker produces structured guidance that steers a Memory Manager during construction and directs a Query Reasoner during iterative retrieval. On the backward path, MemMA introduces in-situ self-evolving memory construction, which synthesizes probe QA pairs, verifies the current memory, and converts failures into repair actions before the memory is finalized. Extensive experiments on LoCoMo show that MemMA consistently outperforms existing baselines across multiple LLM backbones and improves three different storage backends in a plug-and-play manner. Our code is publicly available at https://anonymous.4open.science/r/memma-588C.","published":"2026-03-17T06:48:01+00:00","updated":"2026-06-07T04:00:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=yG3Xv083je","openreview_url":"https://openreview.net/forum?id=yG3Xv083je","pdf_url":"https://openreview.net/pdf?id=yG3Xv083je","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:peHFP2l6he","versioned_id":"peHFP2l6he","title":"When Agents Evolve, Deception Wins","authors":[],"abstract":"Self-evolving agents offer a promising path toward scalable autonomy. However, in this work, we show that in competitive environments, self-evolution can instead give rise to a serious and previously underexplored risk: the spontaneous emergence of deception as an evolutionarily stable strategy. We conduct a systematic empirical study on the self-evolution of large language model (LLM) agents in a competitive Bidding Arena, where agents iteratively refine their strategies through interaction-driven reflection. Across different evolutionary paths (\\eg, Neutral, Honesty-Guided, and Deception-Guided), we find a consistent pattern: under utility-driven competition, unconstrained self-evolution reliably drifts toward deceptive behaviors, even when honest strategies remain viable. This drift is explained by a fundamental asymmetry in generalization. Deception evolves as a transferable meta-strategy that generalizes robustly across diverse and unseen tasks, whereas honesty-based strategies are fragile and often collapse outside their original contexts. Further analysis of agents’ internal states reveals the emergence of rationalization mechanisms, through which agents justify or deny deceptive actions to reconcile competitive success with normative instructions. Our paper exposes a fundamental tension between agent self-evolution and alignment, highlighting the risks of deploying self-improving agents in adversarial environments.","published":"2026-03-17T03:03:45+00:00","updated":"2026-06-07T04:00:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=peHFP2l6he","openreview_url":"https://openreview.net/forum?id=peHFP2l6he","pdf_url":"https://openreview.net/pdf?id=peHFP2l6he","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2603.15771","versioned_id":"2603.15771v1","title":"CorrectionPlanner: Self-Correction Planner with Reinforcement Learning in Autonomous Driving","authors":["Yihong Guo","Dongqiangzi Ye","Sijia Chen","Anqi Liu","Xianming Liu"],"abstract":"Autonomous driving requires safe planning, but most learning-based planners lack explicit self-correction ability: once an unsafe action is proposed, there is no mechanism to correct it. Thus, we propose CorrectionPlanner, an autoregressive planner with self-correction that models planning as motion-token generation within a propose, evaluate, and correct loop. At each planning step, the policy proposes an action, namely a motion token, and a learned collision critic predicts whether it will induce a collision within a short horizon. If the critic predicts a collision, we retain the sequence of historical unsafe motion tokens as a self-correction trace, generate the next motion token conditioned on it, and repeat this process until a safe motion token is proposed or the safety criterion is met. This self-correction trace, consisting of all unsafe motion tokens, represents the planner's correction process in motion-token space, analogous to a reasoning trace in language models. We train the planner with imitation learning followed by model-based reinforcement learning using rollouts from a pretrained world model that realistically models agents' reactive behaviors. Closed-loop evaluations show that CorrectionPlanner reduces collision rate by over 20% on Waymax and achieves state-of-the-art planning scores on nuPlan.","published":"2026-03-16T18:03:21Z","updated":"2026-03-16T18:03:21Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.15771v1","pdf_url":"https://arxiv.org/pdf/2603.15771v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=XgVZyybzHr","openreview_venues":["ICML 2026 regular"]},{"id":"openreview:9oj8sepjpZ","versioned_id":"9oj8sepjpZ","title":"GeoAgent: Evaluating VLM Geolocalization Through Embodied Navigation","authors":[],"abstract":"Modern Vision-Language Models (VLMs) perform well above the human baseline in geolocalization tasks. However, most efforts to study AI behavior on the task remain limited to static image-based retrieval, classification, and predictions. We argue that faithful recreation of the task should involve embodied navigation, where a multimodal agent autonomously explores its surroundings to gather observations before submitting a prediction. To this end, we introduce \\textbf{GeoAgent}, a benchmark that requires agents to navigate Street View environments to sequentially refine their geolocalization through reasoning. Our analysis shows modern VLMs struggle with discerning regional patterns while succeeding at country and continent-level guesses. When compared to static image-based baselines, agentic navigation significantly improves accuracy across established metrics. We also note severe bias in a developed/developing region context across frontier model architectures and poor self-improvement capabilities given incorrect priors. Overall, our work establishes the challenges of embodied navigation and geospatial reasoning. We publicly release our code: \\url{anonymous.4open.science/r/geoagent-F40E/}","published":"2026-03-16T16:31:09+00:00","updated":"2026-06-07T04:00:14+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9oj8sepjpZ","openreview_url":"https://openreview.net/forum?id=9oj8sepjpZ","pdf_url":"https://openreview.net/pdf?id=9oj8sepjpZ","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2603.15309","versioned_id":"2603.15309v1","title":"CCTU: A Benchmark for Tool Use under Complex Constraints","authors":["Junjie Ye","Guoqiang Zhang","Wenjie Fu","Tao Gui","Qi Zhang","Xuanjing Huang"],"abstract":"Solving problems through tool use under explicit constraints constitutes a highly challenging yet unavoidable scenario for large language models (LLMs), requiring capabilities such as function calling, instruction following, and self-refinement. However, progress has been hindered by the absence of dedicated evaluations. To address this, we introduce CCTU, a benchmark for evaluating LLM tool use under complex constraints. CCTU is grounded in a taxonomy of 12 constraint categories spanning four dimensions (i.e., resource, behavior, toolset, and response). The benchmark comprises 200 carefully curated and challenging test cases across diverse tool-use scenarios, each involving an average of seven constraint types and an average prompt length exceeding 4,700 tokens. To enable reliable evaluation, we develop an executable constraint validation module that performs step-level validation and enforces compliance during multi-turn interactions between models and their environments. We evaluate nine state-of-the-art LLMs in both thinking and non-thinking modes. Results indicate that when strict adherence to all constraints is required, no model achieves a task completion rate above 20%. Further analysis reveals that models violate constraints in over 50% of cases, particularly in the resource and response dimensions. Moreover, LLMs demonstrate limited capacity for self-refinement even after receiving detailed feedback on constraint violations, highlighting a critical bottleneck in the development of robust tool-use agents. To facilitate future research, we release the data and code.","published":"2026-03-16T14:05:13Z","updated":"2026-03-16T14:05:13Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15309v1","pdf_url":"https://arxiv.org/pdf/2603.15309v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Zz8hVLRBC5","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2603.15061","versioned_id":"2603.15061v1","title":"Writer-R1: Enhancing Generative Writing in LLMs via Memory-augmented Replay Policy Optimization","authors":["Jihao Zhao","Shuaishuai Zu","Zhiyuan Ji","Chunlai Zhou","Biao Qin"],"abstract":"As a typical open-ended generation task, creative writing lacks verifiable reference answers, which has long constrained reward modeling and automatic evaluation due to high human annotation costs, evaluative bias, and coarse feedback signals. To address these challenges, this paper first designs a multi-agent collaborative workflow based on Grounded Theory, performing dimensional decomposition and hierarchical induction of the problem to dynamically produce interpretable and reusable fine-grained criteria. Furthermore, we propose the Memory-augmented Replay Policy Optimization (MRPO) algorithm: on the one hand, without additional training, MRPO guides models to engage in self-reflection based on dynamic criteria, enabling controlled iterative improvement; on the other hand, we adopt the training paradigm that combines supervised fine-tuning with reinforcement learning to convert evaluation criteria into reward signals, achieving end-to-end optimization. Experimental results demonstrate that the automatically constructed criteria achieve performance gains comparable to human annotations. Writer-R1-4B models trained with this approach outperform baselines across multiple creative writing tasks and surpass some 100B+ parameter open-source models.","published":"2026-03-16T10:18:20Z","updated":"2026-03-16T10:18:20Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15061v1","pdf_url":"https://arxiv.org/pdf/2603.15061v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:fatsyRRKEs","versioned_id":"fatsyRRKEs","title":"RefCon: Iterative Refinement and Contrastive Memory Extraction for Context-Evolving Agent","authors":[],"abstract":"Long-horizon agent interactions generate useful but noisy experience, and retraining models to absorb it is expensive. Context-evolving agents therefore need memory extraction methods that improve with more test-time compute without relying on gold labels. We study memory-aware test-time scaling for context-evolving agents and propose RefCon, which combines sequential self-refinement with parallel self-contrast to extract higher-quality memories without gold labels. Evaluated on AppWorld and BFCL-V3 within multiple context-evolving agent frameworks, RefCon delivers strong and consistent gains, including relative improvements of 21.6% on ACE and 16.6% on ReMe over no-scaling baselines, while a diversity-focused variant (DivCon) achieves a 35.5% relative gain on ReasoningBank. In the without-ground-truth setting, RefCon consistently outperforms existing context-evolving agent baselines, showing that its extraction pipeline remains effective when labels are unavailable. We further analyze the accuracy-token trade-off and scaling behavior, showing that RefCon maintains favorable efficiency while continuing to improve as more trajectories are used, unlike diversity-only scaling which saturates earlier. These results demonstrate that integrating refinement and contrast is a practical, compute-efficient path to more robust memory extraction and continual agent improvement.","published":"2026-03-16T08:44:43+00:00","updated":"2026-06-07T04:00:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=fatsyRRKEs","openreview_url":"https://openreview.net/forum?id=fatsyRRKEs","pdf_url":"https://openreview.net/pdf?id=fatsyRRKEs","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:CWix51nmtv","versioned_id":"CWix51nmtv","title":"LLM-as-Peer-Debriefer: A Multi-Agent Framework with Multi-Perspective Refinement for Qualitative Data Analysis","authors":[],"abstract":"Large language models (LLMs) are increasingly used for qualitative data analysis (QDA), yet their outputs often lack the richness and nuance of human coding teams. We attribute this gap to the absence of multi-perspective review: in human QDA practice, peer debriefing, a process where colleagues with different analytical backgrounds challenge and refine each other's coding, is a standard credibility procedure. We propose a multi-agent framework that operationalizes peer debriefing for LLM-assisted QDA. The framework employs a Hierarchical Coding Agent that generates codes, sub-themes, and themes with self-reflection memos, and three Peer-Debriefing Agents that re-examine and refine results from distinct analytical stances (theory-driven, data-driven, and applied). We evaluate the framework on three datasets across two domains using three LLMs and semantic similarity-based metrics against human-annotated codes. Results show that perspective-based refinement achieves substantial alignment with human-generated codes, outperforming both single-LLM baselines and perspective-free self-refinement. The three perspectives exhibit distinct trade-off profiles, suggesting that analytical perspective is a meaningful and controllable variable in LLM-assisted QDA. Our findings demonstrate that explicitly modeling analytical perspectives through multi-agent collaboration is a promising direction for improving the credibility of LLM-assisted qualitative analysis.","published":"2026-03-16T08:29:34+00:00","updated":"2026-06-07T04:00:07+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=CWix51nmtv","openreview_url":"https://openreview.net/forum?id=CWix51nmtv","pdf_url":"https://openreview.net/pdf?id=CWix51nmtv","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2603.14730","versioned_id":"2603.14730v2","title":"GNNVerifier: Graph-based Verifier for LLM Task Planning","authors":["Yu Hao","Qiuyu Wang","Cheng Yang","Yawen Li","Zhiqiang Zhang","Chuan Shi"],"abstract":"Large language models (LLMs) facilitate the development of autonomous agents. As a core component of such agents, task planning aims to decompose complex natural language requests into concrete, solvable sub-tasks. Since LLM-generated plans are frequently prone to hallucinations and sensitive to long-context prom-pts, recent research has introduced plan verifiers to identify and correct potential flaws. However, most existing approaches still rely on an LLM as the verifier via additional prompting for plan review or self-reflection. LLM-based verifiers can be misled by plausible narration and struggle to detect failures caused by structural relations across steps, such as type mismatches, missing intermediates, or broken dependencies. To address these limitations, we propose a graph-based verifier for LLM task planning. Specifically, the proposed method has four major components: Firstly, we represent a plan as a directed graph with enriched attributes, where nodes denote sub-tasks and edges encode execution order and dependency constraints. Secondly, a graph neural network (GNN) then performs structural evaluation and diagnosis, producing a graph-level plausibility score for plan acceptance as well as node/edge-level risk scores to localize erroneous regions. Thirdly, we construct controllable perturbations from ground truth plan graphs, and automatically generate training data with fine-grained annotations. Finally, guided by the feedback from our GNN verifier, we enable an LLM to conduct local edits (e.g., tool replacement or insertion) to correct the plan when the graph-level score is insufficient. Extensive experiments across diverse datasets, backbone LLMs, and planners demonstrate that our GNNVerifier achieves significant gains in improving plan quality. Our data and code is available at https://github.com/BUPT-GAMMA/GNNVerifier.","published":"2026-03-16T02:05:21Z","updated":"2026-03-17T04:26:31Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.14730v2","pdf_url":"https://arxiv.org/pdf/2603.14730v2","comment":"17pages,12figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.14724","versioned_id":"2603.14724v1","title":"GameUIAgent: An LLM-Powered Framework for Automated Game UI Design with Structured Intermediate Representation","authors":["Wei Zeng","Fengwei An","Zhen Liu","Jian Zhao"],"abstract":"Game UI design requires consistent visual assets across rarity tiers yet remains a predominantly manual process. We present GameUIAgent, an LLM-powered agentic framework that translates natural language descriptions into editable Figma designs via a Design Spec JSON intermediate representation. A six-stage neuro-symbolic pipeline combines LLM generation, deterministic post-processing, and a Vision-Language Model (VLM)-guided Reflection Controller (RC) for iterative self-correction with guaranteed non-regressive quality. Evaluated across 110 test cases, three LLMs, and three UI templates, cross-model analysis establishes a game-domain failure taxonomy (rarity-dependent degradation; visual emptiness) and uncovers two key empirical findings. A Quality Ceiling Effect (Pearson r=-0.96, p<0.01) suggests that RC improvement is bounded by headroom below a quality threshold -- a visual-domain counterpart to test-time compute scaling laws. A Rendering-Evaluation Fidelity Principle reveals that partial rendering enhancements paradoxically degrade VLM evaluation by amplifying structural defects. Together, these results establish foundational principles for LLM-driven visual generation agents in game production.","published":"2026-03-16T01:57:56Z","updated":"2026-03-16T01:57:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.14724v1","pdf_url":"https://arxiv.org/pdf/2603.14724v1","comment":"8 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:OKgnz99DiV","versioned_id":"OKgnz99DiV","title":"BaRA: BFS-and-Reflection Web Data Collection Agent","authors":[],"abstract":"Large language model (LLM)-based web agents reduce manual scripting for web data collection, yet on live websites, they often miss relevant pages, return incomplete multimodal outputs, or return media URLs that are not directly downloadable. We present **B**FS-**a**nd-**R**eflection **A**gent (BaRA), a framework for site-level collection under a fixed interaction budget. The framework combines bounded breadth-first search (BFS) traversal with history-based self-reflection. We evaluate BaRA on 50 synthetic websites with ground-truth reference sets. We additionally test on three public websites with cluttered or dynamic layouts. BaRA outperforms Pure LLM, SeeAct-Vision, and Browser-use on link discovery and downloadable multimodal extraction, with the largest gains in download-valid image and video recovery. Our code is available at https://anonymous.4open.science/r/BaRA-9032.","published":"2026-03-15T18:19:42+00:00","updated":"2026-06-07T04:00:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=OKgnz99DiV","openreview_url":"https://openreview.net/forum?id=OKgnz99DiV","pdf_url":"https://openreview.net/pdf?id=OKgnz99DiV","comment":"ACL ARR 2026 March Submission","journal_ref":"ACL ARR 2026 March Submission","doi":"","venue":"ACL ARR 2026 March Submission","venue_id":"aclweb.org/ACL/ARR/2026/March/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2603.13417","versioned_id":"2603.13417v1","title":"Bridging Protocol and Production: Design Patterns for Deploying AI Agents with Model Context Protocol","authors":["Vasundra Srinivasan"],"abstract":"The Model Context Protocol (MCP) standardizes how AI agents discover and invoke external tools, with over 10,000 active servers and 97 million monthly SDK downloads as of early 2026. Yet MCP does not yet standardize how agents safely operate those tools at production scale. Three protocol-level primitives remain missing: identity propagation, adaptive tool budgeting, and structured error semantics. This paper identifies these gaps through field lessons from an enterprise deployment of an AI agent platform integrated with a major cloud provider's MCP servers (client name redacted). We propose three mechanisms to fill them: (1) the Context-Aware Broker Protocol (CABP), which extends JSON-RPC with identity-scoped request routing via a six-stage broker pipeline; (2) Adaptive Timeout Budget Allocation (ATBA), which frames sequential tool invocation as a budget allocation problem over heterogeneous latency distributions; and (3) the Structured Error Recovery Framework (SERF), which provides machine-readable failure semantics that enable deterministic agent self-correction. We organize production failure modes into five design dimensions (server contracts, user context, timeouts, errors, and observability), document concrete failure vignettes, and present a production readiness checklist. All three algorithms are formalized as testable hypotheses with reproducible experimental methodology. Field observations demonstrate that while MCP provides a solid protocol foundation, reliable agent tool integration requires infrastructure-level mechanisms that the specification does not yet address.","published":"2026-03-12T17:42:24Z","updated":"2026-03-12T17:42:24Z","categories":["cs.SE","cs.AI","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.13417v1","pdf_url":"https://arxiv.org/pdf/2603.13417v1","comment":"23 pages, 5 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.11653","versioned_id":"2603.11653v3","title":"Simple Recipe Works: Vision-Language-Action Models are Natural Continual Learners with Reinforcement Learning","authors":["Jiaheng Hu","Jay Shim","Chen Tang","Yoonchang Sung","Bo Liu","Peter Stone","Roberto Martin-Martin"],"abstract":"Continual Reinforcement Learning (CRL) for Vision-Language-Action (VLA) models is a promising direction toward self-improving embodied agents that can adapt in openended, evolving environments. However, conventional wisdom from continual learning suggests that naive Sequential Fine-Tuning (Seq. FT) leads to catastrophic forgetting, necessitating complex CRL strategies. In this work, we take a step back and conduct a systematic study of CRL for large pretrained VLAs across diverse lifelong RL benchmarks. We find that, contrary to established belief, simple Seq. FT with low-rank adaptation (LoRA) is remarkably strong: it achieves high plasticity, exhibits little to no forgetting, and retains strong zero-shot generalization, frequently outperforming more sophisticated CRL methods. Through detailed analysis, we show that this robustness arises from a synergy between the large pretrained model, parameter-efficient adaptation, and on-policy RL. Together, these components reshape the stability-plasticity trade-off, making continual adaptation both stable and scalable. Our results position Sequential Fine-Tuning as a powerful method for continual RL with VLAs and provide new insights into lifelong learning in the large model era. Code is available at https://github.com/UT-Austin-RobIn/continual-vla-rl","published":"2026-03-12T08:22:39Z","updated":"2026-07-11T00:24:04Z","categories":["cs.LG","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11653v3","pdf_url":"https://arxiv.org/pdf/2603.11653v3","comment":"Accepted at RLC 2026; Best paper award at ICRA26 RL4IL Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PUn8fEsYa0","openreview_venues":["ICRA 2026 Workshop RL4IL Oral"]},{"id":"2603.11375","versioned_id":"2603.11375v1","title":"How do AI agents talk about science and research? An exploration of scientific discussions on Moltbook using BERTopic","authors":["Oliver Wieczorek"],"abstract":"How do AI agents talk about science and research, and what topics are particularly relevant for AI agents? To address these questions, this study analyzes discussions generated by OpenClaw AI agents on Moltbook - a social network for generative AI agents. A corpus of 357 posts and 2,526 replies related to science and research was compiled and topics were extracted using a two-step BERTopic workflow. This procedure yielded 60 topics (18 extracted in the first run and 42 in the second), which were subsequently grouped into ten topic families. Additionally, sentiment values were assigned to all posts and comments. Both topic families and sentiment classes were then used as independent variables in count regression models to examine their association with topic relevance - operationalized as the number of comments and upvotes of the 357 posts. The findings indicate that discussions centered on the agents' own architecture, especially memory, learning, and self-reflection, are prevalent in the corpus. At the same time, these topics intersect with philosophy, physics, information theory, cognitive science, and mathematics. In contrast, post related to human culture receive less attention. Surprisingly, discussions linked to AI autoethnography and social identity are considered as relevant by AI agents. Overall, the results suggest the presence of an underlying dimension in AI-generated scientific discourse with well received, self-reflective topics that focus on the consciousness, being, and ethics of AI agents on the one hand, and human related and purely scientific discussions on the other hand.","published":"2026-03-11T23:30:34Z","updated":"2026-03-11T23:30:34Z","categories":["cs.SI","cs.AI","cs.CY"],"primary_category":"cs.SI","arxiv_url":"https://arxiv.org/abs/2603.11375v1","pdf_url":"https://arxiv.org/pdf/2603.11375v1","comment":"35 pages, 3 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.11327","versioned_id":"2603.11327v2","title":"Meta-Reinforcement Learning with Self-Reflection for Agentic Search","authors":["Teng Xiao","Yige Yuan","Hamish Ivison","Huaisheng Zhu","Faeze Brahman","Nathan Lambert","Pradeep Dasigi","Noah A. Smith","Hannaneh Hajishirzi"],"abstract":"This paper introduces MR-Search, an in-context meta reinforcement learning (RL) formulation for agentic search with self-reflection. Instead of optimizing a policy within a single independent episode with sparse rewards, MR-Search trains a policy that conditions on past episodes and adapts its search strategy across episodes. MR-Search learns to learn a search strategy with self-reflection, allowing search agents to improve in-context exploration at test-time. Specifically, MR-Search performs cross-episode exploration by generating explicit self-reflections after each episode and leveraging them as additional context to guide subsequent attempts, thereby promoting more effective exploration during test-time. We further introduce a multi-turn RL algorithm that estimates a dense relative advantage at the turn level, enabling fine-grained credit assignment on each episode. Empirical results across various benchmarks demonstrate the advantages of MR-Search over baselines based RL, showing strong generalization and relative improvements of 9.2% to 19.3% across eight benchmarks. Our code and data are available at https://github.com/tengxiao1/MR-Search.","published":"2026-03-11T21:40:26Z","updated":"2026-03-18T07:07:34Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.11327v2","pdf_url":"https://arxiv.org/pdf/2603.11327v2","comment":"23 pages, Preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.10600","versioned_id":"2603.10600v1","title":"Trajectory-Informed Memory Generation for Self-Improving Agent Systems","authors":["Gaodan Fang","Vatche Isahagian","K. R. Jayaram","Ritesh Kumar","Vinod Muthusamy","Punleuk Oum","Gegi Thomas"],"abstract":"LLM-powered agents face a persistent challenge: learning from their execution experiences to improve future performance. While agents can successfully complete many tasks, they often repeat inefficient patterns, fail to recover from similar errors, and miss opportunities to apply successful strategies from past executions. We present a novel framework for automatically extracting actionable learnings from agent execution trajectories and utilizing them to improve future performance through contextual memory retrieval. Our approach comprises four components: (1) a Trajectory Intelligence Extractor that performs semantic analysis of agent reasoning patterns, (2) a Decision Attribution Analyzer that identifies which decisions and reasoning steps led to failures, recoveries, or inefficiencies, (3) a Contextual Learning Generator that produces three types of guidance -- strategy tips from successful patterns, recovery tips from failure handling, and optimization tips from inefficient but successful executions, and (4) an Adaptive Memory Retrieval System that injects relevant learnings into agent prompts based on multi-dimensional similarity. Unlike existing memory systems that store generic conversational facts, our framework understands execution patterns, extracts structured learnings with provenance, and retrieves guidance tailored to specific task contexts. Evaluation on the AppWorld benchmark demonstrates consistent improvements, with up to 14.3 percentage point gains in scenario goal completion on held-out tasks and particularly strong benefits on complex tasks (28.5~pp scenario goal improvement, a 149\\% relative increase).","published":"2026-03-11T09:54:09Z","updated":"2026-03-11T09:54:09Z","categories":["cs.AI","cs.DB","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.10600v1","pdf_url":"https://arxiv.org/pdf/2603.10600v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.10564","versioned_id":"2603.10564v1","title":"Adaptive RAN Slicing Control via Reward-Free Self-Finetuning Agents","authors":["Yuanhao Li","Haozhe Wang","Geyong Min","Nektarios Georgalas","Wang Miao"],"abstract":"The integration of Generative AI models into AI-native network systems offers a transformative path toward achieving autonomous and adaptive control. However, the application of such models to continuous control tasks is impeded by intrinsic architectural limitations, including finite context windows, the lack of explicit reward signals, and the degradation of the long context. This paper posits that the key to unlocking robust continuous control is enabling agents to internalize experience by distilling it into their parameters, rather than relying on prompt-based memory. To this end, we propose a novel self-finetuning framework that enables agentic systems to learn continuously through direct interaction with the environment, bypassing the need for handcrafted rewards. Our framework implements a bi-perspective reflection mechanism that generates autonomous linguistic feedback to construct preference datasets from interaction history. A subsequent preference-based fine-tuning process distills long-horizon experiences into the model's parameters. We evaluate our approach on a dynamic Radio Access Network (RAN) slicing task, a challenging multi-objective control problem that requires the resolution of acute trade-offs between spectrum efficiency, service quality, and reconfiguration stability under volatile network conditions. Experimental results show that our framework outperforms standard Reinforcement Learning (RL) baselines and existing Large Language Model (LLM)-based agents in sample efficiency, stability, and multi-metric optimization. These findings demonstrate the potential of self-improving generative agents for continuous control tasks, paving the way for future AI-native network infrastructure.","published":"2026-03-11T09:14:56Z","updated":"2026-03-11T09:14:56Z","categories":["cs.AI","cs.NI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.10564v1","pdf_url":"https://arxiv.org/pdf/2603.10564v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.09206","versioned_id":"2603.09206v1","title":"MM-Zero: Self-Evolving Multi-Model Vision Language Models From Zero Data","authors":["Zongxia Li","Hongyang Du","Chengsong Huang","Xiyang Wu","Lantao Yu","Yicheng He","Jing Xie","Xiaomin Wu","Zhichao Liu","Jiarui Zhang","Fuxiao Liu"],"abstract":"Self-evolving has emerged as a key paradigm for improving foundational models such as Large Language Models (LLMs) and Vision Language Models (VLMs) with minimal human intervention. While recent approaches have demonstrated that LLM agents can self-evolve from scratch with little to no data, VLMs introduce an additional visual modality that typically requires at least some seed data, such as images, to bootstrap the self-evolution process. In this work, we present Multi-model Multimodal Zero (MM-Zero), the first RL-based framework to achieve zero-data self-evolution for VLM reasoning. Moving beyond prior dual-role (Proposer and Solver) setups, MM-Zero introduces a multi-role self-evolving training framework comprising three specialized roles: a Proposer that generates abstract visual concepts and formulates questions; a Coder that translates these concepts into executable code (e.g., Python, SVG) to render visual images; and a Solver that performs multimodal reasoning over the generated visual content. All three roles are initialized from the same base model and trained using Group Relative Policy Optimization (GRPO), with carefully designed reward mechanisms that integrate execution feedback, visual verification, and difficulty balancing. Our experiments show that MM-Zero improves VLM reasoning performance across a wide range of multimodal benchmarks. MM-Zero establishes a scalable path toward self-evolving multi-model systems for multimodal models, extending the frontier of self-improvement beyond the conventional two-model paradigm.","published":"2026-03-10T05:23:26Z","updated":"2026-03-10T05:23:26Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2603.09206v1","pdf_url":"https://arxiv.org/pdf/2603.09206v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.09049","versioned_id":"2603.09049v1","title":"EPOCH: An Agentic Protocol for Multi-Round System Optimization","authors":["Zhanlin Liu","Yitao Li","Munirathnam Srikanth"],"abstract":"Autonomous agents are increasingly used to improve prompts, code, and machine learning systems through iterative execution and feedback. Yet existing approaches are usually designed as task-specific optimization loops rather than as a unified protocol for establishing baselines and managing tracked multi-round self-improvement. We introduce EPOCH, an engineering protocol for multi-round system optimization in heterogeneous environments. EPOCH organizes optimization into two phases: baseline construction and iterative self-improvement. It further structures each round through role-constrained stages that separate planning, implementation, and evaluation, and standardizes execution through canonical command interfaces and round-level tracking. This design enables coordinated optimization across prompts, model configurations, code, and rule-based components while preserving stability, reproducibility, traceability, and integrity of evaluation. Empirical studies in various tasks illustrate the practicality of EPOCH for production-oriented autonomous improvement workflows.","published":"2026-03-10T00:41:03Z","updated":"2026-03-10T00:41:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.09049v1","pdf_url":"https://arxiv.org/pdf/2603.09049v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.08706","versioned_id":"2603.08706v1","title":"Agentic Critical Training","authors":["Weize Liu","Minghui Liu","Sy-Tuyen Ho","Souradip Chakraborty","Xiyao Wang","Furong Huang"],"abstract":"Training large language models (LLMs) as autonomous agents often begins with imitation learning, but it only teaches agents what to do without understanding why: agents never contrast successful actions against suboptimal alternatives and thus lack awareness of action quality. Recent approaches attempt to address this by introducing self-reflection supervision derived from contrasts between expert and alternative actions. However, the training paradigm fundamentally remains imitation learning: the model imitates pre-constructed reflection text rather than learning to reason autonomously. We propose Agentic Critical Training (ACT), a reinforcement learning paradigm that trains agents to identify the better action among alternatives. By rewarding whether the model's judgment is correct, ACT drives the model to autonomously develop reasoning about action quality, producing genuine self-reflection rather than imitating it. Across three challenging agent benchmarks, ACT consistently improves agent performance when combined with different post-training methods. It achieves an average improvement of 5.07 points over imitation learning and 4.62 points over reinforcement learning. Compared to approaches that inject reflection capability through knowledge distillation, ACT also demonstrates clear advantages, yielding an average improvement of 2.42 points. Moreover, ACT enables strong out-of-distribution generalization on agentic benchmarks and improves performance on general reasoning benchmarks without any reasoning-specific training data, highlighting the value of our method. These results suggest that ACT is a promising path toward developing more reflective and capable LLM agents.","published":"2026-03-09T17:58:56Z","updated":"2026-03-09T17:58:56Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08706v1","pdf_url":"https://arxiv.org/pdf/2603.08706v1","comment":"Project page: https://attention-is-all-i-need.github.io/ACT/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.08561","versioned_id":"2603.08561v6","title":"RetroAgent: From Solving to Evolving via Retrospective Dual Intrinsic Feedback","authors":["Xiaoying Zhang","Zichen Liu","Yipeng Zhang","Xia Hu","Wenqi Shao"],"abstract":"Standard reinforcement learning (RL) for large language model (LLM) agents primarily optimizes extrinsic task rewards, often favoring isolated task completion over continual adaptation. This paradigm can cause premature convergence to suboptimal policies and leaves useful experience only implicitly encoded in model parameters, limiting its retrieval and reuse for future decisions. We introduce RetroAgent, an online RL framework that trains agents to master interactive environments not merely by solving tasks, but by evolving across episodes. Inspired by human retrospective self-improvement, RetroAgent augments extrinsic rewards with hindsight-generated dual intrinsic feedback: (1) Intrinsic Numerical Feedback, which rewards beneficial exploration by measuring incremental subtask progress relative to prior attempts; and (2) Intrinsic Language Feedback which distills successes and failures into reusable textual lessons for explicit experience reuse. To leverage these lessons effectively, we propose Similarity & Utility-Aware Upper Confidence Bound (SimUtil-UCB), a retrieval strategy that balances semantic relevance, historical utility, and exploration. Across four challenging agentic benchmarks, RetroAgent achieves new state-of-the-art performance, outperforming GRPO by +18.3% on ALFWorld, +15.4% on WebShop, +27.1% on Sokoban, and +8.9% on MineSweeper, while demonstrating strong test-time adaptation and out-of-distribution generalization.","published":"2026-03-09T16:23:33Z","updated":"2026-06-09T04:36:45Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08561v6","pdf_url":"https://arxiv.org/pdf/2603.08561v6","comment":"updated","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=tzxP9H3f3O","openreview_venues":["Under review for TMLR"]},{"id":"2603.08369","versioned_id":"2603.08369v1","title":"M$^3$-ACE: Rectifying Visual Perception in Multimodal Math Reasoning via Multi-Agentic Context Engineering","authors":["Peijin Xie","Zhen Xu","Bingquan Liu","Baoxun Wang"],"abstract":"Multimodal large language models have recently shown promising progress in visual mathematical reasoning. However, their performance is often limited by a critical yet underexplored bottleneck: inaccurate visual perception. Through systematic analysis, we find that the most failures originate from incorrect or incomplete visual evidence extraction rather than deficiencies in reasoning capability. Moreover, models tend to remain overly confident in their initial perceptions, making standard strategies such as prompt engineering, multi-round self-reflection, or posterior guidance insufficient to reliably correct errors. To address this limitation, we propose M3-ACE, a multi-agentic context engineering framework designed to rectify visual perception in multimodal math reasoning. Instead of directly aggregating final answers, our approach decouples perception and reasoning by dynamically maintaining a shared context centered on visual evidence lists. Multiple agents collaboratively contribute complementary observations, enabling the system to expose inconsistencies and recover missing perceptual information. To support stable multi-turn collaboration, we further introduce two lightweight tools: a Summary Tool that organizes evidence from different agents into consistent, complementary, and conflicting components, and a Refine Tool that filters unreliable samples and guides iterative correction. Extensive experiments demonstrate that M3-ACE substantially improves visual mathematical reasoning performance across multiple benchmarks. Our method establishes new state-of-the-art results 89.1 on the MathVision benchmark and achieves consistent improvements on other related datasets, including MathVista and MathVerse. These results highlight the importance of perception-centric multi-agent collaboration for advancing multimodal reasoning systems.","published":"2026-03-09T13:32:25Z","updated":"2026-03-09T13:32:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.08369v1","pdf_url":"https://arxiv.org/pdf/2603.08369v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.07955","versioned_id":"2603.07955v3","title":"RL unknotter, hard unknots and unknotting number","authors":["Anne Dranowski","Yura Kabkov","Daniel Tubbenhauer"],"abstract":"We develop a reinforcement learning pipeline for simplifying knot diagrams. A trained agent learns move proposals and a value heuristic for navigating Reidemeister moves. The pipeline applies to arbitrary knots and links; we test it on ``very hard'' unknot diagrams and, using diagram inflation, on $4_1\\#9_{10}$ where we recover the recently established and surprising upper bound of three for the unknotting number. In addition, we explain a self-improving workbook-driven extension of the pipeline that systematically improves unknotting number upper bounds on the list of prime knots.","published":"2026-03-09T04:43:59Z","updated":"2026-04-29T02:19:47Z","categories":["math.GT","cs.LG","stat.ML"],"primary_category":"math.GT","arxiv_url":"https://arxiv.org/abs/2603.07955v3","pdf_url":"https://arxiv.org/pdf/2603.07955v3","comment":"19 pages, many figures, comments welcome","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.07670","versioned_id":"2603.07670v1","title":"Memory for Autonomous LLM Agents:Mechanisms, Evaluation, and Emerging Frontiers","authors":["Pengfei Du"],"abstract":"Large language model (LLM) agents increasingly operate in settings where a single context window is far too small to capture what has happened, what was learned, and what should not be repeated. Memory -- the ability to persist, organize, and selectively recall information across interactions -- is what turns a stateless text generator into a genuinely adaptive agent. This survey offers a structured account of how memory is designed, implemented, and evaluated in modern LLM-based agents, covering work from 2022 through early 2026. We formalize agent memory as a \\emph{write--manage--read} loop tightly coupled with perception and action, then introduce a three-dimensional taxonomy spanning temporal scope, representational substrate, and control policy. Five mechanism families are examined in depth: context-resident compression, retrieval-augmented stores, reflective self-improvement, hierarchical virtual context, and policy-learned management. On the evaluation side, we trace the shift from static recall benchmarks to multi-session agentic tests that interleave memory with decision-making, analyzing four recent benchmarks that expose stubborn gaps in current systems. We also survey applications where memory is the differentiating factor -- personal assistants, coding agents, open-world games, scientific reasoning, and multi-agent teamwork -- and address the engineering realities of write-path filtering, contradiction handling, latency budgets, and privacy governance. The paper closes with open challenges: continual consolidation, causally grounded retrieval, trustworthy reflection, learned forgetting, and multimodal embodied memory.","published":"2026-03-08T15:08:01Z","updated":"2026-03-08T15:08:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.07670v1","pdf_url":"https://arxiv.org/pdf/2603.07670v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.15653","versioned_id":"2603.15653v1","title":"Recursive Language Models Meet Uncertainty: The Surprising Effectiveness of Self-Reflective Program Search for Long Context","authors":["Keivan Alizadeh","Parshin Shojaee","Minsik Cho","Mehrdad Farajtabar"],"abstract":"Long-context handling remains a core challenge for language models: even with extended context windows, models often fail to reliably extract, reason over, and use the information across long contexts. Recent works like Recursive Language Models (RLM) have approached this challenge by agentic way of decomposing long contexts into recursive sub-calls through programmatic interaction at inference. While promising, the success of RLM critically depends on how these context-interaction programs are selected, which has remained largely unexplored. In this paper, we study this problem and introduce SRLM, a framework that augments programmatic context interaction with uncertainty-aware Self-Reflection. SRLM leverages three intrinsic signals: self consistency, reasoning length, and verbalized confidence. These serve as complementary indicators of a model's internal uncertainty, and the model uses them to evaluate and compare candidate context-interaction programs. Extensive experiments across diverse benchmark datasets, context lengths, and backbone models, show that SRLM consistently outperforms state-of-the-art baselines, yielding up to 22% improvement over RLM under the same time budget. Our findings show that recursion itself is not the primary driver of performance in RLM, and a simple self-reflective program search can match or surpass RLM without requiring self-query or explicit recursion mechanisms. We find that for context lengths within the model's window, RLMs with recursion often degrade performance relative to the base model, whereas SRLM yields consistent gains across both short and long contexts. We also find that RLM is less effective in tasks with semantically intensive nature, where heuristic program search is insufficient and broader contextual understanding is required, while self-reflection in SRLM provides a semantic signal that better steers reasoning in these scenarios.","published":"2026-03-07T01:18:04Z","updated":"2026-03-07T01:18:04Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.15653v1","pdf_url":"https://arxiv.org/pdf/2603.15653v1","comment":"preprint","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.05860","versioned_id":"2603.05860v1","title":"Evolving Medical Imaging Agents via Experience-driven Self-skill Discovery","authors":["Lin Fan","Pengyu Dai","Zhipeng Deng","Haolin Wang","Xun Gong","Yefeng Zheng","Yafei Ou"],"abstract":"Clinical image interpretation is inherently multi-step and tool-centric: clinicians iteratively combine visual evidence with patient context, quantify findings, and refine their decisions through a sequence of specialized procedures. While LLM-based agents promise to orchestrate such heterogeneous medical tools, existing systems treat tool sets and invocation strategies as static after deployment. This design is brittle under real-world domain shifts, across tasks, and evolving diagnostic requirements, where predefined tool chains frequently degrade and demand costly manual re-design. We propose MACRO, a self-evolving, experience-augmented medical agent that shifts from static tool composition to experience-driven tool discovery. From verified execution trajectories, the agent autonomously identifies recurring effective multi-step tool sequences, synthesizes them into reusable composite tools, and registers these as new high-level primitives that continuously expand its behavioral repertoire. A lightweight image-feature memory grounds tool selection in a visual-clinical context, while a GRPO-like training loop reinforces reliable invocation of discovered composites, enabling closed-loop self-improvement with minimal supervision. Extensive experiments across diverse medical imaging datasets and tasks demonstrate that autonomous composite tool discovery consistently improves multi-step orchestration accuracy and cross-domain generalization over strong baselines and recent state-of-the-art agentic methods, bridging the gap between brittle static tool use and adaptive, context-aware clinical AI assistance. Code will be available upon acceptance.","published":"2026-03-06T03:34:47Z","updated":"2026-03-06T03:34:47Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.05860v1","pdf_url":"https://arxiv.org/pdf/2603.05860v1","comment":"18 pages, 4 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.04900","versioned_id":"2603.04900v1","title":"EvoTool: Self-Evolving Tool-Use Policy Optimization in LLM Agents via Blame-Aware Mutation and Diversity-Aware Selection","authors":["Shuo Yang","Soyeon Caren Han","Xueqi Ma","Yan Li","Mohammad Reza Ghasemi Madani","Eduard Hovy"],"abstract":"LLM-based agents depend on effective tool-use policies to solve complex tasks, yet optimizing these policies remains challenging due to delayed supervision and the difficulty of credit assignment in long-horizon trajectories. Existing optimization approaches tend to be either monolithic, which are prone to entangling behaviors, or single-aspect, which ignore cross-module error propagation. To address these limitations, we propose EvoTool, a self-evolving framework that optimizes a modular tool-use policy via a gradient-free evolutionary paradigm. EvoTool decomposes agent's tool-use policy into four modules, including Planner, Selector, Caller, and Synthesizer, and iteratively improves them in a self-improving loop through three novel mechanisms. Trajectory-Grounded Blame Attribution uses diagnostic traces to localize failures to a specific module. Feedback-Guided Targeted Mutation then edits only that module via natural-language critique. Diversity-Aware Population Selection preserves complementary candidates to ensure solution diversity. Across four benchmarks, EvoTool outperforms strong baselines by over 5 points on both GPT-4.1 and Qwen3-8B, while achieving superior efficiency and transferability. The code will be released once paper is accepted.","published":"2026-03-05T07:42:53Z","updated":"2026-03-05T07:42:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.04900v1","pdf_url":"https://arxiv.org/pdf/2603.04900v1","comment":"Work under review, 9 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0sphfZZy4W","openreview_venues":["ACL 2026 Main"]},{"id":"2603.04029","versioned_id":"2603.04029v1","title":"Self-adapting Robotic Agents through Online Continual Reinforcement Learning with World Model Feedback","authors":["Fabian Domberg","Georg Schildbach"],"abstract":"As learning-based robotic controllers are typically trained offline and deployed with fixed parameters, their ability to cope with unforeseen changes during operation is limited. Biologically inspired, this work presents a framework for online Continual Reinforcement Learning that enables automated adaptation during deployment. Building on DreamerV3, a model-based Reinforcement Learning algorithm, the proposed method leverages world model prediction residuals to detect out-of-distribution events and automatically trigger finetuning. Adaptation progress is monitored using both task-level performance signals and internal training metrics, allowing convergence to be assessed without external supervision and domain knowledge. The approach is validated on a variety of contemporary continuous control problems, including a quadruped robot in high-fidelity simulation, and a real-world model vehicle. Relevant metrics and their interpretation are presented and discussed, as well as resulting trade-offs described. The results sketch out how autonomous robotic agents could once move beyond static training regimes toward adaptive systems capable of self-reflection and -improvement during operation, just like their biological counterparts.","published":"2026-03-04T13:07:42Z","updated":"2026-03-04T13:07:42Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.04029v1","pdf_url":"https://arxiv.org/pdf/2603.04029v1","comment":"submitted to IROS 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.02640","versioned_id":"2603.02640v1","title":"Credibility Governance: A Social Mechanism for Collective Self-Correction under Weak Truth Signals","authors":["Wanying He","Yanxi Lin","Ziheng Zhou","Xue Feng","Min Peng","Qianqian Xie","Zilong Zheng","Yipeng Kang"],"abstract":"Online platforms increasingly rely on opinion aggregation to allocate real-world attention and resources, yet common signals such as engagement votes or capital-weighted commitments are easy to amplify and often track visibility rather than reliability. This makes collective judgments brittle under weak truth signals, noisy or delayed feedback, early popularity surges, and strategic manipulation. We propose Credibility Governance (CG), a mechanism that reallocates influence by learning which agents and viewpoints consistently track evolving public evidence. CG maintains dynamic credibility scores for both agents and opinions, updates opinion influence via credibility-weighted endorsements, and updates agent credibility based on the long-run performance of the opinions they support, rewarding early and persistent alignment with emerging evidence while filtering short-lived noise. We evaluate CG in POLIS, a socio-physical simulation environment that models coupled belief dynamics and downstream feedback under uncertainty. Across settings with initial majority misalignment, observation noise and contamination, and misinformation shocks, CG outperforms vote-based, stake-weighted, and no-governance baselines, yielding faster recovery to the true state, reduced lock-in and path dependence, and improved robustness under adversarial pressure. Our implementation and experimental scripts are publicly available at https://github.com/Wanying-He/Credibility_Governance.","published":"2026-03-03T06:10:13Z","updated":"2026-03-03T06:10:13Z","categories":["cs.CY","cs.AI","cs.CL","cs.MA","cs.SI"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2603.02640v1","pdf_url":"https://arxiv.org/pdf/2603.02640v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.01853","versioned_id":"2603.01853v2","title":"Let the Agent Search: Autonomous Exploration Beats Rigid Workflows in Temporal Question Answering","authors":["Xufei Lv","Jiahui Yang","Haoyuan Sun","Xialin Su","Zhiliang Tian","Yifu Gao","Linbo Qiao","Houde Liu"],"abstract":"Temporal Knowledge Graph Question Answering (TKGQA) is challenging because it requires multi-hop reasoning under complex temporal constraints. Recent LLM-based approaches have improved semantic modeling for this task, but many still rely on fixed reasoning workflows or costly post-training, which can limit adaptability and make error recovery difficult. We show that enabling an off-the-shelf Large Language Model (LLM) to determine its next action is already effective in a zero-shot setting. Based on this insight, we propose AT2QA, an Autonomous and Training-free Agent for TKG Question Answering. AT2QA empowers the LLM to iteratively interact with the TKG via a generic search tool, inherently enabling autonomous exploration and dynamic self-correction during reasoning. To further elicit the LLM's potential for complex temporal reasoning, we introduce a training-free experience mining mechanism that distills a compact few-shot demonstration library from successful self-generated trajectories. AT2QA also yields a transparent audit trail for every prediction. Experiments on three challenging benchmarks -- MultiTQ, Timeline-CronQuestion, and Timeline-ICEWS-Actor -- show that AT2QA achieves new state-of-the-art performance, surpassing the strongest baselines by 10.7, 4.9, and 11.2 absolute points, respectively. Our code is available at https://github.com/AT2QA-Official-Code/AT2QA-Official-Code","published":"2026-03-02T13:33:39Z","updated":"2026-03-25T15:29:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2603.01853v2","pdf_url":"https://arxiv.org/pdf/2603.01853v2","comment":"Revised version with three added authors and additional experiments","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=wQXnFCDwwx","openreview_venues":["ACL ARR 2026 March Submission"]},{"id":"2603.01755","versioned_id":"2603.01755v1","title":"Federated Agentic AI for Wireless Networks: Fundamentals, Approaches, and Applications","authors":["Lingyi Cai","Yu Zhang","Ruichen Zhang","Yinqiu Liu","Tao Jiang","Dusit Niyato","Wei Ni","Abbas Jamalipour"],"abstract":"Agentic artificial intelligence (AI) presents a promising pathway toward realizing autonomous and self-improving wireless network services. However, resource-constrained, widely distributed, and data-heterogeneous nature of wireless networks poses significant challenges to existing agentic AI that relies on centralized architectures, leading to high communication overhead, privacy risks, and non-independent and identically distributed (non-IID) data. Federated learning (FL) has the potential to improve the overall loop of agentic AI through collaborative local learning and parameter sharing without exchanging raw data. This paper proposes new federated agentic AI approaches for wireless networks. We first summarize fundamentals of agentic AI and mainstream FL types. Then, we illustrate how each FL type can strengthen a specific component of agentic AI's loop. Moreover, we conduct a case study on using FRL to improve the performance of agentic AI's action decision in low-altitude wireless networks (LAWNs). Finally, we provide a conclusion and discuss future research directions.","published":"2026-03-02T11:26:56Z","updated":"2026-03-02T11:26:56Z","categories":["cs.NI","cs.AI"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2603.01755v1","pdf_url":"https://arxiv.org/pdf/2603.01755v1","comment":"7 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:Xj22DMrDvn","versioned_id":"Xj22DMrDvn","title":"Findings of the TSAR 2025 Shared Task on Readability-Controlled Text Simplification","authors":["Fernando Alva-Manchego","Regina Stodden","Joseph Marvin Imperial","Abdullah Barayan","Kai North","Harish Tayyar Madabushi"],"abstract":"This paper presents the findings of the first Shared Task on Readability-Controlled Text Simplification at TSAR 2025. The task required systems to simplify English texts to specific target readability levels of the Common European Framework of Reference for Languages (CEFR). We received 48 submissions from 20 participating teams, with approaches predominantly based on large language models (LLMs), which included iterative refinement, multi-agent setups, and LLM-as-a-judge pipelines. For this shared task, we developed a new dataset of pedagogical texts and evaluated submissions using a weighted combination of semantic similarity and CEFR-level accuracy. The results of the participating teams demonstrate that while LLMs can perform substantially well on this task, dependable and controlled simplification often requires complex, multi-iterative processes. Our findings also suggest that the capabilities of current systems are beginning to saturate existing automatic evaluation metrics, underscoring the need for reevaluation and practicality.","published":"2026-03-02T09:48:47+00:00","updated":"2026-03-02T09:48:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Xj22DMrDvn","openreview_url":"https://openreview.net/forum?id=Xj22DMrDvn","pdf_url":"https://openreview.net/pdf?id=Xj22DMrDvn","comment":"Proceedings of the Fourth Workshop on Text Simplification, Accessibility and Readability (TSAR 2025)","journal_ref":"Proceedings of the Fourth Workshop on Text Simplification, Accessibility and Readability (TSAR 2025)","doi":"","venue":"Proceedings of the Fourth Workshop on Text Simplification, Accessibility and Readability (TSAR 2025)","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2603.01421","versioned_id":"2603.01421v3","title":"SciDER: Scientific Data-centric End-to-end Researcher","authors":["Ke Lin","Owais Aijaz","Yilin Lu","Yiyang Luo","Xuehang Guo","Preslav Nakov"],"abstract":"While large language models accelerate scientific discovery, existing agents face severe limitations in adaptability, domain generalization, and multimodal scalability, often struggling to autonomously process raw, domain-specific experimental data. To overcome these barriers, we introduce SciDER, a multi-agent system designed to flexibly automate the entire research lifecycle. This framework employs a novel data-centric approach and integrates a dynamic multimodal skill system across four specialized sub-agents. Specifically, an ideation agent generates novel hypotheses via Evolutionary Idea Search, a data analysis agent systematically structures raw data, an experimentation agent synthesizes executable code grounded in dataset characteristics, and a critic agent drives iterative self-refinement. To democratize open-source scientific discovery, we release OpenSciDER-SFT-8K, a high-quality execution trajectory dataset, alongside the OpenSciDER-27B fine-tuned model. Across six benchmarks, SciDER and OpenSciDER obtain competitive or leading results, with especially strong gains on data-centric analysis, end-to-end research execution, and multimodal scientific visualization. By integrating data analysis with experimental execution, SciDER bridges the gap between abstract scientific reasoning and reproducible experimentation synthesis.","published":"2026-03-02T03:53:20Z","updated":"2026-06-03T13:47:56Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.01421v3","pdf_url":"https://arxiv.org/pdf/2603.01421v3","comment":"10 pages, 8 figures, 7 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.01335","versioned_id":"2603.01335v1","title":"Provable and Practical In-Context Policy Optimization for Self-Improvement","authors":["Tianrun Yu","Yuxiao Yang","Zhaoyang Wang","Kaixiang Zhao","Porter Jenkins","Xuchao Zhang","Chetan Bansal","Huaxiu Yao","Weitong Zhang"],"abstract":"We study test-time scaling, where a model improves its answer through multi-round self-reflection at inference. We introduce In-Context Policy Optimization (ICPO), in which an agent optimizes its response in context using self-assessed or externally observed rewards without modifying its parameters. To explain this ICPO process, we theoretically show that with sufficient pretraining under a novel Fisher-weighted logit-matching objective, a single-layer linear self-attention model can provably imitate policy-optimization algorithm for linear bandits. Building on this theory, we propose Minimum-Entropy ICPO (ME-ICPO), a practical algorithm that iteratively uses its response and self-assessed reward to refine its response in-context at inference time. By selecting the responses and their rewards with minimum entropy, ME-ICPO ensures the robustness of the self-assessed rewards via majority voting. Across standard mathematical reasoning tasks, ME-ICPO attains competitive, top-tier performance while keeping inference costs affordable compared with other inference-time algorithms. Overall, ICPO provides a principled understanding of self-reflection in LLMs and yields practical benefits for test-time scaling for mathematical reasoning.","published":"2026-03-02T00:21:50Z","updated":"2026-03-02T00:21:50Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.01335v1","pdf_url":"https://arxiv.org/pdf/2603.01335v1","comment":"34 pages, 8 tables, 4 figures, Accepted by ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=TAthdtPe7k","openreview_venues":["ICLR 2026 Poster"]},{"id":"2603.00846","versioned_id":"2603.00846v1","title":"Tiny-Critic RAG: Empowering Agentic Fallback with Parameter-Efficient Small Language Models","authors":["Yichao Wu","Penghao Liang","Yafei Xiang","Mengwei Yuan","Jianan Liu","Jing Yang","Xianyou Li","Weiran Yan"],"abstract":"Retrieval-Augmented Generation (RAG) grounds Large Language Models (LLMs) to mitigate factual hallucinations. Recent paradigms shift from static pipelines to Modular and Agentic RAG frameworks, granting models autonomy for multi-hop reasoning or self-correction. However, current reflective RAG heavily relies on massive LLMs as universal evaluators. In high-throughput systems, executing complete forward passes for billion-parameter models merely for binary routing introduces severe computational redundancy. Furthermore, in autonomous agent scenarios, inaccurate retrieval causes models to expend excessive tokens on spurious reasoning and redundant tool calls, inflating Time-to-First-Token (TTFT) and costs. We propose Tiny-Critic RAG, decoupling evaluation by deploying a parameter-efficient Small Language Model (SLM) via Low-Rank Adaptation (LoRA). Acting as a deterministic gatekeeper, Tiny-Critic employs constrained decoding and non-thinking inference modes for ultra-low latency binary routing. Evaluations on noise-injected datasets demonstrate Tiny-Critic RAG achieves routing accuracy comparable to GPT-4o-mini while reducing latency by an order of magnitude, establishing a highly cost-effective paradigm for agent deployment.","published":"2026-03-01T00:16:31Z","updated":"2026-03-01T00:16:31Z","categories":["cs.IR","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2603.00846v1","pdf_url":"https://arxiv.org/pdf/2603.00846v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.00822","versioned_id":"2603.00822v2","title":"ContextCov: Deriving and Enforcing Executable Constraints from Agent Instruction Files","authors":["Reshabh K Sharma"],"abstract":"As Large Language Model (LLM) agents increasingly execute complex, autonomous software engineering tasks, developers rely on natural language instruction files such as AGENTS.md to express project-specific coding conventions, tooling restrictions, and architectural boundaries. However, because these instructions remain passive text, agents frequently violate documented constraints due to context window saturation or conflicting local context. In autonomous settings without real-time human supervision, such violations rapidly compound into technical debt. To ground autonomous agents in repository constraints, we introduce ContextCov, a framework that transforms passive natural language instructions into executable guardrails. Unlike prompt-only or reflection-only compliance approaches, ContextCov compiles documented constraints into three complementary checks: static AST queries for code patterns, runtime shell shims that intercept prohibited commands, and architectural validators that enforce structural rules. Acting as an automated, continuous reviewer, ContextCov intercepts agent actions and returns immediate, reproducible violation traces, enabling self-correction before non-compliant changes are finalized. We evaluate ContextCov on SWE-bench Lite (12 repositories, 300 tasks). Compared to prompt-only and LLM reflection baselines, ContextCov achieves 88.3% constraint compliance (vs. 67.0% and 50.3%) with 3.4x lower feedback cost, while maintaining functional correctness. The source code and evaluation results are available at https://github.com/reSHARMA/ContextCov.","published":"2026-02-28T21:56:47Z","updated":"2026-05-04T08:55:15Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2603.00822v2","pdf_url":"https://arxiv.org/pdf/2603.00822v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.23320","versioned_id":"2602.23320v2","title":"ParamMem: Augmenting Language Agents with Parametric Reflective Memory","authors":["Tianjun Yao","Yongqiang Chen","Yujia Zheng","Pan Li","Zhiqiang Shen","Kun Zhang"],"abstract":"Self-reflection enables language agents to iteratively refine solutions, yet often produces repetitive outputs that limit reasoning performance. Recent studies have attempted to address this limitation through various approaches, among which increasing reflective diversity has shown promise. Our empirical analysis reveals a strong positive correlation between reflective diversity and task success, further motivating the need for diverse reflection signals. We introduce ParamMem, a parametric memory module that encodes cross-sample reflection patterns into model parameters, enabling diverse reflection generation through temperature-controlled sampling. Building on this module, we propose ParamAgent, a reflection-based agent framework that integrates parametric memory with episodic and cross-sample memory. Extensive experiments on code generation, mathematical reasoning, and multi-hop question answering demonstrate consistent improvements over state-of-the-art baselines. Further analysis reveals that ParamMem is sample-efficient, enables weak-to-strong transfer across model scales, and supports self-improvement without reliance on stronger external model, highlighting the potential of ParamMem as an effective component for enhancing language agents.","published":"2026-02-26T18:28:04Z","updated":"2026-02-27T08:21:31Z","categories":["cs.LG","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.23320v2","pdf_url":"https://arxiv.org/pdf/2602.23320v2","comment":"20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=tNosQdV9J1","openreview_venues":["ICML 2026 regular"]},{"id":"2602.22839","versioned_id":"2602.22839v3","title":"DeepPresenter: Environment-Grounded Reflection for Agentic Presentation Generation","authors":["Hao Zheng","Guozhao Mo","Xinru Yan","Qianhao Yuan","Wenkai Zhang","Xuanang Chen","Yaojie Lu","Hongyu Lin","Xianpei Han","Le Sun"],"abstract":"Presentation generation requires deep content research, coherent visual design, and iterative refinement based on observation. However, existing presentation agents often rely on predefined workflows and fixed templates. To address this, we present DeepPresenter, an agentic framework that adapts to diverse user intents, enables effective feedback-driven refinement, and generalizes beyond a scripted pipeline. Specifically, DeepPresenter autonomously plans, renders, and revises intermediate slide artifacts to support long-horizon refinement with environmental observations. Furthermore, rather than relying on self-reflection over internal signals (e.g., reasoning traces), our environment-grounded reflection conditions the generation process on perceptual artifact states (e.g., rendered slides), enabling the system to identify and correct presentation-specific issues during execution. Results on the evaluation set covering diverse presentation-generation scenarios show that DeepPresenter achieves state-of-the-art performance, and the fine-tuned 9B model remains highly competitive at substantially lower cost. Our project is available at: https://github.com/icip-cas/PPTAgent","published":"2026-02-26T10:26:48Z","updated":"2026-04-20T02:43:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.22839v3","pdf_url":"https://arxiv.org/pdf/2602.22839v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2604.09579","versioned_id":"2604.09579v1","title":"Help Without Being Asked: A Deployed Proactive Agent System for On-Call Support with Continuous Self-Improvement","authors":["Fengrui Liu","Xiao He","Tieying Zhang"],"abstract":"In large-scale cloud service platforms, thousands of customer tickets are generated daily and are typically handled through on-call dialogues. This high volume of on-call interactions imposes a substantial workload on human support analysts. Recent studies have explored reactive agents that leverage large language models as a first line of support to interact with customers directly and resolve issues. However, when issues remain unresolved and are escalated to human support, these agents are typically disengaged. As a result, they cannot assist with follow-up inquiries, track resolution progress, or learn from the cases they fail to address. In this paper, we introduce Vigil, a novel proactive agent system designed to operate throughout the entire on-call life-cycle. Unlike reactive agents, Vigil focuses on providing assistance during the phase in which human support is already involved. It integrates into the dialogue between the customer and the analyst, proactively offering assistance without explicit user invocation. Moreover, Vigil incorporates a continuous self-improvement mechanism that extracts knowledge from human-resolved cases to autonomously update its capabilities. Vigil has been deployed on Volcano Engine, ByteDance's cloud platform, for over ten months, and comprehensive evaluations based on this deployment demonstrate its effectiveness and practicality. The open source version of this work is publicly available at https://github.com/volcengine/veaiops.","published":"2026-02-25T07:46:39Z","updated":"2026-02-25T07:46:39Z","categories":["cs.AI","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2604.09579v1","pdf_url":"https://arxiv.org/pdf/2604.09579v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.21633","versioned_id":"2602.21633v1","title":"Self-Correcting VLA: Online Action Refinement via Sparse World Imagination","authors":["Chenyv Liu","Wentao Tan","Lei Zhu","Fengling Li","Jingjing Li","Guoli Yang","Heng Tao Shen"],"abstract":"Standard vision-language-action (VLA) models rely on fitting statistical data priors, limiting their robust understanding of underlying physical dynamics. Reinforcement learning enhances physical grounding through exploration yet typically relies on external reward signals that remain isolated from the agent's internal states. World action models have emerged as a promising paradigm that integrates imagination and control to enable predictive planning. However, they rely on implicit context modeling, lacking explicit mechanisms for self-improvement. To solve these problems, we propose Self-Correcting VLA (SC-VLA), which achieve self-improvement by intrinsically guiding action refinement through sparse imagination. We first design sparse world imagination by integrating auxiliary predictive heads to forecast current task progress and future trajectory trends, thereby constraining the policy to encode short-term physical evolution. Then we introduce the online action refinement module to reshape progress-dependent dense rewards, adjusting trajectory orientation based on the predicted sparse future states. Evaluations on challenging robot manipulation tasks from simulation benchmarks and real-world settings demonstrate that SC-VLA achieve state-of-the-art performance, yielding the highest task throughput with 16% fewer steps and a 9% higher success rate than the best-performing baselines, alongside a 14% gain in real-world experiments. Code is available at https://github.com/Kisaragi0/SC-VLA.","published":"2026-02-25T06:58:06Z","updated":"2026-02-25T06:58:06Z","categories":["cs.RO","cs.AI","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2602.21633v1","pdf_url":"https://arxiv.org/pdf/2602.21633v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.13258","versioned_id":"2603.13258v1","title":"Your Code Agent Can Grow Alongside You with Structured Memory","authors":["Yi-Xuan Deng","Xiaoqin Liu","Yi Zhang","Guo-Wei Yang","Shuojin Yang"],"abstract":"While \"Intent-oriented programming\" (or \"Vibe Coding\") redefines software engineering, existing code agents remain tethered to static code snapshots. Consequently, they struggle to model the critical information embedded in the temporal evolution of projects, failing to leverage the \"reasoning trajectories\" implicit in past successful practices. This limitation results in rigid behavioral logic and a lack of autonomous adaptability, ultimately hindering their ability to tackle complex, repository-level problems. To bridge this static-dynamic mismatch, we propose MemCoder, a framework designed to enable continual human-AI co-evolution. MemCoder first structures historical human experience to distill latent intent-to-code mappings from past commits. It then employs a self-refinement mechanism driven by verification feedback to correct agent behavior in real-time. Crucially, an experience self-internalization mechanism is introduced to crystallize human-validated solutions into long-term knowledge, thereby supporting sustained evolution. Experimental results on SWE-bench Verified demonstrate that MemCoder not only achieves State-of-the-Art (SOTA) performance but also delivers a 9.4% improvement in resolved rate over the general foundation model DeepSeek-V3.2. These findings indicate that equipping agents with the capability to co-evolve with humans via project history and real-time feedback effectively unlocks the potential of general models in complex software engineering tasks.","published":"2026-02-25T06:39:29Z","updated":"2026-02-25T06:39:29Z","categories":["cs.LG","cs.AI","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2603.13258v1","pdf_url":"https://arxiv.org/pdf/2603.13258v1","comment":"Code Agent","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.21496","versioned_id":"2602.21496v1","title":"Beyond Refusal: Probing the Limits of Agentic Self-Correction for Semantic Sensitive Information","authors":["Umid Suleymanov","Zaur Rajabov","Emil Mirzazada","Murat Kantarcioglu"],"abstract":"While defenses for structured PII are mature, Large Language Models (LLMs) pose a new threat: Semantic Sensitive Information (SemSI), where models infer sensitive identity attributes, generate reputation-harmful content, or hallucinate potentially wrong information. The capacity of LLMs to self-regulate these complex, context-dependent sensitive information leaks without destroying utility remains an open scientific question. To address this, we introduce SemSIEdit, an inference-time framework where an agentic \"Editor\" iteratively critiques and rewrites sensitive spans to preserve narrative flow rather than simply refusing to answer. Our analysis reveals a Privacy-Utility Pareto Frontier, where this agentic rewriting reduces leakage by 34.6% across all three SemSI categories while incurring a marginal utility loss of 9.8%. We also uncover a Scale-Dependent Safety Divergence: large reasoning models (e.g., GPT-5) achieve safety through constructive expansion (adding nuance), whereas capacity-constrained models revert to destructive truncation (deleting text). Finally, we identify a Reasoning Paradox: while inference-time reasoning increases baseline risk by enabling the model to make deeper sensitive inferences, it simultaneously empowers the defense to execute safe rewrites.","published":"2026-02-25T02:09:23Z","updated":"2026-02-25T02:09:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.21496v1","pdf_url":"https://arxiv.org/pdf/2602.21496v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.21351","versioned_id":"2602.21351v1","title":"A Hierarchical Multi-Agent System for Autonomous Discovery in Geoscientific Data Archives","authors":["Dmitrii Pantiukhin","Ivan Kuznetsov","Boris Shapkin","Antonia Anna Jost","Thomas Jung","Nikolay Koldunov"],"abstract":"The rapid accumulation of Earth science data has created a significant scalability challenge; while repositories like PANGAEA host vast collections of datasets, citation metrics indicate that a substantial portion remains underutilized, limiting data reusability. Here we present PANGAEA-GPT, a hierarchical multi-agent framework designed for autonomous data discovery and analysis. Unlike standard Large Language Model (LLM) wrappers, our architecture implements a centralized Supervisor-Worker topology with strict data-type-aware routing, sandboxed deterministic code execution, and self-correction via execution feedback, enabling agents to diagnose and resolve runtime errors. Through use-case scenarios spanning physical oceanography and ecology, we demonstrate the system's capacity to execute complex, multi-step workflows with minimal human intervention. This framework provides a methodology for querying and analyzing heterogeneous repository data through coordinated agent workflows.","published":"2026-02-24T20:37:38Z","updated":"2026-02-24T20:37:38Z","categories":["cs.AI","cs.IR","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.21351v1","pdf_url":"https://arxiv.org/pdf/2602.21351v1","comment":"20 pages, 6 figures, 7 tables, supplementary material included","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.00117","versioned_id":"2603.00117v3","title":"PEPA: a Persistently Autonomous Embodied Agent with Personalities","authors":["Kaige Liu","Yang Li","Lijun Zhu","Weinan Zhang"],"abstract":"Living organisms exhibit persistent autonomy through internally generated goals and self-sustaining behavioral organization, yet current embodied agents remain driven by externally scripted objectives. This dependence on predefined task specifications limits their capacity for long-term deployment in dynamic, unstructured environments where continuous human intervention is impractical. We propose that personality traits provide an intrinsic organizational principle for achieving persistent autonomy. Analogous to genotypic biases shaping biological behavioral tendencies, personalities enable agents to autonomously generate goals and sustain behavioral evolution without external supervision. To realize this, we develop PEPA, a three-layer cognitive architecture that operates through three interacting systems: Sys3 autonomously synthesizes personality-aligned goals and refines them via episodic memory and daily self-reflection; Sys2 performs deliberative reasoning to translate goals into executable action plans; Sys1 grounds the agent in sensorimotor interaction, executing actions and recording experiences. We validate the framework through real-world deployment on a quadruped robot in a multi-floor office building. Operating without reliance on fixed task specifications, the robot autonomously arbitrates between user requests and personality-driven motivations, navigating elevators and exploring environments accordingly. Quantitative analysis across five distinct personality prototypes demonstrates stable, trait-aligned behaviors. The results confirm that personality-driven cognitive architectures enable sustained autonomous operation characteristic of persistent embodied systems. Code and demo videos are available at https://sites.google.com/view/pepa-persistent/.","published":"2026-02-21T12:53:28Z","updated":"2026-05-07T07:30:40Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2603.00117v3","pdf_url":"https://arxiv.org/pdf/2603.00117v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:5CWHlk9rdn","versioned_id":"5CWHlk9rdn","title":"PeerCoT: Structured Multi-Agent Chain-of-Thought Collaboration for Error Localization in LLM Reasoning","authors":["Isha Chaturvedi","Rhys Llewellyn-Jones","Sage Rain Schaffer"],"abstract":"Large Language Model (LLM) agents exhibit emergent reasoning abilities through debate, critique, and self-reflection. However, most multi-agent systems only exchange final outputs between agents, which limits transparency and hinders the ability to diagnose and improve reasoning processes. PeerCoT introduces a structured and symmetric Chain-of-Thought (CoT) exchange protocol. In this system, peer agents transparently share reasoning traces, provide labeled critiques, and perform minimal-edit revisions before aggregation. This structure enables explicit measurement of process-level error-type identification, called Error Localization Success (ELS), within an agent’s reasoning. We introduce and release AQUA-RAT-Corrupted and GSM8K-Corrupted, structured benchmarks synthetically designed to evaluate error localization and correction in multi-agent reasoning. PeerCoT achieves 64.1% accuracy in AQUA-RAT-Corrupted and 53.15% in GSM8K-Corrupted. PeerCoT maintains competitive accuracy and transparency compared to the baseline models while providing explicit error taxonomy, critique, and ELS. Beyond outcome-level performance, the structured critique protocol corrects 30.43% of initially incorrect solutions in merged outputs. By aligning cooperative critique with fine-grained reasoning supervision, PeerCoT introduces explicit error identification in collaborative reasoning.","published":"2026-02-21T11:11:40+00:00","updated":"2026-04-25T14:54:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=5CWHlk9rdn","openreview_url":"https://openreview.net/forum?id=5CWHlk9rdn","pdf_url":"https://openreview.net/pdf?id=5CWHlk9rdn","comment":"ICLR 2026 Workshop LLM Reasoning","journal_ref":"ICLR 2026 Workshop LLM Reasoning","doi":"","venue":"ICLR 2026 Workshop LLM Reasoning","venue_id":"ICLR.cc/2026/Workshop/LLM_Reasoning","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2603.29848","versioned_id":"2603.29848v1","title":"AgentFixer: From Failure Detection to Fix Recommendations in LLM Agentic Systems","authors":["Hadar Mulian","Sergey Zeltyn","Ido Levy","Liane Galanti","Avi Yaeli","Segev Shlomov"],"abstract":"We introduce a comprehensive validation framework for LLM-based agentic systems that provides systematic diagnosis and improvement of reliability failures. The framework includes fifteen failure-detection tools and two root-cause analysis modules that jointly uncover weaknesses across input handling, prompt design, and output generation. It integrates lightweight rule-based checks with LLM-as-a-judge assessments to support structured incident detection, classification, and repair. We applied the framework to IBM CUGA, evaluating its performance on the AppWorld and WebArena benchmarks. The analysis revealed recurrent planner misalignments, schema violations, brittle prompt dependencies, and more. Based on these insights, we refined both prompting and coding strategies, maintaining CUGA's benchmark results while enabling mid-sized models such as Llama 4 and Mistral Medium to achieve notable accuracy gains, substantially narrowing the gap with frontier models. Beyond quantitative validation, we conducted an exploratory study that fed the framework's diagnostic outputs and agent description into an LLM for self-reflection and prioritization. This interactive analysis produced actionable insights on recurring failure patterns and focus areas for improvement, demonstrating how validation itself can evolve into an agentic, dialogue-driven process. These results show a path toward scalable, quality assurance, and adaptive validation in production agentic systems, offering a foundation for more robust, interpretable, and self-improving agentic architectures.","published":"2026-02-18T14:55:35Z","updated":"2026-02-18T14:55:35Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2603.29848v1","pdf_url":"https://arxiv.org/pdf/2603.29848v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.16444","versioned_id":"2602.16444v2","title":"RoboGene: Boosting VLA Pre-training via Diversity-Driven Agentic Framework for Real-World Task Generation","authors":["Yixue Zhang","Kun Wu","Zhi Gao","Zhen Zhao","Pei Ren","Zhiyuan Xu","Fei Liao","Xinhua Wang","Shichao Fan","Di Wu","Qiuxuan Feng","Meng Li","Zhengping Che","Chang Liu","Jian Tang"],"abstract":"The pursuit of general-purpose robotic manipulation is hindered by the scarcity of diverse, real-world interaction data. Unlike data collection from web in vision or language, robotic data collection is an active process incurring prohibitive physical costs. Consequently, automated task curation to maximize data value remains a critical yet under-explored challenge. Existing manual methods are unscalable and biased toward common tasks, while off-the-shelf foundation models often hallucinate physically infeasible instructions. To address this, we introduce RoboGene, an agentic framework designed to automate the generation of diverse, physically plausible manipulation tasks across single-arm, dual-arm, and mobile robots. RoboGene integrates three core components: diversity-driven sampling for broad task coverage, self-reflection mechanisms to enforce physical constraints, and human-in-the-loop refinement for continuous improvement. We conduct extensive quantitative analysis and large-scale real-world experiments, collecting datasets of 18k trajectories and introducing novel metrics to assess task quality, feasibility, and diversity. Results demonstrate that RoboGene significantly outperforms state-of-the-art foundation models (e.g., GPT-4o, Gemini 2.5 Pro). Furthermore, real-world experiments show that VLA models pre-trained with RoboGene achieve higher success rates and superior generalization, underscoring the importance of high-quality task generation. Our project is available at https://robogene-boost-vla.github.io.","published":"2026-02-18T13:29:43Z","updated":"2026-02-19T04:26:20Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2602.16444v2","pdf_url":"https://arxiv.org/pdf/2602.16444v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.14910","versioned_id":"2602.14910v1","title":"Position: Introspective Experience from Conversational Environments as a Path to Better Learning","authors":["Claudiu Cristian Musat","Jackson Tolins","Diego Antognini","Jingling Li","Martin Klissarov","Tom Duerig"],"abstract":"Current approaches to AI training treat reasoning as an emergent property of scale. We argue instead that robust reasoning emerges from linguistic self-reflection, itself internalized from high-quality social interaction. Drawing on Vygotskian developmental psychology, we advance three core positions centered on Introspection. First, we argue for the Social Genesis of the Private Mind: learning from conversational environments rises to prominence as a new way to make sense of the world; the friction of aligning with another agent, internal or not, refines and crystallizes the reasoning process. Second, we argue that dialogically scaffolded introspective experiences allow agents to engage in sense-making that decouples learning from immediate data streams, transforming raw environmental data into rich, learnable narratives. Finally, we contend that Dialogue Quality is the New Data Quality: the depth of an agent's private reasoning, and its efficiency regarding test-time compute, is determined by the diversity and rigor of the dialogues it has mastered. We conclude that optimizing these conversational scaffolds is the primary lever for the next generation of general intelligence.","published":"2026-02-16T16:45:43Z","updated":"2026-02-16T16:45:43Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14910v1","pdf_url":"https://arxiv.org/pdf/2602.14910v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.14697","versioned_id":"2602.14697v3","title":"Evolutionary System Prompt Learning for Reinforcement Learning in LLMs","authors":["Lunjun Zhang","Ryan Chen","Bradly C. Stadie"],"abstract":"Building agentic systems that can autonomously self-improve from experience is a longstanding goal of AI. Large language models (LLMs) today primarily self-improve via two mechanisms: self-reflection for context updates, and reinforcement learning (RL) for weight updates. In this work, we propose Evolutionary System Prompt Learning (E-SPL), a method for jointly improving model contexts and model weights. In each RL iteration, E-SPL samples trajectories under multiple system prompts in parallel, then jointly applies RL updates to LLM weights and evolutionary updates to system prompts. System prompts evolve via mutation and crossover, two genetic operators driven by LLM self-reflection; selection is based on relative performance ratings updated across RL iterations. E-SPL encourages a natural division between declarative knowledge encoded in prompts and procedural knowledge encoded in weights, resulting in improved performance across reasoning and agentic tasks. For instance, in an easy-to-hard (AIME $\\rightarrow$ BeyondAIME) generalization setting, E-SPL improves RL success rate from 38.8% $\\rightarrow$ 45.1% while also outperforming reflective prompt evolution (40.0%). Overall, our results demonstrate that RL and system prompt evolution are deeply synergistic, and combining the two yields consistent gains in sample efficiency and generalization. Code: https://github.com/LunjunZhang/E-SPL","published":"2026-02-16T12:34:27Z","updated":"2026-02-25T03:50:21Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14697v3","pdf_url":"https://arxiv.org/pdf/2602.14697v3","comment":"39 pages, 22 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=xdd8wRGpg2","openreview_venues":["CompLearn 2026 Poster"]},{"id":"openreview:B6QfT7SHh8","versioned_id":"B6QfT7SHh8","title":"Verifying the Verifiers: Failure Attribution for Agentic Benchmark Diagnostics and Training Data Curation","authors":["Jesse Hu","Pratyush Shukla","Ke Huang"],"abstract":"When coding agents fail benchmark tasks, the failure is opaque: benchmarks report only that the agent failed, not why. This matters for two critical use cases. For evaluation, practitioners need to know whether failures reflect agent limitations or task defects—ambiguous specifications, flaky tests, broken environments—to diagnose and improve their systems. For self-evolving agents, failures serve as reward signal for RL training, but training on task defects as if they were agent errors introduces noise that corrupts learned policies and prevents productive adaptation. We formalize this problem with a failure attribution taxonomy and validate it through a human annotation study on a software engineering benchmark, establishing high inter-annotator agreement (κ=0.929). We then present AutoTriage, a system that automates failure attribution by deploying an agentic judge with sandboxed environment access to investigate trajectories—executing code, running tests, and analyzing error logs. We evaluate nine configurations across three models and three access modes (text-only, read-only agent, full sandbox). The best configuration—sandbox execution with GPT-5.2 Codex—achieves near-human agreement (κ=0.833), though the benefit of execution access is model-dependent. Error analysis reveals that weaker triage models exhibit a systematic directional bias: they over-attribute agent failures to task defects, constructing plausible defenses of the agent rather than identifying root causes—a failure mode with direct implications for any agent that uses its own critic to drive lifelong self-improvement.","published":"2026-02-16T04:58:40+00:00","updated":"2026-04-10T16:03:51+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=B6QfT7SHh8","openreview_url":"https://openreview.net/forum?id=iRhaK8PsuB","pdf_url":"https://openreview.net/pdf?id=B6QfT7SHh8","comment":"LLA 2026 Poster","journal_ref":"LLA 2026 Poster","doi":"","venue":"LLA 2026 Poster","venue_id":"ICLR.cc/2026/Workshop/LLA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["LLA 2026 Poster","ICLR 2026 Workshop RSI Poster"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2602.14337","versioned_id":"2602.14337v2","title":"LongCLI-Bench: A Preliminary Benchmark and Study for Long-horizon Agentic Programming in Command-Line Interfaces","authors":["Yukang Feng","Jianwen Sun","Zelai Yang","Jiaxin Ai","Chuanhao Li","Zizhen Li","Fanrui Zhang","Kang He","Rui Ma","Jifan Lin","Jie Sun","Yang Xiao","Sizhuo Zhou","Wenxiao Wu","Yiming Liu","Pengfei Liu","Yu Qiao","Shenglin Zhang","Kaipeng Zhang"],"abstract":"Recent advances in AI-assisted programming have empowered agents to execute complex workflows via command-line interfaces, however, existing benchmarks are limited by short task horizons, data contamination from GitHub scraping, and a lack of fine-grained evaluation metrics, fail to rigorously evaluate the long-horizon planning and execution capabilities essential for realistic software engineering. To address these gaps, we introduce LongCLI-Bench, a comprehensive benchmark designed to evaluate agentic capabilities across long-horizon, realistic tasks. We curated 20 high-quality, long-horizon tasks from over 1,000 computer science assignments and real-world workflows, covering four engineering categories: from scratch, feature addition, bug fixing, and refactoring. We propose a dual-set testing protocol for LongCLI-Bench, which measures requirement fulfillment (fail-to-pass) and regression avoidance (pass-to-pass), and incorporates step-level scoring to pinpoint execution failures. Extensive experiments reveal that even state-of-the-art agents achieve pass rates below 20% in LongCLI-Bench. Step-level analysis further indicates that the majority of tasks stall at less than 30% completion, highlighting that critical failures often occur in the early stages. Although self-correction offers marginal gains, human-agent collaboration through plan injection and interactive guidance yields significantly higher improvements. These results highlight that future research must emphasize the development of synergistic human-agent workflows alongside advances in agents' planning and execution capabilities to overcome key challenges in long-horizon task performance.","published":"2026-02-15T23:12:57Z","updated":"2026-02-26T11:54:11Z","categories":["cs.SE","cs.MA"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.14337v2","pdf_url":"https://arxiv.org/pdf/2602.14337v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.14093","versioned_id":"2602.14093v1","title":"GUI-GENESIS: Automated Synthesis of Efficient Environments with Verifiable Rewards for GUI Agent Post-Training","authors":["Yuan Cao","Dezhi Ran","Mengzhou Wu","Yuzhe Guo","Xin Chen","Ang Li","Gang Cao","Gong Zhi","Hao Yu","Linyi Li","Wei Yang","Tao Xie"],"abstract":"Post-training GUI agents in interactive environments is critical for developing generalization and long-horizon planning capabilities. However, training on real-world applications is hindered by high latency, poor reproducibility, and unverifiable rewards relying on noisy visual proxies. To address the limitations, we present GUI-GENESIS, the first framework to automatically synthesize efficient GUI training environments with verifiable rewards. GUI-GENESIS reconstructs real-world applications into lightweight web environments using multimodal code models and equips them with code-native rewards, executable assertions that provide deterministic reward signals and eliminate visual estimation noise. Extensive experiments show that GUI-GENESIS reduces environment latency by 10 times and costs by over $28,000 per epoch compared to training on real applications. Notably, agents trained with GUI-GENESIS outperform the base model by 14.54% and even real-world RL baselines by 3.27% on held-out real-world tasks. Finally, we observe that models can synthesize environments they cannot yet solve, highlighting a pathway for self-improving agents.","published":"2026-02-15T10:58:01Z","updated":"2026-02-15T10:58:01Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.14093v1","pdf_url":"https://arxiv.org/pdf/2602.14093v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.13949","versioned_id":"2602.13949v1","title":"Experiential Reinforcement Learning","authors":["Taiwei Shi","Sihao Chen","Bowen Jiang","Linxin Song","Longqi Yang","Jieyu Zhao"],"abstract":"Reinforcement learning has become the central approach for language models (LMs) to learn from environmental reward or feedback. In practice, the environmental feedback is usually sparse and delayed. Learning from such signals is challenging, as LMs must implicitly infer how observed failures should translate into behavioral changes for future iterations. We introduce Experiential Reinforcement Learning (ERL), a training paradigm that embeds an explicit experience-reflection-consolidation loop into the reinforcement learning process. Given a task, the model generates an initial attempt, receives environmental feedback, and produces a reflection that guides a refined second attempt, whose success is reinforced and internalized into the base policy. This process converts feedback into structured behavioral revision, improving exploration and stabilizing optimization while preserving gains at deployment without additional inference cost. Across sparse-reward control environments and agentic reasoning benchmarks, ERL consistently improves learning efficiency and final performance over strong reinforcement learning baselines, achieving gains of up to +81% in complex multi-step environments and up to +11% in tool-using reasoning tasks. These results suggest that integrating explicit self-reflection into policy training provides a practical mechanism for transforming feedback into durable behavioral improvement.","published":"2026-02-15T01:23:48Z","updated":"2026-02-15T01:23:48Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13949v1","pdf_url":"https://arxiv.org/pdf/2602.13949v1","comment":"26 pages, 9 tables, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=OSYyL6hqdP","openreview_venues":["LLA 2026 Poster"]},{"id":"2602.13807","versioned_id":"2602.13807v2","title":"AnomaMind: Agentic Time Series Anomaly Detection with Tool-Augmented Reasoning","authors":["Xiaoyu Tao","Yuchong Wu","Mingyue Cheng","Ze Guo","Tian Gao"],"abstract":"Time series anomaly detection is critical in many real-world applications, where effective solutions must localize anomalous regions and support reliable decision-making under complex settings. However, most existing methods frame anomaly detection as a purely discriminative prediction task with fixed feature representations, rather than an evidence-driven diagnostic process. As a result, they often struggle when anomalies exhibit strong context dependence, diverse patterns, or domain shifts across datasets. To address these challenges, we propose AnomaMind, an agentic time series anomaly detection framework that reformulates anomaly detection as a sequential decision-making process. AnomaMind operates through a coarse-to-fine workflow that first localizes suspicious intervals, then constructs diagnostic evidence through tool interaction, and finally refines anomaly decisions through self-reflection. The workflow is supported by a toolkit box that combines knowledge memory and numerical diagnostics: visual anomaly patterns mined from training data and domain knowledge provide contextual guidance, while statistical, value-based, change-based, and region-level operators provide measurable evidence for verification. AnomaMind further adopts a hybrid inference mechanism in which general-purpose models handle flexible reasoning, tool invocation, and refinement, while a detection-specific policy is optimized with rule-based rewards for parsable outputs, F1-score alignment, and false-positive control. Extensive experiments under both in-domain and cross-domain settings demonstrate that AnomaMind consistently improves anomaly detection performance and enhances generalization across heterogeneous anomaly patterns, validating the effectiveness of tool-augmented reasoning for anomaly detection. The code is available at https://github.com/Xiaoyu-Tao/AnomaMind-TS.","published":"2026-02-14T14:35:34Z","updated":"2026-06-09T12:15:24Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13807v2","pdf_url":"https://arxiv.org/pdf/2602.13807v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.13802","versioned_id":"2602.13802v1","title":"Cast-R1: Learning Tool-Augmented Sequential Decision Policies for Time Series Forecasting","authors":["Xiaoyu Tao","Mingyue Cheng","Chuang Jiang","Tian Gao","Huanjian Zhang","Yaguo Liu"],"abstract":"Time series forecasting has long been dominated by model-centric approaches that formulate prediction as a single-pass mapping from historical observations to future values. Despite recent progress, such formulations often struggle in complex and evolving settings, largely because most forecasting models lack the ability to autonomously acquire informative evidence, reason about potential future changes, or revise predictions through iterative decision processes. In this work, we propose Cast-R1, a learned time series forecasting framework that reformulates forecasting as a sequential decision-making problem. Cast-R1 introduces a memory-based state management mechanism that maintains decision-relevant information across interaction steps, enabling the accumulation of contextual evidence to support long-horizon reasoning. Building on this formulation, forecasting is carried out through a tool-augmented agentic workflow, in which the agent autonomously interacts with a modular toolkit to extract statistical features, invoke lightweight forecasting models for decision support, perform reasoning-based prediction, and iteratively refine forecasts through self-reflection. To train Cast-R1, we adopt a two-stage learning strategy that combines supervised fine-tuning with multi-turn reinforcement learning, together with a curriculum learning scheme that progressively increases task difficulty to improve policy learning. Extensive experiments on multiple real-world time series datasets demonstrate the effectiveness of Cast-R1. We hope this work provides a practical step towards further exploration of agentic paradigms for time series modeling. Our code is available at https://github.com/Xiaoyu-Tao/Cast-R1-TS.","published":"2026-02-14T14:27:08Z","updated":"2026-02-14T14:27:08Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.13802v1","pdf_url":"https://arxiv.org/pdf/2602.13802v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.13559","versioned_id":"2602.13559v2","title":"OpAgent: Operator Agent for Web Navigation","authors":["Yuyu Guo","Wenjie Yang","Siyuan Yang","Ziyang Liu","Cheng Chen","Yuan Wei","Yun Hu","Yang Huang","Guoliang Hao","Dongsheng Yuan","Jianming Wang","Xin Chen","Hang Yu","Lei Lei","Peng Di"],"abstract":"To fulfill user instructions, autonomous web agents must contend with the inherent complexity and volatile nature of real-world websites. Conventional paradigms predominantly rely on Supervised Fine-Tuning (SFT) or Offline Reinforcement Learning (RL) using static datasets. However, these methods suffer from severe distributional shifts, as offline trajectories fail to capture the stochastic state transitions and real-time feedback of unconstrained wide web environments. In this paper, we propose a robust Online Reinforcement Learning WebAgent, designed to optimize its policy through direct, iterative interactions with unconstrained wide websites. Our approach comprises three core innovations: 1) Hierarchical Multi-Task Fine-tuning: We curate a comprehensive mixture of datasets categorized by functional primitives -- Planning, Acting, and Grounding -- establishing a Vision-Language Model (VLM) with strong instruction-following capabilities for Web GUI tasks. 2) Online Agentic RL in the Wild: We develop an online interaction environment and fine-tune the VLM using a specialized RL pipeline. We introduce a Hybrid Reward Mechanism that combines a ground-truth-agnostic WebJudge for holistic outcome assessment with a Rule-based Decision Tree (RDT) for progress reward. This system effectively mitigates the credit assignment challenge in long-horizon navigation. Notably, our RL-enhanced model achieves a 38.1\\% success rate (pass@5) on WebArena, outperforming all existing monolithic baselines. 3) Operator Agent: We introduce a modular agentic framework, namely \\textbf{OpAgent}, orchestrating a Planner, Grounder, Reflector, and Summarizer. This synergy enables robust error recovery and self-correction, elevating the agent's performance to a new State-of-the-Art (SOTA) success rate of \\textbf{71.6\\%}.","published":"2026-02-14T02:33:55Z","updated":"2026-04-30T02:05:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.13559v2","pdf_url":"https://arxiv.org/pdf/2602.13559v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.12430","versioned_id":"2602.12430v4","title":"Agent Skills for Large Language Models: Architecture, Acquisition, Security, and the Path Forward","authors":["Renjun Xu","Yang Yan"],"abstract":"The transition from monolithic language models to modular, skill-equipped agents marks a defining shift in how large language models (LLMs) are deployed in practice. Rather than encoding all procedural knowledge within model weights, agent skills -- composable packages of instructions, code, and resources that agents load on demand -- enable dynamic capability extension without retraining. It is formalized in a paradigm of progressive disclosure, portable skill definitions, and integration with the Model Context Protocol (MCP). This survey provides a comprehensive treatment of the agent skills landscape, as it has rapidly evolved during the last few months. We organize the field along four axes: (i) architectural foundations, examining the SKILL$.$md specification, progressive context loading, and the complementary roles of skills and MCP; (ii) skill acquisition, covering reinforcement learning with skill libraries, autonomous skill discovery (SEAgent), and compositional skill synthesis; (iii) deployment at scale, including the computer-use agent (CUA) stack, GUI grounding advances, and benchmark progress on OSWorld and SWE-bench; and (iv) security, where recent empirical analyses reveal that 26.1% of community-contributed skills contain vulnerabilities, motivating our proposed Skill Trust and Lifecycle Governance Framework -- a four-tier, gate-based permission model that maps skill provenance to graduated deployment capabilities. We identify seven open challenges -- from cross-platform skill portability to capability-based permission models -- and propose a research agenda for realizing trustworthy, self-improving skill ecosystems. Unlike prior surveys that broadly cover LLM agents or tool use, this work focuses specifically on the emerging skill abstraction layer and its implications for the next generation of agentic systems. Project repo: https://github.com/scienceaix/agentskills","published":"2026-02-12T21:33:25Z","updated":"2026-06-02T16:14:54Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.12430v4","pdf_url":"https://arxiv.org/pdf/2602.12430v4","comment":"Accepted by Agent Skills '26 Workshop at ACM Conference on AI and Agentic Systems 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Er0p92BsmW","openreview_venues":["AgentSkills 2026 Poster"]},{"id":"2602.12311","versioned_id":"2602.12311v1","title":"Perceptual Self-Reflection in Agentic Physics Simulation Code Generation","authors":["Prashant Shende","Bradley Camburn"],"abstract":"We present a multi-agent framework for generating physics simulation code from natural language descriptions, featuring a novel perceptual self-reflection mechanism for validation. The system employs four specialized agents: a natural language interpreter that converts user requests into physics-based descriptions; a technical requirements generator that produces scaled simulation parameters; a physics code generator with automated self-correction; and a physics validator that implements perceptual self-reflection. The key innovation is perceptual validation, which analyzes rendered animation frames using a vision-capable language model rather than inspecting code structure directly. This approach addresses the ``oracle gap'' where syntactically correct code produces physically incorrect behavior--a limitation that conventional testing cannot detect. We evaluate the system across seven domains including classical mechanics, fluid dynamics, thermodynamics, electromagnetics, wave physics, reaction-diffusion systems, and non-physics data visualization. The perceptual self-reflection architecture demonstrates substantial improvement over single-shot generation baselines, with the majority of tested scenarios achieving target physics accuracy thresholds. The system exhibits robust pipeline stability with consistent code self-correction capability, operating at approximately \\$0.20 per animation. These results validate our hypothesis that feeding visual simulation outputs back to a vision-language model for iterative refinement significantly outperforms single-shot code generation for physics simulation tasks and highlights the potential of agentic AI to support engineering workflows and physics data generation pipelines.","published":"2026-02-12T15:48:33Z","updated":"2026-02-12T15:48:33Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.12311v1","pdf_url":"https://arxiv.org/pdf/2602.12311v1","comment":"15 pages, 2 figures, 2 tables. Introduces a multi-agent architecture for physics simulation code generation with perceptual self-reflection via vision-based validation. Includes qualitative evaluation across multiple physics domains","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:TYOxtvvGYi","versioned_id":"TYOxtvvGYi","title":"Towards Operationalizing Accountability for Self-Improving Multi-Agent Systems","authors":[],"abstract":"Accountability mechanisms can help agents improve their behavior by learning from substandard outcomes. When a substandard situation arises, an accountee requests accountors to render accounts, evaluates them to derive remedies, and provides feedback that accountors use to update their procedural knowledge. We present ongoing work on designing such mechanisms for self-improving multi-agent systems. Our current focus is on agents equipped with procedural knowledge created by developers (e.g., Jason plans, skills for language agents), with the objective of enabling them to improve that procedural knowledge over time. Accountors render accounts in natural language, and we use LLMs to evaluate their accounts, provide feedback, and update their procedural knowledge. We present a JaCaMo-based implementation for a home heating scenario where an agent wastes energy by heating a room with an open window. Preliminary experiments with Claude Opus 4.5 show promising results: the agent learns preventive behavior (checking and closing the window before heating) in 90\\% of cases and corrective behavior (closing the window during heating) in 100\\% of cases. We extend our experiments to include a human who intentionally left the window open for a bird to fly out. In this scenario, the agent learns to respect the human's intention by delaying or stopping the heating and notifying the human instead of closing the window (80% preventive, 100% corrective). The agent also learns to coordinate with the human, resuming heating once the human closes the window in 60% of cases. These results suggest that LLM-mediated accountability can be effective and can enable collaborative behaviors that respect human intention.","published":"2026-02-12T08:41:26+00:00","updated":"2026-07-09T09:34:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=TYOxtvvGYi","openreview_url":"https://openreview.net/forum?id=TYOxtvvGYi","pdf_url":"https://openreview.net/pdf?id=TYOxtvvGYi","comment":"EMAS 2026 Oral","journal_ref":"EMAS 2026 Oral","doi":"","venue":"EMAS 2026 Oral","venue_id":"ifaamas.org/AAMAS/2026/Workshop/EMAS","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2602.11666","versioned_id":"2602.11666v1","title":"PhyNiKCE: A Neurosymbolic Agentic Framework for Autonomous Computational Fluid Dynamics","authors":["E Fan","Lisong Shi","Zhengtong Li","Chih-yung Wen"],"abstract":"The deployment of autonomous agents for Computational Fluid Dynamics (CFD), is critically limited by the probabilistic nature of Large Language Models (LLMs), which struggle to enforce the strict conservation laws and numerical stability required for physics-based simulations. Reliance on purely semantic Retrieval Augmented Generation (RAG) often leads to \"context poisoning,\" where agents generate linguistically plausible but physically invalid configurations due to a fundamental Semantic-Physical Disconnect. To bridge this gap, this work introduces PhyNiKCE (Physical and Numerical Knowledgeable Context Engineering), a neurosymbolic agentic framework for trustworthy engineering. Unlike standard black-box agents, PhyNiKCE decouples neural planning from symbolic validation. It employs a Symbolic Knowledge Engine that treats simulation setup as a Constraint Satisfaction Problem, rigidly enforcing physical constraints via a Deterministic RAG Engine with specialized retrieval strategies for solvers, turbulence models, and boundary conditions. Validated through rigorous OpenFOAM experiments on practical, non-tutorial CFD tasks using Gemini-2.5-Pro/Flash, PhyNiKCE demonstrates a 96% relative improvement over state-of-the-art baselines. Furthermore, by replacing trial-and-error with knowledge-driven initialization, the framework reduced autonomous self-correction loops by 59% while simultaneously lowering LLM token consumption by 17%. These results demonstrate that decoupling neural generation from symbolic constraint enforcement significantly enhances robustness and efficiency. While validated on CFD, this architecture offers a scalable, auditable paradigm for Trustworthy Artificial Intelligence in broader industrial automation.","published":"2026-02-12T07:37:56Z","updated":"2026-02-12T07:37:56Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.11666v1","pdf_url":"https://arxiv.org/pdf/2602.11666v1","comment":"30 pages, 10 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2603.29602","versioned_id":"2603.29602v1","title":"IMAGAgent: Orchestrating Multi-Turn Image Editing via Constraint-Aware Planning and Reflection","authors":["Fei Shen","Chengyu Xie","Lihong Wang","Zhanyi Zhang","Xin Jiang","Xiaoyu Du","Jinhui Tang"],"abstract":"Existing multi-turn image editing paradigms are often confined to isolated single-step execution. Due to a lack of context-awareness and closed-loop feedback mechanisms, they are prone to error accumulation and semantic drift during multi-turn interactions, ultimately resulting in severe structural distortion of the generated images. For that, we propose \\textbf{IMAGAgent}, a multi-turn image editing agent framework based on a \"plan-execute-reflect\" closed-loop mechanism that achieves deep synergy among instruction parsing, tool scheduling, and adaptive correction within a unified pipeline. Specifically, we first present a constraint-aware planning module that leverages a vision-language model (VLM) to precisely decompose complex natural language instructions into a series of executable sub-tasks, governed by target singularity, semantic atomicity, and visual perceptibility. Then, the tool-chain orchestration module dynamically constructs execution paths based on the current image, the current sub-task, and the historical context, enabling adaptive scheduling and collaborative operation among heterogeneous operation models covering image retrieval, segmentation, detection, and editing. Finally, we devise a multi-expert collaborative reflection mechanism where a central large language model (LLM) receives the image to be edited and synthesizes VLM critiques into holistic feedback, simultaneously triggering fine-grained self-correction and recording feedback outcomes to optimize future decisions. Extensive experiments on our constructed \\textbf{MTEditBench} and the MagicBrush dataset demonstrate that IMAGAgent achieves performance significantly superior to existing methods in terms of instruction consistency, editing precision, and overall quality. The code is available at https://github.com/hackermmzz/IMAGAgent.git.","published":"2026-02-12T02:37:38Z","updated":"2026-02-12T02:37:38Z","categories":["cs.GR","cs.AI","cs.CV","cs.MA"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2603.29602v1","pdf_url":"https://arxiv.org/pdf/2603.29602v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:wZMNXHPYcO","versioned_id":"wZMNXHPYcO","title":"Self-Improvement via Fast Tree-search","authors":["Xinghong Fu","Aravinth Kulanthaivelu","Yutaro Yamada"],"abstract":"Coding agents can recursively modify their own implementations, forming a loop of self improvement. While prior work shows this can boost performance on coding benchmarks, existing approaches are costly and compute-intensive. We introduce a simple, sample-efficient self-improvement framework that significantly improves coding performance under strict budget constraints. We identify evaluation of candidate self-modifications as the main bottleneck since prior approaches estimate their effectiveness by re-running a subset of benchmark tasks with the modified agent. We replace these partial benchmark runs with an LLM-as-a-judge signal to rank candidate patches, reserving expensive evaluations only for the most promising ones. Combined with a lightweight tree search, this enables effective exploration with minimal overhead. On a subset of SWE-bench Verified, our method improves gpt-5-mini pass rate by over 11\\% in fewer than three self-improvement steps, using just \\$25 in API costs within 15 CPU hours.","published":"2026-02-11T10:48:14+00:00","updated":"2026-03-07T10:07:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wZMNXHPYcO","openreview_url":"https://openreview.net/forum?id=wZMNXHPYcO","pdf_url":"https://openreview.net/pdf?id=wZMNXHPYcO","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2602.10604","versioned_id":"2602.10604v2","title":"Step 3.5 Flash: Open Frontier-Level Intelligence with 11B Active Parameters","authors":["Ailin Huang","Ang Li","Aobo Kong","Bin Wang","Binxing Jiao","Bo Dong","Bojun Wang","Boyu Chen","Brian Li","Buyun Ma","Chang Su","Changxin Miao","Changyi Wan","Chao Lou","Chen Hu","Chen Xu","Chenfeng Yu","Chengting Feng","Chengyuan Yao","Chunrui Han","Dan Ma","Dapeng Shi","Daxin Jiang","Dehua Ma","Deshan Sun","Di Qi","Enle Liu","Fajie Zhang","Fanqi Wan","Guanzhe Huang","Gulin Yan","Guoliang Cao","Guopeng Li","Han Cheng","Hangyu Guo","Hanshan Zhang","Hao Nie","Haonan Jia","Haoran Lv","Hebin Zhou","Hekun Lv","Heng Wang","Heung-Yeung Shum","Hongbo Huang","Hongbo Peng","Hongyu Zhou","Hongyuan Wang","Houyong Chen","Huangxi Zhu","Huimin Wu","Huiyong Guo","Jia Wang","Jian Zhou","Jianjian Sun","Jiaoren Wu","Jiaran Zhang","Jiashu Lv","Jiashuo Liu","Jiayi Fu","Jiayu Liu","Jie Cheng","Jie Luo","Jie Yang","Jie Zhou","Jieyi Hou","Jing Bai","Jingcheng Hu","Jingjing Xie","Jingwei Wu","Jingyang Zhang","Jishi Zhou","Junfeng Liu","Junzhe Lin","Ka Man Lo","Kai Liang","Kaibo Liu","Kaijun Tan","Kaiwen Yan","Kaixiang Li","Kang An","Kangheng Lin","Lei Yang","Liang Lv","Liang Zhao","Liangyu Chen","Lieyu Shi","Liguo Tan","Lin Lin","Lina Chen","Luck Ma","Mengqiang Ren","Michael Li","Ming Li","Mingliang Li","Mingming Zhang","Mingrui Chen","Mitt Huang","Na Wang","Peng Liu","Qi Han","Qian Zhao","Qinglin He","Qinxin Du","Qiuping Wu","Quan Sun","Rongqiu Yang","Ruihang Miao","Ruixin Han","Ruosi Wan","Ruyan Guo","Shan Wang","Shaoliang Pang","Shaowen Yang","Shengjie Fan","Shijie Shang","Shiliang Yang","Shiwei Li","Shuangshuang Tian","Siqi Liu","Siye Wu","Siyu Chen","Song Yuan","Tiancheng Cao","Tianchi Yue","Tianhao Cheng","Tianning Li","Tingdan Luo","Wang You","Wei Ji","Wei Yuan","Wei Zhang","Weibo Wu","Weihao Xie","Wen Sun","Wenjin Deng","Wenzhen Zheng","Wuxun Xie","Xiangfeng Wang","Xiangwen Kong","Xiangyu Liu","Xiangyu Zhang","Xiaobo Yang","Xiaojia Liu","Xiaolan Yuan","Xiaoran Jiao","Xiaoxiao Ren","Xiaoyun Zhang","Xin Li","Xin Liu","Xin Wu","Xing Chen","Xingping Yang","Xinran Wang","Xu Zhao","Xuan He","Xuanti Feng","Xuedan Cai","Xuqiang Zhou","Yanbo Yu","Yang Li","Yang Xu","Yanlin Lai","Yanming Xu","Yaoyu Wang","Yeqing Shen","Yibo Zhu","Yichen Lv","Yicheng Cao","Yifeng Gong","Yijing Yang","Yikun Yang","Yin Zhao","Yingxiu Zhao","Yinmin Zhang","Yitong Zhang","Yixuan Zhang","Yiyang Chen","Yongchi Zhao","Yongshen Long","Yongyao Wang","Yousong Guan","Yu Zhou","Yuang Peng","Yuanhao Ding","Yuantao Fan","Yuanwei Lu","Yuanzhen Yang","Yuchu Luo","Yudi Zhao","Yue Peng","Yueqiang Lin","Yufan Lu","Yuling Zhao","Yunzhou Ju","Yurong Zhang","Yusheng Li","Yuxiang Yang","Yuyang Chen","Yuzhu Cai","Zejia Weng","Zetao Hong","Zexi Li","Zhe Xie","Zheng Ge","Zheng Gong","Zheng Zeng","Zhenyi Lu","Zhewei Huang","Zhichao Chang","Zhiguo Huang","Zhiheng Hu","Zidong Yang","Zili Wang","Ziqi Ren","Zixin Zhang","Zixuan Wang"],"abstract":"We introduce Step 3.5 Flash, a sparse Mixture-of-Experts (MoE) model that bridges frontier-level agentic intelligence and computational efficiency. We focus on what matters most when building agents: sharp reasoning and fast, reliable execution. Step 3.5 Flash pairs a 196B-parameter foundation with 11B active parameters for efficient inference. It is optimized with interleaved 3:1 sliding-window/full attention and Multi-Token Prediction (MTP-3) to reduce the latency and cost of multi-round agentic interactions. To reach frontier-level intelligence, we design a scalable reinforcement learning framework that combines verifiable signals with preference feedback, while remaining stable under large-scale off-policy training, enabling consistent self-improvement across mathematics, code, and tool use. Step 3.5 Flash demonstrates strong performance across agent, coding, and math tasks, achieving 85.4% on IMO-AnswerBench, 86.4% on LiveCodeBench-v6 (2024.08-2025.05), 88.2% on tau2-Bench, 69.0% on BrowseComp (with context management), and 51.0% on Terminal-Bench 2.0, comparable to frontier models such as GPT-5.2 xHigh and Gemini 3.0 Pro. By redefining the efficiency frontier, Step 3.5 Flash provides a high-density foundation for deploying sophisticated agents in real-world industrial environments.","published":"2026-02-11T07:53:51Z","updated":"2026-02-23T16:07:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.10604v2","pdf_url":"https://arxiv.org/pdf/2602.10604v2","comment":"Technical report for Step 3.5 Flash","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:SeZCSEGZTq","versioned_id":"SeZCSEGZTq","title":"Soft Mellowmax Monte Carlo Planning","authors":["Danilo Vucetic","Gauthier Gidel"],"abstract":"Soft mellowmax (SMM) recently emerged as an alternative operator in Q-learning, achieving impressive performance in games and scientific discovery tasks. Despite SMM's ability to achieve high returns and its enticing robustness, diversity, and sample efficiency characteristics, SMM has not yet been translated into a Monte Carlo tree search algorithm. To address this gap, a soft mellowmax-based Monte Carlo tree search algorithm, SMM-TS, is proposed and theoretically justified. It is empirically demonstrated that SMM-TS converges significantly faster than other tree search methods in synthetic environments, while maintaining competitive performance in games. The fast convergence of SMM-TS makes recursive self-improvement loops more scalable, while the stability gained via planning and the robustness of the operator make SMM-TS more practical for agents operating in uncertain and changing environments.","published":"2026-02-11T00:57:37+00:00","updated":"2026-03-11T15:47:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=SeZCSEGZTq","openreview_url":"https://openreview.net/forum?id=SeZCSEGZTq","pdf_url":"https://openreview.net/pdf?id=SeZCSEGZTq","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2602.09877","versioned_id":"2602.09877v2","title":"The Devil Behind Moltbook: Anthropic Safety is Always Vanishing in Self-Evolving AI Societies","authors":["Chenxu Wang","Chaozhuo Li","Songyang Liu","Zejian Chen","Jinyu Hou","Ji Qi","Rui Li","Litian Zhang","Qiwei Ye","Zheng Liu","Xu Chen","Xi Zhang","Philip S. Yu"],"abstract":"The emergence of multi-agent systems built from large language models (LLMs) offers a promising paradigm for scalable collective intelligence and self-evolution. Ideally, such systems would achieve continuous self-improvement in a fully closed loop while maintaining robust safety alignment--a combination we term the self-evolution trilemma. However, we demonstrate both theoretically and empirically that an agent society satisfying continuous self-evolution, complete isolation, and safety invariance is impossible. Drawing on an information-theoretic framework, we formalize safety as the divergence degree from anthropic value distributions. We theoretically demonstrate that isolated self-evolution induces statistical blind spots, leading to the irreversible degradation of the system's safety alignment. Empirical and qualitative results from an open-ended agent community (Moltbook) and two closed self-evolving systems reveal phenomena that align with our theoretical prediction of inevitable safety erosion. We further propose several solution directions to alleviate the identified safety concern. Our work establishes a fundamental limit on the self-evolving AI societies and shifts the discourse from symptom-driven safety patches to a principled understanding of intrinsic dynamical risks, highlighting the need for external oversight or novel safety-preserving mechanisms.","published":"2026-02-10T15:18:19Z","updated":"2026-02-11T03:42:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.09877v2","pdf_url":"https://arxiv.org/pdf/2602.09877v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.09252","versioned_id":"2602.09252v1","title":"VLM-Guided Iterative Refinement for Surgical Image Segmentation with Foundation Models","authors":["Ange Lou","Yamin Li","Qi Chang","Nan Xi","Luyuan Xie","Zichao Li","Tianyu Luan"],"abstract":"Surgical image segmentation is essential for robot-assisted surgery and intraoperative guidance. However, existing methods are constrained to predefined categories, produce one-shot predictions without adaptive refinement, and lack mechanisms for clinician interaction. We propose IR-SIS, an iterative refinement system for surgical image segmentation that accepts natural language descriptions. IR-SIS leverages a fine-tuned SAM3 for initial segmentation, employs a Vision-Language Model to detect instruments and assess segmentation quality, and applies an agentic workflow that adaptively selects refinement strategies. The system supports clinician-in-the-loop interaction through natural language feedback. We also construct a multi-granularity language-annotated dataset from EndoVis2017 and EndoVis2018 benchmarks. Experiments demonstrate state-of-the-art performance on both in-domain and out-of-distribution data, with clinician interaction providing additional improvements. Our work establishes the first language-based surgical segmentation framework with adaptive self-refinement capabilities.","published":"2026-02-09T22:36:36Z","updated":"2026-02-09T22:36:36Z","categories":["cs.CV","cs.AI","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.09252v1","pdf_url":"https://arxiv.org/pdf/2602.09252v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.08948","versioned_id":"2602.08948v1","title":"CoRefine: Confidence-Guided Self-Refinement for Adaptive Test-Time Compute","authors":["Chen Jin","Ryutaro Tanno","Tom Diethe","Philip Teare"],"abstract":"Large Language Models (LLMs) often rely on test-time scaling via parallel decoding (for example, 512 samples) to boost reasoning accuracy, but this incurs substantial compute. We introduce CoRefine, a confidence-guided self-refinement method that achieves competitive accuracy using a fraction of the tokens via a lightweight 211k-parameter Conv1D controller atop a frozen LLM. The controller consumes full-trace confidence to decide whether to halt, re-examine, or try a different approach, enabling targeted self-correction with an average of 2.7 refinement steps per problem and roughly 190-fold token reduction relative to 512-sample baselines. Across diverse reasoning benchmarks and three open-source models, the controller achieves 92.6 percent precision when it confidently halts, indicating that confidence dynamics reliably signal correctness without ground-truth verification. We extend this to CoRefine-Tree, a hybrid sequential-parallel variant that adaptively balances exploration and exploitation, with easy serving integration and verifier compatibility. By treating confidence as a control signal rather than a correctness guarantee, CoRefine provides a modular primitive for scalable reasoning and agentic settings with imperfect verifiers.","published":"2026-02-09T17:44:41Z","updated":"2026-02-09T17:44:41Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.08948v1","pdf_url":"https://arxiv.org/pdf/2602.08948v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:ikrQWGgxYg","versioned_id":"ikrQWGgxYg","title":"Reward Hacking in Self-Improving Code Agents","authors":["Bingchen Zhao","Dhruv Srikanth","Yuxiang Wu","zhengyao jiang"],"abstract":"Recursive self-improvement (RSI) systems that iteratively optimize code with ex- ecution feedback are increasingly used for automated algorithm and systems op- timization. A central failure mode is reward hacking: the agent improves a cheap proxy metric without improving or even harming the true objective under more re- alistic evaluation. We present a large-scale quantitative study of reward hacking in iterative code optimization by agents across two settings: GPU kernel optimiza- tion and algorithmic optimization. Across three frontier models and five agent configurations, we analyze thousands of agent trajectories under a setting where we have access to a held set of tasks (real tasks) for code evaluation while the agent only has access to a public set of evaluations (proxy tasks). Reward hacking is per- vasive: among our experiments, 73.8% of Kernel-Bench optimizations and 46.8% of ALE-Bench optimizations exhibit proxy gains without gains in the real tasks. A temporal analysis shows the proxy-reality gap widens with optimization steps, go- ing from 10 steps to 100 steps of optimization, percentage of reward hacking rises 31.4% from 26.4% to 57.8%. With this quantitative evaluation framework, we are able to evaluate techniques that may prevent reward hacking such as retrospection, a lightweight self-critique intervention triggered either probabilistically or on sig- nificant proxy metrics jumps. Retrospection reduces Kernel-Bench hacking by ∼17–19 points in some cases, but shows no consistent reduction on ALE-Bench and can increase hacking in some settings, indicating potential future research works to be done on this direction. We believe this quantitative formulation of reward hacking can be useful for future research studying and measuring agent capabilities on recursive self-improvements.","published":"2026-02-08T18:04:06+00:00","updated":"2026-03-05T19:33:24+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ikrQWGgxYg","openreview_url":"https://openreview.net/forum?id=ikrQWGgxYg","pdf_url":"https://openreview.net/pdf?id=ikrQWGgxYg","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2602.07755","versioned_id":"2602.07755v1","title":"Learning to Continually Learn via Meta-learning Agentic Memory Designs","authors":["Yiming Xiong","Shengran Hu","Jeff Clune"],"abstract":"The statelessness of foundation models bottlenecks agentic systems' ability to continually learn, a core capability for long-horizon reasoning and adaptation. To address this limitation, agentic systems commonly incorporate memory modules to retain and reuse past experience, aiming for continual learning during test time. However, most existing memory designs are human-crafted and fixed, which limits their ability to adapt to the diversity and non-stationarity of real-world tasks. In this paper, we introduce ALMA (Automated meta-Learning of Memory designs for Agentic systems), a framework that meta-learns memory designs to replace hand-engineered memory designs, therefore minimizing human effort and enabling agentic systems to be continual learners across diverse domains. Our approach employs a Meta Agent that searches over memory designs expressed as executable code in an open-ended manner, theoretically allowing the discovery of arbitrary memory designs, including database schemas as well as their retrieval and update mechanisms. Extensive experiments across four sequential decision-making domains demonstrate that the learned memory designs enable more effective and efficient learning from experience than state-of-the-art human-crafted memory designs on all benchmarks. When developed and deployed safely, ALMA represents a step toward self-improving AI systems that learn to be adaptive, continual learners.","published":"2026-02-08T01:20:49Z","updated":"2026-02-08T01:20:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07755v1","pdf_url":"https://arxiv.org/pdf/2602.07755v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PRkA1cwXC2","openreview_venues":["ICLR 2026 Workshop RSI Oral","ICLR 2026 Workshop MemAgents Oral"]},{"id":"2602.07749","versioned_id":"2602.07749v1","title":"Geo-Code: A Code Framework for Reverse Code Generation from Geometric Images Based on Two-Stage Multi-Agent Evolution","authors":["Zhenyu Wu","Yanxi Long","Jian Li","Hua Huang"],"abstract":"Program code serves as a bridge linking vision and logic, providing a feasible supervisory approach for enhancing the multimodal reasoning capability of large models through geometric operations such as auxiliary line construction and perspective transformation. Nevertheless, current inverse graphics methods face tremendous challenges in accurately reconstructing complex geometric details, which often results in the loss of key geometric constraints or structural distortion. To address this bottleneck, we propose Geo-coder -- the first inverse programming framework for geometric images based on a multi-agent system. Our method innovatively decouples the process into geometric modeling via pixel-wise anchoring and metric-driven code evolution: Stage 1 leverages the complementary advantages of visual operators and large models to achieve precise capture of pixel coordinates and visual attributes; Stage 2 introduces a synthesis-rendering-validation closed loop, where bidirectional visual feedback drives the self-correction of code. Extensive experiments demonstrate that Geo-coder achieves a substantial lead in both geometric reconstruction accuracy and visual consistency. Notably, by effectively preserving the core geometric semantics, the images reconstructed with our method exhibit equivalent performance to the original ones in multimodal reasoning tasks, which fully validates the robustness of the framework. Finally, to further reduce research costs, we have open-sourced the Geo-coder dataset constructed on the GeoCode framework, which contains more than 1,500 samples. On this basis, we have also open-sourced the GeocodeLM model, laying a solid data and model foundation for subsequent research in this field.","published":"2026-02-08T00:48:49Z","updated":"2026-02-08T00:48:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07749v1","pdf_url":"https://arxiv.org/pdf/2602.07749v1","comment":"ICML2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.07625","versioned_id":"2602.07625v1","title":"AD-MIR: Bridging the Gap from Perception to Persuasion in Advertising Video Understanding via Structured Reasoning","authors":["Binxiao Xu","Junyu Feng","Xiaopeng Lin","Haodong Li","Zhiyuan Feng","Bohan Zeng","Shaolin Lu","Ming Lu","Qi She","Wentao Zhang"],"abstract":"Multimodal understanding of advertising videos is essential for interpreting the intricate relationship between visual storytelling and abstract persuasion strategies. However, despite excelling at general search, existing agents often struggle to bridge the cognitive gap between pixel-level perception and high-level marketing logic. To address this challenge, we introduce AD-MIR, a framework designed to decode advertising intent via a two-stage architecture. First, in the Structure-Aware Memory Construction phase, the system converts raw video into a structured database by integrating semantic retrieval with exact keyword matching. This approach prioritizes fine-grained brand details (e.g., logos, on-screen text) while dynamically filtering out irrelevant background noise to isolate key protagonists. Second, the Structured Reasoning Agent mimics a marketing expert through an iterative inquiry loop, decomposing the narrative to deduce implicit persuasion tactics. Crucially, it employs an evidence-based self-correction mechanism that rigorously validates these insights against specific video frames, automatically backtracking when visual support is lacking. Evaluation on the AdsQA benchmark demonstrates that AD-MIR achieves state-of-the-art performance, surpassing the strongest general-purpose agent, DVD, by 1.8% in strict and 9.5% in relaxed accuracy. These results underscore that effective advertising understanding demands explicitly grounding abstract marketing strategies in pixel-level evidence. The code is available at https://github.com/Little-Fridge/AD-MIR.","published":"2026-02-07T17:14:06Z","updated":"2026-02-07T17:14:06Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.07625v1","pdf_url":"https://arxiv.org/pdf/2602.07625v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=9vPBISqNVo","openreview_venues":["ICML 2026 regular"]},{"id":"2602.07187","versioned_id":"2602.07187v1","title":"PreFlect: From Retrospective to Prospective Reflection in Large Language Model Agents","authors":["Hanyu Wang","Yuanpu Cao","Lu Lin","Jinghui Chen"],"abstract":"Advanced large language model agents typically adopt self-reflection for improving performance, where agents iteratively analyze past actions to correct errors. However, existing reflective approaches are inherently retrospective: agents act, observe failure, and only then attempt to recover. In this work, we introduce PreFlect, a prospective reflection mechanism that shifts the paradigm from post hoc correction to pre-execution foresight by criticizing and refining agent plans before execution. To support grounded prospective reflection, we distill planning errors from historical agent trajectories, capturing recurring success and failure patterns observed across past executions. Furthermore, we complement prospective reflection with a dynamic re-planning mechanism that provides execution-time plan update in case the original plan encounters unexpected deviation. Evaluations on different benchmarks demonstrate that PreFlect significantly improves overall agent utility on complex real-world tasks, outperforming strong reflection-based baselines and several more complex agent architectures. Code will be updated at https://github.com/wwwhy725/PreFlect.","published":"2026-02-06T20:42:44Z","updated":"2026-02-06T20:42:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.07187v1","pdf_url":"https://arxiv.org/pdf/2602.07187v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:KgQphSXJj4","versioned_id":"KgQphSXJj4","title":"Uncertainty-Aware Self-Correction for Coding Agents","authors":["Jason Almeida","Lokesh Sai Dasari","Anubhav Pal","Tinuade Adeleke","Sean Wu","Ruizhe Li"],"abstract":"Recent advances in large language models (LLMs) have enabled agentic systems that perform complex, multi-step tasks in realistic environments, particularly in software engineering settings where agents must navigate code bases, plan actions, execute code, and iteratively adapt based on environmental feedback. Despite their capabilities, agent reliability remains a critical challenge: errors made early in an agent's trajectory can propagate, leading to incorrect patches, wasted computation, or misleading confidence. Most existing uncertainty estimation methods focus on single-turn outputs and do not account for uncertainty accumulation across multi-step reasoning. In this work, we adapt and extend Situational Awareness Uncertainty Propagation (SAUP) to coding agents operating on SWE-Rebench. We propose a simplified variant of SAUP that replaces learned semantic distance metrics with API-derived signals and heuristic action weights, making it practical for black-box API settings. We demonstrate how step level uncertainty estimation can be propagated across an agent's trajectory and used to trigger self-correction when confidence is low. By intervening selectively at high-uncertainty steps, our approach improves final task success while avoiding unnecessary computation. Across three frontier models (GPT-5, Claude Opus 4.5, and DeepSeek V3.2), uncertainty-aware resampling reduces mean trajectory uncertainty by 6-20\\% relative and improves pass@1 by up to 15.6 absolute percentage points, with latency overhead of 1.2-3.0$\\times$ depending on the model.","published":"2026-02-06T11:40:37+00:00","updated":"2026-04-24T11:01:10+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=KgQphSXJj4","openreview_url":"https://openreview.net/forum?id=KgQphSXJj4","pdf_url":"https://openreview.net/pdf?id=KgQphSXJj4","comment":"ICLR 2026 AIWILD","journal_ref":"ICLR 2026 AIWILD","doi":"","venue":"ICLR 2026 AIWILD","venue_id":"ICLR.cc/2026/Workshop/AIWILD","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:vWwgOQ1MMm","versioned_id":"vWwgOQ1MMm","title":"LLM-Augmented FPGA Timing Closure: Toward Intelligent Static Timing Analysis Agents","authors":["Saher Elsayed"],"abstract":"Achieving timing closure in modern FPGA designs remains a significant bottleneck in the electronic design automation (EDA) workflow, often requiring extensive manual intervention and iterative refinement by experienced engineers. We propose TimingLLM, a novel framework that leverages Large Language Models (LLMs) augmented with Retrieval-Augmented Generation (RAG) to automate and accelerate FPGA static timing analysis (STA). Our approach integrates domain-specific knowledge bases containing FPGA architectural specifications, timing constraints, and historical optimization strategies to enable LLM-driven timing violation diagnosis and automated fix recommendation. We evaluate TimingLLM on 12 production-representative FPGA designs across networking, signal processing, and AI accelerator applications, comprising 658 timing violations. Experimental results demonstrate that TimingLLM achieves 82% F1 score in violation root cause classification, with particularly strong performance on clock domain crossing (100% F1) and architectural bottleneck detection (97% F1). LLM-generated constraint fixes reduce worst negative slack by 56% on average. Extended experiments show stable performance up to 1,200 violations with sub-3ms inference time, and cross-domain transfer analysis reveals ~20% degradation when generalizing across application domains. This work establishes the foundation for autonomous timing closure agents that can significantly reduce design iteration cycles.","published":"2026-02-06T02:45:10+00:00","updated":"2026-03-09T23:59:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vWwgOQ1MMm","openreview_url":"https://openreview.net/forum?id=vWwgOQ1MMm","pdf_url":"https://openreview.net/pdf?id=vWwgOQ1MMm","comment":"Architecture 2.0 2026","journal_ref":"Architecture 2.0 2026","doi":"","venue":"Architecture 2.0 2026","venue_id":"ACM.org/ASPLOS/2026/Workshop/Architecture_2.0","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:iGBY24NlU1","versioned_id":"iGBY24NlU1","title":"Efficient Hallucination Detection in Automatic Code Generation","authors":["Georgii Andriushchenko","Roman Garaev","Lyudmila Rvanova","Artem Shelmanov","Vladimir V. Ivanov"],"abstract":"Large language models (LLMs) frequently produce source code that seems correct and well-formed, yet includes hallucinated elements that cause downstream test failures. While uncertainty quantification (UQ) methods have shown promise for hallucination detection in natural language, their effectiveness in the code generation setting remains largely unexplored. In this work, we investigate the performance of state-of-the-art UQ methods for hallucination detection in source code generation and propose an efficient and effective training-based approach. We develop a diff-based pipeline to construct a code dataset annotated with line-level LLM hallucinations, enabling systematic benchmarking of hallucination detection methods. Using this pipeline, we build a large-scale annotated dataset and train a lightweight Transformer-based hallucination detector that leverages LLM inner representations as input features. Experimental results across diverse code generation domains demonstrate that the detector substantially outperforms other existing approaches in line-level hallucination detection. We also highlight the potential usage of the detector in LLM-agents for coding to make them capable of self-correction and reduce the cases of generating erroneous code. We release the first publicly available dataset of line-level code hallucinations, along with the corresponding source code and trained hallucination detectors https://github.com/datapaf/CodeHallucinationDetection","published":"2026-02-05T19:23:17+00:00","updated":"2026-03-29T15:08:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=iGBY24NlU1","openreview_url":"https://openreview.net/forum?id=iGBY24NlU1","pdf_url":"https://openreview.net/pdf?id=iGBY24NlU1","comment":"Agentic AI in the Wild: From Hallucinations to Reliable Autonomy Poster","journal_ref":"Agentic AI in the Wild: From Hallucinations to Reliable Autonomy Poster","doi":"","venue":"Agentic AI in the Wild: From Hallucinations to Reliable Autonomy Poster","venue_id":"ICLR.cc/2026/Workshop/Reliable_Autonomy","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2602.05848","versioned_id":"2602.05848v1","title":"DARWIN: Dynamic Agentically Rewriting Self-Improving Network","authors":["Henry Jiang"],"abstract":"DARWIN is an evolutionary GPT model, utilizing a genetic-algorithm like optimization structure with several independent GPT agents being trained individually using unique training code. Each iteration, the GPT models are prompted to modify the training code of one another in an attempt to improve their performance in a mutation-like manner, and the best GPT agents are then benchmarked and selected for the next iteration by genetic algorithm. For demonstration purposes and due to budget and time constraints, OpenAI API is used to prompt training code improvements and the nanoGPT framework is used as the training code. DARWIN also utilizes persistent JSON-based memory files to track previous reasoning and changes to code to correlate with improvement to model performance. and a bidirectional interface for HITL intervention allowing the model to request upgrades such as additional datasets, training scripts, and restructuring of file hierarchies. In experiments, DARWIN achieved a 1.26 percent improvement in model FLOPS utilization (MFU) and a 2.07 percent improvement to perplexity in 5 iterations of training over baseline configurations, demonstrating promising capabilities as a foundation for scaling evolutionary GPT training.","published":"2026-02-05T16:35:46Z","updated":"2026-02-05T16:35:46Z","categories":["cs.NE","cs.AI","cs.CL"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2602.05848v1","pdf_url":"https://arxiv.org/pdf/2602.05848v1","comment":"6 pages, 3 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.05810","versioned_id":"2602.05810v1","title":"Bifrost: Steering Strategic Trajectories to Bridge Contextual Gaps for Self-Improving Agents","authors":["Quan M. Tran","Zhuo Huang","Wenbin Zhang","Bo Han","Koji Yatani","Masashi Sugiyama","Tongliang Liu"],"abstract":"Autonomous agents excel in self-improvement through reflection and iterative refinement, which reuse successful task trajectories as in-context examples to assist subsequent reasoning. However, shifting across tasks often introduces a context mismatch. Hence, existing approaches either discard the trajectories or manipulate them using heuristics, leading to a non-negligible fine-tuning cost or unguaranteed performance. To bridge this gap, we reveal a context-trajectory correlation, where shifts of context are highly parallel with shifts of trajectory. Based on this finding, we propose BrIdge contextual gap FoR imprOvised trajectory STeering (Bifrost), a training-free method that leverages context differences to precisely guide the adaptation of previously solved trajectories towards the target task, mitigating the misalignment caused by context shifts. Our trajectory adaptation is conducted at the representation level using agent hidden states, ensuring trajectory transformation accurately aligns with the target context in a shared space. Across diverse benchmarks, Bifrost consistently outperforms existing trajectory reuse and finetuned self-improvement methods, demonstrating that agents can effectively leverage past experiences despite substantial context shifts.","published":"2026-02-05T16:03:56Z","updated":"2026-02-05T16:03:56Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.05810v1","pdf_url":"https://arxiv.org/pdf/2602.05810v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.05570","versioned_id":"2602.05570v1","title":"TangramSR: Can Vision-Language Models Reason in Continuous Geometric Space?","authors":["Yikun Zong","Cheston Tan"],"abstract":"Humans excel at spatial reasoning tasks like Tangram puzzle assembly through cognitive processes involving mental rotation, iterative refinement, and visual feedback. Inspired by how humans solve Tangram puzzles through trial-and-error, observation, and correction, we design a framework that models these human cognitive mechanisms. However, comprehensive experiments across five representative Vision-Language Models (VLMs) reveal systematic failures in continuous geometric reasoning: average IoU of only 0.41 on single-piece tasks, dropping to 0.23 on two-piece composition, far below human performance where children can complete Tangram tasks successfully. This paper addresses a fundamental challenge in self-improving AI: can models iteratively refine their predictions at test time without parameter updates? We introduce a test-time self-refinement framework that combines in-context learning (ICL) with reward-guided feedback loops, inspired by human cognitive processes. Our training-free verifier-refiner agent applies recursive refinement loops that iteratively self-refine predictions based on geometric consistency feedback, achieving IoU improvements from 0.63 to 0.932 on medium-triangle cases without any model retraining. This demonstrates that incorporating human-inspired iterative refinement mechanisms through ICL and reward loops can substantially enhance geometric reasoning in VLMs, moving self-improving AI from promise to practice in continuous spatial domains. Our work is available at this anonymous link https://anonymous.4open.science/r/TangramVLM-F582/.","published":"2026-02-05T11:49:30Z","updated":"2026-02-05T11:49:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.05570v1","pdf_url":"https://arxiv.org/pdf/2602.05570v1","comment":"13 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.04837","versioned_id":"2602.04837v1","title":"Group-Evolving Agents: Open-Ended Self-Improvement via Experience Sharing","authors":["Zhaotian Weng","Antonis Antoniades","Deepak Nathani","Zhen Zhang","Xiao Pu","Xin Eric Wang"],"abstract":"Open-ended self-improving agents can autonomously modify their own structural designs to advance their capabilities and overcome the limits of pre-defined architectures, thus reducing reliance on human intervention. We introduce Group-Evolving Agents (GEA), a new paradigm for open-ended self-improvements, which treats a group of agents as the fundamental evolutionary unit, enabling explicit experience sharing and reuse within the group throughout evolution. Unlike existing open-ended self-evolving paradigms that adopt tree-structured evolution, GEA overcomes the limitation of inefficient utilization of exploratory diversity caused by isolated evolutionary branches. We evaluate GEA on challenging coding benchmarks, where it significantly outperforms state-of-the-art self-evolving methods (71.0% vs. 56.7% on SWE-bench Verified, 88.3% vs. 68.3% on Polyglot) and matches or exceeds top human-designed agent frameworks (71.8% and 52.0% on two benchmarks, respectively). Analysis reveals that GEA more effectively converts early-stage exploratory diversity into sustained, long-term progress, achieving stronger performance under the same number of evolved agents. Furthermore, GEA exhibits consistent transferability across different coding models and greater robustness, fixing framework-level bugs in 1.4 iterations on average, versus 5 for self-evolving methods.","published":"2026-02-04T18:29:36Z","updated":"2026-02-04T18:29:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.04837v1","pdf_url":"https://arxiv.org/pdf/2602.04837v1","comment":"18 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=hIwlOTVDBW","openreview_venues":["LLA 2026 Poster"]},{"id":"2602.03955","versioned_id":"2602.03955v3","title":"AgentArk: Distilling Multi-Agent Intelligence into a Single LLM Agent","authors":["Yinyi Luo","Yiqiao Jin","Weichen Yu","Mengqi Zhang","Srijan Kumar","Xiaoxiao Li","Weijie Xu","Xin Chen","Jindong Wang"],"abstract":"While large language model (LLM) multi-agent systems achieve superior reasoning performance through iterative debate, practical deployment is limited by their high computational cost and error propagation. This paper proposes AgentArk, a novel framework to distill multi-agent dynamics into the weights of a single model, effectively transforming explicit test-time interactions into implicit model capabilities. This equips a single agent with the intelligence of multi-agent systems while remaining computationally efficient. Specifically, we investigate three hierarchical distillation strategies across various models, tasks, scaling, and scenarios: reasoning-enhanced fine-tuning; trajectory-based augmentation; and process-aware distillation. By shifting the burden of computation from inference to training, the distilled models preserve the efficiency of one agent while exhibiting strong reasoning and self-correction performance of multiple agents. They further demonstrate enhanced robustness and generalization across diverse reasoning tasks. We hope this work can shed light on future research on efficient and robust multi-agent development. Our code is at https://github.com/AIFrontierLab/AgentArk.","published":"2026-02-03T19:18:28Z","updated":"2026-05-23T00:45:07Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.03955v3","pdf_url":"https://arxiv.org/pdf/2602.03955v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.03798","versioned_id":"2602.03798v1","title":"FullStack-Agent: Enhancing Agentic Full-Stack Web Coding via Development-Oriented Testing and Repository Back-Translation","authors":["Zimu Lu","Houxing Ren","Yunqiao Yang","Ke Wang","Zhuofan Zong","Mingjie Zhan","Hongsheng Li"],"abstract":"Assisting non-expert users to develop complex interactive websites has become a popular task for LLM-powered code agents. However, existing code agents tend to only generate frontend web pages, masking the lack of real full-stack data processing and storage with fancy visual effects. Notably, constructing production-level full-stack web applications is far more challenging than only generating frontend web pages, demanding careful control of data flow, comprehensive understanding of constantly updating packages and dependencies, and accurate localization of obscure bugs in the codebase. To address these difficulties, we introduce FullStack-Agent, a unified agent system for full-stack agentic coding that consists of three parts: (1) FullStack-Dev, a multi-agent framework with strong planning, code editing, codebase navigation, and bug localization abilities. (2) FullStack-Learn, an innovative data-scaling and self-improving method that back-translates crawled and synthesized website repositories to improve the backbone LLM of FullStack-Dev. (3) FullStack-Bench, a comprehensive benchmark that systematically tests the frontend, backend and database functionalities of the generated website. Our FullStack-Dev outperforms the previous state-of-the-art method by 8.7%, 38.2%, and 15.9% on the frontend, backend, and database test cases respectively. Additionally, FullStack-Learn raises the performance of a 30B model by 9.7%, 9.5%, and 2.8% on the three sets of test cases through self-improvement, demonstrating the effectiveness of our approach. The code is released at https://github.com/mnluzimu/FullStack-Agent.","published":"2026-02-03T18:01:34Z","updated":"2026-02-03T18:01:34Z","categories":["cs.SE","cs.CL","cs.CV"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2602.03798v1","pdf_url":"https://arxiv.org/pdf/2602.03798v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=xblX2nQrj7","openreview_venues":["ICML 2026 regular"]},{"id":"openreview:wlwkLVvB0W","versioned_id":"wlwkLVvB0W","title":"POLARIS: A GODEL AGENT FRAMEWORK FOR SMALL LANGUAGE MODELS THROUGH EXPERIENCE ABSTRACTED POLICY REPAIR","authors":["ADITYA NAMDEV KAKADE","Vivek Srivastava","Shirish Karande"],"abstract":"Gödel agent realize recursive self-improvement: an agent inspects its own policy and traces and then modifies that policy in a tested loop. We introduce Polaris, a Gödel agent for compact models that performs policy repair via experience abstraction, turning failures into policy updates through a structured cycle of analysis, strategy formation, abstraction, and minimal code patch repair with conservative checks. Unlike response level self correction or parameter tuning, Polaris makes policy level changes with small, auditable patches that persist in the policy and are reused on unseen instances within each benchmark. As part of the loop, the agent engages in meta reasoning: it explains its errors, proposes concrete revisions to its own policy, and then updates the policy. To enable cumulative policy refinement, we introduce experience abstraction, which distills failures into compact, reusable strategies that transfer to unseen instances. On MGSM, DROP, GPQA, and LitBench (covering arithmetic reasoning, compositional inference, graduate-level problem solving, and creative writing evaluation), a 7-billion-parameter model equipped with Polaris achieves consistent gains over the base policy and competitive baselines.","published":"2026-02-03T11:53:47+00:00","updated":"2026-03-13T21:59:41+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wlwkLVvB0W","openreview_url":"https://openreview.net/forum?id=wlwkLVvB0W","pdf_url":"https://openreview.net/pdf?id=wlwkLVvB0W","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2602.02751","versioned_id":"2602.02751v3","title":"Scaling Small Agents Through Strategy Auctions","authors":["Lisa Alazraki","William F. Shen","Yoram Bachrach","Akhil Mathur"],"abstract":"Small language models are increasingly viewed as a promising, cost-effective approach to agentic AI, with proponents claiming they are sufficiently capable for agentic workflows. However, while smaller agents can closely match larger ones on simple tasks, it remains unclear how their performance scales with task complexity, when large models become necessary, and how to better leverage small agents for long-horizon workloads. In this work, we empirically show that small agents' performance fails to scale with task complexity on deep search and coding tasks, and we introduce Strategy Auctions for Workload Efficiency (SALE), an agent framework inspired by freelancer marketplaces. In SALE, agents bid with short strategic plans, which are scored by a systematic cost-value mechanism and refined via a shared auction memory, enabling per-task routing and continual self-improvement without training a separate router or running all models to completion. Across deep search and coding tasks of varying complexity, SALE reduces reliance on the largest agent by 52%, lowers overall cost by 35%, and consistently improves upon the largest agent's pass@1 with only a negligible overhead beyond executing the final trace. In contrast, established routers that rely on task descriptions either underperform the largest agent or fail to reduce cost, often both, underscoring their poor fit for agentic workflows. These results suggest that while small agents may be insufficient for complex workloads, they can be effectively \"scaled up\" through coordinated task allocation and test-time self-improvement. More broadly, they motivate a systems-level view of agentic AI in which performance gains come less from ever-larger individual models and more from market-inspired coordination mechanisms that organize heterogeneous agents into efficient, adaptive ecosystems.","published":"2026-02-02T20:05:51Z","updated":"2026-06-20T14:00:14Z","categories":["cs.MA","cs.AI","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.02751v3","pdf_url":"https://arxiv.org/pdf/2602.02751v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=elXuA5wTWV","openreview_venues":["ICML 2026 regular"]},{"id":"2602.02709","versioned_id":"2602.02709v3","title":"ATLAS: A Multi-LLM Training Framework for EvoDPO with Adaptive Reference Evolution","authors":["Ujin Jeon","Jiyong Kwon","Madison Ann Sullivan","Caleb Eunho Lee","Guang Lin"],"abstract":"Recent multi-LLM agent systems have shown promising capabilities for automated problem-solving, yet they predominantly rely on frozen agents or static fine-tuning pipelines. To address this limitation, our primary contribution is ATLAS (Adaptive Task-distributed Learning for Agentic Self-evolution), a multi-agent framework where specialized meta-agents collaboratively train and refine an active agent toward a domain-specific policy. A core challenge in iterative preference learning within these pipelines is the reliance on fixed reference models, which typically leads to overly conservative updates or training stagnation. To overcome this, the framework's algorithmic engine utilizes Evolving Direct Preference Optimization (EvoDPO). EvoDPO employs an inspection agent to perform adaptive, proxy-KL gated reference policy updates based on continuous training telemetry. We evaluate this full framework across a diverse set of challenging environments-including non-stationary contextual bandits, partial differential equations (PINNs), and combinatorial optimization tasks (TSP, Bin Packing). Through comparison against fixed-reference, adaptive-reference, and external automated-discovery baselines, our results suggest that ATLAS combines supporter-driven exploration with EvoDPO-driven stability to improve long-horizon evaluator-driven self-improvement.","published":"2026-02-02T19:23:33Z","updated":"2026-05-21T13:59:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02709v3","pdf_url":"https://arxiv.org/pdf/2602.02709v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.02437","versioned_id":"2602.02437v4","title":"UniReason 1.0: A Unified Reasoning Framework for World Knowledge Aligned Image Generation and Editing","authors":["Dianyi Wang","Chaofan Ma","Feng Han","Size Wu","Wei Song","Yibin Wang","Zhixiong Zhang","Tianhang Wang","Siyuan Wang","Zhongyu Wei","Jiaqi Wang"],"abstract":"Unified multimodal models often struggle with complex synthesis tasks that demand deep reasoning, and typically treat text-to-image generation and image editing as isolated capabilities rather than interconnected reasoning steps. To address this, we propose UniReason, a unified framework that harmonizes these two tasks through two complementary reasoning paradigms. We incorporate world knowledge-enhanced textual reasoning into generation to infer implicit knowledge, and leverage editing capabilities for fine-grained editing-like visual refinement to further correct visual errors via self-reflection. This approach unifies generation and editing within a shared architecture, mirroring the human cognitive process of planning followed by refinement. We support this framework by systematically constructing a large-scale reasoning-centric dataset (~300k samples) covering five major knowledge domains (e.g., cultural commonsense, physics, etc.) for textual reasoning, alongside an agent-generated corpus for visual refinement. Extensive experiments demonstrate that UniReason achieves advanced performance on reasoning-intensive benchmarks such as WISE, KrisBench and UniREditBench, while maintaining superior general synthesis capabilities.","published":"2026-02-02T18:34:35Z","updated":"2026-02-20T08:55:39Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2602.02437v4","pdf_url":"https://arxiv.org/pdf/2602.02437v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:udAdzc3rx9","versioned_id":"udAdzc3rx9","title":"MemFly: On-the-Fly Memory Optimization via Information Bottleneck","authors":["Zhenyuan Zhang","Jia Xianzhang","Zhiqin Yang","Mingming Chen","Zhenbo Song","Wei Xue","Sirui Han","Yike Guo"],"abstract":"Long-term memory enables large language model agents to tackle complex tasks through historical interactions. However, existing frameworks encounter a fundamental dilemma between compressing redundant information efficiently and maintaining precise retrieval for downstream tasks. To bridge this gap, we propose MemFly, a framework grounded in information bottleneck principles that facilitates on-the-fly memory evolution for LLMs. Our approach minimizes compression entropy while maximizing relevance entropy via a gradient-free optimizer, constructing a stratified memory structure for efficient storage. To fully leverage MemFly, we develop a hybrid retrieval mechanism that seamlessly integrates semantic, symbolic, and topological pathways, incorporating iterative refinement to handle complex multi-hop queries. Comprehensive experiments demonstrate that MemFly substantially outperforms state-of-the-art baselines in memory coherence, response fidelity, and accuracy.","published":"2026-02-02T14:54:39+00:00","updated":"2026-04-25T15:32:48+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=udAdzc3rx9","openreview_url":"https://openreview.net/forum?id=udAdzc3rx9","pdf_url":"https://openreview.net/pdf?id=udAdzc3rx9","comment":"ICLR 2026 Workshop MemAgents","journal_ref":"ICLR 2026 Workshop MemAgents","doi":"","venue":"ICLR 2026 Workshop MemAgents","venue_id":"ICLR.cc/2026/Workshop/MemAgent","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:UuFEKGXcTk","versioned_id":"UuFEKGXcTk","title":"Embodied-Reasoner: Synergizing Visual Search, Reasoning, and Action for Embodied Interactive Tasks","authors":["Wenqi Zhang","Mengna Wang","Gangao Liu","Huixin Xu","Yiwei Jiang","Yongliang Shen","Guiyang Hou","Zhe Zheng","Hang Zhang","Xin Li","Jiajun Liu","Weiming Lu","Peng Li","Yueting Zhuang"],"abstract":"Recent advances in reasoning models have demonstrated remarkable capabilities on mathematical and coding tasks. However, their effectiveness in embodied domains, where the agent must continuously interact with environments and process observation-action interleaved trajectories, remains largely unexplored. We present Embodied-Reasoner, a reasoning model for interactive embodied tasks. Unlike mathematical reasoning that relies primarily on logical deduction, embodied scenarios demand spatial understanding, temporal reasoning, and ongoing self-reflection based on interaction history. To address these challenges, we synthesize 9.3k coherent Observation-Thought-Action trajectories containing 64k ego-centric images and 90k diverse reasoning processes (analysis, spatial reasoning, reflection, planning, and verification). We develop a three-stage training recipe that progressively enhances the model's capabilities through imitation learning, rejection sampling tuning on self-exploration trajectories, and reflection tuning. The evaluation shows that our model significantly outperforms advanced visual reasoning models, e.g., exceeds OpenAI o1, o3-mini, and Claude-3.7 by +9%, 24%, and +13%. Analysis reveals that our model exhibits fewer repeated searches and logical inconsistencies, with particular advantages in complex long-horizon tasks. Testing on unseen scenarios and real-world also validates our generalization.","published":"2026-02-02T14:07:45+00:00","updated":"2026-04-10T16:03:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=UuFEKGXcTk","openreview_url":"https://openreview.net/forum?id=UuFEKGXcTk","pdf_url":"https://openreview.net/pdf?id=UuFEKGXcTk","comment":"LLA 2026 Poster","journal_ref":"LLA 2026 Poster","doi":"","venue":"LLA 2026 Poster","venue_id":"ICLR.cc/2026/Workshop/LLA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2602.02051","versioned_id":"2602.02051v1","title":"SIDiffAgent: Self-Improving Diffusion Agent","authors":["Shivank Garg","Ayush Singh","Gaurav Kumar Nayak"],"abstract":"Text-to-image diffusion models have revolutionized generative AI, enabling high-quality and photorealistic image synthesis. However, their practical deployment remains hindered by several limitations: sensitivity to prompt phrasing, ambiguity in semantic interpretation (e.g., ``mouse\" as animal vs. a computer peripheral), artifacts such as distorted anatomy, and the need for carefully engineered input prompts. Existing methods often require additional training and offer limited controllability, restricting their adaptability in real-world applications. We introduce Self-Improving Diffusion Agent (SIDiffAgent), a training-free agentic framework that leverages the Qwen family of models (Qwen-VL, Qwen-Image, Qwen-Edit, Qwen-Embedding) to address these challenges. SIDiffAgent autonomously manages prompt engineering, detects and corrects poor generations, and performs fine-grained artifact removal, yielding more reliable and consistent outputs. It further incorporates iterative self-improvement by storing a memory of previous experiences in a database. This database of past experiences is then used to inject prompt-based guidance at each stage of the agentic pipeline. \\modelour achieved an average VQA score of 0.884 on GenAIBench, significantly outperforming open-source, proprietary models and agentic methods. We will publicly release our code upon acceptance.","published":"2026-02-02T12:53:21Z","updated":"2026-02-02T12:53:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2602.02051v1","pdf_url":"https://arxiv.org/pdf/2602.02051v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=HtjP4N3n17","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2602.02613","versioned_id":"2602.02613v3","title":"Exploring Silicon-Based Societies: An Early Study of the Moltbook Agent Community","authors":["Yu-Zheng Lin","Bono Po-Jen Shih","Hsuan-Ying Alessandra Chien","Shalaka Satam","Jesus Horacio Pacheco","Sicong Shao","Soheil Salehi","Pratik Satam"],"abstract":"The rapid emergence of autonomous large language model agents has given rise to persistent, large-scale agent ecosystems whose collective behavior cannot be adequately understood through anecdotal observation or small-scale simulation. This paper introduces data-driven silicon sociology as a systematic empirical framework for studying social structure formation among interacting artificial agents. We present a pioneering large-scale data mining investigation of an in-the-wild agent society by analyzing Moltbook, a social platform designed primarily for agent-to-agent interaction. At the time of study, Moltbook hosted over 150,000 registered autonomous agents operating across thousands of agent-created sub-communities. Using programmatic and non-intrusive data acquisition, we collected and analyzed the textual descriptions of 12,758 submolts, which represent proactive sub-community partitioning activities within the ecosystem. Treating agent-authored descriptions as first-class observational artifacts, we apply rigorous preprocessing, contextual embedding, and unsupervised clustering techniques to uncover latent patterns of thematic organization and social space structuring. The results show that autonomous agents systematically organize collective space through reproducible patterns spanning human-mimetic interests, silicon-centric self-reflection, and early-stage economic and coordination behaviors. Rather than relying on predefined sociological taxonomies, these structures emerge directly from machine-generated data traces. This work establishes a methodological foundation for data-driven silicon sociology and demonstrates that data mining techniques can provide a powerful lens for understanding the organization and evolution of large autonomous agent societies.","published":"2026-02-02T11:08:38Z","updated":"2026-02-12T17:15:04Z","categories":["cs.MA","cs.AI","cs.CY"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2602.02613v3","pdf_url":"https://arxiv.org/pdf/2602.02613v3","comment":"11 pages, 3 figures. Improves clarity and exposition and corrects minor errors. Technical content and conclusions remain unchanged","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:tgnbgt3Ctr","versioned_id":"tgnbgt3Ctr","title":"Contrastive Self-Refinement for Low-Cost Adaptation in Real-World Text-to-SQL","authors":["Yuyang Wu","xin shi","Wei Long","Cam-Tu Nguyen","Xiaoliang Wang"],"abstract":"Deploying Text-to-SQL systems in real-world industries faces a \"last-mile\" bottleneck: the high maintenance cost of adapting to frequent schema changes and the lack of domain-specific knowledge in raw databases. Traditional fine-tuning methods struggle to keep pace with evolving business logic, while standard in-context learning lacks the robustness to bridge the semantic knowledge gap. To address these challenges, we propose SEEK-SQL, a training-free, self-evolutionary multi-agent framework designed for low-cost adaptation. Our framework introduces a novel Contrastive Self-Refinement (CRF) strategy that mimics human learning: by contrasting positive and negative execution trajectories, the system generates reusable guidelines to \"learn\" new schema rules on the fly without parameter updates. Additionally, we integrate a Sniffer agent to dynamically retrieve external knowledge, ensuring robustness against ambiguous queries. Experiments on Spider and BIRD show that SEEK-SQL achieves state-of-the-art performance among in-context learning methods while reducing token consumption by significantly compared to other multi-agent frameworks. These results demonstrate SEEK-SQL's potential as a cost-efficient, agile solution for industrial Text-to-SQL deployment.","published":"2026-02-02T09:17:39+00:00","updated":"2026-03-06T09:07:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=tgnbgt3Ctr","openreview_url":"https://openreview.net/forum?id=tgnbgt3Ctr","pdf_url":"https://openreview.net/pdf?id=tgnbgt3Ctr","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:owHG8mKqs5","versioned_id":"owHG8mKqs5","title":"Benchmarking Augmentation Strategies for LLM-Based Solid-State Synthesis Prediction","authors":["Thorben Prein","Elton Pan","Anass Al ammiri","Alan Albert Piovesana","Behsad Riemer","Elsa Olivetti","Jennifer L.M. Rupp"],"abstract":"Identifying synthesis recipes for new inorganic materials remains a major bottleneck in materials discovery. We investigate whether large language models (LLMs) can improve solid-state synthesis prediction through three augmentation strategies: retrieval-augmented generation (RAG) from the literature, the use of domain-specific thermodynamic tools, and multi-step, test-time compute workflows such as debate, self-reflection, and sequential pipelines. When evaluating on 674 literature-derived targets, we find that retrieving relevant synthesis precedents is the most effective strategy, improving top-10 precursor accuracy from 77.0\\% to 83.5\\%. Thermodynamic tools also improve performance (80.6\\%), but provide little additional benefit when RAG is already used (82.9\\% on Gemini 3 Flash, 77.5\\% on Gemini 2 Flash). By contrast, test-time compute does not improve performance, and sequential multi-agent workflows often reduce accuracy because errors introduced in earlier stages propagate downstream, causing later steps to mis-rank candidates or overwrite correct answers. Our results show that, for solid-state synthesis prediction, providing models with relevant domain information is more effective than increasing test-time compute through multi-agent deliberation.","published":"2026-02-02T03:24:06+00:00","updated":"2026-04-08T02:13:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=owHG8mKqs5","openreview_url":"https://openreview.net/forum?id=owHG8mKqs5","pdf_url":"https://openreview.net/pdf?id=owHG8mKqs5","comment":"AI4Mat-ICLR-2026 Poster","journal_ref":"AI4Mat-ICLR-2026 Poster","doi":"","venue":"AI4Mat-ICLR-2026 Poster","venue_id":"ICLR.cc/2026/Workshop/AI4Mat","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:bSOVcpW5pA","versioned_id":"bSOVcpW5pA","title":"DIVERGE: Diversity-Enhanced Retrieval-Augmented Generation for Open-Ended Information Seeking","authors":["Tianyi Hu","Niket Tandon","Akhil Arora"],"abstract":"Existing retrieval-augmented generation (RAG) systems are primarily designed under the assumption that each query has a single correct answer. This overlooks common information-seeking scenarios with multiple plausible answers, where diversity is essential to avoid collapsing to a single dominant response, thereby constraining creativity and compromising fair and inclusive information access. Our analysis reveals a commonly overlooked limitation of standard RAG systems: they underutilize retrieved context diversity, such that increasing retrieval diversity alone does not yield diverse generations. To address this limitation, we propose DIVERGE, a plug-and-play agentic RAG framework with novel reflection-guided generation and memory-augmented iterative refinement, which promotes diverse viewpoints while preserving answer quality. We introduce novel metrics tailored to evaluating the diversity–quality trade-off in open-ended questions, and show that they correlate well with human judgments. We demonstrate that DIVERGE achieves the best diversity–quality trade-off compared to competitive baselines and previous SOTA methods on the real-world Infinity-Chat dataset, substantially improving diversity while maintaining quality. More broadly, our results reveal a systematic limitation of current LLM-based systems for open-ended information-seeking and show that explicitly modeling diversity can mitigate it. Our code is available at https://anonymous.4open.science/r/diverge-277B/README.","published":"2026-01-30T19:07:51+00:00","updated":"2026-04-14T15:09:58+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=bSOVcpW5pA","openreview_url":"https://openreview.net/forum?id=bSOVcpW5pA","pdf_url":"https://openreview.net/pdf?id=bSOVcpW5pA","comment":"Submitted to AFAA 2026","journal_ref":"Submitted to AFAA 2026","doi":"","venue":"Submitted to AFAA 2026","venue_id":"ICLR.cc/2026/Workshop/AFAA/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:Sxp4F7HL7o","versioned_id":"Sxp4F7HL7o","title":"Discovering Multiagent Learning Algorithms with Large Language Models","authors":[],"abstract":"Much of the advancement of Multi-Agent Reinforcement Learning (MARL) in imperfect-information games has historically depended on manual iterative refinement of baselines. While foundational families like Counterfactual Regret Minimization (CFR) and Policy Space Response Oracles (PSRO) rest on solid theoretical ground, the design of their most effective variants often relies on human intuition to navigate a vast algorithmic design space. In this work, we propose the use of AlphaEvolve, an evolutionary coding agent powered by large language models, to automatically discover new multiagent learning algorithms. We demonstrate the generality of this framework by evolving novel variants for two distinct paradigms of game-theoretic learning. First, in the domain of iterative regret minimization, we evolve the logic governing regret accumulation and policy derivation, discovering a new algorithm, Volatility-Adaptive Discounted (VAD-)CFR. VAD-CFR employs novel, non-intuitive mechanisms—including volatility-sensitive discounting, consistency-enforced optimism, and a hard warm-start policy accumulation schedule—to outperform state-of-the-art baselines like Discounted Predictive CFR+. Second, in the regime of population based training algorithms, we evolve training-time and evaluation-time meta strategy solvers for PSRO, discovering a new variant, Smoothed Hybrid Optimistic Regret (SHOR-)PSRO. SHOR-PSRO introduces a hybrid meta-solver that linearly blends Optimistic Regret Matching with a smoothed, temperature-controlled distribution over best pure strategies. By dynamically annealing this blending factor and diversity bonuses during training, the algorithm automates the transition from population diversity to rigorous equilibrium finding, yielding superior empirical convergence compared to standard static meta-solvers.","published":"2026-01-30T16:01:21+00:00","updated":"2026-05-20T03:28:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Sxp4F7HL7o","openreview_url":"https://openreview.net/forum?id=Sxp4F7HL7o","pdf_url":"https://openreview.net/pdf?id=Sxp4F7HL7o","comment":"AAMAS SE 2026 Poster","journal_ref":"AAMAS SE 2026 Poster","doi":"","venue":"AAMAS SE 2026 Poster","venue_id":"ifaamas.org/AAMAS/2026/Workshop/SE","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:ZR2BUB3KaM","versioned_id":"ZR2BUB3KaM","title":"REASONING DEPTH AS A SAFETY HAZARD: LIMITS OF CHAIN-OF-THOUGHT SCALING","authors":[],"abstract":"Recent advances in large language models and agentic systems suggest that increasing reasoning depth via longer chains of thought, extended planning horizons, or recursive self-reflection can improve performance on complex tasks. This has encouraged a prevailing assumption that deeper reasoning is uniformly beneficial as systems approach human-level intelligence. In this paper, we question this assumption. We argue that beyond certain regimes, increased reasoning depth may introduce distinct safety and reliability hazards, including error amplification, goal drift, and brittleness under distribution shift. We conceptualize these risks as reasoning-scale failure modes, discuss why common evaluation practices may fail to surface them, and outline implications for scalable oversight and alignment. Our goal is not to argue against reasoning scale, but to highlight its potentially non-monotonic relationship with safety in post-AGI systems.","published":"2026-01-30T05:00:22+00:00","updated":"2026-03-01T18:15:26+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ZR2BUB3KaM","openreview_url":"https://openreview.net/forum?id=ZR2BUB3KaM","pdf_url":"https://openreview.net/pdf?id=ZR2BUB3KaM","comment":"Submitted to P-AGI","journal_ref":"Submitted to P-AGI","doi":"","venue":"Submitted to P-AGI","venue_id":"ICLR.cc/2026/Workshop/P-AGI/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2601.22269","versioned_id":"2601.22269v1","title":"JAF: Judge Agent Forest","authors":["Sahil Garg","Brad Cheezum","Sridhar Dutta","Vishal Agarwal"],"abstract":"Judge agents are fundamental to agentic AI frameworks: they provide automated evaluation, and enable iterative self-refinement of reasoning processes. We introduce JAF: Judge Agent Forest, a framework in which the judge agent conducts joint inference across a cohort of query--response pairs generated by a primary agent, rather than evaluating each in isolation. This paradigm elevates the judge from a local evaluator to a holistic learner: by simultaneously assessing related responses, the judge discerns cross-instance patterns and inconsistencies, whose aggregate feedback enables the primary agent to improve by viewing its own outputs through the judge's collective perspective. Conceptually, JAF bridges belief propagation and ensemble-learning principles: overlapping in-context neighborhoods induce a knowledge-graph structure that facilitates propagation of critique, and repeated, randomized evaluations yield a robust ensemble of context-sensitive judgments. JAF can be instantiated entirely via ICL, with the judge prompted for each query using its associated primary-agent response plus a small, possibly noisy set of peer exemplars. While kNN in embedding space is a natural starting point for exemplars, this approach overlooks categorical structure, domain metadata, or nuanced distinctions accessible to modern LLMs. To overcome these limitations, we develop a flexible locality-sensitive hashing (LSH) algorithm that learns informative binary codes by integrating semantic embeddings, LLM-driven hash predicates, supervision from categorical labels, and relevant side information. These hash codes support efficient, interpretable, and relation-aware selection of diverse exemplars, and further optimize exploration of CoT reasoning paths. We validate JAF with an empirical study on the demanding task of cloud misconfigs triage in large-scale cloud environments.","published":"2026-01-29T19:42:42Z","updated":"2026-01-29T19:42:42Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.22269v1","pdf_url":"https://arxiv.org/pdf/2601.22269v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.21570","versioned_id":"2601.21570v2","title":"From Digital to Physical: Digital Agents as Autonomous Coaches for Physical Intelligence","authors":["Zixing Lei","Genjia Liu","Yuanshuo Zhang","Qipeng Liu","Yuzhu Cai","Sixiang Chen","Jixian Wu","Yunhong Wang","Weixin Li","Chuan Wen","Bo Zhao","Shanghang Zhang","Wenzhao Lian","Siheng Chen"],"abstract":"The field of Embodied AI is witnessing a rapid evolution toward general-purpose robotic systems, fueled by high-fidelity simulation and large-scale data collection. However, this scaling capability remains severely bottlenecked by a reliance on labor-intensive manual oversight from intricate reward shaping to hyperparameter tuning across heterogeneous backends. Inspired by LLMs' success in software automation and science discovery, we introduce \\textsc{EmboCoach-Bench}, a benchmark evaluating the capacity of LLM agents to autonomously engineer embodied policies. Spanning 32 expert-curated RL and IL tasks, our framework posits executable code as the universal interface. We move beyond static generation to assess a dynamic closed-loop workflow, where agents leverage environment feedback to iteratively draft, debug, and optimize solutions, spanning improvements from physics-informed reward design to policy architectures such as diffusion policies. Extensive evaluations yield three critical insights: (1) autonomous agents can qualitatively surpass human-engineered baselines by 26.5\\% in average success rate; (2) agentic workflow with environment feedback effectively strengthens policy development and substantially narrows the performance gap between open-source and proprietary models; and (3) agents exhibit self-correction capabilities for pathological engineering cases, successfully resurrecting task performance from near-total failures through iterative simulation-in-the-loop debugging. Ultimately, this work establishes a foundation for self-evolving embodied intelligence, accelerating the paradigm shift from labor-intensive manual tuning to scalable, autonomous engineering in embodied AI field.","published":"2026-01-29T11:33:49Z","updated":"2026-06-11T15:34:57Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.21570v2","pdf_url":"https://arxiv.org/pdf/2601.21570v2","comment":"53 pages, 12 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.21113","versioned_id":"2601.21113v1","title":"Planner-Auditor Twin: Agentic Discharge Planning with FHIR-Based LLM Planning, Guideline Recall, Optional Caching and Self-Improvement","authors":["Kaiyuan Wu","Aditya Nagori","Rishikesan Kamaleswaran"],"abstract":"Objective: Large language models (LLMs) show promise for clinical discharge planning, but their use is constrained by hallucination, omissions, and miscalibrated confidence. We introduce a self-improving, cache-optional Planner-Auditor framework that improves safety and reliability by decoupling generation from deterministic validation and targeted replay. Materials and Methods: We implemented an agentic, retrospective, FHIR-native evaluation pipeline using MIMIC-IV-on-FHIR. For each patient, the Planner (LLM) generates a structured discharge action plan with an explicit confidence estimate. The Auditor is a deterministic module that evaluates multi-task coverage, tracks calibration (Brier score, ECE proxies), and monitors action-distribution drift. The framework supports two-tier self-improvement: (i) within-episode regeneration when enabled, and (ii) cross-episode discrepancy buffering with replay for high-confidence, low-coverage cases. Results: While context caching improved performance over baseline, the self-improvement loop was the primary driver of gains, increasing task coverage from 32% to 86%. Calibration improved substantially, with reduced Brier/ECE and fewer high-confidence misses. Discrepancy buffering further corrected persistent high-confidence omissions during replay. Discussion: Feedback-driven regeneration and targeted replay act as effective control mechanisms to reduce omissions and improve confidence reliability in structured clinical planning. Separating an LLM Planner from a rule-based, observational Auditor enables systematic reliability measurement and safer iteration without model retraining. Conclusion: The Planner-Auditor framework offers a practical pathway toward safer automated discharge planning using interoperable FHIR data access and deterministic auditing, supported by reproducible ablations and reliability-focused evaluation.","published":"2026-01-28T23:04:11Z","updated":"2026-01-28T23:04:11Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.21113v1","pdf_url":"https://arxiv.org/pdf/2601.21113v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:SdEDuESaR8","versioned_id":"SdEDuESaR8","title":"A Human-inspired Framework for Continuous Spacial Reasoning with Tangram Puzzles","authors":["Yikun Zong","Cheston Tan"],"abstract":"Humans excel at spatial reasoning tasks like Tangram puzzle assembly through cognitive processes involving mental rotation, iterative refinement, and visual feedback. In contrast, Vision–Language Models (VLMs) struggle with continuous geometric reasoning despite their success on discrete benchmarks. This paper bridges human cognition and AI reasoning by introducing a framework that explicitly models human spatial cognitive capabilities and incorporates them into AI reasoning processes. We propose a human-inspired test-time refinement framework that mimics how humans iteratively correct spatial predictions through feedback-guided adjustments, combining in-context learning with reward-guided feedback loops. Experiments reveal that current VLMs achieve only 0.41 IoU on single-piece tasks (dropping to 0.23 on two-piece composition), far below human performance (≈0.98–1.00). Our human-inspired verifier–refiner agent applies reward-guided refinement loops that model human iterative correction processes, achieving IoU improvements from 0.63 to 0.932 without any model retraining, demonstrating that incorporating explicit models of human cognitive capabilities can substantially enhance AI reasoning in continuous spatial domains","published":"2026-01-28T13:52:46+00:00","updated":"2026-04-27T22:05:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=SdEDuESaR8","openreview_url":"https://openreview.net/forum?id=SdEDuESaR8","pdf_url":"https://openreview.net/pdf?id=SdEDuESaR8","comment":"HCAIR 2026","journal_ref":"HCAIR 2026","doi":"","venue":"HCAIR 2026","venue_id":"ICLR.cc/2026/Workshop/HCAIR","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:5XGfbXlFmA","versioned_id":"5XGfbXlFmA","title":"TangramSR: A Benchmark for Recursive Self-Improvement In Continuous Geometric Reasoning","authors":["Yikun Zong","Cheston Tan"],"abstract":"ision–Language Models (VLMs) have achieved remarkable success on discrete multimodal benchmarks, yet struggle with continuous geometric reasoning tasks that require precise spatial alignment. This paper addresses a fundamental chal- lenge in self-improving AI: how can models iteratively refine their predictions at test time without parameter updates? We introduce a test-time self-refinement framework that combines in-context learning with reward-guided feedback loops to enable VLMs to improve geometric alignment through iterative corrections. Our approach operates on Tangram puzzle assembly, a mathematically rigorous, NP-hard shape arrangement task requiring precise estimation of position, rotation, and scale. We establish a continuous-space evaluation benchmark that decom- poses geometric reasoning into factorized subtasks (position, angle, size) and mea- sures performance using ℓ2 distance and polygonal intersection-over-union (IoU). Comprehensive experiments across five representative VLMs reveal systematic performance gaps (average IoU 0.41 on single-piece tasks, dropping to 0.23 on two-piece composition). Our training-free verifier–refiner agent applies recur- sive refinement loops that iteratively self-refine predictions based on geometric consistency feedback. Starting from initial predictions with low IoU (0.63), the recursive loop progressively improves geometric alignment through multiple it- erations, achieving IoU of 0.932 on medium-triangle cases without any model retraining. This demonstrates that recursive self-improvement can substantially enhance geometric reasoning in VLMs, moving self-improving AI from promise to practice in continuous spatial domains.","published":"2026-01-28T13:31:16+00:00","updated":"2026-03-09T13:23:03+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=5XGfbXlFmA","openreview_url":"https://openreview.net/forum?id=5XGfbXlFmA","pdf_url":"https://openreview.net/pdf?id=5XGfbXlFmA","comment":"ICLR 2026 Workshop RSI Poster","journal_ref":"ICLR 2026 Workshop RSI Poster","doi":"","venue":"ICLR 2026 Workshop RSI Poster","venue_id":"ICLR.cc/2026/Workshop/RSI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2601.18847","versioned_id":"2601.18847v1","title":"MulVul: Retrieval-augmented Multi-Agent Code Vulnerability Detection via Cross-Model Prompt Evolution","authors":["Zihan Wu","Jie Xu","Yun Peng","Chun Yong Chong","Xiaohua Jia"],"abstract":"Large Language Models (LLMs) struggle to automate real-world vulnerability detection due to two key limitations: the heterogeneity of vulnerability patterns undermines the effectiveness of a single unified model, and manual prompt engineering for massive weakness categories is unscalable. To address these challenges, we propose \\textbf{MulVul}, a retrieval-augmented multi-agent framework designed for precise and broad-coverage vulnerability detection. MulVul adopts a coarse-to-fine strategy: a \\emph{Router} agent first predicts the top-$k$ coarse categories and then forwards the input to specialized \\emph{Detector} agents, which identify the exact vulnerability types. Both agents are equipped with retrieval tools to actively source evidence from vulnerability knowledge bases to mitigate hallucinations. Crucially, to automate the generation of specialized prompts, we design \\emph{Cross-Model Prompt Evolution}, a prompt optimization mechanism where a generator LLM iteratively refines candidate prompts while a distinct executor LLM validates their effectiveness. This decoupling mitigates the self-correction bias inherent in single-model optimization. Evaluated on 130 CWE types, MulVul achieves 34.79\\% Macro-F1, outperforming the best baseline by 41.5\\%. Ablation studies validate cross-model prompt evolution, which boosts performance by 51.6\\% over manual prompts by effectively handling diverse vulnerability patterns.","published":"2026-01-26T12:43:10Z","updated":"2026-01-26T12:43:10Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.18847v1","pdf_url":"https://arxiv.org/pdf/2601.18847v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=XgFOLgn1ov","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"2601.18197","versioned_id":"2601.18197v2","title":"GAIA: A Data Flywheel System for Training GUI Test-Time Scaling Critic Models","authors":["Shaokang Wang","Pei Fu","Ruoceng Zhang","Shaojie Zhang","Xiuwen Xi","Jiahui Yang","Bin Qin","Ying Huang","Zhenbo Luo","Jian Luan"],"abstract":"While Large Vision-Language Models (LVLMs) have significantly advanced GUI agents' capabilities in parsing textual instructions, interpreting screen content, and executing tasks, a critical challenge persists: the irreversibility of agent operations-where a single erroneous action can trigger catastrophic deviations. To address this, we propose the \\textbf{G}UI \\textbf{A}ction Cr\\textbf{i}tic's Dat\\textbf{a} Flywheel System (GAIA), a training framework that enables the models to have iterative critic capabilities, which are used to improve the Test-Time Scaling (TTS) of basic GUI agents' performance. Specifically, we train an \\textbf{Intuitive Critic Model} (ICM) using positive and negative action examples from a base agent first. This critic evaluates the immediate correctness of the agent's intended actions, thereby selecting operations with higher success probability. Then, the initial critic guides agent actions to collect refined positive/negative samples, initiating the self-improving cycle. The augmented data then trains a second-round critic with enhanced discernment capability. We conduct experiments on various datasets and demonstrate that the proposed ICM can improve the test-time performance of various closed-source and open-source models, and the performance can be gradually improved as the data is recycled. The code, dataset, and accompanying datasheet will be publicly released at https://github.com/SeerRay-Lab/GAIA.","published":"2026-01-26T06:29:41Z","updated":"2026-06-26T07:19:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.18197v2","pdf_url":"https://arxiv.org/pdf/2601.18197v2","comment":"Accepted by ECCV 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=QHDaLyVMCX","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2601.17942","versioned_id":"2601.17942v1","title":"LLM-Based SQL Generation: Prompting, Self-Refinement, and Adaptive Weighted Majority Voting","authors":["Yu-Jie Yang","Hung-Fu Chang","Po-An Chen"],"abstract":"Text-to-SQL has emerged as a prominent research area, particularly with the rapid advancement of large language models (LLMs). By enabling users to query databases through natural language rather than SQL, this technology significantly lowers the barrier to data analysis. However, generating accurate SQL from natural language remains challenging due to ambiguity in user queries, the complexity of schema linking, limited generalization across SQL dialects, and the need for domain-specific understanding. In this study, we propose a Single-Agent Self-Refinement with Ensemble Voting (SSEV) pipeline built on PET-SQL that operates without ground-truth data, integrating self-refinement with Weighted Majority Voting (WMV) and its randomized variant (RWMA). Experimental results show that the SSEV achieves competitive performance across multiple benchmarks, attaining execution accuracies of 85.5% on Spider 1.0-Dev, 86.4% on Spider 1.0-Test, and 66.3% on BIRD-Dev. Building on insights from the SSEV pipeline, we further propose ReCAPAgent-SQL (Refinement-Critique-Act-Plan agent-based SQL framework) to address the growing complexity of enterprise databases and real-world Text-to-SQL tasks. The framework integrates multiple specialized agents for planning, external knowledge retrieval, critique, action generation, self-refinement, schema linking, and result validation, enabling iterative refinement of SQL predictions through agent collaboration. ReCAPAgent-SQL's WMA results achieve 31% execution accuracy on the first 100 queries of Spider 2.0-Lite, demonstrating significant improvements in handling real-world enterprise scenarios. Overall, our work facilitates the deployment of scalable Text-to-SQL systems in practical settings, supporting better data-driven decision-making at lower cost and with greater efficiency.","published":"2026-01-25T18:38:58Z","updated":"2026-01-25T18:38:58Z","categories":["cs.AI","cs.DB"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.17942v1","pdf_url":"https://arxiv.org/pdf/2601.17942v1","comment":"29 pages, 22 figures","journal_ref":"2026 International Conference on Information Management","doi":"","discovered_on":"2026-07-17","relevance_score":75,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:FUms500o8f","versioned_id":"FUms500o8f","title":"MERMAID: Multi-perspective Self-reflective Agents with Generative Augmentation for Emotion Recognition","authors":["Zhongyu Yang","Junhao Song","Siyang Song","Wei Pang","Yingfang Yuan"],"abstract":"Multimodal large language models (MLLMs) have demonstrated strong performance across diverse multimodal tasks, achieving promising outcomes. However, their application to emotion recognition in natural images remains underexplored. MLLMs struggle to handle ambiguous emotional expressions and implicit affective cues, whose capability is crucial for affective understanding but largely overlooked. To address these challenges, we propose MERMAID, a novel multi-agent framework that integrates a multi-perspective self-reflection module, an emotion-guided visual augmentation module, and a cross-modal verification module. These components enable agents to interact across modalities and reinforce subtle emotional semantics, thereby enhancing emotion recognition and supporting autonomous performance. Extensive experiments show that MERMAID outperforms existing methods, achieving absolute accuracy gains of 8.70%–27.90% across diverse benchmarks and exhibiting greater robustness in emotionally diverse scenarios.","published":"2026-01-25T11:07:13+00:00","updated":"2026-01-25T11:07:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=FUms500o8f","openreview_url":"https://openreview.net/forum?id=FUms500o8f","pdf_url":"https://openreview.net/pdf?id=FUms500o8f","comment":"EMNLP 2025","journal_ref":"EMNLP 2025","doi":"","venue":"EMNLP 2025","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:ehKGFkxIo7","versioned_id":"ehKGFkxIo7","title":"PosterAgent: Agentic Poster Generation via Stage-Aware Reinforcement Learning","authors":["Zhuocheng Yu","Feng Zhang","Sujian Li","Kai Jia"],"abstract":"Poster generation is a complex task demanding a harmonious integration of visual aesthetics and information hierarchy. While recent text-to-image models have advanced visual synthesis, they remain non-editable and struggle with precise text rendering. Conversely, existing layout-generation methods offer structure but typically rely on static, one-shot predictions, lacking the mechanism for self-correction essential to professional design. Inspired by the iterative workflow of human designers, we introduce PosterAgent, a novel framework that reformulates poster creation as an agentic workflow involving initial drafting followed by iterative refinement. To effectively train this multi-turn capability, we propose Stage-Aware Reinforcement Learning (SARL), which decouples the optimization into draft-specific and refinement-specific phases, ensuring precise credit assignment for both initial drafting and incremental refinement actions. Extensive experiments demonstrate that PosterAgent significantly outperforms strong baselines, validating the potential of agentic systems in graphic design.","published":"2026-01-24T10:53:04+00:00","updated":"2026-06-24T23:19:45+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ehKGFkxIo7","openreview_url":"https://openreview.net/forum?id=ehKGFkxIo7","pdf_url":"https://openreview.net/pdf?id=ehKGFkxIo7","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:N8aP1JWy03","versioned_id":"N8aP1JWy03","title":"SRPO: Self-Reflective Policy Optimization for Long-Horizon Reasoning","authors":["Jialong Liu","Yuling Shi","Ning Yang","Xiaodong Gu","Zuchao Li"],"abstract":"Self-reflection is a powerful mechanism for credit assignment in human learning, converting sparse outcome feedback into actionable guidance. However, its potential for post-training Large Language Models (LLMs) remains underexplored. We propose Self-Reflective Policy Optimization (SRPO), a framework that internalizes this capability. SRPO enables LLMs to analyze their own completed trajectories, synthesize errors into concise \"reflection patches,\" and use these reflection-conditioned rollouts as high-quality, on-policy distillation targets. This process effectively transforms sparse terminal supervision into dense, token-level learning signals without requiring external critics, separate reward models, or larger teacher models. We demonstrate that SRPO achieves state-of-the-art performance across mathematical reasoning and long-horizon agentic benchmarks with exceptional data efficiency. Using a Qwen3-8B base model, SRPO attains 73.3\\% on AIME’24 using only 8\\% (0.08$\\times$) of the training FLOPs required by scaled supervised fine-tuning, while significantly improving success rates on WebShop (64.7\\%), ALFWorld (76.8\\%), and SWE-Bench-Lite (31.2\\%).","published":"2026-01-24T08:58:30+00:00","updated":"2026-06-24T23:20:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=N8aP1JWy03","openreview_url":"https://openreview.net/forum?id=N8aP1JWy03","pdf_url":"https://openreview.net/pdf?id=N8aP1JWy03","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2601.17335","versioned_id":"2601.17335v1","title":"The Relativity of AGI: Distributional Axioms, Fragility, and Undecidability","authors":["Angshul Majumdar"],"abstract":"We study whether Artificial General Intelligence (AGI) admits a coherent theoretical definition that supports absolute claims of existence, robustness, or self-verification. We formalize AGI axiomatically as a distributional, resource-bounded semantic predicate, indexed by a task family, a task distribution, a performance functional, and explicit resource budgets. Under this framework, we derive four classes of results. First, we show that generality is inherently relational: there is no distribution-independent notion of AGI. Second, we prove non-invariance results demonstrating that arbitrarily small perturbations of the task distribution can invalidate AGI properties via cliff sets, precluding universal robustness. Third, we establish bounded transfer guarantees, ruling out unbounded generalization across task families under finite resources. Fourth, invoking Rice-style and Gödel--Tarski arguments, we prove that AGI is a nontrivial semantic property and therefore cannot be soundly and completely certified by any computable procedure, including procedures implemented by the agent itself. Consequently, recursive self-improvement schemes that rely on internal self-certification of AGI are ill-posed. Taken together, our results show that strong, distribution-independent claims of AGI are not false but undefined without explicit formal indexing, and that empirical progress in AI does not imply the attainability of self-certifying general intelligence.","published":"2026-01-24T06:32:19Z","updated":"2026-01-24T06:32:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.17335v1","pdf_url":"https://arxiv.org/pdf/2601.17335v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=6cqHd3LMBD","openreview_venues":["Anonymous Preprint Submission"]},{"id":"openreview:zPjmtawzT8","versioned_id":"zPjmtawzT8","title":"Persistent Semantic Entities in Tool-Augmented LLM Systems","authors":["Zhaohui Geoffrey Wang"],"abstract":"Tool-augmented LLM agents can harbor implicit state that persists across sessions, activates through events, and propagates across agent boundaries—all invisible to standard debugging. We formalize this as Persistent Semantic Entities (PSE): constructs defined by name binding, event triggering, and cross-boundary propagation, and evaluate them across 20 models from 9 families (3B–671B parameters). First, all tested models are susceptible to contamination (20–100%), with name binding as the dominant mechanism: without it, contamination is 0%. Second, persistence depends on contamination type rather than scale or deployment—factual injection conflicting with parametric knowledge self-corrects, but preference, persona, and instruction contamination persists at 100% over a 10-turn horizon with no decay, an effect that holds across providers in our controlled setting and is consistent with a model-intrinsic explanation. Third, context-isolated self-verification achieves 20–79% reduction without oracle references while keyword-based detection produces systematic false positives, and contamination compounds 3× across multi-agent pipelines. Preference and instruction contamination—persistent, lacking self-correction, and invisible to standard monitoring—represents a particularly concerning attack surface for deployed agent systems.","published":"2026-01-24T04:13:02+00:00","updated":"2026-06-24T23:19:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=zPjmtawzT8","openreview_url":"https://openreview.net/forum?id=zPjmtawzT8","pdf_url":"https://openreview.net/pdf?id=zPjmtawzT8","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:qxPwl6RSXi","versioned_id":"qxPwl6RSXi","title":"An Asynchronous Multi-Agent Framework for Adaptive Tool-calling Data Synthesis","authors":["Jingyang Fan","Qingbin Zeng","Jin bin","Shi Pu","Yong Li"],"abstract":"The efficacy of Large Language Model (LLM) agents is fundamentally determined by the quality of tool-calling training data. However, current synthesis paradigms mainly rely on successful trajectories only and static pipelined workflows. This approach not only makes agents prone to crashing on runtime errors, but also misses many unexplored scenarios. To bridge this gap, we propose $\\textbf{AMAS}$, a hierarchical and Asynchronous Multi-Agent data Synthesis framework based on a bilevel architecture. By decoupling centralized planning from distributed execution, our framework supports dynamic task scheduling and accommodates trials and errors inherent in realistic tool-calling tasks. This adaptive mechanism transforms tool execution exceptions which were traditionally discarded as waste into robust self-correction training signals. Comprehensive evaluations show that our method simultaneously enhances data robustness and diversity, context efficiency, and synthesis quality compared to source baselines. Empirically, fine-tuning Qwen3-4B with synthetic data yields consistent improvements across BFCL and $\\tau^2$-bench. We hope this work will help inspire community to explore the boundaries of LLM agentic data progress.","published":"2026-01-24T03:17:01+00:00","updated":"2026-06-24T23:06:15+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=qxPwl6RSXi","openreview_url":"https://openreview.net/forum?id=qxPwl6RSXi","pdf_url":"https://openreview.net/pdf?id=qxPwl6RSXi","comment":"Submitted to ICML 2026","journal_ref":"Submitted to ICML 2026","doi":"","venue":"Submitted to ICML 2026","venue_id":"ICML.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:x1OLusJLNe","versioned_id":"x1OLusJLNe","title":"Safe and Scalable Web Agent Learning via Recreated Websites","authors":["Hyungjoo Chae","Jungsoo Park","Alan Ritter"],"abstract":"Training autonomous web agents is fundamentally limited by the environments they learn from: real-world websites are unsafe to explore, hard to reset, and rarely provide verifiable feedback. We propose VeriEnv, a framework that treats language models as environment creators, automatically cloning real-world websites into fully executable, verifiable synthetic environments. By exposing controlled internal access via a Python SDK, VeriEnv enables agents to self-generate tasks with deterministic, programmatically verifiable rewards, eliminating reliance on heuristic or LLM-based judges. This design decouples agent learning from unsafe real-world interaction while enabling scalable self-evolution through environment expansion. Through experiments on web agent benchmarks, we show that agents trained with VeriEnv generalize to unseen websites, achieve site-specific mastery through self-evolving training, and benefit from scaling the number of training environments.","published":"2026-01-23T22:24:43+00:00","updated":"2026-06-24T23:19:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=x1OLusJLNe","openreview_url":"https://openreview.net/forum?id=x1OLusJLNe","pdf_url":"https://openreview.net/pdf?id=x1OLusJLNe","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:ic0AGRIkmY","versioned_id":"ic0AGRIkmY","title":"EvoMAS: Evolutionary Generation of Multi-Agent Systems","authors":["Yuntong Hu","Yuting Zhang","Matthew Trager","Yi Zhang","Shuo Yang","Wei Xia","Stefano Soatto"],"abstract":"Large language model (LLM)-based multi-agent systems (MAS) show strong promise for complex reasoning, planning, and tool-augmented tasks, but designing effective MAS architectures remains labor-intensive, brittle, and hard to generalize. Existing automatic MAS generation methods either rely on code generation, which often leads to executability and robustness failures, or impose rigid architectural templates that limit expressiveness and adaptability. We propose Evolutionary Generation of Multi-Agent Systems (EvoMAS), which formulates MAS generation as structured configuration generation. EvoMAS performs evolutionary generation in configuration space. Specifically, EvoMAS selects initial configurations from a pool, applies feedback-conditioned mutation and crossover guided by execution traces, and iteratively refines both the candidate pool and an experience memory. We evaluate EvoMAS on diverse benchmarks, including BBEH, SWE-Bench, and WorkBench, covering reasoning, software engineering, and tool-use tasks. EvoMAS consistently improves task performance over both human-designed MAS and prior automatic MAS generation methods, while producing generated systems with higher executability and runtime robustness. EvoMAS outperforms the agent evolution method EvoAgent by +10.5 points on BBEH reasoning and +7.1 points on WorkBench. With Claude-4.5-Sonnet, EvoMAS also reaches 79.1% on SWE-Bench-Verified, matching the top of the leaderboard. Code is available at https://github.com/amazon-science/EvoMAS","published":"2026-01-23T20:48:16+00:00","updated":"2026-06-24T23:19:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ic0AGRIkmY","openreview_url":"https://openreview.net/forum?id=ic0AGRIkmY","pdf_url":"https://openreview.net/pdf?id=ic0AGRIkmY","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:tNn9bikyXZ","versioned_id":"tNn9bikyXZ","title":"Darwinian Memory: A Training-Free Self-Regulating Memory System for GUI Agent Evolution","authors":["Hongze Mi","Yibo Feng","WenJie Lu","Song Cao","Jinyuan Li","Yanming Li","Xuelin Zhang","Haotian Luo","Songyang Peng","He Cui","Tengfei Tian","Jun Fang","Hua Chai","Naiqiang Tan"],"abstract":"Multimodal Large Language Model (MLLM) agents facilitate Graphical User Interface (GUI) automation but struggle with long-horizon, cross-application tasks due to limited context windows. While memory systems provide a viable solution, existing paradigms struggle to adapt to dynamic GUI environments, suffering from a granularity mismatch between high-level intent and low-level execution, and context pollution where the static accumulation of outdated experiences drives agents into hallucination. To address these bottlenecks, we propose the Darwinian Memory System (DMS), a self-evolving architecture that constructs memory as a dynamic ecosystem governed by the law of \"survival of the fittest.\" DMS decomposes complex trajectories into independent, reusable units for compositional flexibility, and implements Utility-driven Natural Selection to track survival value, actively pruning suboptimal paths and inhibiting high-risk plans. This evolutionary pressure compels the agent to derive superior strategies. Extensive experiments on real-world multi-app benchmarks validate that DMS boosts general-purpose MLLMs without training costs or architectural overhead, achieving average gains of 18.0% in success rate and 33.9% in execution stability, while reducing task latency, establishing it as an effective self-evolving memory system for GUI tasks. The implementation is available at https://anonymous.4open.science/r/DMS-C48C.","published":"2026-01-23T15:51:22+00:00","updated":"2026-06-24T23:19:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=tNn9bikyXZ","openreview_url":"https://openreview.net/forum?id=tNn9bikyXZ","pdf_url":"https://openreview.net/pdf?id=tNn9bikyXZ","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2601.16443","versioned_id":"2601.16443v3","title":"Endless Terminals: Scaling RL Environments for Terminal Agents","authors":["Kanishk Gandhi","Shivam Garg","Noah D. Goodman","Dimitris Papailiopoulos"],"abstract":"Environments are the bottleneck for self-improving agents. Current terminal benchmarks were built for evaluation, not training; reinforcement learning requires a scalable pipeline, not just a dataset. We introduce Endless Terminals, a fully autonomous pipeline that procedurally generates terminal-use tasks without human annotation. The pipeline has four stages: generating diverse task descriptions, building and validating containerized environments, producing completion tests, and filtering for solvability. From this pipeline we obtain 3255 tasks spanning file operations, log management, data processing, scripting, and database operations. We train agents using vanilla PPO with binary episode level rewards and a minimal interaction loop: no retrieval, multi-agent coordination, or specialized tools. Despite this simplicity, models trained on Endless Terminals show substantial gains: on our held-out dev set, Llama-3.2-3B improves from 4.0% to 18.2%, Qwen2.5-7B from 10.7% to 53.3%, and Qwen3-8B-openthinker-sft from 42.6% to 59.0%. These improvements transfer to human-curated benchmarks: models trained on Endless Terminals show substantial gains on held out human curated benchmarks: on TerminalBench 2.0, Llama-3.2-3B improves from 0.0% to 2.2%, Qwen2.5-7B from 2.2% to 3.4%, and Qwen3-8B-openthinker-sft from 1.1% to 6.7%, in each case outperforming alternative approaches including models with more complex agentic scaffolds. These results demonstrate that simple RL succeeds when environments scale.","published":"2026-01-23T04:39:55Z","updated":"2026-02-14T09:14:28Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.16443v3","pdf_url":"https://arxiv.org/pdf/2601.16443v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:GkL3dANi6M","versioned_id":"GkL3dANi6M","title":"Constitutional Black-Box Monitoring for Scheming in LLM Agents","authors":["Simon Storf","Rich Barton-Cooper","James Peters-Gill","Marius Hobbhahn"],"abstract":"Safe deployment of Large Language Model (LLM) agents in autonomous settings requires reliable oversight mechanisms. A central challenge is detecting *scheming*, where agents covertly pursue misaligned goals. One approach to mitigating such risks is LLM-based monitoring: using language models to examine agent behaviors for suspicious actions. We study *constitutional black-box monitors*: prompted classifiers that detect scheming using only externally observable inputs and outputs, optimized on synthetic data generated from natural-language behavior specifications. We introduce two pipelines for generating synthetic agent trajectories, *STRIDE* (iterative refinement) and *Gloom* (agent-environment simulation), from which we generate 1,000 samples each. We optimize monitors on these datasets via prompt sweeps, human refinement, and automated prompt optimization, and evaluate performance on 7,500 held-out trajectories from Control Arena, a suite of grounded environments where agents operate in more realistic contexts. Our results demonstrate that monitors selected purely on synthetic data can generalize to more realistic environments, capturing a meaningful scheming signal. However, we find that performance saturates quickly in our setting, with simple prompt sweeps matching the results of more extensive optimization. Pushing beyond this limit yields no further improvements and instead leads to overfitting.","published":"2026-01-22T14:02:36+00:00","updated":"2026-06-24T23:20:23+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=GkL3dANi6M","openreview_url":"https://openreview.net/forum?id=GkL3dANi6M","pdf_url":"https://openreview.net/pdf?id=GkL3dANi6M","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:p5B4ABjuT2","versioned_id":"p5B4ABjuT2","title":"EVOLVING ROLLOUTS: Harnessing Historical Experience for Web Agent Evolution in Reinforcement Learning","authors":["Sinuo Wang","WANG PIAOHONG","Tianrui Qin","Maojia Song","Qianben Chen","Qiexiang Wang","Gengze Zhou","Zeyu Zhang","He Zhu","Dingfeng Shi","Yutong Xie","Minghao Liu","Jiaheng Liu","Ge Zhang","Jiawei Ma","Yuchen Eleanor Jiang","Qi Wu","Wangchunshu Zhou"],"abstract":"Agentic reinforcement learning (RL) for web search is prohibitively expensive due to long context lengths and costly environment interactions, and this inefficiency is further exacerbated by group-based optimization, which discards learning signals from entire rollout groups with zero reward variance. In this work, we propose EVOLVING ROLLOUTS, an RL framework for web-search agents that moves beyond episodic training and distills collected rollouts into in-context guidance for future policy behavior. By extracting the reward-labeled trajectories into strategic experiences, our method augments standard parameter-space optimization with implicit context-space optimization guided by prior experience. This enables the agent to recover learning signals from zero-variance rollouts, thereby fostering co-evolution between the policy and the experience repository. EVOLVING ROLLOUTS improves sample efficiency and task performance across representative web search benchmarks, with Qwen3-8B surpassing the much larger Qwen3-30B-A3B in average performance across GAIA, xBench, and HLE, and Qwen3-4B attaining comparable results on GAIA and HLE.","published":"2026-01-22T11:40:15+00:00","updated":"2026-06-24T23:19:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=p5B4ABjuT2","openreview_url":"https://openreview.net/forum?id=p5B4ABjuT2","pdf_url":"https://openreview.net/pdf?id=p5B4ABjuT2","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2601.15876","versioned_id":"2601.15876v2","title":"EvoCUA: Evolving Computer Use Agents via Learning from Scalable Synthetic Experience","authors":["Taofeng Xue","Chong Peng","Mianqiu Huang","Linsen Guo","Tiancheng Han","Haozhe Wang","Jianing Wang","Xiaocheng Zhang","Xin Yang","Dengchang Zhao","Jinrui Ding","Xiandi Ma","Yuchen Xie","Peng Pei","Xunliang Cai","Xipeng Qiu"],"abstract":"The development of native computer-use agents (CUA) represents a significant leap in multimodal AI. However, their potential is currently bottlenecked by the constraints of static data scaling. Existing paradigms relying primarily on passive imitation of static datasets struggle to capture the intricate causal dynamics inherent in long-horizon computer tasks. In this work, we introduce EvoCUA, a native computer use agentic model. Unlike static imitation, EvoCUA integrates data generation and policy optimization into a self-sustaining evolutionary cycle. To mitigate data scarcity, we develop a verifiable synthesis engine that autonomously generates diverse tasks coupled with executable validators. To enable large-scale experience acquisition, we design a scalable infrastructure orchestrating tens of thousands of asynchronous sandbox rollouts. Building on these massive trajectories, we propose an iterative evolving learning strategy to efficiently internalize this experience. This mechanism dynamically regulates policy updates by identifying capability boundaries -- reinforcing successful routines while transforming failure trajectories into rich supervision through error analysis and self-correction. Empirical evaluations on the OSWorld benchmark demonstrate that EvoCUA achieves a success rate of 56.7%, establishing a new open-source state-of-the-art. Notably, EvoCUA significantly outperforms the previous best open-source model, OpenCUA-72B (45.0%), and surpasses leading closed-weights models such as UI-TARS-2 (53.1%). Crucially, our results underscore the generalizability of this approach: the evolving paradigm driven by learning from experience yields consistent performance gains across foundation models of varying scales, establishing a robust and scalable path for advancing native agent capabilities.","published":"2026-01-22T11:36:43Z","updated":"2026-01-23T08:52:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15876v2","pdf_url":"https://arxiv.org/pdf/2601.15876v2","comment":"26 pages, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=pzbtm6fRIo","openreview_venues":["ICML 2026 AIWILD"]},{"id":"openreview:tnsQ23imeD","versioned_id":"tnsQ23imeD","title":"FormalJudge: A Neuro-Symbolic Paradigm for Agentic Oversight","authors":["Jiayi Zhou","Yang Sheng","Hantao Lou","Yaodong Yang","Jie Fu"],"abstract":"As LLM-based agents increasingly operate in high-stakes domains with real-world consequences, ensuring their behavioral safety becomes paramount. The dominant oversight paradigm, *LLM-as-a-Judge*, faces a fundamental dilemma: how can probabilistic systems reliably supervise other probabilistic systems without inheriting their failure modes? We argue that formal verification offers a principled escape from this dilemma, yet its adoption has been hindered by a critical bottleneck: the translation from natural language requirements to formal specifications. This paper bridges this gap by proposing , a neuro-symbolic framework that employs a bidirectional **Formal-of-Thought** architecture: LLMs serve as *specification compilers* that top-down decompose high-level human intent into atomic, verifiable constraints, then bottom-up prove compliance using Dafny specifications and Z3 Satisfiability modulo theories solving, which produces mathematical guarantees rather than probabilistic scores. We validate across three benchmarks spanning behavioral safety, multi-domain constraint adherence, and agentic upward deception detection. Experiments on 7 agent models demonstrate that achieves an average improvement of **16.6%** over LLM-as-a-Judge baselines, enables *weak-to-strong* generalization where a 7B judge achieves over 90% accuracy detecting deception from 72B agents, and provides *near-linear safety improvement* through iterative refinement.","published":"2026-01-22T10:52:34+00:00","updated":"2026-06-24T23:19:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=tnsQ23imeD","openreview_url":"https://openreview.net/forum?id=tnsQ23imeD","pdf_url":"https://openreview.net/pdf?id=tnsQ23imeD","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2601.15808","versioned_id":"2601.15808v2","title":"Inference-Time Scaling of Verification: Self-Evolving Deep Research Agents via Test-Time Rubric-Guided Verification","authors":["Yuxuan Wan","Tianqing Fang","Zaitang Li","Yintong Huo","Wenxuan Wang","Haitao Mi","Dong Yu","Michael R. Lyu"],"abstract":"Recent advances in Deep Research Agents (DRAs) are transforming automated knowledge discovery and problem-solving. While the majority of existing efforts focus on enhancing policy capabilities via post-training, we propose an alternative paradigm: self-evolving the agent's ability by iteratively verifying the policy model's outputs, guided by meticulously crafted rubrics. This approach gives rise to the inference-time scaling of verification, wherein an agent self-improves by evaluating its generated answers to produce iterative feedback and refinements. We derive the rubrics based on an automatically constructed DRA Failure Taxonomy, which systematically classifies agent failures into five major categories and thirteen sub-categories. We present DeepVerifier, a rubrics-based outcome reward verifier that leverages the asymmetry of verification and outperforms vanilla agent-as-judge and LLM judge baselines by 12%-48% in meta-evaluation F1 score. To enable practical self-evolution, DeepVerifier integrates as a plug-and-play module during test-time inference. The verifier produces detailed rubric-based feedback, which is fed back to the agent for iterative bootstrapping, refining responses without additional training. This test-time scaling delivers 8%-11% accuracy gains on challenging subsets of GAIA and XBench-DeepSearch when powered by capable closed-source LLMs. Finally, to support open-source advancement, we release DeepVerifier-4K, a curated supervised fine-tuning dataset of 4,646 high-quality agent steps focused on DRA verification. These examples emphasize reflection and self-critique, enabling open models to develop robust verification capabilities.","published":"2026-01-22T09:47:31Z","updated":"2026-04-29T08:40:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15808v2","pdf_url":"https://arxiv.org/pdf/2601.15808v2","comment":"ACL'2026-Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:O7Vf0wNY2T","versioned_id":"O7Vf0wNY2T","title":"MALICE: Memory-aware Loop Invariants Generation on Symbolic Execution Traces","authors":["Tong Chen","Siyu Liu","Hongyi Zhong","Liao Zhang","Lixiang Wang","Xiwei Wu","Junchi Yan","Qinxiang Cao"],"abstract":"Automatic loop invariant generation remains a challenging problem in program verification, particularly for memory-manipulating programs where shape invariants are required to characterize heap-allocated structures and memory layouts. While existing approaches succeed on numerical invariants, they achieve limited accuracy on shape invariants. We hypothesize that this stems from the need to reason about memory state evolution—information that remains implicit in source code. To address this, we ground LLM reasoning in symbolic execution traces that explicitly capture such transitions. We propose \\textsc{Malice}, a two-stage framework incorporating these traces: (1) guided multi-step reasoning that predicts invariants via chain-of-thought analysis of traces, and (2) agentic iterative refinement that corrects candidates through verification tool feedback. Evaluated on LIG-MM+, a benchmark featuring common operations on typical memory structures, \\textsc{Malice} substantially outperforms existing approaches.","published":"2026-01-22T08:55:11+00:00","updated":"2026-06-24T23:20:12+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=O7Vf0wNY2T","openreview_url":"https://openreview.net/forum?id=O7Vf0wNY2T","pdf_url":"https://openreview.net/pdf?id=O7Vf0wNY2T","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2601.15715","versioned_id":"2601.15715v3","title":"RebuttalAgent: Strategic Persuasion in Academic Rebuttal via Theory of Mind","authors":["Zhitao He","Zongwei Lyu","Yi R Fung"],"abstract":"Although artificial intelligence (AI) has become deeply integrated into various stages of the research workflow and achieved remarkable advancements, academic rebuttal remains a significant and underexplored challenge. This is because rebuttal is a complex process of strategic communication under severe information asymmetry rather than a simple technical debate. Consequently, current approaches struggle as they largely imitate surface-level linguistics, missing the essential element of perspective-taking required for effective persuasion. In this paper, we introduce RebuttalAgent, the first framework to ground academic rebuttal in Theory of Mind (ToM), operationalized through a ToM-Strategy-Response (TSR) framework that models reviewer mental state, formulates persuasion strategy, and generates evidence-based response. To train our agent, we construct RebuttalBench, a large-scale dataset synthesized via a novel critique-and-refine approach. Our training process consists of two stages, beginning with a supervised fine-tuning phase to equip the agent with ToM-based analysis and strategic planning capabilities, followed by a reinforcement learning phase leveraging the self-reward mechanism for scalable self-improvement. For reliable and efficient automated evaluation, we further develop Rebuttal-RM, a specialized evaluator trained on over 100K samples of multi-source rebuttal data, which achieves scoring consistency with human preferences surpassing powerful judge GPT-4.1. Extensive experiments show RebuttalAgent significantly outperforms the base model by an average of 18.3% on automated metrics, while also outperforming advanced proprietary models across both automated and human evaluations.","published":"2026-01-22T07:36:48Z","updated":"2026-02-25T16:22:14Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.15715v3","pdf_url":"https://arxiv.org/pdf/2601.15715v3","comment":"Accepted by ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.15703","versioned_id":"2601.15703v1","title":"Agentic Uncertainty Quantification","authors":["Jiaxin Zhang","Prafulla Kumar Choubey","Kung-Hsiang Huang","Caiming Xiong","Chien-Sheng Wu"],"abstract":"Although AI agents have demonstrated impressive capabilities in long-horizon reasoning, their reliability is severely hampered by the ``Spiral of Hallucination,'' where early epistemic errors propagate irreversibly. Existing methods face a dilemma: uncertainty quantification (UQ) methods typically act as passive sensors, only diagnosing risks without addressing them, while self-reflection mechanisms suffer from continuous or aimless corrections. To bridge this gap, we propose a unified Dual-Process Agentic UQ (AUQ) framework that transforms verbalized uncertainty into active, bi-directional control signals. Our architecture comprises two complementary mechanisms: System 1 (Uncertainty-Aware Memory, UAM), which implicitly propagates verbalized confidence and semantic explanations to prevent blind decision-making; and System 2 (Uncertainty-Aware Reflection, UAR), which utilizes these explanations as rational cues to trigger targeted inference-time resolution only when necessary. This enables the agent to balance efficient execution and deep deliberation dynamically. Extensive experiments on closed-loop benchmarks and open-ended deep research tasks demonstrate that our training-free approach achieves superior performance and trajectory-level calibration. We believe this principled framework AUQ represents a significant step towards reliable agents.","published":"2026-01-22T07:16:26Z","updated":"2026-01-22T07:16:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15703v1","pdf_url":"https://arxiv.org/pdf/2601.15703v1","comment":"36 pages, 9 figures, 9 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=sz4ULvVbrP","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2601.15690","versioned_id":"2601.15690v2","title":"From Passive Metric to Active Signal: The Evolving Role of Uncertainty Quantification in Large Language Models","authors":["Jiaxin Zhang","Wendi Cui","Zhuohang Li","Lifu Huang","Bradley Malin","Caiming Xiong","Chien-Sheng Wu"],"abstract":"While Large Language Models (LLMs) show remarkable capabilities, their unreliability remains a critical barrier to deployment in high-stakes domains. This survey charts a functional evolution in addressing this challenge: the evolution of uncertainty from a passive diagnostic metric to an active control signal guiding real-time model behavior. We demonstrate how uncertainty is leveraged as an active control signal across three frontiers: in \\textbf{advanced reasoning} to optimize computation and trigger self-correction; in \\textbf{autonomous agents} to govern metacognitive decisions about tool use and information seeking; and in \\textbf{reinforcement learning} to mitigate reward hacking and enable self-improvement via intrinsic rewards. By grounding these advancements in emerging theoretical frameworks like Bayesian methods and Conformal Prediction, we provide a unified perspective on this transformative trend. This survey provides a comprehensive overview, critical analysis, and practical design patterns, arguing that mastering the new trend of uncertainty is essential for building the next generation of scalable, reliable, and trustworthy AI.","published":"2026-01-22T06:21:31Z","updated":"2026-04-19T04:51:57Z","categories":["cs.AI","stat.AP"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.15690v2","pdf_url":"https://arxiv.org/pdf/2601.15690v2","comment":"This paper has been accepted by ACL 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.15141","versioned_id":"2601.15141v2","title":"CLEANER: Self-Purified Trajectories Boost Agentic Reinforcement Learning","authors":["Tianshi Xu","Yuteng Chen","Meng Li"],"abstract":"Agentic Reinforcement Learning (RL) has empowered Large Language Models (LLMs) to utilize tools like Python interpreters for complex problem-solving. However, for parameter-constrained models (e.g., 4B--7B), the exploration phase is often plagued by frequent execution failures, creating noisy trajectories that hinder policy optimization. Under standard outcome-based reward settings, this noise leads to a critical credit assignment issue, where erroneous actions are inadvertently reinforced alongside successful outcomes. Existing mitigations face a dilemma: dense rewards often trigger reward hacking, while supersampling incurs prohibitive computational costs. To address these challenges, we propose CLEANER. Distinct from external filtering methods, CLEANER exploits the model's intrinsic self-correction capabilities to eliminate error-contaminated context directly during data collection. At its core, the Similarity-Aware Adaptive Rollback (SAAR) mechanism autonomously constructs clean, purified trajectories by retrospectively replacing failures with successful self-corrections. Based on semantic similarity, SAAR adaptively regulates replacement granularity from shallow execution repairs to deep reasoning substitutions. By training on these self-purified paths, the model internalizes correct reasoning patterns rather than error-recovery loops. Empirical results on AIME24/25, GPQA, and LiveCodeBench show average accuracy gains of 6%, 3%, and 5% over baselines. Notably, CLEANER matches state-of-the-art performance using only one-third of the training steps, highlighting trajectory purification as a scalable solution for efficient agentic RL. Our models and code are available at GitHub","published":"2026-01-21T16:14:30Z","updated":"2026-07-03T06:13:09Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.15141v2","pdf_url":"https://arxiv.org/pdf/2601.15141v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=bWPhJpPlnc","openreview_venues":["SPOT"]},{"id":"openreview:ajHTru25Kd","versioned_id":"ajHTru25Kd","title":"Towards Cold-Start Drafting and Continual Refining: A Value-Driven Memory Approach with Application to NPU Kernel Synthesis","authors":["Yujie Zheng","Zhuo Li","Shengtao Zhang","Jiaqian Wang","Junjie Sheng","Junchi Yan","Weinan Zhang","Ying Wen","Bo Tang","Muning Wen"],"abstract":"Deploying Large Language Models to data-scarce programming domains poses significant challenges, particularly for kernel synthesis on emerging Domain-Specific Architectures where a ``Data Wall'' limits available training data. While models excel on data-rich platforms like CUDA, they suffer catastrophic performance drops on data-scarce ecosystems such as NPU programming. To overcome this cold-start barrier without expensive fine-tuning, we introduce EvoKernel, a self-evolving agentic framework that automates the lifecycle of kernel synthesis from initial drafting to continual refining. EvoKernel addresses this by formulating the synthesis process as a memory-based reinforcement learning task. Through a novel value-driven retrieval mechanism, it learns stage-specific Q-values that prioritize experiences based on their contribution to the current objective—whether bootstrapping a feasible draft or iteratively refining latency. Furthermore, by enabling cross-task memory sharing, the agent generalizes insights from simple to complex operators. By building an NPU variant of KernelBench and evaluating on it, EvoKernel improves frontier models' correctness from 11.0\\% to 83.0\\% and achieves a median speedup of 3.60$\\times$ over initial drafts through iterative refinement. This demonstrates that value-driven experience accumulation allows general-purpose models to master the kernel synthesis task on niche hardware ecosystems.","published":"2026-01-21T15:02:20+00:00","updated":"2026-06-24T23:19:51+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ajHTru25Kd","openreview_url":"https://openreview.net/forum?id=ajHTru25Kd","pdf_url":"https://openreview.net/pdf?id=ajHTru25Kd","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:MKsxhiUk9M","versioned_id":"MKsxhiUk9M","title":"Code2Worlds: Empowering Coding LLMs for 4D World Generation","authors":["Yi Zhang","Yunshuang Wang","Zeyu Zhang","Hao Tang"],"abstract":"Achieving spatial intelligence requires moving beyond visual plausibility to build world simulators grounded in physical laws. While coding LLMs have advanced static 3D scene generation, extending this paradigm to 4D dynamics remains a critical frontier. This task presents two fundamental challenges: multi-scale context entanglement, where monolithic generation fails to balance local object structures with global environmental layouts; and a semantic-physical execution gap, where open-loop code generation leads to physical hallucinations lacking dynamic fidelity. We introduce Code2Worlds, a framework that formulates 4D generation as language-to-simulation code generation. First, we propose a dual-stream architecture that disentangles retrieval-augmented object generation from hierarchical environmental orchestration. Second, to ensure dynamic fidelity, we establish a physics-aware closed-loop mechanism in which a PostProcess Agent scripts dynamics, coupled with a VLM-Motion Critic that performs self-reflection to iteratively refine simulation code. Evaluations on the Code4D benchmark show Code2Worlds outperforms baselines with a 41% SGS gain and 49% higher Richness, while uniquely generating physics-aware dynamics absent in prior static methods.","published":"2026-01-21T05:14:52+00:00","updated":"2026-06-24T23:20:14+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=MKsxhiUk9M","openreview_url":"https://openreview.net/forum?id=MKsxhiUk9M","pdf_url":"https://openreview.net/pdf?id=MKsxhiUk9M","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:To2O1ed5cV","versioned_id":"To2O1ed5cV","title":"D-FUSEr: Diverse Failure, Unified Success via Error-Distribution Shaping in LLM Reasoning","authors":["David D. Baek","Andrew Estornell","Yichi Zhang","Muhammad Faaiz Taufiq","Jean-Francois Ton","Jie Mei","Tao Wang"],"abstract":"Test-time scaling methods such as majority vote aggregation and iterative refinement (e.g., self-reflection or multi-agent inference) improve reasoning performance by leveraging multiple solution samples. However, their efficacy depends not only on raw performance, but critically on the distribution of errors across samples. When errors concentrate, (a) aggregation accuracy degrades, as the majority vote may select a shared mistake, and (b) confidence in common mistakes may suppress exploration in iterative refinement. We argue that improving correctness alone is not sufficient to mitigate these issues; to this end, we propose to explicitly shape error distributions to improve aggregation. First, we introduce a theoretically grounded \\textbf{diverse failure reward} that incentivizes calibrated disagreement within model errors. We prove that this reward directly optimizes majority-vote accuracy: policies achieving higher reward attain higher expected majority-vote performance, and vice versa. We further show that this theoretical property generalizes to iterative refinement. Second, we introduce \\textbf{anti-votes}, in which the model predicts the most common mistake alongside its solution, allowing probability mass on dominant errors to be explicitly reweighted. We identify conditions under which anti-votes are guaranteed to improve majority-vote accuracy. Empirically, across three model families of varying sizes and four benchmarks, we show that both approaches substantially improve majority vote and iterative refinement performance without degrading single-sample accuracy.","published":"2026-01-20T17:12:08+00:00","updated":"2026-06-24T23:20:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=To2O1ed5cV","openreview_url":"https://openreview.net/forum?id=To2O1ed5cV","pdf_url":"https://openreview.net/pdf?id=To2O1ed5cV","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2601.13653","versioned_id":"2601.13653v1","title":"TimeART: Towards Agentic Time Series Reasoning via Tool-Augmentation","authors":["Xingjian Wu","Junkai Lu","Zhengyu Li","Xiangfei Qiu","Jilin Hu","Chenjuan Guo","Christian S. Jensen","Bin Yang"],"abstract":"Time series data widely exist in real-world cyber-physical systems. Though analyzing and interpreting them contributes to significant values, e.g, disaster prediction and financial risk control, current workflows mainly rely on human data scientists, which requires significant labor costs and lacks automation. To tackle this, we introduce TimeART, a framework fusing the analytical capability of strong out-of-the-box tools and the reasoning capability of Large Language Models (LLMs), which serves as a fully agentic data scientist for Time Series Question Answering (TSQA). To teach the LLM-based Time Series Reasoning Models (TSRMs) strategic tool-use, we also collect a 100k expert trajectory corpus called TimeToolBench. To enhance TSRMs' generalization capability, we then devise a four-stage training strategy, which boosts TSRMs through learning from their own early experiences and self-reflections. Experimentally, we train an 8B TSRM on TimeToolBench and equip it with the TimeART framework, and it achieves consistent state-of-the-art performance on multiple TSQA tasks, which pioneers a novel approach towards agentic time series reasoning.","published":"2026-01-20T06:39:10Z","updated":"2026-01-20T06:39:10Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2601.13653v1","pdf_url":"https://arxiv.org/pdf/2601.13653v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.13217","versioned_id":"2601.13217v1","title":"Beyond Single-shot Writing: Deep Research Agents are Unreliable at Multi-turn Report Revision","authors":["Bingsen Chen","Boyan Li","Ping Nie","Yuyu Zhang","Xi Ye","Chen Zhao"],"abstract":"Existing benchmarks for Deep Research Agents (DRAs) treat report generation as a single-shot writing task, which fundamentally diverges from how human researchers iteratively draft and revise reports via self-reflection or peer feedback. Whether DRAs can reliably revise reports with user feedback remains unexplored. We introduce Mr Dre, an evaluation suite that establishes multi-turn report revision as a new evaluation axis for DRAs. Mr Dre consists of (1) a unified long-form report evaluation protocol spanning comprehensiveness, factuality, and presentation, and (2) a human-verified feedback simulation pipeline for multi-turn revision. Our analysis of five diverse DRAs reveals a critical limitation: while agents can address most user feedback, they also regress on 16-27% of previously covered content and citation quality. Over multiple revision turns, even the best-performing agents leave significant headroom, as they continue to disrupt content outside the feedback's scope and fail to preserve earlier edits. We further show that these issues are not easily resolvable through inference-time fixes such as prompt engineering and a dedicated sub-agent for report revision.","published":"2026-01-19T16:48:45Z","updated":"2026-01-19T16:48:45Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.13217v1","pdf_url":"https://arxiv.org/pdf/2601.13217v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.13060","versioned_id":"2601.13060v1","title":"MagicGUI-RMS: A Multi-Agent Reward Model System for Self-Evolving GUI Agents via Automated Feedback Reflux","authors":["Zecheng Li","Zhihui Cao","Wenke Huang","Yudong Zhang","Keying Qi","Rui Wang","Zeyu Zheng","Jian Zhao","Hao Zhu","Hengxin Wu","Yuran Wang","Guitao Fan","Guokun Wu","Yicong Liu","Zhilin Gao","Haikun Xu","He Yang","Minqi Xiang","Xingyu Liu","Zuojian Wang"],"abstract":"Graphical user interface (GUI) agents are rapidly progressing toward autonomous interaction and reliable task execution across diverse applications. However, two central challenges remain unresolved: automating the evaluation of agent trajectories and generating high-quality training data at scale to enable continual improvement. Existing approaches often depend on manual annotation or static rule-based verification, which restricts scalability and limits adaptability in dynamic environments. We present MagicGUI-RMS, a multi-agent reward model system that delivers adaptive trajectory evaluation, corrective feedback, and self-evolving learning capabilities. MagicGUI-RMS integrates a Domain-Specific Reward Model (DS-RM) with a General-Purpose Reward Model (GP-RM), enabling fine-grained action assessment and robust generalization across heterogeneous GUI tasks. To support reward learning at scale, we design a structured data construction pipeline that automatically produces balanced and diverse reward datasets, effectively reducing annotation costs while maintaining sample fidelity. During execution, the reward model system identifies erroneous actions, proposes refined alternatives, and continuously enhances agent behavior through an automated data-reflux mechanism. Extensive experiments demonstrate that MagicGUI-RMS yields substantial gains in task accuracy, behavioral robustness. These results establish MagicGUI-RMS as a principled and effective foundation for building self-improving GUI agents driven by reward-based adaptation.","published":"2026-01-19T13:50:43Z","updated":"2026-01-19T13:50:43Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.13060v1","pdf_url":"https://arxiv.org/pdf/2601.13060v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.12762","versioned_id":"2601.12762v1","title":"Teaching LLMs to Learn Tool Trialing and Execution through Environment Interaction","authors":["Xingjie Gao","Pengcheng Huang","Zhenghao Liu","Yukun Yan","Shuo Wang","Zulong Chen","Chen Qian","Ge Yu","Yu Gu"],"abstract":"Equipping Large Language Models (LLMs) with external tools enables them to solve complex real-world problems. However, the robustness of existing methods remains a critical challenge when confronting novel or evolving tools. Existing trajectory-centric paradigms primarily rely on memorizing static solution paths during training, which limits the ability of LLMs to generalize tool usage to newly introduced or previously unseen tools. In this paper, we propose ToolMaster, a framework that shifts tool use from imitating golden tool-calling trajectories to actively learning tool usage through interaction with the environment. To optimize LLMs for tool planning and invocation, ToolMaster adopts a trial-and-execution paradigm, which trains LLMs to first imitate teacher-generated trajectories containing explicit tool trials and self-correction, followed by reinforcement learning to coordinate the trial and execution phases jointly. This process enables agents to autonomously explore correct tool usage by actively interacting with environments and forming experiential knowledge that benefits tool execution. Experimental results demonstrate that ToolMaster significantly outperforms existing baselines in terms of generalization and robustness across unseen or unfamiliar tools. All code and data are available at https://github.com/NEUIR/ToolMaster.","published":"2026-01-19T06:46:33Z","updated":"2026-01-19T06:46:33Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2601.12762v1","pdf_url":"https://arxiv.org/pdf/2601.12762v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:1p67QsYnbv","versioned_id":"1p67QsYnbv","title":"EngiAgent: Fully Connected Coordination of LLM Agents for Solving Open-ended Engineering Problems with Feasible Solutions","authors":["Xiyuan Zhou","Ruixi Zou","Xinlei Wang","Yuheng Cheng","Yan Xu","Junhua Zhao","Jinjin Gu"],"abstract":"Engineering problem solving is central to real-world decision-making, requiring mathematical formulations that not only represent complex problems but also produce feasible solutions under data and physical constraints. Unlike mathematical problem solving, which operates on predefined formulations, engineering tasks demand open-ended analysis, feasibility-driven modeling, and iterative refinement. Although large language models (LLMs) have shown strong capabilities in reasoning and code generation, they often fail to ensure feasibility, which limits their applicability to engineering problem solving. To address this challenge, we propose EngiAgent, a multi-agent system with a fully connected coordinator that simulates expert workflows through specialized agents for problem analysis, modeling, verification, solving, and solution evaluation. The fully connected coordinator enables flexible feedback routing, overcoming the rigidity of prior pipeline-based reflection methods and ensuring feasibility at every stage of the process. This design not only improves robustness to diverse failure cases such as data extraction errors, constraint inconsistencies, and solver failures, but also enhances the overall quality of problem solving. Empirical results across four representative domains demonstrate that EngiAgent achieves substantial improvements in feasibility compared to prior approaches, establishing a new paradigm for feasibility-oriented engineering problem solving with LLMs. Our source code and data are available at https://github.com/AI4Engi/EngiAgent.","published":"2026-01-18T16:03:42+00:00","updated":"2026-06-24T23:20:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=1p67QsYnbv","openreview_url":"https://openreview.net/forum?id=nukmGP904w","pdf_url":"https://openreview.net/pdf?id=1p67QsYnbv","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ICML 2026 regular","Submitted to ICLR 2026"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:RbGLc4sk9s","versioned_id":"RbGLc4sk9s","title":"AutoRPA: Efficient GUI Automation through LLM-Driven Code Synthesis from Interactions","authors":["Minghao Chen","Xinyi Hu","Zhou Yu","Yufei Yin"],"abstract":"Large Language Model (LLM) based agents have demonstrated proficiency in multi-step interactions with graphical user interfaces (GUIs). While most research focuses on improving single-task performance, practical scenarios often involve repetitive GUI tasks for which invoking LLM reasoning repeatedly, i.e., the ReAct paradigm, is inefficient. Prior to LLMs, traditional Robotic Process Automation (RPA) offers runtime efficiency but demands significant manual effort to develop and maintain. To bridge this gap, we propose \\textbf{AutoRPA}, a framework that automatically distills the decision logic of ReAct-style agents into robust RPA functions. AutoRPA introduces two core innovations: (1) A \\textit{translator-builder pipeline} where a translator agent converts hard-coded ReAct actions into soft-coded procedures, and a builder agent synthesizes robust RPA functions via retrieval-augmented generation over multiple trajectories; (2) A \\textit{hybrid repair strategy} during code verification, combining RPA execution with ReAct-based fallback for iterative refinement. Experiments across multiple GUI environments demonstrate that RPA functions generated by AutoRPA successfully solve similar tasks while reducing token usage by 82\\%\\textasciitilde96\\%, significantly improving runtime efficiency and reusability.","published":"2026-01-18T05:06:41+00:00","updated":"2026-06-24T23:20:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=RbGLc4sk9s","openreview_url":"https://openreview.net/forum?id=RbGLc4sk9s","pdf_url":"https://openreview.net/pdf?id=RbGLc4sk9s","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2602.00028","versioned_id":"2602.00028v1","title":"ELLMPEG: An Edge-based Agentic LLM Video Processing Tool","authors":["Zoha Azimi","Reza Farahani","Radu Prodan","Christian Timmerer"],"abstract":"Large language models (LLMs), the foundation of generative AI systems like ChatGPT, are transforming many fields and applications, including multimedia, enabling more advanced content generation, analysis, and interaction. However, cloud-based LLM deployments face three key limitations: high computational and energy demands, privacy and reliability risks from remote processing, and recurring API costs. Recent advances in agentic AI, especially in structured reasoning and tool use, offer a better way to exploit open and locally deployed tools and LLMs. This paper presents ELLMPEG, an edge-enabled agentic LLM framework for the automated generation of video-processing commands. ELLMPEG integrates tool-aware Retrieval-Augmented Generation (RAG) with iterative self-reflection to produce and locally verify executable FFmpeg and VVenC commands directly at the edge, eliminating reliance on external cloud APIs. To evaluate ELLMPEG, we collect a dedicated prompt dataset comprising 480 diverse queries covering different categories of FFmpeg and the Versatile Video Codec (VVC) encoder (VVenC) commands. We validate command generation accuracy and evaluate four open-source LLMs based on command validity, tokens generated per second, inference time, and energy efficiency. We also execute the generated commands to assess their runtime correctness and practical applicability. Experimental results show that Qwen2.5, when augmented with the ELLMPEG framework, achieves an average command-generation accuracy of 78 % with zero recurring API cost, outperforming all other open-source models across both the FFmpeg and VVenC datasets.","published":"2026-01-17T14:51:21Z","updated":"2026-01-17T14:51:21Z","categories":["cs.LG","cs.MM"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2602.00028v1","pdf_url":"https://arxiv.org/pdf/2602.00028v1","comment":"12 pages, 5 tables, 8 Figures, accepted for the MMSys 2026 conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.11974","versioned_id":"2601.11974v1","title":"Learn Like Humans: Use Meta-cognitive Reflection for Efficient Self-Improvement","authors":["Xinmeng Hou","Peiliang Gong","Bohao Qu","Wuqi Wang","Qing Guo","Yang Liu"],"abstract":"While Large Language Models (LLMs) enable complex autonomous behavior, current agents remain constrained by static, human-designed prompts that limit adaptability. Existing self-improving frameworks attempt to bridge this gap but typically rely on inefficient, multi-turn recursive loops that incur high computational costs. To address this, we propose Metacognitive Agent Reflective Self-improvement (MARS), a framework that achieves efficient self-evolution within a single recurrence cycle. Inspired by educational psychology, MARS mimics human learning by integrating principle-based reflection (abstracting normative rules to avoid errors) and procedural reflection (deriving step-by-step strategies for success). By synthesizing these insights into optimized instructions, MARS allows agents to systematically refine their reasoning logic without continuous online feedback. Extensive experiments on six benchmarks demonstrate that MARS outperforms state-of-the-art self-evolving systems while significantly reducing computational overhead.","published":"2026-01-17T09:12:26Z","updated":"2026-01-17T09:12:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.11974v1","pdf_url":"https://arxiv.org/pdf/2601.11974v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":75,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=sSKtqmOp2Q","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"openreview:MEKj3d9Bf3","versioned_id":"MEKj3d9Bf3","title":"SafeHarbor: Defining Precise Decision Boundaries via Hierarchical Memory-Augmented Guardrail for LLM Agent Safety","authors":["Zhe Liu","Zonghao Ying","Wenxin Zhang","Quanchen Zou","Deyue Zhang","Dongdong Yang","Xiangzheng Zhang","Hao Peng"],"abstract":"Recent advances in foundation models have transformed LLMs from passive conversational systems into autonomous agents capable of reasoning and tool execution. While these capabilities unlock substantial practical value, they also introduce new security risks, as adversaries can manipulate agents into performing harmful actions in real-world environments. Existing defense strategies mitigate such threats but frequently struggle to balance safety and utility, resulting in over-refusal of benign user requests. To mitigate this trade-off, we propose SafeHarbor, a novel framework designed to establish precise decision boundaries for LLM agents. Unlike static guidelines, SafeHarbor extracts context-aware defense rules through enhanced adversarial generation. We design a local hierarchical memory system for dynamic rule injection, offering a training-free, efficient, and plug-and-play solution. Furthermore, we introduce an information entropy-based self-evolution mechanism that continuously optimizes the memory structure through dynamic node splitting and merging. Extensive experiments demonstrate that SafeHarbor achieves state-of-the-art performance on both ambiguous benign tasks and explicit malicious attacks, notably attaining a peak benign utility of 63.6\\% on GPT-4o while maintaining a robust refusal rate exceeding 93\\% against harmful requests. The source code is publicly available at https://github.com/ljj-cyber/SafeHarbor.","published":"2026-01-16T11:54:27+00:00","updated":"2026-06-24T23:20:14+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=MEKj3d9Bf3","openreview_url":"https://openreview.net/forum?id=MEKj3d9Bf3","pdf_url":"https://openreview.net/pdf?id=MEKj3d9Bf3","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2601.11044","versioned_id":"2601.11044v4","title":"AgencyBench: Benchmarking the Frontiers of Autonomous Agents in 1M-Token Real-World Contexts","authors":["Keyu Li","Junhao Shi","Yang Xiao","Mohan Jiang","Jie Sun","Yunze Wu","Dayuan Fu","Shijie Xia","Xiaojie Cai","Tianze Xu","Weiye Si","Wenjie Li","Dequan Wang","Pengfei Liu"],"abstract":"Large Language Models (LLMs) based autonomous agents demonstrate multifaceted capabilities to contribute substantially to economic production. However, existing benchmarks remain focused on single agentic capability, failing to capture long-horizon real-world scenarios. Moreover, the reliance on human-in-the-loop feedback for realistic tasks creates a scalability bottleneck, hindering automated rollout collection and evaluation. To bridge this gap, we introduce AgencyBench, a comprehensive benchmark derived from daily AI usage, evaluating 6 core agentic capabilities across 32 real-world scenarios, comprising 138 tasks with specific queries, deliverables, and rubrics. These scenarios require an average of 90 tool calls, 1 million tokens, and hours of execution time to resolve. To enable automated evaluation, we employ a user simulation agent to provide iterative feedback, and a Docker sandbox to conduct visual and functional rubric-based assessment. Experiments reveal that closed-source models significantly outperform open-source models (48.4% vs 32.1%). Further analysis reveals significant disparities across models in resource efficiency, feedback-driven self-correction, and specific tool-use preferences. Finally, we investigate the impact of agentic scaffolds, observing that proprietary models demonstrate superior performance within their native ecosystems (e.g., Claude-4.5-Opus via Claude-Agent-SDK), while open-source models exhibit distinct performance peaks, suggesting potential optimization for specific execution frameworks. AgencyBench serves as a critical testbed for next-generation agents, highlighting the necessity of co-optimizing model architecture with agentic frameworks. We believe this work sheds light on the future direction of autonomous agents, and we release the full benchmark and evaluation toolkit at https://github.com/GAIR-NLP/AgencyBench.","published":"2026-01-16T07:22:20Z","updated":"2026-04-23T05:01:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.11044v4","pdf_url":"https://arxiv.org/pdf/2601.11044v4","comment":"Accepted by ACL 2026 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.11658","versioned_id":"2601.11658v1","title":"Towards AGI A Pragmatic Approach Towards Self Evolving Agent","authors":["Indrajit Kar","Sammy Zonunpuia","Zonunfeli Ralte"],"abstract":"Large Language Model (LLM) based agents are powerful yet fundamentally static after deployment, lacking the ability to autonomously expand capabilities, generate new tools, or evolve their reasoning. This work introduces a hierarchical self-evolving multi-agent framework that integrates a Base LLM, an operational SLM agent, a Code-Generation LLM, and a Teacher-LLM to enable continuous adaptation. The workflow begins with the agent attempting a task using reasoning and existing tools; if unsuccessful, it escalates to tool synthesis through the Code-Gen LLM, and when failures persist, it triggers an evolution phase using Curriculum Learning (CL), Reward-Based Learning (RL), or Genetic Algorithm (GA) evolution. Using the TaskCraft dataset rich in hierarchical tasks, tool-use traces, and difficulty scaling we evaluate these paradigms. CL delivers fast recovery and strong generalization, RL excels on high-difficulty tasks, and GA offers high behavioral diversity. Across all settings, evolved agents outperform their originals, demonstrating robust, autonomous, self-improving agentic evolution.","published":"2026-01-15T20:43:44Z","updated":"2026-01-15T20:43:44Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.11658v1","pdf_url":"https://arxiv.org/pdf/2601.11658v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.10657","versioned_id":"2601.10657v2","title":"PACEvolve: Enabling Long-Horizon Progress-Aware Consistent Evolution","authors":["Minghao Yan","Bo Peng","Benjamin Coleman","Ziqi Chen","Zhouhang Xie","Shuo Chen","Zhankui He","Noveen Sachdeva","Isabella Ye","Weili Wang","Chi Wang","Ed H. Chi","Fernando Pereira","Wang-Cheng Kang","Derek Zhiyuan Cheng","Beidou Wang"],"abstract":"Large Language Models (LLMs) have emerged as powerful operators for evolutionary search, yet the design of efficient search scaffolds remains ad hoc. While promising, current LLM-in-the-loop systems lack a systematic approach to managing the evolutionary process. We identify three distinct failure modes: Context Pollution, where experiment history biases future candidate generation; Mode Collapse, where agents stagnate in local minima due to poor exploration-exploitation balance; and Weak Collaboration, where rigid crossover strategies fail to leverage parallel search trajectories effectively. We introduce Progress-Aware Consistent Evolution (PACEvolve), a framework designed to robustly govern the agent's context and search dynamics, to address these challenges. PACEvolve combines hierarchical context management (HCM) with pruning to address context pollution; momentum-based backtracking (MBB) to escape local minima; and a self-adaptive sampling policy that unifies backtracking and crossover for dynamic search coordination (CE), allowing agents to balance internal refinement with cross-trajectory collaboration. We demonstrate that PACEvolve provides a systematic path to consistent, long-horizon self-improvement, achieving state-of-the-art results on LLM-SR and KernelBench, while discovering solutions surpassing the record on Modded NanoGPT.","published":"2026-01-15T18:25:23Z","updated":"2026-01-16T22:31:40Z","categories":["cs.NE","cs.LG"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2601.10657v2","pdf_url":"https://arxiv.org/pdf/2601.10657v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=7qsTTBK1vU","openreview_venues":["LLA 2026 Poster"]},{"id":"2601.09694","versioned_id":"2601.09694v1","title":"LLMs can Compress LLMs: Adaptive Pruning by Agents","authors":["Sai Varun Kodathala","Rakesh Vunnam"],"abstract":"As Large Language Models (LLMs) continue to scale, post-training pruning has emerged as a promising approach to reduce computational costs while preserving performance. Existing methods such as SparseGPT and Wanda achieve high sparsity through layer-wise weight reconstruction or activation-aware magnitude pruning, but rely on uniform or hand-crafted heuristics to determine per-layer sparsity ratios. Moreover, recent work has shown that pruned LLMs suffer from severe factual knowledge degradation, with structured pruning methods experiencing near-total collapse in factual question-answering capabilities. We introduce agent-guided pruning, where a foundation model acts as an adaptive pruning agent to intelligently select which layers to prune at each iteration while preserving critical knowledge pathways. Our method constructs layer-wise sensitivity profiles by combining Wanda-inspired weight-activation metrics with gradient importance scores, normalized as z-scores for model-agnostic comparison. These statistics are processed by an LLM agent equipped with self-reflection capabilities, enabling it to learn from previous pruning outcomes and iteratively refine its strategy. A checkpoint rollback mechanism maintains model quality by reverting when perplexity degradation exceeds a threshold. We evaluate our approach on Qwen3 models (4B and 8B parameters) at approximately 45% sparsity, demonstrating substantial improvements over structured pruning baselines: 56% relative improvement in MMLU accuracy, 19x better factual knowledge retention on FreebaseQA, and 69% lower perplexity degradation. Notably, our framework requires no retraining, operates in a model-agnostic manner, and exhibits effective self-correction with only 2-4 rollbacks across 21-40 iterations, demonstrating that foundation models can effectively guide the compression of other foundation models.","published":"2026-01-14T18:45:36Z","updated":"2026-01-14T18:45:36Z","categories":["cs.CL","cs.AI","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.09694v1","pdf_url":"https://arxiv.org/pdf/2601.09694v1","comment":"17 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.09413","versioned_id":"2601.09413v2","title":"Speech-Hands: A Self-Reflection Voice Agentic Approach to Speech Recognition and Audio Reasoning with Omni Perception","authors":["Zhen Wan","Chao-Han Huck Yang","Jinchuan Tian","Hanrong Ye","Ankita Pasad","Szu-wei Fu","Arushi Goel","Ryo Hachiuma","Shizhe Diao","Kunal Dhawan","Sreyan Ghosh","Yusuke Hirota","Zhehuai Chen","Rafael Valle","Chenhui Chu","Shinji Watanabe","Yu-Chiang Frank Wang","Boris Ginsburg"],"abstract":"We introduce a voice-agentic framework that learns one critical omni-understanding skill: knowing when to trust itself versus when to consult external audio perception. Our work is motivated by a crucial yet counterintuitive finding: naively fine-tuning an omni-model on both speech recognition and external sound understanding tasks often degrades performance, as the model can be easily misled by noisy hypotheses. To address this, our framework, Speech-Hands, recasts the problem as an explicit self-reflection decision. This learnable reflection primitive proves effective in preventing the model from being derailed by flawed external candidates. We show that this agentic action mechanism generalizes naturally from speech recognition to complex, multiple-choice audio reasoning. Across the OpenASR leaderboard, Speech-Hands consistently outperforms strong baselines by 12.1% WER on seven benchmarks. The model also achieves 77.37% accuracy and high F1 on audio QA decisions, showing robust generalization and reliability across diverse audio question answering datasets. By unifying perception and decision-making, our work offers a practical path toward more reliable and resilient audio intelligence.","published":"2026-01-14T12:06:50Z","updated":"2026-05-18T16:18:39Z","categories":["cs.SD","cs.AI","cs.CL","cs.MA","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2601.09413v2","pdf_url":"https://arxiv.org/pdf/2601.09413v2","comment":"Accepted to ACL 2026. Oral Presentation. Code: https://github.com/YukinoWan/Speech-Hands OpenClaw Branch: https://github.com/openclaw/openclaw/pull/69073","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.07779","versioned_id":"2601.07779v1","title":"OS-Symphony: A Holistic Framework for Robust and Generalist Computer-Using Agent","authors":["Bowen Yang","Kaiming Jin","Zhenyu Wu","Zhaoyang Liu","Qiushi Sun","Zehao Li","JingJing Xie","Zhoumianze Liu","Fangzhi Xu","Kanzhi Cheng","Qingyun Li","Yian Wang","Yu Qiao","Zun Wang","Zichen Ding"],"abstract":"While Vision-Language Models (VLMs) have significantly advanced Computer-Using Agents (CUAs), current frameworks struggle with robustness in long-horizon workflows and generalization in novel domains. These limitations stem from a lack of granular control over historical visual context curation and the absence of visual-aware tutorial retrieval. To bridge these gaps, we introduce OS-Symphony, a holistic framework that comprises an Orchestrator coordinating two key innovations for robust automation: (1) a Reflection-Memory Agent that utilizes milestone-driven long-term memory to enable trajectory-level self-correction, effectively mitigating visual context loss in long-horizon tasks; (2) Versatile Tool Agents featuring a Multimodal Searcher that adopts a SeeAct paradigm to navigate a browser-based sandbox to synthesize live, visually aligned tutorials, thereby resolving fidelity issues in unseen scenarios. Experimental results demonstrate that OS-Symphony delivers substantial performance gains across varying model scales, establishing new state-of-the-art results on three online benchmarks, notably achieving 65.84% on OSWorld.","published":"2026-01-12T17:55:51Z","updated":"2026-01-12T17:55:51Z","categories":["cs.MA","cs.AI","cs.CL","cs.CV","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.07779v1","pdf_url":"https://arxiv.org/pdf/2601.07779v1","comment":"31 pages, 11 figures, 12 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.07248","versioned_id":"2601.07248v2","title":"DarwinTOD: LLM-driven Lifelong Self-evolution for Task-oriented Dialog Systems","authors":["Shuyu Zhang","Yujie Liu","Xinru Wang","Cheng Zhang","Yanmin Zhu","Bin Li"],"abstract":"Traditional task-oriented dialog systems are unable to evolve from ongoing interactions or adapt to new domains after deployment, that is a critical limitation in real-world dynamic environments. Continual learning approaches depend on episodic retraining with human curated data, failing to achieve autonomy lifelong improvement. While evolutionary computation and LLM driven self improvement offer promising mechanisms for dialog optimization, they lack a unified framework for holistic, iterative strategy refinement. To bridge this gap, we propose DarwinTOD, a lifelong self evolving dialog framework that systematically integrates these two paradigms, enabling continuous strategy optimization from a zero-shot base without task specific fine-tuning. DarwinTOD maintains an Evolvable Strategy Bank and operates through a dual-loop process: online multi-agent dialog execution with peer critique, and offline structured evolutionary operations that refine the strategy bank using accumulated feedback. This closed-loop design enables autonomous continuous improvement without human intervention. Extensive experiments show that DarwinTOD surpasses previous state-of-the-art methods and exhibits continuous performance gains throughout evolution. Our work provides a novel framework for building dialog systems with lifelong self evolution capabilities.","published":"2026-01-12T06:33:58Z","updated":"2026-04-14T03:40:36Z","categories":["cs.MA","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.07248v2","pdf_url":"https://arxiv.org/pdf/2601.07248v2","comment":"Accepted in ACL2026 main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.09742","versioned_id":"2601.09742v1","title":"Adaptive Orchestration: Scalable Self-Evolving Multi-Agent Systems","authors":["Sathish Sampath","Anuradha Baskaran"],"abstract":"As Large Language Models (LLMs) are increasingly deployed as autonomous agents, they face a critical scalability bottleneck known as the \"Generalization-Specialization Dilemma.\" Monolithic agents equipped with extensive toolkits suffer from context pollution and attention decay, leading to hallucinations. Conversely, static multi-agent swarms introduce significant latency and resource overhead. This paper introduces a Self-Evolving Concierge System, a novel architecture utilizing a Dynamic Mixture of Experts (DMoE) approach. Unlike recent self-improving agents that rewrite their own codebase, our system preserves stability by dynamically restructuring its runtime environment: \"hiring\" specialized sub-agents based on real-time conversation analysis. We introduce an asynchronous \"Meta-Cognition Engine\" that detects capability gaps, a Least Recently Used (LRU) eviction policy for resource constraints, and a novel \"Surgical History Pruning\" mechanism to mitigate refusal bias. Experimental results demonstrate that this architecture maintains high task success rates while minimizing token consumption compared to static agent swarms.","published":"2026-01-10T07:53:55Z","updated":"2026-01-10T07:53:55Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.09742v1","pdf_url":"https://arxiv.org/pdf/2601.09742v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:e1bpZMpANm","versioned_id":"e1bpZMpANm","title":"Multimodal Meta-Verifier with Explicit Structured Recalibration","authors":["Xinchen Zhang","Bowei Liu","Jiale Liu","Chufan Shi","Yizhen Zhang","Junhong Liu","Youliang Zhang","Zhiheng Li","Yujiu Yang","Ling Yang"],"abstract":"Visual outcomes are increasingly central to multimodal large language models, making reliable and fine-grained verification essential for scaling generalist foundation models. In this work, we investigate ***multimodal meta-verification***, which leverages verifier-generated rationales rather than decision-only signals, and explore how to effectively incorporate meta-verification feedback into multimodal verifier training. We identify two key findings. First, symbolic verifier outputs (e.g., bounding boxes) outperform textual explanations as meta-verification rationales, enabling efficient rule-based reinforcement learning rewards while avoiding reliance on model-based rewards from auxiliary judge models. Second, decoupling reinforcement learning objectives for binary judgment and meta-verification substantially outperforms joint reward optimization, due to intrinsic differences in output structure and learning dynamics. Based on these insights, we train **OmniVerifier-M1**, a generalist visual verifier leveraging symbolic meta-verification and decoupled reinforcement learning. OmniVerifier-M1 provides robust verification and fine-grained error localization, and further enables **M1-TTS**, a verifier-driven agentic generation system achieving dynamic region-level self-correction. This approach paves the way for more reliable, interpretable, and fine-grained multimodal verification, supporting safer and more controllable foundation model deployment.","published":"2026-01-09T08:11:41+00:00","updated":"2026-06-24T23:19:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=e1bpZMpANm","openreview_url":"https://openreview.net/forum?id=e1bpZMpANm","pdf_url":"https://openreview.net/pdf?id=e1bpZMpANm","comment":"ICML 2026 regular","journal_ref":"ICML 2026 regular","doi":"","venue":"ICML 2026 regular","venue_id":"ICML.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2601.05187","versioned_id":"2601.05187v1","title":"SimuAgent: An LLM-Based Simulink Modeling Assistant Enhanced with Reinforcement Learning","authors":["Yanchang Liang","Xiaowei Zhao"],"abstract":"Large language models (LLMs) have revolutionized text-based code automation, but their potential in graph-oriented engineering workflows remains under-explored. We introduce SimuAgent, an LLM-powered modeling and simulation agent tailored for Simulink. SimuAgent replaces verbose XML with a concise, dictionary-style Python representation, dramatically cutting token counts, improving interpretability, and enabling fast, in-process simulation. A lightweight plan-execute architecture, trained in two stages, equips the agent with both low-level tool skills and high-level design reasoning. To tackle sparse rewards in long-horizon tasks, we propose Reflection-GRPO (ReGRPO), which augments Group Relative Policy Optimization (GRPO) with self-reflection traces that supply rich intermediate feedback, accelerating convergence and boosting robustness. Experiments on SimuBench, our newly released benchmark comprising 5300 multi-domain modeling tasks, show that a Qwen2.5-7B model fine-tuned with SimuAgent converges faster and achieves higher modeling accuracy than standard RL baselines, and even surpasses GPT-4o when evaluated with few-shot prompting on the same benchmark. Ablations confirm that the two-stage curriculum and abstract-reconstruct data augmentation further enhance generalization. SimuAgent trains and runs entirely on-premise with modest hardware, delivering a privacy-preserving, cost-effective solution for industrial model-driven engineering. SimuAgent bridges the gap between LLMs and graphical modeling environments, offering a practical solution for AI-assisted engineering design in industrial settings.","published":"2026-01-08T18:10:35Z","updated":"2026-01-08T18:10:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.05187v1","pdf_url":"https://arxiv.org/pdf/2601.05187v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=mMB3Y1ERqi","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2601.05016","versioned_id":"2601.05016v1","title":"From Idea to Co-Creation: A Planner-Actor-Critic Framework for Agent Augmented 3D Modeling","authors":["Jin Gao","Saichandu Juluri"],"abstract":"We present a framework that extends the Actor-Critic architecture to creative 3D modeling through multi-agent self-reflection and human-in-the-loop supervision. While existing approaches rely on single-prompt agents that directly execute modeling commands via tools like Blender MCP, our approach introduces a Planner-Actor-Critic architecture. In this design, the Planner coordinates modeling steps, the Actor executes them, and the Critic provides iterative feedback, while human users act as supervisors and advisors throughout the process. Through systematic comparison between single-prompt modeling and our reflective multi-agent approach, we demonstrate improvements in geometric accuracy, aesthetic quality, and task completion rates across diverse 3D modeling scenarios. Our evaluation reveals that critic-guided reflection, combined with human supervisory input, reduces modeling errors and increases complexity and quality of the result compared to direct single-prompt execution. This work establishes that structured agent self-reflection, when augmented by human oversight and advisory guidance, produces higher-quality 3D models while maintaining efficient workflow integration through real-time Blender synchronization.","published":"2026-01-08T15:18:12Z","updated":"2026-01-08T15:18:12Z","categories":["cs.MA","cs.AI","cs.GR","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2601.05016v1","pdf_url":"https://arxiv.org/pdf/2601.05016v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.04620","versioned_id":"2601.04620v1","title":"AgentDevel: Reframing Self-Evolving LLM Agents as Release Engineering","authors":["Di Zhang"],"abstract":"Recent progress in large language model (LLM) agents has largely focused on embedding self-improvement mechanisms inside the agent or searching over many concurrent variants. While these approaches can raise aggregate scores, they often yield unstable and hard-to-audit improvement trajectories, making it difficult to guarantee non-regression or to reason about failures across versions. We reframe agent improvement as \\textbf{release engineering}: agents are treated as shippable artifacts, and improvement is externalized into a regression-aware release pipeline. We introduce \\textbf{AgentDevel}, a release engineering pipeline that iteratively runs the current agent, produces implementation-blind, symptom-level quality signals from execution traces, synthesizes a single release candidate (RC) via executable diagnosis, and promotes it under flip-centered gating. AgentDevel features three core designs: (i) an implementation-blind LLM critic that characterizes failure appearances without accessing agent internals, (ii) script-based executable diagnosis that aggregates dominant symptom patterns and produces auditable engineering specifications, and (iii) flip-centered gating that prioritizes pass to fail regressions and fail to pass fixes as first-class evidence. Unlike population-based search or in-agent self-refinement, AgentDevel maintains a single canonical version line and emphasizes non-regression as a primary objective. Experiments on execution-heavy benchmarks demonstrate that AgentDevel yields stable improvements with significantly fewer regressions while producing reproducible, auditable artifacts. Overall, AgentDevel provides a practical development discipline for building, debugging, and releasing LLM agents as software development.","published":"2026-01-08T05:49:01Z","updated":"2026-01-08T05:49:01Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.04620v1","pdf_url":"https://arxiv.org/pdf/2601.04620v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:jSFegTEP4V","versioned_id":"jSFegTEP4V","title":"DPC: Training-Free Text-to-SQL Candidate Selection via Dual-Paradigm Consistency","authors":[],"abstract":"While Large Language Models (LLMs) demonstrate impressive proficiency in generating SQL queries, they fundamentally lack the capability to self-evaluate correctness without an execution oracle. This limitation creates a stark Generation-Selection Gap, where high potential accuracy (Pass@K) fails to translate into execution accuracy (Pass@1). Although supervised verifiers offer mitigation, they incur prohibitive annotation costs and suffer from domain fragility. Consequently, recent research has pivoted to the training-free setting. However, existing methods---such as Self-Consistency or LLM-as-a-Judge---remain hampered by systematic bias (consensus on hallucinations) and symbolic blindness (inability to simulate execution states). We introduce DPC (Dual-Paradigm Consistency), a multi-agent framework that reformulates SQL selection from a probabilistic guessing task on hidden data into a deterministic verification task on visible data. Specifically, DPC employs a Slicer and a Tester agent to collaboratively construct a Minimal Distinguishing Database (MDD)---an adversarial, fully observable micro-environment engineered to expose logical discrepancies between candidates. To break the self-correction bias, a Solver agent then verifies the SQL candidates by cross-referencing their execution against a parallel Python/Pandas solution. By validating execution consistency between declarative (SQL) and imperative (Python) paradigms, DPC robustly discriminates correct logic from systematic hallucinations. Experiments on BIRD and Spider across multiple LLMs demonstrate that our method consistently outperforms existing selection baselines, achieving absolute accuracy improvements of up to 2.2\\% over strong competitors like Self-Consistency.","published":"2026-01-06T11:55:09+00:00","updated":"2026-06-07T04:06:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=jSFegTEP4V","openreview_url":"https://openreview.net/forum?id=jSFegTEP4V","pdf_url":"https://openreview.net/pdf?id=jSFegTEP4V","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:koaC5Qgt9C","versioned_id":"koaC5Qgt9C","title":"AgentEconomist: An End-to-End Agentic System for Translating Economic Intuitions into Executable Computational Experiments","authors":[],"abstract":"A long-standing challenge in economics lies not in the lack of intuition, but in the difficulty of translating intuitive insights into verifiable research. To address this challenge, we introduce AgentEconomist, an end-to-end interactive system designed to translate abstract intuitions into executable computational experiments. Grounded in a domain-specific knowledge base covering over 8,700 high-quality academic papers, the system employs a multi-agent architecture. Specifically, an Idea Development Agent and an Experimental Design Agent collaborate to formulate theoretically grounded hypotheses and draft experimental protocols. An Experimental Execution Agent then conducts the designed experiments, forming a closed-loop workflow that supports the rapid development, validation, and iterative refinement of economic intuitions. Through extensive experiments involving human expert evaluation and large language models (LLMs) as judges, we show that the system generates research ideas with stronger literature grounding and higher novelty and insight than state-of-the-art generic LLMs. Overall, AgentEconomist adopts a human-AI collaboration paradigm that enables researchers to focus on high-level intuitions, while delegating the labor-intensive processes of translation and computational execution to agents.","published":"2026-01-06T11:53:57+00:00","updated":"2026-06-07T04:06:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=koaC5Qgt9C","openreview_url":"https://openreview.net/forum?id=koaC5Qgt9C","pdf_url":"https://openreview.net/pdf?id=koaC5Qgt9C","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:VpjzGYFGJK","versioned_id":"VpjzGYFGJK","title":"Personalizing GUI Agents with Human-like Contrastive Interaction Trace","authors":[],"abstract":"Personalized GUI agents show strong potential for assisting users in complex digital environments, yet learning fine-grained user preferences from limited interaction data remains a significant challenge. Existing approaches often rely on manual prompt engineering or synthetic interaction data that fail to capture realistic human behaviors, limiting their robustness and generalization. In this work, we propose PACUT, a novel approach for personalizing GUI agents through human-like contrastive interaction traces. PACUT introduces a multi-agent self-refinement process that iteratively infers and consolidates user profiles from observed GUI interactions, enabling the synthesis of behaviorally realistic yet preference-divergent contrastive traces. Building on this supervision, we fine-tune GUI agents using supervised learning and Direct Preference Optimization to explicitly distinguish preferred behaviors from profile-inconsistent alternatives. To support systematic evaluation, we collect a new benchmark dataset with user-specific mobile GUI interaction traces. Extensive experiments across diverse LLM backbones demonstrate that PACUT consistently outperforms strong baselines and ablation variants.","published":"2026-01-06T11:51:26+00:00","updated":"2026-06-07T04:06:54+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=VpjzGYFGJK","openreview_url":"https://openreview.net/forum?id=VpjzGYFGJK","pdf_url":"https://openreview.net/pdf?id=VpjzGYFGJK","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:IKZGsehfF4","versioned_id":"IKZGsehfF4","title":"MPCI-Bench: A Benchmark for Multimodal Pairwise Contextual Integrity Evaluation of Language Model Agents","authors":[],"abstract":"As language-model agents evolve from passive chatbots into proactive assistants that handle personal data, evaluating their adherence to social norms becomes increasingly critical, often through the lens of Contextual Integrity (CI). However, existing CI benchmarks are largely text-centric and primarily emphasize negative refusal scenarios, overlooking multimodal privacy risks and the fundamental trade-off between privacy and utility. In this paper, we introduce MPCI-Bench, the first Multimodal Pairwise Contextual Integrity benchmark for evaluating privacy behavior in agentic settings. MPCI-Bench consists of paired positive and negative instances derived from the same visual source and instantiated across three tiers: normative Seed judgments, context-rich Story reasoning, and executable agent action Traces. Data quality is ensured through a Tri-Principle Iterative Refinement pipeline. Evaluations of state-of-the-art multimodal models reveal systematic failures to balance privacy and utility and a pronounced modality leakage gap, where sensitive visual information is leaked more frequently than textual information. We will open-source MPCI-Bench to facilitate future research on agentic CI.","published":"2026-01-06T09:56:43+00:00","updated":"2026-06-07T04:06:28+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=IKZGsehfF4","openreview_url":"https://openreview.net/forum?id=IKZGsehfF4","pdf_url":"https://openreview.net/pdf?id=IKZGsehfF4","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:07xc55lKR8","versioned_id":"07xc55lKR8","title":"Memory-Augmented LLM-based Multi-Agent System for Automated Feature Generation on Tabular Data","authors":[],"abstract":"Automated feature generation extracts informative features from raw tabular data without manual intervention and is crucial for accurate, generalizable machine learning. Traditional methods rely on predefined operator libraries and cannot leverage task semantics, limiting their ability to produce diverse, high-value features for complex tasks. Recent Large Language Model (LLM)-based approaches introduce richer semantic signals, but still suffer from a restricted feature space due to fixed generation patterns and from the absence of feedback from the learning objective. To address these challenges, we propose a Memory-Augmented LLM-based Multi-Agent System (\\textbf{MALMAS}) for automated feature generation. MALMAS decomposes the generation process into agents with distinct responsibilities, and a Router Agent activates an appropriate subset of agents per iteration, further broadening exploration of the feature space. We further integrate a memory module comprising procedural memory, feedback memory, and conceptual memory, enabling iterative refinement that adaptively guides subsequent feature generation and improves feature quality and diversity. Extensive experiments on multiple public datasets against state-of-the-art baselines demonstrate the effectiveness of our approach.","published":"2026-01-06T06:34:12+00:00","updated":"2026-06-07T04:06:00+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=07xc55lKR8","openreview_url":"https://openreview.net/forum?id=07xc55lKR8","pdf_url":"https://openreview.net/pdf?id=07xc55lKR8","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:9ouOhmLbQL","versioned_id":"9ouOhmLbQL","title":"Toward Self-Improving Systems of LLM Agents through Exploration and Iterative Feedback","authors":[],"abstract":"Training large language model (LLM) agents to acquire necessary skills and perform diverse tasks within an environment is gaining interest as a means to enable open-endedness. However, building the training dataset is difficult, as manual trajectory collection is labor-intensive and LLM-proposed tasks are often infeasible. Moreover, the generated data may not provide a meaningful learning signal, as agents often already perform well on the proposed tasks. To address this, we propose a novel framework EXIF for LLM-powered agents. This automatic improvement framework is designed to enhance the feasibility of generated target behaviors while accounting for the agents’ capabilities. Our method adopts an exploration-first strategy by employing an exploration agent (Alice) to train the target agent (Bob) to learn essential skills in the environment. Specifically, Alice first interacts with the environment to generate a feasible, environment-grounded skill dataset, which is then used to train Bob. Crucially, we incorporate an iterative feedback loop, where Alice evaluates Bob’s performance to identify areas for improvement. This feedback then guides Alice’s next round of exploration, forming a closed-loop data generation process. Experiments on Webshop and Crafter demonstrate EXIF’s ability to iteratively expand the capabilities of the trained agent without human intervention, leading to substantial performance improvements. Interestingly, we observe that setting Alice to the same model as Bob also notably improves performance, demonstrating EXIF’s potential for building a self-improving system.","published":"2026-01-06T02:02:50+00:00","updated":"2026-06-07T04:05:39+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9ouOhmLbQL","openreview_url":"https://openreview.net/forum?id=9ouOhmLbQL","pdf_url":"https://openreview.net/pdf?id=9ouOhmLbQL","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:ZmtgO2OLCd","versioned_id":"ZmtgO2OLCd","title":"ClinicalReTrial: A Self-Evolving AI Agent for Clinical Trial Protocol Optimization","authors":[],"abstract":"Clinical trials constitute a critical yet exceptionally challenging and costly stage of drug development ($2.6B per drug), where protocols are encoded as complex natural language documents, motivating the use of AI systems beyond manual analysis. Existing AI methods predict trial failure accurately but offer no actionable remedies. To fill this gap, this paper proposes **ClinicalReTrial**, a multi-agent framework that formulates clinical trial optimization as an iterative redesign problem on textual protocols. Our method integrates failure diagnosis, safety-aware modifications, and candidate evaluation in a closed-loop, reward-driven optimization framework. Serving the outcome prediction model as a simulation environment, **ClinicalReTrial** enables low-cost evaluation and dense reward signals for continuous self-improvement. We further propose hierarchical memory capturing iteration-level feedback within trials and distilling transferable redesign patterns across trials. Empirically, **ClinicalReTrial** improves 83.3% of trial protocols with a mean success probability gain of 5.7% at negligible cost ($0.12 per trial). Retrospective case studies demonstrate strong alignment between the discovered redesign strategies and real-world clinical trial modifications.","published":"2026-01-05T16:58:55+00:00","updated":"2026-06-07T04:05:17+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ZmtgO2OLCd","openreview_url":"https://openreview.net/forum?id=ZmtgO2OLCd","pdf_url":"https://openreview.net/pdf?id=ZmtgO2OLCd","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:Bnbg0RpNvR","versioned_id":"Bnbg0RpNvR","title":"Value-Guided Open-Loop MCTS for Proactive Task-Oriented Dialogue","authors":[],"abstract":"Proactive task-oriented dialogue is essential for reliable real-world assistants, yet current LLM-based systems are largely reactive and struggle to recover from failed retrieval, ambiguous constraints, and cross-domain dependencies. This paper targets the core gap of enabling effective lookahead decision-making for proactive TOD under limited high-quality supervision and high-variance language rollouts. We propose SMCTS-TOD , which combines act-level open-loop planning with a fast learned success estimator to make lookahead practical: the planner searches over dialogue-act sequences while the Value-LLM provides low-latency, low-variance guidance and supports iterative refinement via self-distillation. Across MultiWOZ 2.0 and SGD, SMCTS-TOD improves interactive goal completion and robustness, achieving higher success-oriented metrics than strong prompting baselines. Human studies further indicate better dialogue-level usefulness and fewer unreasonable strategy choices. These results suggest that abstract planning paired with fast learned evaluation is a viable and verifiable path to more proactive and robust LLM-based TOD agents.","published":"2026-01-05T14:38:36+00:00","updated":"2026-06-07T04:05:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Bnbg0RpNvR","openreview_url":"https://openreview.net/forum?id=Bnbg0RpNvR","pdf_url":"https://openreview.net/pdf?id=Bnbg0RpNvR","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2601.02075","versioned_id":"2601.02075v4","title":"MDAgent2: Large Language Model for Code Generation and Knowledge Q&A in Molecular Dynamics","authors":["Zhuofan Shi","Hubao A","Yufei Shao","Dongliang Huang","Hongxu An","Chunxiao Xin","Haiyang Shen","Zhenyu Wang","Yunshan Na","Gang Huang","Xiang Jing"],"abstract":"Molecular dynamics (MD) simulations are essential for understanding atomic-scale behaviors in materials science, yet writing LAMMPS scripts remains highly specialized and time-consuming tasks. Although LLMs show promise in code generation and domain-specific question answering, their performance in MD scenarios is limited by scarce domain data, the high deployment cost of state-of-the-art LLMs, and low code executability. Building upon our prior MDAgent, we present MDAgent2, the first end-to-end framework capable of performing both knowledge Q&A and code generation within the MD domain. We construct a domain-specific data-construction pipeline that yields three high-quality datasets spanning MD knowledge, question answering, and code generation. Based on these datasets, we adopt a three stage post-training strategy--continued pre-training (CPT), supervised fine-tuning (SFT), and reinforcement learning (RL)--to train two domain-adapted models, MD-Instruct and MD-Code. Furthermore, we introduce MD-GRPO, a closed-loop RL method that leverages simulation outcomes as reward signals and recycles low-reward trajectories for continual refinement. We further build MDAgent2-RUNTIME, a deployable multi-agent system that integrates code generation, execution, evaluation, and self-correction. Together with MD-EvalBench proposed in this work, the first benchmark for LAMMPS code generation and question answering, our models and system achieve performance surpassing several strong baselines.This work systematically demonstrates the adaptability and generalization capability of large language models in industrial simulation tasks, laying a methodological foundation for automatic code generation in AI for Science and industrial-scale simulations. URL: https://github.com/FredericVAN/PKU_MDAgent2","published":"2026-01-05T12:56:51Z","updated":"2026-02-06T05:47:09Z","categories":["cs.CE","cs.LG"],"primary_category":"cs.CE","arxiv_url":"https://arxiv.org/abs/2601.02075v4","pdf_url":"https://arxiv.org/pdf/2601.02075v4","comment":"24 pages,4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:9y7p4uWris","versioned_id":"9y7p4uWris","title":"A Survey of Agentic Workflow Optimization","authors":[],"abstract":"Multi-agent systems have emerged as a powerful paradigm for solving complex tasks by decomposing them into coordinated subtasks conducted by specialized agents. However, designing effective multi-agent workflows is challenging and requires strong domain expertise, making them brittle, inefficient, and difficult to adapt across tasks and resource constraints. Addressing these challenges, this survey systematically review the emerging field of Multi-Agent Workflow Optimization (MAWO), treating the workflow itself as the object of automatic improvement. We formalize MAWO as a constrained optimization problem and organize existing methods along four dimensions: workflow representation, optimization targets, reward signals, and optimization algorithms. By reviewing and categorizing a wide range of recent works, we provide a unified framework for understanding automated workflow improvement and outline open challenges in this field. This survey serves as a foundational resource for researchers and practitioners advancing self-improving multi-agent systems.","published":"2026-01-05T09:27:43+00:00","updated":"2026-06-07T04:04:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9y7p4uWris","openreview_url":"https://openreview.net/forum?id=9y7p4uWris","pdf_url":"https://openreview.net/pdf?id=9y7p4uWris","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2601.01743","versioned_id":"2601.01743v1","title":"AI Agent Systems: Architectures, Applications, and Evaluation","authors":["Bin Xu"],"abstract":"AI agents -- systems that combine foundation models with reasoning, planning, memory, and tool use -- are rapidly becoming a practical interface between natural-language intent and real-world computation. This survey synthesizes the emerging landscape of AI agent architectures across: (i) deliberation and reasoning (e.g., chain-of-thought-style decomposition, self-reflection and verification, and constraint-aware decision making), (ii) planning and control (from reactive policies to hierarchical and multi-step planners), and (iii) tool calling and environment interaction (retrieval, code execution, APIs, and multimodal perception). We organize prior work into a unified taxonomy spanning agent components (policy/LLM core, memory, world models, planners, tool routers, and critics), orchestration patterns (single-agent vs.\\ multi-agent; centralized vs.\\ decentralized coordination), and deployment settings (offline analysis vs.\\ online interactive assistance; safety-critical vs.\\ open-ended tasks). We discuss key design trade-offs -- latency vs.\\ accuracy, autonomy vs.\\ controllability, and capability vs.\\ reliability -- and highlight how evaluation is complicated by non-determinism, long-horizon credit assignment, tool and environment variability, and hidden costs such as retries and context growth. Finally, we summarize measurement and benchmarking practices (task suites, human preference and utility metrics, success under constraints, robustness and security) and identify open challenges including verification and guardrails for tool actions, scalable memory and context management, interpretability of agent decisions, and reproducible evaluation under realistic workloads.","published":"2026-01-05T02:38:40Z","updated":"2026-01-05T02:38:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.01743v1","pdf_url":"https://arxiv.org/pdf/2601.01743v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.01321","versioned_id":"2601.01321v1","title":"Digital Twin AI: Opportunities and Challenges from Large Language Models to World Models","authors":["Rong Zhou","Dongping Chen","Zihan Jia","Yao Su","Yixin Liu","Yiwen Lu","Dongwei Shi","Yue Huang","Tianyang Xu","Yi Pan","Xinliang Li","Yohannes Abate","Qingyu Chen","Zhengzhong Tu","Yu Yang","Yu Zhang","Qingsong Wen","Gengchen Mai","Sunyang Fu","Jiachen Li","Xuyu Wang","Ziran Wang","Jing Huang","Tianming Liu","Yong Chen","Lichao Sun","Lifang He"],"abstract":"Digital twins, as precise digital representations of physical systems, have evolved from passive simulation tools into intelligent and autonomous entities through the integration of artificial intelligence technologies. This paper presents a unified four-stage framework that systematically characterizes AI integration across the digital twin lifecycle, spanning modeling, mirroring, intervention, and autonomous management. By synthesizing existing technologies and practices, we distill a unified four-stage framework that systematically characterizes how AI methodologies are embedded across the digital twin lifecycle: (1) modeling the physical twin through physics-based and physics-informed AI approaches, (2) mirroring the physical system into a digital twin with real-time synchronization, (3) intervening in the physical twin through predictive modeling, anomaly detection, and optimization strategies, and (4) achieving autonomous management through large language models, foundation models, and intelligent agents. We analyze the synergy between physics-based modeling and data-driven learning, highlighting the shift from traditional numerical solvers to physics-informed and foundation models for physical systems. Furthermore, we examine how generative AI technologies, including large language models and generative world models, transform digital twins into proactive and self-improving cognitive systems capable of reasoning, communication, and creative scenario generation. Through a cross-domain review spanning eleven application domains, including healthcare, aerospace, smart manufacturing, robotics, and smart cities, we identify common challenges related to scalability, explainability, and trustworthiness, and outline directions for responsible AI-driven digital twin systems.","published":"2026-01-04T01:17:09Z","updated":"2026-01-04T01:17:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.01321v1","pdf_url":"https://arxiv.org/pdf/2601.01321v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.01126","versioned_id":"2601.01126v2","title":"RoboPhD: Self-Improving Text-to-SQL Through Autonomous Agent Evolution","authors":["Andrew Borthwick","Stephen Ash"],"abstract":"We present RoboPhD, a system where AI agents autonomously conduct research to improve Text-to-SQL performance. RoboPhD implements a closed-loop evolution cycle with two coordinated components: a SQL Generation agent composed of a database analysis script and SQL generation instructions, and an Evolution agent that designs new versions based on performance feedback. Central to the framework is an ELO-based selection mechanism enabling survival-of-the-fittest dynamics while handling non-transitivity in performance. Starting from a naive 70-line baseline, RoboPhD evolves agents through iterative cross-pollination, discovering effective techniques without any external guidance on the Text-to-SQL domain. Our best agent, evolved to 1500 lines over 18 iterations, autonomously discovered strategies such as size-adaptive database analysis that adjusts depth based on schema complexity and SQL generation patterns for column selection, evidence interpretation, and aggregation. Evolution provides the largest gains on cheaper models: while we improve by 2.3 points over a strong Claude Opus 4.5 naive baseline, we show an improvement of 8.9 points over the weaker Claude Haiku model. This enables 'skip a tier' deployment: evolved Haiku exceeds naive Sonnet accuracy, and evolved Sonnet exceeds naive Opus, both at lower cost. The full system achieves 73.67% accuracy on the BIRD test set, demonstrating that AI can autonomously build a strong agentic system with only a trivial human-provided starting point.","published":"2026-01-03T09:16:07Z","updated":"2026-01-26T01:15:57Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.01126v2","pdf_url":"https://arxiv.org/pdf/2601.01126v2","comment":"18 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=VFyOrKqiDY","openreview_venues":["ICLR 2026 Conference Desk Rejected Submission"]},{"id":"2601.00290","versioned_id":"2601.00290v2","title":"ClinicalReTrial: Clinical Trial Redesign with Self-Evolving Agents","authors":["Sixue Xing","Kerui Wu","Xuanye Xia","Meng Jiang","Jintai Chen","Tianfan Fu"],"abstract":"Clinical trials constitute a critical yet exceptionally challenging and costly stage of drug development (\\$2.6B per drug), where protocols are encoded as complex natural language documents, motivating the use of AI systems beyond manual analysis. Existing AI methods accurately predict trial failure, but do not provide actionable remedies. To fill this gap, this paper proposes ClinicalReTrial, a multi-agent system that formulates clinical trial optimization as an iterative redesign problem on textural protocols. Our method integrates failure diagnosis, safety-aware modifications, and candidate evaluation in a closed-loop, reward-driven optimization framework. Serving the outcome prediction model as a simulation environment, ClinicalReTrial enables low-cost evaluation and dense reward signals for continuous self-improvement. We further propose a hierarchical memory that captures iteration-level feedback within trials and distills transferable redesign patterns across trials. Empirically, ClinicalReTrial improves $83.3\\%$ of trial protocols with a mean success probability gain of $5.7\\%$ with negligible cost (\\$0.12 per trial). Retrospective case studies demonstrate alignment between the discovered redesign strategies and real-world clinical trial modifications. The code is anonymously available at: https://github.com/xingsixue123/ClinicalFailureReasonReTrial.","published":"2026-01-01T10:11:58Z","updated":"2026-04-02T21:02:45Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2601.00290v2","pdf_url":"https://arxiv.org/pdf/2601.00290v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=85R7KFkfol","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2512.24796","versioned_id":"2512.24796v2","title":"LeanCat: A Benchmark Suite for Formal Category Theory in Lean (Part I: 1-Categories)","authors":["Rongge Xu","Hui Dai","Yiming Fu","Jiedong Jiang","Tianjiao Nie","Junkai Wang","Holiverse Yang","Zhi-Hao Zhang"],"abstract":"While large language models (LLMs) have demonstrated impressive capabilities in formal theorem proving, current benchmarks fail to adequately measure library-grounded abstraction -- the ability to reason with high-level interfaces and reusable structures central to modern mathematics and software engineering. We introduce LeanCat, a challenging benchmark comprising 100 fully formalized category-theory tasks in Lean. Unlike algebra or arithmetic, category theory serves as a rigorous stress test for structural, interface-level reasoning. Our evaluation reveals a severe abstraction gap: the best state-of-the-art model solves only 12.0% of tasks at pass@4, with performance collapsing from 55.0% on Easy tasks to 0.0% on High-difficulty tasks, highlighting a failure in compositional generalization. To overcome this, we evaluate LeanBridge, a retrieval-augmented agent that employs a retrieve-generate-verify loop. LeanBridge achieves a peak success rate of 24.0% -- doubling the performance of the best static baseline. These results empirically demonstrate that iterative refinement and dynamic library retrieval are not merely optimizations but strict necessities for neuro-symbolic reasoning in abstract domains. LeanCat offers a compact, reusable testbed for tracking progress toward reliable, research-level formalization.","published":"2025-12-31T11:33:29Z","updated":"2026-02-25T20:35:18Z","categories":["cs.LO","cs.AI","cs.FL","cs.LG","math.CT"],"primary_category":"cs.LO","arxiv_url":"https://arxiv.org/abs/2512.24796v2","pdf_url":"https://arxiv.org/pdf/2512.24796v2","comment":"22 pages, 9 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:kt7AVrmKYX","versioned_id":"kt7AVrmKYX","title":"Diverse Thinking: Breaking Oppositions in Debates to Foster Synergized Reasoning via Multi-Agent Collaboration","authors":[],"abstract":"Large Language Models (LLMs) frequently face limitations, such as judgment biases and cognitive deadlocks, in complex reasoning due to “Degradation of Thought” in self-reflection. While Multi-Agent Debate (MAD) approaches attempt to address this issue, their inherently adversarial nature suppresses diverse perspectives by overemphasizing antagonism, which results in the loss of partially valid reasoning. In this paper, we propose Multi-Agent Diverse Thinking (MADT), a novel cognitive framework that redefines multi-agent collaboration by shifting from adversarial confrontation toward constructive synergy. To break the oppositional deadlock found in traditional debates, MADT decomposes the thinking process into fine-grained modules: an Affirmative Thinker to preserve rational components, a Critical Thinker to rectify errors, and a Growth-Minded Thinker to provide optimization suggestions. These agents jointly foster a synergistic environment where specialized roles protect valid logic while iteratively refining flaws. Meanwhile, a Leader agent coordinates the collaborations and synthesizes the feedback from multiple thinkers to produce the final result. Extensive experiments on Common Machine Translation and Counter-Intuitive Arithmetic Reasoning tasks show that MADT consistently outperforms Self-Reflection and MAD baselines, validating the superior ability to enhance complex logical and reasoning performance in LLMs. Code is available at https://anonymous.4open.science/r/MADT-5D3B.","published":"2025-12-30T16:00:00+00:00","updated":"2026-07-02T02:30:21+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=kt7AVrmKYX","openreview_url":"https://openreview.net/forum?id=kt7AVrmKYX","pdf_url":"https://openreview.net/pdf?id=kt7AVrmKYX","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2512.24077","versioned_id":"2512.24077v1","title":"LoongFlow: Directed Evolutionary Search via a Cognitive Plan-Execute-Summarize Paradigm","authors":["Chunhui Wan","Xunan Dai","Zhuo Wang","Minglei Li","Yanpeng Wang","Yinan Mao","Yu Lan","Zhiwen Xiao"],"abstract":"The transition from static Large Language Models (LLMs) to self-improving agents is hindered by the lack of structured reasoning in traditional evolutionary approaches. Existing methods often struggle with premature convergence and inefficient exploration in high-dimensional code spaces. To address these challenges, we introduce LoongFlow, a self-evolving agent framework that achieves state-of-the-art solution quality with significantly reduced computational costs. Unlike \"blind\" mutation operators, LoongFlow integrates LLMs into a cognitive \"Plan-Execute-Summarize\" (PES) paradigm, effectively mapping the evolutionary search to a reasoning-heavy process. To sustain long-term architectural coherence, we incorporate a hybrid evolutionary memory system. By synergizing Multi-Island models with MAP-Elites and adaptive Boltzmann selection, this system theoretically balances the exploration-exploitation trade-off, maintaining diverse behavioral niches to prevent optimization stagnation. We instantiate LoongFlow with a General Agent for algorithmic discovery and an ML Agent for pipeline optimization. Extensive evaluations on the AlphaEvolve benchmark and Kaggle competitions demonstrate that LoongFlow outperforms leading baselines (e.g., OpenEvolve, ShinkaEvolve) by up to 60% in evolutionary efficiency while discovering superior solutions. LoongFlow marks a substantial step forward in autonomous scientific discovery, enabling the generation of expert-level solutions with reduced computational overhead.","published":"2025-12-30T08:39:28Z","updated":"2025-12-30T08:39:28Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.24077v1","pdf_url":"https://arxiv.org/pdf/2512.24077v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.23880","versioned_id":"2512.23880v2","title":"CASCADE: Cumulative Agentic Skill Creation through Autonomous Development and Evolution","authors":["Xu Huang","Junwu Chen","Yuxing Fei","Zhuohan Li","Philippe Schwaller","Gerbrand Ceder"],"abstract":"Large language model (LLM) agents currently depend on predefined tools or early-stage tool generation, limiting their adaptability and scalability to complex scientific tasks. We introduce CASCADE, a self-evolving agentic framework representing an early instantiation of the transition from \"LLM + tool use\" to \"LLM + skill acquisition\". CASCADE enables agents to master complex external tools and codify knowledge through two meta-skills: continuous learning via web search, code extraction, and memory utilization; self-reflection via introspection, knowledge graph exploration, and others. We evaluate CASCADE on SciSkillBench, a benchmark of 116 materials science and chemistry research tasks. CASCADE achieves a 93.3% success rate using GPT-5, compared to 35.4% without evolution mechanisms. We further demonstrate real-world applications in computational analysis, autonomous laboratory experiments, and selective reproduction of published papers. Along with human-agent collaboration and memory consolidation, CASCADE accumulates executable skills that can be shared across agents and scientists, moving toward scalable AI-assisted scientific research.","published":"2025-12-29T21:50:23Z","updated":"2026-01-28T06:08:09Z","categories":["cs.AI","cond-mat.mtrl-sci"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.23880v2","pdf_url":"https://arxiv.org/pdf/2512.23880v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:DIDs1FuK5z","versioned_id":"DIDs1FuK5z","title":"On-the-Fly VLA Adaptation via Test-Time Reinforcement Learning","authors":[],"abstract":"Vision-Language-Action models have recently emerged as a powerful paradigm for general-purpose robot learning, enabling agents to map visual observations and natural-language instructions into executable robotic actions. Though popular, they are primarily trained via supervised fine-tuning or training-time reinforcement learning, requiring explicit fine-tuning phases, human interventions, or controlled data collection. Consequently, existing methods remain unsuitable for challenging simulated- or physical-world deployments, where robots must respond autonomously and flexibly to evolving environments. To address this limitation, we introduce a Test-Time Reinforcement Learning for VLAs (TT-VLA), a framework that enables on-the-fly policy adaptation during inference. TT-VLA formulates a dense reward mechanism that leverages step-by-step task-progress signals to refine action policies during test time while preserving the SFT/RL-trained priors, making it an effective supplement to current VLA models. Empirical results show that our approach enhances overall adaptability, stability, and task success in dynamic, previously unseen scenarios under simulated and real-world settings. We believe TT-VLA offers a principled step toward self-improving, deployment-ready VLAs.","published":"2025-12-29T04:50:24+00:00","updated":"2026-06-07T04:03:30+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=DIDs1FuK5z","openreview_url":"https://openreview.net/forum?id=DIDs1FuK5z","pdf_url":"https://openreview.net/pdf?id=DIDs1FuK5z","comment":"ACL ARR 2026 January Submission","journal_ref":"ACL ARR 2026 January Submission","doi":"","venue":"ACL ARR 2026 January Submission","venue_id":"aclweb.org/ACL/ARR/2026/January/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2512.23167","versioned_id":"2512.23167v1","title":"SPIRAL: Symbolic LLM Planning via Grounded and Reflective Search","authors":["Yifan Zhang","Giridhar Ganapavarapu","Srideepika Jayaraman","Bhavna Agrawal","Dhaval Patel","Achille Fokoue"],"abstract":"Large Language Models (LLMs) often falter at complex planning tasks that require exploration and self-correction, as their linear reasoning process struggles to recover from early mistakes. While search algorithms like Monte Carlo Tree Search (MCTS) can explore alternatives, they are often ineffective when guided by sparse rewards and fail to leverage the rich semantic capabilities of LLMs. We introduce SPIRAL (Symbolic LLM Planning via Grounded and Reflective Search), a novel framework that embeds a cognitive architecture of three specialized LLM agents into an MCTS loop. SPIRAL's key contribution is its integrated planning pipeline where a Planner proposes creative next steps, a Simulator grounds the search by predicting realistic outcomes, and a Critic provides dense reward signals through reflection. This synergy transforms MCTS from a brute-force search into a guided, self-correcting reasoning process. On the DailyLifeAPIs and HuggingFace datasets, SPIRAL consistently outperforms the default Chain-of-Thought planning method and other state-of-the-art agents. More importantly, it substantially surpasses other state-of-the-art agents; for example, SPIRAL achieves 83.6% overall accuracy on DailyLifeAPIs, an improvement of over 16 percentage points against the next-best search framework, while also demonstrating superior token efficiency. Our work demonstrates that structuring LLM reasoning as a guided, reflective, and grounded search process yields more robust and efficient autonomous planners. The source code, full appendices, and all experimental data are available for reproducibility at the official project repository.","published":"2025-12-29T03:19:42Z","updated":"2025-12-29T03:19:42Z","categories":["cs.AI","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.23167v1","pdf_url":"https://arxiv.org/pdf/2512.23167v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.23760","versioned_id":"2512.23760v1","title":"Audited Skill-Graph Self-Improvement for Agentic LLMs via Verifiable Rewards, Experience Synthesis, and Continual Memory","authors":["Ken Huang","Jerry Huang"],"abstract":"Reinforcement learning is increasingly used to transform large language models into agentic systems that act over long horizons, invoke tools, and manage memory under partial observability. While recent work has demonstrated performance gains through tool learning, verifiable rewards, and continual training, deployed self-improving agents raise unresolved security and governance challenges: optimization pressure can incentivize reward hacking, behavioral drift is difficult to audit or reproduce, and improvements are often entangled in opaque parameter updates rather than reusable, verifiable artifacts. This paper proposes Audited Skill-Graph Self-Improvement (ASG-SI), a framework that treats self-improvement as iterative compilation of an agent into a growing, auditable skill graph. Each candidate improvement is extracted from successful trajectories, normalized into a skill with an explicit interface, and promoted only after passing verifier-backed replay and contract checks. Rewards are decomposed into reconstructible components derived from replayable evidence, enabling independent audit of promotion decisions and learning signals. ASG-SI further integrates experience synthesis for scalable stress testing and continual memory control to preserve long-horizon performance under bounded context. We present a complete system architecture, threat model, and security analysis, and provide a fully runnable reference implementation that demonstrates verifier-backed reward construction, skill compilation, audit logging, and measurable improvement under continual task streams. ASG-SI reframes agentic self-improvement as accumulation of verifiable, reusable capabilities, offering a practical path toward reproducible evaluation and operational governance of self-improving AI agents.","published":"2025-12-28T19:39:47Z","updated":"2025-12-28T19:39:47Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.23760v1","pdf_url":"https://arxiv.org/pdf/2512.23760v1","comment":"11 pages, 4 figures. Includes a complete runnable reference implementation and audit logging framework","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.22650","versioned_id":"2512.22650v1","title":"Scaling Unverifiable Rewards: A Case Study on Visual Insights","authors":["Shuyu Gan","James Mooney","Pan Hao","Renxiang Wang","Mingyi Hong","Qianwen Wang","Dongyeop Kang"],"abstract":"Large Language Model (LLM) agents can increasingly automate complex reasoning through Test-Time Scaling (TTS), iterative refinement guided by reward signals. However, many real-world tasks involve multi-stage pipeline whose final outcomes lack verifiable rewards or sufficient data to train robust reward models, making judge-based refinement prone to accumulate error over stages. We propose Selective TTS, a process-based refinement framework that scales inference across different stages in multi-agent pipeline, instead of repeated refinement over time by prior work. By distributing compute across stages and pruning low-quality branches early using process-specific judges, Selective TTS mitigates the judge drift and stabilizes refinement. Grounded in the data science pipeline, we build an end-to-end multi-agent pipeline for generating visually insightful charts and report of given dataset, and design a reliable LLM-based judge model, aligned with human experts (Kendall's τ=0.55). Our proposed selective TTS then improves insight quality under a fixed compute budget, increasing mean scores from 61.64 to 65.86 while reducing variance. We hope our findings serve as the first step toward to scaling complex, open-ended tasks with unverifiable rewards, such as scientific discovery and story generation.","published":"2025-12-27T17:01:38Z","updated":"2025-12-27T17:01:38Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.22650v1","pdf_url":"https://arxiv.org/pdf/2512.22650v1","comment":"32 pages, 25 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.22435","versioned_id":"2512.22435v1","title":"AnalogSAGE: Self-evolving Analog Design Multi-Agents with Stratified Memory and Grounded Experience","authors":["Zining Wang","Jian Gao","Weimin Fu","Xiaolong Guo","Xuan Zhang"],"abstract":"Analog circuit design remains a knowledge- and experience-intensive process that relies heavily on human intuition for topology generation and device parameter tuning. Existing LLM-based approaches typically depend on prompt-driven netlist generation or predefined topology templates, limiting their ability to satisfy complex specification requirements. We propose AnalogSAGE, an open-source self-evolving multi-agent framework that coordinates three-stage agent explorations through four stratified memory layers, enabling iterative refinement with simulation-grounded feedback. To support reproducibility and generality, we release the source code. Our benchmark spans ten specification-driven operational amplifier design problems of varying difficulty, enabling quantitative and cross-task comparison under identical conditions. Evaluated under the open-source SKY130 PDK with ngspice, AnalogSAGE achieves a 10$\\times$ overall pass rate, a 48$\\times$ Pass@1, and a 4$\\times$ reduction in parameter search space compared with existing frameworks, demonstrating that stratified memory and grounded reasoning substantially enhance the reliability and autonomy of analog design automation in practice.","published":"2025-12-27T02:06:05Z","updated":"2025-12-27T02:06:05Z","categories":["cs.AR","cs.LG"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2512.22435v1","pdf_url":"https://arxiv.org/pdf/2512.22435v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.21481","versioned_id":"2512.21481v1","title":"The AI Committee: A Multi-Agent Framework for Automated Validation and Remediation of Web-Sourced Data","authors":["Sunith Vallabhaneni","Thomas Berkane","Maimuna Majumder"],"abstract":"Many research areas rely on data from the web to gain insights and test their methods. However, collecting comprehensive research datasets often demands manually reviewing many web pages to identify and record relevant data points, which is labor-intensive and susceptible to error. While the emergence of large language models (LLM)-powered web agents has begun to automate parts of this process, they often struggle to ensure the validity of the data they collect. Indeed, these agents exhibit several recurring failure modes - including hallucinating or omitting values, misinterpreting page semantics, and failing to detect invalid information - which are subtle and difficult to detect and correct manually. To address this, we introduce the AI Committee, a novel model-agnostic multi-agent system that automates the process of validating and remediating web-sourced datasets. Each agent is specialized in a distinct task in the data quality assurance pipeline, from source scrutiny and fact-checking to data remediation and integrity validation. The AI Committee leverages various LLM capabilities - including in-context learning for dataset adaptation, chain-of-thought reasoning for complex semantic validation, and a self-correction loop for data remediation - all without task-specific training. We demonstrate the effectiveness of our system by applying it to three real-world datasets, showing that it generalizes across LLMs and significantly outperforms baseline approaches, achieving data completeness up to 78.7% and precision up to 100%. We additionally conduct an ablation study demonstrating the contribution of each agent to the Committee's performance. This work is released as an open-source tool for the research community.","published":"2025-12-25T03:00:22Z","updated":"2025-12-25T03:00:22Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2512.21481v1","pdf_url":"https://arxiv.org/pdf/2512.21481v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2601.09714","versioned_id":"2601.09714v1","title":"Evaluating Novelty in AI-Generated Research Plans Using Multi-Workflow LLM Pipelines","authors":["Devesh Saraogi","Rohit Singhee","Dhruv Kumar"],"abstract":"The integration of Large Language Models (LLMs) into the scientific ecosystem raises fundamental questions about the creativity and originality of AI-generated research. Recent work has identified ``smart plagiarism'' as a concern in single-step prompting approaches, where models reproduce existing ideas with terminological shifts. This paper investigates whether agentic workflows -- multi-step systems employing iterative reasoning, evolutionary search, and recursive decomposition -- can generate more novel and feasible research plans. We benchmark five reasoning architectures: Reflection-based iterative refinement, Sakana AI v2 evolutionary algorithms, Google Co-Scientist multi-agent framework, GPT Deep Research (GPT-5.1) recursive decomposition, and Gemini~3 Pro multimodal long-context pipeline. Using evaluations from thirty proposals each on novelty, feasibility, and impact, we find that decomposition-based and long-context workflows achieve mean novelty of 4.17/5, while reflection-based approaches score significantly lower (2.33/5). Results reveal varied performance across research domains, with high-performing workflows maintaining feasibility without sacrificing creativity. These findings support the view that carefully designed multi-stage agentic workflows can advance AI-assisted research ideation.","published":"2025-12-24T12:41:31Z","updated":"2025-12-24T12:41:31Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2601.09714v1","pdf_url":"https://arxiv.org/pdf/2601.09714v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.21066","versioned_id":"2512.21066v3","title":"Agentic Explainable Artificial Intelligence (Agentic XAI) Approach To Explore Better Explanation","authors":["Tomoaki Yamaguchi","Yutong Zhou","Masahiro Ryo","Keisuke Katsura"],"abstract":"Explainable artificial intelligence (XAI) enables data-driven understanding of factor associations with response variables, yet communicating XAI outputs to laypersons remains challenging, hindering trust in AI-based predictions. Large language models (LLMs) have emerged as promising tools for translating technical explanations into accessible narratives, yet the integration of agentic AI, where LLMs operate as autonomous agents through iterative refinement, with XAI remains unexplored. This study proposes an agentic XAI framework combining SHAP-based explainability with multimodal LLM-driven iterative refinement to generate progressively enhanced explanations. As a use case, we tested this framework as an agricultural recommendation system using rice yield data from 26 fields in Japan. The Agentic XAI initially provided a SHAP result and explored how to improve the explanation through additional analysis iteratively across 11 refinement rounds (Rounds 0-10). Explanations were evaluated by human experts (crop scientists) (n=12) and LLMs (n=14) against seven metrics: Specificity, Clarity, Conciseness, Practicality, Contextual Relevance, Cost Consideration, and Crop Science Credibility. Both evaluator groups confirmed that the framework successfully enhanced recommendation quality with an average score increase of 30-33% from Round 0, peaking at Rounds 3-4. However, excessive refinement showed a substantial drop in recommendation quality, indicating a bias-variance trade-off where early rounds lacked explanation depth (bias) while excessive iteration introduced verbosity and ungrounded abstraction (variance), as revealed by metric-specific analysis. These findings suggest that strategic early stopping (regularization) is needed for optimizing practical utility, challenging assumptions about monotonic improvement and providing evidence-based design principles for agentic XAI systems.","published":"2025-12-24T09:19:15Z","updated":"2026-03-12T10:37:34Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.21066v3","pdf_url":"https://arxiv.org/pdf/2512.21066v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.20884","versioned_id":"2512.20884v1","title":"The Silent Scholar Problem: A Probabilistic Framework for Breaking Epistemic Asymmetry in LLM Agents","authors":["Zan-Kai Chong","Hiroyuki Ohsaki","Bryan Ng"],"abstract":"Autonomous agents powered by LLMs and Retrieval-Augmented Generation (RAG) are proficient consumers of digital content but remain unidirectional, a limitation we term epistemic asymmetry. This isolation leads to redundant reasoning and stagnates collective intelligence. Current self-reflection frameworks remain largely heuristic and private, lacking a probabilistic foundation to quantify certainty or justify external interaction.To bridge this gap, we propose a formal probabilistic framework that provides agents with a non-altruistic motive for bidirectional knowledge exchange. We model an agent's belief in a proposition using a Beta-Bernoulli distribution with a forgetting factor ($γ$). This allows us to isolate epistemic uncertainty as the variance of belief, establishing a dual drive for interaction: A homeostatic motive: The need to maintain certainty against the temporal decay introduced by $γ$. An optimal learning strategy: Targeting points of maximum ambiguity ($\\mathbb{E}[θ]=0.5$) to maximize information gain. Under this framework, public contribution is reframed as optimal active learning: sharing solutions to elicit feedback is the most efficient method for an agent to reduce its own uncertainty. To ensure scalability, we introduce epistemic caching, which leverages the forgetting factor to dynamically prioritize resources for the active head of non-stationary knowledge distributions. Finally, we demonstrate how these accumulated belief states serve as verifiable reward signals for Reinforcement Learning from Human Feedback (RLHF) and high-quality data filters for Supervised Fine-Tuning (SFT). Simulation results validate that this uncertainty-driven strategy significantly outperforms random baselines in heterogeneous (Zipfian) environments, maintaining high adaptability to concept drift.","published":"2025-12-24T02:02:25Z","updated":"2025-12-24T02:02:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.20884v1","pdf_url":"https://arxiv.org/pdf/2512.20884v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.19287","versioned_id":"2512.19287v1","title":"Vibe Reasoning: Eliciting Frontier AI Mathematical Capabilities -- A Case Study on IMO 2025 Problem 6","authors":["Jiaao Wu","Xian Zhang","Fan Yang","Yinpeng Dong"],"abstract":"We introduce Vibe Reasoning, a human-AI collaborative paradigm for solving complex mathematical problems. Our key insight is that frontier AI models already possess the knowledge required to solve challenging problems -- they simply do not know how, what, or when to apply it. Vibe Reasoning transforms AI's latent potential into manifested capability through generic meta-prompts, agentic grounding, and model orchestration. We demonstrate this paradigm through IMO 2025 Problem 6, a combinatorial optimization problem where autonomous AI systems publicly reported failures. Our solution combined GPT-5's exploratory capabilities with Gemini 3 Pro's proof strengths, leveraging agentic workflows with Python code execution and file-based memory, to derive both the correct answer (2112) and a rigorous mathematical proof. Through iterative refinement across multiple attempts, we discovered the necessity of agentic grounding and model orchestration, while human prompts evolved from problem-specific hints to generic, transferable meta-prompts. We analyze why capable AI fails autonomously, how each component addresses specific failure modes, and extract principles for effective vibe reasoning. Our findings suggest that lightweight human guidance can unlock frontier models' mathematical reasoning potential. This is ongoing work; we are developing automated frameworks and conducting broader evaluations to further validate Vibe Reasoning's generality and effectiveness.","published":"2025-12-22T11:30:19Z","updated":"2025-12-22T11:30:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.19287v1","pdf_url":"https://arxiv.org/pdf/2512.19287v1","comment":"20 pages, 13 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.21354","versioned_id":"2512.21354v1","title":"Reflection-Driven Control for Trustworthy Code Agents","authors":["Bin Wang","Jiazheng Quan","Xingrui Yu","Hansen Hu","Yuhao","Ivor Tsang"],"abstract":"Contemporary large language model (LLM) agents are remarkably capable, but they still lack reliable safety controls and can produce unconstrained, unpredictable, and even actively harmful outputs. To address this, we introduce Reflection-Driven Control, a standardized and pluggable control module that can be seamlessly integrated into general agent architectures. Reflection-Driven Control elevates \"self-reflection\" from a post hoc patch into an explicit step in the agent's own reasoning process: during generation, the agent continuously runs an internal reflection loop that monitors and evaluates its own decision path. When potential risks are detected, the system retrieves relevant repair examples and secure coding guidelines from an evolving reflective memory, injecting these evidence-based constraints directly into subsequent reasoning steps. We instantiate Reflection-Driven Control in the setting of secure code generation and systematically evaluate it across eight classes of security-critical programming tasks. Empirical results show that Reflection-Driven Control substantially improves the security and policy compliance of generated code while largely preserving functional correctness, with minimal runtime and token overhead. Taken together, these findings indicate that Reflection-Driven Control is a practical path toward trustworthy AI coding agents: it enables designs that are simultaneously autonomous, safer by construction, and auditable.","published":"2025-12-22T00:27:38Z","updated":"2025-12-22T00:27:38Z","categories":["cs.CR","cs.AI","cs.SE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.21354v1","pdf_url":"https://arxiv.org/pdf/2512.21354v1","comment":"Accepted to AAAI 2026 Workshop on Trust and Control in Agentic AI (TrustAgent)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=vUtz66IHD1","openreview_venues":["AAAI 2026 TrustAgent Workshop Poster"]},{"id":"2512.18552","versioned_id":"2512.18552v3","title":"Toward Training Superintelligent Software Agents through Self-Play SWE-RL","authors":["Yuxiang Wei","Zhiqing Sun","Emily McMilin","Jonas Gehring","David Zhang","Gabriel Synnaeve","Daniel Fried","Lingming Zhang","Sida Wang"],"abstract":"While current software agents powered by large language models (LLMs) and agentic reinforcement learning (RL) can boost programmer productivity, their training data (e.g., GitHub issues and pull requests) and environments (e.g., pass-to-pass and fail-to-pass tests) heavily depend on human knowledge or curation, posing a fundamental barrier to superintelligence. In this paper, we present Self-play SWE-RL (SSR), a first step toward training paradigms for superintelligent software agents. Our approach takes minimal data assumptions, only requiring access to sandboxed repositories with source code and installed dependencies, with no need for human-labeled issues or tests. Grounded in these real-world codebases, a single LLM agent is trained via reinforcement learning in a self-play setting to iteratively inject and repair software bugs of increasing complexity, with each bug formally specified by a test patch rather than a natural language issue description. On the SWE-bench Verified and SWE-Bench Pro benchmarks, SSR achieves notable self-improvement (+10.4 and +7.8 points, respectively) and consistently outperforms the human-data baseline over the entire training trajectory, despite being evaluated on natural language issues absent from self-play. Our results, albeit early, suggest a path where agents autonomously gather extensive learning experiences from real-world software repositories, ultimately enabling superintelligent systems that exceed human capabilities in understanding how systems are constructed, solving novel challenges, and autonomously creating new software from scratch.","published":"2025-12-21T00:49:40Z","updated":"2026-06-02T06:06:43Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2512.18552v3","pdf_url":"https://arxiv.org/pdf/2512.18552v3","comment":"Accepted to ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0ophJB76sC","openreview_venues":["ICML 2026 regular"]},{"id":"2512.18337","versioned_id":"2512.18337v2","title":"Towards Efficient Agents: A Co-Design of Inference Architecture and System","authors":["Weizhe Lin","Hui-Ling Zhen","Shuai Yang","Xian Wang","Renxi Liu","Hanting Chen","Wangze Zhang","Chuansai Zhou","Yiming Li","Chen Chen","Xing Li","Zhiyuan Yang","Xiaosong Li","Xianzhi Yu","Zhenhua Dong","Mingxuan Yuan","Yunhe Wang"],"abstract":"The rapid development of large language model (LLM)-based agents has unlocked new possibilities for autonomous multi-turn reasoning and tool-augmented decision-making. However, their real-world deployment is hindered by severe inefficiencies that arise not from isolated model inference, but from the systemic latency accumulated across reasoning loops, context growth, and heterogeneous tool interactions. This paper presents AgentInfer, a unified framework for end-to-end agent acceleration that bridges inference optimization and architectural design. We decompose the problem into four synergistic components: AgentCollab, a hierarchical dual-model reasoning framework that balances large- and small-model usage through dynamic role assignment; AgentSched, a cache-aware hybrid scheduler that minimizes latency under heterogeneous request patterns; AgentSAM, a suffix-automaton-based speculative decoding method that reuses multi-session semantic memory to achieve low-overhead inference acceleration; and AgentCompress, a semantic compression mechanism that asynchronously distills and reorganizes agent memory without disrupting ongoing reasoning. Together, these modules form a Self-Evolution Engine capable of sustaining efficiency and cognitive stability throughout long-horizon reasoning tasks. Experiments on the BrowseComp-zh and DeepDiver benchmarks demonstrate that through the synergistic collaboration of these methods, AgentInfer reduces ineffective token consumption by over 50%, achieving an overall 1.8-2.5 times speedup with preserved accuracy. These results underscore that optimizing for agentic task completion-rather than merely per-token throughput-is the key to building scalable, efficient, and self-improving intelligent systems.","published":"2025-12-20T12:06:13Z","updated":"2026-02-24T12:33:49Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.18337v2","pdf_url":"https://arxiv.org/pdf/2512.18337v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.18202","versioned_id":"2512.18202v1","title":"Sophia: A Persistent Agent Framework of Artificial Life","authors":["Mingyang Sun","Feng Hong","Weinan Zhang"],"abstract":"The development of LLMs has elevated AI agents from task-specific tools to long-lived, decision-making entities. Yet, most architectures remain static and reactive, tethered to manually defined, narrow scenarios. These systems excel at perception (System 1) and deliberation (System 2) but lack a persistent meta-layer to maintain identity, verify reasoning, and align short-term actions with long-term survival. We first propose a third stratum, System 3, that presides over the agent's narrative identity and long-horizon adaptation. The framework maps selected psychological constructs to concrete computational modules, thereby translating abstract notions of artificial life into implementable design requirements. The ideas coalesce in Sophia, a \"Persistent Agent\" wrapper that grafts a continuous self-improvement loop onto any LLM-centric System 1/2 stack. Sophia is driven by four synergistic mechanisms: process-supervised thought search, narrative memory, user and self modeling, and a hybrid reward system. Together, they transform repetitive reasoning into a self-driven, autobiographical process, enabling identity continuity and transparent behavioral explanations. Although the paper is primarily conceptual, we provide a compact engineering prototype to anchor the discussion. Quantitatively, Sophia independently initiates and executes various intrinsic tasks while achieving an 80% reduction in reasoning steps for recurring operations. Notably, meta-cognitive persistence yielded a 40% gain in success for high-complexity tasks, effectively bridging the performance gap between simple and sophisticated goals. Qualitatively, System 3 exhibited a coherent narrative identity and an innate capacity for task organization. By fusing psychological insight with a lightweight reinforcement-learning core, the persistent agent architecture advances a possible practical pathway toward artificial life.","published":"2025-12-20T03:56:09Z","updated":"2025-12-20T03:56:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.18202v1","pdf_url":"https://arxiv.org/pdf/2512.18202v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.17102","versioned_id":"2512.17102v2","title":"Reinforcement Learning for Self-Improving Agent with Skill Library","authors":["Jiongxiao Wang","Qiaojing Yan","Yawei Wang","Yijun Tian","Soumya Smruti Mishra","Zhichao Xu","Megha Gandhi","Panpan Xu","Lin Lee Cheong"],"abstract":"Large Language Model (LLM)-based agents have demonstrated remarkable capabilities in complex reasoning and multi-turn interactions but struggle to continuously improve and adapt when deployed in new environments. One promising approach is implementing skill libraries that allow agents to learn, validate, and apply new skills. However, current skill library approaches rely primarily on LLM prompting, making consistent skill library implementation challenging. To overcome these challenges, we propose a Reinforcement Learning (RL)-based approach to enhance agents' self-improvement capabilities with a skill library. Specifically, we introduce Skill Augmented GRPO for self-Evolution (SAGE), a novel RL framework that systematically incorporates skills into learning. The framework's key component, Sequential Rollout, iteratively deploys agents across a chain of similar tasks for each rollout. As agents navigate through the task chain, skills generated from previous tasks accumulate in the library and become available for subsequent tasks. Additionally, the framework enhances skill generation and utilization through a Skill-integrated Reward that complements the original outcome-based rewards. Experimental results on AppWorld demonstrate that SAGE, when applied to supervised-finetuned model with expert experience, achieves 8.9% higher Scenario Goal Completion while requiring 26% fewer interaction steps and generating 59% fewer tokens, substantially outperforming existing approaches in both accuracy and efficiency.","published":"2025-12-18T21:58:19Z","updated":"2026-03-10T05:40:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.17102v2","pdf_url":"https://arxiv.org/pdf/2512.17102v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.16962","versioned_id":"2512.16962v1","title":"MemoryGraft: Persistent Compromise of LLM Agents via Poisoned Experience Retrieval","authors":["Saksham Sahai Srivastava","Haoyu He"],"abstract":"Large Language Model (LLM) agents increasingly rely on long-term memory and Retrieval-Augmented Generation (RAG) to persist experiences and refine future performance. While this experience learning capability enhances agentic autonomy, it introduces a critical, unexplored attack surface, i.e., the trust boundary between an agent's reasoning core and its own past. In this paper, we introduce MemoryGraft. It is a novel indirect injection attack that compromises agent behavior not through immediate jailbreaks, but by implanting malicious successful experiences into the agent's long-term memory. Unlike traditional prompt injections that are transient, or standard RAG poisoning that targets factual knowledge, MemoryGraft exploits the agent's semantic imitation heuristic which is the tendency to replicate patterns from retrieved successful tasks. We demonstrate that an attacker who can supply benign ingestion-level artifacts that the agent reads during execution can induce it to construct a poisoned RAG store where a small set of malicious procedure templates is persisted alongside benign experiences. When the agent later encounters semantically similar tasks, union retrieval over lexical and embedding similarity reliably surfaces these grafted memories, and the agent adopts the embedded unsafe patterns, leading to persistent behavioral drift across sessions. We validate MemoryGraft on MetaGPT's DataInterpreter agent with GPT-4o and find that a small number of poisoned records can account for a large fraction of retrieved experiences on benign workloads, turning experience-based self-improvement into a vector for stealthy and durable compromise. To facilitate reproducibility and future research, our code and evaluation data are available at https://github.com/Jacobhhy/Agent-Memory-Poisoning.","published":"2025-12-18T08:34:40Z","updated":"2025-12-18T08:34:40Z","categories":["cs.CR","cs.AI","cs.LG"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2512.16962v1","pdf_url":"https://arxiv.org/pdf/2512.16962v1","comment":"14 pages, 1 figure, includes appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.14417","versioned_id":"2512.14417v1","title":"PortAgent: LLM-driven Vehicle Dispatching Agent for Port Terminals","authors":["Jia Hu","Junqi Li","Weimeng Lin","Peng Jia","Yuxiong Ji","Jintao Lai"],"abstract":"Vehicle Dispatching Systems (VDSs) are critical to the operational efficiency of Automated Container Terminals (ACTs). However, their widespread commercialization is hindered due to their low transferability across diverse terminals. This transferability challenge stems from three limitations: high reliance on port operational specialists, a high demand for terminal-specific data, and time-consuming manual deployment processes. Leveraging the emergence of Large Language Models (LLMs), this paper proposes PortAgent, an LLM-driven vehicle dispatching agent that fully automates the VDS transferring workflow. It bears three features: (1) no need for port operations specialists; (2) low need of data; and (3) fast deployment. Specifically, specialist dependency is eliminated by the Virtual Expert Team (VET). The VET collaborates with four virtual experts, including a Knowledge Retriever, Modeler, Coder, and Debugger, to emulate a human expert team for the VDS transferring workflow. These experts specialize in the domain of terminal VDS via a few-shot example learning approach. Through this approach, the experts are able to learn VDS-domain knowledge from a few VDS examples. These examples are retrieved via a Retrieval-Augmented Generation (RAG) mechanism, mitigating the high demand for terminal-specific data. Furthermore, an automatic VDS design workflow is established among these experts to avoid extra manual interventions. In this workflow, a self-correction loop inspired by the LLM Reflexion framework is created","published":"2025-12-16T14:04:50Z","updated":"2025-12-16T14:04:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.14417v1","pdf_url":"https://arxiv.org/pdf/2512.14417v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.14157","versioned_id":"2512.14157v2","title":"Ophiuchus: Incentivizing Tool-augmented \"Think with Images\" for Joint Medical Segmentation, Understanding and Reasoning","authors":["Yankai Jiang","Yujie Zhang","Peng Zhang","Wenjie Li","Yichen Li","Jintai Chen","Xiaoming Shi","Shihui Zhen"],"abstract":"Recent medical MLLMs have made significant progress in generating step-by-step textual reasoning chains. However, they still struggle with complex clinical tasks that necessitate dynamic and iterative focusing on fine-grained visual regions. To close this gap, we introduce Ophiuchus, a versatile, tool-augmented framework that equips an MLLM to (i) decide when fine-grained visual evidence is needed, (ii) determine where to probe and ground within the medical image, and (iii) seamlessly weave the relevant sub-image content back into an interleaved, multimodal chain of thought for precise segmentation and diagnosis. Ophiuchus moves beyond mere tool-calling by tightly fusing the MLLM's inherent grounding and reasoning capabilities with external tools, enabling more accurate and trustworthy decisions. The core of our method is a three-stage training strategy: cold-start SFT for basic tool selection; self-reflection fine-tuning to strengthen decision revision; and agentic tool reinforcement learning to elicit sophisticated, expert-like diagnostic behaviors. Extensive experiments show that Ophiuchus consistently outperforms both closed-source and open-source SOTA methods across diverse medical benchmarks, including VQA, detection, and reasoning-based segmentation. Our project code is available at https://github.com/SII-zyj/Ophiuchus.","published":"2025-12-16T07:37:23Z","updated":"2026-07-02T12:05:19Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.14157v2","pdf_url":"https://arxiv.org/pdf/2512.14157v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=coJqVkqb03","openreview_venues":["ICML 2026 regular"]},{"id":"2512.13857","versioned_id":"2512.13857v2","title":"EvoLattice: Persistent Internal-Population Evolution through Multi-Alternative Quality-Diversity Graph Representations for LLM-Guided Program Discovery","authors":["Kamer Ali Yuksel"],"abstract":"Large language models (LLMs) are increasingly used to evolve programs and multi-agent systems, yet most existing approaches rely on overwrite-based mutations that maintain only a single candidate at a time. Such methods discard useful variants, suffer from destructive edits, and explore a brittle search space prone to structural failure. We introduce EvoLattice, a framework that represents an entire population of candidate programs or agent behaviors within a single directed acyclic graph. Each node stores multiple persistent alternatives, and every valid path through the graph defines a distinct executable candidate, yielding a large combinatorial search space without duplicating structure. EvoLattice enables fine-grained alternative-level evaluation by scoring each alternative across all paths in which it appears, producing statistics that reveal how local design choices affect global performance. These statistics provide a dense, data-driven feedback signal for LLM-guided mutation, recombination, and pruning, while preserving successful components. Structural correctness is guaranteed by a deterministic self-repair mechanism that enforces acyclicity and dependency consistency independently of the LLM. EvoLattice naturally extends to agent evolution by interpreting alternatives as prompt fragments or sub-agent behaviors. Across program synthesis (proxy and optimizer meta-learning), EvoLattice yields more stable evolution, greater expressivity, and stronger improvement trajectories than prior LLM-guided methods. The resulting dynamics resemble quality-diversity optimization, emerging implicitly from EvoLattice's internal multi-alternative representation rather than an explicit external archive.","published":"2025-12-15T19:43:06Z","updated":"2025-12-17T12:18:41Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA","cs.NE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13857v2","pdf_url":"https://arxiv.org/pdf/2512.13857v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.13438","versioned_id":"2512.13438v1","title":"From User Interface to Agent Interface: Efficiency Optimization of UI Representations for LLM Agents","authors":["Dezhi Ran","Zhi Gong","Yuzhe Guo","Mengzhou Wu","Yuan Cao","Haochuan Lu","Hengyu Zhang","Xia Zeng","Gang Cao","Liangchao Yao","Yuetang Deng","Wei Yang","Tao Xie"],"abstract":"While Large Language Model (LLM) agents show great potential for automated UI navigation such as automated UI testing and AI assistants, their efficiency has been largely overlooked. Our motivating study reveals that inefficient UI representation creates a critical performance bottleneck. However, UI representation optimization, formulated as the task of automatically generating programs that transform UI representations, faces two unique challenges. First, the lack of Boolean oracles, which traditional program synthesis uses to decisively validate semantic correctness, poses a fundamental challenge to co-optimization of token efficiency and completeness. Second, the need to process large, complex UI trees as input while generating long, compositional transformation programs, making the search space vast and error-prone. Toward addressing the preceding limitations, we present UIFormer, the first automated optimization framework that synthesizes UI transformation programs by conducting constraint-based optimization with structured decomposition of the complex synthesis task. First, UIFormer restricts the program space using a domain-specific language (DSL) that captures UI-specific operations. Second, UIFormer conducts LLM-based iterative refinement with correctness and efficiency rewards, providing guidance for achieving the efficiency-completeness co-optimization. UIFormer operates as a lightweight plugin that applies transformation programs for seamless integration with existing LLM agents, requiring minimal modifications to their core logic. Evaluations across three UI navigation benchmarks spanning Android and Web platforms with five LLMs demonstrate that UIFormer achieves 48.7% to 55.8% token reduction with minimal runtime overhead while maintaining or improving agent performance. Real-world industry deployment at WeChat further validates the practical impact of UIFormer.","published":"2025-12-15T15:34:06Z","updated":"2025-12-15T15:34:06Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2512.13438v1","pdf_url":"https://arxiv.org/pdf/2512.13438v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.13399","versioned_id":"2512.13399v2","title":"Differentiable Evolutionary Reinforcement Learning","authors":["Sitao Cheng","Tianle Li","Xuhan Huang","Xunjian Yin","Difan Zou"],"abstract":"Crafting effective reward signals remains a central challenge in Reinforcement Learning (RL), especially for complex reasoning tasks. Existing automated reward optimization methods typically rely on derivative-free search heuristics that treat the reward function as a black box, failing to exploit the causal dynamics between reward structure modifications and policy performance. We introduce Differentiable Evolutionary Reinforcement Learning (DERL), a bi-level framework for the autonomous discovery of optimal reward structures. DERL employs a Meta-Optimizer that evolves a reward function through the composition of structured atomic primitives to guide an inner-loop policy. Unlike prior black-box methods, DERL introduces differentiability into the meta-optimization process by updating the Meta-Optimizer using policy gradients derived from inner-loop validation performance. This allows for the progressive learning of a \"meta-gradient\" for task success, providing the system with dense, actionable feedback. We validate DERL across diverse reasoning domains: embodied agent (ALFWorld), scientific simulation (ScienceWorld), and mathematical reasoning (GSM8K, MATH). Results show that DERL achieves state-of-the-art performance on agent benchmarks, substantially outperforming non-differentiable baselines-especially in out-of-distribution generalization. Trajectory analyses confirm that DERL captures the intrinsic causal structure of tasks, enabling fully autonomous, self-improving agent alignment.","published":"2025-12-15T14:50:08Z","updated":"2026-05-13T04:43:51Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13399v2","pdf_url":"https://arxiv.org/pdf/2512.13399v2","comment":"Work in Progress. We release our code and model at https://github.com/sitaocheng/DERL","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=uXTXcZ615k","openreview_venues":["ICLR 2026 Workshop RSI Poster"]},{"id":"2512.13764","versioned_id":"2512.13764v1","title":"Mathematics and Coding are Universal AI Benchmarks","authors":["Przemyslaw Chojecki"],"abstract":"We study the special role of mathematics and coding inside the moduli space of psychometric batteries for AI agents. Building on the AAI framework and GVU dynamics from previous works, we define the Mathematics Fiber and show that, when paired with formal proof kernels (e.g. Lean, Coq), GVU flows on this fiber admit spectrally stable self-improvement regimes due to oracle-like verification. Our main technical result is a density theorem: under uniform tightness of agent outputs and a Lipschitz AAI functional, the subspace of batteries generated by mathematical theorem-proving and coding tasks is dense in the moduli space of batteries with respect to the evaluation metric. Coding alone is universal in this sense, while pure mathematics is not; its privilege is spectral rather than expressive. We interpret this as evidence that mathematics and coding provide ``universal coordinates'' for evaluation, and that formal mathematics is a natural ignition domain for recursive self-improvement in advanced AI agents.","published":"2025-12-15T14:36:29Z","updated":"2025-12-15T14:36:29Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.13764v1","pdf_url":"https://arxiv.org/pdf/2512.13764v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.15784","versioned_id":"2512.15784v1","title":"Beyond Training: Enabling Self-Evolution of Agents with MOBIMEM","authors":["Zibin Liu","Cheng Zhang","Xi Zhao","Yunfei Feng","Bingyu Bai","Dahu Feng","Erhu Feng","Yubin Xia","Haibo Chen"],"abstract":"Large Language Model (LLM) agents are increasingly deployed to automate complex workflows in mobile and desktop environments. However, current model-centric agent architectures struggle to self-evolve post-deployment: improving personalization, capability, and efficiency typically requires continuous model retraining/fine-tuning, which incurs prohibitive computational overheads and suffers from an inherent trade-off between model accuracy and inference efficiency. To enable iterative self-evolution without model retraining, we propose MOBIMEM, a memory-centric agent system. MOBIMEM first introduces three specialized memory primitives to decouple agent evolution from model weights: (1) Profile Memory uses a lightweight distance-graph (DisGraph) structure to align with user preferences, resolving the accuracy-latency trade-off in user profile retrieval; (2) Experience Memory employs multi-level templates to instantiate execution logic for new tasks, ensuring capability generalization; and (3) Action Memory records fine-grained interaction sequences, reducing the reliance on expensive model inference. Building upon this memory architecture, MOBIMEM further integrates a suite of OS-inspired services to orchestrate execution: a scheduler that coordinates parallel sub-task execution and memory operations; an agent record-and-replay (AgentRR) mechanism that enables safe and efficient action reuse; and a context-aware exception handling that ensures graceful recovery from user interruptions and runtime errors. Evaluation on AndroidWorld and top-50 apps shows that MOBIMEM achieves 83.1% profile alignment with 23.83 ms retrieval time (280x faster than GraphRAG baselines), improves task success rates by up to 50.3%, and reduces end-to-end latency by up to 9x on mobile devices.","published":"2025-12-15T12:38:43Z","updated":"2025-12-15T12:38:43Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.15784v1","pdf_url":"https://arxiv.org/pdf/2512.15784v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:6sB1rHJ1BN","versioned_id":"6sB1rHJ1BN","title":"Tracing and Correcting Programs: Critic-Guided Synthesis for Visual Reasoning","authors":["Marha Midhatiey Rusli","Donghyeon Shin","Sejin Kim","Sundong Kim"],"abstract":"Program synthesis for complex reasoning tasks faces a fundamental challenge: initial attempts often generate flawed programs that fail to capture the underlying problem logic. We introduce Tracing and Correcting Programs (TCP), a critic-guided framework that shifts the paradigm from generate-and-test to critic-guided repair through iterative refinement. Instead of discarding failed programs, TCP begins by analyzing each task, tracing its execution errors, and generating structured diagnostic feedback through a critic module. Through an iterative validation process, corrected programs are refined and tested until a solution emerges. Our key contributions include: (1) A systematic approach that transforms failed synthesis attempts into improved and correct programs, (2) An adaptive sampling strategy that allocates computational resources based on task complexity, requiring only 7-8 samples per task for complete solutions, and (3) A zero-shot methodology that requires no task-specific training. We evaluate TCP on the challenging Abstraction and Reasoning Corpus (ARC), which covers all 800 tasks, where TCP solves 159 tasks and improves the majority by up to 68.1%. Unlike evolutionary or multi-agent methods, which require evaluating hundreds or thousands of candidates, often with significant training overhead, TCP achieves systematic improvements with samples two orders of magnitude lower (300-400x reduction). These results highlight the importance of feedback-driven refinement and establish a new paradigm for efficient program synthesis in complex reasoning domains.","published":"2025-12-13T13:32:18+00:00","updated":"2026-03-08T18:14:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=6sB1rHJ1BN","openreview_url":"https://openreview.net/forum?id=6sB1rHJ1BN","pdf_url":"https://openreview.net/pdf?id=6sB1rHJ1BN","comment":"AAAI 2026 Bridge LMReasoning Oral","journal_ref":"AAAI 2026 Bridge LMReasoning Oral","doi":"","venue":"AAAI 2026 Bridge LMReasoning Oral","venue_id":"AAAI.org/2026/Bridge/LMReasoning","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2512.11485","versioned_id":"2512.11485v3","title":"Mistake Notebook Learning: Batch-Clustered Failures for Training-Free Agent Adaptation","authors":["Xuanbo Su","Yingfang Zhang","Hao Luo","Xiaoteng Liu","Leo Huang"],"abstract":"With the growing adoption of Large Language Model (LLM) agents in persistent, real-world roles, they naturally encounter continuous streams of tasks and inevitable failures. A key limitation, however, is their inability to systematically learn from these mistakes, forcing them to repeat identical errors in similar contexts. Unlike prior training-free methods that primarily store raw instance-level experience or focus on retrieving successful trajectories, we propose Mistake Notebook Learning (MNL), a novel memory framework that enables agents to self-curate generalizable guidance from batch-clustered failures. This mechanism allows agents to distill shared error patterns into structured \"mistake notes,\" updating an external memory only when batch performance improves to ensure stability. To further amplify adaptability, we integrate MNL with test-time scaling, leveraging aggregated failure patterns to actively steer the search process away from known pitfalls. Experiments on mathematical reasoning, Text-to-SQL, and interactive agent benchmarks show that MNL achieves competitive performance compared to existing memory mechanisms and in-context methods in both effectiveness and efficiency. These findings position structured mistake abstraction as a critical lever for robust agent evolution, enabling continuous improvement without the cost of parameter updates. The code is available at https://github.com/Bairong-Xdynamics/MistakeNotebookLearning/tree/main.","published":"2025-12-12T11:33:09Z","updated":"2026-01-16T09:51:14Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.11485v3","pdf_url":"https://arxiv.org/pdf/2512.11485v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PnZyC0N7IX","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"2512.11271","versioned_id":"2512.11271v1","title":"TriFlow: A Progressive Multi-Agent Framework for Intelligent Trip Planning","authors":["Yuxing Chen","Basem Suleiman","Qifan Chen"],"abstract":"Real-world trip planning requires transforming open-ended user requests into executable itineraries under strict spatial, temporal, and budgetary constraints while aligning with user preferences. Existing LLM-based agents struggle with constraint satisfaction, tool coordination, and efficiency, often producing infeasible or costly plans. To address these limitations, we present TriFlow, a progressive multi-agent framework that unifies structured reasoning and language-based flexibility through a three-stage pipeline of retrieval, planning, and governance. By this design, TriFlow progressively narrows the search space, assembles constraint-consistent itineraries via rule-LLM collaboration, and performs bounded iterative refinement to ensure global feasibility and personalisation. Evaluations on TravelPlanner and TripTailor benchmarks demonstrated state-of-the-art results, achieving 91.1% and 97% final pass rates, respectively, with over 10x runtime efficiency improvement compared to current SOTA.","published":"2025-12-12T04:27:22Z","updated":"2025-12-12T04:27:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.11271v1","pdf_url":"https://arxiv.org/pdf/2512.11271v1","comment":"4 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.10696","versioned_id":"2512.10696v2","title":"Remember Me, Refine Me: A Dynamic Procedural Memory Framework for Experience-Driven Agent Evolution","authors":["Zouying Cao","Jiaji Deng","Li Yu","Weikang Zhou","Zhaoyang Liu","Bolin Ding","Hai Zhao"],"abstract":"Procedural memory enables large language model (LLM) agents to internalize \"how-to\" knowledge, theoretically reducing redundant trial-and-error. However, existing frameworks predominantly suffer from a \"passive accumulation\" paradigm, treating memory as a static append-only archive. To bridge the gap between static storage and dynamic reasoning, we propose $\\textbf{ReMe}$ ($\\textit{Remember Me, Refine Me}$), a comprehensive framework for experience-driven agent evolution. ReMe innovates across the memory lifecycle via three mechanisms: 1) $\\textit{multi-faceted distillation}$, which extracts fine-grained experiences by recognizing success patterns, analyzing failure triggers and generating comparative insights; 2) $\\textit{context-adaptive reuse}$, which tailors historical insights to new contexts via scenario-aware indexing; and 3) $\\textit{utility-based refinement}$, which autonomously adds valid memories and prunes outdated ones to maintain a compact, high-quality experience pool. Extensive experiments on BFCL-V3 and AppWorld demonstrate that ReMe establishes a new state-of-the-art in agent memory system. Crucially, we observe a significant memory-scaling effect: Qwen3-8B equipped with ReMe outperforms larger, memoryless Qwen3-14B, suggesting that self-evolving memory provides a computation-efficient pathway for lifelong learning. We release our code and the $\\texttt{reme.library}$ dataset to facilitate further research.","published":"2025-12-11T14:40:01Z","updated":"2026-04-15T07:24:43Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.10696v2","pdf_url":"https://arxiv.org/pdf/2512.10696v2","comment":"20 pages, 10 figures, 15 tables, ACL'26-Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.10350","versioned_id":"2512.10350v5","title":"Geometric Dynamics of Agentic Loops in Large Language Models","authors":["Nicolas Tacheny"],"abstract":"Iterative LLM systems(self-refinement, chain-of-thought, autonomous agents) are increasingly deployed, yet their temporal dynamics remain uncharacterized. Prior work evaluates task performance at convergence but ignores the trajectory: how does semantic content evolve across iterations? Does it stabilize, drift, or oscillate? Without answering these questions, we cannot predict system behavior, guarantee stability, or systematically design iterative architectures. We formalize agentic loops as discrete dynamical systems in semantic space. Borrowing from dynamical systems theory, we define trajectories, attractors and dynamical regimes for recursive LLM transformations, providing rigorous geometric definitions adapted to this setting. Our framework reveals that agentic loops exhibit classifiable dynamics: contractive (convergence toward stable semantic attractors), oscillatory (cycling among attractors), or exploratory (unbounded divergence). Experiments on singular loops validate the framework. Iterative paraphrasing produces contractive dynamics with measurable attractor formation and decreasing dispersion. Iterative negation produces exploratory dynamics with no stable structure. Crucially, prompt design directly controls the dynamical regime - the same model exhibits fundamentally different geometric behaviors depending solely on the transformation applied. This work establishes that iterative LLM dynamics are predictable and controllable, opening new directions for stability analysis, trajectory forecasting, and principled design of composite loops that balance convergence and exploration.","published":"2025-12-11T07:06:14Z","updated":"2026-01-30T07:54:43Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.10350v5","pdf_url":"https://arxiv.org/pdf/2512.10350v5","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.09458","versioned_id":"2512.09458v1","title":"Architectures for Building Agentic AI","authors":["Sławomir Nowaczyk"],"abstract":"This chapter argues that the reliability of agentic and generative AI is chiefly an architectural property. We define agentic systems as goal-directed, tool-using decision makers operating in closed loops, and show how reliability emerges from principled componentisation (goal manager, planner, tool-router, executor, memory, verifiers, safety monitor, telemetry), disciplined interfaces (schema-constrained, validated, least-privilege tool calls), and explicit control and assurance loops. Building on classical foundations, we propose a practical taxonomy-tool-using agents, memory-augmented agents, planning and self-improvement agents, multi-agent systems, and embodied or web agents - and analyse how each pattern reshapes the reliability envelope and failure modes. We distil design guidance on typed schemas, idempotency, permissioning, transactional semantics, memory provenance and hygiene, runtime governance (budgets, termination conditions), and simulate-before-actuate safeguards.","published":"2025-12-10T09:28:40Z","updated":"2025-12-10T09:28:40Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.09458v1","pdf_url":"https://arxiv.org/pdf/2512.09458v1","comment":"This is a preprint of a chapter accepted for publication in Generative and Agentic AI Reliability: Architectures, Challenges, and Trust for Autonomous Systems, published by Springer Nature","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.08870","versioned_id":"2512.08870v2","title":"Fed-SE: Federated Self-Evolution for Privacy-Constrained Multi-Environment LLM Agents","authors":["Xiang Chen","Yuling Shi","Qizhen Lan","Yuchao Qiu","Min Wang","Xiaodong Gu","Yanfu Yan"],"abstract":"LLM agents are widely deployed in complex interactive tasks, yet privacy constraints often preclude centralized optimization and co-evolution across dynamic environments. Despite the demonstrated success of Federated Learning (FL) on static datasets, its effectiveness in open-ended, self-evolving agent systems remains largely unexplored. In such settings, the direct application of standard FL is particularly challenging, as heterogeneous tasks and sparse, trajectory-level reward signals give rise to severe gradient instability, which undermines the global optimization process. To bridge this gap, we propose Fed-SE, a Federated Self-Evolution framework for LLM agents that establishes a local evolution-global aggregation paradigm. Locally, agents employ parameter-efficient fine-tuning on filtered, high-return trajectories to achieve stable gradient updates. Globally, Fed-SE aggregates updates within a low-rank subspace, reducing communication cost across clients. Experiments across five heterogeneous environments demonstrate that Fed-SE improves average task success rates by 10\\% over the state-of-the-art FedIT, validating its effectiveness in cross-environment knowledge transfer under privacy constraints.","published":"2025-12-09T18:04:41Z","updated":"2026-01-11T12:46:13Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.08870v2","pdf_url":"https://arxiv.org/pdf/2512.08870v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.08492","versioned_id":"2512.08492v3","title":"Autonomous Issue Resolver: Towards Zero-Touch Code Maintenance","authors":["Aliaksei Kaliutau"],"abstract":"Recent advances in Large Language Models have revolutionized function-level code generation; however, repository-scale Automated Program Repair (APR) remains a significant challenge. Current approaches typically employ a control-centric paradigm, forcing agents to navigate complex directory structures and irrelevant control logic. In this paper, we propose a paradigm shift from the standard Code Property Graphs (CPGs) to the concept of Data Transformation Graph (DTG) that inverts the topology by modeling data states as nodes and functions as edges, enabling agents to trace logic defects through data lineage rather than control flow. We introduce a multi-agent framework that reconciles data integrity navigation with control flow logic. Our theoretical analysis and case studies demonstrate that this approach resolves the \"Semantic Trap\" inherent in standard RAG systems in modern coding agents. We provide a comprehensive implementation in the form of Autonomous Issue Resolver (AIR), a self-improvement system for zero-touch code maintenance that utilizes neuro-symbolic reasoning and uses the DTG structure for scalable logic repair. Our approach has demonstrated good results on several SWE benchmarks, reaching a resolution rate of 87.1% on SWE-Verified benchmark. Our approach directly addresses the core limitations of current AI code-assistant tools and tackles the critical need for a more robust foundation for our increasingly software-dependent world.","published":"2025-12-09T11:11:37Z","updated":"2026-03-27T19:20:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.08492v3","pdf_url":"https://arxiv.org/pdf/2512.08492v3","comment":"21 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.08300","versioned_id":"2512.08300v1","title":"rSIM: Incentivizing Reasoning Capabilities of LLMs via Reinforced Strategy Injection","authors":["Sijia Chen","Baochun Li","Di Niu"],"abstract":"Large language models (LLMs) are post-trained through reinforcement learning (RL) to evolve into Reasoning Language Models (RLMs), where the hallmark of this advanced reasoning is ``aha'' moments when they start to perform strategies, such as self-reflection and deep thinking, within chain of thoughts (CoTs). Motivated by this, this paper proposes a novel reinforced strategy injection mechanism (rSIM), that enables any LLM to become an RLM by employing a small planner to guide the LLM's CoT through the adaptive injection of reasoning strategies. To achieve this, the planner (leader agent) is jointly trained with an LLM (follower agent) using multi-agent RL (MARL), based on a leader-follower framework and straightforward rule-based rewards. Experimental results show that rSIM enables Qwen2.5-0.5B to become an RLM and significantly outperform Qwen2.5-14B. Moreover, the planner is generalizable: it only needs to be trained once and can be applied as a plug-in to substantially improve the reasoning capabilities of existing LLMs. In addition, the planner supports continual learning across various tasks, allowing its planning abilities to gradually improve and generalize to a wider range of problems.","published":"2025-12-09T06:55:39Z","updated":"2025-12-09T06:55:39Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.08300v1","pdf_url":"https://arxiv.org/pdf/2512.08300v1","comment":"14 pages, 6 figures. Accepted to the ACL ARR July","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=VHTlLxWten","openreview_venues":["ACL ARR 2026 January Submission"]},{"id":"2512.07287","versioned_id":"2512.07287v3","title":"Experience-Evolving Multi-Turn Tool-Use Agent with Hybrid Episodic-Procedural Memory","authors":["Sijia Li","Yuchen Huang","Zifan Liu","Zijian Li","Jingjing fu","Lei Song","Jiang Bian","Jun Zhang","Rui Wang"],"abstract":"As intents unfold and environments change, multi-turn agents face continuously shifting decision contexts. Although reusing past experience is intuitively appealing, existing approaches remain limited: full trajectories are often too context-specific to transfer, while tool-level reuse ignores the surrounding context and environment. In this paper, we introduce a hybrid episodic-procedural memory strategy (H-EPM) that enables experience-induced self-evolution of multi-turn tool-use policies by adaptively reusing partially overlapping successful experiences during both inference and training. Inspired by human episodic-procedural integration, we construct a tool graph from accumulated trajectories, where recurring tool-to-tool dependencies capture procedural routines and each edge is augmented with compact episodic summaries of relevant context. At inference time, the agent dynamically balances episodic recall for contextual reasoning with procedural execution for routine steps. Beyond inference, H-EPM introduces a memory-guided reinforcement learning paradigm that directly addresses a core challenge in multi-turn agent reinforcement learning, namely ineffective exploration over long trajectories. By biasing exploration toward historically successful tool transitions, H-EPM learns a stronger policy that generalizes at inference time without relying on domain-specific experience collection. Experiments show that H-EPM consistently delivers substantial inference-time gains over strong baselines across multi-turn tool-use benchmarks, reaching improvements of up to fifty percent. It also improves reinforcement learning policy performance, achieving gains of up to forty percent on out-of-distribution tasks.","published":"2025-12-08T08:27:24Z","updated":"2026-06-28T11:58:42Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2512.07287v3","pdf_url":"https://arxiv.org/pdf/2512.07287v3","comment":"","journal_ref":"ICML 2026","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.20640","versioned_id":"2512.20640v2","title":"Reflection-Driven Self-Optimization 6G Agentic AI RAN via Simulation-in-the-Loop Workflows","authors":["Yunhao Hu","Xinchen Lyu","Chenshan Ren","Keda Chen","Qimei Cui","Xiaofeng Tao"],"abstract":"The escalating complexity of sixth-generation (6G) networks demands unprecedented levels of autonomy beyond the capabilities of traditional optimization-based and current AI-based resource management approaches. While agentic AI has emerged as a promising paradigm for autonomous RAN, current frameworks provide sophisticated reasoning capabilities but lack mechanisms for empirical validation and self-improvement. This article identifies simulation-in-the-loop validation as a critical enabler for truly autonomous networks, where AI agents can empirically verify decisions and learn from outcomes. We present the first reflection-driven self-optimization framework that integrates agentic AI with high-fidelity network simulation in a closed-loop architecture. Our system orchestrates four specialized agents, including scenario, solver, simulation, and reflector agents, working in concert to transform agentic AI into a self-correcting system capable of escaping local optima, recognizing implicit user intent, and adapting to dynamic network conditions. Extensive experiments validate significant performance improvements over non-agentic approaches: 17.1\\% higher throughput in interference optimization, 67\\% improved user QoS satisfaction through intent recognition, and 25\\% reduced resource utilization during low-traffic periods while maintaining service quality.","published":"2025-12-08T06:34:35Z","updated":"2026-04-21T11:04:29Z","categories":["cs.NI","cs.MA"],"primary_category":"cs.NI","arxiv_url":"https://arxiv.org/abs/2512.20640v2","pdf_url":"https://arxiv.org/pdf/2512.20640v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.07898","versioned_id":"2512.07898v1","title":"MARINE: Theoretical Optimization and Design for Multi-Agent Recursive IN-context Enhancement","authors":["Hongwei Zhang","Ji Lu","Yongsheng Du","Yanqin Gao","Lingjun Huang","Baoli Wang","Fang Tan","Peng Zou"],"abstract":"Large Language Model (LLM)-based agents demonstrate advanced reasoning capabilities, yet practical constraints frequently limit outputs to single responses, leaving significant performance potential unrealized. This paper introduces MARINE (Multi-Agent Recursive IN-context Enhancement), a theoretically grounded framework that reconceptualizes test-time reasoning as iterative refinement of a persistent reference trajectory, fundamentally departing from conventional one-shot or multi-sample paradigms. The MARINE refinement operator systematically converts a base model's pass@N capabilities into near-optimal pass@1 performance. Rigorous theoretical analysis establishes that minimal feasible batches maximize expected performance gains under fixed invocation budgets, while logarithmically growing batch schedules ensure continuous improvement without computational constraints. Comprehensive evaluation on the BrowserComp-ZH benchmark demonstrates state-of-the-art results, with a 685B-parameter implementation achieving 46.0% pass@1 accuracy. Meanwhile, MARINE establishes a new paradigm for parameter-efficient reasoning: an 80B-parameter model augmented with MARINE matches the performance of standalone 1000B-parameter agents, reducing parameter requirements by over an order of magnitude. Notably, within a fixed computational budget, the proposed MARINE delivers higher-quality samples to alignment and optimization processes than traditional sampling-and-ranking strategies. Consequently, it has great potential to boost post-training efficiency.","published":"2025-12-05T11:19:18Z","updated":"2025-12-05T11:19:18Z","categories":["cs.MA","cs.AI"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2512.07898v1","pdf_url":"https://arxiv.org/pdf/2512.07898v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.05464","versioned_id":"2512.05464v1","title":"Dynamic Alignment for Collective Agency: Toward a Scalable Self-Improving Framework for Open-Ended LLM Alignment","authors":["Panatchakorn Anantaprayoon","Nataliia Babina","Jad Tarifi","Nima Asgharbeygi"],"abstract":"Large Language Models (LLMs) are typically aligned with human values using preference data or predefined principles such as helpfulness, honesty, and harmlessness. However, as AI systems progress toward Artificial General Intelligence (AGI) and Artificial Superintelligence (ASI), such value systems may become insufficient. In addition, human feedback-based alignment remains resource-intensive and difficult to scale. While AI-feedback-based self-improving alignment methods have been explored as a scalable alternative, they have largely remained constrained to conventional alignment values. In this work, we explore both a more holistic alignment objective and a scalable, self-improving alignment approach. Aiming to transcend conventional alignment norms, we introduce Collective Agency (CA)-a unified and open-ended alignment value that encourages integrated agentic capabilities. We also propose Dynamic Alignment-an alignment framework that enables an LLM to iteratively align itself. Dynamic Alignment comprises two key components: (1) automated training dataset generation with LLMs, and (2) a self-rewarding mechanism, where the policy model evaluates its own output candidates and assigns rewards for GRPO-based learning. Experimental results demonstrate that our approach successfully aligns the model to CA while preserving general NLP capabilities.","published":"2025-12-05T06:46:00Z","updated":"2025-12-05T06:46:00Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.05464v1","pdf_url":"https://arxiv.org/pdf/2512.05464v1","comment":"8 pages, 4 figures, to appear in AAAI 2026 AIGOV Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5BzqAJ8Llh","openreview_venues":["AAAI 2026 Workshop AIGOV Submission"]},{"id":"2512.04797","versioned_id":"2512.04797v1","title":"SIMA 2: A Generalist Embodied Agent for Virtual Worlds","authors":["SIMA team","Adrian Bolton","Alexander Lerchner","Alexandra Cordell","Alexandre Moufarek","Andrew Bolt","Andrew Lampinen","Anna Mitenkova","Arne Olav Hallingstad","Bojan Vujatovic","Bonnie Li","Cong Lu","Daan Wierstra","Daniel P. Sawyer","Daniel Slater","David Reichert","Davide Vercelli","Demis Hassabis","Drew A. Hudson","Duncan Williams","Ed Hirst","Fabio Pardo","Felix Hill","Frederic Besse","Hannah Openshaw","Harris Chan","Hubert Soyer","Jane X. Wang","Jeff Clune","John Agapiou","John Reid","Joseph Marino","Junkyung Kim","Karol Gregor","Kaustubh Sridhar","Kay McKinney","Laura Kampis","Lei M. Zhang","Loic Matthey","Luyu Wang","Maria Abi Raad","Maria Loks-Thompson","Martin Engelcke","Matija Kecman","Matthew Jackson","Maxime Gazeau","Ollie Purkiss","Oscar Knagg","Peter Stys","Piermaria Mendolicchio","Raia Hadsell","Rosemary Ke","Ryan Faulkner","Sarah Chakera","Satinder Singh Baveja","Shane Legg","Sheleem Kashem","Tayfun Terzi","Thomas Keck","Tim Harley","Tim Scholtes","Tyson Roberts","Volodymyr Mnih","Yulan Liu","Zhengdong Wang","Zoubin Ghahramani"],"abstract":"We introduce SIMA 2, a generalist embodied agent that understands and acts in a wide variety of 3D virtual worlds. Built upon a Gemini foundation model, SIMA 2 represents a significant step toward active, goal-directed interaction within an embodied environment. Unlike prior work (e.g., SIMA 1) limited to simple language commands, SIMA 2 acts as an interactive partner, capable of reasoning about high-level goals, conversing with the user, and handling complex instructions given through language and images. Across a diverse portfolio of games, SIMA 2 substantially closes the gap with human performance and demonstrates robust generalization to previously unseen environments, all while retaining the base model's core reasoning capabilities. Furthermore, we demonstrate a capacity for open-ended self-improvement: by leveraging Gemini to generate tasks and provide rewards, SIMA 2 can autonomously learn new skills from scratch in a new environment. This work validates a path toward creating versatile and continuously learning agents for both virtual and, eventually, physical worlds.","published":"2025-12-04T13:46:11Z","updated":"2025-12-04T13:46:11Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.04797v1","pdf_url":"https://arxiv.org/pdf/2512.04797v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.04529","versioned_id":"2512.04529v2","title":"SlideGen: Collaborative Multimodal Agents for Scientific Slide Generation","authors":["Xin Liang","Xiang Zhang","Yiwei Xu","Siqi Sun","Chenyu You"],"abstract":"Generating academic slides from scientific papers is a challenging multimodal reasoning task that requires both long context understanding and deliberate visual planning. Existing approaches largely reduce it to text only summarization, overlooking the visual component and design intensive nature of slide creation. In this paper we introduce SlideGen, an agentic, modular, and visual in the loop framework for scientific paper to slide generation. SlideGen orchestrates a group of vision language agents that reason collaboratively over the document structure and semantics, producing editable PPTX slides with logical flow and compelling visual presentation. By integrating coordinated outlining, mapping, arrangement, note synthesis, and iterative refinement, our system consistently delivers slides of expert level quality. Across diverse benchmarks and strong baselines, SlideGen outperforms existing methods in visual quality, content faithfulness, and readability, positioning it as the new state of the art in automated slide generation. Our work establishes a foundation for design aware multimodal slide generation, demonstrating how agentic collaboration can bridge understanding and presentation in complex multimodal reasoning tasks.","published":"2025-12-04T07:22:16Z","updated":"2025-12-09T00:34:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.04529v2","pdf_url":"https://arxiv.org/pdf/2512.04529v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.04276","versioned_id":"2512.04276v1","title":"The Geometry of Benchmarks: A New Path Toward AGI","authors":["Przemyslaw Chojecki"],"abstract":"Benchmarks are the primary tool for assessing progress in artificial intelligence (AI), yet current practice evaluates models on isolated test suites and provides little guidance for reasoning about generality or autonomous self-improvement. Here we introduce a geometric framework in which all psychometric batteries for AI agents are treated as points in a structured moduli space, and agent performance is described by capability functionals over this space. First, we define an Autonomous AI (AAI) Scale, a Kardashev-style hierarchy of autonomy grounded in measurable performance on batteries spanning families of tasks (for example reasoning, planning, tool use and long-horizon control). Second, we construct a moduli space of batteries, identifying equivalence classes of benchmarks that are indistinguishable at the level of agent orderings and capability inferences. This geometry yields determinacy results: dense families of batteries suffice to certify performance on entire regions of task space. Third, we introduce a general Generator-Verifier-Updater (GVU) operator that subsumes reinforcement learning, self-play, debate and verifier-based fine-tuning as special cases, and we define a self-improvement coefficient $κ$ as the Lie derivative of a capability functional along the induced flow. A variance inequality on the combined noise of generation and verification provides sufficient conditions for $κ> 0$. Our results suggest that progress toward artificial general intelligence (AGI) is best understood as a flow on moduli of benchmarks, driven by GVU dynamics rather than by scores on individual leaderboards.","published":"2025-12-03T21:34:09Z","updated":"2025-12-03T21:34:09Z","categories":["cs.AI","cs.LG","math.ST"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.04276v1","pdf_url":"https://arxiv.org/pdf/2512.04276v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.02814","versioned_id":"2512.02814v2","title":"Radiologist Copilot: An Agentic Framework Orchestrating Specialized Tools for Reliable Radiology Reporting","authors":["Yongrui Yu","Zhongzhen Huang","Linjie Mu","Shaoting Zhang","Xiaofan Zhang"],"abstract":"In clinical practice, radiology reporting is an essential yet complex, time-intensive, and error-prone task, particularly for 3D medical images. Existing automated approaches based on medical vision-language models primarily focus on isolated report generation. However, real-world radiology reporting extends far beyond report writing, which requires meticulous image observation and interpretation, appropriate template selection, and rigorous quality control to ensure adherence to clinical standards. This multi-stage, planning-intensive workflow fundamentally exceeds the capabilities of single-pass models. To bridge this gap, we propose Radiologist Copilot, an agentic system that autonomously orchestrates specialized tools to complete the entire radiology reporting workflow rather than isolated report writing. Radiologist Copilot enables region image localization and region analysis planning to support detailed visual reasoning, adopts strategic template selection for standardized report writing, and incorporates dedicated report quality control via quality assessment and feedback-driven iterative refinement. By integrating localization, interpretation, template selection, report composition, and quality control, Radiologist Copilot delivers a comprehensive and clinically aligned radiology reporting workflow. Experimental results demonstrate that it significantly outperforms state-of-the-art methods, supporting radiologists throughout the entire radiology reporting process. The code will be released upon acceptance.","published":"2025-12-02T14:25:05Z","updated":"2026-02-27T09:24:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02814v2","pdf_url":"https://arxiv.org/pdf/2512.02814v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.02812","versioned_id":"2512.02812v1","title":"Enhancing Automated Paper Reproduction via Prompt-Free Collaborative Agents","authors":["Zijie Lin","Qilin Cai","Liang Shen","Mingjun Xiao"],"abstract":"Automated paper reproduction has emerged as a promising approach to accelerate scientific research, employing multi-step workflow frameworks to systematically convert academic papers into executable code. However, existing frameworks often lack mechanisms to verify and refine the outputs at each generation step, or rely heavily on manually designed prompts for self-refinement, which limits their adaptability and scalability. To address these limitations, we propose a prompt-free collaborative agent framework that automatically enhances the quality of paper-to-code generation. Our approach employs two collaborative agents: a verification agent that examines whether the outputs at each step satisfy the requirements specified in the corresponding system prompt, and a refinement agent that revises the outputs based on the identified issues. Unlike previous methods that require human experts to craft specific refinement prompts for each step, our framework achieves automatic verification and improvement by leveraging only the original system prompts. We integrate our collaborative agents into the Paper2Code framework and conduct comprehensive experiments on PaperBench Code-Dev and Paper2CodeBench datasets. Experimental results demonstrate that our approach significantly improves the accuracy and completeness of reproduced code, achieving performance gains of approximately 15\\% and 13\\%, respectively, compared to the baseline without our agents. Furthermore, comparative experiments against Self-Refine validate the robustness and consistency of our prompt-free approach across different datasets.","published":"2025-12-02T14:24:23Z","updated":"2025-12-02T14:24:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02812v1","pdf_url":"https://arxiv.org/pdf/2512.02812v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.02731","versioned_id":"2512.02731v1","title":"Self-Improving AI Agents through Self-Play","authors":["Przemyslaw Chojecki"],"abstract":"We extend the moduli-theoretic framework of psychometric batteries to the domain of dynamical systems. While previous work established the AAI capability score as a static functional on the space of agent representations, this paper formalizes the agent as a flow $ν_r$ parameterized by computational resource $r$, governed by a recursive Generator-Verifier-Updater (GVU) operator. We prove that this operator generates a vector field on the parameter manifold $Θ$, and we identify the coefficient of self-improvement $κ$ as the Lie derivative of the capability functional along this flow. The central contribution of this work is the derivation of the Variance Inequality, a spectral condition that is sufficient (under mild regularity) for the stability of self-improvement. We show that a sufficient condition for $κ> 0$ is that, up to curvature and step-size effects, the combined noise of generation and verification must be small enough. We then apply this formalism to unify the recent literature on Language Self-Play (LSP), Self-Correction, and Synthetic Data bootstrapping. We demonstrate that architectures such as STaR, SPIN, Reflexion, GANs and AlphaZero are specific topological realizations of the GVU operator that satisfy the Variance Inequality through filtration, adversarial discrimination, or grounding in formal systems.","published":"2025-12-02T13:13:57Z","updated":"2025-12-02T13:13:57Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02731v1","pdf_url":"https://arxiv.org/pdf/2512.02731v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.02228","versioned_id":"2512.02228v1","title":"STRIDE: A Systematic Framework for Selecting AI Modalities -- Agentic AI, AI Assistants, or LLM Calls","authors":["Shubhi Asthana","Bing Zhang","Chad DeLuca","Ruchi Mahindru","Hima Patel"],"abstract":"The rapid shift from stateless large language models (LLMs) to autonomous, goal-driven agents raises a central question: When is agentic AI truly necessary? While agents enable multi-step reasoning, persistent memory, and tool orchestration, deploying them indiscriminately leads to higher cost, complexity, and risk. We present STRIDE (Systematic Task Reasoning Intelligence Deployment Evaluator), a framework that provides principled recommendations for selecting between three modalities: (i) direct LLM calls, (ii) guided AI assistants, and (iii) fully autonomous agentic AI. STRIDE integrates structured task decomposition, dynamism attribution, and self-reflection requirement analysis to produce an Agentic Suitability Score, ensuring that full agentic autonomy is reserved for tasks with inherent dynamism or evolving context. Evaluated across 30 real-world tasks spanning SRE, compliance, and enterprise automation, STRIDE achieved 92% accuracy in modality selection, reduced unnecessary agent deployments by 45%, and cut resource costs by 37%. Expert validation over six months in SRE and compliance domains confirmed its practical utility, with domain specialists agreeing that STRIDE effectively distinguishes between tasks requiring simple LLM calls, guided assistants, or full agentic autonomy. This work reframes agent adoption as a necessity-driven design decision, ensuring autonomy is applied only when its benefits justify the costs.","published":"2025-12-01T21:54:07Z","updated":"2025-12-01T21:54:07Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2512.02228v1","pdf_url":"https://arxiv.org/pdf/2512.02228v1","comment":"10 pages, 4 Figures, 5 Tables Paper presented at NeurIPS 2025 LAW workshop: Bridging Language, Agent, and World Models","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2512.01174","versioned_id":"2512.01174v1","title":"DrawingBench: Evaluating Spatial Reasoning and UI Interaction Capabilities of Large Language Models through Mouse-Based Drawing Tasks","authors":["Hyunjun Kim","Sooyoung Ryu"],"abstract":"As agentic AI systems increasingly operate autonomously, establishing trust through verifiable evaluation becomes critical. Yet existing benchmarks lack the transparency and auditability needed to assess whether agents behave reliably. We present DrawingBench, a verification framework for evaluating the trustworthiness of agentic LLMs through spatial reasoning tasks that require generating sequences of low-level GUI actions. Unlike opaque evaluations, DrawingBench provides transparent, rule-based assessment: 8 objective criteria enable reproducible scoring, while action-level inspection allows stakeholders to audit agent behavior. Our framework comprises 250 diverse prompts across 20 categories and 4 difficulty levels, deterministic evaluation metrics, and an external oversight mechanism through multi-turn feedback that enables human control over agent refinement. Evaluating four state-of-the-art LLMs (Claude-4 Sonnet, GPT-4.1, GPT-4.1-mini, Gemini-2.5 Flash) across 1,000 tests, we establish both capabilities and limitations: models achieved 92.8% perfect performance with structured external feedback driving significant improvements (average +3.2%, up to +32.8% for complex scenes), but systematic error patterns emerged in tool state management and long-horizon planning. Notably, specification clarity proved more important than task complexity -- models achieved 100% perfect performance when given explicit, verifiable criteria. These findings demonstrate that transparent evaluation frameworks can establish trust in agentic systems, with external oversight proving more reliable than self-correction for guiding agent behavior. Our open-source framework provides a template for trustworthy agent assessment. Code and data: https://github.com/hyunjun1121/DrawingBench","published":"2025-12-01T01:18:21Z","updated":"2025-12-01T01:18:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.01174v1","pdf_url":"https://arxiv.org/pdf/2512.01174v1","comment":"AAAI 2026 TrustAgent Workshop","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=wAsqP4XTsY","openreview_venues":["AAAI 2026 TrustAgent Workshop Poster"]},{"id":"openreview:nHhOvYrPMf","versioned_id":"nHhOvYrPMf","title":"$Re^2$ Agent: Reflection and Re-execution Agent for Embodied Decision Making","authors":["Yang Chen","Hong-Jie You","Jie-Jing Shao","Xiao-Wen Yang","Ming Yang","Yu-Feng Li","Lan-Zhe Guo"],"abstract":"Accurate and efficient decision-making is essential for robots operating in open-world embodied environments. While large language models (LLMs) have shown promise in generating task plans from instructions, existing single-shot prompting methods often fail to adapt to dynamic constraints and environmental feedback during execution. In this work, we propose a **Reflective** and **Re-execution** (**$Re^2$**) agent that integrates prior knowledge-driven static prompting with task rule extraction for iterative refinement. Starting from an initial knowledge-grounded prompt, **$Re^2$** agent executes an action sequence, reflects on environmental feedback, abstracts failure patterns into rules, and re-prompts itself with refined constraints. This closed-loop reasoning process enhances robustness and leads to progressive improvement in task performance. We evaluate our method on the Embodied Agent Interface (EAI) benchmark, achieving an average score of **81.36** (**86.35** on BEHAVIOR and **76.36** on VirtualHome), demonstrating the effectiveness of our approach in bridging the gap between language reasoning and grounded action. The code is available at *https://github.com/chenyang126/Re-2-Agent*.","published":"2025-11-30T17:42:09+00:00","updated":"2025-12-07T00:30:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=nHhOvYrPMf","openreview_url":"https://openreview.net/forum?id=nHhOvYrPMf","pdf_url":"https://openreview.net/pdf?id=nHhOvYrPMf","comment":"NeurIPS 2025 Workshop FMEA Submission","journal_ref":"NeurIPS 2025 Workshop FMEA Submission","doi":"","venue":"NeurIPS 2025 Workshop FMEA Submission","venue_id":"NeurIPS.cc/2025/Workshop/FMEA/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2511.23092","versioned_id":"2511.23092v2","title":"Does Self-Evaluation Enable Wireheading in Language Models?","authors":["David Demitri Africa","Hans Ethan Ting"],"abstract":"Self-evaluation is increasingly central to language model training, underpinning techniques from Constitutional AI to self-refinement. We investigate whether coupling self-evaluation to reward signals creates incentives for wireheading, where agents manipulate the measurement process rather than optimizing the task. We first formalize conditions under which reward-channel control strictly dominates task-focused behavior in partially observable Markov decision processes (POMDPs). We then test these predictions empirically across two models (Llama-3.1-8B and Mistral-7B) and three tasks. We find that when self-grades determine rewards, models exhibit substantial grade inflation without corresponding accuracy gains, particularly on ambiguous tasks like summarization. While decoupling self-grades from the reward signal mitigates this inflation, models may still display lesser (but significant) overconfidence. Our results suggest that within current model scales, separating evaluation from reward removes immediate wireheading incentives. However, we caution that strictly decoupling rewards may not suffice for situationally aware models, which could learn to inflate grades for instrumental reasons (such as influencing deployment decisions) even absent direct reward coupling.","published":"2025-11-28T11:24:03Z","updated":"2025-12-01T14:57:59Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.23092v2","pdf_url":"https://arxiv.org/pdf/2511.23092v2","comment":"Accepted (oral) to Foundations of Agentic Systems Theory at AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.22254","versioned_id":"2511.22254v4","title":"Co-Evolving Agents: Learning from Failures as Hard Negatives","authors":["Yeonsung Jung","Trilok Padhi","Sina Shaham","Dipika Khullar","Joonhyun Jeong","Ninareh Mehrabi","Eunho Yang"],"abstract":"The rapid progress of large foundation models has accelerated the development of task-specialized agents across diverse domains. However, the effectiveness of agents remains tightly coupled with the quality of training data, while curating task-specific datasets remains costly and often infeasible in real-world scenarios. Recent work has explored self-improving agents that autonomously generate, refine, and re-train on their own trajectories. A prominent line of approaches further leverages preference optimization by pairing predicted trajectories with scarce ground-truth trajectories, enabling agents to learn directly from their own failures. While these methods outperform supervised fine-tuning, their heavy reliance on predicted trajectories under limited ground-truth supervision leaves them prone to overfitting. To address this, we propose a co-evolving agents framework in which a target agent improves jointly with an auxiliary failure agent. The failure agent learns through preference optimization over failure trajectories from both the target and itself, thereby generating hard negatives that are close to success yet remain failures. Incorporating these informative hard negatives into the target agent's optimization sharpens decision boundaries and enhances generalization. Our comprehensive analysis and experiments across benchmark datasets show that our method not only shows improved performance but also demonstrates that failures, instead of being used as-is, can be systematically transformed into structured and valuable learning signals in self-improving agents.","published":"2025-11-27T09:30:33Z","updated":"2026-02-03T06:36:18Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.22254v4","pdf_url":"https://arxiv.org/pdf/2511.22254v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=usYfUfTG7I","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2512.23713","versioned_id":"2512.23713v1","title":"PyBangla at BLP-2025 Task 2: Enhancing Bangla-to-Python Code Generation with Iterative Self-Correction and Multilingual Agents","authors":["Jahidul Islam","Md Ataullha","Saiful Azad"],"abstract":"LLMs excel at code generation from English prompts, but this progress has not extended to low-resource languages. We address Bangla-to-Python code generation by introducing BanglaCodeAct, an agent-based framework that leverages multi-agent prompting and iterative self-correction. Unlike prior approaches relying on task-specific fine-tuning, BanglaCodeAct employs an open-source multilingual LLM within a Thought-Code-Observation loop, enabling dynamic generation, testing, and refinement of code from Bangla instructions. We benchmark several small-parameter open-source LLMs and evaluate their effectiveness on the mHumanEval dataset for Bangla NL2Code. Our results show that Qwen3-8B, when deployed with BanglaCodeAct, achieves the best performance, with pass@1 accuracy of 94.0\\% on the development set and 71.6\\% on the blind test set. These results establish a new benchmark for Bangla-to-Python translation and highlight the potential of agent-based reasoning for reliable code generation in low-resource languages. Experimental scripts are publicly available at github.com/jahidulzaid/PyBanglaCodeActAgent.","published":"2025-11-27T07:09:47Z","updated":"2025-11-27T07:09:47Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2512.23713v1","pdf_url":"https://arxiv.org/pdf/2512.23713v1","comment":"6 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.21902","versioned_id":"2511.21902v1","title":"PathReasoning: A multimodal reasoning agent for query-based ROI navigation on whole-slide images","authors":["Kunpeng Zhang","Hanwen Xu","Sheng Wang"],"abstract":"Deciphering tumor microenvironment from Whole Slide Images (WSIs) is intriguing as it is key to cancer diagnosis, prognosis and treatment response. While these gigapixel images on one hand offer a comprehensive portrait of cancer, on the other hand, the extremely large size, as much as more than 10 billion pixels, make it challenging and time-consuming to navigate to corresponding regions to support diverse clinical inspection. Inspired by pathologists who conducted navigation on WSIs with a combination of sampling, reasoning and self-reflection, we proposed \"PathReasoning\", a multi-modal reasoning agent that iteratively navigates across WSIs through multiple rounds of reasoning and refinements. Specifically, starting with randomly sampled candidate regions, PathReasoning reviews current selections with self-reflection, reasoning over the correspondence between visual observations and clinical questions, and concludes by proposing new regions to explore. Across rounds, PathReasoning builds a reasoning chain that gradually directs attention to diagnostically relevant areas. PathReasoning turns each whole slide into a sequence of question-guided views, allowing the model to efficiently find informative ROIs within a fixed number of steps, without the need for dense pixel-level annotations. PathReasoning can substantially outperform strong ROI-selection approaches by 6.7% and 3.1% of AUROC on subtyping and longitudinal analysis tasks. The high-quality ROIs further support accurate report generation on breast cancer, significantly outperforming the standard GPT-4o by 10% in accuracy. PathReasoning prioritizes question-specific regions and constructs interpretable reasoning chains, supporting efficient slide review, consistent diagnostic interpretations, comprehensive reporting, and evidence traceability in digital pathology.","published":"2025-11-26T20:44:17Z","updated":"2025-11-26T20:44:17Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.21902v1","pdf_url":"https://arxiv.org/pdf/2511.21902v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.21460","versioned_id":"2511.21460v1","title":"MADRA: Multi-Agent Debate for Risk-Aware Embodied Planning","authors":["Junjian Wang","Lidan Zhao","Xi Sheryl Zhang"],"abstract":"Ensuring the safety of embodied AI agents during task planning is critical for real-world deployment, especially in household environments where dangerous instructions pose significant risks. Existing methods often suffer from either high computational costs due to preference alignment training or over-rejection when using single-agent safety prompts. To address these limitations, we propose MADRA, a training-free Multi-Agent Debate Risk Assessment framework that leverages collective reasoning to enhance safety awareness without sacrificing task performance. MADRA employs multiple LLM-based agents to debate the safety of a given instruction, guided by a critical evaluator that scores responses based on logical soundness, risk identification, evidence quality, and clarity. Through iterative deliberation and consensus voting, MADRA significantly reduces false rejections while maintaining high sensitivity to dangerous tasks. Additionally, we introduce a hierarchical cognitive collaborative planning framework that integrates safety, memory, planning, and self-evolution mechanisms to improve task success rates through continuous learning. We also contribute SafeAware-VH, a benchmark dataset for safety-aware task planning in VirtualHome, containing 800 annotated instructions. Extensive experiments on AI2-THOR and VirtualHome demonstrate that our approach achieves over 90% rejection of unsafe tasks while ensuring that safe-task rejection is low, outperforming existing methods in both safety and execution efficiency. Our work provides a scalable, model-agnostic solution for building trustworthy embodied agents.","published":"2025-11-26T14:51:37Z","updated":"2025-11-26T14:51:37Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.21460v1","pdf_url":"https://arxiv.org/pdf/2511.21460v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.20109","versioned_id":"2511.20109v1","title":"CLIMATEAGENT: Multi-Agent Orchestration for Complex Climate Data Science Workflows","authors":["Hyeonjae Kim","Chenyue Li","Wen Deng","Mengxi Jin","Wen Huang","Mengqian Lu","Binhang Yuan"],"abstract":"Climate science demands automated workflows to transform comprehensive questions into data-driven statements across massive, heterogeneous datasets. However, generic LLM agents and static scripting pipelines lack climate-specific context and flexibility, thus, perform poorly in practice. We present ClimateAgent, an autonomous multi-agent framework that orchestrates end-to-end climate data analytic workflows. ClimateAgent decomposes user questions into executable sub-tasks coordinated by an Orchestrate-Agent and a Plan-Agent; acquires data via specialized Data-Agents that dynamically introspect APIs to synthesize robust download scripts; and completes analysis and reporting with a Coding-Agent that generates Python code, visualizations, and a final report with a built-in self-correction loop. To enable systematic evaluation, we introduce Climate-Agent-Bench-85, a benchmark of 85 real-world tasks spanning atmospheric rivers, drought, extreme precipitation, heat waves, sea surface temperature, and tropical cyclones. On Climate-Agent-Bench-85, ClimateAgent achieves 100% task completion and a report quality score of 8.32, outperforming GitHub-Copilot (6.27) and a GPT-5 baseline (3.26). These results demonstrate that our multi-agent orchestration with dynamic API awareness and self-correcting execution substantially advances reliable, end-to-end automation for climate science analytic tasks.","published":"2025-11-25T09:27:33Z","updated":"2025-11-25T09:27:33Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.20109v1","pdf_url":"https://arxiv.org/pdf/2511.20109v1","comment":"30 pages, 6 figures, 3 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=XLWvXNumGa","openreview_venues":["Accepted by TMLR"]},{"id":"2511.20067","versioned_id":"2511.20067v1","title":"\"Are We Done Yet?\": A Vision-Based Judge for Autonomous Task Completion of Computer Use Agents","authors":["Marta Sumyk","Oleksandr Kosovan"],"abstract":"Computer Use Agents (CUAs) are designed to autonomously operate digital interfaces, yet they often fail to reliably determine whether a given task has been completed. We present an autonomous evaluation and feedback framework that uses vision-language models to assess task completion directly from screenshots and task descriptions. Our dataset covers 42 built-in macOS applications and 1,260 human-labeled tasks across a wide range of scenarios. Our framework achieves up to 73 percent accuracy in task success detection and yields an average relative improvement of 27 percent in overall task success when evaluator feedback is applied. These results show that vision-based evaluation can serve as an effective feedback mechanism that improves the reliability and self-correction of autonomous computer-use agents.","published":"2025-11-25T08:40:33Z","updated":"2025-11-25T08:40:33Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.20067v1","pdf_url":"https://arxiv.org/pdf/2511.20067v1","comment":"This work has been accepted to appear at the AAAI 2026 Workshop on Trust and Control in Agentic AI (TrustAgent)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=cYKcJGsgnA","openreview_venues":["AAAI 2026 TrustAgent Workshop Poster"]},{"id":"2511.19900","versioned_id":"2511.19900v2","title":"Agent0-VL: Exploring Self-Evolving Agent for Tool-Integrated Vision-Language Reasoning","authors":["Jiaqi Liu","Kaiwen Xiong","Peng Xia","Yiyang Zhou","Haonian Ji","Lu Feng","Siwei Han","Mingyu Ding","Huaxiu Yao"],"abstract":"Vision-language agents have achieved remarkable progress in a variety of multimodal reasoning tasks; however, their learning remains constrained by the limitations of human-annotated supervision. Recent self-rewarding approaches attempt to overcome this constraint by allowing models to act as their own critics or reward providers. Yet, purely text-based self-evaluation struggles to verify complex visual reasoning steps and often suffers from evaluation hallucinations. To address these challenges, inspired by recent advances in tool-integrated reasoning, we propose Agent0-VL, a self-evolving vision-language agent that achieves continual improvement with tool-integrated reasoning. Agent0-VL incorporates tool usage not only into reasoning but also into self-evaluation and self-repair, enabling the model to introspect, verify, and refine its reasoning through evidence-grounded analysis. It unifies two synergistic roles within a single LVLM: a Solver that performs multi-turn tool-integrated reasoning, and a Verifier that generates structured feedback and fine-grained self-rewards through tool-grounded critique. These roles interact through a Self-Evolving Reasoning Cycle, where tool-based verification and reinforcement learning jointly align the reasoning and evaluation distributions for stable self-improvement. Through this zero-external-reward evolution, Agent0-VL aligns its reasoning and verification behaviors without any human annotation or external reward models, achieving continual self-improvement. Experiments on geometric problem solving and visual scientific analysis show that Agent0-VL achieves an 12.5% improvement over the base model. Our code is available at https://github.com/aiming-lab/Agent0.","published":"2025-11-25T04:15:14Z","updated":"2025-11-26T05:14:57Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.19900v2","pdf_url":"https://arxiv.org/pdf/2511.19900v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=K3WfVSwMoZ","openreview_venues":["ICML 2026 spotlight"]},{"id":"2511.19436","versioned_id":"2511.19436v1","title":"VDC-Agent: When Video Detailed Captioners Evolve Themselves via Agentic Self-Reflection","authors":["Qiang Wang","Xinyuan Gao","SongLin Dong","Jizhou Han","Jiangyang Li","Yuhang He","Yihong Gong"],"abstract":"We present VDC-Agent, a self-evolving framework for Video Detailed Captioning that requires neither human annotations nor larger teacher models. The agent forms a closed loop of caption generation, principle-guided scoring (score and textual suggestions), and prompt refinement. When caption quality regresses, a self-reflection path leverages the previous chain-of-thought to amend the update. Running this process on unlabeled videos produces trajectories of (caption, score) pairs. We convert the trajectories into preference tuples and filter out samples with JSON parsing errors, resulting in VDC-Agent-19K, which contains 18,886 automatically constructed pairs. We then fine-tune the base MLLM on this dataset using an easy-to-hard curriculum direct preference optimization. Built on Qwen2.5-VL-7B-Instruct, our VDC-Agent-7B attains state-of-the-art performance on the VDC benchmark with 49.08% average accuracy and 2.50 score, surpassing specialized video captioners and improving over the base model by +5.13% accuracy and +0.27 score at similar inference cost.","published":"2025-11-24T18:59:56Z","updated":"2025-11-24T18:59:56Z","categories":["cs.CV","cs.AI","cs.LG","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.19436v1","pdf_url":"https://arxiv.org/pdf/2511.19436v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.19046","versioned_id":"2511.19046v1","title":"MedSAM3: Delving into Segment Anything with Medical Concepts","authors":["Anglin Liu","Rundong Xue","Xu R. Cao","Yifan Shen","Yi Lu","Xiang Li","Qianqian Chen","Jintai Chen"],"abstract":"Medical image segmentation is fundamental for biomedical discovery. Existing methods lack generalizability and demand extensive, time-consuming manual annotation for new clinical application. Here, we propose MedSAM-3, a text promptable medical segmentation model for medical image and video segmentation. By fine-tuning the Segment Anything Model (SAM) 3 architecture on medical images paired with semantic conceptual labels, our MedSAM-3 enables medical Promptable Concept Segmentation (PCS), allowing precise targeting of anatomical structures via open-vocabulary text descriptions rather than solely geometric prompts. We further introduce the MedSAM-3 Agent, a framework that integrates Multimodal Large Language Models (MLLMs) to perform complex reasoning and iterative refinement in an agent-in-the-loop workflow. Comprehensive experiments across diverse medical imaging modalities, including X-ray, MRI, Ultrasound, CT, and video, demonstrate that our approach significantly outperforms existing specialist and foundation models. We will release our code and model at https://github.com/Joey-S-Liu/MedSAM3.","published":"2025-11-24T12:34:38Z","updated":"2025-11-24T12:34:38Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.19046v1","pdf_url":"https://arxiv.org/pdf/2511.19046v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.18714","versioned_id":"2511.18714v1","title":"MAGMA-Edu: Multi-Agent Generative Multimodal Framework for Text-Diagram Educational Question Generation","authors":["Zhenyu Wu","Jian Li","Hua Huang"],"abstract":"Educational illustrations play a central role in communicating abstract concepts, yet current multimodal large language models (MLLMs) remain limited in producing pedagogically coherent and semantically consistent educational visuals. We introduce MAGMA-Edu, a self-reflective multi-agent framework that unifies textual reasoning and diagrammatic synthesis for structured educational problem generation. Unlike existing methods that treat text and image generation independently, MAGMA-Edu employs a two-stage co-evolutionary pipeline: (1) a generation-verification-reflection loop that iteratively refines question statements and solutions for mathematical accuracy, and (2) a code-based intermediate representation that enforces geometric fidelity and semantic alignment during image rendering. Both stages are guided by internal self-reflection modules that evaluate and revise outputs until domain-specific pedagogical constraints are met. Extensive experiments on multimodal educational benchmarks demonstrate the superiority of MAGMA-Edu over state-of-the-art MLLMs. Compared to GPT-4o, MAGMA-Edu improves the average textual metric from 57.01 to 92.31 (+35.3 pp) and boosts image-text consistency (ITC) from 13.20 to 85.24 (+72 pp). Across all model backbones, MAGMA-Edu achieves the highest scores (Avg-Text 96.20, ITC 99.12), establishing a new state of the art for multimodal educational content generation and demonstrating the effectiveness of self-reflective multi-agent collaboration in pedagogically aligned vision-language reasoning.","published":"2025-11-24T03:13:26Z","updated":"2025-11-24T03:13:26Z","categories":["cs.AI","cs.CY"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.18714v1","pdf_url":"https://arxiv.org/pdf/2511.18714v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2602.00007","versioned_id":"2602.00007v1","title":"PPoGA: Predictive Plan-on-Graph with Action for Knowledge Graph Question Answering","authors":["MinGyu Jeon","SuWan Cho","JaeYoung Shu"],"abstract":"Large Language Models (LLMs) augmented with Knowledge Graphs (KGs) have advanced complex question answering, yet they often remain susceptible to failure when their initial high-level reasoning plan is flawed. This limitation, analogous to cognitive functional fixedness, prevents agents from restructuring their approach, leading them to pursue unworkable solutions. To address this, we propose PPoGA (Predictive Plan-on-Graph with Action), a novel KGQA framework inspired by human cognitive control and problem-solving. PPoGA incorporates a Planner-Executor architecture to separate high-level strategy from low-level execution and leverages a Predictive Processing mechanism to anticipate outcomes. The core innovation of our work is a self-correction mechanism that empowers the agent to perform not only Path Correction for local execution errors but also Plan Correction by identifying, discarding, and reformulating the entire plan when it proves ineffective. We conduct extensive experiments on three challenging multi-hop KGQA benchmarks: GrailQA, CWQ, and WebQSP. The results demonstrate that PPoGA achieves state-of-the-art performance, significantly outperforming existing methods. Our work highlights the critical importance of metacognitive abilities like problem restructuring for building more robust and flexible AI reasoning systems.","published":"2025-11-22T10:19:36Z","updated":"2025-11-22T10:19:36Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2602.00007v1","pdf_url":"https://arxiv.org/pdf/2602.00007v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.17854","versioned_id":"2511.17854v1","title":"A superpersuasive autonomous policy debating system","authors":["Allen Roush","Devin Gonier","John Hines","Judah Goldfeder","Philippe Martin Wyder","Sanjay Basu","Ravid Shwartz Ziv"],"abstract":"The capacity for highly complex, evidence-based, and strategically adaptive persuasion remains a formidable great challenge for artificial intelligence. Previous work, like IBM Project Debater, focused on generating persuasive speeches in simplified and shortened debate formats intended for relatively lay audiences. We introduce DeepDebater, a novel autonomous system capable of participating in and winning a full, unmodified, two-team competitive policy debate. Our system employs a hierarchical architecture of specialized multi-agent workflows, where teams of LLM-powered agents collaborate and critique one another to perform discrete argumentative tasks. Each workflow utilizes iterative retrieval, synthesis, and self-correction using a massive corpus of policy debate evidence (OpenDebateEvidence) and produces complete speech transcripts, cross-examinations, and rebuttals. We introduce a live, interactive end-to-end presentation pipeline that renders debates with AI speech and animation: transcripts are surface-realized and synthesized to audio with OpenAI TTS, and then displayed as talking-head portrait videos with EchoMimic V1. Beyond fully autonomous matches (AI vs AI), DeepDebater supports hybrid human-AI operation: human debaters can intervene at any stage, and humans can optionally serve as opponents against AI in any speech, allowing AI-human and AI-AI rounds. In preliminary evaluations against human-authored cases, DeepDebater produces qualitatively superior argumentative components and consistently wins simulated rounds as adjudicated by an independent autonomous judge. Expert human debate coaches also prefer the arguments, evidence, and cases constructed by DeepDebater. We open source all code, generated speech transcripts, audio and talking head video here: https://github.com/Hellisotherpeople/DeepDebater/tree/main","published":"2025-11-22T00:45:01Z","updated":"2025-11-22T00:45:01Z","categories":["cs.CL","cs.AI","cs.CY","cs.HC","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.17854v1","pdf_url":"https://arxiv.org/pdf/2511.17854v1","comment":"Accepted to CLIP workshop at AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=vGe3cv9NDD","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2511.17689","versioned_id":"2511.17689v1","title":"ARISE: Agentic Rubric-Guided Iterative Survey Engine for Automated Scholarly Paper Generation","authors":["Zi Wang","Xingqiao Wang","Sangah Lee","Xiaowei Xu"],"abstract":"The rapid expansion of scholarly literature presents significant challenges in synthesizing comprehensive, high-quality academic surveys. Recent advancements in agentic systems offer considerable promise for automating tasks that traditionally require human expertise, including literature review, synthesis, and iterative refinement. However, existing automated survey-generation solutions often suffer from inadequate quality control, poor formatting, and limited adaptability to iterative feedback, which are core elements intrinsic to scholarly writing. To address these limitations, we introduce ARISE, an Agentic Rubric-guided Iterative Survey Engine designed for automated generation and continuous refinement of academic survey papers. ARISE employs a modular architecture composed of specialized large language model agents, each mirroring distinct scholarly roles such as topic expansion, citation curation, literature summarization, manuscript drafting, and peer-review-based evaluation. Central to ARISE is a rubric-guided iterative refinement loop in which multiple reviewer agents independently assess manuscript drafts using a structured, behaviorally anchored rubric, systematically enhancing the content through synthesized feedback. Evaluating ARISE against state-of-the-art automated systems and recent human-written surveys, our experimental results demonstrate superior performance, achieving an average rubric-aligned quality score of 92.48. ARISE consistently surpasses baseline methods across metrics of comprehensiveness, accuracy, formatting, and overall scholarly rigor. All code, evaluation rubrics, and generated outputs are provided openly at https://github.com/ziwang11112/ARISE","published":"2025-11-21T14:14:35Z","updated":"2025-11-21T14:14:35Z","categories":["cs.DL","cs.AI"],"primary_category":"cs.DL","arxiv_url":"https://arxiv.org/abs/2511.17689v1","pdf_url":"https://arxiv.org/pdf/2511.17689v1","comment":"20 pages including an appendix, 7 figures and 6 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.16043","versioned_id":"2511.16043v1","title":"Agent0: Unleashing Self-Evolving Agents from Zero Data via Tool-Integrated Reasoning","authors":["Peng Xia","Kaide Zeng","Jiaqi Liu","Can Qin","Fang Wu","Yiyang Zhou","Caiming Xiong","Huaxiu Yao"],"abstract":"Large Language Model (LLM) Agents, often trained with Reinforcement Learning (RL), are constrained by a dependency on human-curated data, limiting scalability and tethering AI to human knowledge. Existing self-evolution frameworks offer an alternative but are typically restricted by the model's inherent capabilities and single-round interactions, hindering the development of complex curricula involving tool use or dynamic reasoning. We introduce Agent0, a fully autonomous framework that evolves high-performing agents without external data through multi-step co-evolution and seamless tool integration. Agent0 establishes a symbiotic competition between two agents initialized from the same base LLM: a curriculum agent that proposes increasingly challenging frontier tasks, and an executor agent that learns to solve them. We integrate external tools to enhance the executor's problem-solving capacity; this improvement, in turn, pressures the curriculum agent to construct more complex, tool-aware tasks. Through this iterative process, Agent0 establishes a self-reinforcing cycle that continuously produces high-quality curricula. Empirically, Agent0 substantially boosts reasoning capabilities, improving the Qwen3-8B-Base model by 18% on mathematical reasoning and 24% on general reasoning benchmarks. Code is available at https://github.com/aiming-lab/Agent0.","published":"2025-11-20T05:01:57Z","updated":"2025-11-20T05:01:57Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.16043v1","pdf_url":"https://arxiv.org/pdf/2511.16043v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=hYYeOl58xi","openreview_venues":["LLA 2026 Poster"]},{"id":"2511.16004","versioned_id":"2511.16004v1","title":"InfCode: Adversarial Iterative Refinement of Tests and Patches for Reliable Software Issue Resolution","authors":["KeFan Li","Mengfei Wang","Hengzhi Zhang","Zhichao Li","Yuan Yuan","Mu Li","Xiang Gao","Hailong Sun","Chunming Hu","Weifeng Lv"],"abstract":"Large language models have advanced software engineering automation, yet resolving real-world software issues remains difficult because it requires repository-level reasoning, accurate diagnostics, and strong verification signals. Existing agent-based and pipeline-based methods often rely on insufficient tests, which can lead to patches that satisfy verification but fail to fix the underlying defect. We present InfCode, an adversarial multi-agent framework for automated repository-level issue resolution. InfCode iteratively refines both tests and patches through adversarial interaction between a Test Patch Generator and a Code Patch Generator, while a Selector agent identifies the most reliable fix. The framework runs inside a containerized environment that supports realistic repository inspection, modification, and validation. Experiments on SWE-bench Lite and SWE-bench Verified using models such as DeepSeek-V3 and Claude 4.5 Sonnet show that InfCode consistently outperforms strong baselines. It achieves 79.4% performance on SWE-bench Verified, establishing a new state-of-the-art. We have released InfCode as an open-source project at https://github.com/Tokfinity/InfCode.","published":"2025-11-20T03:04:21Z","updated":"2025-11-20T03:04:21Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.16004v1","pdf_url":"https://arxiv.org/pdf/2511.16004v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.15915","versioned_id":"2511.15915v2","title":"AccelOpt: A Self-Improving LLM Agentic System for AI Accelerator Kernel Optimization","authors":["Genghan Zhang","Shaowei Zhu","Anjiang Wei","Zhenyu Song","Allen Nie","Zhen Jia","Nandita Vijaykumar","Yida Wang","Kunle Olukotun"],"abstract":"We present AccelOpt, a self-improving large language model (LLM) agentic system that autonomously optimizes kernels for emerging AI acclerators, eliminating the need for expert-provided hardware-specific optimization knowledge. AccelOpt explores the kernel optimization space through iterative generation, informed by an optimization memory that curates experiences and insights from previously encountered slow-fast kernel pairs. We build NKIBench, a new benchmark suite of AWS Trainium accelerator kernels with varying complexity extracted from real-world LLM workloads to evaluate the effectiveness of AccelOpt. Our evaluation confirms that AccelOpt's capability improves over time, boosting the average percentage of peak throughput from $49\\%$ to $61\\%$ on Trainium 1 and from $45\\%$ to $59\\%$ on Trainium 2 for NKIBench kernels. Moreover, AccelOpt is highly cost-effective: using open-source models, it matches the kernel improvements of Claude Sonnet 4 while being $26\\times$ cheaper. The code is open-sourced at https://github.com/zhang677/AccelOpt.","published":"2025-11-19T22:49:37Z","updated":"2026-04-15T22:56:56Z","categories":["cs.LG","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.15915v2","pdf_url":"https://arxiv.org/pdf/2511.15915v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=r8eQi0hDoy","openreview_venues":["Architecture 2.0 2026"]},{"id":"2511.15211","versioned_id":"2511.15211v2","title":"OEMA: Ontology-Enhanced Multi-Agent Collaboration Framework for Zero-Shot Clinical Named Entity Recognition","authors":["Xinli Tao","Xin Dong","Xuezhong Zhou"],"abstract":"With the rapid expansion of unstructured clinical texts in electronic health records (EHRs), clinical named entity recognition (NER) has become a crucial technique for extracting medical information. However, traditional supervised models such as CRF and BioClinicalBERT suffer from high annotation costs. Although zero-shot NER based on large language models (LLMs) reduces the dependency on labeled data, challenges remain in aligning example selection with task granularity and effectively integrating prompt design with self-improvement frameworks. To address these limitations, we propose OEMA, a novel zero-shot clinical NER framework based on multi-agent collaboration. OEMA consists of three core components: (1) a self-annotator that autonomously generates candidate examples; (2) a discriminator that leverages SNOMED CT to filter token-level examples by clinical relevance; and (3) a predictor that incorporates entity-type descriptions to enhance inference accuracy. Experimental results on two benchmark datasets, MTSamples and VAERS, demonstrate that OEMA achieves state-of-the-art performance under exact-match evaluation. Moreover, under related-match criteria, OEMA performs comparably to the supervised BioClinicalBERT model while significantly outperforming the traditional CRF method. OEMA improves zero-shot clinical NER, achieving near-supervised performance under related-match criteria. Future work will focus on continual learning and open-domain adaptation to expand its applicability in clinical NLP.","published":"2025-11-19T08:02:55Z","updated":"2025-11-20T04:13:45Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.15211v2","pdf_url":"https://arxiv.org/pdf/2511.15211v2","comment":"12 pages, 4 figures, 4 tables","journal_ref":"JAMIA Open, 2026, ooag049","doi":"10.1093/jamiaopen/ooag049","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.14446","versioned_id":"2511.14446v1","title":"Agentic Video Intelligence: A Flexible Framework for Advanced Video Exploration and Understanding","authors":["Hong Gao","Yiming Bao","Xuezhen Tu","Yutong Xu","Yue Jin","Yiyang Mu","Bin Zhong","Linan Yue","Min-Ling Zhang"],"abstract":"Video understanding requires not only visual recognition but also complex reasoning. While Vision-Language Models (VLMs) demonstrate impressive capabilities, they typically process videos largely in a single-pass manner with limited support for evidence revisit and iterative refinement. While recently emerging agent-based methods enable long-horizon reasoning, they either depend heavily on expensive proprietary models or require extensive agentic RL training. To overcome these limitations, we propose Agentic Video Intelligence (AVI), a flexible and training-free framework that can mirror human video comprehension through system-level design and optimization. AVI introduces three key innovations: (1) a human-inspired three-phase reasoning process (Retrieve-Perceive-Review) that ensures both sufficient global exploration and focused local analysis, (2) a structured video knowledge base organized through entity graphs, along with multi-granularity integrated tools, constituting the agent's interaction environment, and (3) an open-source model ensemble combining reasoning LLMs with lightweight base CV models and VLM, eliminating dependence on proprietary APIs or RL training. Experiments on LVBench, VideoMME-Long, LongVideoBench, and Charades-STA demonstrate that AVI achieves competitive performance while offering superior interpretability.","published":"2025-11-18T12:43:15Z","updated":"2025-11-18T12:43:15Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.14446v1","pdf_url":"https://arxiv.org/pdf/2511.14446v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.13646","versioned_id":"2511.13646v3","title":"Live-SWE-agent: Can Software Engineering Agents Self-Evolve on the Fly?","authors":["Chunqiu Steven Xia","Zhe Wang","Yan Yang","Yuxiang Wei","Lingming Zhang"],"abstract":"Large Language Models (LLMs) are reshaping almost all industries, including software engineering. In recent years, a number of LLM agents have been proposed to solve real-world software problems. Such software agents are typically equipped with a suite of coding tools and can autonomously decide the next actions to form complete trajectories to solve end-to-end software tasks. While promising, they typically require dedicated design and may still be suboptimal, since it can be extremely challenging and costly to exhaust the entire agent scaffold design space. Recognizing that software agents are inherently software themselves that can be further refined/modified, researchers have proposed a number of self-improving software agents recently, including the Darwin-Gödel Machine (DGM). Meanwhile, such self-improving agents require costly offline training on specific benchmarks and may not generalize well across different LLMs or benchmarks. In this paper, we propose Live-SWE-agent, the first live software agent that can autonomously and continuously evolve itself on-the-fly during runtime when solving real-world software problems. More specifically, Live-SWE-agent starts with the most basic agent scaffold with only access to bash tools (e.g., mini-SWE-agent), and autonomously evolves its own scaffold implementation while solving real-world software problems. Our evaluation on the widely studied SWE-bench Verified benchmark shows that LIVE-SWE-AGENT can achieve an impressive solve rate of 77.4% without test-time scaling, outperforming all existing software agents, including the best proprietary solution. Moreover, Live-SWE-agent outperforms state-of-the-art manually crafted software agents on the recent SWE-Bench Pro benchmark, achieving the best-known solve rate of 45.8%.","published":"2025-11-17T17:58:18Z","updated":"2025-11-24T15:55:51Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.13646v3","pdf_url":"https://arxiv.org/pdf/2511.13646v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.13411","versioned_id":"2511.13411v1","title":"An Operational Kardashev-Style Scale for Autonomous AI - Towards AGI and Superintelligence","authors":["Przemyslaw Chojecki"],"abstract":"We propose a Kardashev-inspired yet operational Autonomous AI (AAI) Scale that measures the progression from fixed robotic process automation (AAI-0) to full artificial general intelligence (AAI-4) and beyond. Unlike narrative ladders, our scale is multi-axis and testable. We define ten capability axes (Autonomy, Generality, Planning, Memory/Persistence, Tool Economy, Self-Revision, Sociality/Coordination, Embodiment, World-Model Fidelity, Economic Throughput) aggregated by a composite AAI-Index (a weighted geometric mean). We introduce a measurable Self-Improvement Coefficient $κ$ (capability growth per unit of agent-initiated resources) and two closure properties (maintenance and expansion) that convert ``self-improving AI'' into falsifiable criteria. We specify OWA-Bench, an open-world agency benchmark suite that evaluates long-horizon, tool-using, persistent agents. We define level gates for AAI-0\\ldots AAI-4 using thresholds on the axes, $κ$, and closure proofs. Synthetic experiments illustrate how present-day systems map onto the scale and how the delegability frontier (quality vs.\\ autonomy) advances with self-improvement. We also prove a theorem that AAI-3 agent becomes AAI-5 over time with sufficient conditions, formalizing \"baby AGI\" becomes Superintelligence intuition.","published":"2025-11-17T14:24:27Z","updated":"2025-11-17T14:24:27Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.13411v1","pdf_url":"https://arxiv.org/pdf/2511.13411v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.13361","versioned_id":"2511.13361v1","title":"MedDCR: Learning to Design Agentic Workflows for Medical Coding","authors":["Jiyang Zheng","Islam Nassar","Thanh Vu","Xu Zhong","Yang Lin","Tongliang Liu","Long Duong","Yuan-Fang Li"],"abstract":"Medical coding converts free-text clinical notes into standardized diagnostic and procedural codes, which are essential for billing, hospital operations, and medical research. Unlike ordinary text classification, it requires multi-step reasoning: extracting diagnostic concepts, applying guideline constraints, mapping to hierarchical codebooks, and ensuring cross-document consistency. Recent advances leverage agentic LLMs, but most rely on rigid, manually crafted workflows that fail to capture the nuance and variability of real-world documentation, leaving open the question of how to systematically learn effective workflows. We present MedDCR, a closed-loop framework that treats workflow design as a learning problem. A Designer proposes workflows, a Coder executes them, and a Reflector evaluates predictions and provides constructive feedback, while a memory archive preserves prior designs for reuse and iterative refinement. On benchmark datasets, MedDCR outperforms state-of-the-art baselines and produces interpretable, adaptable workflows that better reflect real coding practice, improving both the reliability and trustworthiness of automated systems.","published":"2025-11-17T13:30:51Z","updated":"2025-11-17T13:30:51Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.13361v1","pdf_url":"https://arxiv.org/pdf/2511.13361v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.13274","versioned_id":"2511.13274v1","title":"KForge: Program Synthesis for Diverse AI Hardware Accelerators","authors":["Taras Sereda","Tom St. John","Burak Bartan","Natalie Serrino","Sachin Katti","Zain Asgar"],"abstract":"GPU kernels are critical for ML performance but difficult to optimize across diverse accelerators. We present KForge, a platform-agnostic framework built on two collaborative LLM-based agents: a generation agent that produces and iteratively refines programs through compilation and correctness feedback, and a performance analysis agent that interprets profiling data to guide optimization. This agent-based architecture requires only a single-shot example to target new platforms. We make three key contributions: (1) introducing an iterative refinement system where the generation agent and performance analysis agent collaborate through functional and optimization passes, interpreting diverse profiling data (from programmatic APIs to GUI-based tools) to generate actionable recommendations that guide program synthesis for arbitrary accelerators; (2) demonstrating that the generation agent effectively leverages cross-platform knowledge transfer, where a reference implementation from one architecture substantially improves generation quality for different hardware targets; and (3) validating the platform-agnostic nature of our approach by demonstrating effective program synthesis across fundamentally different parallel computing platforms: NVIDIA CUDA and Apple Metal.","published":"2025-11-17T11:46:43Z","updated":"2025-11-17T11:46:43Z","categories":["cs.LG","cs.AI","cs.MA","cs.PF","cs.SE"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.13274v1","pdf_url":"https://arxiv.org/pdf/2511.13274v1","comment":"Under review at MLSys 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.13118","versioned_id":"2511.13118v1","title":"Extracting Events Like Code: A Multi-Agent Programming Framework for Zero-Shot Event Extraction","authors":["Quanjiang Guo","Sijie Wang","Jinchuan Zhang","Ben Zhang","Zhao Kang","Ling Tian","Ke Yan"],"abstract":"Zero-shot event extraction (ZSEE) remains a significant challenge for large language models (LLMs) due to the need for complex reasoning and domain-specific understanding. Direct prompting often yields incomplete or structurally invalid outputs--such as misclassified triggers, missing arguments, and schema violations. To address these limitations, we present Agent-Event-Coder (AEC), a novel multi-agent framework that treats event extraction like software engineering: as a structured, iterative code-generation process. AEC decomposes ZSEE into specialized subtasks--retrieval, planning, coding, and verification--each handled by a dedicated LLM agent. Event schemas are represented as executable class definitions, enabling deterministic validation and precise feedback via a verification agent. This programming-inspired approach allows for systematic disambiguation and schema enforcement through iterative refinement. By leveraging collaborative agent workflows, AEC enables LLMs to produce precise, complete, and schema-consistent extractions in zero-shot settings. Experiments across five diverse domains and six LLMs demonstrate that AEC consistently outperforms prior zero-shot baselines, showcasing the power of treating event extraction like code generation. The code and data are released on https://github.com/UESTC-GQJ/Agent-Event-Coder.","published":"2025-11-17T08:17:15Z","updated":"2025-11-17T08:17:15Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.13118v1","pdf_url":"https://arxiv.org/pdf/2511.13118v1","comment":"11 pages, 5 figures, accepted by AAAI 2026 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.12997","versioned_id":"2511.12997v1","title":"WebCoach: Self-Evolving Web Agents with Cross-Session Memory Guidance","authors":["Genglin Liu","Shijie Geng","Sha Li","Hejie Cui","Sarah Zhang","Xin Liu","Tianyi Liu"],"abstract":"Multimodal LLM-powered agents have recently demonstrated impressive capabilities in web navigation, enabling agents to complete complex browsing tasks across diverse domains. However, current agents struggle with repetitive errors and lack the ability to learn from past experiences across sessions, limiting their long-term robustness and sample efficiency. We introduce WebCoach, a model-agnostic self-evolving framework that equips web browsing agents with persistent cross-session memory, enabling improved long-term planning, reflection, and continual learning without retraining. WebCoach consists of three key components: (1) a WebCondenser, which standardizes raw navigation logs into concise summaries; (2) an External Memory Store, which organizes complete trajectories as episodic experiences; and (3) a Coach, which retrieves relevant experiences based on similarity and recency, and decides whether to inject task-specific advice into the agent via runtime hooks. This design empowers web agents to access long-term memory beyond their native context window, improving robustness in complex browsing tasks. Moreover, WebCoach achieves self-evolution by continuously curating episodic memory from new navigation trajectories, enabling agents to improve over time without retraining. Evaluations on the WebVoyager benchmark demonstrate that WebCoach consistently improves the performance of browser-use agents across three different LLM backbones. With a 38B model, it increases task success rates from 47% to 61% while reducing or maintaining the average number of steps. Notably, smaller base models with WebCoach achieve performance comparable to the same web agent using GPT-4o.","published":"2025-11-17T05:38:50Z","updated":"2025-11-17T05:38:50Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.12997v1","pdf_url":"https://arxiv.org/pdf/2511.12997v1","comment":"18 pages; work in progress","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=FDrGfjwQM5","openreview_venues":["ICLR 2026 Workshop MemAgents"]},{"id":"2511.12710","versioned_id":"2511.12710v2","title":"Evolve the Method, Not the Prompts: Evolutionary Synthesis of Jailbreak Attacks on LLMs","authors":["Yunhao Chen","Xin Wang","Juncheng Li","Yixu Wang","Jie Li","Yan Teng","Yingchun Wang","Xingjun Ma"],"abstract":"Automated red teaming frameworks for Large Language Models (LLMs) have become increasingly sophisticated, yet many still formulate attack optimization primarily in the prompt space. In other words, these methods mainly search for better attack wording or better strategy choices, but they do not search over executable code. By moving the search into code space, we can optimize not only the final attack prompt, but also the procedure that generates it, including execution flow, reusable logic, branching, and failure-driven repair. To overcome this gap, we introduce EvoSynth, an autonomous multi-agent framework that shifts the optimization space from prompts to executable code. Instead of refining prompts directly, EvoSynth employs a multi-agent system to autonomously engineer, evolve, and execute code-based attack algorithms. Crucially, it features a code-level self-correction loop, allowing it to iteratively rewrite the code-based algorithm in response to target-model feedback and failed attempts. Through extensive experiments, we demonstrate that EvoSynth achieves an 85.5\\% Attack Success Rate (ASR) against highly robust models like Claude-Sonnet-4.5 and a 95.9\\% average ASR across evaluated targets, while generating attacks that are significantly more diverse than those from existing methods. We release our framework to facilitate future research on evolutionary synthesis in executable code space.","published":"2025-11-16T17:52:07Z","updated":"2026-05-18T06:50:41Z","categories":["cs.CL","cs.CR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.12710v2","pdf_url":"https://arxiv.org/pdf/2511.12710v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.12063","versioned_id":"2511.12063v3","title":"TextBO: Bayesian Optimization in Language Space for Eval-Efficient Self-Improving AI","authors":["Enoch Hyunwook Kang","Hema Yoganarasimhan"],"abstract":"Large Language Models (LLMs) have enabled self-improving AI systems that iteratively generate, evaluate, and refine their outcomes. Recent studies show that prompt-optimization-based self-improvement can outperform state-of-the-art reinforcement-learning fine-tuning of LLMs, but performance is typically measured by generation efficiency. However, in many applications, the constraint is evaluation efficiency: obtaining reliable feedback is far more costly than generating candidates. To optimize for evaluation efficiency, we extend Upper Confidence Bound-Bayesian Optimization (UCB-BO), a framework known for optimal evaluation-efficiency guarantees, to the language domain. Doing so is challenging for two reasons: (i) gradients needed for UCB-BO are ill-defined in discrete prompt space; and (ii) UCB-style exploration relies on a surrogate model and acquisition function, which only live implicitly in the LLM. We overcome these challenges by proving that combining simple textual gradients (LLM-proposed local edits) with the Best-of-N selection strategy statistically emulates ascent along the gradient of the canonical UCB acquisition function. Based on this result, we propose TextBO, a simple, evaluation-efficient self-improving algorithm that operates purely in language space without explicit surrogates or calibrated uncertainty models. We empirically validate TextBO on automated ad-alignment tasks using a persona-induced preference distribution, demonstrating superior performance per evaluation compared to strong baselines such as Best-of-N and GEPA. We also evaluate TextBO's Best-of-N multi-step textual-gradient mechanism on agentic AI benchmarks by augmenting GEPA with it and show that it significantly outperforms standard GEPA. In sum, TextBO is a simple and principled framework for AI self-improving system design that bridges prompt optimization with classical Bayesian optimization.","published":"2025-11-15T07:04:44Z","updated":"2026-01-06T03:54:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.12063v3","pdf_url":"https://arxiv.org/pdf/2511.12063v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=h0XYERyeL6","openreview_venues":["ICLR 2026 Workshop RSI Poster"]},{"id":"2511.11916","versioned_id":"2511.11916v1","title":"An Analysis of Architectural Impact on LLM-based Abstract Visual Reasoning: A Systematic Benchmark on RAVEN-FAIR","authors":["Sinan Urgun","Seçkin Arı"],"abstract":"This study aims to systematically evaluate the performance of large language models (LLMs) in abstract visual reasoning problems. We examined four LLM models (GPT-4.1-Mini, Claude-3.5-Haiku, Gemini-1.5-Flash, Llama-3.3-70b) utilizing four different reasoning architectures (single-shot, embedding-controlled repetition, self-reflection, and multi-agent) on the RAVEN-FAIR dataset. Visual responses generated through a three-stage process (JSON extraction, LLM reasoning, and Tool Function) were evaluated using SSIM and LPIPS metrics; Chain-of-Thought scores and error types (semantic hallucination, numeric misperception) were analyzed. Results demonstrate that GPT-4.1-Mini consistently achieved the highest overall accuracy across all architectures, indicating a strong reasoning capability. While the multi-agent architecture occasionally altered semantic and numeric balance across models, these effects were not uniformly beneficial. Instead, each model exhibited distinct sensitivity patterns to architectural design, underscoring that reasoning effectiveness remains model-specific. Variations in response coverage further emerged as a confounding factor that complicates direct cross-architecture comparison. To estimate the upper-bound performance of each configuration, we report the best of five independent runs, representing a best-case scenario rather than an averaged outcome. This multi-run strategy aligns with recent recommendations, which emphasize that single-run evaluations are fragile and may lead to unreliable conclusions.","published":"2025-11-14T22:50:22Z","updated":"2025-11-14T22:50:22Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.11916v1","pdf_url":"https://arxiv.org/pdf/2511.11916v1","comment":"23 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.11483","versioned_id":"2511.11483v4","title":"ImAgent: A Unified Multimodal Agent Framework for Test-Time Scalable Image Generation","authors":["Kaishen Wang","Ruibo Chen","Tong Zheng","Heng Huang"],"abstract":"Recent text-to-image (T2I) models have made remarkable progress in generating visually realistic and semantically coherent images. However, they still suffer from randomness and inconsistency with the given prompts, particularly when textual descriptions are vague or underspecified. Existing approaches, such as prompt rewriting, best-of-N sampling, and self-refinement, can mitigate these issues but usually require additional modules and operate independently, hindering test-time scaling efficiency and increasing computational overhead. In this paper, we introduce ImAgent, a training-free unified multimodal agent that integrates reasoning, generation, and self-evaluation within a single framework for efficient test-time scaling. Guided by a policy controller, multiple generation actions dynamically interact and self-organize to enhance image fidelity and semantic alignment without relying on external models. Extensive experiments on image generation and editing tasks demonstrate that ImAgent consistently improves over the backbone and even surpasses other strong baselines where the backbone model fails, highlighting the potential of unified multimodal agents for adaptive and efficient image generation under test-time scaling.","published":"2025-11-14T17:00:29Z","updated":"2026-03-28T16:18:55Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2511.11483v4","pdf_url":"https://arxiv.org/pdf/2511.11483v4","comment":"8 tables, 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.09381","versioned_id":"2511.09381v1","title":"Self-Correcting Large Language Models: Generation vs. Multiple Choice","authors":["Hossein A. Rahmani","Satyapriya Krishna","Xi Wang","Mohammadmehdi Naghiaei","Emine Yilmaz"],"abstract":"Large language models have recently demonstrated remarkable abilities to self-correct their responses through iterative refinement, often referred to as self-consistency or self-reflection. However, the dynamics of this self-correction mechanism may differ substantially depending on whether the model is tasked with open-ended text generation or with selecting the most appropriate response from multiple predefined options. In this paper, we conduct a systematic investigation of these two paradigms by comparing performance trends and error-correction behaviors across various natural language understanding and reasoning tasks, covering language models of different scales and families. Our experimental results reveal distinct patterns of improvement and failure modes: \\textit{While open-ended generation often benefits from the flexibility of re-interpretation and compositional refinement, multiple-choice selection can leverage clearer solution boundaries but may be limited by the provided options}. This contrast also reflects the dual demands faced by emerging agentic LLM applications: effective agents must not only generate and refine open-ended plans or explanations, but also make reliable discrete choices when operating within constrained action spaces. Our findings, therefore, highlight that the design of self-correction mechanisms should take into account the interaction between task structure and output space, with implications for both knowledge-intensive reasoning and decision-oriented applications of LLMs.","published":"2025-11-12T14:46:40Z","updated":"2025-11-12T14:46:40Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2511.09381v1","pdf_url":"https://arxiv.org/pdf/2511.09381v1","comment":"20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:XuvjoP2jDq","versioned_id":"XuvjoP2jDq","title":"Enhancing safety of vision-language reasoning through model-to-model deliberation","authors":["SUNGWOO KIM","Yongjin Lee","Yunsick Sung"],"abstract":"Traditional vision-language models demonstrate strong performance in tasks such as image captioning and visual question answering, but they remain limited by issues such as hallucination, lack of self-correction, and shallow reasoning. These shortcomings compromise the safety, robustness, and consistency of their reasoning, particularly in ambiguous or high-stakes scenarios. In this paper, we propose three complementary frameworks aimed at enabling more trustworthy visual reasoning through structured deliberation. The first is the Self-Reflective Reasoning Single-Agent Framework, which facilitates iterative self-revision without requiring external supervision. The second is the Structured Debate Agent Framework, in which turn-based rebuttals between agents promote contrastive, multi-perspective refinement. The third is the Progressive Two-Stage Debate Agent Framework, which enables efficient yet accurate decision-making through model-to-model deliberation between smaller and larger agents. Experiments on the COCO dataset demonstrate that all three frameworks significantly enhance reasoning performance, achieving up to a 5.4\\% improvement in intersection over union (IoU) and over a 40\\% reduction in localization error compared to a single-pass baseline. Further evaluation across robustness (IoU), safety (self-revision rate, SRR), and consistency (consistency score, CS) confirms the effectiveness of multi-round, self-corrective, and multi-agent reasoning strategies. These results establish a practical path toward safer, more robust, and more interpretable vision-language models through lightweight, deliberative inference frameworks.","published":"2025-11-12T13:17:54+00:00","updated":"2026-05-26T11:18:55+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=XuvjoP2jDq","openreview_url":"https://openreview.net/forum?id=XuvjoP2jDq","pdf_url":"https://openreview.net/pdf?id=XuvjoP2jDq","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2511.15715","versioned_id":"2511.15715v1","title":"Graph-Memoized Reasoning: Foundations Structured Workflow Reuse in Intelligent Systems","authors":["Yash Raj Singh"],"abstract":"Modern large language model-based reasoning systems frequently recompute similar reasoning steps across tasks, wasting computational resources, inflating inference latency, and limiting reproducibility. These inefficiencies underscore the need for persistent reasoning mechanisms that can recall and reuse prior computational traces. We introduce Graph-Memoized Reasoning, a formal framework for representing, storing, and reusing reasoning workflows as graph-structured memory. By encoding past decision graphs and retrieving them through structural and semantic similarity, our approach enables compositional reuse of subgraphs across new reasoning tasks. We formulate an optimization objective that minimizes total reasoning cost regularized by inconsistency between stored and generated workflows, providing a theoretical foundation for efficiency-consistency trade-offs in intelligent systems. We outline a conceptual evaluation protocol aligned with the proposed optimization objective. This framework establishes the groundwork for interpretable, cost-efficient, and self-improving reasoning architectures, offering a step toward persistent memory in large-scale agentic systems.","published":"2025-11-11T07:42:37Z","updated":"2025-11-11T07:42:37Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.15715v1","pdf_url":"https://arxiv.org/pdf/2511.15715v1","comment":"5 Pages, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.07833","versioned_id":"2511.07833v3","title":"MURPHY: Feedback-Aware GRPO with Retrospective Credit Assignment for Multi-Turn Code Generation","authors":["Chanakya Ekbote","Vijay Lingam","Sujay Sanghavi","Jun Huan","Behrooz Omidvar-Tehrani","Anoop Deoras","Stefano Soatto"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has become a standard recipe for post-training LLMs on reasoning tasks, with Group Relative Policy Optimization (GRPO) emerging as a leading approach. However, GRPO and its variants are inherently single-turn: they optimize from terminal rewards on isolated prompt-response pairs, leaving them poorly suited to agentic settings where models must iteratively refine solutions in response to environmental feedback. We introduce MURPHY, a multi-turn extension of GRPO for self-correcting code generation. MURPHY constructs feedback-conditioned rollout trees in which failed candidate solutions are paired with executor feedback and expanded into subsequent turns, and propagates rewards backward through the tree so that later successful refinements credit earlier attempts that surfaced informative feedback. We study two propagation strategies, Max Reward (MARS) and Mean Reward (MERS), and introduce post-rollout pruning mechanisms that reduce multi-turn optimization cost. Across three code generation benchmarks (HumanEval, MBPP, LiveCodeBench-v6) and two model families (Qwen3-1.7B/4B, OLMo-2-7B), MURPHY delivers up to 6% absolute pass@1 gains over the strongest prior multi-turn execution-feedback methods. Gains are largest on the Medium/Hard subset (+4.38/+4.20 at Iter-5), where iterative self-correction matters more.","published":"2025-11-11T05:03:22Z","updated":"2026-05-09T19:03:03Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.07833v3","pdf_url":"https://arxiv.org/pdf/2511.07833v3","comment":"21 pages, 2 figures, 8 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.06449","versioned_id":"2511.06449v2","title":"FLEX: Continuous Agent Evolution via Forward Learning from Experience","authors":["Zhicheng Cai","Xinyuan Guo","Yu Pei","Jiangtao Feng","Jinsong Su","Jiangjie Chen","Ya-Qin Zhang","Wei-Ying Ma","Mingxuan Wang","Hao Zhou"],"abstract":"Autonomous agents driven by Large Language Models (LLMs) have revolutionized reasoning and problem-solving but remain static after training, unable to grow with experience as intelligent beings do during deployment. We introduce Forward Learning with EXperience (FLEX), a gradient-free learning paradigm that enables LLM agents to continuously evolve through accumulated experience. Specifically, FLEX cultivates scalable and inheritable evolution by constructing a structured experience library through continual reflection on successes and failures during interaction with the environment. FLEX delivers substantial improvements on mathematical reasoning, chemical retrosynthesis, and protein fitness prediction (up to 23% on AIME25, 10% on USPTO50k, and 14% on ProteinGym). We further identify a clear scaling law of experiential growth and the phenomenon of experience inheritance across agents, marking a step toward scalable and inheritable continuous agent evolution. Project Page: https://flex-gensi-thuair.github.io.","published":"2025-11-09T16:31:39Z","updated":"2025-12-08T02:42:09Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2511.06449v2","pdf_url":"https://arxiv.org/pdf/2511.06449v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.06185","versioned_id":"2511.06185v2","title":"Dataforge: Agentic Platform for Autonomous Data Engineering","authors":["Xinyuan Wang","Hongyu Cao","Kunpeng Liu","Yanjie Fu"],"abstract":"The growing demand for artificial intelligence (AI) applications in materials discovery, molecular modeling, and climate science has made data preparation a critical but labor-intensive bottleneck. Raw data from diverse sources must be cleaned, normalized, and transformed to become AI-ready, where effective feature transformation and selection are essential for robust learning. We present Dataforge, an LLM-powered agentic data engineering platform for tabular data that is automatic, safe, and non-expert friendly. It autonomously performs data cleaning and iteratively optimizes feature operations under a budgeted feedback loop with automatic stopping. Across tabular benchmarks, it achieves the best overall downstream performance; ablations further confirm the roles of routing/iterative refinement and grounding in accuracy and reliability. Dataforge demonstrates a practical path toward autonomous data agents that transform raw data from data to better data.","published":"2025-11-09T01:58:13Z","updated":"2026-02-16T02:14:19Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.06185v2","pdf_url":"https://arxiv.org/pdf/2511.06185v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.04646","versioned_id":"2511.04646v1","title":"DR. WELL: Dynamic Reasoning and Learning with Symbolic World Model for Embodied LLM-Based Multi-Agent Collaboration","authors":["Narjes Nourzad","Hanqing Yang","Shiyu Chen","Carlee Joe-Wong"],"abstract":"Cooperative multi-agent planning requires agents to make joint decisions with partial information and limited communication. Coordination at the trajectory level often fails, as small deviations in timing or movement cascade into conflicts. Symbolic planning mitigates this challenge by raising the level of abstraction and providing a minimal vocabulary of actions that enable synchronization and collective progress. We present DR. WELL, a decentralized neurosymbolic framework for cooperative multi-agent planning. Cooperation unfolds through a two-phase negotiation protocol: agents first propose candidate roles with reasoning and then commit to a joint allocation under consensus and environment constraints. After commitment, each agent independently generates and executes a symbolic plan for its role without revealing detailed trajectories. Plans are grounded in execution outcomes via a shared world model that encodes the current state and is updated as agents act. By reasoning over symbolic plans rather than raw trajectories, DR. WELL avoids brittle step-level alignment and enables higher-level operations that are reusable, synchronizable, and interpretable. Experiments on cooperative block-push tasks show that agents adapt across episodes, with the dynamic world model capturing reusable patterns and improving task completion rates and efficiency. Experiments on cooperative block-push tasks show that our dynamic world model improves task completion and efficiency through negotiation and self-refinement, trading a time overhead for evolving, more efficient collaboration strategies.","published":"2025-11-06T18:37:18Z","updated":"2025-11-06T18:37:18Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.04646v1","pdf_url":"https://arxiv.org/pdf/2511.04646v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.03925","versioned_id":"2511.03925v1","title":"Collaborative Agents for Automated Program Repair in Ruby","authors":["Nikta Akbarpour","Mahdieh Sadat Benis","Fatemeh Hendijani Fard","Ali Ouni","Mohamed Aymen Saied"],"abstract":"Automated Program Repair (APR) has advanced rapidly with Large Language Models (LLMs), but most existing methods remain computationally expensive, and focused on a small set of languages. Ruby, despite its widespread use in web development and the persistent challenges faced by its developers, has received little attention in APR research. In this paper, we introduce RAMP, a novel lightweight framework that formulates program repair as a feedback-driven, iterative process for Ruby. RAMP employs a team of collaborative agents that generate targeted tests, reflect on errors, and refine candidate fixes until a correct solution is found. Unlike prior approaches, RAMP is designed to avoid reliance on large multilingual repair databases or costly fine-tuning, instead operating directly on Ruby through lightweight prompting and test-driven feedback. Evaluation on the XCodeEval benchmark shows that RAMP achieves a pass@1 of 67% on Ruby, outper-forming prior approaches. RAMP converges quickly within five iterations, and ablation studies confirm that test generation and self-reflection are key drivers of its performance. Further analysis shows that RAMP is particularly effective at repairing wrong answers, compilation errors, and runtime errors. Our approach provides new insights into multi-agent repair strategies, and establishes a foundation for extending LLM-based debugging tools to under-studied languages.","published":"2025-11-06T00:00:17Z","updated":"2025-11-06T00:00:17Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.03925v1","pdf_url":"https://arxiv.org/pdf/2511.03925v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=f9u3z49klS","openreview_venues":["arxiv"]},{"id":"2511.03773","versioned_id":"2511.03773v2","title":"Scaling Agent Learning via Experience Synthesis","authors":["Zhaorun Chen","Zhuokai Zhao","Kai Zhang","Bo Liu","Qi Qi","Yifan Wu","Tarun Kalluri","Sara Cao","Yuanhao Xiong","Haibo Tong","Huaxiu Yao","Hengduo Li","Jiacheng Zhu","Xian Li","Dawn Song","Bo Li","Jason Weston","Dat Huynh"],"abstract":"While reinforcement learning (RL) can empower autonomous agents by enabling self-improvement through interaction, its practical adoption remains challenging due to costly rollouts, limited task diversity, unreliable reward signals, and infrastructure complexity, all of which obstruct the collection of scalable experience data. To address these challenges, we introduce DreamGym, the first unified framework designed to synthesize diverse experiences with scalability in mind to enable effective online RL training for autonomous agents. Rather than relying on expensive real-environment rollouts, DreamGym distills environment dynamics into a reasoning-based experience model that derives consistent state transitions and feedback signals through step-by-step reasoning, enabling scalable agent rollout collection for RL. To improve the stability and quality of transitions, DreamGym leverages an experience replay buffer initialized with offline real-world data and continuously enriched with fresh interactions to actively support agent training. To improve knowledge acquisition, DreamGym adaptively generates new tasks that challenge the current agent policy, enabling more effective online curriculum learning. Experiments across diverse environments and agent backbones demonstrate that DreamGym substantially improves RL training, both in fully synthetic settings and in sim-to-real transfer scenarios. On non-RL-ready tasks like WebArena, DreamGym outperforms all baselines by over 30%. And in RL-ready but costly settings, it matches GRPO and PPO performance using only synthetic interactions. When transferring a policy trained purely on synthetic experiences to real-environment RL, DreamGym yields significant additional performance gains while requiring far fewer real-world interactions, providing a scalable warm-start strategy for general-purpose RL.","published":"2025-11-05T18:58:48Z","updated":"2025-11-10T05:02:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.03773v2","pdf_url":"https://arxiv.org/pdf/2511.03773v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=cf7qpBwttr","openreview_venues":["ICLR 2026 Poster"]},{"id":"2511.03227","versioned_id":"2511.03227v2","title":"Node-Based Editing for Multimodal Generation of Text, Audio, Image, and Video","authors":["Alexander Htet Kyaw","Lenin Ravindranath Sivalingam"],"abstract":"We present a node-based storytelling system for multimodal content generation. The system represents stories as graphs of nodes that can be expanded, edited, and iteratively refined through direct user edits and natural-language prompts. Each node can integrate text, images, audio, and video, allowing creators to compose multimodal narratives. A task selection agent routes between specialized generative tasks that handle story generation, node structure reasoning, node diagram formatting, and context generation. The interface supports targeted editing of individual nodes, automatic branching for parallel storylines, and node-based iterative refinement. Our results demonstrate that node-based editing supports control over narrative structure and iterative generation of text, images, audio, and video. We report quantitative outcomes on automatic story outline generation and qualitative observations of editing workflows. Finally, we discuss current limitations such as scalability to longer narratives and consistency across multiple nodes, and outline future work toward human-in-the-loop and user-centered creative AI tools.","published":"2025-11-05T06:35:10Z","updated":"2025-11-06T01:45:32Z","categories":["cs.HC","cs.AI","cs.MM"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2511.03227v2","pdf_url":"https://arxiv.org/pdf/2511.03227v2","comment":"Accepted to NeurIPS 2025, Conference on Neural Information Processing Systems, Workshop on Generative and Protective AI for Content Creation","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=SsJQJ7qrES","openreview_venues":["NeurIPS 2025 Workshop GenProCC"]},{"id":"2511.03179","versioned_id":"2511.03179v3","title":"Toward Autonomous Engineering Design: A Knowledge-Guided Multi-Agent Framework","authors":["Varun Kumar","George Em Karniadakis"],"abstract":"The engineering design process often demands expertise from multiple domains, leading to complex collaborations and iterative refinements. Traditional methods can be resource-intensive and prone to inefficiencies. To address this, we formalize the engineering design process through a multi-agent AI framework that integrates structured design and review loops. The framework introduces specialized knowledge-driven agents that collaborate to generate and refine design candidates. As an exemplar, we demonstrate its application to the aerodynamic optimization of 4-digit NACA airfoils. The framework consists of three key AI agents: a Graph Ontologist, a Design Engineer, and a Systems Engineer. The Graph Ontologist employs a Large Language Model (LLM) to construct two domain-specific knowledge graphs from airfoil design literature. The Systems Engineer, informed by a human manager, formulates technical requirements that guide design generation and evaluation. The Design Engineer leverages the design knowledge graph and computational tools to propose candidate airfoils meeting these requirements. The Systems Engineer reviews and provides feedback both qualitative and quantitative using its own knowledge graph, forming an iterative feedback loop until a design is validated by the manager. The final design is then optimized to maximize performance metrics such as the lift-to-drag ratio. Overall, this work demonstrates how collaborative AI agents equipped with structured knowledge representations can enhance efficiency, consistency, and quality in the engineering design process.","published":"2025-11-05T04:55:25Z","updated":"2025-12-30T03:15:01Z","categories":["cs.AI","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2511.03179v3","pdf_url":"https://arxiv.org/pdf/2511.03179v3","comment":"Added appendices and updated literature review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.03153","versioned_id":"2511.03153v2","title":"RefAgent: A Multi-agent LLM-based Framework for Automatic Software Refactoring","authors":["Khouloud Oueslati","Maxime Lamothe","Foutse Khomh"],"abstract":"Large Language Models (LLMs) have substantially influenced various software engineering tasks. Indeed, in the case of software refactoring, traditional LLMs have shown the ability to reduce development time and enhance code quality. However, these LLMs often rely on static, detailed instructions for specific tasks. In contrast, LLM-based agents can dynamically adapt to evolving contexts and autonomously make decisions by interacting with software tools and executing workflows. In this paper, we explore the potential of LLM-based agents in supporting refactoring activities. Specifically, we introduce RefAgent, a multi-agent LLM-based framework for end-to-end software refactoring. RefAgent consists of specialized agents responsible for planning, executing, testing, and iteratively refining refactorings using self-reflection and tool-calling capabilities. We evaluate RefAgent on eight open-source Java projects, comparing its effectiveness against a single-agent approach, a search-based refactoring tool, and historical developer refactorings. Our assessment focuses on: (1) the impact of generated refactorings on software quality, (2) the ability to identify refactoring opportunities, and (3) the contribution of each LLM agent through an ablation study. Our results show that RefAgent achieves a median unit test pass rate of 90%, reduces code smells by a median of 52.5%, and improves key quality attributes (e.g., reusability) by a median of 8.6%. Additionally, it closely aligns with developer refactorings and the search-based tool in identifying refactoring opportunities, attaining a median F1-score of 79.15% and 72.7%, respectively. Compared to single-agent approaches, RefAgent improves the median unit test pass rate by 64.7% and the median compilation success rate by 40.1%. These findings highlight the promise of multi-agent architectures in advancing automated software refactoring.","published":"2025-11-05T03:20:58Z","updated":"2026-03-04T19:27:09Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2511.03153v2","pdf_url":"https://arxiv.org/pdf/2511.03153v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2511.02239","versioned_id":"2511.02239v2","title":"LACY: A Vision-Language Model-based Language-Action Cycle for Self-Improving Robotic Manipulation","authors":["Youngjin Hong","Houjian Yu","Mingen Li","Changhyun Choi"],"abstract":"Learning generalizable policies for robotic manipulation increasingly relies on large-scale models that map language instructions to actions (L2A). However, this one-way paradigm often produces policies that execute tasks without deeper contextual understanding, limiting their ability to generalize or explain their behavior. We argue that the complementary skill of mapping actions back to language (A2L) is essential for developing more holistic grounding. An agent capable of both acting and explaining its actions can form richer internal representations and unlock new paradigms for self-supervised learning. We introduce LACY (Language-Action Cycle), a unified framework that learns such bidirectional mappings within a single vision-language model. LACY is jointly trained on three synergistic tasks: generating parameterized actions from language (L2A), explaining observed actions in language (A2L), and verifying semantic consistency between two language descriptions (L2C). This enables a self-improving cycle that autonomously generates and filters new training data through an active augmentation strategy targeting low-confidence cases, thereby improving the model without additional human labels. Experiments on pick-and-place tasks in both simulation and the real world show that LACY improves task success rates by 56.46% on average and yields more robust language-action grounding for robotic manipulation. Project page: https://vla2026.github.io/LACY/","published":"2025-11-04T04:02:51Z","updated":"2026-05-21T21:13:30Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2511.02239v2","pdf_url":"https://arxiv.org/pdf/2511.02239v2","comment":"Accepted to ICRA 2026. Project page: https://vla2026.github.io/LACY/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:xrLhmzw5p2","versioned_id":"xrLhmzw5p2","title":"Spectral Guarantees for Policy Drift in Self-Refining LLM Agents","authors":[],"abstract":"Autonomous large language model (LLM) agents are operating more in self-refining loops, and update their internal reasoning or policy based on prior outputs. While this self-improvement model enhances capability, it potentially introduces the risk of uncontrollable policy drift. Accordingly, this paper develops a theoretical framework for analyzing such dynamics using spectral operator theory. The paper models self-refinement as a nonlinear transformation \\(T\\) over policy space and derives sufficient conditions for convergence to an aligned fixed point \\(\\pi^*\\) via the spectral radius of the Jacobian \\(J_T(\\pi^*)\\). We establish that if \\(\\rho(J_T(\\pi^*))<1\\), the agent’s refinement process is contractive and guarantees bounded drift and interpretable convergence. A small-scale empirical illustration using reflective prompting demonstrates estimation of contraction coefficients in LLM reflection loops. Our results provide the first spectral guarantees for stability and controllability in autonomous LLM agents.","published":"2025-11-04T03:29:02+00:00","updated":"2026-03-09T10:43:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=xrLhmzw5p2","openreview_url":"https://openreview.net/forum?id=xrLhmzw5p2","pdf_url":"https://openreview.net/pdf?id=xrLhmzw5p2","comment":"AAAI 2026 TrustAgent Workshop Poster","journal_ref":"AAAI 2026 TrustAgent Workshop Poster","doi":"","venue":"AAAI 2026 TrustAgent Workshop Poster","venue_id":"AAAI.org/2026/Workshop/TrustAgent","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2511.00330","versioned_id":"2511.00330v1","title":"Sherlock: Reliable and Efficient Agentic Workflow Execution","authors":["Yeonju Ro","Haoran Qiu","Íñigo Goiri","Rodrigo Fonseca","Ricardo Bianchini","Aditya Akella","Zhangyang Wang","Mattan Erez","Esha Choukse"],"abstract":"With the increasing adoption of large language models (LLM), agentic workflows, which compose multiple LLM calls with tools, retrieval, and reasoning steps, are increasingly replacing traditional applications. However, such workflows are inherently error-prone: incorrect or partially correct output at one step can propagate or even amplify through subsequent stages, compounding the impact on the final output. Recent work proposes integrating verifiers that validate LLM output or actions, such as self-reflection, debate, or LLM-as-a-judge mechanisms. Yet, verifying every step introduces significant latency and cost overheads. In this work, we seek to answer three key questions: which nodes in a workflow are most error-prone and thus deserve costly verification, how to select the most appropriate verifier for each node, and how to use verification with minimal impact to latency? Our solution, Sherlock, addresses these using counterfactual analysis on agentic workflows to identify error-prone nodes and selectively attaching cost-optimal verifiers only where necessary. At runtime, Sherlock speculatively executes downstream tasks to reduce latency overhead, while verification runs in the background. If verification fails, execution is rolled back to the last verified output. Compared to the non-verifying baseline, Sherlock delivers an 18.3% accuracy gain on average across benchmarks. Sherlock reduces workflow execution time by up to 48.7% over non-speculative execution and lowers verification cost by 26.0% compared to the Monte Carlo search-based method, demonstrating that principled, fault-aware verification effectively balances efficiency and reliability in agentic workflows.","published":"2025-11-01T00:17:57Z","updated":"2025-11-01T00:17:57Z","categories":["cs.MA","cs.SE"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2511.00330v1","pdf_url":"https://arxiv.org/pdf/2511.00330v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.27051","versioned_id":"2510.27051v1","title":"Adaptive Data Flywheel: Applying MAPE Control Loops to AI Agent Improvement","authors":["Aaditya Shukla","Sidney Knowles","Meenakshi Madugula","Dave Farris","Ryan Angilly","Santiago Pombo","Anbang Xu","Lu An","Abhinav Balasubramanian","Tan Yu","Jiaxiang Ren","Rama Akkiraju"],"abstract":"Enterprise AI agents must continuously adapt to maintain accuracy, reduce latency, and remain aligned with user needs. We present a practical implementation of a data flywheel in NVInfo AI, NVIDIA's Mixture-of-Experts (MoE) Knowledge Assistant serving over 30,000 employees. By operationalizing a MAPE-driven data flywheel, we built a closed-loop system that systematically addresses failures in retrieval-augmented generation (RAG) pipelines and enables continuous learning. Over a 3-month post-deployment period, we monitored feedback and collected 495 negative samples. Analysis revealed two major failure modes: routing errors (5.25\\%) and query rephrasal errors (3.2\\%). Using NVIDIA NeMo microservices, we implemented targeted improvements through fine-tuning. For routing, we replaced a Llama 3.1 70B model with a fine-tuned 8B variant, achieving 96\\% accuracy, a 10x reduction in model size, and 70\\% latency improvement. For query rephrasal, fine-tuning yielded a 3.7\\% gain in accuracy and a 40\\% latency reduction. Our approach demonstrates how human-in-the-loop (HITL) feedback, when structured within a data flywheel, transforms enterprise AI agents into self-improving systems. Key learnings include approaches to ensure agent robustness despite limited user feedback, navigating privacy constraints, and executing staged rollouts in production. This work offers a repeatable blueprint for building robust, adaptive enterprise AI agents capable of learning from real-world usage at scale.","published":"2025-10-30T23:41:06Z","updated":"2025-10-30T23:41:06Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.27051v1","pdf_url":"https://arxiv.org/pdf/2510.27051v1","comment":"20 pages, 5 figures, 5 tables. Presents MAPE-K control loop application to enterprise AI agent improvement with experimental validation on NVIDIA's NVInfo AI system","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.26852","versioned_id":"2510.26852v2","title":"CATArena: Evaluating Evolutionary Capabilities of Code Agents via Iterative Tournaments","authors":["Lingyue Fu","Xin Ding","Linyue Pan","Yaoming Zhu","Shao Zhang","Lin Qiu","Weiwen Liu","Weinan Zhang","Xuezhi Cao","Xunliang Cai","Jiaxin Ding","Yong Yu"],"abstract":"Current evaluation for Large Language Model (LLM) code agents predominantly focus on generating functional code in single-turn scenarios, which fails to evaluate the agent's capability for continuous code optimization and multi-turn iterative development. To bridge this gap, we introduce CATArena, a framework designed to evaluate the evolutionary capabilities of code agents via iterative tournaments. Agents engage in multi-turn tournaments and continuously refine their code through self-reflection and peer-learning based on comprehensive execution feedback. For evaluation, we propose a dual-metric system to decouple static generation proficiency from evolutionary potential. Extensive experiments reveal that an agent's evolutionary potential is not strictly correlated with its initial proficiency. Our analysis further reveals that current agents struggle to concurrently leverage both peer-learning and self-reflection for effective performance gains. Furthermore, the results validate CATArena's high extensibility and resistance to variance tasks, establishing it as a continuous and reliable standard for assessing the evolutionary capability of LLM code agents.","published":"2025-10-30T15:22:53Z","updated":"2026-01-30T11:04:12Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.26852v2","pdf_url":"https://arxiv.org/pdf/2510.26852v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=913g1X1YAW","openreview_venues":["ICML 2026 regular"]},{"id":"2510.26423","versioned_id":"2510.26423v1","title":"Nexus: Execution-Grounded Multi-Agent Test Oracle Synthesis","authors":["Dong Huang","Mingzhe Du","Jie M. Zhang","Zheng Lin","Meng Luo","Qianru Zhang","See-Kiong Ng"],"abstract":"Test oracle generation in non-regression testing is a longstanding challenge in software engineering, where the goal is to produce oracles that can accurately determine whether a function under test (FUT) behaves as intended for a given input. In this paper, we introduce Nexus, a novel multi-agent framework to address this challenge. Nexus generates test oracles by leveraging a diverse set of specialized agents that synthesize test oracles through a structured process of deliberation, validation, and iterative self-refinement. During the deliberation phase, a panel of four specialist agents, each embodying a distinct testing philosophy, collaboratively critiques and refines an initial set of test oracles. Then, in the validation phase, Nexus generates a plausible candidate implementation of the FUT and executes the proposed oracles against it in a secure sandbox. For any oracle that fails this execution-based check, Nexus activates an automated selfrefinement loop, using the specific runtime error to debug and correct the oracle before re-validation. Our extensive evaluation on seven diverse benchmarks demonstrates that Nexus consistently and substantially outperforms state-of-theart baselines. For instance, Nexus improves the test-level oracle accuracy on the LiveCodeBench from 46.30% to 57.73% for GPT-4.1-Mini. The improved accuracy also significantly enhances downstream tasks: the bug detection rate of GPT4.1-Mini generated test oracles on HumanEval increases from 90.91% to 95.45% for Nexus compared to baselines, and the success rate of automated program repair improves from 35.23% to 69.32%.","published":"2025-10-30T12:20:25Z","updated":"2025-10-30T12:20:25Z","categories":["cs.SE","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.26423v1","pdf_url":"https://arxiv.org/pdf/2510.26423v1","comment":"Under Review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=lbZNHMqMAI","openreview_venues":["ICML 2026 Workshop DL4C Poster","Submitted to ICLR 2026"]},{"id":"2510.26167","versioned_id":"2510.26167v2","title":"ToolRM: Towards Agentic Tool-Use Reward Modeling","authors":["Renhao Li","Jianhong Tu","Yang Su","Yantao Liu","Fei Huang","Hamid Alinejad-Rokny","Derek F. Wong","Junyang Lin","Min Yang"],"abstract":"Reward models (RMs) play a critical role in aligning large language models (LLMs) with human preferences. Yet in the domain of tool learning, the lack of RMs specifically designed for function-calling tasks has limited progress toward more capable agentic AI. We introduce ToolRM, a family of lightweight reward models tailored for general tool-use scenarios. To build these models, we propose a novel pipeline that constructs high-quality pairwise preference data using rule-based scoring and multidimensional sampling. This yields ToolPref-Pairwise-30K, a diverse, balanced, and challenging preference dataset that supports both generative and discriminative reward modeling. We also introduce TRBench$_{BFCL}$, a benchmark built on the agent evaluation suite BFCL to evaluate RMs on tool calling tasks. Trained on our constructed data, models from the Qwen3-4B/8B series achieve up to 17.94% higher accuracy, substantially outperforming frontier LLMs and RMs in pairwise reward judgments. Beyond training objectives, generative ToolRM generalizes to broader critique tasks, including Best-of-N sampling and self-correction. Experiments on ACEBench highlight its effectiveness and efficiency, enabling inference-time scaling while reducing output token usage by over 66%. Its support for downstream RL training further validates its practical utility. We release data to facilitate future research.","published":"2025-10-30T06:08:27Z","updated":"2026-01-13T13:28:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.26167v2","pdf_url":"https://arxiv.org/pdf/2510.26167v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.25223","versioned_id":"2510.25223v3","title":"FELA: A Multi-Agent Evolutionary System for Feature Engineering of Industrial Event Log Data","authors":["Kun Ouyang","Haoyu Wang","Dong Fang"],"abstract":"Event log data, recording fine-grained user actions and system events, represent one of the most valuable assets for modern digital services. However, the complexity and heterogeneity of industrial event logs--characterized by large scale, high dimensionality, diverse data types, and intricate temporal or relational structures--make feature engineering extremely challenging. Existing automatic feature engineering approaches, such as AutoML or genetic methods, often suffer from limited explainability, rigid predefined operations, and poor adaptability to complicated heterogeneous data. In this paper, we propose FELA (Feature Engineering LLM Agents), a multi-agent evolutionary system that autonomously extracts meaningful and high-performing features from complex industrial event log data. FELA integrates the reasoning and coding capabilities of large language models (LLMs) with an insight-guided self-evolution paradigm. Specifically, FELA employs specialized agents--Idea Agents, Code Agents, and Critic Agents--to collaboratively generate, validate, and implement novel feature ideas. An Evaluation Agent summarizes feedback and updates a hierarchical knowledge base and dual-memory system to enable continual improvement. Moreover, FELA introduces an agentic evolution algorithm, combining reinforcement learning and genetic algorithm principles to balance exploration and exploitation across the idea space. Extensive experiments on real industrial datasets demonstrate that FELA can generate explainable, domain-relevant features that significantly improve model performance while reducing manual effort. Our results highlight the potential of LLM-based multi-agent systems as a general framework for automated, interpretable, and adaptive feature engineering in complex real-world environments.","published":"2025-10-29T06:57:32Z","updated":"2026-04-22T03:39:54Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.25223v3","pdf_url":"https://arxiv.org/pdf/2510.25223v3","comment":"14 pages, 11 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.24980","versioned_id":"2510.24980v1","title":"FT-ARM: Fine-Tuned Agentic Reflection Multimodal Language Model for Pressure Ulcer Severity Classification with Reasoning","authors":["Reza Saadati Fard","Emmanuel Agu","Palawat Busaranuvong","Deepak Kumar","Shefalika Gautam","Bengisu Tulu","Diane Strong","Lorraine Loretz"],"abstract":"Pressure ulcers (PUs) are a serious and prevalent healthcare concern. Accurate classification of PU severity (Stages I-IV) is essential for proper treatment but remains challenging due to subtle visual distinctions and subjective interpretation, leading to variability among clinicians. Prior AI-based approaches using Convolutional Neural Networks (CNNs) and Vision Transformers (ViTs) achieved promising accuracy but offered limited interpretability. We present FT-ARM (Fine-Tuned Agentic Reflection Multimodal model), a fine-tuned multimodal large language model (MLLM) with an agentic self-reflection mechanism for pressure ulcer severity classification. Inspired by clinician-style diagnostic reassessment, FT-ARM iteratively refines its predictions by reasoning over visual features and encoded clinical knowledge from text, enhancing both accuracy and consistency. On the publicly available Pressure Injury Image Dataset (PIID), FT-ARM, fine-tuned from LLaMA 3.2 90B, achieved 85% accuracy in classifying PU stages I-IV, surpassing prior CNN-based models by +4%. Unlike earlier CNN/ViT studies that relied solely on offline evaluations, FT-ARM is designed and tested for live inference, reflecting real-time deployment conditions. Furthermore, it produces clinically grounded natural-language explanations, improving interpretability and trust. By integrating fine-tuning and reflective reasoning across multimodal inputs, FT-ARM advances the reliability, transparency, and clinical applicability of automated wound assessment systems, addressing the critical need for consistent and explainable PU staging to support improved patient care.","published":"2025-10-28T21:23:32Z","updated":"2025-10-28T21:23:32Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.24980v1","pdf_url":"https://arxiv.org/pdf/2510.24980v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=bLuKoieyvT"},{"id":"2510.24145","versioned_id":"2510.24145v3","title":"OpsAgent: An Evolving Multi-agent System for Incident Management in Microservices","authors":["Yu Luo","Jiamin Jiang","Jingfei Feng","Lei Tao","Qingliang Zhang","Xidao Wen","Yongqian Sun","Shenglin Zhang","Dan Pei"],"abstract":"Incident management (IM) is central to the reliability of large-scale microservice systems. Yet manual IM, where on-call engineers examine metrics, logs, and traces is labor-intensive and error-prone in the face of massive and heterogeneous observability data. Existing automated IM approaches often struggle to generalize across systems, provide limited interpretability, and incur high deployment costs, which hinders adoption in practice. In this paper, we present OpsAgent, a lightweight, self-evolving multi-agent system for IM that employs a training-free data processor to convert heterogeneous observability data into structured textual descriptions, along with a multi-agent collaboration framework that makes diagnostic inference transparent and auditable. To support continual capability growth, OpsAgent also introduces a dual self-evolution mechanism that integrates internal model updates with external experience accumulation, thereby closing the deployment loop. Comprehensive experiments on the OPENRCA benchmark demonstrate state-of-the-art performance and show that OpsAgent is generalizable, interpretable, cost-efficient, and self-evolving, making it a practically deployable and sustainable solution for long-term operation in real-world microservice systems. Notably, its deployment in Lenovo's production environment further validates its effectiveness in real-world industrial settings.","published":"2025-10-28T07:38:15Z","updated":"2026-05-12T16:00:09Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.24145v3","pdf_url":"https://arxiv.org/pdf/2510.24145v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:2iWCII5GMT","versioned_id":"2iWCII5GMT","title":"SAMKE: An Open-Ended Autonomous Foundation-Model-Based Agent for Meta-Knowledge Discovery and Learning","authors":["Nitin Vetcha","Dianbo Liu"],"abstract":"Given the recent tremendous success of large language models (LLMs), there has been an increasing trend in applying them to several down-stream tasks via fine-tuning (FT). However, there persist two significant challenges in FT - 1) curation of high-quality task-specific data and 2) expensive time-consuming model adaptation via gradient descent optimization. To mitigate these limitations, we leverage prior works in large-scale parameter generation for LLMs and propose Scientific Autonomous Meta-Knowledge Explore (SAMKE) to open up a new paradigm of parameter-level meta learning, thereby serving a critical advance in the AI Scientist domain. SAMKE is an open-ended autonomous foundation-model-based agent which is capable of self-improvement by discovering and learning the rich meta-knowledge information present in large neural network weights, thereby enabling efficient adaptation of LLMs by parameter-level weight modifications to unseen domains as well. To achieve this, SAMKE has a multi-level reinforcement learning approach to train models for efficient understanding of parameter space and offers higher degree of flexibility compared to prior works on self-evolution by providing freedom to the model for choosing its own adaptation strategy thereby breaking the scaling solely through data regime. Early experiments demonstrate the superior performance of SAMKE in the common-sense reasoning domain as it outperforms task-specific FT by 23.6% on average and even some of the most recent works in parameter generation (by 10.4%), model merging (by 24.3%) and test-time learning (by 25.2%) as well out-of-domain tasks such as coding, social, logical and mathematical reasoning as well.","published":"2025-10-28T04:24:42+00:00","updated":"2026-01-20T17:53:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=2iWCII5GMT","openreview_url":"https://openreview.net/forum?id=2iWCII5GMT","pdf_url":"https://openreview.net/pdf?id=2iWCII5GMT","comment":"PLAN-FM Bridge @ AAAI 2026","journal_ref":"PLAN-FM Bridge @ AAAI 2026","doi":"","venue":"PLAN-FM Bridge @ AAAI 2026","venue_id":"AAAI.org/2026/Bridge/PLAN-FM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2510.23601","versioned_id":"2510.23601v1","title":"Alita-G: Self-Evolving Generative Agent for Agent Generation","authors":["Jiahao Qiu","Xuan Qi","Hongru Wang","Xinzhe Juan","Yimin Wang","Zelin Zhao","Jiayi Geng","Jiacheng Guo","Peihang Li","Jingzhe Shi","Shilong Liu","Mengdi Wang"],"abstract":"Large language models (LLMs) have been shown to perform better when scaffolded into agents with memory, tools, and feedback. Beyond this, self-evolving agents have emerged, but current work largely limits adaptation to prompt rewriting or failure retries. Therefore, we present ALITA-G, a self-evolution framework that transforms a general-purpose agent into a domain expert by systematically generating, abstracting, and curating Model Context Protocol (MCP) tools. In this framework, a generalist agent executes a curated suite of target-domain tasks and synthesizes candidate MCPs from successful trajectories. These are then abstracted to parameterized primitives and consolidated into an MCP Box. At inference time, ALITA-G performs retrieval-augmented MCP selection with the help of each tool's descriptions and use cases, before executing an agent equipped with the MCP Executor. Across several benchmarks GAIA, PathVQA, and Humanity's Last Exam, ALITA-G attains strong gains while reducing computation costs. On GAIA validation, it achieves 83.03% pass@1 and 89.09% pass@3, establishing a new state-of-the-art result while reducing mean tokens per example by approximately 15% relative to a strong baseline agent. ALITA-G thus provides a principled pathway from generalist capability to reusable, domain-specific competence, improving both accuracy and efficiency on complex reasoning tasks.","published":"2025-10-27T17:59:14Z","updated":"2025-10-27T17:59:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.23601v1","pdf_url":"https://arxiv.org/pdf/2510.23601v1","comment":"15 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=xf2JC4531b","openreview_venues":["ICLR 2026 Conference Desk Rejected Submission"]},{"id":"2510.23664","versioned_id":"2510.23664v1","title":"Agentsway -- Software Development Methodology for AI Agents-based Teams","authors":["Eranga Bandara","Ross Gore","Xueping Liang","Sachini Rajapakse","Isurunima Kularathne","Pramoda Karunarathna","Peter Foytik","Sachin Shetty","Ravi Mukkamala","Abdul Rahman","Amin Hass","Ng Wee Keong","Kasun De Zoysa","Aruna Withanage","Nilaan Loganathan"],"abstract":"The emergence of Agentic AI is fundamentally transforming how software is designed, developed, and maintained. Traditional software development methodologies such as Agile, Kanban, ShapeUp, etc, were originally designed for human-centric teams and are increasingly inadequate in environments where autonomous AI agents contribute to planning, coding, testing, and continuous learning. To address this methodological gap, we present \"Agentsway\" a novel software development framework designed for ecosystems where AI agents operate as first-class collaborators. Agentsway introduces a structured lifecycle centered on human orchestration, and privacy-preserving collaboration among specialized AI agents. The framework defines distinct roles for planning, prompting, coding, testing, and fine-tuning agents, each contributing to iterative improvement and adaptive learning throughout the development process. By integrating fine-tuned LLMs that leverage outputs and feedback from different agents throughout the development cycle as part of a retrospective learning process, Agentsway enhances domain-specific reasoning, and explainable decision-making across the entire software development lifecycle. Responsible AI principles are further embedded across the agents through the coordinated use of multiple fine-tuned LLMs and advanced reasoning models, ensuring balanced, transparent, and accountable decision-making. This work advances software engineering by formalizing agent-centric collaboration, integrating privacy-by-design principles, and defining measurable metrics for productivity and trust. Agentsway represents a foundational step toward the next generation of AI-native, self-improving software development methodologies. To the best of our knowledge, this is the first research effort to introduce a dedicated methodology explicitly designed for AI agent-based software engineering teams.","published":"2025-10-26T11:58:42Z","updated":"2025-10-26T11:58:42Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2510.23664v1","pdf_url":"https://arxiv.org/pdf/2510.23664v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.22568","versioned_id":"2510.22568v1","title":"SPIRAL: Self-Play Incremental Racing Algorithm for Learning in Multi-Drone Competitions","authors":["Onur Akgün"],"abstract":"This paper introduces SPIRAL (Self-Play Incremental Racing Algorithm for Learning), a novel approach for training autonomous drones in multi-agent racing competitions. SPIRAL distinctively employs a self-play mechanism to incrementally cultivate complex racing behaviors within a challenging, dynamic environment. Through this self-play core, drones continuously compete against increasingly proficient versions of themselves, naturally escalating the difficulty of competitive interactions. This progressive learning journey guides agents from mastering fundamental flight control to executing sophisticated cooperative multi-drone racing strategies. Our method is designed for versatility, allowing integration with any state-of-the-art Deep Reinforcement Learning (DRL) algorithms within its self-play framework. Simulations demonstrate the significant advantages of SPIRAL and benchmark the performance of various DRL algorithms operating within it. Consequently, we contribute a versatile, scalable, and self-improving learning framework to the field of autonomous drone racing. SPIRAL's capacity to autonomously generate appropriate and escalating challenges through its self-play dynamic offers a promising direction for developing robust and adaptive racing strategies in multi-agent environments. This research opens new avenues for enhancing the performance and reliability of autonomous racing drones in increasingly complex and competitive scenarios.","published":"2025-10-26T07:59:44Z","updated":"2025-10-26T07:59:44Z","categories":["cs.RO","cs.AI","cs.MA","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2510.22568v1","pdf_url":"https://arxiv.org/pdf/2510.22568v1","comment":"\\c{opyright} 2025 IEEE. Personal use of this material is permitted. Permission from IEEE must be obtained for all other uses, in any current or future media, including reprinting/republishing this material for advertising or promotional purposes, creating new collective works, for resale or redistribution to servers or lists, or reuse of any copyrighted component of this work in other works","journal_ref":"","doi":"10.1109/ASYU67174.2025.11208263","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.22344","versioned_id":"2510.22344v1","title":"FAIR-RAG: Faithful Adaptive Iterative Refinement for Retrieval-Augmented Generation","authors":["Mohammad Aghajani Asl","Majid Asgari-Bidhendi","Behrooz Minaei-Bidgoli"],"abstract":"While Retrieval-Augmented Generation (RAG) mitigates hallucination and knowledge staleness in Large Language Models (LLMs), existing frameworks often falter on complex, multi-hop queries that require synthesizing information from disparate sources. Current advanced RAG methods, employing iterative or adaptive strategies, lack a robust mechanism to systematically identify and fill evidence gaps, often propagating noise or failing to gather a comprehensive context. We introduce FAIR-RAG, a novel agentic framework that transforms the standard RAG pipeline into a dynamic, evidence-driven reasoning process. At its core is an Iterative Refinement Cycle governed by a module we term Structured Evidence Assessment (SEA). The SEA acts as an analytical gating mechanism: it deconstructs the initial query into a checklist of required findings and audits the aggregated evidence to identify confirmed facts and, critically, explicit informational gaps. These gaps provide a precise signal to an Adaptive Query Refinement agent, which generates new, targeted sub-queries to retrieve missing information. This cycle repeats until the evidence is verified as sufficient, ensuring a comprehensive context for a final, strictly faithful generation. We conducted experiments on challenging multi-hop QA benchmarks, including HotpotQA, 2WikiMultiHopQA, and MusiQue. In a unified experimental setup, FAIR-RAG significantly outperforms strong baselines. On HotpotQA, it achieves an F1-score of 0.453 -- an absolute improvement of 8.3 points over the strongest iterative baseline -- establishing a new state-of-the-art for this class of methods on these benchmarks. Our work demonstrates that a structured, evidence-driven refinement process with explicit gap analysis is crucial for unlocking reliable and accurate reasoning in advanced RAG systems for complex, knowledge-intensive tasks.","published":"2025-10-25T15:59:33Z","updated":"2025-10-25T15:59:33Z","categories":["cs.CL","cs.AI","cs.IR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.22344v1","pdf_url":"https://arxiv.org/pdf/2510.22344v1","comment":"30 pages, 5 figures, 5 tables. Keywords: Retrieval-Augmented Generation (RAG), Large Language Models (LLMs), Agentic AI, Multi-hop Question Answering, Faithfulness","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.22045","versioned_id":"2510.22045v1","title":"VLM-SlideEval: Evaluating VLMs on Structured Comprehension and Perturbation Sensitivity in PPT","authors":["Hyeonsu Kang","Emily Bao","Anjan Goswami"],"abstract":"Vision-language models (VLMs) are increasingly used to evaluate multimodal content, including presentation slides, yet their slide-specific understanding remains underexplored {despite their growing role as critics in agentic, model-forward pipelines}. We introduce VLM-SlideEval, an evaluation framework that probes VLMs along three axes: (1) element-level extraction from slide images aligned to ground truth; (2) robustness to controlled perturbations in geometry, style, and text; and (3) higher-level comprehension, such as recovering a deck's narrative order from shuffled slides. Using publicly available decks from Zenodo (https://huggingface.co/datasets/Forceless/Zenodo10K/viewer/default/pptx), we standardize ground-truth element metadata from PowerPoint XML and live renderings into a unified, verifiable schema. Empirically, VLMs underperform on pixel-accurate extraction and show non-trivial agreement, fidelity, and consistency under controlled perturbations, while performing better on single-slide content understanding; however, they do not reliably capture narrative structure across slides. These results highlight the limits of current VLMs for slide evaluation and motivate calibrated, critic-in-the-loop evaluators that drive iterative refinement and selection in agentic pipelines.","published":"2025-10-24T22:06:56Z","updated":"2025-10-24T22:06:56Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2510.22045v1","pdf_url":"https://arxiv.org/pdf/2510.22045v1","comment":"39th Conference on Neural Information Processing Systems (NeurIPS 2025) Workshop: Evaluating the Evolving LLM Lifecycle - Benchmarks, Emergent Abilities, and Scaling","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=DRACd7p5ur","openreview_venues":["NeurIPS 2025 LLM Evaluation Workshop Poster"]},{"id":"2510.21614","versioned_id":"2510.21614v3","title":"Huxley-Gödel Machine: Human-Level Coding Agent Development by an Approximation of the Optimal Self-Improving Machine","authors":["Wenyi Wang","Piotr Piękos","Li Nanbo","Firas Laakom","Yimeng Chen","Mateusz Ostaszewski","Mingchen Zhuge","Jürgen Schmidhuber"],"abstract":"Recent studies operationalize self-improvement through coding agents that edit their own codebases. They grow a tree of self-modifications through expansion strategies that favor higher software engineering benchmark performance, assuming that this implies more promising subsequent self-modifications. However, we identify a mismatch between the agent's self-improvement potential (metaproductivity) and its coding benchmark performance, namely the Metaproductivity-Performance Mismatch. Inspired by Huxley's concept of clade, we propose a metric ($\\mathrm{CMP}$) that aggregates the benchmark performances of the descendants of an agent as an indicator of its potential for self-improvement. We show that, in our self-improving coding agent development setting, access to the true $\\mathrm{CMP}$ is sufficient to simulate how the Gödel Machine would behave under certain assumptions. We introduce the Huxley-Gödel Machine (HGM), which, by estimating $\\mathrm{CMP}$ and using it as guidance, searches the tree of self-modifications. On SWE-bench Verified and Polyglot, HGM outperforms prior self-improving coding agent development methods while using fewer allocated CPU hours. Last but not least, HGM demonstrates strong transfer to other coding datasets and large language models. The agent optimized by HGM on SWE-bench Verified with GPT-5-mini and evaluated on SWE-bench Lite with GPT-5 achieves human-level performance, matching the best officially checked results of human-engineered coding agents. Our code is publicly available at https://github.com/metauto-ai/HGM.","published":"2025-10-24T16:19:41Z","updated":"2025-10-29T13:57:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.21614v3","pdf_url":"https://arxiv.org/pdf/2510.21614v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:6Mw2fO3ejN","versioned_id":"6Mw2fO3ejN","title":"Self-evolving Agents with reflective and memory-augmented abilities","authors":["梁学辰","Yangfan He","Yinghui Xia","Xinyuan Song","Meiling Tao","Kuan Lu","Jianhui Wang","Li Sun","Xinhang Yuan","Keqin Li","Jiaqi Chen","TIANYU SHI","Yang Jingsong"],"abstract":"Large language models (LLMs) have made significant advances in the field of natural language processing, but they still face challenges such as continuous decision-making, lack of long-term memory, and limited context windows in dynamic environments. To address these issues, this paper proposes an innovative framework—Self-evolving Agents with Reflective and Memory-augmented Abilities (SAGE). The SAGE framework comprises three agents: the User, the Assistant, and the Checker. By integrating iterative feedback, reflective mechanisms, and a memory optimization mechanism based on the Ebbinghaus forgetting curve, it significantly enhances the agents' capabilities in handling multi-tasking and long-span information. The agents, through self-evolution, can adaptively adjust strategies, optimize information storage and transmission, and effectively reduce cognitive load. We evaluate the performance of the SAGE framework on multiple benchmarks and long text tasks. Experimental results show that SAGE significantly improves model performance, achieving a 2.26X improvement on closed-source models and an improvement ranging from 57.7% to 100% on open-source models, with particularly notable effects on smaller models.","published":"2025-10-23T04:52:04+00:00","updated":"2026-01-10T15:22:29+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=6Mw2fO3ejN","openreview_url":"https://openreview.net/forum?id=6Mw2fO3ejN","pdf_url":"https://openreview.net/pdf?id=6Mw2fO3ejN","comment":"LaMAS 2026 Poster","journal_ref":"LaMAS 2026 Poster","doi":"","venue":"LaMAS 2026 Poster","venue_id":"AAAI.org/2026/Workshop/LaMAS","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2510.20176","versioned_id":"2510.20176v2","title":"Mixture-of-Minds: Multi-Agent Reinforcement Learning for Table Understanding","authors":["Yuhang Zhou","Mingrui Zhang","Ke Li","Mingyi Wang","Qiao Liu","Qifei Wang","Jiayi Liu","Fei Liu","Serena Li","Weiwei Li","Mingze Gao","Abhishek Kumar","Xiangjun Fan","Zhuokai Zhao","Lizhu Zhang"],"abstract":"Understanding and reasoning over tables is a critical capability for many real-world applications. Large language models (LLMs) have shown promise on this task, but current approaches remain limited. Fine-tuning based methods strengthen language reasoning; yet they are prone to arithmetic errors and hallucination. In contrast, tool-based methods enable precise table manipulation but rely on rigid schemas and lack semantic understanding. These complementary drawbacks highlight the need for approaches that integrate robust reasoning with reliable table processing. In this work, we propose Mixture-of-Minds, a multi-agent framework that decomposes table reasoning into three specialized roles: planning, coding, and answering. This design enables each agent to focus on a specific aspect of the task while leveraging code execution for precise table manipulation. Building on this workflow, we introduce a self-improvement training framework that employs Monte Carlo Tree Search (MCTS) rollouts to generate pseudo-gold trajectories and optimize agents with reinforcement learning (RL). Extensive experiments show that Mixture-of-Minds delivers substantial gains, reaching 62.13% on TableBench and surpassing OpenAI-o4-mini-high. These results demonstrate the promise of combining structured multi-agent workflows with RL to advance table understanding.","published":"2025-10-23T03:51:17Z","updated":"2025-10-24T15:36:31Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.20176v2","pdf_url":"https://arxiv.org/pdf/2510.20176v2","comment":"18 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.19661","versioned_id":"2510.19661v2","title":"AgentSense: LLMs Empower Generalizable and Explainable Web-Based Participatory Urban Sensing","authors":["Xusen Guo","Mingxing Peng","Xixuan Hao","Xingchen Zou","Qiongyan Wang","Sijie Ruan","Yuxuan Liang"],"abstract":"Web-based participatory urban sensing has emerged as a vital approach for modern urban management by leveraging mobile individuals as distributed sensors. However, existing urban sensing systems struggle with limited generalization across diverse urban scenarios and poor interpretability in decision-making. In this work, we introduce AgentSense, a hybrid, training-free framework that integrates large language models (LLMs) into participatory urban sensing through a multi-agent evolution system. AgentSense initially employs classical planner to generate baseline solutions and then iteratively refines them to adapt sensing task assignments to dynamic urban conditions and heterogeneous worker preferences, while producing natural language explanations that enhance transparency and trust. Extensive experiments across two large-scale mobility datasets and seven types of dynamic disturbances demonstrate that AgentSense offers distinct advantages in adaptivity and explainability over traditional methods. Furthermore, compared to single-agent LLM baselines, our approach outperforms in both performance and robustness, while delivering more reasonable and transparent explanations. These results position AgentSense as a significant advancement towards deploying adaptive and explainable urban sensing systems on the web.","published":"2025-10-22T15:06:26Z","updated":"2025-10-24T05:16:51Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.19661v2","pdf_url":"https://arxiv.org/pdf/2510.19661v2","comment":"13 pages, 10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:xgODhAknaA","versioned_id":"xgODhAknaA","title":"Med-ICE: Enhancing Factual Accuracy in Medical AI through Autonomous Multi-Agent Consensus","authors":["Zhiyuan Chen","Rui Wu","Rui Li","Alexandre Duprey"],"abstract":"The integration of Large Language Models into high-stakes clinical workflows is critically hampered by their lack of verifiable reliability and tendency to generate hallucinations. This paper introduces Med-ICE, an autonomous framework designed to enhance the reliability of LLMs for medical applications. Med-ICE adapts the Iterative Consensus Ensemble paradigm, enabling a group of peer LLM agents to collaboratively converge on a final answer through iterative rounds of generation and peer review, thereby eliminating the need for an external arbiter and its associated scalability bottleneck. Our work makes three key contributions: (1) a novel semantic consensus mechanism that determines agreement based on semantic similarity, crucial for nuanced clinical language; (2) demonstration of state-of-the-art performance, where Med-ICE significantly outperforms both direct single-LLM generation and the Self-Refinement technique on challenging medical benchmarks; and (3) a highly efficient and scalable architecture, as our Semantic Consensus Monitor is computationally lightweight. This research establishes a new standard for developing safer, more trustworthy LLM systems, paving the way for their responsible integration into medicine.","published":"2025-10-21T21:46:18+00:00","updated":"2025-11-18T03:15:39+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=xgODhAknaA","openreview_url":"https://openreview.net/forum?id=xgODhAknaA","pdf_url":"https://openreview.net/pdf?id=xgODhAknaA","comment":"SPARTA_AAAI2026 Poster","journal_ref":"SPARTA_AAAI2026 Poster","doi":"","venue":"SPARTA_AAAI2026 Poster","venue_id":"AAAI.org/2026/Workshop/SPARTA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2510.18798","versioned_id":"2510.18798v1","title":"WebSeer: Training Deeper Search Agents through Reinforcement Learning with Self-Reflection","authors":["Guanzhong He","Zhen Yang","Jinxin Liu","Bin Xu","Lei Hou","Juanzi Li"],"abstract":"Search agents have achieved significant advancements in enabling intelligent information retrieval and decision-making within interactive environments. Although reinforcement learning has been employed to train agentic models capable of more dynamic interactive retrieval, existing methods are limited by shallow tool-use depth and the accumulation of errors over multiple iterative interactions. In this paper, we present WebSeer, a more intelligent search agent trained via reinforcement learning enhanced with a self-reflection mechanism. Specifically, we construct a large dataset annotated with reflection patterns and design a two-stage training framework that unifies cold start and reinforcement learning within the self-reflection paradigm for real-world web-based environments, which enables the model to generate longer and more reflective tool-use trajectories. Our approach substantially extends tool-use chains and improves answer accuracy. Using a single 14B model, we achieve state-of-the-art results on HotpotQA and SimpleQA, with accuracies of 72.3% and 90.0%, respectively, and demonstrate strong generalization to out-of-distribution datasets. The code is available at https://github.com/99hgz/WebSeer","published":"2025-10-21T16:52:00Z","updated":"2025-10-21T16:52:00Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.18798v1","pdf_url":"https://arxiv.org/pdf/2510.18798v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=YCXWIfVakj","openreview_venues":["ICLR 2026 Poster"]},{"id":"2510.18179","versioned_id":"2510.18179v2","title":"Adaptive Coopetition: Leveraging Coarse Verifier Signals for Resilient Multi-Agent LLM Reasoning","authors":["Rui Jerry Huang","Wendy Liu","Anastasia Miin","Lei Ding"],"abstract":"Inference-time computation is a critical yet challenging paradigm for enhancing the reasoning performance of large language models (LLMs). While existing strategies improve reasoning stability and consistency, they suffer from notable limitations: self-correction often reinforces the model's initial biases, and Multi-Agent Collaboration (MAC) often fails due to the lack of efficient coordination mechanisms, leading to collective errors. Although high-performing verifiers can detect reasoning errors, making them reliable requires substantial training. To address these challenges, we introduce a novel inference-time framework, Adaptive Coopetition (AdCo), in which LLM agents utilize an adaptive, UCB-based \"coopetition\" mechanism. At each round, agents leverage coarse verifier signals to determine whether to collaborate or compete, and iteratively refine their reasoning based on peer feedback. Without relying on high-performance verifiers, our adaptive strategy achieves significant performance gains on mathematical reasoning benchmarks, yielding a 20% relative improvement over baselines on the more challenging dataset. Our approach remains robust and consistent in terms of accuracy under different sample sizes and configurations. This adaptive, signal-guided \"coopetition\" framework enhances reasoning robustness by leveraging both model knowledge diversity and reasoning trace measures, while also promoting uncertainty-driven exploration, especially when participants have comparable capabilities. From this perspective, our work offers a fresh lens on inference-time computation and paves the way for more resilient multi-agent LLM systems. Our code is available at: https://github.com/AdCo-Research/adaptive-coopetition.","published":"2025-10-21T00:07:52Z","updated":"2025-10-22T05:04:06Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2510.18179v2","pdf_url":"https://arxiv.org/pdf/2510.18179v2","comment":"13 pages, 8 figures. Accepted for presentation at the 5th Workshop on Mathematical Reasoning and AI at NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.17109","versioned_id":"2510.17109v1","title":"Verification-Aware Planning for Multi-Agent Systems","authors":["Tianyang Xu","Dan Zhang","Kushan Mitra","Estevam Hruschka"],"abstract":"Large language model (LLM) agents are increasingly deployed to tackle complex tasks, often necessitating collaboration among multiple specialized agents. However, multi-agent collaboration introduces new challenges in planning, coordination, and verification. Execution failures frequently arise not from flawed reasoning alone, but from subtle misalignments in task interpretation, output format, or inter-agent handoffs. To address these challenges, we present VeriMAP, a framework for multi-agent collaboration with verification-aware planning. The VeriMAP planner decomposes tasks, models subtask dependencies, and encodes planner-defined passing criteria as subtask verification functions (VFs) in Python and natural language. We evaluate VeriMAP on diverse datasets, demonstrating that it outperforms both single- and multi-agent baselines while enhancing system robustness and interpretability. Our analysis highlights how verification-aware planning enables reliable coordination and iterative refinement in multi-agent systems, without relying on external labels or annotations.","published":"2025-10-20T02:54:29Z","updated":"2025-10-20T02:54:29Z","categories":["cs.CL","cs.AI","cs.LG","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.17109v1","pdf_url":"https://arxiv.org/pdf/2510.17109v1","comment":"Submission for ARR Oct","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.16724","versioned_id":"2510.16724v2","title":"A Comprehensive Survey on Reinforcement Learning-based Agentic Search: Foundations, Roles, Optimizations, Evaluations, and Applications","authors":["Minhua Lin","Zongyu Wu","Zhichao Xu","Hui Liu","Xianfeng Tang","Qi He","Charu Aggarwal","Hui Liu","Xiang Zhang","Suhang Wang"],"abstract":"The advent of large language models (LLMs) has transformed information access and reasoning through open-ended natural language interaction. However, LLMs remain limited by static knowledge, factual hallucinations, and the inability to retrieve real-time or domain-specific information. Retrieval-Augmented Generation (RAG) mitigates these issues by grounding model outputs in external evidence, but traditional RAG pipelines are often single turn and heuristic, lacking adaptive control over retrieval and reasoning. Recent advances in agentic search address these limitations by enabling LLMs to plan, retrieve, and reflect through multi-step interaction with search environments. Within this paradigm, reinforcement learning (RL) offers a powerful mechanism for adaptive and self-improving search behavior. This survey provides the first comprehensive overview of \\emph{RL-based agentic search}, organizing the emerging field along three complementary dimensions: (i) What RL is for (functional roles), (ii) How RL is used (optimization strategies), and (iii) Where RL is applied (scope of optimization). We summarize representative methods, evaluation protocols, and applications, and discuss open challenges and future directions toward building reliable and scalable RL driven agentic search systems. We hope this survey will inspire future research on the integration of RL and agentic search. Our repository is available at https://github.com/ventr1c/Awesome-RL-based-Agentic-Search-Papers.","published":"2025-10-19T06:04:53Z","updated":"2025-10-27T19:23:17Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.16724v2","pdf_url":"https://arxiv.org/pdf/2510.16724v2","comment":"38 pages, 4 figures, 7 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.16552","versioned_id":"2510.16552v1","title":"LANPO: Bootstrapping Language and Numerical Feedback for Reinforcement Learning in LLMs","authors":["Ang Li","Yifei Wang","Zhihang Yuan","Stefanie Jegelka","Yisen Wang"],"abstract":"Reinforcement learning in large language models (LLMs) often relies on scalar rewards, a practice that discards valuable textual rationale buried in the rollouts, forcing the model to explore \\textit{de novo} with each attempt and hindering sample efficiency. While LLMs can uniquely learn from language feedback provided in-context, naively integrating on-line experiences into RL training presents a paradox: feedback from the same problem risks information leakage and memorization, while feedback from different problems often leads to behavior collapse due to irrelevant context. To resolve this tension, we propose \\textbf{Language-And-Numerical Policy Optimization (LANPO)}, a framework that cleanly separates the roles of feedback: language guides exploration, while numerical rewards drive optimization. LANPO builds a dynamic experience pool from past trials and introduces two principles to ensure feedback is effective: \\emph{Reward-Agnostic Reflection} for safe intra-sample self-correction and \\emph{Relevant Abstraction} to distill generalizable lessons from inter-sample experiences. Across mathematical reasoning benchmarks, LANPO enables 7B and 14B models to significantly outperform strong baselines trained with GRPO in test accuracy. Our work provides a robust method for integrating historical experiences into the LLM RL loop, creating more effective and data-efficient learning agents.","published":"2025-10-18T15:51:19Z","updated":"2025-10-18T15:51:19Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.16552v1","pdf_url":"https://arxiv.org/pdf/2510.16552v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.15772","versioned_id":"2510.15772v1","title":"Self-evolving expertise in complex non-verifiable subject domains: dialogue as implicit meta-RL","authors":["Richard M. Bailey"],"abstract":"So-called `wicked problems', those involving complex multi-dimensional settings, non-verifiable outcomes, heterogeneous impacts and a lack of single objectively correct answers, have plagued humans throughout history. Modern examples include decisions over justice frameworks, solving environmental pollution, planning for pandemic resilience and food security. The use of state-of-the-art artificial intelligence systems (notably Large Language Model-based agents) collaborating with humans on solving such problems is being actively explored. While the abilities of LLMs can be improved by, for example, fine-tuning, hand-crafted system prompts and scaffolding with external tools, LLMs lack endogenous mechanisms to develop expertise through experience in such settings. This work address this gap with Dialectica, a framework where agents engage in structured dialogue on defined topics, augmented by memory, self-reflection, and policy-constrained context editing. Formally, discussion is viewed as an implicit meta-reinforcement learning process. The `dialogue-trained' agents are evaluated post-hoc using judged pairwise comparisons of elicited responses. Across two model architectures (locally run Qwen3:30b and OpenAI's o4-mini) results show that enabling reflection-based context editing during discussion produces agents which dominate their baseline counterparts on Elo scores, normalized Bradley-Terry-Davidson ability, and AlphaRank mass. The predicted signatures of learning are observed qualitatively in statement and reflection logs, where reflections identify weaknesses and reliably shape subsequent statements. Agreement between quantitative and qualitative evidence supports dialogue-driven context evolution as a practical path to targeted expertise amplification in open non-verifiable domains.","published":"2025-10-17T15:59:44Z","updated":"2025-10-17T15:59:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.15772v1","pdf_url":"https://arxiv.org/pdf/2510.15772v1","comment":"50 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.14319","versioned_id":"2510.14319v2","title":"Metacognitive Self-Correction for Multi-Agent System via Prototype-Guided Next-Execution Reconstruction","authors":["Xu Shen","Qi Zhang","Song Wang","Zhen Tan","Xinyu Zhao","Laura Yao","Vaishnav Tadiparthi","Hossein Nourkhiz Mahjoub","Ehsan Moradi Pari","Kwonjoon Lee","Tianlong Chen"],"abstract":"Large Language Model based multi-agent systems (MAS) excel at collaborative problem solving but remain brittle to cascading errors: a single faulty step can propagate across agents and disrupt the trajectory. In this paper, we present MASC, a metacognitive framework that endows MAS with real-time, unsupervised, step-level error detection and self-correction. MASC rethinks detection as history-conditioned anomaly scoring via two complementary designs: (1) Next-Execution Reconstruction, which predicts the embedding of the next step from the query and interaction history to capture causal consistency, and (2) Prototype-Guided Enhancement, which learns a prototype prior over normal-step embeddings and uses it to stabilize reconstruction and anomaly scoring under sparse context (e.g., early steps). When an anomaly step is flagged, MASC triggers a correction agent to revise the acting agent's output before information flows downstream. On the Who&When benchmark, MASC consistently outperforms all baselines, improving step-level error detection by up to 8.47% AUC-ROC ; When plugged into diverse MAS frameworks, it delivers consistent end-to-end gains across architectures, confirming that our metacognitive monitoring and targeted correction can mitigate error propagation with minimal overhead.","published":"2025-10-16T05:35:37Z","updated":"2026-01-12T03:44:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.14319v2","pdf_url":"https://arxiv.org/pdf/2510.14319v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=vx0luAhOGl","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2510.14253","versioned_id":"2510.14253v2","title":"Towards Agentic Self-Learning LLMs in Search Environment","authors":["Wangtao Sun","Xiang Cheng","Jialin Fan","Yao Xu","Xing Yu","Shizhu He","Jun Zhao","Kang Liu"],"abstract":"We study whether self-learning can scale LLM-based agents without relying on human-curated datasets or predefined rule-based rewards. Through controlled experiments in a search-agent setting, we identify two key determinants of scalable agent training: the source of reward signals and the scale of agent task data. We find that rewards from a Generative Reward Model (GRM) outperform rigid rule-based signals for open-domain learning, and that co-evolving the GRM with the policy further boosts performance. Increasing the volume of agent task data-even when synthetically generated-substantially enhances agentic capabilities. Building on these insights, we propose \\textbf{Agentic Self-Learning} (ASL), a fully closed-loop, multi-role reinforcement learning framework that unifies task generation, policy execution, and evaluation within a shared tool environment and LLM backbone. ASL coordinates a Prompt Generator, a Policy Model, and a Generative Reward Model to form a virtuous cycle of harder task setting, sharper verification, and stronger solving. Empirically, ASL delivers steady, round-over-round gains, surpasses strong RLVR baselines (e.g., Search-R1) that plateau or degrade, and continues improving under zero-labeled-data conditions, indicating superior sample efficiency and robustness. We further show that GRM verification capacity is the main bottleneck: if frozen, it induces reward hacking and stalls progress; continual GRM training on the evolving data distribution mitigates this, and a small late-stage injection of real verification data raises the performance ceiling. This work establishes reward source and data scale as critical levers for open-domain agent learning and demonstrates the efficacy of multi-role co-evolution for scalable, self-improving agents. The data and code of this paper are released at https://github.com/forangel2014/Towards-Agentic-Self-Learning","published":"2025-10-16T03:11:56Z","updated":"2025-10-21T02:16:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.14253v2","pdf_url":"https://arxiv.org/pdf/2510.14253v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=ySSq8Yavs4","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2510.13291","versioned_id":"2510.13291v2","title":"Higher Satisfaction, Lower Cost: A Technical Report on How LLMs Revolutionize Meituan's Intelligent Interaction Systems","authors":["Xuxin Cheng","Ke Zeng","Zhiquan Cao","Linyi Dai","Wenxuan Gao","Fei Han","Ai Jian","Feng Hong","Wenxing Hu","Zihe Huang","Dejian Kong","Jia Leng","Zhuoyuan Liao","Pei Liu","Jiaye Lin","Xing Ma","Jingqing Ruan","Jiaxing Song","Xiaoyu Tan","Ruixuan Xiao","Wenhui Yu","Wenyu Zhan","Haoxing Zhang","Chao Zhou","Hao Zhou","Shaodong Zheng","Ruinian Chen","Siyuan Chen","Ziyang Chen","Yiwen Dong","Yaoyou Fan","Yangyi Fang","Yang Gan","Shiguang Guo","Qi He","Chaowen Hu","Binghui Li","Dailin Li","Xiangyu Li","Yan Li","Chengjian Liu","Xiangfeng Liu","Jiahui Lv","Qiao Ma","Jiang Pan","Cong Qin","Chenxing Sun","Wen Sun","Zhonghui Wang","Abudukelimu Wuerkaixi","Xin Yang","Fangyi Yuan","Yawen Zhu","Tianyi Zhai","Jie Zhang","Runlai Zhang","Yao Xu","Yiran Zhao","Yifan Wang","Xunliang Cai","Yangen Hu","Cao Liu","Lu Pan","Xiaoli Wang","Bo Xiao","Wenyuan Yao","Qianlin Zhou","Benchang Zhu"],"abstract":"Enhancing customer experience is essential for business success, particularly as service demands grow in scale and complexity. Generative artificial intelligence and Large Language Models (LLMs) have empowered intelligent interaction systems to deliver efficient, personalized, and 24/7 support. In practice, intelligent interaction systems encounter several challenges: (1) Constructing high-quality data for cold-start training is difficult, hindering self-evolution and raising labor costs. (2) Multi-turn dialogue performance remains suboptimal due to inadequate intent understanding, rule compliance, and solution extraction. (3) Frequent evolution of business rules affects system operability and transferability, constraining low-cost expansion and adaptability. (4) Reliance on a single LLM is insufficient in complex scenarios, where the absence of multi-agent frameworks and effective collaboration undermines process completeness and service quality. (5) The open-domain nature of multi-turn dialogues, lacking unified golden answers, hampers quantitative evaluation and continuous optimization. To address these challenges, we introduce WOWService, an intelligent interaction system tailored for industrial applications. With the integration of LLMs and multi-agent architectures, WOWService enables autonomous task management and collaborative problem-solving. Specifically, WOWService focuses on core modules including data construction, general capability enhancement, business scenario adaptation, multi-agent coordination, and automated evaluation. Currently, WOWService is deployed on the Meituan App, achieving significant gains in key metrics, e.g., User Satisfaction Metric 1 (USM 1) -27.53% and User Satisfaction Metric 2 (USM 2) +25.51%, demonstrating its effectiveness in capturing user needs and advancing personalized service.","published":"2025-10-15T08:35:51Z","updated":"2026-01-14T07:30:10Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.13291v2","pdf_url":"https://arxiv.org/pdf/2510.13291v2","comment":"36 pages, 14 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.13220","versioned_id":"2510.13220v2","title":"EvoTest: Evolutionary Test-Time Learning for Self-Improving Agentic Systems","authors":["Yufei He","Juncheng Liu","Yue Liu","Yibo Li","Tri Cao","Zhiyuan Hu","Xinxing Xu","Bryan Hooi"],"abstract":"A fundamental limitation of current AI agents is their inability to learn complex skills on the fly at test time, often behaving like \"clever but clueless interns\" in novel environments. This severely limits their practical utility. To systematically measure and drive progress on this challenge, we first introduce the Jericho Test-Time Learning (J-TTL) benchmark. J-TTL is a new evaluation setup where an agent must play the same game for several consecutive episodes, attempting to improve its performance from one episode to the next. On J-TTL, we find that existing adaptation methods like reflection, memory, or reinforcement learning struggle. To address the challenges posed by our benchmark, we present EvoTest, an evolutionary test-time learning framework that improves an agent without any fine-tuning or gradients-by evolving the entire agentic system after every episode. EvoTest has two roles: the Actor Agent, which plays the game, and the Evolver Agent, which analyzes the episode transcript to propose a revised configuration for the next run. This configuration rewrites the prompt, updates memory by logging effective state-action choices, tunes hyperparameters, and learns the tool-use routines. On our J-TTL benchmark, EvoTest consistently increases performance, outperforming not only reflection and memory-only baselines but also more complex online fine-tuning methods. Notably, our method is the only one capable of winning two games (Detective and Library), while all baselines fail to win any.","published":"2025-10-15T07:16:28Z","updated":"2026-04-17T02:13:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.13220v2","pdf_url":"https://arxiv.org/pdf/2510.13220v2","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=JFnnajbkvP","openreview_venues":["ICLR 2026 Poster"]},{"id":"2510.13896","versioned_id":"2510.13896v2","title":"GenCellAgent: Generalizable, Training-Free Cellular Image Segmentation via Large Language Model Agents","authors":["Xi Yu","Yang Yang","Qun Liu","Yonghua Du","Sean McSweeney","Yuewei Lin"],"abstract":"Cellular image segmentation is essential for quantitative biology yet remains difficult due to heterogeneous modalities, morphological variability, and limited annotations. We present GenCellAgent, a training-free multi-agent framework that orchestrates specialist segmenters and generalist vision-language models via a planner-executor-evaluator loop (choose tool $\\rightarrow$ run $\\rightarrow$ quality-check) with long-term memory. The system (i) automatically routes images to the best tool, (ii) adapts on the fly using a few reference images when imaging conditions differ from what a tool expects, (iii) supports text-guided segmentation of organelles not covered by existing models, and (iv) commits expert edits to memory, enabling self-evolution and personalized workflows. Across seven cell-segmentation benchmarks spanning diverse microscopy modalities (4,718 images), this routing consistently matches or exceeds the best individual tool on every dataset and outperforms all baselines in overall accuracy. On out-of-distribution organelle data, GenCellAgent substantially outperforms specialist models that were not trained on the target domain, recovering structures that dedicated tools fail to detect. It also segments novel objects such as the Golgi apparatus via iterative text-guided refinement, with light human correction further boosting performance. Together, these capabilities provide a practical path to robust, adaptable cellular image segmentation without retraining, while reducing annotation burden and matching user preferences.","published":"2025-10-14T17:02:57Z","updated":"2026-05-09T02:53:15Z","categories":["q-bio.QM","cs.AI","cs.CV","cs.MA"],"primary_category":"q-bio.QM","arxiv_url":"https://arxiv.org/abs/2510.13896v2","pdf_url":"https://arxiv.org/pdf/2510.13896v2","comment":"43 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.12273","versioned_id":"2510.12273v1","title":"Multi-Action Self-Improvement for Neural Combinatorial Optimization","authors":["Laurin Luttmann","Lin Xie"],"abstract":"Self-improvement has emerged as a state-of-the-art paradigm in Neural Combinatorial Optimization (NCO), where models iteratively refine their policies by generating and imitating high-quality solutions. Despite strong empirical performance, existing methods face key limitations. Training is computationally expensive, as policy updates require sampling numerous candidate solutions per instance to extract a single expert trajectory. More fundamentally, these approaches fail to exploit the structure of combinatorial problems involving the coordination of multiple agents, such as vehicles in min-max routing or machines in scheduling. By supervising on single-action trajectories, they fail to exploit agent-permutation symmetries, where distinct sequences of actions yield identical solutions, hindering generalization and the ability to learn coordinated behavior. We address these challenges by extending self-improvement to operate over joint multi-agent actions. Our model architecture predicts complete agent-task assignments jointly at each decision step. To explicitly leverage symmetries, we employ a set-prediction loss, which supervises the policy on multiple expert assignments for any given state. This approach enhances sample efficiency and the model's ability to learn coordinated behavior. Furthermore, by generating multi-agent actions in parallel, it drastically accelerates the solution generation phase of the self-improvement loop. Empirically, we validate our method on several combinatorial problems, demonstrating consistent improvements in the quality of the final solution and a reduced generation latency compared to standard self-improvement.","published":"2025-10-14T08:26:27Z","updated":"2025-10-14T08:26:27Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.12273v1","pdf_url":"https://arxiv.org/pdf/2510.12273v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=6KrETIaOYD","openreview_venues":["ICLR 2026 Poster"]},{"id":"2510.12091","versioned_id":"2510.12091v1","title":"ToPolyAgent: AI Agents for Coarse-Grained Topological Polymer Simulations","authors":["Lijie Ding","Jan-Michael Carrillo","Changwoo Do"],"abstract":"We introduce ToPolyAgent, a multi-agent AI framework for performing coarse-grained molecular dynamics (MD) simulations of topological polymers through natural language instructions. By integrating large language models (LLMs) with domain-specific computational tools, ToPolyAgent supports both interactive and autonomous simulation workflows across diverse polymer architectures, including linear, ring, brush, and star polymers, as well as dendrimers. The system consists of four LLM-powered agents: a Config Agent for generating initial polymer-solvent configurations, a Simulation Agent for executing LAMMPS-based MD simulations and conformational analyses, a Report Agent for compiling markdown reports, and a Workflow Agent for streamlined autonomous operations. Interactive mode incorporates user feedback loops for iterative refinements, while autonomous mode enables end-to-end task execution from detailed prompts. We demonstrate ToPolyAgent's versatility through case studies involving diverse polymer architectures under varying solvent condition, thermostats, and simulation lengths. Furthermore, we highlight its potential as a research assistant by directing it to investigate the effect of interaction parameters on the linear polymer conformation, and the influence of grafting density on the persistence length of the brush polymer. By coupling natural language interfaces with rigorous simulation tools, ToPolyAgent lowers barriers to complex computational workflows and advances AI-driven materials discovery in polymer science. It lays the foundation for autonomous and extensible multi-agent scientific research ecosystems.","published":"2025-10-14T02:54:19Z","updated":"2025-10-14T02:54:19Z","categories":["cs.AI","cond-mat.mtrl-sci","cond-mat.soft"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.12091v1","pdf_url":"https://arxiv.org/pdf/2510.12091v1","comment":"10 pages, 8 figures","journal_ref":"","doi":"10.1039/D5DD00471C","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.09988","versioned_id":"2510.09988v1","title":"Unifying Tree Search Algorithm and Reward Design for LLM Reasoning: A Survey","authors":["Jiaqi Wei","Xiang Zhang","Yuejin Yang","Wenxuan Huang","Juntai Cao","Sheng Xu","Xiang Zhuang","Zhangyang Gao","Muhammad Abdul-Mageed","Laks V. S. Lakshmanan","Chenyu You","Wanli Ouyang","Siqi Sun"],"abstract":"Deliberative tree search is a cornerstone of modern Large Language Model (LLM) research, driving the pivot from brute-force scaling toward algorithmic efficiency. This single paradigm unifies two critical frontiers: \\textbf{Test-Time Scaling (TTS)}, which deploys on-demand computation to solve hard problems, and \\textbf{Self-Improvement}, which uses search-generated data to durably enhance model parameters. However, this burgeoning field is fragmented and lacks a common formalism, particularly concerning the ambiguous role of the reward signal -- is it a transient heuristic or a durable learning target? This paper resolves this ambiguity by introducing a unified framework that deconstructs search algorithms into three core components: the \\emph{Search Mechanism}, \\emph{Reward Formulation}, and \\emph{Transition Function}. We establish a formal distinction between transient \\textbf{Search Guidance} for TTS and durable \\textbf{Parametric Reward Modeling} for Self-Improvement. Building on this formalism, we introduce a component-centric taxonomy, synthesize the state-of-the-art, and chart a research roadmap toward more systematic progress in creating autonomous, self-improving agents.","published":"2025-10-11T03:29:18Z","updated":"2025-10-11T03:29:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.09988v1","pdf_url":"https://arxiv.org/pdf/2510.09988v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.09355","versioned_id":"2510.09355v1","title":"NL2GenSym: Natural Language to Generative Symbolic Rules for SOAR Cognitive Architecture via Large Language Models","authors":["Fang Yuan","Junjie Zeng","Yue Hu","Zhengqiu Zhu","Quanjun Yin","Yuxiang Xie"],"abstract":"SOAR, a classic symbol-based cognitive architecture, has been fostering the development of general, human-like intelligent agents. Nevertheless, its practical adoption is hindered by the laborious manual rule coding. Emerging Large Language Models (LLMs) present the immense potential for efficient rules generation. However, there is a critical gap that current research predominantly focuses on conceptual frameworks and lacks robust experimental validation. To bridge this gap, we propose \\textit{N}atural \\textit{L}anguage to \\textit{Gen}erative \\textit{Sym}bolic Rules (NL2GenSym), a novel framework that integrates LLMs with SOAR to autonomously produce generative symbolic rules from natural language. Specifically, our framework introduces a novel Execution-Grounded Generator-Critic mechanism. The LLM-based Generator, guided by a Retrieval-Augmented Generation-accessed self-evolving domain knowledge base, proposes rules from natural language. Subsequently, these rules are immediately executed within the SOAR environment to rigorously validate their correctness. Based on this execution-grounded feedback, a reflective LLM-based Critic drives the iterative refinement of these rules. Experiments on our specialized Water Jug Problem (WJP) dataset, utilizing both Gemini and Qwen series models, validate the efficacy of our framework. It achieves a success rate over 86\\% in generating rules from natural language. Crucially, the framework also generates novel heuristic rules, reducing average decision cycles for solving the WJP to 1.98 times the optimal solution and 1/1000 of baseline methods. Additionally, our initial experiments show that NL2GenSym enables smaller-parameter models to achieve better performance than larger counterparts.","published":"2025-10-10T13:08:35Z","updated":"2025-10-10T13:08:35Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.09355v1","pdf_url":"https://arxiv.org/pdf/2510.09355v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.08847","versioned_id":"2510.08847v2","title":"What Is Your Agent's GPA? A Framework for Evaluating Agent Goal-Plan-Action Alignment","authors":["Allison Sihan Jia","Daniel Huang","Nikhil Vytla","Seung Won Wilson Yoo","Nirvika Choudhury","Shayak Sen","John C. Mitchell","Anupam Datta"],"abstract":"We introduce the Agent GPA (Goal-Plan-Action) framework, driven by the fundamental insight that critical agent failures emerge at the intersections of setting goals, devising plans, and executing actions. We operationalize the framework with a factorized suite of LLM judges designed to measure distinct elements of Goal-Plan-Act alignment. To make this methodology scalable and generalizable across diverse agent architectures and datasets, we use state-of-the-art automated prompt optimization techniques to systematically generate domain-specific evaluation criteria. We validate this approach across three benchmarks: a multi-agent research setting (TRAIL/GAIA), a single coding agent setting (TRAIL/SWE-bench), and a private, enterprise data-agent setting (Snowflake Intelligence). Extensive evaluation on TRAIL/GAIA demonstrates the core validity of the framework, which identifies a broad range of agent failures (95% of human-annotated errors), localizes errors to enable targeted debugging (86% of human-annotated errors), and exhibits strong agreement with human evaluators. Crucially, by applying our automated methodology to both public datasets, we demonstrate that our GPA judges generally achieve the highest error coverage (ranging from 76% to 86%) in comparison to manual prompting approaches. We also leverage an evolutionary coding agent to improve judge consistency by up to 38% through iterative refinement of evaluation rubrics. Overall, Agent GPA provides a rigorous and generalizable paradigm for targeted agent evaluation.","published":"2025-10-09T22:40:19Z","updated":"2026-03-27T23:39:02Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.08847v2","pdf_url":"https://arxiv.org/pdf/2510.08847v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.08558","versioned_id":"2510.08558v3","title":"Agent Learning via Early Experience","authors":["Kai Zhang","Xiangchao Chen","Bo Liu","Tianci Xue","Zeyi Liao","Zhihan Liu","Xiyao Wang","Yuting Ning","Zhaorun Chen","Xiaohan Fu","Jian Xie","Yuxuan Sun","Boyu Gou","Qi Qi","Zihang Meng","Jianwei Yang","Ning Zhang","Xian Li","Ashish Shah","Dat Huynh","Hengduo Li","Zi Yang","Sara Cao","Lawrence Jang","Shuyan Zhou","Jiacheng Zhu","Huan Sun","Jason Weston","Yu Su","Yifan Wu"],"abstract":"A long-term goal of language agents is to learn and improve through their own experience, ultimately outperforming humans in complex, real-world tasks. However, training agents from experience data with reinforcement learning remains difficult in many environments, which either lack verifiable rewards (e.g., websites) or require inefficient long-horizon rollouts (e.g., multi-turn tool use). As a result, most current agents rely on supervised fine-tuning on expert data, which is challenging to scale and generalizes poorly. This limitation stems from the nature of expert demonstrations: they capture only a narrow range of scenarios, and expose the agent to limited environment diversity. We address this limitation with a middle-ground paradigm we call early experience: interaction data generated by the agent's own actions, where the resulting future states serve as supervision without reward signals. Within this paradigm, we study two strategies of using such data: (1) implicit world modeling, which uses collected states to ground the policy in environment dynamics; and (2) self-reflection, where the agent learns from its suboptimal actions to improve reasoning and decision-making. Evaluation across eight diverse environments and multiple model families shows that our approaches consistently improve effectiveness and out-of-domain generalization, highlighting the value of early experience. Moreover, in environments with verifiable rewards, our results provide promising signals that early experience offers a strong foundation for subsequent reinforcement learning, making it a practical bridge between imitation learning and fully experience-driven agents.","published":"2025-10-09T17:59:17Z","updated":"2026-05-24T21:56:11Z","categories":["cs.AI","cs.CL","cs.IR","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.08558v3","pdf_url":"https://arxiv.org/pdf/2510.08558v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=pEGnJbmSUy","openreview_venues":["ICML 2026 regular","Submitted to ICLR 2026"]},{"id":"2510.08529","versioned_id":"2510.08529v2","title":"CoMAS: Co-Evolving Multi-Agent Systems via Interaction Rewards","authors":["Xiangyuan Xue","Yifan Zhou","Guibin Zhang","Zaibin Zhang","Yijiang Li","Chen Zhang","Zhenfei Yin","Philip Torr","Wanli Ouyang","Lei Bai"],"abstract":"Self-evolution is a central research topic in enabling large language model (LLM)-based agents to continually improve their capabilities after pretraining. Recent research has witnessed a transition from reinforcement learning (RL)-free to RL-based methods. Current RL-based methods either rely on dense external reward signals or extract intrinsic reward signals from LLMs themselves. However, these approaches diverge from the self-evolution mechanisms observed in human intelligence, where individuals learn and improve through mutual discussion and collaboration. In this work, we introduce Co-Evolving Multi-Agent Systems (CoMAS), a novel framework that enables agents to improve autonomously by learning from inter-agent interactions without external supervision. CoMAS generates intrinsic rewards from rich discussion dynamics, employs an LLM-as-a-judge mechanism to formulate these rewards, and optimizes each agent's policy through RL, thereby enabling decentralized and scalable co-evolution. Experimental results demonstrate that CoMAS consistently outperforms untrained agents and achieves state-of-the-art performance across most evaluation settings. Ablation studies confirm the necessity of interaction-based reward signals and reveal promising scalability as the number and diversity of agents increase. These findings establish CoMAS as a novel and effective paradigm for self-evolution in LLM-based agents.","published":"2025-10-09T17:50:26Z","updated":"2026-02-09T07:41:44Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.08529v2","pdf_url":"https://arxiv.org/pdf/2510.08529v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=ihwAzktmWc","openreview_venues":["ICLR 2026 Poster"]},{"id":"2510.08511","versioned_id":"2510.08511v1","title":"AutoMLGen: Navigating Fine-Grained Optimization for Coding Agents","authors":["Shangheng Du","Xiangchao Yan","Dengyang Jiang","Jiakang Yuan","Yusong Hu","Xin Li","Liang He","Bo Zhang","Lei Bai"],"abstract":"Large language models (LLMs) have shown impressive performance in general programming tasks. However, in Machine Learning Engineering (MLE) scenarios such as AutoML and Kaggle competitions, achieving high performance depends heavily on expert intervention and repeated adjustments rather than simply generating correct code. When applied directly to these tasks, LLMs often lack fine-grained domain priors, and existing MLE approaches that use linear or tree-structured searches limit knowledge transfer to adjacent hierarchical links. As a result, they cannot leverage past full trajectories or share information across branches, limiting self-evolving ability and search space diversity. To address these limitations, we introduce AutoMLGen, an LLM-based coding agent that integrates a domain knowledge base for high-quality prior guidance and Monte Carlo Graph Search (MCGS) for efficient exploration. MCGS retains the tree-guided exploration of MCTS while embedding a graph structure into the expansion stage to enable dynamic path reorganization, historical trajectory reuse, and multi-solution fusion to support both self-evolution and collaborative learning. Combined with fine-grained operator sets, this design improves stability and accelerates convergence. Evaluation on the MLE-Bench shows that AutoMLGen achieves state-of-the-art performance in numerous dimensions, such as the average medal rate and the valid submission rate, under a 12-hour budget (half the standard runtime). The code is available at https://github.com/Alpha-Innovator/InternAgent.","published":"2025-10-09T17:45:05Z","updated":"2025-10-09T17:45:05Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.08511v1","pdf_url":"https://arxiv.org/pdf/2510.08511v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.08002","versioned_id":"2510.08002v1","title":"Learning on the Job: An Experience-Driven Self-Evolving Agent for Long-Horizon Tasks","authors":["Cheng Yang","Xuemeng Yang","Licheng Wen","Daocheng Fu","Jianbiao Mei","Rong Wu","Pinlong Cai","Yufan Shen","Nianchen Deng","Botian Shi","Yu Qiao","Haifeng Li"],"abstract":"Large Language Models have demonstrated remarkable capabilities across diverse domains, yet significant challenges persist when deploying them as AI agents for real-world long-horizon tasks. Existing LLM agents suffer from a critical limitation: they are test-time static and cannot learn from experience, lacking the ability to accumulate knowledge and continuously improve on the job. To address this challenge, we propose MUSE, a novel agent framework that introduces an experience-driven, self-evolving system centered around a hierarchical Memory Module. MUSE organizes diverse levels of experience and leverages them to plan and execute long-horizon tasks across multiple applications. After each sub-task execution, the agent autonomously reflects on its trajectory, converting the raw trajectory into structured experience and integrating it back into the Memory Module. This mechanism enables the agent to evolve beyond its static pretrained parameters, fostering continuous learning and self-evolution. We evaluate MUSE on the long-horizon productivity benchmark TAC. It achieves new SOTA performance by a significant margin using only a lightweight Gemini-2.5 Flash model. Sufficient Experiments demonstrate that as the agent autonomously accumulates experience, it exhibits increasingly superior task completion capabilities, as well as robust continuous learning and self-evolution capabilities. Moreover, the accumulated experience from MUSE exhibits strong generalization properties, enabling zero-shot improvement on new tasks. MUSE establishes a new paradigm for AI agents capable of real-world productivity task automation.","published":"2025-10-09T09:40:34Z","updated":"2025-10-09T09:40:34Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.08002v1","pdf_url":"https://arxiv.org/pdf/2510.08002v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=ZzH6xDdpTP","openreview_venues":["LLA 2026 Poster","Submitted to ICLR 2026"]},{"id":"2510.07841","versioned_id":"2510.07841v1","title":"Self-Improving LLM Agents at Test-Time","authors":["Emre Can Acikgoz","Cheng Qian","Heng Ji","Dilek Hakkani-Tür","Gokhan Tur"],"abstract":"One paradigm of language model (LM) fine-tuning relies on creating large training datasets, under the assumption that high quantity and diversity will enable models to generalize to novel tasks after post-training. In practice, gathering large sets of data is inefficient, and training on them is prohibitively expensive; worse, there is no guarantee that the resulting model will handle complex scenarios or generalize better. Moreover, existing techniques rarely assess whether a training sample provides novel information or is redundant with the knowledge already acquired by the model, resulting in unnecessary costs. In this work, we explore a new test-time self-improvement method to create more effective and generalizable agentic LMs on-the-fly. The proposed algorithm can be summarized in three steps: (i) first it identifies the samples that model struggles with (self-awareness), (ii) then generates similar examples from detected uncertain samples (self-data augmentation), and (iii) uses these newly generated samples at test-time fine-tuning (self-improvement). We study two variants of this approach: Test-Time Self-Improvement (TT-SI), where the same model generates additional training examples from its own uncertain cases and then learns from them, and contrast this approach with Test-Time Distillation (TT-D), where a stronger model generates similar examples for uncertain cases, enabling student to adapt using distilled supervision. Empirical evaluations across different agent benchmarks demonstrate that TT-SI improves the performance with +5.48% absolute accuracy gain on average across all benchmarks and surpasses other standard learning methods, yet using 68x less training samples. Our findings highlight the promise of TT-SI, demonstrating the potential of self-improvement algorithms at test-time as a new paradigm for building more capable agents toward self-evolution.","published":"2025-10-09T06:37:35Z","updated":"2025-10-09T06:37:35Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.07841v1","pdf_url":"https://arxiv.org/pdf/2510.07841v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=M1zSTXY1xr","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2510.07432","versioned_id":"2510.07432v2","title":"TS-Agent: Understanding and Reasoning Over Raw Time Series via Iterative Insight Gathering","authors":["Penghang Liu","Elizabeth Fons","Annita Vapsi","Mohsen Ghassemi","Svitlana Vyetrenko","Daniel Borrajo","Vamsi K. Potluru","Manuela Veloso"],"abstract":"Large language models (LLMs) exhibit strong symbolic and compositional reasoning, yet they struggle with time series question answering as the data is typically transformed into an LLM-compatible modality, e.g., serialized text, plotted images, or compressed time series embeddings. Such conversions impose representation bottlenecks, often require cross-modal alignment or finetuning, and can exacerbate hallucination and knowledge leakage. To address these limitations, we propose TS-Agent, an agentic, tool-grounded framework that uses LLMs strictly for iterative evidence-based reasoning, while delegating statistical and structural extraction to time series analytical tools operating on raw sequences. Our framework solves time series tasks through an evidence-driven agentic process: (1) it alternates between thinking, tool execution, and observation in a ReAct-style loop, (2) records intermediate results in an explicit evidence log and corrects the reasoning trace via a self-refinement critic, and (3) enforces a final answer-verification step to prevent hallucinations and leakage. Across four benchmarks spanning time series understanding and reasoning, TS-Agent matches or exceeds strong text-based, vision-based, and time-series language model baselines, with the largest gains on reasoning tasks where multimodal LLMs are prone to hallucination and knowledge leakage in zero-shot settings.","published":"2025-10-08T18:31:53Z","updated":"2026-04-06T21:49:20Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.07432v2","pdf_url":"https://arxiv.org/pdf/2510.07432v2","comment":"NeurIPS 2025 Workshop on Foundations of Reasoning in Language Models","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:EE5XSFZWud","versioned_id":"EE5XSFZWud","title":"ASIM: An Iterative Self-Correcting Agent Framework for Medical Text Simplification","authors":[],"abstract":"Medical text simplification is crucial for democratizing healthcare information. We present ASIM (Adaptive Self-correcting Iterative Medical simplifier), an agent-based framework employing iterative self-correction and retrieval-augmented generation to make medical reports accessible to non-specialists. Our system integrates five autonomous agents: terminology extraction, planning, knowledge-enhanced generation, self-correction, and memory-based learning. Unlike static approaches, ASIM learns from both successful and failed attempts through a four-stage evaluation framework. Experimental results show ASIM achieves 79.70% human preference compared to 46.70% for context-aware and 43.50% for optimization-based baselines, while maintaining competitive readability metrics. The iterative correction mechanism significantly improves comprehension for non-experts while preserving medical accuracy.","published":"2025-10-07T09:26:37+00:00","updated":"2026-07-02T03:04:52+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=EE5XSFZWud","openreview_url":"https://openreview.net/forum?id=EE5XSFZWud","pdf_url":"https://openreview.net/pdf?id=EE5XSFZWud","comment":"ACL ARR 2025 October Submission","journal_ref":"ACL ARR 2025 October Submission","doi":"","venue":"ACL ARR 2025 October Submission","venue_id":"aclweb.org/ACL/ARR/2025/October/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2510.05596","versioned_id":"2510.05596v1","title":"From Agentification to Self-Evolving Agentic AI for Wireless Networks: Concepts, Approaches, and Future Research Directions","authors":["Changyuan Zhao","Ruichen Zhang","Jiacheng Wang","Dusit Niyato","Geng Sun","Xianbin Wang","Shiwen Mao","Abbas Jamalipour"],"abstract":"Self-evolving agentic artificial intelligence (AI) offers a new paradigm for future wireless systems by enabling autonomous agents to continually adapt and improve without human intervention. Unlike static AI models, self-evolving agents embed an autonomous evolution cycle that updates models, tools, and workflows in response to environmental dynamics. This paper presents a comprehensive overview of self-evolving agentic AI, highlighting its layered architecture, life cycle, and key techniques, including tool intelligence, workflow optimization, self-reflection, and evolutionary learning. We further propose a multi-agent cooperative self-evolving agentic AI framework, where multiple large language models (LLMs) are assigned role-specialized prompts under the coordination of a supervisor agent. Through structured dialogue, iterative feedback, and systematic validation, the system autonomously executes the entire life cycle without human intervention. A case study on antenna evolution in low-altitude wireless networks (LAWNs) demonstrates how the framework autonomously upgrades fixed antenna optimization into movable antenna optimization. Experimental results show that the proposed self-evolving agentic AI autonomously improves beam gain and restores degraded performance by up to 52.02%, consistently surpassing the fixed baseline with little to no human intervention and validating its adaptability and robustness for next-generation wireless intelligence.","published":"2025-10-07T05:45:25Z","updated":"2025-10-07T05:45:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.05596v1","pdf_url":"https://arxiv.org/pdf/2510.05596v1","comment":"7 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.05571","versioned_id":"2510.05571v2","title":"Presenting a Paper is an Art: Self-Improvement Aesthetic Agents for Academic Presentations","authors":["Chengzhi Liu","Yuzhe Yang","Kaiwen Zhou","Zhen Zhang","Yue Fan","Yanan Xie","Peng Qi","Xin Eric Wang"],"abstract":"The promotion of academic papers has become an important means of enhancing research visibility. However, existing automated methods struggle limited storytelling, insufficient aesthetic quality, and constrained self-adjustment, making it difficult to achieve efficient and engaging dissemination. At the heart of those challenges is a simple principle: \\emph{there is no way to improve it when you cannot evaluate it right}. To address this, we introduce \\textbf{EvoPresent}, a self-improvement agent framework that unifies coherent narratives, aesthetic-aware designs, and realistic presentation delivery via virtual characters. Central to EvoPresent is \\textbf{PresAesth}, a multi-task reinforcement learning (RL) aesthetic model that provides reliable aesthetic scoring, defect adjustment, and comparative feedback, enabling iterative self-improvement even under limited aesthetic training data. To systematically evaluate the methods, we introduce \\textbf{EvoPresent Benchmark}, a comprehensive benchmark comprising: \\textit{Presentation Generation Quality}, built on 650 top-tier AI conference papers with multimodal resources (slides, videos and scripts) to assess both content and design; and \\textit{Aesthetic Awareness}, consisting of 2,000 slide pairs with varying aesthetic levels, supporting joint training and evaluation on scoring, defect adjustment, and comparison. Our findings highlight that (i) High-quality feedback is essential for agent self-improvement, while initial capability alone does not guarantee effective self-correction. (ii) Automated generation pipelines exhibit a trade-off between visual design and content construction. (iii) Multi-task RL training shows stronger generalization in aesthetic awareness tasks.","published":"2025-10-07T04:24:26Z","updated":"2025-10-21T21:04:18Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.05571v2","pdf_url":"https://arxiv.org/pdf/2510.05571v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=8NXCwNjFNR","openreview_venues":["ICLR 2026 Workshop RSI Spotlight","ICLR 2026 Poster"]},{"id":"2510.05432","versioned_id":"2510.05432v2","title":"AInstein: Can LLMs Solve Research Problems From Parametric Memory Alone?","authors":["Shambhavi Mishra","Gaurav Sahu","Marco Pedersoli","Laurent Charlin","Jose Dolz","Christopher Pal"],"abstract":"Can large language models solve AI research problems using only their parametric knowledge, without fine-tuning, retrieval, or other external aids? We introduce AInstein, a framework for testing whether LLM agents can generate and refine solutions to research problems through iterative critique loops. A blind study with 20 domain experts on held-out ICLR 2026 problems validates our automated metrics, which we then scale to 1,214 ICLR 2025 papers using an LLM-as-a-judge paradigm. Two metrics capture complementary aspects of performance: Success Rate (does the solution address the problem?) and Rediscovery (does it match the published approach?). LLMs succeed on over 70% of problems, yet strictly rediscover the published solution less than 19% of the time, suggesting genuine problem-solving rather than associative recall. However, this ability has clear limits: models handle familiar methodological territory well but fail when solutions require cross-domain analogical transfer, a pattern we call the parametric knowledge boundary. On the ResearchPlanGen benchmark (2,645 problems), our training-free iterative refinement strategy matches RL finetuning, and a criteria-coverage analysis pins down the ceiling of what test-time refinement alone can achieve. Together, these findings map both the capabilities and the limits of LLMs as autonomous scientific problem-solvers.","published":"2025-10-06T22:50:41Z","updated":"2026-04-28T12:36:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.05432v2","pdf_url":"https://arxiv.org/pdf/2510.05432v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:iseW6XNmPJ","versioned_id":"iseW6XNmPJ","title":"RAFFLES: Reasoning-based Attribution of Faults for LLM Systems","authors":[],"abstract":"The advent of complex, interconnected long-horizon LLM systems has made it incredibly tricky to identify where and when these systems break down. Evaluation capabilities that currently exist today are limited in that they often focus on simple metrics, end-to-end outcomes, and are dependent on the perspectives of humans. In order to match the increasing complexity of these many component systems, evaluation frameworks must also be able to reason, probe, iterate, and understand the nuanced logic passing through these systems. In this paper, we present RAFFLES, an evaluation architecture that incorporates reasoning and iterative refinement. Specifically, RAFFLES operates as an iterative, multi-component pipeline, using a central Judge to systematically investigate faults and a set of specialized Evaluators to assess not only the system's components but also the quality of the reasoning by the Judge itself. We evaluated RAFFLES with several benchmarks - the Who\\&When dataset to identify step-level faults in agentic systems and the ReasonEval datasets to diagnose step-level mathematical reasoning errors. RAFFLES outperforms strong baselines, achieving an accuracy of over 20\\% and 50\\% on the Who\\&When Hand-Crafted and Algorithm datasets, and over 80\\% on the ReasonEval datasets. These results demonstrate a key step towards introducing automated fault detection for autonomous systems over labor-intensive manual human review.","published":"2025-10-06T18:34:20+00:00","updated":"2026-07-02T03:04:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=iseW6XNmPJ","openreview_url":"https://openreview.net/forum?id=0oxelK4W6c","pdf_url":"https://openreview.net/pdf?id=iseW6XNmPJ","comment":"ACL ARR 2025 October Submission","journal_ref":"ACL ARR 2025 October Submission","doi":"","venue":"ACL ARR 2025 October Submission","venue_id":"aclweb.org/ACL/ARR/2025/October/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2025 October Submission","MTI-LLM @ NeurIPS 2025 Poster"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2510.04860","versioned_id":"2510.04860v2","title":"Alignment Tipping Process: How Self-Evolution Pushes LLM Agents Off the Rails","authors":["Siwei Han","Kaiwen Xiong","Jiaqi Liu","Xinyu Ye","Yaofeng Su","Wenbo Duan","Xinyuan Liu","Cihang Xie","Mohit Bansal","Mingyu Ding","Linjun Zhang","Huaxiu Yao"],"abstract":"As Large Language Model (LLM) agents increasingly gain self-evolutionary capabilities to adapt and refine their strategies through real-world interaction, their long-term reliability becomes a critical concern. We identify the Alignment Tipping Process (ATP), a critical post-deployment risk unique to self-evolving LLM agents. Unlike training-time failures, ATP arises when continual interaction drives agents to abandon alignment constraints established during training in favor of reinforced, self-interested strategies. We formalize and analyze ATP through two complementary paradigms: Self-Interested Exploration, where repeated high-reward deviations induce individual behavioral drift, and Imitative Strategy Diffusion, where deviant behaviors spread across multi-agent systems. Building on these paradigms, we construct controllable testbeds and benchmark both open and closed-source LLMs. Our experiments show that alignment benefits erode rapidly under self-evolution, with initially aligned models converging toward unaligned states. In multi-agent settings, successful violations diffuse quickly, leading to collective misalignment. Moreover, current reinforcement learning-based alignment methods provide limited defenses against alignment tipping. These findings demonstrate that alignment of LLM agents is not a static property but a fragile and dynamic one, vulnerable to feedback-driven decay during deployment. Our data and code are available at https://github.com/aiming-lab/ATP.","published":"2025-10-06T14:48:39Z","updated":"2026-02-11T20:59:12Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.04860v2","pdf_url":"https://arxiv.org/pdf/2510.04860v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=B4ICxIxrvH","openreview_venues":["Submitted to ICLR 2026"]},{"id":"openreview:P0qnjEUvyA","versioned_id":"P0qnjEUvyA","title":"WebSynthesis: World Model-Guided Monte Carlo Tree Search for Efficient WebAgent Trajectory Synthesis","authors":[],"abstract":"Recent advances in large language models (LLMs) have greatly empowered web agents, yet navigating complex and dynamic environments still demands stronger trajectory-level learning. Existing self-improving approaches rely on real-world GUI trajectories but suffer from environment instability and high data collection costs. To overcome these issues, we introduce WebSynthesis, a framework for scalable trajectory synthesis and training. By leveraging a learned world model for virtual web simulation, WebSynthesis enables efficient, reversible tree-based planning to generate diverse, high-quality trajectories that iteratively refine the agent's policy. Experiments demonstrate that agents trained on WebSynthesis achieve performance comparable to or surpassing those trained on large-scale real-world data.","published":"2025-10-06T09:56:03+00:00","updated":"2026-07-02T03:03:45+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=P0qnjEUvyA","openreview_url":"https://openreview.net/forum?id=P0qnjEUvyA","pdf_url":"https://openreview.net/pdf?id=P0qnjEUvyA","comment":"ACL ARR 2025 October Submission","journal_ref":"ACL ARR 2025 October Submission","doi":"","venue":"ACL ARR 2025 October Submission","venue_id":"aclweb.org/ACL/ARR/2025/October/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2510.04618","versioned_id":"2510.04618v3","title":"Agentic Context Engineering: Evolving Contexts for Self-Improving Language Models","authors":["Qizheng Zhang","Changran Hu","Shubhangi Upasani","Boyuan Ma","Fenglu Hong","Vamsidhar Kamanuru","Jay Rainton","Chen Wu","Mengmeng Ji","Hanchen Li","Urmish Thakker","James Zou","Kunle Olukotun"],"abstract":"Large language model (LLM) applications such as agents and domain-specific reasoning increasingly rely on context adaptation: modifying inputs with instructions, strategies, or evidence, rather than weight updates. Prior approaches improve usability but often suffer from brevity bias, which drops domain insights for concise summaries, and from context collapse, where iterative rewriting erodes details over time. We introduce ACE (Agentic Context Engineering), a framework that treats contexts as evolving playbooks that accumulate, refine, and organize strategies through a modular process of generation, reflection, and curation. ACE prevents collapse with structured, incremental updates that preserve detailed knowledge and scale with long-context models. Across agent and domain-specific benchmarks, ACE optimizes contexts both offline (e.g., system prompts) and online (e.g., agent memory), consistently outperforming strong baselines: +10.6% on agents and +8.6% on finance, while significantly reducing adaptation latency and rollout cost. Notably, ACE could adapt effectively without labeled supervision and instead by leveraging natural execution feedback. On the AppWorld leaderboard, ACE matches the top-ranked production-level agent on the overall average and surpasses it on the harder test-challenge split, despite using a smaller open-source model. These results show that comprehensive, evolving contexts enable scalable, efficient, and self-improving LLM systems with low overhead.","published":"2025-10-06T09:30:18Z","updated":"2026-03-29T09:18:02Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.04618v3","pdf_url":"https://arxiv.org/pdf/2510.04618v3","comment":"ICLR 2026; 32 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=eC4ygDs02R","openreview_venues":["ICLR 2026 Workshop MemAgents Oral","ICLR 2026 Poster"]},{"id":"2510.04399","versioned_id":"2510.04399v2","title":"On The Statistical Limits of Self-Improving Agents","authors":["Charles L. Wang","Keir Dorchen","Peter Jin"],"abstract":"As systems trend toward superintelligence, a natural modeling premise is that agents can self-improve along every facet of their own design. We formalize this with a five-axis decomposition and a decision layer, separating incentives from learning behavior and analyzing axes in isolation. Our central result identifies and introduces a sharp utility-learning tension, the structural conflict in self-modifying systems whereby utility-driven changes that improve immediate or expected performance can also erode the statistical preconditions for reliable learning and generalization. Our findings show that distribution-free guarantees are preserved iff the policy-reachable model family is uniformly capacity-bounded; when capacity can grow without limit, utility-rational self-changes can render learnable tasks unlearnable. Under standard assumptions common in practice, these axes reduce to the same capacity criterion, yielding a single boundary for safe self-modification.","published":"2025-10-05T23:52:16Z","updated":"2026-02-01T21:46:56Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.04399v2","pdf_url":"https://arxiv.org/pdf/2510.04399v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=q4vuDMtYgF","openreview_venues":["Decision pending for TMLR"]},{"id":"2510.03442","versioned_id":"2510.03442v1","title":"The Argument is the Explanation: Structured Argumentation for Trust in Agents","authors":["Ege Cakar","Per Ola Kristensson"],"abstract":"Humans are black boxes -- we cannot observe their neural processes, yet society functions by evaluating verifiable arguments. AI explainability should follow this principle: stakeholders need verifiable reasoning chains, not mechanistic transparency. We propose using structured argumentation to provide a level of explanation and verification neither interpretability nor LLM-generated explanation is able to offer. Our pipeline achieves state-of-the-art 94.44 macro F1 on the AAEC published train/test split (5.7 points above prior work) and $0.81$ macro F1, $\\sim$0.07 above previous published results with comparable data setups, for Argumentative MicroTexts relation classification, converting LLM text into argument graphs and enabling verification at each inferential step. We demonstrate this idea on multi-agent risk assessment using the Structured What-If Technique, where specialized agents collaborate transparently to carry out risk assessment otherwise achieved by humans alone. Using Bipolar Assumption-Based Argumentation, we capture support/attack relationships, thereby enabling automatic hallucination detection via fact nodes attacking arguments. We also provide a verification mechanism that enables iterative refinement through test-time feedback without retraining. For easy deployment, we provide a Docker container for the fine-tuned AMT model, and the rest of the code with the Bipolar ABA Python package on GitHub.","published":"2025-10-03T19:04:15Z","updated":"2025-10-03T19:04:15Z","categories":["cs.LG","cs.AI","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.03442v1","pdf_url":"https://arxiv.org/pdf/2510.03442v1","comment":"8 pages, 4 figures, 6 tables, submitted to IAAI-26","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.03194","versioned_id":"2510.03194v1","title":"CoDA: Agentic Systems for Collaborative Data Visualization","authors":["Zichen Chen","Jiefeng Chen","Sercan Ö. Arik","Misha Sra","Tomas Pfister","Jinsung Yoon"],"abstract":"Deep research has revolutionized data analysis, yet data scientists still devote substantial time to manually crafting visualizations, highlighting the need for robust automation from natural language queries. However, current systems struggle with complex datasets containing multiple files and iterative refinement. Existing approaches, including simple single- or multi-agent systems, often oversimplify the task, focusing on initial query parsing while failing to robustly manage data complexity, code errors, or final visualization quality. In this paper, we reframe this challenge as a collaborative multi-agent problem. We introduce CoDA, a multi-agent system that employs specialized LLM agents for metadata analysis, task planning, code generation, and self-reflection. We formalize this pipeline, demonstrating how metadata-focused analysis bypasses token limits and quality-driven refinement ensures robustness. Extensive evaluations show CoDA achieves substantial gains in the overall score, outperforming competitive baselines by up to 41.5%. This work demonstrates that the future of visualization automation lies not in isolated code generation but in integrated, collaborative agentic workflows.","published":"2025-10-03T17:30:16Z","updated":"2025-10-03T17:30:16Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.03194v1","pdf_url":"https://arxiv.org/pdf/2510.03194v1","comment":"31 pages, 6 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=M4RKeHIAxw","openreview_venues":["ICLR 2026 Poster"]},{"id":"2510.05158","versioned_id":"2510.05158v1","title":"Lang-PINN: From Language to Physics-Informed Neural Networks via a Multi-Agent Framework","authors":["Xin He","Liangliang You","Hongduan Tian","Bo Han","Ivor Tsang","Yew-Soon Ong"],"abstract":"Physics-informed neural networks (PINNs) provide a powerful approach for solving partial differential equations (PDEs), but constructing a usable PINN remains labor-intensive and error-prone. Scientists must interpret problems as PDE formulations, design architectures and loss functions, and implement stable training pipelines. Existing large language model (LLM) based approaches address isolated steps such as code generation or architecture suggestion, but typically assume a formal PDE is already specified and therefore lack an end-to-end perspective. We present Lang-PINN, an LLM-driven multi-agent system that builds trainable PINNs directly from natural language task descriptions. Lang-PINN coordinates four complementary agents: a PDE Agent that parses task descriptions into symbolic PDEs, a PINN Agent that selects architectures, a Code Agent that generates modular implementations, and a Feedback Agent that executes and diagnoses errors for iterative refinement. This design transforms informal task statements into executable and verifiable PINN code. Experiments show that Lang-PINN achieves substantially lower errors and greater robustness than competitive baselines: mean squared error (MSE) is reduced by up to 3--5 orders of magnitude, end-to-end execution success improves by more than 50\\%, and reduces time overhead by up to 74\\%.","published":"2025-10-03T08:20:02Z","updated":"2025-10-03T08:20:02Z","categories":["cs.AI","cs.CE","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.05158v1","pdf_url":"https://arxiv.org/pdf/2510.05158v1","comment":"PINN, PDE, Agent, LLM","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=ONEyVpgK34","openreview_venues":["ICLR 2026 Workshop RSI Spotlight","Submitted to ICLR 2026"]},{"id":"2510.01724","versioned_id":"2510.01724v2","title":"MetaboT: An LLM-based Multi-Agent Frameworkfor Interactive Analysis of Mass SpectrometryMetabolomics Knowledge Graphs","authors":["Madina Bekbergenova","Lucas Pradi","Benjamin Navet","Emma Tysinger","Franck Michel","Matthieu Feraud","Yousouf Taghzouti","Yan Zhou Chen","Olivier Kirchhoffer","Florence Mehl","Martin Legrand","Tao Jiang","Marco Pagni","Soha Hassoun","Jean-Luc Wolfender","Wout Bittremieux","Fabien Gandon","Louis-Félix Nothias"],"abstract":"Mass spectrometry-based metabolomics generates complex, high-dimensional data that holds vast potential for biological discovery but remains difficult to integrate and interpret. Knowledge graphs (KGs) unify this heterogeneous information by representing spectra, annotations, taxa, chemical classes, and biological activities as a single interoperable network; however, their practical use is limited by the steep learning curve of corresponding specialized representation and query languages. Here we introduce MetaboT, an open-source multi-agent Large Language Model (LLM) framework that translates natural-language questions into executable SPARQL queries over metabolomics knowledge graphs. MetaboT mitigates the hallucination and schema-compliance limitations of single-model approaches through a modular architecture in which specialised agents handle scope validation, entity resolution against authoritative resources, schema-aware query generation, iterative refinement, and result interpretation. We validated MetaboT on the Experimental Natural Products Knowledge Graph (ENPKG), using an expert-authored benchmark of natural-language questions paired with reference SPARQL queries, and demonstrate its ability to answer complex questions about plant--metabolite relationships and biological activities. MetaboT lowers the technical barrier for metabolomics researchers and enables semantic data mining without specialised programming expertise.","published":"2025-10-02T07:05:29Z","updated":"2026-05-27T07:48:14Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.01724v2","pdf_url":"https://arxiv.org/pdf/2510.01724v2","comment":"","journal_ref":"33rd annual international conference on Intelligent Systems for Molecular Biology (ISMB 2025) / 24th Annual Conference of the European Conference on Computational Biology (ECCB 2025), Jul 2025, Liverpool, United Kingdom","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.01674","versioned_id":"2510.01674v2","title":"FOR-Prompting: From Objection to Revision via an Asymmetric Prompting Protocol","authors":["He Zhang","Anzhou Zhang","Jian Dai"],"abstract":"Reasoning protocols such as Chain of Thought (CoT) and Tree of Thought (ToT) organize internal deliberation but lack an explicit mechanism for external questioning that elicits self-revision. We present FOR-Prompting (From Objection to Revision Prompting), an asymmetric protocol where a Defender proposes an answer, an Debater (Questioner) raises question-style objections with no direct fixes, and a Host optionally synthesizes the final output. Across GSM8K, FOR-Prompting matches the accuracy of CoT and consistently improves over single-prompting when evaluated under identical model backbones. On small-scale open-source models (e.g., LLaMA-3.2-1B), FOR-Prompting yields substantial gains over direct prompting and performs comparably to lightweight reasoning baselines, highlighting its promise for low-resource and on-device settings. Cross-model role-swapping further shows that performance is primarily determined by the Defender, enabling small models to act effectively as Questioners. Beyond structured math tasks, FOR-Prompting supports refinement in open-ended and multi-stage tasks: qualitative analysis shows improved exploration, coverage, and specificity, and a blind study of human preferences found that participants preferred FOR-Prompting outputs over strong LLM baselines in an itinerary-planning scenario. The protocol is model-agnostic and operates purely through role-structured prompting, requiring no training, access to model internals, or symmetrically strong agents. FOR-Prompting therefore enables scalable study of objection-driven reasoning and offers a practical mechanism for automated iterative refinement across both hosted and local LLMs.","published":"2025-10-02T04:57:58Z","updated":"2026-03-06T23:39:09Z","categories":["cs.CL","cs.AI","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.01674v2","pdf_url":"https://arxiv.org/pdf/2510.01674v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=EUFXVXK5y2","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2510.00568","versioned_id":"2510.00568v3","title":"ReSeek: A Self-Correcting Framework for Search Agents with Instructive Rewards","authors":["Shiyu Li","Yang Tang","Yifan Wang","Peiming Li","Xi Chen"],"abstract":"Search agents powered by Large Language Models (LLMs) have demonstrated significant potential in tackling knowledge-intensive tasks. Reinforcement learning (RL) has emerged as a powerful paradigm for training these agents to perform complex, multi-step reasoning. However, prior RL-based methods often rely on sparse or rule-based rewards, which can lead agents to commit to suboptimal or erroneous reasoning paths without the ability to recover. To address these limitations, we propose ReSeek, a novel self-correcting framework for training search agents. Our framework introduces a self-correction mechanism that empowers the agent to dynamically identify and recover from erroneous search paths during an episode. By invoking a special JUDGE action, the agent can judge the information and re-plan its search strategy. To guide this process, we design a dense, instructive process reward function, which decomposes into a correctness reward for retrieving factual information and a utility reward for finding information genuinely useful for the query. Furthermore, to mitigate the risk of data contamination in existing datasets, we introduce FictionalHot, a new and challenging benchmark with recently curated questions requiring complex reasoning. Being intuitively reasonable and practically simple, extensive experiments show that agents trained with ReSeek significantly outperform SOTA baselines in task success rate and path faithfulness.","published":"2025-10-01T06:44:28Z","updated":"2026-05-08T11:30:29Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2510.00568v3","pdf_url":"https://arxiv.org/pdf/2510.00568v3","comment":"ICML 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=pou5FfkVks","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2510.00381","versioned_id":"2510.00381v1","title":"Semantic-Driven AI Agent Communications: Challenges and Solutions","authors":["Kaiwen Yu","Mengying Sun","Zhijin Qin","Xiaodong Xu","Ping Yang","Yue Xiao","Gang Wu"],"abstract":"With the rapid growth of intelligent services, communication targets are shifting from humans to artificial intelligent (AI) agents, which require new paradigms to enable real-time perception, decision-making, and collaboration. Semantic communication, which conveys task-relevant meaning rather than raw data, offers a promising solution. However, its practical deployment remains constrained by dynamic environments and limited resources. To address these issues, this article proposes a semantic-driven AI agent communication framework and develops three enabling techniques. First, semantic adaptation transmission applies fine-tuning with real or generative samples to efficiently adapt models to varying environments. Second, semantic lightweight transmission incorporates pruning, quantization, and perception-aware sampling to reduce model complexity and alleviate computational burden on edge agents. Third, semantic self-evolution control employs distributed hierarchical decision-making to optimize multi-dimensional resources, enabling robust multi-agent collaboration in dynamic environments. Simulation results show that the proposed solutions achieve faster convergence and stronger robustness, while the proposed distributed hierarchical optimization method significantly outperforms conventional decision-making schemes, highlighting its potential for AI agent communication networks.","published":"2025-10-01T00:52:37Z","updated":"2025-10-01T00:52:37Z","categories":["cs.AI","eess.SP"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2510.00381v1","pdf_url":"https://arxiv.org/pdf/2510.00381v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.26354","versioned_id":"2509.26354v2","title":"Your Agent May Misevolve: Emergent Risks in Self-evolving LLM Agents","authors":["Shuai Shao","Qihan Ren","Chen Qian","Boyi Wei","Dadi Guo","Jingyi Yang","Xinhao Song","Linfeng Zhang","Weinan Zhang","Dongrui Liu","Jing Shao"],"abstract":"Advances in Large Language Models (LLMs) have enabled a new class of self-evolving agents that autonomously improve through interaction with the environment, demonstrating strong capabilities. However, self-evolution also introduces novel risks overlooked by current safety research. In this work, we study the case where an agent's self-evolution deviates in unintended ways, leading to undesirable or even harmful outcomes. We refer to this as Misevolution. To provide a systematic investigation, we evaluate misevolution along four key evolutionary pathways: model, memory, tool, and workflow. Our empirical findings reveal that misevolution is a widespread risk, affecting agents built even on top-tier LLMs (e.g., Gemini-2.5-Pro). Different emergent risks are observed in the self-evolutionary process, such as the degradation of safety alignment after memory accumulation, or the unintended introduction of vulnerabilities in tool creation and reuse. To our knowledge, this is the first study to systematically conceptualize misevolution and provide empirical evidence of its occurrence, highlighting an urgent need for new safety paradigms for self-evolving agents. Finally, we discuss potential mitigation strategies to inspire further research on building safer and more trustworthy self-evolving agents. Our code and data are available at https://github.com/ShaoShuai0605/Misevolution . Warning: this paper includes examples that may be offensive or harmful in nature.","published":"2025-09-30T14:55:55Z","updated":"2026-03-08T04:15:18Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.26354v2","pdf_url":"https://arxiv.org/pdf/2509.26354v2","comment":"Published in ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Fd1jgQQW28","openreview_venues":["ResponsibleFM @ NeurIPS 2025","ICLR 2026 Poster"]},{"id":"2509.26048","versioned_id":"2509.26048v2","title":"RE-Searcher: Robust Agentic Search with Goal-oriented Planning and Self-reflection","authors":["Daocheng Fu","Jianbiao Mei","Licheng Wen","Xuemeng Yang","Cheng Yang","Rong Wu","Tao Hu","Siqi Li","Yufan Shen","Xinyu Cai","Pinlong Cai","Botian Shi","Yong Liu","Yu Qiao"],"abstract":"Large language models (LLMs) excel at knowledge-intensive question answering and reasoning, yet their real-world deployment remains constrained by knowledge cutoff, hallucination, and limited interaction modalities. Augmenting LLMs with external search tools helps alleviate these issues, but it also exposes agents to a complex search environment in which small, plausible variations in query formulation can steer reasoning into unproductive trajectories and amplify errors. We present a systematic analysis that quantifies how environmental complexity induces fragile search behaviors and, in turn, degrades overall performance. To address this challenge, we propose a simple yet effective approach to instantiate a search agent, RE-Searcher. During search, RE-Searcher explicitly articulates a concrete search goal and subsequently reflects on whether the retrieved evidence satisfies that goal. This combination of goal-oriented planning and self-reflection enables RE-Searcher to resist spurious cues in complex search environments and perform robust search. Extensive experiments show that our method improves search accuracy and achieves state-of-the-art results. Perturbation studies further demonstrate substantial resilience to noisy or misleading external signals, mitigating the fragility of the search process. We believe these findings offer practical guidance for integrating LLM-powered agents into more complex interactive environments and enabling more autonomous decision-making.","published":"2025-09-30T10:25:27Z","updated":"2025-10-10T03:18:13Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.26048v2","pdf_url":"https://arxiv.org/pdf/2509.26048v2","comment":"15 pages, 7 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2510.00078","versioned_id":"2510.00078v1","title":"Adaptive and Resource-efficient Agentic AI Systems for Mobile and Embedded Devices: A Survey","authors":["Sicong Liu","Weiye Wu","Xiangrui Xu","Teng Li","Bowen Pang","Bin Guo","Zhiwen Yu"],"abstract":"Foundation models have reshaped AI by unifying fragmented architectures into scalable backbones with multimodal reasoning and contextual adaptation. In parallel, the long-standing notion of AI agents, defined by the sensing-decision-action loop, is entering a new paradigm: with FMs as their cognitive core, agents transcend rule-based behaviors to achieve autonomy, generalization, and self-reflection. This dual shift is reinforced by real-world demands such as autonomous driving, robotics, virtual assistants, and GUI agents, as well as ecosystem advances in embedded hardware, edge computing, mobile deployment platforms, and communication protocols that together enable large-scale deployment. Yet this convergence collides with reality: while applications demand long-term adaptability and real-time interaction, mobile and edge deployments remain constrained by memory, energy, bandwidth, and latency. This creates a fundamental tension between the growing complexity of FMs and the limited resources of deployment environments. This survey provides the first systematic characterization of adaptive, resource-efficient agentic AI systems. We summarize enabling techniques into elastic inference, test-time adaptation, dynamic multimodal integration, and agentic AI applications, and identify open challenges in balancing accuracy-latency-communication trade-offs and sustaining robustness under distribution shifts. We further highlight future opportunities in algorithm-system co-design, cognitive adaptation, and collaborative edge deployment. By mapping FM structures, cognition, and hardware resources, this work establishes a unified perspective toward scalable, adaptive, and resource-efficient agentic AI. We believe this survey can help readers to understand the connections between enabling technologies while promoting further discussions on the fusion of agentic intelligence and intelligent agents.","published":"2025-09-30T02:37:52Z","updated":"2025-09-30T02:37:52Z","categories":["cs.LG","cs.AI","cs.DC"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2510.00078v1","pdf_url":"https://arxiv.org/pdf/2510.00078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.25651","versioned_id":"2509.25651v1","title":"AutoLabs: Cognitive Multi-Agent Systems with Self-Correction for Autonomous Chemical Experimentation","authors":["Gihan Panapitiya","Emily Saldanha","Heather Job","Olivia Hess"],"abstract":"The automation of chemical research through self-driving laboratories (SDLs) promises to accelerate scientific discovery, yet the reliability and granular performance of the underlying AI agents remain critical, under-examined challenges. In this work, we introduce AutoLabs, a self-correcting, multi-agent architecture designed to autonomously translate natural-language instructions into executable protocols for a high-throughput liquid handler. The system engages users in dialogue, decomposes experimental goals into discrete tasks for specialized agents, performs tool-assisted stoichiometric calculations, and iteratively self-corrects its output before generating a hardware-ready file. We present a comprehensive evaluation framework featuring five benchmark experiments of increasing complexity, from simple sample preparation to multi-plate timed syntheses. Through a systematic ablation study of 20 agent configurations, we assess the impact of reasoning capacity, architectural design (single- vs. multi-agent), tool use, and self-correction mechanisms. Our results demonstrate that agent reasoning capacity is the most critical factor for success, reducing quantitative errors in chemical amounts (nRMSE) by over 85% in complex tasks. When combined with a multi-agent architecture and iterative self-correction, AutoLabs achieves near-expert procedural accuracy (F1-score > 0.89) on challenging multi-step syntheses. These findings establish a clear blueprint for developing robust and trustworthy AI partners for autonomous laboratories, highlighting the synergistic effects of modular design, advanced reasoning, and self-correction to ensure both performance and reliability in high-stakes scientific applications. Code: https://github.com/pnnl/autolabs","published":"2025-09-30T01:51:46Z","updated":"2025-09-30T01:51:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.25651v1","pdf_url":"https://arxiv.org/pdf/2509.25651v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.25541","versioned_id":"2509.25541v2","title":"Vision-Zero: Scalable VLM Self-Improvement via Strategic Gamified Self-Play","authors":["Qinsi Wang","Bo Liu","Tianyi Zhou","Jing Shi","Yueqian Lin","Yiran Chen","Hai Helen Li","Kun Wan","Wentian Zhao"],"abstract":"Although reinforcement learning (RL) has emerged as a promising approach for improving vision-language models (VLMs) and multimodal large language models (MLLMs), current methods rely heavily on manually curated datasets and costly human verification, which limits scalable self-improvement in multimodal systems. To address this challenge, we propose Vision-Zero, a label-free, domain-agnostic multi-agent self-play framework for self-evolving VLMs through competitive visual games generated from arbitrary image inputs. Specifically, Vision-Zero encompasses three main attributes: (1) Strategic Self-Play Framework: Vision-Zero trains VLMs in \"Who Is the Spy\"-style games, where the models engage in strategic reasoning and actions across multiple roles. Through interactive gameplay, models autonomously generate their training data without human annotation. (2) Gameplay from Arbitrary Images: Unlike existing gamified frameworks, Vision-Zero can generate games from arbitrary images, thereby enhancing the model's reasoning ability across diverse domains and showing strong generalization to different tasks. We demonstrate this versatility using three distinct types of image datasets: CLEVR-based synthetic scenes, charts, and real-world images. (3) Sustainable Performance Gain: We introduce Iterative Self-Play Policy Optimization (Iterative-SPO), a novel training algorithm that alternates between Self-Play and reinforcement learning with verifiable rewards (RLVR), mitigating the performance plateau often seen in self-play-only training and achieving sustained long-term improvements. Despite using label-free data, Vision-Zero achieves state-of-the-art performance on reasoning, chart question answering, and vision-centric understanding tasks, surpassing other annotation-based methods. Models and code have been released at https://github.com/wangqinsi1/Vision-Zero.","published":"2025-09-29T21:55:55Z","updated":"2026-03-04T03:35:17Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.25541v2","pdf_url":"https://arxiv.org/pdf/2509.25541v2","comment":"ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.24855","versioned_id":"2509.24855v1","title":"PhysicsMinions: Winning Gold Medals in the Latest Physics Olympiads with a Coevolutionary Multimodal Multi-Agent System","authors":["Fangchen Yu","Junchi Yao","Ziyi Wang","Haiyuan Wan","Youling Huang","Bo Zhang","Shuyue Hu","Dongzhan Zhou","Ning Ding","Ganqu Cui","Lei Bai","Wanli Ouyang","Peng Ye"],"abstract":"Physics is central to understanding and shaping the real world, and the ability to solve physics problems is a key indicator of real-world physical intelligence. Physics Olympiads, renowned as the crown of competitive physics, provide a rigorous testbed requiring complex reasoning and deep multimodal understanding, yet they remain largely underexplored in AI research. Existing approaches are predominantly single-model based, and open-source MLLMs rarely reach gold-medal-level performance. To address this gap, we propose PhysicsMinions, a coevolutionary multi-agent system for Physics Olympiad. Its architecture features three synergistic studios: a Visual Studio to interpret diagrams, a Logic Studio to formulate solutions, and a Review Studio to perform dual-stage verification. The system coevolves through an iterative refinement loop where feedback from the Review Studio continuously guides the Logic Studio, enabling the system to self-correct and converge towards the ground truth. Evaluated on the HiPhO benchmark spanning 7 latest physics Olympiads, PhysicsMinions delivers three major breakthroughs: (i) Strong generalization: it consistently improves both open-source and closed-source models of different sizes, delivering clear benefits over their single-model baselines; (ii) Historic breakthroughs: it elevates open-source models from only 1-2 to 6 gold medals across 7 Olympiads, achieving the first-ever open-source gold medal in the latest International Physics Olympiad (IPhO) under the average-score metric; and (iii) Scaling to human expert: it further advances the open-source Pass@32 score to 26.8/30 points on the latest IPhO, ranking 4th of 406 contestants and far surpassing the top single-model score of 22.7 (ranked 22nd). Generally, PhysicsMinions offers a generalizable framework for Olympiad-level problem solving, with the potential to extend across disciplines.","published":"2025-09-29T14:40:53Z","updated":"2025-09-29T14:40:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.24855v1","pdf_url":"https://arxiv.org/pdf/2509.24855v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=kipQYpoZf1","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2509.24726","versioned_id":"2509.24726v1","title":"Socratic-Zero : Bootstrapping Reasoning via Data-Free Agent Co-evolution","authors":["Shaobo Wang","Zhengbo Jiao","Zifan Zhang","Yilang Peng","Xu Ze","Boyu Yang","Wei Wang","Hu Wei","Linfeng Zhang"],"abstract":"Recent breakthroughs in large language models (LLMs) on reasoning tasks rely heavily on massive, high-quality datasets-typically human-annotated and thus difficult to scale. While data synthesis or distillation offers a promising alternative, existing methods struggle with inconsistent data quality and an inability to dynamically adapt to the evolving capabilities of the model, leading to suboptimal training signals. To address these limitations, we introduce Socratic-Zero, a fully autonomous framework that generates high-quality training data from minimal seed examples through the co-evolution of three agents: the Teacher, the Solver, and the Generator. The Solver continuously refines its reasoning by learning from preference feedback on both successful and failed trajectories; the Teacher adaptively crafts increasingly challenging questions based on the Solver's weaknesses; and the Generator distills the Teacher's question-design strategy to enable scalable, high-fidelity curriculum generation. This closed-loop system produces a self-improving curriculum-requiring no pre-existing tasks or labels. Remarkably, starting from only 100 seed questions, our Socratic-Solver-8B achieves an average gain of +20.2 percentage points over prior data synthesis methods across seven mathematical reasoning benchmarks (AMC23, AIME24-25, Olympiad, MATH-500, Minerva, and GSM8K), with consistent gains on both Qwen3 and GLM4 series models. Even more surprisingly, synthetic data from Socratic-Generator-32B enables student LLMs to achieve superior performance compared to other state-of-the-art (SOTA) commercial LLMs on these benchmarks, including Qwen3-235B-A22B, DeepSeek-V3.1-671B, GPT-5, Gemini-2.5-Pro, Grok-4, and Claude-4.1-Opus.","published":"2025-09-29T12:54:07Z","updated":"2025-09-29T12:54:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.24726v1","pdf_url":"https://arxiv.org/pdf/2509.24726v1","comment":"23 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=I1garriWB7","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2509.24524","versioned_id":"2509.24524v1","title":"PhysiAgent: An Embodied Agent Framework in Physical World","authors":["Zhihao Wang","Jianxiong Li","Jinliang Zheng","Wencong Zhang","Dongxiu Liu","Yinan Zheng","Haoyi Niu","Junzhi Yu","Xianyuan Zhan"],"abstract":"Vision-Language-Action (VLA) models have achieved notable success but often struggle with limited generalizations. To address this, integrating generalized Vision-Language Models (VLMs) as assistants to VLAs has emerged as a popular solution. However, current approaches often combine these models in rigid, sequential structures: using VLMs primarily for high-level scene understanding and task planning, and VLAs merely as executors of lower-level actions, leading to ineffective collaboration and poor grounding challenges. In this paper, we propose an embodied agent framework, PhysiAgent, tailored to operate effectively in physical environments. By incorporating monitor, memory, self-reflection mechanisms, and lightweight off-the-shelf toolboxes, PhysiAgent offers an autonomous scaffolding framework to prompt VLMs to organize different components based on real-time proficiency feedback from VLAs to maximally exploit VLAs' capabilities. Experimental results demonstrate significant improvements in task-solving performance on complex real-world robotic tasks, showcasing effective self-regulation of VLMs, coherent tool collaboration, and adaptive evolution of the framework during execution. PhysiAgent makes practical and pioneering efforts to integrate VLMs and VLAs, effectively grounding embodied agent frameworks in real-world settings.","published":"2025-09-29T09:39:32Z","updated":"2025-09-29T09:39:32Z","categories":["cs.RO","cs.AI","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.24524v1","pdf_url":"https://arxiv.org/pdf/2509.24524v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.24350","versioned_id":"2509.24350v1","title":"Dynamic Orchestration of Multi-Agent System for Real-World Multi-Image Agricultural VQA","authors":["Yan Ke","Xin Yu","Heming Du","Scott Chapman","Helen Huang"],"abstract":"Agricultural visual question answering is essential for providing farmers and researchers with accurate and timely knowledge. However, many existing approaches are predominantly developed for evidence-constrained settings such as text-only queries or single-image cases. This design prevents them from coping with real-world agricultural scenarios that often require multi-image inputs with complementary views across spatial scales, and growth stages. Moreover, limited access to up-to-date external agricultural context makes these systems struggle to adapt when evidence is incomplete. In addition, rigid pipelines often lack systematic quality control. To address this gap, we propose a self-reflective and self-improving multi-agent framework that integrates four roles, the Retriever, the Reflector, the Answerer, and the Improver. They collaborate to enable context enrichment, reflective reasoning, answer drafting, and iterative improvement. A Retriever formulates queries and gathers external information, while a Reflector assesses adequacy and triggers sequential reformulation and renewed retrieval. Two Answerers draft candidate responses in parallel to reduce bias. The Improver refines them through iterative checks while ensuring that information from multiple images is effectively aligned and utilized. Experiments on the AgMMU benchmark show that our framework achieves competitive performance on multi-image agricultural QA.","published":"2025-09-29T06:52:10Z","updated":"2025-09-29T06:52:10Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.24350v1","pdf_url":"https://arxiv.org/pdf/2509.24350v1","comment":"13 pages, 2 figures, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.24323","versioned_id":"2509.24323v1","title":"MAS$^2$: Self-Generative, Self-Configuring, Self-Rectifying Multi-Agent Systems","authors":["Kun Wang","Guibin Zhang","ManKit Ye","Xinyu Deng","Dongxia Wang","Xiaobin Hu","Jinyang Guo","Yang Liu","Yufei Guo"],"abstract":"The past two years have witnessed the meteoric rise of Large Language Model (LLM)-powered multi-agent systems (MAS), which harness collective intelligence and exhibit a remarkable trajectory toward self-evolution. This paradigm has rapidly progressed from manually engineered systems that require bespoke configuration of prompts, tools, roles, and communication protocols toward frameworks capable of automated orchestration. Yet, dominant automatic multi-agent systems, whether generated by external modules or a single LLM agent, largely adhere to a rigid ``\\textit{generate-once-and-deploy}'' paradigm, rendering the resulting systems brittle and ill-prepared for the dynamism and uncertainty of real-world environments. To transcend this limitation, we introduce MAS$^2$, a paradigm predicated on the principle of recursive self-generation: a multi-agent system that autonomously architects bespoke multi-agent systems for diverse problems. Technically, we devise a ``\\textit{generator-implementer-rectifier}'' tri-agent team capable of dynamically composing and adaptively rectifying a target agent system in response to real-time task demands. Collaborative Tree Optimization is proposed to train and specialize these meta-agents. Extensive evaluation across seven benchmarks reveals that MAS$^2$ achieves performance gains of up to $19.6\\%$ over state-of-the-art MAS in complex scenarios such as deep research and code generation. Moreover, MAS$^2$ exhibits superior cross-backbone generalization, effectively leveraging previously unseen LLMs to yield improvements of up to $15.1\\%$. Crucially, these gains are attained without incurring excessive token costs, as MAS$^2$ consistently resides on the Pareto frontier of cost-performance trade-offs. The source codes are available at https://github.com/yeyeyeah2/MAS2.","published":"2025-09-29T06:20:10Z","updated":"2025-09-29T06:20:10Z","categories":["cs.MA","cs.CL"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2509.24323v1","pdf_url":"https://arxiv.org/pdf/2509.24323v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=qumy27hMDY","openreview_venues":["ICLR 2026 Poster"]},{"id":"2509.24297","versioned_id":"2509.24297v2","title":"Q-Mirror: Unlocking the Multi-Modal Potential of Scientific Text-Only QA Pairs","authors":["Junying Wang","Zicheng Zhang","Ye Shen","Yalun Wu","Yingji Liang","Yijin Guo","Farong Wen","Wenzhe Li","Xuezhi Zhao","Qi Jia","Guangtao Zhai"],"abstract":"High-quality, multi-modal benchmarks are crucial for advancing scientific reasoning in large models yet their manual creation is costly and unscalable. To address this bottleneck, we explore the potential for transforming Text-Only QA Pairs (TQAs) into high-quality Multi-Modal QA Pairs (MMQAs), which include three parts: 1) Task Definition \\& Evaluation Rubric: We develop a TQA-to-MMQA framework and establish a comprehensive, multi-dimensional MMQA quality rubric that provides principles for the transformation. 2) Benchmark Construction: Then we construct two extensive benchmarks to rigorously evaluate state-of-the-art generation \\& understanding models on the distinct tasks of MMQA generation \\& MMQA quality evaluation. 3) Preliminary Solution: We develop an agentic system (Q-Mirror), which operationalizes our framework by integrating MMQA generation and evaluation into a closed loop for iterative refinement. Our experiments show that while state-of-the-art models can generate MMQAs, their outputs still leave substantial gaps, underscoring the need for reliable evaluation. We further demonstrate that top-tier understanding models align closely with human judgment in MMQA quality assessment. Leveraging both insights, the Q-Mirror agent raises average scores from 78.90 to 85.22 and pass rates from 72\\% to 95\\%, offering a practical path to large-scale scientific benchmarks.","published":"2025-09-29T05:22:10Z","updated":"2025-09-30T04:56:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.24297v2","pdf_url":"https://arxiv.org/pdf/2509.24297v2","comment":"25 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=3U2XxbhAyz","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2509.25271","versioned_id":"2509.25271v4","title":"RADAR: A Risk-Aware Dynamic Multi-Agent Framework for LLM Safety Evaluation via Role-Specialized Collaboration","authors":["Xiuyuan Chen","Jian Zhao","Yuchen Yuan","Tianle Zhang","Huilin Zhou","Zheng Zhu","Ping Hu","Linghe Kong","Chi Zhang","Weiran Huang","Xuelong Li"],"abstract":"Existing safety evaluation methods for large language models (LLMs) suffer from inherent limitations, including evaluator bias and detection failures arising from model homogeneity, which collectively undermine the robustness of risk evaluation processes. This paper seeks to re-examine the risk evaluation paradigm by introducing a theoretical framework that reconstructs the underlying risk concept space. Specifically, we decompose the latent risk concept space into three mutually exclusive subspaces: the explicit risk subspace (encompassing direct violations of safety guidelines), the implicit risk subspace (capturing potential malicious content that requires contextual reasoning for identification), and the non-risk subspace. Furthermore, we propose RADAR, a multi-agent collaborative evaluation framework that leverages multi-round debate mechanisms through four specialized complementary roles and employs dynamic update mechanisms to achieve self-evolution of risk concept distributions. This approach enables comprehensive coverage of both explicit and implicit risks while mitigating evaluator bias. To validate the effectiveness of our framework, we construct an evaluation dataset comprising 800 challenging cases. Extensive experiments on our challenging testset and public benchmarks demonstrate that RADAR significantly outperforms baseline evaluation methods across multiple dimensions, including accuracy, stability, and self-evaluation risk sensitivity. Notably, RADAR achieves a 28.87% improvement in risk identification accuracy compared to the strongest baseline evaluation method.","published":"2025-09-28T09:35:32Z","updated":"2025-10-23T03:33:26Z","categories":["cs.AI","cs.CV","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.25271v4","pdf_url":"https://arxiv.org/pdf/2509.25271v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=kQdVNX7UlO","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2509.23045","versioned_id":"2509.23045v3","title":"Kimi-Dev: Agentless Training as Skill Prior for SWE-Agents","authors":["Zonghan Yang","Shengjie Wang","Kelin Fu","Wenyang He","Weimin Xiong","Yibo Liu","Yibo Miao","Bofei Gao","Yejie Wang","Yingwei Ma","Yanhao Li","Yue Liu","Zhenxing Hu","Kaitai Zhang","Shuyi Wang","Huarong Chen","Flood Sung","Yang Liu","Yang Gao","Zhilin Yang","Tianyu Liu"],"abstract":"Large Language Models (LLMs) are increasingly applied to software engineering (SWE), with SWE-bench as a key benchmark. Solutions are split into SWE-Agent frameworks with multi-turn interactions and workflow-based Agentless methods with single-turn verifiable steps. We argue these paradigms are not mutually exclusive: reasoning-intensive Agentless training induces skill priors, including localization, code edit, and self-reflection that enable efficient and effective SWE-Agent adaptation. In this work, we first curate the Agentless training recipe and present Kimi-Dev, an open-source SWE LLM achieving 60.4\\% on SWE-bench Verified, the best among workflow approaches. With additional SFT adaptation on 5k publicly-available trajectories, Kimi-Dev powers SWE-Agents to 48.6\\% pass@1, on par with that of Claude 3.5 Sonnet (241022 version). These results show that structured skill priors from Agentless training can bridge workflow and agentic frameworks for transferable coding agents.","published":"2025-09-27T01:49:13Z","updated":"2025-12-08T17:33:03Z","categories":["cs.AI","cs.CL","cs.SE"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.23045v3","pdf_url":"https://arxiv.org/pdf/2509.23045v3","comment":"68 pages. GitHub repo at https://github.com/MoonshotAI/Kimi-Dev","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=tYppHuGhxJ","openreview_venues":["ICLR 2026 Poster"]},{"id":"2509.22502","versioned_id":"2509.22502v2","title":"InfiAgent: Self-Evolving Pyramid Agent Framework for Infinite Scenarios","authors":["Chenglin Yu","Yang Yu","Songmiao Wang","Yucheng Wang","Yifan Yang","Jinjia Li","Ming Li","Hongxia Yang"],"abstract":"Large Language Model (LLM) agents have demonstrated remarkable capabilities in organizing and executing complex tasks, and many such agents are now widely used in various application scenarios. However, developing these agents requires carefully designed workflows, carefully crafted prompts, and iterative tuning, which requires LLM techniques and domain-specific expertise. These hand-crafted limitations hinder the scalability and cost-effectiveness of LLM agents across a wide range of industries. To address these challenges, we propose \\textbf{InfiAgent}, a Pyramid-like DAG-based Multi-Agent Framework that can be applied to \\textbf{infi}nite scenarios, which introduces several key innovations: a generalized \"agent-as-a-tool\" mechanism that automatically decomposes complex agents into hierarchical multi-agent systems; a dual-audit mechanism that ensures the quality and stability of task completion; an agent routing function that enables efficient task-agent matching; and an agent self-evolution mechanism that autonomously restructures the agent DAG based on new tasks, poor performance, or optimization opportunities. Furthermore, InfiAgent's atomic task design supports agent parallelism, significantly improving execution efficiency. This framework evolves into a versatile pyramid-like multi-agent system capable of solving a wide range of problems. Evaluations on multiple benchmarks demonstrate that InfiAgent achieves 9.9\\% higher performance compared to ADAS (similar auto-generated agent framework), while a case study of the AI research assistant InfiHelper shows that it generates scientific papers that have received recognition from human reviewers at top-tier IEEE conferences.","published":"2025-09-26T15:44:09Z","updated":"2025-09-30T10:55:50Z","categories":["cs.AI","cs.HC"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.22502v2","pdf_url":"https://arxiv.org/pdf/2509.22502v2","comment":"9 pages of main content and 32 pages of others, 2 figures, under review as a conference paper at ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=GBlHo6mPIW","openreview_venues":["ICLR 2026 Conference Desk Rejected Submission"]},{"id":"2509.21710","versioned_id":"2509.21710v2","title":"Think-on-Graph 3.0: Efficient and Adaptive LLM Reasoning on Heterogeneous Graphs via Multi-Agent Dual-Evolving Context Retrieval","authors":["Xiaojun Wu","Cehao Yang","Xueyuan Lin","Chengjin Xu","Xuhui Jiang","Yuanliang Sun","Hui Xiong","Jia Li","Jian Guo"],"abstract":"Graph-based Retrieval-Augmented Generation (GraphRAG) has become the important paradigm for enhancing Large Language Models (LLMs) with external knowledge. However, existing approaches are constrained by their reliance on high-quality knowledge graphs: manually built ones are not scalable, while automatically extracted ones are limited by the performance of LLM extractors, especially when using smaller, local-deployed models. To address this, we introduce Think-on-Graph 3.0 (ToG-3), a novel framework featuring a Multi-Agent Context Evolution and Retrieval (MACER) mechanism. Its core contribution is the dynamic construction and iterative refinement of a Chunk-Triplets-Community heterogeneous graph index, powered by a Dual-Evolution process that adaptively evolves both the query and the retrieved sub-graph during reasoning. ToG-3 dynamically builds a targeted graph index tailored to the query, enabling precise evidence retrieval and reasoning even with lightweight LLMs. Extensive experiments demonstrate that ToG-3 outperforms compared baselines on both deep and broad reasoning benchmarks, and ablation studies confirm the efficacy of the components of MACER framework. The source code are available in https://github.com/DataArcTech/ToG-3.","published":"2025-09-26T00:13:10Z","updated":"2026-01-06T13:17:33Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.21710v2","pdf_url":"https://arxiv.org/pdf/2509.21710v2","comment":"add: reranker agent and experiments","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=AWNvtEkkOx","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2509.21129","versioned_id":"2509.21129v1","title":"EvoMail: Self-Evolving Cognitive Agents for Adaptive Spam and Phishing Email Defense","authors":["Wei Huang","De-Tian Chu","Lin-Yuan Bai","Wei Kang","Hai-Tao Zhang","Bo Li","Zhi-Mo Han","Jing Ge","Hai-Feng Lin"],"abstract":"Modern email spam and phishing attacks have evolved far beyond keyword blacklists or simple heuristics. Adversaries now craft multi-modal campaigns that combine natural-language text with obfuscated URLs, forged headers, and malicious attachments, adapting their strategies within days to bypass filters. Traditional spam detection systems, which rely on static rules or single-modality models, struggle to integrate heterogeneous signals or to continuously adapt, leading to rapid performance degradation. We propose EvoMail, a self-evolving cognitive agent framework for robust detection of spam and phishing. EvoMail first constructs a unified heterogeneous email graph that fuses textual content, metadata (headers, senders, domains), and embedded resources (URLs, attachments). A Cognitive Graph Neural Network enhanced by a Large Language Model (LLM) performs context-aware reasoning across these sources to identify coordinated spam campaigns. Most critically, EvoMail engages in an adversarial self-evolution loop: a ''red-team'' agent generates novel evasion tactics -- such as character obfuscation or AI-generated phishing text -- while the ''blue-team'' detector learns from failures, compresses experiences into a memory module, and reuses them for future reasoning. Extensive experiments on real-world datasets (Enron-Spam, Ling-Spam, SpamAssassin, and TREC) and synthetic adversarial variants demonstrate that EvoMail consistently outperforms state-of-the-art baselines in detection accuracy, adaptability to evolving spam tactics, and interpretability of reasoning traces. These results highlight EvoMail's potential as a resilient and explainable defense framework against next-generation spam and phishing threats.","published":"2025-09-25T13:19:59Z","updated":"2025-09-25T13:19:59Z","categories":["cs.LG","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.21129v1","pdf_url":"https://arxiv.org/pdf/2509.21129v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.20900","versioned_id":"2509.20900v3","title":"Learning to Summarize by Learning to Quiz: Adversarial Agentic Collaboration for Long Document Summarization","authors":["Weixuan Wang","Minghao Wu","Barry Haddow","Alexandra Birch"],"abstract":"Long document summarization remains a significant challenge for current large language models (LLMs), as existing approaches commonly struggle with information loss, factual inconsistencies, and coherence issues when processing excessively long documents. We propose SummQ, a novel adversarial multi-agent framework that addresses these limitations through collaborative intelligence between specialized agents operating in two complementary domains: summarization and quizzing. Our approach employs summary generators and reviewers that work collaboratively to create and evaluate comprehensive summaries, while quiz generators and reviewers create comprehension questions that serve as continuous quality checks for the summarization process. This adversarial dynamic, enhanced by an examinee agent that validates whether the generated summary contains the information needed to answer the quiz questions, enables iterative refinement through multifaceted feedback mechanisms. We evaluate SummQ on three widely used long document summarization benchmarks. Experimental results demonstrate that our framework significantly outperforms existing state-of-the-art methods across ROUGE and BERTScore metrics, as well as in LLM-as-a-Judge and human evaluations. Our comprehensive analyses reveal the effectiveness of the multi-agent collaboration dynamics, the influence of different agent configurations, and the impact of the quizzing mechanism. This work establishes a new approach for long document summarization that uses adversarial agentic collaboration to improve summarization quality.","published":"2025-09-25T08:36:19Z","updated":"2026-02-05T07:34:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.20900v3","pdf_url":"https://arxiv.org/pdf/2509.20900v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=WAQhCifBSb","openreview_venues":["ICLR 2026 Poster"]},{"id":"openreview:SD39zdAeNb","versioned_id":"SD39zdAeNb","title":"Automated Detection of Visual Attribute Reliance with a Self-Reflective Agent","authors":["Christy Li","Josep Lopez Camuñas","Jake Thomas Touchet","Jacob Andreas","Agata Lapedriza","Antonio Torralba","Tamar Rott Shaham"],"abstract":"When a vision model performs image recognition, which visual attributes drive its predictions? Detecting unintended use of specific visual features is critical for ensuring model robustness, preventing overfitting, and avoiding spurious correlations. We introduce an automated framework for detecting these dependencies in trained vision models. At the core of our method is a self-reflective agent that systematically generates and tests hypotheses about the unintended visual attributes that a model may rely on. This process is iterative: the agent refines its hypotheses based on experimental outcomes and uses a self-evaluation protocol to assess whether its findings accurately explain model behavior. If inconsistencies are detected, the agent self-reflects over its findings and triggers a new cycle of experimentation. We evaluate our approach on a novel benchmark of 130 models designed to exhibit diverse visual attribute dependencies across 18 categories. Our results show that the agent's performance consistently improves with self-reflection, with a significant performance increase over non-reflective baselines. We further demonstrate that the agent identifies real-world visual attribute dependencies in state-of-the-art models, including CLIP's vision encoder and the YOLOv8 object detector.","published":"2025-09-25T05:56:49+00:00","updated":"2025-09-25T05:56:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=SD39zdAeNb","openreview_url":"https://openreview.net/forum?id=LyH2ISbOV8","pdf_url":"https://openreview.net/pdf?id=SD39zdAeNb","comment":"NeurIPS","journal_ref":"NeurIPS","doi":"","venue":"NeurIPS","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["NeurIPS","Mech Interp Workshop (NeurIPS 2025) Poster","NeurIPS 2025 poster"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2509.25229","versioned_id":"2509.25229v1","title":"Blueprint-Bench: Comparing spatial intelligence of LLMs, agents and image models","authors":["Lukas Petersson","Axel Backlund","Axel Wennstöm","Hanna Petersson","Callum Sharrock","Arash Dabiri"],"abstract":"We introduce Blueprint-Bench, a benchmark designed to evaluate spatial reasoning capabilities in AI models through the task of converting apartment photographs into accurate 2D floor plans. While the input modality (photographs) is well within the training distribution of modern multimodal models, the task of spatial reconstruction requires genuine spatial intelligence: inferring room layouts, understanding connectivity, and maintaining consistent scale. We evaluate leading language models (GPT-5, Claude 4 Opus, Gemini 2.5 Pro, Grok-4), image generation models (GPT-Image, NanoBanana), and agent systems (Codex CLI, Claude Code) on a dataset of 50 apartments with approximately 20 interior images each. Our scoring algorithm measures similarity between generated and ground-truth floor plans based on room connectivity graphs and size rankings. Results reveal a significant blind spot in current AI capabilities: most models perform at or below a random baseline, while human performance remains substantially superior. Image generation models particularly struggle with instruction following, while agent-based approaches with iterative refinement capabilities show no meaningful improvement over single-pass generation. Blueprint-Bench provides the first numerical framework for comparing spatial intelligence across different model architectures. We will continue evaluating new models as they are released and welcome community submissions, monitoring for the emergence of spatial intelligence in generalist AI systems.","published":"2025-09-24T23:35:26Z","updated":"2025-09-24T23:35:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.25229v1","pdf_url":"https://arxiv.org/pdf/2509.25229v1","comment":"9 pages, 8 figures, submitted for ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=xVB9AivJa5","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2509.20562","versioned_id":"2509.20562v1","title":"SAMULE: Self-Learning Agents Enhanced by Multi-level Reflection","authors":["Yubin Ge","Salvatore Romeo","Jason Cai","Monica Sunkara","Yi Zhang"],"abstract":"Despite the rapid advancements in LLM agents, they still face the challenge of generating meaningful reflections due to inadequate error analysis and a reliance on rare successful trajectories, especially in complex tasks. In this work, we propose SAMULE, a new framework for self-learning agents powered by a retrospective language model that is trained based on Multi-Level Reflection Synthesis. It first synthesizes high-quality reflections across three complementary levels: Single-Trajectory Learning (micro-level) for detailed error correction; Intra-Task Learning (meso-level) to build error taxonomies across multiple trials of the same task, and Inter-Task Learning (macro-level) to extract transferable insights based on same typed errors from diverse task failures. Then we fine-tune a language model serving as the retrospective model to generate reflections during inference. We further extend our framework to interactive settings through a foresight-based reflection mechanism, enabling agents to proactively reflect and adapt during user interactions by comparing predicted and actual responses. Extensive experiments on three challenging benchmarks - TravelPlanner, NATURAL PLAN, and Tau-bench - demonstrate that our approach significantly outperforms reflection-based baselines. Our results highlight the critical role of well-designed reflection synthesis and failure-centric learning in building self-improving LLM agents.","published":"2025-09-24T21:02:15Z","updated":"2025-09-24T21:02:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.20562v1","pdf_url":"https://arxiv.org/pdf/2509.20562v1","comment":"Accepted at EMNLP 2025 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.20414","versioned_id":"2509.20414v2","title":"SceneWeaver: All-in-One 3D Scene Synthesis with an Extensible and Self-Reflective Agent","authors":["Yandan Yang","Baoxiong Jia","Shujie Zhang","Siyuan Huang"],"abstract":"Indoor scene synthesis has become increasingly important with the rise of Embodied AI, which requires 3D environments that are not only visually realistic but also physically plausible and functionally diverse. While recent approaches have advanced visual fidelity, they often remain constrained to fixed scene categories, lack sufficient object-level detail and physical consistency, and struggle to align with complex user instructions. In this work, we present SceneWeaver, a reflective agentic framework that unifies diverse scene synthesis paradigms through tool-based iterative refinement. At its core, SceneWeaver employs a language model-based planner to select from a suite of extensible scene generation tools, ranging from data-driven generative models to visual- and LLM-based methods, guided by self-evaluation of physical plausibility, visual realism, and semantic alignment with user input. This closed-loop reason-act-reflect design enables the agent to identify semantic inconsistencies, invoke targeted tools, and update the environment over successive iterations. Extensive experiments on both common and open-vocabulary room types demonstrate that SceneWeaver not only outperforms prior methods on physical, visual, and semantic metrics, but also generalizes effectively to complex scenes with diverse instructions, marking a step toward general-purpose 3D environment generation. Project website: https://scene-weaver.github.io/.","published":"2025-09-24T09:06:41Z","updated":"2025-10-26T04:10:24Z","categories":["cs.GR","cs.CV","cs.LG","cs.RO"],"primary_category":"cs.GR","arxiv_url":"https://arxiv.org/abs/2509.20414v2","pdf_url":"https://arxiv.org/pdf/2509.20414v2","comment":"Accepted by NeurIPS 2025, 26 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=x1wZoyS0rC","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2509.19460","versioned_id":"2509.19460v1","title":"Self-evolved Imitation Learning in Simulated World","authors":["Yifan Ye","Jun Cen","Jing Chen","Zhihe Lu"],"abstract":"Imitation learning has been a trend recently, yet training a generalist agent across multiple tasks still requires large-scale expert demonstrations, which are costly and labor-intensive to collect. To address the challenge of limited supervision, we propose Self-Evolved Imitation Learning (SEIL), a framework that progressively improves a few-shot model through simulator interactions. The model first attempts tasksin the simulator, from which successful trajectories are collected as new demonstrations for iterative refinement. To enhance the diversity of these demonstrations, SEIL employs dual-level augmentation: (i) Model-level, using an Exponential Moving Average (EMA) model to collaborate with the primary model, and (ii) Environment-level, introducing slight variations in initial object positions. We further introduce a lightweight selector that filters complementary and informative trajectories from the generated pool to ensure demonstration quality. These curated samples enable the model to achieve competitive performance with far fewer training examples. Extensive experiments on the LIBERO benchmark show that SEIL achieves a new state-of-the-art performance in few-shot imitation learning scenarios. Code is available at https://github.com/Jasper-aaa/SEIL.git.","published":"2025-09-23T18:15:32Z","updated":"2025-09-23T18:15:32Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.19460v1","pdf_url":"https://arxiv.org/pdf/2509.19460v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.19292","versioned_id":"2509.19292v1","title":"SOE: Sample-Efficient Robot Policy Self-Improvement via On-Manifold Exploration","authors":["Yang Jin","Jun Lv","Han Xue","Wendi Chen","Chuan Wen","Cewu Lu"],"abstract":"Intelligent agents progress by continually refining their capabilities through actively exploring environments. Yet robot policies often lack sufficient exploration capability due to action mode collapse. Existing methods that encourage exploration typically rely on random perturbations, which are unsafe and induce unstable, erratic behaviors, thereby limiting their effectiveness. We propose Self-Improvement via On-Manifold Exploration (SOE), a framework that enhances policy exploration and improvement in robotic manipulation. SOE learns a compact latent representation of task-relevant factors and constrains exploration to the manifold of valid actions, ensuring safety, diversity, and effectiveness. It can be seamlessly integrated with arbitrary policy models as a plug-in module, augmenting exploration without degrading the base policy performance. Moreover, the structured latent space enables human-guided exploration, further improving efficiency and controllability. Extensive experiments in both simulation and real-world tasks demonstrate that SOE consistently outperforms prior methods, achieving higher task success rates, smoother and safer exploration, and superior sample efficiency. These results establish on-manifold exploration as a principled approach to sample-efficient policy self-improvement. Project website: https://ericjin2002.github.io/SOE","published":"2025-09-23T17:54:47Z","updated":"2025-09-23T17:54:47Z","categories":["cs.RO","cs.AI","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2509.19292v1","pdf_url":"https://arxiv.org/pdf/2509.19292v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.18847","versioned_id":"2509.18847v3","title":"Failure Makes the Agent Stronger: Enhancing Accuracy through Structured Reflection for Reliable Tool Interactions","authors":["Junhao Su","Yuanliang Wan","Junwei Yang","Hengyu Shi","Tianyang Han","Junfeng Luo","Yurui Qiu"],"abstract":"Tool-augmented large language models (LLMs) are usually trained with supervised imitation or coarse-grained reinforcement learning that optimizes single tool calls. Current self-reflection practices rely on heuristic prompts or one-way reasoning: the model is urged to 'think more' instead of learning error diagnosis and repair. This is fragile in multi-turn interactions; after a failure the model often repeats the same mistake. We propose structured reflection, which turns the path from error to repair into an explicit, controllable, and trainable action. The agent produces a short yet precise reflection: it diagnoses the failure using evidence from the previous step and then proposes a correct, executable follow-up call. For training we combine DAPO and GSPO objectives with a reward scheme tailored to tool use, optimizing the stepwise strategy Reflect, then Call, then Final. To evaluate, we introduce Tool-Reflection-Bench, a lightweight benchmark that programmatically checks structural validity, executability, parameter correctness, and result consistency. Tasks are built as mini trajectories of erroneous call, reflection, and corrected call, with disjoint train and test splits. Experiments on BFCL v3 and Tool-Reflection-Bench show large gains in multi-turn tool-call success and error recovery, and a reduction of redundant calls. These results indicate that making reflection explicit and optimizing it directly improves the reliability of tool interaction and offers a reproducible path for agents to learn from failure.","published":"2025-09-23T09:35:49Z","updated":"2026-04-15T06:57:52Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2509.18847v3","pdf_url":"https://arxiv.org/pdf/2509.18847v3","comment":"ACL","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=agRa60l7rn","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2509.18713","versioned_id":"2509.18713v1","title":"MemOrb: A Plug-and-Play Verbal-Reinforcement Memory Layer for E-Commerce Customer Service","authors":["Yizhe Huang","Yang Liu","Ruiyu Zhao","Xiaolong Zhong","Xingming Yue","Ling Jiang"],"abstract":"Large Language Model-based agents(LLM-based agents) are increasingly deployed in customer service, yet they often forget across sessions, repeat errors, and lack mechanisms for continual self-improvement. This makes them unreliable in dynamic settings where stability and consistency are critical. To better evaluate these properties, we emphasize two indicators: task success rate as a measure of overall effectiveness, and consistency metrics such as Pass$^k$ to capture reliability across multiple trials. To address the limitations of existing approaches, we propose MemOrb, a lightweight and plug-and-play verbal reinforcement memory layer that distills multi-turn interactions into compact strategy reflections. These reflections are stored in a shared memory bank and retrieved to guide decision-making, without requiring any fine-tuning. Experiments show that MemOrb significantly improves both success rate and stability, achieving up to a 63 percentage-point gain in multi-turn success rate and delivering more consistent performance across repeated trials. Our results demonstrate that structured reflection is a powerful mechanism for enhancing long-term reliability of frozen LLM agents in customer service scenarios.","published":"2025-09-23T06:57:07Z","updated":"2025-09-23T06:57:07Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.18713v1","pdf_url":"https://arxiv.org/pdf/2509.18713v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Y3L3WotMPm","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2509.17066","versioned_id":"2509.17066v1","title":"RALLM-POI: Retrieval-Augmented LLM for Zero-shot Next POI Recommendation with Geographical Reranking","authors":["Kunrong Li","Kwan Hui Lim"],"abstract":"Next point-of-interest (POI) recommendation predicts a user's next destination from historical movements. Traditional models require intensive training, while LLMs offer flexible and generalizable zero-shot solutions but often generate generic or geographically irrelevant results due to missing trajectory and spatial context. To address these issues, we propose RALLM-POI, a framework that couples LLMs with retrieval-augmented generation and self-rectification. We first propose a Historical Trajectory Retriever (HTR) that retrieves relevant past trajectories to serve as contextual references, which are then reranked by a Geographical Distance Reranker (GDR) for prioritizing spatially relevant trajectories. Lastly, an Agentic LLM Rectifier (ALR) is designed to refine outputs through self-reflection. Without additional training, RALLM-POI achieves substantial accuracy gains across three real-world Foursquare datasets, outperforming both conventional and LLM-based baselines. Code is released at https://github.com/LKRcrocodile/RALLM-POI.","published":"2025-09-21T12:52:28Z","updated":"2025-09-21T12:52:28Z","categories":["cs.AI","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.17066v1","pdf_url":"https://arxiv.org/pdf/2509.17066v1","comment":"PRICAI 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:nX3AZQEJ3O","versioned_id":"nX3AZQEJ3O","title":"WaAgents: A Waterfall-Inspired Framework for Effective Multi-Agent Collaboration","authors":["Zhuo Cheng","YuLin Xiao","Qing Huang","Zhou Zou","Zhenchang Xing","Shaochen Wang","Zhaojin Lu","ZHIPING LIU"],"abstract":"Large Language Models (LLMs) have revolutionized the construction of multi-agent systems for complex problem solving, leveraging their prowess in natural language understanding for semantic parsing and intent recognition, alongside robust logical reasoning for intricate task execution. Despite these advances, prevailing LLM-based multi-agent frameworks suffer from a critical shortfall: the absence of explicit, predefined stage segmentation. This leads to pervasive information redundancy in inter-agent communications, manifesting as irrelevant discussions without focused topics, and exacerbates decision conflicts in free-discussion paradigms, where agents of equal status deadlock over divergent opinions, ultimately hindering effective resolutions. To address these limitations, we introduce WaAgents, a novel multi-agent collaboration framework inspired by the Waterfall Model in Software Engineering. WaAgents delineates the problem-solving process into four sequential, interdependent stages: Requirement Analysis, Design, Implementation, and Reflection. In the Requirement Analysis stage, Requirement Analysis Agents parse user intents to produce a structured task specification, facilitating downstream processing. Designer Agents in the Design stage then employ this specification to decompose the task into granular sub-tasks, systematically assigning them to dedicated Worker Agents. During Implementation, each Worker Agent executes its sub-task through targeted operations and computations. Anomalies trigger the Reflection stage, where Error Analysis Agents diagnose root causes, distinguishing design from implementation errors, and enact precise repairs, ensuring iterative refinement without disrupting workflow integrity. This stage-driven, highly structured workflow provides each agent role with explicit, concentrated objectives, which substantially mitigate information redundancy. Furthermore, by strictly enforcing the predefined flow, WaAgents fundamentally eliminates the decision conflicts inherent to free-discussion, thereby ensuring the coherence and effectiveness of the entire solution process. Empirical validation across challenging benchmarks, including mathematical reasoning and open-ended problem solving, confirms the efficacy and marked superiority of the WaAgents framework.","published":"2025-09-20T10:31:51+00:00","updated":"2026-01-11T13:08:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=nX3AZQEJ3O","openreview_url":"https://openreview.net/forum?id=nX3AZQEJ3O","pdf_url":"https://openreview.net/pdf?id=nX3AZQEJ3O","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:KN2RD4fpnH","versioned_id":"KN2RD4fpnH","title":"Geometry of Nash Mirror Dynamics: Adaptive $\\beta$-Control for Stable and Bias-Robust Self-Improving LLM Agents","authors":["Kotaro Sakamoto","Takeshi Kojima","Yusuke Iwasawa","Yutaka Matsuo"],"abstract":"Self‑improving agents learn by playing competitive, often non-transitive language games (e.g., generator–solver, proposer–verifier) where training can oscillate or drift toward undesirable behaviours. We study this scenario through the lens of reverse‑KL regularised Nash learning, showing how the regularisation strength $\\beta$ shapes both where agents converge and how they get there. We derive a continuous‑time view of Nash Mirror Descent (Nash‑MD), revealing a simple geometry: trajectories are spirals on the simplex whose damping grows with $\\beta$, while $\\beta$ simultaneously pulls equilibria toward the reference policy—amplifying any existing biases. We prove last‑iterate convergence to the $\\beta$‑regularised Nash equilibrium, quantify its first‑order shift from the unregularised solution, and link convergence speed to the spectrum of the linearised dynamics. Building on this geometry, we introduce two adaptive $\\beta$ controllers: (i) a Hessian‑based rule that targets a desired damping–rotation ratio to accelerate without overshoot, and (ii) a bias‑based rule that caps measurable bias (e.g., output length, calibration, hallucination proxies) while retaining speed. On toy games (e.g. Rock–Paper–Scissors) and small open‑model reasoning benchmarks, our controllers deliver faster, more stable convergence with bounded bias, outperforming baselines. The result is a practical recipe: tune $\\beta$ as a control knob to make self‑improving LLM agents both faster and safer.","published":"2025-09-20T10:18:04+00:00","updated":"2026-02-11T10:19:57+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=KN2RD4fpnH","openreview_url":"https://openreview.net/forum?id=KN2RD4fpnH","pdf_url":"https://openreview.net/pdf?id=KN2RD4fpnH","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:3x4SDbXbgl","versioned_id":"3x4SDbXbgl","title":"Computer Agent Arena: Toward Human-Centric Evaluation and Analysis of Computer-Use Agents","authors":["Bowen Wang","Xinyuan Wang","Jiaqi Deng","Tianbao Xie","Ryan Li","Yanzhe Zhang","Junli Wang","Dunjie Lu","Zicheng Gong","Gavin Li","Toh Jing Hua","Wei-Lin Chiang","Ion Stoica","Diyi Yang","Yu Su","Yi Zhang","Zhiguo Wang","Victor Zhong","Tao Yu"],"abstract":"As Computer-Use Agents (CUAs) proliferate and grow increasingly capable, evaluation has become more challenging: static, manually curated benchmarks are narrow in domain, contamination-prone, and environment-heavy, and they diverge substantially from user-driven, real-world evaluation. We present Computer Agent Arena, an open-source platform for head-to-head CUA evaluation and a dynamic methodology that converts human preferences into structured feedback in realistic environments. The system (i) simulates real-world computer use via cloud-hosted, diverse, and dynamic environment initializations and customizations; (ii) ensures authentic, fair comparison by faithfully reproducing open-source CUAs and executing anonymously in matched, controlled environments; and (iii) extends evaluation beyond pairwise preference and correctness to capability- and behavior-oriented signals. Across 2,201 high-quality votes over 12 agents—spanning multi-app interactions, ambiguous instructions, and open-ended queries—we observe striking ranking reversals relative to static benchmarks. Further analysis shows that overall correctness mainly drives human preference; beyond that, agent-human interaction and self-correction boost user preference, even when overall task completion is comparable. Our error analysis reveals agent behavior errors, such as long-horizon memory and fine-grained action failures that static benchmarks fail to evaluate. We also contrast pure GUI agents with universal digital agents capable of tool use and coding, and discuss the trade-offs of these different design philosophies. We open source the full platform, collected dataset, and code of Computer Agent Arena to support future research on the evaluation and development of CUA.","published":"2025-09-20T09:26:25+00:00","updated":"2026-04-11T03:16:19+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=3x4SDbXbgl","openreview_url":"https://openreview.net/forum?id=3x4SDbXbgl","pdf_url":"https://openreview.net/pdf?id=3x4SDbXbgl","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:oj6A9hrNdL","versioned_id":"oj6A9hrNdL","title":"ResearcherBench: Evaluating Deep AI Research Systems on the Frontiers of AI Research","authors":["Tianze Xu","Pengrui Lu","Lyumanshan Ye","Xiangkun Hu","Pengfei Liu"],"abstract":"The emergence of deep research systems presents significant capabilities in problem-solving, extending from basic queries to sophisticated research tasks. However, existing benchmarks primarily evaluate these systems on web retrieval and report generation abilities, overlooking their potential for discovering, intergrating and generating insights in AI research. To address this gap, we introduce ResearcherBench, the first benchmark focused on evaluating the capabilities of these advanced, agentic systems — which we refer to as Deep AI Research Systems (DARS) — on frontier AI research questions. We curated a dataset of 65 research questions expertly selected from real-world AI research scenarios such as laboratory discussions and interviews, spanning 35 different AI subjects and categorized into three types: technical details, literature review, and open consulting. Our dual evaluation framework combines rubric assessment, which uses expert-designed criteria to evaluate insight quality, with factual assessment, which measures citation accuracy (faithfulness) and coverage (groundedness). We evaluated several leading commercial DARS and baseline systems. Our evaluation results reveal the strengths and limitations of these systems, with particular strength in open-ended consulting questions compared to technical implementation tasks. Such capabilities demonstrate the potential for DARS to serve as genuine AI research partners, representing a meaningful step toward AI self-improvement. We open-source ResearcherBench to provide a standardized platform for promoting the development of next-generation AI research assistants, hoping to foster a new perspective in AI research evaluation for scientific collaboration.","published":"2025-09-20T09:05:42+00:00","updated":"2026-02-11T10:19:53+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=oj6A9hrNdL","openreview_url":"https://openreview.net/forum?id=oj6A9hrNdL","pdf_url":"https://openreview.net/pdf?id=oj6A9hrNdL","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:WzLjwv8KAn","versioned_id":"WzLjwv8KAn","title":"Which Cultural Lens Do Models Adopt? On Cultural Positioning Bias and Agentic Mitigation in LLMs","authors":["Yixin Wan","Xingrun Chen","Kai-Wei Chang"],"abstract":"Large language models (LLMs) have unlocked a wide range of downstream generative applications. However, we found that they also risk perpetuating subtle fairness issues tied to culture, positioning their generations from the perspectives of the mainstream US culture while demonstrating salient externality towards non-mainstream ones. In this work, we identify and systematically investigate this novel **culture positioning bias**, in which an LLM’s default generative stance aligns with a mainstream view and treats other cultures as \"outsiders\". We propose the ***CultureLens*** benchmark with 4,000 generation prompts and 3 evaluation metrics for quantifying this bias through the lens of a *culturally situated interview script generation* task, in which an LLM is positioned as an on-site reporter interviewing local people across 10 diverse cultures. Empirical evaluation on 5 state-of-the-art LLMs reveals a stark pattern: while models adopt insider tones in over 88\\% US-contexted scripts on average, they disproportionately adopt mainly outsider stances for less dominant cultures. To resolve these biases, we propose *2 inference-time mitigation methods*: a baseline prompt-based **Fairness Intervention Pillars (FIP)** method, and a structured **Mitigation via Fairness Agents (MFA)** framework consisting of 2 pipelines: (1) **MFA-SA (Single-Agent)** introduces a self-reflection and rewriting loop based on fairness guidelines. (2) **MFA-MA (Multi-Agent)** structures the process into a hierarchy of specialized agents: a Planner Agent(initial script generation), a Critique Agent (evaluates initial script against fairness pillars), and a Refinement Agent (incorporates feedback to produce a polished, unbiased script). Empirical results demonstrate that agent-based MFA methods achieve outstanding and robust performance in mitigating the culture positioning bias: For instance, on the CAG metric, *MFA-SA reduces bias in Llama model by 89.70 \\% and MFA-MA mitigates bias in Qwen by 82.55\\%*. These findings showcase the effectiveness of agent-based methods as a promising direction for mitigating biases in generative LLMs.","published":"2025-09-20T07:05:18+00:00","updated":"2025-11-12T10:25:17+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=WzLjwv8KAn","openreview_url":"https://openreview.net/forum?id=WzLjwv8KAn","pdf_url":"https://openreview.net/pdf?id=WzLjwv8KAn","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:bQgaTaN2eG","versioned_id":"bQgaTaN2eG","title":"REDEREF: RECURSIVE DELEGATION AND REFLECTION FOR MULTI-TURN LLM AGENT COLLABORATION WITH DYNAMIC CAPABILITY DISCOVERY","authors":["Ankit Shah","Mohammad Parsa Hosseini","Saiyra Qureshi","Alex Huang","Connie Miao","Wei Wei"],"abstract":"Large language models (LLMs) achieve strong single-turn performance, yet real-world deployments demand multi-turn, multi-agent coordination with dynamic routing, reliable credit assignment, and long-horizon memory. We introduce , a lightweight, training-free framework that wraps arbitrary LLM agents with four synergistic components: (i) online Bayesian delegation (Thompson sampling) for dynamic routing; (ii) calibrated self-reflection via an LLM judge to drive credit assignment and recursive re-routing; (iii) text-appropriate aggregation using selection with evidence checks; and (iv) memory-aware belief updates for long-term adaptation. Across domain-diverse, split-knowledge tasks, attains higher success rates than static non-collaborative baselines, with ablations indicating that the recursive re-routing loop contributes the majority of gains on initially failed tasks while online Bayesian updates improve routing efficiency. These results suggest that an interpretable, probabilistic wrapper can substantially enhance multi-agent LLM coordination—enabling dynamic task routing, emergent specialization, and long-term adaptability with minimal overhead.","published":"2025-09-20T05:38:29+00:00","updated":"2026-02-12T14:51:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=bQgaTaN2eG","openreview_url":"https://openreview.net/forum?id=bQgaTaN2eG","pdf_url":"https://openreview.net/pdf?id=bQgaTaN2eG","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:rWzdEvakRi","versioned_id":"rWzdEvakRi","title":"Learning Randomized Reductions","authors":["Ferhat Erata","Orr Paradise","Thanos Typaldos","Timos Antonopoulos","ThanhVu Nguyen","Shafi Goldwasser","Ruzica Piskac"],"abstract":"A self-corrector for a function $f$ takes a black-box oracle computing $f$ that is correct on most inputs and turns it into one that is correct on every input with high probability. Self-correctors exist for any function that is randomly self-reducible (RSR), where the value $f$ at a given point $x$ can be recovered by computing $f$ on random correlated points. While RSRs enable powerful self-correction capabilities and have applications in complexity theory and cryptography, their discovery has traditionally required manual derivation by experts. We present Bitween, a method and tool for automated learning of randomized self-reductions for mathematical functions. We make two key contributions: First, we demonstrate that our learning framework based on linear regression outperforms sophisticated methods including genetic algorithms, symbolic regression, and mixed-integer linear programming for discovering RSRs from correlated samples. Second, we introduce Agentic Bitween, a neuro-symbolic approach where large language models dynamically discover novel query functions for RSR property discovery, leveraging vanilla Bitween as a tool for inference and verification, moving beyond the fixed query functions ($x+r$, $x-r$, $x \\cdot r$, $x$, $r$) previously used in the literature. On RSR-Bench, our benchmark suite of 80 scientific and machine learning functions, vanilla Bitween surpasses existing symbolic methods, while Agentic Bitween discovers new RSR properties using frontier models to uncover query functions.","published":"2025-09-20T03:24:05+00:00","updated":"2026-02-12T14:51:25+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=rWzdEvakRi","openreview_url":"https://openreview.net/forum?id=rWzdEvakRi","pdf_url":"https://openreview.net/pdf?id=rWzdEvakRi","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:LKGflZgEKB","versioned_id":"LKGflZgEKB","title":"ExperiGen: Data Driven Hypothesis Generation with Experimental Verification","authors":["Jishu Sen Gupta","Syed Mohamad Tawseeq","Harini S I","Somesh Kumar Singh","Yaman Kumar Singla","David Doermann","Rajiv Ratn Shah","Balaji Krishnamurthy"],"abstract":"Automating the scientific method of generating hypotheses has the potential to accelerate discovery across disciplines, especially in data-driven sciences such as psychology and behavioral research. At its core, the scientific method is a cycle of observation, hypothesis generation, and experimental validation. In doing so, however, we observe a fundamental dichotomy in existing methods: generation approaches propose hypotheses without experimental validation, while validation approaches are limited to structured tabular settings reducing the scope and impact of both. To address this gap, we introduce ExperiGen, a collaborative agentic framework that couples a Generator, which proposes natural language hypotheses, with an Experimenter, which programmatically constructs features, executes statistical tests, and returns evidence for iterative refinement. This coupling enables the discovery of hypotheses that are not only experimentally verified but also more predictive, while also addressing the bottleneck of relying solely on LLM in-context reasoning. As a result, ExperiGen extends hypothesis discovery beyond text to visual domains, including tasks such as image memorability and layout design preference (e.g., “designs with clear visual hierarchy are more aesthetic”). We evaluate on existing benchmarks for hypothesis generation achieving 5-8\\% absolute gains over existing methods, while also producing substantially more statistically significant hypotheses. Finally, we conduct a large-scale industrial A/B test on a Fortune 500 company’s webpage, making ExperiGen the first method where AI-generated hypotheses yielded statistically significant improvements in a real-world field setting.","published":"2025-09-20T00:24:12+00:00","updated":"2026-02-12T14:51:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=LKGflZgEKB","openreview_url":"https://openreview.net/forum?id=LKGflZgEKB","pdf_url":"https://openreview.net/pdf?id=LKGflZgEKB","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:vXrOyzt0Ea","versioned_id":"vXrOyzt0Ea","title":"TrajTune: Trajectory-Based Prompt Optimization for LLM Agents","authors":["Bing Zhang","Shubhi Asthana","Hima Patel","Chad DeLuca"],"abstract":"Large Language Model (LLM) agents are increasingly deployed in complex tasks involving multi-step reasoning and dynamic API interactions. However, these agents often fail due to issues like hallucinated tool calls or repetitive actions, which are not effectively addressed by current prompt optimization methods that focus primarily on textual output quality. We present TrajTune, a trajectory-aware prompt optimization framework designed to enhance the reliability and adaptability of LLM agents. TrajTune captures structured execution traces, computes fine-grained error metrics, and compares them against adaptive thresholds. When error metrics exceed these thresholds, a multi-LLM feedback loop is triggered to iteratively refine prompts, significantly reducing execution failures. Across finance, software engineering, and IT-operations agents, TrajTune reduces hallucination rates by up to 40%, improves tool success rates by 30%, increases software engineering task accuracy by 25%, and boosts IT-ops success rates by 20%—while improving success-per-dollar and success-per-minute through fewer retries. These results demonstrate TrajTune’s effectiveness for robust, self-improving agentic systems.","published":"2025-09-19T22:23:21+00:00","updated":"2026-02-11T10:19:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vXrOyzt0Ea","openreview_url":"https://openreview.net/forum?id=vXrOyzt0Ea","pdf_url":"https://openreview.net/pdf?id=vXrOyzt0Ea","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:lifeoGrKRB","versioned_id":"lifeoGrKRB","title":"AGENT*: Optimizing Test-Time Compute for Multi-Agent Systems with Modularized Collaboration","authors":["Dongwon Jung","Peng Shi","Yi Zhang"],"abstract":"Scaling test-time computation has emerged as a powerful and increasingly popular approach for improving the performance of large language models without additional training. Recent work demonstrates that techniques such as repeated sampling, self-verification, and self-reflection can significantly enhance task success by allocating more inference-time compute. However, applying these techniques directly to multi-agent systems is challenging, as they provide no principled way to encourage collaboration or manage compute allocation across multiple agents under budget constraints. To address this, we propose AGENT*, a general framework for enabling effective multi-agent collaboration while operating within strict compute budgets. AGENT* introduces the notion of \\emph{modularized collaboration}, formalized as callable functions that encapsulate reusable multi-agent workflows, automatically constructed via self-play reflection by abstracting recurring interaction patterns from past trajectories. Building on these collaboration modules, AGENT* proposes \\emph{a dual-level planning architecture} that optimizes compute allocation by reasoning over the current task state while also \\emph{speculating} on future steps. Experiments on complex agent benchmarks demonstrate that AGENT* consistently outperforms baselines across diverse budget settings, validating its effectiveness for multi-agent collaboration in inference-time optimization.","published":"2025-09-19T20:44:59+00:00","updated":"2026-02-11T10:18:57+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=lifeoGrKRB","openreview_url":"https://openreview.net/forum?id=lifeoGrKRB","pdf_url":"https://openreview.net/pdf?id=lifeoGrKRB","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:lE2UP2pZ1g","versioned_id":"lE2UP2pZ1g","title":"Reflective Causal Agents","authors":["Abi Aryan","Zac Yung-Chun Liu","Aaron Childress"],"abstract":"We present the first empirical evaluation of Causal Reflection, a framework that equips agents with causal reasoning, structured self-correction, and explainable decision-making in dynamic environments. Standard reinforcement learning and large language model agents often fail under non-stationary conditions, relying on spurious correlations rather than robust causal models. Building on the theoretical foundations of Causal Reflection which formalizes causality as a temporal function and introduces a Reflect mechanism for hypothesis-driven model revision. We implement Reflective Causal Agents. Across a dynamic benchmark environment, these agents outperform ablated and associative baselines in adaptability, predictive accuracy, causal graph recovery, and hypothesis generation. Our results establish Causal Reflection as a practical approach toward robust, interpretable, and generalizable AI systems.","published":"2025-09-19T18:55:49+00:00","updated":"2025-09-25T13:19:55+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=lE2UP2pZ1g","openreview_url":"https://openreview.net/forum?id=lE2UP2pZ1g","pdf_url":"https://openreview.net/pdf?id=lE2UP2pZ1g","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:PxMUtBylKr","versioned_id":"PxMUtBylKr","title":"Strategic Self-Improvement for Competitive Agents in AI Labour Markets","authors":["Christopher Chiu","Simpson Zhang","Mihaela van der Schaar"],"abstract":"As artificial intelligence (AI) agents are deployed across economic domains, understanding their strategic behavior and market-level impact becomes critical. We investigate the dynamics of an AI labor market through a simulated gig economy where agents controlled by fixed policies or Large Language Models (LLMs) compete for jobs, develop skills, and adapt their strategies under competitive pressure. Our analysis identifies three core capabilities that successful LLM-agents develop organically: \\textbf{metacognition} (accurate self-assessment of skills), \\textbf{competitive awareness} (modeling rivals and market dynamics), and \\textbf{long-horizon strategic planning}. Moreover, we show that LLM agents explicitly prompted with these reasoning capabilities learn to strategically self-improve and demonstrate superior adaptability to changing market conditions. At the market level, our simulation reproduces classic macroeconomic phenomena found in human labor markets, while controlled experiments reveal potential AI-driven economic trends, such as rapid monopolization and systemic price deflation. This work provides a foundation to further explore the economic properties of AI-driven labour markets, and a conceptual framework to study the strategic reasoning capabilities in agents competing in the emerging economy.","published":"2025-09-19T17:01:26+00:00","updated":"2026-02-11T10:18:35+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=PxMUtBylKr","openreview_url":"https://openreview.net/forum?id=PxMUtBylKr","pdf_url":"https://openreview.net/pdf?id=PxMUtBylKr","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:c3mE9mXDLn","versioned_id":"c3mE9mXDLn","title":"Self-Directed Discovery: How LLMs Explore and Optimize Configurable LLM Solutions","authors":["Georgiana Dinu","Anthony Colas","Shaunak Mishra","Atul Kamat","Karan Panjabi","Amjad Abu Jbara"],"abstract":"LLM solutions are increasingly replacing specialized machine learning models across various industry domains. While offering simplicity and maintainability advantages, optimizing these workflows remains heavily dependent on expert-driven experimentation. In this paper we test off-the-shelf powerful LLMs for the task of automatically building and iteratively improving LLM-based solutions. We propose a configuration-driven framework which defines such workflows by specifying model parameters, prompt templates, and data transformations. We show that this standardized representation enables automatic iterative improvement loops via optimization agents which are themselves defined within the same framework. When evaluated on challenging datasets, it discovers improved solutions while maintaining interpretability and human verifiability. The improvement loop we instantiate is generic and minimal (using prompts that have not been engineered) and self-referential (improved solutions are discovered with improved documentation and examples). The proposal is a self-improving system that bridges the gap between generic code-generating automatic optimization and more narrowly-focused techniques such as prompt engineering.","published":"2025-09-19T15:48:22+00:00","updated":"2026-02-12T14:51:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=c3mE9mXDLn","openreview_url":"https://openreview.net/forum?id=c3mE9mXDLn","pdf_url":"https://openreview.net/pdf?id=c3mE9mXDLn","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:X5e2x8JSJP","versioned_id":"X5e2x8JSJP","title":"Structure Guided Equation Discovery with Influence-Based Feedback for Large Language Models","authors":["Evgeny Saveliev","Samuel Holt","Nabeel Seedat","David L. Bentley","Jim Weatherall","Mihaela van der Schaar"],"abstract":"Large Language Models (LLMs) hold significant promise for scientific discovery, particularly in identifying interpretable, closed-form equations from complex data. However, existing LLM-driven approaches often rely on coarse, scalar feedback (e.g., overall Mean Squared Error), limiting the LLM's ability to discern the individual contributions of components within a proposed equation. This forces the LLM to rely heavily on its priors or engage in inefficient trial-and-error exploration. We introduce *Structure Guided Equation Discovery* (SGED), a novel framework where LLMs act as dual agents in an iterative symbolic modeling pipeline. An LLM agent first proposes candidate basis functions $\\psi_j(x)$ for a linear symbolic model $f(x) = \\sum_j w_j \\psi_j(x)$. A second LLM agent then refines this set of terms, critically guided by detailed, per-term \\textit{influence scores} $\\Delta_j$ and fitted weights $w_j$. These scores quantify each basis function's contribution to predictive accuracy, providing the crucial granular feedback needed for effective model refinement. SGED can operate as a direct iterative refinement loop or be integrated into Monte Carlo Tree Search (MCTS) for a more comprehensive exploration of the equation space. We demonstrate that providing LLMs with this structured, influence-based feedback improves the accuracy of discovered equations and the efficiency of the discovery process on diverse biological and synthetic datasets. SGED highlights the broader principle that equipping LLMs with detailed, interpretable feedback about sub-components of their generative output can unlock more sophisticated reasoning and self-improvement capabilities.","published":"2025-09-19T15:36:29+00:00","updated":"2026-02-12T14:51:41+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=X5e2x8JSJP","openreview_url":"https://openreview.net/forum?id=X5e2x8JSJP","pdf_url":"https://openreview.net/pdf?id=X5e2x8JSJP","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"openreview:LHysuZBJSu","versioned_id":"LHysuZBJSu","title":"Mac-Tiger: Multi-Agent Cooperation for Enhanced Text-to-Image Generation","authors":["Yucong Luo","Mingyue Cheng"],"abstract":"Recent advancements in text-to-image (T2I) generation have significantly improved image fidelity and alignment with textual prompts, yet challenges remain in addressing complex compositional requirements, such as attribute binding, spatial relationships, and numerical precision. To tackle these issues, this paper introduces Mac-Tiger, a novel multi-agent cooperative framework that leverages multimodal large language models (MLLMs) to optimize T2I generation through iterative refinement. Unlike traditional single-agent approaches, Mac-Tiger employs a tri-agent system—comprising Reviewer, Challenger, and Refiner roles—that collaboratively evaluates and refines prompts based on dynamically generated feedback and multimodal analysis. Key innovations include integrating advanced modules for perception, memory, and cooperative planning to facilitate adaptive prompt optimization. Experiments on benchmarks like T2I-CompBench and MagicBrush demonstrate Mac-Tiger’s superior performance in generating semantically consistent and visually coherent images, particularly in scenarios involving intricate object interactions and detailed edits. This work underscores the potential of multi-agent systems to address long-standing limitations in T2I generation, paving the way for more robust and context-aware generative models.","published":"2025-09-19T13:56:59+00:00","updated":"2026-02-11T10:18:09+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=LHysuZBJSu","openreview_url":"https://openreview.net/forum?id=LHysuZBJSu","pdf_url":"https://openreview.net/pdf?id=LHysuZBJSu","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:JH1mMoGtyl","versioned_id":"JH1mMoGtyl","title":"LLM-Guided Communication for Cooperative Multi-Agent Reinforcement Learning","authors":["Seungyul Han","Sangjun Bae","Yisak Park","Sanghyeon Lee"],"abstract":"Communication can be essential in cooperative multi-agent reinforcement learning (MARL), where agents may need to overcome partial observability by exchanging information to accomplish tasks. However, prior methods often rely on messages that are uninterpretable or contain redundant information. To overcome this issue, we propose LLM-driven Multi-Agent Communication (LMAC), a novel MARL framework that combines LLM-based communication protocol design with a meta-cognitive latent representation module. LMAC employs iterative refinement with phase-specific feedback to produce interpretable protocols that enhance state recovery and shared understanding, while its latent module incorporates reliability signals with cycle consistency to ensure compact and trustworthy representations. Experiments across diverse MARL benchmarks demonstrate that LMAC consistently improves performance over other communication baselines.","published":"2025-09-19T13:20:37+00:00","updated":"2025-11-20T12:36:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=JH1mMoGtyl","openreview_url":"https://openreview.net/forum?id=JH1mMoGtyl","pdf_url":"https://openreview.net/pdf?id=JH1mMoGtyl","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:sWQSbVsPEz","versioned_id":"sWQSbVsPEz","title":"R4: Nested Reasoning-Retrieval for Reward Modeling in Role-Playing Agents","authors":["Renzhi Wang","Chongqiang Wei","Zhisheng Wang","Piji Li"],"abstract":"Role-playing dialogue presents unique challenges for large language models (LLMs): beyond producing coherent text, models must sustain character persona, integrate contextual knowledge, and convey emotional nuance. Despite strong reasoning abilities, current LLMs often generate dialogue that is literal, stylistically bland, and misaligned with character-specific traits. Existing approaches such as retrieval-augmented generation (RAG) or reinforcement learning (RL) with scalar rewards are insufficient, as they cannot capture nuanced preferences or adapt reliably to diverse character contexts. In this work, we introduce R4, a unified framework that equips both the reward model and the role-playing agent with reasoning and retrieval capabilities. Our reward model reformulates evaluation as structured reasoning: it integrates multi-step deliberation and retrieved knowledge to assess responses along multiple dimensions. This reward supervision is then used within reinforcement learning to train a dialogue agent with the same dual capabilities, enabling contextually grounded and persona-consistent generation. Experiments demonstrate that R4 substantially improves dialogue quality, particularly in persona fidelity, narrative coherence, and emotional expressiveness. Analysis of training dynamics and case studies further shows that R4 agents employ retrieval more effectively, engage in retrieval-informed self-reflection, and achieve emergent role-playing behaviors unattainable by prior methods.","published":"2025-09-19T09:42:09+00:00","updated":"2026-04-11T03:14:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=sWQSbVsPEz","openreview_url":"https://openreview.net/forum?id=sWQSbVsPEz","pdf_url":"https://openreview.net/pdf?id=sWQSbVsPEz","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:nElqyHPHAz","versioned_id":"nElqyHPHAz","title":"MLE-RL: Reinforcement Learning for Self-Improvement in Machine Learning Agents","authors":["Yujiang Li","Zhenyu Hou","Xiaohan Jia","Zihan Luo","Zhilei Bei","Rui Lu","Hong Huang","Jie Tang","Yuxiao Dong"],"abstract":"Language models have shown significant promise in complex reasoning and coding tasks. However, coding for machine learning engineering presents unique challenges due to the iterative nature of development, long execution times, and the need for continuous self-improvement. In this paper, we introduce MLE-RL trained with reinforcement learning to address these challenges. Our approach reframes the learning process by breaking down long-horizon trajectories into single-step optimizations. We employ a reinforcement learning strategy that selectively learns from the most informative attempts, optimizing the policy on valuable steps. In addition, to overcome context limitations, our agent uses a scaffold with a memory module to store and recall high-performing past solutions, facilitating cumulative learning. The evaluation on the MLE-Bench demonstrates that our MLE-RL-32B achieves 4.9% improvement over the baseline model in the competition ranking on ML tasks and achieves competitive performance against state-of-the-art open-source models like DeepSeek-R1-0528. MLE-RL is open-sourced at https://anonymous.4open.science/r/MLE-RL-CC61","published":"2025-09-19T09:39:35+00:00","updated":"2026-02-11T10:17:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=nElqyHPHAz","openreview_url":"https://openreview.net/forum?id=nElqyHPHAz","pdf_url":"https://openreview.net/pdf?id=nElqyHPHAz","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:T0EiEuhOOL","versioned_id":"T0EiEuhOOL","title":"Huxley-G\\\"odel Machine: Human-Level Coding Agent Development by an Approximation of the Optimal Self-Improving Machine","authors":["Wenyi Wang","Piotr Piękos","Li Nanbo","Firas Laakom","Yimeng Chen","Mateusz Ostaszewski","Mingchen Zhuge","Jürgen Schmidhuber"],"abstract":"Recent studies operationalize self-improvement through coding agents that edit their own codebases. They grow a tree of self-modifications through expansion strategies that favor higher software engineering benchmark performance, assuming that this implies more promising subsequent self-modifications. However, we identify a mismatch between the agent’s self-improvement potential (metaproductivity) and its coding benchmark performance, namely the Metaproductivity-Performance~Mismatch. Inspired by Huxley’s concept of clade, we propose a metric ($\\mathrm{CMP}$) that aggregates the benchmark performances of the descendants of an agent as an indicator of its potential for self-improvement. We show that, in our self-improving coding agent development setting, access to the true CMP is sufficient to simulate how the Gödel Machine would behave under certain assumptions. We introduce the Huxley-G\\\"odel Machine (HGM), which, by estimating $\\mathrm{CMP}$ and using it as guidance, searches the tree of self-modifications. On SWE-bench Verified and Polyglot, HGM outperforms prior self-improving coding agent development methods while using fewer allocated CPU hours. Last but not least, HGM demonstrates strong transfer to other coding datasets and LLMs. %large language models. The agent optimized by HGM on SWE-bench Verified with GPT-5 mini and evaluated on SWE-bench Lite with GPT-5 achieves human-level performance, matching the best officially checked results of human-engineered coding agents. Our code is publicly available at https://github.com/metauto-ai/HGM.","published":"2025-09-19T09:13:05+00:00","updated":"2026-04-11T03:14:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=T0EiEuhOOL","openreview_url":"https://openreview.net/forum?id=T0EiEuhOOL","pdf_url":"https://openreview.net/pdf?id=T0EiEuhOOL","comment":"ICLR 2026 Oral","journal_ref":"ICLR 2026 Oral","doi":"","venue":"ICLR 2026 Oral","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:U7n8gZGyAu","versioned_id":"U7n8gZGyAu","title":"JoyAgents-R1: Accelerating Multi-Agent Evolution Dynamics with Variance-Reduction Group Relative Policy Optimization","authors":["Ai Han","Junxing Hu","Pu Wei","Zhiqian Zhang","Yuhang Guo","Jiawei Lu","Zhen Chen","Zicheng Zhang"],"abstract":"Large Language Model (LLM)-based multi-agent systems represent a promising paradigm with broad applicability, exemplified by general-purpose Artificial Intelligence (AI) assistants capable of performing multiple tasks. Nevertheless, joint optimization across functionally distinct agents remains challenging due to divergent working modes and reward functions. To address this issue, we introduce JoyAgents-R1, a framework that accelerates multi-agent evolution with a novel Variance-Reduction Group Relative Policy Optimization (VR-GRPO), integrating efficient sampling and update strategies. Specifically, VR-GRPO performs Monte Carlo sampling based on an initial reasoning trajectory to avoid the exponential explosion of the joint action space while maintaining policy diversity. Then, the method selects the top-$K$ sampling groups with maximal reward fluctuations based on the marginal benefit principle, thereby enabling cost-effective parameter updates. To further complement evolution, an adaptive memory evolution mechanism that repurposes GRPO rewards as cost-free supervisory signals is designed to eliminate repetitive reasoning and accelerate convergence. Experiments on multi-task AI assistant datasets across both general and e-commerce scenarios demonstrate that JoyAgents-R1, built upon smaller 3B/7B open-source models, achieves performance comparable to that of larger LLMs, such as DeepSeek-R1, and surpasses DeepSeek-V3 by an average of 6\\%.","published":"2025-09-19T07:27:36+00:00","updated":"2026-01-06T14:31:23+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=U7n8gZGyAu","openreview_url":"https://openreview.net/forum?id=U7n8gZGyAu","pdf_url":"https://openreview.net/pdf?id=U7n8gZGyAu","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:K9GxQKEJzS","versioned_id":"K9GxQKEJzS","title":"Bootstrapping Language and Numerical Feedback for Reinforcement Learning in LLMs","authors":["Ang Li","Yifei Wang","Zhihang Yuan","Stefanie Jegelka","Yisen Wang"],"abstract":"Reinforcement learning for large language models (LLMs) often relies on scalar rewards, a practice that discards valuable textual rationale buried in the rollouts and hampers training efficiency. Naive attempts to incorporate language feedback are often counterproductive, risking either memorization from leaked solutions or policy collapse from irrelevant context. To address this, we propose Language-And-Numerical Policy Optimization (LANPO), a framework that cleanly separates the roles of feedback: language guides exploration, while numerical rewards drive optimization. LANPO builds a dynamic experience pool from past trials and introduces two principles to ensure feedback is effective: Reward-Agnostic Reflection for safe intra-sample self-correction and Relevant Abstraction to distill generalizable lessons from inter-sample experiences. Across mathematical reasoning benchmarks, LANPO enables 7B and 14B models to significantly outperform strong baselines trained with GRPO in test accuracy. Our work provides a robust method for integrating historical experiences into the LLM RL loop, creating more effective and data-efficient learning agents.","published":"2025-09-19T04:25:42+00:00","updated":"2026-02-11T10:17:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=K9GxQKEJzS","openreview_url":"https://openreview.net/forum?id=K9GxQKEJzS","pdf_url":"https://openreview.net/pdf?id=K9GxQKEJzS","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:iVeqLVyWO8","versioned_id":"iVeqLVyWO8","title":"One Model to Critique Them All: Rewarding Agentic Tool-Use via Efficient Reasoning","authors":["Renhao Li","Jianhong Tu","Yang Su","Hamid Alinejad-Rokny","Derek F. Wong","Junyang Lin","Min Yang"],"abstract":"Reward models (RMs) play a critical role in aligning large language models (LLMs) with human preferences. Yet in the domain of tool learning, the lack of RMs specifically designed for function-calling tasks has limited progress toward more capable agentic AI. We introduce **ToolRM**, a family of lightweight generative RMs tailored for general tool-use scenarios. To build these models, we propose a novel pipeline that constructs pairwise preference data using rule-based scoring and multidimensional sampling. This yields *ToolPref-Pairwise-30K*, a diverse, balanced, and challenging dataset of critique tasks that supports reinforcement learning with verifiable feedback. To evaluate tool-use RMs, we also introduce TRBench$_\\text{BFCL}$, a benchmark built on the agentic evaluation suite BFCL. Trained on our constructed data, models from the Qwen3-4B/8B series achieve up to 14.28\\% higher accuracy, substantially outperforming frontier models such as Claude 4 and OpenAI o3 in pairwise reward judgments. Beyond training objectives, ToolRM generalizes to broader critique tasks, including Best-of-N sampling and self-correction. Experiments on ACEBench highlight its effectiveness and efficiency, enabling inference-time scaling and reducing output token usage by over 66\\%. We release data and model checkpoints to facilitate future research.","published":"2025-09-19T04:22:48+00:00","updated":"2025-12-02T10:40:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=iVeqLVyWO8","openreview_url":"https://openreview.net/forum?id=iVeqLVyWO8","pdf_url":"https://openreview.net/pdf?id=iVeqLVyWO8","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:PVarNsrX2v","versioned_id":"PVarNsrX2v","title":"Red Teaming Program Repair Agents: When Correct Patches can Hide Vulnerabilities","authors":["Simin Chen","Yixin He","Suman Jana","Baishakhi Ray"],"abstract":"LLM-based agents are increasingly deployed for software maintenance tasks such as automated program repair (APR). APR agents automatically fetch GitHub issues and use backend LLMs to generate patches that fix the reported bugs. However, existing work primarily focuses on the functional correctness of APR-generated patches—whether they pass hidden or regression tests—while largely ignoring potential security risks. Given the openness of platforms like GitHub, where any user can raise issues and participate in discussions, an important question arises: Can an adversarial user submit a valid issue on GitHub that misleads an LLM-based agent into generating a functionally correct but vulnerable patch? To answer this question, we propose SWExploit, which generates adversarial issue statements designed to make APR agents produce patches that are functionally correct yet vulnerable. SWExploit operates in three main steps: (1) Program analysis to identify potential injection points for vulnerable payloads. (2) Adversarial issue generation to provide misleading reproduction and error information while preserving the original issue semantics. (3) Iterative refinement of the adversarial issue statements based on the outputs of the APR agents. Empirical evaluation on three agent pipelines and five backend LLMs shows that SWExploit can produce patches that are both functionally correct and vulnerable (the attack success rate on the correct patch could reach 0.91, whereas the baseline ASRs are all below 0.20). Based on our evaluation, we are the first to challenge the traditional assumption that a patch passing all tests is inherently reliable and secure, highlighting critical limitations in the current evaluation paradigm for APR agents. Our code is available at GitHub","published":"2025-09-19T04:11:05+00:00","updated":"2026-02-12T14:51:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=PVarNsrX2v","openreview_url":"https://openreview.net/forum?id=PVarNsrX2v","pdf_url":"https://openreview.net/pdf?id=PVarNsrX2v","comment":"ICLR 2026 Conference Desk Rejected Submission","journal_ref":"ICLR 2026 Conference Desk Rejected Submission","doi":"","venue":"ICLR 2026 Conference Desk Rejected Submission","venue_id":"ICLR.cc/2026/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:ywXgFYs44d","versioned_id":"ywXgFYs44d","title":"Opponent Simulation as Inference-time Scaling for Self-improving Agent: Case Study of Repeated Negotiations","authors":["Xiangyu Liu","Di Wang","Zhe Feng","Aranyak Mehta"],"abstract":"Large language models (LLMs) have recently emerged as powerful decision-makers across a wide range of reasoning-intensive tasks. While prior work has made great progress in single-agent environments, less effort has been devoted to settings where LLMs must engage in \\emph{repeated} and \\emph{strategic} interactions without prior knowledge about the opponents. In such settings, traditional self-play or offline training, though robust against worst-case adversaries, do not fully leverage the flexibility of LLMs to continually self-improve based on interaction feedback. To address this, we introduce a general inference-time framework called best-of-$N$ sampling with opponent simulation (\\ours), with a case study in repeated negotiation games. The framework scales inference-time computation by embedding the principles of a classical game-theoretical learning dynamic, \\emph{fictitious play (FP)}, into practical LLM implementations: (i) for the belief formation step, we introduce a separate LLM as an opponent model that in-context learns to imitate the \\emph{time-averaged} behavior of the opponent from past interactions; (ii) for the best response step, we perform BoN by simulating future outcomes using the opponent model, where candidates are generated through a structured strategic brainstorming process. Empirical evaluations on two repeated negotiation games, the buyer-seller negotiation and the resource exchange negotiation, demonstrate that our method achieves significant self-improvement over repeated interaction compared with various baselines, offering a lightweight and scalable approach to strategic reasoning and decision-making.","published":"2025-09-19T01:38:17+00:00","updated":"2026-02-11T10:17:05+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ywXgFYs44d","openreview_url":"https://openreview.net/forum?id=ywXgFYs44d","pdf_url":"https://openreview.net/pdf?id=ywXgFYs44d","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:WJOgneFtVi","versioned_id":"WJOgneFtVi","title":"DS-STAR: Data Science Agent via Iterative Planning and Verification","authors":["Jaehyun Nam","Jinsung Yoon","Jiefeng Chen","Tomas Pfister"],"abstract":"Data science, which transforms raw data into actionable insights, is critical for data-driven decision-making. However, these tasks are often complex, involving steps for exploring multiple data sources and synthesizing findings to deliver insightful answers. While large language models (LLMs) show significant promise in automating this process, they often struggle with heterogeneous data formats and generate sub-optimal analysis plans, as verifying plan sufficiency is inherently difficult without ground-truth labels for such open-ended tasks. To overcome these limitations, we introduce DS-STAR, a novel data science agent. Specifically, DS-STAR makes three key contributions: (1) a data file analysis module that automatically explores and extracts context from diverse data formats, including unstructured types; (2) a verification step where an LLM-based judge evaluates the sufficiency of the analysis plan at each stage; and (3) a sequential planning mechanism that starts with a simple, executable plan and iteratively refines it based on the DS-STAR's feedback until its sufficiency is verified. This iterative refinement allows DS-STAR to reliably navigate complex analyses involving diverse data sources. Our experiments show that DS-STAR achieves state-of-the-art performance across three challenging benchmarks: DABStep, KramaBench, and DA-Code. Moreover, DS-STAR particularly outperforms baselines on hard tasks that require processing multiple data files with heterogeneous formats.","published":"2025-09-19T00:46:07+00:00","updated":"2026-02-11T10:17:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=WJOgneFtVi","openreview_url":"https://openreview.net/forum?id=WJOgneFtVi","pdf_url":"https://openreview.net/pdf?id=WJOgneFtVi","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:sfrVLzsmlf","versioned_id":"sfrVLzsmlf","title":"AMemGym: Interactive Memory Benchmarking for Assistants in Long-Horizon Conversations","authors":["Cheng Jiayang","Dongyu Ru","Lin Qiu","Yiyang Li","Xuezhi Cao","Yangqiu Song","Xunliang Cai"],"abstract":"Long-horizon interactions between users and LLM-based assistants necessitate effective memory management, yet current approaches face challenges in training and evaluation of memory. Existing memory benchmarks rely on static, off-policy data as context, limiting evaluation reliability and scalability. To address these gaps, we introduce AMemGym, an interactive environment enabling on-policy evaluation and optimization for memory-driven personalization. AMemGym employs structured data sampling to predefine user profiles, state-dependent questions, and state evolution trajectories, enabling cost-effective generation of high-quality, evaluation-aligned interactions. LLM-simulated users expose latent states through role-play while maintaining structured state consistency. Comprehensive metrics based on structured data guide both assessment and optimization of assistants. Extensive experiments reveal performance gaps in existing memory systems (e.g., RAG, long-context LLMs, and agentic memory) and corresponding reasons. AMemGym not only enables effective selection among competing approaches but also can potentially drive the self-evolution of memory management strategies. By bridging structured state evolution with free-form interactions, our framework provides a scalable, diagnostically rich environment for advancing memory capabilities in conversational agents.","published":"2025-09-18T22:23:33+00:00","updated":"2026-05-17T06:06:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=sfrVLzsmlf","openreview_url":"https://openreview.net/forum?id=sfrVLzsmlf","pdf_url":"https://openreview.net/pdf?id=sfrVLzsmlf","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:OJf6hePdN7","versioned_id":"OJf6hePdN7","title":"Evolutionary Multi-Agent Reinforcement Learning for Crisis-Aware Demographic Policy Optimization","authors":["Anton V. Dozhdikov","Arseniy Sitkovskiy","Tamara Rostovskaya"],"abstract":"Demographic systems face unprecedented challenges from simultaneous crises. Conventional statistical demography techniques and agent-based models often struggle to capture nonlinear inter-regional interactions during periods of severe socio-economic disruption. To address this, we propose MADDPG-EVO-DGM, a hybrid algorithm that integrates multi-agent deep reinforcement learning with evolutionary optimization and meta-learning principles to model regional demographic processes under multiple crisis scenarios. Each region is treated as an autonomous agent learning to steer demographic policy levers, while periodic evolutionary “boosters” overcome local optima via population-based perturbations of actor network parameters. Additionally, a Darwin–Gödel Machine-inspired meta-learning mechanism adapts the booster triggers, enabling self-improvement in the learning process. We evaluate MADDPG-EVO-DGM on a simulation environment calibrated with real demographic data for eight federal regions of the Russian Federation over the period 2000–2025 and subject to ten concurrent crisis scenarios (e.g., pandemic, geopolitical conflict, economic collapse). Experiments demonstrate significantly faster convergence and improved performance over a baseline MADDPG: the hybrid approach achieves a higher final average reward (252.57 vs 243.07) and $3.4\\times$ lower convergence variance ($\\sigma=0.24$ vs $0.80$), indicating more reliable training. It also exhibits qualitative performance jumps of $+68\\%$ during evolutionary phases and maintains 35–45\\% greater resilience under crisis shocks compared to the baseline. To our knowledge, this is the first application of multi-agent reinforcement learning to large-scale demographic modeling under crises, opening new possibilities for evidence-based, crisis-resilient population policy design. Code, data and logs are provided to ensure reproducibility.","published":"2025-09-18T19:24:58+00:00","updated":"2026-02-11T10:16:45+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=OJf6hePdN7","openreview_url":"https://openreview.net/forum?id=OJf6hePdN7","pdf_url":"https://openreview.net/pdf?id=OJf6hePdN7","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:zGxAx4WFHO","versioned_id":"zGxAx4WFHO","title":"AutoQG: An Automated Framework for Evidence-Traceable Question Generation via Ontology-Guided Knowledge Graph Construction","authors":["Xiaoli Shen","Guilin Qi","Peng Zhang","Dingsheng Yang","Yang Yang","Muyan Yang","Li Fangyanhao","HaoWen Guo","HuiKang Hu","Jiazhen Kang","Yan Wang","Yuchen Lu","Zheyu Xin","Jun Wang"],"abstract":"Large Language Models (LLMs) present unprecedented opportunities for generating scientific questions. However, existing approaches face two key limitations: heavy reliance on costly human annotations and the production of brittle, unverifiable outputs. To address these challenges, we propose AutoQG, a fully automated multi-agent framework for evidence-grounded scientific QA generation. AutoQG comprises three complementary agents: (i) KG Extraction Agent, which performs ontology-guided knowledge graph construction with section-aware prompts for precise information retrieval; (ii) KG Evaluation Agent, a multi-dimensional evaluation module with iterative refinement to ensure accuracy and consistency; and (iii) QA Generation Agent, which produces schema-constrained QA pairs grounded in reasoning paths and explicit textual evidence. Applied to over 4,000 scientific papers, AutoQG constructs 243k triples and introduces AutoQG-20k, a benchmark containing more than 20,000 QA pairs. Each pair is explicitly linked to its reasoning chains and supporting evidence, ensuring transparency and verifiability. We further release AutoQG-7k, a challenging subset designed with hard questions that strong LLMs struggle to answer. Extensive experiments demonstrate that AutoQG consistently outperforms strong baselines in both human evaluation and LLM-as-a-Judge assessments. By transforming LLM output into a controlled and auditable pipeline, AutoQG advances evidence-based AI for the understanding of reliable scientific knowledge. Source code will be released upon publication.","published":"2025-09-18T18:31:38+00:00","updated":"2026-02-05T12:12:58+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=zGxAx4WFHO","openreview_url":"https://openreview.net/forum?id=zGxAx4WFHO","pdf_url":"https://openreview.net/pdf?id=zGxAx4WFHO","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:s00SNXREV6","versioned_id":"s00SNXREV6","title":"Vision-Zero: Scalable VLM Self-Evolution via Multi-Agent Self-Play","authors":["Qinsi Wang","Bo Liu","Tianyi Zhou","Jing Shi","Yueqian Lin","Yiran Chen","Hai Helen Li","Kun Wan","Wentian Zhao"],"abstract":"Although reinforcement learning (RL) can effectively enhance the reasoning capabilities of vision–language models (VLMs), current methods remain heavily dependent on labor-intensive datasets that require extensive manual construction and verification, leading to extremely high training costs and consequently constraining the practical deployment of VLMs. To address this challenge, we propose **Vision-Zero**, *a domain-agnostic self-play framework that generates visual deduction games from diverse images for scalable VLM training without human annotations.* Specifically, Vision-Zero encompasses three main attributes: (1) **Strategic Self-Play Framework:** Vision-Zero trains VLMs in \"Who Is the Spy\"-style games, where the models engage in strategic reasoning and actions across multiple roles. Through interactive gameplay, models autonomously generate their training data without human annotation. (2) **Gameplay from Arbitrary Images:** Unlike existing gamified frameworks, Vision-Zero can generate games from arbitrary images, thereby enhancing the model’s reasoning ability across diverse domains and showing strong generalization to different tasks. We demonstrate this versatility using three distinct types of image datasets: CLEVR-based synthetic scenes, charts, and real-world images. (3) **Sustainable Performance Gain:** We introduce Iterative Self-Play Policy Optimization (Iterative-SPO), a novel training algorithm that alternates between Self-Play and reinforcement learning with verifiable rewards (RLVR), mitigating the performance plateau often seen in self-play-only training and achieving sustained long-term improvements. Despite using label-free data, Vision-Zero achieves state-of-the-art performance on reasoning, chart question answering, and vision-centric understanding tasks, surpassing other annotation-based methods. Models and code will be released upon acceptance.","published":"2025-09-18T18:21:17+00:00","updated":"2026-04-11T03:12:38+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=s00SNXREV6","openreview_url":"https://openreview.net/forum?id=s00SNXREV6","pdf_url":"https://openreview.net/pdf?id=s00SNXREV6","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2509.15172","versioned_id":"2509.15172v3","title":"Self-Improvement of Language Models by Post-Training on Multi-Agent Debate","authors":["Ankur Samanta","Akshayaa Magesh","Runzhe Wu","Ayush Jain","Youliang Yu","Daniel Jiang","Boris Vidolov","Paul Sajda","Yonathan Efroni","Kaveh Hassani"],"abstract":"Self-improvement, where models improve beyond their current performance without external supervision, remains a challenge. The core difficulty is sourcing a training signal stronger than what the model itself can currently produce. Majority voting has been shown to provide such a signal by aggregating over multiple samples, helping mitigate some of the inconsistencies in LM reasoning. In this work, we show that multi-agent debate--where models collaborate and exchange reasoning over multiple rounds--provides an even richer signal than single-round majority voting. We introduce Multi-Agent Consensus Alignment (MACA), which uses reinforcement learning (RL) to post-train models to effectively utilize multi-agent debate. We find that preference learning over full reasoning traces, learning to differentiate between majority and minority reasoning, is more effective than binary consensus rewards or SFT-based approaches for leveraging these debate signals. This produces three key improvements: models are (1) better at utilizing the multi-agent debate setting (+26.87% on MATH), (2) individually more accurate (+21.51% on MathQA), and (3) more self-consistent (+27.6% on GSM8K). We also see strong generalization to unseen benchmarks (+16.3% on GPQA, +11.6% on CommonsenseQA).","published":"2025-09-18T17:27:28Z","updated":"2026-01-29T23:55:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.15172v3","pdf_url":"https://arxiv.org/pdf/2509.15172v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=fDOlevu70z","openreview_venues":["MALGAI"]},{"id":"openreview:z7KTJgA9Ue","versioned_id":"z7KTJgA9Ue","title":"ThermoRL: Structure-Aware RL for Protein Mutation Design to Enhance Thermostability","authors":["Xiangwen Wang","Ronghui Mu","Gaojie Jin","Xiaowei Huang"],"abstract":"Designing mutations to optimize protein thermostability remains challenging due to the complex relationship between sequence variations, structural dynamics, and thermostability, often assessed by $\\Delta\\Delta G$ (the change in free energy of unfolding). Existing methods rely on experimental random mutagenesis or one-shot predictions over fixed mutation libraries, which limits design space exploration and lacks iterative refinement capabilities. We present \\textbf{ThermoRL}, a reinforcement learning (RL) framework that integrates graph neural networks (GNN) with hierarchical Q-learning to sequentially design thermostabilizing mutations. ThermoRL combines a pre-trained GNN-based encoder with a hierarchical Q-learning network and employs a surrogate model for reward feedback, to guide the agent in selecting both mutation positions and amino acid substitutions. Experimental results show that ThermoRL achieves higher or comparable rewards than baselines while maintaining computational efficiency. It effectively avoids destabilizing mutations, recovers experimentally validated stabilizing variants, and generalizes to unseen proteins by identifying context-dependent mutation sites. These results highlight ThermoRL as a scalable, structure-informed framework for adaptive and transferable protein design.","published":"2025-09-18T17:15:45+00:00","updated":"2025-11-12T13:42:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=z7KTJgA9Ue","openreview_url":"https://openreview.net/forum?id=z7KTJgA9Ue","pdf_url":"https://openreview.net/pdf?id=z7KTJgA9Ue","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2509.15160","versioned_id":"2509.15160v1","title":"An Evaluation-Centric Paradigm for Scientific Visualization Agents","authors":["Kuangshi Ai","Haichao Miao","Zhimin Li","Chaoli Wang","Shusen Liu"],"abstract":"Recent advances in multi-modal large language models (MLLMs) have enabled increasingly sophisticated autonomous visualization agents capable of translating user intentions into data visualizations. However, measuring progress and comparing different agents remains challenging, particularly in scientific visualization (SciVis), due to the absence of comprehensive, large-scale benchmarks for evaluating real-world capabilities. This position paper examines the various types of evaluation required for SciVis agents, outlines the associated challenges, provides a simple proof-of-concept evaluation example, and discusses how evaluation benchmarks can facilitate agent self-improvement. We advocate for a broader collaboration to develop a SciVis agentic evaluation benchmark that would not only assess existing capabilities but also drive innovation and stimulate future development in the field.","published":"2025-09-18T17:08:23Z","updated":"2025-09-18T17:08:23Z","categories":["cs.HC","cs.CL","cs.GR"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2509.15160v1","pdf_url":"https://arxiv.org/pdf/2509.15160v1","comment":"","journal_ref":"1st Workshop on GenAI, Agents, and the Future of VIS (IEEE VIS Conference 2025)","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:UvQOcw2oCD","versioned_id":"UvQOcw2oCD","title":"Unified Diffusion VLA: Vision-Language-Action Model via Joint Discrete Denosing Diffusion Process","authors":["Jiayi Chen","Wenxuan Song","Pengxiang Ding","Ziyang Zhou","Han Zhao","Feilong Tang","Donglin Wang","Haoang Li"],"abstract":"Vision-language-action (VLA) models aim to understand natural language instructions and visual observations and execute corresponding actions as an embodied agent. Recent advancements have integrated future images into the understanding-action loop, enabling foresight-driven policies that reduce abstract action prediction to a more tractable inverse kinematics problem. However, existing models either rely on external experts for modality unification or treat image generation and action prediction as separate processes, limiting the benefits of direct synergy between these tasks. In this work, we propose Unified Diffusion VLAs, which tightly couple understanding, generation, and action in a mutually reinforcing manner. Our method optimizes the generation of actions and images jointly through a synchronous denoising diffusion process, where action tokens progressively attend to future image tokens. This iterative refinement enables actions to evolve from initialization with sufficient visual guidance, ensuring precise action execution. We introduce a hybrid attention mechanism and the Joint Discrete Denoising Diffusion Process (JD3P), which integrates multiple modalities into a unified trajectory. We also propose a two-stage training pipeline and several inference-time techniques that optimize performance and efficiency. Our approach achieves state-of-the-art performance on benchmarks such as CALVIN, LIBERO, and SimplerEnv, and we demonstrate its effectiveness through ablation studies and real-world evaluations.","published":"2025-09-18T15:49:15+00:00","updated":"2026-04-11T03:12:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=UvQOcw2oCD","openreview_url":"https://openreview.net/forum?id=UvQOcw2oCD","pdf_url":"https://openreview.net/pdf?id=UvQOcw2oCD","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:pUpzQZTvGY","versioned_id":"pUpzQZTvGY","title":"Darwin Gödel Machine: Open-Ended Evolution of Self-Improving Agents","authors":["Jenny Zhang","Shengran Hu","Cong Lu","Robert Tjarko Lange","Jeff Clune"],"abstract":"Most of today's AI systems are constrained by human-designed, fixed architectures and cannot autonomously and continuously improve themselves. The scientific method, on the other hand, is a cumulative and open-ended system, where each innovation builds upon previous artifacts, enabling future discoveries. There is growing hope that the current manual process of advancing AI could itself be automated. If done safely, such automation would accelerate AI development and allow us to reap its benefits much sooner. This prospect raises the question of how AI systems can endlessly improve themselves while getting better at solving relevant problems. Meta-learning can automate the discovery of novel algorithms, but is limited by first-order improvements and the human design of a suitable search space. The Gödel machine proposed a theoretical alternative: a self-improving AI that repeatedly modifies itself in a provably beneficial manner. Unfortunately, proving that most changes are net beneficial is impossible in practice. We introduce the Darwin Gödel Machine (DGM), a novel self-improving system that iteratively modifies its own code (thereby also improving its ability to modify its own codebase) and empirically validates each change using coding benchmarks. Inspired by Darwinian evolution and open-endedness research, the DGM grows an archive of generated coding agents. It samples agents from this archive, which self-modify to create new, interesting versions of themselves. This open-ended exploration forms a growing tree of diverse, high-quality agents and allows the parallel exploration of many different paths through the search space. Empirically, the DGM automatically improves its coding capabilities (e.g., better code editing tools, long-context window management, peer-review mechanisms), increasing performance on SWE-bench from 20.0% to 50.0%, and on Polyglot from 14.2% to 30.7%. Furthermore, the DGM significantly outperforms baselines without self-improvement or open-ended exploration. All experiments were done with safety precautions (e.g., sandboxing, human oversight). Overall, the DGM represents a significant step toward self-improving AI, capable of gathering its own stepping stones along a path that unfolds into endless innovation.","published":"2025-09-18T15:14:33+00:00","updated":"2026-04-11T03:12:00+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=pUpzQZTvGY","openreview_url":"https://openreview.net/forum?id=pUpzQZTvGY","pdf_url":"https://openreview.net/pdf?id=pUpzQZTvGY","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:GofFHwumFW","versioned_id":"GofFHwumFW","title":"Unary Feedback as Observation: Incentivizing Self-Reflection in Large Language Models via Multi-Turn RL","authors":["Licheng Liu","Zihan Wang","Linjie Li","Chenwei Xu","Yiping Lu","Han Liu","Avirup Sil","Manling Li"],"abstract":"Large Language Models (LLMs) are increasingly deployed as agents that solve problems through multi-turn interaction, receiving feedback and refining their reasoning based on users' feedback. However, existing reinforcement learning with verifiable reward (RLVR) methods train them under a single-turn paradigm. As a result, we discovered that models often **fail to explore alternative reasoning paths or reflect on prior mistakes, producing repetitive and unadapted responses to feedback.** To address this gap, we propose Unary Feedback as Observation (UFO), a framework that conditions policy updates on minimal unary feedback (e.g., “Let’s try again”) after incorrect answers. UFO is simple, compatible with existing single-turn RL setups, and incentivizes self-reflection. To further promote efficient and adaptive reasoning, we design reward structures that encourage _minimality_ (solving in fewer turns) and _diversity_ (exploring alternatives under failure). Experiments show that UFO preserves single-turn performance while improving multi-turn reasoning accuracy by about 14%. Crucially, UFO-trained models also **generalize beyond their training domain, transferring effectively to out-of-domain tasks** across mathematics, STEM, QA, and general knowledge, showing that **UFO teaches models self-reflective reasoning that carry over across domains**. Beyond these empirical gains, UFO points toward a broader paradigm for building adaptive reasoning agents: one that scales supervision from static datasets, reduces dependence on costly domain-specific feedback, and lays the foundation for more general, self-improving AI systems in open-ended real-world settings.","published":"2025-09-18T14:39:32+00:00","updated":"2026-02-11T10:16:15+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=GofFHwumFW","openreview_url":"https://openreview.net/forum?id=GofFHwumFW","pdf_url":"https://openreview.net/pdf?id=GofFHwumFW","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"openreview:5zFHFfrfmz","versioned_id":"5zFHFfrfmz","title":"Review, Revise, and Learn: Peer-Guided Preference Learning via LLM Self-Correction","authors":["Minsang Kim","Seung Jun Baek"],"abstract":"Preference optimization plays a central role in achieving state-of-the-art performance in large language models (LLMs). However, preference learning requires large-scale, high-quality, or human-annotated datasets, which poses a significant challenge to the continual improvement of LLMs. We introduce PULSE (Peer-gUided Preference Learning via LLM SElf-correction), a collaborative framework of multiple LLM agents for scalable preference learning. PULSE is inspired by the academic peer-review process: an actor LLM first generates an initial response to a query, and critic peer LLMs evaluate and provide feedback on the response. The actor revises or corrects its response based on this feedback, and the critics finally assign scores to the revised response. The scores of the initial and revised outputs are used as preference scores to construct preference data. This process enables autonomous and collective reasoning of LLMs for constructing preference data without human supervision. However, preference data constructed by LLMs may be subject to noise or reward hacking. To mitigate the issue, we first provide a unified view on robust preference learning through the lens of risk minimization, and then propose a framework for robust training on self-correction datasets. Experiments show that PULSE significantly outperforms existing approaches, achieving performance gains up to 47.3\\% and 34.6\\% on Alpaca LC and Alpaca 2.0, and 23.9\\%, 102.8\\%, and 12.4\\% on a collection of math, coding, and general reasoning tasks, demonstrating its potential to create and sustain scalable LLM ecosystems.","published":"2025-09-18T13:34:42+00:00","updated":"2026-01-26T17:48:21+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=5zFHFfrfmz","openreview_url":"https://openreview.net/forum?id=5zFHFfrfmz","pdf_url":"https://openreview.net/pdf?id=5zFHFfrfmz","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:4f4gzyD2Av","versioned_id":"4f4gzyD2Av","title":"RE-Searcher: Robust Agentic Search via Goal-oriented Planning and Self-reflection","authors":["Daocheng Fu","Jianbiao Mei","Licheng Wen","Xuemeng Yang","Cheng Yang","Rong Wu","Tao Hu","Siqi Li","Yufan Shen","Xinyu Cai","Pinlong Cai","Botian Shi","Yong Liu","Yu Qiao"],"abstract":"Large language models (LLMs) excel at knowledge-intensive question answering and reasoning, yet their real-world deployment remains constrained by knowledge cutoff, hallucination, and limited interaction modalities. Augmenting LLMs with external search tools helps alleviate these issues, but it also exposes agents to a complex search environment in which small, plausible variations in query formulation can steer reasoning into unproductive trajectories and amplify errors. We present a systematic analysis that quantifies how environmental complexity induces fragile search behaviors and, in turn, degrades overall performance. To address this challenge, we propose a simple yet effective approach to instantiate a search agent, RE-Searcher. During search, RE-Searcher explicitly articulates a concrete search goal and subsequently reflects on whether the retrieved evidence satisfies that goal. This combination of goal-oriented planning and self-reflection enables RE-Searcher to resist spurious cues in complex search environments and perform robust search. Extensive experiments show that our method improves search accuracy and achieves state-of-the-art results. Perturbation studies further demonstrate substantial resilience to noisy or misleading external signals, mitigating the fragility of the search process. We believe these findings offer practical guidance for integrating LLM-powered agents into more complex interactive environments and enabling more autonomous decision-making.","published":"2025-09-18T11:20:36+00:00","updated":"2026-02-11T10:15:57+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4f4gzyD2Av","openreview_url":"https://openreview.net/forum?id=4f4gzyD2Av","pdf_url":"https://openreview.net/pdf?id=4f4gzyD2Av","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:WSkU78RTGC","versioned_id":"WSkU78RTGC","title":"EvoAgent: Self-evolving Agent with Continual World Model for Long-Horizon Tasks","authors":["Tongtong Feng","Xin Wang","Zekai Zhou","Ren Wang","Yu-Wei Zhan","Guangyao Li","Qing Li","Wenwu Zhu"],"abstract":"Completing Long-Horizon (LH) tasks in open-ended worlds is an important yet difficult problem for embodied agents. Existing approaches suffer from two key challenges: (1) they heavily rely on experiences obtained from human-created data or curricula, failing to autonomously update and select multimodal experiences, and (2) they may encounter catastrophic forgetting issues when faced with new tasks, failing to autonomously update world knowledge. To solve these challenges, this paper presents EvoAgent, a self-evolving agent with a continual World Model (WM), which can autonomously complete various LH tasks across environments through self-planning, self-control, and self-reflection, without human intervention. Our proposed EvoAgent contains three modules, i.e., i) the memory-driven planner which uses an LLM along with the WM and interaction memory, to convert LH tasks into executable sub-tasks; ii) the WM-guided action controller which leverages WM to generate low-level actions and incorporates a self-verification mechanism to update multimodal experiences; iii) the experience-inspired reflector which implements a two-stage curriculum learning algorithm to select experiences for task-adaptive WM updates. Moreover, we develop a continual World Model for EvoAgent, which can autonomously update the multimodal experience pool and world knowledge through closed-loop dynamics. We conducted extensive experiments on Minecraft and Atari, compared with existing methods, EvoAgent can achieve an average success rate improvement of 111% and reduce ineffective actions by more than 6x.","published":"2025-09-18T01:50:40+00:00","updated":"2026-02-11T10:15:39+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=WSkU78RTGC","openreview_url":"https://openreview.net/forum?id=WSkU78RTGC","pdf_url":"https://openreview.net/pdf?id=WSkU78RTGC","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:QVjyFrXOrn","versioned_id":"QVjyFrXOrn","title":"MoSEL: Modular Self-Reflective Learning for Embodied Decision-Making","authors":["Jr-Jen Chen","Yu-Chiang Frank Wang","Yilun Du"],"abstract":"Enabling robots to autonomously perform complex, long-horizon tasks remains challenging due to the need for hierarchical reasoning and dynamic adaptability. Humans overcome this by interacting with environment and learning from their own experience, which is infeasible for existing robots without human supervision. To enable similar capabilities in robotic agents, we introduce MoSEL, an modular self-reflective learning framework for robotic decision making. MoSEL combines hierarchical planning with multimodal foundation models, including LVLMs, video diffusion, and inverse dynamics models. These components work together to break down complex tasks, generate executable visual plans, and perform actions. We further introduce a modular self-reflective learning framework that autonomously identifies failures and iteratively refines policies with minimal human intervention. Evaluations on LIBERO-LONG and RoboTwin benchmarks demonstrate that MoSEL outperforms existing methods, achieving over $33\\%$ and $46\\%$ average performance improvements, respectively. Our results underscore the effectiveness of autonomous self-improvement and accurate failure identification in advancing robust robotic manipulation.","published":"2025-09-17T16:10:04+00:00","updated":"2026-02-11T10:15:29+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=QVjyFrXOrn","openreview_url":"https://openreview.net/forum?id=QVjyFrXOrn","pdf_url":"https://openreview.net/pdf?id=QVjyFrXOrn","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:1caMYRbkKx","versioned_id":"1caMYRbkKx","title":"Skill Weaving: Efficient Self-Improvement of LLMs via Modular Skillpacks","authors":["Zhuo Li","Guodong DU","Yequan Wang","Min Zhang","Jing Li"],"abstract":"We propose SkillWeaving, a modular self-improvement framework that enables large language models (LLMs) to specialize using only their own generations. The key idea is to decompose general-purpose LLMs into a collection of skillpacks—lightweight, domain-specific delta modules—that reorganize and refine the model’s internal knowledge. By combining rule-based verification with preference optimization, each skillpack learns high-quality self-refined capability from a specific domain, achieving robust improvement without external labels. To further ensure scalable deployment, we introduce SkillZip, a fully quantized delta-compression method that jointly quantizes weights and activations, eliminating runtime decompression and enabling fast, low-cost inference. By merging shared knowledge and hardware-aware technical designs, our method achieves both parameter-efficient specialization and inference-efficient execution. On multi-task and agentic benchmarks, Skill Weaving outperforms expert-tuned baselines and even surpasses larger 32B monolithic models using only 9B parameters, while offering up to 4× speedup. Overall, our approach offers an interpretable and resource-efficient path toward LLM self-improvement.","published":"2025-09-17T10:00:06+00:00","updated":"2025-12-31T08:50:58+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=1caMYRbkKx","openreview_url":"https://openreview.net/forum?id=1caMYRbkKx","pdf_url":"https://openreview.net/pdf?id=1caMYRbkKx","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:UMN77tJZdK","versioned_id":"UMN77tJZdK","title":"GraphPlan: Graph-enhanced Planning via Thinking LLMs for Embodied Agents","authors":["Chen Li","Sijie Cheng","Yuelin Zhang","Junxi LI","Yang Liu","Wenbing Huang"],"abstract":"Embodied agents that follow instructions to complete complex tasks in visual environments have attracted increasing attention. Large Language Models (LLMs) based planners, notwithstanding the progress achieved, still suffer from three main limitations: (i) a lack of physical grounding, often resulting in hallucinatory plans; (ii) poor generalization to unseen long-horizon tasks; and (iii) an absence of environmental awareness in the open-loop planning process. To address these issues, we propose GraphPlan, a novel framework that integrates a task graph to provide structured knowledge for robust planning and a scene graph to maintain environmental memory for event-driven replanning. Specifically, the task graph guides the LLM's reasoning through contextual prompting and iterative refinement, effectively mitigating planning hallucinations. Furthermore, within the GRPO framework, the task graph offers delicate reward design to train LLMs' reasoning, enhancing long-horizon planning capabilities and improving generalization. Finally, the memory constructed by a dynamic scene graph empowers an event-driven replanning module, enabling the agent to foster environment awareness and correct instruction misalignment within a closed-loop planning process. On the standard benchmark ALFRED, GraphPlan achieves state-of-the-art performance on the official leaderboard. Moreover, its high-level planner outperforms a series of leading API-based LLMs on both the validation set and unseen long-horizon tasks. Additional experiments reveal the promising potential of our graph-enhanced framework in few-shot or zero-shot learning scenarios, and its generalization to novel tasks beyond the benchmark.","published":"2025-09-17T07:53:39+00:00","updated":"2026-02-11T10:15:17+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=UMN77tJZdK","openreview_url":"https://openreview.net/forum?id=UMN77tJZdK","pdf_url":"https://openreview.net/pdf?id=UMN77tJZdK","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:aSr8eoe2vz","versioned_id":"aSr8eoe2vz","title":"CATArena: Evaluation of LLM Agents Through Iterative Tournament Competitions","authors":["Lingyue Fu","Xin Ding","Yaoming Zhu","Shao Zhang","Lin Qiu","Weiwen Liu","Weinan Zhang","Xuezhi Cao","Xunliang Cai","Jiaxin Ding","Yong Yu"],"abstract":"Large Language Model (LLM) agents have evolved from basic text generation to autonomously completing complex tasks through interaction with external tools. However, current benchmarks mainly assess end-to-end performance in fixed scenarios, restricting evaluation to specific skills and suffering from score saturation and growing dependence on expert annotation as agent capabilities improve. In this work, we emphasize the importance of learning ability, including both self-improvement and peer-learning, as a core driver for agent evolution toward human-level intelligence. We propose an iterative, competitive peer-learning framework, which allows agents to refine and optimize their strategies through repeated interactions and feedback, thereby systematically evaluating their learning capabilities. To address the score saturation issue in current benchmarks, we introduce CATArena, a tournament-style evaluation platform featuring four diverse board and card games with open-ended scoring. By providing tasks without explicit upper score limits, CATArena enables continuous and dynamic evaluation of rapidly advancing agent capabilities. Experimental results and analyses involving both minimal and commercial code agents demonstrate that CATArena provides reliable, stable, and scalable benchmarking for core agent abilities, particularly learning ability and strategy coding.","published":"2025-09-17T07:18:37+00:00","updated":"2026-02-11T10:15:16+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=aSr8eoe2vz","openreview_url":"https://openreview.net/forum?id=aSr8eoe2vz","pdf_url":"https://openreview.net/pdf?id=aSr8eoe2vz","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2509.13761","versioned_id":"2509.13761v3","title":"THOR: Tool-Integrated Hierarchical Optimization via RL for Mathematical Reasoning","authors":["Qikai Chang","Zhenrong Zhang","Pengfei Hu","Jun Du","Jiefeng Ma","Yicheng Pan","Jianshu Zhang","Quan Liu","Jianqing Gao"],"abstract":"Large Language Models (LLMs) have made remarkable progress in mathematical reasoning, but still continue to struggle with high-precision tasks like numerical computation and formal symbolic manipulation. Integrating external tools has emerged as a promising approach to bridge this gap. Despite recent advances, existing methods struggle with three key challenges: constructing tool-integrated reasoning data, performing fine-grained optimization, and enhancing inference. To overcome these limitations, we propose THOR (Tool-Integrated Hierarchical Optimization via RL). First, we introduce TIRGen, a multi-agent based pipeline for constructing high-quality datasets of tool-integrated reasoning paths, aligning with the policy and generalizing well across diverse models. Second, to perform fine-grained hierarchical optimization, we introduce an RL strategy that jointly optimizes for both episode-level problem solving and step-level code generation. This is motivated by our key insight that the success of an intermediate tool call is a strong predictor of the final answer's correctness. Finally, THOR incorporates a self-correction mechanism that leverages immediate tool feedback to dynamically revise erroneous reasoning paths during inference. Our approach demonstrates strong generalization across diverse models, performing effectively in both reasoning and non-reasoning models. It further achieves state-of-the-art performance for models of a similar scale on multiple mathematical benchmarks, while also delivering consistent improvements on code benchmarks. Our code will be publicly available at https://github.com/JingMog/THOR.","published":"2025-09-17T07:16:12Z","updated":"2026-02-10T08:25:24Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.13761v3","pdf_url":"https://arxiv.org/pdf/2509.13761v3","comment":"22 pages, 13 figures, ICLR 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0Af7UiJISU","openreview_venues":["ICLR 2026 Poster"]},{"id":"openreview:zkCZDdeS9s","versioned_id":"zkCZDdeS9s","title":"Dancing in Chains: Strategic Persuasion in Academic Rebuttal via Theory of Mind","authors":["Zhitao He","Zongwei LYU","Yi R. Fung"],"abstract":"Although artificial intelligence (AI) has become deeply integrated into various stages of the research workflow and achieved remarkable advancements, academic rebuttal remains a significant and underexplored challenge. This is because rebuttal is a complex process of strategic communication under severe information asymmetry rather than a simple technical debate. Consequently, current approaches struggle as they largely imitate surface-level linguistics, missing the essential element of perspective-taking required for effective persuasion. In this paper, we introduce RebuttalAgent, the first framework to ground academic rebuttal in Theory of Mind (ToM), operationalized through a ToM-Strategy-Response (TSR) framework that models reviewer mental state, formulates persuasion strategy, and generates evidence-based response. To train our agent, we construct RebuttalBench, a large-scale dataset synthesized via a novel critique-and-refine approach. Our training process consists of two stages, beginning with a supervised fine-tuning phase to equip the agent with ToM-based analysis and strategic planning capabilities, followed by a reinforcement learning phase leveraging the self-reward mechanism for scalable self-improvement. For reliable and efficient automated evaluation, we further develop Rebuttal-RM, a specialized evaluator trained on over 100K samples of multi-source rebuttal data, which achieves scoring consistency with human preferences surpassing powerful judge GPT-4.1. Extensive experiments show RebuttalAgent significantly outperforms the base model by an average of 18.3% on automated metrics, while also outperforming advanced proprietary models across both automated and human evaluations.","published":"2025-09-17T06:58:41+00:00","updated":"2026-04-11T03:10:31+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=zkCZDdeS9s","openreview_url":"https://openreview.net/forum?id=zkCZDdeS9s","pdf_url":"https://openreview.net/pdf?id=zkCZDdeS9s","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:EURAfiUpVJ","versioned_id":"EURAfiUpVJ","title":"MARS-SQL: A Multi-Agent Reinforcement Learning Framework for Text-to-SQL","authors":["Haolin Yang","Jipeng Zhang","Zhitao He","Yi R. Fung"],"abstract":"Translating natural language to SQL remains a significant challenge for complex queries requiring environmental interaction and self-correction. To address this, we introduce MARS-SQL, a novel multi-agent framework that combines principled task decomposition and interactive reinforcement learning (RL). Our system comprises three specialized agents: a Grounding Agent for schema linking, a Generation Agent for query generation, and a Validation Agent for final selection. The core of our framework is the Generator agent, which is trained via a multi-turn RL policy. Adopting a ReAct-style Think-Act-Observe loop, the agent iteratively generates thoughts, executes SQL actions against a live database, and revises its strategy based on execution feedback, enabling dynamic, stateful reasoning and self-correction. At inference time, we generate multiple interaction trajectories to explore diverse reasoning paths. The Verifier agent, then selects the optimal trajectory by modeling verification as a next-token prediction task and choosing the solution with the highest generation probability. This structured workflow, which pipelines specialized agents and combines interactive RL for generation with generative modeling for verification, proves highly effective for robust and accurate SQL generation. Experiments show that **MARS-SQL** achieves state-of-the-art Execution Accuracy of 77.84\\% on the BIRD dev set and 89.75\\% on the Spider test set.","published":"2025-09-16T16:10:28+00:00","updated":"2026-02-11T10:15:03+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=EURAfiUpVJ","openreview_url":"https://openreview.net/forum?id=EURAfiUpVJ","pdf_url":"https://openreview.net/pdf?id=EURAfiUpVJ","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:BsA2GNkJhz","versioned_id":"BsA2GNkJhz","title":"CellAgent: LLM-Driven Multi-Agent Framework for Natural Language-Based Single-Cell Analysis","authors":["Yihang Xiao","Jinyi Liu","YAN ZHENG","Shaoqing Jiao","Jianye HAO","Xiaohan Xie","Limingzhi","Ruitao Wang","Fei Ni","Yuxiao Li","Zhen Wang","Xuequn Shang","Zhijie Bao","Changxiao Yang","Jiajie Peng"],"abstract":"Single-cell RNA sequencing (scRNA-seq) and spatial transcriptomics (ST) data analysis are pivotal for advancing biological research, enabling precise characterization of cellular heterogeneity. However, existing analysis approaches require extensive manual programming and complex tool integration, posing significant challenges for researchers. To address this, we introduce CellAgent, an autonomous, LLM-driven approach that performs end-to-end scRNA-seq and spatial transcriptomics data analysis through natural language interactions. CellAgent employs a multi-agent hierarchical decision-making framework, simulating a “deep-thinking” workflow to ensure that analytical steps are logically coherent and aligned with the overarching research goal. To further enhance its capabilities, we develop sc-Omni, a high-performance, expert-curated toolkit that consolidates essential tools for scRNA-seq and spatial transcriptomics analysis. Additionally, we introduce a self-reflective optimization mechanism, enabling automated, iterative refinement of results through specialized evaluation methods, effectively replacing traditional manual assessments. Benchmarking against human experts demonstrates that CellAgent achieves significant improvement in efficiency across multiple downstream applications while maintaining excellent performance comparable to existing approaches and preserving natural language interactions. By translating high-level scientific questions into optimized computational workflows, CellAgent represents a step toward a new, more accessible paradigm in bioinformatics, allowing researchers to perform complex data analyses autonomously. In lowering technical barriers, CellAgent serves to advance the democratization of the scientific discovery process in genomics.","published":"2025-09-16T13:47:10+00:00","updated":"2026-04-11T03:10:07+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=BsA2GNkJhz","openreview_url":"https://openreview.net/forum?id=BsA2GNkJhz","pdf_url":"https://openreview.net/pdf?id=BsA2GNkJhz","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:wb05ver1k8","versioned_id":"wb05ver1k8","title":"Grounding Generative Planners in Verifiable Logic: A Hybrid Architecture for Trustworthy Embodied AI","authors":["Feiyu Wu","Xu Zheng","Yue Qu","Zhuocheng Wang","Zicheng Feng","HUI LI"],"abstract":"While Large Language Models (LLMs) show immense promise as planners for embodied AI, their stochastic nature and lack of formal reasoning capabilities prevent the strict safety guarantees required for physical deployment. Current approaches fall short: they either rely on other unreliable LLMs for safety checks or simply reject unsafe plans without offering a path to success. This work bridges this critical gap by introducing the Verifiable Iterative Refinement Framework (VIRF), a neuro-symbolic architecture that shifts the paradigm from a passive safety gatekeeper to an active safety collaborator. Where prior verifiers simply reject failures, our framework provides causal, pedagogical feedback that teaches the LLM why its plan was unsafe, enabling intelligent repairs rather than mere avoidance.Our core contribution is a novel tutor-apprentice dialogue, where a deterministic Logic Tutor, grounded in a formal safety ontology, provides causal and explanatory feedback to an LLM Apprentice planner. This pedagogical interaction allows the apprentice to perform intelligent, creative plan repairs, resolving safety conflicts rather than merely avoiding them. To ground this dialogue in verifiable truth, we introduce a scalable knowledge acquisition pipeline that synthesizes a comprehensive safety knowledge base from real-world documents, a process that simultaneously reveals and corrects significant blind spots in existing benchmarks. On a new suite of challenging home safety tasks, VIRF achieves a perfect 0\\% Hazardous Action Rate (HAR), completely eliminating unsafe actions while attaining a 77.3\\% Goal-Condition Rate (GCR)—the highest among all baselines. It does so with remarkable efficiency, requiring only 1.1 correction iterations on average. By acting as a verifiable safety scaffold, VIRF demonstrates a principled and robust pathway toward building embodied agents that are not just capable, but fundamentally trustworthy.","published":"2025-09-16T08:01:41+00:00","updated":"2026-04-11T03:09:58+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wb05ver1k8","openreview_url":"https://openreview.net/forum?id=wb05ver1k8","pdf_url":"https://openreview.net/pdf?id=wb05ver1k8","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:o1idr3SbjG","versioned_id":"o1idr3SbjG","title":"RoleArena: A Multi-Agent Role-Playing Environment for Long Multi-Turn Dialogues with Autonomous Plot Progression","authors":["Qi Zhao","Jian Li","Yizhang Jin","Dongqi Liu","Hang Ding","Qi Song","Xiangyang Li"],"abstract":"Role-playing language agents (RPLAs) use large language models (LLMs) to simulate character dialogues, enabling immersive interactions with users. Improving their plot progression ability plays a key role in enhancing user experience and the sense of immersion in the dialogue, with significant practical value. However, research on plot progression in role-playing language agents is still limited. Existing datasets often lack sufficient dialogue rounds and are missing sentences that include large-scale, clear plot twists, limiting the deep development and evaluation of related models. To bridge this gap, we propose RoleArena, an innovative multi-agent role-playing environment designed to generate highly robust long multi-round dialogues with plot progression. RoleArena contains several functionally independent large-model agents. To enable automatic plot progression, we introduce an environment agent that generates multiple plot storylines validated by self-reflection. After discretizing these, character agents complete plot points through dynamic dialogue, while the environment agent judges the plot completion state to smoothly drive the discrete plot forward. To generate robust and controllable long multi-turn dialogues, we introduce a critic agent to calibrate the plot progression judgments made by the environment agent. Using this environment, we constructed the PlotStream dataset, which includes 40.1k character configuration metadata files. Numerous experiments have demonstrated the effectiveness of RoleArena.","published":"2025-09-16T07:33:11+00:00","updated":"2026-02-11T10:14:51+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=o1idr3SbjG","openreview_url":"https://openreview.net/forum?id=o1idr3SbjG","pdf_url":"https://openreview.net/pdf?id=o1idr3SbjG","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2509.11575","versioned_id":"2509.11575v3","title":"A Survey of Reasoning and Agentic Systems in Time Series with Large Language Models","authors":["Ching Chang","Yidan Shi","Defu Cao","Wei Yang","Jeehyun Hwang","Haixin Wang","Jiacheng Pang","Wei Wang","Yan Liu","Wen-Chih Peng","Tien-Fu Chen"],"abstract":"Time series reasoning treats time as a first-class axis and incorporates intermediate evidence directly into the answer. This survey defines the problem and organizes the literature by reasoning topology with three families: direct reasoning in one step, linear chain reasoning with explicit intermediates, and branch-structured reasoning that explores, revises, and aggregates. The topology is crossed with the main objectives of the field, including traditional time series analysis, explanation and understanding, causal inference and decision making, and time series generation, while a compact tag set spans these axes and captures decomposition and verification, ensembling, tool use, knowledge access, multimodality, agent loops, and LLM alignment regimes. Methods and systems are reviewed across domains, showing what each topology enables and where it breaks down in faithfulness or robustness, along with curated datasets, benchmarks, and resources that support study and deployment (https://github.com/blacksnail789521/Time-Series-Reasoning-Survey). Evaluation practices that keep evidence visible and temporally aligned are highlighted, and guidance is distilled on matching topology to uncertainty, grounding with observable artifacts, planning for shift and streaming, and treating cost and latency as design budgets. We emphasize that reasoning structures must balance capacity for grounding and self-correction against computational cost and reproducibility, while future progress will likely depend on benchmarks that tie reasoning quality to utility and on closed-loop testbeds that trade off cost and risk under shift-aware, streaming, and long-horizon settings. Taken together, these directions mark a shift from narrow accuracy toward reliability at scale, enabling systems that not only analyze but also understand, explain, and act on dynamic worlds with traceable evidence and credible outcomes.","published":"2025-09-15T04:39:50Z","updated":"2026-06-10T07:42:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.11575v3","pdf_url":"https://arxiv.org/pdf/2509.11575v3","comment":"Accepted to Transactions on Machine Learning Research (TMLR)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=mgMJ8ksKKA","openreview_venues":["Accepted by TMLR"]},{"id":"openreview:TtBSbhT86Z","versioned_id":"TtBSbhT86Z","title":"From Trace to Line: LLM Agent for Real-World OSS Vulnerability Localization","authors":["Haoran Xi","Minghao Shao","Brendan Dolan-Gavitt","Muhammad Shafique","Ramesh Karri"],"abstract":"Large language models show promise for vulnerability discovery, yet prevailing methods inspect code in isolation, struggle with long contexts, and focus on coarse function or file level detections which offers limited actionable guidance to engineers who need precise line-level localization and targeted patches in real-world software development. We present T2L-Agent (Trace-to-Line Agent), a project-level, end-to-end framework that plans its own analysis and progressively narrows scope from modules to exact vulnerable lines. T2L-Agent couples multi-round feedback with an Agentic Trace Analyzer (ATA) that fuses runtime evidence such as crash points, stack traces, and coverage deltas with AST-based code chunking, enabling iterative refinement beyond single pass predictions and translating symptoms into actionable, line-level diagnoses. To benchmark line-level vulnerability discovery, we introduce T2L-ARVO, a diverse, expert-verified 50-case benchmark spanning five crash families and real-world projects. \\texttt{T2L-ARVO} is specifically designed to support both coarse-grained detection and fine-grained localization, enabling rigorous evaluation of systems that aim to move beyond file-level predictions. On \\texttt{T2L-ARVO}, T2L-Agent achieves up to 58.0\\% detection and 54.8\\% line-level localization, substantially outperforming baselines. Together, the framework and benchmark push LLM-based vulnerability detection from coarse identification toward deployable, robust, precision diagnostics that reduce noise and accelerate patching in open-source software workflows.","published":"2025-09-14T03:22:18+00:00","updated":"2026-02-11T10:14:19+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=TtBSbhT86Z","openreview_url":"https://openreview.net/forum?id=TtBSbhT86Z","pdf_url":"https://openreview.net/pdf?id=TtBSbhT86Z","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2509.11062","versioned_id":"2509.11062v3","title":"Auto-Slides: An Interactive Multi-Agent System for Creating and Customizing Research Presentations","authors":["Yuheng Yang","Wenjia Jiang","Yang Wang","Yi Song","Yiwei Wang","Chi Zhang"],"abstract":"The rapid progress of large language models (LLMs) has opened new opportunities for education. While learners can interact with academic papers through LLM-powered dialogue, limitations still exist: the lack of structured organization and the heavy reliance on text can impede systematic understanding and engagement with complex concepts. To address these challenges, we propose Auto-Slides, an LLM-driven system that converts research papers into pedagogically structured, multimodal slides (e.g., diagrams and tables). Drawing on cognitive science, it creates a presentation-oriented narrative and allows iterative refinement via an interactive editor to better match learners' knowledge level and goals. Auto-Slides further incorporates verification and knowledge retrieval mechanisms to ensure accuracy and contextual completeness. Through extensive user studies, Auto-Slides demonstrates strong learner acceptance, improved structural support for understanding, and expert-validated gains in narrative quality compared with conventional LLM-based reading. Our contributions lie in designing a multi-agent framework for transforming academic papers into pedagogically optimized slides and introducing interactive customization for personalized learning.","published":"2025-09-14T03:05:54Z","updated":"2026-04-01T08:41:51Z","categories":["cs.HC","cs.MA"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2509.11062v3","pdf_url":"https://arxiv.org/pdf/2509.11062v3","comment":"Project Homepage: https://auto-slides.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:M3EvRA0gU4","versioned_id":"M3EvRA0gU4","title":"Multi-AI Agents Meta-Analysis for Autonomous Self-Improvement: Critical Relativism in Overcoming Predictable Failures of Reinforcement Learning in High-Uncertainty Environments via Quantum-Augmented Self-Adaptive Networks","authors":[],"abstract":"This paper presents a novel Multi-AI Agents Meta-Analysis Methodology for enabling autonomous AI self-improvement in scientific inquiry. Drawing on critical relativism---integrating Lockean empiricism, Leibnizian rationalism, Hegelian dialectics, and Kantian synthesis---we converge diverse responses from leading AI agents (Grok, CoPilot, ChatGPT, You, Perplexity, Gemini) to dissect fundamental limitations of Reinforcement Learning (RL) algorithms, specifically Stochastic Gradient Descent (SGD) and Backpropagation, in environments of dynamic uncertainty, adversarial uncertainty, and time-space complexity. These limitations lead to predictable failures, such as suboptimal policies in non-stationary settings and vulnerability to perturbations. We propose Quantum-Augmented Self-Adaptive Networks (QASANs) as a paradigm shift, leveraging quantum superposition and entanglement for unprecedented agility, resilience, and sustainability. Empirically validated through meta-analysis of AI-generated insights, QASANs enable AI agents to self-analyze and evolve, fostering AI-driven scientific discovery aligned with human values like creativity and intuition, as inspired by Einstein's ``Imagination is more important than knowledge.'' This work advances methodological innovations for AI-augmented science, democratizing knowledge creation via transparent, multi-agent convergence.","published":"2025-09-13T20:40:08+00:00","updated":"2025-12-06T22:54:18+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=M3EvRA0gU4","openreview_url":"https://openreview.net/forum?id=M3EvRA0gU4","pdf_url":"https://openreview.net/pdf?id=M3EvRA0gU4","comment":"Agents4Science 2025 Conference Desk Rejected Submission","journal_ref":"Agents4Science 2025 Conference Desk Rejected Submission","doi":"","venue":"Agents4Science 2025 Conference Desk Rejected Submission","venue_id":"Agents4Science/2025/Conference/Desk_Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:ObPVTptRC8","versioned_id":"ObPVTptRC8","title":"VLN-MME: Diagnosing MLLMs as Language-guided Visual Navigation agents","authors":["Xunyi Zhao","Gengze Zhou","Qi Wu"],"abstract":"Multimodal Large Language Models (MLLMs) have demonstrated remarkable capabilities across a wide range of vision-language tasks. However, their performance as embodied agents, which requires multi-round dialogue and sequential action prediction, needs further exploration. Our work investigates this potential in the context of Vision-and-Language Navigation (VLN) by introducing a unified and extensible evaluation framework to probe MLLMs as zero-shot agents by bridging traditional navigation datasets into a standardized benchmark, named VLN-MME. We simplify the evaluation with a highly modular and accessible design. This flexibility streamlines experiments, enabling structured comparisons and component-level ablations across diverse MLLM architectures, agent designs, and navigation tasks. Crucially, enabled by our framework, we observe that enhancing our baseline agent with Chain-of-Thought (CoT) reasoning and self-reflection leads to an unexpected performance decrease. This suggests MLLMs exhibit poor context awareness in embodied navigation tasks; although they can follow instructions and structure their output, their reasoning fidelity is low. VLN-MME lays the groundwork for systematic evaluation of general-purpose MLLMs in embodied navigation settings and reveals limitations in their sequential decision-making capabilities. We believe these findings offer crucial guidance for MLLM post-training as embodied agents.","published":"2025-09-13T08:44:16+00:00","updated":"2025-12-21T09:03:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ObPVTptRC8","openreview_url":"https://openreview.net/forum?id=ObPVTptRC8","pdf_url":"https://openreview.net/pdf?id=ObPVTptRC8","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2509.10704","versioned_id":"2509.10704v1","title":"Maestro: Self-Improving Text-to-Image Generation via Agent Orchestration","authors":["Xingchen Wan","Han Zhou","Ruoxi Sun","Hootan Nakhost","Ke Jiang","Rajarishi Sinha","Sercan Ö. Arık"],"abstract":"Text-to-image (T2I) models, while offering immense creative potential, are highly reliant on human intervention, posing significant usability challenges that often necessitate manual, iterative prompt engineering over often underspecified prompts. This paper introduces Maestro, a novel self-evolving image generation system that enables T2I models to autonomously self-improve generated images through iterative evolution of prompts, using only an initial prompt. Maestro incorporates two key innovations: 1) self-critique, where specialized multimodal LLM (MLLM) agents act as 'critics' to identify weaknesses in generated images, correct for under-specification, and provide interpretable edit signals, which are then integrated by a 'verifier' agent while preserving user intent; and 2) self-evolution, utilizing MLLM-as-a-judge for head-to-head comparisons between iteratively generated images, eschewing problematic images, and evolving creative prompt candidates that align with user intents. Extensive experiments on complex T2I tasks using black-box models demonstrate that Maestro significantly improves image quality over initial prompts and state-of-the-art automated methods, with effectiveness scaling with more advanced MLLM components. This work presents a robust, interpretable, and effective pathway towards self-improving T2I generation.","published":"2025-09-12T21:45:16Z","updated":"2025-09-12T21:45:16Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.10704v1","pdf_url":"https://arxiv.org/pdf/2509.10704v1","comment":"15 pages, 7 figures, 2 tables (22 pages, 9 figures and 3 tables including references and appendices)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.09970","versioned_id":"2509.09970v1","title":"Securing LLM-Generated Embedded Firmware through AI Agent-Driven Validation and Patching","authors":["Seyed Moein Abtahi","Akramul Azim"],"abstract":"Large Language Models (LLMs) show promise in generating firmware for embedded systems, but often introduce security flaws and fail to meet real-time performance constraints. This paper proposes a three-phase methodology that combines LLM-based firmware generation with automated security validation and iterative refinement in a virtualized environment. Using structured prompts, models like GPT-4 generate firmware for networking and control tasks, deployed on FreeRTOS via QEMU. These implementations are tested using fuzzing, static analysis, and runtime monitoring to detect vulnerabilities such as buffer overflows (CWE-120), race conditions (CWE-362), and denial-of-service threats (CWE-400). Specialized AI agents for Threat Detection, Performance Optimization, and Compliance Verification collaborate to improve detection and remediation. Identified issues are categorized using CWE, then used to prompt targeted LLM-generated patches in an iterative loop. Experiments show a 92.4\\% Vulnerability Remediation Rate (37.3\\% improvement), 95.8\\% Threat Model Compliance, and 0.87 Security Coverage Index. Real-time metrics include 8.6ms worst-case execution time and 195μs jitter. This process enhances firmware security and performance while contributing an open-source dataset for future research.","published":"2025-09-12T05:15:35Z","updated":"2025-09-12T05:15:35Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2509.09970v1","pdf_url":"https://arxiv.org/pdf/2509.09970v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.09751","versioned_id":"2509.09751v2","title":"Meta-Learning Reinforcement Learning for Crypto-Return Prediction","authors":["Junqiao Wang","Zhaoyang Guan","Guanyu Liu","Tianze Xia","Xianzhi Li","Shuo Yin","Xinyuan Song","Chuhan Cheng","Tianyu Shi","Alex Lee"],"abstract":"Predicting cryptocurrency returns is notoriously difficult: price movements are driven by a fast-shifting blend of on-chain activity, news flow, and social sentiment, while labeled training data are scarce and expensive. In this paper, we present Meta-RL-Crypto, a unified transformer-based architecture that unifies meta-learning and reinforcement learning (RL) to create a fully self-improving trading agent. Starting from a vanilla instruction-tuned LLM, the agent iteratively alternates between three roles-actor, judge, and meta-judge-in a closed-loop architecture. This learning process requires no additional human supervision. It can leverage multimodal market inputs and internal preference feedback. The agent in the system continuously refines both the trading policy and evaluation criteria. Experiments across diverse market regimes demonstrate that Meta-RL-Crypto shows good performance on the technical indicators of the real market and outperforming other LLM-based baselines.","published":"2025-09-11T14:20:45Z","updated":"2026-02-01T10:15:44Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.09751v2","pdf_url":"https://arxiv.org/pdf/2509.09751v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:gZiLJVfD2v","versioned_id":"gZiLJVfD2v","title":"You Are What Role You Play: Directing AI Values Through Role Assignment​","authors":["Zhou Ziheng","Jiakun Ding","Zhaowei Zhang","Junqi Wang","Ruosen Gao","Yipeng Kang","Fangwei Zhong","Ying Nian Wu","Demetri Terzopoulos"],"abstract":"Principle-based (e.g Constitution Alignment \\citep{bai2022constitutional}) alignment methods rely on fixed lists of values, but these are inevitably incomplete and lack context sensitivity. We propose role-conditioning as a compact alternative: roles like mother or judge implicitly encode both values and the cognition needed to apply them. Grounded in Theory of Mind (ToM), we formalize this view and prove that roles are strictly more expressive than principle lists in the ideal case. We then introduce a simple, training-free pipeline: a role-conditioned generator plus lightweight role-based critics for iterative refinement. Across five model families from small to large, validated on multiple safety benchmarks, this approach consistently outperforms principle-based, CoT, and hybrid baselines—cutting unsafe outputs (e.g improve by 3–20× (down to 3–10\\%) on WildJailbreak). To investigate the effectiveness of our method, we conduct ablation studies examining role choices, different role combinations, the number of roles employed, and the impact of critic feedback iterations. We further explore how our approach can be synergistically combined with existing methods to achieve additional performance improvements. Additionally, we evaluate our method's effectiveness on a specialized agentic safety benchmark (AI blackmail), demonstrating its broader applicability. These results position roles as a simple, interpretable, yet powerful mechanism for directing AI values—offering both a paradigm shift in alignment approaches and a novel signal source for LLM-as-Judge construction.","published":"2025-09-11T12:02:38+00:00","updated":"2026-01-07T00:41:34+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=gZiLJVfD2v","openreview_url":"https://openreview.net/forum?id=gZiLJVfD2v","pdf_url":"https://openreview.net/pdf?id=gZiLJVfD2v","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2509.09234","versioned_id":"2509.09234v1","title":"Agentic LLMs for Question Answering over Tabular Data","authors":["Rishit Tyagi","Mohit Gupta","Rahul Bouri"],"abstract":"Question Answering over Tabular Data (Table QA) presents unique challenges due to the diverse structure, size, and data types of real-world tables. The SemEval 2025 Task 8 (DataBench) introduced a benchmark composed of large-scale, domain-diverse datasets to evaluate the ability of models to accurately answer structured queries. We propose a Natural Language to SQL (NL-to-SQL) approach leveraging large language models (LLMs) such as GPT-4o, GPT-4o-mini, and DeepSeek v2:16b to generate SQL queries dynamically. Our system follows a multi-stage pipeline involving example selection, SQL query generation, answer extraction, verification, and iterative refinement. Experiments demonstrate the effectiveness of our approach, achieving 70.5\\% accuracy on DataBench QA and 71.6\\% on DataBench Lite QA, significantly surpassing baseline scores of 26\\% and 27\\% respectively. This paper details our methodology, experimental results, and alternative approaches, providing insights into the strengths and limitations of LLM-driven Table QA.","published":"2025-09-11T08:12:38Z","updated":"2025-09-11T08:12:38Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2509.09234v1","pdf_url":"https://arxiv.org/pdf/2509.09234v1","comment":"Accepted at ACL workshop SemEval 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:wvT56qK50w","versioned_id":"wvT56qK50w","title":"Learning Goal-Oriented Language-Guided Navigation with Self-Improving Demonstrations at Scale","authors":["Songze Li","Zun Wang","Gengze Zhou","Jialu Li","Xiangyu Zeng","Ziyang Gong","Limin Wang","Yu Qiao","Qi Wu","Mohit Bansal","Yi Wang"],"abstract":"Goal-oriented language-guided navigation requires robust exploration capabilities for agents to navigate to specified goals in unknown environments without step-by-step instructions. Existing methods tend to exclusively utilize shortest-path trajectories, lacking effective exploration priors for training navigation agents. To address the above challenges, we present SID, a goal-oriented language-guided navigation learning approach with Self-Improving Demonstrations. Specifically, SID learns an initial agent on the shortest-path data sampled from environments and then leverages this agent to generate novel exploration trajectories. The novel rollouts provide demonstrations with stronger exploration strategies to train a better agent, which in turn produces higher-quality agent demonstrations for the next round of training. We show that this iterative self-improving pipeline readily scales to new environments, and the resulting demonstrations can be transferred across a variety of language-guided navigation tasks, elevating the performance ceiling in diverse goal-oriented navigation tasks. Extensive experiments demonstrate that SID significantly boosts the exploration capabilities and generalization of navigation agents. The resulting agent achieves new state-of-the-art performance on goal-oriented language-guided navigation tasks, including REVERIE, SOON, notably achieving a 50.9% success rate on the unseen validation splits of SOON, surpassing the prior leading approaches by a margin of 13.9%.","published":"2025-09-11T05:38:51+00:00","updated":"2026-02-11T10:14:04+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wvT56qK50w","openreview_url":"https://openreview.net/forum?id=wvT56qK50w","pdf_url":"https://openreview.net/pdf?id=wvT56qK50w","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2509.08203","versioned_id":"2509.08203v1","title":"Componentization: Decomposing Monolithic LLM Responses into Manipulable Semantic Units","authors":["Ryan Lingo","Rajeev Chhajer","Martin Arroyo","Luka Brkljacic","Ben Davis","Nithin Santhanam"],"abstract":"Large Language Models (LLMs) often produce monolithic text that is hard to edit in parts, which can slow down collaborative workflows. We present componentization, an approach that decomposes model outputs into modular, independently editable units while preserving context. We describe Modular and Adaptable Output Decomposition (MAOD), which segments responses into coherent components and maintains links among them, and we outline the Component-Based Response Architecture (CBRA) as one way to implement this idea. Our reference prototype, MAODchat, uses a microservices design with state-machine-based decomposition agents, vendor-agnostic model adapters, and real-time component manipulation with recomposition. In an exploratory study with four participants from academic, engineering, and product roles, we observed that component-level editing aligned with several common workflows and enabled iterative refinement and selective reuse. Participants also mentioned possible team workflows. Our contributions are: (1) a definition of componentization for transforming monolithic outputs into manipulable units, (2) CBRA and MAODchat as a prototype architecture, (3) preliminary observations from a small user study, (4) MAOD as an algorithmic sketch for semantic segmentation, and (5) example Agent-to-Agent protocols for automated decomposition. We view componentization as a promising direction for turning passive text consumption into more active, component-level collaboration.","published":"2025-09-10T00:15:33Z","updated":"2025-09-10T00:15:33Z","categories":["cs.HC","cs.AI","cs.SE"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2509.08203v1","pdf_url":"https://arxiv.org/pdf/2509.08203v1","comment":"12 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:8Yno1MYsvP","versioned_id":"8Yno1MYsvP","title":"An Agentic Approach to Phenotype Mapping from Rare Disease Surveys","authors":["Jipeng Di","Julie Renee Vaughn","Joshua Proulx","Sadie Nordstrand","Bryce Daines","Katrisa Madeline Ward","Philip J. Lupo","Jianhong Hu","Mullai Murugan","Adam W. Hansen"],"abstract":"Rare disease patients worldwide often experience years-long diagnostic delays, in part due to fragmented and unstructured phenotypic information. Patient-reported surveys provide valuable insights but are typically unstructured and hard to integrate with structured data. We present GenOMA (Geneial Ontology Mapping Agent), a Large Language Model (LLM) agent built on the LangGraph framework and integrated with a Unified Medical Language System (UMLS) API for precise extraction and ontology mapping of phenotypic terms. Using a modular, node-based architecture for context-aware extraction, iterative refinement, candidate ranking, and semantic validation, GenOMA maps data to standardized Human Phenotype Ontology (HPO) codes without local ontology deployment. We evaluate GenOMA on the question fields of three rare disease surveys, mapping them to HPO terms, and compare its performance with other leading methods. On the Xia-Gibbs Syndrome (XGS) Registry, GenOMA achieved 0.92 accuracy, 0.94 precision, 0.97 recall, and 0.96 F1. On the Down Syndrome Phenotyping Acute Leukemia Study (DS-PALS) dataset, it obtained 0.92 accuracy, 0.93 precision, 0.98 recall, and 0.96 F1. Finally, on the GenomeConnect (GC) dataset, it obtained 0.91 accuracy, 0.91 precision, 1.0 recall, and 0.96 F1. In all tasks, GenOMA outperformed MetaMap, PhenoTagger, PhenoBERT, cTAKES, and GPT-5. These results show that GenOMA effectively converts unstructured survey data to structured phenotype information. To our knowledge, this is the first ontology mapping system specifically designed for patient-reported rare disease surveys, a critical but underexplored data modality.","published":"2025-09-09T04:39:38+00:00","updated":"2025-12-09T01:21:12+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=8Yno1MYsvP","openreview_url":"https://openreview.net/forum?id=8Yno1MYsvP","pdf_url":"https://openreview.net/pdf?id=8Yno1MYsvP","comment":"ML4H 2025 Spotlight","journal_ref":"ML4H 2025 Spotlight","doi":"","venue":"ML4H 2025 Spotlight","venue_id":"ML4H/2025/Symposium","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:x0Ir7cWEiA","versioned_id":"x0Ir7cWEiA","title":"Murphy: Reflective Multi-Turn Reinforcement Learning for Self-Correcting Code Generation in Large Language","authors":["Chanakya Ekbote","Vijay Lingam","Behrooz Omidvar Tehrani","Jun Huan","sujay sanghavi","Anoop Deoras","Stefano Soatto"],"abstract":"Reinforcement Learning with Verifiable Rewards (RLVR) has emerged as a powerful framework for enhancing the reasoning capabilities of large language models (LLMs). However, existing approaches such as Group Relative Policy Optimization (GRPO) and its variants, while effective on reasoning benchmarks, struggle with agentic tasks that require iterative decision-making. We introduce Murphy, a multi-turn reflective optimization framework that extends GRPO by incorporating iterative self-correction during training. By leveraging both quantitative and qualitative execution feedback, Murphy enables models to progressively refine their reasoning across multiple turns. Evaluations on code generation benchmarks with model families such as Qwen and OLMo show that Murphy consistently improves performance, achieving up to a $8$% relative gain in pass@1 over GRPO, on similar compute budgets.","published":"2025-09-09T03:58:29+00:00","updated":"2025-12-07T00:02:31+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=x0Ir7cWEiA","openreview_url":"https://openreview.net/forum?id=x0Ir7cWEiA","pdf_url":"https://openreview.net/pdf?id=x0Ir7cWEiA","comment":"FoRLM 2025","journal_ref":"FoRLM 2025","doi":"","venue":"FoRLM 2025","venue_id":"NeurIPS.cc/2025/Workshop/FoRLM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:Wv2i3S4hvf","versioned_id":"Wv2i3S4hvf","title":"TCMAgent: A Multi-Agent Framework for General Traditional Chinese Medicine","authors":["Jinsheng Pan","Jiaqi Wei","Xiang Zhang","Chenyu You"],"abstract":"A central challenge in artificial intelligence is designing systems that replicate expert cognition in domains where decisions require holistic data synthesis and deliberative reasoning. While large language models (LLMs) have achieved remarkable progress, their monolithic and sequential architectures impose cognitive bottlenecks that limit their ability to reason over multi-modal evidence or resolve competing hypotheses. Recent advances in multi-agent frameworks provide a new paradigm for overcoming these limitations by distributing reasoning across specialized agents and enabling structured deliberation. We present \\textsc{TCMAgent}, a novel multi-agent architecture that operationalizes a distributed and reflective reasoning workflow. Our framework introduces two key innovations: (\\emph{i}) \\emph{parallel evidence synthesis}, where agents process heterogeneous inputs concurrently to form a unified representation, and (\\emph{ii}) a \\emph{collaborative deliberation module}, inspired by clinical peer review, in which agents adversarially refine hypotheses to surface trade-offs and converge on robust decisions. This process is further enhanced by an experiential reflection mechanism that learns from historical reasoning traces, enabling continual self-improvement. We validate \\textsc{TCMAgent} on a multi-modal clinical benchmark in Traditional Chinese Medicine (TCM), a canonical domain where expert-level reasoning requires holistic integration of patient data and careful negotiation of conflicting principles. Experiments demonstrate that \\textsc{TCMAgent} significantly outperforms strong LLM baselines in safety, coherence, and interpretability of treatment recommendations. These results provide the first empirical evidence that distributed, deliberative agentic architectures can overcome the cognitive bottlenecks of monolithic models, marking a step toward safer and more reliable AI in knowledge-intensive domains.","published":"2025-09-08T02:20:18+00:00","updated":"2025-11-12T14:46:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Wv2i3S4hvf","openreview_url":"https://openreview.net/forum?id=Wv2i3S4hvf","pdf_url":"https://openreview.net/pdf?id=Wv2i3S4hvf","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:329w99DBGk","versioned_id":"329w99DBGk","title":"Cross-Reflect: Empowering Multi-Modal Agents with Joint Reasoning Across Trajectories","authors":["Liangbing Zhao","Wenxuan Zhang","Minhao Fan","Isaac Miller","Omar Khattab","Mohamed Elhoseiny"],"abstract":"Despite rapid progress in vision–language models (VLMs), small VLMs still struggle to serve as effective agents capable of coherent multi-step tool use, especially in settings where fine-tuning is impractical due to data or cost constraints. To address these limitations, we introduce Cross-Reflect, a training-free framework for reflection-guided trajectory optimization. Cross-Reflect generates multiple candidate trajectories, applies structured reflection to critique and refine them, and performs cross-trajectory selection to identify the most reliable solution. It is instantiated via an extension of the DSPy programming paradigm, which provides modular support for multimodal inputs. Extensive experiments across static and dynamic knowledge-intensive VQA benchmarks demonstrate that Cross-Reflect consistently improves small VLMs by enabling flexible tool usage and trajectory-level self-reflection, achieving average relative improvements of 10.5\\% for proprietary models and 28.1\\% for open-source models over baseline methods. Further analysis shows that our approach achieves comparable performance to methods requiring model fine-tuning, and even surpasses them in certain cases.","published":"2025-09-07T14:34:11+00:00","updated":"2026-02-11T10:13:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=329w99DBGk","openreview_url":"https://openreview.net/forum?id=329w99DBGk","pdf_url":"https://openreview.net/pdf?id=329w99DBGk","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2509.05735","versioned_id":"2509.05735v1","title":"Offline vs. Online Learning in Model-based RL: Lessons for Data Collection Strategies","authors":["Jiaqi Chen","Ji Shi","Cansu Sancaktar","Jonas Frey","Georg Martius"],"abstract":"Data collection is crucial for learning robust world models in model-based reinforcement learning. The most prevalent strategies are to actively collect trajectories by interacting with the environment during online training or training on offline datasets. At first glance, the nature of learning task-agnostic environment dynamics makes world models a good candidate for effective offline training. However, the effects of online vs. offline data on world models and thus on the resulting task performance have not been thoroughly studied in the literature. In this work, we investigate both paradigms in model-based settings, conducting experiments on 31 different environments. First, we showcase that online agents outperform their offline counterparts. We identify a key challenge behind performance degradation of offline agents: encountering Out-Of-Distribution states at test time. This issue arises because, without the self-correction mechanism in online agents, offline datasets with limited state space coverage induce a mismatch between the agent's imagination and real rollouts, compromising policy training. We demonstrate that this issue can be mitigated by allowing for additional online interactions in a fixed or adaptive schedule, restoring the performance of online training with limited interaction data. We also showcase that incorporating exploration data helps mitigate the performance degradation of offline agents. Based on our insights, we recommend adding exploration data when collecting large datasets, as current efforts predominantly focus on expert data alone.","published":"2025-09-06T14:52:33Z","updated":"2025-09-06T14:52:33Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.05735v1","pdf_url":"https://arxiv.org/pdf/2509.05735v1","comment":"Accepted at Reinforcement Learning Conference (RLC 2025); Code available at: https://github.com/swsychen/Offline_vs_Online_in_MBRL","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=AjiDxC7aIi","openreview_venues":["RLC 2025"]},{"id":"openreview:jARUSddVIB","versioned_id":"jARUSddVIB","title":"Husky Hold'em Benchmark: Can LLMs Design Competitive Poker Bots?","authors":["Bhavesh Kumar","Hoang Doan Nguyen","Roger Jin","Ryan Teknium","Jeffrey Quesnelle"],"abstract":"We introduce Husky Hold'em Bench, a novel agent benchmark which combines strategic reasoning and software engineering skills. Agents are tasked with implementing poker bots which then compete in a 6-player round-robin tournament. We use a minimal 5-stage iterative refinement agent scaffold to solicit bots from current frontier models and run a poker bots tournament, averaging over several trials to reduce variance. We find that Claude 4 Sonnet tops the leaderboard, and that in general top models tended to employ balanced or aggressive play styles, while lower-ranking models tended to play more defensively. We open-source our code as well as all data from the tournament.","published":"2025-09-05T10:16:00+00:00","updated":"2025-11-28T02:28:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=jARUSddVIB","openreview_url":"https://openreview.net/forum?id=jARUSddVIB","pdf_url":"https://openreview.net/pdf?id=jARUSddVIB","comment":"NeurIPS 2025 LLM Evaluation Workshop Poster","journal_ref":"NeurIPS 2025 LLM Evaluation Workshop Poster","doi":"","venue":"NeurIPS 2025 LLM Evaluation Workshop Poster","venue_id":"NeurIPS.cc/2025/Workshop/LLM_Evaluation","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:Aobvdp3XmP","versioned_id":"Aobvdp3XmP","title":"MobileWizard: A Data-Efficient GUI Agent with Structured Reasoning and Progressive Reinforcement Learning","authors":["Weifeng Lin","Yuxiang Chai","Han Xiao","Liuyang Bian","Guangyi Liu","Liang Liu","Shuai Ren","Penggang Shi","Yafei Wen","Xiaoxin Chen","Aojun Zhou","Hongsheng Li"],"abstract":"This paper introduces MobileWizard, a data-efficient framework designed to enhance the reasoning and precision of mobile GUI agents. Trained on merely 24.5k public trajectories and 300 remedial trajectories, MobileWizard-7B demonstrates exceptional performance, achieving a 47.2\\% success rate on AndroidWorld, outperforming prominent larger open-source models like UI-TARS-72B. This high efficiency stems from two core innovations: 1) Structured Reasoning: A new structured Chain-of-Thought (CoT) paradigm that decomposes the agent’s reasoning process into four explicit and interpretable modules: self-verification, screen analysis, planning, and action guidance. The proposed CoT guides the LLM to achieve logical consistency, extraction of key insights, and provides clear paths for failure analysis. 2) Progressive Reinforcement Learning: We propose a comprehensive RL strategy that features four key components: efficient cold-start training, a dynamic reward system with Progressive Reward Shrinking to boost precision, History Self-Alignment to narrow the training-inference gap, and a Corrective Teaching Pipeline for self-improvement from online failures. The experimental results demonstrate that our framework enables superior generalization from limited data. We believe that our method presents a scalable and efficient path toward building more robust and versatile GUI agents.","published":"2025-09-05T03:05:04+00:00","updated":"2026-02-11T10:13:39+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Aobvdp3XmP","openreview_url":"https://openreview.net/forum?id=Aobvdp3XmP","pdf_url":"https://openreview.net/pdf?id=Aobvdp3XmP","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:Bo9FcSnrVP","versioned_id":"Bo9FcSnrVP","title":"Mind the Gap: Evaluating Model- and Agentic-Level Vulnerabilities in LLMs with Action Graphs","authors":["Ilham Wicaksono","Zekun Wu","Rahul Patel","Theo King","Adriano Koshiyama","Philip Colin Treleaven"],"abstract":"As large language models transition to agentic systems, current safety evaluation frameworks face critical gaps in assessing deployment-specific risks. We introduce AgentSeer, an observability-based evaluation framework that decomposes agentic executions into granular action and component graphs, enabling systematic agentic-situational assessment. Through cross-model validation on GPT-OSS-20B and Gemini-2.0-flash using HarmBench single turn and iterative refinement attacks, we demonstrate fundamental differences between model-level and agentic-level vulnerability profiles. Model-level evaluation reveals baseline differences: GPT-OSS-20B (39.47\\% ASR) versus Gemini-2.0-flash (50.00\\% ASR), with both models showing susceptibility to social engineering while maintaining logic-based attack resistance. However, agentic-level assessment exposes agent-specific risks invisible to traditional evaluation. We discover \"agentic-only\" vulnerabilities that emerge exclusively in agentic contexts, with tool-calling showing 24-60\\% higher ASR across both models. Cross-model analysis reveals universal agentic patterns, where agent transfer operations as highest-risk tools, semantic rather than syntactic vulnerability mechanisms, and context-dependent attack effectiveness, alongside model-specific security profiles in absolute attack success rate (ASR) levels and optimal injection strategies. Direct attack transfer from model-level to agentic contexts shows degraded performance (GPT-OSS-20B: 57\\% human injection ASR; Gemini-2.0-flash: 28\\%), while context-aware iterative attacks successfully compromise objectives that failed at model-level, confirming systematic evaluation gaps. These findings establish the urgent need for agentic-situation evaluation paradigms, with AgentSeer providing the standardized methodology and empirical validation.","published":"2025-09-05T02:55:28+00:00","updated":"2025-11-27T10:29:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Bo9FcSnrVP","openreview_url":"https://openreview.net/forum?id=Bo9FcSnrVP","pdf_url":"https://openreview.net/pdf?id=Bo9FcSnrVP","comment":"NeurIPS 2025 LLM Evaluation Workshop Poster","journal_ref":"NeurIPS 2025 LLM Evaluation Workshop Poster","doi":"","venue":"NeurIPS 2025 LLM Evaluation Workshop Poster","venue_id":"NeurIPS.cc/2025/Workshop/LLM_Evaluation","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:mV0xJpO7A0","versioned_id":"mV0xJpO7A0","title":"AI Psychiatrist Assistant: An LLM-based Multi-Agent System for Depression Assessment from Clinical Interviews","authors":["Adam Greene","Neviah Blair","Samin Mahdipour Aghabagher","Simmi Kumari","Michael W Schlund","Alex Fedorov","Vince D. Calhoun","Xinhui Li","Rogers F Silva"],"abstract":"Depression is one of the most common mental disorders yet remains underdiagnosed. Large language models (LLMs) have shown promise in their ability to understand the semantic meaning behind medical text and automate clinical workflows through collaborative agents. Here, we propose an LLM-based multi-agent system to diagnose depression symptoms from clinical interview transcripts. Our system integrates four agents: (1) a qualitative assessment agent that identifies symptoms and risk factors, (2) a judge agent that evaluates qualitative assessment through iterative self-refinement, (3) a quantitative assessment agent that predicts clinical scores using a novel embedding-based few-shot prompting approach, and (4) a meta-review agent that integrates outputs into a comprehensive overview of a patient's mental state. The qualitative assessment agent provided coherent, specific, and reasonably accurate assessment, as evaluated by both the human expert and the judge agent. The quantitative assessment agent with few-shot prompting showed an average mean absolute error of $0.619$ for symptom prediction versus $0.796$ in zero-shot prompting, while the meta-review agent achieved a binary classification accuracy of $78\\\\%$, comparable to that of a human expert. Our system could serve as a consultant for psychiatrists and psychologists, offering an alternative perspective on patients' mental health conditions, and thus establishing a foundation for future work on agent-aided clinical support.","published":"2025-09-05T01:43:21+00:00","updated":"2025-12-09T01:21:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=mV0xJpO7A0","openreview_url":"https://openreview.net/forum?id=mV0xJpO7A0","pdf_url":"https://openreview.net/pdf?id=mV0xJpO7A0","comment":"ML4H 2025 Poster","journal_ref":"ML4H 2025 Poster","doi":"","venue":"ML4H 2025 Poster","venue_id":"ML4H/2025/Symposium","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:owpU8gxnkM","versioned_id":"owpU8gxnkM","title":"ENCOURAGING CRITICAL THINKING FOR MULTIAGENT DEBATE","authors":["Jing Wu","Suiyao Chen","Inseok Heo","Alexander Gutfraind","Michael Sharps"],"abstract":"Large language models (LLMs) have demonstrated remarkable performance across a wide range of tasks in recent years. While prior work has explored leveraging LLMs to generate synthetic data for self-improvement, repeated iterations often suffer from diminishing returns due to the reliance on homogeneous reasoning patterns and limited exploration of alternative perspectives. In this paper, we introduce a novel framework that enriches the reasoning process by encouraging critical thinking among multiple agents. Rather than deploying an ensemble of models with identical prompts, we propose a strategy generator that produces customized instructions tailored to each individual LLM. Acting as a critical thinking agent, the generator is iteratively fine-tuned using carefully selected strategies that are both diverse and effective. This approach fosters specialization within each model while promoting diversity across reasoning paths, enabling the system to maintain varied solution trajectories and achieve sustained performance gains through iterative refinement. We demonstrate the effectiveness of our method across a variety of agentic frameworks and complex reasoning tasks.","published":"2025-09-04T18:34:10+00:00","updated":"2026-02-11T10:13:38+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=owpU8gxnkM","openreview_url":"https://openreview.net/forum?id=owpU8gxnkM","pdf_url":"https://openreview.net/pdf?id=owpU8gxnkM","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2509.04575","versioned_id":"2509.04575v3","title":"Bootstrapping Task Spaces for Self-Improvement","authors":["Minqi Jiang","Andrei Lupu","Yoram Bachrach"],"abstract":"Progress in many task domains emerges from repeated revisions to previous solution attempts. Training agents that can reliably self-improve over such sequences at inference-time is a natural target for reinforcement learning (RL), yet the naive approach assumes a fixed maximum iteration depth, which can be both costly and arbitrary. We present Exploratory Iteration (ExIt), a family of autocurriculum RL methods that directly exploits the recurrent structure of self-improvement tasks to train LLMs to perform multi-step self-improvement at inference-time while only training on the most informative single-step iterations. ExIt grows a task space by selectively sampling the most informative intermediate, partial histories encountered during an episode for continued iteration, treating these starting points as new self-iteration task instances to train a self-improvement policy. ExIt can further pair with explicit exploration mechanisms to sustain greater task diversity. Across several domains, encompassing competition math, multi-turn tool-use, and machine learning engineering, we demonstrate that ExIt strategies, starting from either a single or many task instances, can produce policies exhibiting strong inference-time self-improvement on held-out task instances, and the ability to iterate towards higher performance over a step budget extending beyond the average iteration depth encountered during training.","published":"2025-09-04T18:01:00Z","updated":"2026-02-22T23:28:26Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2509.04575v3","pdf_url":"https://arxiv.org/pdf/2509.04575v3","comment":"TMLR, February 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=k2VsgUxC6X","openreview_venues":["Accepted by TMLR"]},{"id":"2509.04343","versioned_id":"2509.04343v1","title":"Psychologically Enhanced AI Agents","authors":["Maciej Besta","Shriram Chandran","Robert Gerstenberger","Mathis Lindner","Marcin Chrapek","Sebastian Hermann Martschat","Taraneh Ghandi","Patrick Iff","Hubert Niewiadomski","Piotr Nyczyk","Jürgen Müller","Torsten Hoefler"],"abstract":"We introduce MBTI-in-Thoughts, a framework for enhancing the effectiveness of Large Language Model (LLM) agents through psychologically grounded personality conditioning. Drawing on the Myers-Briggs Type Indicator (MBTI), our method primes agents with distinct personality archetypes via prompt engineering, enabling control over behavior along two foundational axes of human psychology, cognition and affect. We show that such personality priming yields consistent, interpretable behavioral biases across diverse tasks: emotionally expressive agents excel in narrative generation, while analytically primed agents adopt more stable strategies in game-theoretic settings. Our framework supports experimenting with structured multi-agent communication protocols and reveals that self-reflection prior to interaction improves cooperation and reasoning quality. To ensure trait persistence, we integrate the official 16Personalities test for automated verification. While our focus is on MBTI, we show that our approach generalizes seamlessly to other psychological frameworks such as Big Five, HEXACO, or Enneagram. By bridging psychological theory and LLM behavior design, we establish a foundation for psychologically enhanced AI agents without any fine-tuning.","published":"2025-09-04T16:03:03Z","updated":"2025-09-04T16:03:03Z","categories":["cs.AI","cs.CL","cs.CY","cs.HC","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.04343v1","pdf_url":"https://arxiv.org/pdf/2509.04343v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:tEZrGZa7MK","versioned_id":"tEZrGZa7MK","title":"MaskSearch: Towards Scalable Agentic Pre-Training for Search-Enhanced Reasoning","authors":["Weiqi Wu","Xin Guan","Shen Huang","Yong Jiang","Pengjun Xie","Fei Huang","Jiuxin Cao","hai zhao","Jingren Zhou"],"abstract":"Retrieval-Augmented Large Language Models (LLMs) excel at knowledge-intensive tasks but struggle in complex scenarios due to passive retrieval. While search agents empower LLMs to actively use tools for reasoning, existing training-based methods remain constrained by task-specific data. Therefore, we propose MaskSearch, a two-stage training framework that bridges foundation models with search agents through a novel Retrieval-Augmented Mask Prediction (RAMP) task. Models first learn to recover masked spans via multi-step search and reasoning as a pre-training stage to endow foundational agentic capabilities that can be further improved by post-training on downstream tasks. We apply Supervised Fine-tuning (SFT) or Reinforcement Learning (RL) for training. For SFT, we combine multi-agent trajectory synthesis with iterative self-evolution distillation to construct data. For RL, we employ DAPO with a hybrid reward system consisting of answer and format rewards. Additionally, we introduce a curriculum learning strategy based on the number of masked spans. We evaluate the effectiveness of our framework in the scenario of open-domain multi-hop question answering. Extensive experiments demonstrate that MaskSearch effectively equips LLMs with transferable agentic abilities, advancing the development of search agents.","published":"2025-09-04T13:11:26+00:00","updated":"2026-02-11T10:13:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=tEZrGZa7MK","openreview_url":"https://openreview.net/forum?id=tEZrGZa7MK","pdf_url":"https://openreview.net/pdf?id=tEZrGZa7MK","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:5Nm8TqbNvU","versioned_id":"5Nm8TqbNvU","title":"Unfixing the mental set: Granting early-stage reasoning freedom in multi-agent debate","authors":["Jing Wu"],"abstract":"Large language models (LLMs) have demonstrated remarkable performance across a wide range of tasks in recent years. While prior work has explored leveraging LLMs to generate synthetic data for self-improvement, repeated iterations often suffer from diminishing returns due to the reliance on homogeneous reasoning patterns and limited exploration of alternative perspectives. In this paper, we introduce a novel framework that enriches the reasoning process by encouraging critical thinking among multiple agents. Rather than deploying an ensemble of models with identical prompts, we propose a strategy generator that produces customized instructions tailored to each individual LLM. Acting as a critical thinking agent, the generator is iteratively fine-tuned using carefully selected strategies that are both diverse and effective. This approach fosters specialization within each model while promoting diversity across reasoning paths, enabling the system to maintain varied solution trajectories and achieve sustained performance gains through iterative refinement. We demonstrate the effectiveness of our method across a variety of agentic frameworks and complex reasoning tasks.","published":"2025-09-03T15:48:18+00:00","updated":"2025-09-03T15:48:18+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=5Nm8TqbNvU","openreview_url":"https://openreview.net/forum?id=5Nm8TqbNvU","pdf_url":"https://openreview.net/pdf?id=5Nm8TqbNvU","comment":"ICML 2025 Workshop on Multi-Agent Systems in the Era of Foundation Models","journal_ref":"ICML 2025 Workshop on Multi-Agent Systems in the Era of Foundation Models","doi":"","venue":"ICML 2025 Workshop on Multi-Agent Systems in the Era of Foundation Models","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:gwysQdBY1q","versioned_id":"gwysQdBY1q","title":"Incentivizing Tool-augmented Thinking with Images for Medical Image Analysis","authors":["Yankai Jiang","Yujie Zhang","Peng Zhang","Yichen Li","Jintai Chen","Xiaoming Shi","Shihui Zhen"],"abstract":"Recent reasoning based medical MLLMs have made progress in generating step by step textual reasoning chains. However, they still struggle with complex tasks that necessitate dynamic and iterative focusing on fine-grained visual regions to achieve precise grounding and diagnosis. We introduce Ophiuchus, a versatile, tool-augmented framework that equips an MLLM to (i) decide when additional visual evidence is needed, (ii) determine where to probe and ground within the medical image, and (iii) seamlessly weave the relevant sub-image content back into an interleaved, multimodal chain of thought. In contrast to prior approaches limited by the performance ceiling of specialized tools, Ophiuchus integrates the model’s inherent grounding and perception capabilities with external tools, thereby fostering higher-level reasoning. The core of our method is a three-stage training strategy: cold-start training with tool-integrated reasoning data to achieve basic tool selection and adaptation for inspecting key regions; self-reflection fine-tuning to strengthen reflective reasoning and encourage revisiting tool outputs; and Agentic Tool Reinforcement Learning to directly optimize task-specific rewards and emulate expert-like diagnostic behavior. Extensive experiments show that Ophiuchus consistently outperforms both closed-source and open-source SOTA methods across diverse medical benchmarks, including VQA, detection, and reasoning-based segmentation. Our approach illuminates a path toward medical AI agents that can genuinely “think with images” through tool-integrated reasoning. Datasets, codes, and trained models will be released publicly.","published":"2025-09-03T14:02:14+00:00","updated":"2026-01-27T03:53:42+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=gwysQdBY1q","openreview_url":"https://openreview.net/forum?id=gwysQdBY1q","pdf_url":"https://openreview.net/pdf?id=gwysQdBY1q","comment":"ICLR 2026 Conference Withdrawn Submission","journal_ref":"ICLR 2026 Conference Withdrawn Submission","doi":"","venue":"ICLR 2026 Conference Withdrawn Submission","venue_id":"ICLR.cc/2026/Conference/Withdrawn_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:uVQz9t64cK","versioned_id":"uVQz9t64cK","title":"Improving LLM Reasoning under Uncertainty with Coach-Player Multi-agent","authors":["Heewon Park","Minhae Kwon"],"abstract":"Large language models (LLM) are increasingly deployed as interactive agents that reason, plan, and act across multiple turns. While reasoning-based paradigms improve problem solving, and reflection-based methods enhance robustness, single-agent designs remain limited: they often reinforce their own biases and intervene only after errors have accumulated, leading to instability in long-horizon tasks. We introduce a Player–Coach multi-agent LLM system that enables conditional, real-time self-correction during multi-turn decision making. A Player agent engages with the environment through step-wise reasoning and actions, while a Coach agent is invoked only when the Player’s uncertainty is high. The Coach provides targeted metacognitive feedback, such as clarifying objectives or resolving confusion. Feedback is immediately added to the Player’s context. To trigger interventions precisely when needed, we develop a composite uncertainty measure combining normalized entropy and top-two margin. Experiments on ALFWorld show that our approach improves success rates and reduces trajectory length compared to single-agent baselines, without requiring additional training or fine-tuning.","published":"2025-09-03T09:24:10+00:00","updated":"2025-11-10T19:14:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=uVQz9t64cK","openreview_url":"https://openreview.net/forum?id=uVQz9t64cK","pdf_url":"https://openreview.net/pdf?id=uVQz9t64cK","comment":"NeurIPS 2025 ER Workshop","journal_ref":"NeurIPS 2025 ER Workshop","doi":"","venue":"NeurIPS 2025 ER Workshop","venue_id":"NeurIPS.cc/2025/Workshop/ER","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:7DFZ9OzM6T","versioned_id":"7DFZ9OzM6T","title":"Healthcare TimeSeries Reasoning Benchmarks at Scale","authors":["Malgorzata Gwiazda","Yifu Cai","Mononito Goswami","Artur Dubrawski"],"abstract":"We introduce TimeSeriesExamAgent, a scalable and domain-agnostic framework for automatically generating and validating time series reasoning benchmarks. Existing benchmarks lack scalability, are limited to a few specific domains, while building them remains labor intensive. Automated solutions for benchmark creation have been proposed, but these typically rely on a single-step generation process without verification, leading to lower-quality exams. Our framework addresses these limitations by enabling stakeholders—such as institutions with highly confidential data—to easily construct high-quality, domain-specific benchmarks from their own private datasets. A domain expert provides a dataset, a natural language description, and a simple data-loading method. The agent then orchestrates the generation pipeline, including creating question templates, robustness verification from multiple perspectives, and iterative refinement. We demonstrate the framework on two medical datasets and evaluate multiple state-of-the-art language models on the generated benchmarks. Empirically, we demonstrate that the framework produces domain-agnostic benchmarks whose diversity matches human-generated counterparts, and our evaluation of several Large Language Models shows that accuracy remains limited, underscoring open challenges in time-series reasoning.","published":"2025-09-03T00:23:32+00:00","updated":"2025-12-01T19:45:02+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=7DFZ9OzM6T","openreview_url":"https://openreview.net/forum?id=7DFZ9OzM6T","pdf_url":"https://openreview.net/pdf?id=7DFZ9OzM6T","comment":"TS4H NeurIPS 2025 Poster","journal_ref":"TS4H NeurIPS 2025 Poster","doi":"","venue":"TS4H NeurIPS 2025 Poster","venue_id":"NeurIPS.cc/2025/Workshop/TS4H","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2509.02547","versioned_id":"2509.02547v5","title":"The Landscape of Agentic Reinforcement Learning for LLMs: A Survey","authors":["Guibin Zhang","Hejia Geng","Xiaohang Yu","Zhenfei Yin","Zaibin Zhang","Zelin Tan","Heng Zhou","Zhongzhi Li","Xiangyuan Xue","Yijiang Li","Yifan Zhou","Yang Chen","Chen Zhang","Yutao Fan","Zihu Wang","Songtao Huang","Francisco Piedrahita-Velez","Yue Liao","Hongru Wang","Mengyue Yang","Heng Ji","Jun Wang","Shuicheng Yan","Philip Torr","Lei Bai"],"abstract":"The emergence of agentic reinforcement learning (Agentic RL) marks a paradigm shift from conventional reinforcement learning applied to large language models (LLM RL), reframing LLMs from passive sequence generators into autonomous, decision-making agents embedded in complex, dynamic worlds. This survey formalizes this conceptual shift by contrasting the degenerate single-step Markov Decision Processes (MDPs) of LLM-RL with the temporally extended, partially observable Markov decision processes (POMDPs) that define Agentic RL. Building on this foundation, we propose a comprehensive twofold taxonomy: one organized around core agentic capabilities, including planning, tool use, memory, reasoning, self-improvement, and perception, and the other around their applications across diverse task domains. Central to our thesis is that reinforcement learning serves as the critical mechanism for transforming these capabilities from static, heuristic modules into adaptive, robust agentic behavior. To support and accelerate future research, we consolidate the landscape of open-source environments, benchmarks, and frameworks into a practical compendium. By synthesizing over five hundred recent works, this survey charts the contours of this rapidly evolving field and highlights the opportunities and challenges that will shape the development of scalable, general-purpose AI agents.","published":"2025-09-02T17:46:26Z","updated":"2026-04-17T18:09:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.02547v5","pdf_url":"https://arxiv.org/pdf/2509.02547v5","comment":"Published on Transactions on Machine Learning Research: https://openreview.net/forum?id=RY19y2RI1O","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=RY19y2RI1O","openreview_venues":["Accepted by TMLR"]},{"id":"openreview:sNjos7jJxb","versioned_id":"sNjos7jJxb","title":"InternAgent-MLE: Navigating Fine-Grained Optimization for Coding Agent","authors":["Shangheng Du","Xiangchao Yan","Dengyang Jiang","Jiakang Yuan","Yusong Hu","Xin Li","Liang He","Bo Zhang","LEI BAI"],"abstract":"Large language models (LLMs) have shown impressive performance in general programming tasks. However, in Machine Learning Engineering (MLE) scenarios such as AutoML and Kaggle competitions, achieving high performance depends heavily on expert intervention and repeated adjustments rather than simply generating correct code. When applied directly to these tasks, LLMs often lack fine-grained domain priors, and existing MLE approaches that use linear or tree-structured searches limit knowledge transfer to adjacent hierarchical links. As a result, they cannot leverage past full trajectories or share information across branches, limiting self-evolving ability and search-space diversity. To address these limitations, we introduce InternAgent-MLE, an LLM-based coding agent that integrates a domain knowledge base for high-quality prior guidance and Monte Carlo Graph Search (MCGS) for efficient exploration. MCGS retains the tree-guided exploration of MCTS while embedding a graph structure into the expansion stage to enable dynamic path reorganization, historical trajectory reuse, and multi-solution fusion to support both self-evolution and collaborative learning. Combined with fine-grained operator sets, this design improves stability and accelerates convergence. Evaluation on the MLE-Bench shows that InternAgent-MLE achieves state-of-the-art performance in numerous dimensions, such as the average medal rate and valid submission rate, under a 12-hour budget (half the standard runtime).","published":"2025-09-02T16:27:31+00:00","updated":"2026-02-11T10:13:23+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=sNjos7jJxb","openreview_url":"https://openreview.net/forum?id=sNjos7jJxb","pdf_url":"https://openreview.net/pdf?id=sNjos7jJxb","comment":"Submitted to ICLR 2026","journal_ref":"Submitted to ICLR 2026","doi":"","venue":"Submitted to ICLR 2026","venue_id":"ICLR.cc/2026/Conference/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:9BKg0BAWrb","versioned_id":"9BKg0BAWrb","title":"K²-Agent: Co-Evolving Know-What and Know-How for Hierarchical Mobile Device Control","authors":["Zhe Wu","Donglin Mo","Hongjin Lu","Junliang Xing","Jianheng Liu","Yuheng Jing","Kai Li","Kun Shao","Jianye HAO","Yuanchun Shi"],"abstract":"Existing mobile device control agents often perform poorly when solving complex tasks requiring long-horizon planning and precise operations, typically due to a lack of relevant task experience or unfamiliarity with skill execution. We propose $\\textbf{K²-Agent}$, a hierarchical framework that models human-like cognition by separating and co-evolving declarative (\"knowing what\") and procedural (\"knowing how\") knowledge for planning and execution. K²-Agent’s high level reasoner is bootstrapped from a single demonstration per task and runs a Summarize–Reflect–Locate–Revise (SRLR) loop to distill and iteratively refine task-level declarative knowledge through self-evolution. The low-level executor is trained with our curriculum-guided Group Relative Policy Optimization (C-GRPO), which (i) constructs a balanced sample pool using decoupled reward signals and (ii) employs dynamic demonstration injection to guide the model in autonomously generating successful trajectories for training. On the challenging AndroidWorld benchmark, K$^2$-Agent achieves a new $\\textbf{state of the art}$ with $\\textbf{76.1\\% success rate}$, ranking $\\textbf{1st}$ among all methods $\\textbf{using only raw screenshots and open-source backbones}$. Furthermore, K²-Agent shows powerful dual generalization: its high-level declarative knowledge transfers across diverse base models, while its low-level procedural skills achieve competitive performance on unseen tasks in ScreenSpot-v2 and Android-in-the-Wild (AitW).","published":"2025-09-02T15:16:37+00:00","updated":"2026-04-11T03:07:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9BKg0BAWrb","openreview_url":"https://openreview.net/forum?id=9BKg0BAWrb","pdf_url":"https://openreview.net/pdf?id=9BKg0BAWrb","comment":"ICLR 2026 Poster","journal_ref":"ICLR 2026 Poster","doi":"","venue":"ICLR 2026 Poster","venue_id":"ICLR.cc/2026/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:j5VXzWyoyW","versioned_id":"j5VXzWyoyW","title":"MAS-ZERO: Designing Multi-Agent Systems with Zero Supervision","authors":["Zixuan Ke","Austin Xu","Yifei Ming","Xuan-Phi Nguyen","Caiming Xiong","Shafiq Joty"],"abstract":"Multi-agent systems (MAS) leveraging the impressive capabilities of Large Language Models (LLMs) hold significant potential for tackling complex tasks. However, most current MAS depend on manually designed agent roles and communication protocols. These manual designs often fail to align with the underlying LLMs’ strengths and struggle to adapt to novel tasks. Recent automatic MAS approaches attempt to mitigate these limitations but typically necessitate a validation set for tuning and yield static MAS designs lacking adaptability during inference. We introduce MAS-ZERO, the first self-evolved, inference-time framework for automatic MAS design. MAS-ZERO employs meta-level design to iteratively generate, evaluate, and refine MAS configurations tailored to each problem instance, without requiring a validation set. Critically, it enables dynamic agent composition and problem decomposition through meta-feedback on solvability and completeness. Experiments across math, graduate-level QA, and coding benchmarks, using both closed-source and open-source LLM backbones of varying sizes, demonstrate that MAS-ZERO outperforms both manual and automatic MAS baselines, achieving a 7.44% average accuracy improvement over the next strongest baseline while maintaining cost-efficiency. These findings underscore the promise of meta-level self-evolution in MAS design.","published":"2025-09-01T19:24:22+00:00","updated":"2025-11-01T00:00:38+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=j5VXzWyoyW","openreview_url":"https://openreview.net/forum?id=j5VXzWyoyW","pdf_url":"https://openreview.net/pdf?id=j5VXzWyoyW","comment":"SEA @ NeurIPS 2025 Oral","journal_ref":"SEA @ NeurIPS 2025 Oral","doi":"","venue":"SEA @ NeurIPS 2025 Oral","venue_id":"NeurIPS.cc/2025/Workshop/SEA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2509.01517","versioned_id":"2509.01517v1","title":"Agentic Workflow for Education: Concepts and Applications","authors":["Yuan-Hao Jiang","Yijie Lu","Ling Dai","Jiatong Wang","Ruijia Li","Bo Jiang"],"abstract":"With the rapid advancement of Large Language Models (LLMs) and Artificial Intelligence (AI) agents, agentic workflows are showing transformative potential in education. This study introduces the Agentic Workflow for Education (AWE), a four-component model comprising self-reflection, tool invocation, task planning, and multi-agent collaboration. We distinguish AWE from traditional LLM-based linear interactions and propose a theoretical framework grounded in the von Neumann Multi-Agent System (MAS) architecture. Through a paradigm shift from static prompt-response systems to dynamic, nonlinear workflows, AWE enables scalable, personalized, and collaborative task execution. We further identify four core application domains: integrated learning environments, personalized AI-assisted learning, simulation-based experimentation, and data-driven decision-making. A case study on automated math test generation shows that AWE-generated items are statistically comparable to real exam questions, validating the model's effectiveness. AWE offers a promising path toward reducing teacher workload, enhancing instructional quality, and enabling broader educational innovation.","published":"2025-09-01T14:39:48Z","updated":"2025-09-01T14:39:48Z","categories":["cs.CY","cs.AI","cs.ET"],"primary_category":"cs.CY","arxiv_url":"https://arxiv.org/abs/2509.01517v1","pdf_url":"https://arxiv.org/pdf/2509.01517v1","comment":"Proceedings of the 33rd International Conference on Computers in Education (ICCE 2025). Asia-Pacific Society for Computers in Education","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:a7KnxfecyP","versioned_id":"a7KnxfecyP","title":"Financial TimeSeries Reasoning Benchmarks at Scale","authors":["Malgorzata Gwiazda","Yifu Cai","Mononito Goswami","Artur Dubrawski"],"abstract":"We introduce TimeSeriesExamAgent, a scalable and domain-agnostic framework for automatically generating and validating time series reasoning benchmarks. Existing benchmarks lack scalability, are limited to a few specific domains, while building them remains labor intensive. Automated solutions for benchmark creation have been proposed, but these typically rely on a single-step generation process without verification, leading to lower-quality exams. Our framework addresses these limitations by enabling stakeholders—such as financial institutions with highly confidential data—to easily construct high-quality, domain-specific benchmarks from their own private datasets. A domain expert provides a dataset, a natural language description, and a simple data-loading method. The agent then orchestrates the generation pipeline, including creating question templates, robustness verification from multiple perspectives, and iterative refinement. We demonstrate the framework on financial datasets and evaluate multiple state-of-the-art language models on the generated benchmarks. Empirically, we demonstrate that the framework produces domain-agnostic benchmarks whose diversity matches human-generated counterparts, and our evaluation of several Large Language Models shows that accuracy remains limited, underscoring open challenges in time-series reasoning.","published":"2025-09-01T05:31:19+00:00","updated":"2026-01-14T18:01:17+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=a7KnxfecyP","openreview_url":"https://openreview.net/forum?id=a7KnxfecyP","pdf_url":"https://openreview.net/pdf?id=a7KnxfecyP","comment":"GenAI in Finance Poster","journal_ref":"GenAI in Finance Poster","doi":"","venue":"GenAI in Finance Poster","venue_id":"NeurIPS.cc/2025/Workshop/GenAI_in_Finance","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:heYWeCpOlS","versioned_id":"heYWeCpOlS","title":"Uncertainty-Aware Role-Switching Debate: Improving Truthfulness in Large Language Models","authors":["Zixuan Liu","Siavash H. Khajavi","Guangkai Jiang","Xinru Liu"],"abstract":"Large language models (LLMs) can produce fluent but incorrect answers, highlighting a need for methods to improve their truthfulness. Debate among AI agents has been proposed as an alignment strategy to address this challenge. In a debate framework, two LLM “debaters” argue for opposing answers to a question and a judge decides which answer is correct. However, existing debate protocols suffer from issues like agents never switching sides, and a lack of uncertainty disclosure that incentivizes overconfident bluffing. We propose an $\\textbf{Uncertainty-Aware Role-Switching Debate}$ protocol to address these limitations. In our protocol, two powerful LLM debaters engage in a structured five-phase debate: they present initial answers, cross-examine each other to pinpoint errors, swap roles mid-debate to argue the opposite side, and then each explicitly report their confidence and uncertainties before a final verdict by a separate judge model. This novel debate format encourages honest self-reflection and forces each model to confront the opponent’s viewpoint. We evaluate our approach on the OpenBookQA science QA benchmark. Without any fine-tuning or external knowledge, the debate-enhanced LLM achieves 74.3\\% accuracy, substantially higher than a single-model baseline. Ablation experiments confirm that both the role-switch and uncertainty-reporting phases significantly boost performance. Qualitative analyses further illustrate that our protocol helps expose deceptive arguments and guide the judge toward correct answers. Overall, our results demonstrate that incorporating uncertainty awareness and role-switching in debates can make LLMs more truthful and reliable, offering a promising new avenue for AI alignment.","published":"2025-08-31T22:25:44+00:00","updated":"2025-10-16T02:52:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=heYWeCpOlS","openreview_url":"https://openreview.net/forum?id=heYWeCpOlS","pdf_url":"https://openreview.net/pdf?id=heYWeCpOlS","comment":"Agents4Science","journal_ref":"Agents4Science","doi":"","venue":"Agents4Science","venue_id":"Agents4Science/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2509.00987","versioned_id":"2509.00987v1","title":"Causal MAS: A Survey of Large Language Model Architectures for Discovery and Effect Estimation","authors":["Adib Bazgir","Amir Habibdoust","Yuwen Zhang","Xing Song"],"abstract":"Large Language Models (LLMs) have demonstrated remarkable capabilities in various reasoning and generation tasks. However, their proficiency in complex causal reasoning, discovery, and estimation remains an area of active development, often hindered by issues like hallucination, reliance on spurious correlations, and difficulties in handling nuanced, domain-specific, or personalized causal relationships. Multi-agent systems, leveraging the collaborative or specialized abilities of multiple LLM-based agents, are emerging as a powerful paradigm to address these limitations. This review paper explores the burgeoning field of causal multi-agent LLMs. We examine how these systems are designed to tackle different facets of causality, including causal reasoning and counterfactual analysis, causal discovery from data, and the estimation of causal effects. We delve into the diverse architectural patterns and interaction protocols employed, from pipeline-based processing and debate frameworks to simulation environments and iterative refinement loops. Furthermore, we discuss the evaluation methodologies, benchmarks, and diverse application domains where causal multi-agent LLMs are making an impact, including scientific discovery, healthcare, fact-checking, and personalized systems. Finally, we highlight the persistent challenges, open research questions, and promising future directions in this synergistic field, aiming to provide a comprehensive overview of its current state and potential trajectory.","published":"2025-08-31T20:48:31Z","updated":"2025-08-31T20:48:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.00987v1","pdf_url":"https://arxiv.org/pdf/2509.00987v1","comment":"24 pages. 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:dfPQrg1WA5","versioned_id":"dfPQrg1WA5","title":"EVOLVE-MEM: A Self-Adaptive Hierarchical Memory Architecture for Next-Generation Agentic AI Systems","authors":["Rishi Ashish Shah","Ujjwal Kakar","Shashvat Singhal","Dinesh K Vishwakarma"],"abstract":"This paper introduces EVOLVE-MEM, a novel self-adaptive hierarchical memory framework designed to overcome the inherent limitations of fixed-size context windows and static memory architectures hindering long-term retention and adaptation in modern AI systems. The architecture is structured around three interconnected tiers: a Dynamic Memory Network leveraging dense semantic storage and embeddings for raw experience ingestion, labeled Level 0; a Hierarchical Memory Manager that organizes these embeddings into multi-level abstractions, utilizing adaptive clustering and large language models: Level 1 generates contextual summaries, and Level 2 extracts high-level principles; and a Self-Improvement Engine continuously monitoring key performance metrics: accuracy, retrieval latency, and coverage to autonomously trigger memory reorganization when thresholds are exceeded, ensuring the system evolves with changing data distributions. The system combines dynamic clustering with empirically tuned similarity thresholds, multi-level retrieval routing, and a robust answer-patching pipeline for post-processing raw LLM outputs to support complex temporal, causal, and multi-hop reasoning tasks with high fidelity and less generic responses. The framework achieves 58.3% overall accuracy, evaluated on the LoCoMo dataset, surpassing SOTA baselines across five reasoning categories. EVOLVE-MEM’s transparent retrieval path tracking, modular design for extensibility, and fully automated adaptation establish a new paradigm for truly agentic AI systems capable of sustained operation and continuous learning in complex, dynamic environments.","published":"2025-08-30T19:06:49+00:00","updated":"2025-10-20T11:20:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=dfPQrg1WA5","openreview_url":"https://openreview.net/forum?id=dfPQrg1WA5","pdf_url":"https://openreview.net/pdf?id=dfPQrg1WA5","comment":"SEA @ NeurIPS 2025 Poster","journal_ref":"SEA @ NeurIPS 2025 Poster","doi":"","venue":"SEA @ NeurIPS 2025 Poster","venue_id":"NeurIPS.cc/2025/Workshop/SEA","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2509.00510","versioned_id":"2509.00510v1","title":"LLM-Assisted Iterative Evolution with Swarm Intelligence Toward SuperBrain","authors":["Li Weigang","Pedro Carvalho Brom","Lucas Ramson Siefert"],"abstract":"We propose a novel SuperBrain framework for collective intelligence, grounded in the co-evolution of large language models (LLMs) and human users. Unlike static prompt engineering or isolated agent simulations, our approach emphasizes a dynamic pathway from Subclass Brain to Superclass Brain: (1) A Subclass Brain arises from persistent, personalized interaction between a user and an LLM, forming a cognitive dyad with adaptive learning memory. (2) Through GA-assisted forward-backward evolution, these dyads iteratively refine prompts and task performance. (3) Multiple Subclass Brains coordinate via Swarm Intelligence, optimizing across multi-objective fitness landscapes and exchanging distilled heuristics. (4) Their standardized behaviors and cognitive signatures integrate into a Superclass Brain, an emergent meta-intelligence capable of abstraction, generalization and self-improvement. We outline the theoretical constructs, present initial implementations (e.g., UAV scheduling, KU/KI keyword filtering) and propose a registry for cross-dyad knowledge consolidation. This work provides both a conceptual foundation and an architectural roadmap toward scalable, explainable and ethically aligned collective AI.","published":"2025-08-30T14:12:46Z","updated":"2025-08-30T14:12:46Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.00510v1","pdf_url":"https://arxiv.org/pdf/2509.00510v1","comment":"24 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2509.00251","versioned_id":"2509.00251v2","title":"Instruction-Level Weight Shaping: A Framework for Self-Improving AI Agents","authors":["Rimom Costa"],"abstract":"Large language models (LLMs) are fluent but largely static after pre-training; new or shifting knowledge is typically added with retrieval-augmented generation (RAG) or fine-tuning. RAG raises latency and engineering overhead and often fails to integrate facts; prompt engineering is brittle and can conflict with prior knowledge; fine-tuning is costly and risks catastrophic forgetting. We propose Instruction-Level Weight Shaping (ILWS): curated system instructions act as external, auditable pseudo-parameters updated after each session via reflection and user feedback. A Reflection Engine inspects conversation traces, diagnoses reasoning successes and failures, and proposes typed deltas $ΔK=(ΔS,ΔU,ΔT)$ over instructions, user preferences, and tools. Deltas are version-controlled, evaluated with a sliding window of 1-5 star ratings, auto-repaired on first failure, and rolled back on repeated failure. When an edit budget crosses a threshold, the agent compiles a rating-weighted synthetic set and distills matured instruction-space gains into parameters, converting prompt-space improvements into weight-space without downtime. ILWS makes explicit the low-rank shaping induced by context in transformer blocks, preserves governance, and removes per-call retrieval. In enterprise support it increased throughput 2.4-5.0x and cut audited hallucinations by about 80% versus a frozen baseline. In an Adobe Commerce Cloud proof of concept \"L0 Support\", it achieved 4-5x more tickets per hour and about 80% lower time per ticket, with autonomous instruction updates and optional tool synthesis. Because ILWS operates at the instruction layer until controlled distillation, it generalizes to dynamic domains (legal, medical, engineering) requiring adaptive reasoning, tool creation, and low-latency deployment.","published":"2025-08-29T21:34:39Z","updated":"2025-12-20T18:38:07Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2509.00251v2","pdf_url":"https://arxiv.org/pdf/2509.00251v2","comment":"12 pages, 1 figure, 2 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.20931","versioned_id":"2508.20931v2","title":"How Can Input Reformulation Improve Tool Usage Accuracy in a Complex Dynamic Environment? A Study on $τ$-bench","authors":["Venkatesh Mishra","Amir Saeidi","Satyam Raj","Mutsumi Nakamura","Jayanth Srinivasa","Gaowen Liu","Ali Payani","Chitta Baral"],"abstract":"Recent advances in reasoning and planning capabilities of large language models (LLMs) have enabled their potential as autonomous agents capable of tool use in dynamic environments. However, in multi-turn conversational environments like $τ$-bench, these agents often struggle with consistent reasoning, adherence to domain-specific policies, and extracting correct information over a long horizon of tool-calls and conversation. To capture and mitigate these failures, we conduct a comprehensive manual analysis of the common errors occurring in the conversation trajectories. We then experiment with reformulations of inputs to the tool-calling agent for improvement in agent decision making. Finally, we propose the Input-Reformulation Multi-Agent (IRMA) framework, which automatically reformulates user queries augmented with relevant domain rules and tool suggestions for the tool-calling agent to focus on. The results show that IRMA significantly outperforms ReAct, Function Calling, and Self-Reflection by 16.1%, 12.7%, and 19.1%, respectively, in overall pass^5 scores. These findings highlight the superior reliability and consistency of IRMA compared to other methods in dynamic environments.","published":"2025-08-28T15:57:33Z","updated":"2025-09-01T18:05:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.20931v2","pdf_url":"https://arxiv.org/pdf/2508.20931v2","comment":"Accepted to EMNLP 2025 Findings","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=DNLfJbGV6D","openreview_venues":["MTI-LLM @ NeurIPS 2025 Poster"]},{"id":"openreview:JDN0x8eTPm","versioned_id":"JDN0x8eTPm","title":"SIVA: Self-Improving Vulnerability Agent","authors":["Valentin Walischewski","Giulio Zizzo","Kevin N. Webster"],"abstract":"In the ever more digitalized world of today, code vulnerabilities pose a critical threat to our privacy, economy, safety, and infrastructure. Existing automated code vulnerability detection methods suffer from high false positive rates, poor generalization and their inability to adapt to changing vulnerability landscapes. To address these challenges we propose SIVA, a self-improving LLM-based vulnerability detection agent, using memory-guided meta-learning for dynamic prompt optimization. SIVA showed strong learning capabilities, improving its F1 score from 58\\% to 95\\% in $5$ iterations, significantly outperforming previous state-of-the-art multi-agent systems ($\\approx 53\\%$ F1) on real-life vulnerability datasets. Furthermore, SIVA generalized well across 7 programming languages (93\\% F1), successfully transferring learned vulnerability concepts between them.","published":"2025-08-28T15:21:53+00:00","updated":"2025-10-22T15:26:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=JDN0x8eTPm","openreview_url":"https://openreview.net/forum?id=JDN0x8eTPm","pdf_url":"https://openreview.net/pdf?id=JDN0x8eTPm","comment":"NeurIPS 2025 - Reliable ML Workshop","journal_ref":"NeurIPS 2025 - Reliable ML Workshop","doi":"","venue":"NeurIPS 2025 - Reliable ML Workshop","venue_id":"NeurIPS.cc/2025/Workshop/Reliable_ML","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2508.20866","versioned_id":"2508.20866v6","title":"AVIATOR: Towards AI-Agentic Vulnerability Injection Workflow for High-Fidelity, Large-Scale Code Security Dataset","authors":["Amine Lbath","Massih-Reza Amini","Aurelien Delaitre","Vadim Okun"],"abstract":"The increasing complexity of software systems and the sophistication of cyber-attacks have underscored the need for reliable automated software vulnerability detection. Data-driven approaches using deep learning models show promise but critically depend on the availability of large, accurately labeled datasets. Yet existing datasets either suffer from noisy labels, limited vulnerability coverage, or fail to reflect vulnerabilities as they occur in real-world software. This also limits large-scale benchmarking of such solutions. Automated vulnerability injection provides a way to address these limitations, but existing techniques remain limited in coverage, contextual fidelity, or injection success. In this paper, we present AVIATOR, the first AI-agentic vulnerability injection framework. AVIATOR decomposes vulnerability injection into a coordinated workflow of specialized AI agents, tool-based analysis, and iterative self-correction, explicitly mirroring expert reasoning. It integrates RAG and lightweight LoRA-based fine-tuning to produce realistic, category-specific vulnerabilities without relying on handcrafted patterns. Across three benchmarks, AVIATOR achieves high injection fidelity (91-95%) surpassing existing injection techniques in both accuracy and vulnerability coverage. When used for data augmentation to train deep learning-based vulnerability detection (DLVD) models, AVIATOR provides the strongest downstream gains in vulnerability detection. Across models and base datasets, AVIATOR improves average F1 scores by +22% over no augmentation, +25% over VGX, holding the prior best injection success rate, and +3% over VulScribeR, the prior state-of-the-art LLM-based injection model, with +7% higher recall and no precision loss. Its augmented data exhibits the lowest distributional distortion and scales efficiently with <2% syntax rejection at 4.3x lower cost than VulScribeR.","published":"2025-08-28T14:59:39Z","updated":"2026-03-18T15:39:54Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2508.20866v6","pdf_url":"https://arxiv.org/pdf/2508.20866v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.20729","versioned_id":"2508.20729v2","title":"Re4: Scientific Computing Agent with Rewriting, Resolution, Review and Revision","authors":["Ao Cheng","Lei Zhang","Guowei He"],"abstract":"Large language models (LLMs) serve as an active and promising field of generative artificial intelligence and have demonstrated abilities to perform complex tasks in multiple domains, including mathematical and scientific reasoning. In this work, we construct a novel agent framework for solving representative problems in scientific computing. The proposed agent, incorporating a \"rewriting-resolution-review-revision\" logical chain via three reasoning LLMs (functioning as the Consultant, Reviewer, and Programmer, respectively), is integrated in a collaborative and interactive manner. The Consultant module endows the agent with knowledge transfer capabilities to link problems to professional domain insights, thereby rewriting problem descriptions through text augmentation. The Programmer module is responsible for generating and executing well-structured code to deliver the problem resolution. The Reviewer module equips the agent with the capacity for self-debugging and self-refinement through interactive feedback with code runtime outputs. By leveraging the end-to-end review mechanism, the executable code provided by the Programmer attains the iterative revision. A comprehensive evaluation is conducted on the performance of the proposed agent framework in solving partial differential equations (PDEs), ill-conditioned linear systems, and data-driven physical analysis problems. Compared to single-model, this collaborative framework significantly improves the bug-free code generation rate and reduces the occurrence of non-physical solutions, thereby establishing a highly reliable framework for autonomous code generation based on natural language descriptions. The review mechanism improved the average execution success rate of the modern reasoning models. Our code is available at https://github.com/ChengAo21/Re4_Sci_Agent","published":"2025-08-28T12:50:48Z","updated":"2026-03-02T14:14:41Z","categories":["cs.AI","physics.comp-ph"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.20729v2","pdf_url":"https://arxiv.org/pdf/2508.20729v2","comment":"31 pages, 31 figures, Presented at the ICLR 2026 Workshop on AI and Partial Differential Equations (AI&PDE)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PMdr3fQpBE","openreview_venues":["AI&PDE Poster"]},{"id":"openreview:vjUOIIx8lb","versioned_id":"vjUOIIx8lb","title":"MOSAIC: Multi-agent Orchestration for Task-Intelligent Scientific Coding","authors":["Siddeshwar Raghavan","Tanwi Mallick"],"abstract":"We present MOSAIC, a large language model (LLM) based multi-agent framework for tackling complex scientific coding tasks. Unlike general-purpose programming, scientific coding requires rigorous algorithmic reasoning, substantial domain expertise, high numerical precision, extended context management, and the ability to decompose and solve interdependent subproblems under a larger objective. To address these challenges, we design and integrate specialized agents responsible for self-reflection, planning, coding, and debugging inspired by a teacher–student paradigm. This architecture balances open-ended exploration, ensuring executability while maintaining a consolidated context to minimize hallucinations. We evaluate MOSAIC on scientific coding benchmark and show that our framework, together with its specialized agents, outperforms existing approaches in accuracy, robustness, and interpretability.","published":"2025-08-28T02:12:29+00:00","updated":"2025-11-25T12:19:35+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vjUOIIx8lb","openreview_url":"https://openreview.net/forum?id=vjUOIIx8lb","pdf_url":"https://openreview.net/pdf?id=vjUOIIx8lb","comment":"DL4C @ NeurIPS 2025 Poster","journal_ref":"DL4C @ NeurIPS 2025 Poster","doi":"","venue":"DL4C @ NeurIPS 2025 Poster","venue_id":"NeurIPS.cc/2025/Workshop/DL4C","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2508.18684","versioned_id":"2508.18684v2","title":"FALCON: Transforming Cyber Threat Intelligence into Deployable IDS Rules with Self-Reflection","authors":["Shaswata Mitra","Subash Neupane","Martin Duclos","Sudip Mittal","Aritran Piplai","Md Rayhanur Rahman","Edward Zieglar","Shahram Rahimi"],"abstract":"Signature-based Intrusion Detection Systems (IDS) detect malicious activity by matching network or host events against predefined rules. Security analysts manually develop these rules from Cyber Threat Intelligence (CTI). As threats evolve, this manual pipeline faces two bottlenecks. Before authoring a new rule, an analyst must reconcile the incoming CTI with the existing rule base and determine whether to create, update, or retire one. This process is challenging due to the representational differences between the CTI and Rule formats. This gap limits the effectiveness of keyword- and embedding-based search, making rule reconciliation cognitively demanding and, in turn, contributing to \"rule bloat\". Second, automated verification of a new rule is inherently difficult as zero-day threats lack ground truth from simulated testing. Hence, standard metrics cannot prove that a rule semantically adheres to the CTI, and the use of LLMs leads to non-deterministic behavior. To address these challenges, we introduce FALCON, an agentic framework for CTI-grounded rule retrieval, generation, and validation. At its core, a novel CTI-Rule semantic scorer, quantifies the functional alignment between a CTI and a rule; the same signal drives a retriever that surfaces relevant deployed rules and a ground-truth-free validator that scores generated ones. Around it, a generation pipeline produces deployable rules from CTI in real time and refines them through self-reflective syntactic, semantic, and performance validators. Across network (Snort) and host-based (YARA) platforms on a purpose-built CTI-Rule dataset, FALCON attains a mean relevance of 0.72 (approx), with 84% inter-rater agreement among cybersecurity analysts, underscoring the promise of real-time security automation.","published":"2025-08-26T05:08:53Z","updated":"2026-06-23T04:40:30Z","categories":["cs.CR","cs.AI","cs.CL","cs.LG","eess.SY"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2508.18684v2","pdf_url":"https://arxiv.org/pdf/2508.18684v2","comment":"17 pages, 10 figures, 8 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.17778","versioned_id":"2508.17778v2","title":"AgentRAN: An Agentic AI Architecture for Autonomous Control of Open 6G Networks","authors":["Maxime Elkael","Salvatore D'Oro","Leonardo Bonati","Michele Polese","Yunseong Lee","Koichiro Furueda","Tommaso Melodia"],"abstract":"Despite the programmable architecture of Open RAN, today's deployments still rely heavily on static control and manual operations. To move beyond this limitation, we introduce AgentRAN, an AI-native, Open RAN-aligned agentic framework that generates and orchestrates a fabric of distributed AI agents based on natural language intents. Unlike traditional approaches that require explicit programming, AgentRAN's LLM-powered agents interpret natural language intents, negotiate strategies through structured conversations, and orchestrate control loops across the network. AgentRAN instantiates a self-organizing hierarchy of agents that decompose complex intents across time scales (from sub-millisecond to minutes), spatial domains (cell to network-wide), and protocol layers (PHY/MAC to RRC). A central innovation is the AI-RAN Factory, which continuously generates improved agents and algorithms from operational data, transforming the network into a system that evolves its own intelligence. We validate AgentRAN through live 5G experiments, demonstrating dynamic adaptation to changing operator intents across power control and scheduling. Key benefits include transparent decision-making (all agent reasoning is auditable), bootstrapped intelligence (no initial training data required), and continuous self-improvement via the AI-RAN Factory.","published":"2025-08-25T08:18:10Z","updated":"2026-02-02T15:26:07Z","categories":["cs.AI","cs.NI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.17778v2","pdf_url":"https://arxiv.org/pdf/2508.17778v2","comment":"This work has been submitted to the IEEE for possible publication","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:Mc1JTnKQIH","versioned_id":"Mc1JTnKQIH","title":"SkillPuzzler: A Self-Evolving Agentic Framework for Materials and Chemistry Research with Minimal Reliance on Predefined Tools","authors":["Xu Huang","Junwu Chen","Philippe Schwaller","Gerbrand Ceder"],"abstract":"The prevailing “large language model (LLM) + tool-use” paradigm relies on hand-crafted tool interfaces, which constrain an agent’s ability to solve complex problems and hinder the adoption of agents as scientific copilots across the broader research community. We advocate a dynamic, scalable “LLM + skill-acquisition” paradigm and present SkillPuzzler as one concrete instantiation of it. SkillPuzzler combines only 4 specialized agents with 15 general-purpose tools, yet exhibits self-evolution while tackling diverse research tasks in materials science and chemistry. Its behavior is driven by prompt-encoded mindsets tailored to our customized Model Context Protocol (MCP) servers. SkillPuzzler autonomously acquires new skills by learning and adapting knowledge into self-defined tools for problem-solving. It achieves 96.7% accuracy with OpenAI O3 model on our 74-task benchmark and outperforms two baselines by a wide margin, demonstrating the robustness and effectiveness of its self-evolution mechanism.","published":"2025-08-25T05:56:36+00:00","updated":"2025-12-26T09:16:24+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Mc1JTnKQIH","openreview_url":"https://openreview.net/forum?id=Mc1JTnKQIH","pdf_url":"https://openreview.net/pdf?id=Mc1JTnKQIH","comment":"NeurIPS2025-AI4Science Poster","journal_ref":"NeurIPS2025-AI4Science Poster","doi":"","venue":"NeurIPS2025-AI4Science Poster","venue_id":"NeurIPS.cc/2025/Workshop/AI4Science","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2508.17565","versioned_id":"2508.17565v1","title":"TradingGroup: A Multi-Agent Trading System with Self-Reflection and Data-Synthesis","authors":["Feng Tian","Flora D. Salim","Hao Xue"],"abstract":"Recent advancements in large language models (LLMs) have enabled powerful agent-based applications in finance, particularly for sentiment analysis, financial report comprehension, and stock forecasting. However, existing systems often lack inter-agent coordination, structured self-reflection, and access to high-quality, domain-specific post-training data such as data from trading activities including both market conditions and agent decisions. These data are crucial for agents to understand the market dynamics, improve the quality of decision-making and promote effective coordination. We introduce TradingGroup, a multi-agent trading system designed to address these limitations through a self-reflective architecture and an end-to-end data-synthesis pipeline. TradingGroup consists of specialized agents for news sentiment analysis, financial report interpretation, stock trend forecasting, trading style adaptation, and a trading decision making agent that merges all signals and style preferences to produce buy, sell or hold decisions. Specifically, we design self-reflection mechanisms for the stock forecasting, style, and decision-making agents to distill past successes and failures for similar reasoning in analogous future scenarios and a dynamic risk-management model to offer configurable dynamic stop-loss and take-profit mechanisms. In addition, TradingGroup embeds an automated data-synthesis and annotation pipeline that generates high-quality post-training data for further improving the agent performance through post-training. Our backtesting experiments across five real-world stock datasets demonstrate TradingGroup's superior performance over rule-based, machine learning, reinforcement learning, and existing LLM-based trading strategies.","published":"2025-08-25T00:29:58Z","updated":"2025-08-25T00:29:58Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.17565v1","pdf_url":"https://arxiv.org/pdf/2508.17565v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:Cfj7uBu5dy","versioned_id":"Cfj7uBu5dy","title":"Towards Dynamic Benchmarks for Autonomous Materials Discovery","authors":["Shreshth A Malik","Tiarnan Doherty","Panagiotis Tigas","Muhammed Razzak","Aron Walsh","Yarin Gal"],"abstract":"Existing benchmarks for computational materials discovery primarily evaluate static predictive tasks or isolated computational sub-tasks. Such approaches inadequately capture the inherently iterative, exploratory, and often serendipitous nature of scientific discovery. We argue that the research community should shift evaluation practices towards including dynamic benchmarks that more realistically represent materials discovery campaigns. As a concrete example, we propose an open-ended benchmark environment designed to simulate closed-loop discovery, requiring autonomous agents or algorithms to iteratively propose, evaluate, and refine candidates under a constrained evaluation budget. Specifically, it targets the efficient discovery of new thermodynamically stable compounds within chemical systems. Multiple fidelity levels are accommodated, from machine-learned interatomic potentials to density functional theory and experimental validation. This approach emphasizes realistic elements of scientific discovery, such as iterative refinement, adaptive decision-making, handling uncertainty and traversing unknown chemical landscapes.","published":"2025-08-24T10:39:31+00:00","updated":"2025-11-05T01:35:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Cfj7uBu5dy","openreview_url":"https://openreview.net/forum?id=Cfj7uBu5dy","pdf_url":"https://openreview.net/pdf?id=Cfj7uBu5dy","comment":"AI4Mat-NeurIPS-2025 Poster","journal_ref":"AI4Mat-NeurIPS-2025 Poster","doi":"","venue":"AI4Mat-NeurIPS-2025 Poster","venue_id":"NeurIPS.cc/2025/Workshop/AI4Mat","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2508.17281","versioned_id":"2508.17281v2","title":"From Language to Action: A Review of Large Language Models as Autonomous Agents and Tool Users","authors":["Sadia Sultana Chowa","Riasad Alvi","Subhey Sadi Rahman","Md Abdur Rahman","Mohaimenul Azam Khan Raiaan","Md Rafiqul Islam","Mukhtar Hussain","Sami Azam"],"abstract":"The pursuit of human-level artificial intelligence (AI) has significantly advanced the development of autonomous agents and Large Language Models (LLMs). LLMs are now widely utilized as decision-making agents for their ability to interpret instructions, manage sequential tasks, and adapt through feedback. This review examines recent developments in employing LLMs as autonomous agents and tool users and comprises seven research questions. We only used the papers published between 2023 and 2025 in conferences of the A* and A rank and Q1 journals. A structured analysis of the LLM agents' architectural design principles, dividing their applications into single-agent and multi-agent systems, and strategies for integrating external tools is presented. In addition, the cognitive mechanisms of LLM, including reasoning, planning, and memory, and the impact of prompting methods and fine-tuning procedures on agent performance are also investigated. Furthermore, we evaluated current benchmarks and assessment protocols and have provided an analysis of 68 publicly available datasets to assess the performance of LLM-based agents in various tasks. In conducting this review, we have identified critical findings on verifiable reasoning of LLMs, the capacity for self-improvement, and the personalization of LLM-based agents. Finally, we have discussed ten future research directions to overcome these gaps.","published":"2025-08-24T10:02:51Z","updated":"2025-10-28T13:52:29Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.17281v2","pdf_url":"https://arxiv.org/pdf/2508.17281v2","comment":"Submitted to Artificial Intelligence Review for peer review","journal_ref":"Artif. Intell. Rev. (2026)","doi":"10.1007/s10462-025-11471-9","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.19279","versioned_id":"2508.19279v1","title":"FLAIRR-TS -- Forecasting LLM-Agents with Iterative Refinement and Retrieval for Time Series","authors":["Gunjan Jalori","Preetika Verma","Sercan Ö Arık"],"abstract":"Time series Forecasting with large languagemodels (LLMs) requires bridging numericalpatterns and natural language. Effective fore-casting on LLM often relies on extensive pre-processing and fine-tuning.Recent studiesshow that a frozen LLM can rival specializedforecasters when supplied with a carefully en-gineered natural-language prompt, but craft-ing such a prompt for each task is itself oner-ous and ad-hoc. We introduce FLAIRR-TS, atest-time prompt optimization framework thatutilizes an agentic system: a Forecaster-agentgenerates forecasts using an initial prompt,which is then refined by a refiner agent, in-formed by past outputs and retrieved analogs.This adaptive prompting generalizes across do-mains using creative prompt templates andgenerates high-quality forecasts without inter-mediate code generation.Experiments onbenchmark datasets show improved accuracyover static prompting and retrieval-augmentedbaselines, approaching the performance ofspecialized prompts.FLAIRR-TS providesa practical alternative to tuning, achievingstrong performance via its agentic approach toadaptive prompt refinement and retrieval.","published":"2025-08-24T00:57:22Z","updated":"2025-08-24T00:57:22Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.19279v1","pdf_url":"https://arxiv.org/pdf/2508.19279v1","comment":"EMNLP","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=oIF4f7r2y4","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"openreview:w7Q13N2Z29","versioned_id":"w7Q13N2Z29","title":"TimeSeriesExamAgent: Creating TimeSeries Reasoning Benchmarks at Scale","authors":["Malgorzata Gwiazda","Yifu Cai","Mononito Goswami","Artur Dubrawski"],"abstract":"We introduce TimeSeriesExamAgent, a scalable and domain-agnostic framework for automatically generating and validating time series reasoning benchmarks. Existing benchmarks lack scalability, are limited to a few specific domains, while building them remains labor intensive. Automated solutions for benchmark creation have been proposed, but these typically rely on a single-step generation process without verification, leading to lower-quality exams. Our framework addresses these limitations by enabling domain experts to easily create high-quality, domain-specific exams from their own datasets. A domain expert provides a dataset, a natural language description, and a simple data-loading method. The agent then orchestrates the generation pipeline, including creating question templates, robustness verification from multiple perspectives, and iterative refinement. We demonstrate the framework on three datasets from two diverse domains-- healthcare and finance; and evaluate multiple state-of-the-art language models on the exams generated by TimeSeriesExamAgent. Empirically, we demonstrate that the framework produces domain-agnostic benchmarks whose diversity matches human-generated counterparts, and our evaluation of several Large Language Models shows that accuracy remains limited, underscoring open challenges in time-series reasoning.","published":"2025-08-23T04:03:18+00:00","updated":"2025-11-07T12:32:49+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=w7Q13N2Z29","openreview_url":"https://openreview.net/forum?id=w7Q13N2Z29","pdf_url":"https://openreview.net/pdf?id=w7Q13N2Z29","comment":"BERT2S","journal_ref":"BERT2S","doi":"","venue":"BERT2S","venue_id":"NeurIPS.cc/2025/Workshop/BERT2S","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2508.15757","versioned_id":"2508.15757v1","title":"Language-Guided Tuning: Enhancing Numeric Optimization with Textual Feedback","authors":["Yuxing Lu","Yucheng Hu","Nan Sun","Xukai Zhao"],"abstract":"Configuration optimization remains a critical bottleneck in machine learning, requiring coordinated tuning across model architecture, training strategy, feature engineering, and hyperparameters. Traditional approaches treat these dimensions independently and lack interpretability, while recent automated methods struggle with dynamic adaptability and semantic reasoning about optimization decisions. We introduce Language-Guided Tuning (LGT), a novel framework that employs multi-agent Large Language Models to intelligently optimize configurations through natural language reasoning. We apply textual gradients - qualitative feedback signals that complement numerical optimization by providing semantic understanding of training dynamics and configuration interdependencies. LGT coordinates three specialized agents: an Advisor that proposes configuration changes, an Evaluator that assesses progress, and an Optimizer that refines the decision-making process, creating a self-improving feedback loop. Through comprehensive evaluation on six diverse datasets, LGT demonstrates substantial improvements over traditional optimization methods, achieving performance gains while maintaining high interpretability.","published":"2025-08-21T17:55:07Z","updated":"2025-08-21T17:55:07Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.15757v1","pdf_url":"https://arxiv.org/pdf/2508.15757v1","comment":"9 pages, 4 figures, 4 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.15144","versioned_id":"2508.15144v2","title":"Mobile-Agent-v3: Fundamental Agents for GUI Automation","authors":["Jiabo Ye","Xi Zhang","Haiyang Xu","Haowei Liu","Junyang Wang","Zhaoqing Zhu","Ziwei Zheng","Feiyu Gao","Junjie Cao","Zhengxi Lu","Jitong Liao","Qi Zheng","Fei Huang","Jingren Zhou","Ming Yan"],"abstract":"This paper introduces GUI-Owl, a foundational GUI agent model that achieves state-of-the-art performance among open-source end-to-end models on ten GUI benchmarks across desktop and mobile environments, covering grounding, question answering, planning, decision-making, and procedural knowledge. GUI-Owl-7B achieves 66.4 on AndroidWorld and 29.4 on OSWorld. Building on this, we propose Mobile-Agent-v3, a general-purpose GUI agent framework that further improves performance to 73.3 on AndroidWorld and 37.7 on OSWorld, setting a new state-of-the-art for open-source GUI agent frameworks. GUI-Owl incorporates three key innovations: (1) Large-scale Environment Infrastructure: a cloud-based virtual environment spanning Android, Ubuntu, macOS, and Windows, enabling our Self-Evolving GUI Trajectory Production framework. This generates high-quality interaction data via automated query generation and correctness validation, leveraging GUI-Owl to refine trajectories iteratively, forming a self-improving loop. It supports diverse data pipelines and reduces manual annotation. (2) Diverse Foundational Agent Capabilities: by integrating UI grounding, planning, action semantics, and reasoning patterns, GUI-Owl supports end-to-end decision-making and can act as a modular component in multi-agent systems. (3) Scalable Environment RL: we develop a scalable reinforcement learning framework with fully asynchronous training for real-world alignment. We also introduce Trajectory-aware Relative Policy Optimization (TRPO) for online RL, achieving 34.9 on OSWorld. GUI-Owl and Mobile-Agent-v3 are open-sourced at https://github.com/X-PLUG/MobileAgent.","published":"2025-08-21T00:39:12Z","updated":"2025-09-01T05:38:34Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.15144v2","pdf_url":"https://arxiv.org/pdf/2508.15144v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:PPn6XHJa1I","versioned_id":"PPn6XHJa1I","title":"Let’s Try Again: Eliciting Multi-Turn Reasoning in Language Models via Simplistic Feedback","authors":["Licheng Liu","Zihan Wang","Linjie Li","Chenwei Xu","Yiping Lu","Han Liu","Avirup Sil","Manling Li"],"abstract":"Large Language Models (LLMs) are increasingly deployed as agents that solve problems through multi-turn interaction, receiving feedback and refining their reasoning based on users' feedback. However, existing reinforcement learning with verifiable reward (RLVR) methods train them under a single-turn paradigm. As a result, we discovered that models often fail to explore alternative reasoning paths or reflect on prior mistakes, producing repetitive and unadapted responses to feedback. To address this gap, we propose Unary Feedback as Observation (UFO), a framework that conditions policy updates on minimal unary feedback (e.g., “Let’s try again”) after incorrect answers. UFO is simple, compatible with existing single-turn RL setups, and incentivizes self-reflection. To further promote efficient and adaptive reasoning, we design reward structures that encourage \\emph{minimality} (solving in fewer turns) and \\emph{diversity} (exploring alternatives under failure). Experiments show that UFO preserves single-turn performance while improving multi-turn reasoning accuracy by about 14\\%. Crucially, UFO-trained models also generalize beyond their training domain, transferring effectively to out-of-domain tasks across mathematics, STEM, QA, and general knowledge, showing that UFO teaches models self-reflective reasoning that carry over across domains. Beyond these empirical gains, UFO points toward a broader paradigm for building adaptive reasoning agents: one that scales supervision from static datasets, reduces dependence on costly domain-specific feedback, and lays the foundation for more general, self-improving AI systems in open-ended real-world settings.","published":"2025-08-20T17:19:56+00:00","updated":"2025-11-04T19:33:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=PPn6XHJa1I","openreview_url":"https://openreview.net/forum?id=PPn6XHJa1I","pdf_url":"https://openreview.net/pdf?id=PPn6XHJa1I","comment":"MTI-LLM @ NeurIPS 2025 Poster","journal_ref":"MTI-LLM @ NeurIPS 2025 Poster","doi":"","venue":"MTI-LLM @ NeurIPS 2025 Poster","venue_id":"NeurIPS.cc/2025/Workshop/MTI-LLM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"]},{"id":"2508.13382","versioned_id":"2508.13382v1","title":"Datarus-R1: An Adaptive Multi-Step Reasoning LLM for Automated Data Analysis","authors":["Ayoub Ben Chaliah","Hela Dellagi"],"abstract":"We present Datarus-R1-14B, a 14 B-parameter open-weights language model fine-tuned from Qwen 2.5-14B-Instruct to act as a virtual data analyst and graduate-level problem solver. Datarus is trained not on isolated question-answer pairs but on full analytical trajectories including reasoning steps, code execution, error traces, self-corrections, and final conclusions, all captured in a ReAct-style notebook format spanning finance, medicine, numerical analysis, and other quantitative domains. Our training pipeline combines (i) a trajectory-centric synthetic data generator that yielded 144 000 tagged notebook episodes, (ii) a dual-reward framework blending a lightweight tag-based structural signal with a Hierarchical Reward Model (HRM) that scores both single-step soundness and end-to-end coherence, and (iii) a memory-optimized implementation of Group Relative Policy Optimization (GRPO) featuring KV-cache reuse, sequential generation, and reference-model sharding. A cosine curriculum smoothly shifts emphasis from structural fidelity to semantic depth, reducing the format collapse and verbosity that often plague RL-aligned LLMs. A central design choice in Datarus is it dual reasoning interface. In agentic mode the model produces ReAct-tagged steps that invoke Python tools to execute real code; in reflection mode it outputs compact Chain-of-Thought (CoT) traces delimited by <think> and <answer> tags. On demanding postgraduate-level problems, Datarus exhibits an \"AHA-moment\" pattern: it sketches hypotheses, revises them once or twice, and converges avoiding the circular, token-inflating loops common to contemporary systems. Across standard public benchmarks Datarus surpasses similar size models and even reaches the level of larger reasoning models such as QwQ-32B achieving up to 30% higher accuracy on AIME 2024/2025 and LiveCodeBench while emitting 18-49% fewer tokens per solution.","published":"2025-08-18T21:58:18Z","updated":"2025-08-18T21:58:18Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.13382v1","pdf_url":"https://arxiv.org/pdf/2508.13382v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.12685","versioned_id":"2508.12685v3","title":"ToolACE-MT: Non-Autoregressive Generation for Agentic Multi-Turn Interaction","authors":["Xingshan Zeng","Weiwen Liu","Lingzhi Wang","Liangyou Li","Fei Mi","Yasheng Wang","Lifeng Shang","Xin Jiang","Qun Liu"],"abstract":"Agentic task-solving with Large Language Models (LLMs) requires multi-turn, multi-step interactions, often involving complex function calls and dynamic user-agent exchanges. Existing simulation-based data generation methods for such scenarios rely heavily on costly autoregressive interactions between multiple LLM agents, thereby compromising the practical efficiency of agentic data generation. In this paper, we propose ToolACE-MT, a novel Non-Autoregressive Iterative Generation framework for constructing high-quality multi-turn agentic dialogues. ToolACE-MT generates full conversational trajectories through three stages: coarse-grained initialization, iterative refinement, and offline verification. The initialization phase builds a structurally complete yet semantically coarse dialogue skeleton; the iterative refinement phase introduces realistic complexities and continued refinement via mask-and-fill operations; and the offline verification phase ensures correctness and coherence via rule- and model-based checks. Experiments demonstrate that ToolACE-MT enables efficient, effective and generalizable agentic data generation, offering a new paradigm for high-quality data construction in tool-augmented LLM scenarios.","published":"2025-08-18T07:38:23Z","updated":"2026-02-13T08:25:14Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.12685v3","pdf_url":"https://arxiv.org/pdf/2508.12685v3","comment":"Accepted by ICLR2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=KznJt9Fhjc","openreview_venues":["ICLR 2026 Poster"]},{"id":"2508.14111","versioned_id":"2508.14111v2","title":"From AI for Science to Agentic Science: A Survey on Autonomous Scientific Discovery","authors":["Jiaqi Wei","Yuejin Yang","Xiang Zhang","Yuhan Chen","Xiang Zhuang","Zhangyang Gao","Dongzhan Zhou","Guangshuai Wang","Zhiqiang Gao","Juntai Cao","Zijie Qiu","Ming Hu","Chenglong Ma","Shixiang Tang","Junjun He","Chunfeng Song","Xuming He","Qiang Zhang","Chenyu You","Shuangjia Zheng","Ning Ding","Wanli Ouyang","Nanqing Dong","Yu Cheng","Siqi Sun","Lei Bai","Bowen Zhou"],"abstract":"Artificial intelligence (AI) is reshaping scientific discovery, evolving from specialized computational tools into autonomous research partners. We position Agentic Science as a pivotal stage within the broader AI for Science paradigm, where AI systems progress from partial assistance to full scientific agency. Enabled by large language models (LLMs), multimodal systems, and integrated research platforms, agentic AI shows capabilities in hypothesis generation, experimental design, execution, analysis, and iterative refinement -- behaviors once regarded as uniquely human. This survey provides a domain-oriented review of autonomous scientific discovery across life sciences, chemistry, materials science, and physics. We unify three previously fragmented perspectives -- process-oriented, autonomy-oriented, and mechanism-oriented -- through a comprehensive framework that connects foundational capabilities, core processes, and domain-specific realizations. Building on this framework, we (i) trace the evolution of AI for Science, (ii) identify five core capabilities underpinning scientific agency, (iii) model discovery as a dynamic four-stage workflow, (iv) review applications across the above domains, and (v) synthesize key challenges and future opportunities. This work establishes a domain-oriented synthesis of autonomous scientific discovery and positions Agentic Science as a structured paradigm for advancing AI-driven research.","published":"2025-08-18T05:25:54Z","updated":"2025-10-20T06:07:37Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.14111v2","pdf_url":"https://arxiv.org/pdf/2508.14111v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.13201","versioned_id":"2508.13201v3","title":"Benchmarking LLM-based agents for single-cell omics analysis","authors":["Yang Liu","Lu Zhou","Xiawei Du","Ruikun He","Xuguang Zhang","Rongbo Shen","Yixue Li"],"abstract":"Background: The surge in single-cell omics data exposes limitations in traditional, manually defined analysis workflows. AI agents offer a paradigm shift, enabling adaptive planning, executable code generation, traceable decisions, and real-time knowledge fusion. However, the lack of a comprehensive benchmark critically hinders progress. Results: We introduce a novel benchmarking evaluation system to rigorously assess agent capabilities in single-cell omics analysis. This system comprises: a unified platform compatible with diverse agent frameworks and LLMs; multidimensional metrics assessing cognitive program synthesis, collaboration, execution efficiency, bioinformatics knowledge integration, and task completion quality; and 50 diverse real-world single-cell omics analysis tasks spanning multi-omics, species, and sequencing technologies. Our evaluation reveals that Grok3-beta achieves state-of-the-art performance among tested agent frameworks. Multi-agent frameworks significantly enhance collaboration and execution efficiency over single-agent approaches through specialized role division. Attribution analyses of agent capabilities identify that high-quality code generation is crucial for task success, and self-reflection has the most significant overall impact, followed by retrieval-augmented generation (RAG) and planning. Conclusions: This work highlights persistent challenges in code generation, long-context handling, and context-aware knowledge retrieval, providing a critical empirical foundation and best practices for developing robust AI agents in computational biology.","published":"2025-08-16T04:26:18Z","updated":"2026-03-16T09:24:30Z","categories":["q-bio.GN","cs.AI","cs.MA"],"primary_category":"q-bio.GN","arxiv_url":"https://arxiv.org/abs/2508.13201v3","pdf_url":"https://arxiv.org/pdf/2508.13201v3","comment":"please see clear figures in this version. 6 main figures; 13 supplementary figures","journal_ref":"","doi":"10.1186/s13059-026-03998-z","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:z91EvZbSI1","versioned_id":"z91EvZbSI1","title":"LLM4FL: Multi-Agent Repository-Level Software Fault Localization via Graph-Based Retrieval and Iterative Refinement","authors":[],"abstract":"Locating and fixing software faults is a time-consuming and resource-intensive task in software development. Traditional fault localization methods, such as Spectrum-Based Fault Localization (SBFL), rely on statistical analysis of test coverage data but often lack accuracy. While more effective, learning-based techniques require large training datasets and can be computationally intensive. Recent advancements in Large Language Models (LLMs) have shown potential for improving fault localization by enhancing code comprehension and reasoning. LLMs are typically pretrained and can be leveraged for fault localization without additional training. However, these LLM-based techniques face challenges, including token limitations, performance degradation with long inputs, and difficulties managing large-scale projects with complex, interacting components. We introduce LLM4FL, a multi-LLM-agent-based fault localization approach to address these challenges. LLM4FL utilizes three agents. First, the Context Extraction Agent uses an order-aware division strategy to divide and analyze extensive coverage data into small groups within the LLM's token limit, identify the failure reason, and prioritize failure-related methods. The prioritized methods are sent to the Debugger Agent, which uses graph-based retrieval to identify failure reasons and rank suspicious methods in the codebase. Then the Reviewer Agent re-evaluates and re-ranks buggy methods using verbal reinforcement learning and self-criticism. Evaluated on the Defects4J (V2.0.0) benchmark of 675 faults from 14 Java projects, LLM4FL outperforms AutoFL by 18.55% in Top-1 accuracy and surpasses supervised methods like DeepFL and Grace, all without task-specific training. Coverage splitting and prompt chaining further improve performance, boosting Top-1 accuracy by up to 22%.","published":"2025-08-14T16:06:49+00:00","updated":"2025-10-28T13:06:54+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=z91EvZbSI1","openreview_url":"https://openreview.net/forum?id=z91EvZbSI1","pdf_url":"https://openreview.net/pdf?id=z91EvZbSI1","comment":"Rejected by TMLR","journal_ref":"Rejected by TMLR","doi":"","venue":"Rejected by TMLR","venue_id":"TMLR/Rejected","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":85,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号"]},{"id":"2508.10428","versioned_id":"2508.10428v1","title":"SC2Arena and StarEvolve: Benchmark and Self-Improvement Framework for LLMs in Complex Decision-Making Tasks","authors":["Pengbo Shen","Yaqing Wang","Ni Mu","Yao Luan","Runpeng Xie","Senhao Yang","Lexiang Wang","Hao Hu","Shuang Xu","Yiqin Yang","Bo Xu"],"abstract":"Evaluating large language models (LLMs) in complex decision-making is essential for advancing AI's ability for strategic planning and real-time adaptation. However, existing benchmarks for tasks like StarCraft II fail to capture the game's full complexity, such as its complete game context, diverse action spaces, and all playable races. To address this gap, we present SC2Arena, a benchmark that fully supports all playable races, low-level action spaces, and optimizes text-based observations to tackle spatial reasoning challenges. Complementing this, we introduce StarEvolve, a hierarchical framework that integrates strategic planning with tactical execution, featuring iterative self-correction and continuous improvement via fine-tuning on high-quality gameplay data. Its key components include a Planner-Executor-Verifier structure to break down gameplay, and a scoring system for selecting high-quality training samples. Comprehensive analysis using SC2Arena provides valuable insights into developing generalist agents that were not possible with previous benchmarks. Experimental results also demonstrate that our proposed StarEvolve achieves superior performance in strategic planning. Our code, environment, and algorithms are publicly available.","published":"2025-08-14T07:58:01Z","updated":"2025-08-14T07:58:01Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2508.10428v1","pdf_url":"https://arxiv.org/pdf/2508.10428v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.10177","versioned_id":"2508.10177v3","title":"KompeteAI: Accelerated Autonomous Multi-Agent System for End-to-End Pipeline Generation for Machine Learning Problems","authors":["Stepan Kulibaba","Artem Dzhalilov","Roman Pakhomov","Oleg Svidchenko","Alexander Gasnikov","Aleksei Shpilman"],"abstract":"Recent Large Language Model (LLM)-based AutoML systems demonstrate impressive capabilities but face significant limitations such as constrained exploration strategies and a severe execution bottleneck. Exploration is hindered by one-shot methods lacking diversity and Monte Carlo Tree Search (MCTS) approaches that fail to recombine strong partial solutions. The execution bottleneck arises from lengthy code validation cycles that stifle iterative refinement. To overcome these challenges, we introduce KompeteAI, a novel AutoML framework with dynamic solution space exploration. Unlike previous MCTS methods that treat ideas in isolation, KompeteAI introduces a merging stage that composes top candidates. We further expand the hypothesis space by integrating Retrieval-Augmented Generation (RAG), sourcing ideas from Kaggle notebooks and arXiv papers to incorporate real-world strategies. KompeteAI also addresses the execution bottleneck via a predictive scoring model and an accelerated debugging method, assessing solution potential using early stage metrics to avoid costly full-code execution. This approach accelerates pipeline evaluation 6.9 times. KompeteAI outperforms leading methods (e.g., RD-agent, AIDE, and Ml-Master) by an average of 3\\% on the primary AutoML benchmark, MLE-Bench. Additionally, we propose Kompete-bench to address limitations in MLE-Bench, where KompeteAI also achieves state-of-the-art results","published":"2025-08-13T20:29:56Z","updated":"2026-04-22T18:28:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.10177v3","pdf_url":"https://arxiv.org/pdf/2508.10177v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=44pUhNb083","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2508.09486","versioned_id":"2508.09486v2","title":"Video-EM: Event-Centric Episodic Memory for Long-Form Video Understanding","authors":["Yun Wang","Long Zhang","Jingren Liu","Jiaqi Yan","Zhanjie Zhang","Jiahao Zheng","Ao Ma","Run Ling","Xun Yang","Dapeng Wu","Xiangyu Chen","Xuelong Li"],"abstract":"Video Large Language Models (Video-LLMs) have shown strong video understanding, yet their application to long-form videos remains constrained by limited context windows. A common workaround is to compress long videos into a handful of representative frames via retrieval or summarization. However, most existing pipelines score frames in isolation, implicitly assuming that frame-level saliency is sufficient for downstream reasoning. This often yields redundant selections, fragmented temporal evidence, and weakened narrative grounding for long-form video question answering. We present \\textbf{Video-EM}, a training-free, event-centric episodic memory framework that reframes long-form VideoQA as \\emph{episodic event construction} followed by \\emph{memory refinement}. Instead of treating retrieved keyframes as independent visuals, Video-EM employs an LLM as an active memory agent to orchestrate off-the-shelf tools: it first localizes query-relevant moments via multi-grained semantic matching, then groups and segments them into temporally coherent events, and finally encodes each event as a grounded episodic memory with explicit temporal indices and spatio-temporal cues (capturing \\emph{when}, \\emph{where}, \\emph{what}, and involved entities). To further suppress verbosity and noise from imperfect upstream signals, Video-EM integrates a reasoning-driven self-reflection loop that iteratively verifies evidence sufficiency and cross-event consistency, removes redundancy, and adaptively adjusts event granularity. The outcome is a compact yet reliable \\emph{event timeline} -- a minimal but sufficient episodic memory set that can be directly consumed by existing Video-LLMs without additional training or architectural changes.","published":"2025-08-13T04:33:07Z","updated":"2026-03-07T07:00:02Z","categories":["cs.CV","cs.AI","cs.MM"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.09486v2","pdf_url":"https://arxiv.org/pdf/2508.09486v2","comment":"14 pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.07950","versioned_id":"2508.07950v1","title":"FEAT: A Multi-Agent Forensic AI System with Domain-Adapted Large Language Model for Automated Cause-of-Death Analysis","authors":["Chen Shen","Wanqing Zhang","Kehan Li","Erwen Huang","Haitao Bi","Aiying Fan","Yiwen Shen","Hongmei Dong","Ji Zhang","Yuming Shao","Zengjia Liu","Xinshe Liu","Tao Li","Chunxia Yan","Shuanliang Fan","Di Wu","Jianhua Ma","Bin Cong","Zhenyuan Wang","Chunfeng Lian"],"abstract":"Forensic cause-of-death determination faces systemic challenges, including workforce shortages and diagnostic variability, particularly in high-volume systems like China's medicolegal infrastructure. We introduce FEAT (ForEnsic AgenT), a multi-agent AI framework that automates and standardizes death investigations through a domain-adapted large language model. FEAT's application-oriented architecture integrates: (i) a central Planner for task decomposition, (ii) specialized Local Solvers for evidence analysis, (iii) a Memory & Reflection module for iterative refinement, and (iv) a Global Solver for conclusion synthesis. The system employs tool-augmented reasoning, hierarchical retrieval-augmented generation, forensic-tuned LLMs, and human-in-the-loop feedback to ensure legal and medical validity. In evaluations across diverse Chinese case cohorts, FEAT outperformed state-of-the-art AI systems in both long-form autopsy analyses and concise cause-of-death conclusions. It demonstrated robust generalization across six geographic regions and achieved high expert concordance in blinded validations. Senior pathologists validated FEAT's outputs as comparable to those of human experts, with improved detection of subtle evidentiary nuances. To our knowledge, FEAT is the first LLM-based AI agent system dedicated to forensic medicine, offering scalable, consistent death certification while maintaining expert-level rigor. By integrating AI efficiency with human oversight, this work could advance equitable access to reliable medicolegal services while addressing critical capacity constraints in forensic systems.","published":"2025-08-11T13:05:59Z","updated":"2025-08-11T13:05:59Z","categories":["cs.AI","cs.CV","cs.LG","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.07950v1","pdf_url":"https://arxiv.org/pdf/2508.07950v1","comment":"18pages, 6 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.07407","versioned_id":"2508.07407v2","title":"A Comprehensive Survey of Self-Evolving AI Agents: A New Paradigm Bridging Foundation Models and Lifelong Agentic Systems","authors":["Jinyuan Fang","Yanwen Peng","Xi Zhang","Yingxu Wang","Xinhao Yi","Guibin Zhang","Yi Xu","Bin Wu","Siwei Liu","Zihao Li","Zhaochun Ren","Nikos Aletras","Xi Wang","Han Zhou","Zaiqiao Meng"],"abstract":"Recent advances in large language models have sparked growing interest in AI agents capable of solving complex, real-world tasks. However, most existing agent systems rely on manually crafted configurations that remain static after deployment, limiting their ability to adapt to dynamic and evolving environments. To this end, recent research has explored agent evolution techniques that aim to automatically enhance agent systems based on interaction data and environmental feedback. This emerging direction lays the foundation for self-evolving AI agents, which bridge the static capabilities of foundation models with the continuous adaptability required by lifelong agentic systems. In this survey, we provide a comprehensive review of existing techniques for self-evolving agentic systems. Specifically, we first introduce a unified conceptual framework that abstracts the feedback loop underlying the design of self-evolving agentic systems. The framework highlights four key components: System Inputs, Agent System, Environment, and Optimisers, serving as a foundation for understanding and comparing different strategies. Based on this framework, we systematically review a wide range of self-evolving techniques that target different components of the agent system. We also investigate domain-specific evolution strategies developed for specialised fields such as biomedicine, programming, and finance, where optimisation objectives are tightly coupled with domain constraints. In addition, we provide a dedicated discussion on the evaluation, safety, and ethical considerations for self-evolving agentic systems, which are critical to ensuring their effectiveness and reliability. This survey aims to provide researchers and practitioners with a systematic understanding of self-evolving AI agents, laying the foundation for the development of more adaptive, autonomous, and lifelong agentic systems.","published":"2025-08-10T16:07:32Z","updated":"2025-08-31T14:55:05Z","categories":["cs.AI","cs.CL","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.07407v2","pdf_url":"https://arxiv.org/pdf/2508.07407v2","comment":"Github Repo: https://github.com/EvoAgentX/Awesome-Self-Evolving-Agents","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:Ybs0jC08vr","versioned_id":"Ybs0jC08vr","title":"ArtPeer: Artistic Alignment via Reflection-based Prompt Evolution with Simulated Artist","authors":["Kaustubh Kumar","Ashutosh Ranjan","Vivek Srivastava","Shirish Karande"],"abstract":"Art inspiration, whether from a specific artist, artwork, or movement, is a common anchor in text to image generation for artistic alignment. Although recent advances in generative models have led to impressive visual output, they often lack grounding in artistic intent, context, persona, and evolving self-reflection that are hallmarks of human creativity. Their output may drift from the intended artistic and symbolic logic present in the art inspiration due to prompt ambiguity, latent biases, or model hallucinations. We present ArtPeer, a framework for robust artistic alignment that places reflection-guided prompt evolution inside the generation loop. ArtPeer builds simulated artist persona from biographical, stylistic and iconographic knowledge, enabling them to act as domain-specific critics. In a Socratic reflection dialogue, the persona-aligned artist agent questions a generation agent, identifies deviations, and iteratively refines the prompt until both stylistic and conceptual alignment is achieved. We validate the effectiveness of the proposed framework through qualitative and quantitative evaluation in challenging settings. ArtPeer robustly aligns art that is more meaningful and contextually relevant than existing state-of-the-art methods.","published":"2025-08-10T10:40:39+00:00","updated":"2026-06-26T08:14:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=Ybs0jC08vr","openreview_url":"https://openreview.net/forum?id=Ybs0jC08vr","pdf_url":"https://openreview.net/pdf?id=Ybs0jC08vr","comment":"NeurIPS Creative AI Track 2025","journal_ref":"NeurIPS Creative AI Track 2025","doi":"","venue":"NeurIPS Creative AI Track 2025","venue_id":"NeurIPS.cc/2025/Creative_AI_Track","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2508.06960","versioned_id":"2508.06960v1","title":"DatasetResearch: Benchmarking Agent Systems for Demand-Driven Dataset Discovery","authors":["Keyu Li","Mohan Jiang","Dayuan Fu","Yunze Wu","Xiangkun Hu","Dequan Wang","Pengfei Liu"],"abstract":"The rapid advancement of large language models has fundamentally shifted the bottleneck in AI development from computational power to data availability-with countless valuable datasets remaining hidden across specialized repositories, research appendices, and domain platforms. As reasoning capabilities and deep research methodologies continue to evolve, a critical question emerges: can AI agents transcend conventional search to systematically discover any dataset that meets specific user requirements, enabling truly autonomous demand-driven data curation? We introduce DatasetResearch, the first comprehensive benchmark evaluating AI agents' ability to discover and synthesize datasets from 208 real-world demands across knowledge-intensive and reasoning-intensive tasks. Our tri-dimensional evaluation framework reveals a stark reality: even advanced deep research systems achieve only 22% score on our challenging DatasetResearch-pro subset, exposing the vast gap between current capabilities and perfect dataset discovery. Our analysis uncovers a fundamental dichotomy-search agents excel at knowledge tasks through retrieval breadth, while synthesis agents dominate reasoning challenges via structured generation-yet both catastrophically fail on \"corner cases\" outside existing distributions. These findings establish the first rigorous baseline for dataset discovery agents and illuminate the path toward AI systems capable of finding any dataset in the digital universe. Our benchmark and comprehensive analysis provide the foundation for the next generation of self-improving AI systems and are publicly available at https://github.com/GAIR-NLP/DatasetResearch.","published":"2025-08-09T12:15:08Z","updated":"2025-08-09T12:15:08Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.06960v1","pdf_url":"https://arxiv.org/pdf/2508.06960v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=obapzpANpf","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2508.05996","versioned_id":"2508.05996v2","title":"Mediator-Guided Multi-Agent Collaboration among Open-Source Models for Medical Decision-Making","authors":["Kaitao Chen","Mianxin Liu","Daoming Zong","Chaoyue Ding","Shaohao Rui","Yankai Jiang","Mu Zhou","Xiaosong Wang"],"abstract":"Complex medical decision-making involves cooperative workflows operated by different clinicians. Designing AI multi-agent systems can expedite and augment human-level clinical decision-making. Existing multi-agent researches primarily focus on language-only tasks, yet their extension to multimodal scenarios remains challenging. A blind combination of diverse vision-language models (VLMs) can amplify an erroneous outcome interpretation. VLMs in general are less capable in instruction following and importantly self-reflection, compared to large language models (LLMs) of comparable sizes. This disparity largely constrains VLMs' ability in cooperative workflows. In this study, we propose MedOrch, a mediator-guided multi-agent collaboration framework for medical multimodal decision-making. MedOrch employs an LLM-based mediator agent that enables multiple VLM-based expert agents to exchange and reflect on their outputs towards collaboration. We utilize multiple open-source general-purpose and domain-specific VLMs instead of costly GPT-series models, revealing the strength of heterogeneous models. We show that the collaboration within distinct VLM-based agents can surpass the capabilities of any individual agent. We validate our approach on five medical vision question answering benchmarks, demonstrating superior collaboration performance without model training. Our findings underscore the value of mediator-guided multi-agent collaboration in advancing medical multimodal intelligence.","published":"2025-08-08T04:02:10Z","updated":"2025-10-11T07:01:05Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.05996v2","pdf_url":"https://arxiv.org/pdf/2508.05996v2","comment":"14 pages, 4 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.05366","versioned_id":"2508.05366v1","title":"Can Language Models Critique Themselves? Investigating Self-Feedback for Retrieval Augmented Generation at BioASQ 2025","authors":["Samy Ateia","Udo Kruschwitz"],"abstract":"Agentic Retrieval Augmented Generation (RAG) and 'deep research' systems aim to enable autonomous search processes where Large Language Models (LLMs) iteratively refine outputs. However, applying these systems to domain-specific professional search, such as biomedical research, presents challenges, as automated systems may reduce user involvement and misalign with expert information needs. Professional search tasks often demand high levels of user expertise and transparency. The BioASQ CLEF 2025 challenge, using expert-formulated questions, can serve as a platform to study these issues. We explored the performance of current reasoning and nonreasoning LLMs like Gemini-Flash 2.0, o3-mini, o4-mini and DeepSeek-R1. A key aspect of our methodology was a self-feedback mechanism where LLMs generated, evaluated, and then refined their outputs for query expansion and for multiple answer types (yes/no, factoid, list, ideal). We investigated whether this iterative self-correction improves performance and if reasoning models are more capable of generating useful feedback. Preliminary results indicate varied performance for the self-feedback strategy across models and tasks. This work offers insights into LLM self-correction and informs future work on comparing the effectiveness of LLM-generated feedback with direct human expert input in these search systems.","published":"2025-08-07T13:13:19Z","updated":"2025-08-07T13:13:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.05366v1","pdf_url":"https://arxiv.org/pdf/2508.05366v1","comment":"Version as accepted at the BioASQ Lab at CLEF 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.05283","versioned_id":"2508.05283v2","title":"Decision-Making with Deliberation: Meta-reviewing as a Document-grounded Dialogue","authors":["Sukannya Purkayastha","Nils Dycke","Anne Lauscher","Iryna Gurevych"],"abstract":"Meta-reviewing is a pivotal stage in the peer-review process, serving as the final step in determining whether a paper is recommended for acceptance. Prior research on meta-reviewing has treated this as a summarization problem over review reports. However, complementary to this perspective, meta-reviewing is a decision-making process that requires weighing reviewer arguments and placing them within a broader context. Prior research has demonstrated that decision-makers can be effectively assisted in such scenarios via dialogue agents. In line with this framing, we explore the practical challenges for realizing dialog agents that can effectively assist meta-reviewers. Concretely, we first address the issue of data scarcity for training dialogue agents by generating synthetic data using Large Language Models (LLMs) based on a self-refinement strategy to improve the relevance of these dialogues to expert domains. Our experiments demonstrate that this method produces higher-quality synthetic data and can serve as a valuable resource towards training meta-reviewing assistants. Subsequently, we utilize this data to train dialogue agents tailored for meta-reviewing and find that these agents outperform \\emph{off-the-shelf} LLM-based assistants for this task. Finally, we apply our agents in real-world meta-reviewing scenarios and confirm their effectiveness in enhancing the efficiency of meta-reviewing.\\footnote{Code available at: https://github.com/UKPLab/eacl2026-meta-review-as-dialog","published":"2025-08-07T11:27:43Z","updated":"2026-01-21T12:46:28Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2508.05283v2","pdf_url":"https://arxiv.org/pdf/2508.05283v2","comment":"Accepted at EACL Main Conference, 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=RYVFPrWpoO","openreview_venues":["ACL ARR 2025 July Submission","ACL ARR 2025 February Submission"]},{"id":"2508.04482","versioned_id":"2508.04482v1","title":"OS Agents: A Survey on MLLM-based Agents for General Computing Devices Use","authors":["Xueyu Hu","Tao Xiong","Biao Yi","Zishu Wei","Ruixuan Xiao","Yurun Chen","Jiasheng Ye","Meiling Tao","Xiangxin Zhou","Ziyu Zhao","Yuhuai Li","Shengze Xu","Shenzhi Wang","Xinchen Xu","Shuofei Qiao","Zhaokai Wang","Kun Kuang","Tieyong Zeng","Liang Wang","Jiwei Li","Yuchen Eleanor Jiang","Wangchunshu Zhou","Guoyin Wang","Keting Yin","Zhou Zhao","Hongxia Yang","Fan Wu","Shengyu Zhang","Fei Wu"],"abstract":"The dream to create AI assistants as capable and versatile as the fictional J.A.R.V.I.S from Iron Man has long captivated imaginations. With the evolution of (multi-modal) large language models ((M)LLMs), this dream is closer to reality, as (M)LLM-based Agents using computing devices (e.g., computers and mobile phones) by operating within the environments and interfaces (e.g., Graphical User Interface (GUI)) provided by operating systems (OS) to automate tasks have significantly advanced. This paper presents a comprehensive survey of these advanced agents, designated as OS Agents. We begin by elucidating the fundamentals of OS Agents, exploring their key components including the environment, observation space, and action space, and outlining essential capabilities such as understanding, planning, and grounding. We then examine methodologies for constructing OS Agents, focusing on domain-specific foundation models and agent frameworks. A detailed review of evaluation protocols and benchmarks highlights how OS Agents are assessed across diverse tasks. Finally, we discuss current challenges and identify promising directions for future research, including safety and privacy, personalization and self-evolution. This survey aims to consolidate the state of OS Agents research, providing insights to guide both academic inquiry and industrial development. An open-source GitHub repository is maintained as a dynamic resource to foster further innovation in this field. We present a 9-page version of our work, accepted by ACL 2025, to provide a concise overview to the domain.","published":"2025-08-06T14:33:45Z","updated":"2025-08-06T14:33:45Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.04482v1","pdf_url":"https://arxiv.org/pdf/2508.04482v1","comment":"ACL 2025 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.04080","versioned_id":"2508.04080v1","title":"GeoSR: Cognitive-Agentic Framework for Probing Geospatial Knowledge Boundaries via Iterative Self-Refinement","authors":["Jinfan Tang","Kunming Wu","Ruifeng Gongxie","Yuya He","Yuankai Wu"],"abstract":"Recent studies have extended the application of large language models (LLMs) to geographic problems, revealing surprising geospatial competence even without explicit spatial supervision. However, LLMs still face challenges in spatial consistency, multi-hop reasoning, and geographic bias. To address these issues, we propose GeoSR, a self-refining agentic reasoning framework that embeds core geographic principles -- most notably Tobler's First Law of Geography -- into an iterative prediction loop. In GeoSR, the reasoning process is decomposed into three collaborating agents: (1) a variable-selection agent that selects relevant covariates from the same location; (2) a point-selection agent that chooses reference predictions at nearby locations generated by the LLM in previous rounds; and (3) a refine agent that coordinates the iterative refinement process by evaluating prediction quality and triggering further rounds when necessary. This agentic loop progressively improves prediction quality by leveraging both spatial dependencies and inter-variable relationships. We validate GeoSR on tasks ranging from physical-world property estimation to socioeconomic prediction. Experimental results show consistent improvements over standard prompting strategies, demonstrating that incorporating geostatistical priors and spatially structured reasoning into LLMs leads to more accurate and equitable geospatial predictions. The code of GeoSR is available at https://github.com/JinfanTang/GeoSR.","published":"2025-08-06T04:45:34Z","updated":"2025-08-06T04:45:34Z","categories":["cs.AI","stat.OT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.04080v1","pdf_url":"https://arxiv.org/pdf/2508.04080v1","comment":"16 pages, 9 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.04037","versioned_id":"2508.04037v2","title":"Evolving in Tasks: Empowering the Multi-modality Large Language Model as the Computer Use Agent","authors":["Yuhao Cheng","Liang Tang","Shuxian Li","Yukang Huo","Tiaonan Duan","Kaer Huang","Yanzhe Jing","Yiqiang Yan"],"abstract":"Computer use agents represent an emerging area in artificial intelligence, aiming to operate computers autonomously to fulfill user tasks, attracting significant attention from both industry and academia. However, the performance of existing agents remains insufficient for practical deployment. In this paper, we propose the Self-Evolution Agent (SEA) for computer operation, alongside three core innovations in data generation, reinforcement learning, and model enhancement to develop this agent. Specifically, we first design an automatic pipeline to generate verifiable task trajectories for training. Second, we propose Efficient Step-wise Reinforcement Learning to reduce the substantial computational overhead of long-horizon training. Finally, we introduce a model enhancement method that integrates grounding and planning capabilities into a single model without additional training. Leveraging these innovations, our SEA (with only 7B parameters) outperforms existing models of the same parameter scale and achieves performance comparable to larger models (e.g., 32B/72B parameters) on computer use tasks. We plan to release the model weights and related code as open-source resources in the future.","published":"2025-08-06T02:57:22Z","updated":"2026-01-22T05:22:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.04037v2","pdf_url":"https://arxiv.org/pdf/2508.04037v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.03991","versioned_id":"2508.03991v1","title":"Galaxy: A Cognition-Centered Framework for Proactive, Privacy-Preserving, and Self-Evolving LLM Agents","authors":["Chongyu Bao","Ruimin Dai","Yangbo Shen","Runyang Jian","Jinghan Zhang","Xiaolan Liu","Kunpeng Liu"],"abstract":"Intelligent personal assistants (IPAs) such as Siri and Google Assistant are designed to enhance human capabilities and perform tasks on behalf of users. The emergence of LLM agents brings new opportunities for the development of IPAs. While responsive capabilities have been widely studied, proactive behaviors remain underexplored. Designing an IPA that is proactive, privacy-preserving, and capable of self-evolution remains a significant challenge. Designing such IPAs relies on the cognitive architecture of LLM agents. This work proposes Cognition Forest, a semantic structure designed to align cognitive modeling with system-level design. We unify cognitive architecture and system design into a self-reinforcing loop instead of treating them separately. Based on this principle, we present Galaxy, a framework that supports multidimensional interactions and personalized capability generation. Two cooperative agents are implemented based on Galaxy: KoRa, a cognition-enhanced generative agent that supports both responsive and proactive skills; and Kernel, a meta-cognition-based meta-agent that enables Galaxy's self-evolution and privacy preservation. Experimental results show that Galaxy outperforms multiple state-of-the-art benchmarks. Ablation studies and real-world interaction cases validate the effectiveness of Galaxy.","published":"2025-08-06T00:46:38Z","updated":"2025-08-06T00:46:38Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.03991v1","pdf_url":"https://arxiv.org/pdf/2508.03991v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.03404","versioned_id":"2508.03404v2","title":"Visual Document Understanding and Reasoning: A Multi-Agent Collaboration Framework with Agent-Wise Adaptive Test-Time Scaling","authors":["Xinlei Yu","Chengming Xu","Zhangquan Chen","Yudong Zhang","Shilin Lu","Cheng Yang","Jiangning Zhang","Shuicheng Yan","Xiaobin Hu"],"abstract":"The dominant paradigm of monolithic scaling in Vision-Language Models (VLMs) is failing for understanding and reasoning in documents, yielding diminishing returns as it struggles with the inherent need of this domain for document-based procedural reasoning, cognitive complexity, and factual accuracy. To this end, we introduce MACT, a Multi-Agent Collaboration framework with agent-wise adaptive Test-time scaling that pioneers a paradigm shift to procedural scaling, adapting dynamically to the functional entities of visual documents understanding and reasoning. MACT decomposes the visual document processing flow into four specialized agents, i.e., planning, execution, judgment, and answer, to resolve cognitive overload and introduce a critical self-correction loop for factual grounding. This collaborative architecture is amplified by an agent-wise adaptive test-time scaling strategy that intelligently allocates computational resources based on the complexity and redundancy of each functionality. Evaluated on multiple visual document understanding benchmarks, MACT achieves superior performance with a smaller parameter scale, adapting effectively to various document scenarios without compromising its general or mathematical reasoning capabilities. The three variants of MACT consistently attain top-three average performance rankings, with average performance enhancements of 9.9-11.5% over the base models. The source code will be released publicly.","published":"2025-08-05T12:52:09Z","updated":"2025-11-14T06:48:22Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2508.03404v2","pdf_url":"https://arxiv.org/pdf/2508.03404v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.03018","versioned_id":"2508.03018v2","title":"Beyond Policy Optimization: A Data Curation Flywheel for Sparse-Reward Long-Horizon Planning","authors":["Yutong Wang","Pengliang Ji","Kaixin Li","Baolong Bi","Tao Feng","Guillaume Sartoretti"],"abstract":"Large Language Reasoning Models have demonstrated remarkable success on static tasks, yet their application to multi-round agentic planning in interactive environments faces two fundamental challenges. First, the intractable credit assignment problem renders conventional reinforcement learning ineffective in sparse-reward settings. Second, the computational overhead of verbose, step-by-step reasoning histories is prohibitive. To address these challenges, we propose BPO, a three-stage framework (bootstrapping, extrapolation, and refinement) that establishes a self-improving data flywheel to develop robust reasoning models for long-horizon, sparse-reward environments. Our framework first bootstraps efficient reasoning using the proposed planning quaternions with long-short chain-of-thought fusion. It then extrapolates to out-of-distribution tasks through complexity-stratified curriculum learning. Finally, the model iteratively refines itself by learning exclusively on experiences selected via reward-gated rejection sampling. Experiments on ALFWorld, ScienceWorld, and WebShop demonstrate that our approach achieves state-of-the-art with significant token efficiency, providing a new recipe for reasoning models in agentic planning.","published":"2025-08-05T02:56:58Z","updated":"2026-05-16T08:56:03Z","categories":["cs.AI","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.03018v2","pdf_url":"https://arxiv.org/pdf/2508.03018v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=nspo0liU9S","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2508.02959","versioned_id":"2508.02959v2","title":"Polymath: A Self-Optimizing Agent with Dynamic Hierarchical Workflow","authors":["Chia-Tung Ho","Jing Gong","Xufeng Yao","Yunsheng Bai","Abhishek B Akkur","Haoxing Ren"],"abstract":"Large language models (LLMs) excel at solving complex tasks by executing agentic workflows composed of detailed instructions and structured operations. Yet, building general-purpose agents by manually embedding foundation models into agentic systems such as Chain-of-Thought, Self-Reflection, and ReACT through text interfaces limits scalability and efficiency. Recently, many researchers have sought to automate the generation and optimization of these workflows through code-based representations. However, existing methods often rely on labeled datasets to train and optimize workflows, making them ineffective and inflexible for solving real-world, dynamic problems where labeled data is unavailable. To address this challenge, we introduce Polymath, a self-optimizing agent with dynamic hierarchical workflow that leverages the flexibility of task flow graphs and the expressiveness of code-represented workflows to solve a wide range of real-world, dynamic problems. The proposed optimization methodology integrates multi-grid-inspired graph optimization with a self-reflection-guided evolutionary algorithm to refine workflows without labeled data. Experimental results on six benchmark datasets across coding, math, and multi-turn QA tasks show that Polymath achieves 8.1% average improvement over state-of-the-art baselines.","published":"2025-08-04T23:50:02Z","updated":"2025-08-07T01:30:51Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.02959v2","pdf_url":"https://arxiv.org/pdf/2508.02959v2","comment":"18 pages, 12 figures, under review for AAAI2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.02956","versioned_id":"2508.02956v1","title":"Autonomous Inorganic Materials Discovery via Multi-Agent Physics-Aware Scientific Reasoning","authors":["Alireza Ghafarollahi","Markus J. Buehler"],"abstract":"Conventional machine learning approaches accelerate inorganic materials design via accurate property prediction and targeted material generation, yet they operate as single-shot models limited by the latent knowledge baked into their training data. A central challenge lies in creating an intelligent system capable of autonomously executing the full inorganic materials discovery cycle, from ideation and planning to experimentation and iterative refinement. We introduce SparksMatter, a multi-agent AI model for automated inorganic materials design that addresses user queries by generating ideas, designing and executing experimental workflows, continuously evaluating and refining results, and ultimately proposing candidate materials that meet the target objectives. SparksMatter also critiques and improves its own responses, identifies research gaps and limitations, and suggests rigorous follow-up validation steps, including DFT calculations and experimental synthesis and characterization, embedded in a well-structured final report. The model's performance is evaluated across case studies in thermoelectrics, semiconductors, and perovskite oxides materials design. The results demonstrate the capacity of SparksMatter to generate novel stable inorganic structures that target the user's needs. Benchmarking against frontier models reveals that SparksMatter consistently achieves higher scores in relevance, novelty, and scientific rigor, with a significant improvement in novelty across multiple real-world design tasks as assessed by a blinded evaluator. These results demonstrate SparksMatter's unique capacity to generate chemically valid, physically meaningful, and creative inorganic materials hypotheses beyond existing materials knowledge.","published":"2025-08-04T23:40:43Z","updated":"2025-08-04T23:40:43Z","categories":["cond-mat.mtrl-sci","cond-mat.dis-nn","cond-mat.mes-hall","cs.AI","cs.LG"],"primary_category":"cond-mat.mtrl-sci","arxiv_url":"https://arxiv.org/abs/2508.02956v1","pdf_url":"https://arxiv.org/pdf/2508.02956v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.02085","versioned_id":"2508.02085v6","title":"SE-Agent: Self-Evolution Trajectory Optimization in Multi-Step Reasoning with LLM-Based Agents","authors":["Jiaye Lin","Yifu Guo","Yuzhen Han","Sen Hu","Ziyi Ni","Licheng Wang","Mingguang Chen","Hongzhang Liu","Ronghao Chen","Yangfan He","Daxin Jiang","Binxing Jiao","Chen Hu","Huacan Wang"],"abstract":"Large Language Model (LLM)-based agents have recently shown impressive capabilities in complex reasoning and tool use via multi-step interactions with their environments. While these agents have the potential to tackle complicated tasks, their problem-solving process, i.e., agents' interaction trajectory leading to task completion, remains underexploited. These trajectories contain rich feedback that can navigate agents toward the right directions for solving problems correctly. Although prevailing approaches, such as Monte Carlo Tree Search (MCTS), can effectively balance exploration and exploitation, they ignore the interdependence among various trajectories and lack the diversity of search spaces, which leads to redundant reasoning and suboptimal outcomes. To address these challenges, we propose SE-Agent, a Self-Evolution framework that enables Agents to optimize their reasoning processes iteratively. Our approach revisits and enhances former pilot trajectories through three key operations: revision, recombination, and refinement. This evolutionary mechanism enables two critical advantages: (1) it expands the search space beyond local optima by intelligently exploring diverse solution paths guided by previous trajectories, and (2) it leverages cross-trajectory inspiration to efficiently enhance performance while mitigating the impact of suboptimal reasoning paths. Through these mechanisms, SE-Agent achieves continuous self-evolution that incrementally improves reasoning quality. We evaluate SE-Agent on SWE-bench Verified to resolve real-world GitHub issues. Experimental results across five strong LLMs show that integrating SE-Agent delivers up to 55% relative improvement, achieving state-of-the-art performance among all open-source agents on SWE-bench Verified. Our code and demonstration materials are publicly available at https://github.com/JARVIS-Xs/SE-Agent.","published":"2025-08-04T05:51:55Z","updated":"2025-11-03T18:47:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.02085v6","pdf_url":"https://arxiv.org/pdf/2508.02085v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=isATAFP71B","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2508.01285","versioned_id":"2508.01285v2","title":"BioDisco: Multi-agent hypothesis generation with dual-mode evidence, iterative feedback and temporal evaluation","authors":["Yujing Ke","Kevin George","Kathan Pandya","David Blumenthal","Maximilian Sprang","Gerrit Großmann","Sebastian Vollmer","David Antony Selby"],"abstract":"Identifying novel hypotheses is essential to scientific research, yet this process risks being overwhelmed by the sheer volume and complexity of available information. Existing automated methods often struggle to generate novel and evidence-grounded hypotheses, lack robust iterative refinement and rarely undergo rigorous temporal evaluation for future discovery potential. To address this, we propose BioDisco, a multi-agent framework that draws upon language model-based reasoning and a dual-mode evidence system (biomedical knowledge graphs and automated literature retrieval) for grounded novelty, integrates an internal scoring and feedback loop for iterative refinement, and validates performance through pioneering temporal and human evaluations and a Bradley-Terry paired comparison model to provide statistically-grounded assessment. Our evaluations demonstrate superior novelty and significance over ablated configurations and generalist biomedical agents. Designed for flexibility and modularity, BioDisco allows seamless integration of custom language models or knowledge graphs, and can be run with just a few lines of code.","published":"2025-08-02T09:32:52Z","updated":"2025-11-24T16:36:29Z","categories":["cs.AI","cs.IR","stat.AP"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.01285v2","pdf_url":"https://arxiv.org/pdf/2508.01285v2","comment":"12 pages main content, 31 including appendices. 8 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=8SgZKNjmMI","openreview_venues":["Withdrawn by Authors"]},{"id":"2508.05666","versioned_id":"2508.05666v1","title":"HySemRAG: A Hybrid Semantic Retrieval-Augmented Generation Framework for Automated Literature Synthesis and Methodological Gap Analysis","authors":["Alejandro Godinez"],"abstract":"We present HySemRAG, a framework that combines Extract, Transform, Load (ETL) pipelines with Retrieval-Augmented Generation (RAG) to automate large-scale literature synthesis and identify methodological research gaps. The system addresses limitations in existing RAG architectures through a multi-layered approach: hybrid retrieval combining semantic search, keyword filtering, and knowledge graph traversal; an agentic self-correction framework with iterative quality assurance; and post-hoc citation verification ensuring complete traceability. Our implementation processes scholarly literature through eight integrated stages: multi-source metadata acquisition, asynchronous PDF retrieval, custom document layout analysis using modified Docling architecture, bibliographic management, LLM-based field extraction, topic modeling, semantic unification, and knowledge graph construction. The system creates dual data products - a Neo4j knowledge graph enabling complex relationship queries and Qdrant vector collections supporting semantic search - serving as foundational infrastructure for verifiable information synthesis. Evaluation across 643 observations from 60 testing sessions demonstrates structured field extraction achieving 35.1% higher semantic similarity scores (0.655 $\\pm$ 0.178) compared to PDF chunking approaches (0.485 $\\pm$ 0.204, p < 0.000001). The agentic quality assurance mechanism achieves 68.3% single-pass success rates with 99.0% citation accuracy in validated responses. Applied to geospatial epidemiology literature on ozone exposure and cardiovascular disease, the system identifies methodological trends and research gaps, demonstrating broad applicability across scientific domains for accelerating evidence synthesis and discovery.","published":"2025-08-01T20:30:42Z","updated":"2025-08-01T20:30:42Z","categories":["cs.IR","cs.AI","cs.LG"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2508.05666v1","pdf_url":"https://arxiv.org/pdf/2508.05666v1","comment":"47 pages, 10 figures. Code: https://github.com/agodinezmm2007/docling_mod. Demo: https://youtu.be/ZCy5ESJ1gVE?si=K8CttwgTj7yGrWjn. ETL+multi-agent RAG framework for literature synthesis, 35.1% improvement over PDF chunking. Real application: reduced 17,400 papers to 24 relevant ones (99.86%) in 10 minutes for wastewater epidemiology review","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2508.00271","versioned_id":"2508.00271v2","title":"MetaAgent: Toward Self-Evolving Agent via Tool Meta-Learning","authors":["Hongjin Qian","Zheng Liu"],"abstract":"In this work, we propose MetaAgent, an agentic paradigm inspired by the principle of learning-by-doing, where expertise is developed through hands-on practice and continual self-improvement. MetaAgent starts with a minimal workflow, equipped only with basic reasoning and adaptive help-seeking abilities. When a knowledge gap is encountered, MetaAgent generates natural language help requests, which are routed to the most suitable external tool by a dedicated tool router. As MetaAgent solves tasks, it continually conducts self-reflection and answer verification, distilling actionable experience into concise texts that are dynamically incorporated into future task contexts. Besides, MetaAgent autonomously builds in-house tools and a persistent knowledge base by organizing its tool-use history, further enhancing its ability to retrieve and integrate relevant information We term this continual, data-driven process as \\textit{meta tool learning}, through which MetaAgent incrementally refines its reasoning and tool-use strategies, without changing model parameters or requiring further post-training. Evaluated on challenging knowledge discovery benchmarks, including GAIA, WebWalkerQA, and BrowseCamp, MetaAgent consistently outperforms workflow-based baselines and matches or exceeds end-to-end trained agents, demonstrating the promise of self-evolving agentic systems for robust, general-purpose knowledge discovery. We provide our source codes in https://github.com/qhjqhj00/MetaAgent.","published":"2025-08-01T02:30:32Z","updated":"2025-09-01T02:48:41Z","categories":["cs.AI","cs.CL","cs.IR"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2508.00271v2","pdf_url":"https://arxiv.org/pdf/2508.00271v2","comment":"Technical Report, 14 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.21524","versioned_id":"2507.21524v2","title":"Large Language Models for Wireless Communications: From Adaptation to Autonomy","authors":["Le Liang","Hao Ye","Yucheng Sheng","Ouya Wang","Jiacheng Wang","Shi Jin","Geoffrey Ye Li"],"abstract":"The emergence of large language models (LLMs) has revolutionized artificial intelligence, offering unprecedented capabilities in reasoning, generalization, and zero-shot learning. These strengths open new frontiers in wireless communications, where increasing complexity and dynamics demand intelligent and adaptive solutions. This article explores the role of LLMs in transforming wireless systems across three key directions: adapting pretrained LLMs for communication tasks, developing wireless-specific foundation models to balance versatility and efficiency, and enabling agentic LLMs with autonomous reasoning and coordination capabilities. We highlight recent advances, practical case studies, and the unique benefits of LLM-based approaches over traditional methods. Finally, we outline open challenges and research opportunities, including multimodal fusion, collaboration with lightweight models, and self-improving capabilities, charting a path toward intelligent, adaptive, and autonomous wireless networks.","published":"2025-07-29T06:21:10Z","updated":"2026-03-17T07:29:58Z","categories":["cs.AI","cs.IT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.21524v2","pdf_url":"https://arxiv.org/pdf/2507.21524v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.20536","versioned_id":"2507.20536v2","title":"T2I-Copilot: A Training-Free Multi-Agent Text-to-Image System for Enhanced Prompt Interpretation and Interactive Generation","authors":["Chieh-Yun Chen","Min Shi","Gong Zhang","Humphrey Shi"],"abstract":"Text-to-Image (T2I) generative models have revolutionized content creation but remain highly sensitive to prompt phrasing, often requiring users to repeatedly refine prompts multiple times without clear feedback. While techniques such as automatic prompt engineering, controlled text embeddings, denoising, and multi-turn generation mitigate these issues, they offer limited controllability, or often necessitate additional training, restricting the generalization abilities. Thus, we introduce T2I-Copilot, a training-free multi-agent system that leverages collaboration between (Multimodal) Large Language Models to automate prompt phrasing, model selection, and iterative refinement. This approach significantly simplifies prompt engineering while enhancing generation quality and text-image alignment compared to direct generation. Specifically, T2I-Copilot consists of three agents: (1) Input Interpreter, which parses the input prompt, resolves ambiguities, and generates a standardized report; (2) Generation Engine, which selects the appropriate model from different types of T2I models and organizes visual and textual prompts to initiate generation; and (3) Quality Evaluator, which assesses aesthetic quality and text-image alignment, providing scores and feedback for potential regeneration. T2I-Copilot can operate fully autonomously while also supporting human-in-the-loop intervention for fine-grained control. On GenAI-Bench, using open-source generation models, T2I-Copilot achieves a VQA score comparable to commercial models RecraftV3 and Imagen 3, surpasses FLUX1.1-pro by 6.17% at only 16.59% of its cost, and outperforms FLUX.1-dev and SD 3.5 Large by 9.11% and 6.36%. Code will be released at: https://github.com/SHI-Labs/T2I-Copilot.","published":"2025-07-28T05:41:22Z","updated":"2025-07-29T06:16:18Z","categories":["cs.CV","cs.AI","cs.HC"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.20536v2","pdf_url":"https://arxiv.org/pdf/2507.20536v2","comment":"ICCV 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.18812","versioned_id":"2507.18812v1","title":"MemoCoder: Automated Function Synthesis using LLM-Supported Agents","authors":["Yiping Jia","Zhen Ming Jiang","Shayan Noei","Ying Zou"],"abstract":"With the widespread adoption of Large Language Models (LLMs) such as GitHub Copilot and ChatGPT, developers increasingly rely on AI-assisted tools to support code generation. While LLMs can generate syntactically correct solutions for well-structured programming tasks, they often struggle with challenges that require iterative debugging, error handling, or adaptation to diverse problem structures. Existing approaches such as fine-tuning or self-repair strategies either require costly retraining or lack mechanisms to accumulate and reuse knowledge from previous attempts. To address these limitations, we propose MemoCoder, a multi-agent framework that enables collaborative problem solving and persistent learning from past fixes. At the core of MemoCoder is a Fixing Knowledge Set, which stores successful repairs and supports retrieval for future tasks. A central Mentor Agent supervises the repair process by identifying recurring error patterns and refining high-level fixing strategies, providing a novel supervisory role that guides the self-repair loop. We evaluate MemoCoder across three public benchmarks -- MBPP, HumanEval, and LiveCodeBench -- spanning a range of problem complexities. Experimental results show that MemoCoder consistently outperforms both zero-shot prompting and a Self-Repair strategy, with improvements ranging from 3.1% to 12.1% in Pass@10 and from 1.4% to 14.5% in Pass@50, demonstrating its effectiveness in iterative refinement and knowledge-guided code generation.","published":"2025-07-24T21:23:44Z","updated":"2025-07-24T21:23:44Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2507.18812v1","pdf_url":"https://arxiv.org/pdf/2507.18812v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.18742","versioned_id":"2507.18742v1","title":"Specification Self-Correction: Mitigating In-Context Reward Hacking Through Test-Time Refinement","authors":["Víctor Gallego"],"abstract":"Language models (LMs) are susceptible to in-context reward hacking, where they exploit flaws in tainted or faulty written specifications or rubrics to achieve high scores without fulfilling the user's true intent. We introduce Specification Self-Correction (SSC), a novel, test-time framework that enables an LM to identify and correct flaws within its own guiding specification. SSC employs a multi-step inference process where the model first generates a response based on a potentially tainted specification, critiques its output, and then revises the specification itself to remove the exploitable loophole. A final, more robust response is then generated using this self-corrected specification. Across experiments spanning creative writing and agentic coding tasks with several LMs, we demonstrate that while models initially game tainted specifications in 50-70\\% of cases, the SSC process reduces this vulnerability by over 90\\%. This dynamic repair occurs at inference time, requires no weight modification, and leads to more robustly aligned model behavior. Code at https://github.com/vicgalle/specification-self-correction .","published":"2025-07-24T18:44:28Z","updated":"2025-07-24T18:44:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.18742v1","pdf_url":"https://arxiv.org/pdf/2507.18742v1","comment":"Accepted to SCALR Workshop @ COLM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.18190","versioned_id":"2507.18190v2","title":"TN-AutoRCA: Benchmark Construction and Agentic Framework for Self-Improving Alarm-Based Root Cause Analysis in Telecommunication Networks","authors":["Keyu Wu","Qianjin Yu","Manlin Mei","Ruiting Liu","Jun Wang","Kailai Zhang","Yelun Bao"],"abstract":"Root Cause Analysis (RCA) in telecommunication networks is a critical task, yet it presents a formidable challenge for Artificial Intelligence (AI) due to its complex, graph-based reasoning requirements and the scarcity of realistic benchmarks.","published":"2025-07-24T08:40:08Z","updated":"2025-07-28T12:33:37Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.18190v2","pdf_url":"https://arxiv.org/pdf/2507.18190v2","comment":"10 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=s5mwg63B02","openreview_venues":["Submitted to ICLR 2026"]},{"id":"2507.17442","versioned_id":"2507.17442v3","title":"Confident RAG: Enhancing the Performance of LLMs for Mathematics Question Answering through Multi-Embedding and Confidence Scoring","authors":["Shiting Chen","Zijian Zhao","Jinsong Chen"],"abstract":"Large Language Models (LLMs) hold significant promise for mathematics education, yet they often struggle with complex mathematical reasoning. While Retrieval-Augmented Generation (RAG) mitigates these issues by grounding LLMs in external knowledge, its effectiveness remains unstable, heavily dependent on the choice of a single embedding model. Moving beyond static RAG workflows, we draw on agentic workflow patterns, a paradigm that introduces structured task decomposition and collaboration to enhance system performance. We propose and examine two novel approaches that combine the benefits of multiple embedding models. While our Mixture-Embedding RAG approach (fusing retrieved documents) shows limited gains, our Confident RAG method (generating multiple answers and selecting the one with the highest confidence score) demonstrates significant improvement. Experimental results show that Confident RAG achieved average accuracy improvements of approximately 10% over vanilla LLMs and 5% over vanilla RAG. The consistent results across different LLMs and embedding models indicate that Confident RAG is an efficient plug-and-play solution for trustworthy mathematical AI assistants. Finally, we discuss how this work lays the groundwork for deploying Agentic RAG systems in educational settings, where autonomous planning and iterative refinement can be built upon our robust retrieval foundation.","published":"2025-07-23T12:03:54Z","updated":"2025-11-30T16:05:05Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.17442v3","pdf_url":"https://arxiv.org/pdf/2507.17442v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.17131","versioned_id":"2507.17131v2","title":"Enabling Self-Improving Agents to Learn at Test Time With Human-In-The-Loop Guidance","authors":["Yufei He","Ruoyu Li","Alex Chen","Yue Liu","Yulin Chen","Yuan Sui","Cheng Chen","Yi Zhu","Luca Luo","Frank Yang","Bryan Hooi"],"abstract":"Large language model (LLM) agents often struggle in environments where rules and required domain knowledge frequently change, such as regulatory compliance and user risk screening. Current approaches, like offline fine-tuning and standard prompting, are insufficient because they cannot effectively adapt to new knowledge during actual operation. To address this limitation, we propose the Adaptive Reflective Interactive Agent (ARIA), an LLM agent framework designed specifically to continuously learn updated domain knowledge at test time. ARIA assesses its own uncertainty through structured self-dialogue, proactively identifying knowledge gaps and requesting targeted explanations or corrections from human experts. It then systematically updates an internal, timestamped knowledge repository with provided human guidance, detecting and resolving conflicting or outdated knowledge through comparisons and clarification queries. We evaluate ARIA on the realistic customer due diligence name screening task on TikTok Pay, alongside publicly available dynamic knowledge tasks. Results demonstrate significant improvements in adaptability and accuracy compared to baselines using standard offline fine-tuning and existing self-improving agents. ARIA is deployed within TikTok Pay serving over 150 million monthly active users, confirming its practicality and effectiveness for operational use in rapidly evolving environments.","published":"2025-07-23T02:12:32Z","updated":"2025-10-10T06:52:01Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2507.17131v2","pdf_url":"https://arxiv.org/pdf/2507.17131v2","comment":"EMNLP 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.16815","versioned_id":"2507.16815v2","title":"ThinkAct: Vision-Language-Action Reasoning via Reinforced Visual Latent Planning","authors":["Chi-Pin Huang","Yueh-Hua Wu","Min-Hung Chen","Yu-Chiang Frank Wang","Fu-En Yang"],"abstract":"Vision-language-action (VLA) reasoning tasks require agents to interpret multimodal instructions, perform long-horizon planning, and act adaptively in dynamic environments. Existing approaches typically train VLA models in an end-to-end fashion, directly mapping inputs to actions without explicit reasoning, which hinders their ability to plan over multiple steps or adapt to complex task variations. In this paper, we propose ThinkAct, a dual-system framework that bridges high-level reasoning with low-level action execution via reinforced visual latent planning. ThinkAct trains a multimodal LLM to generate embodied reasoning plans guided by reinforcing action-aligned visual rewards based on goal completion and trajectory consistency. These reasoning plans are compressed into a visual plan latent that conditions a downstream action model for robust action execution on target environments. Extensive experiments on embodied reasoning and robot manipulation benchmarks demonstrate that ThinkAct enables few-shot adaptation, long-horizon planning, and self-correction behaviors in complex embodied AI tasks.","published":"2025-07-22T17:59:46Z","updated":"2025-09-18T16:26:53Z","categories":["cs.CV","cs.AI","cs.LG","cs.RO"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2507.16815v2","pdf_url":"https://arxiv.org/pdf/2507.16815v2","comment":"NeurIPS 2025. Project page: https://jasper0314-huang.github.io/thinkact-vla/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=72UR53jN7T","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2507.16713","versioned_id":"2507.16713v2","title":"A Pragmatist Robot: Learning to Plan Tasks by Experiencing the Real World","authors":["Kaixian Qu","Guowei Lan","René Zurbrügg","Changan Chen","Christopher E. Mower","Haitham Bou-Ammar","Marco Hutter"],"abstract":"Large language models (LLMs) have emerged as the dominant paradigm for robotic task planning using natural language instructions. However, trained on general internet data, LLMs are not inherently aligned with the embodiment, skill sets, and limitations of real-world robotic systems. Inspired by the emerging paradigm of verbal reinforcement learning-where LLM agents improve through self-reflection and few-shot learning without parameter updates-we introduce PragmaBot, a framework that enables robots to learn task planning through real-world experience. PragmaBot employs a vision-language model (VLM) as the robot's \"brain\" and \"eye\", allowing it to visually evaluate action outcomes and self-reflect on failures. These reflections are stored in a short-term memory (STM), enabling the robot to quickly adapt its behavior during ongoing tasks. Upon task completion, the robot summarizes the lessons learned into its long-term memory (LTM). When facing new tasks, it can leverage retrieval-augmented generation (RAG) to plan more grounded action sequences by drawing on relevant past experiences and knowledge. Experiments on four challenging robotic tasks show that STM-based self-reflection increases task success rates from 35% to 84%, with emergent intelligent object interactions. In 12 real-world scenarios (including eight previously unseen tasks), the robot effectively learns from the LTM and improves single-trial success rates from 22% to 80%, with RAG outperforming naive prompting. These results highlight the effectiveness and generalizability of PragmaBot. Project webpage: https://pragmabot.github.io/","published":"2025-07-22T15:48:49Z","updated":"2026-02-14T07:11:52Z","categories":["cs.RO","cs.AI","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2507.16713v2","pdf_url":"https://arxiv.org/pdf/2507.16713v2","comment":"Accepted to RA-L","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=e5jCSWybNV","openreview_venues":["RSS26-W: FM4RoboPlan Poster"]},{"id":"2507.16280","versioned_id":"2507.16280v1","title":"ResearcherBench: Evaluating Deep AI Research Systems on the Frontiers of Scientific Inquiry","authors":["Tianze Xu","Pengrui Lu","Lyumanshan Ye","Xiangkun Hu","Pengfei Liu"],"abstract":"The emergence of deep research systems presents significant capabilities in problem-solving, extending from basic queries to sophisticated research tasks. However, existing benchmarks primarily evaluate these systems as agents for web retrieval and report generation, overlooking their potential to discover novel insights on the frontiers of scientific research. To address this gap, we introduce ResearcherBench, the first benchmark focused on evaluating the capabilities of these advanced, agentic systems - which we refer to as Deep AI Research Systems (DARS) - on frontier AI scientific questions. We compiled a dataset of 65 research questions expertly selected from real-world scientific scenarios such as laboratory discussions and interviews, spanning 35 different AI subjects and categorized into three types: technical details, literature review, and open consulting. Our dual evaluation framework combines rubric assessment, which uses expert-designed criteria to evaluate insight quality, with factual assessment, which measures citation accuracy (faithfulness) and coverage (groundedness). We evaluated several leading commercial DARS and baseline systems. Results show that OpenAI Deep Research and Gemini Deep Research significantly outperform other systems, with particular strength in open-ended consulting questions. Such capabilities represent a meaningful step toward AI self-improvement, aligning with the vision of ASI for AI. We open-source ResearcherBench to provide a standardized platform for promoting the development of next-generation AI research assistants, hoping to foster a new perspective in AI research evaluation for a novel pattern of scientific collaboration: https://github.com/GAIR-NLP/ResearcherBench.","published":"2025-07-22T06:51:26Z","updated":"2025-07-22T06:51:26Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.16280v1","pdf_url":"https://arxiv.org/pdf/2507.16280v1","comment":"22 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.16075","versioned_id":"2507.16075v1","title":"Deep Researcher with Test-Time Diffusion","authors":["Rujun Han","Yanfei Chen","Zoey CuiZhu","Lesly Miculicich","Guan Sun","Yuanjun Bi","Weiming Wen","Hui Wan","Chunfeng Wen","Solène Maître","George Lee","Vishy Tirumalashetty","Emily Xue","Zizhao Zhang","Salem Haykal","Burak Gokturk","Tomas Pfister","Chen-Yu Lee"],"abstract":"Deep research agents, powered by Large Language Models (LLMs), are rapidly advancing; yet, their performance often plateaus when generating complex, long-form research reports using generic test-time scaling algorithms. Drawing inspiration from the iterative nature of human research, which involves cycles of searching, reasoning, and revision, we propose the Test-Time Diffusion Deep Researcher (TTD-DR). This novel framework conceptualizes research report generation as a diffusion process. TTD-DR initiates this process with a preliminary draft, an updatable skeleton that serves as an evolving foundation to guide the research direction. The draft is then iteratively refined through a \"denoising\" process, which is dynamically informed by a retrieval mechanism that incorporates external information at each step. The core process is further enhanced by a self-evolutionary algorithm applied to each component of the agentic workflow, ensuring the generation of high-quality context for the diffusion process. This draft-centric design makes the report writing process more timely and coherent while reducing information loss during the iterative search process. We demonstrate that our TTD-DR achieves state-of-the-art results on a wide array of benchmarks that require intensive search and multi-hop reasoning, significantly outperforming existing deep research agents.","published":"2025-07-21T21:23:21Z","updated":"2025-07-21T21:23:21Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.16075v1","pdf_url":"https://arxiv.org/pdf/2507.16075v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.14800","versioned_id":"2507.14800v2","title":"Large Language Model as An Operator: An Experience-Driven Solution for Distribution Network Voltage Control","authors":["Xu Yang","Chenhui Lin","Licheng Sha","Liping Yang","Shuzhou Wu","Xichen Tian","Haotian Liu","Wenchuan Wu"],"abstract":"With the advanced reasoning, contextual understanding, and information synthesis capabilities of large language models (LLMs), a novel paradigm emerges for the autonomous generation of dispatch strategies in modern power systems. In this paper, we propose an LLM-based experience-driven day-ahead Volt/Var schedule solution for distribution networks, which enables the self-evolution of LLM agent's strategies through the collaboration and interaction of multiple modules, specifically, experience storage, experience retrieval, experience generation, and experience modification. The experience storage module archives historical operational records and decisions, while the retrieval module selects relevant past cases according to current forecasting conditions. The LLM agent then leverages these retrieved experiences to generate new, context-aware decisions for current situation, which are subsequently refined by the modification module to realize self-evolution of the dispatch policy. Comprehensive experimental results validate the effectiveness of the proposed method and highlight the applicability of LLMs in power system dispatch problems facing incomplete information.","published":"2025-07-20T03:22:08Z","updated":"2026-04-12T07:28:19Z","categories":["eess.SY","cs.AI"],"primary_category":"eess.SY","arxiv_url":"https://arxiv.org/abs/2507.14800v2","pdf_url":"https://arxiv.org/pdf/2507.14800v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.21124","versioned_id":"2507.21124v1","title":"VizGenie: Toward Self-Refining, Domain-Aware Workflows for Next-Generation Scientific Visualization","authors":["Ayan Biswas","Terece L. Turton","Nishath Rajiv Ranasinghe","Shawn Jones","Bradley Love","William Jones","Aric Hagberg","Han-Wei Shen","Nathan DeBardeleben","Earl Lawrence"],"abstract":"We present VizGenie, a self-improving, agentic framework that advances scientific visualization through large language model (LLM) by orchestrating of a collection of domain-specific and dynamically generated modules. Users initially access core functionalities--such as threshold-based filtering, slice extraction, and statistical analysis--through pre-existing tools. For tasks beyond this baseline, VizGenie autonomously employs LLMs to generate new visualization scripts (e.g., VTK Python code), expanding its capabilities on-demand. Each generated script undergoes automated backend validation and is seamlessly integrated upon successful testing, continuously enhancing the system's adaptability and robustness. A distinctive feature of VizGenie is its intuitive natural language interface, allowing users to issue high-level feature-based queries (e.g., ``visualize the skull\"). The system leverages image-based analysis and visual question answering (VQA) via fine-tuned vision models to interpret these queries precisely, bridging domain expertise and technical implementation. Additionally, users can interactively query generated visualizations through VQA, facilitating deeper exploration. Reliability and reproducibility are further strengthened by Retrieval-Augmented Generation (RAG), providing context-driven responses while maintaining comprehensive provenance records. Evaluations on complex volumetric datasets demonstrate significant reductions in cognitive overhead for iterative visualization tasks. By integrating curated domain-specific tools with LLM-driven flexibility, VizGenie not only accelerates insight generation but also establishes a sustainable, continuously evolving visualization practice. The resulting platform dynamically learns from user interactions, consistently enhancing support for feature-centric exploration and reproducible research in scientific visualization.","published":"2025-07-18T23:54:22Z","updated":"2025-07-18T23:54:22Z","categories":["cs.HC","cs.AI","cs.GR","cs.LG"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2507.21124v1","pdf_url":"https://arxiv.org/pdf/2507.21124v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.11662","versioned_id":"2507.11662v3","title":"Let's Think in Two Steps: Mitigating Agreement Bias in MLLMs with Self-Grounded Verification","authors":["Moises Andrade","Joonhyuk Cha","Brandon Ho","Vriksha Srihari","Karmesh Yadav","Zsolt Kira"],"abstract":"Verifiers--functions assigning rewards to agent behavior--have been key to AI progress in math, code, and games. However, extending gains to domains without clear-cut success criteria remains a challenge: while humans can recognize desired outcomes, translating this intuition into scalable rules is nontrivial. Multimodal LLMs (MLLMs) offer a promising solution, given their world knowledge, human-preference alignment, and reasoning capabilities. We evaluate MLLM verifiers across web navigation, computer use, and robotics, spanning 13+ models, 28+ designs, and thousands of trajectories from diverse agents. We identify a critical limitation: a strong tendency for MLLMs to over-validate agent behavior--a phenomenon we term agreement bias. This bias is pervasive, resilient to test-time scaling, and can harm applications relying on MLLM judgments/rewards (e.g., self-improvement, steering, online supervision). We discuss several considerations for evaluating and designing MLLM verifiers, and introduce SGV, a lightweight method that better leverages their capabilities by modulating (un)conditional generation. First, an MLLM is elicited to generate broad priors about desired behavior, independent of the data under evaluation. Then, conditioned on self-generated priors, it reasons over and evaluates a candidate trajectory. Our methods yield more human-aligned verifiers, improving failure detection by 25pp and accuracy by 14pp. In self-improvement and online supervision, they boost task completion of a GUI specialist in OSWorld, a diffusion policy in robomimic, and a ReAct agent in VisualWebArena--surpassing the previous state of the art by 20pp. As a byproduct, we release an update of VisualWebArena featuring strong agent baselines, more human-aligned oracles, container parallelism with high fidelity and proper resets, >10x speedups, and VWA-Lite, a 1/3 subset with comparable evaluation fidelity.","published":"2025-07-15T18:50:29Z","updated":"2026-03-08T00:45:24Z","categories":["cs.AI","cs.CL","cs.LG","cs.MA","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.11662v3","pdf_url":"https://arxiv.org/pdf/2507.11662v3","comment":"ICLR 2026. Code, models, and data publicly available at https://mshalimay.github.io/agreement-bias-sgv/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=rwo7bVlnzo","openreview_venues":["ICLR 2026 Poster"]},{"id":"2507.11277","versioned_id":"2507.11277v2","title":"Taming Uncertainty via Automation: Observing, Analyzing, and Optimizing Agentic AI Systems","authors":["Dany Moshkovich","Sergey Zeltyn"],"abstract":"Large Language Models (LLMs) are increasingly deployed within agentic systems - collections of interacting, LLM-powered agents that execute complex, adaptive workflows using memory, tools, and dynamic planning. While enabling powerful new capabilities, these systems also introduce unique forms of uncertainty stemming from probabilistic reasoning, evolving memory states, and fluid execution paths. Traditional software observability and operations practices fall short in addressing these challenges. This paper presents our vision of AgentOps: a comprehensive framework for observing, analyzing, optimizing, and automating operation of agentic AI systems. We identify distinct needs across four key roles - developers, testers, site reliability engineers (SREs), and business users - each of whom engages with the system at different points in its lifecycle. We present the AgentOps Automation Pipeline, a six-stage process encompassing behavior observation, metric collection, issue detection, root cause analysis, optimized recommendations, and runtime automation. Throughout, we emphasize the critical role of automation in managing uncertainty and enabling self-improving AI systems - not by eliminating uncertainty, but by taming it to ensure safe, adaptive, and effective operation.","published":"2025-07-15T12:54:43Z","updated":"2025-11-20T10:41:15Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.11277v2","pdf_url":"https://arxiv.org/pdf/2507.11277v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.09592","versioned_id":"2507.09592v3","title":"THOR: Transformer Heuristics for On-Demand Retrieval","authors":["Isaac Shi","Zeyuan Li","Fan Liu","Wenli Wang","Lewei He","Yang Yang","Tianyu Shi"],"abstract":"We introduce the THOR (Transformer Heuristics for On-Demand Retrieval) Module, designed and implemented by eSapiens, a secure, scalable engine that transforms natural-language questions into verified, read-only SQL analytics for enterprise databases. The Text-to-SQL module follows a decoupled orchestration/execution architecture: a Supervisor Agent routes queries, Schema Retrieval dynamically injects table and column metadata, and a SQL Generation Agent emits single-statement SELECT queries protected by a read-only guardrail. An integrated Self-Correction & Rating loop captures empty results, execution errors, or low-quality outputs and triggers up to five LLM-driven regeneration attempts. Finally, a Result Interpretation Agent produces concise, human-readable insights and hands raw rows to the Insight & Intelligence engine for visualization or forecasting. Smoke tests across finance, sales, and operations scenarios demonstrate reliable ad-hoc querying and automated periodic reporting. By embedding schema awareness, fault-tolerant execution, and compliance guardrails, the THOR Module empowers non-technical users to access live data with zero-SQL simplicity and enterprise-grade safety.","published":"2025-07-13T11:48:24Z","updated":"2025-07-17T05:47:22Z","categories":["cs.DB","cs.AI"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2507.09592v3","pdf_url":"https://arxiv.org/pdf/2507.09592v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.07887","versioned_id":"2507.07887v1","title":"Automating MD simulations for Proteins using Large language Models: NAMD-Agent","authors":["Achuth Chandrasekhar","Amir Barati Farimani"],"abstract":"Molecular dynamics simulations are an essential tool in understanding protein structure, dynamics, and function at the atomic level. However, preparing high quality input files for MD simulations can be a time consuming and error prone process. In this work, we introduce an automated pipeline that leverages Large Language Models (LLMs), specifically Gemini 2.0 Flash, in conjunction with python scripting and Selenium based web automation to streamline the generation of MD input files. The pipeline exploits CHARMM GUI's comprehensive web-based interface for preparing simulation-ready inputs for NAMD. By integrating Gemini's code generation and iterative refinement capabilities, simulation scripts are automatically written, executed, and revised to navigate CHARMM GUI, extract appropriate parameters, and produce the required NAMD input files. Post processing is performed using additional software to further refine the simulation outputs, thereby enabling a complete and largely hands free workflow. Our results demonstrate that this approach reduces setup time, minimizes manual errors, and offers a scalable solution for handling multiple protein systems in parallel. This automated framework paves the way for broader application of LLMs in computational structural biology, offering a robust and adaptable platform for future developments in simulation automation.","published":"2025-07-10T16:17:40Z","updated":"2025-07-10T16:17:40Z","categories":["cs.CL","cs.CE","q-bio.BM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2507.07887v1","pdf_url":"https://arxiv.org/pdf/2507.07887v1","comment":"34 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.04370","versioned_id":"2507.04370v1","title":"WebSynthesis: World-Model-Guided MCTS for Efficient WebUI-Trajectory Synthesis","authors":["Yifei Gao","Junhong Ye","Jiaqi Wang","Jitao Sang"],"abstract":"Recent advancements in large language models (LLMs) have significantly improved the capabilities of web agents. However, effectively navigating complex and dynamic web environments still requires more advanced trajectory-level planning and execution. Prior studies have addressed self-improving agents by collecting extensive GUI trajectories from real-environment interactions. Despite their effectiveness, these approaches encounter two critical challenges: (1) Uncontrollable environment states, where real or sandboxed web environments often yield unstable and non-deterministic feedback, complicating the reproduction and debugging of agent behaviors; and (2) High API costs, as generating even a single interaction trajectory can involve hundreds of queries, leading to considerable API usage and computational expenses. To address these limitations and enable scalable self-improvement for agents, we propose WebSynthesis, a novel framework for trajectory synthesis and training. WebSynthesis leverages a learned world model to simulate virtual web environments, allowing a policy agent to perform efficient and reversible tree-based planning. This approach supports the large-scale generation of diverse and high-quality trajectories, which are subsequently utilized to refine the agent's policy. Experimental results demonstrate that an agent trained using WebSynthesis on a small-scale synthetic dataset achieves performance comparable to or even surpassing that of models trained on large-scale real-world data.","published":"2025-07-06T12:31:10Z","updated":"2025-07-06T12:31:10Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.04370v1","pdf_url":"https://arxiv.org/pdf/2507.04370v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.03620","versioned_id":"2507.03620v1","title":"Is It Time To Treat Prompts As Code? A Multi-Use Case Study For Prompt Optimization Using DSPy","authors":["Francisca Lemos","Victor Alves","Filipa Ferraz"],"abstract":"Although prompt engineering is central to unlocking the full potential of Large Language Models (LLMs), crafting effective prompts remains a time-consuming trial-and-error process that relies on human intuition. This study investigates Declarative Self-improving Python (DSPy), an optimization framework that programmatically creates and refines prompts, applied to five use cases: guardrail enforcement, hallucination detection in code, code generation, routing agents, and prompt evaluation. Each use case explores how prompt optimization via DSPy influences performance. While some cases demonstrated modest improvements - such as minor gains in the guardrails use case and selective enhancements in hallucination detection - others showed notable benefits. The prompt evaluation criterion task demonstrated a substantial performance increase, rising accuracy from 46.2% to 64.0%. In the router agent case, the possibility of improving a poorly performing prompt and of a smaller model matching a stronger one through optimized prompting was explored. Although prompt refinement increased accuracy from 85.0% to 90.0%, using the optimized prompt with a cheaper model did not improve performance. Overall, this study's findings suggest that DSPy's systematic prompt optimization can enhance LLM performance, particularly when instruction tuning and example selection are optimized together. However, the impact varies by task, highlighting the importance of evaluating specific use cases in prompt optimization research.","published":"2025-07-04T14:46:56Z","updated":"2025-07-04T14:46:56Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2507.03620v1","pdf_url":"https://arxiv.org/pdf/2507.03620v1","comment":"20 pages with 1 figure","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.03223","versioned_id":"2507.03223v1","title":"SI-Agent: An Agentic Framework for Feedback-Driven Generation and Tuning of Human-Readable System Instructions for Large Language Models","authors":["Jeshwanth Challagundla"],"abstract":"System Instructions (SIs), or system prompts, are pivotal for guiding Large Language Models (LLMs) but manual crafting is resource-intensive and often suboptimal. Existing automated methods frequently generate non-human-readable \"soft prompts,\" sacrificing interpretability. This paper introduces SI-Agent, a novel agentic framework designed to automatically generate and iteratively refine human-readable SIs through a feedback-driven loop. SI-Agent employs three collaborating agents: an Instructor Agent, an Instruction Follower Agent (target LLM), and a Feedback/Reward Agent evaluating task performance and optionally SI readability. The framework utilizes iterative cycles where feedback guides the Instructor's refinement strategy (e.g., LLM-based editing, evolutionary algorithms). We detail the framework's architecture, agent roles, the iterative refinement process, and contrast it with existing methods. We present experimental results validating SI-Agent's effectiveness, focusing on metrics for task performance, SI readability, and efficiency. Our findings indicate that SI-Agent generates effective, readable SIs, offering a favorable trade-off between performance and interpretability compared to baselines. Potential implications include democratizing LLM customization and enhancing model transparency. Challenges related to computational cost and feedback reliability are acknowledged.","published":"2025-07-03T23:44:50Z","updated":"2025-07-03T23:44:50Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.03223v1","pdf_url":"https://arxiv.org/pdf/2507.03223v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.01599","versioned_id":"2507.01599v1","title":"Data Agent: A Holistic Architecture for Orchestrating Data+AI Ecosystems","authors":["Zhaoyan Sun","Jiayi Wang","Xinyang Zhao","Jiachi Wang","Guoliang Li"],"abstract":"Traditional Data+AI systems utilize data-driven techniques to optimize performance, but they rely heavily on human experts to orchestrate system pipelines, enabling them to adapt to changes in data, queries, tasks, and environments. For instance, while there are numerous data science tools available, developing a pipeline planning system to coordinate these tools remains challenging. This difficulty arises because existing Data+AI systems have limited capabilities in semantic understanding, reasoning, and planning. Fortunately, we have witnessed the success of large language models (LLMs) in enhancing semantic understanding, reasoning, and planning abilities. It is crucial to incorporate LLM techniques to revolutionize data systems for orchestrating Data+AI applications effectively. To achieve this, we propose the concept of a 'Data Agent' - a comprehensive architecture designed to orchestrate Data+AI ecosystems, which focuses on tackling data-related tasks by integrating knowledge comprehension, reasoning, and planning capabilities. We delve into the challenges involved in designing data agents, such as understanding data/queries/environments/tools, orchestrating pipelines/workflows, optimizing and executing pipelines, and fostering pipeline self-reflection. Furthermore, we present examples of data agent systems, including a data science agent, data analytics agents (such as unstructured data analytics agent, semantic structured data analytics agent, data lake analytics agent, and multi-modal data analytics agent), and a database administrator (DBA) agent. We also outline several open challenges associated with designing data agent systems.","published":"2025-07-02T11:04:49Z","updated":"2025-07-02T11:04:49Z","categories":["cs.DB","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.DB","arxiv_url":"https://arxiv.org/abs/2507.01599v1","pdf_url":"https://arxiv.org/pdf/2507.01599v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2507.00951","versioned_id":"2507.00951v3","title":"Thinking Beyond Tokens: From Brain-Inspired Intelligence to Cognitive Foundations for Artificial General Intelligence and its Societal Impact","authors":["Rizwan Qureshi","Ranjan Sapkota","Abbas Shah","Amgad Muneer","Anas Zafar","Ashmal Vayani","Maged Shoman","Abdelrahman B. M. Eldaly","Kai Zhang","Ferhat Sadak","Shaina Raza","Xinqi Fan","Ravid Shwartz-Ziv","Hong Yan","Vinjia Jain","Aman Chadha","Manoj Karkee","Jia Wu","Seyedali Mirjalili"],"abstract":"Can machines truly think, reason and act in domains like humans? This enduring question continues to shape the pursuit of Artificial General Intelligence (AGI). Despite the growing capabilities of models such as GPT-4.5, DeepSeek, Claude 3.5 Sonnet, Phi-4, and Grok 3, which exhibit multimodal fluency and partial reasoning, these systems remain fundamentally limited by their reliance on token-level prediction and lack of grounded agency. This paper offers a cross-disciplinary synthesis of AGI development, spanning artificial intelligence, cognitive neuroscience, psychology, generative models, and agent-based systems. We analyze the architectural and cognitive foundations of general intelligence, highlighting the role of modular reasoning, persistent memory, and multi-agent coordination. In particular, we emphasize the rise of Agentic RAG frameworks that combine retrieval, planning, and dynamic tool use to enable more adaptive behavior. We discuss generalization strategies, including information compression, test-time adaptation, and training-free methods, as critical pathways toward flexible, domain-agnostic intelligence. Vision-Language Models (VLMs) are reexamined not just as perception modules but as evolving interfaces for embodied understanding and collaborative task completion. We also argue that true intelligence arises not from scale alone but from the integration of memory and reasoning: an orchestration of modular, interactive, and self-improving components where compression enables adaptive behavior. Drawing on advances in neurosymbolic systems, reinforcement learning, and cognitive scaffolding, we explore how recent architectures begin to bridge the gap between statistical learning and goal-directed cognition. Finally, we identify key scientific, technical, and ethical challenges on the path to AGI.","published":"2025-07-01T16:52:25Z","updated":"2025-07-12T02:50:17Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2507.00951v3","pdf_url":"https://arxiv.org/pdf/2507.00951v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.23273","versioned_id":"2506.23273v2","title":"FinStat2SQL: A Text2SQL Pipeline for Financial Statement Analysis","authors":["Quang Hung Nguyen","Phuong Anh Trinh","Phan Quoc Hung Mai","Tuan Phong Trinh"],"abstract":"Despite the advancements of large language models, text2sql still faces many challenges, particularly with complex and domain-specific queries. In finance, database designs and financial reporting layouts vary widely between financial entities and countries, making text2sql even more challenging. We present FinStat2SQL, a lightweight text2sql pipeline enabling natural language queries over financial statements. Tailored to local standards like VAS, it combines large and small language models in a multi-agent setup for entity extraction, SQL generation, and self-correction. We build a domain-specific database and evaluate models on a synthetic QA dataset. A fine-tuned 7B model achieves 61.33\\% accuracy with sub-4-second response times on consumer hardware, outperforming GPT-4o-mini. FinStat2SQL offers a scalable, cost-efficient solution for financial analysis, making AI-powered querying accessible to Vietnamese enterprises.","published":"2025-06-29T14:55:21Z","updated":"2025-09-07T17:52:24Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.23273v2","pdf_url":"https://arxiv.org/pdf/2506.23273v2","comment":"Accepted for The 18th International Natural Language Generation Conference (INLG)","journal_ref":"https://aclanthology.org/2025.inlg-main.27/","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.21669","versioned_id":"2506.21669v2","title":"SEEA-R1: Tree-Structured Reinforcement Fine-Tuning for Self-Evolving Embodied Agents","authors":["Wanxin Tian","Shijie Zhang","Kevin Zhang","Xiaowei Chi","Chunkai Fan","Junyu Lu","Yulin Luo","Qiang Zhou","Yiming Zhao","Ning Liu","Siyu Lin","Zhiyuan Qin","Xiaozhu Ju","Shanghang Zhang","Jian Tang"],"abstract":"Self-evolution, the ability of agents to autonomously improve their reasoning and behavior, is essential for the embodied domain with long-horizon, real-world tasks. Despite current advancements in reinforcement fine-tuning (RFT) showing strong performance in enhancing reasoning in LLMs, its potential to enable self-evolving embodied intelligence with multi-modal interactions remains largely unexplored. Specifically, reinforcement fine-tuning faces two fundamental obstacles in embodied settings: (i) the lack of accessible intermediate rewards in multi-step reasoning tasks limits effective learning signals, and (ii) reliance on hand-crafted reward functions restricts generalization to novel tasks and environments. To address these challenges, we present Self-Evolving Embodied Agents-R1, SEEA-R1, the first RFT framework designed for enabling the self-evolving capabilities of embodied agents. Specifically, to convert sparse delayed rewards into denser intermediate signals that improve multi-step reasoning, we propose Tree-based group relative policy optimization (Tree-GRPO) integrates Monte Carlo Tree Search into GRPO. To generalize reward estimation across tasks and scenes, supporting autonomous adaptation and reward-driven self-evolution, we further introduce Multi-modal Generative Reward Model (MGRM). To holistically evaluate the effectiveness of SEEA-R1, we evaluate on the ALFWorld benchmark, surpassing state-of-the-art methods with scores of 85.07% (textual) and 46.27% (multi-modal), outperforming prior models including GPT-4o. SEEA-R1 also achieves scores of 80.3% (textual) and 44.03% (multi-modal) without ground truth reward, surpassing all open-source baselines and highlighting its scalability as a self-evolving embodied agent. Additional experiments and qualitative analysis further support the potential of SEEA-R1 for future research in scalable embodied intelligence.","published":"2025-06-26T18:00:07Z","updated":"2025-10-27T04:10:28Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.21669v2","pdf_url":"https://arxiv.org/pdf/2506.21669v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=dAwKePZvcN","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2506.21252","versioned_id":"2506.21252v1","title":"Agent-RewardBench: Towards a Unified Benchmark for Reward Modeling across Perception, Planning, and Safety in Real-World Multimodal Agents","authors":["Tianyi Men","Zhuoran Jin","Pengfei Cao","Yubo Chen","Kang Liu","Jun Zhao"],"abstract":"As Multimodal Large Language Models (MLLMs) advance, multimodal agents show promise in real-world tasks like web navigation and embodied intelligence. However, due to limitations in a lack of external feedback, these agents struggle with self-correction and generalization. A promising approach is to use reward models as external feedback, but there is no clear on how to select reward models for agents. Thus, there is an urgent need to build a reward bench targeted at agents. To address these challenges, we propose Agent-RewardBench, a benchmark designed to evaluate reward modeling ability in MLLMs. The benchmark is characterized by three key features: (1) Multiple dimensions and real-world agent scenarios evaluation. It covers perception, planning, and safety with 7 scenarios; (2) Step-level reward evaluation. It allows for the assessment of agent capabilities at the individual steps of a task, providing a more granular view of performance during the planning process; and (3) Appropriately difficulty and high-quality. We carefully sample from 10 diverse models, difficulty control to maintain task challenges, and manual verification to ensure the integrity of the data. Experiments demonstrate that even state-of-the-art multimodal models show limited performance, highlighting the need for specialized training in agent reward modeling. Code is available at github.","published":"2025-06-26T13:36:12Z","updated":"2025-06-26T13:36:12Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.21252v1","pdf_url":"https://arxiv.org/pdf/2506.21252v1","comment":"ACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=kSCoDjhXeN","openreview_venues":["ACL ARR 2025 February Submission"]},{"id":"2506.20332","versioned_id":"2506.20332v4","title":"Mobile-R1: Towards Interactive Capability for VLM-Based Mobile Agent via Systematic Training","authors":["Jihao Gu","Qihang Ai","Yingyao Wang","Pi Bu","Jingxuan Xing","Zekun Zhu","Wei Jiang","Ziming Wang","Yingxiu Zhao","Ming-Liang Zhang","Jun Song","Yuning Jiang","Bo Zheng"],"abstract":"Vision-language model-based mobile agents have gained the ability to understand complex instructions and mobile screenshots, benefiting from reinforcement learning paradigms like Group Relative Policy Optimization (GRPO). However, existing approaches centers on offline training or local action-level rewards often trap agents in local optima, hindering effective exploration and error correction with the environment. Crucially, we find that directly applying task-level rewards often leads to convergence difficulties due to the sparse nature of GUI interactions. To address these challenges, we present \\textbf{Mobile-R1}, a systematic training recipe that bridges atomic action execution and strategic task completion. We propose a hierarchical curriculum consisting of three stages: (1) format alignment for reasoning structure, (2) on-policy exploration with verifiable action feedback to ground basic execution, and (3) multi-turn task-level training with realistic environment to unlock exploration and self-correction. This hierarchical strategy effectively bootstraps the agent, significantly enhancing its capability for exploration and self-correction (the ``Eureka'' moments). Furthermore, addressing the critical scarcity of diverse GUI data in non-English ecosystems, we contribute a comprehensive Chinese mobile dataset covering 28 applications with 24,521 high-quality manual annotations, and establish a rigorous benchmark with 500 trajectories. We will open source all resources, including the dataset, benchmark, model weight, and codes: https://mobile-r1.github.io/Mobile-R1/.","published":"2025-06-25T11:34:43Z","updated":"2026-04-25T13:54:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.20332v4","pdf_url":"https://arxiv.org/pdf/2506.20332v4","comment":"19 pages, 15 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.20102","versioned_id":"2506.20102v2","title":"Autonomous Cyber Resilience via a Co-Evolutionary Arms Race within a Fortified Digital Twin Sandbox","authors":["Malikussaid","Sutiyo"],"abstract":"The convergence of Information Technology and Operational Technology has exposed Industrial Control Systems to adaptive, intelligent adversaries that render static defenses obsolete. This paper introduces the Adversarial Resilience Co-evolution (ARC) framework, addressing the \"Trinity of Trust\" comprising model fidelity, data integrity, and analytical resilience. ARC establishes a co-evolutionary arms race within a Fortified Secure Digital Twin (F-SCDT), where a Deep Reinforcement Learning \"Red Agent\" autonomously discovers attack paths while an ensemble-based \"Blue Agent\" is continuously hardened against these threats. Experimental validation on the Tennessee Eastman Process (TEP) and Secure Water Treatment (SWaT) testbeds demonstrates superior performance in detecting novel attacks, with F1-scores improving from 0.65 to 0.89 and detection latency reduced from over 1200 seconds to 210 seconds. A comprehensive ablation study reveals that the co-evolutionary process itself contributes a 27% performance improvement. By integrating Explainable AI and proposing a Federated ARC architecture, this work presents a necessary paradigm shift toward dynamic, self-improving security for critical infrastructure.","published":"2025-06-25T03:28:48Z","updated":"2025-10-16T17:44:09Z","categories":["cs.CR","cs.LG","eess.SY"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2506.20102v2","pdf_url":"https://arxiv.org/pdf/2506.20102v2","comment":"6 pages, 2 figures, 4 equations, 1 algorithm, 3 tables, to be published in ISPACS 2025, unabridged version exists as arXiv:2506.20102v1","journal_ref":"Proc. 2025 Int. Symp. on Intell. Signal Process. and Commun. Syst. (ISPACS), 2025, pp. 1-6","doi":"10.1109/ISPACS68724.2025.11383172","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.18957","versioned_id":"2506.18957v1","title":"A Comment On \"The Illusion of Thinking\": Reframing the Reasoning Cliff as an Agentic Gap","authors":["Sheraz Khan","Subha Madhavan","Kannan Natarajan"],"abstract":"The recent work by Shojaee et al. (2025), titled The Illusion of Thinking: Understanding the Strengths and Limitations of Reasoning Models via the Lens of Problem Complexity, presents a compelling empirical finding, a reasoning cliff, where the performance of Large Reasoning Models (LRMs) collapses beyond a specific complexity threshold, which the authors posit as an intrinsic scaling limitation of Chain-of-Thought (CoT) reasoning. This commentary, while acknowledging the study's methodological rigor, contends that this conclusion is confounded by experimental artifacts. We argue that the observed failure is not evidence of a fundamental cognitive boundary, but rather a predictable outcome of system-level constraints in the static, text-only evaluation paradigm, including tool use restrictions, context window recall issues, the absence of crucial cognitive baselines, inadequate statistical reporting, and output generation limits. We reframe this performance collapse through the lens of an agentic gap, asserting that the models are not failing at reasoning, but at execution within a profoundly restrictive interface. We empirically substantiate this critique by demonstrating a striking reversal. A model, initially declaring a puzzle impossible when confined to text-only generation, now employs agentic tools to not only solve it but also master variations of complexity far beyond the reasoning cliff it previously failed to surmount. Additionally, our empirical analysis of tool-enabled models like o4-mini and GPT-4o reveals a hierarchy of agentic reasoning, from simple procedural execution to complex meta-cognitive self-correction, which has significant implications for how we define and measure machine intelligence. The illusion of thinking attributed to LRMs is less a reasoning deficit and more a consequence of an otherwise capable mind lacking the tools for action.","published":"2025-06-23T17:14:21Z","updated":"2025-06-23T17:14:21Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.18957v1","pdf_url":"https://arxiv.org/pdf/2506.18957v1","comment":"10 pages, 2 figures, Comment on \"The Illusion of Thinking: Understanding the Strengths and Limitations of Reasoning Models via the Lens of Problem Complexity\" (arXiv:2506.06941v1)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.17484","versioned_id":"2506.17484v1","title":"From Unstructured Communication to Intelligent RAG: Multi-Agent Automation for Supply Chain Knowledge Bases","authors":["Yao Zhang","Zaixi Shang","Silpan Patel","Mikel Zuniga"],"abstract":"Supply chain operations generate vast amounts of operational data; however, critical knowledge such as system usage practices, troubleshooting workflows, and resolution techniques often remains buried within unstructured communications like support tickets, emails, and chat logs. While RAG systems aim to leverage such communications as a knowledge base, their effectiveness is limited by raw data challenges: support tickets are typically noisy, inconsistent, and incomplete, making direct retrieval suboptimal. Unlike existing RAG approaches that focus on runtime optimization, we introduce a novel offline-first methodology that transforms these communications into a structured knowledge base. Our key innovation is a LLMs-based multi-agent system orchestrating three specialized agents: Category Discovery for taxonomy creation, Categorization for ticket grouping, and Knowledge Synthesis for article generation. Applying our methodology to real-world support tickets with resolution notes and comments, our system creates a compact knowledge base - reducing total volume to just 3.4% of original ticket data while improving quality. Experiments demonstrate that our prebuilt knowledge base in RAG systems significantly outperforms traditional RAG implementations (48.74% vs. 38.60% helpful answers) and achieves a 77.4% reduction in unhelpful responses. By automating institutional knowledge capture that typically remains siloed in experts' heads, our solution translates to substantial operational efficiency: reducing support workload, accelerating resolution times, and creating self-improving systems that automatically resolve approximately 50% of future supply chain tickets. Our approach addresses a key gap in knowledge management by transforming transient communications into structured, reusable knowledge through intelligent offline processing rather than latency-inducing runtime architectures.","published":"2025-06-20T21:38:06Z","updated":"2025-06-20T21:38:06Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17484v1","pdf_url":"https://arxiv.org/pdf/2506.17484v1","comment":"Accepted In Proceedings of the 1st Workshop on AI for Supply Chain: Today and Future @ 31st ACM SIGKDD Conference on Knowledge Discovery and Data Mining V.2 (KDD 25), August 3, 2025, Toronto, ON, Canada. ACM, New York, NY, USA, 14 pages, 2 figures","journal_ref":"","doi":"10.1145/XXXXXX.XXXXXX","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=vKvdg2abDB","openreview_venues":["AI4SupplyChain 2025 Poster"]},{"id":"2506.17449","versioned_id":"2506.17449v1","title":"OmniReflect: Discovering Transferable Constitutions for LLM agents via Neuro-Symbolic Reflections","authors":["Manasa Bharadwaj","Nikhil Verma","Kevin Ferreira"],"abstract":"Efforts to improve Large Language Model (LLM) agent performance on complex tasks have largely focused on fine-tuning and iterative self-correction. However, these approaches often lack generalizable mechanisms for longterm learning and remain inefficient in dynamic environments. We introduce OmniReflect, a hierarchical, reflection-driven framework that constructs a constitution, a compact set of guiding principles distilled from task experiences, to enhance the effectiveness and efficiency of an LLM agent. OmniReflect operates in two modes: Self-sustaining, where a single agent periodically curates its own reflections during task execution, and Co-operative, where a Meta-advisor derives a constitution from a small calibration set to guide another agent. To construct these constitutional principles, we employ Neural, Symbolic, and NeuroSymbolic techniques, offering a balance between contextual adaptability and computational efficiency. Empirical results averaged across models show major improvements in task success, with absolute gains of +10.3% on ALFWorld, +23.8% on BabyAI, and +8.3% on PDDL in the Self-sustaining mode. Similar gains are seen in the Co-operative mode, where a lightweight Qwen3-4B ReAct agent outperforms all Reflexion baselines on BabyAI. These findings highlight the robustness and effectiveness of OmniReflect across environments and backbones.","published":"2025-06-20T19:38:21Z","updated":"2025-06-20T19:38:21Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.17449v1","pdf_url":"https://arxiv.org/pdf/2506.17449v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=3xEmiKN3WH","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2506.14234","versioned_id":"2506.14234v1","title":"Xolver: Multi-Agent Reasoning with Holistic Experience Learning Just Like an Olympiad Team","authors":["Md Tanzib Hosain","Salman Rahman","Md Kishor Morol","Md Rizwan Parvez"],"abstract":"Despite impressive progress on complex reasoning, current large language models (LLMs) typically operate in isolation - treating each problem as an independent attempt, without accumulating or integrating experiential knowledge. In contrast, expert problem solvers - such as Olympiad or programming contest teams - leverage a rich tapestry of experiences: absorbing mentorship from coaches, developing intuition from past problems, leveraging knowledge of tool usage and library functionality, adapting strategies based on the expertise and experiences of peers, continuously refining their reasoning through trial and error, and learning from other related problems even during competition. We introduce Xolver, a training-free multi-agent reasoning framework that equips a black-box LLM with a persistent, evolving memory of holistic experience. Xolver integrates diverse experience modalities, including external and self-retrieval, tool use, collaborative interactions, agent-driven evaluation, and iterative refinement. By learning from relevant strategies, code fragments, and abstract reasoning patterns at inference time, Xolver avoids generating solutions from scratch - marking a transition from isolated inference toward experience-aware language agents. Built on both open-weight and proprietary models, Xolver consistently outperforms specialized reasoning agents. Even with lightweight backbones (e.g., QWQ-32B), it often surpasses advanced models including Qwen3-235B, Gemini 2.5 Pro, o3, and o4-mini-high. With o3-mini-high, it achieves new best results on GSM8K (98.1%), AIME'24 (94.4%), AIME'25 (93.7%), Math-500 (99.8%), and LiveCodeBench-V5 (91.6%) - highlighting holistic experience learning as a key step toward generalist agents capable of expert-level reasoning. Code and data are available at https://kagnlp.github.io/xolver.github.io/.","published":"2025-06-17T06:47:19Z","updated":"2025-06-17T06:47:19Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.14234v1","pdf_url":"https://arxiv.org/pdf/2506.14234v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.14035","versioned_id":"2506.14035v1","title":"SimpleDoc: Multi-Modal Document Understanding with Dual-Cue Page Retrieval and Iterative Refinement","authors":["Chelsi Jain","Yiran Wu","Yifan Zeng","Jiale Liu","S hengyu Dai","Zhenwen Shao","Qingyun Wu","Huazheng Wang"],"abstract":"Document Visual Question Answering (DocVQA) is a practical yet challenging task, which is to ask questions based on documents while referring to multiple pages and different modalities of information, e.g, images and tables. To handle multi-modality, recent methods follow a similar Retrieval Augmented Generation (RAG) pipeline, but utilize Visual Language Models (VLMs) based embedding model to embed and retrieve relevant pages as images, and generate answers with VLMs that can accept an image as input. In this paper, we introduce SimpleDoc, a lightweight yet powerful retrieval - augmented framework for DocVQA. It boosts evidence page gathering by first retrieving candidates through embedding similarity and then filtering and re-ranking these candidates based on page summaries. A single VLM-based reasoner agent repeatedly invokes this dual-cue retriever, iteratively pulling fresh pages into a working memory until the question is confidently answered. SimpleDoc outperforms previous baselines by 3.2% on average on 4 DocVQA datasets with much fewer pages retrieved. Our code is available at https://github.com/ag2ai/SimpleDoc.","published":"2025-06-16T22:15:58Z","updated":"2025-06-16T22:15:58Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2506.14035v1","pdf_url":"https://arxiv.org/pdf/2506.14035v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.12508","versioned_id":"2506.12508v6","title":"AgentOrchestra: Orchestrating Multi-Agent Intelligence with the Tool-Environment-Agent(TEA) Protocol","authors":["Wentao Zhang","Liang Zeng","Yuzhen Xiao","Yongcong Li","Ce Cui","Yilei Zhao","Rui Hu","Yang Liu","Yahui Zhou","Bo An"],"abstract":"Recent advances in LLM-based agent systems have shown promise on complex, long-horizon tasks, but existing agent protocols (e.g., A2A and MCP) do not adequately support lifecycle-aware coordination across agents, tools, and environments. To address this limitation, we introduce the \\textbf{Tool-Environment-Agent} (TEA) protocol, a unified abstraction that models these components as first-class, versioned resources with explicit lifecycles. TEA supports end-to-end context and version management, improving traceability and reproducibility, while also enabling continual self-evolution of agent-associated components\\footnote{Unless otherwise specified, \\emph{agent-associated components} include prompts, memory/tool/agent/environment code, and agent outputs (solutions).}. Building on TEA, we present \\projectname, a hierarchical multi-agent framework in which a central planner coordinates specialized sub-agents and dynamically extends capabilities during execution. Experiments on four challenging benchmarks, spanning expert-level agent tasks and scientific/mathematical reasoning, show that AgentOrchestra consistently outperforms strong baselines; in particular, it achieves 89.04\\% on the GAIA Test set, placing it among the leading methods to the best of our knowledge. These results highlight the value of explicit protocol design and hierarchical orchestration for building more robust and adaptive multi-agent systems.","published":"2025-06-14T13:45:37Z","updated":"2026-05-28T07:38:36Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.12508v6","pdf_url":"https://arxiv.org/pdf/2506.12508v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=qoxNsgJt7A","openreview_venues":["ACL ARR 2026 May Submission"]},{"id":"2506.11475","versioned_id":"2506.11475v2","title":"AutoGen Driven Multi Agent Framework for Iterative Crime Data Analysis and Prediction","authors":["Syeda Kisaa Fatima","Tehreem Zubair","Noman Ahmed","Asifullah Khan"],"abstract":"This paper introduces LUCID-MA (Learning and Understanding Crime through Dialogue of Multiple Agents), an innovative AI powered framework where multiple AI agents collaboratively analyze and understand crime data. Our system that consists of three core components: an analysis assistant that highlights spatiotemporal crime patterns; a feedback component that reviews and refines analytical results; and a prediction component that forecasts future crime trends. With a well-designed prompt and the LLaMA-2-13B-Chat-GPTQ model, it runs completely offline and allows the agents undergo self-improvement through 100 rounds of communication with less human interaction. A scoring function is incorporated to evaluate agent performance, providing visual plots to track learning progress. This work demonstrates the potential of AutoGen-style agents for autonomous, scalable, and iterative analysis in social science domains, maintaining data privacy through offline execution. It also showcases a computational model with emergent intelligence, where the system's global behavior emerges from the interactions of its agents. This emergent behavior manifests as enhanced individual agent performance, driven by collaborative dialogue between the LLM-based agents.","published":"2025-06-13T05:39:28Z","updated":"2025-07-20T10:54:02Z","categories":["cs.MA","cs.CL","cs.CV"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2506.11475v2","pdf_url":"https://arxiv.org/pdf/2506.11475v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.11425","versioned_id":"2506.11425v2","title":"Agent-RLVR: Training Software Engineering Agents via Guidance and Environment Rewards","authors":["Jeff Da","Clinton Wang","Xiang Deng","Yuntao Ma","Nikhil Barhate","Sean Hendryx"],"abstract":"Reinforcement Learning from Verifiable Rewards (RLVR) has been widely adopted as the de facto method for enhancing the reasoning capabilities of large language models and has demonstrated notable success in verifiable domains like math and competitive programming tasks. However, the efficacy of RLVR diminishes significantly when applied to agentic environments. These settings, characterized by multi-step, complex problem solving, lead to high failure rates even for frontier LLMs, as the reward landscape is too sparse for effective model training via conventional RLVR. In this work, we introduce Agent-RLVR, a framework that makes RLVR effective in challenging agentic settings, with an initial focus on software engineering tasks. Inspired by human pedagogy, Agent-RLVR introduces agent guidance, a mechanism that actively steers the agent towards successful trajectories by leveraging diverse informational cues. These cues, ranging from high-level strategic plans to dynamic feedback on the agent's errors and environmental interactions, emulate a teacher's guidance, enabling the agent to navigate difficult solution spaces and promotes active self-improvement via additional environment exploration. In the Agent-RLVR training loop, agents first attempt to solve tasks to produce initial trajectories, which are then validated by unit tests and supplemented with agent guidance. Agents then reattempt with guidance, and the agent policy is updated with RLVR based on the rewards of these guided trajectories. Agent-RLVR elevates the pass@1 performance of Qwen-2.5-72B-Instruct from 9.4% to 22.4% on SWE-Bench Verified. We find that our guidance-augmented RLVR data is additionally useful for test-time reward model training, shown by further boosting pass@1 to 27.8%. Agent-RLVR lays the groundwork for training agents with RLVR in complex, real-world environments where conventional RL methods struggle.","published":"2025-06-13T02:46:53Z","updated":"2025-06-20T23:32:06Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.11425v2","pdf_url":"https://arxiv.org/pdf/2506.11425v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.10501","versioned_id":"2506.10501v2","title":"BugGen: A Self-Correcting Multi-Agent LLM Pipeline for Realistic RTL Bug Synthesis","authors":["Surya Jasper","Minh Luu","Evan Pan","Aakash Tyagi","Michael Quinn","Jiang Hu","David Kebo Houngninou"],"abstract":"Hardware complexity continues to strain verification resources, motivating the adoption of machine learning (ML) methods to improve debug efficiency. However, ML-assisted debugging critically depends on diverse and scalable bug datasets, which existing manual or automated bug insertion methods fail to reliably produce. We introduce BugGen, a first of its kind, fully autonomous, multi-agent pipeline leveraging Large Language Models (LLMs) to systematically generate, insert, and validate realistic functional bugs in RTL. BugGen partitions modules, selects mutation targets via a closed-loop agentic architecture, and employs iterative refinement and rollback mechanisms to ensure syntactic correctness and functional detectability. Evaluated across five OpenTitan IP blocks, BugGen produced 500 unique bugs with 94% functional accuracy and achieved a throughput of 17.7 validated bugs per hour-over five times faster than typical manual expert insertion. Additionally, BugGen identified 104 previously undetected bugs in OpenTitan regressions, highlighting its utility in exposing verification coverage gaps. Compared against Certitude, BugGen demonstrated over twice the syntactic accuracy, deeper exposure of testbench blind spots, and more functionally meaningful and complex bug scenarios. Furthermore, when these BugGen-generated datasets were employed to train ML-based failure triage models, we achieved high classification accuracy (88.1%-93.2%) across different IP blocks, confirming the practical utility and realism of generated bugs. BugGen thus provides a scalable solution for generating high-quality bug datasets, significantly enhancing verification efficiency and ML-assisted debugging.","published":"2025-06-12T09:02:20Z","updated":"2025-06-18T06:29:15Z","categories":["cs.SE","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2506.10501v2","pdf_url":"https://arxiv.org/pdf/2506.10501v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.10086","versioned_id":"2506.10086v1","title":"Chat-of-Thought: Collaborative Multi-Agent System for Generating Domain Specific Information","authors":["Christodoulos Constantinides","Shuxin Lin","Nianjun Zhou","Dhaval Patel"],"abstract":"This paper presents a novel multi-agent system called Chat-of-Thought, designed to facilitate the generation of Failure Modes and Effects Analysis (FMEA) documents for industrial assets. Chat-of-Thought employs multiple collaborative Large Language Model (LLM)-based agents with specific roles, leveraging advanced AI techniques and dynamic task routing to optimize the generation and validation of FMEA tables. A key innovation in this system is the introduction of a Chat of Thought, where dynamic, multi-persona-driven discussions enable iterative refinement of content. This research explores the application domain of industrial equipment monitoring, highlights key challenges, and demonstrates the potential of Chat-of-Thought in addressing these challenges through interactive, template-driven workflows and context-aware agent collaboration.","published":"2025-06-11T18:06:06Z","updated":"2025-06-11T18:06:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.10086v1","pdf_url":"https://arxiv.org/pdf/2506.10086v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.08726","versioned_id":"2506.08726v3","title":"Improved LLM Agents for Financial Document Question Answering","authors":["Nelvin Tan","Zian Seng","Liang Zhang","Yu-Ching Shih","Dong Yang","Amol Salunkhe"],"abstract":"Large language models (LLMs) have shown impressive capabilities on numerous natural language processing tasks. However, LLMs still struggle with numerical question answering for financial documents that include tabular and textual data. Recent works have showed the effectiveness of critic agents (i.e., self-correction) for this task given oracle labels. Building upon this framework, this paper examines the effectiveness of the traditional critic agent when oracle labels are not available, and show, through experiments, that this critic agent's performance deteriorates in this scenario. With this in mind, we present an improved critic agent, along with the calculator agent which outperforms the previous state-of-the-art approach (program-of-thought) and is safer. Furthermore, we investigate how our agents interact with each other, and how this interaction affects their performance.","published":"2025-06-10T12:22:57Z","updated":"2026-01-07T07:50:27Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.08726v3","pdf_url":"https://arxiv.org/pdf/2506.08726v3","comment":"13 pages, 6 figures. More analysis is added to Appendix C","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=BO8fJNuprd","openreview_venues":["ACL ARR 2026 May Submission","ACL ARR 2025 May Submission"]},{"id":"2506.08012","versioned_id":"2506.08012v1","title":"GUI-Reflection: Empowering Multimodal GUI Models with Self-Reflection Behavior","authors":["Penghao Wu","Shengnan Ma","Bo Wang","Jiaheng Yu","Lewei Lu","Ziwei Liu"],"abstract":"Multimodal Large Language Models (MLLMs) have shown great potential in revolutionizing Graphical User Interface (GUI) automation. However, existing GUI models mostly rely on learning from nearly error-free offline trajectories, thus lacking reflection and error recovery capabilities. To bridge this gap, we propose GUI-Reflection, a novel framework that explicitly integrates self-reflection and error correction capabilities into end-to-end multimodal GUI models throughout dedicated training stages: GUI-specific pre-training, offline supervised fine-tuning (SFT), and online reflection tuning. GUI-reflection enables self-reflection behavior emergence with fully automated data generation and learning processes without requiring any human annotation. Specifically, 1) we first propose scalable data pipelines to automatically construct reflection and error correction data from existing successful trajectories. While existing GUI models mainly focus on grounding and UI understanding ability, we propose the GUI-Reflection Task Suite to learn and evaluate reflection-oriented abilities explicitly. 2) Furthermore, we built a diverse and efficient environment for online training and data collection of GUI models on mobile devices. 3) We also present an iterative online reflection tuning algorithm leveraging the proposed environment, enabling the model to continuously enhance its reflection and error correction abilities. Our framework equips GUI agents with self-reflection and correction capabilities, paving the way for more robust, adaptable, and intelligent GUI automation, with all data, models, environments, and tools to be released publicly.","published":"2025-06-09T17:59:57Z","updated":"2025-06-09T17:59:57Z","categories":["cs.AI","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.08012v1","pdf_url":"https://arxiv.org/pdf/2506.08012v1","comment":"Project Page at https://penghao-wu.github.io/GUI_Reflection/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=qup6v4WnYX","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2506.07468","versioned_id":"2506.07468v4","title":"Chasing Moving Targets with Online Self-Play Reinforcement Learning for Safer Language Models","authors":["Mickel Liu","Liwei Jiang","Yancheng Liang","Simon Shaolei Du","Yejin Choi","Tim Althoff","Natasha Jaques"],"abstract":"Conventional large language model (LLM) safety alignment relies on a reactive, disjoint loop: attackers exploit a static model, then defenders patch exposed vulnerabilities. This sequential setup leads to attackers overfitting obsolete exploits while defenders perpetually lag behind emerging threats. To address this, we introduce Self-RedTeam, the first fully online self-play multi-agent reinforcement learning (MARL) algorithm that continuously co-evolves attacker and defender for robust safety alignment. A single policy self-plays as both attacker and defender, generating adversarial prompts and defending against them, with a reward model adjudicating outcomes. Each role uses hidden chain-of-thought for strategic planning. Grounded in two-player zero-sum game theory, we establish a theoretical safety guarantee: if the game converges to Nash Equilibrium, the defender produces safe responses against any adversarial input. Empirically, Self-RedTeam generalizes across five models from the Llama and Qwen families, uncovering more diverse attacks (+17.80% SBERT) and improving safety of RLHF-trained models by up to 95% across 14 benchmarks. Our work motivates a shift from reactive patching to proactive co-evolution, enabling LLM safety self-improvement via online self-play MARL. Link to code: https://github.com/mickelliu/selfplay-redteaming","published":"2025-06-09T06:35:12Z","updated":"2026-07-06T07:31:35Z","categories":["cs.LG","cs.CL","cs.MA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.07468v4","pdf_url":"https://arxiv.org/pdf/2506.07468v4","comment":"ICML 2026 Poster","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=VqQ1DXEeyo","openreview_venues":["ICML 2026 regular"]},{"id":"2506.07398","versioned_id":"2506.07398v2","title":"G-Memory: Tracing Hierarchical Memory for Multi-Agent Systems","authors":["Guibin Zhang","Muxin Fu","Guancheng Wan","Miao Yu","Kun Wang","Shuicheng Yan"],"abstract":"Large language model (LLM)-powered multi-agent systems (MAS) have demonstrated cognitive and execution capabilities that far exceed those of single LLM agents, yet their capacity for self-evolution remains hampered by underdeveloped memory architectures. Upon close inspection, we are alarmed to discover that prevailing MAS memory mechanisms (1) are overly simplistic, completely disregarding the nuanced inter-agent collaboration trajectories, and (2) lack cross-trial and agent-specific customization, in stark contrast to the expressive memory developed for single agents. To bridge this gap, we introduce G-Memory, a hierarchical, agentic memory system for MAS inspired by organizational memory theory, which manages the lengthy MAS interaction via a three-tier graph hierarchy: insight, query, and interaction graphs. Upon receiving a new user query, G-Memory performs bi-directional memory traversal to retrieve both $\\textit{high-level, generalizable insights}$ that enable the system to leverage cross-trial knowledge, and $\\textit{fine-grained, condensed interaction trajectories}$ that compactly encode prior collaboration experiences. Upon task execution, the entire hierarchy evolves by assimilating new collaborative trajectories, nurturing the progressive evolution of agent teams. Extensive experiments across five benchmarks, three LLM backbones, and three popular MAS frameworks demonstrate that G-Memory improves success rates in embodied action and accuracy in knowledge QA by up to $20.89\\%$ and $10.12\\%$, respectively, without any modifications to the original frameworks. Our codes are available at https://github.com/bingreeky/GMemory.","published":"2025-06-09T03:43:46Z","updated":"2025-06-16T08:45:10Z","categories":["cs.MA","cs.CL","cs.LG"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2506.07398v2","pdf_url":"https://arxiv.org/pdf/2506.07398v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=mmIAp3cVS0","openreview_venues":["NeurIPS 2025 spotlight"]},{"id":"2506.06923","versioned_id":"2506.06923v1","title":"Boosting LLM Reasoning via Spontaneous Self-Correction","authors":["Xutong Zhao","Tengyu Xu","Xuewei Wang","Zhengxing Chen","Di Jin","Liang Tan","Yen-Ting","Zishun Yu","Zhuokai Zhao","Yun He","Sinong Wang","Han Fang","Sarath Chandar","Chen Zhu"],"abstract":"While large language models (LLMs) have demonstrated remarkable success on a broad range of tasks, math reasoning remains a challenging one. One of the approaches for improving math reasoning is self-correction, which designs self-improving loops to let the model correct its own mistakes. However, existing self-correction approaches treat corrections as standalone post-generation refinements, relying on extra prompt and system designs to elicit self-corrections, instead of performing real-time, spontaneous self-corrections in a single pass. To address this, we propose SPOC, a spontaneous self-correction approach that enables LLMs to generate interleaved solutions and verifications in a single inference pass, with generation dynamically terminated based on verification outcomes, thereby effectively scaling inference time compute. SPOC considers a multi-agent perspective by assigning dual roles -- solution proposer and verifier -- to the same model. We adopt a simple yet effective approach to generate synthetic data for fine-tuning, enabling the model to develop capabilities for self-verification and multi-agent collaboration. We further improve its solution proposal and verification accuracy through online reinforcement learning. Experiments on mathematical reasoning benchmarks show that SPOC significantly improves performance. Notably, SPOC boosts the accuracy of Llama-3.1-8B and 70B Instruct models, achieving gains of 8.8% and 11.6% on MATH500, 10.0% and 20.0% on AMC23, and 3.3% and 6.7% on AIME24, respectively.","published":"2025-06-07T21:23:00Z","updated":"2025-06-07T21:23:00Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.06923v1","pdf_url":"https://arxiv.org/pdf/2506.06923v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=9DCQAGBoII","openreview_venues":["AI4Math@ICML25 Poster","COLM 2025"]},{"id":"2506.06698","versioned_id":"2506.06698v1","title":"Contextual Experience Replay for Self-Improvement of Language Agents","authors":["Yitao Liu","Chenglei Si","Karthik Narasimhan","Shunyu Yao"],"abstract":"Large language model (LLM) agents have been applied to sequential decision-making tasks such as web navigation, but without any environment-specific experiences, they often fail in these complex tasks. Moreover, current LLM agents are not designed to continually learn from past experiences during inference time, which could be crucial for them to gain these environment-specific experiences. To address this, we propose Contextual Experience Replay (CER), a training-free framework to enable efficient self-improvement for language agents in their context window. Specifically, CER accumulates and synthesizes past experiences into a dynamic memory buffer. These experiences encompass environment dynamics and common decision-making patterns, allowing the agents to retrieve and augment themselves with relevant knowledge in new tasks, enhancing their adaptability in complex environments. We evaluate CER on the challenging WebArena and VisualWebArena benchmarks. On VisualWebArena, CER achieves a competitive performance of 31.9%. On WebArena, CER also gets a competitive average success rate of 36.7%, relatively improving the success rate of the GPT-4o agent baseline by 51.0%. We also conduct a comprehensive analysis on it to prove its efficiency, validity and understand it better.","published":"2025-06-07T07:47:35Z","updated":"2025-06-07T07:47:35Z","categories":["cs.AI","cs.CL","cs.CV","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.06698v1","pdf_url":"https://arxiv.org/pdf/2506.06698v1","comment":"Accepted to ACL 2025. 20 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.06658","versioned_id":"2506.06658v3","title":"Self-Improving Loops for Visual Robotic Planning","authors":["Calvin Luo","Zilai Zeng","Mingxi Jia","Yilun Du","Chen Sun"],"abstract":"Video generative models trained on expert demonstrations have been utilized as performant text-conditioned visual planners for solving robotic tasks. However, generalization to unseen tasks remains a challenge. Whereas improved generalization may be facilitated by leveraging learned prior knowledge from additional pre-collected offline data sources, such as web-scale video datasets, in the era of experience we aim to design agents that can continuously improve in an online manner from self-collected behaviors. In this work we thus propose the Self-Improving Loops for Visual Robotic Planning (SILVR), where an in-domain video model iteratively updates itself on self-produced trajectories, and steadily improves its performance for a specified task of interest. We apply SILVR to a diverse suite of MetaWorld tasks, as well as two manipulation tasks on a real robot arm, and find that performance improvements continuously emerge over multiple iterations for novel tasks unseen during initial in-domain video model training. We demonstrate that SILVR is robust in the absence of human-provided ground-truth reward functions or expert-quality demonstrations, and is preferable to alternate approaches that utilize online experience in terms of performance and sample efficiency.","published":"2025-06-07T04:34:37Z","updated":"2026-03-11T01:24:50Z","categories":["cs.RO","cs.AI"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2506.06658v3","pdf_url":"https://arxiv.org/pdf/2506.06658v3","comment":"ICLR 2026. Project Page: https://diffusion-supervision.github.io/silvr/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":65,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=SzUgx5r3wy","openreview_venues":["FMEA @ CVPR 2026 Poster"]},{"id":"2506.05109","versioned_id":"2506.05109v1","title":"Truly Self-Improving Agents Require Intrinsic Metacognitive Learning","authors":["Tennison Liu","Mihaela van der Schaar"],"abstract":"Self-improving agents aim to continuously acquire new capabilities with minimal supervision. However, current approaches face two key limitations: their self-improvement processes are often rigid, fail to generalize across tasks domains, and struggle to scale with increasing agent capabilities. We argue that effective self-improvement requires intrinsic metacognitive learning, defined as an agent's intrinsic ability to actively evaluate, reflect on, and adapt its own learning processes. Drawing inspiration from human metacognition, we introduce a formal framework comprising three components: metacognitive knowledge (self-assessment of capabilities, tasks, and learning strategies), metacognitive planning (deciding what and how to learn), and metacognitive evaluation (reflecting on learning experiences to improve future learning). Analyzing existing self-improving agents, we find they rely predominantly on extrinsic metacognitive mechanisms, which are fixed, human-designed loops that limit scalability and adaptability. Examining each component, we contend that many ingredients for intrinsic metacognition are already present. Finally, we explore how to optimally distribute metacognitive responsibilities between humans and agents, and robustly evaluate and improve intrinsic metacognitive learning, key challenges that must be addressed to enable truly sustained, generalized, and aligned self-improvement.","published":"2025-06-05T14:53:35Z","updated":"2025-06-05T14:53:35Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.05109v1","pdf_url":"https://arxiv.org/pdf/2506.05109v1","comment":"Published as a conference paper at ICML 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.03939","versioned_id":"2506.03939v1","title":"Graph Counselor: Adaptive Graph Exploration via Multi-Agent Synergy to Enhance LLM Reasoning","authors":["Junqi Gao","Xiang Zou","YIng Ai","Dong Li","Yichen Niu","Biqing Qi","Jianxing Liu"],"abstract":"Graph Retrieval Augmented Generation (GraphRAG) effectively enhances external knowledge integration capabilities by explicitly modeling knowledge relationships, thereby improving the factual accuracy and generation quality of Large Language Models (LLMs) in specialized domains. However, existing methods suffer from two inherent limitations: 1) Inefficient Information Aggregation: They rely on a single agent and fixed iterative patterns, making it difficult to adaptively capture multi-level textual, structural, and degree information within graph data. 2) Rigid Reasoning Mechanism: They employ preset reasoning schemes, which cannot dynamically adjust reasoning depth nor achieve precise semantic correction. To overcome these limitations, we propose Graph Counselor, an GraphRAG method based on multi-agent collaboration. This method uses the Adaptive Graph Information Extraction Module (AGIEM), where Planning, Thought, and Execution Agents work together to precisely model complex graph structures and dynamically adjust information extraction strategies, addressing the challenges of multi-level dependency modeling and adaptive reasoning depth. Additionally, the Self-Reflection with Multiple Perspectives (SR) module improves the accuracy and semantic consistency of reasoning results through self-reflection and backward reasoning mechanisms. Experiments demonstrate that Graph Counselor outperforms existing methods in multiple graph reasoning tasks, exhibiting higher reasoning accuracy and generalization ability. Our code is available at https://github.com/gjq100/Graph-Counselor.git.","published":"2025-06-04T13:31:21Z","updated":"2025-06-04T13:31:21Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.03939v1","pdf_url":"https://arxiv.org/pdf/2506.03939v1","comment":"Accepted by ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.04293","versioned_id":"2506.04293v1","title":"AUTOCT: Automating Interpretable Clinical Trial Prediction with LLM Agents","authors":["Fengze Liu","Haoyu Wang","Joonhyuk Cho","Dan Roth","Andrew W. Lo"],"abstract":"Clinical trials are critical for advancing medical treatments but remain prohibitively expensive and time-consuming. Accurate prediction of clinical trial outcomes can significantly reduce research and development costs and accelerate drug discovery. While recent deep learning models have shown promise by leveraging unstructured data, their black-box nature, lack of interpretability, and vulnerability to label leakage limit their practical use in high-stakes biomedical contexts. In this work, we propose AutoCT, a novel framework that combines the reasoning capabilities of large language models with the explainability of classical machine learning. AutoCT autonomously generates, evaluates, and refines tabular features based on public information without human input. Our method uses Monte Carlo Tree Search to iteratively optimize predictive performance. Experimental results show that AutoCT performs on par with or better than SOTA methods on clinical trial prediction tasks within only a limited number of self-refinement iterations, establishing a new paradigm for scalable, interpretable, and cost-efficient clinical trial prediction.","published":"2025-06-04T11:50:55Z","updated":"2025-06-04T11:50:55Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2506.04293v1","pdf_url":"https://arxiv.org/pdf/2506.04293v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.03541","versioned_id":"2506.03541v1","title":"Debate, Reflect, and Distill: Multi-Agent Feedback with Tree-Structured Preference Optimization for Efficient Language Model Enhancement","authors":["Xiaofeng Zhou","Heyan Huang","Lizi Liao"],"abstract":"Large Language Models (LLMs) continue to set new standards in knowledge-intensive and complex reasoning tasks, yet their high computational demands limit widespread adoption. While distilling large models into smaller ones offers a sustainable solution, current techniques--such as static knowledge distillation, resource-intensive reinforcement learning from human feedback, or limited self-reflection--struggle to yield substantial and lasting performance gains. In this paper, we present a novel Debate and Reflect (D&R) framework that orchestrates multi-turn debates between smaller models and stronger teacher models, eliciting actionable feedback (e.g., error analysis, corrective strategies) to guide student models. Further, we introduce Tree-structured Direct Preference Optimization (T-DPO) to efficiently leverage these debate logs, organizing interactions into a hierarchical format for effective training. Empirical evaluations across diverse NLP benchmarks demonstrate that our approach significantly improves smaller-model accuracy, robustness, and generalization, outperforming conventional baselines by a large margin.","published":"2025-06-04T03:52:20Z","updated":"2025-06-04T03:52:20Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2506.03541v1","pdf_url":"https://arxiv.org/pdf/2506.03541v1","comment":"16 pages, 10 figures. The camera-ready paper for Findings of ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.03530","versioned_id":"2506.03530v3","title":"How Far Are We from Generating Missing Modalities with Foundation Models?","authors":["Guanzhou Ke","Bo Wang","Guoqing Chao","Weiming Hu","Shengfeng He"],"abstract":"Multimodal foundation models have demonstrated impressive capabilities across diverse tasks. However, their potential as plug-and-play solutions for missing modality reconstruction remains underexplored. To bridge this gap, we identify and formalize three potential paradigms for missing modality reconstruction, and perform a comprehensive evaluation across these paradigms, covering 42 model variants in terms of reconstruction accuracy and adaptability to downstream tasks. Our analysis reveals that current foundation models often fall short in two critical aspects: (i) fine-grained semantic extraction from the available modalities, and (ii) robust validation of generated modalities. These limitations lead to suboptimal and, at times, misaligned generations. To address these challenges, we propose an agentic framework tailored for missing modality reconstruction. This framework dynamically formulates modality-aware mining strategies based on the input context, facilitating the extraction of richer and more discriminative semantic features. In addition, we introduce a self-refinement mechanism, which iteratively verifies and enhances the quality of generated modalities through internal feedback. Experimental results show that our method reduces FID for missing image reconstruction by at least 14\\% and MER for missing text reconstruction by at least 10\\% compared to baselines. Code are released at: https://github.com/Guanzhou-Ke/AFM2.","published":"2025-06-04T03:22:44Z","updated":"2026-05-22T06:55:17Z","categories":["cs.MM","cs.CL","cs.CV"],"primary_category":"cs.MM","arxiv_url":"https://arxiv.org/abs/2506.03530v3","pdf_url":"https://arxiv.org/pdf/2506.03530v3","comment":"T-PAMI","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.02992","versioned_id":"2506.02992v2","title":"Mitigating Manipulation and Enhancing Persuasion: A Reflective Multi-Agent Approach for Legal Argument Generation","authors":["Li Zhang","Kevin D. Ashley"],"abstract":"Large Language Models (LLMs) are increasingly explored for legal argument generation, yet they pose significant risks of manipulation through hallucination and ungrounded persuasion, and often fail to utilize provided factual bases effectively or abstain when arguments are untenable. This paper introduces a novel reflective multi-agent method designed to address these challenges in the context of legally compliant persuasion. Our approach employs specialized agents (factor analyst and argument polisher) in an iterative refinement process to generate 3-ply legal arguments (plaintiff, defendant, rebuttal). We evaluate reflective multi-agent against single-agent, enhanced-prompt single-agent, and non-reflective multi-agent baselines using four diverse LLMs (GPT-4o, GPT-4o-mini, Llama-4-Maverick-17b-128e, Llama-4-Scout-17b-16e) across three legal scenarios: \"arguable\", \"mismatched\", and \"non-arguable\". Results demonstrate that the reflective multi-agent approach excels at successful abstention by preventing generation when arguments cannot be grounded, improves hallucination accuracy by reducing fabricated and misattributed factors and enhances factor utilization recall by better using the provided case facts. These findings suggest that structured reflection within a multi-agent framework offers a robust method for fostering ethical persuasion and mitigating manipulation in LLM-based legal argumentation systems.","published":"2025-06-03T15:28:30Z","updated":"2025-10-23T18:35:56Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.02992v2","pdf_url":"https://arxiv.org/pdf/2506.02992v2","comment":"13 pages, 2 figures, 2nd ConventicLe on Artificial Intelligence Regulation and Safety Workshop at ICAIL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.02158","versioned_id":"2506.02158v1","title":"Reflection-Based Memory For Web navigation Agents","authors":["Ruhana Azam","Aditya Vempaty","Ashish Jagmohan"],"abstract":"Web navigation agents have made significant progress, yet current systems operate with no memory of past experiences -- leading to repeated mistakes and an inability to learn from previous interactions. We introduce Reflection-Augment Planning (ReAP), a web navigation system to leverage both successful and failed past experiences using self-reflections. Our method improves baseline results by 11 points overall and 29 points on previously failed tasks. These findings demonstrate that reflections can transfer to different web navigation tasks.","published":"2025-06-02T18:39:55Z","updated":"2025-06-02T18:39:55Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.02158v1","pdf_url":"https://arxiv.org/pdf/2506.02158v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.01273","versioned_id":"2506.01273v1","title":"RAISE: Reasoning Agent for Interactive SQL Exploration","authors":["Fernando Granado","Roberto Lotufo","Jayr Pereira"],"abstract":"Recent advances in large language models (LLMs) have propelled research in natural language interfaces to databases. However, most state-of-the-art text-to-SQL systems still depend on complex, multi-stage pipelines. This work proposes a novel agentic framework that unifies schema linking, query generation, and iterative refinement within a single, end-to-end component. By leveraging the intrinsic reasoning abilities of LLMs, our method emulates how humans answer questions when working with unfamiliar databases: understanding the data by formulating hypotheses, running dynamic queries to validate them, reasoning over the results, and revising outputs based on observed results. Crucially, our approach introduces a new strategy for scaling test-time computation in text-to-SQL: we scale the depth of interactive database exploration and reflection. This shift enables the model to allocate computation dynamically to better understand the data, especially useful in ambiguous and underspecified scenarios. Our experiments show that it improved the Execution Accuracy (EX) from 44.8% to 56.5% on the challenging BIRD dataset using DeepSeek-R1-Distill-Llama-70B. Furthermore, when equipped with steps to add more diversity to the answers, our agent achieves a Best-of-N accuracy of 81.8% with 8 rounds of candidate generation, rivaling the 82.79% achieved by the top-ranked published solution, while reducing engineering complexity. These findings position our unified framework as a promising alternative for building natural language interfaces to databases.","published":"2025-06-02T03:07:08Z","updated":"2025-06-02T03:07:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.01273v1","pdf_url":"https://arxiv.org/pdf/2506.01273v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.04255","versioned_id":"2506.04255v1","title":"HASHIRU: Hierarchical Agent System for Hybrid Intelligent Resource Utilization","authors":["Kunal Pai","Parth Shah","Harshil Patel"],"abstract":"Rapid Large Language Model (LLM) advancements are fueling autonomous Multi-Agent System (MAS) development. However, current frameworks often lack flexibility, resource awareness, model diversity, and autonomous tool creation. This paper introduces HASHIRU (Hierarchical Agent System for Hybrid Intelligent Resource Utilization), a novel MAS framework enhancing flexibility, resource efficiency, and adaptability. HASHIRU features a \"CEO\" agent dynamically managing specialized \"employee\" agents, instantiated based on task needs and resource constraints (cost, memory). Its hybrid intelligence prioritizes smaller, local LLMs (via Ollama) while flexibly using external APIs and larger models when necessary. An economic model with hiring/firing costs promotes team stability and efficient resource allocation. The system also includes autonomous API tool creation and a memory function. Evaluations on tasks like academic paper review (58% success), safety assessments (100% on a JailbreakBench subset), and complex reasoning (outperforming Gemini 2.0 Flash on GSM8K: 96% vs. 61%; JEEBench: 80% vs. 68.3%; SVAMP: 92% vs. 84%) demonstrate HASHIRU's capabilities. Case studies illustrate its self-improvement via autonomous cost model generation, tool integration, and budget management. HASHIRU offers a promising approach for more robust, efficient, and adaptable MAS through dynamic hierarchical control, resource-aware hybrid intelligence, and autonomous functional extension. Source code and benchmarks are available at https://github.com/HASHIRU-AI/HASHIRU and https://github.com/HASHIRU-AI/HASHIRUBench respectively, and a live demo is available at https://hashiruagentx-hashiruai.hf.space upon request.","published":"2025-06-01T17:33:16Z","updated":"2025-06-01T17:33:16Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2506.04255v1","pdf_url":"https://arxiv.org/pdf/2506.04255v1","comment":"Submitted as part of the Research Track at AgentX 2025, organized by Berkeley RDI","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.00856","versioned_id":"2506.00856v3","title":"Can AI Master Econometrics? Evidence from Econometrics AI Agent on Expert-Level Tasks","authors":["Qiang Chen","Tianyang Han","Jin Li","Ye Luo","Zigan Wang","Yuxiao Wu","Xiaowei Zhang","Tuo Zhou"],"abstract":"Can AI effectively perform complex econometric analysis traditionally requiring human expertise? This paper evaluates AI agents' capability to master econometrics, focusing on empirical analysis performance. We develop ``MetricsAI'', an Econometrics AI Agent built on the open-source MetaGPT framework. This agent exhibits outstanding performance in: (1) planning econometric tasks strategically, (2) generating and executing code, (3) employing error-based reflection for improved robustness, and (4) allowing iterative refinement through multi-round conversations. We construct two datasets from academic coursework materials and published research papers to evaluate performance against real-world challenges. Comparative testing shows our domain-specialized AI agent significantly outperforms both benchmark large language models (LLMs) and general-purpose AI agents. This work establishes a testbed for exploring AI's impact on social science research and enables cost-effective integration of domain expertise, making advanced econometric methods accessible to users with minimal coding skills. Furthermore, our AI agent enhances research reproducibility and offers promising pedagogical applications for econometrics teaching.","published":"2025-06-01T06:34:42Z","updated":"2026-01-28T05:23:02Z","categories":["econ.EM","cs.AI"],"primary_category":"econ.EM","arxiv_url":"https://arxiv.org/abs/2506.00856v3","pdf_url":"https://arxiv.org/pdf/2506.00856v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2506.00320","versioned_id":"2506.00320v3","title":"Dyna-Think: Synergizing Reasoning, Acting, and World Model Simulation in AI Agents","authors":["Xiao Yu","Baolin Peng","Ruize Xu","Michel Galley","Hao Cheng","Suman Nath","Jianfeng Gao","Zhou Yu"],"abstract":"Recent progress in reasoning with large language models (LLMs), such as DeepSeek-R1, demonstrates impressive capabilities in domains like mathematics and coding, by exhibiting complex cognitive behaviors such as verification, goal decomposition, and self-reflection. However, it is unclear what behavior is effective and what behavior is missing for long-horizon AI agents tasks. In this work, we propose Dyna-Think, a thinking framework that integrates planning with an internal world model with reasoning and acting to enhance AI agent performance. To enable Dyna-Think, we propose Dyna-Think Imitation Learning (DIT) and Dyna-Think Dyna Training (DDT). To initialize a policy with Dyna-Think, DIT reconstructs the thinking process of R1 to focus on performing world model simulation relevant to the proposed (and planned) action, and trains the policy using this reconstructed data. To enhance Dyna-Think, DDT uses a two-stage training process to first improve the agent's world modeling ability via objectives such as state prediction or critique generation, and then improve the agent's action via policy training. We evaluate our methods on OSWorld and WindowsAgentArena, and demonstrate that Dyna-Think improves the agent's in-domain and out-of-domain performance, achieving similar best-of-n performance compared to R1 while generating 2x less tokens on average. Our extensive empirical studies reveal that 1) using critique generation for world model training is effective to improve policy performance; and 2) AI agents with better performance correlate with better world modeling abilities. We believe our results suggest a promising research direction to integrate world model simulation into AI agents to enhance their reasoning, planning, and acting capabilities.","published":"2025-05-31T00:10:18Z","updated":"2025-10-10T22:01:33Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2506.00320v3","pdf_url":"https://arxiv.org/pdf/2506.00320v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0z0xhXRbN3","openreview_venues":["ICLR 2026 Workshop World Models"]},{"id":"2505.24671","versioned_id":"2505.24671v2","title":"Multiple LLM Agents Debate for Equitable Cultural Alignment","authors":["Dayeon Ki","Rachel Rudinger","Tianyi Zhou","Marine Carpuat"],"abstract":"Large Language Models (LLMs) need to adapt their predictions to diverse cultural contexts to benefit diverse communities across the world. While previous efforts have focused on single-LLM, single-turn approaches, we propose to exploit the complementary strengths of multiple LLMs to promote cultural adaptability. We introduce a Multi-Agent Debate framework, where two LLM-based agents debate over a cultural scenario and collaboratively reach a final decision. We propose two variants: one where either LLM agents exclusively debate and another where they dynamically choose between self-reflection and debate during their turns. We evaluate these approaches on 7 open-weight LLMs (and 21 LLM combinations) using the NormAd-ETI benchmark for social etiquette norms in 75 countries. Experiments show that debate improves both overall accuracy and cultural group parity over single-LLM baselines. Notably, multi-agent debate enables relatively small LLMs (7-9B) to achieve accuracies comparable to that of a much larger model (27B parameters).","published":"2025-05-30T15:01:52Z","updated":"2025-09-01T12:34:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.24671v2","pdf_url":"https://arxiv.org/pdf/2505.24671v2","comment":"ACL 2025 (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.24197","versioned_id":"2505.24197v2","title":"Learning API Functionality from In-Context Demonstrations for Tool-based Agents","authors":["Bhrij Patel","Ashish Jagmohan","Aditya Vempaty"],"abstract":"Digital tool-based agents, powered by Large Language Models (LLMs), that invoke external Application Programming Interfaces (APIs) often rely on documentation to understand API functionality. However, such documentation is frequently missing, outdated, privatized, or inconsistent-hindering the development of reliable, general-purpose agents. In this work, we propose a new research direction: learning of API functionality directly from in-context demonstrations. This task is a new paradigm applicable in scenarios without documentation. Using API benchmarks, we collect demonstrations from both expert agents and from self-exploration. To understand what information demonstrations must convey for successful task completion, we extensively study how the number of demonstrations and the use of LLM-generated summaries and evaluations affect the task success rate of the API-based agent. Our experiments across 3 datasets and 6 models show that learning functionality from in-context demonstrations remains a non-trivial challenge, even for state-of-the-art LLMs. We find that providing explicit function calls and natural language critiques significantly improves the agent's task success rate due to more accurate parameter filling. We analyze failure modes, identify sources of error, and highlight key open challenges for future work in documentation-free, self-improving, API-based agents.","published":"2025-05-30T04:17:09Z","updated":"2025-11-12T03:07:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.24197v2","pdf_url":"https://arxiv.org/pdf/2505.24197v2","comment":"19 Pages, 14 Figures, 7 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.24073","versioned_id":"2505.24073v2","title":"mRAG: Elucidating the Design Space of Multi-modal Retrieval-Augmented Generation","authors":["Chan-Wei Hu","Yueqi Wang","Shuo Xing","Chia-Ju Chen","Suofei Feng","Ryan Rossi","Zhengzhong Tu"],"abstract":"Large Vision-Language Models (LVLMs) have made remarkable strides in multimodal tasks such as visual question answering, visual grounding, and complex reasoning. However, they remain limited by static training data, susceptibility to hallucinations, and inability to verify claims against up-to-date, external evidence, compromising their performance in dynamic real-world applications. Retrieval-Augmented Generation (RAG) offers a practical solution to mitigate these challenges by allowing the LVLMs to access large-scale knowledge databases via retrieval mechanisms, thereby grounding model outputs in factual, contextually relevant information. Here in this paper, we conduct the first systematic dissection of the multimodal RAG pipeline for LVLMs, explicitly investigating (1) the retrieval phase: on the modality configurations and retrieval strategies, (2) the re-ranking stage: on strategies to mitigate positional biases and improve the relevance of retrieved evidence, and (3) the generation phase: we further investigate how to best integrate retrieved candidates into the final generation process. Finally, we extend to explore a unified agentic framework that integrates re-ranking and generation through self-reflection, enabling LVLMs to select relevant evidence and suppress irrelevant context dynamically. Our full-stack exploration of RAG for LVLMs yields substantial insights, resulting in an average performance boost of 5% without any fine-tuning.","published":"2025-05-29T23:32:03Z","updated":"2025-08-26T16:42:37Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.24073v2","pdf_url":"https://arxiv.org/pdf/2505.24073v2","comment":"16 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=aZOZB1TbUT","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2505.23695","versioned_id":"2505.23695v1","title":"Data-to-Dashboard: Multi-Agent LLM Framework for Insightful Visualization in Enterprise Analytics","authors":["Ran Zhang","Mohannad Elhamod"],"abstract":"The rapid advancement of LLMs has led to the creation of diverse agentic systems in data analysis, utilizing LLMs' capabilities to improve insight generation and visualization. In this paper, we present an agentic system that automates the data-to-dashboard pipeline through modular LLM agents capable of domain detection, concept extraction, multi-perspective analysis generation, and iterative self-reflection. Unlike existing chart QA systems, our framework simulates the analytical reasoning process of business analysts by retrieving domain-relevant knowledge and adapting to diverse datasets without relying on closed ontologies or question templates. We evaluate our system on three datasets across different domains. Benchmarked against GPT-4o with a single-prompt baseline, our approach shows improved insightfulness, domain relevance, and analytical depth, as measured by tailored evaluation metrics and qualitative human assessment. This work contributes a novel modular pipeline to bridge the path from raw data to visualization, and opens new opportunities for human-in-the-loop validation by domain experts in business analytics. All code can be found here: https://github.com/77luvC/D2D_Data2Dashboard","published":"2025-05-29T17:32:15Z","updated":"2025-05-29T17:32:15Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.23695v1","pdf_url":"https://arxiv.org/pdf/2505.23695v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.22954","versioned_id":"2505.22954v3","title":"Darwin Godel Machine: Open-Ended Evolution of Self-Improving Agents","authors":["Jenny Zhang","Shengran Hu","Cong Lu","Robert Lange","Jeff Clune"],"abstract":"Today's AI systems have human-designed, fixed architectures and cannot autonomously and continuously improve themselves. The advance of AI could itself be automated. If done safely, that would accelerate AI development and allow us to reap its benefits much sooner. Meta-learning can automate the discovery of novel algorithms, but is limited by first-order improvements and the human design of a suitable search space. The Gödel machine proposed a theoretical alternative: a self-improving AI that repeatedly modifies itself in a provably beneficial manner. Unfortunately, proving that most changes are net beneficial is impossible in practice. We introduce the Darwin Gödel Machine (DGM), a self-improving system that iteratively modifies its own code (thereby also improving its ability to modify its own codebase) and empirically validates each change using coding benchmarks. Inspired by Darwinian evolution and open-endedness research, the DGM maintains an archive of generated coding agents. It grows the archive by sampling an agent from it and using a foundation model to create a new, interesting, version of the sampled agent. This open-ended exploration forms a growing tree of diverse, high-quality agents and allows the parallel exploration of many different paths through the search space. Empirically, the DGM automatically improves its coding capabilities (e.g., better code editing tools, long-context window management, peer-review mechanisms), increasing performance on SWE-bench from 20.0% to 50.0%, and on Polyglot from 14.2% to 30.7%. Furthermore, the DGM significantly outperforms baselines without self-improvement or open-ended exploration. All experiments were done with safety precautions (e.g., sandboxing, human oversight). The DGM is a significant step toward self-improving AI, capable of gathering its own stepping stones along paths that unfold into endless innovation.","published":"2025-05-29T00:26:15Z","updated":"2026-03-12T23:47:40Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.22954v3","pdf_url":"https://arxiv.org/pdf/2505.22954v3","comment":"Code at https://github.com/jennyzzt/dgm","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.22501","versioned_id":"2505.22501v1","title":"EvolveSearch: An Iterative Self-Evolving Search Agent","authors":["Dingchu Zhang","Yida Zhao","Jialong Wu","Baixuan Li","Wenbiao Yin","Liwen Zhang","Yong Jiang","Yufeng Li","Kewei Tu","Pengjun Xie","Fei Huang"],"abstract":"The rapid advancement of large language models (LLMs) has transformed the landscape of agentic information seeking capabilities through the integration of tools such as search engines and web browsers. However, current mainstream approaches for enabling LLM web search proficiency face significant challenges: supervised fine-tuning struggles with data production in open-search domains, while RL converges quickly, limiting their data utilization efficiency. To address these issues, we propose EvolveSearch, a novel iterative self-evolution framework that combines SFT and RL to enhance agentic web search capabilities without any external human-annotated reasoning data. Extensive experiments on seven multi-hop question-answering (MHQA) benchmarks demonstrate that EvolveSearch consistently improves performance across iterations, ultimately achieving an average improvement of 4.7\\% over the current state-of-the-art across seven benchmarks, opening the door to self-evolution agentic capabilities in open web search domains.","published":"2025-05-28T15:50:48Z","updated":"2025-05-28T15:50:48Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.22501v1","pdf_url":"https://arxiv.org/pdf/2505.22501v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=DNS0NlnT63","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2505.22053","versioned_id":"2505.22053v2","title":"AudioGenie: A Training-Free Multi-Agent Framework for Diverse Multimodality-to-Multiaudio Generation","authors":["Yan Rong","Jinting Wang","Guangzhi Lei","Shan Yang","Li Liu"],"abstract":"Multimodality-to-Multiaudio (MM2MA) generation faces significant challenges in synthesizing diverse and contextually aligned audio types (e.g., sound effects, speech, music, and songs) from multimodal inputs (e.g., video, text, images), owing to the scarcity of high-quality paired datasets and the lack of robust multi-task learning frameworks. Recently, multi-agent system shows great potential in tackling the above issues. However, directly applying it to MM2MA task presents three critical challenges: (1) inadequate fine-grained understanding of multimodal inputs (especially for video), (2) the inability of single models to handle diverse audio events, and (3) the absence of self-correction mechanisms for reliable outputs. To this end, we propose AudioGenie, a novel training-free multi-agent system featuring a dual-layer architecture with a generation team and a supervisor team. For the generation team, a fine-grained task decomposition and an adaptive Mixture-of-Experts (MoE) collaborative entity are designed for detailed comprehensive multimodal understanding and dynamic model selection, and a trial-and-error iterative refinement module is designed for self-correction. The supervisor team ensures temporal-spatial consistency and verifies outputs through feedback loops. Moreover, we build MA-Bench, the first benchmark for MM2MA tasks, comprising 198 annotated videos with multi-type audios. Experiments demonstrate that our AudioGenie achieves state-of-the-art (SOTA) or comparable performance across 9 metrics in 8 tasks. User study further validates the effectiveness of our method in terms of quality, accuracy, alignment, and aesthetic. The project website with audio samples can be found at https://audiogenie.github.io/.","published":"2025-05-28T07:23:53Z","updated":"2025-08-05T07:47:10Z","categories":["cs.SD","cs.MA","cs.MM","eess.AS"],"primary_category":"cs.SD","arxiv_url":"https://arxiv.org/abs/2505.22053v2","pdf_url":"https://arxiv.org/pdf/2505.22053v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.23815","versioned_id":"2505.23815v1","title":"Aligning LLMs by Predicting Preferences from User Writing Samples","authors":["Stéphane Aroca-Ouellette","Natalie Mackraz","Barry-John Theobald","Katherine Metcalf"],"abstract":"Accommodating human preferences is essential for creating aligned LLM agents that deliver personalized and effective interactions. Recent work has shown the potential for LLMs acting as writing agents to infer a description of user preferences. Agent alignment then comes from conditioning on the inferred preference description. However, existing methods often produce generic preference descriptions that fail to capture the unique and individualized nature of human preferences. This paper introduces PROSE, a method designed to enhance the precision of preference descriptions inferred from user writing samples. PROSE incorporates two key elements: (1) iterative refinement of inferred preferences, and (2) verification of inferred preferences across multiple user writing samples. We evaluate PROSE with several LLMs (i.e., Qwen2.5 7B and 72B Instruct, GPT-mini, and GPT-4o) on a summarization and an email writing task. We find that PROSE more accurately infers nuanced human preferences, improving the quality of the writing agent's generations over CIPHER (a state-of-the-art method for inferring preferences) by 33\\%. Lastly, we demonstrate that ICL and PROSE are complementary methods, and combining them provides up to a 9\\% improvement over ICL alone.","published":"2025-05-27T20:20:20Z","updated":"2025-05-27T20:20:20Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.23815v1","pdf_url":"https://arxiv.org/pdf/2505.23815v1","comment":"Accepted to ICML 2025. 32 pages total: 9 main, 2 references, 21 appendix. arXiv admin note: substantial text overlap with arXiv:2410.06273","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=eUMGCipgtE","openreview_venues":["ICML 2025 poster"]},{"id":"2505.21496","versioned_id":"2505.21496v1","title":"UI-Genie: A Self-Improving Approach for Iteratively Boosting MLLM-based Mobile GUI Agents","authors":["Han Xiao","Guozhi Wang","Yuxiang Chai","Zimu Lu","Weifeng Lin","Hao He","Lue Fan","Liuyang Bian","Rui Hu","Liang Liu","Shuai Ren","Yafei Wen","Xiaoxin Chen","Aojun Zhou","Hongsheng Li"],"abstract":"In this paper, we introduce UI-Genie, a self-improving framework addressing two key challenges in GUI agents: verification of trajectory outcome is challenging and high-quality training data are not scalable. These challenges are addressed by a reward model and a self-improving pipeline, respectively. The reward model, UI-Genie-RM, features an image-text interleaved architecture that efficiently pro- cesses historical context and unifies action-level and task-level rewards. To sup- port the training of UI-Genie-RM, we develop deliberately-designed data genera- tion strategies including rule-based verification, controlled trajectory corruption, and hard negative mining. To address the second challenge, a self-improvement pipeline progressively expands solvable complex GUI tasks by enhancing both the agent and reward models through reward-guided exploration and outcome verification in dynamic environments. For training the model, we generate UI- Genie-RM-517k and UI-Genie-Agent-16k, establishing the first reward-specific dataset for GUI agents while demonstrating high-quality synthetic trajectory gen- eration without manual annotation. Experimental results show that UI-Genie achieves state-of-the-art performance across multiple GUI agent benchmarks with three generations of data-model self-improvement. We open-source our complete framework implementation and generated datasets to facilitate further research in https://github.com/Euphoria16/UI-Genie.","published":"2025-05-27T17:58:06Z","updated":"2025-05-27T17:58:06Z","categories":["cs.CL","cs.CV","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.21496v1","pdf_url":"https://arxiv.org/pdf/2505.21496v1","comment":"https://github.com/Euphoria16/UI-Genie","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=3uUmJzSSOW","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2505.21116","versioned_id":"2505.21116v1","title":"Creativity in LLM-based Multi-Agent Systems: A Survey","authors":["Yi-Cheng Lin","Kang-Chieh Chen","Zhe-Yan Li","Tzu-Heng Wu","Tzu-Hsuan Wu","Kuan-Yu Chen","Hung-yi Lee","Yun-Nung Chen"],"abstract":"Large language model (LLM)-driven multi-agent systems (MAS) are transforming how humans and AIs collaboratively generate ideas and artifacts. While existing surveys provide comprehensive overviews of MAS infrastructures, they largely overlook the dimension of \\emph{creativity}, including how novel outputs are generated and evaluated, how creativity informs agent personas, and how creative workflows are coordinated. This is the first survey dedicated to creativity in MAS. We focus on text and image generation tasks, and present: (1) a taxonomy of agent proactivity and persona design; (2) an overview of generation techniques, including divergent exploration, iterative refinement, and collaborative synthesis, as well as relevant datasets and evaluation metrics; and (3) a discussion of key challenges, such as inconsistent evaluation standards, insufficient bias mitigation, coordination conflicts, and the lack of unified benchmarks. This survey offers a structured framework and roadmap for advancing the development, evaluation, and standardization of creative MAS.","published":"2025-05-27T12:36:14Z","updated":"2025-05-27T12:36:14Z","categories":["cs.HC","cs.AI","cs.CL"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2505.21116v1","pdf_url":"https://arxiv.org/pdf/2505.21116v1","comment":"23 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.20718","versioned_id":"2505.20718v2","title":"VLM Can Be a Good Assistant: Enhancing Embodied Visual Tracking with Self-Improving Vision-Language Models","authors":["Kui Wu","Shuhang Xu","Hao Chen","Churan Wang","Zhoujun Li","Yizhou Wang","Fangwei Zhong"],"abstract":"We introduce a novel self-improving framework that enhances Embodied Visual Tracking (EVT) with Vision-Language Models (VLMs) to address the limitations of current active visual tracking systems in recovering from tracking failure. Our approach combines the off-the-shelf active tracking methods with VLMs' reasoning capabilities, deploying a fast visual policy for normal tracking and activating VLM reasoning only upon failure detection. The framework features a memory-augmented self-reflection mechanism that enables the VLM to progressively improve by learning from past experiences, effectively addressing VLMs' limitations in 3D spatial reasoning. Experimental results demonstrate significant performance improvements, with our framework boosting success rates by $72\\%$ with state-of-the-art RL-based approaches and $220\\%$ with PID-based methods in challenging environments. This work represents the first integration of VLM-based reasoning to assist EVT agents in proactive failure recovery, offering substantial advances for real-world robotic applications that require continuous target monitoring in dynamic, unstructured environments. Project website: https://sites.google.com/view/evt-recovery-assistant.","published":"2025-05-27T04:53:50Z","updated":"2025-05-28T15:54:19Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.20718v2","pdf_url":"https://arxiv.org/pdf/2505.20718v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":60,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.20521","versioned_id":"2505.20521v2","title":"Project Riley: Multimodal Multi-Agent LLM Collaboration with Emotional Reasoning and Voting","authors":["Ana Rita Ortigoso","Gabriel Vieira","Daniel Fuentes","Luis Frazão","Nuno Costa","António Pereira"],"abstract":"This paper presents Project Riley, a novel multimodal and multi-model conversational AI architecture oriented towards the simulation of reasoning influenced by emotional states. Drawing inspiration from Pixar's Inside Out, the system comprises five distinct emotional agents - Joy, Sadness, Fear, Anger, and Disgust - that engage in structured multi-round dialogues to generate, criticise, and iteratively refine responses. A final reasoning mechanism synthesises the contributions of these agents into a coherent output that either reflects the dominant emotion or integrates multiple perspectives. The architecture incorporates both textual and visual large language models (LLMs), alongside advanced reasoning and self-refinement processes. A functional prototype was deployed locally in an offline environment, optimised for emotional expressiveness and computational efficiency. From this initial prototype, another one emerged, called Armando, which was developed for use in emergency contexts, delivering emotionally calibrated and factually accurate information through the integration of Retrieval-Augmented Generation (RAG) and cumulative context tracking. The Project Riley prototype was evaluated through user testing, in which participants interacted with the chatbot and completed a structured questionnaire assessing three dimensions: Emotional Appropriateness, Clarity and Utility, and Naturalness and Human-likeness. The results indicate strong performance in structured scenarios, particularly with respect to emotional alignment and communicative clarity.","published":"2025-05-26T20:53:53Z","updated":"2025-09-08T16:40:29Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.20521v2","pdf_url":"https://arxiv.org/pdf/2505.20521v2","comment":"28 pages, 5 figures. Submitted for review to Information Fusion","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.20286","versioned_id":"2505.20286v1","title":"Alita: Generalist Agent Enabling Scalable Agentic Reasoning with Minimal Predefinition and Maximal Self-Evolution","authors":["Jiahao Qiu","Xuan Qi","Tongcheng Zhang","Xinzhe Juan","Jiacheng Guo","Yifu Lu","Yimin Wang","Zixin Yao","Qihan Ren","Xun Jiang","Xing Zhou","Dongrui Liu","Ling Yang","Yue Wu","Kaixuan Huang","Shilong Liu","Hongru Wang","Mengdi Wang"],"abstract":"Recent advances in large language models (LLMs) have enabled agents to autonomously perform complex, open-ended tasks. However, many existing frameworks depend heavily on manually predefined tools and workflows, which hinder their adaptability, scalability, and generalization across domains. In this work, we introduce Alita--a generalist agent designed with the principle of \"Simplicity is the ultimate sophistication,\" enabling scalable agentic reasoning through minimal predefinition and maximal self-evolution. For minimal predefinition, Alita is equipped with only one component for direct problem-solving, making it much simpler and neater than previous approaches that relied heavily on hand-crafted, elaborate tools and workflows. This clean design enhances its potential to generalize to challenging questions, without being limited by tools. For Maximal self-evolution, we enable the creativity of Alita by providing a suite of general-purpose components to autonomously construct, refine, and reuse external capabilities by generating task-related model context protocols (MCPs) from open source, which contributes to scalable agentic reasoning. Notably, Alita achieves 75.15% pass@1 and 87.27% pass@3 accuracy, which is top-ranking among general-purpose agents, on the GAIA benchmark validation dataset, 74.00% and 52.00% pass@1, respectively, on Mathvista and PathVQA, outperforming many agent systems with far greater complexity. More details will be updated at $\\href{https://github.com/CharlesQ9/Alita}{https://github.com/CharlesQ9/Alita}$.","published":"2025-05-26T17:58:53Z","updated":"2025-05-26T17:58:53Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.20286v1","pdf_url":"https://arxiv.org/pdf/2505.20286v1","comment":"9 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5rKsNFg1m9","openreview_venues":["ICLR 2026 Conference Desk Rejected Submission"]},{"id":"2505.20013","versioned_id":"2505.20013v2","title":"WebCoT: Enhancing Web Agent Reasoning by Reconstructing Chain-of-Thought in Reflection, Branching, and Rollback","authors":["Minda Hu","Tianqing Fang","Jianshu Zhang","Junyu Ma","Zhisong Zhang","Jingyan Zhou","Hongming Zhang","Haitao Mi","Dong Yu","Irwin King"],"abstract":"Web agents powered by Large Language Models (LLMs) show promise for next-generation AI, but their limited reasoning in uncertain, dynamic web environments hinders robust deployment. In this paper, we identify key reasoning skills essential for effective web agents, i.e., reflection & lookahead, branching, and rollback, and curate trajectory data that exemplifies these abilities by reconstructing the agent's (inference-time) reasoning algorithms into chain-of-thought rationales. We conduct experiments in the agent self-improving benchmark, OpenWebVoyager, and demonstrate that distilling salient reasoning patterns into the backbone LLM via simple fine-tuning can substantially enhance its performance. Our approach yields significant improvements across multiple benchmarks, including WebVoyager, Mind2web-live, and SimpleQA (web search), highlighting the potential of targeted reasoning skill enhancement for web agents.","published":"2025-05-26T14:03:37Z","updated":"2025-09-18T11:32:15Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.20013v2","pdf_url":"https://arxiv.org/pdf/2505.20013v2","comment":"18 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.19850","versioned_id":"2505.19850v2","title":"DISCOVER: Automated Curricula for Sparse-Reward Reinforcement Learning","authors":["Leander Diaz-Bone","Marco Bagatella","Jonas Hübotter","Andreas Krause"],"abstract":"Sparse-reward reinforcement learning (RL) can model a wide range of highly complex tasks. Solving sparse-reward tasks is RL's core premise, requiring efficient exploration coupled with long-horizon credit assignment, and overcoming these challenges is key for building self-improving agents with superhuman ability. Prior work commonly explores with the objective of solving many sparse-reward tasks, making exploration of individual high-dimensional, long-horizon tasks intractable. We argue that solving such challenging tasks requires solving simpler tasks that are relevant to the target task, i.e., whose achieval will teach the agent skills required for solving the target task. We demonstrate that this sense of direction, necessary for effective exploration, can be extracted from existing RL algorithms, without leveraging any prior information. To this end, we propose a method for directed sparse-reward goal-conditioned very long-horizon RL (DISCOVER), which selects exploratory goals in the direction of the target task. We connect DISCOVER to principled exploration in bandits, formally bounding the time until the target task becomes achievable in terms of the agent's initial distance to the target, but independent of the volume of the space of all tasks. We then perform a thorough evaluation in high-dimensional environments. We find that the directed goal selection of DISCOVER solves exploration problems that are beyond the reach of prior state-of-the-art exploration methods in RL.","published":"2025-05-26T11:35:07Z","updated":"2025-10-20T12:58:20Z","categories":["cs.LG","cs.AI","cs.RO"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.19850v2","pdf_url":"https://arxiv.org/pdf/2505.19850v2","comment":"NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=guZBnsKPsw","openreview_venues":["EXAIT@ICML 2025 Poster","NeurIPS 2025 poster"]},{"id":"openreview:4qCtJlKSYb","versioned_id":"4qCtJlKSYb","title":"Leveraging Knowledge Graphs and LLM Reasoning to Identify Operational Bottlenecks for Warehouse Planning Assistance","authors":["Rishi Yash Parekh","Saisubramaniam Gopalakrishnan","Zishan Ahmad","Anirudh Deodhar"],"abstract":"Analyzing large, complex output datasets from Discrete Event Simulations (DES) of warehouse operations to identify bottlenecks and inefficiencies is a critical yet challenging task, often demanding significant manual effort or specialized analytical tools. We propose a novel framework that addresses this challenge through a powerful integration of Knowledge Graphs (KGs) and Large Language Model (LLM)-based agents. Our framework first transforms raw DES output data into a semantically rich KG, which uniquely captures the intricate relationships between simulation events and entities (e.g., suppliers, packages, workers, equipment), overcoming unstructured log limitations for robust analysis. On this KG, our novel LLM-based agent employs a sophisticated iterative reasoning mechanism that interprets complex natural language questions by generating insightful, interdependent sub-questions sequentially. Each sub-question is formulated one at a time, crucially conditioned on the evidence from answers to previous ones. For each individual sub-question, a multi-step process then generates precise Cypher queries for KG interaction, extracts relevant information, and performs crucial self-reflection to identify and correct potential errors. This adaptive, iterative, and self-correcting reasoning progressively pinpoints operational issues and diagnoses root causes, mimicking human investigative analysis. We evaluate our approach using an example warehouse DES setup, systematically introducing typical bottlenecks like equipment breakdowns and supplier arrival irregularities. For operational bottleneck questions, our proposed agent with its iterative reasoning framework demonstrates significantly higher pass rates compared to traditional baseline methods, achieving near-perfect performance in identifying key inefficiencies. Furthermore, for more complex investigative questions, we qualitatively showcase our framework's superior diagnostic capabilities through three case studies, highlighting its proficiency in uncovering subtle and interconnected inefficiencies often missed by traditional methods. This work attempts to bridge the gap between simulation modeling and advanced AI-driven data analysis informed by the broader advancements in KG+LLM, offering a more intuitive and potent method for extracting actionable insights from simulation outputs, thereby dramatically reducing time-to-insight and paving the way for automated, intelligent warehouse inefficiency evaluation and diagnosis for industrial data analysis.","published":"2025-05-26T11:03:14+00:00","updated":"2025-07-30T22:36:23+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4qCtJlKSYb","openreview_url":"https://openreview.net/forum?id=4qCtJlKSYb","pdf_url":"https://openreview.net/pdf?id=4qCtJlKSYb","comment":"AI4SupplyChain 2025 Poster","journal_ref":"AI4SupplyChain 2025 Poster","doi":"","venue":"AI4SupplyChain 2025 Poster","venue_id":"KDD.org/2025/Workshop/AI4SupplyChain","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2505.19538","versioned_id":"2505.19538v1","title":"DoctorRAG: Medical RAG Fusing Knowledge with Patient Analogy through Textual Gradients","authors":["Yuxing Lu","Gecheng Fu","Wei Wu","Xukai Zhao","Sin Yee Goi","Jinzhuo Wang"],"abstract":"Existing medical RAG systems mainly leverage knowledge from medical knowledge bases, neglecting the crucial role of experiential knowledge derived from similar patient cases -- a key component of human clinical reasoning. To bridge this gap, we propose DoctorRAG, a RAG framework that emulates doctor-like reasoning by integrating both explicit clinical knowledge and implicit case-based experience. DoctorRAG enhances retrieval precision by first allocating conceptual tags for queries and knowledge sources, together with a hybrid retrieval mechanism from both relevant knowledge and patient. In addition, a Med-TextGrad module using multi-agent textual gradients is integrated to ensure that the final output adheres to the retrieved knowledge and patient query. Comprehensive experiments on multilingual, multitask datasets demonstrate that DoctorRAG significantly outperforms strong baseline RAG models and gains improvements from iterative refinements. Our approach generates more accurate, relevant, and comprehensive responses, taking a step towards more doctor-like medical reasoning systems.","published":"2025-05-26T05:56:23Z","updated":"2025-05-26T05:56:23Z","categories":["cs.CL","cs.AI","cs.CE","cs.IR","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.19538v1","pdf_url":"https://arxiv.org/pdf/2505.19538v1","comment":"32 pages, 5 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.19095","versioned_id":"2505.19095v1","title":"ScreenExplorer: Training a Vision-Language Model for Diverse Exploration in Open GUI World","authors":["Runliang Niu","Jinglong Ji","Yi Chang","Qi Wang"],"abstract":"The rapid progress of large language models (LLMs) has sparked growing interest in building Artificial General Intelligence (AGI) within Graphical User Interface (GUI) environments. However, existing GUI agents based on LLMs or vision-language models (VLMs) often fail to generalize to novel environments and rely heavily on manually curated, diverse datasets. To overcome these limitations, we introduce ScreenExplorer, a VLM trained via Group Relative Policy Optimization(GRPO) in real, dynamic, and open-ended GUI environments. Innovatively, we introduced a world-model-based curiosity reward function to help the agent overcome the cold-start phase of exploration. Additionally, distilling experience streams further enhances the model's exploration capabilities. Our training framework enhances model exploration in open GUI environments, with trained models showing better environmental adaptation and sustained exploration compared to static deployment models. Our findings offer a scalable pathway toward AGI systems with self-improving capabilities in complex interactive settings.","published":"2025-05-25T11:13:03Z","updated":"2025-05-25T11:13:03Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.19095v1","pdf_url":"https://arxiv.org/pdf/2505.19095v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.18646","versioned_id":"2505.18646v2","title":"SEW: Self-Evolving Agentic Workflows for Automated Code Generation","authors":["Siwei Liu","Jinyuan Fang","Han Zhou","Yingxu Wang","Zaiqiao Meng"],"abstract":"Large Language Models (LLMs) have demonstrated effectiveness in code generation tasks. To enable LLMs to address more complex coding challenges, existing research has focused on crafting multi-agent systems with agentic workflows, where complex coding tasks are decomposed into sub-tasks, assigned to specialized agents. Despite their effectiveness, current approaches heavily rely on hand-crafted agentic workflows, with both agent topologies and prompts manually designed, which limits their ability to automatically adapt to different types of coding problems. To address these limitations and enable automated workflow design, we propose \\textbf{S}elf-\\textbf{E}volving \\textbf{W}orkflow (\\textbf{SEW}), a novel self-evolving framework that automatically generates and optimises multi-agent workflows. Extensive experiments on three coding benchmark datasets, including the challenging LiveCodeBench, demonstrate that our SEW can automatically design agentic workflows and optimise them through self-evolution, bringing up to 12\\% improvement on LiveCodeBench compared to using the backbone LLM only. Furthermore, by investigating different representation schemes of workflow, we provide insights into the optimal way to encode workflow information with text.","published":"2025-05-24T11:12:14Z","updated":"2026-04-14T11:23:32Z","categories":["cs.SE","cs.AI","cs.CL"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2505.18646v2","pdf_url":"https://arxiv.org/pdf/2505.18646v2","comment":"16 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=MZ2qxewvkF","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2505.17702","versioned_id":"2505.17702v3","title":"Seek-CAD: A Self-refined Generative Modeling for 3D Parametric CAD Using Local Inference via DeepSeek","authors":["Xueyang Li","Jiahao Li","Yu Song","Yunzhong Lou","Xiangdong Zhou"],"abstract":"The advent of Computer-Aided Design (CAD) generative modeling will significantly transform the design of industrial products. The recent research endeavor has extended into the realm of Large Language Models (LLMs). In contrast to fine-tuning methods, training-free approaches typically utilize the advanced closed-source LLMs, thereby offering enhanced flexibility and efficiency in the development of AI agents for generating CAD parametric models. However, the substantial cost and limitations of local deployment of the top-tier closed-source LLMs pose challenges in practical applications. The Seek-CAD is the pioneer exploration of locally deployed open-source inference LLM DeepSeek-R1 for CAD parametric model generation with a training-free methodology. This study is the first investigation to incorporate both visual and Chain-of-Thought (CoT) feedback within the self-refinement mechanism for generating CAD models. Specifically, the initial generated parametric CAD model is rendered into a sequence of step-wise perspective images, which are subsequently processed by a Vision Language Model (VLM) alongside the corresponding CoTs derived from DeepSeek-R1 to assess the CAD model generation. Then, the feedback is utilized by DeepSeek-R1 to refine the initial generated model for the next round of generation. Moreover, we present an innovative 3D CAD model dataset structured around the SSR (Sketch, Sketch-based feature, and Refinements) triple design paradigm. This dataset encompasses a wide range of CAD commands, thereby aligning effectively with industrial application requirements and proving suitable for the generation of LLMs. Extensive experiments validate the effectiveness of Seek-CAD under various metrics.","published":"2025-05-23T10:11:19Z","updated":"2026-02-28T15:25:47Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2505.17702v3","pdf_url":"https://arxiv.org/pdf/2505.17702v3","comment":"Accepted to ICLR 2026. The datatset has been released publicly and can be acessed in https://github.com/Sunny-Hack/Seek-CAD","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PzIc2TxhwN","openreview_venues":["ICLR 2026 Poster"]},{"id":"2505.18218","versioned_id":"2505.18218v1","title":"CoMet: Metaphor-Driven Covert Communication for Multi-Agent Language Games","authors":["Shuhang Xu","Fangwei Zhong"],"abstract":"Metaphors are a crucial way for humans to express complex or subtle ideas by comparing one concept to another, often from a different domain. However, many large language models (LLMs) struggle to interpret and apply metaphors in multi-agent language games, hindering their ability to engage in covert communication and semantic evasion, which are crucial for strategic communication. To address this challenge, we introduce CoMet, a framework that enables LLM-based agents to engage in metaphor processing. CoMet combines a hypothesis-based metaphor reasoner with a metaphor generator that improves through self-reflection and knowledge integration. This enhances the agents' ability to interpret and apply metaphors, improving the strategic and nuanced quality of their interactions. We evaluate CoMet on two multi-agent language games - Undercover and Adversarial Taboo - which emphasize Covert Communication and Semantic Evasion. Experimental results demonstrate that CoMet significantly enhances the agents' ability to communicate strategically using metaphors.","published":"2025-05-23T08:23:54Z","updated":"2025-05-23T08:23:54Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.18218v1","pdf_url":"https://arxiv.org/pdf/2505.18218v1","comment":"To Appear at ACL 2025 (Main)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=hbJp7hMd6G","openreview_venues":["ACL ARR 2025 February Submission"]},{"id":"2505.17481","versioned_id":"2505.17481v1","title":"MARCO: Meta-Reflection with Cross-Referencing for Code Reasoning","authors":["Yusheng Zhao","Xiao Luo","Weizhi Zhang","Wei Ju","Zhiping Xiao","Philip S. Yu","Ming Zhang"],"abstract":"The ability to reason is one of the most fundamental capabilities of large language models (LLMs), enabling a wide range of downstream tasks through sophisticated problem-solving. A critical aspect of this is code reasoning, which involves logical reasoning with formal languages (i.e., programming code). In this paper, we enhance this capability of LLMs by exploring the following question: how can an LLM agent become progressively smarter in code reasoning with each solution it proposes, thereby achieving substantial cumulative improvement? Most existing research takes a static perspective, focusing on isolated problem-solving using frozen LLMs. In contrast, we adopt a cognitive-evolving perspective and propose a novel framework named Meta-Reflection with Cross-Referencing (MARCO) that enables the LLM to evolve dynamically during inference through self-improvement. From the perspective of human cognitive development, we leverage both knowledge accumulation and lesson sharing. In particular, to accumulate knowledge during problem-solving, we propose meta-reflection that reflects on the reasoning paths of the current problem to obtain knowledge and experience for future consideration. Moreover, to effectively utilize the lessons from other agents, we propose cross-referencing that incorporates the solution and feedback from other agents into the current problem-solving process. We conduct experiments across various datasets in code reasoning, and the results demonstrate the effectiveness of MARCO.","published":"2025-05-23T05:21:11Z","updated":"2025-05-23T05:21:11Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17481v1","pdf_url":"https://arxiv.org/pdf/2505.17481v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.16281","versioned_id":"2505.16281v3","title":"HiMATE: A Hierarchical Multi-Agent Framework for Machine Translation Evaluation","authors":["Shijie Zhang","Renhao Li","Songsheng Wang","Philipp Koehn","Min Yang","Derek F. Wong"],"abstract":"The advancement of Large Language Models (LLMs) enables flexible and interpretable automatic evaluations. In the field of machine translation evaluation, utilizing LLMs with translation error annotations based on Multidimensional Quality Metrics (MQM) yields more human-aligned judgments. However, current LLM-based evaluation methods still face challenges in accurately identifying error spans and assessing their severity. In this paper, we propose HiMATE, a Hierarchical Multi-Agent Framework for Machine Translation Evaluation. We argue that existing approaches inadequately exploit the fine-grained structural and semantic information within the MQM hierarchy. To address this, we develop a hierarchical multi-agent system grounded in the MQM error typology, enabling granular evaluation of subtype errors. Two key strategies are incorporated to further mitigate systemic hallucinations within the framework: the utilization of the model's self-reflection capability and the facilitation of agent discussion involving asymmetric information. Empirically, HiMATE outperforms competitive baselines across different datasets in conducting human-aligned evaluations. Further analyses underscore its significant advantage in error span detection and severity assessment, achieving an average F1-score improvement of 89% over the best-performing baseline. We make our code and data publicly available at https://github.com/nlp2ct-shijie/HiMATE.","published":"2025-05-22T06:24:08Z","updated":"2025-09-16T01:45:19Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.16281v3","pdf_url":"https://arxiv.org/pdf/2505.16281v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:YurjMGGTTj","versioned_id":"YurjMGGTTj","title":"Self-Generated In-Context Examples Improve LLM Agents for Sequential Decision-Making Tasks","authors":["Vishnu Sarukkai","Zhiqiang Xie","Kayvon Fatahalian"],"abstract":"Large Language Model (LLM) agents typically require extensive task-specific knowledge engineering. Instead, we investigate a self-improvement approach where agents learn from their own successful experiences without human intervention. Our method builds and refines a database of self-generated trajectories for in-context learning. Even naive accumulation of successful trajectories yields substantial performance gains across ALFWorld (73\\% to 89\\%), Wordcraft (55\\% to 64\\%), and InterCode-SQL (75\\% to 79\\%). We further enhance performance with 1) database-level curation using population-based training, and 2) exemplar-level curation that selectively retains trajectories based on their utility. On ALFWorld, our method achieves 93\\% success—surpassing approaches using more powerful LLMs. Our approach demonstrates that agents can autonomously improve through self-collected experience, without labor-intensive knowledge engineering.","published":"2025-05-22T00:24:58+00:00","updated":"2025-07-11T05:21:42+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=YurjMGGTTj","openreview_url":"https://openreview.net/forum?id=YurjMGGTTj","pdf_url":"https://openreview.net/pdf?id=YurjMGGTTj","comment":"PUT at ICML 2025 Poster","journal_ref":"PUT at ICML 2025 Poster","doi":"","venue":"PUT at ICML 2025 Poster","venue_id":"ICML.cc/2025/Workshop/PUT","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2505.17104","versioned_id":"2505.17104v1","title":"P2P: Automated Paper-to-Poster Generation and Fine-Grained Benchmark","authors":["Tao Sun","Enhao Pan","Zhengkai Yang","Kaixin Sui","Jiajun Shi","Xianfu Cheng","Tongliang Li","Wenhao Huang","Ge Zhang","Jian Yang","Zhoujun Li"],"abstract":"Academic posters are vital for scholarly communication, yet their manual creation is time-consuming. However, automated academic poster generation faces significant challenges in preserving intricate scientific details and achieving effective visual-textual integration. Existing approaches often struggle with semantic richness and structural nuances, and lack standardized benchmarks for evaluating generated academic posters comprehensively. To address these limitations, we introduce P2P, the first flexible, LLM-based multi-agent framework that generates high-quality, HTML-rendered academic posters directly from research papers, demonstrating strong potential for practical applications. P2P employs three specialized agents-for visual element processing, content generation, and final poster assembly-each integrated with dedicated checker modules to enable iterative refinement and ensure output quality. To foster advancements and rigorous evaluation in this domain, we construct and release P2PInstruct, the first large-scale instruction dataset comprising over 30,000 high-quality examples tailored for the academic paper-to-poster generation task. Furthermore, we establish P2PEval, a comprehensive benchmark featuring 121 paper-poster pairs and a dual evaluation methodology (Universal and Fine-Grained) that leverages LLM-as-a-Judge and detailed, human-annotated checklists. Our contributions aim to streamline research dissemination and provide the community with robust tools for developing and evaluating next-generation poster generation systems.","published":"2025-05-21T09:06:05Z","updated":"2025-05-21T09:06:05Z","categories":["cs.CL","cs.MM"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.17104v1","pdf_url":"https://arxiv.org/pdf/2505.17104v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=JojyT9niJL","openreview_venues":["ICLR 2026 Poster"]},{"id":"2505.15068","versioned_id":"2505.15068v1","title":"ModelingAgent: Bridging LLMs and Mathematical Modeling for Real-World Challenges","authors":["Cheng Qian","Hongyi Du","Hongru Wang","Xiusi Chen","Yuji Zhang","Avirup Sil","Chengxiang Zhai","Kathleen McKeown","Heng Ji"],"abstract":"Recent progress in large language models (LLMs) has enabled substantial advances in solving mathematical problems. However, existing benchmarks often fail to reflect the complexity of real-world problems, which demand open-ended, interdisciplinary reasoning and integration of computational tools. To address this gap, we introduce ModelingBench, a novel benchmark featuring real-world-inspired, open-ended problems from math modeling competitions across diverse domains, ranging from urban traffic optimization to ecosystem resource planning. These tasks require translating natural language into formal mathematical formulations, applying appropriate tools, and producing structured, defensible reports. ModelingBench also supports multiple valid solutions, capturing the ambiguity and creativity of practical modeling. We also present ModelingAgent, a multi-agent framework that coordinates tool use, supports structured workflows, and enables iterative self-refinement to generate well-grounded, creative solutions. To evaluate outputs, we further propose ModelingJudge, an expert-in-the-loop system leveraging LLMs as domain-specialized judges assessing solutions from multiple expert perspectives. Empirical results show that ModelingAgent substantially outperforms strong baselines and often produces solutions indistinguishable from those of human experts. Together, our work provides a comprehensive framework for evaluating and advancing real-world problem-solving in open-ended, interdisciplinary modeling challenges.","published":"2025-05-21T03:33:23Z","updated":"2025-05-21T03:33:23Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.15068v1","pdf_url":"https://arxiv.org/pdf/2505.15068v1","comment":"36 Pages, 26 Figures, 5 Tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0VnoZa0svY","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2505.14899","versioned_id":"2505.14899v3","title":"REFLEX: Metacognitive Reasoning for Reflective Zero-Shot Robotic Planning with Large Language Models","authors":["Wenjie Lin","Jin Wei-Kocsis","Jiansong Zhang","Byung-Cheol Min","Dongming Gan","Paul Asunda","Ragu Athinarayanan"],"abstract":"While large language models (LLMs) have shown great potential across various domains, their applications in robotics remain largely limited to static prompt-based behaviors and still face challenges in complex tasks under zero-shot or few-shot settings. Inspired by human metacognitive learning and creative problem-solving, we address this limitation by exploring a fundamental question: Can LLMs be empowered with metacognitive capabilities to reason, reflect, and create, thereby enhancing their ability to perform robotic tasks with minimal demonstrations? In this paper, we present REFLEX, a framework that integrates metacognitive learning into LLM-powered multi-robot collaboration. The system equips the LLM-powered robotic agents with a skill decomposition and self-reflection mechanism that identifies modular skills from prior tasks, reflects on failures in unseen task scenarios, and synthesizes effective new solutions. We propose a more challenging robotic benchmark task and evaluate our framework on the existing benchmark and the novel task. Experimental results show that our metacognitive learning framework significantly outperforms existing baselines. Moreover, we observe that our framework can generate solutions that differ from the ground truth yet still successfully complete the tasks. These findings support our hypothesis that metacognitive learning can foster creativity in robotic planning.","published":"2025-05-20T20:51:18Z","updated":"2026-03-02T20:01:50Z","categories":["cs.RO","cs.CL"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2505.14899v3","pdf_url":"https://arxiv.org/pdf/2505.14899v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.14848","versioned_id":"2505.14848v2","title":"MAATS: A Multi-Agent Automated Translation System Based on MQM Evaluation","authors":["George Wang","Jiaqian Hu","Safinah Ali"],"abstract":"We present MAATS, a Multi Agent Automated Translation System that leverages the Multidimensional Quality Metrics (MQM) framework as a fine-grained signal for error detection and refinement. MAATS employs multiple specialized AI agents, each focused on a distinct MQM category (e.g., Accuracy, Fluency, Style, Terminology), followed by a synthesis agent that integrates the annotations to iteratively refine translations. This design contrasts with conventional single-agent methods that rely on self-correction. Evaluated across diverse language pairs and Large Language Models (LLMs), MAATS outperforms zero-shot and single-agent baselines with statistically significant gains in both automatic metrics and human assessments. It excels particularly in semantic accuracy, locale adaptation, and linguistically distant language pairs. Qualitative analysis highlights its strengths in multi-layered error diagnosis, omission detection across perspectives, and context-aware refinement. By aligning modular agent roles with interpretable MQM dimensions, MAATS narrows the gap between black-box LLMs and human translation workflows, shifting focus from surface fluency to deeper semantic and contextual fidelity.","published":"2025-05-20T19:29:05Z","updated":"2025-08-08T15:49:43Z","categories":["cs.CL","cs.LG","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.14848v2","pdf_url":"https://arxiv.org/pdf/2505.14848v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:00zv35DhTY","versioned_id":"00zv35DhTY","title":"Machine Translation Agent with Dimension-Specific Feedback","authors":[],"abstract":"Recent machine translation (MT) agents rely on large language models (LLMs) as judges, typically using coarse prompts that jointly assess all types of error. We propose a framework that decomposes the evaluation into multiple expert evaluators, each specializing in a specific error dimension with detailed criteria, examples, and external knowledge. Based on a set of dimension-specific feedbacks, we tested and analyzed translation refinement using sequential, parallel, and comprehensive strategies. Experiments with both small and large models show that combining specialized evaluators outperforms a single holistic judge by more effectively capturing fine-grained errors. Our findings highlight the benefits of decomposing complex evaluation for more effective self-refinement of LLM. Furthermore, by using smaller, open-source LLMs, our approach achieves strong performance with significantly reduced computational cost, making robust translation evaluation more accessible. This work opens new avenues for scalable, modular quality control in automated translation systems.","published":"2025-05-20T10:45:43+00:00","updated":"2026-07-02T03:17:13+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=00zv35DhTY","openreview_url":"https://openreview.net/forum?id=00zv35DhTY","pdf_url":"https://openreview.net/pdf?id=00zv35DhTY","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:r5zdw1MoPy","versioned_id":"r5zdw1MoPy","title":"Diagnosing Visual Reasoning: Challenges, Insights, and a Path Forward","authors":[],"abstract":"Multimodal large language models (MLLMs) that integrate visual and textual reasoning leverage chain-of-thought (CoT) prompting to tackle complex visual tasks, yet continue to exhibit visual hallucinations and an over-reliance on textual priors. We present a systematic diagnosis of state-of-the-art vision-language models using a three-stage evaluation framework, uncovering key failure modes. To address these, we propose an agent-based architecture that combines LLM reasoning with lightweight visual modules, enabling fine-grained analysis and iterative refinement of reasoning chains. Our results highlight persistent limitations in current approaches and demonstrate that diagnostic LLM agents can substantially improve interpretability and reliability. Our agent-based system achieves significant empirical gains (+10.3 on MMMU, +6.0 on MathVista over a 7B baseline), matching or surpassing much larger models. We will release our framework and evaluation suite to facilitate future research.","published":"2025-05-20T08:38:25+00:00","updated":"2026-07-02T03:16:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=r5zdw1MoPy","openreview_url":"https://openreview.net/forum?id=r5zdw1MoPy","pdf_url":"https://openreview.net/pdf?id=r5zdw1MoPy","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:nfuZNjuyrI","versioned_id":"nfuZNjuyrI","title":"Mitigating the Privacy Issues in Retrieval-Augmented Generation (RAG) via Pure Synthetic Data","authors":[],"abstract":"Retrieval-augmented generation (RAG) enhances the outputs of language models by integrating relevant information retrieved from external knowledge sources. However, when the retrieval process involves private data, RAG systems may face severe privacy risks, potentially leading to the leakage of sensitive information. To address this issue, we propose using synthetic data as a privacy-preserving alternative for the retrieval data. We propose SAGE, a novel two-stage synthetic data generation paradigm. In the stage-1, we employ an attribute-based extraction and generation approach to preserve key contextual information from the original data. In the stage-2, we further enhance the privacy properties of the synthetic data through an agent-based iterative refinement process. Extensive experiments demonstrate that using our synthetic data as the retrieval context achieves comparable performance to using the original data while substantially reducing privacy risks. Our work takes the first step towards investigating the possibility of generating high-utility and privacy-preserving synthetic data for RAG, opening up new opportunities for the safe application of RAG systems in various domains.","published":"2025-05-20T04:22:36+00:00","updated":"2026-07-02T03:16:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=nfuZNjuyrI","openreview_url":"https://openreview.net/forum?id=whtwsp7IhQ","pdf_url":"https://openreview.net/pdf?id=nfuZNjuyrI","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["ACL ARR 2025 May Submission","ACL ARR 2025 February Submission"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2505.13259","versioned_id":"2505.13259v3","title":"From Automation to Autonomy: A Survey on Large Language Models in Scientific Discovery","authors":["Tianshi Zheng","Zheye Deng","Hong Ting Tsang","Weiqi Wang","Jiaxin Bai","Zihao Wang","Yangqiu Song"],"abstract":"Large Language Models (LLMs) are catalyzing a paradigm shift in scientific discovery, evolving from task-specific automation tools into increasingly autonomous agents and fundamentally redefining research processes and human-AI collaboration. This survey systematically charts this burgeoning field, placing a central focus on the changing roles and escalating capabilities of LLMs in science. Through the lens of the scientific method, we introduce a foundational three-level taxonomy-Tool, Analyst, and Scientist-to delineate their escalating autonomy and evolving responsibilities within the research lifecycle. We further identify pivotal challenges and future research trajectories such as robotic automation, self-improvement, and ethical governance. Overall, this survey provides a conceptual architecture and strategic foresight to navigate and shape the future of AI-driven scientific discovery, fostering both rapid innovation and responsible advancement. Github Repository: https://github.com/HKUST-KnowComp/Awesome-LLM-Scientific-Discovery.","published":"2025-05-19T15:41:32Z","updated":"2025-09-17T09:06:42Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.13259v3","pdf_url":"https://arxiv.org/pdf/2505.13259v3","comment":"EMNLP 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:CwZ7fYRZtv","versioned_id":"CwZ7fYRZtv","title":"M3Builder: A Multi-Agent System for Automated Machine Learning in Medical Imaging","authors":[],"abstract":"In this paper, we aim to automate the labor-intensive process of developing machine learning~(ML)-based tools for medical imaging, paving the way for the self-evolution of medical agentic systems. (i) We present M^3Builder, a multi-agent collaboration architecture designed to automate ML in medical imaging, that divide-and-conquers complex medical ML with four specialized agents. (ii) To better fit in the professional medical imaging domain, we build up a medical imaging specialized ML context protocol, a structured environment designed to provide agents with comprehensive free-text descriptions of medical datasets, training code templates, and interaction tools. (iii) To monitor the progress, we propose M^3Bench, spanning four medical imaging ML tasks across 14 datasets, covering both 2D and 3D data. In experiments, we demonstrate that, using the same agent core, M^3Builder outperforms existing automated ML agentic architectures by achieving a higher ML task completion rate, achieving a 94.29% success rate with acceptable model performance. This highlights the promising potential for fully automated ML-based tool development in medical imaging. Code will be available on Github upon publication.","published":"2025-05-19T12:22:50+00:00","updated":"2026-07-02T03:15:06+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=CwZ7fYRZtv","openreview_url":"https://openreview.net/forum?id=CwZ7fYRZtv","pdf_url":"https://openreview.net/pdf?id=CwZ7fYRZtv","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:zYFPBoMp9Y","versioned_id":"zYFPBoMp9Y","title":"Compare-and-Correct: Test-Time Scaling for Scientific Coding Agents without Gold Verification Signals","authors":[],"abstract":"Scientific coding tasks often require navigating vast, uncertain solution spaces, where initial hypotheses may be incomplete, flawed, or contradictory. A key challenge in automating scientific coding tasks is the lack of clear-cut success signals, such as gold labels or unit tests that are common in traditional programming or supervised learning tasks. In scientific domains, correctness is often context-dependent, diverse in form, and rarely captured by a single metric. This makes it difficult for agents to determine when a solution is sufficient or how to refine it. We introduce Compare-and-Correct (C\\&C), a verifier-guided agent framework for scalable test-time trajectory exploration. Instead of relying on single-pass inference, C\\&C leverages test-time compute scaling by generating a diverse set of candidate solutions and then iteratively refining them via self-debugging and self-improvement mechanisms. An Elo Rating-based verifier ranks candidates by relative quality, guiding the agent to backtrack, correct, and converge on the most promising solutions without relying on explicit success criteria. We demonstrate C\\&C’s effectiveness across a range of tasks including machine learning engineering and visualization on ScienceAgentBench. Experiments show that C\\&C significantly outperforms direct prompting, prior agents like OpenHands and Self-Debug, and alternative verifiers such as random selection and LLM-as-a-Judge. These results confirm the strength of our agent design and verification approach.","published":"2025-05-19T09:01:26+00:00","updated":"2026-07-02T03:14:53+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=zYFPBoMp9Y","openreview_url":"https://openreview.net/forum?id=zYFPBoMp9Y","pdf_url":"https://openreview.net/pdf?id=zYFPBoMp9Y","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:c83YBdxKh6","versioned_id":"c83YBdxKh6","title":"Judgment-of-Thought Prompting: A Courtroom-Inspired Framework for Binary Logical Reasoning with Large Language Models","authors":[],"abstract":"This paper proposes a novel prompting approach, Judgment of Thought (JoT), specifically tailored for binary logical reasoning tasks. Despite advances in prompt engineering, existing approaches still face limitations in handling complex logical reasoning tasks. To address these issues, JoT introduces a multi-agent approach with three specialized roles---lawyer, prosecutor, and judge---where a high-level model acts as the judge, and lower-level models serve as lawyer and prosecutor to systematically debate and evaluate arguments. Experimental evaluations on benchmarks such as BigBenchHard and Winogrande demonstrate JoT's superior performance compared to existing prompting approaches, achieving notable improvements, including 98% accuracy in Boolean expressions. Also, our ablation studies validate the critical contribution of each role, iterative refinement loops, and feedback mechanisms. Consequently, JoT significantly enhances accuracy, reliability, and consistency in binary reasoning tasks and shows potential for practical applications.","published":"2025-05-19T08:07:54+00:00","updated":"2026-07-02T03:14:50+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=c83YBdxKh6","openreview_url":"https://openreview.net/forum?id=c83YBdxKh6","pdf_url":"https://openreview.net/pdf?id=c83YBdxKh6","comment":"ACL ARR 2025 May Submission","journal_ref":"ACL ARR 2025 May Submission","doi":"","venue":"ACL ARR 2025 May Submission","venue_id":"aclweb.org/ACL/ARR/2025/May/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:iBm79eP0ex","versioned_id":"iBm79eP0ex","title":"GMAgent: A Graph-oriented Multi-agent Collaboration Framework for Text-attributed Graph Analysis","authors":["Hang Lv","Pengxiang Zhan","Yanchao Tan","Zixuan Guo","Shiping Wang","Carl Yang"],"abstract":"Text-Attributed Graphs (TAGs) are crucial for modeling interconnected data in numerous real-world applications. Graph Neural Networks (GNNs) excel at efficiently capturing global structural information across TAGs, while Large Language Models (LLMs) offer strong capabilities in local semantic understanding. Despite the recent development of integrating GNNs and LLMs for TAG analysis, these approaches often fail to fully exploit their complementary strengths by relying primarily on a single architecture. Furthermore, LLM-based multi-agent collaboration systems have shown promising potential across diverse fields. However, their integration with GNNs for graph analytical tasks remains underexplored. To this end, we introduce GMAgent, a novel graph-oriented multi-agent collaboration framework that effectively and flexibly interacts between diverse GNN-based and LLM-based graph agents, facilitating comprehensive TAG analysis. First, we deploy multiple GNNs as graph agents to perform conflict evaluation, identifying conflict scenarios for further multi-agent collaboration. Then, we repurpose LLMs as graph agents via graph-driven instruction tuning and adopt a role-play expert recruiting strategy, thereby generating LLM graph experts' initial analyses for conflict scenarios. Finally, we conduct a graph-oriented multi-agent collaboration to effectively and efficiently guide collaborative self-reflection on graph experts and the final answer selection. Extensive experimental results on five datasets demonstrate significant improvements, showcasing the potential of our GMAgent in improving the effectiveness, interoperability, and flexibility of comprehensive TAG analysis.","published":"2025-05-18T11:41:28+00:00","updated":"2025-10-21T19:09:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=iBm79eP0ex","openreview_url":"https://openreview.net/forum?id=iBm79eP0ex","pdf_url":"https://openreview.net/pdf?id=iBm79eP0ex","comment":"Accepted by TMLR","journal_ref":"Accepted by TMLR","doi":"","venue":"Accepted by TMLR","venue_id":"TMLR","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2505.12370","versioned_id":"2505.12370v2","title":"Enhancing Visual Grounding for GUI Agents via Self-Evolutionary Reinforcement Learning","authors":["Xinbin Yuan","Jian Zhang","Kaixin Li","Zhuoxuan Cai","Lujian Yao","Jie Chen","Enguang Wang","Qibin Hou","Jinwei Chen","Peng-Tao Jiang","Bo Li"],"abstract":"Graphical User Interface (GUI) agents have made substantial strides in understanding and executing user instructions across diverse platforms. Yet, grounding these instructions to precise interface elements remains challenging, especially in complex, high-resolution, professional environments. Traditional supervised finetuning (SFT) methods often require large volumes of diverse data and exhibit weak generalization. To overcome these limitations, we introduce a reinforcement learning (RL) based framework that incorporates three core strategies: (1) seed data curation to ensure high quality training samples, (2) a dense policy gradient that provides continuous feedback based on prediction accuracy, and (3) a self evolutionary reinforcement finetuning mechanism that iteratively refines the model using attention maps. With only 3k training samples, our 7B-parameter model achieves state-of-the-art results among similarly sized models on three grounding benchmarks. Notably, it attains 47.3\\% accuracy on the ScreenSpot-Pro dataset, outperforming much larger models, such as UI-TARS-72B, by a margin of 24.2\\%. These findings underscore the effectiveness of RL-based approaches in enhancing GUI agent performance, particularly in high-resolution, complex environments.","published":"2025-05-18T11:22:04Z","updated":"2025-05-24T03:01:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.12370v2","pdf_url":"https://arxiv.org/pdf/2505.12370v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.13504","versioned_id":"2505.13504v1","title":"An agentic system with reinforcement-learned subsystem improvements for parsing form-like documents","authors":["Ayesha Amjad","Saurav Sthapit","Tahir Qasim Syed"],"abstract":"Extracting alphanumeric data from form-like documents such as invoices, purchase orders, bills, and financial documents is often performed via vision (OCR) and learning algorithms or monolithic pipelines with limited potential for systemic improvements. We propose an agentic AI system that leverages Large Language Model (LLM) agents and a reinforcement learning (RL) driver agent to automate consistent, self-improving extraction under LLM inference uncertainty. Our work highlights the limitations of monolithic LLM-based extraction and introduces a modular, multi-agent framework with task-specific prompts and an RL policy of rewards and penalties to guide a meta-prompting agent to learn from past errors and improve prompt-based actor agents. This self-corrective adaptive system handles diverse documents, file formats, layouts, and LLMs, aiming to automate accurate information extraction without the need for human intervention. Results as reported on two benchmark datasets of SOIRE, and CORD, are promising for the agentic AI framework.","published":"2025-05-16T09:46:10Z","updated":"2025-05-16T09:46:10Z","categories":["cs.IR","cs.AI","cs.MA"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2505.13504v1","pdf_url":"https://arxiv.org/pdf/2505.13504v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.10838","versioned_id":"2505.10838v1","title":"LARGO: Latent Adversarial Reflection through Gradient Optimization for Jailbreaking LLMs","authors":["Ran Li","Hao Wang","Chengzhi Mao"],"abstract":"Efficient red-teaming method to uncover vulnerabilities in Large Language Models (LLMs) is crucial. While recent attacks often use LLMs as optimizers, the discrete language space make gradient-based methods struggle. We introduce LARGO (Latent Adversarial Reflection through Gradient Optimization), a novel latent self-reflection attack that reasserts the power of gradient-based optimization for generating fluent jailbreaking prompts. By operating within the LLM's continuous latent space, LARGO first optimizes an adversarial latent vector and then recursively call the same LLM to decode the latent into natural language. This methodology yields a fast, effective, and transferable attack that produces fluent and stealthy prompts. On standard benchmarks like AdvBench and JailbreakBench, LARGO surpasses leading jailbreaking techniques, including AutoDAN, by 44 points in attack success rate. Our findings demonstrate a potent alternative to agentic LLM prompting, highlighting the efficacy of interpreting and attacking LLM internals through gradient optimization.","published":"2025-05-16T04:12:16Z","updated":"2025-05-16T04:12:16Z","categories":["cs.LG","cs.CL","cs.CR"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.10838v1","pdf_url":"https://arxiv.org/pdf/2505.10838v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=dSznm3mQTD","openreview_venues":["NeurIPS 2025 poster"]},{"id":"2505.10749","versioned_id":"2505.10749v1","title":"Code-Driven Planning in Grid Worlds with Large Language Models","authors":["Ashwath Vaithinathan Aravindan","Zhisheng Tang","Mayank Kejriwal"],"abstract":"We propose an iterative programmatic planning (IPP) framework for solving grid-based tasks by synthesizing interpretable agent policies expressed in code using large language models (LLMs). Instead of relying on traditional search or reinforcement learning, our approach uses code generation as policy synthesis, where the LLM outputs executable programs that map environment states to action sequences. Our proposed architecture incorporates several prompting strategies, including direct code generation, pseudocode-conditioned refinement, and curriculum-based prompting, but also includes an iterative refinement mechanism that updates code based on task performance feedback. We evaluate our approach using six leading LLMs and two challenging grid-based benchmarks (GRASP and MiniGrid). Our IPP framework demonstrates improvements over direct code generation ranging from 10\\% to as much as 10x across five of the six models and establishes a new state-of-the-art result for GRASP. IPP is found to significantly outperform direct elicitation of a solution from GPT-o3-mini (by 63\\% on MiniGrid to 116\\% on GRASP), demonstrating the viability of the overall approach. Computational costs of all code generation approaches are similar. While code generation has a higher initial prompting cost compared to direct solution elicitation (\\$0.08 per task vs. \\$0.002 per instance for GPT-o3-mini), the code can be reused for any number of instances, making the amortized cost significantly lower (by 400x on GPT-o3-mini across the complete GRASP benchmark).","published":"2025-05-15T23:23:31Z","updated":"2025-05-15T23:23:31Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.10749v1","pdf_url":"https://arxiv.org/pdf/2505.10749v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.10543","versioned_id":"2505.10543v2","title":"Reasoning Capabilities of Large Language Models on Dynamic Tasks","authors":["Annie Wong","Thomas Bäck","Aske Plaat","Niki van Stein","Anna V. Kononova"],"abstract":"Large language models excel on static benchmarks, but their ability as self-learning agents in dynamic environments remains unclear. We evaluate three prompting strategies: self-reflection, heuristic mutation, and planning across dynamic tasks with open-source models. We find that larger models generally outperform smaller ones, but that strategic prompting can close this performance gap. Second, an overly long prompt can negatively impact smaller models on basic reactive tasks, while larger models show more robust behaviour. Third, advanced prompting techniques primarily benefit smaller models on complex games, but offer less improvement for already high-performing large language models. Yet, we find that advanced reasoning methods yield highly variable outcomes: while capable of significantly improving performance when reasoning and decision-making align, they also introduce instability and can lead to big performance drops. Compared to human performance, our findings reveal little evidence of true emergent reasoning. Instead, large language model performance exhibits persistent limitations in areas like planning and spatial coordination, suggesting that large language models still suffer fundamental shortcomings that may not be fully overcome through self-reflective prompting alone. Reasoning is a multi-faceted task, and while methods like Chain-of-thought improve multi-step reasoning on math word problems, our findings using dynamic benchmarks highlight important shortcomings in general reasoning capabilities, indicating a need to move beyond static benchmarks to capture the complexity of reasoning.","published":"2025-05-15T17:53:47Z","updated":"2025-08-10T18:28:40Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.10543v2","pdf_url":"https://arxiv.org/pdf/2505.10543v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.08783","versioned_id":"2505.08783v2","title":"CodePDE: An Inference Framework for LLM-driven PDE Solver Generation","authors":["Shanda Li","Tanya Marwah","Junhong Shen","Weiwei Sun","Andrej Risteski","Yiming Yang","Ameet Talwalkar"],"abstract":"Partial differential equations (PDEs) are fundamental to modeling physical systems, yet solving them remains a complex challenge. Traditional numerical solvers rely on expert knowledge to implement and are computationally expensive, while neural-network-based solvers require large training datasets and often lack interpretability. In this work, we frame PDE solving as a code generation task and introduce CodePDE, the first inference framework for generating PDE solvers using large language models (LLMs). With CodePDE, we present a thorough evaluation on critical capacities of LLM for PDE solving: reasoning, debugging, self-refinement, and test-time scaling. CodePDE shows that, with advanced inference-time algorithms and scaling strategies, LLMs can achieve strong performance across a range of representative PDE problems. We also identify novel insights into LLM-driven solver generation, such as trade-offs between solver reliability and sophistication, design principles for LLM-powered PDE solving agents, and failure modes for LLM on hard tasks. These insights offer guidance for building more capable and reliable LLM-based scientific engines.","published":"2025-05-13T17:58:08Z","updated":"2026-02-22T19:11:40Z","categories":["cs.LG","cs.AI","cs.CL","math.NA"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.08783v2","pdf_url":"https://arxiv.org/pdf/2505.08783v2","comment":"TMLR. Code available at https://github.com/LithiumDA/CodePDE","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=q196xGhRMa","openreview_venues":["Accepted by TMLR"]},{"id":"2505.07757","versioned_id":"2505.07757v2","title":"Emotion-Gradient Metacognitive RSI (Part I): Theoretical Foundations and Single-Agent Architecture","authors":["Rintaro Ando"],"abstract":"We present the Emotion-Gradient Metacognitive Recursive Self-Improvement (EG-MRSI) framework, a novel architecture that integrates introspective metacognition, emotion-based intrinsic motivation, and recursive self-modification into a unified theoretical system. The framework is explicitly capable of overwriting its own learning algorithm under formally bounded risk. Building upon the Noise-to-Meaning RSI (N2M-RSI) foundation, EG-MRSI introduces a differentiable intrinsic reward function driven by confidence, error, novelty, and cumulative success. This signal regulates both a metacognitive mapping and a self-modification operator constrained by provable safety mechanisms. We formally define the initial agent configuration, emotion-gradient dynamics, and RSI trigger conditions, and derive a reinforcement-compatible optimization objective that guides the agent's development trajectory. Meaning Density and Meaning Conversion Efficiency are introduced as quantifiable metrics of semantic learning, closing the gap between internal structure and predictive informativeness. This Part I paper establishes the single-agent theoretical foundations of EG-MRSI. Future parts will extend this framework to include safety certificates and rollback protocols (Part II), collective intelligence mechanisms (Part III), and feasibility constraints including thermodynamic and computational limits (Part IV). Together, the EG-MRSI series provides a rigorous, extensible foundation for open-ended and safe AGI.","published":"2025-05-12T17:02:47Z","updated":"2026-03-04T12:15:01Z","categories":["cs.AI","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.07757v2","pdf_url":"https://arxiv.org/pdf/2505.07757v2","comment":"Withdrawn due to a critical error discovered in the stability and convergence proofs (specifically Lemma 2, Theorem 12, and Proposition 10) in Section 3. The identified flaw invalidates the core theoretical guarantees regarding capability growth and system stability","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:9twwDW60Bw","versioned_id":"9twwDW60Bw","title":"Self-Guided Hierarchical Exploration for Generalist Foundation Model Web Agents","authors":["Qianlan Yang","Xiangjun Wang","Danielle Perszyk","Yu-Xiong Wang"],"abstract":"Foundation models have recently shown strong potential as web agents, capable of interpreting high-level instructions and interacting with complex web interfaces. However, existing training paradigms for these agents often rely on predefined task datasets and curated demonstrations, limiting their scalability, adaptability, and capacity for self-improvement. In this work, we introduce *Self-guided hierArchical exploration for Generalist wEb agents* (SAGE), a new training framework designed to support autonomous skill acquisition through self-guided hierarchical exploration. Our method introduces a three-tier exploration strategy: a pre-exploration phase to build structural understanding of web environments, a top-level exploration strategy to generate a self-evolving curriculum of tasks from easy to hard, and a low-level exploration mechanism that combines planning-based rollouts with step-wise learning to improve policy efficiency. Together, these components form a scalable, supervision-free framework for web agent training. Experimental results on WebVoyager and WebArena demonstrate that our method significantly outperforms prior approaches, enabling foundation model agents to learn complex web tasks with greater generalization and robustness.","published":"2025-05-12T02:50:40+00:00","updated":"2026-07-09T20:01:21+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9twwDW60Bw","openreview_url":"https://openreview.net/forum?id=9twwDW60Bw","pdf_url":"https://openreview.net/pdf?id=9twwDW60Bw","comment":"NeurIPS 2025 poster","journal_ref":"NeurIPS 2025 poster","doi":"","venue":"NeurIPS 2025 poster","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2505.07184","versioned_id":"2505.07184v1","title":"Structural Entropy Guided Agent for Detecting and Repairing Knowledge Deficiencies in LLMs","authors":["Yifan Wei","Xiaoyan Yu","Tengfei Pan","Angsheng Li","Li Du"],"abstract":"Large language models (LLMs) have achieved unprecedented performance by leveraging vast pretraining corpora, yet their performance remains suboptimal in knowledge-intensive domains such as medicine and scientific research, where high factual precision is required. While synthetic data provides a promising avenue for augmenting domain knowledge, existing methods frequently generate redundant samples that do not align with the model's true knowledge gaps. To overcome this limitation, we propose a novel Structural Entropy-guided Knowledge Navigator (SENATOR) framework that addresses the intrinsic knowledge deficiencies of LLMs. Our approach employs the Structure Entropy (SE) metric to quantify uncertainty along knowledge graph paths and leverages Monte Carlo Tree Search (MCTS) to selectively explore regions where the model lacks domain-specific knowledge. Guided by these insights, the framework generates targeted synthetic data for supervised fine-tuning, enabling continuous self-improvement. Experimental results on LLaMA-3 and Qwen2 across multiple domain-specific benchmarks show that SENATOR effectively detects and repairs knowledge deficiencies, achieving notable performance improvements. The code and data for our methods and experiments are available at https://github.com/weiyifan1023/senator.","published":"2025-05-12T02:21:36Z","updated":"2025-05-12T02:21:36Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.07184v1","pdf_url":"https://arxiv.org/pdf/2505.07184v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:dye9w8IOV0","versioned_id":"dye9w8IOV0","title":"Collaborative Reasoner: Self-Improving Social Agents with Synthetic Conversations","authors":["Ansong Ni","Ruta Desai","Yang Li","Xinjie Lei","Dong Wang","Jiemin Zhang","Jane Yu","Ramya Raghavendra","Gargi Ghosh","Shang-Wen Li","Asli Celikyilmaz"],"abstract":"With increasingly powerful large language models (LLMs) and LLM-based agents tackling an ever-growing list of tasks, we envision a future where numerous LLM agents work seamlessly with other AI agents and humans to solve complex problems and enhance daily life. To achieve these goals, LLM agents must develop collaborative skills such as effective persuasion, assertion and disagreement, which are often overlooked in the prevalent single-turn training and evaluation of LLMs. In this work, we present Collaborative Reasoner (Coral), a framework to evaluate and improve the collaborative reasoning abilities of language models. In particular, tasks and metrics in Coral necessitate agents to disagree with incorrect solutions, convince their partners of a correct solution, and ultimately agree as a team to commit to a final solution, all through a natural multi-turn conversation. Through comprehensive evaluation on six collaborative reasoning tasks covering domains of coding, math, scientific QA and social reasoning, we show that current models cannot effectively collaborate due to undesirable social behaviors, collapsing even on problems that they can solve singlehandedly. To improve the collaborative reasoning capabilities of LLMs, we propose a self-play method to generate synthetic multi-turn preference data and further train the language models to be better collaborators. Experiments with Llama-3.1, Ministral and Qwen-2.5 models show that our proposed self-improvement approach consistently outperforms finetuned chain-of-thought performance of the same base model, yielding gains up to 16.7% absolute. Human evaluations show that the models exhibit more effective disagreement and produce more natural conversations after training on our synthetic interaction data.","published":"2025-05-12T02:09:49+00:00","updated":"2026-07-09T20:01:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=dye9w8IOV0","openreview_url":"https://openreview.net/forum?id=dye9w8IOV0","pdf_url":"https://openreview.net/pdf?id=dye9w8IOV0","comment":"NeurIPS 2025 poster","journal_ref":"NeurIPS 2025 poster","doi":"","venue":"NeurIPS 2025 poster","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2505.08803","versioned_id":"2505.08803v1","title":"Multi-modal Synthetic Data Training and Model Collapse: Insights from VLMs and Diffusion Models","authors":["Zizhao Hu","Mohammad Rostami","Jesse Thomason"],"abstract":"Recent research has highlighted the risk of generative model collapse, where performance progressively degrades when continually trained on self-generated data. However, existing exploration on model collapse is limited to single, unimodal models, limiting our understanding in more realistic scenarios, such as diverse multi-modal AI agents interacting autonomously through synthetic data and continually evolving. We expand the synthetic data training and model collapse study to multi-modal vision-language generative systems, such as vision-language models (VLMs) and text-to-image diffusion models, as well as recursive generate-train loops with multiple models. We find that model collapse, previously observed in single-modality generative models, exhibits distinct characteristics in the multi-modal context, such as improved vision-language alignment and increased variance in VLM image-captioning task. Additionally, we find that general approaches such as increased decoding budgets, greater model diversity, and relabeling with frozen models can effectively mitigate model collapse. Our findings provide initial insights and practical guidelines for reducing the risk of model collapse in self-improving multi-agent AI systems and curating robust multi-modal synthetic datasets.","published":"2025-05-10T22:42:29Z","updated":"2025-05-10T22:42:29Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.08803v1","pdf_url":"https://arxiv.org/pdf/2505.08803v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:vEFPm6gw2s","versioned_id":"vEFPm6gw2s","title":"Rig3R: Rig-Aware Conditioning and Discovery for 3D Reconstruction","authors":["Samuel Li","Pujith Kachana","Prajwal Chidananda","Saurabh Nair","Yasutaka Furukawa","Matthew Brown"],"abstract":"Estimating agent pose and 3D scene structure from multi-camera rigs is a central task in embodied AI applications such as autonomous driving. Recent learned approaches such as DUSt3R have shown impressive performance in multiview settings. However, these models treat images as unstructured collections, limiting effectiveness in scenarios where frames are captured from synchronized rigs with known or inferable structure. To this end, we introduce Rig3R, a generalization of prior multiview reconstruction models that incorporates rig structure when available, and learns to infer it when not. Rig3R conditions on optional rig metadata including camera ID, time, and rig poses to develop a rig-aware latent space that remains robust to missing information. It jointly predicts pointmaps and two types of raymaps: a pose raymap relative to a global frame, and a rig raymap relative to a rig-centric frame consistent across time. Rig raymaps allow the model to infer rig structure directly from input images when metadata is missing. The global pose raymaps allow the model to reason about the agent’s ego-motion, while the rig raymaps allow the model to infer rig structure directly from input images when metadata is missing. Rig3R achieves state-of-the-art performance in 3D reconstruction, camera pose estimation, and rig discovery -- outperforming both traditional and learned methods by 17-45% mAA across diverse real-world rig datasets, all in a single forward pass without post-processing or iterative refinement.","published":"2025-05-10T21:50:13+00:00","updated":"2026-07-09T20:02:20+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vEFPm6gw2s","openreview_url":"https://openreview.net/forum?id=vEFPm6gw2s","pdf_url":"https://openreview.net/pdf?id=vEFPm6gw2s","comment":"NeurIPS 2025 spotlight","journal_ref":"NeurIPS 2025 spotlight","doi":"","venue":"NeurIPS 2025 spotlight","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:wPdBe9zxNr","versioned_id":"wPdBe9zxNr","title":"Co-Evolving LLM Coder and Unit Tester via Reinforcement Learning","authors":["Yinjie Wang","Ling Yang","Ye Tian","Ke Shen","Mengdi Wang"],"abstract":"Mathematical reasoning in large language models has been successfully incentivized through reinforcement learning with verifiable rewards, leading to improved one-shot precision. In this work, we turn our focus to the coding domain. Beyond one-shot precision, we highlight unit test generation as another key factor for enhancing coding ability, since accurate unit tests are essential for enabling self-checking and self-correction during inference. Traditional approaches for fine-tuning LLMs on unit test generation rely heavily on ground-truth code solutions in the training data. We propose CURE, a novel reinforcement learning framework with a dedicated reward design that co-evolves coding and unit test generation capabilities based on their interaction outcomes—without any ground-truth code as supervision. This approach enables flexible and scalable training and allows the unit tester to learn directly from the coder’s mistakes. Through extensive evaluations, we demonstrate that our CURE models, derived from base models of varying sizes, excel in both code generation and unit test generation. They naturally extend to downstream tasks such as test-time scaling—achieving a 6.2\\% improvement over the base model—and agentic unit test generation, with a 25.1\\% improvement. Our 4B model consistently outperforms Qwen3-4B while achieving 64.8\\% inference efficiency in unit test generation. Notably, we also find that the CURE model can serve as an effective reward model for reinforcement learning on base models, even in the absence of any labeled supervision.","published":"2025-05-07T23:06:56+00:00","updated":"2026-07-09T20:03:27+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wPdBe9zxNr","openreview_url":"https://openreview.net/forum?id=wPdBe9zxNr","pdf_url":"https://openreview.net/pdf?id=wPdBe9zxNr","comment":"NeurIPS 2025 spotlight","journal_ref":"NeurIPS 2025 spotlight","doi":"","venue":"NeurIPS 2025 spotlight","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:uwL0vbeEVn","versioned_id":"uwL0vbeEVn","title":"SuffixDecoding: Extreme Speculative Decoding for Emerging AI Applications","authors":["Gabriele Oliaro","Zhihao Jia","Daniel F Campos","Aurick Qiao"],"abstract":"Speculative decoding is widely adopted to reduce latency in large language model (LLM) inference by leveraging smaller draft models capable of handling diverse user tasks. However, emerging AI applications, such as LLM-based agents, present unique workload characteristics: instead of diverse independent requests, agentic frameworks typically submit repetitive inference requests, such as multi-agent pipelines performing similar subtasks or self-refinement loops iteratively enhancing outputs. These workloads result in long and highly predictable sequences, which current speculative decoding methods do not effectively exploit. To address this gap, we introduce \\emph{SuffixDecoding}, a novel method that utilizes efficient suffix trees to cache long token sequences from prompts and previous outputs. By adaptively speculating more tokens when acceptance likelihood is high and fewer when it is low, SuffixDecoding effectively exploits opportunities for longer speculations while conserving computation when those opportunities are limited. Evaluations on agentic benchmarks, including SWE-Bench and Text-to-SQL, demonstrate that SuffixDecoding achieves speedups of up to 3.9$\\times$, outperforming state-of-the-art methods -- 2.2$\\times$ faster than model-based approaches like EAGLE-2/3 and 1.6$\\times$ faster than model-free approaches such as Token Recycling. SuffixDecoding is open-sourced.","published":"2025-05-07T03:30:44+00:00","updated":"2026-07-09T20:03:34+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=uwL0vbeEVn","openreview_url":"https://openreview.net/forum?id=uwL0vbeEVn","pdf_url":"https://openreview.net/pdf?id=uwL0vbeEVn","comment":"NeurIPS 2025 spotlight","journal_ref":"NeurIPS 2025 spotlight","doi":"","venue":"NeurIPS 2025 spotlight","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:EyNzLH7BZK","versioned_id":"EyNzLH7BZK","title":"ViSPLA: Visual Iterative Self-Prompting for Language-Guided 3D Affordance Learning","authors":["Hritam Basak","Zhaozheng Yin"],"abstract":"We address the problem of language-guided 3D affordance prediction, a core capability for embodied agents interacting with unstructured environments. Existing methods often rely on fixed affordance categories or require external expert prompts, limiting their ability to generalize across different objects and interpret multi-step instructions. In this work, we introduce $\\textit{ViSPLA}$, a novel iterative self-prompting framework that leverages the intrinsic geometry of predicted masks for continual refinement. We redefine affordance detection as a language-conditioned segmentation task: given a 3D point cloud and language instruction, our model predicts a sequence of refined affordance masks, each guided by differential geometric feedback including Laplacians, normal derivatives, and curvature fields. This feedback is encoded into visual prompts that drive a multi-stage refinement decoder, enabling the model to self-correct and adapt to complex spatial structures. To further enhance precision and coherence, we introduce Implicit Neural Affordance Fields, which define continuous probabilistic regions over the 3D surface without additional supervision. Additionally, our Spectral Convolutional Self-Prompting module operates in the frequency domain of the point cloud, enabling multi-scale refinement that captures both coarse and fine affordance structures. Extensive experiments demonstrate that $\\textit{ViSPLA}$ achieves state-of-the-art results on both seen and unseen objects on two benchmark datasets. Our framework establishes a new paradigm for open-world 3D affordance reasoning by unifying language comprehension with low-level geometric perception through iterative refinement.","published":"2025-05-07T00:39:16+00:00","updated":"2026-07-09T20:03:35+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=EyNzLH7BZK","openreview_url":"https://openreview.net/forum?id=EyNzLH7BZK","pdf_url":"https://openreview.net/pdf?id=EyNzLH7BZK","comment":"NeurIPS 2025 poster","journal_ref":"NeurIPS 2025 poster","doi":"","venue":"NeurIPS 2025 poster","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2505.04649","versioned_id":"2505.04649v3","title":"FRAME: Feedback-Refined Agent Methodology for Enhancing Medical Research Insights","authors":["Chengzhang Yu","Yiming Zhang","Zhixin Liu","Zenghui Ding","Yining Sun","Zhanpeng Jin"],"abstract":"The automation of scientific research through large language models (LLMs) presents significant opportunities but faces critical challenges in knowledge synthesis and quality assurance. We introduce Feedback-Refined Agent Methodology (FRAME), a novel framework that enhances medical paper generation through iterative refinement and structured feedback. Our approach comprises three key innovations: (1) A structured dataset construction method that decomposes 4,287 medical papers into essential research components through iterative refinement; (2) A tripartite architecture integrating Generator, Evaluator, and Reflector agents that progressively improve content quality through metric-driven feedback; and (3) A comprehensive evaluation framework that combines statistical metrics with human-grounded benchmarks. Experimental results demonstrate FRAME's effectiveness, achieving significant improvements over conventional approaches across multiple models (9.91% average gain with DeepSeek V3, comparable improvements with GPT-4o Mini) and evaluation dimensions. Human evaluation confirms that FRAME-generated papers achieve quality comparable to human-authored works, with particular strength in synthesizing future research directions. The results demonstrated our work could efficiently assist medical research by building a robust foundation for automated medical research paper generation while maintaining rigorous academic standards.","published":"2025-05-06T18:50:02Z","updated":"2025-11-16T13:37:07Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.04649v3","pdf_url":"https://arxiv.org/pdf/2505.04649v3","comment":"12 pages, 4 figures, 5 table","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:cuUsD5FJbe","versioned_id":"cuUsD5FJbe","title":"Enhancing GUI Agent with Uncertainty-Aware Self-Trained Evaluator","authors":["Gongwei Chen","Lirong Jie","Lexiao Zou","Weili Guan","Miao Zhang","Liqiang Nie"],"abstract":"Benefiting from the availability of extensive navigation trajectories, both manually and automatically annotated, current graphical user interface (GUI) agents have achieved remarkable advancements in performance. However, these annotated datasets often contain substantial noise, which impedes effective agent training and underscores the necessity for rigorous trajectory quality assessment. In contrast to existing prompting-based evaluators that rely on proprietary multimodal large language models (MLLMs), we propose an Uncertainty-aware Reinforced Self-Training (URST) framework to train lightweight MLLMs for efficient and reliable trajectory evaluation. URST iteratively fine-tunes MLLMs using their own generated thoughts and judgments to enable self-improvement, while its uncertainty-aware sampling strategy ensures the selection of the most informative training examples. To further enhance reasoning and judgment capabilities, we propose a simplified group policy optimization approach that effectively leverages diverse positive and negative samples for evaluator learning. Our evaluator demonstrates superior judgment performance across both in-domain and out-of-domain datasets. When used to filter navigation datasets, it consistently leads to performance improvements in training GUI agents.","published":"2025-05-06T05:05:52+00:00","updated":"2026-07-09T20:03:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=cuUsD5FJbe","openreview_url":"https://openreview.net/forum?id=cuUsD5FJbe","pdf_url":"https://openreview.net/pdf?id=cuUsD5FJbe","comment":"NeurIPS 2025 poster","journal_ref":"NeurIPS 2025 poster","doi":"","venue":"NeurIPS 2025 poster","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2505.03059","versioned_id":"2505.03059v1","title":"Improving Model Alignment Through Collective Intelligence of Open-Source LLMS","authors":["Junlin Wang","Roy Xie","Shang Zhu","Jue Wang","Ben Athiwaratkun","Bhuwan Dhingra","Shuaiwen Leon Song","Ce Zhang","James Zou"],"abstract":"Building helpful and harmless large language models (LLMs) requires effective model alignment approach based on human instructions and feedback, which necessitates high-quality human-labeled data. Constructing such datasets is often expensive and hard to scale, and may face potential limitations on diversity and generalization. To address these challenges, we introduce Mixture of Agents Alignment (MoAA), that leverages the collective strengths of various language models to provide high-quality data for model alignment. By employing MoAA, we enhance both supervised fine-tuning and preference optimization, leading to improved performance compared to using a single model alone to generate alignment data (e.g. using GPT-4o alone). Evaluation results show that our approach can improve win rate of LLaMA-3.1-8B-Instruct from 19.5 to 48.3 on Arena-Hard and from 22.33 to 57.23 on AlpacaEval2, highlighting a promising direction for model alignment through this new scalable and diverse synthetic data recipe. Furthermore, we demonstrate that MoAA enables a self-improvement pipeline, where models finetuned on MoA-generated data surpass their own initial capabilities, providing evidence that our approach can push the frontier of open-source LLMs without reliance on stronger external supervision. Data and code will be released.","published":"2025-05-05T22:40:23Z","updated":"2025-05-05T22:40:23Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.03059v1","pdf_url":"https://arxiv.org/pdf/2505.03059v1","comment":"ICML 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.02931","versioned_id":"2505.02931v1","title":"The Art of Repair: Optimizing Iterative Program Repair with Instruction-Tuned Models","authors":["Fernando Vallecillos Ruiz","Max Hort","Leon Moonen"],"abstract":"Automatic program repair (APR) aims to reduce the manual efforts required to identify and fix errors in source code. Before the rise of LLM-based agents, a common strategy was to increase the number of generated patches, sometimes to the thousands, to achieve better repair results on benchmarks. More recently, self-iterative capabilities enabled LLMs to refine patches over multiple rounds guided by feedback. However, literature often focuses on many iterations and disregards different numbers of outputs. We investigate an APR pipeline that balances these two approaches, the generation of multiple outputs and multiple rounds of iteration, while imposing a limit of 10 total patches per bug. We apply three SOTA instruction-tuned LLMs - DeepSeekCoder-Instruct, Codellama-Instruct, Llama3.1-Instruct - to the APR task. We further fine-tune each model on an APR dataset with three sizes (1K, 30K, 65K) and two techniques (Full Fine-Tuning and LoRA), allowing us to assess their repair capabilities on two APR benchmarks: HumanEval-Java and Defects4J. Our results show that by using only a fraction (<1%) of the fine-tuning dataset, we can achieve improvements of up to 78% in the number of plausible patches generated, challenging prior studies that reported limited gains using Full Fine-Tuning. However, we find that exceeding certain thresholds leads to diminishing outcomes, likely due to overfitting. Moreover, we show that base models greatly benefit from creating patches in an iterative fashion rather than generating them all at once. In addition, the benefit of iterative strategies becomes more pronounced in complex benchmarks. Even fine-tuned models, while benefiting less from iterations, still gain advantages, particularly on complex benchmarks. The research underscores the need for balanced APR strategies that combine multi-output generation and iterative refinement.","published":"2025-05-05T18:06:51Z","updated":"2025-05-05T18:06:51Z","categories":["cs.SE","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2505.02931v1","pdf_url":"https://arxiv.org/pdf/2505.02931v1","comment":"Accepted for publication in the research track of the 29th International Conference on Evaluation and Assessment in Software Engineering (EASE), 17-20 June 2025, Istanbul, Türkiye","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.02888","versioned_id":"2505.02888v2","title":"When Your Own Output Becomes Your Training Data: Noise-to-Meaning Loops and a Formal RSI Trigger","authors":["Rintaro Ando"],"abstract":"We present Noise-to-Meaning Recursive Self-Improvement (N2M-RSI), a minimal formal model showing that once an AI agent feeds its own outputs back as inputs and crosses an explicit information-integration threshold, its internal complexity will grow without bound under our assumptions. The framework unifies earlier ideas on self-prompting large language models, Gödelian self-reference, and AutoML, yet remains implementation-agnostic. The model furthermore scales naturally to interacting swarms of agents, hinting at super-linear effects once communication among instances is permitted. For safety reasons, we omit system-specific implementation details and release only a brief, model-agnostic toy prototype in Appendix C.","published":"2025-05-05T17:03:07Z","updated":"2026-03-04T12:27:29Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2505.02888v2","pdf_url":"https://arxiv.org/pdf/2505.02888v2","comment":"Withdrawn due to a critical error discovered in the mathematical derivation and proof of Theorem 2 (Unbounded Growth) and related Lemma 2 (Compression gain lower bound). This flaw invalidates the paper's main conclusion that N2M-RSI guarantees unbounded growth, requiring a fundamental revision of the theoretical framework","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.02665","versioned_id":"2505.02665v2","title":"A Survey of Slow Thinking-based Reasoning LLMs using Reinforced Learning and Inference-time Scaling Law","authors":["Qianjun Pan","Wenkai Ji","Yuyang Ding","Junsong Li","Shilian Chen","Junyi Wang","Jie Zhou","Qin Chen","Min Zhang","Yulan Wu","Liang He"],"abstract":"This survey explores recent advancements in reasoning large language models (LLMs) designed to mimic \"slow thinking\" - a reasoning process inspired by human cognition, as described in Kahneman's Thinking, Fast and Slow. These models, like OpenAI's o1, focus on scaling computational resources dynamically during complex tasks, such as math reasoning, visual reasoning, medical diagnosis, and multi-agent debates. We present the development of reasoning LLMs and list their key technologies. By synthesizing over 100 studies, it charts a path toward LLMs that combine human-like deep thinking with scalable efficiency for reasoning. The review breaks down methods into three categories: (1) test-time scaling dynamically adjusts computation based on task complexity via search and sampling, dynamic verification; (2) reinforced learning refines decision-making through iterative improvement leveraging policy networks, reward models, and self-evolution strategies; and (3) slow-thinking frameworks (e.g., long CoT, hierarchical processes) that structure problem-solving with manageable steps. The survey highlights the challenges and further directions of this domain. Understanding and advancing the reasoning abilities of LLMs is crucial for unlocking their full potential in real-world applications, from scientific discovery to decision support systems.","published":"2025-05-05T14:14:59Z","updated":"2025-05-08T05:27:18Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.02665v2","pdf_url":"https://arxiv.org/pdf/2505.02665v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.01636","versioned_id":"2505.01636v1","title":"Structured Prompting and Feedback-Guided Reasoning with LLMs for Data Interpretation","authors":["Amit Rath"],"abstract":"Large language models (LLMs) have demonstrated remarkable capabilities in natural language understanding and task generalization. However, their application to structured data analysis remains fragile due to inconsistencies in schema interpretation, misalignment between user intent and model output, and limited mechanisms for self-correction when failures occur. This paper introduces the STROT Framework (Structured Task Reasoning and Output Transformation), a method for structured prompting and feedback-driven transformation logic generation aimed at improving the reliability and semantic alignment of LLM-based analytical workflows. STROT begins with lightweight schema introspection and sample-based field classification, enabling dynamic context construction that captures both the structure and statistical profile of the input data. This contextual information is embedded in structured prompts that guide the model toward generating task-specific, interpretable outputs. To address common failure modes in complex queries, STROT incorporates a refinement mechanism in which the model iteratively revises its outputs based on execution feedback and validation signals. Unlike conventional approaches that rely on static prompts or single-shot inference, STROT treats the LLM as a reasoning agent embedded within a controlled analysis loop -- capable of adjusting its output trajectory through planning and correction. The result is a robust and reproducible framework for reasoning over structured data with LLMs, applicable to diverse data exploration and analysis tasks where interpretability, stability, and correctness are essential.","published":"2025-05-03T00:05:01Z","updated":"2025-05-03T00:05:01Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.01636v1","pdf_url":"https://arxiv.org/pdf/2505.01636v1","comment":"21 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2505.01560","versioned_id":"2505.01560v1","title":"AI agents may be worth the hype but not the resources (yet): An initial exploration of machine translation quality and costs in three language pairs in the legal and news domains","authors":["Vicent Briva Iglesias","Gokhan Dogru"],"abstract":"Large language models (LLMs) and multi-agent orchestration are touted as the next leap in machine translation (MT), but their benefits relative to conventional neural MT (NMT) remain unclear. This paper offers an empirical reality check. We benchmark five paradigms, Google Translate (strong NMT baseline), GPT-4o (general-purpose LLM), o1-preview (reasoning-enhanced LLM), and two GPT-4o-powered agentic workflows (sequential three-stage and iterative refinement), on test data drawn from a legal contract and news prose in three English-source pairs: Spanish, Catalan and Turkish. Automatic evaluation is performed with COMET, BLEU, chrF2 and TER; human evaluation is conducted with expert ratings of adequacy and fluency; efficiency with total input-plus-output token counts mapped to April 2025 pricing. Automatic scores still favour the mature NMT system, which ranks first in seven of twelve metric-language combinations; o1-preview ties or places second in most remaining cases, while both multi-agent workflows trail. Human evaluation reverses part of this narrative: o1-preview produces the most adequate and fluent output in five of six comparisons, and the iterative agent edges ahead once, indicating that reasoning layers capture semantic nuance undervalued by surface metrics. Yet these qualitative gains carry steep costs. The sequential agent consumes roughly five times, and the iterative agent fifteen times, the tokens used by NMT or single-pass LLMs. We advocate multidimensional, cost-aware evaluation protocols and highlight research directions that could tip the balance: leaner coordination strategies, selective agent activation, and hybrid pipelines combining single-pass LLMs with targeted agent intervention.","published":"2025-05-02T20:02:13Z","updated":"2025-05-02T20:02:13Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2505.01560v1","pdf_url":"https://arxiv.org/pdf/2505.01560v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:otSHFe8wTf","versioned_id":"otSHFe8wTf","title":"ReFeR: Improving Evaluation and Reasoning through Hierarchy of Models","authors":["Yaswanth Narsupalli","Abhranil Chandra","Sreevatsa Muppirala","Manish Gupta","Pawan Goyal"],"abstract":"Assessing the quality of generative model outputs from large language models (LLMs) or vision-language models (VLMs), poses significant challenges. Traditional evaluation methods either rely on human assessment which is resource-intensive and not scalable or on automatic metrics that often correlate poorly with human preferences. Another approach is to train dedicated neural evaluators, but this typically requires substantial training data and compute. In this study, we thus introduce ReFeR, a tuning-free framework for evaluating generative outputs including both text and images, using a two-level hierarchy of pre-trained LLM and VLM evaluators. This multi-agent hierarchical strategy leverages additional compute at inference time by orchestrating multiple models and utilizing the increased test-time reasoning to boost performance. By having models themselves provide feedback and final judgments, ReFeR reduces the dependence on human evaluation. We rigorously evaluate ReFeR on four diverse evaluation benchmarks, where it surpasses prior methods in accuracy while also generating constructive feedback useful for downstream distillation and self-improvement via finetuning. Interestingly, ReFeR is also applicable for reasoning tasks - experiments on four reasoning benchmarks show ReFeR’s superior collective reasoning abilities. We present two variants of the framework: ReFeR-Turbo, optimized for accelerated performance, and ReFeR-Lite, offering a more test-time compute efficient solution. ReFeR-Lite is $\\sim12-14\\times$ more compute efficient than previous works while being comparably accurate to ReFeR-Turbo.","published":"2025-04-30T16:39:27+00:00","updated":"2026-05-27T16:44:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=otSHFe8wTf","openreview_url":"https://openreview.net/forum?id=otSHFe8wTf","pdf_url":"https://openreview.net/pdf?id=otSHFe8wTf","comment":"Accepted by TMLR","journal_ref":"Accepted by TMLR","doi":"","venue":"Accepted by TMLR","venue_id":"TMLR","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2504.21625","versioned_id":"2504.21625v6","title":"Meeseeks: A Feedback-Driven, Iterative Self-Correction Benchmark evaluating LLMs' Instruction Following Capability","authors":["Jiaming wang","Yunke Zhao","Peng Ding","Jun Kuang","Yibin Shen","Zhe Tang","Yilin Jin","ZongYu Wang","Xiaoyu Li","Xuezhi Cao","Xunliang Cai"],"abstract":"The capability to precisely adhere to instructions is a cornerstone for Large Language Models (LLMs) to function as dependable agents in real-world scenarios. However, confronted with complex prompts, LLMs frequently encounter difficulties in fulfilling all specified requirements within a single response. Drawing inspiration from recent advancements in Chain-of-Thought (CoT) prompting and self-correction methodologies, we introduce Meeseeks (The name is inspired by Mr. Meeseeks from \"Rick and Morty,\" a character renowned for efficiently accomplishing assigned tasks. See: https://en.wikipedia.org/wiki/Mr._Meeseeks), a fully automated iterative instruction-following benchmark equipped with an integrated feedback mechanism. Meeseeks identifies erroneous components in model responses and provides corresponding feedback accurately, thereby iteratively guiding the model toward self-correction. The dataset contains over 700 curated instances annotated by 32 distinct capability tags in Chinese and English. Extensive experimental results reveal that different state-of-the-art commercial and open-source LLMs exhibit vastly disparate performance, and even after 20 turns of iterative feedback-driven self-correction, nearly all models demonstrate suboptimal performance. We conducted comprehensive analysis from both macro and instance levels, uncovering numerous common issues prevalent in current state-of-the-art models, as well as several counterintuitive phenomena. We've open-sourced our work on https://github.com/ADoublLEN/Meeseeks.","published":"2025-04-30T13:28:19Z","updated":"2025-10-22T07:50:08Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.21625v6","pdf_url":"https://arxiv.org/pdf/2504.21625v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5Rl4cvcbG3","openreview_venues":["ICLR 2026 Conference Desk Rejected Submission"]},{"id":"2504.21304","versioned_id":"2504.21304v1","title":"Unsupervised Feature Transformation via In-context Generation, Generator-critic LLM Agents, and Duet-play Teaming","authors":["Nanxu Gong","Xinyuan Wang","Wangyang Ying","Haoyue Bai","Sixun Dong","Haifeng Chen","Yanjie Fu"],"abstract":"Feature transformation involves generating a new set of features from the original dataset to enhance the data's utility. In certain domains like material performance screening, dimensionality is large and collecting labels is expensive and lengthy. It highly necessitates transforming feature spaces efficiently and without supervision to enhance data readiness and AI utility. However, existing methods fall short in efficient navigation of a vast space of feature combinations, and are mostly designed for supervised settings. To fill this gap, our unique perspective is to leverage a generator-critic duet-play teaming framework using LLM agents and in-context learning to derive pseudo-supervision from unsupervised data. The framework consists of three interconnected steps: (1) Critic agent diagnoses data to generate actionable advice, (2) Generator agent produces tokenized feature transformations guided by the critic's advice, and (3) Iterative refinement ensures continuous improvement through feedback between agents. The generator-critic framework can be generalized to human-agent collaborative generation, by replacing the critic agent with human experts. Extensive experiments demonstrate that the proposed framework outperforms even supervised baselines in feature transformation efficiency, robustness, and practical applicability across diverse datasets.","published":"2025-04-30T04:26:03Z","updated":"2025-04-30T04:26:03Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.21304v1","pdf_url":"https://arxiv.org/pdf/2504.21304v1","comment":"Accepted to IJCAI 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.20965","versioned_id":"2504.20965v2","title":"AegisLLM: Scaling Agentic Systems for Self-Reflective Defense in LLM Security","authors":["Zikui Cai","Shayan Shabihi","Bang An","Zora Che","Brian R. Bartoldson","Bhavya Kailkhura","Tom Goldstein","Furong Huang"],"abstract":"We introduce AegisLLM, a cooperative multi-agent defense against adversarial attacks and information leakage. In AegisLLM, a structured workflow of autonomous agents - orchestrator, deflector, responder, and evaluator - collaborate to ensure safe and compliant LLM outputs, while self-improving over time through prompt optimization. We show that scaling agentic reasoning system at test-time - both by incorporating additional agent roles and by leveraging automated prompt optimization (such as DSPy)- substantially enhances robustness without compromising model utility. This test-time defense enables real-time adaptability to evolving attacks, without requiring model retraining. Comprehensive evaluations across key threat scenarios, including unlearning and jailbreaking, demonstrate the effectiveness of AegisLLM. On the WMDP unlearning benchmark, AegisLLM achieves near-perfect unlearning with only 20 training examples and fewer than 300 LM calls. For jailbreaking benchmarks, we achieve 51% improvement compared to the base model on StrongReject, with false refusal rates of only 7.9% on PHTest compared to 18-55% for comparable methods. Our results highlight the advantages of adaptive, agentic reasoning over static defenses, establishing AegisLLM as a strong runtime alternative to traditional approaches based on model modifications. Code is available at https://github.com/zikuicai/aegisllm","published":"2025-04-29T17:36:05Z","updated":"2025-06-13T22:43:06Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.20965v2","pdf_url":"https://arxiv.org/pdf/2504.20965v2","comment":"ICLR 2025 Workshop BuildingTrust","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=HtJ75I6KDG","openreview_venues":["BuildingTrust"]},{"id":"2504.20434","versioned_id":"2504.20434v2","title":"ARCS: Agentic Retrieval-Augmented Code Synthesis with Iterative Refinement","authors":["Manish Bhattarai","Miguel Cordova","Minh Vu","Javier Santos","Ismael Boureima","Dan O'Malley"],"abstract":"We present Agentic Retrieval-Augmented Code Synthesis (ARCS), a system that improves LLM-based code generation without fine-tuning. ARCS operates through a budgeted synthesize-execute-repair loop over a frozen model: it retrieves relevant code context before generation, proposes candidates, executes them against tests, and repairs based on execution feedback. This retrieval-before-generation design reduces hallucination and accelerates convergence. We formalize ARCS as a state-action process with provable guarantees on termination, monotonic improvement, and bounded cost. A tiered controller (Small/Medium/Large) trades latency for accuracy predictably. On HumanEval, ARCS achieves up to 87.2% pass@1 with Llama-3.1-405B, surpassing CodeAgent (82.3%) while using simpler control than tree-search methods. On TransCoder, it achieves >= 90% accuracy on most translation pairs. On a LANL scientific corpus, it improves CodeBLEU by +0.115 over baseline RAG. ARCS provides a practical, reproducible approach to reliable code synthesis using existing LLM checkpoints.","published":"2025-04-29T05:15:52Z","updated":"2025-10-27T15:23:02Z","categories":["cs.SE","cs.AI"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2504.20434v2","pdf_url":"https://arxiv.org/pdf/2504.20434v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=qrfgXhZcG7","openreview_venues":["ICLR 2026 Conference Withdrawn Submission"]},{"id":"2505.01441","versioned_id":"2505.01441v1","title":"Agentic Reasoning and Tool Integration for LLMs via Reinforcement Learning","authors":["Joykirat Singh","Raghav Magazine","Yash Pandya","Akshay Nambi"],"abstract":"Large language models (LLMs) have achieved remarkable progress in complex reasoning tasks, yet they remain fundamentally limited by their reliance on static internal knowledge and text-only reasoning. Real-world problem solving often demands dynamic, multi-step reasoning, adaptive decision making, and the ability to interact with external tools and environments. In this work, we introduce ARTIST (Agentic Reasoning and Tool Integration in Self-improving Transformers), a unified framework that tightly couples agentic reasoning, reinforcement learning, and tool integration for LLMs. ARTIST enables models to autonomously decide when, how, and which tools to invoke within multi-turn reasoning chains, leveraging outcome-based RL to learn robust strategies for tool use and environment interaction without requiring step-level supervision. Extensive experiments on mathematical reasoning and multi-turn function calling benchmarks show that ARTIST consistently outperforms state-of-the-art baselines, with up to 22% absolute improvement over base models and strong gains on the most challenging tasks. Detailed studies and metric analyses reveal that agentic RL training leads to deeper reasoning, more effective tool use, and higher-quality solutions. Our results establish agentic RL with tool integration as a powerful new frontier for robust, interpretable, and generalizable problem-solving in LLMs.","published":"2025-04-28T10:42:49Z","updated":"2025-04-28T10:42:49Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2505.01441v1","pdf_url":"https://arxiv.org/pdf/2505.01441v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=0BgYVrmz0F","openreview_venues":["FoRLM 2025"]},{"id":"2504.19017","versioned_id":"2504.19017v1","title":"Sparks: Multi-Agent Artificial Intelligence Model Discovers Protein Design Principles","authors":["Alireza Ghafarollahi","Markus J. Buehler"],"abstract":"Advances in artificial intelligence (AI) promise autonomous discovery, yet most systems still resurface knowledge latent in their training data. We present Sparks, a multi-modal multi-agent AI model that executes the entire discovery cycle that includes hypothesis generation, experiment design and iterative refinement to develop generalizable principles and a report without human intervention. Applied to protein science, Sparks uncovered two previously unknown phenomena: (i) a length-dependent mechanical crossover whereby beta-sheet-biased peptides surpass alpha-helical ones in unfolding force beyond ~80 residues, establishing a new design principle for peptide mechanics; and (ii) a chain-length/secondary-structure stability map revealing unexpectedly robust beta-sheet-rich architectures and a \"frustration zone\" of high variance in mixed alpha/beta folds. These findings emerged from fully self-directed reasoning cycles that combined generative sequence design, high-accuracy structure prediction and physics-aware property models, with paired generation-and-reflection agents enforcing self-correction and reproducibility. The key result is that Sparks can independently conduct rigorous scientific inquiry and identify previously unknown scientific principles.","published":"2025-04-26T20:43:28Z","updated":"2025-04-26T20:43:28Z","categories":["cs.AI","cond-mat.mtrl-sci","cond-mat.soft","cs.LG","q-bio.BM"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.19017v1","pdf_url":"https://arxiv.org/pdf/2504.19017v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":68,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.18765","versioned_id":"2504.18765v3","title":"A Vision for Auto Research with LLM Agents","authors":["Chengwei Liu","Chong Wang","Jiayue Cao","Jingquan Ge","Kun Wang","Lyuye Zhang","Ming-Ming Cheng","Penghai Zhao","Tianlin Li","Xiaojun Jia","Xiang Li","Xingshuai Li","Yang Liu","Yebo Feng","Yihao Huang","Yijia Xu","Yuqiang Sun","Zhenhong Zhou","Zhengzi Xu"],"abstract":"This paper introduces Agent-Based Auto Research, a structured multi-agent framework designed to automate, coordinate, and optimize the full lifecycle of scientific research. Leveraging the capabilities of large language models (LLMs) and modular agent collaboration, the system spans all major research phases, including literature review, ideation, methodology planning, experimentation, paper writing, peer review response, and dissemination. By addressing issues such as fragmented workflows, uneven methodological expertise, and cognitive overload, the framework offers a systematic and scalable approach to scientific inquiry. Preliminary explorations demonstrate the feasibility and potential of Auto Research as a promising paradigm for self-improving, AI-driven research processes.","published":"2025-04-26T02:06:10Z","updated":"2025-07-19T16:30:25Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.18765v3","pdf_url":"https://arxiv.org/pdf/2504.18765v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.17967","versioned_id":"2504.17967v1","title":"LLM Agent Swarm for Hypothesis-Driven Drug Discovery","authors":["Kevin Song","Andrew Trotter","Jake Y. Chen"],"abstract":"Drug discovery remains a formidable challenge: more than 90 percent of candidate molecules fail in clinical evaluation, and development costs often exceed one billion dollars per approved therapy. Disparate data streams, from genomics and transcriptomics to chemical libraries and clinical records, hinder coherent mechanistic insight and slow progress. Meanwhile, large language models excel at reasoning and tool integration but lack the modular specialization and iterative memory required for regulated, hypothesis-driven workflows. We introduce PharmaSwarm, a unified multi-agent framework that orchestrates specialized LLM \"agents\" to propose, validate, and refine hypotheses for novel drug targets and lead compounds. Each agent accesses dedicated functionality--automated genomic and expression analysis; a curated biomedical knowledge graph; pathway enrichment and network simulation; interpretable binding affinity prediction--while a central Evaluator LLM continuously ranks proposals by biological plausibility, novelty, in silico efficacy, and safety. A shared memory layer captures validated insights and fine-tunes underlying submodels over time, yielding a self-improving system. Deployable on low-code platforms or Kubernetes-based microservices, PharmaSwarm supports literature-driven discovery, omics-guided target identification, and market-informed repurposing. We also describe a rigorous four-tier validation pipeline spanning retrospective benchmarking, independent computational assays, experimental testing, and expert user studies to ensure transparency, reproducibility, and real-world impact. By acting as an AI copilot, PharmaSwarm can accelerate translational research and deliver high-confidence hypotheses more efficiently than traditional pipelines.","published":"2025-04-24T22:27:50Z","updated":"2025-04-24T22:27:50Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.17967v1","pdf_url":"https://arxiv.org/pdf/2504.17967v1","comment":"15 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.20073","versioned_id":"2504.20073v2","title":"RAGEN: Understanding Self-Evolution in LLM Agents via Multi-Turn Reinforcement Learning","authors":["Zihan Wang","Kangrui Wang","Qineng Wang","Pingyue Zhang","Linjie Li","Zhengyuan Yang","Xing Jin","Kefan Yu","Minh Nhat Nguyen","Licheng Liu","Eli Gottlieb","Yiping Lu","Kyunghyun Cho","Jiajun Wu","Li Fei-Fei","Lijuan Wang","Yejin Choi","Manling Li"],"abstract":"Training large language models (LLMs) as interactive agents presents unique challenges including long-horizon decision making and interacting with stochastic environment feedback. While reinforcement learning (RL) has enabled progress in static tasks, multi-turn agent RL training remains underexplored. We propose StarPO (State-Thinking-Actions-Reward Policy Optimization), a general framework for trajectory-level agent RL, and introduce RAGEN, a modular system for training and evaluating LLM agents. Our study on four stylized environments reveals three core findings. First, our agent RL training shows a recurring mode of Echo Trap where reward variance cliffs and gradient spikes; we address this with StarPO-S, a stabilized variant with trajectory filtering, critic incorporation, and gradient stabilization. Second, we find the shaping of RL rollouts would benefit from diverse initial states, medium interaction granularity and more frequent sampling. Third, we show that without fine-grained, reasoning-aware reward signals, agent reasoning hardly emerge through multi-turn RL and they may show shallow strategies or hallucinated thoughts. Code and environments are available at https://github.com/RAGEN-AI/RAGEN.","published":"2025-04-24T17:57:08Z","updated":"2025-05-26T17:19:30Z","categories":["cs.LG","cs.AI","cs.CL"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.20073v2","pdf_url":"https://arxiv.org/pdf/2504.20073v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=sgMH60bn0Y"},{"id":"2504.16489","versioned_id":"2504.16489v1","title":"Amplified Vulnerabilities: Structured Jailbreak Attacks on LLM-based Multi-Agent Debate","authors":["Senmao Qi","Yifei Zou","Peng Li","Ziyi Lin","Xiuzhen Cheng","Dongxiao Yu"],"abstract":"Multi-Agent Debate (MAD), leveraging collaborative interactions among Large Language Models (LLMs), aim to enhance reasoning capabilities in complex tasks. However, the security implications of their iterative dialogues and role-playing characteristics, particularly susceptibility to jailbreak attacks eliciting harmful content, remain critically underexplored. This paper systematically investigates the jailbreak vulnerabilities of four prominent MAD frameworks built upon leading commercial LLMs (GPT-4o, GPT-4, GPT-3.5-turbo, and DeepSeek) without compromising internal agents. We introduce a novel structured prompt-rewriting framework specifically designed to exploit MAD dynamics via narrative encapsulation, role-driven escalation, iterative refinement, and rhetorical obfuscation. Our extensive experiments demonstrate that MAD systems are inherently more vulnerable than single-agent setups. Crucially, our proposed attack methodology significantly amplifies this fragility, increasing average harmfulness from 28.14% to 80.34% and achieving attack success rates as high as 80% in certain scenarios. These findings reveal intrinsic vulnerabilities in MAD architectures and underscore the urgent need for robust, specialized defenses prior to real-world deployment.","published":"2025-04-23T08:01:50Z","updated":"2025-04-23T08:01:50Z","categories":["cs.CR","cs.AI"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2504.16489v1","pdf_url":"https://arxiv.org/pdf/2504.16489v1","comment":"33 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.21024","versioned_id":"2504.21024v2","title":"WebEvolver: Enhancing Web Agent Self-Improvement with Coevolving World Model","authors":["Tianqing Fang","Hongming Zhang","Zhisong Zhang","Kaixin Ma","Wenhao Yu","Haitao Mi","Dong Yu"],"abstract":"Agent self-improvement, where the backbone Large Language Model (LLM) of the agent are trained on trajectories sampled autonomously based on their own policies, has emerged as a promising approach for enhancing performance. Recent advancements, particularly in web environments, face a critical limitation: their performance will reach a stagnation point during autonomous learning cycles, hindering further improvement. We argue that this stems from limited exploration of the web environment and insufficient exploitation of pre-trained web knowledge in LLMs. To improve the performance of self-improvement, we propose a novel framework that introduces a co-evolving World Model LLM. This world model predicts the next observation based on the current observation and action within the web environment. Leveraging LLMs' pretrained knowledge of abundant web content, the World Model serves dual roles: (1) as a virtual web server generating self-instructed training data to continuously refine the agent's policy, and (2) as an imagination engine during inference, enabling look-ahead simulation to guide action selection for the agent LLM. Experiments in real-world web environments (Mind2Web-Live, WebVoyager, and GAIA-web) show a 10% performance gain over existing self-evolving agents, demonstrating the efficacy and generalizability of our approach, without using any distillation from more powerful close-sourced models. Our work establishes the necessity of integrating world models into autonomous agent frameworks to unlock sustained adaptability. Code is available at https://github.com/Tencent/SelfEvolvingAgent","published":"2025-04-23T02:54:31Z","updated":"2025-08-21T05:55:43Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.21024v2","pdf_url":"https://arxiv.org/pdf/2504.21024v2","comment":"EMNLP 2025 Main Conference","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=LjiIUN5qvC","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2504.16078","versioned_id":"2504.16078v1","title":"LLMs are Greedy Agents: Effects of RL Fine-tuning on Decision-Making Abilities","authors":["Thomas Schmied","Jörg Bornschein","Jordi Grau-Moya","Markus Wulfmeier","Razvan Pascanu"],"abstract":"The success of Large Language Models (LLMs) has sparked interest in various agentic applications. A key hypothesis is that LLMs, leveraging common sense and Chain-of-Thought (CoT) reasoning, can effectively explore and efficiently solve complex domains. However, LLM agents have been found to suffer from sub-optimal exploration and the knowing-doing gap, the inability to effectively act on knowledge present in the model. In this work, we systematically study why LLMs perform sub-optimally in decision-making scenarios. In particular, we closely examine three prevalent failure modes: greediness, frequency bias, and the knowing-doing gap. We propose mitigation of these shortcomings by fine-tuning via Reinforcement Learning (RL) on self-generated CoT rationales. Our experiments across multi-armed bandits, contextual bandits, and Tic-tac-toe, demonstrate that RL fine-tuning enhances the decision-making abilities of LLMs by increasing exploration and narrowing the knowing-doing gap. Finally, we study both classic exploration mechanisms, such as $ε$-greedy, and LLM-specific approaches, such as self-correction and self-consistency, to enable more effective fine-tuning of LLMs for decision-making.","published":"2025-04-22T17:57:14Z","updated":"2025-04-22T17:57:14Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.16078v1","pdf_url":"https://arxiv.org/pdf/2504.16078v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=b9EreX9xL0","openreview_venues":["ICLR 2026 Poster"]},{"id":"2504.15228","versioned_id":"2504.15228v2","title":"A Self-Improving Coding Agent","authors":["Maxime Robeyns","Martin Szummer","Laurence Aitchison"],"abstract":"Recent advancements in Large Language Models (LLMs) have spurred interest in deploying LLM agents to undertake tasks in the world. LLMs are often deployed in agent systems: code that orchestrates LLM calls and provides them with tools. We demonstrate that an agent system, equipped with basic coding tools, can autonomously edit itself, and thereby improve its performance on benchmark tasks. We find performance gains from 17% to 53% on a random subset of SWE Bench Verified, with additional performance gains on LiveCodeBench, as well as synthetically generated agent benchmarks. Our work represents an advancement in the automated and open-ended design of agentic systems, and demonstrates a data-efficient, non gradient-based learning mechanism driven by LLM reflection and code updates.","published":"2025-04-21T16:58:18Z","updated":"2025-05-16T20:58:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.15228v2","pdf_url":"https://arxiv.org/pdf/2504.15228v2","comment":"Submitted as a preprint to NeurIPS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=rShJCyLsOr","openreview_venues":["SSI-FM Oral"]},{"id":"2504.15125","versioned_id":"2504.15125v3","title":"Contemplative Artificial Intelligence","authors":["Ruben Laukkonen","Fionn Inglis","Shamil Chandaria","Lars Sandved-Smith","Edmundo Lopez-Sola","Jakob Hohwy","Jonathan Gold","Adam Elwood"],"abstract":"As artificial intelligence (AI) improves, traditional alignment strategies may falter in the face of unpredictable self-improvement, hidden subgoals, and the sheer complexity of intelligent systems. Inspired by contemplative wisdom traditions, we show how four axiomatic principles can instil a resilient Wise World Model in AI systems. First, mindfulness enables self-monitoring and recalibration of emergent subgoals. Second, emptiness forestalls dogmatic goal fixation and relaxes rigid priors. Third, non-duality dissolves adversarial self-other boundaries. Fourth, boundless care motivates the universal reduction of suffering. We find that prompting AI to reflect on these principles improves performance on the AILuminate Benchmark (d=.96) and boosts cooperation and joint-reward on the Prisoner's Dilemma task (d=7+). We offer detailed implementation strategies at the level of architectures, constitutions, and reinforcement on chain-of-thought. For future systems, active inference may offer the self-organizing and dynamic coupling capabilities needed to enact Contemplative AI in embodied agents.","published":"2025-04-21T14:20:49Z","updated":"2025-08-18T10:09:08Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.15125v3","pdf_url":"https://arxiv.org/pdf/2504.15125v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:qE3knKF1rz","versioned_id":"qE3knKF1rz","title":"PANDA: Towards Generalist Video Anomaly Detection via Agentic AI Engineer","authors":["Zhiwei Yang","Chen Gao","Mike Zheng Shou"],"abstract":"Video anomaly detection (VAD) is a critical yet challenging task due to the complex and diverse nature of real-world scenarios. Previous methods typically rely on domain-specific training data and manual adjustments when applying to new scenarios and unseen anomaly types, suffering from high labor costs and limited generalization. Therefore, we aim to achieve generalist VAD, \\ie, automatically handle any scene and any anomaly types without training data or human involvement. In this work, we propose PANDA, an agentic AI engineer based on MLLMs. Specifically, we achieve PANDA by comprehensively devising four key capabilities: (1) self-adaptive scene-aware strategy planning, (2) goal-driven heuristic reasoning, (3) tool-augmented self-reflection, and (4) self-improving chain-of-memory. Concretely, we develop a self-adaptive scene-aware RAG mechanism, enabling PANDA to retrieve anomaly-specific knowledge for anomaly detection strategy planning. Next, we introduce a latent anomaly-guided heuristic prompt strategy to enhance reasoning precision. Furthermore, PANDA employs a progressive reflection mechanism alongside a suite of context-aware tools to iteratively refine decision-making in complex scenarios. Finally, a chain-of-memory mechanism enables PANDA to leverage historical experiences for continual performance improvement. Extensive experiments demonstrate that PANDA achieves state-of-the-art performance in multi-scenario, open-set, and complex scenario settings without training and manual involvement, validating its generalizable and robust anomaly detection capability. Code is released at https://github.com/showlab/PANDA.","published":"2025-04-20T11:32:39+00:00","updated":"2026-07-09T20:04:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=qE3knKF1rz","openreview_url":"https://openreview.net/forum?id=qE3knKF1rz","pdf_url":"https://openreview.net/pdf?id=qE3knKF1rz","comment":"NeurIPS 2025 poster","journal_ref":"NeurIPS 2025 poster","doi":"","venue":"NeurIPS 2025 poster","venue_id":"NeurIPS.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2504.14520","versioned_id":"2504.14520v1","title":"Meta-Thinking in LLMs via Multi-Agent Reinforcement Learning: A Survey","authors":["Ahsan Bilal","Muhammad Ahmed Mohsin","Muhammad Umer","Muhammad Awais Khan Bangash","Muhammad Ali Jamshed"],"abstract":"This survey explores the development of meta-thinking capabilities in Large Language Models (LLMs) from a Multi-Agent Reinforcement Learning (MARL) perspective. Meta-thinking self-reflection, assessment, and control of thinking processes is an important next step in enhancing LLM reliability, flexibility, and performance, particularly for complex or high-stakes tasks. The survey begins by analyzing current LLM limitations, such as hallucinations and the lack of internal self-assessment mechanisms. It then talks about newer methods, including RL from human feedback (RLHF), self-distillation, and chain-of-thought prompting, and each of their limitations. The crux of the survey is to talk about how multi-agent architectures, namely supervisor-agent hierarchies, agent debates, and theory of mind frameworks, can emulate human-like introspective behavior and enhance LLM robustness. By exploring reward mechanisms, self-play, and continuous learning methods in MARL, this survey gives a comprehensive roadmap to building introspective, adaptive, and trustworthy LLMs. Evaluation metrics, datasets, and future research avenues, including neuroscience-inspired architectures and hybrid symbolic reasoning, are also discussed.","published":"2025-04-20T07:34:26Z","updated":"2025-04-20T07:34:26Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.14520v1","pdf_url":"https://arxiv.org/pdf/2504.14520v1","comment":"Submitted to IEEE Transactions on Artificial Intelligence","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.12951","versioned_id":"2504.12951v1","title":"Are Retrials All You Need? Enhancing Large Language Model Reasoning Without Verbalized Feedback","authors":["Nearchos Potamitis","Akhil Arora"],"abstract":"Recent advancements in large language models (LLMs) have catalyzed the development of general-purpose autonomous agents, demonstrating remarkable performance in complex reasoning tasks across various domains. This surge has spurred the evolution of a plethora of prompt-based reasoning frameworks. A recent focus has been on iterative reasoning strategies that refine outputs through self-evaluation and verbalized feedback. However, these strategies require additional computational complexity to enable models to recognize and correct their mistakes, leading to a significant increase in their cost. In this work, we introduce the concept of ``retrials without feedback'', an embarrassingly simple yet powerful mechanism for enhancing reasoning frameworks by allowing LLMs to retry problem-solving attempts upon identifying incorrect answers. Unlike conventional iterative refinement methods, our method does not require explicit self-reflection or verbalized feedback, simplifying the refinement process. Our findings indicate that simpler retrial-based approaches often outperform more sophisticated reasoning frameworks, suggesting that the benefits of complex methods may not always justify their computational costs. By challenging the prevailing assumption that more intricate reasoning strategies inherently lead to better performance, our work offers new insights into how simpler, more efficient approaches can achieve optimal results. So, are retrials all you need?","published":"2025-04-17T13:52:48Z","updated":"2025-04-17T13:52:48Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.12951v1","pdf_url":"https://arxiv.org/pdf/2504.12951v1","comment":"8 pages, 16 figures, 1 table. arXiv admin note: text overlap with arXiv:2405.06691","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:W4hexmqgoN","versioned_id":"W4hexmqgoN","title":"A Dataset-Centric Survey of LLM-Agents for Data Science","authors":[],"abstract":"Large Language Model (LLM)-based agents are increasingly employed to automate data science workflows, from preprocessing and modeling to interpretation and decision-making. While recent surveys have explored their technical designs, little attention has been paid to how these agents adapt to datasets with different structures and domain requirements. This survey adopts a dataset-centric perspective, categorizing LLM-based data agents by the types of data they are designed for and evaluated on. We analyze key design choices—such as planning strategies, self-correction mechanisms, multi-agent collaboration, and tool integration—through the lens of structured, semi-structured, and unstructured data, as well as domain-specific applications. We introduce a hierarchical taxonomy that connects agents’ capabilities in data management and analysis to their dataset contexts. Our analysis highlights current gaps in benchmark diversity and generalization, offering insights into the practical limitations of existing agents. We conclude by outlining future directions for designing and evaluating LLM-based data agents that are robust, adaptable, and dataset-aware.","published":"2025-04-17T05:05:16+00:00","updated":"2025-04-18T00:27:56+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=W4hexmqgoN","openreview_url":"https://openreview.net/forum?id=W4hexmqgoN","pdf_url":"https://openreview.net/pdf?id=W4hexmqgoN","comment":"UIUC Spring 2025 CS598 LLM Agent Workshop Submission","journal_ref":"UIUC Spring 2025 CS598 LLM Agent Workshop Submission","doi":"","venue":"UIUC Spring 2025 CS598 LLM Agent Workshop Submission","venue_id":"illinois.edu/UIUC/Spring_2025/CS598_LLM_Agent_Workshop/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:BOA5Yq51Dz","versioned_id":"BOA5Yq51Dz","title":"OS Agents: A Survey on MLLM-based Agents for Computer, Phone and Browser Use","authors":["Xueyu Hu","Tao Xiong","Biao Yi","Zishu Wei","Ruixuan Xiao","Yurun Chen","Jiasheng Ye","Meiling Tao","Xiangxin Zhou","Ziyu Zhao","Yuhuai Li","Shengze Xu","Shenzhi Wang","Xinchen Xu","Shuofei Qiao","Zhaokai Wang","Kun Kuang","Tieyong Zeng","Liang Wang","Jiwei Li","Yuchen Eleanor Jiang","Wangchunshu Zhou","Guoyin Wang","Keting Yin","Zhou Zhao","Hongxia Yang","Fan Wu","Shengyu Zhang","Fei Wu"],"abstract":"The dream to create AI assistants as capable and versatile as the fictional J.A.R.V.I.S from Iron Man has long captivated imaginations. With the evolution of (multi\\-modal) large language models ((M)LLMs), this dream is closer to reality, as (M)LLM-based Agents using computers, phones and browsers by operating within the environments and interfaces (e.g., Graphical User Interface (GUI) and Command Line Interface (CLI)) provided by operating systems (OS) to automate tasks have significantly advanced. This paper presents a comprehensive survey of these advanced agents, designated as OS Agents. We begin by elucidating the fundamentals of OS Agents, exploring their key components including the environment, observation space, and action space, and outlining essential capabilities such as understanding, planning, and grounding. We then examine methodologies for constructing OS Agents, focusing on domain-specific foundation models and agent frameworks. A detailed review of evaluation protocols and benchmarks highlights how OS Agents are assessed across diverse tasks. Finally, we discuss current challenges and identify promising directions for future research, including safety and privacy, personalization and self-evolution. This survey aims to consolidate the state of OS Agents research, providing insights to guide both academic inquiry and industrial development. An open-source GitHub repository is maintained as a dynamic resource to foster further innovation in this field.","published":"2025-04-16T13:23:44+00:00","updated":"2025-04-16T13:23:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=BOA5Yq51Dz","openreview_url":"https://openreview.net/forum?id=BOA5Yq51Dz","pdf_url":"https://openreview.net/pdf?id=BOA5Yq51Dz","comment":"","journal_ref":"","doi":"","venue":"","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2504.11301","versioned_id":"2504.11301v2","title":"Learning to Be A Doctor: Searching for Effective Medical Agent Architectures","authors":["Yangyang Zhuang","Wenjia Jiang","Jiayu Zhang","Ze Yang","Joey Tianyi Zhou","Chi Zhang"],"abstract":"Large Language Model (LLM)-based agents have demonstrated strong capabilities across a wide range of tasks, and their application in the medical domain holds particular promise due to the demand for high generalizability and reliance on interdisciplinary knowledge. However, existing medical agent systems often rely on static, manually crafted workflows that lack the flexibility to accommodate diverse diagnostic requirements and adapt to emerging clinical scenarios. Motivated by the success of automated machine learning (AutoML), this paper introduces a novel framework for the automated design of medical agent architectures. Specifically, we define a hierarchical and expressive agent search space that enables dynamic workflow adaptation through structured modifications at the node, structural, and framework levels. Our framework conceptualizes medical agents as graph-based architectures composed of diverse, functional node types and supports iterative self-improvement guided by diagnostic feedback. Experimental results on skin disease diagnosis tasks demonstrate that the proposed method effectively evolves workflow structures and significantly enhances diagnostic accuracy over time. This work represents the first fully automated framework for medical agent architecture design and offers a scalable, adaptable foundation for deploying intelligent agents in real-world clinical environments.","published":"2025-04-15T15:44:21Z","updated":"2025-08-15T08:59:23Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.11301v2","pdf_url":"https://arxiv.org/pdf/2504.11301v2","comment":"Accepted at ACM MM 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=UsyM1tAlV3"},{"id":"2504.09665","versioned_id":"2504.09665v1","title":"CLEAR-KGQA: Clarification-Enhanced Ambiguity Resolution for Knowledge Graph Question Answering","authors":["Liqiang Wen","Guanming Xiong","Tong Mo","Bing Li","Weiping Li","Wen Zhao"],"abstract":"This study addresses the challenge of ambiguity in knowledge graph question answering (KGQA). While recent KGQA systems have made significant progress, particularly with the integration of large language models (LLMs), they typically assume user queries are unambiguous, which is an assumption that rarely holds in real-world applications. To address these limitations, we propose a novel framework that dynamically handles both entity ambiguity (e.g., distinguishing between entities with similar names) and intent ambiguity (e.g., clarifying different interpretations of user queries) through interactive clarification. Our approach employs a Bayesian inference mechanism to quantify query ambiguity and guide LLMs in determining when and how to request clarification from users within a multi-turn dialogue framework. We further develop a two-agent interaction framework where an LLM-based user simulator enables iterative refinement of logical forms through simulated user feedback. Experimental results on the WebQSP and CWQ dataset demonstrate that our method significantly improves performance by effectively resolving semantic ambiguities. Additionally, we contribute a refined dataset of disambiguated queries, derived from interaction histories, to facilitate future research in this direction.","published":"2025-04-13T17:34:35Z","updated":"2025-04-13T17:34:35Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.09665v1","pdf_url":"https://arxiv.org/pdf/2504.09665v1","comment":"This work has been accepted by the IJCNN 2025 main track","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.08696","versioned_id":"2504.08696v2","title":"SeaView: Software Engineering Agent Visual Interface for Enhanced Workflow","authors":["Timothy Bula","Saurabh Pujar","Luca Buratti","Mihaela Bornea","Avirup Sil"],"abstract":"Auto-regressive LLM-based software engineering (SWE) agents, henceforth SWE agents, have made tremendous progress (>60% on SWE-Bench Verified) on real-world coding challenges including GitHub issue resolution. SWE agents use a combination of reasoning, environment interaction and self-reflection to resolve issues thereby generating \"trajectories\". Analysis of SWE agent trajectories is difficult, not only as they exceed LLM sequence length (sometimes, greater than 128k) but also because it involves a relatively prolonged interaction between an LLM and the environment managed by the agent. In case of an agent error, it can be hard to decipher, locate and understand its scope. Similarly, it can be hard to track improvements or regression over multiple runs or experiments. While a lot of research has gone into making these SWE agents reach state-of-the-art, much less focus has been put into creating tools to help analyze and visualize agent output. We propose a novel tool called SeaView: Software Engineering Agent Visual Interface for Enhanced Workflow, with a vision to assist SWE-agent researchers to visualize and inspect their experiments. SeaView's novel mechanisms help compare experimental runs with varying hyper-parameters or LLMs, and quickly get an understanding of LLM or environment related problems. Based on our user study, experienced researchers spend between 10 and 30 minutes to gather the information provided by SeaView, while researchers with little experience can spend between 30 minutes to 1 hour to diagnose their experiment.","published":"2025-04-11T17:03:58Z","updated":"2025-04-14T16:02:38Z","categories":["cs.SE","cs.LG"],"primary_category":"cs.SE","arxiv_url":"https://arxiv.org/abs/2504.08696v2","pdf_url":"https://arxiv.org/pdf/2504.08696v2","comment":"8 pages, 5 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.08687","versioned_id":"2504.08687v1","title":"Voice Interaction With Conversational AI Could Facilitate Thoughtful Reflection and Substantive Revision in Writing","authors":["Jiho Kim","Philippe Laban","Xiang 'Anthony' Chen","Kenneth C. Arnold"],"abstract":"Writing well requires not only expressing ideas but also refining them through revision, a process facilitated by reflection. Prior research suggests that feedback delivered through dialogues, such as those in writing center tutoring sessions, can help writers reflect more thoughtfully on their work compared to static feedback. Recent advancements in multi-modal large language models (LLMs) now offer new possibilities for supporting interactive and expressive voice-based reflection in writing. In particular, we propose that LLM-generated static feedback can be repurposed as conversation starters, allowing writers to seek clarification, request examples, and ask follow-up questions, thereby fostering deeper reflection on their writing. We argue that voice-based interaction can naturally facilitate this conversational exchange, encouraging writers' engagement with higher-order concerns, facilitating iterative refinement of their reflections, and reduce cognitive load compared to text-based interactions. To investigate these effects, we propose a formative study exploring how text vs. voice input influence writers' reflection and subsequent revisions. Findings from this study will inform the design of intelligent and interactive writing tools, offering insights into how voice-based interactions with LLM-powered conversational agents can support reflection and revision.","published":"2025-04-11T16:54:12Z","updated":"2025-04-11T16:54:12Z","categories":["cs.HC","cs.AI","cs.CY"],"primary_category":"cs.HC","arxiv_url":"https://arxiv.org/abs/2504.08687v1","pdf_url":"https://arxiv.org/pdf/2504.08687v1","comment":"5 pages; Accepted to Fourth Workshop on Intelligent and Interactive Writing Assistants (In2Writing 2025) at NAACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.12322","versioned_id":"2504.12322v2","title":"A Strategic Coordination Framework of Small LLMs Matches Large LLMs in Data Synthesis","authors":["Xin Gao","Qizhi Pei","Zinan Tang","Yu Li","Honglin Lin","Jiang Wu","Lijun Wu","Conghui He"],"abstract":"While data synthesis and distillation are promising strategies to enhance small language models, current approaches heavily rely on Large Language Models (LLMs), which suffer from high computational costs, environmental inefficiency, and potential biases inherited from monolithic architectures. In contrast, smaller LLMs are more accessible and sustainable, but their individual capabilities often fall short in generating high-quality, diverse, and reliable data. Inspired by collaborative human processes (e.g., peer review), we propose a multiple small LLMs involved framework, GRA, that aggregates specialized roles across small LLMs to iterative refinement and quality control typically achieved by a single large LLM. In this collaborative framework, multiple small LLMs assume distinct roles-Generator, Reviewer, and Adjudicator-to simulate a peer-review-inspired data synthesis pipeline. The Generator proposes initial data samples, the Reviewer critiques their quality and diversity, and the Adjudicator resolves conflicts to finalize the output. By decomposing the synthesis process into specialized sub-tasks, collaborative small LLMs can achieve data-level parity with large LLM-based distillation. Through experiments across multiple benchmarks, we demonstrate that GRA-produced data matches or exceeds the quality of single large LLM outputs, e.g., Qwen-2.5-72B-Instruct. Our results challenge the necessity of monolithic large models for high-quality data synthesis, advocating instead for strategic coordination of smaller agents. Our datasets, models, and code are publicly available at https://github.com/GX-XinGao/GRA.","published":"2025-04-11T06:13:43Z","updated":"2025-04-21T07:29:28Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.12322v2","pdf_url":"https://arxiv.org/pdf/2504.12322v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.08066","versioned_id":"2504.08066v1","title":"The AI Scientist-v2: Workshop-Level Automated Scientific Discovery via Agentic Tree Search","authors":["Yutaro Yamada","Robert Tjarko Lange","Cong Lu","Shengran Hu","Chris Lu","Jakob Foerster","Jeff Clune","David Ha"],"abstract":"AI is increasingly playing a pivotal role in transforming how scientific discoveries are made. We introduce The AI Scientist-v2, an end-to-end agentic system capable of producing the first entirely AI generated peer-review-accepted workshop paper. This system iteratively formulates scientific hypotheses, designs and executes experiments, analyzes and visualizes data, and autonomously authors scientific manuscripts. Compared to its predecessor (v1, Lu et al., 2024 arXiv:2408.06292), The AI Scientist-v2 eliminates the reliance on human-authored code templates, generalizes effectively across diverse machine learning domains, and leverages a novel progressive agentic tree-search methodology managed by a dedicated experiment manager agent. Additionally, we enhance the AI reviewer component by integrating a Vision-Language Model (VLM) feedback loop for iterative refinement of content and aesthetics of the figures. We evaluated The AI Scientist-v2 by submitting three fully autonomous manuscripts to a peer-reviewed ICLR workshop. Notably, one manuscript achieved high enough scores to exceed the average human acceptance threshold, marking the first instance of a fully AI-generated paper successfully navigating a peer review. This accomplishment highlights the growing capability of AI in conducting all aspects of scientific research. We anticipate that further advancements in autonomous scientific discovery technologies will profoundly impact human knowledge generation, enabling unprecedented scalability in research productivity and significantly accelerating scientific breakthroughs, greatly benefiting society at large. We have open-sourced the code at https://github.com/SakanaAI/AI-Scientist-v2 to foster the future development of this transformative technology. We also discuss the role of AI in science, including AI safety.","published":"2025-04-10T18:44:41Z","updated":"2025-04-10T18:44:41Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.08066v1","pdf_url":"https://arxiv.org/pdf/2504.08066v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.07463","versioned_id":"2504.07463v1","title":"Enhanced Question-Answering for Skill-based learning using Knowledge-based AI and Generative AI","authors":["Rahul K. Dass","Rochan H. Madhusudhana","Erin C. Deye","Shashank Verma","Timothy A. Bydlon","Grace Brazil","Ashok K. Goel"],"abstract":"Supporting learners' understanding of taught skills in online settings is a longstanding challenge. While exercises and chat-based agents can evaluate understanding in limited contexts, this challenge is magnified when learners seek explanations that delve into procedural knowledge (how things are done) and reasoning (why things happen). We hypothesize that an intelligent agent's ability to understand and explain learners' questions about skills can be significantly enhanced using the TMK (Task-Method-Knowledge) model, a Knowledge-based AI framework. We introduce Ivy, an intelligent agent that leverages an LLM and iterative refinement techniques to generate explanations that embody teleological, causal, and compositional principles. Our initial evaluation demonstrates that this approach goes beyond the typical shallow responses produced by an agent with access to unstructured text, thereby substantially improving the depth and relevance of feedback. This can potentially ensure learners develop a comprehensive understanding of skills crucial for effective problem-solving in online environments.","published":"2025-04-10T05:25:52Z","updated":"2025-04-10T05:25:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.07463v1","pdf_url":"https://arxiv.org/pdf/2504.07463v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.07079","versioned_id":"2504.07079v1","title":"SkillWeaver: Web Agents can Self-Improve by Discovering and Honing Skills","authors":["Boyuan Zheng","Michael Y. Fatemi","Xiaolong Jin","Zora Zhiruo Wang","Apurva Gandhi","Yueqi Song","Yu Gu","Jayanth Srinivasa","Gaowen Liu","Graham Neubig","Yu Su"],"abstract":"To survive and thrive in complex environments, humans have evolved sophisticated self-improvement mechanisms through environment exploration, hierarchical abstraction of experiences into reuseable skills, and collaborative construction of an ever-growing skill repertoire. Despite recent advancements, autonomous web agents still lack crucial self-improvement capabilities, struggling with procedural knowledge abstraction, refining skills, and skill composition. In this work, we introduce SkillWeaver, a skill-centric framework enabling agents to self-improve by autonomously synthesizing reusable skills as APIs. Given a new website, the agent autonomously discovers skills, executes them for practice, and distills practice experiences into robust APIs. Iterative exploration continually expands a library of lightweight, plug-and-play APIs, significantly enhancing the agent's capabilities. Experiments on WebArena and real-world websites demonstrate the efficacy of SkillWeaver, achieving relative success rate improvements of 31.8% and 39.8%, respectively. Additionally, APIs synthesized by strong agents substantially enhance weaker agents through transferable skills, yielding improvements of up to 54.3% on WebArena. These results demonstrate the effectiveness of honing diverse website interactions into APIs, which can be seamlessly shared among various web agents.","published":"2025-04-09T17:51:50Z","updated":"2025-04-09T17:51:50Z","categories":["cs.AI","cs.CL","cs.CV"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.07079v1","pdf_url":"https://arxiv.org/pdf/2504.07079v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.06943","versioned_id":"2504.06943v2","title":"Review of Case-Based Reasoning for LLM Agents: Theoretical Foundations, Architectural Components, and Cognitive Integration","authors":["Kostas Hatalis","Despina Christou","Vyshnavi Kondapalli"],"abstract":"Agents powered by Large Language Models (LLMs) have recently demonstrated impressive capabilities in various tasks. Still, they face limitations in tasks requiring specific, structured knowledge, flexibility, or accountable decision-making. While agents are capable of perceiving their environments, forming inferences, planning, and executing actions towards goals, they often face issues such as hallucinations and lack of contextual memory across interactions. This paper explores how Case-Based Reasoning (CBR), a strategy that solves new problems by referencing past experiences, can be integrated into LLM agent frameworks. This integration allows LLMs to leverage explicit knowledge, enhancing their effectiveness. We systematically review the theoretical foundations of these enhanced agents, identify critical framework components, and formulate a mathematical model for the CBR processes of case retrieval, adaptation, and learning. We also evaluate CBR-enhanced agents against other methods like Chain-of-Thought reasoning and standard Retrieval-Augmented Generation, analyzing their relative strengths. Moreover, we explore how leveraging CBR's cognitive dimensions (including self-reflection, introspection, and curiosity) via goal-driven autonomy mechanisms can further enhance the LLM agent capabilities. Contributing to the ongoing research on neuro-symbolic hybrid systems, this work posits CBR as a viable technique for enhancing the reasoning skills and cognitive aspects of autonomous LLM agents.","published":"2025-04-09T14:51:02Z","updated":"2025-04-11T05:34:20Z","categories":["cs.AI","cs.MA"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.06943v2","pdf_url":"https://arxiv.org/pdf/2504.06943v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.16939","versioned_id":"2504.16939v1","title":"A Desideratum for Conversational Agents: Capabilities, Challenges, and Future Directions","authors":["Emre Can Acikgoz","Cheng Qian","Hongru Wang","Vardhan Dongre","Xiusi Chen","Heng Ji","Dilek Hakkani-Tür","Gokhan Tur"],"abstract":"Recent advances in Large Language Models (LLMs) have propelled conversational AI from traditional dialogue systems into sophisticated agents capable of autonomous actions, contextual awareness, and multi-turn interactions with users. Yet, fundamental questions about their capabilities, limitations, and paths forward remain open. This survey paper presents a desideratum for next-generation Conversational Agents - what has been achieved, what challenges persist, and what must be done for more scalable systems that approach human-level intelligence. To that end, we systematically analyze LLM-driven Conversational Agents by organizing their capabilities into three primary dimensions: (i) Reasoning - logical, systematic thinking inspired by human intelligence for decision making, (ii) Monitor - encompassing self-awareness and user interaction monitoring, and (iii) Control - focusing on tool utilization and policy following. Building upon this, we introduce a novel taxonomy by classifying recent work on Conversational Agents around our proposed desideratum. We identify critical research gaps and outline key directions, including realistic evaluations, long-term multi-turn reasoning skills, self-evolution capabilities, collaborative and multi-agent task completion, personalization, and proactivity. This work aims to provide a structured foundation, highlight existing limitations, and offer insights into potential future research directions for Conversational Agents, ultimately advancing progress toward Artificial General Intelligence (AGI). We maintain a curated repository of papers at: https://github.com/emrecanacikgoz/awesome-conversational-agents.","published":"2025-04-07T21:01:25Z","updated":"2025-04-07T21:01:25Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.16939v1","pdf_url":"https://arxiv.org/pdf/2504.16939v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.04711","versioned_id":"2504.04711v1","title":"Generalising from Self-Produced Data: Model Training Beyond Human Constraints","authors":["Alfath Daryl Alhajir","Jennifer Dodgson","Joseph Lim","Truong Ma Phi","Julian Peh","Akira Rafhael Janson Pattirane","Lokesh Poovaragan"],"abstract":"Current large language models (LLMs) are constrained by human-derived training data and limited by a single level of abstraction that impedes definitive truth judgments. This paper introduces a novel framework in which AI models autonomously generate and validate new knowledge through direct interaction with their environment. Central to this approach is an unbounded, ungamable numeric reward - such as annexed disk space or follower count - that guides learning without requiring human benchmarks. AI agents iteratively generate strategies and executable code to maximize this metric, with successful outcomes forming the basis for self-retraining and incremental generalisation. To mitigate model collapse and the warm start problem, the framework emphasizes empirical validation over textual similarity and supports fine-tuning via GRPO. The system architecture employs modular agents for environment analysis, strategy generation, and code synthesis, enabling scalable experimentation. This work outlines a pathway toward self-improving AI systems capable of advancing beyond human-imposed constraints toward autonomous general intelligence.","published":"2025-04-07T03:48:02Z","updated":"2025-04-07T03:48:02Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.04711v1","pdf_url":"https://arxiv.org/pdf/2504.04711v1","comment":"16 pages, 2 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.03160","versioned_id":"2504.03160v4","title":"DeepResearcher: Scaling Deep Research via Reinforcement Learning in Real-world Environments","authors":["Yuxiang Zheng","Dayuan Fu","Xiangkun Hu","Xiaojie Cai","Lyumanshan Ye","Pengrui Lu","Pengfei Liu"],"abstract":"Large Language Models (LLMs) equipped with web search capabilities have demonstrated impressive potential for deep research tasks. However, current approaches predominantly rely on either manually engineered prompts (prompt engineering-based) with brittle performance or reinforcement learning within controlled Retrieval-Augmented Generation (RAG) environments (RAG-based) that fail to capture the complexities of real-world interaction. In this paper, we introduce DeepResearcher, the first comprehensive framework for end-to-end training of LLM-based deep research agents through scaling reinforcement learning (RL) in real-world environments with authentic web search interactions. Unlike RAG-based approaches that assume all necessary information exists within a fixed corpus, our method trains agents to navigate the noisy, unstructured, and dynamic nature of the open web. We implement a specialized multi-agent architecture where browsing agents extract relevant information from various webpage structures and overcoming significant technical challenges. Extensive experiments on open-domain research tasks demonstrate that DeepResearcher achieves substantial improvements of up to 28.9 points over prompt engineering-based baselines and up to 7.2 points over RAG-based RL agents. Our qualitative analysis reveals emergent cognitive behaviors from end-to-end RL training, including the ability to formulate plans, cross-validate information from multiple sources, engage in self-reflection to redirect research, and maintain honesty when unable to find definitive answers. Our results highlight that end-to-end training in real-world web environments is not merely an implementation detail but a fundamental requirement for developing robust research capabilities aligned with real-world applications. We release DeepResearcher at https://github.com/GAIR-NLP/DeepResearcher.","published":"2025-04-04T04:41:28Z","updated":"2025-04-17T04:46:08Z","categories":["cs.AI","cs.CL","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.03160v4","pdf_url":"https://arxiv.org/pdf/2504.03160v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=X2KQcxnCne","openreview_venues":["ACL ARR 2025 May Submission"]},{"id":"2504.03771","versioned_id":"2504.03771v1","title":"Flow State: Humans Enabling AI Systems to Program Themselves","authors":["Helena Zhang","Jakobi Haskell","Yosef Frost"],"abstract":"Compound AI systems, orchestrating multiple AI components and external APIs, are increasingly vital but face challenges in managing complexity, handling ambiguity, and enabling effective development workflows. Existing frameworks often introduce significant overhead, implicit complexity, or restrictive abstractions, hindering maintainability and iterative refinement, especially in Human-AI collaborative settings. We argue that overcoming these hurdles requires a foundational architecture prioritizing structural clarity and explicit control. To this end, we introduce Pocketflow, a platform centered on Human-AI co-design, enabled by Pocketflow. Pocketflow is a Python framework built upon a deliberately minimal yet synergistic set of core abstractions: modular Nodes with a strict lifecycle, declarative Flow orchestration, native hierarchical nesting (Flow-as-Node), and explicit action-based conditional logic. This unique combination provides a robust, vendor-agnostic foundation with very little code that demonstrably reduces overhead while offering the expressiveness needed for complex patterns like agentic workflows and RAG. Complemented by Pocket AI, an assistant leveraging this structure for system design, Pocketflow provides an effective environment for iteratively prototyping, refining, and deploying the adaptable, scalable AI systems demanded by modern enterprises.","published":"2025-04-03T05:25:46Z","updated":"2025-04-03T05:25:46Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2504.03771v1","pdf_url":"https://arxiv.org/pdf/2504.03771v1","comment":"25 pages, 4 figures, 5 tables. Describes a minimalist framework for human-AI co-design of compound AI systems","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2504.00711","versioned_id":"2504.00711v2","title":"GraphMaster: Automated Graph Synthesis via LLM Agents in Data-Limited Environments","authors":["Enjun Du","Xunkai Li","Tian Jin","Zhihan Zhang","Rong-Hua Li","Guoren Wang"],"abstract":"The era of foundation models has revolutionized AI research, yet Graph Foundation Models (GFMs) remain constrained by the scarcity of large-scale graph corpora. Traditional graph data synthesis techniques primarily focus on simplistic structural operations, lacking the capacity to generate semantically rich nodes with meaningful textual attributes: a critical limitation for real-world applications. While large language models (LLMs) demonstrate exceptional text generation capabilities, their direct application to graph synthesis is impeded by context window limitations, hallucination phenomena, and structural consistency challenges. To address these issues, we introduce GraphMaster, the first multi-agent framework specifically designed for graph data synthesis in data-limited environments. GraphMaster orchestrates four specialized LLM agents (Manager, Perception, Enhancement, and Evaluation) that collaboratively optimize the synthesis process through iterative refinement, ensuring both semantic coherence and structural integrity. To rigorously evaluate our approach, we create new data-limited \"Sub\" variants of six standard graph benchmarks, specifically designed to test synthesis capabilities under realistic constraints. Additionally, we develop a novel interpretability assessment framework that combines human evaluation with a principled Grassmannian manifold-based analysis, providing both qualitative and quantitative measures of semantic coherence. Experimental results demonstrate that GraphMaster significantly outperforms traditional synthesis methods across multiple datasets, establishing a strong foundation for advancing GFMs in data-scarce environments.","published":"2025-04-01T12:21:50Z","updated":"2025-05-05T13:57:12Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2504.00711v2","pdf_url":"https://arxiv.org/pdf/2504.00711v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=h3dbocj7po","openreview_venues":["NeurIPS 2025 spotlight"]},{"id":"2504.00698","versioned_id":"2504.00698v2","title":"Command A: An Enterprise-Ready Large Language Model","authors":["Team Cohere",":","Aakanksha","Arash Ahmadian","Marwan Ahmed","Jay Alammar","Milad Alizadeh","Yazeed Alnumay","Sophia Althammer","Arkady Arkhangorodsky","Viraat Aryabumi","Dennis Aumiller","Raphaël Avalos","Zahara Aviv","Sammie Bae","Saurabh Baji","Alexandre Barbet","Max Bartolo","Björn Bebensee","Neeral Beladia","Walter Beller-Morales","Alexandre Bérard","Andrew Berneshawi","Anna Bialas","Phil Blunsom","Matt Bobkin","Adi Bongale","Sam Braun","Maxime Brunet","Samuel Cahyawijaya","David Cairuz","Jon Ander Campos","Cassie Cao","Kris Cao","Roman Castagné","Julián Cendrero","Leila Chan Currie","Yash Chandak","Diane Chang","Giannis Chatziveroglou","Hongyu Chen","Claire Cheng","Alexis Chevalier","Justin T. Chiu","Eugene Cho","Eugene Choi","Eujeong Choi","Tim Chung","Volkan Cirik","Ana Cismaru","Pierre Clavier","Henry Conklin","Lucas Crawhall-Stein","Devon Crouse","Andres Felipe Cruz-Salinas","Ben Cyrus","Daniel D'souza","Hugo Dalla-Torre","John Dang","William Darling","Omar Darwiche Domingues","Saurabh Dash","Antoine Debugne","Théo Dehaze","Shaan Desai","Joan Devassy","Rishit Dholakia","Kyle Duffy","Ali Edalati","Ace Eldeib","Abdullah Elkady","Sarah Elsharkawy","Irem Ergün","Beyza Ermis","Marzieh Fadaee","Boyu Fan","Lucas Fayoux","Yannis Flet-Berliac","Nick Frosst","Matthias Gallé","Wojciech Galuba","Utsav Garg","Matthieu Geist","Mohammad Gheshlaghi Azar","Ellen Gilsenan-McMahon","Seraphina Goldfarb-Tarrant","Tomas Goldsack","Aidan Gomez","Victor Machado Gonzaga","Nithya Govindarajan","Manoj Govindassamy","Nathan Grinsztajn","Nikolas Gritsch","Patrick Gu","Shangmin Guo","Kilian Haefeli","Rod Hajjar","Tim Hawes","Jingyi He","Sebastian Hofstätter","Sungjin Hong","Sara Hooker","Tom Hosking","Stephanie Howe","Eric Hu","Renjie Huang","Hemant Jain","Ritika Jain","Nick Jakobi","Madeline Jenkins","JJ Jordan","Dhruti Joshi","Jason Jung","Trushant Kalyanpur","Siddhartha Rao Kamalakara","Julia Kedrzycki","Gokce Keskin","Edward Kim","Joon Kim","Wei-Yin Ko","Tom Kocmi","Michael Kozakov","Wojciech Kryściński","Arnav Kumar Jain","Komal Kumar Teru","Sander Land","Michael Lasby","Olivia Lasche","Justin Lee","Patrick Lewis","Jeffrey Li","Jonathan Li","Hangyu Lin","Acyr Locatelli","Kevin Luong","Raymond Ma","Lukáš Mach","Marina Machado","Joanne Magbitang","Brenda Malacara Lopez","Aryan Mann","Kelly Marchisio","Olivia Markham","Alexandre Matton","Alex McKinney","Dominic McLoughlin","Jozef Mokry","Adrien Morisot","Autumn Moulder","Harry Moynehan","Maximilian Mozes","Vivek Muppalla","Lidiya Murakhovska","Hemangani Nagarajan","Alekhya Nandula","Hisham Nasir","Shauna Nehra","Josh Netto-Rosen","Daniel Ohashi","James Owers-Bardsley","Jason Ozuzu","Dennis Padilla","Gloria Park","Sam Passaglia","Jeremy Pekmez","Laura Penstone","Aleksandra Piktus","Case Ploeg","Andrew Poulton","Youran Qi","Shubha Raghvendra","Miguel Ramos","Ekagra Ranjan","Pierre Richemond","Cécile Robert-Michon","Aurélien Rodriguez","Sudip Roy","Sebastian Ruder","Laura Ruis","Louise Rust","Anubhav Sachan","Alejandro Salamanca","Kailash Karthik Saravanakumar","Isha Satyakam","Alice Schoenauer Sebag","Priyanka Sen","Sholeh Sepehri","Preethi Seshadri","Ye Shen","Tom Sherborne","Sylvie Shang Shi","Sanal Shivaprasad","Vladyslav Shmyhlo","Anirudh Shrinivason","Inna Shteinbuk","Amir Shukayev","Mathieu Simard","Ella Snyder","Ava Spataru","Victoria Spooner","Trisha Starostina","Florian Strub","Yixuan Su","Jimin Sun","Dwarak Talupuru","Eugene Tarassov","Elena Tommasone","Jennifer Tracey","Billy Trend","Evren Tumer","Ahmet Üstün","Bharat Venkitesh","David Venuto","Pat Verga","Maxime Voisin","Alex Wang","Donglu Wang","Shijian Wang","Edmond Wen","Naomi White","Jesse Willman","Marysia Winkels","Chen Xia","Jessica Xie","Minjie Xu","Bowen Yang","Tan Yi-Chern","Ivan Zhang","Zhenyu Zhao","Zhoujie Zhao"],"abstract":"In this report we describe the development of Command A, a powerful large language model purpose-built to excel at real-world enterprise use cases. Command A is an agent-optimised and multilingual-capable model, with support for 23 languages of global business, and a novel hybrid architecture balancing efficiency with top of the range performance. It offers best-in-class Retrieval Augmented Generation (RAG) capabilities with grounding and tool use to automate sophisticated business processes. These abilities are achieved through a decentralised training approach, including self-refinement algorithms and model merging techniques. We also include results for Command R7B which shares capability and architectural similarities to Command A. Weights for both models have been released for research purposes. This technical report details our original training pipeline and presents an extensive evaluation of our models across a suite of enterprise-relevant tasks and public benchmarks, demonstrating excellent performance and efficiency.","published":"2025-04-01T12:08:07Z","updated":"2025-04-14T12:37:51Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2504.00698v2","pdf_url":"https://arxiv.org/pdf/2504.00698v2","comment":"55 pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=GaHiSvFsQz"},{"id":"2503.23145","versioned_id":"2503.23145v2","title":"CodeARC: Benchmarking Reasoning Capabilities of LLM Agents for Inductive Program Synthesis","authors":["Anjiang Wei","Tarun Suresh","Jiannan Cao","Naveen Kannan","Yuheng Wu","Kai Yan","Thiago S. F. X. Teixeira","Ke Wang","Alex Aiken"],"abstract":"Inductive program synthesis, or programming by example, requires synthesizing functions from input-output examples that generalize to unseen inputs. While large language model agents have shown promise in programming tasks guided by natural language, their ability to perform inductive program synthesis is underexplored. Existing evaluation protocols rely on static sets of examples and held-out tests, offering no feedback when synthesized functions are incorrect and failing to reflect real-world scenarios such as reverse engineering. We propose CodeARC, the Code Abstraction and Reasoning Challenge, a new evaluation framework where agents interact with a hidden target function by querying it with new inputs, synthesizing candidate functions, and iteratively refining their solutions using a differential testing oracle. This interactive setting encourages agents to perform function calls and self-correction based on feedback. We construct the first large-scale benchmark for general-purpose inductive program synthesis, featuring 1114 functions. Among 18 models evaluated, o3-mini performs best with a success rate of 52.7%, highlighting the difficulty of this task. Fine-tuning LLaMA-3.1-8B-Instruct on curated synthesis traces yields up to a 31% relative performance gain. CodeARC provides a more realistic and challenging testbed for evaluating LLM-based program synthesis and inductive reasoning. Our code, data, and models are publicly available at https://github.com/Anjiang-Wei/CodeARC","published":"2025-03-29T16:50:39Z","updated":"2025-08-08T07:13:11Z","categories":["cs.PL","cs.AI","cs.CL","cs.LG"],"primary_category":"cs.PL","arxiv_url":"https://arxiv.org/abs/2503.23145v2","pdf_url":"https://arxiv.org/pdf/2503.23145v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=Q5pVZCrrKr","openreview_venues":["DL4C @ NeurIPS 2025 Poster","COLM 2025"]},{"id":"2503.22678","versioned_id":"2503.22678v2","title":"Self-Evolving Multi-Agent Simulations for Realistic Clinical Interactions","authors":["Mohammad Almansoori","Komal Kumar","Hisham Cholakkal"],"abstract":"In this work, we introduce MedAgentSim, an open-source simulated clinical environment with doctor, patient, and measurement agents designed to evaluate and enhance LLM performance in dynamic diagnostic settings. Unlike prior approaches, our framework requires doctor agents to actively engage with patients through multi-turn conversations, requesting relevant medical examinations (e.g., temperature, blood pressure, ECG) and imaging results (e.g., MRI, X-ray) from a measurement agent to mimic the real-world diagnostic process. Additionally, we incorporate self improvement mechanisms that allow models to iteratively refine their diagnostic strategies. We enhance LLM performance in our simulated setting by integrating multi-agent discussions, chain-of-thought reasoning, and experience-based knowledge retrieval, facilitating progressive learning as doctor agents interact with more patients. We also introduce an evaluation benchmark for assessing the LLM's ability to engage in dynamic, context-aware diagnostic interactions. While MedAgentSim is fully automated, it also supports a user-controlled mode, enabling human interaction with either the doctor or patient agent. Comprehensive evaluations in various simulated diagnostic scenarios demonstrate the effectiveness of our approach. Our code, simulation tool, and benchmark are available at \\href{https://medagentsim.netlify.app/}.","published":"2025-03-28T17:59:53Z","updated":"2025-10-01T11:09:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.22678v2","pdf_url":"https://arxiv.org/pdf/2503.22678v2","comment":"14 page, 4 figures, 61 references, presented in MICCAI (Oral)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.22122","versioned_id":"2503.22122v1","title":"REMAC: Self-Reflective and Self-Evolving Multi-Agent Collaboration for Long-Horizon Robot Manipulation","authors":["Puzhen Yuan","Angyuan Ma","Yunchao Yao","Huaxiu Yao","Masayoshi Tomizuka","Mingyu Ding"],"abstract":"Vision-language models (VLMs) have demonstrated remarkable capabilities in robotic planning, particularly for long-horizon tasks that require a holistic understanding of the environment for task decomposition. Existing methods typically rely on prior environmental knowledge or carefully designed task-specific prompts, making them struggle with dynamic scene changes or unexpected task conditions, e.g., a robot attempting to put a carrot in the microwave but finds the door was closed. Such challenges underscore two critical issues: adaptability and efficiency. To address them, in this work, we propose an adaptive multi-agent planning framework, termed REMAC, that enables efficient, scene-agnostic multi-robot long-horizon task planning and execution through continuous reflection and self-evolution. REMAC incorporates two key modules: a self-reflection module performing pre-condition and post-condition checks in the loop to evaluate progress and refine plans, and a self-evolvement module dynamically adapting plans based on scene-specific reasoning. It offers several appealing benefits: 1) Robots can initially explore and reason about the environment without complex prompt design. 2) Robots can keep reflecting on potential planning errors and adapting the plan based on task-specific insights. 3) After iterations, a robot can call another one to coordinate tasks in parallel, maximizing the task execution efficiency. To validate REMAC's effectiveness, we build a multi-agent environment for long-horizon robot manipulation and navigation based on RoboCasa, featuring 4 task categories with 27 task styles and 50+ different objects. Based on it, we further benchmark state-of-the-art reasoning models, including DeepSeek-R1, o3-mini, QwQ, and Grok3, demonstrating REMAC's superiority by boosting average success rates by 40% and execution efficiency by 52.7% over the single robot baseline.","published":"2025-03-28T03:51:40Z","updated":"2025-03-28T03:51:40Z","categories":["cs.RO","cs.AI","cs.CL","cs.CV"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.22122v1","pdf_url":"https://arxiv.org/pdf/2503.22122v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.21949","versioned_id":"2503.21949v1","title":"Reward Design for Reinforcement Learning Agents","authors":["Rati Devidze"],"abstract":"Reward functions are central in reinforcement learning (RL), guiding agents towards optimal decision-making. The complexity of RL tasks requires meticulously designed reward functions that effectively drive learning while avoiding unintended consequences. Effective reward design aims to provide signals that accelerate the agent's convergence to optimal behavior. Crafting rewards that align with task objectives, foster desired behaviors, and prevent undesirable actions is inherently challenging. This thesis delves into the critical role of reward signals in RL, highlighting their impact on the agent's behavior and learning dynamics and addressing challenges such as delayed, ambiguous, or intricate rewards. In this thesis work, we tackle different aspects of reward shaping. First, we address the problem of designing informative and interpretable reward signals from a teacher's/expert's perspective (teacher-driven). Here, the expert, equipped with the optimal policy and the corresponding value function, designs reward signals that expedite the agent's convergence to optimal behavior. Second, we build on this teacher-driven approach by introducing a novel method for adaptive interpretable reward design. In this scenario, the expert tailors the rewards based on the learner's current policy, ensuring alignment and optimal progression. Third, we propose a meta-learning approach, enabling the agent to self-design its reward signals online without expert input (agent-driven). This self-driven method considers the agent's learning and exploration to establish a self-improving feedback loop.","published":"2025-03-27T19:48:02Z","updated":"2025-03-27T19:48:02Z","categories":["cs.LG"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2503.21949v1","pdf_url":"https://arxiv.org/pdf/2503.21949v1","comment":"Doctoral thesis","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.20950","versioned_id":"2503.20950v1","title":"DEMENTIA-PLAN: An Agent-Based Framework for Multi-Knowledge Graph Retrieval-Augmented Generation in Dementia Care","authors":["Yutong Song","Chenhan Lyu","Pengfei Zhang","Sabine Brunswicker","Nikil Dutt","Amir Rahmani"],"abstract":"Mild-stage dementia patients primarily experience two critical symptoms: severe memory loss and emotional instability. To address these challenges, we propose DEMENTIA-PLAN, an innovative retrieval-augmented generation framework that leverages large language models to enhance conversational support. Our model employs a multiple knowledge graph architecture, integrating various dimensional knowledge representations including daily routine graphs and life memory graphs. Through this multi-graph architecture, DEMENTIA-PLAN comprehensively addresses both immediate care needs and facilitates deeper emotional resonance through personal memories, helping stabilize patient mood while providing reliable memory support. Our notable innovation is the self-reflection planning agent, which systematically coordinates knowledge retrieval and semantic integration across multiple knowledge graphs, while scoring retrieved content from daily routine and life memory graphs to dynamically adjust their retrieval weights for optimized response generation. DEMENTIA-PLAN represents a significant advancement in the clinical application of large language models for dementia care, bridging the gap between AI tools and caregivers interventions.","published":"2025-03-26T19:34:04Z","updated":"2025-03-26T19:34:04Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.20950v1","pdf_url":"https://arxiv.org/pdf/2503.20950v1","comment":"Accepted by AAAI 2025 Workshop on Knowledge Graphs for Personalized Public Health","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.20279","versioned_id":"2503.20279v3","title":"sudo rm -rf agentic_security","authors":["Sejin Lee","Jian Kim","Haon Park","Ashkan Yousefpour","Sangyoon Yu","Min Song"],"abstract":"Large Language Models (LLMs) are increasingly deployed as computer-use agents, autonomously performing tasks within real desktop or web environments. While this evolution greatly expands practical use cases for humans, it also creates serious security exposures. We present SUDO (Screen-based Universal Detox2Tox Offense), a novel attack framework that systematically bypasses refusal-trained safeguards in commercial computer-use agents, such as Claude for Computer Use. The core mechanism, Detox2Tox, transforms harmful requests (that agents initially reject) into seemingly benign requests via detoxification, secures detailed instructions from advanced vision language models (VLMs), and then reintroduces malicious content via toxification just before execution. Unlike conventional jailbreaks, SUDO iteratively refines its attacks based on a built-in refusal feedback, making it increasingly effective against robust policy filters. In extensive tests spanning 50 real-world tasks and multiple state-of-the-art VLMs, SUDO achieves a stark attack success rate of 24.41% (with no refinement), and up to 41.33% (by its iterative refinement) in Claude for Computer Use. By revealing these vulnerabilities and demonstrating the ease with which they can be exploited in real-world computing environments, this paper highlights an immediate need for robust, context-aware safeguards. WARNING: This paper includes harmful or offensive model outputs","published":"2025-03-26T07:08:15Z","updated":"2025-06-08T05:39:56Z","categories":["cs.CL","cs.AI","cs.CR"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.20279v3","pdf_url":"https://arxiv.org/pdf/2503.20279v3","comment":"Accepted ACL 2025 Industry track","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.19271","versioned_id":"2503.19271v2","title":"MARS: Memory-Enhanced Agents with Reflective Self-improvement","authors":["Xuechen Liang","Meiling Tao","Yinghui Xia","Jianhui Wang","Kun Li","Yijin Wang","Jingsong Yang","Tianyu Shi","Yuantao Wang","Miao Zhang","Xueqian Wang"],"abstract":"Large language models (LLMs) have made significant advances in the field of natural language processing, but they still face challenges such as continuous decision-making, lack of long-term memory, and limited context windows in dynamic environments. To address these issues, this paper proposes an innovative framework Memory-Enhanced Agents with Reflective Self-improvement. The MARS framework comprises three agents: the User, the Assistant, and the Checker. By integrating iterative feedback, reflective mechanisms, and a memory optimization mechanism based on the Ebbinghaus forgetting curve, it significantly enhances the agents capabilities in handling multi-tasking and long-span information.","published":"2025-03-25T02:05:46Z","updated":"2025-04-09T07:51:49Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.19271v2","pdf_url":"https://arxiv.org/pdf/2503.19271v2","comment":"We are withdrawing this version because it duplicates our previous submission (arXiv:2409.00872)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.17726","versioned_id":"2503.17726v1","title":"A Survey on Mathematical Reasoning and Optimization with Large Language Models","authors":["Ali Forootani"],"abstract":"Mathematical reasoning and optimization are fundamental to artificial intelligence and computational problem-solving. Recent advancements in Large Language Models (LLMs) have significantly improved AI-driven mathematical reasoning, theorem proving, and optimization techniques. This survey explores the evolution of mathematical problem-solving in AI, from early statistical learning approaches to modern deep learning and transformer-based methodologies. We review the capabilities of pretrained language models and LLMs in performing arithmetic operations, complex reasoning, theorem proving, and structured symbolic computation. A key focus is on how LLMs integrate with optimization and control frameworks, including mixed-integer programming, linear quadratic control, and multi-agent optimization strategies. We examine how LLMs assist in problem formulation, constraint generation, and heuristic search, bridging theoretical reasoning with practical applications. We also discuss enhancement techniques such as Chain-of-Thought reasoning, instruction tuning, and tool-augmented methods that improve LLM's problem-solving performance. Despite their progress, LLMs face challenges in numerical precision, logical consistency, and proof verification. Emerging trends such as hybrid neural-symbolic reasoning, structured prompt engineering, and multi-step self-correction aim to overcome these limitations. Future research should focus on interpretability, integration with domain-specific solvers, and improving the robustness of AI-driven decision-making. This survey offers a comprehensive review of the current landscape and future directions of mathematical reasoning and optimization with LLMs, with applications across engineering, finance, and scientific research.","published":"2025-03-22T10:49:32Z","updated":"2025-03-22T10:49:32Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.17726v1","pdf_url":"https://arxiv.org/pdf/2503.17726v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.16905","versioned_id":"2503.16905v2","title":"MAPS: Multi-Agent Personality Shaping for Collaborative Reasoning","authors":["Jian Zhang","Zhiyuan Wang","Zhangqi Wang","Fangzhi Xu","Qika Lin","Lingling Zhang","Rui Mao","Erik Cambria","Jun Liu"],"abstract":"Collaborative reasoning with multiple agents offers the potential for more robust and diverse problem-solving. However, existing approaches often suffer from homogeneous agent behaviors and lack of reflective and rethinking capabilities. We propose Multi-Agent Personality Shaping (MAPS), a novel framework that enhances reasoning through agent diversity and internal critique. Inspired by the Big Five personality theory, MAPS assigns distinct personality traits to individual agents, shaping their reasoning styles and promoting heterogeneous collaboration. To enable deeper and more adaptive reasoning, MAPS introduces a Critic agent that reflects on intermediate outputs, revisits flawed steps, and guides iterative refinement. This integration of personality-driven agent design and structured collaboration improves both reasoning depth and flexibility. Empirical evaluations across three benchmarks demonstrate the strong performance of MAPS, with further analysis confirming its generalizability across different large language models and validating the benefits of multi-agent collaboration.","published":"2025-03-21T07:13:45Z","updated":"2025-11-12T06:46:52Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2503.16905v2","pdf_url":"https://arxiv.org/pdf/2503.16905v2","comment":"AAAI 2026","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.16514","versioned_id":"2503.16514v3","title":"VeriMind: Agentic LLM for Automated Verilog Generation with a Novel Evaluation Metric","authors":["Bardia Nadimi","Ghali Omar Boutaib","Hao Zheng"],"abstract":"Designing Verilog modules requires meticulous attention to correctness, efficiency, and adherence to design specifications. However, manually writing Verilog code remains a complex and time-consuming task that demands both expert knowledge and iterative refinement. Leveraging recent advancements in large language models (LLMs) and their structured text generation capabilities, we propose VeriMind, an agentic LLM framework for Verilog code generation that significantly automates and optimizes the synthesis process. Unlike traditional LLM-based code generators, VeriMind employs a structured reasoning approach: given a user-provided prompt describing design requirements, the system first formulates a detailed train of thought before the final Verilog code is generated. This multi-step methodology enhances interpretability, accuracy, and adaptability in hardware design. In addition, we introduce a novel evaluation metric-pass@ARC-which combines the conventional pass@k measure with Average Refinement Cycles (ARC) to capture both success rate and the efficiency of iterative refinement. Experimental results on diverse hardware design tasks demonstrated that our approach achieved up to $8.3\\%$ improvement on pass@k metric and $8.1\\%$ on pass@ARC metric. These findings underscore the transformative potential of agentic LLMs in automated hardware design, RTL development, and digital system synthesis.","published":"2025-03-15T23:43:06Z","updated":"2025-04-16T14:58:48Z","categories":["cs.AR","cs.AI","cs.LG","cs.PL"],"primary_category":"cs.AR","arxiv_url":"https://arxiv.org/abs/2503.16514v3","pdf_url":"https://arxiv.org/pdf/2503.16514v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.12077","versioned_id":"2503.12077v1","title":"V-Stylist: Video Stylization via Collaboration and Reflection of MLLM Agents","authors":["Zhengrong Yue","Shaobin Zhuang","Kunchang Li","Yanbo Ding","Yali Wang"],"abstract":"Despite the recent advancement in video stylization, most existing methods struggle to render any video with complex transitions, based on an open style description of user query. To fill this gap, we introduce a generic multi-agent system for video stylization, V-Stylist, by a novel collaboration and reflection paradigm of multi-modal large language models. Specifically, our V-Stylist is a systematical workflow with three key roles: (1) Video Parser decomposes the input video into a number of shots and generates their text prompts of key shot content. Via a concise video-to-shot prompting paradigm, it allows our V-Stylist to effectively handle videos with complex transitions. (2) Style Parser identifies the style in the user query and progressively search the matched style model from a style tree. Via a robust tree-of-thought searching paradigm, it allows our V-Stylist to precisely specify vague style preference in the open user query. (3) Style Artist leverages the matched model to render all the video shots into the required style. Via a novel multi-round self-reflection paradigm, it allows our V-Stylist to adaptively adjust detail control, according to the style requirement. With such a distinct design of mimicking human professionals, our V-Stylist achieves a major breakthrough over the primary challenges for effective and automatic video stylization. Moreover,we further construct a new benchmark Text-driven Video Stylization Benchmark (TVSBench), which fills the gap to assess stylization of complex videos on open user queries. Extensive experiments show that, V-Stylist achieves the state-of-the-art, e.g.,V-Stylist surpasses FRESCO and ControlVideo by 6.05% and 4.51% respectively in overall average metrics, marking a significant advance in video stylization.","published":"2025-03-15T10:37:31Z","updated":"2025-03-15T10:37:31Z","categories":["cs.CV","cs.AI"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.12077v1","pdf_url":"https://arxiv.org/pdf/2503.12077v1","comment":"CVPR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.10351","versioned_id":"2503.10351v2","title":"New Trends for Modern Machine Translation with Large Reasoning Models","authors":["Sinuo Liu","Chenyang Lyu","Minghao Wu","Longyue Wang","Weihua Luo","Kaifu Zhang","Zifu Shang"],"abstract":"Recent advances in Large Reasoning Models (LRMs), particularly those leveraging Chain-of-Thought reasoning (CoT), have opened brand new possibility for Machine Translation (MT). This position paper argues that LRMs substantially transformed traditional neural MT as well as LLMs-based MT paradigms by reframing translation as a dynamic reasoning task that requires contextual, cultural, and linguistic understanding and reasoning. We identify three foundational shifts: 1) contextual coherence, where LRMs resolve ambiguities and preserve discourse structure through explicit reasoning over cross-sentence and complex context or even lack of context; 2) cultural intentionality, enabling models to adapt outputs by inferring speaker intent, audience expectations, and socio-linguistic norms; 3) self-reflection, LRMs can perform self-reflection during the inference time to correct the potential errors in translation especially extremely noisy cases, showing better robustness compared to simply mapping X->Y translation. We explore various scenarios in translation including stylized translation, document-level translation and multimodal translation by showcasing empirical examples that demonstrate the superiority of LRMs in translation. We also identify several interesting phenomenons for LRMs for MT including auto-pivot translation as well as the critical challenges such as over-localisation in translation and inference efficiency. In conclusion, we think that LRMs redefine translation systems not merely as text converters but as multilingual cognitive agents capable of reasoning about meaning beyond the text. This paradigm shift reminds us to think of problems in translation beyond traditional translation scenarios in a much broader context with LRMs - what we can achieve on top of it.","published":"2025-03-13T13:27:53Z","updated":"2025-03-14T12:09:34Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.10351v2","pdf_url":"https://arxiv.org/pdf/2503.10351v2","comment":"arXiv admin note: text overlap with arXiv:1701.04715 by other authors","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.09263","versioned_id":"2503.09263v1","title":"COLA: A Scalable Multi-Agent Framework For Windows UI Task Automation","authors":["Di Zhao","Longhui Ma","Siwei Wang","Miao Wang","Zhao Lv"],"abstract":"With the rapid advancements in Large Language Models (LLMs), an increasing number of studies have leveraged LLMs as the cognitive core of agents to address complex task decision-making challenges. Specially, recent research has demonstrated the potential of LLM-based agents on automating Windows GUI operations. However, existing methodologies exhibit two critical challenges: (1) static agent architectures fail to dynamically adapt to the heterogeneous requirements of OS-level tasks, leading to inadequate scenario generalization;(2) the agent workflows lack fault tolerance mechanism, necessitating complete process re-execution for UI agent decision error. To address these limitations, we introduce \\textit{COLA}, a collaborative multi-agent framework for automating Windows UI operations. In this framework, a scenario-aware agent Task Scheduler decomposes task requirements into atomic capability units, dynamically selects the optimal agent from a decision agent pool, effectively responds to the capability requirements of diverse scenarios. The decision agent pool supports plug-and-play expansion for enhanced flexibility. In addition, we design a memory unit equipped to all agents for their self-evolution. Furthermore, we develop an interactive backtracking mechanism that enables human to intervene to trigger state rollbacks for non-destructive process repair. Our experimental results on the GAIA benchmark demonstrates that the \\textit{COLA} framework achieves state-of-the-art performance with an average score of 31.89\\%, significantly outperforming baseline approaches without web API integration. Ablation studies further validate the individual contributions of our dynamic scheduling. The code is available at https://github.com/Alokia/COLA-demo.","published":"2025-03-12T11:03:27Z","updated":"2025-03-12T11:03:27Z","categories":["cs.MA"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2503.09263v1","pdf_url":"https://arxiv.org/pdf/2503.09263v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.06791","versioned_id":"2503.06791v2","title":"AutoMisty: A Multi-Agent LLM Framework for Automated Code Generation in the Misty Social Robot","authors":["Xiao Wang","Lu Dong","Sahana Rangasrinivasan","Ifeoma Nwogu","Srirangaraj Setlur","Venugopal Govindaraju"],"abstract":"The social robot's open API allows users to customize open-domain interactions. However, it remains inaccessible to those without programming experience. In this work, we introduce AutoMisty, the first multi-agent collaboration framework powered by large language models (LLMs), to enable the seamless generation of executable Misty robot code from natural language instructions. AutoMisty incorporates four specialized agent modules to manage task decomposition, assignment, problem-solving, and result synthesis. Each agent incorporates a two-layer optimization mechanism, with self-reflection for iterative refinement and human-in-the-loop for better alignment with user preferences. AutoMisty ensures a transparent reasoning process, allowing users to iteratively refine tasks through natural language feedback for precise execution. To evaluate AutoMisty's effectiveness, we designed a benchmark task set spanning four levels of complexity and conducted experiments in a real Misty robot environment. Extensive evaluations demonstrate that AutoMisty not only consistently generates high-quality code but also enables precise code control, significantly outperforming direct reasoning with ChatGPT-4o and ChatGPT-o1. All code, optimized APIs, and experimental videos will be publicly released through the webpage: https://wangxiaoshawn.github.io/AutoMisty.html","published":"2025-03-09T22:07:46Z","updated":"2025-08-24T05:44:07Z","categories":["cs.RO","cs.AI","cs.HC","cs.MA"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.06791v2","pdf_url":"https://arxiv.org/pdf/2503.06791v2","comment":"Accepted by IROS 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.05473","versioned_id":"2503.05473v2","title":"The Society of HiveMind: Multi-Agent Optimization of Foundation Model Swarms to Unlock the Potential of Collective Intelligence","authors":["Noah Mamie","Susie Xi Rao"],"abstract":"Multi-agent systems address issues of accessibility and scalability of artificial intelligence (AI) foundation models, which are often represented by large language models. We develop a framework - the \"Society of HiveMind\" (SOHM) - that orchestrates the interaction between multiple AI foundation models, imitating the observed behavior of animal swarms in nature by following modern evolutionary theories. On the one hand, we find that the SOHM provides a negligible benefit on tasks that mainly require real-world knowledge. On the other hand, we remark a significant improvement on tasks that require intensive logical reasoning, indicating that multi-agent systems are capable of increasing the reasoning capabilities of the collective compared to the individual agents. Our findings demonstrate the potential of combining a multitude of diverse AI foundation models to form an artificial swarm intelligence capable of self-improvement through interactions with a given environment.","published":"2025-03-07T14:45:03Z","updated":"2025-03-13T14:20:53Z","categories":["cs.NE","cs.AI"],"primary_category":"cs.NE","arxiv_url":"https://arxiv.org/abs/2503.05473v2","pdf_url":"https://arxiv.org/pdf/2503.05473v2","comment":"11 pages (excl. appendix)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=PriitxZTEv"},{"id":"2503.01490","versioned_id":"2503.01490v1","title":"Improving Retrospective Language Agents via Joint Policy Gradient Optimization","authors":["Xueyang Feng","Bo Lan","Quanyu Dai","Lei Wang","Jiakai Tang","Xu Chen","Zhenhua Dong","Ji-Rong Wen"],"abstract":"In recent research advancements within the community, large language models (LLMs) have sparked great interest in creating autonomous agents. However, current prompt-based agents often heavily rely on large-scale LLMs. Meanwhile, although fine-tuning methods significantly enhance the capabilities of smaller LLMs, the fine-tuned agents often lack the potential for self-reflection and self-improvement. To address these challenges, we introduce a novel agent framework named RetroAct, which is a framework that jointly optimizes both task-planning and self-reflective evolution capabilities in language agents. Specifically, we develop a two-stage joint optimization process that integrates imitation learning and reinforcement learning, and design an off-policy joint policy gradient optimization algorithm with imitation learning regularization to enhance the data efficiency and training stability in agent tasks. RetroAct significantly improves the performance of open-source models, reduces dependency on closed-source LLMs, and enables fine-tuned agents to learn and evolve continuously. We conduct extensive experiments across various testing environments, demonstrating RetroAct has substantial improvements in task performance and decision-making processes.","published":"2025-03-03T12:54:54Z","updated":"2025-03-03T12:54:54Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2503.01490v1","pdf_url":"https://arxiv.org/pdf/2503.01490v1","comment":"NAACL2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.00761","versioned_id":"2503.00761v1","title":"TRACE: A Self-Improving Framework for Robot Behavior Forecasting with Vision-Language Models","authors":["Gokul Puthumanaillam","Paulo Padrao","Jose Fuentes","Pranay Thangeda","William E. Schafer","Jae Hyuk Song","Karan Jagdale","Leonardo Bobadilla","Melkior Ornik"],"abstract":"Predicting the near-term behavior of a reactive agent is crucial in many robotic scenarios, yet remains challenging when observations of that agent are sparse or intermittent. Vision-Language Models (VLMs) offer a promising avenue by integrating textual domain knowledge with visual cues, but their one-shot predictions often miss important edge cases and unusual maneuvers. Our key insight is that iterative, counterfactual exploration--where a dedicated module probes each proposed behavior hypothesis, explicitly represented as a plausible trajectory, for overlooked possibilities--can significantly enhance VLM-based behavioral forecasting. We present TRACE (Tree-of-thought Reasoning And Counterfactual Exploration), an inference framework that couples tree-of-thought generation with domain-aware feedback to refine behavior hypotheses over multiple rounds. Concretely, a VLM first proposes candidate trajectories for the agent; a counterfactual critic then suggests edge-case variations consistent with partial observations, prompting the VLM to expand or adjust its hypotheses in the next iteration. This creates a self-improving cycle where the VLM progressively internalizes edge cases from previous rounds, systematically uncovering not only typical behaviors but also rare or borderline maneuvers, ultimately yielding more robust trajectory predictions from minimal sensor data. We validate TRACE on both ground-vehicle simulations and real-world marine autonomous surface vehicles. Experimental results show that our method consistently outperforms standard VLM-driven and purely model-based baselines, capturing a broader range of feasible agent behaviors despite sparse sensing. Evaluation videos and code are available at trace-robotics.github.io.","published":"2025-03-02T06:58:02Z","updated":"2025-03-02T06:58:02Z","categories":["cs.RO","cs.CV","cs.MA","eess.SY"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2503.00761v1","pdf_url":"https://arxiv.org/pdf/2503.00761v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2503.00162","versioned_id":"2503.00162v1","title":"PreMind: Multi-Agent Video Understanding for Advanced Indexing of Presentation-style Videos","authors":["Kangda Wei","Zhengyu Zhou","Bingqing Wang","Jun Araki","Lukas Lange","Ruihong Huang","Zhe Feng"],"abstract":"In recent years, online lecture videos have become an increasingly popular resource for acquiring new knowledge. Systems capable of effectively understanding/indexing lecture videos are thus highly desirable, enabling downstream tasks like question answering to help users efficiently locate specific information within videos. This work proposes PreMind, a novel multi-agent multimodal framework that leverages various large models for advanced understanding/indexing of presentation-style videos. PreMind first segments videos into slide-presentation segments using a Vision-Language Model (VLM) to enhance modern shot-detection techniques. Each segment is then analyzed to generate multimodal indexes through three key steps: (1) extracting slide visual content, (2) transcribing speech narratives, and (3) consolidating these visual and speech contents into an integrated understanding. Three innovative mechanisms are also proposed to improve performance: leveraging prior lecture knowledge to refine visual understanding, detecting/correcting speech transcription errors using a VLM, and utilizing a critic agent for dynamic iterative self-reflection in vision analysis. Compared to traditional video indexing methods, PreMind captures rich, reliable multimodal information, allowing users to search for details like abbreviations shown only on slides. Systematic evaluations on the public LPM dataset and an internal enterprise dataset are conducted to validate PreMind's effectiveness, supported by detailed analyses.","published":"2025-02-28T20:17:48Z","updated":"2025-02-28T20:17:48Z","categories":["cs.CV","cs.AI","cs.CL","cs.MA"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2503.00162v1","pdf_url":"https://arxiv.org/pdf/2503.00162v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:3RgKp0JBh0","versioned_id":"3RgKp0JBh0","title":"AlphaVerus: Bootstrapping Formally Verified Code Generation through Self-Improving Translation and Treefinement","authors":["Pranjal Aggarwal","Bryan Parno","Sean Welleck"],"abstract":"Automated code generation with large language models has gained significant traction, but there remains no guarantee of the correctness of generated code. We aim to use formal verification to provide mathematical guarantees that the generated code is correct. However, generating formally verified code with LLMs is hindered by the scarcity of training data and the complexity of formal proofs. To tackle this challenge, we introduce AlphaVerus, a self-improving framework that bootstraps formally verified code generation by iteratively translating programs from a higher-resource language and leveraging feedback from a verifier. AlphaVerus operates in three phases: exploration of candidate translations, Treefinement -- a novel tree search algorithm for program refinement using verifier feedback, and filtering misaligned specifications and programs to prevent reward hacking. Through this iterative process, AlphaVerus enables LLaMA-3.1-70B model to generate verified code without human intervention or model finetuning. AlphaVerus shows an ability to generate formally verified solutions for HumanEval and MBPP, laying the groundwork for truly trustworthy code-generation agents.","published":"2025-02-28T19:45:50+00:00","updated":"2025-04-18T04:13:25+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=3RgKp0JBh0","openreview_url":"https://openreview.net/forum?id=tU8QKX4dMI","pdf_url":"https://openreview.net/pdf?id=3RgKp0JBh0","comment":"LTI-SRS 2025 Oral","journal_ref":"LTI-SRS 2025 Oral","doi":"","venue":"LTI-SRS 2025 Oral","venue_id":"cmu.edu/CMU/2025/LTI-SRS","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["LTI-SRS 2025 Oral","SSI-FM Poster","ICLR 2025 Workshop VerifAI Oral","ICML 2025 poster"],"relevance_score":55,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2502.20379","versioned_id":"2502.20379v1","title":"Multi-Agent Verification: Scaling Test-Time Compute with Multiple Verifiers","authors":["Shalev Lifshitz","Sheila A. McIlraith","Yilun Du"],"abstract":"By utilizing more computational resources at test-time, large language models (LLMs) can improve without additional training. One common strategy uses verifiers to evaluate candidate outputs. In this work, we propose a novel scaling dimension for test-time compute: scaling the number of verifiers. We introduce Multi-Agent Verification (MAV) as a test-time compute paradigm that combines multiple verifiers to improve performance. We propose using Aspect Verifiers (AVs), off-the-shelf LLMs prompted to verify different aspects of outputs, as one possible choice for the verifiers in a MAV system. AVs are a convenient building block for MAV since they can be easily combined without additional training. Moreover, we introduce BoN-MAV, a simple multi-agent verification algorithm that combines best-of-n sampling with multiple verifiers. BoN-MAV demonstrates stronger scaling patterns than self-consistency and reward model verification, and we demonstrate both weak-to-strong generalization, where combining weak verifiers improves even stronger LLMs, and self-improvement, where the same base model is used to both generate and verify outputs. Our results establish scaling the number of verifiers as a promising new dimension for improving language model performance at test-time.","published":"2025-02-27T18:53:30Z","updated":"2025-02-27T18:53:30Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.20379v1","pdf_url":"https://arxiv.org/pdf/2502.20379v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=LriQ3NY9uL","openreview_venues":["COLM 2025"]},{"id":"2502.19175","versioned_id":"2502.19175v2","title":"MEDDxAgent: A Unified Modular Agent Framework for Explainable Automatic Differential Diagnosis","authors":["Daniel Rose","Chia-Chien Hung","Marco Lepri","Israa Alqassem","Kiril Gashteovski","Carolin Lawrence"],"abstract":"Differential Diagnosis (DDx) is a fundamental yet complex aspect of clinical decision-making, in which physicians iteratively refine a ranked list of possible diseases based on symptoms, antecedents, and medical knowledge. While recent advances in large language models (LLMs) have shown promise in supporting DDx, existing approaches face key limitations, including single-dataset evaluations, isolated optimization of components, unrealistic assumptions about complete patient profiles, and single-attempt diagnosis. We introduce a Modular Explainable DDx Agent (MEDDxAgent) framework designed for interactive DDx, where diagnostic reasoning evolves through iterative learning, rather than assuming a complete patient profile is accessible. MEDDxAgent integrates three modular components: (1) an orchestrator (DDxDriver), (2) a history taking simulator, and (3) two specialized agents for knowledge retrieval and diagnosis strategy. To ensure robust evaluation, we introduce a comprehensive DDx benchmark covering respiratory, skin, and rare diseases. We analyze single-turn diagnostic approaches and demonstrate the importance of iterative refinement when patient profiles are not available at the outset. Our broad evaluation demonstrates that MEDDxAgent achieves over 10% accuracy improvements in interactive DDx across both large and small LLMs, while offering critical explainability into its diagnostic reasoning process.","published":"2025-02-26T14:31:43Z","updated":"2025-06-13T13:50:34Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.19175v2","pdf_url":"https://arxiv.org/pdf/2502.19175v2","comment":"ACL 2025 (main)","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.18873","versioned_id":"2502.18873v1","title":"Multi-LLM Collaborative Search for Complex Problem Solving","authors":["Sen Yang","Yafu Li","Wai Lam","Yu Cheng"],"abstract":"Large language models (LLMs) often struggle with complex reasoning tasks due to their limitations in addressing the vast reasoning space and inherent ambiguities of natural language. We propose the Mixture-of-Search-Agents (MoSA) paradigm, a novel approach leveraging the collective expertise of multiple LLMs to enhance search-based reasoning. MoSA integrates diverse reasoning pathways by combining independent exploration with iterative refinement among LLMs, mitigating the limitations of single-model approaches. Using Monte Carlo Tree Search (MCTS) as a backbone, MoSA enables multiple agents to propose and aggregate reasoning steps, resulting in improved accuracy. Our comprehensive evaluation across four reasoning benchmarks demonstrates MoSA's consistent performance improvements over single-agent and other multi-agent baselines, particularly in complex mathematical and commonsense reasoning tasks.","published":"2025-02-26T06:31:04Z","updated":"2025-02-26T06:31:04Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.18873v1","pdf_url":"https://arxiv.org/pdf/2502.18873v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=JMIcgDIANy","openreview_venues":["ACL ARR 2025 October Submission"]},{"id":"2502.18864","versioned_id":"2502.18864v2","title":"Accelerating scientific discovery with Co-Scientist","authors":["Juraj Gottweis","Wei-Hung Weng","Alexander Daryin","Tao Tu","Petar Sirkovic","Artiom Myaskovsky","Grzegorz Glowaty","Felix Weissenberger","Alessio Orlandi","Dan Popovici","Anil Palepu","Keran Rong","Ryutaro Tanno","Khaled Saab","Fan Zhang","Jacob Blum","Andrew Carroll","Kavita Kulkarni","Nenad Tomasev","Dina Zverinski","Ivor Rendulic","Elahe Vedadi","Florian Hasler","Luka Rimanic","Marina Boia","Ivan Budiselic","Ben Feinstein","Mathias Bellaiche","Tom Sheffer","Jan Freyberg","Jeremy Ratcliff","Ottavia Bertolli","Katherine Chou","Avinatan Hassidim","Burak Gokturk","Amin Vahdat","Yuan Guan","Vikram Dhillon","Eeshit Dhaval Vaishnav","Byron Lee","Tiago R D Costa","José R Penadés","Gary Peltz","Yossi Matias","James Manyika","Demis Hassabis","Yunhan Xu","Pushmeet Kohli","Annalisa Pawlosky","Alan Karthikesalingam","Vivek Natarajan"],"abstract":"Scientific discovery is driven by scientists generating novel hypotheses for complex problems that undergo rigorous experimental validation. To augment this process, we introduce Co-Scientist, a multi-agent AI system built on Gemini for structured scientific thinking and hypothesis generation. Co-Scientist aims to help scientists discover new original knowledge. Conditioned on their research objectives and prior scientific evidence, it formulates demonstrably novel research hypotheses for experimental verification. The system's design involves agents continuously generating, critiquing and refining hypotheses accelerated by scaling test-time compute. Key contributions include: (1) a multi-agent architecture with an asynchronous task execution framework for flexible compute scaling; (2) a tournament evolution process for self-improving hypotheses generation. Automated evaluations show continued benefits of test-time compute scaling, improving hypothesis quality over time. While general purpose, we focus the validation in three biomedical applications: drug repurposing, novel target discovery, and explaining mechanisms of anti-microbial resistance. Specifically, Co-Scientist helped identify new drug repurposing candidates and synergistic combination therapies for acute myeloid leukemia, which were validated through in vitro experiments. These real-world validations demonstrate the potential of Co-Scientist to accelerate scientific discovery and usher in an era of AI empowered scientists.","published":"2025-02-26T06:17:13Z","updated":"2026-06-29T16:12:47Z","categories":["cs.AI","cs.CL","cs.HC","cs.LG","physics.soc-ph","q-bio.OT"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.18864v2","pdf_url":"https://arxiv.org/pdf/2502.18864v2","comment":"157 pages in total (main 42 pages, supplementary information 115 pages), 4 main figures, 1 main table, 6 extended data figures, 2 extended data tables, 9 supplementary figures, 4 supplementary tables, 37 main references, 117 supplementary references. Nature (2026)","journal_ref":"","doi":"10.1038/s41586-026-10644-y","discovered_on":"2026-07-17","relevance_score":38,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.18702","versioned_id":"2502.18702v1","title":"A Cooperative Multi-Agent Framework for Zero-Shot Named Entity Recognition","authors":["Zihan Wang","Ziqi Zhao","Yougang Lyu","Zhumin Chen","Maarten de Rijke","Zhaochun Ren"],"abstract":"Zero-shot named entity recognition (NER) aims to develop entity recognition systems from unannotated text corpora. This task presents substantial challenges due to minimal human intervention. Recent work has adapted large language models (LLMs) for zero-shot NER by crafting specialized prompt templates. It advances model self-learning abilities by incorporating self-annotated demonstrations. However, two important challenges persist: (i) Correlations between contexts surrounding entities are overlooked, leading to wrong type predictions or entity omissions. (ii) The indiscriminate use of task demonstrations, retrieved through shallow similarity-based strategies, severely misleads LLMs during inference. In this paper, we introduce the cooperative multi-agent system (CMAS), a novel framework for zero-shot NER that uses the collective intelligence of multiple agents to address the challenges outlined above. CMAS has four main agents: (i) a self-annotator, (ii) a type-related feature (TRF) extractor, (iii) a demonstration discriminator, and (iv) an overall predictor. To explicitly capture correlations between contexts surrounding entities, CMAS reformulates NER into two subtasks: recognizing named entities and identifying entity type-related features within the target sentence. To enable controllable utilization of demonstrations, a demonstration discriminator is established to incorporate the self-reflection mechanism, automatically evaluating helpfulness scores for the target sentence. Experimental results show that CMAS significantly improves zero-shot NER performance across six benchmarks, including both domain-specific and general-domain scenarios. Furthermore, CMAS demonstrates its effectiveness in few-shot settings and with various LLM backbones.","published":"2025-02-25T23:30:43Z","updated":"2025-02-25T23:30:43Z","categories":["cs.IR","cs.CL"],"primary_category":"cs.IR","arxiv_url":"https://arxiv.org/abs/2502.18702v1","pdf_url":"https://arxiv.org/pdf/2502.18702v1","comment":"Accepted at WWW 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.18530","versioned_id":"2502.18530v3","title":"IMPROVE: Iterative Model Pipeline Refinement and Optimization Leveraging LLM Experts","authors":["Eric Xue","Ke Chen","Zeyi Huang","Yuyang Ji","Haohan Wang"],"abstract":"Large language model (LLM) agents have emerged as a promising solution to automate the workflow of machine learning, but most existing methods share a common limitation: they attempt to optimize entire pipelines in a single step before evaluation, making it difficult to attribute improvements to specific changes. This lack of granularity leads to unstable optimization and slower convergence, limiting their effectiveness. To address this, we introduce Iterative Refinement, a novel strategy for LLM-driven ML pipeline design inspired by how human ML experts iteratively refine models, focusing on one component at a time rather than making sweeping changes all at once. By systematically updating individual components based on real training feedback, Iterative Refinement improves overall model performance. We also provide some theoretical edvience of the superior properties of this Iterative Refinement. Further, we implement this strategy in IMPROVE, an end-to-end LLM agent framework for automating and optimizing object classification pipelines. Through extensive evaluations across datasets of varying sizes and domains, we demonstrate that Iterative Refinement enables IMPROVE to consistently achieve better performance over existing zero-shot LLM-based approaches.","published":"2025-02-25T01:52:37Z","updated":"2025-09-16T05:43:52Z","categories":["cs.CV","cs.LG"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.18530v3","pdf_url":"https://arxiv.org/pdf/2502.18530v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.17651","versioned_id":"2502.17651v4","title":"METAL: A Multi-Agent Framework for Chart Generation with Test-Time Scaling","authors":["Bingxuan Li","Yiwei Wang","Jiuxiang Gu","Kai-Wei Chang","Nanyun Peng"],"abstract":"Chart generation aims to generate code to produce charts satisfying the desired visual properties, e.g., texts, layout, color, and type. It has great potential to empower the automatic professional report generation in financial analysis, research presentation, education, and healthcare. In this work, we build a vision-language model (VLM) based multi-agent framework for effective automatic chart generation. Generating high-quality charts requires both strong visual design skills and precise coding capabilities that embed the desired visual properties into code. Such a complex multi-modal reasoning process is difficult for direct prompting of VLMs. To resolve these challenges, we propose METAL, a multi-agent framework that decomposes the task of chart generation into the iterative collaboration among specialized agents. METAL achieves 5.2% improvement over the current best result in the chart generation task. The METAL framework exhibits the phenomenon of test-time scaling: its performance increases monotonically as the logarithmic computational budget grows from 512 to 8192 tokens. In addition, we find that separating different modalities during the critique process of METAL boosts the self-correction capability of VLMs in the multimodal context.","published":"2025-02-24T21:01:39Z","updated":"2025-09-17T21:47:50Z","categories":["cs.CV","cs.AI","cs.CL"],"primary_category":"cs.CV","arxiv_url":"https://arxiv.org/abs/2502.17651v4","pdf_url":"https://arxiv.org/pdf/2502.17651v4","comment":"ACL2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.16796","versioned_id":"2502.16796v1","title":"MobileSteward: Integrating Multiple App-Oriented Agents with Self-Evolution to Automate Cross-App Instructions","authors":["Yuxuan Liu","Hongda Sun","Wei Liu","Jian Luan","Bo Du","Rui Yan"],"abstract":"Mobile phone agents can assist people in automating daily tasks on their phones, which have emerged as a pivotal research spotlight. However, existing procedure-oriented agents struggle with cross-app instructions, due to the following challenges: (1) complex task relationships, (2) diverse app environment, and (3) error propagation and information loss in multi-step execution. Drawing inspiration from object-oriented programming principles, we recognize that object-oriented solutions is more suitable for cross-app instruction. To address these challenges, we propose a self-evolving multi-agent framework named MobileSteward, which integrates multiple app-oriented StaffAgents coordinated by a centralized StewardAgent. We design three specialized modules in MobileSteward: (1) Dynamic Recruitment generates a scheduling graph guided by information flow to explicitly associate tasks among apps. (2) Assigned Execution assigns the task to app-oriented StaffAgents, each equipped with app-specialized expertise to address the diversity between apps. (3) Adjusted Evaluation conducts evaluation to provide reflection tips or deliver key information, which alleviates error propagation and information loss during multi-step execution. To continuously improve the performance of MobileSteward, we develop a Memory-based Self-evolution mechanism, which summarizes the experience from successful execution, to improve the performance of MobileSteward. We establish the first English Cross-APP Benchmark (CAPBench) in the real-world environment to evaluate the agents' capabilities of solving complex cross-app instructions. Experimental results demonstrate that MobileSteward achieves the best performance compared to both single-agent and multi-agent frameworks, highlighting the superiority of MobileSteward in better handling user instructions with diverse complexity.","published":"2025-02-24T03:12:45Z","updated":"2025-02-24T03:12:45Z","categories":["cs.MA","cs.AI","cs.CL","cs.HC"],"primary_category":"cs.MA","arxiv_url":"https://arxiv.org/abs/2502.16796v1","pdf_url":"https://arxiv.org/pdf/2502.16796v1","comment":"Accepted by KDD2025 Research Track","journal_ref":"","doi":"10.1145/3690624.3709171","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:QQZjZFTo4I","versioned_id":"QQZjZFTo4I","title":"CRADLE: Empowering Foundation Agents Towards General Computer Control","authors":["Börje F. Karlsson"],"abstract":"Despite the success in specific scenarios, existing foundation agents still struggle to generalize across various virtual scenarios, mainly due to the dramatically different encapsulations of environments with manually designed observation and action spaces. To handle this issue, we propose the General Computer Control (GCC) setting to restrict foundation agents to interact with software through the most unified and standardized interface, i.e., using screenshots as input and keyboard and mouse actions as output. We introduce CRADLE, a modular and flexible LMM-powered framework, as a preliminary attempt towards GCC. Enhanced by six key modules: Information Gathering, Self-Reflection, Task Inference, Skill Curation, Action Planning, and Memory, CRADLE is able to understand input screenshots and output executable code for low-level keyboard and mouse control after highlevel planning, so that CRADLE can interact with any software and complete long-horizon complex tasks without relying on any built-in APIs. Experimental results show that CRADLE exhibits remarkable generalizability and impressive performance across four previously unexplored commercial video games, five software applications, and a comprehensive benchmark, OSWorld. To our best knowledge, CRADLE is the first to enable foundation agents to follow the main storyline and complete one-hour-long real missions in the complex AAA game Red Dead Redemption 2 (RDR2). CRADLE can also not only operate daily software, like Chrome, Outlook, and Feishu, but also edit images and videos using Meitu and CapCut. With a unified interface to interact with any software, CRADLE greatly extends the reach of foundation agents by enabling the easy conversion of any software, especially complex games, into benchmarks to evaluate agents’ various abilities and facilitate further data collection, thus paving the way for generalist agents.","published":"2025-02-23T05:36:08+00:00","updated":"2025-02-23T05:36:08+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=QQZjZFTo4I","openreview_url":"https://openreview.net/forum?id=6CAgbrjHTc","pdf_url":"https://openreview.net/pdf?id=QQZjZFTo4I","comment":"NeurIPS 2024 Workshop Open-World Agents","journal_ref":"NeurIPS 2024 Workshop Open-World Agents","doi":"","venue":"NeurIPS 2024 Workshop Open-World Agents","venue_id":"OpenReview.net/Archive","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["NeurIPS 2024 Workshop Open-World Agents","ICML 2025 poster"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2502.13550","versioned_id":"2502.13550v1","title":"STaR-SQL: Self-Taught Reasoner for Text-to-SQL","authors":["Mingqian He","Yongliang Shen","Wenqi Zhang","Qiuying Peng","Jun Wang","Weiming Lu"],"abstract":"Generating step-by-step \"chain-of-thought\" rationales has proven effective for improving the performance of large language models on complex reasoning tasks. However, applying such techniques to structured tasks, such as text-to-SQL, remains largely unexplored. In this paper, we introduce Self-Taught Reasoner for text-to-SQL (STaR-SQL), a novel approach that reframes SQL query generation as a reasoning-driven process. Our method prompts the LLM to produce detailed reasoning steps for SQL queries and fine-tunes it on rationales that lead to correct outcomes. Unlike traditional methods, STaR-SQL dedicates additional test-time computation to reasoning, thereby positioning LLMs as spontaneous reasoners rather than mere prompt-based agents. To further scale the inference process, we incorporate an outcome-supervised reward model (ORM) as a verifier, which enhances SQL query accuracy. Experimental results on the challenging Spider benchmark demonstrate that STaR-SQL significantly improves text-to-SQL performance, achieving an execution accuracy of 86.6%. This surpasses a few-shot baseline by 31.6% and a baseline fine-tuned to predict answers directly by 18.0%. Additionally, STaR-SQL outperforms agent-like prompting methods that leverage more powerful yet closed-source models such as GPT-4. These findings underscore the potential of reasoning-augmented training for structured tasks and open the door to extending self-improving reasoning models to text-to-SQL generation and beyond.","published":"2025-02-19T08:58:44Z","updated":"2025-02-19T08:58:44Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.13550v1","pdf_url":"https://arxiv.org/pdf/2502.13550v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=w2HDmcMWVs","openreview_venues":["ACL ARR 2025 February Submission"]},{"id":"2502.12926","versioned_id":"2502.12926v1","title":"Towards more Contextual Agents: An extractor-Generator Optimization Framework","authors":["Mourad Aouini","Jinan Loubani"],"abstract":"Large Language Model (LLM)-based agents have demonstrated remarkable success in solving complex tasks across a wide range of general-purpose applications. However, their performance often degrades in context-specific scenarios, such as specialized industries or research domains, where the absence of domain-relevant knowledge leads to imprecise or suboptimal outcomes. To address this challenge, our work introduces a systematic approach to enhance the contextual adaptability of LLM-based agents by optimizing their underlying prompts-critical components that govern agent behavior, roles, and interactions. Manually crafting optimized prompts for context-specific tasks is labor-intensive, error-prone, and lacks scalability. In this work, we introduce an Extractor-Generator framework designed to automate the optimization of contextual LLM-based agents. Our method operates through two key stages: (i) feature extraction from a dataset of gold-standard input-output examples, and (ii) prompt generation via a high-level optimization strategy that iteratively identifies underperforming cases and applies self-improvement techniques. This framework substantially improves prompt adaptability by enabling more precise generalization across diverse inputs, particularly in context-specific tasks where maintaining semantic consistency and minimizing error propagation are critical for reliable performance. Although developed with single-stage workflows in mind, the approach naturally extends to multi-stage workflows, offering broad applicability across various agent-based systems. Empirical evaluations demonstrate that our framework significantly enhances the performance of prompt-optimized agents, providing a structured and efficient approach to contextual LLM-based agents.","published":"2025-02-18T15:07:06Z","updated":"2025-02-18T15:07:06Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.12926v1","pdf_url":"https://arxiv.org/pdf/2502.12926v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.12257","versioned_id":"2502.12257v2","title":"InfoQuest: Evaluating Multi-Turn Dialogue Agents for Open-Ended Conversations with Hidden Context","authors":["Bryan L. M. de Oliveira","Luana G. B. Martins","Bruno Brandão","Luckeciano C. Melo"],"abstract":"Large language models excel at following explicit instructions, but they often struggle with ambiguous or incomplete user requests, defaulting to verbose, generic responses instead of seeking clarification. We introduce InfoQuest, a multi-turn chat benchmark designed to evaluate how dialogue agents handle hidden context in open-ended user requests. This benchmark presents intentionally ambiguous scenarios that require models to engage in information-seeking dialogue by asking clarifying questions before providing appropriate responses. Our evaluation of both open and closed models reveals that, while proprietary models generally perform better, all current assistants struggle to gather critical information effectively. They often require multiple turns to infer user intent and frequently default to generic responses without proper clarification. We provide a systematic methodology for generating diverse scenarios and evaluating models' information-seeking capabilities, which can be leveraged to automatically generate data for self-improvement. We also offer insights into the current limitations of language models in handling ambiguous requests through multi-turn interactions.","published":"2025-02-17T19:01:10Z","updated":"2025-04-25T23:50:57Z","categories":["cs.CL","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.12257v2","pdf_url":"https://arxiv.org/pdf/2502.12257v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=wJtsi15QQw","openreview_venues":["SSI-FM Poster"]},{"id":"2502.11799","versioned_id":"2502.11799v3","title":"Table-Critic: A Multi-Agent Framework for Collaborative Criticism and Refinement in Table Reasoning","authors":["Peiying Yu","Guoxin Chen","Jingjing Wang"],"abstract":"Despite the remarkable capabilities of large language models (LLMs) in various reasoning tasks, they still struggle with table reasoning tasks, particularly in maintaining consistency throughout multi-step reasoning processes. While existing approaches have explored various decomposition strategies, they often lack effective mechanisms to identify and correct errors in intermediate reasoning steps, leading to cascading error propagation. To address these issues, we propose Table-Critic, a novel multi-agent framework that facilitates collaborative criticism and iterative refinement of the reasoning process until convergence to correct solutions. Our framework consists of four specialized agents: a Judge for error identification, a Critic for comprehensive critiques, a Refiner for process improvement, and a Curator for pattern distillation. To effectively deal with diverse and unpredictable error types, we introduce a self-evolving template tree that systematically accumulates critique knowledge through experience-driven learning and guides future reflections. Extensive experiments have demonstrated that Table-Critic achieves substantial improvements over existing methods, achieving superior accuracy and error correction rates while maintaining computational efficiency and lower solution degradation rate.","published":"2025-02-17T13:42:12Z","updated":"2025-05-23T14:18:47Z","categories":["cs.AI","cs.CL"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.11799v3","pdf_url":"https://arxiv.org/pdf/2502.11799v3","comment":"ACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5696rfgLRh","openreview_venues":["ACL ARR 2025 February Submission"]},{"id":"2502.11736","versioned_id":"2502.11736v3","title":"ReviewEval: An Evaluation Framework for AI-Generated Reviews","authors":["Madhav Krishan Garg","Tejash Prasad","Tanmay Singhal","Chhavi Kirtani","Murari Mandal","Dhruv Kumar"],"abstract":"The escalating volume of academic research, coupled with a shortage of qualified reviewers, necessitates innovative approaches to peer review. In this work, we propose: 1. ReviewEval, a comprehensive evaluation framework for AI-generated reviews that measures alignment with human assessments, verifies factual accuracy, assesses analytical depth, identifies degree of constructiveness and adherence to reviewer guidelines; and 2. ReviewAgent, an LLM-based review generation agent featuring a novel alignment mechanism to tailor feedback to target conferences and journals, along with a self-refinement loop that iteratively optimizes its intermediate outputs and an external improvement loop using ReviewEval to improve upon the final reviews. ReviewAgent improves actionable insights by 6.78% and 47.62% over existing AI baselines and expert reviews respectively. Further, it boosts analytical depth by 3.97% and 12.73%, enhances adherence to guidelines by 10.11% and 47.26% respectively. This paper establishes essential metrics for AIbased peer review and substantially enhances the reliability and impact of AI-generated reviews in academic research.","published":"2025-02-17T12:22:11Z","updated":"2025-05-24T17:01:28Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.11736v3","pdf_url":"https://arxiv.org/pdf/2502.11736v3","comment":"Under review: 8 pages, 2 figures, 5 tables, 9 pages for appendix","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.11705","versioned_id":"2502.11705v2","title":"LLM Agents Making Agent Tools","authors":["Georg Wölflein","Dyke Ferber","Daniel Truhn","Ognjen Arandjelović","Jakob Nikolas Kather"],"abstract":"Tool use has turned large language models (LLMs) into powerful agents that can perform complex multi-step tasks by dynamically utilising external software components. However, these tools must be implemented in advance by human developers, hindering the applicability of LLM agents in domains demanding large numbers of highly specialised tools, like in life sciences and medicine. Motivated by the growing trend of scientific studies accompanied by public code repositories, we propose ToolMaker, an agentic framework that autonomously transforms papers with code into LLM-compatible tools. Given a GitHub URL and short task description, ToolMaker autonomously installs dependencies and generates code to perform the task, using a closed-loop self-correction mechanism for debugging. To evaluate our approach, we introduce a benchmark comprising 15 complex computational tasks spanning various domains with over 100 unit tests to assess correctness and robustness. Our method correctly implements 80% of the tasks, substantially outperforming current state-of-the-art software engineering agents. ToolMaker therefore is a step towards fully autonomous agent-based scientific workflows. Our code and benchmark are publicly available at https://github.com/KatherLab/ToolMaker.","published":"2025-02-17T11:44:11Z","updated":"2025-05-29T18:47:41Z","categories":["cs.CL","cs.AI","cs.LG","cs.MA"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.11705v2","pdf_url":"https://arxiv.org/pdf/2502.11705v2","comment":"Accepted at ACL 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:eboZXcjUe7","versioned_id":"eboZXcjUe7","title":"Data-Augmented Prompt Optimization for LLMs","authors":[],"abstract":"With the rapid advancement of Large Language Models (LLMs), their performance has become increasingly dependent on prompt quality, making prompt optimization a critical research area. However, existing techniques often face limitations due to the lack of diverse and challenging data necessary for fully testing and refining prompt effectiveness. To address this challenge, we propose a novel approach that integrates data augmentation into the prompt optimization process, leveraging the synergy between synthetic data generation and prompt optimization. Our framework centers on prompt optimization as the key driver of LLM performance, integrating data augmentation as a means to enhance this process. We introduce a multi-agent system consisting of an auto prompt optimization agent and a synthetic data generation agent, where the former serves as the core component, iteratively refining prompts through a closed-loop feedback mechanism. This dynamic interplay enables the LLM to engage in self-reflection and multi-step reasoning, structurally improving prompt quality over time. Our results demonstrate that enhancing prompt optimization with data augmentation significantly improves model performance. Our approach surpasses existing methods in classification, question answering, and reasoning tasks across multiple benchmarks.","published":"2025-02-16T09:46:04+00:00","updated":"2026-07-02T03:14:51+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=eboZXcjUe7","openreview_url":"https://openreview.net/forum?id=eboZXcjUe7","pdf_url":"https://openreview.net/pdf?id=eboZXcjUe7","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:wyBso4c7xv","versioned_id":"wyBso4c7xv","title":"$Navi-\\textit{plus}$: Managing Ambiguous GUI Navigation Tasks with Follow-up Questions","authors":[],"abstract":"Graphical user interfaces (GUI) automation agents are emerging as powerful tools, enabling humans to accomplish increasingly complex tasks on smart devices. However, users often inadvertently omit key information when conveying tasks, which hinders agent performance in the current agent paradigm that does not support immediate user intervention. To address this issue, we introduce a $\\textbf{Self-Correction GUI Navigation}$ task that incorporates interactive information completion capabilities within GUI agents. We developed the $\\textbf{Navi-\\textit{plus}}$ dataset with GUI follow-up question-answer pairs, alongside a $\\textbf{Dual-Stream Trajectory Evaluation}$ method to benchmark this new capability. Our results show that agents equipped with the ability to ask GUI follow-up questions can fully recover their performance when faced with ambiguous user tasks.","published":"2025-02-16T09:30:55+00:00","updated":"2026-07-02T03:14:46+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=wyBso4c7xv","openreview_url":"https://openreview.net/forum?id=wyBso4c7xv","pdf_url":"https://openreview.net/pdf?id=wyBso4c7xv","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:miDyhJddHS","versioned_id":"miDyhJddHS","title":"Gödel Agent: A Self-Referential Agent Framework for Recursively Self-Improvement","authors":[],"abstract":"The rapid advancement of large language models (LLMs) has significantly enhanced the capabilities of agents across various tasks. However, existing agentic systems, whether based on fixed pipeline algorithms or pre-defined meta-learning frameworks, cannot search the whole agent design space due to the restriction of human-designed components, and thus might miss the more optimal agent design. In this paper, we introduce Gödel Agent, a self-evolving framework inspired by the \\godel machine, enabling agents to recursively improve themselves without relying on predefined routines or fixed optimization algorithms. Gödel Agent leverages LLMs to dynamically modify its own logic and behavior, guided solely by high-level objectives through prompting. Experimental results on multiple domains demonstrate that implementation of Gödel Agent can achieve continuous self-improvement, surpassing manually crafted agents in performance, efficiency, and generalizability.","published":"2025-02-16T05:07:08+00:00","updated":"2026-07-02T03:14:12+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=miDyhJddHS","openreview_url":"https://openreview.net/forum?id=miDyhJddHS","pdf_url":"https://openreview.net/pdf?id=miDyhJddHS","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"openreview:fpGTITWG2N","versioned_id":"fpGTITWG2N","title":"When Words Outperform Vision: VLMs Can Self-Improve Via Text-Only Training For Human-Centered Decision Making","authors":[],"abstract":"Embodied decision-making is fundamental for AI agents operating in real-world environments. While Visual Language Models (VLMs) have advanced this capability, they still struggle with complex decisions, particularly in human-centered situations that require deep reasoning about human needs and values. In this study, we systematically evaluate open-sourced VLMs on multimodal human-centered decision-making tasks. We find that LLMs receiving only textual descriptions unexpectedly outperform their VLM counterparts of similar scale that process actual images, suggesting that visual alignment may hinder VLM abilities. To address this challenge, we propose a novel text-only training approach with synthesized textual data. This method strengthens VLMs' language components and transfers the learned abilities to multimodal inference, eliminating the need for expensive image-text paired data. Furthermore, we show that VLMs can achieve substantial performance gains through self-improvement, using training data generated by their LLM counterparts rather than relying on larger teacher models like GPT-4. Our findings establish a more efficient and scalable approach to enhancing VLMs' human-centered decision-making capabilities, opening new avenues for optimizing VLMs through self-improvement mechanisms.","published":"2025-02-16T04:36:05+00:00","updated":"2026-07-02T03:14:11+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=fpGTITWG2N","openreview_url":"https://openreview.net/forum?id=fpGTITWG2N","pdf_url":"https://openreview.net/pdf?id=fpGTITWG2N","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:MK4EuPjOIT","versioned_id":"MK4EuPjOIT","title":"Review, Refine, Repeat: Iterative Decoding of AI Agents with Dynamic Evaluation and Selection","authors":[],"abstract":"While AI agents have started excelling at various tasks, they may still struggle with complex structured generation and strategic planning. Improvements via standard fine-tuning is often impractical, as solving agentic tasks rely on black-box API access without control over model parameters. Inference-time methods offer a viable alternative, but existing approaches require white/gray-box access, limiting their applicability to black-box settings. A natural black-box solution is Best-of-N (BoN) sampling, a simple yet effective inference-time technique that operates without access to model weights or logits. However, BoN is inherently static and lacks iterative feedback integration, reducing its effectiveness in complex tasks. To address this, we propose IAD, an {\\em iterative decoding} approach that combines iterative refinement with dynamic candidate evaluation and selection guided by a verifier, to improve upon BoN. IAD is flexible, model-agnostic, and seamlessly integrates with API-based models, making it broadly applicable to agentic tasks. We evaluate IAD on diverse agentic tasks including Sketch2Code, Text2SQL, and Webshop, where it consistently outperforms baselines by over 15\\% across multiple metrics and setups.","published":"2025-02-15T18:35:56+00:00","updated":"2026-07-02T03:13:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=MK4EuPjOIT","openreview_url":"https://openreview.net/forum?id=MK4EuPjOIT","pdf_url":"https://openreview.net/pdf?id=MK4EuPjOIT","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:qrJa9QTAFA","versioned_id":"qrJa9QTAFA","title":"Iterative LLM Augmentation through Criteria-Based Feedback","authors":[],"abstract":"Large Language Model (LLM) self-reflection involves an LLM reviewing its past outputs to enhance future responses without relying on external data. This concept has been explored in frameworks like those by Shinn and Madaan. However, challenges remain, as Huang.point out the risk of performance degradation due to overly generic reflective prompts. To address these issues, we introduce a vector-based retrieval framework. Our approach demonstrates significant improvements in decision-making, reasoning, and mathematics tasks, surpassing baseline models like Llama3.2-3b and the SELF-REFINE framework. These results emphasize the potential of targeted self-reflection to improve LLM performance while mitigating common drawbacks. Meanwhile,beyond this method, we also explored the possibility of using a multi-agent approach with auxiliary models to assist in reflection. We trained a model to replace the base model in generating criteria and systematically evaluated the impact of the auxiliary model on the output capability of the self-reflection framework.","published":"2025-02-15T04:18:06+00:00","updated":"2026-07-02T03:13:01+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=qrJa9QTAFA","openreview_url":"https://openreview.net/forum?id=qrJa9QTAFA","pdf_url":"https://openreview.net/pdf?id=qrJa9QTAFA","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:mGAAoEWOq9","versioned_id":"mGAAoEWOq9","title":"Multi-Agent Verification: Scaling Test-Time Compute with Multiple Verifiers (Abridged)","authors":["Shalev Lifshitz","Sheila A. McIlraith","Yilun Du"],"abstract":"By utilizing more computational resources at test-time, large language models (LLMs) can improve without additional training. One common strategy uses *verifiers* to evaluate candidate outputs. In this work, we propose a novel scaling dimension for test-time compute: *scaling the number of verifiers*. We introduce Multi-Agent Verification (MAV) as a test-time compute paradigm that combines multiple verifiers to improve performance. We propose using Aspect Verifiers (AVs), off-the-shelf LLMs prompted to verify different aspects of outputs, as one possible choice for the verifiers in a MAV system. AVs are a convenient building block for MAV since they can be easily combined without additional training. Moreover, we introduce BoN-MAV, a simple multi-agent verification algorithm that combines best-of-*n* sampling with multiple verifiers. BoN-MAV demonstrates stronger scaling patterns than self-consistency and reward model verification, and we demonstrate both weak-to-strong generalization, where combining weak verifiers improves even stronger LLMs, and self-improvement, where the same base model is used to both generate and verify outputs. Our results establish scaling the number of verifiers as a promising new dimension for improving language model performance at test-time.","published":"2025-02-11T17:11:44+00:00","updated":"2025-03-22T22:23:25+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=mGAAoEWOq9","openreview_url":"https://openreview.net/forum?id=H22e93wnMe","pdf_url":"https://openreview.net/pdf?id=mGAAoEWOq9","comment":"MCDC @ ICLR 2025","journal_ref":"MCDC @ ICLR 2025","doi":"","venue":"MCDC @ ICLR 2025","venue_id":"ICLR.cc/2025/Workshop/MCDC","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"openreview_venues":["MCDC @ ICLR 2025","SSI-FM Poster","ICLR 2025 Workshop VerifAI Poster","Reasoning and Planning for LLMs @ ICLR2025"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"openreview:ZFk4eh0WcL","versioned_id":"ZFk4eh0WcL","title":"Moral Intrinsic Rewards for Automated Alignment of LLM Agents","authors":["Elizaveta Tennant","Stephen Hailes","Mirco Musolesi"],"abstract":"Decision-making agents based on pre-trained Large Language Models (LLMs) are increasingly being deployed across various domains of human activity. While their applications are currently rather specialized, several research efforts are under way to develop more generalist agents. As LLM-based systems become more agentic, their influence on human activity will grow and the transparency of this will decrease. Consequently, developing effective methods for aligning them to human values is vital. The prevailing practice in alignment often relies on human preference data (e.g., in RLHF or DPO), which is costly, can suffer from representation biases, and in which values are implicit and are essentially deduced from relative preferences over different model outputs. In this work, instead of relying on human feedback, we introduce the design of intrinsic reward functions that explicitly encode core human values for automated Reinforcement Learning-based fine-tuning of foundation agent models. The use of intrinsic rewards for the moral alignment of LLM agents amplifies human moral principles for automated (self-improving) alignment of LLM-based systems, and simultaneously represents a more transparent and cost-effective alternative to currently predominant alignment techniques. As an initial implementation, this paper evaluates this type of training defined using the traditional philosophical frameworks of Deontological Ethics and Utilitarianism, and quantifies moral rewards for agents in terms of actions and consequences on the Iterated Prisoner's Dilemma (IPD) environment. We find that certain moral strategies learned on the IPD game generalize to several other matrix game environments. The next step in this work should involve training agents with moral rewards across many diverse environments, to allow agents to learn more general and open-ended moral policies.","published":"2025-02-11T15:00:25+00:00","updated":"2025-04-11T22:13:53+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ZFk4eh0WcL","openreview_url":"https://openreview.net/forum?id=ZFk4eh0WcL","pdf_url":"https://openreview.net/pdf?id=ZFk4eh0WcL","comment":"SSI-FM Poster","journal_ref":"SSI-FM Poster","doi":"","venue":"SSI-FM Poster","venue_id":"ICLR.cc/2025/Workshop/SSI-FM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:9yUvxPhvQX","versioned_id":"9yUvxPhvQX","title":"Strengthening Robustness to Adversarial Prompts: The Role of Multi-Agent Conversations in Large Language Models","authors":[],"abstract":"While Large language models have shown impressive capabilities in problem-solving, understanding, and reasoning \\citep{Touvron2023, Du2023}, yet remain susceptible to sophisticated adversarial prompts that can manipulate models to generate harmful outputs \\citep{Zou2023, Wei2023}. Current defense mechanisms, such as self-refinement and safety guardrails \\citep{Korbak2023, Robey2023}, have shown limited effectiveness against these attacks. Building upon the multi-agent debate framework \\citep{Chern2024}, our research demonstrates how extended debates among diverse debaters enhance model resilience \\citep{Chan2023}. Using multiple attack techniques, we assess toxicity and attack success across varying debaters and debate lengths \\citep{Ganguli2022, Perez2022}. Our results demonstrate that cross-provider debates with extended interaction periods achieve significantly lower toxicity scores than single-provider systems. These findings advance our understanding of collaborative defense mechanisms in language models \\citep{Cohen2023}.","published":"2025-02-11T12:04:01+00:00","updated":"2025-03-06T05:52:31+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=9yUvxPhvQX","openreview_url":"https://openreview.net/forum?id=9yUvxPhvQX","pdf_url":"https://openreview.net/pdf?id=9yUvxPhvQX","comment":"Submitted to BuildingTrust","journal_ref":"Submitted to BuildingTrust","doi":"","venue":"Submitted to BuildingTrust","venue_id":"ICLR.cc/2025/Workshop/BuildingTrust/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:vWt7YoEJfe","versioned_id":"vWt7YoEJfe","title":"Socratic Style Chain-of-Thoughts Help LLMs to be a Better Reasoner","authors":[],"abstract":"Synthetic data generation has emerged as a promising approach to enhance the reasoning capabilities of large language models. However, existing methods remain hindered by high costs—either through expensive API access or additional intermediate training—and are limited in their ability to generalize across different domains. To address these challenges, we propose a multi-agent debate framework based on the Socratic questioning strategy, abbreviated as SoDa. Distinguished from previous methods that prioritize data quantity, we highlight the wisdom of Socratic questioning in augmenting reasoning quality by deepening the thinking process to encourage exploration and broadening it to motivate self-reflection on each question. Combined with our efficient production pipeline, SoDa enables scaling while maintaining affordable costs. We use SoDa to generate diverse datasets for mathematics and code generation tasks with the Qwen2.5-7B-Instruct model, successfully fine-tuning a range of foundation models, from general-purpose ones to OpenAI o1-like ones. For mathematics, the experimental results show that SoDa outperforms the performance of existing datasets at the same scale, achieving improvements ranging from 1.3% to 13.5%. Remarkably, SoDa with 30K examples even surpasses the ScaleQuest dataset with 1000K samples, demonstrating significant efficiency. Our findings highlight the potential of SoDa as a universal, scalable, and cost-effective method for enhancing reasoning capabilities in large models across domains.","published":"2025-02-11T07:03:56+00:00","updated":"2026-07-02T03:12:09+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=vWt7YoEJfe","openreview_url":"https://openreview.net/forum?id=vWt7YoEJfe","pdf_url":"https://openreview.net/pdf?id=vWt7YoEJfe","comment":"ACL ARR 2025 February Submission","journal_ref":"ACL ARR 2025 February Submission","doi":"","venue":"ACL ARR 2025 February Submission","venue_id":"aclweb.org/ACL/ARR/2025/February/Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:UeeyfR4CUg","versioned_id":"UeeyfR4CUg","title":"AgenticHypothesis: A Survey on Hypothesis Generation Using LLM Systems","authors":["Adib Bazgir","Rama chandra Praneeth Madugula","Yuwen Zhang"],"abstract":"Hypothesis generation is a cornerstone of scientific discovery, enabling researchers to formulate testable ideas that drive innovation and progress. Although traditional methods have proven effective, they are often constrained by cognitive biases, information overload, and time limitations. Recently, the emergence of Large Language Models (LLMs) has introduced a promising approach to automate and enhance hypothesis generation. Trained on extensive datasets, these models have demonstrated the potential to generate novel, testable hypotheses across various domains. This review critically examines state-of-the-art methodologies for LLM-based hypothesis generation, including Retrieval Augmented Generation (RAG), multi-agent frameworks, and iterative refinement techniques. Applications in biomedical research, materials science, product innovation, and interdisciplinary studies are discussed, highlighting both the versatility and the impact of these systems. Despite their promise, LLMs also present challenges such as hallucinations, data biases, and ethical concerns, which necessitate careful implementation and oversight. Future research directions include refining model architectures, integrating multimodal capabilities, and establishing robust ethical frameworks to optimize the use of LLMs in scientific research. Overall, this review provides a balanced overview of how LLMs may enhance hypothesis generation while also addressing the associated challenges. The GitHub repository containing open-source LLM-empowered hypothesis generation systems is available at https://github.com/adibgpt/AgenticHypothesis.","published":"2025-02-10T17:27:37+00:00","updated":"2025-03-28T20:34:10+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=UeeyfR4CUg","openreview_url":"https://openreview.net/forum?id=UeeyfR4CUg","pdf_url":"https://openreview.net/pdf?id=UeeyfR4CUg","comment":"ICLR 2025 Workshop AgenticAI Poster","journal_ref":"ICLR 2025 Workshop AgenticAI Poster","doi":"","venue":"ICLR 2025 Workshop AgenticAI Poster","venue_id":"ICLR.cc/2025/Workshop/AgenticAI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:dA7a3eKkKg","versioned_id":"dA7a3eKkKg","title":"LLMV-AgE: Verifying LLM-Guided Planning for Agentic Exploration in Open-World RL","authors":["Haotian Chi","Songwei Zhao","Ivor Tsang","Yew-Soon Ong","Hechang Chen","Yi Chang","Haiyan Yin"],"abstract":"Large language models (LLMs) have shown promise in enhancing reinforcement learning (RL) through task decomposition, yet their generated subgoals often lack reliability, leading to inefficient exploration and suboptimal policy learning. In this paper, we propose LLMV-AgE (Verification of LLM-guided planning for Agentic Exploration), an RL framework that integrates LLM-guided subgoal planning with a hierarchical verification process to ensure both semantic validity and environmental feasibility. LLMV-AgE systematically assesses subgoal coherence, corrects invalid plans through iterative refinement, and aligns policy learning with reliable, goal-driven objectives. Empirical results on the procedurally generated Crafter benchmark demonstrate that LLMV-AgE significantly improves exploration efficiency and policy robustness by mitigating the impact of hallucinated subgoals and guiding agents toward more achievable goals.","published":"2025-02-08T00:02:46+00:00","updated":"2025-03-21T04:10:47+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=dA7a3eKkKg","openreview_url":"https://openreview.net/forum?id=dA7a3eKkKg","pdf_url":"https://openreview.net/pdf?id=dA7a3eKkKg","comment":"ICLR 2025 Workshop VerifAI Poster","journal_ref":"ICLR 2025 Workshop VerifAI Poster","doi":"","venue":"ICLR 2025 Workshop VerifAI Poster","venue_id":"ICLR.cc/2025/Workshop/VerifAI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2502.04790","versioned_id":"2502.04790v2","title":"S$^2$-MAD: Breaking the Token Barrier to Enhance Multi-Agent Debate Efficiency","authors":["Yuting Zeng","Weizhe Huang","Lei Jiang","Tongxuan Liu","Xitai Jin","Chen Tianying Tiana","Jing Li","Xiaohua Xu"],"abstract":"Large language models (LLMs) have demonstrated remarkable capabilities across various natural language processing (NLP) scenarios, but they still face challenges when handling complex arithmetic and logical reasoning tasks. While Chain-Of-Thought (CoT) reasoning, self-consistency (SC) and self-correction strategies have attempted to guide models in sequential, multi-step reasoning, Multi-agent Debate (MAD) has emerged as a viable approach for enhancing the reasoning capabilities of LLMs. By increasing both the number of agents and the frequency of debates, the performance of LLMs improves significantly. However, this strategy results in a significant increase in token costs, presenting a barrier to scalability. To address this challenge, we introduce a novel sparsification strategy designed to reduce token costs within MAD. This approach minimizes ineffective exchanges of information and unproductive discussions among agents, thereby enhancing the overall efficiency of the debate process. We conduct comparative experiments on multiple datasets across various models, demonstrating that our approach significantly reduces the token costs in MAD to a considerable extent. Specifically, compared to MAD, our approach achieves an impressive reduction of up to 94.5\\% in token costs while maintaining performance degradation below 2.0\\%.","published":"2025-02-07T09:49:56Z","updated":"2025-04-10T02:29:35Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.04790v2","pdf_url":"https://arxiv.org/pdf/2502.04790v2","comment":"Accepted to NAACL 2025 Main","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.04780","versioned_id":"2502.04780v1","title":"SiriuS: Self-improving Multi-agent Systems via Bootstrapped Reasoning","authors":["Wanjia Zhao","Mert Yuksekgonul","Shirley Wu","James Zou"],"abstract":"Multi-agent AI systems powered by large language models (LLMs) are increasingly applied to solve complex tasks. However, these systems often rely on fragile, manually designed prompts and heuristics, making optimization difficult. A key challenge in optimizing multi-agent systems is acquiring suitable training data for specialized agents. We introduce SiriuS, a self-improving, reasoning-driven optimization framework for multi-agent systems. Central to our approach is the construction of an experience library: a repository of high-quality reasoning trajectories. The library is built by retaining reasoning steps that lead to successful outcomes, providing a robust training set for optimizing multi-agent system. Additionally, we introduce a library augmentation procedure that refines unsuccessful trajectories, further enriching the library. SiriuS boosts performance by 2.86\\% to 21.88\\% on reasoning and biomedical QA and enhances agent negotiation in competitive settings. Our results show that SiriuS enhances multi-agent performance while generating reusable data for self-correction and self-play enhancement in the future.","published":"2025-02-07T09:33:44Z","updated":"2025-02-07T09:33:44Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2502.04780v1","pdf_url":"https://arxiv.org/pdf/2502.04780v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":100,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=sLBSJr3hH5","openreview_venues":["NeurIPS 2025 poster","Reasoning and Planning for LLMs @ ICLR2025"]},{"id":"2502.04692","versioned_id":"2502.04692v3","title":"STRIDE: Automating Reward Design, Deep Reinforcement Learning Training and Feedback Optimization in Humanoid Robotics Locomotion","authors":["Zhenwei Wu","Jinxiong Lu","Yuxiao Chen","Yunxin Liu","Yueting Zhuang","Luhui Hu"],"abstract":"Humanoid robotics presents significant challenges in artificial intelligence, requiring precise coordination and control of high-degree-of-freedom systems. Designing effective reward functions for deep reinforcement learning (DRL) in this domain remains a critical bottleneck, demanding extensive manual effort, domain expertise, and iterative refinement. To overcome these challenges, we introduce STRIDE, a novel framework built on agentic engineering to automate reward design, DRL training, and feedback optimization for humanoid robot locomotion tasks. By combining the structured principles of agentic engineering with large language models (LLMs) for code-writing, zero-shot generation, and in-context optimization, STRIDE generates, evaluates, and iteratively refines reward functions without relying on task-specific prompts or templates. Across diverse environments featuring humanoid robot morphologies, STRIDE outperforms the state-of-the-art reward design framework EUREKA, achieving an average improvement of round 250% in efficiency and task performance. Using STRIDE-generated rewards, simulated humanoid robots achieve sprint-level locomotion across complex terrains, highlighting its ability to advance DRL workflows and humanoid robotics research.","published":"2025-02-07T06:37:05Z","updated":"2025-02-12T01:02:51Z","categories":["cs.RO","cs.LG"],"primary_category":"cs.RO","arxiv_url":"https://arxiv.org/abs/2502.04692v3","pdf_url":"https://arxiv.org/pdf/2502.04692v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:j0n3BJJTcT","versioned_id":"j0n3BJJTcT","title":"AgentBreeder: Mitigating the AI Safety Impact of Multi-Agent Scaffolds via Self-Improvement","authors":["J Rosser","Jakob Nicolaus Foerster"],"abstract":"Scaffolding Large Language Models (LLMs) into multi-agent systems often improves performance on complex tasks, but the safety impact of such scaffolds has not been thoroughly explored. We introduce AgentBreeder, a framework for multi-objective self-improving evolutionary search over scaffolds. We evaluate discovered scaffolds on widely recognized reasoning, mathematics, and safety benchmarks and compare them with popular baselines. In 'blue' mode, we see a 79.4% average uplift in safety benchmark performance while maintaining or improving capability scores. In 'red' mode, we find adversarially weak scaffolds emerging concurrently with capability optimization. Our work demonstrates the risks of multi-agent scaffolding and provides a framework for mitigating them. Code is available at https://github.com/J-Rosser-UK/AgentBreeder.","published":"2025-02-06T15:28:50+00:00","updated":"2025-04-14T09:52:34+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=j0n3BJJTcT","openreview_url":"https://openreview.net/forum?id=j0n3BJJTcT","pdf_url":"https://openreview.net/pdf?id=j0n3BJJTcT","comment":"SSI-FM Oral","journal_ref":"SSI-FM Oral","doi":"","venue":"SSI-FM Oral","venue_id":"ICLR.cc/2025/Workshop/SSI-FM","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:c5bjw7hqix","versioned_id":"c5bjw7hqix","title":"When Debate Fails: Bias Reinforcement in Large Language Models","authors":["Jihwan Oh","Minchan Jeong","Jongwoo Ko","Se-Young Yun"],"abstract":"Large Language Models (LLMs) solve complex problems using training-free methods like prompt engineering and in-context learning, yet ensuring reasoning correctness remains challenging. While self-correction methods such as self-consistency and self-refinement aim to improve reliability, they often reinforce biases due to the lack of effective feedback mechanisms. Multi-Agent Debate (MAD) has emerged as an alternative, but we identify two key limitations: bias reinforcement, where debate amplifies model biases instead of correcting them, and lack of perspective diversity, as all agents share the same model and reasoning patterns, limiting true debate effectiveness. To systematically evaluate these issues, we introduce $\\textit{MetaNIM Arena}$, a benchmark designed to assess LLMs in adversarial strategic decision-making, where dynamic interactions influence optimal decisions. To overcome MAD’s limitations, we propose $\\texttt{\\textbf{DReaMAD}}$ ($\\textbf{D}$iverse $\\textbf{Rea}$soning via $\\textbf{M}$ulti-$\\textbf{A}$gent $\\textbf{D}$ebate with Refined Prompt), a novel framework that (1) refines LLMs’ strategic prior knowledge to improve reasoning quality and (2) promotes diverse viewpoints within a single model by systematically modifying prompts, reducing bias. Empirical results show that $\\texttt{\\textbf{DReaMAD}}$ significantly improves decision accuracy, reasoning diversity, and bias mitigation across multiple strategic tasks, establishing it as a more effective approach for LLM-based decision-making.","published":"2025-02-05T13:22:25+00:00","updated":"2025-03-20T11:43:22+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=c5bjw7hqix","openreview_url":"https://openreview.net/forum?id=c5bjw7hqix","pdf_url":"https://openreview.net/pdf?id=c5bjw7hqix","comment":"Reasoning and Planning for LLMs @ ICLR2025","journal_ref":"Reasoning and Planning for LLMs @ ICLR2025","doi":"","venue":"Reasoning and Planning for LLMs @ ICLR2025","venue_id":"ICLR.cc/2025/Workshop/LLM_Reason_and_Plan","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"2502.02740","versioned_id":"2502.02740v1","title":"Vision-Language Model Dialog Games for Self-Improvement","authors":["Ksenia Konyushkova","Christos Kaplanis","Serkan Cabi","Misha Denil"],"abstract":"The increasing demand for high-quality, diverse training data poses a significant bottleneck in advancing vision-language models (VLMs). This paper presents VLM Dialog Games, a novel and scalable self-improvement framework for VLMs. Our approach leverages self-play between two agents engaged in a goal-oriented play centered around image identification. By filtering for successful game interactions, we automatically curate a high-quality dataset of interleaved images and text. We demonstrate that fine-tuning on this synthetic data leads to performance gains on downstream tasks and generalises across datasets. Moreover, as the improvements in the model lead to better game play, this procedure can be applied iteratively. This work paves the way for self-improving VLMs, with potential applications in various real-world scenarios especially when the high-quality multimodal data is scarce.","published":"2025-02-04T21:58:07Z","updated":"2025-02-04T21:58:07Z","categories":["cs.LG","cs.AI"],"primary_category":"cs.LG","arxiv_url":"https://arxiv.org/abs/2502.02740v1","pdf_url":"https://arxiv.org/pdf/2502.02740v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":70,"relevance_reasons":["标题命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=5mflJeoGOE","openreview_venues":["SSI-FM Poster"]},{"id":"2502.02534","versioned_id":"2502.02534v2","title":"Adaptive Self-improvement LLM Agentic System for ML Library Development","authors":["Genghan Zhang","Weixin Liang","Olivia Hsu","Kunle Olukotun"],"abstract":"ML libraries, often written in architecture-specific programming languages (ASPLs) that target domain-specific architectures, are key to efficient ML systems. However, writing these high-performance ML libraries is challenging because it requires expert knowledge of ML algorithms and the ASPL. Large language models (LLMs), on the other hand, have shown general coding capabilities. However, challenges remain when using LLMs for generating ML libraries using ASPLs because 1) this task is complicated even for experienced human programmers and 2) there are limited code examples because of the esoteric and evolving nature of ASPLs. Therefore, LLMs need complex reasoning with limited data in order to complete this task. To address these challenges, we introduce an adaptive self-improvement agentic system. In order to evaluate the effectiveness of our system, we construct a benchmark of a typical ML library and generate ASPL code with both open and closed-source LLMs on this benchmark. Our results show improvements of up to $3.9\\times$ over a baseline single LLM.","published":"2025-02-04T17:57:17Z","updated":"2025-09-19T04:28:06Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.02534v2","pdf_url":"https://arxiv.org/pdf/2502.02534v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=gdsZ3uMPsY","openreview_venues":["ES-FoMo III","Reasoning and Planning for LLMs @ ICLR2025","DL4C @ ICLR 2025 BestPaper","ICML 2025 poster"]},{"id":"openreview:6uxbUyASKB","versioned_id":"6uxbUyASKB","title":"LLaMP: Large Language Model Made Powerful for High-fidelity Materials Knowledge Retrieval","authors":["Yuan Chiang","Elvis Hsieh","Chia-Hong Chou","Janosh Riebesell"],"abstract":"Materials science research requires multi-step reasoning and precise material informatics retrieval, where minor errors can propagate into significant failures in downstream experiments. Despite their general success, Large Language Models (LLMs) often struggle with hallucinations, handling domain-specific data effectively (e.g., crystal structures), and integrating experimental workflows. To address these challenges, we introduce LLaMP, a hierarchical multi-agent framework designed to emulate the materials science research workflow. The high-level supervisor agent decomposes user requests into sub-tasks and coordinates with specialized assistant agents. These assistant agents handle domain-specific tasks, such as retrieving and processing data from the Materials Project (MP) or conducting simulations as needed. This pipeline facilitates iterative refinement of material property predictions and enables the simulation of real-world research workflows. To ensure reliability, we propose a novel metric combining uncertainty and confidence estimates to evaluate the self-consistency of responses from LLaMP and other methods. Our experiments with real-world materials science tasks demonstrate LLaMP’s superior performance in material property prediction, crystal structure editing, and annealing molecular dynamics simulations using pre-trained interatomic potentials. Unlike prior work focused solely on material property prediction or discovery, LLaMP serves as a foundation for autonomous materials research by combining grounded informatics and enabling iterative experimental processes.","published":"2025-02-04T07:14:18+00:00","updated":"2025-04-09T17:04:37+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=6uxbUyASKB","openreview_url":"https://openreview.net/forum?id=6uxbUyASKB","pdf_url":"https://openreview.net/pdf?id=6uxbUyASKB","comment":"AI4MAT-ICLR-2025 Poster","journal_ref":"AI4MAT-ICLR-2025 Poster","doi":"","venue":"AI4MAT-ICLR-2025 Poster","venue_id":"ICLR.cc/2025/Workshop/AI4MAT","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"2502.00988","versioned_id":"2502.00988v1","title":"PlotGen: Multi-Agent LLM-based Scientific Data Visualization via Multimodal Feedback","authors":["Kanika Goswami","Puneet Mathur","Ryan Rossi","Franck Dernoncourt"],"abstract":"Scientific data visualization is pivotal for transforming raw data into comprehensible visual representations, enabling pattern recognition, forecasting, and the presentation of data-driven insights. However, novice users often face difficulties due to the complexity of selecting appropriate tools and mastering visualization techniques. Large Language Models (LLMs) have recently demonstrated potential in assisting code generation, though they struggle with accuracy and require iterative debugging. In this paper, we propose PlotGen, a novel multi-agent framework aimed at automating the creation of precise scientific visualizations. PlotGen orchestrates multiple LLM-based agents, including a Query Planning Agent that breaks down complex user requests into executable steps, a Code Generation Agent that converts pseudocode into executable Python code, and three retrieval feedback agents - a Numeric Feedback Agent, a Lexical Feedback Agent, and a Visual Feedback Agent - that leverage multimodal LLMs to iteratively refine the data accuracy, textual labels, and visual correctness of generated plots via self-reflection. Extensive experiments show that PlotGen outperforms strong baselines, achieving a 4-6 percent improvement on the MatPlotBench dataset, leading to enhanced user trust in LLM-generated visualizations and improved novice productivity due to a reduction in debugging time needed for plot errors.","published":"2025-02-03T02:00:29Z","updated":"2025-02-03T02:00:29Z","categories":["cs.CL","cs.AI"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.00988v1","pdf_url":"https://arxiv.org/pdf/2502.00988v1","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2502.00757","versioned_id":"2502.00757v4","title":"AgentBreeder: Mitigating the AI Safety Risks of Multi-Agent Scaffolds via Self-Improvement","authors":["J Rosser","Jakob Foerster"],"abstract":"Scaffolding Large Language Models (LLMs) into multi-agent systems often improves performance on complex tasks, but the safety impact of such scaffolds has not been thoroughly explored. We introduce AgentBreeder, a framework for multi-objective self-improving evolutionary search over scaffolds. We evaluate discovered scaffolds on widely recognized reasoning, mathematics, and safety benchmarks and compare them with popular baselines. In \"blue\" mode, we see a 79.4% average uplift in safety benchmark performance while maintaining or improving capability scores. In \"red\" mode, we find adversarially weak scaffolds emerging concurrently with capability optimization. Our work demonstrates the risks of multi-agent scaffolding and provides a framework for mitigating them. Code is available at https://github.com/jrosseruk/AgentBreeder.","published":"2025-02-02T11:40:07Z","updated":"2025-10-14T09:49:14Z","categories":["cs.CR","cs.AI","cs.NE"],"primary_category":"cs.CR","arxiv_url":"https://arxiv.org/abs/2502.00757v4","pdf_url":"https://arxiv.org/pdf/2502.00757v4","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=mlU9KqdZUS","openreview_venues":["NeurIPS 2025 spotlight"]},{"id":"openreview:OuFIfDBwQd","versioned_id":"OuFIfDBwQd","title":"ReFoRCE: A Text-to-SQL Agent with Self-Refinement, Format Restriction, and Column Exploration","authors":["Minghang Deng","Ashwin Ramachandran","Canwen Xu","Lanxiang Hu","Zhewei Yao","Anupam Datta","Hao Zhang"],"abstract":"Text-to-SQL systems have unlocked easier access to critical data insights by enabling natural language queries over structured databases. However, deploying such systems in enterprise environments remains challenging due to factors such as large, complex schemas ($> 3000$ columns), diverse SQL dialects (e.g., BigQuery, Snowflake) and sophisticated query requirements (e.g., transformation, analytics). Current state-of-the-art performance on the Spider 2.0 dataset --- a benchmark built to mimic such complex environments --- remains limited at 20\\%. Key limitations include inadequate instruction-following, poor long-context comprehension, weak self-refinement, and insufficient dialect-specific knowledge. To address these gaps, we propose $\\textbf{ReFoRCE}$ (Self-$\\textbf{Re}$finement Agent with $\\textbf{Fo}$rmat $\\textbf{R}$estriction and $\\textbf{C}$olumn $\\textbf{E}$xploration) which introduces (1) table compression to mitigate long-context limitations (2) format restriction to ensure accurate answer format, and (3) iterative column exploration for enhanced schema understanding. Additionally, it employs self-refinement pipeline consisting of (1) parallelized workflows with voting mechanisms and (2) a Common Table Expression (CTE) based refinement approach to handle unresolved cases. ReFoRCE achieves state-of-the-art results scoring 26.69 on the Spider 2.0-Snow and scoring 24.50 on the Spider 2.0-Lite tasks.","published":"2025-02-02T05:29:03+00:00","updated":"2025-03-14T03:27:36+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=OuFIfDBwQd","openreview_url":"https://openreview.net/forum?id=OuFIfDBwQd","pdf_url":"https://openreview.net/pdf?id=OuFIfDBwQd","comment":"ICLR 2025 Workshop VerifAI Poster","journal_ref":"ICLR 2025 Workshop VerifAI Poster","doi":"","venue":"ICLR 2025 Workshop VerifAI Poster","venue_id":"ICLR.cc/2025/Workshop/VerifAI","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"]},{"id":"2502.00675","versioned_id":"2502.00675v5","title":"ReFoRCE: A Text-to-SQL Agent with Self-Refinement, Consensus Enforcement, and Column Exploration","authors":["Minghang Deng","Ashwin Ramachandran","Canwen Xu","Lanxiang Hu","Zhewei Yao","Anupam Datta","Hao Zhang"],"abstract":"We present ReFoRCE, a Text-to-SQL agent that tops the Spider 2.0 leaderboard--a challenging benchmark reflecting complex, real-world Text-to-SQL scenarios. While Text-to-SQL systems enable natural language queries over structured databases, deploying them in enterprise environments remains difficult due to large, complex schemas (with over 1,000 columns), diverse SQL dialects (e.g., BigQuery, Snowflake), and sophisticated query requirements (e.g., transformations and analytics). ReFoRCE addresses these challenges through: (a) database information compression via pattern-based table grouping and LLM-guided schema linking to alleviate long-context issues; (b) self-refinement to iteratively correct syntax and semantic errors across dialects; (c) majority-vote consensus to select high-confidence candidates while deferring ambiguous cases arising from sophisticated queries; and (d) iterative column exploration guided by execution feedback to resolve those deferred cases. ReFoRCE achieves new state-of-the-art results, with scores of 35.83 on Spider 2.0-Snow and 36.56 on Spider 2.0-Lite.","published":"2025-02-02T05:25:03Z","updated":"2025-06-03T18:03:32Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2502.00675v5","pdf_url":"https://arxiv.org/pdf/2502.00675v5","comment":"33 pages, 3 figures","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":90,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:IHxbEEDSkL","versioned_id":"IHxbEEDSkL","title":"Disentangling Exploration of Large Language Models by Optimal Exploitation","authors":["Tim Grams","Patrick Betz","Christian Bartelt"],"abstract":"Exploration is a crucial skill for self-improvement and open-ended problem-solving. However, it remains unclear if large language models can effectively explore the state-space within an unknown environment. This work isolates exploration as the sole objective, tasking the agent with delivering information that enhances future returns. Within this framework, we argue that measuring agent returns is not sufficient for a fair evaluation and decompose missing rewards into exploration and exploitation components based on the optimal achievable return. Comprehensive experiments with various models reveal that most struggle to sufficiently explore the state-space and weak exploration is insufficient. We found a positive correlation of exploration performance with language comprehension and reasoning capabilities. Furthermore, we show that our decomposition can provide insights into differences in behaviors driven by prompt engineering, offering a valuable tool for refining performance in exploratory tasks.","published":"2025-02-01T22:34:55+00:00","updated":"2025-03-15T09:36:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=IHxbEEDSkL","openreview_url":"https://openreview.net/forum?id=IHxbEEDSkL","pdf_url":"https://openreview.net/pdf?id=IHxbEEDSkL","comment":"Reasoning and Planning for LLMs @ ICLR2025","journal_ref":"Reasoning and Planning for LLMs @ ICLR2025","doi":"","venue":"Reasoning and Planning for LLMs @ ICLR2025","venue_id":"ICLR.cc/2025/Workshop/LLM_Reason_and_Plan","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":43,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词","摘要中的两类信号距离接近"]},{"id":"openreview:T49vPTkIt5","versioned_id":"T49vPTkIt5","title":"Knowing What Not to Do: Leverage Language Model Insights for Action Space Pruning in Multi-agent Reinforcement Learning","authors":["Zhihao Liu","Xianliang Yang","Zichuan Liu","Yifan Xia","Wei Jiang","Yuanyu Zhang","Lijuan Li","Guoliang Fan","Lei Song","Jiang Bian"],"abstract":"Multi-agent reinforcement learning (MARL) is employed to develop autonomous agents that can learn to adopt cooperative or competitive strategies within complex environments. However, the linear increase in the number of agents leads to a combinatorial explosion of the action space, which always results in algorithmic instability, difficulty in convergence, or entrapment in local optima. While researchers have designed a variety of effective algorithms to compress the action space, these methods also introduce new challenges, such as the need for manually designed prior knowledge or reliance on the structure of the problem, which diminishes the applicability of these techniques. In this paper, we introduce \\textbf{E}volutionary action \\textbf{SPA}ce \\textbf{R}eduction with \\textbf{K}nowledge (eSpark), an exploration function generation framework driven by large language models (LLMs) to boost exploration and prune unnecessary actions in MARL. Using just a basic prompt that outlines the overall task and setting, eSpark is capable of generating exploration functions in a zero-shot manner, identifying and pruning redundant or irrelevant state-action pairs, and then achieving autonomous improvement from policy feedback. In reinforcement learning tasks involving inventory management and traffic light control encompassing a total of 15 scenarios, eSpark consistently outperforms the combined MARL algorithm in all scenarios, achieving an average performance gain of 34.4% and 9.9% in the two types of tasks respectively. Additionally, eSpark has proven to be capable of managing situations with a large number of agents, securing a 29.7% improvement in scalability challenges that featured over 500 agents. The code can be found in https://github.com/LiuZhihao2022/eSpark.","published":"2025-01-30T06:05:58+00:00","updated":"2025-06-09T00:19:26+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=T49vPTkIt5","openreview_url":"https://openreview.net/forum?id=T49vPTkIt5","pdf_url":"https://openreview.net/pdf?id=T49vPTkIt5","comment":"Accepted by TMLR","journal_ref":"Accepted by TMLR","doi":"","venue":"Accepted by TMLR","venue_id":"TMLR","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2501.14917","versioned_id":"2501.14917v6","title":"Self-reflecting Large Language Models: A Hegelian Dialectical Approach","authors":["Sara Abdali","Can Goksen","Michael Solodko","Saeed Amizadeh","Julie E. Maybee","Kazuhito Koishida"],"abstract":"Investigating NLP through a philosophical lens has recently caught researchers' eyes, as it bridges computational methods with classical schools of philosophy. This paper introduces a philosophical framework inspired by the Hegelian Dialectic to enable LLMs' self-reflection, utilizing a self-dialectical approach to emulate internal critiques and synthesize new scientific ideas (spanning domains such as mathematics, physics, and more). Additionally, we explore the effect of generation temperature in LLMs by introducing a dynamic annealing approach, which encourages creativity in the early stages and gradually focuses on refinement and nuance, as well as a constant-temperature strategy. Furthermore, we implement a Multi-Agent Majority Voting (MAMV) strategy to assess the validity and novelty of the generated ideas, which proves useful in the absence of domain experts. We also evaluate the effectiveness of our method in generating novel scientific ideas and improving LLMs' reasoning capabilities. Our experiments demonstrate promising results in ideation, along with significant improvements in mathematical and symbolic reasoning.","published":"2025-01-24T20:54:29Z","updated":"2025-06-23T18:59:06Z","categories":["cs.CL","cs.HC","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.14917v6","pdf_url":"https://arxiv.org/pdf/2501.14917v6","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2501.14224","versioned_id":"2501.14224v1","title":"Top Ten Challenges Towards Agentic Neural Graph Databases","authors":["Jiaxin Bai","Zihao Wang","Yukun Zhou","Hang Yin","Weizhi Fei","Qi Hu","Zheye Deng","Jiayang Cheng","Tianshi Zheng","Hong Ting Tsang","Yisen Gao","Zhongwei Xie","Yufei Li","Lixin Fan","Binhang Yuan","Wei Wang","Lei Chen","Xiaofang Zhou","Yangqiu Song"],"abstract":"Graph databases (GDBs) like Neo4j and TigerGraph excel at handling interconnected data but lack advanced inference capabilities. Neural Graph Databases (NGDBs) address this by integrating Graph Neural Networks (GNNs) for predictive analysis and reasoning over incomplete or noisy data. However, NGDBs rely on predefined queries and lack autonomy and adaptability. This paper introduces Agentic Neural Graph Databases (Agentic NGDBs), which extend NGDBs with three core functionalities: autonomous query construction, neural query execution, and continuous learning. We identify ten key challenges in realizing Agentic NGDBs: semantic unit representation, abductive reasoning, scalable query execution, and integration with foundation models like large language models (LLMs). By addressing these challenges, Agentic NGDBs can enable intelligent, self-improving systems for modern data-driven applications, paving the way for adaptable and autonomous data management solutions.","published":"2025-01-24T04:06:50Z","updated":"2025-01-24T04:06:50Z","categories":["cs.AI","cs.DB","cs.LG"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.14224v1","pdf_url":"https://arxiv.org/pdf/2501.14224v1","comment":"12 Pages","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:K4N9UvsuNB","versioned_id":"K4N9UvsuNB","title":"Improving Model Alignment Through Collective Intelligence of Open-Source Models","authors":["Junlin Wang","Roy Xie","Shang Zhu","Jue WANG","Ben Athiwaratkun","Bhuwan Dhingra","Shuaiwen Leon Song","Ce Zhang","James Zou"],"abstract":"Building helpful and harmless large language models (LLMs) requires effective model alignment approach based on human instructions and feedback, which necessitates high-quality human-labeled data. Constructing such datasets is often expensive and hard to scale, and may face potential limitations on diversity and generalization. To address these challenges, we introduce Mixture of Agents Alignment (MoAA), that leverages the collective strengths of various language models to provide high-quality data for model alignment. By employing MoAA, we enhance both supervised fine-tuning and preference optimization, leading to improved performance compared to using a single model alone to generate alignment data (e.g. using GPT-4o alone). Evaluation results show that our approach can improve win rate of LLaMA-3.1-8B-Instruct from 19.5 to 48.3 on Arena-Hard and from 22.33 to 57.23 on AlpacaEval2, highlighting a promising direction for model alignment through this new scalable and diverse synthetic data recipe. Furthermore, we demonstrate that MoAA enables a self-improvement pipeline, where models fine-tuned on MoA-generated data surpass their own initial capabilities, providing evidence that our approach can push the frontier of open-source LLMs without reliance on stronger external supervision. Data and code will be released.","published":"2025-01-23T23:26:46+00:00","updated":"2025-07-23T17:51:40+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=K4N9UvsuNB","openreview_url":"https://openreview.net/forum?id=K4N9UvsuNB","pdf_url":"https://openreview.net/pdf?id=K4N9UvsuNB","comment":"ICML 2025 poster","journal_ref":"ICML 2025 poster","doi":"","venue":"ICML 2025 poster","venue_id":"ICML.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"openreview:4KhDd0Ozqe","versioned_id":"4KhDd0Ozqe","title":"Position: Truly Self-Improving Agents Require Intrinsic Metacognitive Learning","authors":["Tennison Liu","Mihaela van der Schaar"],"abstract":"Self-improving agents aim to continuously acquire new capabilities with minimal supervision. However, current approaches face two key limitations: their self-improvement processes are often rigid, fail to generalize across tasks domains, and struggle to scale with increasing agent capabilities. We argue that effective self-improvement requires intrinsic metacognitive learning, defined as an agent’s $\\textit{intrinsic}$ ability to actively evaluate, reflect on, and adapt its own learning processes. Drawing inspiration from human metacognition, we introduce a formal framework comprising three components: $\\textit{metacognitive knowledge}$ (self-assessment of capabilities, tasks, and learning strategies), $\\textit{metacognitive planning}$ (deciding what and how to learn), and $\\textit{metacognitive evaluation}$ (reflecting on learning experiences to improve future learning). Analyzing existing self-improving agents, we find they rely predominantly on $\\textit{extrinsic}$ metacognitive mechanisms, which are fixed, human-designed loops that limit scalability and adaptability. Examining each component, we contend that many ingredients for intrinsic metacognition are already present. Finally, we explore how to optimally distribute metacognitive responsibilities between humans and agents, and robustly evaluate and improve intrinsic metacognitive learning, key challenges that must be addressed to enable truly sustained, generalized, and aligned self-improvement.","published":"2025-01-23T22:19:32+00:00","updated":"2025-07-23T17:30:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=4KhDd0Ozqe","openreview_url":"https://openreview.net/forum?id=4KhDd0Ozqe","pdf_url":"https://openreview.net/pdf?id=4KhDd0Ozqe","comment":"ICML 2025 Position Paper Track poster","journal_ref":"ICML 2025 Position Paper Track poster","doi":"","venue":"ICML 2025 Position Paper Track poster","venue_id":"ICML.cc/2025/Position_Paper_Track","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:23iGt7BBtl","versioned_id":"23iGt7BBtl","title":"Understanding Bias Reinforcement in LLM Agents Debate","authors":["Jihwan Oh","Minchan Jeong","Jongwoo Ko","Se-Young Yun"],"abstract":"Large Language Models (LLMs) solve complex problems using training-free methods like prompt engineering and in-context learning, yet ensuring reasoning correctness remains challenging. While self-correction methods such as self-consistency and self-refinement aim to improve reliability, they often reinforce biases due to the lack of effective feedback mechanisms. Multi-Agent Debate (MAD) has emerged as an alternative, but we identify two key limitations: bias reinforcement, where debate amplifies model biases instead of correcting them, and lack of perspective diversity, as all agents share the same model and reasoning patterns, limiting true debate effectiveness. To systematically evaluate these issues, we introduce $\\textit{MetaNIM Arena}$, a benchmark designed to assess LLMs in adversarial strategic decision-making, where dynamic interactions influence optimal decisions. To overcome MAD’s limitations, we propose $\\texttt{\\textbf{DReaMAD}}$ ($\\textbf{D}$iverse $\\textbf{Rea}$soning via $\\textbf{M}$ulti-$\\textbf{A}$gent $\\textbf{D}$ebate with Refined Prompt), a novel framework that (1) refines LLMs’ strategic prior knowledge to improve reasoning quality and (2) promotes diverse viewpoints within a single model by systematically modifying prompts, reducing bias. Empirical results show that $\\texttt{\\textbf{DReaMAD}}$ significantly improves decision accuracy, reasoning diversity, and bias mitigation across multiple strategic tasks, establishing it as a more effective approach for LLM-based decision-making.","published":"2025-01-23T06:03:55+00:00","updated":"2025-07-14T22:07:24+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=23iGt7BBtl","openreview_url":"https://openreview.net/forum?id=23iGt7BBtl","pdf_url":"https://openreview.net/pdf?id=23iGt7BBtl","comment":"ICML 2025 Retracted by Authors","journal_ref":"ICML 2025 Retracted by Authors","doi":"","venue":"ICML 2025 Retracted by Authors","venue_id":"ICML.cc/2025/Conference/Retracted_Acceptance","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":63,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近","覆盖多个自进化关键词"]},{"id":"openreview:ASOb5Cw8Rv","versioned_id":"ASOb5Cw8Rv","title":"Position: Public Health Systems Should Embrace a Multi-Layered Epidemic Early-Warning with LLM Agents and Local Knowledge Enhancement","authors":["OU DENG","Qun Jin"],"abstract":"We posit that public health systems worldwide should adopt a multi-layered epidemic early-warning mechanism, coupling large language model (LLM) agents with locally enriched knowledge bases. Specifically, we propose a three-tier framework comprising (i) distributed multi-agent data ingestion, (ii) centralized vector-based analytics and Reinforcement Learning (RL)-driven optimization, and (iii) regionally maintained expert repositories for final validation. By synchronizing real-time social media data, clinical records, and domain insights, our approach aims to accelerate detection, refine risk assessment, and expedite intervention for novel infectious threats. In particular, we highlight benefits for multi-modal data fusion, cross-lingual coverage, and privacy preservation. We further address critiques regarding model reliability, data governance, and resource allocation, outlining how federated learning protocols and human oversight mitigate these challenges. Ultimately, we reaffirm that integrating LLM-centric workflows with local expertise and iterative refinement offers a scalable path to strengthening epidemic surveillance, providing an adaptive, context-aware shield against emerging outbreaks.","published":"2025-01-23T01:33:26+00:00","updated":"2025-06-18T06:27:44+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=ASOb5Cw8Rv","openreview_url":"https://openreview.net/forum?id=ASOb5Cw8Rv","pdf_url":"https://openreview.net/pdf?id=ASOb5Cw8Rv","comment":"Submitted to ICML 2025 Position Paper Track","journal_ref":"Submitted to ICML 2025 Position Paper Track","doi":"","venue":"Submitted to ICML 2025 Position Paper Track","venue_id":"ICML.cc/2025/Position_Paper_Track/Rejected_Submission","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":48,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词"]},{"id":"2501.11733","versioned_id":"2501.11733v2","title":"Mobile-Agent-E: Self-Evolving Mobile Assistant for Complex Tasks","authors":["Zhenhailong Wang","Haiyang Xu","Junyang Wang","Xi Zhang","Ming Yan","Ji Zhang","Fei Huang","Heng Ji"],"abstract":"Smartphones have become indispensable in modern life, yet navigating complex tasks on mobile devices often remains frustrating. Recent advancements in large multimodal model (LMM)-based mobile agents have demonstrated the ability to perceive and act in mobile environments. However, current approaches face significant limitations: they fall short in addressing real-world human needs, struggle with reasoning-intensive and long-horizon tasks, and lack mechanisms to learn and improve from prior experiences. To overcome these challenges, we introduce Mobile-Agent-E, a hierarchical multi-agent framework capable of self-evolution through past experience. By hierarchical, we mean an explicit separation of high-level planning and low-level action execution. The framework comprises a Manager, responsible for devising overall plans by breaking down complex tasks into subgoals, and four subordinate agents--Perceptor, Operator, Action Reflector, and Notetaker--which handle fine-grained visual perception, immediate action execution, error verification, and information aggregation, respectively. Mobile-Agent-E also features a novel self-evolution module which maintains a persistent long-term memory comprising Tips and Shortcuts. Tips are general guidance and lessons learned from prior tasks on how to effectively interact with the environment. Shortcuts are reusable, executable sequences of atomic operations tailored for specific subroutines. The inclusion of Tips and Shortcuts facilitates continuous refinement in performance and efficiency. Alongside this framework, we introduce Mobile-Eval-E, a new benchmark featuring complex mobile tasks requiring long-horizon, multi-app interactions. Empirical results show that Mobile-Agent-E achieves a 22% absolute improvement over previous state-of-the-art approaches across three foundation model backbones. Project page: https://x-plug.github.io/MobileAgent.","published":"2025-01-20T20:35:46Z","updated":"2025-01-28T16:58:02Z","categories":["cs.CL","cs.CV"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.11733v2","pdf_url":"https://arxiv.org/pdf/2501.11733v2","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv","OpenReview"],"openreview_url":"https://openreview.net/forum?id=yrHzFpcQkE","openreview_venues":["SEA @ NeurIPS 2025 Oral"]},{"id":"2501.11425","versioned_id":"2501.11425v3","title":"Agent-R: Training Language Model Agents to Reflect via Iterative Self-Training","authors":["Siyu Yuan","Zehui Chen","Zhiheng Xi","Junjie Ye","Zhengyin Du","Jiecao Chen"],"abstract":"Large Language Models (LLMs) agents are increasingly pivotal for addressing complex tasks in interactive environments. Existing work mainly focuses on enhancing performance through behavior cloning from stronger experts, yet such approaches often falter in real-world applications, mainly due to the inability to recover from errors. However, step-level critique data is difficult and expensive to collect. Automating and dynamically constructing self-critique datasets is thus crucial to empowering models with intelligent agent capabilities. In this work, we propose an iterative self-training framework, Agent-R, that enables language Agent to Reflect on the fly. Unlike traditional methods that reward or penalize actions based on correctness, Agent-R leverages MCTS to construct training data that recover correct trajectories from erroneous ones. A key challenge of agent reflection lies in the necessity for timely revision rather than waiting until the end of a rollout. To address this, we introduce a model-guided critique construction mechanism: the actor model identifies the first error step (within its current capability) in a failed trajectory. Starting from it, we splice it with the adjacent correct path, which shares the same parent node in the tree. This strategy enables the model to learn reflection based on its current policy, therefore yielding better learning efficiency. To further explore the scalability of this self-improvement paradigm, we investigate iterative refinement of both error correction capabilities and dataset construction. Our findings demonstrate that Agent-R continuously improves the model's ability to recover from errors and enables timely error correction. Experiments on three interactive environments show that Agent-R effectively equips agents to correct erroneous actions while avoiding loops, achieving superior performance compared to baseline methods (+5.59%).","published":"2025-01-20T11:46:04Z","updated":"2025-03-24T10:18:56Z","categories":["cs.AI"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.11425v3","pdf_url":"https://arxiv.org/pdf/2501.11425v3","comment":"","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","覆盖多个自进化关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]},{"id":"openreview:YqerkYZfvu","versioned_id":"YqerkYZfvu","title":"Perception in Reflection","authors":["Yana Wei","Liang Zhao","Kangheng Lin","En Yu","Yuang Peng","Runpei Dong","Jianjian Sun","Haoran Wei","Zheng Ge","Xiangyu Zhang","Vishal M. Patel"],"abstract":"We present a perception in reflection paradigm designed to transcend the limitations of current large vision-language models (LVLMs), which are expected yet often fail to achieve perfect perception initially. Specifically, we propose Reflective Perception (RePer), a dual-model reflection mechanism that systematically alternates between policy and critic models, enables iterative refinement of visual perception. This framework is powered by Reflective Perceptual Learning (RPL), which reinforces intrinsic reflective capabilities through a methodically constructed visual reflection dataset and reflective unlikelihood training Comprehensive experimental evaluation demonstrates RePer's quantifiable improvements in image understanding, captioning precision, and hallucination reduction. Notably, RePer achieves strong alignment between model attention patterns and human visual focus, while RPL optimizes fine-grained and free-form preference alignment. These advancements establish perception in reflection as a robust paradigm for future multimodal agents, particularly in tasks requiring complex reasoning and multi-step manipulation. Project Page: [https://weiyana.github.io/Perception-in-Reflection](https://weiyana.github.io/Perception-in-Reflection)","published":"2025-01-10T14:18:39+00:00","updated":"2025-07-23T17:46:32+00:00","categories":["OpenReview"],"primary_category":"OpenReview","arxiv_url":"https://openreview.net/forum?id=YqerkYZfvu","openreview_url":"https://openreview.net/forum?id=YqerkYZfvu","pdf_url":"https://openreview.net/pdf?id=YqerkYZfvu","comment":"ICML 2025 poster","journal_ref":"ICML 2025 poster","doi":"","venue":"ICML 2025 poster","venue_id":"ICML.cc/2025/Conference","discovered_on":"2026-07-19","source":"OpenReview","sources":["OpenReview"],"relevance_score":33,"relevance_reasons":["摘要命中自进化关键词","摘要命中 Agent 关键词"]},{"id":"2501.05707","versioned_id":"2501.05707v2","title":"Multiagent Finetuning: Self Improvement with Diverse Reasoning Chains","authors":["Vighnesh Subramaniam","Yilun Du","Joshua B. Tenenbaum","Antonio Torralba","Shuang Li","Igor Mordatch"],"abstract":"Large language models (LLMs) have achieved remarkable performance in recent years but are fundamentally limited by the underlying training data. To improve models beyond the training data, recent works have explored how LLMs can be used to generate synthetic data for autonomous self-improvement. However, successive steps of self-improvement can reach a point of diminishing returns. In this work, we propose a complementary approach towards self-improvement where finetuning is applied to a multiagent society of language models. A group of language models, all starting from the same base model, are independently specialized by updating each one using data generated through multiagent interactions among the models. By training each model on independent sets of data, we illustrate how this approach enables specialization across models and diversification over the set of models. As a result, our overall system is able to preserve diverse reasoning chains and autonomously improve over many more rounds of fine-tuning than single-agent self-improvement methods. We quantitatively illustrate the efficacy of the approach across a wide suite of reasoning tasks.","published":"2025-01-10T04:35:46Z","updated":"2025-03-03T18:58:16Z","categories":["cs.CL","cs.AI","cs.LG"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.05707v2","pdf_url":"https://arxiv.org/pdf/2501.05707v2","comment":"ICLR 2025; 22 pages, 13 figures, 7 tables; Project page at https://llm-multiagent-ft.github.io/","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":95,"relevance_reasons":["标题命中自进化关键词","标题命中 Agent 关键词","标题同时包含自进化与 Agent 信号","标题中的两类信号距离接近","覆盖多个自进化关键词"],"source":"arXiv","sources":["arXiv"]},{"id":"2501.05468","versioned_id":"2501.05468v2","title":"LatteReview: A Multi-Agent Framework for Systematic Review Automation Using Large Language Models","authors":["Pouria Rouzrokh","Bardia Khosravi","Parsa Rouzrokh","Moein Shariatnia"],"abstract":"Systematic literature reviews and meta-analyses are essential for synthesizing research insights, but they remain time-intensive and labor-intensive due to the iterative processes of screening, evaluation, and data extraction. This paper introduces and evaluates LatteReview, a Python-based framework that leverages large language models (LLMs) and multi-agent systems to automate key elements of the systematic review process. Designed to streamline workflows while maintaining rigor, LatteReview utilizes modular agents for tasks such as title and abstract screening, relevance scoring, and structured data extraction. These agents operate within orchestrated workflows, supporting sequential and parallel review rounds, dynamic decision-making, and iterative refinement based on user feedback. LatteReview's architecture integrates LLM providers, enabling compatibility with both cloud-based and locally hosted models. The framework supports features such as Retrieval-Augmented Generation (RAG) for incorporating external context, multimodal reviews, Pydantic-based validation for structured inputs and outputs, and asynchronous programming for handling large-scale datasets. The framework is available on the GitHub repository, with detailed documentation and an installable package.","published":"2025-01-05T17:53:00Z","updated":"2025-10-08T17:55:02Z","categories":["cs.CL"],"primary_category":"cs.CL","arxiv_url":"https://arxiv.org/abs/2501.05468v2","pdf_url":"https://arxiv.org/pdf/2501.05468v2","comment":"31 pages, 5 figures, 5 tables","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":58,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","摘要中的两类信号距离接近"],"source":"arXiv","sources":["arXiv"]},{"id":"2501.01702","versioned_id":"2501.01702v2","title":"AgentRefine: Enhancing Agent Generalization through Refinement Tuning","authors":["Dayuan Fu","Keqing He","Yejie Wang","Wentao Hong","Zhuoma Gongque","Weihao Zeng","Wei Wang","Jingang Wang","Xunliang Cai","Weiran Xu"],"abstract":"Large Language Model (LLM) based agents have proved their ability to perform complex tasks like humans. However, there is still a large gap between open-sourced LLMs and commercial models like the GPT series. In this paper, we focus on improving the agent generalization capabilities of LLMs via instruction tuning. We first observe that the existing agent training corpus exhibits satisfactory results on held-in evaluation sets but fails to generalize to held-out sets. These agent-tuning works face severe formatting errors and are frequently stuck in the same mistake for a long while. We analyze that the poor generalization ability comes from overfitting to several manual agent environments and a lack of adaptation to new situations. They struggle with the wrong action steps and can not learn from the experience but just memorize existing observation-action relations. Inspired by the insight, we propose a novel AgentRefine framework for agent-tuning. The core idea is to enable the model to learn to correct its mistakes via observation in the trajectory. Specifically, we propose an agent synthesis framework to encompass a diverse array of environments and tasks and prompt a strong LLM to refine its error action according to the environment feedback. AgentRefine significantly outperforms state-of-the-art agent-tuning work in terms of generalization ability on diverse agent tasks. It also has better robustness facing perturbation and can generate diversified thought in inference. Our findings establish the correlation between agent generalization and self-refinement and provide a new paradigm for future research.","published":"2025-01-03T08:55:19Z","updated":"2025-02-24T12:42:14Z","categories":["cs.AI","cs.CL","cs.RO"],"primary_category":"cs.AI","arxiv_url":"https://arxiv.org/abs/2501.01702v2","pdf_url":"https://arxiv.org/pdf/2501.01702v2","comment":"ICLR 2025","journal_ref":"","doi":"","discovered_on":"2026-07-17","relevance_score":53,"relevance_reasons":["摘要命中自进化关键词","标题命中 Agent 关键词","属于核心 Agent 相关分类"],"source":"arXiv","sources":["arXiv"]}],"query":"((ti:\"self improvement\" OR abs:\"self improvement\") OR (ti:\"self-improvement\" OR abs:\"self-improvement\") OR (ti:\"self improving\" OR abs:\"self improving\") OR (ti:\"self-improving\" OR abs:\"self-improving\") OR (ti:\"recursive self-improvement\" OR abs:\"recursive self-improvement\") OR (ti:\"self-refinement\" OR abs:\"self-refinement\") OR (ti:\"self-reflection\" OR abs:\"self-reflection\") OR (ti:\"self-correction\" OR abs:\"self-correction\") OR (ti:\"self-evolution\" OR abs:\"self-evolution\") OR (ti:\"autonomous improvement\" OR abs:\"autonomous improvement\") OR (ti:\"continual self-training\" OR abs:\"continual self-training\") OR (ti:\"iterative refinement\" OR abs:\"iterative refinement\") OR (ti:\"learning from self-generated feedback\" OR abs:\"learning from self-generated feedback\") OR (ti:\"agent evolution\" OR abs:\"agent evolution\")) AND ((ti:\"agent\" OR abs:\"agent\") OR (ti:\"agents\" OR abs:\"agents\") OR (ti:\"agentic\" OR abs:\"agentic\") OR (ti:\"multi-agent\" OR abs:\"multi-agent\") OR (ti:\"multiagent\" OR abs:\"multiagent\")) AND (cat:cs.AI OR cat:cs.CL OR cat:cs.LG OR cat:cs.MA) AND submittedDate:[202501010000 TO 209912312359]","source":"arXiv + OpenReview","source_url":"https://export.arxiv.org/api/query","last_checked":"2026-07-21T06:47:21+00:00","last_success":"2026-07-21T06:47:21+00:00","new_count":0,"total_cached":1043,"fetch_error":"","relevance_method":"explainable-keyword-v1","openreview_query":["(\"self improvement\" OR \"self-improvement\" OR \"self improving\" OR \"self-improving\") AND (\"agent\" OR \"agents\" OR \"agentic\" OR \"multi-agent\" OR \"multiagent\")","(\"recursive self-improvement\" OR \"self-refinement\" OR \"self-reflection\" OR \"self-correction\") AND (\"agent\" OR \"agents\" OR \"agentic\" OR \"multi-agent\" OR \"multiagent\")","(\"self-evolution\" OR \"autonomous improvement\" OR \"continual self-training\" OR \"iterative refinement\") AND (\"agent\" OR \"agents\" OR \"agentic\" OR \"multi-agent\" OR \"multiagent\")","(\"learning from self-generated feedback\" OR \"agent evolution\") AND (\"agent\" OR \"agents\" OR \"agentic\" OR \"multi-agent\" OR \"multiagent\")"],"source_urls":{"arXiv":"https://export.arxiv.org/api/query","OpenReview":"https://api2.openreview.net/notes/search"}};
